// ── KITCHEN MEAL LIBRARY — data layer ───────────────────────────────────
// SINGLE FILE for everything kitchen-library-related: the MEAL_LIBRARY data
// itself plus every helper that reads it (filter bands, curated shelves,
// meal lookup). kitchen-library-enriched.json and the old habit of treating
// the JSON dump as a separate artifact are retired — this file is now the
// one source of truth the app loads, and the one file to hand-edit
// cook_steps into. Originally rebuilt from themealdb_full.json (733
// recipes) via the enrichment pass described in kitchen-overhaul-prompt.md
// §0/§1 (enrich_library.py + nutrition_table.py + match_ingredient.py +
// parse_measure.py, run offline, not in the app). kcal/protein_g/carbs_g/
// fat_g/portions/prep_minutes are calculated per-recipe from the actual
// ingredient list + measures against a nutrition table — NOT guessed live
// per-card. See enrichment-qa-report.md for match-confidence stats and the
// handful of recipes worth a manual spot-check (macro_confidence field on
// each meal reflects this per-recipe).
//
// Shape per meal (matches kitchen-overhaul-prompt.md §1):
// { id, name, image, local_image, category, area, diet_tag, prep_minutes,
//   prep_minutes_source, portions, kcal, protein_g, carbs_g, fat_g,
//   macro_confidence, ingredients:[{ingredient,measure}], instructions,
//   equipment_tags:[], is_new, video, cook_steps:[...] }
//
// video — YouTube URL for the recipe, sourced from TheMealDB's own
// `youtube` field on the raw recipe (themealdb_full.json), matched in by
// id. 592/733 recipes have one; the rest are null (TheMealDB itself has no
// video for them, not a merge gap). kitchen.js's Cook Mode reads
// meal.video directly and just hides the video toggle when it is null.
//
// cook_steps — structured cook-mode steps, REPLACES live client-side
// instruction-splitting. Each recipe's raw `instructions` field is messy
// scraped text (often starting with a restated ingredient list, section
// headers like "TOPPING:"/"FILLING:", inconsistent sentence lengths) — the
// old runtime parser (_ckSplitSteps/_ckDeriveTitle in kitchen.js) guesses
// step boundaries and titles from that text live, which produces broken
// output like "Step 2 of 44: 12 CUPS CHOPPED MIXED" (an ingredient line
// mistaken for a step). cook_steps is pre-written instead, max 12 steps,
// each shaped:
//   { step: 1, label: "Bake the potatoes", instruction: "...",
//     timer_seconds: 2700 | null, background: true | false }
// - label: short title shown as the step heading (NOT derived from text
//   at runtime anymore).
// - timer_seconds: null if the step has no wait (e.g. "chop the onions"),
//   otherwise the countdown duration.
// - background: true means this step's timer can run unattended while
//   later steps are worked on (e.g. "put the roast in the oven" — steps
//   5/6/7 happen WHILE it bakes). kitchen.js promotes an unfinished
//   background timer into a small persistent bar instead of discarding it
//   when the user advances past that step — see ckAdvanceStep()/
//   ckSession.backgroundTimers there. background:false + a timer means the
//   step blocks progress until that timer finishes (e.g. a final
//   rest/thicken step where there is nothing else to do anyway).
//
// MIGRATION STATUS: 396/733 recipes have a hand-authored cook_steps array
// as of this file (ids 53079-53184 — Fish Soup through Spanish Rice &
// Prawn One-Pot — were added across the last three passes). Do not
// bulk-generate the remaining ~337 here — that is ongoing manual/authoring
// work happening across sessions. Every recipe WITHOUT cook_steps still
// falls back to the legacy live text-splitter in kitchen.js
// (_ckParseSteps). That fallback is unchanged — recipes without cook_steps
// will keep showing the old (occasionally rough) step breakdown until they
// are migrated.
//
// equipment_tags is populated (AirFryer/SlowCooker/Blender/FoodProcessor/
// Grill) via keyword-matching against each recipe's instructions in the
// enrichment pass — see enrich_library.py's equipment_tags_for(). Coverage
// is keyword-based, not exhaustive, so treat it as "recipe mentions this"
// rather than a guaranteed complete equipment list.
// is_new is currently always false — no "recently added" concept defined
// yet; ribbon logic is wired and ready whenever that is decided.

const MEAL_LIBRARY = [{"id": "52764", "name": "Garides Saganaki", "category": "Seafood", "area": "Greek", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/wuvryu1468232995.jpg", "local_image": "52764.jpg", "ingredients": [{"ingredient": "Raw king prawns", "measure": "500g"}, {"ingredient": "Olive oil", "measure": "3 tablespoons"}, {"ingredient": "Chopped onion", "measure": "1"}, {"ingredient": "Freshly chopped parsley", "measure": "pinch"}, {"ingredient": "White wine", "measure": "250ml"}, {"ingredient": "Chopped tomatoes", "measure": "1 (400g) tin"}, {"ingredient": "Minced garlic", "measure": "1/2 teaspoon"}, {"ingredient": "Cubed Feta cheese", "measure": "1 (200g) pack"}], "instructions": "Place the prawns in a pot and add enough water to cover. Boil for 5 minutes. Drain, reserving the liquid, and set aside.\r\nHeat 2 tablespoons of oil in a saucepan. Add the onion; cook and stir until soft. Mix in the parsley, wine, tomatoes, garlic and remaining olive oil. Simmer, stirring occasionally, for about 30 minutes, or until the sauce is thickened.\r\nWhile the sauce is simmering, the prawns should become cool enough to handle. First remove the legs by pinching them, and then pull off the shells, leaving the head and tail on.\r\nWhen the sauce has thickened, stir in the prawns. Bring to a simmer again if the sauce has cooled with the prawns, and cook for about 5 minutes. Add the feta and remove from the heat. Let stand until the cheese starts to melt. Serve warm with slices of crusty bread.\r\nThough completely untraditional, you can add a few tablespoons of stock or passata to this recipe to make a delicious pasta sauce. Toss with pasta after adding the feta, and serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 605, "protein_g": 51.1, "carbs_g": 12.7, "fat_g": 33.6, "total_kcal": 1816, "total_protein_g": 153.2, "total_carbs_g": 38.2, "total_fat_g": 100.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil and shell the prawns", "instruction": "Cover the prawns with water in a pot and boil for 5 minutes. Drain, reserving the liquid, and set aside to cool.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Build the tomato sauce", "instruction": "Heat 2 tablespoons of oil in a saucepan, add the onion and cook until soft. Stir in the parsley, wine, tomatoes, garlic and remaining oil. Simmer, stirring occasionally, until thickened.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Peel the prawns", "instruction": "While the sauce simmers, pinch off the legs and pull off the shells, leaving the head and tail on.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Finish and serve", "instruction": "Stir the prawns into the thickened sauce and simmer for about 5 minutes. Add the feta, remove from heat, and let stand until it starts to melt. Serve warm with crusty bread.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=uO0ejc85zSE"}, {"id": "52765", "name": "Chicken Enchilada Casserole", "category": "Chicken", "area": "Mexican", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qtuwxu1468233098.jpg", "local_image": "52765.jpg", "ingredients": [{"ingredient": "Enchilada sauce", "measure": "14 oz jar"}, {"ingredient": "shredded Monterey Jack cheese", "measure": "3 Cups"}, {"ingredient": "corn tortillas", "measure": "6"}, {"ingredient": "chicken breasts", "measure": "2"}], "instructions": "Cut each chicken breast in about 3 pieces, so that it cooks faster and put it in a small pot. Pour Enchilada sauce over it and cook covered on low to medium heat until chicken is cooked through, about 20 minutes. No water is needed, the chicken will cook in the Enchilada sauce. Make sure you stir occasionally so that it doesn't stick to the bottom.\r\nRemove chicken from the pot and shred with two forks.\r\nPreheat oven to 375 F degrees.\r\nStart layering the casserole. Start with about ¼ cup of the leftover Enchilada sauce over the bottom of a baking dish. I used a longer baking dish, so that I can put 2 corn tortillas across. Place 2 tortillas on the bottom, top with ⅓ of the chicken and ⅓ of the remaining sauce. Sprinkle with ⅓ of the cheese and repeat starting with 2 more tortillas, then chicken, sauce, cheese. Repeat with last layer with the remaining ingredients, tortillas, chicken, sauce and cheese.\r\nBake for 20 to 30 minutes uncovered, until bubbly and cheese has melted and started to brown on top.\r\nServe warm.", "equipment_tags": [], "portions": 3, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 1286, "protein_g": 87.1, "carbs_g": 54.7, "fat_g": 79.5, "total_kcal": 3858, "total_protein_g": 261.4, "total_carbs_g": 164.1, "total_fat_g": 238.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Poach the chicken in sauce", "instruction": "Cut each chicken breast into about 3 pieces and place in a small pot. Pour the enchilada sauce over it and cook covered on low-medium heat, stirring occasionally, until cooked through.", "timer_seconds": 1200, "background": false}, {"step": 2, "label": "Shred the chicken", "instruction": "Remove the chicken from the pot and shred with two forks.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Preheat the oven", "instruction": "Preheat the oven to 375°F (190°C).", "timer_seconds": null, "background": false}, {"step": 4, "label": "Layer the casserole", "instruction": "Spread a little leftover sauce in the bottom of a baking dish. Layer 2 tortillas, a third of the chicken, sauce and cheese; repeat twice more, finishing with tortillas, chicken, sauce and cheese.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Bake uncovered until bubbly and the cheese has melted and started to brown on top.", "timer_seconds": 1500, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=EtVkwVKLc_M"}, {"id": "52767", "name": "Bakewell tart", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wyrqqq1468233628.jpg", "local_image": "52767.jpg", "ingredients": [{"ingredient": "plain flour", "measure": "175g/6oz"}, {"ingredient": "chilled butter", "measure": "75g/2½oz"}, {"ingredient": "cold water", "measure": "2-3 tbsp"}, {"ingredient": "raspberry jam", "measure": "1 tbsp"}, {"ingredient": "butter", "measure": "125g/4½oz"}, {"ingredient": "caster sugar", "measure": "125g/4½oz"}, {"ingredient": "ground almonds", "measure": "125g/4½oz"}, {"ingredient": "free-range egg, beaten", "measure": "1"}, {"ingredient": "almond extract", "measure": "½ tsp"}, {"ingredient": "flaked almonds", "measure": "50g/1¾oz"}], "instructions": "To make the pastry, measure the flour into a bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs. Add the water, mixing to form a soft dough.\r\nRoll out the dough on a lightly floured work surface and use to line a 20cm/8in flan tin. Leave in the fridge to chill for 30 minutes.\r\nPreheat the oven to 200C/400F/Gas 6 (180C fan).\r\nLine the pastry case with foil and fill with baking beans. Bake blind for about 15 minutes, then remove the beans and foil and cook for a further five minutes to dry out the base.\r\nFor the filing, spread the base of the flan generously with raspberry jam.\r\nMelt the butter in a pan, take off the heat and then stir in the sugar. Add ground almonds, egg and almond extract. Pour into the flan tin and sprinkle over the flaked almonds.\r\nBake for about 35 minutes. If the almonds seem to be browning too quickly, cover the tart loosely with foil to prevent them burning.", "equipment_tags": [], "portions": 6, "prep_minutes": 80, "prep_minutes_source": "explicit", "kcal": 615, "protein_g": 10.4, "carbs_g": 51.3, "fat_g": 42.7, "total_kcal": 3688, "total_protein_g": 62.6, "total_carbs_g": 307.8, "total_fat_g": 256.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the pastry", "instruction": "Rub the butter into the flour until it resembles fine breadcrumbs, then mix in the water to form a soft dough.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Line the tin and chill", "instruction": "Roll out the dough and use it to line a 20cm flan tin. Chill in the fridge.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Preheat the oven", "instruction": "While the pastry chills, preheat the oven to 200°C/400°F/Gas 6 (180°C fan).", "timer_seconds": null, "background": false}, {"step": 4, "label": "Blind bake the case", "instruction": "Line the pastry with foil and baking beans and bake blind, then remove the beans and foil and bake a little longer to dry out the base.", "timer_seconds": 1200, "background": true}, {"step": 5, "label": "Add the jam", "instruction": "Spread the base of the flan generously with raspberry jam.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Make the frangipane filling", "instruction": "Melt the butter, take off the heat, then stir in the sugar, ground almonds, egg and almond extract. Pour into the flan tin and sprinkle with the flaked almonds.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Bake the tart", "instruction": "Bake until golden, covering loosely with foil if the almonds start browning too quickly.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=1ahpSTf_Pvk"}, {"id": "52768", "name": "Apple Frangipan Tart", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wxywrq1468235067.jpg", "local_image": "52768.jpg", "ingredients": [{"ingredient": "digestive biscuits", "measure": "175g/6oz"}, {"ingredient": "butter", "measure": "75g/3oz"}, {"ingredient": "Bramley apples", "measure": "200g/7oz"}, {"ingredient": "Salted Butter", "measure": "75g/3oz"}, {"ingredient": "caster sugar", "measure": "75g/3oz"}, {"ingredient": "free-range eggs, beaten", "measure": "2"}, {"ingredient": "ground almonds", "measure": "75g/3oz"}, {"ingredient": "almond extract", "measure": "1 tsp"}, {"ingredient": "flaked almonds", "measure": "50g/1¾oz"}], "instructions": "Preheat the oven to 200C/180C Fan/Gas 6.\r\nPut the biscuits in a large re-sealable freezer bag and bash with a rolling pin into fine crumbs. Melt the butter in a small pan, then add the biscuit crumbs and stir until coated with butter. Tip into the tart tin and, using the back of a spoon, press over the base and sides of the tin to give an even layer. Chill in the fridge while you make the filling.\r\nCream together the butter and sugar until light and fluffy. You can do this in a food processor if you have one. Process for 2-3 minutes. Mix in the eggs, then add the ground almonds and almond extract and blend until well combined.\r\nPeel the apples, and cut thin slices of apple. Do this at the last minute to prevent the apple going brown. Arrange the slices over the biscuit base. Spread the frangipane filling evenly on top. Level the surface and sprinkle with the flaked almonds.\r\nBake for 20-25 minutes until golden-brown and set.\r\nRemove from the oven and leave to cool for 15 minutes. Remove the sides of the tin. An easy way to do this is to stand the tin on a can of beans and push down gently on the edges of the tin.\r\nTransfer the tart, with the tin base attached, to a serving plate. Serve warm with cream, crème fraiche or ice cream.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 6, "prep_minutes": 43, "prep_minutes_source": "explicit", "kcal": 529, "protein_g": 8.8, "carbs_g": 41.9, "fat_g": 38.5, "total_kcal": 3175, "total_protein_g": 52.6, "total_carbs_g": 251.2, "total_fat_g": 231.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat the oven", "instruction": "Preheat the oven to 200°C/180°C fan/Gas 6.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the biscuit base", "instruction": "Crush the digestive biscuits into fine crumbs. Melt the butter, stir in the crumbs, then press into the tart tin base and sides. Chill while you make the filling.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the frangipane filling", "instruction": "Cream the butter and sugar until light and fluffy, then mix in the eggs, ground almonds and almond extract until well combined.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Assemble the tart", "instruction": "Peel and thinly slice the apples and arrange over the biscuit base. Spread the frangipane filling on top, level, and sprinkle with flaked almonds.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Bake until golden-brown and set.", "timer_seconds": 1500, "background": true}, {"step": 6, "label": "Cool and unmould", "instruction": "Remove from the oven and leave to cool before removing the sides of the tin, then transfer to a serving plate.", "timer_seconds": 900, "background": true}], "video": "https://www.youtube.com/watch?v=rp8Slv4INLk"}, {"id": "52769", "name": "Kapsalon", "category": "Lamb", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sxysrt1468240488.jpg", "local_image": "52769.jpg", "ingredients": [{"ingredient": "Fries", "measure": "250 Grams"}, {"ingredient": "Doner Meat", "measure": "500 Grams"}, {"ingredient": "Garlic sauce", "measure": "Topping"}, {"ingredient": "Hotsauce", "measure": "Topping"}, {"ingredient": "Lettuce", "measure": "1 Bulb"}, {"ingredient": "Tomato", "measure": "1"}, {"ingredient": "Cucumber", "measure": "3rd"}, {"ingredient": "Gouda cheese", "measure": "100 Grams"}], "instructions": "Cut the meat into strips. Heat oil in a pan and fry the strips for 6 minutes until it's ready.\r\nBake the fries until golden brown in a deep fryrer. When ready transfer to a backing dish. Make sure the fries are spread over the whole dish.\r\nCover the fries with a new layer of meat and spread evenly.\r\nAdd a layer of cheese over the meat. You can also use grated cheese. When done put in the oven for a few minutes until the cheese is melted.\r\nChop the lettuce, tomato and cucumber in small pieces and mix together. for a basic salad. As extra you can add olives jalapenos and a red union.\r\nDived the salad over the dish and Serve with garlicsauce and hot sauce", "equipment_tags": [], "portions": 2, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 1191, "protein_g": 63.7, "carbs_g": 70.2, "fat_g": 74.4, "total_kcal": 2381, "total_protein_g": 127.3, "total_carbs_g": 140.4, "total_fat_g": 148.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Fry the doner meat", "instruction": "Cut the meat into strips. Heat oil in a pan and fry the strips until ready.", "timer_seconds": 360, "background": false}, {"step": 2, "label": "Fry the chips", "instruction": "Meanwhile, deep-fry the fries until golden brown, then transfer to a baking dish, spreading them over the whole dish.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Layer meat and cheese", "instruction": "Cover the fries with the fried meat, then top with a layer of cheese.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Melt the cheese", "instruction": "Put the dish in the oven for a few minutes until the cheese is melted.", "timer_seconds": 300, "background": true}, {"step": 5, "label": "Make the salad", "instruction": "While the cheese melts, chop the lettuce, tomato and cucumber into small pieces and mix together for a basic salad.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Finish and serve", "instruction": "Divide the salad over the dish and serve with garlic sauce and hot sauce.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=UIcuiU1kV8I"}, {"id": "52770", "name": "Spaghetti Bolognese", "category": "Beef", "area": "Italian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/sutysw1468247559.jpg", "local_image": "52770.jpg", "ingredients": [{"ingredient": "onions", "measure": "2"}, {"ingredient": "olive oil", "measure": "1tbsp"}, {"ingredient": "garlic", "measure": "1 clove"}, {"ingredient": "lean minced beef", "measure": "500g"}, {"ingredient": "mushrooms", "measure": "90g"}, {"ingredient": "dried oregano", "measure": "1tsp"}, {"ingredient": "tomatoes", "measure": "400g can"}, {"ingredient": "hot beef stock", "measure": "300ml"}, {"ingredient": "tomato puree", "measure": "1tbsp"}, {"ingredient": "worcestershire sauce", "measure": "1tbsp"}, {"ingredient": "spaghetti", "measure": "350g"}, {"ingredient": "parmesan", "measure": "Topping"}], "instructions": "Put the onion and oil in a large pan and fry over a fairly high heat for 3-4 mins. Add the garlic and mince and fry until they both brown. Add the mushrooms and herbs, and cook for another couple of mins.\r\n\r\nStir in the tomatoes, beef stock, tomato ketchup or purée, Worcestershire sauce and seasoning. Bring to the boil, then reduce the heat, cover and simmer, stirring occasionally, for 30 mins.\r\n\r\nMeanwhile, cook the spaghetti in a large pan of boiling, salted water, according to packet instructions. Drain well, run hot water through it, put it back in the pan and add a dash of olive oil, if you like, then stir in the meat sauce. Serve in hot bowls and hand round Parmesan cheese, for sprinkling on top.", "equipment_tags": [], "portions": 12, "prep_minutes": 34, "prep_minutes_source": "explicit", "kcal": 255, "protein_g": 12.8, "carbs_g": 26.3, "fat_g": 10.8, "total_kcal": 3056, "total_protein_g": 153.5, "total_carbs_g": 315.1, "total_fat_g": 129.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the mince", "instruction": "Fry the onion in oil over fairly high heat, then add the garlic and mince and fry until both brown. Add the mushrooms and oregano and cook for a couple more minutes.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Simmer the sauce", "instruction": "Stir in the tomatoes, beef stock, tomato purée, Worcestershire sauce and seasoning. Bring to the boil, then reduce heat, cover and simmer, stirring occasionally.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Cook the spaghetti", "instruction": "While the sauce simmers, cook the spaghetti in a large pan of boiling salted water according to packet instructions, then drain.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Toss the spaghetti with a dash of olive oil, stir in the meat sauce, and serve in hot bowls with Parmesan for sprinkling.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=-gF8d-fitkU"}, {"id": "52771", "name": "Spicy Arrabiata Penne", "category": "Vegetarian", "area": "Italian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ustsqw1468250014.jpg", "local_image": "52771.jpg", "ingredients": [{"ingredient": "penne rigate", "measure": "1 pound"}, {"ingredient": "olive oil", "measure": "1/4 cup"}, {"ingredient": "garlic", "measure": "3 cloves"}, {"ingredient": "chopped tomatoes", "measure": "1 tin"}, {"ingredient": "red chilli flakes", "measure": "1/2 teaspoon"}, {"ingredient": "italian seasoning", "measure": "1/2 teaspoon"}, {"ingredient": "basil", "measure": "6 leaves"}, {"ingredient": "Parmigiano-Reggiano", "measure": "sprinkling"}], "instructions": "Bring a large pot of water to a boil. Add kosher salt to the boiling water, then add the pasta. Cook according to the package instructions, about 9 minutes.\r\nIn a large skillet over medium-high heat, add the olive oil and heat until the oil starts to shimmer. Add the garlic and cook, stirring, until fragrant, 1 to 2 minutes. Add the chopped tomatoes, red chile flakes, Italian seasoning and salt and pepper to taste. Bring to a boil and cook for 5 minutes. Remove from the heat and add the chopped basil.\r\nDrain the pasta and add it to the sauce. Garnish with Parmigiano-Reggiano flakes and more basil and serve warm.", "equipment_tags": [], "portions": 6, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 399, "protein_g": 12.5, "carbs_g": 60.2, "fat_g": 12.0, "total_kcal": 2393, "total_protein_g": 74.9, "total_carbs_g": 361.4, "total_fat_g": 71.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the penne", "instruction": "Bring a large pot of salted water to the boil and cook the pasta according to the package instructions.", "timer_seconds": 540, "background": false}, {"step": 2, "label": "Make the arrabiata sauce", "instruction": "While the pasta cooks, heat the olive oil in a large skillet, add the garlic and cook until fragrant. Add the chopped tomatoes, chilli flakes, Italian seasoning, salt and pepper. Bring to a boil and cook until slightly reduced, then stir in the basil.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Combine and serve", "instruction": "Drain the pasta and toss it into the sauce. Garnish with Parmigiano-Reggiano and more basil, then serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=1IszT_guI08"}, {"id": "52772", "name": "Teriyaki Chicken Casserole", "category": "Chicken", "area": "Japanese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/wvpsxx1468256321.jpg", "local_image": "52772.jpg", "ingredients": [{"ingredient": "soy sauce", "measure": "3/4 cup"}, {"ingredient": "water", "measure": "1/2 cup"}, {"ingredient": "brown sugar", "measure": "1/4 cup"}, {"ingredient": "ground ginger", "measure": "1/2 teaspoon"}, {"ingredient": "minced garlic", "measure": "1/2 teaspoon"}, {"ingredient": "cornstarch", "measure": "4 Tablespoons"}, {"ingredient": "chicken breasts", "measure": "2"}, {"ingredient": "stir-fry vegetables", "measure": "1 (12 oz.)"}, {"ingredient": "brown rice", "measure": "3 cups"}], "instructions": "Preheat oven to 350° F. Spray a 9x13-inch baking pan with non-stick spray.\r\nCombine soy sauce, ½ cup water, brown sugar, ginger and garlic in a small saucepan and cover. Bring to a boil over medium heat. Remove lid and cook for one minute once boiling.\r\nMeanwhile, stir together the corn starch and 2 tablespoons of water in a separate dish until smooth. Once sauce is boiling, add mixture to the saucepan and stir to combine. Cook until the sauce starts to thicken then remove from heat.\r\nPlace the chicken breasts in the prepared pan. Pour one cup of the sauce over top of chicken. Place chicken in oven and bake 35 minutes or until cooked through. Remove from oven and shred chicken in the dish using two forks.\r\n*Meanwhile, steam or cook the vegetables according to package directions.\r\nAdd the cooked vegetables and rice to the casserole dish with the chicken. Add most of the remaining sauce, reserving a bit to drizzle over the top when serving. Gently toss everything together in the casserole dish until combined. Return to oven and cook 15 minutes. Remove from oven and let stand 5 minutes before serving. Drizzle each serving with remaining sauce. Enjoy!", "equipment_tags": [], "portions": 3, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 1075, "protein_g": 44.0, "carbs_g": 207.5, "fat_g": 4.8, "total_kcal": 3226, "total_protein_g": 132.0, "total_carbs_g": 622.6, "total_fat_g": 14.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep the pan", "instruction": "Preheat the oven to 350°F and spray a 9x13-inch baking pan with non-stick spray.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the teriyaki sauce", "instruction": "Combine the soy sauce, water, brown sugar, ginger and garlic in a small saucepan, cover and bring to a boil, then uncover and cook for one minute.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Thicken the sauce", "instruction": "Whisk the cornstarch with 2 tablespoons of water until smooth, add to the boiling sauce, and stir until it thickens, then remove from heat.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake the chicken", "instruction": "Place the chicken breasts in the prepared pan, pour a cup of the sauce over the top, and bake until cooked through, then shred with two forks in the dish.", "timer_seconds": 2100, "background": true}, {"step": 5, "label": "Steam the vegetables", "instruction": "While the chicken bakes, steam or cook the stir-fry vegetables according to package directions.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Combine and finish baking", "instruction": "Add the cooked vegetables, rice and most of the remaining sauce to the casserole dish, toss together, and return to the oven.", "timer_seconds": 900, "background": true}, {"step": 7, "label": "Rest and serve", "instruction": "Let stand for 5 minutes, then drizzle each serving with the reserved sauce.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=4aZr5hZXP_s"}, {"id": "52773", "name": "Honey Teriyaki Salmon", "category": "Seafood", "area": "Japanese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/xxyupu1468262513.jpg", "local_image": "52773.jpg", "ingredients": [{"ingredient": "Salmon", "measure": "1 lb"}, {"ingredient": "Olive oil", "measure": "1 tablespoon"}, {"ingredient": "Soy Sauce", "measure": "2 tablespoons"}, {"ingredient": "Sake", "measure": "2 tablespoons"}, {"ingredient": "Sesame Seed", "measure": "4 tablespoons"}], "instructions": "Mix all the ingredients in the Honey Teriyaki Glaze together. Whisk to blend well. Combine the salmon and the Glaze together.\r\n\r\nHeat up a skillet on medium-low heat. Add the oil, Pan-fry the salmon on both sides until it’s completely cooked inside and the glaze thickens.\r\n\r\nGarnish with sesame and serve immediately.", "equipment_tags": [], "portions": 1, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 1465, "protein_g": 104.0, "carbs_g": 16.8, "fat_g": 102.9, "total_kcal": 1465, "total_protein_g": 104.0, "total_carbs_g": 16.8, "total_fat_g": 102.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the glaze and marinate", "instruction": "Whisk together the soy sauce, sake, honey and sesame seed to make the honey teriyaki glaze, then combine it with the salmon.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Pan-fry the salmon", "instruction": "Heat a skillet over medium-low heat, add the oil, and pan-fry the salmon on both sides until cooked through and the glaze has thickened.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Serve", "instruction": "Garnish with sesame and serve immediately.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=4MpYuaJsvRw"}, {"id": "52774", "name": "Pad See Ew", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/uuuspp1468263334.jpg", "local_image": "52774.jpg", "ingredients": [{"ingredient": "rice stick noodles", "measure": "6oz/180g"}, {"ingredient": "dark soy sauce", "measure": "2 tbsp"}, {"ingredient": "oyster sauce", "measure": "2 tbsp"}, {"ingredient": "soy sauce", "measure": "2 tsp"}, {"ingredient": "white vinegar", "measure": "2 tsp"}, {"ingredient": "sugar", "measure": "2 tsp"}, {"ingredient": "water", "measure": "2 tbsp"}, {"ingredient": "peanut oil", "measure": "2 tbsp"}, {"ingredient": "garlic", "measure": "2 cloves"}, {"ingredient": "Chicken", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Chinese broccoli", "measure": "4 cups"}], "instructions": "Mix Sauce in small bowl.\r\nMince garlic into wok with oil. Place over high heat, when hot, add chicken and Chinese broccoli stems, cook until chicken is light golden.\r\nPush to the side of the wok, crack egg in and scramble. Don't worry if it sticks to the bottom of the wok - it will char and which adds authentic flavour.\r\nAdd noodles, Chinese broccoli leaves and sauce. Gently mix together until the noodles are stained dark and leaves are wilted. Serve immediately!", "equipment_tags": [], "portions": 3, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 443, "protein_g": 32.0, "carbs_g": 42.8, "fat_g": 18.7, "total_kcal": 1330, "total_protein_g": 95.9, "total_carbs_g": 128.5, "total_fat_g": 56.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix the sauce", "instruction": "Combine the dark soy sauce, oyster sauce, soy sauce, vinegar, sugar and water in a small bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the chicken", "instruction": "Mince the garlic into a wok with oil over high heat. When hot, add the chicken and Chinese broccoli stems, and cook until the chicken is light golden.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Scramble the egg", "instruction": "Push everything to the side of the wok, crack in the egg and scramble, letting it char a little on the bottom for flavour.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Add the noodles, Chinese broccoli leaves and sauce, and gently mix until the noodles are stained dark and the leaves are wilted. Serve immediately.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Ohy1DELF4is"}, {"id": "52775", "name": "Vegan Lasagna", "category": "Vegan", "area": "Italian", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/rvxxuy1468312893.jpg", "local_image": "52775.jpg", "ingredients": [{"ingredient": "green red lentils", "measure": "1 cups"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "onion", "measure": "1"}, {"ingredient": "zucchini", "measure": "1 small"}, {"ingredient": "coriander", "measure": "sprinking"}, {"ingredient": "spinach", "measure": "150g"}, {"ingredient": "lasagne sheets", "measure": "10"}, {"ingredient": "vegan butter", "measure": "35g"}, {"ingredient": "flour", "measure": "4 tablespoons"}, {"ingredient": "soya milk", "measure": "300ml"}, {"ingredient": "mustard", "measure": "1.5 teaspoons"}, {"ingredient": "vinegar", "measure": "1 teaspoon"}], "instructions": "1) Preheat oven to 180 degrees celcius. \r\n2) Boil vegetables for 5-7 minutes, until soft. Add lentils and bring to a gentle simmer, adding a stock cube if desired. Continue cooking and stirring until the lentils are soft, which should take about 20 minutes. \r\n3) Blanch spinach leaves for a few minutes in a pan, before removing and setting aside. \r\n4) Top up the pan with water and cook the lasagne sheets. When cooked, drain and set aside.\r\n5) To make the sauce, melt the butter and add the flour, then gradually add the soya milk along with the mustard and the vinegar. Cook and stir until smooth and then assemble the lasagne as desired in a baking dish. \r\n6) Bake in the preheated oven for about 25 minutes.", "equipment_tags": [], "portions": 2, "prep_minutes": 52, "prep_minutes_source": "explicit", "kcal": 527, "protein_g": 24.6, "carbs_g": 68.4, "fat_g": 18.6, "total_kcal": 1054, "total_protein_g": 49.2, "total_carbs_g": 136.8, "total_fat_g": 37.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat the oven", "instruction": "Preheat the oven to 180°C.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the vegetables and lentils", "instruction": "Boil the carrots, onion and zucchini until soft, then add the lentils and simmer gently, stirring, until the lentils are soft.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Blanch the spinach", "instruction": "While the lentils cook, blanch the spinach leaves in a pan for a few minutes, then remove and set aside.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Cook the lasagne sheets", "instruction": "Top up the pan with water and cook the lasagne sheets, then drain and set aside.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Make the sauce", "instruction": "Melt the butter, add the flour, then gradually whisk in the soya milk with the mustard and vinegar. Cook and stir until smooth.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Assemble and bake", "instruction": "Layer the lasagne sheets, lentil-vegetable mixture, spinach and sauce in a baking dish as desired, then bake in the preheated oven.", "timer_seconds": 1500, "background": true}], "video": "https://www.youtube.com/watch?v=VU8cXvlGbvc"}, {"id": "52776", "name": "Chocolate Gateau", "category": "Dessert", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tqtywx1468317395.jpg", "local_image": "52776.jpg", "ingredients": [{"ingredient": "Plain chocolate", "measure": "250g"}, {"ingredient": "Butter", "measure": "175g"}, {"ingredient": "Milk", "measure": "2 tablespoons"}, {"ingredient": "Eggs", "measure": "5"}, {"ingredient": "Granulated Sugar", "measure": "175g"}, {"ingredient": "Flour", "measure": "125g"}], "instructions": "Preheat the oven to 180°C/350°F/Gas Mark 4. Grease and line the base of an 8 in round spring form cake tin with baking parchment\r\nBreak the chocolate into a heatproof bowl and place over a saucepan of gently simmering water and stir until it melts. (or melt in the microwave for 2-3 mins stirring occasionally)\r\nPlace the butter and sugar in a mixing bowl and cream together with a wooden spoon until light and fluffy. Gradually beat in the eggs, adding a little flour if the mixture begins to curdle. Fold in the remaining flour with the cooled, melted chocolate and milk. Mix until smooth.\r\nSpread the mixture into the cake tin and bake for 50-55 mins or until firm in the centre and a skewer comes out cleanly. Cool for 10 minutes, then turn out and cool completely.", "equipment_tags": [], "portions": 7, "prep_minutes": 68, "prep_minutes_source": "explicit", "kcal": 590, "protein_g": 9.6, "carbs_g": 61.0, "fat_g": 35.2, "total_kcal": 4128, "total_protein_g": 67.0, "total_carbs_g": 426.9, "total_fat_g": 246.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat the oven and prep the tin", "instruction": "Preheat the oven to 180°C/350°F/Gas Mark 4. Grease and line the base of an 8in round springform tin with baking parchment.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Melt the chocolate", "instruction": "Break the chocolate into a heatproof bowl and melt over a pan of gently simmering water, or in the microwave, stirring occasionally.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the batter", "instruction": "Cream the butter and sugar together until light and fluffy. Gradually beat in the eggs, adding a little flour if it curdles, then fold in the remaining flour with the melted chocolate and milk until smooth.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake the cake", "instruction": "Spread the mixture into the tin and bake until firm in the centre and a skewer comes out clean.", "timer_seconds": 3150, "background": true}, {"step": 5, "label": "Cool and turn out", "instruction": "Cool in the tin for 10 minutes, then turn out and cool completely.", "timer_seconds": 600, "background": true}], "video": "https://www.youtube.com/watch?v=dsJtgmAhFF4"}, {"id": "52777", "name": "Mediterranean Pasta Salad", "category": "Seafood", "area": "Italian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/wvqpwt1468339226.jpg", "local_image": "52777.jpg", "ingredients": [{"ingredient": "mozzarella balls", "measure": "200 g"}, {"ingredient": "baby plum tomatoes", "measure": "250 g"}, {"ingredient": "fresh basil", "measure": "1  bunch"}, {"ingredient": "farfalle", "measure": "350 g"}, {"ingredient": "extra virgin olive oil", "measure": "3  tablespoons"}, {"ingredient": "Green Olives", "measure": "40 g"}, {"ingredient": "tuna", "measure": "200 g"}, {"ingredient": "salt", "measure": "to taste"}, {"ingredient": "pepper", "measure": "to taste"}], "instructions": "Bring a large saucepan of salted water to the boil\r\nAdd the pasta, stir once and cook for about 10 minutes or as directed on the packet.\r\nMeanwhile, wash the tomatoes and cut into quarters. Slice the olives. Wash the basil.\r\nPut the tomatoes into a salad bowl and tear the basil leaves over them. Add a tablespoon of olive oil and mix.\r\nWhen the pasta is ready, drain into a colander and run cold water over it to cool it quickly.\r\nToss the pasta into the salad bowl with the tomatoes and basil.\r\nAdd the sliced olives, drained mozzarella balls, and chunks of tuna. Mix well and let the salad rest for at least half an hour to allow the flavours to mingle.\r\nSprinkle the pasta with a generous grind of black pepper and drizzle with the remaining olive oil just before serving.", "equipment_tags": [], "portions": 9, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 292, "protein_g": 16.8, "carbs_g": 31.3, "fat_g": 10.8, "total_kcal": 2625, "total_protein_g": 151.2, "total_carbs_g": 281.4, "total_fat_g": 97.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the pasta", "instruction": "Bring a large saucepan of salted water to the boil, add the pasta, stir once, and cook according to packet instructions.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Prep the salad base", "instruction": "While the pasta cooks, wash and quarter the tomatoes, slice the olives, and wash the basil. Put the tomatoes in a salad bowl, tear the basil over them, and mix with a tablespoon of olive oil.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cool the pasta", "instruction": "When the pasta is ready, drain in a colander and run cold water over it to cool quickly.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Combine and rest", "instruction": "Toss the pasta into the salad bowl with the tomatoes and basil, then add the olives, mozzarella balls and tuna. Mix well and let rest to allow the flavours to mingle.", "timer_seconds": 1800, "background": true}, {"step": 5, "label": "Finish and serve", "instruction": "Sprinkle with black pepper and drizzle with the remaining olive oil just before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=e52IL8zYmaE"}, {"id": "52779", "name": "Cream Cheese Tart", "category": "Starter", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wurrux1468416624.jpg", "local_image": "52779.jpg", "ingredients": [{"ingredient": "Flour", "measure": "250g"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Cheese", "measure": "300g"}, {"ingredient": "Milk", "measure": "100ml milk"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Parmesan Cheese", "measure": "100g"}, {"ingredient": "Plum tomatoes", "measure": "350g"}, {"ingredient": "White Vinegar", "measure": "3tbsp"}, {"ingredient": "Honey", "measure": "1 tbsp"}, {"ingredient": "Basil", "measure": "Topping"}], "instructions": "Crust: make a dough from 250g flour (I like mixing different flours like plain and wholegrain spelt flour), 125g butter, 1 egg and a pinch of salt, press it into a tart form and place it in the fridge. Filling: stir 300g cream cheese and 100ml milk until smooth, add in 3 eggs, 100g grated parmesan cheese and season with salt, pepper and nutmeg. Take the crust out of the fridge and prick the bottom with a fork. Pour in the filling and bake at 175 degrees C for about 25 minutes. Cover the tart with some aluminium foil after half the time. In the mean time, slice about 350g mini tomatoes. In a small pan heat 3tbsp olive oil, 3tbsp white vinegar, 1 tbsp honey, salt and pepper and combine well. Pour over the tomato slices and mix well. With a spoon, place the tomato slices on the tart, avoiding too much liquid on it. Decorate with basil leaves and enjoy", "equipment_tags": [], "portions": 10, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 378, "protein_g": 16.9, "carbs_g": 23.9, "fat_g": 24.1, "total_kcal": 3777, "total_protein_g": 169.5, "total_carbs_g": 239.3, "total_fat_g": 240.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the crust and chill", "instruction": "Mix the flour, butter, egg and a pinch of salt into a dough, press it into a tart form, and place in the fridge.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Make the filling", "instruction": "While the crust chills, stir the cream cheese and milk until smooth, then mix in the eggs and grated Parmesan, and season with salt, pepper and nutmeg.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fill and bake", "instruction": "Prick the chilled crust with a fork, pour in the filling, and bake at 175°C, covering with foil after half the time.", "timer_seconds": 1500, "background": true}, {"step": 4, "label": "Make the tomato topping", "instruction": "While the tart bakes, slice the tomatoes. Heat olive oil, white vinegar and honey in a small pan with salt and pepper, combine well, then pour over the tomato slices and mix.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Finish and serve", "instruction": "Arrange the tomato slices on the tart, avoiding excess liquid, and decorate with basil leaves.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=UhQPwO4uymo"}, {"id": "52780", "name": "Potato Gratin with Chicken", "category": "Chicken", "area": "Italian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qwrtut1468418027.jpg", "local_image": "52780.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "800g"}, {"ingredient": "Onions", "measure": "3"}, {"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Chicken Stock", "measure": "100ml"}, {"ingredient": "Creme Fraiche", "measure": "1 pot"}, {"ingredient": "Parmesan", "measure": "Topping"}, {"ingredient": "Chicken Breasts", "measure": "4"}, {"ingredient": "Bacon", "measure": "4"}, {"ingredient": "Spinach", "measure": "Topping"}, {"ingredient": "Peas", "measure": "Topping"}], "instructions": "15 minute potato gratin with chicken and bacon greens: a gratin always seems more effort and more indulgent than ordinary boiled or roasts, but it doesn't have to take 45mins, it's nice for a change and you can control the calorie content by going with full fat to low fat creme fraiche. (It's always tastes better full fat though obviously!) to serve 4: use 800g of potatoes, finely slice and boil in a pan for about 5-8 mins till firmish, not soft. Finely slice 3 onions and place in an oven dish with 2 tblsp of olive oil and 100ml of chicken stock. Cook till the onions are soft then drain the potatoes and pour onto the onions. Season and spoon over cream or creme fraiche till all is covered but not swimming. Grate Parmesan over the top then finish under the grill till nicely golden. serve with chicken and bacon, peas and spinach.", "equipment_tags": ["Grill"], "portions": 4, "prep_minutes": 68, "prep_minutes_source": "explicit", "kcal": 776, "protein_g": 61.1, "carbs_g": 44.6, "fat_g": 38.1, "total_kcal": 3105, "total_protein_g": 244.2, "total_carbs_g": 178.4, "total_fat_g": 152.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Par-boil the potatoes", "instruction": "Finely slice the potatoes and boil in a pan until firmish, not soft.", "timer_seconds": 420, "background": false}, {"step": 2, "label": "Soften the onions", "instruction": "Finely slice the onions and place in an oven dish with the olive oil and chicken stock, cooking until soft.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Assemble the gratin", "instruction": "Drain the potatoes and pour onto the softened onions. Season and spoon over the crème fraîche until covered but not swimming, then grate Parmesan over the top.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Grill until golden", "instruction": "Finish the gratin under the grill until nicely golden.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve with the chicken and bacon, peas and spinach.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=p3u8eiy3yHI"}, {"id": "52781", "name": "Irish stew", "category": "Beef", "area": "Irish", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/sxxpst1468569714.jpg", "local_image": "52781.jpg", "ingredients": [{"ingredient": "whole wheat", "measure": "300g soaked overnight in water"}, {"ingredient": "lamb loin chops", "measure": "2kg cut into 3cm cubes"}, {"ingredient": "olive oil", "measure": "120ml"}, {"ingredient": "shallots", "measure": "24 Skinned"}, {"ingredient": "Carrots", "measure": "4 large"}, {"ingredient": "turnips", "measure": "2"}, {"ingredient": "celeriac", "measure": "1"}, {"ingredient": "charlotte potatoes", "measure": "350g"}, {"ingredient": "white wine", "measure": "150ml"}, {"ingredient": "caster sugar", "measure": "1 tsp"}, {"ingredient": "fresh thyme", "measure": "4 sprigs"}, {"ingredient": "oregano", "measure": "4 sprigs"}, {"ingredient": "chicken stock", "measure": "450ml"}], "instructions": "Heat the oven to 180C/350F/gas mark 4. Drain and rinse the soaked wheat, put it in a medium pan with lots of water, bring to a boil and simmer for an hour, until cooked. Drain and set aside.\r\n\r\nSeason the lamb with a teaspoon of salt and some black pepper. Put one tablespoon of oil in a large, deep sauté pan for which you have a lid; place on a medium-high heat. Add some of the lamb – don't overcrowd the pan – and sear for four minutes on all sides. Transfer to a bowl, and repeat with the remaining lamb, adding oil as needed.\r\n\r\nLower the heat to medium and add a tablespoon of oil to the pan. Add the shallots and fry for four minutes, until caramelised. Tip these into the lamb bowl, and repeat with the remaining vegetables until they are all nice and brown, adding more oil as you need it.\r\n\r\nOnce all the vegetables are seared and removed from the pan, add the wine along with the sugar, herbs, a teaspoon of salt and a good grind of black pepper. Boil on a high heat for about three minutes.\r\n\r\nTip the lamb, vegetables and whole wheat back into the pot, and add the stock. Cover and boil for five minutes, then transfer to the oven for an hour and a half.\r\n\r\nRemove the stew from the oven and check the liquid; if there is a lot, remove the lid and boil for a few minutes.", "equipment_tags": [], "portions": 10, "prep_minutes": 55, "prep_minutes_source": "estimated", "kcal": 935, "protein_g": 58.5, "carbs_g": 52.8, "fat_g": 54.1, "total_kcal": 9348, "total_protein_g": 585.5, "total_carbs_g": 527.8, "total_fat_g": 541.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat oven and cook the wheat", "instruction": "Heat the oven to 180°C/350°F/gas 4. Drain and rinse the soaked wheat, put it in a pan with plenty of water, bring to a boil and simmer until cooked, then drain and set aside.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Sear the lamb", "instruction": "While the wheat cooks, season the lamb with salt and pepper. Heat a tablespoon of oil in a large deep sauté pan and sear the lamb in batches on all sides, without overcrowding the pan, then transfer to a bowl.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Brown the vegetables", "instruction": "Lower the heat to medium, add another tablespoon of oil and fry the shallots until caramelised, then transfer to the lamb bowl. Repeat with the remaining vegetables, adding oil as needed, until all are nicely browned.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Deglaze the pan", "instruction": "Add the wine, sugar, herbs, salt and pepper to the pan and boil on high heat for about 3 minutes.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Braise in the oven", "instruction": "Tip the lamb, vegetables and cooked wheat back into the pot, add the stock, cover and boil for 5 minutes, then transfer to the oven.", "timer_seconds": 5400, "background": true}, {"step": 6, "label": "Finish", "instruction": "Remove the stew from the oven and check the liquid; if there's a lot, remove the lid and boil for a few minutes to reduce before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=kYH2qJXnSMo"}, {"id": "52782", "name": "Lamb tomato and sweet spices", "category": "Lamb", "area": "Moroccan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qtwtss1468572261.jpg", "local_image": "52782.jpg", "ingredients": [{"ingredient": "olive oil", "measure": "2 tbsp"}, {"ingredient": "ginger", "measure": "4cm piece finely chopped"}, {"ingredient": "garlic", "measure": "2 cloves peeled and chopped"}, {"ingredient": "tomatoes", "measure": "800g peeled and chopped"}, {"ingredient": "lemon juice", "measure": "2 tbsp"}, {"ingredient": "caster sugar", "measure": "1 tsp"}, {"ingredient": "vine leaves", "measure": "50"}, {"ingredient": "fennel bulb", "measure": "1 large"}, {"ingredient": "lamb mince", "measure": "400g"}, {"ingredient": "onion", "measure": "1 medium"}, {"ingredient": "potatoes", "measure": "1 small peeled and coarsely grated"}, {"ingredient": "basmati rice", "measure": "2 tbsp"}, {"ingredient": "chopped parsley", "measure": "2 tbsp"}, {"ingredient": "coriander", "measure": "2 tbsp chopped"}, {"ingredient": "lemon juice", "measure": "1 tbsp"}, {"ingredient": "garlic", "measure": "2 cloves"}, {"ingredient": "clove", "measure": "½ tsp ground"}, {"ingredient": "cinnamon", "measure": "½ tsp ground"}, {"ingredient": "tomatoes", "measure": "2 medium"}], "instructions": "Use pickled vine leaves here, preserved in brine. Small delicate leaves are better than the large bristly ones but, if only large leaves are to hand, then trim them to roughly 12 by 12 cms so that you don't get too many layers of leaves around the filling. And remove any stalks. Drain the preserved leaves, immerse them in boiling water for 10 minutes and then leave to dry on a tea towel before use. \r\nBasmati rice with butter and pine nuts is an ideal accompaniment. Couscous is great, too. Serves four.\r\nFirst make the filling. Put all the ingredients, apart from the tomatoes, in a bowl. Cut the tomatoes in half, coarsely grate into the bowl and discard the skins. Add half a teaspoon of salt and some black pepper, and stir. Leave on the side, or in the fridge, for up to a day. Before using, gently squeeze with your hands and drain away any juices that come out.\r\nTo make the sauce, heat the oil in a medium pan. Add the ginger and garlic, cook for a minute or two, taking care not to burn them, then add the tomato, lemon juice and sugar. Season, and simmer for 20 minutes.\r\nWhile the sauce is bubbling away, prepare the vine leaves. Use any torn or broken leaves to line the base of a wide, heavy saucepan. Trim any leaves from the fennel, cut it vertically into 0.5cm-thick slices and spread over the base of the pan to cover completely.\r\nLay a prepared vine leaf (see intro) on a work surface, veiny side up. Put two teaspoons of filling at the base of the leaf in a 2cm-long by 1cm-wide strip. Fold the sides of the leaf over the filling, then roll it tightly from bottom to top, in a cigar shape. Place in the pan, seam down, and repeat with the remaining leaves, placing them tightly next to each other in lines or circles (in two layers if necessary).\r\nPour the sauce over the leaves (and, if needed, add water just to cover). Place a plate on top, to weigh the leaves down, then cover with a lid. Bring to a boil, reduce the heat and cook on a bare simmer for 70 minutes. Most of the liquid should evaporate. Remove from the heat, and leave to cool a little - they are best served warm. When serving, bring to the table in the pan - it looks great. Serve a few vine leaves and fennel slices with warm rice. Spoon the braising juices on top and garnish with coriander.", "equipment_tags": [], "portions": 4, "prep_minutes": 100, "prep_minutes_source": "explicit", "kcal": 520, "protein_g": 24.8, "carbs_g": 39.4, "fat_g": 30.2, "total_kcal": 2078, "total_protein_g": 99.1, "total_carbs_g": 157.4, "total_fat_g": 120.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the vine leaves", "instruction": "Drain the preserved vine leaves, immerse them in boiling water for 10 minutes, then leave to dry on a tea towel.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Make the filling", "instruction": "Meanwhile, put all the filling ingredients except the tomatoes in a bowl. Coarsely grate the tomatoes into the bowl, discarding the skins, then season and stir. Leave to rest, then squeeze out and discard any excess juice before using.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the sauce", "instruction": "Heat the oil in a medium pan, add the ginger and garlic and cook for a minute or two without burning, then add the tomato, lemon juice and sugar. Season and simmer.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Line the pan with fennel", "instruction": "While the sauce simmers, line the base of a wide heavy saucepan with any torn vine leaves, then slice the fennel and spread it over the base.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Roll the vine leaves", "instruction": "Lay a leaf veiny side up, put 2 teaspoons of filling near the base, fold in the sides, then roll tightly into a cigar shape. Place seam-down in the pan and repeat with the remaining leaves.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Braise", "instruction": "Pour the sauce over the rolls, topping up with water to cover if needed. Weigh down with a plate, cover with a lid, bring to a boil, then reduce heat and simmer very gently until most of the liquid has evaporated.", "timer_seconds": 4200, "background": true}, {"step": 7, "label": "Rest and serve", "instruction": "Remove from the heat and leave to cool a little. Serve warm from the pan with rice, spooning the braising juices on top and garnishing with coriander.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=vaZb1MnFBgA"}, {"id": "52783", "name": "Rigatoni with fennel sausage sauce", "category": "Lamb", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qtqvys1468573168.jpg", "local_image": "52783.jpg", "ingredients": [{"ingredient": "olive oil", "measure": "2½ tbsp"}, {"ingredient": "Italian fennel sausages", "measure": "6 cut into 1.5cm-thick slices"}, {"ingredient": "onion", "measure": "1 large peeled and chopped"}, {"ingredient": "fennel bulb", "measure": "1 trimmed and roughly chopped; reserve any fronds to garnish"}, {"ingredient": "smoky paprika", "measure": "½ tsp"}, {"ingredient": "garlic", "measure": "1 clove, peeled and sliced"}, {"ingredient": "fennel seeds", "measure": "2 tsp lightly toasted and then gently crushed"}, {"ingredient": "red wine", "measure": "100ml"}, {"ingredient": "chopped tomatoes", "measure": "400g tinned"}, {"ingredient": "caster sugar", "measure": "½ tsp"}, {"ingredient": "pitted black olives", "measure": "50g cut in half lengthways"}, {"ingredient": "rigatoni", "measure": "500g"}, {"ingredient": "pecorino", "measure": "30g roughly crumbled into 0.5cm pieces"}, {"ingredient": "anchovy fillet", "measure": "1  rinsed and patted dry"}, {"ingredient": "garlic", "measure": "1 clove, peeled and crushed"}, {"ingredient": "olive oil", "measure": "60ml"}, {"ingredient": "basil leaves", "measure": "50g torn"}], "instructions": "Heat a tablespoon of oil in a large saute pan for which you have a lid. Add the sausage pieces and fry on a medium-high heat for 10 minutes, stirring regularly, until golden-brown all over. Transfer the sausages to a plate, then add the onion and fennel to the hot pan and fry for 15 minutes, stirring once in a while, until soft and caramelised; if the pan goes a bit dry, add a teaspoon or so of extra oil. Stir in the paprika, garlic and half the fennel seeds, fry for two minutes more, then pour on the wine and boil for 30 seconds, to reduce by half. Add the tomatoes, sugar, 100ml water, the seared sausage and half a teaspoon of salt, cover and simmer for 30 minutes; remove the lid after 10 minutes, and cook until the sauce is thick and rich. Remove from the heat, stir through the olives and remaining fennel seeds and set aside until you’re ready to serve.\r\n\r\nBring a large pot of salted water to a boil, add the pasta and cook for 12-14 minutes (or according to the instructions on the packet), until al dente. Meanwhile, reheat the sauce. Drain the pasta, return it to the pot, stir in a tablespoon of oil, then divide between the bowls. \r\n\r\nPut all the pesto ingredients except the basil in the small bowl of a food processor. Add a tablespoon of water and blitz to a rough paste. Add the basil, then blitz until just combined (the pesto has a much better texture if the basil is not overblended).\r\n\r\nSpoon over the ragù and top with a spoonful of pesto. Finish with a sprinkling of chopped fennel fronds, if you have any, and serve at once.", "equipment_tags": ["FoodProcessor"], "portions": 4, "prep_minutes": 79, "prep_minutes_source": "explicit", "kcal": 1226, "protein_g": 41.3, "carbs_g": 108.0, "fat_g": 68.3, "total_kcal": 4904, "total_protein_g": 165.1, "total_carbs_g": 432.2, "total_fat_g": 273.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the sausage", "instruction": "Heat a tablespoon of oil in a large sauté pan with a lid. Add the sausage pieces and fry on medium-high heat, stirring regularly, until golden-brown all over, then transfer to a plate.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Soften the onion and fennel", "instruction": "Add the onion and fennel to the hot pan and fry, stirring occasionally, until soft and caramelised, adding a little extra oil if the pan goes dry.", "timer_seconds": 900, "background": false}, {"step": 3, "label": "Build the ragù", "instruction": "Stir in the paprika, garlic and half the fennel seeds and fry for 2 minutes, then pour in the wine and boil for 30 seconds to reduce by half. Add the tomatoes, sugar, water, the seared sausage and salt, cover and simmer, removing the lid after 10 minutes and cooking until thick and rich.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Finish the ragù", "instruction": "Remove from the heat and stir through the olives and remaining fennel seeds; set aside until ready to serve.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Cook the rigatoni", "instruction": "While the ragù cooks, bring a large pot of salted water to a boil and cook the pasta until al dente, then meanwhile reheat the sauce.", "timer_seconds": 780, "background": false}, {"step": 6, "label": "Make the pesto", "instruction": "Put all the pesto ingredients except the basil into a food processor with a tablespoon of water and blitz to a rough paste, then add the basil and pulse just until combined.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Serve", "instruction": "Drain the pasta, toss with a little oil, divide between bowls, spoon over the ragù, top with pesto and a sprinkling of chopped fennel fronds.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=45dpOfESxr8"}, {"id": "52784", "name": "Smoky Lentil Chili with Squash", "category": "Vegetarian", "area": "British", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/uwxqwy1483389553.jpg", "local_image": "52784.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbls"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Leek", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Cumin", "measure": "4 tsp ground"}, {"ingredient": "Coriander", "measure": "2 tsp ground"}, {"ingredient": "Smoked Paprika", "measure": "1 tsp"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Chili Powder", "measure": "1 tsp"}, {"ingredient": "Cocoa", "measure": "1 tsp"}, {"ingredient": "Dried Oregano", "measure": "1/2 tsp"}, {"ingredient": "Diced Tomatoes", "measure": "1 can"}, {"ingredient": "Water", "measure": "3 cups"}, {"ingredient": "Carrots", "measure": "3 chopped"}, {"ingredient": "Brown Lentils", "measure": "1 1/2 cups"}, {"ingredient": "Sea Salt", "measure": "1 tsp"}, {"ingredient": "Squash", "measure": "1 Small"}, {"ingredient": "Cashews", "measure": "1 Cup"}, {"ingredient": "Apple Cider Vinegar", "measure": "1 tsp"}], "instructions": "Begin by roasting the squash. Slice it into thin crescents and drizzle with a little oil and sprinkle with sea salt. I added a fresh little sage I had in the fridge, but it’s unnecessary. Roast the squash a 205 C (400 F) for 20-30 minutes, flipping halfway through, until soft and golden. Let cool and chop into cubes.\r\nMeanwhile, rinse the lentils and cover them with water. Bring them to the boil then turn down to a simmer and let cook (uncovered) for 20-30 minutes, or until tender. Drain and set aside.\r\nWhile the lentils are cooking heat the 1 Tbsp. of oil on low in a medium pot. Add the onions and leeks and sauté for 5 or so minutes, or until they begin to soften. Add the garlic next along with the cumin and coriander, cooking for a few more minutes. Add the remaining spices – paprika, cinnamon, chilli, cocoa, Worcestershire sauce, salt, and oregano. Next add the can of tomatoes, the water or stock, and carrots. Let simmer, covered, for 20 minutes or until the veg is tender and the mixture has thickened up. You’ll need to check on the pot periodically for a stir and a top of of liquid if needed.\r\nAdd the lentils and chopped roasted squash. Let cook for 10 more minutes to heat through.\r\nServe with sliced jalapeno, lime wedges, cilantro, green onions, and cashew sour cream.\r\n\r\nSIMPLE CASHEW SOUR CREAM\r\n\r\n1 Cup Raw Unsalted Cashews\r\nPinch Sea Salt\r\n1 tsp. Apple Cider Vinegar\r\nWater\r\n\r\nBring some water to the boil, and use it to soak the cashews for at least four hours. Alternatively, you can use cold water and let the cashews soak overnight, but I’m forgetful/lazy, so often use the boil method which is much faster.\r\nAfter the cashews have soaked, drain them and add to a high speed blender. Begin to puree, slowly adding about 1/2 cup fresh water, until a creamy consistency is reached. You may need to add less or more water to reach the desired consistency.\r\nAdd a pinch of sea salt and vinegar (or lemon juice).", "equipment_tags": ["Blender"], "portions": 4, "prep_minutes": 80, "prep_minutes_source": "explicit", "kcal": 641, "protein_g": 22.6, "carbs_g": 55.6, "fat_g": 41.3, "total_kcal": 2564, "total_protein_g": 90.3, "total_carbs_g": 222.3, "total_fat_g": 165.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the squash", "instruction": "Slice the squash into thin crescents, drizzle with oil, sprinkle with salt, and roast at 205°C/400°F, flipping halfway through, until soft and golden. Let cool, then chop into cubes.", "timer_seconds": 1500, "background": true}, {"step": 2, "label": "Cook the lentils", "instruction": "Meanwhile, rinse the lentils, cover with water, bring to a boil, then simmer uncovered until tender. Drain and set aside.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Build the chilli base", "instruction": "While the lentils cook, heat the oil in a medium pot and sauté the onions and leeks until softening. Add the garlic, cumin and coriander and cook a few more minutes, then stir in the remaining spices.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Simmer the chilli", "instruction": "Add the tomatoes, water and carrots and simmer covered, stirring and topping up liquid as needed, until the vegetables are tender and the mixture has thickened.", "timer_seconds": 1200, "background": true}, {"step": 5, "label": "Combine and finish", "instruction": "Add the cooked lentils and roasted squash and cook to heat through.", "timer_seconds": 600, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve with sliced jalapeño, lime wedges, cilantro, green onions and cashew sour cream.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=pKmqawK2Tqs"}, {"id": "52785", "name": "Dal fry", "category": "Vegetarian", "area": "India", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wuxrtu1483564410.jpg", "local_image": "52785.jpg", "ingredients": [{"ingredient": "Toor dal", "measure": "1 cup"}, {"ingredient": "Water", "measure": "2-1/2 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Turmeric", "measure": "1/4 tsp"}, {"ingredient": "Ghee", "measure": "3 tbs"}, {"ingredient": "Chopped tomatoes", "measure": "1 cup"}, {"ingredient": "Cumin seeds", "measure": "1/2 tsp"}, {"ingredient": "Mustard Seeds", "measure": "1/2 tsp"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Green Chilli", "measure": "1 tbs chopped"}, {"ingredient": "Ginger", "measure": "2 tsp shredded"}, {"ingredient": "Cilantro", "measure": "2 tbs"}, {"ingredient": "Red Pepper", "measure": "1/2 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Garam Masala", "measure": "1/4 tsp"}], "instructions": "Wash and soak toor dal in approx. 3 cups of water, for at least one hours. Dal will be double in volume after soaking. Drain the water.\r\nCook dal with 2-1/2 cups water and add salt, turmeric, on medium high heat, until soft in texture (approximately 30 mins) it should be like thick soup.\r\nIn a frying pan, heat the ghee. Add cumin seeds, and mustard seeds. After the seeds crack, add bay leaves, green chili, ginger and chili powder. Stir for a few seconds.\r\nAdd tomatoes, salt and sugar stir and cook until tomatoes are tender and mushy.\r\nAdd cilantro and garam masala cook for about one minute.\r\nPour the seasoning over dal mix it well and cook for another minute.\r\nServe with Naan.", "equipment_tags": [], "portions": 1, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 1341, "protein_g": 57.7, "carbs_g": 172.9, "fat_g": 51.1, "total_kcal": 1341, "total_protein_g": 57.7, "total_carbs_g": 172.9, "total_fat_g": 51.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the dal", "instruction": "Wash and soak the toor dal in about 3 cups of water for at least an hour, until doubled in volume, then drain.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Cook the dal", "instruction": "Cook the dal with the measured water, salt and turmeric on medium-high heat until soft and thick like a soup.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Make the tempering", "instruction": "Heat the ghee in a frying pan, add the cumin and mustard seeds, and once they crackle add the bay leaves, green chilli, ginger and chilli powder, stirring for a few seconds.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the tomatoes", "instruction": "Add the tomatoes, salt and sugar to the tempering and cook, stirring, until tender and mushy.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Finish the tempering", "instruction": "Add the cilantro and garam masala and cook for about a minute.", "timer_seconds": 60, "background": false}, {"step": 6, "label": "Combine and serve", "instruction": "Pour the tempering over the cooked dal, mix well, and cook for another minute. Serve with naan.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=J4D855Q9-jg"}, {"id": "52786", "name": "Rocky Road Fudge", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vtxyxv1483567157.jpg", "local_image": "52786.jpg", "ingredients": [{"ingredient": "Miniature Marshmallows", "measure": "2 cups"}, {"ingredient": "Chocolate Chips", "measure": "3 cups"}, {"ingredient": "Peanut Butter", "measure": "½ cup"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Peanuts", "measure": "1 ¼ cups"}], "instructions": "Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.\r\nPour ½ cup of the miniature marshmallows into the bottom of the lined baking dish.\r\nIn a microwave-safe bowl, combine the chocolate chips and peanut butter. Microwave the chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.\r\nAdd the vanilla extract and stir well, until smooth.\r\nReserve 2 tablespoons of the chopped almonds or peanuts, and set aside.\r\nFold 1 ½ cups of the miniature marshmallows and the remaining chopped nuts into the chocolate mixture.\r\nTransfer the chocolate mixture into the prepared pan and spread into an even layer. Immediately top with the reserved chopped nuts and the mallow bits or additional miniature marshmallows, if using.\r\nRefrigerate for 4 hours, or until set.\r\nRemove the fudge and wax paper from the pan. Carefully peel all of wax paper from the fudge.\r\nCut the fudge into bite-sized pieces and serve.", "equipment_tags": [], "portions": 9, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 647, "protein_g": 4.7, "carbs_g": 91.3, "fat_g": 32.1, "total_kcal": 5826, "total_protein_g": 42.2, "total_carbs_g": 821.6, "total_fat_g": 289.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the pan", "instruction": "Line an 8-inch square baking pan with wax paper or foil, coat with non-stick spray, and scatter half a cup of the marshmallows into the bottom.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Melt the chocolate", "instruction": "In a microwave-safe bowl, combine the chocolate chips and peanut butter. Microwave in 20-second intervals, stirring in between, until melted.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Finish the fudge mixture", "instruction": "Stir in the vanilla extract until smooth. Reserve 2 tablespoons of the peanuts, then fold the remaining marshmallows and peanuts into the chocolate mixture.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Set and chill", "instruction": "Spread the mixture evenly into the prepared pan, top with the reserved peanuts and any extra marshmallows, then refrigerate until set.", "timer_seconds": 14400, "background": true}, {"step": 5, "label": "Cut and serve", "instruction": "Lift the fudge and wax paper from the pan, peel off the paper, and cut into bite-sized pieces to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=N1aJ3nEYXyg"}, {"id": "52787", "name": "Hot Chocolate Fudge", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xrysxr1483568462.jpg", "local_image": "52787.jpg", "ingredients": [{"ingredient": "Chocolate Chips", "measure": "2 cups"}, {"ingredient": "Heavy Cream", "measure": "2 tbs"}, {"ingredient": "Condensed Milk", "measure": "1 – 14-ounce can"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "White Chocolate Chips", "measure": "1-⅓ cups"}, {"ingredient": "Miniature Marshmallows", "measure": "1-½ cups"}], "instructions": "Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.\r\nIn a microwave-safe bowl, combine the dark chocolate chips, heavy cream and half of the sweetened condensed milk. Microwave the dark chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.\r\nAdd the vanilla extract to the dark chocolate mixture and stir well until smooth.\r\nTransfer the dark chocolate mixture into the prepared pan and spread into an even layer.\r\nIn a separate bowl, combine the white chocolate chips with the remaining half of the sweetened condensed milk. Microwave the white chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.\r\nEvenly spread the white chocolate mixture on top of dark chocolate layer.\r\nTop the chocolate layers with the Mallow Bits or miniature marshmallows, and gently press them down.\r\nRefrigerate for 4 hours, or until set.\r\nRemove the fudge and wax paper from the pan. Carefully peel all of the wax paper from the fudge.\r\nCut the fudge into bite-sized pieces and serve.", "equipment_tags": [], "portions": 4, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 728, "protein_g": 7.0, "carbs_g": 90.5, "fat_g": 40.4, "total_kcal": 2912, "total_protein_g": 27.9, "total_carbs_g": 361.8, "total_fat_g": 161.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the pan", "instruction": "Line an 8-inch square baking pan with wax paper or foil and coat with non-stick spray.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the dark chocolate layer", "instruction": "In a microwave-safe bowl, combine the dark chocolate chips, cream and half the condensed milk. Microwave in 20-second intervals, stirring in between, until melted, then stir in the vanilla extract until smooth.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Set the base layer", "instruction": "Spread the dark chocolate mixture evenly into the prepared pan.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the white chocolate layer", "instruction": "In a separate bowl, combine the white chocolate chips with the remaining condensed milk and microwave in 20-second intervals, stirring in between, until melted.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Layer and top", "instruction": "Spread the white chocolate mixture over the dark chocolate layer, then press the marshmallows on top.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Chill until set", "instruction": "Refrigerate until set.", "timer_seconds": 14400, "background": true}, {"step": 7, "label": "Cut and serve", "instruction": "Remove the fudge and paper from the pan, peel off the paper, and cut into bite-sized pieces.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=oJvbsVSblfk"}, {"id": "52788", "name": "Christmas Pudding Flapjack", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vvusxs1483907034.jpg", "local_image": "52788.jpg", "ingredients": [{"ingredient": "salted butter", "measure": "250g"}, {"ingredient": "dark soft brown sugar", "measure": "225g"}, {"ingredient": "golden syrup", "measure": "150g"}, {"ingredient": "orange", "measure": "Zest of 1"}, {"ingredient": "rolled oats", "measure": "500g"}, {"ingredient": "Christmas pudding", "measure": "250g"}], "instructions": "Preheat the oven to 180°C/fan 160°C/gas mark 4 and grease and line a 25cm x 20cm tin. Melt the butter, sugar, syrup and orange zest in a large saucepan over a medium heat. The aim is to dissolve all the ingredients so that they are smooth, but to not lose any volume through boiling so be careful not to overheat.\r\n\r\nAdd the oats and stir well until evenly coated. Stir through the leftover Christmas pudding and tip into the prepared tin. Use a spoon to flatten the top and bake for 40 minutes until the edges start to brown. Whilst still warm in the tin, score into 12 squares. Allow to cool completely before cutting along the scores.\r\n\r\nKeeps for 5 days in an air tight tin or freeze for up to 1 month.", "equipment_tags": [], "portions": 9, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 658, "protein_g": 10.7, "carbs_g": 90.0, "fat_g": 29.4, "total_kcal": 5919, "total_protein_g": 96.3, "total_carbs_g": 810.4, "total_fat_g": 265.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep the tin", "instruction": "Preheat the oven to 180°C/fan 160°C/gas 4 and grease and line a 25cm x 20cm tin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Melt the base mixture", "instruction": "Melt the butter, sugar, syrup and orange zest together in a large saucepan over medium heat, taking care not to overheat or boil off volume.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Mix in the oats", "instruction": "Add the oats and stir well until evenly coated, then stir through the leftover Christmas pudding.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Tip into the prepared tin, flatten the top with a spoon, and bake until the edges start to brown.", "timer_seconds": 2400, "background": true}, {"step": 5, "label": "Score and cool", "instruction": "While still warm in the tin, score into 12 squares, then allow to cool completely before cutting along the scores.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=OaqvGvEiwzU"}, {"id": "52791", "name": "Eton Mess", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uuxwvq1483907861.jpg", "local_image": "52791.jpg", "ingredients": [{"ingredient": "strawberries", "measure": "500g"}, {"ingredient": "double cream", "measure": "400ml"}, {"ingredient": "meringue nests", "measure": "3 x 7.5cm"}, {"ingredient": "ginger cordial", "measure": "1 tbsp"}, {"ingredient": "Mint", "measure": "sprigs of fresh"}], "instructions": "Purée half the strawberries in a blender. Chop the remaining strawberries, reserving four for decoration.\r\nWhip the double cream until stiff peaks form, then fold in the strawberry purée and crushed meringue. Fold in the chopped strawberries and ginger cordial, if using.\r\nSpoon equal amounts of the mixture into four cold wine glasses. Serve garnished with the remaining strawberries and a sprig of mint.", "equipment_tags": ["Blender"], "portions": 7, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 364, "protein_g": 3.2, "carbs_g": 27.2, "fat_g": 27.7, "total_kcal": 2551, "total_protein_g": 22.5, "total_carbs_g": 190.2, "total_fat_g": 193.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the strawberries", "instruction": "Purée half the strawberries in a blender. Chop the remaining strawberries, reserving four for decoration.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Whip the cream and fold", "instruction": "Whip the double cream until stiff peaks form, then fold in the strawberry purée and crushed meringue. Fold in the chopped strawberries and ginger cordial if using.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Assemble and serve", "instruction": "Spoon equal amounts into cold wine glasses and serve garnished with the reserved strawberries and a sprig of mint.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=43WgiNq54L8"}, {"id": "52792", "name": "Bread and Butter Pudding", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xqwwpy1483908697.jpg", "local_image": "52792.jpg", "ingredients": [{"ingredient": "butter", "measure": "25g/1oz"}, {"ingredient": "bread", "measure": "8 thin slices"}, {"ingredient": "sultanas", "measure": "50g/2oz"}, {"ingredient": "cinnamon", "measure": "2 tsp"}, {"ingredient": "milk", "measure": "350ml/12fl"}, {"ingredient": "double cream", "measure": "50ml/2fl oz"}, {"ingredient": "eggs", "measure": "2 free-range"}, {"ingredient": "sugar", "measure": "25g/1oz"}, {"ingredient": "nutmeg", "measure": "grated, to taste"}], "instructions": "Grease a 1 litre/2 pint pie dish with butter.\r\nCut the crusts off the bread. Spread each slice with on one side with butter, then cut into triangles.\r\nArrange a layer of bread, buttered-side up, in the bottom of the dish, then add a layer of sultanas. Sprinkle with a little cinnamon, then repeat the layers of bread and sultanas, sprinkling with cinnamon, until you have used up all of the bread. Finish with a layer of bread, then set aside.\r\nGently warm the milk and cream in a pan over a low heat to scalding point. Don't let it boil.\r\nCrack the eggs into a bowl, add three quarters of the sugar and lightly whisk until pale.\r\nAdd the warm milk and cream mixture and stir well, then strain the custard into a bowl.\r\nPour the custard over the prepared bread layers and sprinkle with nutmeg and the remaining sugar and leave to stand for 30 minutes.\r\nPreheat the oven to 180C/355F/Gas 4.\r\nPlace the dish into the oven and bake for 30-40 minutes, or until the custard has set and the top is golden-brown.", "equipment_tags": [], "portions": 10, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 210, "protein_g": 6.4, "carbs_g": 28.8, "fat_g": 7.9, "total_kcal": 2096, "total_protein_g": 63.8, "total_carbs_g": 288.4, "total_fat_g": 79.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the bread", "instruction": "Grease a pie dish with butter. Cut the crusts off the bread, butter each slice on one side, then cut into triangles.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Layer the dish", "instruction": "Arrange a layer of bread buttered-side up in the dish, add a layer of sultanas and a sprinkle of cinnamon, and repeat until all the bread is used, finishing with bread.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Warm the milk and cream", "instruction": "Gently warm the milk and cream in a pan over low heat to scalding point, without letting it boil.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the custard", "instruction": "Whisk the eggs with three quarters of the sugar until pale, stir in the warm milk mixture, then strain into a bowl.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Soak the bread", "instruction": "Pour the custard over the bread, sprinkle with nutmeg and the remaining sugar, and leave to stand.", "timer_seconds": 1800, "background": true}, {"step": 6, "label": "Bake", "instruction": "Preheat the oven to 180°C/355°F/Gas 4 and bake until the custard has set and the top is golden-brown.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=Vz5W1-BmOE4"}, {"id": "52793", "name": "Sticky Toffee Pudding Ultimate", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xrptpq1483909204.jpg", "local_image": "52793.jpg", "ingredients": [{"ingredient": "Medjool dates", "measure": "225g"}, {"ingredient": "water", "measure": "175ml Boiling"}, {"ingredient": "vanilla extract", "measure": "1 tsp"}, {"ingredient": "self-raising flour", "measure": "175g"}, {"ingredient": "bicarbonate of soda", "measure": "1 tsp"}, {"ingredient": "eggs", "measure": "2"}, {"ingredient": "butter", "measure": "85g"}, {"ingredient": "demerara sugar", "measure": "140g"}, {"ingredient": "black treacle", "measure": "2 tbsp"}, {"ingredient": "milk", "measure": "100ml"}, {"ingredient": "ice cream", "measure": "1 scoop"}, {"ingredient": "muscovado sugar", "measure": "175g"}, {"ingredient": "butter", "measure": "50g"}, {"ingredient": "double cream", "measure": "225ml"}, {"ingredient": "black treacle", "measure": "1 tbsp"}], "instructions": "Stone and chop the dates quite small, put them in a bowl, then pour the boiling water over. Leave for about 30 mins until cool and well-soaked, then mash a bit with a fork. Stir in the vanilla extract. Butter and flour seven mini pudding tins (each about 200ml/7fl oz) and sit them on a baking sheet. Heat oven to 180C/fan 160C/gas 4.\r\nWhile the dates are soaking, make the puddings. Mix the flour and bicarbonate of soda together and beat the eggs in a separate bowl. Beat the butter and sugar together in a large bowl for a few mins until slightly creamy (the mixture will be grainy from the sugar). Add the eggs a little at a time, beating well between additions. Beat in the black treacle then, using a large metal spoon, gently fold in one-third of the flour, then half the milk, being careful not to overbeat. Repeat until all the flour and milk is used. Stir the soaked dates into the pudding batter. The mix may look a little curdled at this point and will be like a soft, thick batter. Spoon it evenly between the tins and bake for 20-25 mins, until risen and firm.\r\nMeanwhile, put the sugar and butter for the sauce in a medium saucepan with half the cream. Bring to the boil over a medium heat, stirring all the time, until the sugar has completely dissolved. Stir in the black treacle, turn up the heat slightly and let the mixture bubble away for 2-3 mins until it is a rich toffee colour, stirring occasionally to make sure it doesn’t burn. Take the pan off the heat and beat in the rest of the cream.\r\nRemove the puddings from the oven. Leave in the tins for a few mins, then loosen them well from the sides of the tins with a small palette knife before turning them out. You can serve them now with the sauce drizzled over, but they’ll be even stickier if left for a day or two coated in the sauce. To do this, pour about half the sauce into one or two ovenproof serving dishes. Sit the upturned puddings on the sauce, then pour the rest of the sauce over them. Cover with a loose tent of foil so that the sauce doesn’t smudge (no need to chill).\r\nWhen ready to serve, heat oven to 180C/fan 160C/gas 4. Warm the puddings through, still covered, for 15-20 mins or until the sauce is bubbling. Serve them on their own, or with cream or custard.", "equipment_tags": [], "portions": 10, "prep_minutes": 78, "prep_minutes_source": "explicit", "kcal": 482, "protein_g": 4.7, "carbs_g": 67.0, "fat_g": 23.8, "total_kcal": 4823, "total_protein_g": 46.7, "total_carbs_g": 669.9, "total_fat_g": 238.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the dates", "instruction": "Stone and finely chop the dates, put them in a bowl, and pour the boiling water over. Leave until cool and well soaked, then mash a bit with a fork and stir in the vanilla extract.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Prep tins and preheat", "instruction": "Butter and flour seven mini pudding tins and heat the oven to 180°C/fan 160°C/gas 4.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the batter", "instruction": "Mix the flour and bicarbonate of soda together. Beat the butter and sugar until slightly creamy, add the eggs a little at a time, beat in the black treacle, then fold in the flour and milk alternately.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fill and bake", "instruction": "Stir the soaked dates into the batter, spoon evenly between the tins, and bake until risen and firm.", "timer_seconds": 1350, "background": true}, {"step": 5, "label": "Make the toffee sauce", "instruction": "While the puddings bake, put the sauce sugar and butter in a saucepan with half the cream. Bring to a boil, stirring, until the sugar dissolves, then stir in the treacle and bubble until rich toffee-coloured.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Finish the sauce", "instruction": "Take off the heat and beat in the rest of the cream.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Unmould and serve", "instruction": "Leave the puddings in the tins for a few minutes, then loosen and turn out. Pour over the sauce and serve, or coat and rest for a day for extra stickiness.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=hKq6RbxJHBo"}, {"id": "52794", "name": "Vegan Chocolate Cake", "category": "Vegan", "area": "United States", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/qxutws1486978099.jpg", "local_image": "52794.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "1 1/4 cup"}, {"ingredient": "coco sugar", "measure": "1/2 cup"}, {"ingredient": "cacao", "measure": "1/3 cup raw"}, {"ingredient": "baking powder", "measure": "1 tsp"}, {"ingredient": "flax eggs", "measure": "2"}, {"ingredient": "almond milk", "measure": "1/2 cup"}, {"ingredient": "vanilla", "measure": "1 tsp"}, {"ingredient": "water", "measure": "1/2 cup boiling"}], "instructions": "Simply mix all dry ingredients with wet ingredients and blend altogether. Bake for 45 min on 180 degrees. Decorate with some melted vegan chocolate ", "equipment_tags": [], "portions": 1, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 1282, "protein_g": 44.8, "carbs_g": 274.3, "fat_g": 24.6, "total_kcal": 1282, "total_protein_g": 44.8, "total_carbs_g": 274.3, "total_fat_g": 24.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat the oven", "instruction": "Preheat the oven to 180°C.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Mix the batter", "instruction": "Mix all the dry ingredients with the wet ingredients and blend together until smooth.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Pour into a prepared tin and bake.", "timer_seconds": 2700, "background": true}, {"step": 4, "label": "Decorate and serve", "instruction": "Once cooled, decorate with some melted vegan chocolate.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=C3pAgB7pync"}, {"id": "52795", "name": "Chicken Handi", "category": "Chicken", "area": "India", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/wyxwsp1486979827.jpg", "local_image": "52795.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1.2 kg"}, {"ingredient": "Onion", "measure": "5 thinly sliced"}, {"ingredient": "Tomatoes", "measure": "2 finely chopped"}, {"ingredient": "Garlic", "measure": "8 cloves chopped"}, {"ingredient": "Ginger paste", "measure": "1 tbsp"}, {"ingredient": "Vegetable oil", "measure": "¼ cup"}, {"ingredient": "Cumin seeds", "measure": "2 tsp"}, {"ingredient": "Coriander seeds", "measure": "3 tsp"}, {"ingredient": "Turmeric powder", "measure": "1 tsp"}, {"ingredient": "Chilli powder", "measure": "1 tsp"}, {"ingredient": "Green chilli", "measure": "2"}, {"ingredient": "Yogurt", "measure": "1 cup"}, {"ingredient": "Cream", "measure": "¾ cup"}, {"ingredient": "fenugreek", "measure": "3 tsp Dried"}, {"ingredient": "Garam masala", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "Take a large pot or wok, big enough to cook all the chicken, and heat the oil in it. Once the oil is hot, add sliced onion and fry them until deep golden brown. Then take them out on a plate and set aside.\r\nTo the same pot, add the chopped garlic and sauté for a minute. Then add the chopped tomatoes and cook until tomatoes turn soft. This would take about 5 minutes.\r\nThen return the fried onion to the pot and stir. Add ginger paste and sauté well.\r\nNow add the cumin seeds, half of the coriander seeds and chopped green chillies. Give them a quick stir.\r\nNext goes in the spices – turmeric powder and red chilli powder. Sauté the spices well for couple of minutes.\r\nAdd the chicken pieces to the wok, season it with salt to taste and cook the chicken covered on medium-low heat until the chicken is almost cooked through. This would take about 15 minutes. Slowly sautéing the chicken will enhance the flavor, so do not expedite this step by putting it on high heat.\r\nWhen the oil separates from the spices, add the beaten yogurt keeping the heat on lowest so that the yogurt doesn’t split. Sprinkle the remaining coriander seeds and add half of the dried fenugreek leaves. Mix well.\r\nFinally add the cream and give a final mix to combine everything well.\r\nSprinkle the remaining kasuri methi and garam masala and serve the chicken handi hot with naan or rotis. Enjoy!", "equipment_tags": [], "portions": 5, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 653, "protein_g": 56.8, "carbs_g": 23.9, "fat_g": 36.3, "total_kcal": 3264, "total_protein_g": 284.2, "total_carbs_g": 119.6, "total_fat_g": 181.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Fry the onions", "instruction": "Heat the oil in a large pot or wok and fry the sliced onion until deep golden brown, then remove and set aside.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Build the tomato base", "instruction": "In the same pot, sauté the garlic for a minute, then add the tomatoes and cook until soft, about 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Season the base", "instruction": "Return the fried onions to the pot, stir in the ginger paste, then add the cumin seeds, half the coriander seeds and chopped green chillies. Stir in the turmeric and chilli powder and sauté well.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the chicken", "instruction": "Add the chicken pieces, season with salt, and cook covered on medium-low heat until almost cooked through.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Finish with yogurt and cream", "instruction": "Once the oil separates from the spices, stir in the beaten yogurt on the lowest heat so it doesn't split, then sprinkle in the remaining coriander seeds and half the dried fenugreek leaves and mix well.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Serve", "instruction": "Add the cream and give a final mix. Sprinkle with the remaining kasuri methi and garam masala, and serve hot with naan or rotis.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=IO0issT0Rmc"}, {"id": "52796", "name": "Chicken Alfredo Primavera", "category": "Chicken", "area": "Italian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/syqypv1486981727.jpg", "local_image": "52796.jpg", "ingredients": [{"ingredient": "Butter", "measure": "2 tablespoons"}, {"ingredient": "Olive Oil", "measure": "3 tablespoons"}, {"ingredient": "Chicken", "measure": "5 boneless"}, {"ingredient": "Salt", "measure": "1 teaspoon"}, {"ingredient": "Squash", "measure": "1 cut into 1/2-inch cubes"}, {"ingredient": "Broccoli", "measure": "1 Head chopped"}, {"ingredient": "mushrooms", "measure": "8-ounce sliced"}, {"ingredient": "Pepper", "measure": "1 red"}, {"ingredient": "onion", "measure": "1 chopped"}, {"ingredient": "garlic", "measure": "3 cloves"}, {"ingredient": "red pepper flakes", "measure": "1/2 teaspoon"}, {"ingredient": "white wine", "measure": "1/2 cup"}, {"ingredient": "milk", "measure": "1/2 cup"}, {"ingredient": "heavy cream", "measure": "1/2 cup"}, {"ingredient": "Parmesan cheese", "measure": "1 cup grated"}, {"ingredient": "bowtie pasta", "measure": "16 ounces"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Parsley", "measure": "chopped"}], "instructions": "Heat 1 tablespoon of butter and 2 tablespoons of olive oil in a large skillet over medium-high heat. Season both sides of each chicken breast with seasoned salt and a pinch of pepper. Add the chicken to the skillet and cook for 5-7 minutes on each side, or until cooked through.  While the chicken is cooking, bring a large pot of water to a boil. Season the boiling water with a few generous pinches of kosher salt. Add the pasta and give it a stir. Cook, stirring occasionally, until al dente, about 12 minutes. Reserve 1/2 cup of  pasta water before draining the pasta.  Remove the chicken from the pan and transfer it to a cutting board; allow it to rest. Turn the heat down to medium and dd the remaining 1 tablespoon of butter and olive oil to the same pan you used to cook the chicken. Add the veggies (minus the garlic) and red pepper flakes to the pan and stir to coat with the oil and butter (refrain from seasoning with salt until the veggies are finished browning). Cook, stirring often, until the veggies are tender, about 5 minutes. Add the garlic and a generous pinch of salt and pepper to the pan and cook for 1 minute.  Deglaze the pan with the white wine. Continue to cook until the wine has reduced by half, about 3 minutes. Stir in the milk, heavy cream, and reserved pasta water. Bring the mixture to a gentle boil and allow to simmer and reduce for 2-3 minutes. Turn off the heat and add the Parmesan cheese and cooked pasta. Season with salt and pepper to taste. Garnish with Parmesan cheese and chopped parsley, if desired. ", "equipment_tags": [], "portions": 4, "prep_minutes": 31, "prep_minutes_source": "explicit", "kcal": 1141, "protein_g": 56.9, "carbs_g": 99.6, "fat_g": 55.2, "total_kcal": 4566, "total_protein_g": 227.4, "total_carbs_g": 398.6, "total_fat_g": 220.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the chicken", "instruction": "Heat half the butter and olive oil in a large skillet over medium-high heat. Season the chicken breasts and cook on each side until cooked through, then remove and let rest.", "timer_seconds": 720, "background": false}, {"step": 2, "label": "Cook the pasta", "instruction": "While the chicken cooks, bring a large pot of salted water to a boil and cook the pasta, stirring occasionally, until al dente. Reserve some pasta water before draining.", "timer_seconds": 720, "background": false}, {"step": 3, "label": "Sauté the vegetables", "instruction": "Add the remaining butter and oil to the pan used for the chicken. Add the vegetables (not the garlic) and red pepper flakes, and cook, stirring often, until tender.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Add garlic and deglaze", "instruction": "Add the garlic, salt and pepper and cook for a minute, then deglaze the pan with white wine and cook until reduced by half.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Build the sauce", "instruction": "Stir in the milk, heavy cream and reserved pasta water. Bring to a gentle boil and simmer to reduce slightly.", "timer_seconds": 180, "background": false}, {"step": 6, "label": "Combine and serve", "instruction": "Turn off the heat, add the Parmesan and cooked pasta, and season to taste. Slice the rested chicken over the top and garnish with Parmesan and parsley.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=qCIbq8HywpQ"}, {"id": "52797", "name": "Spicy North African Potato Salad", "category": "Vegetarian", "area": "Moroccan", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/urtwux1486983078.jpg", "local_image": "52797.jpg", "ingredients": [{"ingredient": "Small Potatoes", "measure": "650g/1lb 8 oz"}, {"ingredient": "Harissa Spice", "measure": "1 tsp"}, {"ingredient": "olive oil", "measure": "2 tsp"}, {"ingredient": "Lemon", "measure": "juice of half"}, {"ingredient": "Spring onions", "measure": "4"}, {"ingredient": "Rocket", "measure": "150g/6oz"}, {"ingredient": "Feta", "measure": "80g/3oz"}, {"ingredient": "Mint", "measure": "20 chopped"}, {"ingredient": "Pine nuts", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "Cook potatoes - place potatoes in a pot of cold water, and bring to the boil. Boil 20 minutes, or until potatoes are tender. You know they are cooked when you can stick a knife in them and the knife goes straight through.\r\nCombine harissa spice, olive oil, salt and pepper and lemon juice in a small bowl and whisk until combined.\r\nOnce potatoes are cooked, drain water and roughly chop potatoes in half.\r\nAdd harissa mix and spring onions/green onions to potatoes and stir.\r\nIn a large salad bowl, lay out arugula/rocket.\r\nTop with potato mix and toss.\r\nAdd fetta, mint and sprinkle over pine nuts.\r\nAdjust salt and pepper to taste.", "equipment_tags": [], "portions": 12, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 136, "protein_g": 6.6, "carbs_g": 20.2, "fat_g": 4.7, "total_kcal": 1629, "total_protein_g": 78.8, "total_carbs_g": 243.0, "total_fat_g": 56.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil the potatoes", "instruction": "Place the potatoes in a pot of cold water, bring to the boil, and cook until tender enough for a knife to slide through easily.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Make the dressing", "instruction": "While the potatoes cook, whisk together the harissa spice, olive oil, salt, pepper and lemon juice in a small bowl.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Dress the potatoes", "instruction": "Drain the potatoes and roughly chop in half, then add the harissa dressing and spring onions and stir.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Assemble the salad", "instruction": "Lay the rocket out in a large salad bowl, top with the potato mixture and toss.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Finish and serve", "instruction": "Add the feta, mint and pine nuts, and adjust the seasoning to taste.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=zxBzwJvTK4g"}, {"id": "52802", "name": "Fish pie", "category": "Seafood", "area": "British", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/ysxwuq1487323065.jpg", "local_image": "52802.jpg", "ingredients": [{"ingredient": "Floury Potatoes", "measure": "900g"}, {"ingredient": "Olive Oil", "measure": "2 tbsp"}, {"ingredient": "Semi-skimmed Milk", "measure": "600ml"}, {"ingredient": "White Fish Fillets", "measure": "800g"}, {"ingredient": "Plain flour", "measure": "1 tbsp"}, {"ingredient": "Nutmeg", "measure": "Grating"}, {"ingredient": "Double Cream", "measure": "3 tbsp"}, {"ingredient": "Jerusalem Artichokes", "measure": "200g"}, {"ingredient": "Leek", "measure": "1 finely sliced"}, {"ingredient": "Prawns", "measure": "200g peeled raw"}, {"ingredient": "Parsley", "measure": "Large handful"}, {"ingredient": "Dill", "measure": "Handful"}, {"ingredient": "Lemon", "measure": "Grated zest of 1"}, {"ingredient": "Gruyère", "measure": "25g grated"}, {"ingredient": "Lemon", "measure": "Juice of 1"}], "instructions": "01.Put the potatoes in a large pan of cold salted water and bring to the boil. Lower the heat, cover, then simmer gently for 15 minutes until tender. Drain, then return to the pan over a low heat for 30 seconds to drive off any excess water. Mash with 1 tbsp olive oil, then season.\r\n02.Meanwhile put the milk in a large sauté pan, add the fish and bring to the boil. Remove from the heat, cover and stand for 3 minutes. Remove the fish (reserving the milk) and pat dry with kitchen paper, then gently flake into an ovenproof dish, discarding the skin and any bones.\r\n03.Heat the remaining oil in a pan, stir in the flour and cook for 30 seconds. Gradually stir in 200-250ml of the reserved milk (discard the rest). Grate in nutmeg, season, then bubble until thick. Stir in the cream.\r\n04.Preheat the oven to 190°C/fan170°C/gas 5. Grate the artichokes and add to the dish with the leek, prawns and herbs. Stir the lemon zest and juice into the sauce, then pour over. Mix gently with a wooden spoon.\r\n05.Spoon the mash onto the fish mixture, then use a fork to make peaks, which will crisp and brown as it cooks. Sprinkle over the cheese, then bake for 35-40 minutes until golden and bubbling. Serve with wilted greens.", "equipment_tags": [], "portions": 6, "prep_minutes": 58, "prep_minutes_source": "explicit", "kcal": 441, "protein_g": 41.6, "carbs_g": 37.9, "fat_g": 13.9, "total_kcal": 2648, "total_protein_g": 249.7, "total_carbs_g": 227.5, "total_fat_g": 83.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook and mash the potatoes", "instruction": "Put the potatoes in a large pan of cold salted water, bring to the boil, then simmer gently until tender. Drain, dry over low heat for 30 seconds, then mash with a tablespoon of oil and season.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Poach the fish", "instruction": "Meanwhile, put the milk in a large sauté pan, add the fish and bring to the boil. Remove from the heat, cover and stand, then remove the fish (reserving the milk), pat dry, and flake into an ovenproof dish, discarding skin and bones.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Make the sauce", "instruction": "Heat the remaining oil in a pan, stir in the flour, and cook for 30 seconds. Gradually stir in the reserved milk, grate in nutmeg, season, and bubble until thick, then stir in the cream.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Assemble the filling", "instruction": "Preheat the oven to 190°C/fan170°C/gas 5. Grate the artichokes and add to the dish with the leek, prawns and herbs. Stir the lemon zest and juice into the sauce, then pour over and mix gently.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Top and bake", "instruction": "Spoon the mash onto the fish mixture, fork the top into peaks, sprinkle with cheese, and bake until golden and bubbling. Serve with wilted greens.", "timer_seconds": 2250, "background": true}], "video": "https://www.youtube.com/watch?v=2sX4fCgg-UI"}, {"id": "52803", "name": "Beef Wellington", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/vvpprx1487325699.jpg", "local_image": "52803.jpg", "ingredients": [{"ingredient": "mushrooms", "measure": "400g"}, {"ingredient": "English Mustard", "measure": "1-2tbsp"}, {"ingredient": "Olive Oil", "measure": "Dash"}, {"ingredient": "Beef Fillet", "measure": "750g piece"}, {"ingredient": "Parma ham", "measure": "6-8 slices"}, {"ingredient": "Puff Pastry", "measure": "500g"}, {"ingredient": "Flour", "measure": "Dusting"}, {"ingredient": "Egg Yolks", "measure": "2 Beaten"}], "instructions": "Put the mushrooms into a food processor with some seasoning and pulse to a rough paste. Scrape the paste into a pan and cook over a high heat for about 10 mins, tossing frequently, to cook out the moisture from the mushrooms. Spread out on a plate to cool.\r\nHeat in a frying pan and add a little olive oil. Season the beef and sear in the hot pan for 30 secs only on each side. (You don't want to cook it at this stage, just colour it). Remove the beef from the pan and leave to cool, then brush all over with the mustard.\r\nLay a sheet of cling film on a work surface and arrange the Parma ham slices on it, in slightly overlapping rows. With a palette knife, spread the mushroom paste over the ham, then place the seared beef fillet in the middle. Keeping a tight hold of the cling film from the edge, neatly roll the Parma ham and mushrooms around the beef to form a tight barrel shape. Twist the ends of the cling film to secure. Chill for 15-20 mins to allow the beef to set and keep its shape.\r\nRoll out the puff pastry on a floured surface to a large rectangle, the thickness of a £1 coin. Remove the cling film from the beef, then lay in the centre. Brush the surrounding pastry with egg yolk. Fold the ends over, the wrap the pastry around the beef, cutting off any excess. Turn over, so the seam is underneath, and place on a baking sheet. Brush over all the pastry with egg and chill for about 15 mins to let the pastry rest.\r\nHeat the oven to 200C, 400F, gas 6.\r\nLightly score the pastry at 1cm intervals and glaze again with beaten egg yolk. Bake for 20 minutes, then lower the oven setting to 180C, 350F, gas 4 and cook for another 15 mins. Allow to rest for 10-15 mins before slicing and serving with the side dishes of your choice. The beef should still be pink in the centre when you serve it.", "equipment_tags": ["FoodProcessor"], "portions": 5, "prep_minutes": 95, "prep_minutes_source": "explicit", "kcal": 1370, "protein_g": 65.1, "carbs_g": 110.0, "fat_g": 74.3, "total_kcal": 6849, "total_protein_g": 325.6, "total_carbs_g": 550.2, "total_fat_g": 371.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the mushroom duxelles", "instruction": "Pulse the mushrooms with seasoning in a food processor to a rough paste, then cook in a pan over high heat, tossing frequently, to cook out the moisture. Spread on a plate to cool.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Sear the beef", "instruction": "Heat oil in a frying pan, season the beef, and sear for 30 seconds on each side just to colour it, not cook it. Remove and leave to cool, then brush all over with mustard.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Wrap in ham and chill", "instruction": "Arrange the Parma ham slices overlapping on cling film, spread with the mushroom paste, place the beef in the middle, and roll tightly into a barrel shape using the cling film. Chill to set.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Wrap in pastry and chill again", "instruction": "Roll out the puff pastry, unwrap the beef and place it in the centre, brush the pastry with egg yolk, fold and wrap around the beef, trim excess, and turn seam-side down. Brush with egg and chill.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Preheat the oven", "instruction": "Heat the oven to 200°C/400°F/gas 6.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake", "instruction": "Score the pastry at 1cm intervals, glaze again with egg yolk, and bake, then lower the oven and cook further until the pastry is golden.", "timer_seconds": 2100, "background": true}, {"step": 7, "label": "Rest and serve", "instruction": "Allow to rest before slicing and serving with your choice of sides. The beef should still be pink in the centre.", "timer_seconds": 780, "background": true}], "video": "https://www.youtube.com/watch?v=FS8u1RBdf6I"}, {"id": "52804", "name": "Poutine", "category": "Miscellaneous", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uuyrrx1487327597.jpg", "local_image": "52804.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "Dash"}, {"ingredient": "Beef Gravy", "measure": "1 Can"}, {"ingredient": "Potatoes", "measure": "5 thin cut"}, {"ingredient": "Cheese Curds", "measure": "2 cups"}], "instructions": "Heat oil in a deep fryer or deep heavy skillet to 365°F (185°C).\r\nWarm gravy in saucepan or microwave.\r\nPlace the fries into the hot oil, and cook until light brown, about 5 minutes.\r\nRemove to a paper towel lined plate to drain.\r\nPlace the fries on a serving platter, and sprinkle the cheese over them.\r\nLadle gravy over the fries and cheese, and serve immediately.", "equipment_tags": [], "portions": 3, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 826, "protein_g": 47.0, "carbs_g": 56.7, "fat_g": 45.8, "total_kcal": 2479, "total_protein_g": 141.0, "total_carbs_g": 170.1, "total_fat_g": 137.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Heat the oil", "instruction": "Heat the oil in a deep fryer or heavy skillet to 365°F (185°C).", "timer_seconds": null, "background": false}, {"step": 2, "label": "Warm the gravy", "instruction": "Warm the gravy in a saucepan or the microwave.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fry the fries", "instruction": "Place the fries into the hot oil and cook until light brown, then remove to a paper-towel-lined plate to drain.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Assemble and serve", "instruction": "Place the fries on a serving platter, sprinkle with cheese curds, ladle over the hot gravy, and serve immediately.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=UVAMAoA2_WU"}, {"id": "52805", "name": "Lamb Biryani", "category": "Lamb", "area": "India", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xrttsx1487339558.jpg", "local_image": "52805.jpg", "ingredients": [{"ingredient": "Cashew nuts", "measure": "12"}, {"ingredient": "Khus khus", "measure": "½ tbsp"}, {"ingredient": "Cumin seeds", "measure": "½ tbsp"}, {"ingredient": "Onions", "measure": "3 sliced thinly"}, {"ingredient": "Ginger garlic paste", "measure": "2 tsp"}, {"ingredient": "Garlic", "measure": "4 whole"}, {"ingredient": "Mint", "measure": "Leaves"}, {"ingredient": "Cilantro", "measure": "Leaves"}, {"ingredient": "Saffron", "measure": "½ tsp dissolved in ½ cup warm milk"}, {"ingredient": "Ghee", "measure": "2 tbsp"}, {"ingredient": "Basmati rice", "measure": "2 Cups"}, {"ingredient": "Full fat yogurt", "measure": "½ cup"}, {"ingredient": "Cumin Seeds", "measure": "1 tbsp"}, {"ingredient": "Bay leaf", "measure": "½"}, {"ingredient": "Cinnamon", "measure": "1 thin piece"}, {"ingredient": "Cloves", "measure": "3"}, {"ingredient": "Cardamom", "measure": "2"}, {"ingredient": "Lamb", "measure": "1 lb"}, {"ingredient": "Red Chilli powder", "measure": "1 tsp"}, {"ingredient": "Biryani masala", "measure": "1 tbsp"}], "instructions": "Grind the cashew, poppy seeds and cumin seeds into a smooth paste, using as little water as possible. Set aside. \r\n\r\nDeep fry the sliced onions when it is hot. Don’t overcrowd the oil. When the onions turn light brown, remove from oil and drain on paper towel. The fried onion will crisp up as it drains. Also fry the cashewnuts till golden brown. Set aside.\r\n\r\nWash the rice and soak in water for twenty minutes.\r\nMeanwhile, take a big wide pan, add oil in medium heat, add the sliced onions, add the blended paste, to it add the green chillies, ginger garlic paste and garlic and fry for a minute.\r\nThen add the tomatoes and sauté them well till they are cooked and not mushy.\r\n\r\nThen to it add the red chilli powder, biryani powder, mint, coriander leaves and sauté them well.\r\nAdd the yogurt and mix well. I always move the skillet away from the heat when adding yogurt which prevents it from curdling.\r\n\r\nNow after returning the skillet back to the stove, add the washed lamb and salt and ½ cup water and mix well. Cook for 1 hour and cook it covered in medium low heat or put it in a pressure cooker for 6 whistles. If the water is not drained totally, heat it by keeping it open.\r\n\r\nTake another big pan, add thrice the cup of rice you use, and boil it. When it is boiling high, add the rice, salt and jeera and mix well. After 7 minutes exact or when the rice is 80% done. Switch off and drain the rice.\r\n\r\nNow, the layering starts. To the lamb, pat and level it. Add the drained hot rice on the top of it. Garnish with fried onions, ghee, mint, coriander leaves and saffron dissolved in milk.\r\n\r\nCover the dish and bake in a 350f oven for 15 minutes or till the cooked but not mushy. Or cook in the stove medium heat for 12 minutes and lowest heat for 5 minutes. And switch off. Mix and serve hot!\r\nNotes\r\n1. If you are cooking in oven, do make sure to cook in a big oven safe pan and cover it tight and then keep in oven for the final step.\r\n2. You can skip biryani masala if you don’t have and add just garam masala (1 tsp and red chilli powder – 3 tsp instead of 1 tsp)\r\n3. If it is spicy in the end, squeeze some lemon, it will reduce the heat and enhance the flavors also.", "equipment_tags": [], "portions": 3, "prep_minutes": 99, "prep_minutes_source": "explicit", "kcal": 1293, "protein_g": 59.6, "carbs_g": 153.1, "fat_g": 50.6, "total_kcal": 3879, "total_protein_g": 178.8, "total_carbs_g": 459.4, "total_fat_g": 151.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the paste and fry garnishes", "instruction": "Grind the cashew, poppy seeds and cumin seeds into a smooth paste with a little water and set aside. Deep-fry the sliced onions in batches until light brown and crisp, then fry the cashew nuts until golden; drain both on paper towel.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Soak the rice", "instruction": "Wash the rice and soak in water.", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Build the masala", "instruction": "Meanwhile, in a wide pan, fry the sliced onions with the blended paste, green chillies, ginger garlic paste and garlic. Add the tomatoes and sauté until cooked but not mushy, then stir in the chilli powder, biryani powder, mint and coriander.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the lamb", "instruction": "Add the yogurt away from the heat to prevent curdling, then return to the stove and add the washed lamb, salt and water. Cook covered on medium-low heat until tender.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Par-cook the rice", "instruction": "In another pan, bring plenty of water to a boil, add the rice, salt and cumin, and cook until about 80% done, then drain.", "timer_seconds": 420, "background": false}, {"step": 6, "label": "Layer the biryani", "instruction": "Pat the lamb level in its pan, top with the drained rice, and garnish with fried onions, ghee, mint, coriander and the saffron milk.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Steam and serve", "instruction": "Cover and bake in a 350°F oven, or cook on the stovetop on medium then very low heat, until the rice is cooked but not mushy. Mix and serve hot.", "timer_seconds": 900, "background": true}], "video": "https://www.youtube.com/watch?v=r7SYVSG5nxo"}, {"id": "52806", "name": "Tandoori chicken", "category": "Chicken", "area": "India", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qptpvt1487339892.jpg", "local_image": "52806.jpg", "ingredients": [{"ingredient": "lemons", "measure": "2 Juice"}, {"ingredient": "paprika", "measure": "4 tsp"}, {"ingredient": "red onions", "measure": "2 finely chopped"}, {"ingredient": "chicken thighs", "measure": "16 skinnless"}, {"ingredient": "vegetable oil", "measure": "For brushing"}, {"ingredient": "Greek yogurt", "measure": "300ml"}, {"ingredient": "ginger", "measure": "large piece"}, {"ingredient": "garlic clove", "measure": "4"}, {"ingredient": "garam masala", "measure": "¾ tsp"}, {"ingredient": "ground cumin", "measure": "¾ tsp"}, {"ingredient": "chilli powder", "measure": "½ tsp"}, {"ingredient": "turmeric", "measure": "¼ tsp"}], "instructions": "Mix the lemon juice with the paprika and red onions in a large shallow dish. Slash each chicken thigh three times, then turn them in the juice and set aside for 10 mins.\r\nMix all of the marinade ingredients together and pour over the chicken. Give everything a good mix, then cover and chill for at least 1 hr. This can be done up to a day in advance.\r\nHeat the grill. Lift the chicken pieces onto a rack over a baking tray. Brush over a little oil and grill for 8 mins on each side or until lightly charred and completely cooked through.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 78, "prep_minutes_source": "explicit", "kcal": 583, "protein_g": 65.3, "carbs_g": 21.9, "fat_g": 25.8, "total_kcal": 1750, "total_protein_g": 195.8, "total_carbs_g": 65.8, "total_fat_g": 77.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "First marinade", "instruction": "Mix the lemon juice with the paprika and red onions in a large shallow dish. Slash each chicken thigh three times, turn them in the juice, and set aside.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Second marinade and chill", "instruction": "Mix the remaining marinade ingredients together, pour over the chicken, mix well, cover and chill.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Grill", "instruction": "Heat the grill. Lift the chicken onto a rack over a baking tray, brush with a little oil, and grill on each side until lightly charred and completely cooked through.", "timer_seconds": 960, "background": false}], "video": "https://www.youtube.com/watch?v=-CKvt1KNU74"}, {"id": "52807", "name": "Baingan Bharta", "category": "Vegetarian", "area": "India", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/urtpqw1487341253.jpg", "local_image": "52807.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "1 large"}, {"ingredient": "Onion", "measure": "½ cup"}, {"ingredient": "Tomatoes", "measure": "1 cup"}, {"ingredient": "Garlic", "measure": "6 cloves"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Red Chilli Powder", "measure": "¼ teaspoon"}, {"ingredient": "Oil", "measure": "1.5 tablespoon"}, {"ingredient": "Coriander Leaves", "measure": "1 tablespoon chopped"}, {"ingredient": "salt", "measure": "as required"}], "instructions": "Rinse the baingan (eggplant or aubergine) in water. Pat dry with a kitchen napkin. Apply some oil all over and\r\nkeep it for roasting on an open flame. You can also grill the baingan or roast in the oven. But then you won't get\r\nthe smoky flavor of the baingan. Keep the eggplant turning after a 2 to 3 minutes on the flame, so that its evenly\r\ncooked. You could also embed some garlic cloves in the baingan and then roast it.\r\n2. Roast the aubergine till its completely cooked and tender. With a knife check the doneness. The knife should slid\r\neasily in aubergines without any resistance. Remove the baingan and immerse in a bowl of water till it cools\r\ndown.\r\n3. You can also do the dhungar technique of infusing charcoal smoky flavor in the baingan. This is an optional step.\r\nUse natural charcoal for this method. Heat a small piece of charcoal on flame till it becomes smoking hot and red.\r\n4. Make small cuts on the baingan with a knife. Place the red hot charcoal in the same plate where the roasted\r\naubergine is kept. Add a few drops of oil on the charcoal. The charcoal would begin to smoke.\r\n5. As soon as smoke begins to release from the charcoal, cover the entire plate tightly with a large bowl. Allow the\r\ncharcoal smoke to get infused for 1 to 2 minutes. The more you do, the more smoky the baingan bharta will\r\nbecome. I just keep for a minute. Alternatively, you can also do this dhungar method once the baingan bharta is\r\ncooked, just like the way we do for Dal Tadka.\r\n6. Peel the skin from the roasted and smoked eggplant.\r\n7. Chop the cooked eggplant finely or you can even mash it.\r\n8. In a kadai or pan, heat oil. Then add finely chopped onions and garlic.\r\n9. Saute the onions till translucent. Don't brown them.\r\n10. Add chopped green chilies and saute for a minute.\r\n11. Add the chopped tomatoes and mix it well.\r\n12. Bhuno (saute) the tomatoes till the oil starts separating from the mixture.\r\n13. Now add the red chili powder. Stir and mix well.\r\n14. Add the chopped cooked baingan.\r\n15. Stir and mix the chopped baingan very well with the onion­tomato masala mixture.\r\n16. Season with salt. Stir and saute for some more 4 to 5 minutes more.\r\n17. Finally stir in the coriander leaves with the baingan bharta or garnish it with them. Serve Baingan Bharta with\r\nphulkas, rotis or chapatis. It goes well even with bread, toasted or grilled bread and plain rice or jeera rice.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 340, "protein_g": 6.6, "carbs_g": 35.1, "fat_g": 21.9, "total_kcal": 340, "total_protein_g": 6.6, "total_carbs_g": 35.1, "total_fat_g": 21.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the aubergine", "instruction": "Rinse and dry the aubergine, rub with oil, and roast over an open flame (or grill/oven), turning every couple of minutes, until completely tender and a knife slides in easily. Immerse in a bowl of water to cool.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Optional smoking step", "instruction": "For a smoky flavour, make small cuts in the aubergine, place red-hot charcoal on the plate beside it, add a few drops of oil, and cover tightly with a bowl to let the smoke infuse.", "timer_seconds": 90, "background": false}, {"step": 3, "label": "Peel and chop", "instruction": "Peel the skin from the roasted aubergine and chop or mash it finely.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Sauté the aromatics", "instruction": "Heat oil in a pan, add the chopped onions and garlic, and sauté until translucent without browning. Add the green chillies and sauté for a minute.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Cook the tomatoes", "instruction": "Add the tomatoes and cook, stirring, until the oil starts to separate from the mixture.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Combine and finish", "instruction": "Stir in the red chilli powder, then add the chopped aubergine and mix well with the masala. Season with salt and sauté a few more minutes.", "timer_seconds": 300, "background": false}, {"step": 7, "label": "Serve", "instruction": "Stir in the coriander leaves or use as a garnish, and serve with rotis, chapatis, bread or rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=-84Zz2EP4h4"}, {"id": "52808", "name": "Lamb Rogan josh", "category": "Lamb", "area": "India", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vvstvq1487342592.jpg", "local_image": "52808.jpg", "ingredients": [{"ingredient": "Onion", "measure": "2 quartered"}, {"ingredient": "Sunflower Oil", "measure": "4 tbsp"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Ginger", "measure": "Thumb sized peeled and very finely grated"}, {"ingredient": "Madras Paste", "measure": "2 tbsp"}, {"ingredient": "Paprika", "measure": "2 tsp"}, {"ingredient": "cinnamon stick", "measure": "1"}, {"ingredient": "Cardamom", "measure": "6 bashed to break shells"}, {"ingredient": "Cloves", "measure": "4"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Tomato Purée", "measure": "1 tbsp"}, {"ingredient": "Lamb", "measure": "1kg cubed"}, {"ingredient": "Greek yogurt", "measure": "150ml"}, {"ingredient": "Coriander", "measure": "Garnish chopped"}], "instructions": "\r\nPut the onions in a food processor and whizz until very finely chopped. Heat the oil in a large heavy-based pan, then fry the onion with the lid on, stirring every now and then, until it is really golden and soft. Add the garlic and ginger, then fry for 5 mins more.\r\nTip the curry paste, all the spices and the bay leaves into the pan, with the tomato purée. Stir well over the heat for about 30 secs, then add the meat and 300ml water. Stir to mix, turn down the heat, then add the yogurt.\r\nCover the pan, then gently simmer for 40-60 mins until the meat is tender and the sauce nice and thick. Serve scattered with coriander, with plain basmati or pilau rice.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 1272, "protein_g": 90.5, "carbs_g": 18.5, "fat_g": 92.6, "total_kcal": 3816, "total_protein_g": 271.5, "total_carbs_g": 55.5, "total_fat_g": 277.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onions", "instruction": "Finely chop the onions in a food processor. Heat the oil in a large heavy pan and fry the onion with the lid on, stirring occasionally, until really golden and soft. Add the garlic and ginger and fry a few minutes more.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Add the spices", "instruction": "Tip in the curry paste, spices, bay leaves and tomato purée, and stir well over the heat.", "timer_seconds": 30, "background": false}, {"step": 3, "label": "Add the lamb", "instruction": "Add the meat and water, stir to mix, turn down the heat, then stir in the yogurt.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Simmer", "instruction": "Cover the pan and simmer gently until the meat is tender and the sauce is nice and thick.", "timer_seconds": 3000, "background": true}, {"step": 5, "label": "Serve", "instruction": "Serve scattered with coriander, with plain basmati or pilau rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=NZVo32n7iS8"}, {"id": "52809", "name": "Recheado Masala Fish", "category": "Seafood", "area": "India", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/uwxusv1487344500.jpg", "local_image": "52809.jpg", "ingredients": [{"ingredient": "Mackerel", "measure": "4"}, {"ingredient": "Red Chilli", "measure": "18 dried"}, {"ingredient": "Ginger", "measure": "1 inch"}, {"ingredient": "Garlic", "measure": "8 cloves"}, {"ingredient": "Pepper", "measure": "1.5 tsp"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Turmeric", "measure": "½ tsp"}, {"ingredient": "Cinnamon stick", "measure": ""}, {"ingredient": "Cloves", "measure": "4"}, {"ingredient": "Cardamom", "measure": "2"}, {"ingredient": "Sugar", "measure": "1 tbsp"}, {"ingredient": "Tamarind ball", "measure": "2 marble sized"}, {"ingredient": "Vinegar", "measure": "2.5 tbsp"}, {"ingredient": "Oil", "measure": "for frying"}], "instructions": "Soak all the spices, ginger, garlic, tamarind pulp and kashmiri chilies except oil in vinegar.\r\nAdd sugar and salt.\r\nAlso add turmeric powder.\r\nCombine all nicely and marinate for 35-40 mins.\r\nGrind the mixture until soft and smooth. Add more vinegar if required but ensure the paste has to be thick so add vinegar accordingly. If the masala paste is thin then it would not stick to the fish.\r\nRinse the fish slit from the center and give some incision from the top. You could see the fish below for clarity.\r\nNow stuff the paste into the center and into the incision. Coat the entire fish with this paste. Marinate the fish for 30 mins.\r\nPlace oil in a shallow pan, once oil is quite hot shallow fry the stuffed mackerels.\r\nFry until golden brown from both sides\r\nServe the recheado mackerels hot with salad, lime wedges, rice and curry.\r\nNotes\r\n1. Ensure the masala paste is thick else the result won't be good.\r\n2. If you aren't able to find kashmiri chilies then use bedgi chilies or kashmiri red chili powder.\r\n3. You could use white vinegar or coconut vinegar.\r\n4. Any left over paste could be stored in the fridge for future use.\r\n5. Cinnamon could be avoided as it's a strong spice used generally for meat or chicken.", "equipment_tags": [], "portions": 3, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 487, "protein_g": 20.8, "carbs_g": 61.4, "fat_g": 21.5, "total_kcal": 1460, "total_protein_g": 62.4, "total_carbs_g": 184.1, "total_fat_g": 64.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the spice paste ingredients", "instruction": "Soak all the spices, ginger, garlic, tamarind pulp and dried chillies (except the oil) in vinegar, then add sugar, salt and turmeric powder and combine well.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the paste base", "instruction": "Leave the mixture to marinate.", "timer_seconds": 2400, "background": true}, {"step": 3, "label": "Grind the paste", "instruction": "Grind the mixture until soft and smooth, adding more vinegar as needed to keep it thick enough to stick to the fish.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Stuff and coat the fish", "instruction": "Rinse the fish, slit from the centre and make an incision on top. Stuff the paste into the centre and incision, then coat the entire fish with the remaining paste.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Marinate the fish", "instruction": "Leave the stuffed fish to marinate.", "timer_seconds": 1800, "background": true}, {"step": 6, "label": "Fry", "instruction": "Heat oil in a shallow pan until quite hot, then shallow-fry the stuffed mackerels until golden brown on both sides.", "timer_seconds": 600, "background": false}, {"step": 7, "label": "Serve", "instruction": "Serve the recheado mackerels hot with salad, lime wedges, rice and curry.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FXtCris37nE"}, {"id": "52810", "name": "Osso Buco alla Milanese", "category": "Miscellaneous", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wwuqvt1487345467.jpg", "local_image": "52810.jpg", "ingredients": [{"ingredient": "Veal", "measure": "4 meaty shanks"}, {"ingredient": "Flour", "measure": "½ cup"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Butter", "measure": "3 tablespoons"}, {"ingredient": "Onion", "measure": "1 medium chopped into ½-inch pieces"}, {"ingredient": "Carrots", "measure": "1 chopped into ½-inch pieces"}, {"ingredient": "Celery", "measure": "1 chopped into ½-inch pieces"}, {"ingredient": "Fennel", "measure": "1 bulb chopped into ½-inch pieces"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Orange Zest", "measure": "2 strips"}, {"ingredient": "Marjoram", "measure": "1 ½ teaspoons"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Dry White Wine", "measure": "1 cup"}, {"ingredient": "Chicken Stock", "measure": "½ cup"}, {"ingredient": "Tomatoes", "measure": "1 cup chopped with juice"}, {"ingredient": "Parsley", "measure": "2 tablespoons chopped"}, {"ingredient": "Garlic", "measure": "1 teaspoon minced"}, {"ingredient": "Lemon Zest", "measure": "1 teaspoon grated"}], "instructions": "Heat the oven to 300 degrees.\r\nDredging the shanks: pour the flour into a shallow dish (a pie plate works nicely). Season the veal shanks on all sides with salt and pepper. One at a time, roll the shanks around in the flour coat, and shake and pat the shank to remove any excuses flour. Discard the remaining flour.\r\nBrowning the shanks: put the oil and 1 tablespoon of the butter in a wide Dutch oven or heavy braising pot (6 to 7 quart) and heat over medium-high heat. When the butter has melted and the oil is shimmering, lower the shanks into the pot, flat side down; if the shanks won’t fit without touching one another, do this in batches. Brown the shanks, turning once with tongs, until both flat sides are well caramelized, about 5 minutes per side. If the butter-oil mixture starts to burn, lower the heat just a bit. Transfer the shanks to a large platter or tray and set aside.\r\nThe aromatics: pour off and discard the fat from the pot. Wipe out any burnt bits with a damp paper towel, being careful not to remove any delicious little caramelized bits. Ad the remaining 2 tablespoons butter to the pot and melt it over medium heat. When the butter has stopped foaming, add the onion, carrot, celery, and fennel. Season with salt and pepper, stir, and cook the vegetables until they begin to soften but do not brown, about 6 minutes. Stir in the garlic, orange zest, marjoram, and bay leaf, and stew for another minute or two.\r\nThe braising liquid: add the wine, increase the heat to high, and bring to a boil. Boil, stirring occasionally, to reduce the wine by about half, 5 minutes. Add the stock and tomatoes, with their juice, and boil again to reduce the liquid to about 1 cup total, about 10 minutes.\r\nThe braise: Place the shanks in the pot so that they are sitting with the exposed bone facing up, and pour over any juices that accumulated as they sat. Cover with parchment paper, pressing down so the parchment nearly touches the veal and the edges hang over the sides of the pot by about an inch. Cover tightly with the lid, and slide into the lower part of the oven to braise at a gentle simmer. Check the pot after the first 15 minutes, and if the liquid is simmering too aggressively, lower the oven heat by 10 or 15 degrees. Continue braising, turning the shanks and spooning some pan juices over the top after the first 40 minutes, until the meat is completely tender and pulling away from the bone, about 2 hours.\r\nThe gremolata: While the shanks are braising, stir together the garlic, parsley, and lemon zest in a small bowl. Cover with plastic wrap and set aside in a cool place (or the refrigerator, if your kitchen is very warm.)\r\nThe finish: When the veal is fork-tender and falling away from the bone, remove the lid and sprinkle over half of the gremolata. Return the veal to the oven, uncovered, for another 15 minutes to caramelize it some.\r\nUsing a slotted spatula or spoon, carefully lift the shanks from the braising liquid, doing your best to keep them intact. The shanks will be very tender and threatening to fall into pieces, and the marrow will be wobbly inside the bones, so this can be a bit tricky. But if they do break apart, don’t worry, the flavor won’t suffer at all. Arrange the shanks on a serving platter or other large plate, without stacking, and cover with foil to keep warm.\r\nFinishing the sauce: Set the braising pot on top of the stove and evaluate the sauce: if there is a visible layer of fat floating on the surface, use a large spoon to skim it off and discard it. Taste the sauce for concentration of flavor. If it tastes a bit weak or flat, bring it to a boil over high heat, and boil to reduce the volume and intensify the flavor for 5 to 10 minutes. Taste again for salt and pepper. If the sauce wants more zip, stir in a teaspoon or two of the remaining gremolata.\r\nPortioning the veal shanks: if the shanks are reasonably sized, serve one per person. If the shanks are gargantuan or you’re dealing with modest appetites, pull apart the larger shanks, separating them at their natural seams, and serve smaller amounts. Be sure to give the marrow bones to whomever prizes them most.\r\nServing: Arrange the veal shanks on warm dinner plates accompanied by the risotto, if serving. Just before carrying the plates to the table, sprinkle on the remaining gremolata and then spoon over a generous amount of sauce – the contact with the hot liquid will aromatize the gremolata and perk up everyone’s appetite with the whiff of garlic and lemon.", "equipment_tags": [], "portions": 3, "prep_minutes": 226, "prep_minutes_source": "explicit", "kcal": 586, "protein_g": 23.7, "carbs_g": 51.6, "fat_g": 28.1, "total_kcal": 1759, "total_protein_g": 71.0, "total_carbs_g": 154.9, "total_fat_g": 84.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat the oven", "instruction": "Heat the oven to 300°F.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Dredge and brown the shanks", "instruction": "Season the veal shanks and roll them in flour, shaking off excess. Heat oil and butter in a wide Dutch oven and brown the shanks on both flat sides until well caramelised, then set aside.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Cook the aromatics", "instruction": "Pour off the fat, add the remaining butter, and cook the onion, carrot, celery and fennel until beginning to soften but not brown. Stir in the garlic, orange zest, marjoram and bay leaf.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Reduce the braising liquid", "instruction": "Add the wine, bring to a boil and reduce by about half, then add the stock and tomatoes and boil again to reduce the liquid.", "timer_seconds": 900, "background": false}, {"step": 5, "label": "Braise in the oven", "instruction": "Place the shanks bone-up in the pot, cover with parchment and then a tight lid, and braise in the oven, turning and basting after the first 40 minutes, until the meat is completely tender and pulling from the bone.", "timer_seconds": 7200, "background": true}, {"step": 6, "label": "Make the gremolata", "instruction": "While the shanks braise, stir together the garlic, parsley and lemon zest, cover and set aside in a cool place.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Finish and rest", "instruction": "Sprinkle half the gremolata over the veal and return to the oven uncovered to caramelise a little, then carefully lift out the shanks and cover with foil to keep warm.", "timer_seconds": 900, "background": true}, {"step": 8, "label": "Finish the sauce and serve", "instruction": "Skim any fat from the sauce, reduce further if needed for flavour, adjust seasoning, and stir in more gremolata if desired. Serve the shanks with the sauce, sprinkling on the remaining gremolata at the table.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=9GUTC2Qwrf0"}, {"id": "52811", "name": "Ribollita", "category": "Vegetarian", "area": "Italian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/xrrwpx1487347049.jpg", "local_image": "52811.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "5 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "1 chopped"}, {"ingredient": "Celery", "measure": "1 stalk chopped"}, {"ingredient": "Garlic", "measure": "1 tablespoon minced"}, {"ingredient": "Cannellini Beans", "measure": "2 cups"}, {"ingredient": "Canned tomatoes", "measure": "1"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Rosemary", "measure": "1 fresh sprig"}, {"ingredient": "Thyme", "measure": "1 fresh sprig"}, {"ingredient": "Kale", "measure": "1 pound chopped"}, {"ingredient": "Wholegrain Bread", "measure": "4 thick slices"}, {"ingredient": "Red Onions", "measure": "1 thinly sliced"}, {"ingredient": "Parmesan", "measure": "½ cup freshly grated"}], "instructions": "Put 2 tablespoons of the oil in a large pot over medium heat. When it’s hot, add onion, carrot, celery and garlic; sprinkle with salt and pepper and cook, stirring occasionally, until vegetables are soft, 5 to 10 minutes.\r\nHeat the oven to 500 degrees. Drain the beans; if they’re canned, rinse them as well. Add them to the pot along with tomatoes and their juices and stock, rosemary and thyme. Bring to a boil, then reduce heat so the soup bubbles steadily; cover and cook, stirring once or twice to break up the tomatoes, until the flavors meld, 15 to 20 minutes.\r\nFish out and discard rosemary and thyme stems, if you like, and stir in kale. Taste and adjust seasoning. Lay bread slices on top of the stew so they cover the top and overlap as little as possible. Scatter red onion slices over the top, drizzle with the remaining 3 tablespoons oil and sprinkle with Parmesan.\r\nPut the pot in the oven and bake until the bread, onions and cheese are browned and crisp, 10 to 15 minutes. (If your pot fits under the broiler, you can also brown the top there.) Divide the soup and bread among 4 bowls and serve.", "equipment_tags": [], "portions": 6, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 461, "protein_g": 22.4, "carbs_g": 51.9, "fat_g": 20.2, "total_kcal": 2766, "total_protein_g": 134.5, "total_carbs_g": 311.4, "total_fat_g": 121.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the vegetables", "instruction": "Heat 2 tablespoons of the oil in a large pot over medium heat. Add the onion, carrot, celery and garlic, season, and cook, stirring occasionally, until soft.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Simmer the soup base", "instruction": "Heat the oven to 500°F. Add the beans, tomatoes with their juices and stock, rosemary and thyme. Bring to a boil, then reduce to a steady simmer, cover and cook, stirring once or twice, until the flavours meld.", "timer_seconds": 1050, "background": true}, {"step": 3, "label": "Add the kale", "instruction": "Discard the rosemary and thyme stems if you like, then stir in the kale. Taste and adjust seasoning.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Top with bread and cheese", "instruction": "Lay the bread slices over the top of the stew, scatter over the red onion slices, drizzle with the remaining oil, and sprinkle with Parmesan.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake and serve", "instruction": "Put the pot in the oven and bake until the bread, onions and cheese are browned and crisp. Divide among bowls and serve.", "timer_seconds": 750, "background": true}], "video": "https://www.youtube.com/watch?v=BiQUYTBb6eQ"}, {"id": "52812", "name": "Beef Brisket Pot Roast", "category": "Beef", "area": "United States", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/ursuup1487348423.jpg", "local_image": "52812.jpg", "ingredients": [{"ingredient": "Beef Brisket", "measure": "4-5 pound"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Onion", "measure": "3"}, {"ingredient": "Garlic", "measure": "5 cloves"}, {"ingredient": "Thyme", "measure": "1 Sprig"}, {"ingredient": "Rosemary", "measure": "1 sprig"}, {"ingredient": "Bay Leaves", "measure": "4"}, {"ingredient": "beef stock", "measure": "2 cups"}, {"ingredient": "Carrots", "measure": "3 Large"}, {"ingredient": "Mustard", "measure": "1 Tbsp"}, {"ingredient": "Potatoes", "measure": "4 Mashed"}], "instructions": "1 Prepare the brisket for cooking: On one side of the brisket there should be a layer of fat, which you want. If there are any large chunks of fat, cut them off and discard them. Large pieces of fat will not be able to render out completely.\r\nUsing a sharp knife, score the fat in parallel lines, about 3/4-inch apart. Slice through the fat, not the beef. Repeat in the opposite direction to make a cross-hatch pattern.\r\nSalt the brisket well and let it sit at room temperature for 30 minutes.\r\n \r\n2 Sear the brisket: You'll need an oven-proof, thick-bottomed pot with a cover, or Dutch oven, that is just wide enough to hold the brisket roast with a little room for the onions.\r\nPat the brisket dry and place it, fatty side down, into the pot and place it on medium high heat. Cook for 5-8 minutes, lightly sizzling, until the fat side is nicely browned. (If the roast seems to be cooking too fast, turn the heat down to medium. You want a steady sizzle, not a raging sear.)\r\nTurn the brisket over and cook for a few minutes more to brown the other side.\r\n\r\n3 Sauté the onions and garlic: When the brisket has browned, remove it from the pot and set aside. There should be a couple tablespoons of fat rendered in the pot, if not, add some olive oil.\r\nAdd the chopped onions and increase the heat to high. Sprinkle a little salt on the onions. Sauté, stirring often, until the onions are lightly browned, 5-8 minutes. Stir in the garlic and cook 1-2 more minutes.\r\n \r\n4 Return brisket to pot, add herbs, stock, bring to simmer, cover, cook in oven: Preheat the oven to 300°F. Use kitchen twine to tie together the bay leaves, rosemary and thyme.\r\nMove the onions and garlic to the sides of the pot and nestle the brisket inside. Add the beef stock and the tied-up herbs. Bring the stock to a boil on the stovetop.\r\nCover the pot, place the pot in the 300°F oven and cook for 3 hours. Carefully flip the brisket every hour so it cooks evenly.\r\n \r\n5 Add carrots, continue to cook: After 3 hours, add the carrots. Cover the pot and cook for 1 hour more, or until the carrots are cooked through and the brisket is falling-apart tender.\r\n6 Remove brisket to cutting board, tent with foil: When the brisket is falling-apart tender, take the pot out of the oven and remove the brisket to a cutting board. Cover it with foil. Pull out and discard the herbs.\r\n7 Make sauce (optional): At this point you have two options. You can serve as is, or you can make a sauce with the drippings and some of the onions. If you serve as is, skip this step.\r\nTo make a sauce, remove the carrots and half of the onions, set aside and cover them with foil. Pour the ingredients that are remaining into the pot into a blender, and purée until smooth. If you want, add 1 tablespoon of mustard to the mix. Put into a small pot and keep warm.\r\n8 Slice the meat across the grain: Notice the lines of the muscle fibers of the roast. This is the \"grain\" of the meat. Slice the meat perpendicular to these lines, or across the grain (cutting this way further tenderizes the meat), in 1/4-inch to 1/2-inch slices.\r\nServe with the onions, carrots and gravy. Serve with mashed, roasted or boiled potatoes, egg noodles or polenta.", "equipment_tags": ["Blender"], "portions": 8, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 610, "protein_g": 59.6, "carbs_g": 21.9, "fat_g": 31.5, "total_kcal": 4876, "total_protein_g": 476.7, "total_carbs_g": 175.3, "total_fat_g": 252.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the brisket", "instruction": "Trim any large chunks of fat from the brisket, then score the remaining fat in a cross-hatch pattern. Salt well and let sit at room temperature.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Sear the brisket", "instruction": "Pat the brisket dry and place fatty side down in a thick-bottomed pot over medium-high heat. Cook until well browned, then turn and brown the other side.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Sauté the onions and garlic", "instruction": "Remove the brisket and set aside. Add the chopped onions with a little salt to the pot and sauté on high heat until lightly browned, then stir in the garlic and cook a couple more minutes.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Braise in the oven", "instruction": "Preheat the oven to 300°F. Tie the herbs with kitchen twine, nestle the brisket back into the pot with the onions, add the stock and herbs, bring to a boil, cover, and braise in the oven, flipping every hour.", "timer_seconds": 10800, "background": true}, {"step": 5, "label": "Add the carrots", "instruction": "Add the carrots, cover, and continue cooking until the carrots are tender and the brisket is falling-apart tender.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Rest the brisket", "instruction": "Remove the brisket to a cutting board, cover with foil, and discard the herbs.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Make the sauce (optional)", "instruction": "If desired, set aside the carrots and half the onions, then purée the remaining pot contents in a blender until smooth, adding mustard if you like. Keep warm in a small pot.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Slice and serve", "instruction": "Slice the brisket across the grain and serve with the onions, carrots and gravy, alongside mashed, roasted or boiled potatoes, egg noodles or polenta.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=gh48wM6bPWQ"}, {"id": "52813", "name": "Kentucky Fried Chicken", "category": "Chicken", "area": "United States", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/40r49m1763197022.jpg", "local_image": "52813.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1 whole"}, {"ingredient": "Oil", "measure": "2 quarts neutral frying"}, {"ingredient": "Egg White", "measure": "1"}, {"ingredient": "Flour", "measure": "1 1/2 cups"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "1 tablespoon"}, {"ingredient": "paprika", "measure": "1 tablespoon"}, {"ingredient": "onion salt", "measure": "2 teaspoons"}, {"ingredient": "chili powder", "measure": "1 teaspoon"}, {"ingredient": "black pepper", "measure": "1 teaspoon"}, {"ingredient": "celery salt", "measure": "1/2 teaspoon"}, {"ingredient": "sage", "measure": "1/2 teaspoon"}, {"ingredient": "garlic powder", "measure": "1/2 teaspoon"}, {"ingredient": "allspice", "measure": "1/2 teaspoon"}, {"ingredient": "oregano", "measure": "1/2 teaspoon"}, {"ingredient": "basil", "measure": "1/2 teaspoon"}, {"ingredient": "marjoram", "measure": "1/2 teaspoon"}], "instructions": "Preheat fryer to 350°F. Thoroughly mix together all the spice mix ingredients.\r\nCombine spice mix with flour, brown sugar and salt.\r\nDip chicken pieces in egg white to lightly coat them, then transfer to flour mixture. Turn a few times and make sure the flour mix is really stuck to the chicken. Repeat with all the chicken pieces.\r\nLet chicken pieces rest for 5 minutes so crust has a chance to dry a bit.\r\nFry chicken in batches. Breasts and wings should take 12-14 minutes, and legs and thighs will need a few more minutes. Chicken pieces are done when a meat thermometer inserted into the thickest part reads 165°F.\r\nLet chicken drain on a few paper towels when it comes out of the fryer. Serve hot.", "equipment_tags": [], "portions": 4, "prep_minutes": 19, "prep_minutes_source": "explicit", "kcal": 1051, "protein_g": 80.8, "carbs_g": 45.0, "fat_g": 59.0, "total_kcal": 4205, "total_protein_g": 323.2, "total_carbs_g": 180.1, "total_fat_g": 235.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Heat the fryer and mix seasonings", "instruction": "Preheat the fryer to 350°F. Thoroughly mix together all the spice mix ingredients, then combine with the flour, brown sugar and salt.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Coat the chicken", "instruction": "Dip the chicken pieces in egg white to lightly coat, then transfer to the flour mixture, turning to coat thoroughly. Repeat with all the pieces.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Rest the crust", "instruction": "Let the chicken pieces rest so the crust has a chance to dry a bit.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Fry", "instruction": "Fry the chicken in batches until a thermometer in the thickest part reads 165°F — breasts and wings take a bit less time, legs and thighs a bit more.", "timer_seconds": 780, "background": false}, {"step": 5, "label": "Drain and serve", "instruction": "Let the chicken drain on paper towels as it comes out of the fryer. Serve hot.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=PTUxCvCz8Bc"}, {"id": "52814", "name": "Thai Green Curry", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/sstssx1487349585.jpg", "local_image": "52814.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "225g new"}, {"ingredient": "green beans", "measure": "100g"}, {"ingredient": "sunflower oil", "measure": "1 tbsp"}, {"ingredient": "garlic", "measure": "1 clove"}, {"ingredient": "Thai green curry paste", "measure": "4 tsp"}, {"ingredient": "coconut milk", "measure": "400ml"}, {"ingredient": "Thai fish sauce", "measure": "2 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Chicken", "measure": "450g boneless"}, {"ingredient": "lime", "measure": "2 fresh kaffir leaves"}, {"ingredient": "basil", "measure": "handfull"}, {"ingredient": "Rice", "measure": "Boiled"}], "instructions": "Put the potatoes in a pan of boiling water and cook for 5 minutes. Throw in the beans and cook for a further 3 minutes, by which time both should be just tender but not too soft. Drain and put to one side.\r\nIn a wok or large frying pan, heat the oil until very hot, then drop in the garlic and cook until golden, this should take only a few seconds. Don’t let it go very dark or it will spoil the taste. Spoon in the curry paste and stir it around for a few seconds to begin to cook the spices and release all the flavours. Next, pour in the coconut milk and let it come to a bubble.\r\nStir in the fish sauce and sugar, then the pieces of chicken. Turn the heat down to a simmer and cook, covered, for about 8 minutes until the chicken is cooked.\r\nTip in the potatoes and beans and let them warm through in the hot coconut milk, then add a lovely citrussy flavour by stirring in the shredded lime leaves (or lime zest). The basil leaves go in next, but only leave them briefly on the heat or they will quickly lose their brightness. Scatter with the lime garnish and serve immediately with boiled rice.", "equipment_tags": [], "portions": 3, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 709, "protein_g": 38.5, "carbs_g": 38.7, "fat_g": 47.0, "total_kcal": 2126, "total_protein_g": 115.4, "total_carbs_g": 116.1, "total_fat_g": 141.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Par-cook the vegetables", "instruction": "Put the potatoes in a pan of boiling water and cook, then add the beans and cook further, until both are just tender. Drain and set aside.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Fry the garlic and curry paste", "instruction": "In a wok, heat the oil until very hot, drop in the garlic and cook until golden (just a few seconds), then spoon in the curry paste and stir for a few seconds to release the flavours.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Build the curry sauce", "instruction": "Pour in the coconut milk and bring to a bubble, then stir in the fish sauce and sugar.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the chicken", "instruction": "Add the chicken pieces, turn the heat down to a simmer, and cook covered until the chicken is cooked through.", "timer_seconds": 480, "background": false}, {"step": 5, "label": "Finish and serve", "instruction": "Add the potatoes and beans to warm through, stir in the lime leaves briefly, then the basil leaves just before serving. Scatter with lime garnish and serve immediately with boiled rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=LIbKVpBQKJI"}, {"id": "52815", "name": "French Lentils With Garlic and Thyme", "category": "Miscellaneous", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vwwspt1487394060.jpg", "local_image": "52815.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "3 tablespoons"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "French Lentils", "measure": "2 1/4 cups"}, {"ingredient": "Thyme", "measure": "1 teaspoon"}, {"ingredient": "Bay Leaf", "measure": "3"}, {"ingredient": "Salt", "measure": "1 tablespoon"}, {"ingredient": "Celery", "measure": "2 sticks"}], "instructions": "Place a large saucepan over medium heat and add oil. When hot, add chopped vegetables and sauté until softened, 5 to 10 minutes.\r\nAdd 6 cups water, lentils, thyme, bay leaves and salt. Bring to a boil, then reduce to a fast simmer.\r\nSimmer lentils until they are tender and have absorbed most of the water, 20 to 25 minutes. If necessary, drain any excess water after lentils have cooked. Serve immediately, or allow them to cool and reheat later.\r\nFor a fuller taste, use some chicken stock and reduce the water by the same amount.", "equipment_tags": [], "portions": 2, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 540, "protein_g": 25.6, "carbs_g": 64.2, "fat_g": 22.0, "total_kcal": 1079, "total_protein_g": 51.2, "total_carbs_g": 128.4, "total_fat_g": 44.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sauté the vegetables", "instruction": "Heat the oil in a large saucepan over medium heat, add the chopped vegetables, and sauté until softened.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Simmer the lentils", "instruction": "Add the water, lentils, thyme, bay leaves and salt. Bring to a boil, then reduce to a fast simmer and cook until the lentils are tender and have absorbed most of the water.", "timer_seconds": 1350, "background": true}, {"step": 3, "label": "Finish and serve", "instruction": "Drain any excess water if needed. Serve immediately, or cool and reheat later.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=CrlTS1mJQMA"}, {"id": "52816", "name": "Roasted Eggplant With Tahini, Pine Nuts, and Lentils", "category": "Vegetarian", "area": "United States", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ysqrus1487425681.jpg", "local_image": "52816.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Carrots", "measure": "2 small cut into chunks"}, {"ingredient": "Celery", "measure": "2 small stalks"}, {"ingredient": "Onion", "measure": "1 medium finely diced"}, {"ingredient": "Garlic", "measure": "6 medium cloves sliced"}, {"ingredient": "Brown Lentils", "measure": "12 ounces (340g)"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Apple Cider Vinegar", "measure": "2 teaspoons (10ml)"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Egg Plants", "measure": "2 large"}, {"ingredient": "Rosemary", "measure": "4 sprigs"}, {"ingredient": "Pine nuts", "measure": "1/4 cup"}, {"ingredient": "Parsley", "measure": "2 tablespoons"}], "instructions": "\r\nFor the Lentils: Adjust oven rack to center position and preheat oven to 450°F to prepare for roasting eggplant. Meanwhile, heat 2 tablespoons olive oil in a medium saucepan over medium heat until shimmering. Add carrots, celery, and onion and cook, stirring, until softened but not browned, about 4 minutes. Add garlic and cook, stirring, until fragrant, about 30 seconds. Add lentils, bay leaves, stock or water, and a pinch of salt. Bring to a simmer, cover with the lid partially ajar, and cook until lentils are tender, about 30 minutes. (Top up with water if lentils are at any point not fully submerged.) Remove lid, stir in vinegar, and reduce until lentils are moist but not soupy. Season to taste with salt and pepper, cover, and keep warm until ready to serve.\r\n\r\n2.\r\nFor the Eggplant: While lentils cook, cut each eggplant in half. Score flesh with the tip of a paring knife in a cross-hatch pattern at 1-inch intervals. Transfer to a foil-lined rimmed baking sheet, cut side up, and brush each eggplant half with 1 tablespoon oil, letting each brushstroke be fully absorbed before brushing with more. Season with salt and pepper. Place a rosemary sprig on top of each one. Transfer to oven and roast until completely tender and well charred, 25 to 35 minutes. Remove from oven and discard rosemary.\r\n\r\n3.\r\nTo Serve: Heat 2 tablespoons olive oil and pine nuts in a medium skillet set over medium heat. Cook, tossing nuts frequently, until golden brown and aromatic, about 4 minutes. Transfer to a bowl to halt cooking. Stir half of parsley and rosemary into lentils and transfer to a serving platter. Arrange eggplant halves on top. Spread a few tablespoons of tahini sauce over each eggplant half and sprinkle with pine nuts. Sprinkle with remaining parsley and rosemary, drizzle with additional olive oil, and serve.", "equipment_tags": [], "portions": 4, "prep_minutes": 73, "prep_minutes_source": "explicit", "kcal": 442, "protein_g": 18.9, "carbs_g": 51.4, "fat_g": 20.6, "total_kcal": 1768, "total_protein_g": 75.4, "total_carbs_g": 205.5, "total_fat_g": 82.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Start the lentils", "instruction": "Preheat the oven to 450°F. Heat the oil in a saucepan and cook the carrots, celery and onion, stirring, until softened, then add the garlic and cook until fragrant.", "timer_seconds": 270, "background": false}, {"step": 2, "label": "Simmer the lentils", "instruction": "Add the lentils, bay leaves, water and a pinch of salt, bring to a simmer, cover partially, and cook until the lentils are tender, topping up with water if needed.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Score and roast the eggplant", "instruction": "While the lentils cook, halve the eggplants and score the flesh in a cross-hatch pattern. Brush with oil, season, top with rosemary sprigs, and roast until completely tender and well charred.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Finish the lentils", "instruction": "Remove the lid from the lentils, stir in the vinegar, and reduce until moist but not soupy. Season to taste, cover and keep warm.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Toast the pine nuts", "instruction": "Heat oil and pine nuts in a skillet over medium heat and toss frequently until golden brown and aromatic.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Assemble and serve", "instruction": "Discard the rosemary from the eggplant. Stir half the parsley and rosemary into the lentils and transfer to a platter, arrange the eggplant halves on top, spread with tahini sauce, sprinkle with pine nuts and remaining herbs, and drizzle with olive oil.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=HkywCtna9t0"}, {"id": "52817", "name": "Stovetop Eggplant With Harissa, Chickpeas, and Cumin Yogurt", "category": "Vegetarian", "area": "United States", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/yqwtvu1487426027.jpg", "local_image": "52817.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Egg Plants", "measure": "6 small"}, {"ingredient": "Harissa Spice", "measure": "½ tablespoon"}, {"ingredient": "Chickpeas", "measure": "1 can"}, {"ingredient": "Cherry Tomatoes", "measure": "2 cups halved"}, {"ingredient": "Greek yogurt", "measure": "1 1/2 cups"}, {"ingredient": "Ground cumin", "measure": "1 tablespoon"}, {"ingredient": "Parsley", "measure": "½ cup"}], "instructions": "Heat the oil in a 12-inch skillet over high heat until shimmering. Add the eggplants and lower the heat to medium. Season with salt and pepper as you rotate the eggplants, browning them on all sides. Continue to cook, turning regularly, until a fork inserted into the eggplant meets no resistance (you may have to stand them up on their fat end to finish cooking the thickest parts), about 20 minutes, lowering the heat and sprinkling water into the pan as necessary if the eggplants threaten to burn or smoke excessively.\r\n\r\n2.\r\nMix the harissa, chickpeas and tomatoes together, then add to the eggplants. Cook until the tomatoes have blistered and broken down, about 5 minutes more. Season with salt and pepper and add water as necessary to thin to a saucy consistency. Meanwhile, combine the yogurt and cumin in a serving bowl. Season with salt and pepper.\r\n\r\n3.\r\nTop the eggplant mixture with the parsley, drizzle with more extra virgin olive oil, and serve with the yogurt on the side.", "equipment_tags": [], "portions": 3, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 705, "protein_g": 39.3, "carbs_g": 53.6, "fat_g": 39.8, "total_kcal": 2116, "total_protein_g": 117.8, "total_carbs_g": 160.9, "total_fat_g": 119.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the eggplants", "instruction": "Heat the oil in a large skillet over high heat, add the eggplants, lower the heat to medium, and cook, turning and seasoning regularly, until a fork meets no resistance, standing them on end to finish the thickest parts, and adding a splash of water if they threaten to burn.", "timer_seconds": 1200, "background": false}, {"step": 2, "label": "Add the harissa and chickpeas", "instruction": "Mix the harissa, chickpeas and tomatoes together, add to the eggplants, and cook until the tomatoes have blistered and broken down, thinning with water as needed.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Make the cumin yogurt", "instruction": "Meanwhile, combine the yogurt and cumin in a serving bowl and season with salt and pepper.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Top the eggplant mixture with parsley, drizzle with olive oil, and serve with the cumin yogurt on the side.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=uYB-1xJp4lg"}, {"id": "52818", "name": "Chicken Fajita Mac and Cheese", "category": "Chicken", "area": "United States", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qrqywr1503066605.jpg", "local_image": "52818.jpg", "ingredients": [{"ingredient": "macaroni", "measure": "500g"}, {"ingredient": "chicken stock", "measure": "2 cups"}, {"ingredient": "heavy cream", "measure": "1/2 cup"}, {"ingredient": "fajita seasoning", "measure": "1 packet"}, {"ingredient": "salt", "measure": "1 tsp"}, {"ingredient": "chicken breast", "measure": "3 diced"}, {"ingredient": "olive oil", "measure": "2 tbsp"}, {"ingredient": "onion", "measure": "1 small finely diced"}, {"ingredient": "red pepper", "measure": "2 finely diced"}, {"ingredient": "garlic", "measure": "2 cloves minced"}, {"ingredient": "cheddar cheese", "measure": "1 cup"}, {"ingredient": "parsley", "measure": "garnish chopped"}], "instructions": "Fry your onion, peppers and garlic in olive oil until nicely translucent. Make a well in your veg and add your chicken. Add your seasoning and salt. Allow to colour slightly.\r\nAdd your cream, stock and macaroni.\r\nCook on low for 20 minutes. Add your cheeses, stir to combine.\r\nTop with roasted peppers and parsley.", "equipment_tags": [], "portions": 4, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 1128, "protein_g": 61.1, "carbs_g": 112.2, "fat_g": 47.6, "total_kcal": 4511, "total_protein_g": 244.5, "total_carbs_g": 448.9, "total_fat_g": 190.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sauté the vegetables and chicken", "instruction": "Fry the onion, peppers and garlic in olive oil until translucent. Make a well in the middle, add the chicken, season with the fajita seasoning and salt, and cook until lightly coloured.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Simmer the macaroni", "instruction": "Add the cream, stock and macaroni, and cook on low heat, stirring occasionally.", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Finish with cheese", "instruction": "Stir in the cheddar cheese until combined.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Top with roasted peppers and chopped parsley.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=bwTSmLTZKNg"}, {"id": "52819", "name": "Cajun spiced fish tacos", "category": "Seafood", "area": "Mexican", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/uvuyxu1503067369.jpg", "local_image": "52819.jpg", "ingredients": [{"ingredient": "cajun", "measure": "2 tbsp"}, {"ingredient": "cayenne pepper", "measure": "1 tsp"}, {"ingredient": "white fish", "measure": "4 fillets"}, {"ingredient": "vegetable oil", "measure": "1 tsp"}, {"ingredient": "flour tortilla", "measure": "8"}, {"ingredient": "avocado", "measure": "1 sliced"}, {"ingredient": "little gem lettuce", "measure": "2 shredded"}, {"ingredient": "Spring Onions", "measure": "4 shredded"}, {"ingredient": "salsa", "measure": "1 x 300ml"}, {"ingredient": "sour cream", "measure": "1 pot"}, {"ingredient": "lemon", "measure": "1"}, {"ingredient": "garlic", "measure": "1 clove finely chopped"}], "instructions": "Cooking in a cajun spice and cayenne pepper marinade makes this fish super succulent and flavoursome. Top with a zesty dressing and serve in a tortilla for a quick, fuss-free main that's delightfully summery.\r\n\r\nOn a large plate, mix the cajun spice and cayenne pepper with a little seasoning and use to coat the fish all over.\r\n\r\nHeat a little oil in a frying pan, add in the fish and cook over a medium heat until golden. Reduce the heat and continue frying until the fish is cooked through, about 10 minutes. Cook in batches if you don’t have enough room in the pan.\r\n\r\nMeanwhile, prepare the dressing by combining all the ingredients with a little seasoning.\r\nSoften the tortillas by heating in the microwave for 5-10 seconds. Pile high with the avocado, lettuce and spring onion, add a spoonful of salsa, top with large flakes of fish and drizzle over the dressing.", "equipment_tags": [], "portions": 4, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 560, "protein_g": 39.2, "carbs_g": 67.0, "fat_g": 14.4, "total_kcal": 2238, "total_protein_g": 156.7, "total_carbs_g": 268.0, "total_fat_g": 57.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Coat the fish", "instruction": "Mix the cajun spice and cayenne pepper with a little seasoning on a large plate and use to coat the fish all over.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the fish", "instruction": "Heat a little oil in a frying pan, add the fish, and cook over medium heat until golden, then reduce the heat and continue frying until cooked through, in batches if needed.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Make the dressing", "instruction": "While the fish cooks, prepare the dressing by combining all the dressing ingredients with a little seasoning.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Warm the tortillas", "instruction": "Soften the tortillas by heating briefly in the microwave.", "timer_seconds": 10, "background": false}, {"step": 5, "label": "Assemble and serve", "instruction": "Pile the tortillas with avocado, lettuce and spring onion, add a spoonful of salsa, top with flaked fish, and drizzle with the dressing.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=N4EdUt0Ou48"}, {"id": "52820", "name": "Katsu Chicken curry", "category": "Chicken", "area": "Japanese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/vwrpps1503068729.jpg", "local_image": "52820.jpg", "ingredients": [{"ingredient": "chicken breast", "measure": "4 pounded to 1cm thickness"}, {"ingredient": "plain flour", "measure": "2 tablespoons"}, {"ingredient": "egg", "measure": "1 beaten"}, {"ingredient": "breadcrumbs", "measure": "100g fine"}, {"ingredient": "vegetable oil", "measure": "230ml frying"}, {"ingredient": "sunflower oil", "measure": "2 tablespoons"}, {"ingredient": "onions", "measure": "2 sliced"}, {"ingredient": "garlic", "measure": "5 chopped cloves"}, {"ingredient": "carrot", "measure": "2 sliced"}, {"ingredient": "plain flour", "measure": "2 tablespoons"}, {"ingredient": "curry powder", "measure": "4 teaspoons"}, {"ingredient": "chicken stock", "measure": "600ml"}, {"ingredient": "honey", "measure": "2 teaspoons"}, {"ingredient": "soy sauce", "measure": "4 teaspoons"}, {"ingredient": "bay leaf", "measure": "1"}, {"ingredient": "garam masala", "measure": "1 teaspoon"}], "instructions": "Prep:15min  ›  Cook:30min  ›  Ready in:45min \r\n\r\nFor the curry sauce: Heat oil in medium non-stick saucepan, add onion and garlic and cook until softened. Stir in carrots and cook over low heat for 10 to 12 minutes.\r\nAdd flour and curry powder; cook for 1 minute. Gradually stir in stock until combined; add honey, soy sauce and bay leaf. Slowly bring to the boil.\r\nTurn down heat and simmer for 20 minutes or until sauce thickens but is still of pouring consistency. Stir in garam masala. Pour the curry sauce through a sieve; return to saucepan and keep on low heat until ready to serve.\r\nFor the chicken: Season both sides of chicken breasts with salt and pepper. Place flour, egg and breadcrumbs in separate bowls and arrange in a row. Coat the chicken breasts in flour, then dip them into the egg, then coat in breadcrumbs, making sure you cover both sides.\r\nHeat oil in large frying pan over medium-high heat. Place chicken into hot oil and cook until golden brown, about 3 or 4 minutes each side. Once cooked, place on kitchen paper to absorb excess oil.\r\nPour curry sauce over chicken, serve with white rice and enjoy!", "equipment_tags": [], "portions": 4, "prep_minutes": 127, "prep_minutes_source": "explicit", "kcal": 593, "protein_g": 46.4, "carbs_g": 60.6, "fat_g": 19.2, "total_kcal": 2372, "total_protein_g": 185.4, "total_carbs_g": 242.4, "total_fat_g": 76.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Start the curry sauce", "instruction": "Heat oil in a saucepan, add the onion and garlic, and cook until softened. Stir in the carrots and cook over low heat.", "timer_seconds": 660, "background": false}, {"step": 2, "label": "Thicken the sauce base", "instruction": "Add the flour and curry powder and cook for 1 minute, then gradually stir in the stock until combined. Add the honey, soy sauce and bay leaf, and slowly bring to a boil.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Simmer the sauce", "instruction": "Turn down the heat and simmer until the sauce thickens but is still pourable. Stir in the garam masala, then pass through a sieve and keep warm on low heat.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Bread the chicken", "instruction": "Season the chicken breasts with salt and pepper. Coat each in flour, then egg, then breadcrumbs, covering both sides.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fry the chicken", "instruction": "Heat oil in a large frying pan over medium-high heat and cook the chicken until golden brown on both sides, then drain on kitchen paper.", "timer_seconds": 480, "background": false}, {"step": 6, "label": "Serve", "instruction": "Slice the chicken, pour the curry sauce over the top, and serve with white rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=MWzxDFRtVbc"}, {"id": "52821", "name": "Laksa King Prawn Noodles", "category": "Seafood", "area": "Malaysian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/rvypwy1503069308.jpg", "local_image": "52821.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbsp"}, {"ingredient": "Red Chilli", "measure": "1 finely sliced"}, {"ingredient": "Thai red curry paste", "measure": "2 ½ tbsp"}, {"ingredient": "vegetable stock cube", "measure": "1"}, {"ingredient": "coconut milk", "measure": "400ml can"}, {"ingredient": "fish sauce", "measure": "2 tsp"}, {"ingredient": "rice noodles", "measure": "100g"}, {"ingredient": "lime", "measure": "2 juice of 1, the other halved"}, {"ingredient": "king prawns", "measure": "150g"}, {"ingredient": "coriander", "measure": "½ small pack"}], "instructions": "Heat the oil in a medium saucepan and add the chilli. Cook for 1 min, then add the curry paste, stir and cook for 1 min more. Dissolve the stock cube in a large jug in 700ml boiling water, then pour into the pan and stir to combine. Tip in the coconut milk and bring to the boil.\r\nAdd the fish sauce and a little seasoning. Toss in the noodles and cook for a further 3-4 mins until softening. Squeeze in the lime juice, add the prawns and cook through until warm, about 2-3 mins. Scatter over some of the coriander.\r\nServe in bowls with the remaining coriander and lime wedges on top for squeezing over.", "equipment_tags": [], "portions": 2, "prep_minutes": 9, "prep_minutes_source": "explicit", "kcal": 859, "protein_g": 25.7, "carbs_g": 70.9, "fat_g": 57.9, "total_kcal": 1717, "total_protein_g": 51.4, "total_carbs_g": 141.8, "total_fat_g": 115.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Build the curry base", "instruction": "Heat the oil in a medium saucepan and add the chilli, cooking for a minute, then add the curry paste and cook for a minute more.", "timer_seconds": 120, "background": false}, {"step": 2, "label": "Add the broth", "instruction": "Dissolve the stock cube in boiling water in a jug, then pour into the pan and stir to combine. Add the coconut milk and bring to a boil.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the noodles", "instruction": "Add the fish sauce and seasoning, toss in the noodles, and cook until softening.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Finish and serve", "instruction": "Squeeze in the lime juice, add the prawns, and cook through until warm. Scatter with some coriander and serve in bowls with the remaining coriander and lime wedges.", "timer_seconds": 150, "background": false}], "video": "https://www.youtube.com/watch?v=OcarztU8cYo"}, {"id": "52822", "name": "Toad In The Hole", "category": "Pork", "area": "British", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/ytuvwr1503070420.jpg", "local_image": "52822.jpg", "ingredients": [{"ingredient": "sausages", "measure": "8"}, {"ingredient": "vegetable oil", "measure": "3 tbsp"}, {"ingredient": "plain flour", "measure": "100g"}, {"ingredient": "eggs", "measure": "2 medium"}, {"ingredient": "horseradish", "measure": "1 tbsp grated"}, {"ingredient": "milk", "measure": "225ml"}, {"ingredient": "cherry tomatoes", "measure": "200g"}], "instructions": "Preheat the oven to 200°C/fan180°C/gas 6. fry sausages in a non-stick pan until browned.\r\nDrizzle vegetable oil in a 30cm x 25cm x 6cm deep roasting tray and heat in the oven for 5 minutes.\r\nPut the plain flour in a bowl, crack in the medium free-range eggs, then stir in the grated horseradish. Gradually beat in the semi-skimmed milk. Season.\r\nPut the sausages into the hot roasting tray and pour over the batter. Top with cherry tomatoes on the vine and cook for 30 minutes until puffed and golden.", "equipment_tags": [], "portions": 2, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 1127, "protein_g": 42.1, "carbs_g": 54.7, "fat_g": 82.2, "total_kcal": 2253, "total_protein_g": 84.2, "total_carbs_g": 109.4, "total_fat_g": 164.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and brown the sausages", "instruction": "Preheat the oven to 200°C/fan180°C/gas 6. Fry the sausages in a non-stick pan until browned.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Heat the roasting tray", "instruction": "Drizzle oil into a deep roasting tray and heat it in the oven.", "timer_seconds": 300, "background": true}, {"step": 3, "label": "Make the batter", "instruction": "While the tray heats, put the flour in a bowl, crack in the eggs, and stir in the grated horseradish. Gradually beat in the milk until smooth, then season.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Put the browned sausages into the hot tray and pour over the batter. Top with cherry tomatoes and bake until puffed and golden.", "timer_seconds": 1800, "background": true}], "video": "https://www.youtube.com/watch?v=t1dWkDrC330"}, {"id": "52823", "name": "Salmon Prawn Risotto", "category": "Seafood", "area": "Italian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/xxrxux1503070723.jpg", "local_image": "52823.jpg", "ingredients": [{"ingredient": "butter", "measure": "50g/2oz"}, {"ingredient": "onion", "measure": "1 finely chopped"}, {"ingredient": "rice", "measure": "150g"}, {"ingredient": "white wine", "measure": "125ml"}, {"ingredient": "vegetable stock", "measure": "1 litre hot"}, {"ingredient": "lemon", "measure": "The juice and zest of one"}, {"ingredient": "King Prawns", "measure": "240g large"}, {"ingredient": "salmon", "measure": "150g"}, {"ingredient": "asparagus", "measure": "100g tips blanched briefly in boiling water"}, {"ingredient": "black pepper", "measure": "ground"}, {"ingredient": "Parmesan", "measure": "50g shavings"}], "instructions": "Melt the butter in a thick-based pan and gently cook the onion without colour until it is soft.\r\nAdd the rice and stir to coat all the grains in the butter\r\nAdd the wine and cook gently stirring until it is absorbed\r\nGradually add the hot stock, stirring until each addition is absorbed. Keep stirring until the rice is tender\r\nSeason with the lemon juice and zest, and pepper to taste. (there will probably be sufficient saltiness from the salmon to not need to add salt) Stir gently to heat through\r\nServe scattered with the Parmesan and seasonal vegetables.\r\nGrill the salmon and gently place onto the risotto with the prawns and asparagus", "equipment_tags": ["Grill"], "portions": 10, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 187, "protein_g": 11.7, "carbs_g": 15.0, "fat_g": 7.8, "total_kcal": 1865, "total_protein_g": 117.1, "total_carbs_g": 150.4, "total_fat_g": 78.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Melt the butter in a thick-based pan and gently cook the onion, without colouring, until soft.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Toast the rice", "instruction": "Add the rice and stir to coat all the grains in the butter.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Deglaze with wine", "instruction": "Add the wine and cook gently, stirring, until absorbed.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Add the stock gradually", "instruction": "Gradually add the hot stock, stirring until each addition is absorbed before adding more, until the rice is tender.", "timer_seconds": 1200, "background": false}, {"step": 5, "label": "Season the risotto", "instruction": "Season with the lemon juice and zest and pepper to taste (the salmon should provide enough saltiness), and stir gently to heat through.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Grill the salmon", "instruction": "While the risotto finishes, grill the salmon until cooked through.", "timer_seconds": 480, "background": false}, {"step": 7, "label": "Serve", "instruction": "Scatter the risotto with Parmesan, then gently place the salmon on top with the prawns and blanched asparagus tips.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=V2PMvBv52IE"}, {"id": "52824", "name": "Beef Sunday Roast", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/ssrrrs1503664277.jpg", "local_image": "52824.jpg", "ingredients": [{"ingredient": "Beef", "measure": "8 slices"}, {"ingredient": "Broccoli", "measure": "12 florets"}, {"ingredient": "Potatoes", "measure": "1 Packet"}, {"ingredient": "Carrots", "measure": "1 Packet"}, {"ingredient": "plain flour", "measure": "140g"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "milk", "measure": "200ml"}, {"ingredient": "sunflower oil", "measure": "drizzle (for cooking)"}], "instructions": "Cook the Broccoli and Carrots in a pan of boiling water until tender.\r\n\r\nRoast the Beef and Potatoes in the oven for 45mins, the potatoes may need to be checked regularly to not overcook.\r\n\r\nTo make the Yorkshire puddings:\r\nHeat oven to 230C/fan 210C/gas 8. Drizzle a little sunflower oil evenly into 2 x 4-hole Yorkshire pudding tins or a 12-hole non-stick muffin tin and place in the oven to heat through\r\nTo make the batter, tip 140g plain flour into a bowl and beat in four eggs until smooth. Gradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper. Pour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes. Place the tins back in the oven and leave undisturbed for 20-25 mins until the puddings have puffed up and browned. Serve immediately.\r\n\r\nPlate up and add the Gravy as desired.", "equipment_tags": [], "portions": 3, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 622, "protein_g": 35.4, "carbs_g": 62.4, "fat_g": 27.6, "total_kcal": 1865, "total_protein_g": 106.1, "total_carbs_g": 187.2, "total_fat_g": 82.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the vegetables", "instruction": "Cook the broccoli and carrots in a pan of boiling water until tender.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Roast the beef and potatoes", "instruction": "Roast the beef and potatoes in the oven, checking the potatoes regularly so they don't overcook.", "timer_seconds": 2700, "background": true}, {"step": 3, "label": "Heat the pudding tins", "instruction": "For the Yorkshire puddings, heat the oven to 230°C/fan 210°C/gas 8, drizzle a little oil into the pudding tins, and place them in the oven to heat through.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the batter", "instruction": "Tip the flour into a bowl and beat in the eggs until smooth, then gradually beat in the milk until lump-free. Season with salt and pepper and pour into a jug.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake the puddings", "instruction": "Remove the hot tins from the oven, carefully and evenly pour in the batter, then return to the oven and leave undisturbed until puffed up and browned.", "timer_seconds": 1350, "background": true}, {"step": 6, "label": "Serve", "instruction": "Plate up the beef, vegetables and Yorkshire puddings, and add gravy as desired.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=2l3-dBdNehY"}, {"id": "52826", "name": "Braised Beef Chilli", "category": "Beef", "area": "Mexican", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/uuqvwu1504629254.jpg", "local_image": "52826.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1kg"}, {"ingredient": "Onions", "measure": "3"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Olive oil", "measure": "Dash"}, {"ingredient": "Chorizo", "measure": "300g"}, {"ingredient": "Cumin", "measure": "2 tsp"}, {"ingredient": "Allspice", "measure": "2 tsp"}, {"ingredient": "Cloves", "measure": "1 tsp"}, {"ingredient": "Cinnamon stick", "measure": "1 large"}, {"ingredient": "Bay Leaves", "measure": "3"}, {"ingredient": "Oregano", "measure": "2 tsp dried"}, {"ingredient": "Ancho Chillies", "measure": "2 ancho"}, {"ingredient": "Balsamic Vinegar", "measure": "3 tbsp"}, {"ingredient": "Plum Tomatoes", "measure": "2 x 400g"}, {"ingredient": "Tomato Ketchup", "measure": "2 tbsp"}, {"ingredient": "Dark Brown Sugar", "measure": "2 tbsp"}, {"ingredient": "Borlotti Beans", "measure": "2 x 400g tins"}], "instructions": "Preheat the oven to 120C/225F/gas mark 1.\r\n\r\nTake the meat out of the fridge to de-chill. Pulse the onions and garlic in a food processor until finely chopped. Heat 2 tbsp olive oil in a large casserole and sear the meat on all sides until golden.\r\n\r\nSet to one side and add another small slug of oil to brown the chorizo. Remove and add the onion and garlic, spices, herbs and chillies then cook until soft in the chorizo oil. Season with salt and pepper and add the vinegar, tomatoes, ketchup and sugar.\r\n\r\nPut all the meat back into the pot with 400ml water (or red wine if you prefer), bring up to a simmer and cook, covered, in the low oven.\r\n\r\nAfter 2 hours, check the meat and add the beans. Cook for a further hour and just before serving, pull the meat apart with a pair of forks.", "equipment_tags": ["FoodProcessor"], "portions": 5, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 883, "protein_g": 66.2, "carbs_g": 51.0, "fat_g": 48.1, "total_kcal": 4413, "total_protein_g": 330.9, "total_carbs_g": 255.0, "total_fat_g": 240.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat the oven", "instruction": "Preheat the oven to 120°C/225°F/gas mark 1.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Sear the beef", "instruction": "Pulse the onions and garlic in a food processor until finely chopped. Heat oil in a large casserole and sear the meat on all sides until golden, then set aside.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Brown the chorizo and build the base", "instruction": "Add a little more oil to brown the chorizo, then remove and add the onion, garlic, spices, herbs and chillies, cooking until soft in the chorizo oil. Season and add the vinegar, tomatoes, ketchup and sugar.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Braise", "instruction": "Return all the meat to the pot with water (or red wine), bring to a simmer, cover, and cook in the low oven.", "timer_seconds": 7200, "background": true}, {"step": 5, "label": "Add the beans", "instruction": "Check the meat and add the beans, then continue cooking.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Finish and serve", "instruction": "Just before serving, pull the meat apart with two forks.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=z4kSoJgsu6Y"}, {"id": "52827", "name": "Massaman Beef curry", "category": "Beef", "area": "Thai", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/tvttqv1504640475.jpg", "local_image": "52827.jpg", "ingredients": [{"ingredient": "Peanuts", "measure": "85g"}, {"ingredient": "Coconut cream", "measure": "400ml can"}, {"ingredient": "Massaman curry paste", "measure": "4 tbsp"}, {"ingredient": "Beef", "measure": "600g stewing cut into strips"}, {"ingredient": "Potatoes", "measure": "450g waxy"}, {"ingredient": "Onion", "measure": "1 cut thin wedges"}, {"ingredient": "Lime", "measure": "4 leaves"}, {"ingredient": "Cinnamon stick", "measure": "1"}, {"ingredient": "Tamarind paste", "measure": "1 tbsp"}, {"ingredient": "Brown sugar", "measure": "1 tbsp palm or soft light"}, {"ingredient": "Fish Sauce", "measure": "1 tbsp"}, {"ingredient": "chilli", "measure": "1 red deseeded and finely sliced, to serve"}, {"ingredient": "Jasmine Rice", "measure": "to serve"}], "instructions": "Heat oven to 200C/180C fan/gas 6, then roast the peanuts on a baking tray for 5 mins until golden brown. When cool enough to handle, roughly chop. Reduce oven to 180C/160C fan/gas 4.\r\nHeat 2 tbsp coconut cream in a large casserole dish with a lid. Add the curry paste and fry for 1 min, then stir in the beef and fry until well coated and sealed. Stir in the rest of the coconut with half a can of water, the potatoes, onion, lime leaves, cinnamon, tamarind, sugar, fish sauce and most of the peanuts. Bring to a simmer, then cover and cook for 2 hrs in the oven until the beef is tender.\r\nSprinkle with sliced chilli and the remaining peanuts, then serve straight from the dish with jasmine rice.", "equipment_tags": [], "portions": 4, "prep_minutes": 126, "prep_minutes_source": "explicit", "kcal": 1223, "protein_g": 46.5, "carbs_g": 65.1, "fat_g": 92.8, "total_kcal": 4890, "total_protein_g": 186.2, "total_carbs_g": 260.4, "total_fat_g": 371.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the peanuts", "instruction": "Heat the oven to 200°C/180°C fan/gas 6 and roast the peanuts on a baking tray until golden brown, then roughly chop once cool. Reduce the oven to 180°C/160°C fan/gas 4.", "timer_seconds": 300, "background": true}, {"step": 2, "label": "Fry the curry paste", "instruction": "Heat a little coconut cream in a large casserole dish, add the curry paste and fry for a minute, then stir in the beef and fry until well coated and sealed.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Build the curry", "instruction": "Stir in the rest of the coconut cream with water, the potatoes, onion, lime leaves, cinnamon, tamarind, sugar, fish sauce and most of the peanuts. Bring to a simmer.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Braise in the oven", "instruction": "Cover and cook in the oven until the beef is tender.", "timer_seconds": 7200, "background": true}, {"step": 5, "label": "Serve", "instruction": "Sprinkle with sliced chilli and the remaining peanuts, then serve straight from the dish with jasmine rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=mVxgZSCU9_g"}, {"id": "52828", "name": "Vietnamese Grilled Pork (bun-thit-nuong)", "category": "Pork", "area": "Vietnamese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/qqwypw1504642429.jpg", "local_image": "52828.jpg", "ingredients": [{"ingredient": "Pork", "measure": "1.5 pounds sliced"}, {"ingredient": "Rice Vermicelli", "measure": "1 package thin"}, {"ingredient": "Egg Rolls", "measure": "4-6"}, {"ingredient": "Challots", "measure": "3 tablespoons minced"}, {"ingredient": "Garlic", "measure": "1.5 tablespoons minced garlic"}, {"ingredient": "Sugar", "measure": "¼ cup"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Soy sauce", "measure": "½ tablespoon thick"}, {"ingredient": "Pepper", "measure": "½ tablespoon"}, {"ingredient": "Olive Oil", "measure": "3 tablespoons"}, {"ingredient": "Cucumber", "measure": "Sliced"}, {"ingredient": "Mint", "measure": "Leaves"}, {"ingredient": "Peanuts", "measure": "Crushed"}], "instructions": "Slice the uncooked pork thinly, about ⅛\". It helps to slightly freeze it (optional).\r\nMince garlic and shallots. Mix in a bowl with sugar, fish sauce, thick soy sauce, pepper, and oil until sugar dissolves.\r\nMarinate the meat for 1 hour, or overnight for better results.\r\nBake the pork at 375F for 10-15 minutes or until about 80% cooked. Finish cooking by broiling in the oven until a nice golden brown color develops, flipping the pieces midway.\r\nAssemble your bowl with veggies, noodles, and garnish. Many like to mix the whole bowl up and pour the fish sauce on top, but I like to make individual bites and sauce it slowly.", "equipment_tags": [], "portions": 2, "prep_minutes": 75, "prep_minutes_source": "explicit", "kcal": 1194, "protein_g": 88.9, "carbs_g": 60.6, "fat_g": 65.7, "total_kcal": 2388, "total_protein_g": 177.7, "total_carbs_g": 121.1, "total_fat_g": 131.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Slice and marinate the pork", "instruction": "Slice the pork thinly (slightly freezing it first makes this easier). Mix the minced garlic and shallots with the sugar, fish sauce, thick soy sauce, pepper and oil until the sugar dissolves, then coat the pork in the marinade.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate", "instruction": "Marinate the meat, ideally overnight for best results.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Bake and broil the pork", "instruction": "Bake the pork at 375°F until about 80% cooked, then finish under the broiler until golden brown, flipping midway.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Assemble and serve", "instruction": "Assemble the bowls with vermicelli noodles, egg rolls, cucumber, mint and the pork. Sauce as you like and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Q3qcQcENzbU"}, {"id": "52829", "name": "Grilled Mac and Cheese Sandwich", "category": "Pasta", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xutquv1505330523.jpg", "local_image": "52829.jpg", "ingredients": [{"ingredient": "Macaroni", "measure": "8 ounces (230 grams)"}, {"ingredient": "Plain Flour", "measure": "1/3 cup"}, {"ingredient": "Mustard Powder", "measure": "3/4 teaspoon"}, {"ingredient": "Garlic powder", "measure": "1/2 teaspoon"}, {"ingredient": "Kosher salt", "measure": "1/2 teaspoon"}, {"ingredient": "Black pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Cayenne pepper", "measure": "1/8 teaspoon"}, {"ingredient": "Butter", "measure": "6 tablespoons (85 grams)"}, {"ingredient": "Whole Milk", "measure": "1 1/2 cups (360 milliliters)"}, {"ingredient": "Heavy Cream", "measure": "1 cup (240 milliliters)"}, {"ingredient": "Monterey Jack Cheese", "measure": "1 pound (455 grams)"}, {"ingredient": "Butter", "measure": "4 tablespoons (55 grams)"}, {"ingredient": "garlic powder", "measure": "1 teaspoon"}, {"ingredient": "Bread", "measure": "16 slices square"}, {"ingredient": "Cheddar Cheese", "measure": "8 slices mild"}, {"ingredient": "Colby Jack Cheese", "measure": "8 slices"}, {"ingredient": "Butter", "measure": "4 tablespoons (55 grams)"}], "instructions": "Make the mac and cheese\r\n\r\n1. Bring a medium saucepan of generously salted water (you want it to taste like seawater) to a boil. Add the pasta and cook, stirring occasionally, until al dente, 8 to 10 minutes, or according to the package directions. The pasta should be tender but still chewy.\r\n2. While the pasta is cooking, in a small bowl, whisk together the flour, mustard powder, garlic powder, salt, black pepper, and cayenne pepper.\r\n3. Drain the pasta in a colander. Place the empty pasta pan (no need to wash it) over low heat and add the butter. When the butter has melted, whisk in the flour mixture and continue to cook, whisking frequently, until the mixture is beginning to brown and has a pleasant, nutty aroma, about 1 minute. Watch carefully so it does not scorch on the bottom of the pan.\r\n4. Slowly whisk the milk and cream into the flour mixture until everything is really well combined. Cook, whisking constantly, until the sauce is heated through and just begins to thicken, about 2 minutes. Remove from the heat. Gradually add the cheese while stirring constantly with a wooden spoon or silicone spatula and keep stirring until the cheese has melted into the sauce. Then stir in the drained cooked pasta.\r\n5. Line a 9-by-13-inch (23-by-33-centimeter) rimmed baking sheet with parchment paper or aluminum foil. Coat the paper or foil with nonstick cooking spray or slick it with butter. Pour the warm mac and cheese onto the prepared baking sheet and spread it evenly with a spatula. Coat another piece of parchment paper with cooking spray or butter and place it, oiled or buttered side down, directly on the surface of the mac and cheese. Refrigerate until cool and firm, about 1 hour.\r\n\r\nMake the grilled cheese\r\n6. Heat a large cast-iron or nonstick skillet over medium-low heat.\r\n7. In a small bowl, stir together the 4 tablespoons (55 grams) butter and garlic powder until well blended.\r\n8. Remove the mac and cheese from the refrigerator and peel off the top layer of parchment paper. Carefully cut into 8 equal pieces. Each piece will make 1 grilled mac and cheese sandwich. (You can stash each individual portion in a double layer of resealable plastic bags and refrigerate for up to 3 days or freeze it for up to 1 month.)\r\n9. Spread 3/4 teaspoon garlic butter on one side of each bread slice. Place half of the slices, buttered-side down, on a clean cutting board. Top each with one slice of Cheddar, then 1 piece of the mac and cheese. (Transfer from the baking sheet by scooting your hand or a spatula under each piece of mac and cheese and then flipping it over onto a sandwich.) Place 1 slice of Jack on top of each. Finish with the remaining bread slices, buttered-side up.\r\n10. Using a wide spatula, place as many sandwiches in the pan as will fit without crowding it. Cover and cook until the bottoms are nicely browned, about 4 minutes. Turn and cook until the second sides are browned, the cheese is melted, and the mac and cheese is heated through, about 4 minutes more.\r\n11. Repeat with the remaining ingredients. Cut the sandwiches in half, if desired, and serve.", "equipment_tags": ["Grill"], "portions": 12, "prep_minutes": 81, "prep_minutes_source": "explicit", "kcal": 670, "protein_g": 24.9, "carbs_g": 36.7, "fat_g": 47.2, "total_kcal": 8038, "total_protein_g": 298.3, "total_carbs_g": 440.0, "total_fat_g": 566.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the pasta", "instruction": "Bring a pan of well-salted water to a boil, add the macaroni, and cook, stirring occasionally, until al dente.", "timer_seconds": 540, "background": false}, {"step": 2, "label": "Mix the seasoned flour", "instruction": "While the pasta cooks, whisk together the flour, mustard powder, garlic powder, salt, black pepper and cayenne pepper.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the roux", "instruction": "Drain the pasta. In the same pan over low heat, melt the butter, whisk in the flour mixture, and cook, whisking, until beginning to brown and smelling nutty.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Build the cheese sauce", "instruction": "Slowly whisk in the milk and cream until combined, and cook, whisking, until just beginning to thicken. Remove from the heat and gradually stir in the cheese until melted, then stir in the drained pasta.", "timer_seconds": 120, "background": false}, {"step": 5, "label": "Chill the mac and cheese", "instruction": "Spread the mac and cheese evenly onto a lined baking sheet, press another sheet of parchment directly on top, and refrigerate until cool and firm.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Prep for grilling", "instruction": "Heat a large skillet over medium-low heat. Mix the remaining butter with garlic powder. Cut the chilled mac and cheese into 8 equal pieces.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Assemble the sandwiches", "instruction": "Spread garlic butter on one side of each bread slice. Layer buttered-side down bread with Cheddar, a piece of mac and cheese, and Jack cheese, then top with the remaining bread buttered-side up.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Grill and serve", "instruction": "Cook the sandwiches in the skillet, covered, until the bottoms are browned, then flip and cook the other side until browned, the cheese is melted, and the mac and cheese is heated through. Repeat with remaining sandwiches, cut in half if desired, and serve.", "timer_seconds": 480, "background": false}], "video": "https://www.youtube.com/watch?v=PYq31xLj-DY"}, {"id": "52830", "name": "Crock Pot Chicken Baked Tacos", "category": "Chicken", "area": "Mexican", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/ypxvwv1505333929.jpg", "local_image": "52830.jpg", "ingredients": [{"ingredient": "Chicken Breasts", "measure": "4 - 6"}, {"ingredient": "Vinaigrette Dressing", "measure": "1 bottle"}, {"ingredient": "Cumin", "measure": "1½ tablespoon"}, {"ingredient": "Smoked Paprika", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "1 teaspoon"}, {"ingredient": "Refried Beans", "measure": "1 can"}, {"ingredient": "Hard Taco Shells", "measure": "12"}, {"ingredient": "Shredded Mexican Cheese", "measure": "2 cups"}, {"ingredient": "Grape Tomatoes", "measure": "Halved"}, {"ingredient": "Jalapeno", "measure": "Sliced and Seeded"}, {"ingredient": "Avocado", "measure": "Peeled and Sliced"}, {"ingredient": "Green Salsa", "measure": "2 tablespoons"}, {"ingredient": "Sour Cream", "measure": "3 tablespoons"}, {"ingredient": "Milk", "measure": "1 tablespoon"}], "instructions": "Put the uncooked chicken breasts in the crock pot. Pour the full bottle of salad dressing over the chicken. Sprinkle the rest of the ingredients over the top and mix them in a bit with a spoon.\r\nCover your crock pot with the lid and cook on high for 4 hours.\r\nRemove all the chicken breasts from the crock pot and let cool.\r\nShred the chicken breasts and move to a glass bowl.\r\nPour most of the liquid over the shredded chicken.\r\nFOR THE TACOS:\r\nMake the guacamole sauce by mixing the avocado and green salsa together. Pour the guacamole mixture through a strainer until smooth and transfer to a squeeze bottle. Cut the tip off the lid of the squeeze bottle to make the opening more wide if needed.\r\nMake the sour cream sauce by mixing the sour cream and milk together until you get a more liquid sour cream sauce. Transfer to a squeeze bottle.\r\nIn a 9x 13 glass baking dish, fill all 12+ tacos with a layer of refried beans, cooked chicken and shredded cheese.\r\nBake at 450 for 10-15 minutes just until the cheese is melted and bubbling.\r\nOut of the oven top all the tacos with the sliced grape tomaotes, jalapeno and cilantro.\r\nFinish with a drizzle of guacamole and sour cream.\r\nEnjoy!", "equipment_tags": ["SlowCooker"], "portions": 5, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 1209, "protein_g": 64.4, "carbs_g": 92.7, "fat_g": 63.6, "total_kcal": 6043, "total_protein_g": 322.0, "total_carbs_g": 463.7, "total_fat_g": 318.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Load the crock pot", "instruction": "Put the uncooked chicken breasts in the crock pot, pour over the salad dressing, and sprinkle over the cumin, paprika and garlic, mixing in a bit with a spoon.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Slow cook the chicken", "instruction": "Cover and cook on high.", "timer_seconds": 14400, "background": true}, {"step": 3, "label": "Shred the chicken", "instruction": "Remove the chicken and let cool, then shred and transfer to a bowl. Pour most of the liquid over the shredded chicken.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the sauces", "instruction": "Mix the avocado and green salsa, strain until smooth, and transfer to a squeeze bottle for the guacamole sauce. Mix the sour cream and milk into a pourable consistency and transfer to another squeeze bottle.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fill and bake the tacos", "instruction": "Fill each taco shell with a layer of refried beans, shredded chicken and cheese in a baking dish, then bake until the cheese is melted and bubbling.", "timer_seconds": 750, "background": true}, {"step": 6, "label": "Finish and serve", "instruction": "Top the tacos with grape tomatoes, jalapeño and cilantro, then finish with a drizzle of the guacamole and sour cream sauces.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=oqL0mLDBzS4"}, {"id": "52831", "name": "Chicken Karaage", "category": "Chicken", "area": "Japanese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/tyywsw1505930373.jpg", "local_image": "52831.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "450 grams Boneless skin"}, {"ingredient": "Ginger", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Soy sauce", "measure": "2 tablespoons"}, {"ingredient": "Sake", "measure": "1 tablespoon"}, {"ingredient": "Granulated sugar", "measure": "2 teaspoon"}, {"ingredient": "Potato starch", "measure": "1/3 cup"}, {"ingredient": "Vegetable oil", "measure": "1/3 cup"}, {"ingredient": "Lemon", "measure": "1/3 cup"}], "instructions": "Add the ginger, garlic, soy sauce, sake and sugar to a bowl and whisk to combine. Add the chicken, then stir to coat evenly. Cover and refrigerate for at least 1 hour.\r\n\r\nAdd 1 inch of vegetable oil to a heavy bottomed pot and heat until the oil reaches 360 degrees F. Line a wire rack with 2 sheets of paper towels and get your tongs out. Put the potato starch in a bowl\r\n\r\nAdd a handful of chicken to the potato starch and toss to coat each piece evenly.\r\n\r\nFry the karaage in batches until the exterior is a medium brown and the chicken is cooked through. Transfer the fried chicken to the paper towel lined rack. If you want the karaage to stay crispy longer, you can fry the chicken a second time, until it's a darker color after it's cooled off once. Serve with lemon wedges.", "equipment_tags": [], "portions": 2, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 748, "protein_g": 50.0, "carbs_g": 17.7, "fat_g": 51.7, "total_kcal": 1496, "total_protein_g": 99.9, "total_carbs_g": 35.5, "total_fat_g": 103.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the chicken", "instruction": "Whisk the ginger, garlic, soy sauce, sake and sugar together in a bowl. Add the chicken, stir to coat, cover and refrigerate.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Heat the oil", "instruction": "Add oil to a heavy-bottomed pot and heat to 360°F. Line a wire rack with paper towels and set out potato starch in a bowl.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Coat the chicken", "instruction": "Toss a handful of the marinated chicken at a time in the potato starch to coat each piece evenly.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fry", "instruction": "Fry the karaage in batches until medium brown and cooked through, transferring to the rack. For extra crispness, fry a second time once cooled.", "timer_seconds": 480, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve with lemon wedges.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=XivddFddthc"}, {"id": "52832", "name": "Coq au vin", "category": "Chicken", "area": "France", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qstyvs1505931190.jpg", "local_image": "52832.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1½ tbsp"}, {"ingredient": "Bacon", "measure": "3 rashers (100g) chopped dry-cured"}, {"ingredient": "Shallots", "measure": "12 small"}, {"ingredient": "Chicken Legs", "measure": "2 (460g)"}, {"ingredient": "Chicken Thighs", "measure": "4 (650g)"}, {"ingredient": "Chicken Breasts", "measure": "2 (280g)"}, {"ingredient": "Garlic", "measure": "3 finely chopped"}, {"ingredient": "Brandy", "measure": "3 tbsp"}, {"ingredient": "Red Wine", "measure": "600ml"}, {"ingredient": "Chicken Stock", "measure": "150ml"}, {"ingredient": "tomato puree", "measure": "2 tsp"}, {"ingredient": "thyme", "measure": "3 sprigs"}, {"ingredient": "Rosemary", "measure": "2 sprigs"}, {"ingredient": "bay leaves", "measure": "2"}, {"ingredient": "parsley", "measure": "garnish"}, {"ingredient": "chestnut mushroom", "measure": "250g"}, {"ingredient": "plain flour", "measure": "2 tbsp"}, {"ingredient": "butter", "measure": "1 tsp"}], "instructions": "Heat 1 tbsp of the oil in a large, heavy-based saucepan or flameproof dish. Tip in the bacon and fry until crisp. Remove and drain on kitchen paper. Add the shallots to the pan and fry, stirring or shaking the pan often, for 5-8 mins until well browned all over. Remove and set aside with the bacon.\r\nPat the chicken pieces dry with kitchen paper. Pour the remaining oil into the pan, then fry half the chicken pieces, turning regularly, for 5-8 mins until well browned. Remove, then repeat with the remaining chicken. Remove and set aside.\r\nScatter in the garlic and fry briefly, then, with the heat medium-high, pour in the brandy or Cognac, stirring the bottom of the pan to deglaze. The alcohol should sizzle and start to evaporate so there is not much left.\r\nReturn the chicken legs and thighs to the pan along with any juices, then pour in a little of the wine, stirring the bottom of the pan again. Stir in the rest of the wine, the stock and tomato purée, drop in the bouquet garni, season with pepper and a pinch of salt, then return the bacon and shallots to the pan. Cover, lower the heat to a gentle simmer, add the chicken breasts and cook for 50 mins-1hr.\r\nJust before ready to serve, heat the oil for the mushrooms in a large non-stick frying pan. Add the mushrooms and fry over a high heat for a few mins until golden. Remove and keep warm.\r\nLift the chicken, shallots and bacon from the pan and transfer to a warmed serving dish. Remove the bouquet garni. To make the thickener, mix the flour, olive oil and butter in a small bowl using the back of a teaspoon. Bring the wine mixture to a gentle boil, then gradually drop in small pieces of the thickener, whisking each piece in using a wire whisk. Simmer for 1-2 mins. Scatter the mushrooms over the chicken, then pour over the wine sauce. Garnish with chopped parsley.", "equipment_tags": [], "portions": 7, "prep_minutes": 128, "prep_minutes_source": "explicit", "kcal": 606, "protein_g": 52.0, "carbs_g": 27.9, "fat_g": 22.6, "total_kcal": 4239, "total_protein_g": 363.8, "total_carbs_g": 195.2, "total_fat_g": 158.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Crisp the bacon and shallots", "instruction": "Heat oil in a large heavy pan, fry the bacon until crisp, then remove and drain. Add the shallots and fry, shaking the pan, until well browned all over, then remove and set aside with the bacon.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Brown the chicken", "instruction": "Pat the chicken dry, add the remaining oil, and fry the chicken pieces in batches, turning regularly, until well browned, then remove and set aside.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Deglaze with brandy", "instruction": "Fry the garlic briefly, then pour in the brandy over medium-high heat, stirring to deglaze the pan, and let the alcohol sizzle off.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Braise", "instruction": "Return the chicken legs and thighs to the pan with any juices, add the wine, stock, tomato purée and bouquet garni, season, and return the bacon and shallots. Cover, add the chicken breasts, and simmer gently until tender.", "timer_seconds": 3300, "background": true}, {"step": 5, "label": "Fry the mushrooms", "instruction": "Just before serving, heat oil in a separate pan and fry the mushrooms over high heat until golden, then remove and keep warm.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Thicken the sauce", "instruction": "Lift the chicken, shallots and bacon into a warmed serving dish and remove the bouquet garni. Mix the flour, oil and butter into a paste, bring the wine mixture to a gentle boil, and whisk in small pieces of the paste to thicken. Simmer briefly.", "timer_seconds": 90, "background": false}, {"step": 7, "label": "Serve", "instruction": "Scatter the mushrooms over the chicken, pour over the sauce, and garnish with chopped parsley.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_ise46LADBs"}, {"id": "52833", "name": "Salted Caramel Cheescake", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xqrwyr1511133646.jpg", "local_image": "52833.jpg", "ingredients": [{"ingredient": "Digestive Biscuits", "measure": "250g"}, {"ingredient": "Pretzels", "measure": "75g"}, {"ingredient": "Butter", "measure": "135g"}, {"ingredient": "Cream Cheese", "measure": "450g"}, {"ingredient": "Vanilla Extract", "measure": "1tsp"}, {"ingredient": "Icing Sugar", "measure": "100g"}, {"ingredient": "Caramel", "measure": "150g"}, {"ingredient": "Sea Salt", "measure": "1tsp"}, {"ingredient": "Double Cream", "measure": "300ml"}, {"ingredient": "Caramel Sauce", "measure": "drizzle"}, {"ingredient": "Toffee Popcorn", "measure": "Top"}, {"ingredient": "Pretzels", "measure": "Top"}], "instructions": "1) Blitz the biscuits and the pretzels in a food processor and mix the biscuits with the melted butter. Spread on the bottom of an 8″/20cm Deep Springform Tin and press down firmly. Leave to set in the fridge whilst you make the rest!\r\n\r\n2) Using an electric mixer, I use my KitchenAid with the whisk attachment, whisk together the cream cheese, vanilla, and icing sugar until smooth and then add the caramel and whisk again until smooth and lump free – this could take a couple of minutes, I whisk it at half speed so not too quick or slow!\r\n\r\n3) Pour in the double cream & Salt flakes and continue to whisk for a couple of minutes until its very thick and mousse like (I mix it on a medium speed, level 6/10) – Now this could take up to 5 minutes depending on your mixer, but you seriously have to stick at it – it will hold itself completely when finished mixing (like a meringue does!) If you don’t mix it enough it will not set well enough, but don’t get impatient and whisk it really quick because that’ll make it split! Spread over the biscuit base and leave to set in the fridge overnight.\r\n\r\n4) Remove the Cheesecake from the tin carefully and decorate the cheesecake – I drizzled over some of the spare caramel, and then some Toffee Popcorn and more Pretzels!", "equipment_tags": ["FoodProcessor"], "portions": 10, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 667, "protein_g": 6.4, "carbs_g": 55.9, "fat_g": 47.7, "total_kcal": 6665, "total_protein_g": 64.3, "total_carbs_g": 559.2, "total_fat_g": 477.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and chill the base", "instruction": "Blitz the biscuits and pretzels in a food processor and mix with the melted butter. Press into the base of a deep springform tin and chill while you make the filling.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Whip the cream cheese filling", "instruction": "Using an electric mixer, whisk the cream cheese, vanilla and icing sugar until smooth, then add the caramel and whisk again until smooth and lump-free.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Whip to a mousse texture", "instruction": "Pour in the double cream and sea salt, and continue whisking at medium speed until thick and mousse-like — it should hold its shape when finished.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Set", "instruction": "Spread the filling over the biscuit base and leave to set in the fridge overnight.", "timer_seconds": 43200, "background": true}, {"step": 5, "label": "Decorate and serve", "instruction": "Carefully remove the cheesecake from the tin and decorate with a drizzle of caramel, toffee popcorn and more pretzels.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=q5dQp3qpmI4"}, {"id": "52834", "name": "Beef stroganoff", "category": "Beef", "area": "Russian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/svprys1511176755.jpg", "local_image": "52834.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbls"}, {"ingredient": "Onions", "measure": "1"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Butter", "measure": "1 tbsp"}, {"ingredient": "Mushrooms", "measure": "250g"}, {"ingredient": "Beef Fillet", "measure": "500g"}, {"ingredient": "Plain Flour", "measure": "1tbsp"}, {"ingredient": "Creme Fraiche", "measure": "150g"}, {"ingredient": "English Mustard", "measure": "1 tbsp"}, {"ingredient": "Beef Stock", "measure": "100ml"}, {"ingredient": "Parsley", "measure": "Topping"}], "instructions": "Heat the olive oil in a non-stick frying pan then add the sliced onion and cook on a medium heat until completely softened, so around 15 mins, adding a little splash of water if they start to stick at all. Crush in the garlic and cook for a 2-3 mins further, then add the butter. Once the butter is foaming a little, add the mushrooms and cook for around 5 mins until completely softened. Season everything well, then tip onto a plate.\r\nTip the flour into a bowl with a big pinch of salt and pepper, then toss the steak in the seasoned flour. Add the steak pieces to the pan, splashing in a little oil if the pan looks particularly dry, and fry for 3-4 mins, until well coloured. Tip the onions and mushrooms back into the pan. Whisk the crème fraîche, mustard and beef stock together, then pour into the pan. Cook over a medium heat for around 5 mins. Scatter with parsley, then serve with pappardelle or rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 1021, "protein_g": 57.9, "carbs_g": 17.0, "fat_g": 81.7, "total_kcal": 2041, "total_protein_g": 115.7, "total_carbs_g": 34.1, "total_fat_g": 163.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onions and mushrooms", "instruction": "Heat the oil in a non-stick frying pan and cook the sliced onion on medium heat until completely softened, adding a splash of water if it sticks. Crush in the garlic and cook a couple minutes more, then add the butter and mushrooms and cook until softened. Season and tip onto a plate.", "timer_seconds": 1320, "background": false}, {"step": 2, "label": "Sear the steak", "instruction": "Toss the steak pieces in seasoned flour, then fry in the same pan, adding a little oil if dry, until well coloured.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Finish the sauce", "instruction": "Return the onions and mushrooms to the pan. Whisk the crème fraîche, mustard and beef stock together, pour in, and cook over medium heat until the sauce comes together.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Serve", "instruction": "Scatter with parsley and serve with pappardelle or rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=PQHgQX1Ss74"}, {"id": "52835", "name": "Fettucine alfredo", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uquqtu1511178042.jpg", "local_image": "52835.jpg", "ingredients": [{"ingredient": "Clotted Cream", "measure": "227g"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Corn Flour", "measure": "1 tsp"}, {"ingredient": "Parmesan Cheese", "measure": "100g"}, {"ingredient": "Nutmeg", "measure": "Grated"}, {"ingredient": "Fettuccine", "measure": "250g"}, {"ingredient": "Parsley", "measure": "Chopped"}], "instructions": "In a medium saucepan, stir the clotted cream, butter and cornflour over a low-ish heat and bring to a low simmer. Turn off the heat and keep warm.\r\nMeanwhile, put the cheese and nutmeg in a small bowl and add a good grinding of black pepper, then stir everything together (don’t add any salt at this stage).\r\nPut the pasta in another pan with 2 tsp salt, pour over some boiling water and cook following pack instructions (usually 3-4 mins). When cooked, scoop some of the cooking water into a heatproof jug or mug and drain the pasta, but not too thoroughly.\r\nAdd the pasta to the pan with the clotted cream mixture, then sprinkle over the cheese and gently fold everything together over a low heat using a rubber spatula. When combined, splash in 3 tbsp of the cooking water. At first, the pasta will look wet and sloppy: keep stirring until the water is absorbed and the sauce is glossy. Check the seasoning before transferring to heated bowls. Sprinkle over some chives or parsley, then serve immediately.", "equipment_tags": [], "portions": 4, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 724, "protein_g": 18.8, "carbs_g": 50.6, "fat_g": 49.4, "total_kcal": 2894, "total_protein_g": 75.3, "total_carbs_g": 202.5, "total_fat_g": 197.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the cream base", "instruction": "In a medium saucepan, stir the clotted cream, butter and cornflour over a low-ish heat and bring to a low simmer, then turn off the heat and keep warm.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Prep the cheese", "instruction": "Meanwhile, mix the Parmesan and nutmeg in a small bowl with a good grinding of black pepper (no salt yet).", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the fettuccine", "instruction": "Cook the pasta in salted boiling water following pack instructions, then scoop out some cooking water before draining, keeping the pasta a little wet.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Combine and emulsify", "instruction": "Add the pasta to the cream mixture, sprinkle over the cheese, and gently fold together over low heat, splashing in the reserved cooking water and stirring until the sauce turns glossy.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Serve", "instruction": "Check the seasoning, transfer to heated bowls, and sprinkle with chives or parsley to serve immediately.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FLEnwZvGzOE"}, {"id": "52836", "name": "Seafood fideuà", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/wqqvyq1511179730.jpg", "local_image": "52836.jpg", "ingredients": [{"ingredient": "Mussels", "measure": "400g"}, {"ingredient": "Prawns", "measure": "8"}, {"ingredient": "Saffron", "measure": "2 pinches"}, {"ingredient": "Vermicelli Pasta", "measure": "350g"}, {"ingredient": "Olive Oil", "measure": "5 tblsp"}, {"ingredient": "Onions", "measure": "1 large"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Paprika", "measure": "2 tbs"}, {"ingredient": "Monkfish", "measure": "1 tail"}, {"ingredient": "Baby Squid", "measure": "4"}, {"ingredient": "Fish Stock", "measure": "650ml"}, {"ingredient": "Tomatoes", "measure": "2 large"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Parsley", "measure": "Topping"}], "instructions": "Boil the kettle. Empty the mussels into a colander and run under cold water. Throw away any with broken shells. Pick through the shells, tapping each one on the side of the sink – they should be closed or should slowly close when tapped – if they stay open, throw them away. If any of the shells still have barnacles or stringy beards attached, pull them off with a cutlery knife and rinse the shells well. Keep in the colander, covered with a cold, damp cloth, until you’re ready to cook. Peel the prawn shells on the body section only – leave the heads and tails intact. Score down the backs and pull out any gritty entrails. Chill until you’re ready to cook.\r\nPut the saffron in a small cup, cover with 50ml kettle-hot water and set aside for 10 mins. If using vermicelli, put in a bowl and crush to little pieces (about 1cm long) with your hands.\r\nHeat the oil in a large frying pan with at least a 3cm lip, or a 40cm paella pan. Add the onion and stir around the pan for 5 mins until soft. Add the garlic and cook for 1 min more, then tip in the vermicelli and cook for 5 mins, stirring from time to time, until the vermicelli is toasted brown. Stir in the paprika.\r\nKeeping the heat moderate, stir through the monkfish, squid and saffron with its water, seasoning well. Spread the ingredients out in an even layer, then pour over the hot stock and scatter the tomatoes on top. Bring to a simmer, then cover the whole dish with a tight-fitting lid (or foil). Turn the heat to medium and cook for 6 mins.\r\nUncover and stir to incorporate the dry top layer of pasta. Push the mussels into the pasta so the hinges are buried in the bottom of the dish, and they stand straight up. Arrange the prawns on top, cover tightly and cook for another 6 mins or until the mussels are open, the prawns are pink and the pasta is cooked through. Leave to simmer for another 2-3 mins to cook off most of the remaining liquid (leave a little in the pan to prevent the pasta from sticking together). Allow to sit for 2-3 mins, then squeeze over the lemon juice and arrange the wedges on top. Scatter with parsley before serving.", "equipment_tags": [], "portions": 5, "prep_minutes": 39, "prep_minutes_source": "explicit", "kcal": 610, "protein_g": 44.9, "carbs_g": 66.3, "fat_g": 18.8, "total_kcal": 3048, "total_protein_g": 224.6, "total_carbs_g": 331.4, "total_fat_g": 94.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the shellfish", "instruction": "Rinse the mussels under cold water, discarding any with broken or open shells, and remove any beards. Peel the prawn body shells, leaving heads and tails on, and devein. Chill both until needed.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Steep the saffron", "instruction": "Put the saffron in a cup, cover with hot water, and set aside. If using vermicelli, crush it into small pieces.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Toast the vermicelli", "instruction": "Heat the oil in a large frying pan or paella pan, cook the onion until soft, then add the garlic and cook a minute more. Tip in the vermicelli and cook, stirring occasionally, until toasted brown, then stir in the paprika.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Add fish and stock", "instruction": "Stir through the monkfish, squid and saffron water, season, then spread in an even layer. Pour over the hot stock, scatter with tomatoes, bring to a simmer, cover tightly and cook.", "timer_seconds": 360, "background": true}, {"step": 5, "label": "Add the shellfish", "instruction": "Uncover and stir to incorporate the dry top layer. Push the mussels hinge-down into the pasta, arrange the prawns on top, cover tightly and cook until the mussels open, the prawns are pink, and the pasta is cooked through.", "timer_seconds": 360, "background": true}, {"step": 6, "label": "Rest and serve", "instruction": "Let simmer briefly to cook off excess liquid, then let sit before squeezing over the lemon juice and scattering with parsley.", "timer_seconds": 180, "background": false}], "video": "https://www.youtube.com/watch?v=itsFEc8W468"}, {"id": "52837", "name": "Pilchard puttanesca", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vvtvtr1511180578.jpg", "local_image": "52837.jpg", "ingredients": [{"ingredient": "Spaghetti", "measure": "300g"}, {"ingredient": "Olive Oil", "measure": "1 tbls"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Red Chilli", "measure": "1"}, {"ingredient": "Tomato Puree", "measure": "1 tbls"}, {"ingredient": "Pilchards", "measure": "425g"}, {"ingredient": "Black Olives", "measure": "70g"}, {"ingredient": "Parmesan", "measure": "Shaved"}], "instructions": "Cook the pasta following pack instructions. Heat the oil in a non-stick frying pan and cook the onion, garlic and chilli for 3-4 mins to soften. Stir in the tomato purée and cook for 1 min, then add the pilchards with their sauce. Cook, breaking up the fish with a wooden spoon, then add the olives and continue to cook for a few more mins.\r\n\r\nDrain the pasta and add to the pan with 2-3 tbsp of the cooking water. Toss everything together well, then divide between plates and serve, scattered with Parmesan.", "equipment_tags": [], "portions": 8, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 316, "protein_g": 17.9, "carbs_g": 33.3, "fat_g": 12.4, "total_kcal": 2532, "total_protein_g": 142.8, "total_carbs_g": 266.1, "total_fat_g": 99.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the pasta", "instruction": "Cook the spaghetti following pack instructions.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Build the sauce", "instruction": "Meanwhile, heat the oil in a non-stick frying pan and cook the onion, garlic and chilli until softened. Stir in the tomato purée and cook for 1 minute.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Add the pilchards", "instruction": "Add the pilchards with their sauce and cook, breaking up the fish with a wooden spoon, then add the olives and cook a few minutes more.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Drain the pasta, add to the pan with some cooking water, toss together well, then divide between plates and scatter with Parmesan.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=wqZzLAPmr9k"}, {"id": "52838", "name": "Venetian Duck Ragu", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qvrwpt1511181864.jpg", "local_image": "52838.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbls"}, {"ingredient": "Duck Legs", "measure": "4"}, {"ingredient": "Onions", "measure": "2 finely chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Cinnamon", "measure": "2 tsp ground"}, {"ingredient": "Plain Flour", "measure": "2 tsp"}, {"ingredient": "Red Wine", "measure": "250ml"}, {"ingredient": "Chopped Tomatoes", "measure": "800g"}, {"ingredient": "Chicken Stock Cube", "measure": "1"}, {"ingredient": "Rosemary", "measure": "3 sprigs"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Milk", "measure": "2 tbs"}, {"ingredient": "Paccheri Pasta", "measure": "600g"}, {"ingredient": "Parmesan Cheese", "measure": "Grated"}], "instructions": "Heat the oil in a large pan. Add the duck legs and brown on all sides for about 10 mins. Remove to a plate and set aside. Add the onions to the pan and cook for 5 mins until softened. Add the garlic and cook for a further 1 min, then stir in the cinnamon and flour and cook for a further min. Return the duck to the pan, add the wine, tomatoes, stock, herbs, sugar and seasoning. Bring to a simmer, then lower the heat, cover with a lid and cook for 2 hrs, stirring every now and then.\r\nCarefully lift the duck legs out of the sauce and place on a plate – they will be very tender so try not to lose any of the meat. Pull off and discard the fat, then shred the meat with 2 forks and discard the bones. Add the meat back to the sauce with the milk and simmer, uncovered, for a further 10-15 mins while you cook the pasta.\r\nCook the pasta following pack instructions, then drain, reserving a cup of the pasta water, and add the pasta to the ragu. Stir to coat all the pasta in the sauce and cook for 1 min more, adding a splash of cooking liquid if it looks dry. Serve with grated Parmesan, if you like.", "equipment_tags": [], "portions": 12, "prep_minutes": 152, "prep_minutes_source": "explicit", "kcal": 335, "protein_g": 11.7, "carbs_g": 44.3, "fat_g": 10.6, "total_kcal": 4016, "total_protein_g": 140.0, "total_carbs_g": 531.2, "total_fat_g": 127.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the duck", "instruction": "Heat the oil in a large pan, add the duck legs, and brown on all sides, then remove to a plate.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Build the sauce base", "instruction": "Add the onions to the pan and cook until softened, then add the garlic and cook a minute more. Stir in the cinnamon and flour and cook a further minute.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Braise the duck", "instruction": "Return the duck to the pan, add the wine, tomatoes, stock, herbs, sugar and seasoning. Bring to a simmer, then cover and cook over low heat, stirring occasionally.", "timer_seconds": 7200, "background": true}, {"step": 4, "label": "Shred the duck", "instruction": "Lift the duck out, discard the fat, and shred the meat, discarding the bones. Return the meat to the sauce with the milk and simmer uncovered while you cook the pasta.", "timer_seconds": 750, "background": false}, {"step": 5, "label": "Cook the pasta and finish", "instruction": "Cook the pasta following pack instructions, drain, reserving some cooking water, and add to the ragù. Stir to coat, cooking a minute more and adding cooking liquid if dry.", "timer_seconds": 60, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve with grated Parmesan, if you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=oWQDVgjB_Lw"}, {"id": "52839", "name": "Chilli prawn linguine", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/usywpp1511189717.jpg", "local_image": "52839.jpg", "ingredients": [{"ingredient": "Linguine Pasta", "measure": "280g"}, {"ingredient": "Sugar Snap Peas", "measure": "200g"}, {"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Garlic Clove", "measure": "2 cloves chopped"}, {"ingredient": "Red Chilli", "measure": "1 large"}, {"ingredient": "King Prawns", "measure": "24 Skinned"}, {"ingredient": "Cherry Tomatoes", "measure": "12"}, {"ingredient": "Basil Leaves", "measure": "Handful"}, {"ingredient": "Lettuce", "measure": "Leaves"}, {"ingredient": "Bread", "measure": "to serve"}, {"ingredient": "Fromage Frais", "measure": "2 tbsp"}, {"ingredient": "Lime", "measure": "Grated Zest of 2"}, {"ingredient": "Caster Sugar", "measure": "2 tsp"}], "instructions": "Mix the dressing ingredients in a small bowl and season with salt and pepper. Set aside.\r\n\r\nCook the pasta according to the packet instructions. Add the sugar snap peas for the last minute or so of cooking time.\r\n\r\nMeanwhile, heat the oil in a wok or large frying pan, toss in the garlic and chilli and cook over a fairly gentle heat for about 30 seconds without letting the garlic brown. Tip in the prawns and cook over a high heat, stirring frequently, for about 3 minutes until they turn pink.\r\n\r\nAdd the tomatoes and cook, stirring occasionally, for 3 minutes until they just start to soften. Drain the pasta and sugar snaps well, then toss into the prawn mixture. Tear in the basil leaves, stir, and season with salt and pepper.\r\n\r\nServe with salad leaves drizzled with the lime dressing, and warm crusty bread.", "equipment_tags": [], "portions": 12, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 290, "protein_g": 24.5, "carbs_g": 41.2, "fat_g": 3.6, "total_kcal": 3476, "total_protein_g": 294.4, "total_carbs_g": 494.7, "total_fat_g": 42.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dressing", "instruction": "Mix the dressing ingredients in a small bowl, season, and set aside.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the pasta and peas", "instruction": "Cook the pasta according to packet instructions, adding the sugar snap peas for the last minute.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Cook the prawns", "instruction": "Meanwhile, heat the oil in a wok, add the garlic and chilli and cook gently without browning the garlic. Add the prawns and cook over high heat, stirring, until pink.", "timer_seconds": 210, "background": false}, {"step": 4, "label": "Add the tomatoes", "instruction": "Add the tomatoes and cook, stirring occasionally, until they just start to soften.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Combine and serve", "instruction": "Drain the pasta and sugar snaps, toss into the prawn mixture, tear in the basil, season, and serve with lime-dressed salad leaves and warm crusty bread.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=SC17Mc70Db0"}, {"id": "52840", "name": "Clam chowder", "category": "Starter", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rvtvuw1511190488.jpg", "local_image": "52840.jpg", "ingredients": [{"ingredient": "Clams", "measure": "1½ kg"}, {"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Bacon", "measure": "150g"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Thyme", "measure": "sprigs of fresh"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Plain Flour", "measure": "1 tbls"}, {"ingredient": "Milk", "measure": "150ml"}, {"ingredient": "Double Cream", "measure": "150ml"}, {"ingredient": "Potatoes", "measure": "2 medium"}, {"ingredient": "Parsley", "measure": "Chopped"}], "instructions": "Rinse the clams in several changes of cold water and drain well. Tip the clams into a large pan with 500ml of water. Cover, bring to the boil and simmer for 2 mins until the clams have just opened. Tip the contents of the pan into a colander over a bowl to catch the clam stock. When cool enough to handle, remove the clams from their shells – reserving a handful of empty shells for presentation if you want. Strain the clam stock into a jug, leaving any grit in the bottom of the bowl. You should have around 800ml stock.\r\nHeat the butter in the same pan and sizzle the bacon for 3-4 mins until it starts to brown. Stir in the onion, thyme and bay and cook everything gently for 10 mins until the onion is soft and golden. Scatter over the flour and stir in to make a sandy paste, cook for 2 mins more, then gradually stir in the clam stock then the milk and the cream.\r\nThrow in the potatoes, bring everything to a simmer and leave to bubble away gently for 10 mins or until the potatoes are cooked. Use a fork to crush a few of the potato chunks against the side of the pan to help thicken – you still want lots of defined chunks though. Stir through the clam meat and the few clam shells, if you've gone down that route, and simmer for a minute to reheat. Season with plenty of black pepper and a little salt, if needed, then stir through the parsley just before ladling into bowls or hollowed-out crusty rolls.", "equipment_tags": [], "portions": 7, "prep_minutes": 28, "prep_minutes_source": "explicit", "kcal": 353, "protein_g": 12.2, "carbs_g": 17.6, "fat_g": 26.0, "total_kcal": 2474, "total_protein_g": 85.4, "total_carbs_g": 123.3, "total_fat_g": 182.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Steam the clams", "instruction": "Rinse the clams well. Tip into a large pan with water, cover, bring to the boil and simmer until they've just opened. Strain the contents over a bowl to catch the stock, then remove the clam meat from the shells.", "timer_seconds": 120, "background": false}, {"step": 2, "label": "Cook the bacon and aromatics", "instruction": "Heat the butter in the same pan and fry the bacon until it starts to brown. Stir in the onion, thyme and bay and cook gently until the onion is soft and golden.", "timer_seconds": 840, "background": false}, {"step": 3, "label": "Build the base", "instruction": "Scatter over the flour and stir into a paste, cook for 2 minutes, then gradually stir in the clam stock, milk and cream.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Cook the potatoes", "instruction": "Add the potatoes, bring to a simmer, and cook gently until tender, crushing a few chunks against the pan to help thicken.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Finish and serve", "instruction": "Stir through the clam meat and reserved shells if using, simmer briefly to reheat, season, then stir through the parsley before ladling into bowls or hollowed-out rolls.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=fEN_fm6kX6k"}, {"id": "52841", "name": "Creamy Tomato Soup", "category": "Starter", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/stpuws1511191310.jpg", "local_image": "52841.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "3 tbsp"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Celery", "measure": "2 sticks"}, {"ingredient": "Carrots", "measure": "300g"}, {"ingredient": "Potatoes", "measure": "500g"}, {"ingredient": "Bay Leaf", "measure": "4"}, {"ingredient": "Tomato Puree", "measure": "5 tblsp"}, {"ingredient": "Sugar", "measure": "2 tblsp"}, {"ingredient": "White Vinegar", "measure": "2 tblsp"}, {"ingredient": "Chopped Tomatoes", "measure": "1½ kg"}, {"ingredient": "Passata", "measure": "500g"}, {"ingredient": "Vegetable Stock Cube", "measure": "3"}, {"ingredient": "Whole Milk", "measure": "400ml"}], "instructions": "Put the oil, onions, celery, carrots, potatoes and bay leaves in a big casserole dish, or two saucepans. Fry gently until the onions are softened – about 10-15 mins. Fill the kettle and boil it.\r\nStir in the tomato purée, sugar, vinegar, chopped tomatoes and passata, then crumble in the stock cubes. Add 1 litre boiling water and bring to a simmer. Cover and simmer for 15 mins until the potato is tender, then remove the bay leaves. Purée with a stick blender (or ladle into a blender in batches) until very smooth. Season to taste and add a pinch more sugar if it needs it. The soup can now be cooled and chilled for up to 2 days, or frozen for up to 3 months.\r\nTo serve, reheat the soup, stirring in the milk – try not to let it boil. Serve in small bowls with cheesy sausage rolls.", "equipment_tags": ["Blender"], "portions": 12, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 130, "protein_g": 3.4, "carbs_g": 19.4, "fat_g": 4.9, "total_kcal": 1562, "total_protein_g": 41.0, "total_carbs_g": 233.2, "total_fat_g": 58.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the base vegetables", "instruction": "Put the oil, onions, celery, carrots, potatoes and bay leaves in a large casserole and fry gently until the onions are softened. Boil the kettle.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Simmer the soup", "instruction": "Stir in the tomato purée, sugar, vinegar, chopped tomatoes and passata, crumble in the stock cubes, add the boiling water, and bring to a simmer. Cover and simmer until the potato is tender, then remove the bay leaves.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Blend", "instruction": "Purée with a stick blender (or in batches in a blender) until very smooth. Season to taste, adding a touch more sugar if needed.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Reheat, stirring in the milk without letting it boil. Serve in small bowls with cheesy sausage rolls.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=lBhwjjUiFk4"}, {"id": "52842", "name": "Broccoli & Stilton soup", "category": "Starter", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tvvxpv1511191952.jpg", "local_image": "52842.jpg", "ingredients": [{"ingredient": "Rapeseed Oil", "measure": "2 tblsp"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Celery", "measure": "1"}, {"ingredient": "Leek", "measure": "1 sliced"}, {"ingredient": "Potatoes", "measure": "1 medium"}, {"ingredient": "Butter", "measure": "1 knob"}, {"ingredient": "Vegetable Stock", "measure": "1 litre hot"}, {"ingredient": "Broccoli", "measure": "1 Head chopped"}, {"ingredient": "Stilton Cheese", "measure": "140g"}], "instructions": "Heat the rapeseed oil in a large saucepan and then add the onions. Cook on a medium heat until soft. Add a splash of water if the onions start to catch.\r\n\r\nAdd the celery, leek, potato and a knob of butter. Stir until melted, then cover with a lid. Allow to sweat for 5 minutes. Remove the lid.\r\n\r\nPour in the stock and add any chunky bits of broccoli stalk. Cook for 10 – 15 minutes until all the vegetables are soft.\r\n\r\nAdd the rest of the broccoli and cook for a further 5 minutes. Carefully transfer to a blender and blitz until smooth. Stir in the stilton, allowing a few lumps to remain. Season with black pepper and serve.", "equipment_tags": ["Blender"], "portions": 11, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 102, "protein_g": 3.8, "carbs_g": 5.3, "fat_g": 7.5, "total_kcal": 1126, "total_protein_g": 41.6, "total_carbs_g": 58.3, "total_fat_g": 82.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Heat the oil in a large saucepan and cook the onion on medium heat until soft, adding a splash of water if it starts to catch.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Sweat the vegetables", "instruction": "Add the celery, leek, potato and a knob of butter, stir until melted, cover with a lid, and allow to sweat.", "timer_seconds": 300, "background": true}, {"step": 3, "label": "Simmer with stock", "instruction": "Remove the lid, pour in the stock, add any chunky broccoli stalks, and cook until the vegetables are soft.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Add the broccoli", "instruction": "Add the rest of the broccoli and cook a further 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Blend and finish", "instruction": "Carefully transfer to a blender and blitz until smooth. Stir in the Stilton, leaving a few lumps, season with black pepper and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_HgVLpmNxTY"}, {"id": "52843", "name": "Lamb Tagine", "category": "Lamb", "area": "Moroccan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yuwtuu1511295751.jpg", "local_image": "52843.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Onion", "measure": "1 finely sliced"}, {"ingredient": "Carrots", "measure": "2 chopped"}, {"ingredient": "Lamb Leg", "measure": "500g"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Cumin", "measure": "½ tsp"}, {"ingredient": "Ginger", "measure": "½ tsp"}, {"ingredient": "Saffron", "measure": "¼ tsp"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Honey", "measure": "1 tblsp"}, {"ingredient": "Apricot", "measure": "100g"}, {"ingredient": "Vegetable Stock Cube", "measure": "1"}, {"ingredient": "Butternut Squash", "measure": "1 medium chopped"}, {"ingredient": "Couscous", "measure": "Steamed"}, {"ingredient": "Parsley", "measure": "Chopped"}], "instructions": "Heat the olive oil in a heavy-based pan and add the onion and carrot. Cook for 3- 4 mins until softened.\r\n\r\nAdd the diced lamb and brown all over. Stir in the garlic and all the spices and cook for a few mins more or until the aromas are released.\r\n\r\nAdd the honey and apricots, crumble in the stock cube and pour over roughly 500ml boiling water or enough to cover the meat. Give it a good stir and bring to the boil. Turn down to a simmer, put the lid on and cook for 1 hour.\r\n\r\nRemove the lid and cook for a further 30 mins, then stir in the squash. Cook for 20 – 30 mins more until the squash is soft and the lamb is tender. Serve alongside rice or couscous and sprinkle with parsley and pine nuts, if using.", "equipment_tags": [], "portions": 2, "prep_minutes": 124, "prep_minutes_source": "explicit", "kcal": 1048, "protein_g": 67.8, "carbs_g": 44.0, "fat_g": 67.3, "total_kcal": 2096, "total_protein_g": 135.5, "total_carbs_g": 88.0, "total_fat_g": 134.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion and carrot", "instruction": "Heat the oil in a heavy-based pan and cook the onion and carrot until softened.", "timer_seconds": 240, "background": false}, {"step": 2, "label": "Brown the lamb", "instruction": "Add the diced lamb and brown all over, then stir in the garlic and spices and cook until fragrant.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the tagine", "instruction": "Add the honey and apricots, crumble in the stock cube, pour over boiling water to just cover the meat, stir, bring to the boil, then reduce to a simmer, cover, and cook.", "timer_seconds": 3600, "background": true}, {"step": 4, "label": "Add the squash", "instruction": "Remove the lid and cook further, then stir in the squash and continue cooking until soft and the lamb is tender.", "timer_seconds": 3000, "background": true}, {"step": 5, "label": "Serve", "instruction": "Serve alongside rice or couscous, sprinkled with parsley and pine nuts if using.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=bR5Cqu84S_k"}, {"id": "52844", "name": "Lasagne", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wtsvxx1511296896.jpg", "local_image": "52844.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Bacon", "measure": "2"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Celery", "measure": "1 Stick"}, {"ingredient": "Carrots", "measure": "1 medium"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Minced Beef", "measure": "500g"}, {"ingredient": "Tomato Puree", "measure": "1 tbls"}, {"ingredient": "Chopped Tomatoes", "measure": "800g"}, {"ingredient": "Honey", "measure": "1 tblsp"}, {"ingredient": "Lasagne Sheets", "measure": "500g"}, {"ingredient": "Creme Fraiche", "measure": "400ml"}, {"ingredient": "Mozzarella Balls", "measure": "125g"}, {"ingredient": "Parmesan Cheese", "measure": "50g"}, {"ingredient": "Basil Leaves", "measure": "Topping"}], "instructions": "Heat the oil in a large saucepan. Use kitchen scissors to snip the bacon into small pieces, or use a sharp knife to chop it on a chopping board. Add the bacon to the pan and cook for just a few mins until starting to turn golden. Add the onion, celery and carrot, and cook over a medium heat for 5 mins, stirring occasionally, until softened.\r\nAdd the garlic and cook for 1 min, then tip in the mince and cook, stirring and breaking it up with a wooden spoon, for about 6 mins until browned all over.\r\nStir in the tomato purée and cook for 1 min, mixing in well with the beef and vegetables. Tip in the chopped tomatoes. Fill each can half full with water to rinse out any tomatoes left in the can, and add to the pan. Add the honey and season to taste. Simmer for 20 mins.\r\nHeat oven to 200C/180C fan/gas 6. To assemble the lasagne, ladle a little of the ragu sauce into the bottom of the roasting tin or casserole dish, spreading the sauce all over the base. Place 2 sheets of lasagne on top of the sauce overlapping to make it fit, then repeat with more sauce and another layer of pasta. Repeat with a further 2 layers of sauce and pasta, finishing with a layer of pasta.\r\nPut the crème fraîche in a bowl and mix with 2 tbsp water to loosen it and make a smooth pourable sauce. Pour this over the top of the pasta, then top with the mozzarella. Sprinkle Parmesan over the top and bake for 25–30 mins until golden and bubbling. Serve scattered with basil, if you like.", "equipment_tags": [], "portions": 12, "prep_minutes": 63, "prep_minutes_source": "explicit", "kcal": 491, "protein_g": 22.1, "carbs_g": 40.2, "fat_g": 26.8, "total_kcal": 5897, "total_protein_g": 265.3, "total_carbs_g": 482.8, "total_fat_g": 321.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the bacon and soften vegetables", "instruction": "Heat the oil in a large saucepan, snip in the bacon and cook until starting to turn golden. Add the onion, celery and carrot and cook, stirring occasionally, until softened.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Brown the mince", "instruction": "Add the garlic and cook a minute, then tip in the mince and cook, breaking it up, until browned all over.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Simmer the ragù", "instruction": "Stir in the tomato purée, then the chopped tomatoes with a little water to rinse the cans, add the honey, season, and simmer.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Layer the lasagne", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Ladle a little ragù into a roasting tin, top with lasagne sheets overlapping to fit, then repeat with more sauce and pasta until you have 4 layers, finishing with pasta.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Top and bake", "instruction": "Loosen the crème fraîche with water and pour over the top, then top with mozzarella and Parmesan. Bake until golden and bubbling.", "timer_seconds": 1650, "background": true}, {"step": 6, "label": "Serve", "instruction": "Scatter with basil, if you like, before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=gfhfsBPt46s"}, {"id": "52845", "name": "Turkey Meatloaf", "category": "Miscellaneous", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ypuxtw1511297463.jpg", "local_image": "52845.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Worcestershire Sauce", "measure": "2 tblsp"}, {"ingredient": "Tomato Puree", "measure": "3 tsp"}, {"ingredient": "Turkey Mince", "measure": "500g"}, {"ingredient": "Eggs", "measure": "1 large"}, {"ingredient": "Breadcrumbs", "measure": "85g"}, {"ingredient": "Barbeque Sauce", "measure": "2 tblsp"}, {"ingredient": "Cannellini Beans", "measure": "800g"}, {"ingredient": "Parsley", "measure": "2 tblsp"}], "instructions": "Heat oven to 180C/160C fan/gas 4. Heat the oil in a large frying pan and cook the onion for 8-10 mins until softened. Add the garlic, Worcestershire sauce and 2 tsp tomato purée, and stir until combined. Set aside to cool.\r\n\r\nPut the turkey mince, egg, breadcrumbs and cooled onion mix in a large bowl and season well. Mix everything to combine, then shape into a rectangular loaf and place in a large roasting tin. Spread 2 tbsp barbecue sauce over the meatloaf and bake for 30 mins.\r\n\r\nMeanwhile, drain 1 can of beans only, then pour both cans into a large bowl. Add the remaining barbecue sauce and tomato purée. Season and set aside.\r\n\r\nWhen the meatloaf has had its initial cooking time, scatter the beans around the outside and bake for 15 mins more until the meatloaf is cooked through and the beans are piping hot. Scatter over the parsley and serve the meatloaf in slices.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 764, "protein_g": 63.5, "carbs_g": 92.7, "fat_g": 16.0, "total_kcal": 2292, "total_protein_g": 190.4, "total_carbs_g": 278.0, "total_fat_g": 48.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the onion base", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Heat the oil in a large frying pan and cook the onion until softened. Add the garlic, Worcestershire sauce and 2 tsp tomato purée, stir until combined, then set aside to cool.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Shape the meatloaf", "instruction": "Mix the turkey mince, egg, breadcrumbs and cooled onion mix in a large bowl, season, then shape into a rectangular loaf in a roasting tin.", "timer_seconds": null, "background": false}, {"step": 3, "label": "First bake", "instruction": "Spread barbecue sauce over the meatloaf and bake.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Prep the beans", "instruction": "While the meatloaf bakes, drain one can of beans and combine with the second can, the remaining barbecue sauce and tomato purée. Season and set aside.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Finish baking", "instruction": "Scatter the beans around the meatloaf and bake further until the meatloaf is cooked through and the beans are piping hot.", "timer_seconds": 900, "background": true}, {"step": 6, "label": "Serve", "instruction": "Scatter with parsley and serve the meatloaf in slices.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=mTvlmY4vCug"}, {"id": "52846", "name": "Chicken & mushroom Hotpot", "category": "Chicken", "area": "British", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/uuuspp1511297945.jpg", "local_image": "52846.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Mushrooms", "measure": "100g"}, {"ingredient": "Plain Flour", "measure": "40g"}, {"ingredient": "Chicken Stock Cube", "measure": "1"}, {"ingredient": "Nutmeg", "measure": "pinch"}, {"ingredient": "Mustard Powder", "measure": "pinch"}, {"ingredient": "Chicken", "measure": "250g"}, {"ingredient": "Sweetcorn", "measure": "2 Handfuls"}, {"ingredient": "Potatoes", "measure": "2 large"}, {"ingredient": "Butter", "measure": "1 knob"}], "instructions": "Heat oven to 200C/180C fan/gas 6. Put the butter in a medium-size saucepan and place over a medium heat. Add the onion and leave to cook for 5 mins, stirring occasionally. Add the mushrooms to the saucepan with the onions.\r\n\r\nOnce the onion and mushrooms are almost cooked, stir in the flour – this will make a thick paste called a roux. If you are using a stock cube, crumble the cube into the roux now and stir well. Put the roux over a low heat and stir continuously for 2 mins – this will cook the flour and stop the sauce from having a floury taste.\r\n\r\nTake the roux off the heat. Slowly add the fresh stock, if using, or pour in 500ml water if you’ve used a stock cube, stirring all the time. Once all the liquid has been added, season with pepper, a pinch of nutmeg and mustard powder. Put the saucepan back onto a medium heat and slowly bring it to the boil, stirring all the time. Once the sauce has thickened, place on a very low heat. Add the cooked chicken and vegetables to the sauce and stir well. Grease a medium-size ovenproof pie dish with a little butter and pour in the chicken and mushroom filling.\r\n\r\nCarefully lay the potatoes on top of the hot-pot filling, overlapping them slightly, almost like a pie top.\r\n\r\nBrush the potatoes with a little melted butter and cook in the oven for about 35 mins. The hot-pot is ready once the potatoes are cooked and golden brown.", "equipment_tags": [], "portions": 2, "prep_minutes": 42, "prep_minutes_source": "explicit", "kcal": 686, "protein_g": 35.2, "carbs_g": 56.9, "fat_g": 35.6, "total_kcal": 1372, "total_protein_g": 70.5, "total_carbs_g": 113.8, "total_fat_g": 71.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion and mushrooms", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Melt the butter in a saucepan and cook the onion, then add the mushrooms and cook until almost done.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Make the roux", "instruction": "Stir in the flour and, if using a stock cube, crumble it in, then cook over low heat, stirring continuously.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Build the sauce", "instruction": "Off the heat, slowly stir in the stock or water, then season with pepper, nutmeg and mustard powder. Return to medium heat and bring to a boil, stirring, until thickened.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Add the chicken and pour into the dish", "instruction": "Stir the cooked chicken and vegetables into the sauce, then pour into a greased ovenproof pie dish.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Top with potatoes and bake", "instruction": "Lay the potato slices overlapping on top like a pie crust, brush with melted butter, and bake until the potatoes are cooked and golden brown.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=bXKWu4GojNI"}, {"id": "52847", "name": "Pork Cassoulet", "category": "Pork", "area": "France", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/wxuvuv1511299147.jpg", "local_image": "52847.jpg", "ingredients": [{"ingredient": "Goose Fat", "measure": "4 tbsp"}, {"ingredient": "Pork", "measure": "350g"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Garlic", "measure": "10"}, {"ingredient": "Carrots", "measure": "1 thinly sliced"}, {"ingredient": "Fennel Seeds", "measure": "1 tsp"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tblsp"}, {"ingredient": "Vegetable Stock", "measure": "600ml"}, {"ingredient": "Tomato Puree", "measure": "1 tblsp"}, {"ingredient": "Rosemary", "measure": "2 sticks"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Haricot Beans", "measure": "400g"}, {"ingredient": "Breadcrumbs", "measure": "2 tblsp"}, {"ingredient": "Oil", "measure": "drizzle"}, {"ingredient": "Bread", "measure": "to serve"}, {"ingredient": "Broccoli", "measure": "to serve"}], "instructions": "Heat oven to 140C/120C fan/gas 1. Put a large ovenproof pan (with a tight-fitting lid) on a high heat. Add your fat and diced meat, cook for a few mins to seal the edges, giving it a quick stir to cook evenly. Reduce the heat to low, add the sliced onion, whole garlic cloves, carrot and fennel seeds, and cook gently to soften the veg for a few mins.\r\nPour over the red wine vinegar, scraping any meaty bits off the bottom of the pan. Add the stock, tomato purée, and half the rosemary and parsley. Bring to the boil and simmer for 10 mins, then season, cover with a lid and put into the oven for 2 hrs, removing the lid for the final hour of cooking. Stir occasionally and add the beans with 30 mins to go.\r\nRemove the pan from the oven and heat the grill. Scatter the top with the remaining herbs and breadcrumbs, drizzle a little oil over the top, and return to the oven for 5-10 mins, until the breadcrumbs are golden. Serve with crusty bread and green veg.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 170, "prep_minutes_source": "explicit", "kcal": 597, "protein_g": 30.3, "carbs_g": 64.9, "fat_g": 25.5, "total_kcal": 2984, "total_protein_g": 151.7, "total_carbs_g": 324.6, "total_fat_g": 127.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Seal the pork", "instruction": "Heat the oven to 140°C/120°C fan/gas 1. Heat the fat in a large ovenproof pan and cook the diced pork briefly to seal the edges.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Soften the vegetables", "instruction": "Reduce the heat, add the onion, garlic, carrot and fennel seeds, and cook gently to soften.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Deglaze and simmer", "instruction": "Pour over the vinegar, scraping the pan, then add the stock, tomato purée and half the herbs. Bring to the boil and simmer.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Braise in the oven", "instruction": "Season, cover with a lid and cook in the oven, stirring occasionally and adding the beans with 30 minutes to go, removing the lid for the final hour.", "timer_seconds": 7200, "background": true}, {"step": 5, "label": "Finish under the grill", "instruction": "Remove from the oven and heat the grill. Scatter with the remaining herbs and breadcrumbs, drizzle with oil, and return to the oven or grill until golden.", "timer_seconds": 450, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve with crusty bread and green vegetables.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=MEdHMTD0VCA"}, {"id": "52848", "name": "Bean & Sausage Hotpot", "category": "Miscellaneous", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vxuyrx1511302687.jpg", "local_image": "52848.jpg", "ingredients": [{"ingredient": "Sausages", "measure": "8 large"}, {"ingredient": "Tomato Sauce", "measure": "1 Jar"}, {"ingredient": "Butter Beans", "measure": "1200g"}, {"ingredient": "Black Treacle", "measure": "1 tbls"}, {"ingredient": "English Mustard", "measure": "1 tsp"}], "instructions": "In a large casserole, fry the sausages until brown all over – about 10 mins.\r\n\r\nAdd the tomato sauce, stirring well, then stir in the beans, treacle or sugar and mustard. Bring to the simmer, cover and cook for 30 mins. Great served with crusty bread or rice.", "equipment_tags": [], "portions": 4, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 725, "protein_g": 39.9, "carbs_g": 82.3, "fat_g": 27.7, "total_kcal": 2901, "total_protein_g": 159.5, "total_carbs_g": 329.1, "total_fat_g": 110.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the sausages", "instruction": "Fry the sausages in a large casserole until brown all over.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Build and simmer", "instruction": "Add the tomato sauce and stir well, then stir in the beans, treacle and mustard. Bring to a simmer, cover, and cook.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Serve", "instruction": "Serve with crusty bread or rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=B0YX0yPX4Wo"}, {"id": "52849", "name": "Spinach & Ricotta Cannelloni", "category": "Vegetarian", "area": "Italian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wspuvp1511303478.jpg", "local_image": "52849.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "3 tbsp"}, {"ingredient": "Garlic", "measure": "8 cloves chopped"}, {"ingredient": "Caster Sugar", "measure": "3 tbsp"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tblsp"}, {"ingredient": "Chopped Tomatoes", "measure": "3 400g Cans"}, {"ingredient": "Basil Leaves", "measure": "Bunch"}, {"ingredient": "Mascarpone", "measure": "2 tubs"}, {"ingredient": "Milk", "measure": "3 tbsp"}, {"ingredient": "Parmesan", "measure": "85g"}, {"ingredient": "Mozzarella", "measure": "2 sliced"}, {"ingredient": "Spinach", "measure": "1kg"}, {"ingredient": "Parmesan", "measure": "100g"}, {"ingredient": "Ricotta", "measure": "3 tubs"}, {"ingredient": "Nutmeg", "measure": "pinch"}, {"ingredient": "Cannellini Beans", "measure": "400g"}], "instructions": "First make the tomato sauce. Heat the oil in a large pan and fry the garlic for 1 min. Add the sugar, vinegar, tomatoes and some seasoning and simmer for 20 mins, stirring occasionally, until thick. Add the basil and divide the sauce between 2 or more shallow ovenproof dishes (see Tips for freezing, below). Set aside. Make a sauce by beating the mascarpone with the milk until smooth, season, then set aside.\r\n\r\nPut the spinach in a large colander and pour over a kettle of boiling water to wilt it (you may need to do this in batches). When cool enough to handle squeeze out the excess water. Roughly chop the spinach and mix in a large bowl with 100g Parmesan and ricotta. Season well with salt, pepper and the nutmeg.\r\n\r\nHeat oven to 200C/180C fan/gas 6. Using a piping bag or plastic food bag with the corner snipped off, squeeze the filling into the cannelloni tubes. Lay the tubes, side by side, on top of the tomato sauce and spoon over the mascarpone sauce. Top with Parmesan and mozzarella. You can now freeze the cannelloni, uncooked, or you can cook it first and then freeze. Bake for 30-35 mins until golden and bubbling. Remove from oven and let stand for 5 mins before serving.", "equipment_tags": [], "portions": 5, "prep_minutes": 61, "prep_minutes_source": "explicit", "kcal": 634, "protein_g": 38.3, "carbs_g": 42.5, "fat_g": 36.9, "total_kcal": 3169, "total_protein_g": 191.5, "total_carbs_g": 212.3, "total_fat_g": 184.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the tomato sauce", "instruction": "Heat the oil in a large pan and fry the garlic for 1 minute. Add the sugar, vinegar, tomatoes and seasoning, and simmer, stirring occasionally, until thick.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Finish the tomato sauce and mascarpone sauce", "instruction": "Add the basil to the tomato sauce and divide between ovenproof dishes. Separately, beat the mascarpone with the milk until smooth and season.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Wilt the spinach", "instruction": "Put the spinach in a colander and pour over boiling water to wilt it, working in batches if needed. Once cool enough to handle, squeeze out the excess water and chop roughly.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the filling", "instruction": "Mix the chopped spinach with the 100g Parmesan and ricotta, and season with salt, pepper and nutmeg.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fill and assemble", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Pipe the filling into the cannelloni tubes and lay them on top of the tomato sauce. Spoon over the mascarpone sauce and top with Parmesan and mozzarella.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake and rest", "instruction": "Bake until golden and bubbling, then let stand before serving.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=rYGaEJjyLQA"}, {"id": "52850", "name": "Chicken Couscous", "category": "Chicken", "area": "Moroccan", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qxytrx1511304021.jpg", "local_image": "52850.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Chicken Breast", "measure": "200g"}, {"ingredient": "Ginger", "measure": "pinch"}, {"ingredient": "Harissa Spice", "measure": "2 tblsp"}, {"ingredient": "Dried Apricots", "measure": "10"}, {"ingredient": "Chickpeas", "measure": "220g"}, {"ingredient": "Couscous", "measure": "200g"}, {"ingredient": "Chicken Stock", "measure": "200ml"}, {"ingredient": "Coriander", "measure": "Handful"}], "instructions": "Heat the olive oil in a large frying pan and cook the onion for 1-2 mins just until softened. Add the chicken and fry for 7-10 mins until cooked through and the onions have turned golden. Grate over the ginger, stir through the harissa to coat everything and cook for 1 min more.\r\n\r\nTip in the apricots, chickpeas and couscous, then pour over the stock and stir once. Cover with a lid or tightly cover the pan with foil and leave for about 5 mins until the couscous has soaked up all the stock and is soft. Fluff up the couscous with a fork and scatter over the coriander to serve. Serve with extra harissa, if you like.", "equipment_tags": [], "portions": 3, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 925, "protein_g": 37.1, "carbs_g": 181.7, "fat_g": 10.3, "total_kcal": 2774, "total_protein_g": 111.3, "total_carbs_g": 545.1, "total_fat_g": 31.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the onion and chicken", "instruction": "Heat the oil in a large frying pan and cook the onion until softened, then add the chicken and fry until cooked through and the onions have turned golden.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Add the spices", "instruction": "Grate in the ginger, stir through the harissa to coat everything, and cook a minute more.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Steam the couscous", "instruction": "Tip in the apricots, chickpeas and couscous, pour over the stock, stir once, then cover tightly and leave until the couscous has soaked up all the stock and is soft.", "timer_seconds": 300, "background": true}, {"step": 4, "label": "Serve", "instruction": "Fluff up the couscous with a fork, scatter over the coriander, and serve with extra harissa if you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=GZQGy9oscVk"}, {"id": "52851", "name": "Nutty Chicken Curry", "category": "Chicken", "area": "India", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/yxsurp1511304301.jpg", "local_image": "52851.jpg", "ingredients": [{"ingredient": "Red Chilli", "measure": "1 large"}, {"ingredient": "Ginger", "measure": "0.5"}, {"ingredient": "Garlic", "measure": "1 large"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Sunflower Oil", "measure": "1 tbsp"}, {"ingredient": "Chicken Breasts", "measure": "4"}, {"ingredient": "Peanut Butter", "measure": "5 tblsp"}, {"ingredient": "Chicken Stock", "measure": "150ml"}, {"ingredient": "Greek Yogurt", "measure": "200g"}], "instructions": "Finely slice a quarter of the chilli, then put the rest in a food processor with the ginger, garlic, coriander stalks and one-third of the leaves. Whizz to a rough paste with a splash of water if needed.\r\nHeat the oil in a frying pan, then quickly brown the chicken chunks for 1 min. Stir in the paste for another min, then add the peanut butter, stock and yogurt. When the sauce is gently bubbling, cook for 10 mins until the chicken is just cooked through and sauce thickened. Stir in most of the remaining coriander, then scatter the rest on top with the chilli, if using. Eat with rice or mashed sweet potato.", "equipment_tags": ["FoodProcessor"], "portions": 2, "prep_minutes": 11, "prep_minutes_source": "explicit", "kcal": 841, "protein_g": 79.8, "carbs_g": 17.9, "fat_g": 49.3, "total_kcal": 1681, "total_protein_g": 159.6, "total_carbs_g": 35.7, "total_fat_g": 98.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the paste", "instruction": "Finely slice a quarter of the chilli and set aside. Put the rest with the ginger, garlic, coriander stalks and a third of the leaves into a food processor and whizz to a rough paste, adding a splash of water if needed.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Brown the chicken", "instruction": "Heat the oil in a frying pan and quickly brown the chicken chunks.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Build the sauce", "instruction": "Stir in the paste for a minute, then add the peanut butter, stock and yogurt. Once gently bubbling, cook until the chicken is just cooked through and the sauce has thickened.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Serve", "instruction": "Stir in most of the remaining coriander, scatter the rest on top with the reserved chilli, and serve with rice or mashed sweet potato.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=nSQNfZxOdeU"}, {"id": "52852", "name": "Tuna Nicoise", "category": "Seafood", "area": "France", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/yypwwq1511304979.jpg", "local_image": "52852.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "450g"}, {"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Red Wine Vinegar", "measure": "1 tbls"}, {"ingredient": "Capers", "measure": "2 tblsp"}, {"ingredient": "Sunflower Oil", "measure": "50g"}, {"ingredient": "Red Onions", "measure": "½"}, {"ingredient": "Spinach", "measure": "100g"}, {"ingredient": "Tuna", "measure": "400g"}], "instructions": "Heat oven to 200C/fan 180C/gas 6. Toss the potatoes with 2 tsp oil and some seasoning. Tip onto a large baking tray, then roast for 20 mins, stirring halfway, until crisp, golden and cooked through.\r\nMeanwhile, put eggs in a small pan of water, bring to the boil, then simmer for 8-10 mins, depending on how you like them cooked. Plunge into a bowl of cold water to cool for a few mins. Peel away the shells, then cut into halves.\r\nIn a large salad bowl, whisk together the remaining oil, red wine vinegar, capers and chopped tomatoes. Season, tip in the onion, spinach, tuna and potatoes, then gently toss together. Top with the eggs, then serve straight away.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 652, "protein_g": 43.7, "carbs_g": 29.7, "fat_g": 39.6, "total_kcal": 1955, "total_protein_g": 131.2, "total_carbs_g": 89.1, "total_fat_g": 118.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the potatoes", "instruction": "Heat the oven to 200°C/fan180°C/gas 6. Toss the potatoes with oil and seasoning, tip onto a baking tray, and roast, stirring halfway, until crisp, golden and cooked through.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Boil the eggs", "instruction": "Meanwhile, put the eggs in a pan of water, bring to the boil, and simmer to your preferred doneness, then plunge into cold water to cool. Peel and halve.", "timer_seconds": 540, "background": false}, {"step": 3, "label": "Assemble the salad", "instruction": "In a large salad bowl, whisk together the remaining oil, vinegar, capers and chopped tomatoes. Season, then toss in the onion, spinach, tuna and roasted potatoes.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Top with the halved eggs and serve straight away.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=3_UAxkx0u6U"}, {"id": "52853", "name": "Chocolate Avocado Mousse", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uttuxy1511382180.jpg", "local_image": "52853.jpg", "ingredients": [{"ingredient": "Banana", "measure": "1"}, {"ingredient": "Cacao", "measure": "3 tbsp"}, {"ingredient": "Avocado", "measure": "1"}, {"ingredient": "Honey", "measure": "2 tblsp"}, {"ingredient": "Lemon Juice", "measure": "1 tsp"}, {"ingredient": "Vanilla", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "2 tbsp"}, {"ingredient": "Sea Salt", "measure": "pinch"}], "instructions": "1. Blend all the mousse ingredients together in your food processor until smooth. Add the cacao powder first and, as you blend, have all the ingredients to hand in order to adjust the ratios slightly as the size of avocados and bananas varies so much. The perfect ratio in order to avoid the dish tasting too much of either is to use equal amounts of both.\r\n\r\n2. Taste and add a few drops of stevia if you feel you need more sweetness.\r\n\r\n3. Fill little cups or shot glasses with the mousse, sprinkle with the cacao powder or nibs and serve.\r\n\r\nTip If you don’t have a frozen banana to hand you can just use a normal one and then chill the mousse before serving for a cooling dessert.", "equipment_tags": ["FoodProcessor"], "portions": 2, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 186, "protein_g": 5.4, "carbs_g": 38.9, "fat_g": 6.9, "total_kcal": 372, "total_protein_g": 10.7, "total_carbs_g": 77.8, "total_fat_g": 13.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Blend the mousse", "instruction": "Blend all the mousse ingredients together in a food processor until smooth, starting with the cacao powder and adjusting the ratio of avocado to banana as you go.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Taste and adjust", "instruction": "Taste and add a few drops of stevia if you'd like more sweetness.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Serve", "instruction": "Fill small cups or shot glasses with the mousse, sprinkle with cacao powder or nibs, and serve. Chill first for a cooler dessert if you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=wuZffe60q4M"}, {"id": "52854", "name": "Pancakes", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rwuyqx1511383174.jpg", "local_image": "52854.jpg", "ingredients": [{"ingredient": "Flour", "measure": "100g"}, {"ingredient": "Eggs", "measure": "2 large"}, {"ingredient": "Milk", "measure": "300ml"}, {"ingredient": "Sunflower Oil", "measure": "1 tbls"}, {"ingredient": "Sugar", "measure": "to serve"}, {"ingredient": "Raspberries", "measure": "to serve"}, {"ingredient": "Blueberries", "measure": "to serve"}], "instructions": "Put the flour, eggs, milk, 1 tbsp oil and a pinch of salt into a bowl or large jug, then whisk to a smooth batter. Set aside for 30 mins to rest if you have time, or start cooking straight away.\r\nSet a medium frying pan or crêpe pan over a medium heat and carefully wipe it with some oiled kitchen paper. When hot, cook your pancakes for 1 min on each side until golden, keeping them warm in a low oven as you go.\r\nServe with lemon wedges and sugar, or your favourite filling. Once cold, you can layer the pancakes between baking parchment, then wrap in cling film and freeze for up to 2 months.", "equipment_tags": [], "portions": 4, "prep_minutes": 31, "prep_minutes_source": "explicit", "kcal": 320, "protein_g": 8.3, "carbs_g": 32.4, "fat_g": 17.8, "total_kcal": 1281, "total_protein_g": 33.2, "total_carbs_g": 129.4, "total_fat_g": 71.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the batter", "instruction": "Put the flour, eggs, milk, oil and a pinch of salt into a bowl or jug and whisk to a smooth batter. Rest if you have time.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Cook the pancakes", "instruction": "Heat a medium frying pan over medium heat and wipe with oiled kitchen paper. Cook the pancakes for about a minute on each side until golden, keeping warm in a low oven as you go.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Serve", "instruction": "Serve with lemon wedges and sugar, or your favourite filling.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=LWuuCndtJr0"}, {"id": "52855", "name": "Banana Pancakes", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sywswr1511383814.jpg", "local_image": "52855.jpg", "ingredients": [{"ingredient": "Banana", "measure": "1 large"}, {"ingredient": "Eggs", "measure": "2 medium"}, {"ingredient": "Baking Powder", "measure": "pinch"}, {"ingredient": "Vanilla Extract", "measure": "spinkling"}, {"ingredient": "Oil", "measure": "1 tsp"}, {"ingredient": "Pecan Nuts", "measure": "25g"}, {"ingredient": "Raspberries", "measure": "125g"}], "instructions": "In a bowl, mash the banana with a fork until it resembles a thick purée. Stir in the eggs, baking powder and vanilla.\r\nHeat a large non-stick frying pan or pancake pan over a medium heat and brush with half the oil. Using half the batter, spoon two pancakes into the pan, cook for 1-2 mins each side, then tip onto a plate. Repeat the process with the remaining oil and batter. Top the pancakes with the pecans and raspberries.", "equipment_tags": [], "portions": 2, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 235, "protein_g": 8.7, "carbs_g": 15.7, "fat_g": 16.8, "total_kcal": 469, "total_protein_g": 17.4, "total_carbs_g": 31.4, "total_fat_g": 33.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the batter", "instruction": "Mash the banana with a fork until it resembles a thick purée, then stir in the eggs, baking powder and vanilla.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the pancakes", "instruction": "Heat a non-stick frying pan over medium heat and brush with half the oil. Spoon in two pancakes at a time and cook on each side, then tip onto a plate. Repeat with the remaining oil and batter.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Serve", "instruction": "Top the pancakes with pecans and raspberries.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=kSKtb2Sv-_U"}, {"id": "52856", "name": "Choc Chip Pecan Pie", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rqvwxt1511384809.jpg", "local_image": "52856.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "300g"}, {"ingredient": "Butter", "measure": "75g"}, {"ingredient": "Cream Cheese", "measure": "100g"}, {"ingredient": "Icing Sugar", "measure": "1 tbls"}, {"ingredient": "Butter", "measure": "150g"}, {"ingredient": "Maple Syrup", "measure": "200ml"}, {"ingredient": "Light Brown Soft Sugar", "measure": "250g"}, {"ingredient": "Dark Brown Soft Sugar", "measure": "100g"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Pecan Nuts", "measure": "400g"}, {"ingredient": "Dark Chocolate Chips", "measure": "200g"}], "instructions": "First, make the pastry. Tip the ingredients into a food processor with 1 /4 tsp salt. Blend until the mixture resembles breadcrumbs. Drizzle 2-3 tsp cold water into the funnel while the blade is running – the mixture should start to clump together. Tip onto a work surface and bring together, kneading briefly into a ball. Pat into a disc, wrap in cling film, and chill for at least 20 mins. Heat oven to 200C/180C fan/gas 6.\r\n\r\nRemove the pastry from the fridge and leave at room temperature for 5 mins to soften. Flour the work surface, then unwrap the pastry and roll to a circle the thickness of a £1 coin. Use the pastry to line a deep, 23cm round fluted tin – mine was about 3cm deep. Press the pastry into the corners and up the sides, making sure there are no gaps. Leave 1cm pastry overhanging (save some of the pastry scraps for later). Line with baking parchment (scrunch it up first to make it more pliable) and fill with baking beans. Blind-bake for 15-20 mins until the sides are set, then remove the parchment and beans and return to the oven for 5 mins until golden brown. Trim the pastry so it’s flush with the top of the tin – a small serrated knife is best for this. If there are any cracks, patch them up with the pastry scraps.\r\n\r\nMeanwhile, weigh the butter, syrup and sugars into a pan, and add 1 /4 tsp salt. Heat until the butter has melted and the sugar dissolved, stirring until smooth. Remove from the heat and cool for 10 mins. Reduce oven to 160C/140C fan/gas 3.\r\n\r\nBeat the eggs in a bowl. Add the syrup mixture, vanilla and pecans, and mix until well combined. Pour half the mixture into the tart case, scatter over half the chocolate chips, then cover with the remaining filling and chocolate chips. Bake on the middle shelf for 50-55 mins until set. Remove from the oven and leave to cool, then chill for at least 2 hrs before serving.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 12, "prep_minutes": 235, "prep_minutes_source": "explicit", "kcal": 779, "protein_g": 9.2, "carbs_g": 83.2, "fat_g": 48.4, "total_kcal": 9349, "total_protein_g": 109.8, "total_carbs_g": 998.7, "total_fat_g": 581.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and chill the pastry", "instruction": "Blend the pastry ingredients with salt in a food processor until it resembles breadcrumbs, drizzle in cold water until it clumps together, then bring into a ball, pat into a disc, wrap and chill.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Line the tin and blind bake", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Roll out the pastry and line a deep 23cm tin, leaving a little overhang. Line with parchment and baking beans and blind-bake until the sides are set, then remove the beans and bake further until golden. Trim the pastry flush with the tin.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Make the filling base", "instruction": "Melt the butter, syrup and sugars together in a pan with salt, stirring until smooth, then remove from the heat and cool. Reduce the oven to 160°C/140°C fan/gas 3.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Fill and bake", "instruction": "Beat the eggs, then mix in the syrup mixture, vanilla and pecans. Pour half into the tart case, scatter over half the chocolate chips, cover with the rest of the filling and remaining chips, and bake until set.", "timer_seconds": 3150, "background": true}, {"step": 5, "label": "Cool and chill", "instruction": "Leave to cool, then chill before serving.", "timer_seconds": 7200, "background": true}], "video": "https://www.youtube.com/watch?v=fDpoT0jvg4Y"}, {"id": "52857", "name": "Pumpkin Pie", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/usuqtp1511385394.jpg", "local_image": "52857.jpg", "ingredients": [{"ingredient": "Pumpkin", "measure": "750g"}, {"ingredient": "Shortcrust Pastry", "measure": "350g"}, {"ingredient": "Plain Flour", "measure": "Dusting"}, {"ingredient": "Caster Sugar", "measure": "140g"}, {"ingredient": "Salt", "measure": "½ tsp"}, {"ingredient": "Nutmeg", "measure": "½ tsp"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Milk", "measure": "175g"}, {"ingredient": "Icing Sugar", "measure": "1 tblsp"}], "instructions": "Place the pumpkin in a large saucepan, cover with water and bring to the boil. Cover with a lid and simmer for 15 mins or until tender. Drain pumpkin; let cool.\r\nHeat oven to 180C/160C fan/gas 4. Roll out the pastry on a lightly floured surface and use it to line a 22cm loose-bottomed tart tin. Chill for 15 mins. Line the pastry with baking parchment and baking beans, then bake for 15 mins. Remove the beans and paper, and cook for a further 10 mins until the base is pale golden and biscuity. Remove from the oven and allow to cool slightly.\r\nIncrease oven to 220C/200C fan/gas 7. Push the cooled pumpkin through a sieve into a large bowl. In a separate bowl, combine the sugar, salt, nutmeg and half the cinnamon. Mix in the beaten eggs, melted butter and milk, then add to the pumpkin purée and stir to combine. Pour into the tart shell and cook for 10 mins, then reduce the temperature to 180C/160C fan/gas 4. Continue to bake for 35-40 mins until the filling has just set.\r\nLeave to cool, then remove the pie from the tin. Mix the remaining cinnamon with the icing sugar and dust over the pie. Serve chilled.", "equipment_tags": [], "portions": 12, "prep_minutes": 105, "prep_minutes_source": "explicit", "kcal": 356, "protein_g": 7.3, "carbs_g": 56.8, "fat_g": 11.6, "total_kcal": 4272, "total_protein_g": 87.7, "total_carbs_g": 681.5, "total_fat_g": 139.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the pumpkin", "instruction": "Place the pumpkin in a saucepan, cover with water, bring to the boil, cover and simmer until tender. Drain and let cool.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Line and blind bake the pastry", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Roll out the pastry and line a 22cm tart tin, chill, then line with parchment and baking beans and bake, removing the beans partway through to finish the base.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Make the filling", "instruction": "Increase the oven to 220°C/200°C fan/gas 7. Push the cooled pumpkin through a sieve. Combine the sugar, salt, nutmeg and half the cinnamon in a separate bowl, mix in the eggs, melted butter and milk, then combine with the pumpkin purée.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake the pie", "instruction": "Pour the filling into the tart shell and bake, then reduce the temperature and continue baking until the filling has just set.", "timer_seconds": 2700, "background": true}, {"step": 5, "label": "Cool and serve", "instruction": "Leave to cool, then remove from the tin. Mix the remaining cinnamon with icing sugar, dust over the pie, and serve chilled.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=hpapqEeb36k"}, {"id": "52858", "name": "New York cheesecake", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/swttys1511385853.jpg", "local_image": "52858.jpg", "ingredients": [{"ingredient": "Butter", "measure": "85g"}, {"ingredient": "Sour Cream", "measure": "140g"}, {"ingredient": "Sugar", "measure": "1tbsp"}, {"ingredient": "Cream Cheese", "measure": "900g"}, {"ingredient": "Caster Sugar", "measure": "250g"}, {"ingredient": "Plain Flour", "measure": "3 tbs"}, {"ingredient": "Lemon Juice", "measure": "1 ½ teaspoons"}, {"ingredient": "Eggs", "measure": "3 Large"}, {"ingredient": "Sour Cream", "measure": "250ml"}, {"ingredient": "Sour Cream", "measure": "150ml"}, {"ingredient": "Caster Sugar", "measure": "1 tbsp"}, {"ingredient": "Lemon Juice", "measure": "2 tsp"}], "instructions": "Position an oven shelf in the middle of the oven. Preheat the oven to fan 160C/conventional 180C/gas 4. Line the base of a 23cm springform cake tin with parchment paper. For the crust, melt the butter in a medium pan. Stir in the biscuit crumbs and sugar so the mixture is evenly moistened. Press the mixture into the bottom of the pan and bake for 10 minutes. Cool on a wire rack while preparing the filling.\r\nFor the filling, increase the oven temperature to fan 200C/conventional 240C/gas 9. In a table top mixer fitted with the paddle attachment, beat the soft cheese at medium-low speed until creamy, about 2 minutes. With the mixer on low, gradually add the sugar, then the flour and a pinch of salt, scraping down the sides of the bowl and the paddle twice.\r\nSwap the paddle attachment for the whisk. Continue by adding the vanilla, lemon zest and juice. Whisk in the eggs and yolk, one at a time, scraping the bowl and whisk at least twice. Stir the 284ml carton of soured cream until smooth, then measure 200ml/7fl oz (just over 3⁄4 of the carton). Continue on low speed as you add the measured soured cream (reserve the rest). Whisk to blend, but don't over-beat. The batter should be smooth, light and somewhat airy.\r\nBrush the sides of the springform tin with melted butter and put on a baking sheet. Pour in the filling - if there are any lumps, sink them using a knife - the top should be as smooth as possible. Bake for 10 minutes. Reduce oven temperature to fan 90C/conventional 110C/gas 1⁄4 and bake for 25 minutes more. If you gently shake the tin, the filling should have a slight wobble. Turn off the oven and open the oven door for a cheesecake that's creamy in the centre, or leave it closed if you prefer a drier texture. Let cool in the oven for 2 hours. The cheesecake may get a slight crack on top as it cools.\r\nCombine the reserved soured cream with the 142ml carton, the sugar and lemon juice for the topping. Spread over the cheesecake right to the edges. Cover loosely with foil and refrigerate for at least 8 hours or overnight.\r\nRun a round-bladed knife around the sides of the tin to loosen any stuck edges. Unlock the side, slide the cheesecake off the bottom of the tin onto a plate, then slide the parchment paper out from underneath.", "equipment_tags": [], "portions": 12, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 512, "protein_g": 7.5, "carbs_g": 30.1, "fat_g": 41.1, "total_kcal": 6140, "total_protein_g": 89.9, "total_carbs_g": 361.0, "total_fat_g": 492.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and bake the crust", "instruction": "Position an oven shelf in the middle and preheat to fan 160°C/180°C/gas 4. Line a springform tin with parchment. Melt the butter, stir in the biscuit crumbs and sugar, press into the base, and bake, then cool on a rack.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Beat the cream cheese", "instruction": "Increase the oven to fan 200°C/240°C/gas 9. Beat the soft cheese until creamy, then gradually add the sugar and flour with a pinch of salt.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Whisk in eggs and sour cream", "instruction": "Switch to the whisk attachment, add the vanilla, lemon zest and juice, then whisk in the eggs and yolk one at a time. Fold in the measured sour cream on low speed until smooth and airy.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake the cheesecake", "instruction": "Pour the filling into the prepared tin, smoothing the top, and bake, then reduce the oven temperature significantly and bake further until just barely wobbling.", "timer_seconds": 2100, "background": true}, {"step": 5, "label": "Cool slowly", "instruction": "Turn off the oven and let the cheesecake cool inside with the door open or closed depending on your preferred texture.", "timer_seconds": 7200, "background": true}, {"step": 6, "label": "Top and chill", "instruction": "Combine the reserved sour cream with the second carton, sugar and lemon juice, spread over the cheesecake, cover loosely, and refrigerate.", "timer_seconds": 28800, "background": true}, {"step": 7, "label": "Unmould and serve", "instruction": "Run a knife around the tin to loosen, unlock the side, and slide the cheesecake onto a plate, removing the parchment from underneath.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=tspdJ6hxqnc"}, {"id": "52859", "name": "Key Lime Pie", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qpqtuu1511386216.jpg", "local_image": "52859.jpg", "ingredients": [{"ingredient": "Digestive Biscuits", "measure": "300g"}, {"ingredient": "Butter", "measure": "150g"}, {"ingredient": "Condensed Milk", "measure": "400g"}, {"ingredient": "Egg Yolks", "measure": "3"}, {"ingredient": "Lime", "measure": "4"}, {"ingredient": "Double Cream", "measure": "300ml"}, {"ingredient": "Icing Sugar", "measure": "1 tbls"}, {"ingredient": "Lime", "measure": "to serve"}], "instructions": "Heat the oven to 160C/fan 140C/gas 3. Whizz the biscuits to crumbs in a food processor (or put in a strong plastic bag and bash with a rolling pin). Mix with the melted butter and press into the base and up the sides of a 22cm loose-based tart tin. Bake in the oven for 10 minutes. Remove and cool.\r\nPut the egg yolks in a large bowl and whisk for a minute with electric beaters. Add the condensed milk and whisk for 3 minutes then add the zest and juice and whisk again for 3 minutes. Pour the filling into the cooled base then put back in the oven for 15 minutes. Cool then chill for at least 3 hours or overnight if you like.\r\nWhen you are ready to serve, carefully remove the pie from the tin and put on a serving plate. To decorate, softly whip together the cream and icing sugar. Dollop or pipe the cream onto the top of the pie and finish with extra lime zest.", "equipment_tags": ["FoodProcessor"], "portions": 11, "prep_minutes": 211, "prep_minutes_source": "explicit", "kcal": 441, "protein_g": 6.2, "carbs_g": 29.2, "fat_g": 34.8, "total_kcal": 4850, "total_protein_g": 68.2, "total_carbs_g": 321.0, "total_fat_g": 382.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and bake the base", "instruction": "Heat the oven to 160°C/fan 140°C/gas 3. Blitz the biscuits to crumbs, mix with melted butter, and press into the base and sides of a 22cm tart tin. Bake, then remove and cool.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Whisk the filling", "instruction": "Whisk the egg yolks for a minute, add the condensed milk and whisk further, then add the lime zest and juice and whisk again.", "timer_seconds": 420, "background": false}, {"step": 3, "label": "Bake the filling", "instruction": "Pour the filling into the cooled base and bake.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Chill", "instruction": "Cool, then chill for at least a few hours or overnight.", "timer_seconds": 10800, "background": true}, {"step": 5, "label": "Decorate and serve", "instruction": "Remove from the tin onto a serving plate. Softly whip the cream and icing sugar, dollop or pipe onto the pie, and finish with extra lime zest.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=q4Rz7tUkX9A"}, {"id": "52860", "name": "Chocolate Raspberry Brownies", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yypvst1511386427.jpg", "local_image": "52860.jpg", "ingredients": [{"ingredient": "Dark Chocolate", "measure": "200g"}, {"ingredient": "Milk Chocolate", "measure": "100g"}, {"ingredient": "Salted Butter", "measure": "250g"}, {"ingredient": "Light Brown Soft Sugar", "measure": "400g"}, {"ingredient": "Eggs", "measure": "4 large"}, {"ingredient": "Plain Flour", "measure": "140g"}, {"ingredient": "Cocoa", "measure": "50g"}, {"ingredient": "Raspberries", "measure": "200g"}], "instructions": "Heat oven to 180C/160C fan/gas 4. Line a 20 x 30cm baking tray tin with baking parchment. Put the chocolate, butter and sugar in a pan and gently melt, stirring occasionally with a wooden spoon. Remove from the heat.\r\nStir the eggs, one by one, into the melted chocolate mixture. Sieve over the flour and cocoa, and stir in. Stir in half the raspberries, scrape into the tray, then scatter over the remaining raspberries. Bake on the middle shelf for 30 mins or, if you prefer a firmer texture, for 5 mins more. Cool before slicing into squares. Store in an airtight container for up to 3 days.", "equipment_tags": [], "portions": 10, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 551, "protein_g": 7.3, "carbs_g": 68.9, "fat_g": 29.8, "total_kcal": 5507, "total_protein_g": 73.5, "total_carbs_g": 688.6, "total_fat_g": 297.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Melt the chocolate mixture", "instruction": "Heat the oven to 180°C/160°C fan/gas 4 and line a baking tray. Melt the chocolate, butter and sugar together in a pan, stirring occasionally, then remove from the heat.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Build the batter", "instruction": "Stir in the eggs one at a time. Sieve over the flour and cocoa and stir in, then stir in half the raspberries.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Scrape into the tray, scatter over the remaining raspberries, and bake on the middle shelf.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Cool and serve", "instruction": "Cool before slicing into squares.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Pi89PqsAaAg"}, {"id": "52861", "name": "Peanut Butter Cheesecake", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qtuuys1511387068.jpg", "local_image": "52861.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Peanut Cookies", "measure": "175g"}, {"ingredient": "Gelatine Leafs", "measure": "5"}, {"ingredient": "Ricotta", "measure": "500g"}, {"ingredient": "Peanut Butter", "measure": "175g"}, {"ingredient": "Golden Syrup", "measure": "175g"}, {"ingredient": "Milk", "measure": "150ml"}, {"ingredient": "Double Cream", "measure": "275ml"}, {"ingredient": "Light Brown Soft Sugar", "measure": "2 tblsp"}, {"ingredient": "Peanut Brittle", "measure": "Crushed"}], "instructions": "Oil and line a 20cm round loose- bottomed cake tin with cling film, making it as smooth as possible. Melt the butter in a pan. Crush the biscuits by bashing them in a bag with a rolling pin, then stir them into the butter until very well coated. Press the mixture firmly into the base of the tin and chill.\r\nSoak the gelatine in water while you make the filling. Tip the ricotta into a bowl, then beat in the peanut butter and syrup. Ricotta has a slightly grainy texture so blitz until smooth with a stick blender for a smoother texture if you prefer.\r\nTake the soaked gelatine from the water and squeeze dry. Put it into a pan with the milk and heat very gently until the gelatine dissolves. Beat into the peanut mixture, then tip onto the biscuit base. Chill until set.\r\nTo freeze, leave in the tin and as soon as it is solid, cover the surface with cling film, then wrap the tin with cling film and foil.\r\nTo defrost, thaw in the fridge overnight.\r\nTo serve, carefully remove from the tin. Whisk the cream with the sugar until it holds its shape, then spread on top of the cheesecake and scatter with the peanut brittle.", "equipment_tags": ["Blender"], "portions": 10, "prep_minutes": 55, "prep_minutes_source": "estimated", "kcal": 548, "protein_g": 8.9, "carbs_g": 31.8, "fat_g": 43.2, "total_kcal": 5483, "total_protein_g": 88.7, "total_carbs_g": 318.1, "total_fat_g": 432.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and chill the base", "instruction": "Oil and line a round tin with cling film. Melt the butter, crush the biscuits and stir into the butter until coated, then press firmly into the base and chill.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Soak the gelatine and make the filling", "instruction": "Soak the gelatine in water. Beat the ricotta with the peanut butter and syrup until smooth.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Dissolve the gelatine", "instruction": "Squeeze dry the soaked gelatine, put it in a pan with the milk, and heat very gently until dissolved. Beat into the peanut mixture.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Set", "instruction": "Tip the filling onto the biscuit base and chill until set.", "timer_seconds": 14400, "background": true}, {"step": 5, "label": "Finish and serve", "instruction": "Remove from the tin, whisk the cream with sugar until it holds its shape, spread on top, and scatter with peanut brittle.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=QSTsturcyL0"}, {"id": "52862", "name": "Peach & Blueberry Grunt", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ssxvup1511387476.jpg", "local_image": "52862.jpg", "ingredients": [{"ingredient": "Corn Flour", "measure": "1 tsp"}, {"ingredient": "Orange", "measure": "Juice of 2"}, {"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Caster Sugar", "measure": "2 tbs"}, {"ingredient": "Peaches", "measure": "6"}, {"ingredient": "Blueberries", "measure": "250g"}, {"ingredient": "Self-raising Flour", "measure": "200g"}, {"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Muscovado Sugar", "measure": "100g"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Milk", "measure": "6 tblsp"}], "instructions": "Heat oven to 190C/170C fan/gas 5. Butter a wide shallow ovenproof dish. Blend the cornflour with the orange zest and juice, and put in a large pan with the sugar. Halve, stone and slice the peaches and add to the pan. Bring slowly to the boil, stirring gently until the sauce is shiny and thickened, about 3-4 mins. Remove from the heat, stir in the blueberries and tip into the prepared dish.\r\nTip the flour into a mixing bowl and add the 50g butter. Rub the butter into the flour until it resembles fine breadcrumbs, then stir in half the sugar. Mix the remaining sugar with the cinnamon and set aside.\r\nAdd the milk to the dry ingredients and mix to a soft dough. Turn out onto a lightly floured surface and knead briefly. Roll out to an oblong roughly 16 x 24cm. Brush with melted butter and sprinkle evenly with the spicy sugar. Roll up from one long side and cut into 12 slices. Arrange around the top of the dish, leaving the centre uncovered.\r\nBake for 20-25 mins, until the topping is crisp and golden. Serve warm.", "equipment_tags": [], "portions": 7, "prep_minutes": 29, "prep_minutes_source": "explicit", "kcal": 266, "protein_g": 3.9, "carbs_g": 51.5, "fat_g": 6.7, "total_kcal": 1862, "total_protein_g": 27.5, "total_carbs_g": 360.3, "total_fat_g": 47.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the fruit filling", "instruction": "Heat the oven to 190°C/170°C fan/gas 5 and butter a shallow ovenproof dish. Blend the cornflour with orange zest and juice, add to a pan with the sugar and sliced peaches, and bring slowly to the boil, stirring, until shiny and thickened.", "timer_seconds": 240, "background": false}, {"step": 2, "label": "Fill the dish", "instruction": "Remove from the heat, stir in the blueberries, and tip into the prepared dish.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the dumpling dough", "instruction": "Rub the butter into the flour until it resembles fine breadcrumbs, stir in half the sugar, and mix the remaining sugar with the cinnamon separately.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Shape the dumplings", "instruction": "Add the milk to the dry ingredients and mix to a soft dough. Knead briefly, roll into an oblong, brush with melted butter, sprinkle with the spicy sugar, roll up, and cut into 12 slices.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Arrange the slices around the top of the dish, leaving the centre uncovered, and bake until the topping is crisp and golden.", "timer_seconds": 1350, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=SNeO28BCpsc"}, {"id": "52863", "name": "Vegetarian Casserole", "category": "Vegetarian", "area": "British", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/vptwyt1511450962.jpg", "local_image": "52863.jpg", "ingredients": [{"ingredient": "Rapeseed Oil", "measure": "1"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Cumin", "measure": "½ tsp"}, {"ingredient": "Thyme", "measure": "1 tblsp"}, {"ingredient": "Carrots", "measure": "3 Medium"}, {"ingredient": "Celery", "measure": "2 small stalks"}, {"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Yellow Pepper", "measure": "1"}, {"ingredient": "Tomato", "measure": "2 x 400g tins"}, {"ingredient": "Vegetable Stock Cube", "measure": "250ml"}, {"ingredient": "Courgettes", "measure": "2 sliced"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Lentils", "measure": "250g"}], "instructions": "Heat the oil in a large, heavy-based pan. Add the onions and cook gently for 5 – 10 mins until softened.\r\nAdd the garlic, spices, dried thyme, carrots, celery and peppers and cook for 5 minutes.\r\nAdd the tomatoes, stock, courgettes and fresh thyme and cook for 20 - 25 minutes.\r\nTake out the thyme sprigs. Stir in the lentils and bring back to a simmer. Serve with wild and white basmati rice, mash or quinoa.", "equipment_tags": [], "portions": 3, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 342, "protein_g": 11.7, "carbs_g": 37.9, "fat_g": 18.2, "total_kcal": 1026, "total_protein_g": 35.0, "total_carbs_g": 113.7, "total_fat_g": 54.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Heat the oil in a large heavy-based pan and cook the onions gently until softened.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Add spices and vegetables", "instruction": "Add the garlic, spices, dried thyme, carrots, celery and peppers and cook.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the casserole", "instruction": "Add the tomatoes, stock, courgettes and fresh thyme and cook until the vegetables are tender.", "timer_seconds": 1350, "background": true}, {"step": 4, "label": "Finish and serve", "instruction": "Remove the thyme sprigs, stir in the lentils, bring back to a simmer, and serve with rice, mash or quinoa.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=oHmKE9mWtWM"}, {"id": "52864", "name": "Mushroom & Chestnut Rotolo", "category": "Vegetarian", "area": "British", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ssyqwr1511451678.jpg", "local_image": "52864.jpg", "ingredients": [{"ingredient": "Mushrooms", "measure": "30g"}, {"ingredient": "Chestnuts", "measure": "240g"}, {"ingredient": "Challots", "measure": "3"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Rosemary", "measure": "3 sprigs"}, {"ingredient": "Wild Mushrooms", "measure": "500g"}, {"ingredient": "Soy Sauce", "measure": "2 tblsp"}, {"ingredient": "White Wine", "measure": "125ml"}, {"ingredient": "Lasagne Sheets", "measure": "350g"}, {"ingredient": "Breadcrumbs", "measure": "4 tbsp"}, {"ingredient": "Sage", "measure": "1/2 handful"}, {"ingredient": "Truffle Oil", "measure": "to serve"}], "instructions": "Soak the dried mushrooms in 350ml boiling water and set aside until needed. Blitz ¾ of the chestnuts with 150ml water until creamy. Roughly chop the remaining chestnuts.\r\nHeat 2 tbsp olive oil in a large non-stick frying pan. Fry the shallots with a pinch of salt until softened, then add the garlic, chopped chestnuts and rosemary, and fry for 2 mins more. Add the wild mushrooms, 2 tbsp oil and some seasoning. Cook for 3 mins until they begin to soften. Drain and roughly chop the dried mushrooms (reserve the soaking liquid), then add those too, along with the soy sauce, and fry for 2 mins more.\r\nWhisk the wine, reserved mushroom liquid and chestnut cream together to create a sauce. Season, then add half to the mushroom mixture in the pan and cook for 1 min until the sauce becomes glossy. Remove and discard the rosemary sprigs, then set the mixture aside.\r\nHeat oven to 180C/160C fan/gas 4. Bring a large pan of salted water to the boil and get a large bowl of ice water ready. Drop the lasagne sheets into the boiling water for 2 mins or until pliable and a little cooked, then immediately plunge them into the cold water. Using your fingers, carefully separate the sheets and transfer to a clean tea towel. Spread a good spoonful of the sauce on the bottom two thirds of each sheet, then, rolling away from yourself, roll up the shorter ends. Cut each roll in half, then position the rolls of pasta cut-side up in a pie dish that you are happy to serve from at the table. If you have any mushroom sauce remaining after you’ve rolled up all the sheets, simply push it into some of the exposed rolls of pasta.\r\nPour the rest of the sauce over the top of the pasta, then bake for 10 mins or until the pasta no longer has any resistance when tested with a skewer.\r\nMeanwhile, put the breadcrumbs, the last 2 tbsp olive oil, sage leaves and some seasoning in a bowl, and toss everything together. Scatter the rotolo with the crumbs and sage, then bake for another 10 mins, until the top is golden and the sage leaves are crispy. Leave to cool for 10 mins to allow the pasta to absorb the sauce, then drizzle with a little truffle oil, if you like, before taking your dish to the table.", "equipment_tags": [], "portions": 3, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 908, "protein_g": 28.1, "carbs_g": 158.1, "fat_g": 16.1, "total_kcal": 2723, "total_protein_g": 84.3, "total_carbs_g": 474.3, "total_fat_g": 48.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the mushrooms and prep the chestnuts", "instruction": "Soak the dried mushrooms in boiling water and set aside. Blitz three quarters of the chestnuts with water until creamy, and roughly chop the rest.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Build the filling", "instruction": "Fry the shallots with salt until softened, add the garlic, chopped chestnuts and rosemary, then add the wild mushrooms, oil and seasoning and cook until beginning to soften.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Add the soaked mushrooms", "instruction": "Drain and chop the dried mushrooms, reserving the liquid, and add to the pan with the soy sauce, frying a couple minutes more.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Make the sauce", "instruction": "Whisk the wine, reserved mushroom liquid and chestnut cream together, season, then stir half into the mushroom mixture and cook until glossy. Discard the rosemary sprigs and set aside.", "timer_seconds": 60, "background": false}, {"step": 5, "label": "Cook and roll the pasta sheets", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Blanch the lasagne sheets in boiling water until pliable, then plunge into ice water. Spread each sheet with the mushroom sauce and roll up, then halve each roll and arrange cut-side up in a pie dish.", "timer_seconds": 120, "background": false}, {"step": 6, "label": "Bake", "instruction": "Pour the remaining sauce over the rolls and bake until the pasta has no resistance when tested with a skewer.", "timer_seconds": 600, "background": true}, {"step": 7, "label": "Top and finish baking", "instruction": "Toss the breadcrumbs, remaining oil, sage and seasoning together, scatter over the rotolo, and bake further until golden and the sage is crispy.", "timer_seconds": 600, "background": true}, {"step": 8, "label": "Rest and serve", "instruction": "Leave to cool a little so the pasta absorbs the sauce, then drizzle with truffle oil if using and serve.", "timer_seconds": 600, "background": true}], "video": "https://www.youtube.com/watch?v=GNN7_ZSJ5YE"}, {"id": "52865", "name": "Matar Paneer", "category": "Vegetarian", "area": "India", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/xxpqsy1511452222.jpg", "local_image": "52865.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "1 tbls"}, {"ingredient": "Paneer", "measure": "225g"}, {"ingredient": "Ginger", "measure": "2"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Turmeric", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "1 tsp"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Tomato", "measure": "4 large"}, {"ingredient": "Peas", "measure": "150g"}, {"ingredient": "Garam Masala", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "Small bunch"}, {"ingredient": "Naan Bread", "measure": "to serve"}], "instructions": "Heat the oil in a frying pan over high heat until it’s shimmering hot. Add the paneer, then turn the heat down a little. Fry until it starts to brown at the edges, then turn it over and brown on each side – the paneer will brown faster than you think, so don’t walk away. Remove the paneer from the pan and drain on kitchen paper.\r\nPut the ginger, cumin, turmeric, ground coriander and chilli in the pan, and fry everything for 1 min. Add the tomatoes, mashing them with the back of a spoon and simmer everything for 5 mins until the sauce smells fragrant. Add a splash of water if it’s too thick. Season well. Add the peas and simmer for a further 2 mins, then stir in the paneer and sprinkle over the garam masala. Divide between two bowls, top with coriander leaves and serve with naan bread, roti or rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 735, "protein_g": 30.2, "carbs_g": 42.9, "fat_g": 50.3, "total_kcal": 1470, "total_protein_g": 60.5, "total_carbs_g": 85.8, "total_fat_g": 100.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the paneer", "instruction": "Heat the oil in a frying pan until shimmering, add the paneer, turn the heat down a little, and fry until browned on each side, watching closely. Remove and drain on kitchen paper.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Fry the spices", "instruction": "Add the ginger, cumin, turmeric, ground coriander and chilli to the pan and fry for a minute.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Build the sauce", "instruction": "Add the tomatoes, mashing with the back of a spoon, and simmer until fragrant, thinning with water if needed. Season well.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Finish", "instruction": "Add the peas and simmer a little longer, then stir in the paneer and sprinkle over the garam masala.", "timer_seconds": 120, "background": false}, {"step": 5, "label": "Serve", "instruction": "Divide between bowls, top with coriander leaves, and serve with naan bread, roti or rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=wlseYNqwLNs"}, {"id": "52866", "name": "Squash linguine", "category": "Vegetarian", "area": "Italian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wxswxy1511452625.jpg", "local_image": "52866.jpg", "ingredients": [{"ingredient": "Butternut Squash", "measure": "350g"}, {"ingredient": "Garlic", "measure": "3 parts"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Linguine Pasta", "measure": "350g"}, {"ingredient": "Sage", "measure": "Small bunch"}], "instructions": "Heat oven to 200C/180C fan/gas 6. Put the squash and garlic on a baking tray and drizzle with the olive oil. Roast for 35-40 mins until soft. Season.\r\nCook the pasta according to pack instructions. Drain, reserving the water. Use a stick blender to whizz the squash with 400ml cooking water. Heat some oil in a frying pan, fry the sage until crisp, then drain on kitchen paper. Tip the pasta and sauce into the pan and warm through. Scatter with sage.", "equipment_tags": ["Blender"], "portions": 6, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 346, "protein_g": 10.4, "carbs_g": 59.1, "fat_g": 8.6, "total_kcal": 2073, "total_protein_g": 62.2, "total_carbs_g": 354.5, "total_fat_g": 51.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the squash", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Put the squash and garlic on a baking tray, drizzle with olive oil, and roast until soft. Season.", "timer_seconds": 2250, "background": true}, {"step": 2, "label": "Cook the pasta", "instruction": "Cook the pasta according to pack instructions, then drain, reserving the cooking water.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Blend the sauce", "instruction": "Use a stick blender to whizz the roasted squash with the reserved cooking water into a sauce.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Crisp the sage", "instruction": "Heat a little oil in a frying pan and fry the sage until crisp, then drain on kitchen paper.", "timer_seconds": 60, "background": false}, {"step": 5, "label": "Combine and serve", "instruction": "Tip the pasta and sauce into the pan and warm through, then scatter with the crispy sage.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=xHZ-PoGwTLQ"}, {"id": "52867", "name": "Vegetarian Chilli", "category": "Vegetarian", "area": "British", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wqurxy1511453156.jpg", "local_image": "52867.jpg", "ingredients": [{"ingredient": "Roasted Vegetables", "measure": "400g"}, {"ingredient": "Kidney Beans", "measure": "1 can"}, {"ingredient": "Chopped Tomatoes", "measure": "1 can"}, {"ingredient": "Mixed Grain", "measure": "1 Packet"}], "instructions": "Heat oven to 200C/180C fan/ gas 6. Cook the vegetables in a casserole dish for 15 mins. Tip in the beans and tomatoes, season, and cook for another 10-15 mins until piping hot. Heat the pouch in the microwave on High for 1 min and serve with the chilli.", "equipment_tags": [], "portions": 3, "prep_minutes": 31, "prep_minutes_source": "explicit", "kcal": 390, "protein_g": 18.8, "carbs_g": 71.6, "fat_g": 3.9, "total_kcal": 1170, "total_protein_g": 56.4, "total_carbs_g": 214.8, "total_fat_g": 11.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the vegetables", "instruction": "Heat the oven to 200°C/180°C fan/gas 6 and cook the roasted vegetables in a casserole dish.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Add beans and tomatoes", "instruction": "Tip in the beans and tomatoes, season, and cook until piping hot.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Heat the grains and serve", "instruction": "Heat the mixed grain pouch in the microwave and serve alongside the chilli.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=D0bFRVH_EqU"}, {"id": "52868", "name": "Kidney Bean Curry", "category": "Vegetarian", "area": "India", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/sywrsu1511463066.jpg", "local_image": "52868.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tbls"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Ginger", "measure": "1 part"}, {"ingredient": "Coriander", "measure": "1 Packet"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Garam Masala", "measure": "2 tsp"}, {"ingredient": "Chopped Tomatoes", "measure": "400g"}, {"ingredient": "Kidney Beans", "measure": "400g"}, {"ingredient": "Basmati Rice", "measure": "to serve"}], "instructions": "Heat the oil in a large frying pan over a low-medium heat. Add the onion and a pinch of salt and cook slowly, stirring occasionally, until softened and just starting to colour. Add the garlic, ginger and coriander stalks and cook for a further 2 mins, until fragrant.\r\n\r\nAdd the spices to the pan and cook for another 1 min, by which point everything should smell aromatic. Tip in the chopped tomatoes and kidney beans in their water, then bring to the boil.\r\n\r\nTurn down the heat and simmer for 15 mins until the curry is nice and thick. Season to taste, then serve with the basmati rice and the coriander leaves.", "equipment_tags": [], "portions": 2, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 655, "protein_g": 24.2, "carbs_g": 82.5, "fat_g": 28.6, "total_kcal": 1310, "total_protein_g": 48.4, "total_carbs_g": 165.0, "total_fat_g": 57.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Heat the oil in a large frying pan over low-medium heat, add the onion and a pinch of salt, and cook slowly, stirring occasionally, until softened and just starting to colour.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Add the aromatics", "instruction": "Add the garlic, ginger and coriander stalks and cook until fragrant.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Add the spices", "instruction": "Add the spices to the pan and cook until aromatic.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Simmer the curry", "instruction": "Tip in the chopped tomatoes and kidney beans with their liquid, bring to the boil, then turn down the heat and simmer until thick.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Serve", "instruction": "Season to taste and serve with basmati rice and coriander leaves.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Tp_PMWvIKzo"}, {"id": "52869", "name": "Tahini Lentils", "category": "Vegetarian", "area": "Moroccan", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/vpxyqt1511464175.jpg", "local_image": "52869.jpg", "ingredients": [{"ingredient": "Tahini", "measure": "50g"}, {"ingredient": "Lemon", "measure": "zest and juice of 1"}, {"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Red Onions", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Yellow Pepper", "measure": "1 thinly sliced"}, {"ingredient": "Green Beans", "measure": "200g"}, {"ingredient": "Courgettes", "measure": "1 sliced"}, {"ingredient": "Kale", "measure": "100g shredded"}, {"ingredient": "Lentils", "measure": "250g pack"}], "instructions": "In a jug, mix the tahini with the zest and juice of the lemon and 50ml of cold water to make a runny dressing. Season to taste, then set aside.\r\nHeat the oil in a wok or large frying pan over a medium-high heat. Add the red onion, along with a pinch of salt, and fry for 2 mins until starting to soften and colour. Add the garlic, pepper, green beans and courgette and fry for 5 min, stirring frequently.\r\nTip in the kale, lentils and the tahini dressing. Keep the pan on the heat for a couple of mins, stirring everything together until the kale is wilted and it’s all coated in the creamy dressing.", "equipment_tags": [], "portions": 2, "prep_minutes": 7, "prep_minutes_source": "explicit", "kcal": 505, "protein_g": 20.7, "carbs_g": 49.8, "fat_g": 28.6, "total_kcal": 1011, "total_protein_g": 41.3, "total_carbs_g": 99.5, "total_fat_g": 57.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dressing", "instruction": "Mix the tahini with the lemon zest and juice and cold water to make a runny dressing. Season and set aside.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the onion", "instruction": "Heat the oil in a wok over medium-high heat, add the red onion with a pinch of salt, and fry until starting to soften and colour.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Cook the vegetables", "instruction": "Add the garlic, pepper, green beans and courgette and fry, stirring frequently, until tender.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Finish and serve", "instruction": "Tip in the kale, lentils and tahini dressing, and keep on the heat, stirring, until the kale is wilted and everything is coated in the creamy dressing.", "timer_seconds": 120, "background": false}], "video": "https://www.youtube.com/watch?v=8kRlmz8pW0I"}, {"id": "52870", "name": "Chickpea Fajitas", "category": "Vegetarian", "area": "Mexican", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/tvtxpq1511464705.jpg", "local_image": "52870.jpg", "ingredients": [{"ingredient": "Chickpeas", "measure": "400g"}, {"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Paprika", "measure": "pinch"}, {"ingredient": "Tomatoes", "measure": "2 small cut chunks"}, {"ingredient": "Red Onions", "measure": "1 finely sliced"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tsp"}, {"ingredient": "Avocado", "measure": "1"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Lime", "measure": "Chopped"}, {"ingredient": "Sour Cream", "measure": "100g"}, {"ingredient": "Harissa Spice", "measure": "2 tsp"}, {"ingredient": "Corn Tortillas", "measure": "4"}, {"ingredient": "Coriander", "measure": "to serve"}], "instructions": "Heat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Drain the chickpeas, pat dry and tip onto the prepared baking tray. Add the oil and paprika, toss to coat, then roast for 20-25 mins until browned and crisp, shaking halfway through cooking.\r\n\r\nMeanwhile, put the tomatoes and onion in a small bowl with the vinegar and set aside to pickle. Put the avocado in another bowl and mash with a fork, leaving some larger chunks. Stir in the lime juice and season well. Mix the soured cream with the harissa and set aside until ready to serve.\r\n\r\nHeat a griddle pan until nearly smoking. Add the tortillas , one at a time, charring each side until hot with griddle lines. \r\n\r\nPut everything on the table and build the fajitas : spread a little of the harissa cream over the tortilla, top with roasted chickpeas, guacamole, pickled salsa and coriander, if you like. Serve with the lime wedges for squeezing over.", "equipment_tags": [], "portions": 2, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 806, "protein_g": 27.4, "carbs_g": 117.4, "fat_g": 28.9, "total_kcal": 1611, "total_protein_g": 54.8, "total_carbs_g": 234.7, "total_fat_g": 57.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the chickpeas", "instruction": "Heat the oven to 200°C/180°C fan/gas 6 and line a tray with foil. Drain and pat dry the chickpeas, toss with oil and paprika on the tray, and roast, shaking halfway, until browned and crisp.", "timer_seconds": 1350, "background": true}, {"step": 2, "label": "Pickle the salsa", "instruction": "Meanwhile, put the tomatoes and onion in a bowl with the vinegar and set aside to pickle.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Make the guacamole and harissa cream", "instruction": "Mash the avocado with a fork leaving some chunks, stir in the lime juice and season. Mix the sour cream with the harissa and set aside.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Char the tortillas", "instruction": "Heat a griddle pan until nearly smoking and char the tortillas one at a time on each side.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Assemble and serve", "instruction": "Spread harissa cream over each tortilla, top with roasted chickpeas, guacamole, pickled salsa and coriander, and serve with lime wedges.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=LGY3V7EGpT0"}, {"id": "52871", "name": "Yaki Udon", "category": "Vegetarian", "area": "Japanese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wrustq1511475474.jpg", "local_image": "52871.jpg", "ingredients": [{"ingredient": "Udon Noodles", "measure": "250g"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Cabbage", "measure": "0.25"}, {"ingredient": "Shiitake Mushrooms", "measure": "10"}, {"ingredient": "Spring Onions", "measure": "4"}, {"ingredient": "Mirin", "measure": "4 tbsp"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Caster Sugar", "measure": "1 tblsp"}, {"ingredient": "Worcestershire Sauce", "measure": "1 tblsp"}], "instructions": "Boil some water in a large saucepan. Add 250ml cold water and the udon noodles. (As they are so thick, adding cold water helps them to cook a little bit slower so the middle cooks through). If using frozen or fresh noodles, cook for 2 mins or until al dente; dried will take longer, about 5-6 mins. Drain and leave in the colander.\r\nHeat 1 tbsp of the oil, add the onion and cabbage and sauté for 5 mins until softened. Add the mushrooms and some spring onions, and sauté for 1 more min. Pour in the remaining sesame oil and the noodles. If using cold noodles, let them heat through before adding the ingredients for the sauce – otherwise tip in straight away and keep stir-frying until sticky and piping hot. Sprinkle with the remaining spring onions.", "equipment_tags": [], "portions": 3, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 357, "protein_g": 12.0, "carbs_g": 56.7, "fat_g": 10.4, "total_kcal": 1071, "total_protein_g": 36.1, "total_carbs_g": 170.0, "total_fat_g": 31.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the noodles", "instruction": "Boil water in a large saucepan, add cold water and the udon noodles, and cook until al dente (timing depends on fresh, frozen or dried noodles). Drain and leave in the colander.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Sauté the vegetables", "instruction": "Heat 1 tbsp of the oil, add the onion and cabbage, and sauté until softened. Add the mushrooms and some spring onions and sauté a minute more.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Combine and finish", "instruction": "Pour in the remaining sesame oil and the noodles with the sauce ingredients, and keep stir-frying until sticky and piping hot. Sprinkle with the remaining spring onions.", "timer_seconds": 180, "background": false}], "video": "https://www.youtube.com/watch?v=5Iy0MCowSvA"}, {"id": "52872", "name": "Spanish Tortilla", "category": "Vegetarian", "area": "Spanish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/quuxsx1511476154.jpg", "local_image": "52872.jpg", "ingredients": [{"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Olive Oil", "measure": "4 tbsp"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Potatoes", "measure": "400g"}, {"ingredient": "Garlic", "measure": "6 cloves"}, {"ingredient": "Eggs", "measure": "8"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Baguette", "measure": "1"}, {"ingredient": "Vine Tomatoes", "measure": "4"}, {"ingredient": "Olive Oil", "measure": "drizzle"}], "instructions": "Put a large non-stick frying pan on a low heat. Cook the onion slowly in the oil and butter until soft but not brown – this should take about 15 mins. Add the potatoes, cover the pan and cook for a further 15-20 mins, stirring occasionally to make sure they fry evenly.\r\nWhen the potatoes are soft and the onion is shiny, crush 2 garlic cloves and stir in, followed by the beaten eggs.\r\nPut the lid back on the pan and leave the tortilla to cook gently. After 20 mins, the edges and base should be golden, the top set but the middle still a little wobbly. To turn it over, slide it onto a plate and put another plate on top, turn the whole thing over and slide it back into the pan to finish cooking. Once cooked, transfer to a plate and serve the tortilla warm or cold, scattered with the chopped parsley.\r\nTo accompany, take slices of warmed baguette, stab all over with a fork and rub with the remaining garlic, pile on grated tomatoes and season with sea salt and a drizzle of olive oil.", "equipment_tags": [], "portions": 3, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 700, "protein_g": 23.9, "carbs_g": 44.2, "fat_g": 49.4, "total_kcal": 2101, "total_protein_g": 71.6, "total_carbs_g": 132.6, "total_fat_g": 148.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Cook the onion slowly in the oil and butter in a large non-stick frying pan over low heat until soft but not brown.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Cook the potatoes", "instruction": "Add the potatoes, cover the pan, and cook, stirring occasionally, until soft and the onion is shiny.", "timer_seconds": 1050, "background": true}, {"step": 3, "label": "Add eggs", "instruction": "Crush 2 garlic cloves and stir in, followed by the beaten eggs.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the tortilla", "instruction": "Put the lid back on and cook gently until the edges and base are golden, the top set but the middle still a little wobbly, then flip using a plate and slide back into the pan to finish cooking.", "timer_seconds": 1200, "background": true}, {"step": 5, "label": "Serve", "instruction": "Transfer to a plate and serve warm or cold, scattered with chopped parsley, alongside garlic-rubbed grated tomato baguette slices.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=JceGMNG7rpU"}, {"id": "52873", "name": "Beef Dumpling Stew", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/uyqrrv1511553350.jpg", "local_image": "52873.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Beef", "measure": "750g"}, {"ingredient": "Plain Flour", "measure": "2 tblsp"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Onions", "measure": "175g"}, {"ingredient": "Celery", "measure": "150g"}, {"ingredient": "Carrots", "measure": "150g"}, {"ingredient": "Leek", "measure": "2 chopped"}, {"ingredient": "Swede", "measure": "200g"}, {"ingredient": "Red Wine", "measure": "150ml"}, {"ingredient": "Beef Stock", "measure": "500g"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Thyme", "measure": "3 tbs"}, {"ingredient": "Parsley", "measure": "3 tblsp chopped"}, {"ingredient": "Plain Flour", "measure": "125g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Suet", "measure": "60g"}, {"ingredient": "Water", "measure": "Splash"}], "instructions": "Preheat the oven to 180C/350F/Gas 4.\r\n\r\nFor the beef stew, heat the oil and butter in an ovenproof casserole and fry the beef until browned on all sides.\r\n\r\nSprinkle over the flour and cook for a further 2-3 minutes.\r\n\r\nAdd the garlic and all the vegetables and fry for 1-2 minutes.\r\n\r\nStir in the wine, stock and herbs, then add the Worcestershire sauce and balsamic vinegar, to taste. Season with salt and freshly ground black pepper.\r\n\r\nCover with a lid, transfer to the oven and cook for about two hours, or until the meat is tender.\r\n\r\nFor the dumplings, sift the flour, baking powder and salt into a bowl.\r\nAdd the suet and enough water to form a thick dough.\r\n\r\nWith floured hands, roll spoonfuls of the dough into small balls.\r\n\r\nAfter two hours, remove the lid from the stew and place the balls on top of the stew. Cover, return to the oven and cook for a further 20 minutes, or until the dumplings have swollen and are tender. (If you prefer your dumplings with a golden top, leave the lid off when returning to the oven.)\r\n\r\nTo serve, place a spoonful of mashed potato onto each of four serving plates and top with the stew and dumplings. Sprinkle with chopped parsley.", "equipment_tags": [], "portions": 5, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 663, "protein_g": 36.0, "carbs_g": 39.7, "fat_g": 38.3, "total_kcal": 3317, "total_protein_g": 180.2, "total_carbs_g": 198.6, "total_fat_g": 191.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "Preheat the oven to 180°C/350°F/gas 4. Heat the oil and butter in an ovenproof casserole and fry the beef until browned on all sides.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Cook the flour and vegetables", "instruction": "Sprinkle over the flour and cook a couple minutes, then add the garlic and all the vegetables and fry.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Braise the stew", "instruction": "Stir in the wine, stock and herbs, add the Worcestershire sauce and balsamic vinegar to taste, season, cover with a lid, and cook in the oven until the meat is tender.", "timer_seconds": 7200, "background": true}, {"step": 4, "label": "Make the dumplings", "instruction": "Sift the flour, baking powder and salt into a bowl, add the suet and enough water to form a thick dough, then roll into small balls with floured hands.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Add the dumplings", "instruction": "After the stew has cooked, remove the lid, place the dumpling balls on top, cover, and return to the oven until the dumplings have swollen and are tender.", "timer_seconds": 1200, "background": true}, {"step": 6, "label": "Serve", "instruction": "Spoon mashed potato onto each plate, top with the stew and dumplings, and sprinkle with parsley.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=6NgheY-r5t0"}, {"id": "52874", "name": "Beef and Mustard Pie", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/sytuqu1511553755.jpg", "local_image": "52874.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1kg"}, {"ingredient": "Plain Flour", "measure": "2 tbs"}, {"ingredient": "Rapeseed Oil", "measure": "2 tbs"}, {"ingredient": "Red Wine", "measure": "200ml"}, {"ingredient": "Beef Stock", "measure": "400ml"}, {"ingredient": "Onion", "measure": "1 finely sliced"}, {"ingredient": "Carrots", "measure": "2 chopped"}, {"ingredient": "Thyme", "measure": "3 sprigs"}, {"ingredient": "Mustard", "measure": "2 tbs"}, {"ingredient": "Egg Yolks", "measure": "2 free-range"}, {"ingredient": "Puff Pastry", "measure": "400g"}, {"ingredient": "Green Beans", "measure": "300g"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Pepper", "measure": "pinch"}], "instructions": "Preheat the oven to 150C/300F/Gas 2.\r\nToss the beef and flour together in a bowl with some salt and black pepper.\r\nHeat a large casserole until hot, add half of the rapeseed oil and enough of the beef to just cover the bottom of the casserole.\r\nFry until browned on each side, then remove and set aside. Repeat with the remaining oil and beef.\r\nReturn the beef to the pan, add the wine and cook until the volume of liquid has reduced by half, then add the stock, onion, carrots, thyme and mustard, and season well with salt and pepper.\r\nCover with a lid and place in the oven for two hours.\r\nRemove from the oven, check the seasoning and set aside to cool. Remove the thyme.\r\nWhen the beef is cool and you're ready to assemble the pie, preheat the oven to 200C/400F/Gas 6.\r\nTransfer the beef to a pie dish, brush the rim with the beaten egg yolks and lay the pastry over the top. Brush the top of the pastry with more beaten egg.\r\nTrim the pastry so there is just enough excess to crimp the edges, then place in the oven and bake for 30 minutes, or until the pastry is golden-brown and cooked through.\r\nFor the green beans, bring a saucepan of salted water to the boil, add the beans and cook for 4-5 minutes, or until just tender.\r\nDrain and toss with the butter, then season with black pepper.\r\nTo serve, place a large spoonful of pie onto each plate with some green beans alongside.", "equipment_tags": [], "portions": 5, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 1048, "protein_g": 50.7, "carbs_g": 50.1, "fat_g": 69.5, "total_kcal": 5238, "total_protein_g": 253.4, "total_carbs_g": 250.4, "total_fat_g": 347.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sear the beef", "instruction": "Preheat the oven to 150°C/300°F/gas 2. Toss the beef and flour together with seasoning. Heat a casserole, add half the oil and enough beef to cover the bottom, and fry until browned on each side, then remove. Repeat with the remaining oil and beef.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Build the braise", "instruction": "Return the beef to the pan, add the wine, and cook until reduced by half. Add the stock, onion, carrots, thyme and mustard, and season well.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Braise in the oven", "instruction": "Cover with a lid and place in the oven until tender.", "timer_seconds": 7200, "background": true}, {"step": 4, "label": "Cool and assemble the pie", "instruction": "Remove from the oven, check seasoning, remove the thyme, and set aside to cool. When ready, preheat the oven to 200°C/400°F/gas 6, transfer the beef to a pie dish, brush the rim with egg yolk, and lay the pastry over the top, brushing with more egg.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake the pie", "instruction": "Trim the pastry, crimp the edges, and bake until golden-brown and cooked through.", "timer_seconds": 1800, "background": true}, {"step": 6, "label": "Cook the green beans and serve", "instruction": "Bring a pan of salted water to the boil, cook the green beans until just tender, drain and toss with butter and black pepper. Serve alongside the pie.", "timer_seconds": 270, "background": false}], "video": "https://www.youtube.com/watch?v=nMyBC9staMU"}, {"id": "52875", "name": "Chicken Ham and Leek Pie", "category": "Chicken", "area": "British", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/xrrtss1511555269.jpg", "local_image": "52875.jpg", "ingredients": [{"ingredient": "Chicken Stock", "measure": "450ml"}, {"ingredient": "Chicken Breast", "measure": "3"}, {"ingredient": "Butter", "measure": "75g"}, {"ingredient": "Leek", "measure": "2 sliced"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Plain Flour", "measure": "50g"}, {"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "White Wine", "measure": "3 tbs"}, {"ingredient": "Double Cream", "measure": "150ml"}, {"ingredient": "Ham", "measure": "150g"}, {"ingredient": "Sea Salt", "measure": "spinkling"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Plain Flour", "measure": "350g"}, {"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Free-range Egg, Beaten", "measure": "1"}, {"ingredient": "Cold Water", "measure": "1 tbls"}, {"ingredient": "Free-range Egg, Beaten", "measure": "1"}], "instructions": "Heat the chicken stock in a lidded saucepan. Add the chicken breast and bring to a low simmer. Cover with a lid and cook for 10 minutes. Remove the chicken breasts from the water with tongs and place on a plate. Pour the cooking liquor into a large jug.\r\nMelt 25g/1oz of the butter in a large heavy-based saucepan over a low heat. Stir in the leeks and fry gently for two minutes, stirring occasionally until just softened. Add the garlic and cook for a further minute. Add the remaining butter and stir in the flour as soon as the butter has melted. Cook for 30 seconds, stirring constantly.\r\nSlowly pour the milk into the pan, just a little at a time, stirring well between each adding. Gradually add 250ml/10fl oz of the reserved stock and the wine, if using, stirring until the sauce is smooth and thickened slightly. Bring to a gentle simmer and cook for 3 minutes.\r\nSeason the mixture, to taste, with salt and freshly ground black pepper. Remove from the heat and stir in the cream. Pour into a large bowl and cover the surface of the sauce with cling ilm to prevent a skin forming. Set aside to cool.\r\nPreheat the oven to 200C/400F/Gas 6. Put a baking tray in the oven to heat.\r\nFor the pastry, put the flour and butter in a food processor and blend on the pulse setting until the mixture resembles fine breadcrumbs. With the motor running, add the beaten egg and water and blend until the mixture forms a ball. Portion off 250g/10oz of pastry for the lid.\r\nRoll the remaining pastry out on a lightly floured surface, turning the pastry frequently until around 5mm/¼in thick and 4cm/1½in larger than the pie dish. Lift the pastry over the rolling pin and place it gently into the pie dish. Press the pastry firmly up the sides, making sure there are no air bubbles. Leave the excess pastry overhanging the sides.\r\nCut the chicken breasts into 3cm/1¼in pieces. Stir the chicken, ham and leeks into the cooled sauce. Pour the chicken filling into the pie dish. Brush the rim of the dish with beaten egg. Roll out the reserved pastry for the lid.\r\nCover the pie with the pastry lid and press the edges together firmly to seal. Trim any excess pastry.\r\nMake a small hole in the centre of the pie with the tip of a knife. Glaze the top of the pie with beaten egg. Bake on the preheated tray in the centre of the oven for 35-40 minutes or until the pie is golden-brown all over and the filling is piping hot.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 5, "prep_minutes": 53, "prep_minutes_source": "explicit", "kcal": 1051, "protein_g": 40.6, "carbs_g": 68.4, "fat_g": 67.4, "total_kcal": 5254, "total_protein_g": 203.1, "total_carbs_g": 341.9, "total_fat_g": 336.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Poach the chicken", "instruction": "Heat the chicken stock in a lidded saucepan, add the chicken breast, bring to a low simmer, cover and cook. Remove the chicken and reserve the cooking liquor.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Build the sauce", "instruction": "Melt some of the butter in a saucepan, fry the leeks gently until softened, add the garlic and cook a minute more, then add the remaining butter and stir in the flour once melted, cooking briefly.", "timer_seconds": 210, "background": false}, {"step": 3, "label": "Finish the sauce", "instruction": "Slowly stir in the milk a little at a time, then gradually add the reserved stock and wine, stirring until smooth and thickened. Simmer gently, season, then remove from the heat and stir in the cream.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Cool the filling", "instruction": "Pour into a bowl, cover with cling film to prevent a skin forming, and set aside to cool.", "timer_seconds": null, "background": true}, {"step": 5, "label": "Make the pastry", "instruction": "Preheat the oven to 200°C/400°F/gas 6 and heat a baking tray. Blend the flour and butter in a food processor to fine breadcrumbs, then add the beaten egg and water and blend to a ball. Portion off pastry for the lid.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Line the dish", "instruction": "Roll out the remaining pastry and line the pie dish, pressing firmly up the sides.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Fill and top", "instruction": "Cut the chicken into pieces and stir into the cooled sauce with the ham and leeks, then pour into the pastry case. Brush the rim with egg, roll out the lid, cover the pie and seal the edges.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Bake", "instruction": "Cut a steam hole, glaze with beaten egg, and bake on the preheated tray until golden-brown and the filling is piping hot.", "timer_seconds": 2250, "background": true}], "video": "https://www.youtube.com/watch?v=xr-CpPE_lNk"}, {"id": "52876", "name": "Minced Beef Pie", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/xwutvy1511555540.jpg", "local_image": "52876.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Minced Beef", "measure": "500g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Tomato Puree", "measure": "1 tbls"}, {"ingredient": "Plain Flour", "measure": "1 ½ tbsp"}, {"ingredient": "Mushrooms", "measure": "75g"}, {"ingredient": "Beef Stock", "measure": "250ml"}, {"ingredient": "Worcestershire Sauce", "measure": "Dash"}, {"ingredient": "Shortcrust Pastry", "measure": "400g"}, {"ingredient": "Egg Yolks", "measure": "1"}], "instructions": "Preheat the oven to 200C/400F/Gas 6.\r\nHeat the oil in a deep frying pan and fry the beef mince for 4-5 minutes, breaking it up with a wooden spoon as it browns.\r\nAdd the onion and cook for 2-3 minutes, then stir in the tomato purée and cook for 2-3 more minutes. Stir in the flour and cook for a further minute, then add the chopped mushrooms, the stout or beef stock and a couple of dashes of Worcestershire sauce. Bring to the boil, then reduce the heat, cover the pan with a lid and leave to simmer for 20 minutes. Set aside and leave to cool, then turn the meat mixture into a one litre pie dish.\r\nRoll out the pastry on a floured work surface until it is slightly larger than the pie dish. Gently drape the pastry over the dish, pressing firmly onto the edges. Trim, then shape the edges into a fluted shape.\r\nCut some leaf shapes out of the pastry trimmings and decorate the top of the pie, sticking them to the pastry with the beaten egg yolk.\r\nMake three or four slits in the pastry to allow the steam to escape, then brush the pie with the rest of the beaten egg yolk and bake in the oven for 20-25 minutes, or until golden-brown.\r\nTo serve, slice into wedges.", "equipment_tags": [], "portions": 3, "prep_minutes": 53, "prep_minutes_source": "explicit", "kcal": 1271, "protein_g": 43.7, "carbs_g": 84.5, "fat_g": 84.9, "total_kcal": 3813, "total_protein_g": 131.1, "total_carbs_g": 253.4, "total_fat_g": 254.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the mince", "instruction": "Preheat the oven to 200°C/400°F/gas 6. Heat the oil in a deep frying pan and fry the mince, breaking it up, until browned.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Build the filling", "instruction": "Add the onion and cook, then stir in the tomato purée and cook further. Stir in the flour and cook a minute, then add the mushrooms, stock and Worcestershire sauce.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer", "instruction": "Bring to the boil, then reduce heat, cover, and simmer.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Cool and fill the dish", "instruction": "Set aside to cool, then turn the meat mixture into a pie dish.", "timer_seconds": null, "background": true}, {"step": 5, "label": "Top with pastry", "instruction": "Roll out the pastry slightly larger than the dish, drape over, press onto the edges, trim, and flute. Decorate with pastry leaf cutouts stuck with egg yolk, then cut steam slits.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake and serve", "instruction": "Brush with the remaining egg yolk and bake until golden-brown, then slice into wedges to serve.", "timer_seconds": 1350, "background": true}], "video": "https://www.youtube.com/watch?v=QY47h-uqq5g"}, {"id": "52877", "name": "Lamb and Potato pie", "category": "Lamb", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sxrpws1511555907.jpg", "local_image": "52877.jpg", "ingredients": [{"ingredient": "Lamb Shoulder", "measure": "500g"}, {"ingredient": "Flour", "measure": "1 tbls"}, {"ingredient": "Vegetable Oil", "measure": "Dash"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Carrots", "measure": "2 sliced"}, {"ingredient": "Vegetable Stock", "measure": "350ml/12fl"}, {"ingredient": "Potatoes", "measure": "500g"}, {"ingredient": "Shortcrust Pastry", "measure": "450g"}, {"ingredient": "Eggs", "measure": "To Glaze"}], "instructions": "Dust the meat with flour to lightly coat.\r\nHeat enough vegetable oil in a large saucepan to fill the base, and fry the onion and meat until lightly browned. Season with salt and pepper.\r\nAdd the carrots, stock and more seasoning to taste.\r\nBring to the boil, cover and reduce the heat to a simmer. Simmer for at least an hour or until the meat is tender. Take your time cooking the meat, the longer you leave it to cook, the better the flavour will be.\r\nPreheat the oven to 180C/350F/Gas 4.\r\nAdd the drained potato cubes to the lamb.\r\nTurn the mixture into a pie dish or casserole and cover with the shortcrust pastry. Make three slits in the top of the pastry to release any steam while cooking.\r\nBrush with beaten egg and bake for about 40 minutes, until the pastry is golden brown.\r\nServe.", "equipment_tags": [], "portions": 4, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 1056, "protein_g": 43.7, "carbs_g": 87.6, "fat_g": 59.2, "total_kcal": 4224, "total_protein_g": 174.9, "total_carbs_g": 350.5, "total_fat_g": 236.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the lamb", "instruction": "Dust the meat lightly with flour. Heat oil in a large saucepan and fry the onion and meat until lightly browned. Season.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Simmer the filling", "instruction": "Add the carrots, stock and seasoning, bring to the boil, cover, and simmer until the meat is tender.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Assemble the pie", "instruction": "Preheat the oven to 180°C/350°F/gas 4. Add the drained potato cubes to the lamb, turn into a pie dish, and cover with the shortcrust pastry, cutting a few steam slits.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake and serve", "instruction": "Brush with beaten egg and bake until the pastry is golden brown, then serve.", "timer_seconds": 2400, "background": true}], "video": "https://www.youtube.com/watch?v=NCyPaaUNYUk"}, {"id": "52878", "name": "Beef and Oyster pie", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/wrssvt1511556563.jpg", "local_image": "52878.jpg", "ingredients": [{"ingredient": "Beef", "measure": "900g"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Shallots", "measure": "3"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Bacon", "measure": "125g"}, {"ingredient": "Thyme", "measure": "1 tbs chopped"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Stout", "measure": "330ml"}, {"ingredient": "Beef Stock", "measure": "400ml"}, {"ingredient": "Corn Flour", "measure": "2 tbs"}, {"ingredient": "Oysters", "measure": "8"}, {"ingredient": "Plain Flour", "measure": "400g"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Butter", "measure": "250g"}, {"ingredient": "Eggs", "measure": "To Glaze"}], "instructions": "Season the beef cubes with salt and black pepper. Heat a tablespoon of oil in the frying pan and fry the meat over a high heat. Do this in three batches so that you don’t overcrowd the pan, transferring the meat to a large flameproof casserole dish once it is browned all over. Add extra oil if the pan seems dry.\r\nIn the same pan, add another tablespoon of oil and cook the shallots for 4-5 minutes, then add the garlic and fry for 30 seconds. Add the bacon and fry until slightly browned. Transfer the onion and bacon mixture to the casserole dish and add the herbs.\r\nPreheat the oven to 180C/350F/Gas 4.\r\nPour the stout into the frying pan and bring to the boil, stirring to lift any stuck-on browned bits from the bottom of the pan. Pour the stout over the beef in the casserole dish and add the stock. Cover the casserole and place it in the oven for 1½-2 hours, or until the beef is tender and the sauce is reduced.\r\nSkim off any surface fat, taste and add salt and pepper if necessary, then stir in the cornflour paste. Put the casserole dish on the hob – don’t forget that it will be hot – and simmer for 1-2 minutes, stirring, until thickened. Leave to cool.\r\nIncrease the oven to 200C/400F/Gas 6. To make the pastry, put the flour and salt in a very large bowl. Grate the butter and stir it into the flour in three batches. Gradually add 325ml/11fl oz cold water – you may not need it all – and stir with a round-bladed knife until the mixture just comes together. Knead the pastry lightly into a ball on a lightly floured surface and set aside 250g/9oz for the pie lid.\r\nRoll the rest of the pastry out until about 2cm/¾in larger than the dish you’re using. Line the dish with the pastry then pile in the filling, tucking the oysters in as well. Brush the edge of the pastry with beaten egg.\r\nRoll the remaining pastry until slightly larger than your dish and gently lift over the filling, pressing the edges firmly to seal, then trim with a sharp knife. Brush with beaten egg to glaze. Put the dish on a baking tray and bake for 25-30 minutes, or until the pastry is golden-brown and the filling is bubbling.", "equipment_tags": [], "portions": 6, "prep_minutes": 157, "prep_minutes_source": "explicit", "kcal": 1097, "protein_g": 52.1, "carbs_g": 63.7, "fat_g": 68.9, "total_kcal": 6582, "total_protein_g": 312.7, "total_carbs_g": 382.3, "total_fat_g": 413.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "Season the beef cubes. Heat oil in a frying pan and fry the meat over high heat in batches until browned all over, transferring to a casserole dish.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Cook the aromatics", "instruction": "In the same pan, cook the shallots, then the garlic, then the bacon until slightly browned. Transfer to the casserole with the herbs.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Braise in the oven", "instruction": "Preheat the oven to 180°C/350°F/gas 4. Deglaze the frying pan with the stout, pour over the beef, add the stock, cover, and braise in the oven until tender.", "timer_seconds": 6300, "background": true}, {"step": 4, "label": "Thicken and cool", "instruction": "Skim off fat, adjust seasoning, stir in the cornflour paste, and simmer on the hob until thickened, then leave to cool.", "timer_seconds": 90, "background": false}, {"step": 5, "label": "Make the pastry", "instruction": "Increase the oven to 200°C/400°F/gas 6. Grate the butter into the flour and salt in batches, gradually add cold water, and stir until it just comes together. Knead lightly and set aside pastry for the lid.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Line the dish", "instruction": "Roll out the rest of the pastry, line the dish, then pile in the filling and oysters, brushing the pastry edge with egg.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Top and bake", "instruction": "Roll out the lid pastry, lift over the filling, seal and trim the edges, brush with egg, and bake until golden-brown and bubbling.", "timer_seconds": 1650, "background": true}], "video": "https://www.youtube.com/watch?v=ONX74yP6JnI"}, {"id": "52879", "name": "Chicken Parmentier", "category": "Chicken", "area": "France", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/uwvxpv1511557015.jpg", "local_image": "52879.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1.5kg"}, {"ingredient": "Butter", "measure": "30g"}, {"ingredient": "Double Cream", "measure": "5 tblsp"}, {"ingredient": "Egg Yolks", "measure": "2"}, {"ingredient": "Butter", "measure": "30g"}, {"ingredient": "Shallots", "measure": "7"}, {"ingredient": "Carrots", "measure": "3 chopped"}, {"ingredient": "Celery", "measure": "2 sticks"}, {"ingredient": "Garlic Clove", "measure": "1 finely chopped"}, {"ingredient": "White Wine", "measure": "4 tbsp"}, {"ingredient": "Tomato Puree", "measure": "1 tbls"}, {"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Chicken Stock", "measure": "350ml"}, {"ingredient": "Chicken", "measure": "600g"}, {"ingredient": "Black Olives", "measure": "16"}, {"ingredient": "Parsley", "measure": "2 tbs"}, {"ingredient": "Gruyere cheese", "measure": "50g"}], "instructions": "For the topping, boil the potatoes in salted water until tender. Drain and push through a potato ricer, or mash thoroughly. Stir in the butter, cream and egg yolks. Season and set aside.\r\nFor the filling, melt the butter in a large pan. Add the shallots, carrots and celery and gently fry until soft, then add the garlic. Pour in the wine and cook for 1 minute. Stir in the tomato purée, chopped tomatoes and stock and cook for 10–15 minutes, until thickened. Add the shredded chicken, olives and parsley. Season to taste with salt and pepper.\r\nPreheat the oven to 180C/160C Fan/Gas 4.\r\nPut the filling in a 20x30cm/8x12in ovenproof dish and top with the mashed potato. Grate over the Gruyère. Bake for 30–35 minutes, until piping hot and the potato is golden-brown.", "equipment_tags": [], "portions": 9, "prep_minutes": 51, "prep_minutes_source": "explicit", "kcal": 537, "protein_g": 24.1, "carbs_g": 47.5, "fat_g": 28.7, "total_kcal": 4834, "total_protein_g": 216.8, "total_carbs_g": 427.3, "total_fat_g": 258.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the mash topping", "instruction": "Boil the potatoes in salted water until tender, drain, and mash or push through a ricer. Stir in the butter, cream and egg yolks, season, and set aside.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Cook the vegetables", "instruction": "Melt the butter in a large pan, add the shallots, carrots and celery, and gently fry until soft, then add the garlic.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Build the sauce", "instruction": "Pour in the wine and cook for a minute, then stir in the tomato purée, chopped tomatoes and stock, and cook until thickened.", "timer_seconds": 750, "background": false}, {"step": 4, "label": "Finish the filling", "instruction": "Add the shredded chicken, olives and parsley, and season to taste.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Assemble and bake", "instruction": "Preheat the oven to 180°C/160°C fan/gas 4. Put the filling in an ovenproof dish, top with the mashed potato, grate over Gruyère, and bake until piping hot and golden-brown.", "timer_seconds": 1950, "background": true}], "video": "https://www.youtube.com/watch?v=tiG-xlmeyjg"}, {"id": "52880", "name": "McSinghs Scotch pie", "category": "Lamb", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vssrtx1511557680.jpg", "local_image": "52880.jpg", "ingredients": [{"ingredient": "Cumin", "measure": "2 tsp"}, {"ingredient": "Rapeseed Oil", "measure": "1 tbs"}, {"ingredient": "Red Onions", "measure": "2 finely chopped"}, {"ingredient": "Garlic Clove", "measure": "6"}, {"ingredient": "Green Chilli", "measure": "3 finely chopped"}, {"ingredient": "Red Pepper", "measure": "1 finely chopped"}, {"ingredient": "Nutmeg", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "2 tsp"}, {"ingredient": "Lamb Mince", "measure": "1kg"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "3 tbs"}, {"ingredient": "Plain Flour", "measure": "340g"}, {"ingredient": "Salt", "measure": "½ tsp"}, {"ingredient": "Milk", "measure": "90 ml"}, {"ingredient": "Lard", "measure": "150g"}, {"ingredient": "Egg Yolks", "measure": "Beaten"}], "instructions": "Heat a large frying pan and toast the cumin seeds for a few minutes, then set aside. Heat the oil in the same pan and fry the onion, garlic, chilli, pepper and a good pinch of salt for around eight minutes, until there is no moisture left. Remove from the heat, stir in the toasted cumin seeds, ground mace (or nutmeg) and ground coriander. Leave to cool.\r\nIn a large bowl mix together the minced lamb, white pepper, fresh coriander, and the cooled spiced onion mixture until combined. Set aside, covered, in the fridge.\r\nPreheat the oven to 200C/400F/Gas 6 and generously grease a 20cm/8in diameter loose-bottomed or springform round cake tin with lard.\r\nTo make the pastry, sift the flour and salt in a large bowl and make a well in the centre.\r\nPut the milk, lard and 90ml/3fl oz of water in a saucepan and heat gently. When the lard has melted, increase the heat and bring to the boil.\r\nPour the boiling liquid into the flour, and use a wooden spoon to combine until cool enough to handle. Bring together into a ball.\r\nDust a work surface with flour and, working quickly, knead the dough briefly – it will be soft and moist. Set aside a third of the pastry and roll the rest out on a well-floured surface. Line the pie dish with the pastry, pressing it right up the sides until it pokes just over the top of the tin.\r\nAdd the filling into the pastry-lined tin bit by bit. As you reach the top, form a slight peak. Roll out the reserved pastry and top the pie with it. Pinch the edges to seal and trim the excess. Poke a hole in the top of the pie and insert a small tube made from aluminium foil to allow steam to escape.\r\nBrush the top of the pie with a little beaten egg yolk, and bake in the preheated oven for 30 minutes (put a tray on the shelf below to catch any drips). Then reduce the temperature to 160C/325F/Gas 3 and cook for a further 1¼ hours until golden-brown. Leave to cool completely before refrigerating for two hours, or overnight.\r\nRun a knife around the edge of the pie, remove from the tin and serve with chutneys, salads or pickles.", "equipment_tags": [], "portions": 4, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 1170, "protein_g": 60.2, "carbs_g": 77.6, "fat_g": 66.4, "total_kcal": 4678, "total_protein_g": 240.7, "total_carbs_g": 310.2, "total_fat_g": 265.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Toast and cook the spices", "instruction": "Toast the cumin seeds in a dry pan, then set aside. Heat the oil in the same pan and fry the onion, garlic, chilli, pepper and salt until no moisture remains.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Finish the spice mix", "instruction": "Off the heat, stir in the toasted cumin, nutmeg and coriander, then leave to cool.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Make the filling", "instruction": "Mix the minced lamb, white pepper, fresh coriander and cooled spiced onion mixture together, then cover and chill.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the hot-water pastry", "instruction": "Preheat the oven to 200°C/400°F/gas 6 and grease a cake tin with lard. Sift the flour and salt into a bowl. Heat the milk, lard and water in a pan until boiling, then pour into the flour and combine with a wooden spoon into a dough.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Line the tin", "instruction": "Knead the dough briefly, set aside a third for the lid, then roll the rest out and line the tin, pressing up the sides.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Fill and top", "instruction": "Pack in the filling, forming a peak, then top with the rolled-out reserved pastry, pinching to seal and trimming. Poke a steam hole with a foil tube.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Bake", "instruction": "Brush with egg yolk and bake, then reduce the oven temperature and continue baking until golden-brown.", "timer_seconds": 6300, "background": true}, {"step": 8, "label": "Cool and chill", "instruction": "Leave to cool completely, then refrigerate before serving with chutneys, salads or pickles.", "timer_seconds": 7200, "background": true}], "video": "https://www.youtube.com/watch?v=1nArqhRyszw"}, {"id": "52881", "name": "Steak and Kidney Pie", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/qysyss1511558054.jpg", "local_image": "52881.jpg", "ingredients": [{"ingredient": "Puff Pastry", "measure": "300g"}, {"ingredient": "Egg White", "measure": "Beaten"}, {"ingredient": "Egg Yolks", "measure": "Beaten"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Beef", "measure": "70 ml"}, {"ingredient": "Lamb Kidney", "measure": "200g"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Plain Flour", "measure": "30g"}, {"ingredient": "Beef Stock", "measure": "85 ml"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Worcestershire Sauce", "measure": "Dash"}], "instructions": "Preheat the oven to 220C/425F/Gas 7\r\nHeat the vegetable oil in a large frying pan, and brown the beef all over. (You may need to do this in batches.) Set aside, then brown the kidneys on both sides in the same pan. Add the onions and cook for 3-4 minutes.\r\nReturn the beef to the pan, sprinkle flour over and coat the meat and onions\r\nAdd the stock to the pan, stir well and bring to the boil.\r\nTurn the heat down and simmer for 1½ hours without a lid. If the liquid evaporates too much, add more stock.\r\nRemove from the heat. Add salt, pepper and Worcestershire sauce and allow to cool completely. Place the cooked meat mixture into a pie dish.\r\nRoll out the pastry to 5mm/¼in thick and 5cm/2in larger than the dish you are using.\r\nUsing a rolling pin, lift the pastry and place it over the top of the pie dish. Trim and crimp the edges with your fingers and thumb.\r\nBrush the surface with the beaten egg mixture and bake for 30-40 minutes until golden-brown and puffed.\r\nServe with creamy mash and steamed vegetables to soak up the gravy.", "equipment_tags": [], "portions": 2, "prep_minutes": 44, "prep_minutes_source": "explicit", "kcal": 1474, "protein_g": 48.0, "carbs_g": 90.3, "fat_g": 103.0, "total_kcal": 2948, "total_protein_g": 96.0, "total_carbs_g": 180.7, "total_fat_g": 206.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the meat", "instruction": "Preheat the oven to 220°C/425°F/gas 7. Heat oil in a large frying pan and brown the beef all over in batches, then set aside. Brown the kidneys in the same pan.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Cook the onions and thicken", "instruction": "Add the onions and cook, then return the beef to the pan, sprinkle over flour, and coat the meat and onions.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the filling", "instruction": "Add the stock, stir well, bring to the boil, then turn down and simmer without a lid, topping up with more stock if it evaporates too much.", "timer_seconds": 5400, "background": true}, {"step": 4, "label": "Cool and fill", "instruction": "Remove from heat, season with salt, pepper and Worcestershire sauce, allow to cool completely, then place in a pie dish.", "timer_seconds": null, "background": true}, {"step": 5, "label": "Top and bake", "instruction": "Roll out the pastry larger than the dish, place over the top, trim and crimp the edges, brush with beaten egg, and bake until golden-brown and puffed.", "timer_seconds": 2100, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve with creamy mash and steamed vegetables.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=oTw5tPt4KmA"}, {"id": "52882", "name": "Three Fish Pie", "category": "Seafood", "area": "British", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/spswqs1511558697.jpg", "local_image": "52882.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1kg"}, {"ingredient": "Butter", "measure": "Knob"}, {"ingredient": "Milk", "measure": "Dash"}, {"ingredient": "Gruyere", "measure": "50g"}, {"ingredient": "Butter", "measure": "75g"}, {"ingredient": "Leek", "measure": "2 sliced"}, {"ingredient": "Plain Flour", "measure": "75g"}, {"ingredient": "White Wine", "measure": "150ml"}, {"ingredient": "Milk", "measure": "568ml"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}, {"ingredient": "Salmon", "measure": "250g"}, {"ingredient": "Haddock", "measure": "250g"}, {"ingredient": "Smoked Haddock", "measure": "250g"}, {"ingredient": "Eggs", "measure": "6"}], "instructions": "Preheat the oven to 200C/400F/Gas 6 (180C fan).\r\nPut the potatoes into a saucepan of cold salted water. Bring up to the boil and simmer until completely tender. Drain well and then mash with the butter and milk. Add pepper and taste to check the seasoning. Add salt and more pepper if necessary.\r\nFor the fish filling, melt the butter in a saucepan, add the leeks and stir over the heat. Cover with a lid and simmer gently for 10 minutes, or until soft. Measure the flour into a small bowl. Add the wine and whisk together until smooth.\r\nAdd the milk to the leeks, bring to the boil and then add the wine mixture. Stir briskly until thickened. Season and add the parsley and fish. Stir over the heat for two minutes, then spoon into an ovenproof casserole. Scatter over the eggs. Allow to cool until firm.\r\nSpoon the mashed potatoes over the fish mixture and mark with a fork. Sprinkle with cheese.\r\nBake for 30-40 minutes, or until lightly golden-brown on top and bubbling around the edges.", "equipment_tags": [], "portions": 6, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 633, "protein_g": 40.4, "carbs_g": 46.2, "fat_g": 29.3, "total_kcal": 3796, "total_protein_g": 242.6, "total_carbs_g": 277.5, "total_fat_g": 176.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and make the mash", "instruction": "Preheat the oven to 200°C/400°F/gas 6. Boil the potatoes until tender, drain, and mash with butter and milk, seasoning to taste.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Cook the leeks", "instruction": "Melt the butter in a saucepan, add the leeks, and simmer gently until soft. Whisk the flour with the wine until smooth.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Build the sauce", "instruction": "Add the milk to the leeks, bring to the boil, then add the wine mixture and stir briskly until thickened. Season and add the parsley and fish.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Assemble", "instruction": "Stir over the heat for two minutes, then spoon into an ovenproof casserole. Scatter over the eggs and allow to cool until firm.", "timer_seconds": 120, "background": true}, {"step": 5, "label": "Top and bake", "instruction": "Spoon the mashed potato over the fish mixture, mark with a fork, sprinkle with cheese, and bake until lightly golden-brown and bubbling.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=Ds1Jb8H5Sg8"}, {"id": "52883", "name": "Sticky Toffee Pudding", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xqqqtu1511637379.jpg", "local_image": "52883.jpg", "ingredients": [{"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Muscovado Sugar", "measure": "175g"}, {"ingredient": "Eggs", "measure": "2 large"}, {"ingredient": "Self-raising Flour", "measure": "225g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Bicarbonate Of Soda", "measure": "1 tsp"}, {"ingredient": "Black Treacle", "measure": "3 tbs"}, {"ingredient": "Milk", "measure": "275ml"}, {"ingredient": "Double Cream", "measure": "to serve"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Muscovado Sugar", "measure": "125g"}, {"ingredient": "Black Treacle", "measure": "1 tbs"}, {"ingredient": "Double Cream", "measure": "300ml"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}], "instructions": "Preheat the oven to 180C/160C Fan/Gas 4. Butter a wide shallow 1.7-litre/3-pint ovenproof dish.\r\nPut the butter, sugar, eggs, flour, baking powder, bicarbonate of soda and treacle into a mixing bowl. Beat using an electric handheld whisk for about 30 seconds or until combined. Pour in the milk gradually and whisk again until smooth. Pour into the prepared dish. Bake for 35–40 minutes or until well risen and springy in the centre.\r\nTo make the sauce, put all the ingredients into a saucepan and stir over a low heat until the sugar has dissolved and the butter has melted. Bring to the boil, stirring for a minute.\r\nTo serve, pour half the sauce over the pudding in the baking dish. Serve with the cream or ice cream.", "equipment_tags": [], "portions": 10, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 528, "protein_g": 5.5, "carbs_g": 53.3, "fat_g": 34.2, "total_kcal": 5280, "total_protein_g": 54.9, "total_carbs_g": 532.9, "total_fat_g": 341.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and make the batter", "instruction": "Preheat the oven to 180°C/160°C fan/gas 4 and butter an ovenproof dish. Beat the butter, sugar, eggs, flour, baking powder, bicarbonate of soda and treacle together, then gradually whisk in the milk.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bake", "instruction": "Pour into the prepared dish and bake until well risen and springy in the centre.", "timer_seconds": 2250, "background": true}, {"step": 3, "label": "Make the sauce", "instruction": "Put all the sauce ingredients in a saucepan and stir over low heat until the sugar dissolves and butter melts, then bring to the boil and stir for a minute.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Serve", "instruction": "Pour half the sauce over the pudding and serve with cream or ice cream.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Wytv3bjqJII"}, {"id": "52884", "name": "Lancashire hotpot", "category": "Lamb", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uttrxw1511637813.jpg", "local_image": "52884.jpg", "ingredients": [{"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Lamb", "measure": "900g"}, {"ingredient": "Lamb Kidney", "measure": "3"}, {"ingredient": "Onions", "measure": "2 medium"}, {"ingredient": "Carrots", "measure": "4 sliced"}, {"ingredient": "Plain Flour", "measure": "25g"}, {"ingredient": "Worcestershire Sauce", "measure": "2 tsp"}, {"ingredient": "Chicken Stock", "measure": "500ml"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Potatoes", "measure": "900g"}], "instructions": "Heat oven to 160C/fan 140C/gas 3. Heat some dripping or butter in a large shallow casserole dish, brown the lamb in batches, lift to a plate, then repeat with the kidneys.\r\nFry the onions and carrots in the pan with a little more dripping until golden. Sprinkle over the flour, allow to cook for a couple of mins, shake over the Worcestershire sauce, pour in the stock, then bring to the boil. Stir in the meat and bay leaves, then turn off the heat. Arrange the sliced potatoes on top of the meat, then drizzle with a little more dripping. Cover, then place in the oven for about 1½ hrs until the potatoes are cooked.\r\nRemove the lid, brush the potatoes with a little more dripping, then turn the oven up to brown the potatoes, or finish under the grill for 5-8 mins until brown.", "equipment_tags": ["Grill"], "portions": 6, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 802, "protein_g": 48.5, "carbs_g": 37.1, "fat_g": 50.7, "total_kcal": 4809, "total_protein_g": 291.0, "total_carbs_g": 222.5, "total_fat_g": 303.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the meat", "instruction": "Heat the oven to 160°C/fan 140°C/gas 3. Heat dripping or butter in a large casserole and brown the lamb in batches, then the kidneys, transferring each to a plate.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Cook the vegetables and build the sauce", "instruction": "Fry the onions and carrots until golden. Sprinkle over the flour, cook briefly, add the Worcestershire sauce and stock, and bring to the boil.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Assemble and braise", "instruction": "Stir in the meat and bay leaves, arrange the sliced potatoes on top, drizzle with dripping, cover and bake in the oven until the potatoes are cooked.", "timer_seconds": 5400, "background": true}, {"step": 4, "label": "Brown the top", "instruction": "Remove the lid, brush the potatoes with more dripping, and increase the oven temperature or finish under the grill until brown.", "timer_seconds": 420, "background": false}], "video": "https://www.youtube.com/watch?v=w6TS5J8YRA4"}, {"id": "52886", "name": "Spotted Dick", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xqvyqr1511638875.jpg", "local_image": "52886.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Suet", "measure": "125g"}, {"ingredient": "Currants", "measure": "175g"}, {"ingredient": "Caster Sugar", "measure": "80g"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Milk", "measure": "150ml"}, {"ingredient": "Custard", "measure": "to serve"}], "instructions": "Put the flour and salt in a bowl. Add the suet, currants, sugar, lemon and orange zest.\r\nPour in 150ml milk and mix to a firm but moist dough, adding the extra milk if necessary.\r\nShape into a fat roll about 20cm long. Place on a large rectangle of baking parchment. Wrap loosely to allow for the pudding to rise and tie the ends with string like a Christmas cracker.\r\nPlace a steamer over a large pan of boiling water, add the pudding to the steamer, cover and steam for 1 1/2 hours. Top up the pan with water from time to time.\r\nRemove from the steamer and allow to cool slightly before unwrapping. Serve sliced with custard.", "equipment_tags": [], "portions": 6, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 474, "protein_g": 6.5, "carbs_g": 70.3, "fat_g": 21.1, "total_kcal": 2845, "total_protein_g": 38.7, "total_carbs_g": 422.1, "total_fat_g": 126.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Put the flour and salt in a bowl, add the suet, currants, sugar, lemon and orange zest, then pour in the milk and mix to a firm but moist dough.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Shape and wrap", "instruction": "Shape into a fat roll and wrap loosely in baking parchment, tying the ends like a Christmas cracker.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Steam", "instruction": "Place in a steamer over boiling water, cover and steam, topping up the pan with water as needed.", "timer_seconds": 5400, "background": true}, {"step": 4, "label": "Serve", "instruction": "Remove and cool slightly before unwrapping, then serve sliced with custard.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=fu15XOF-ros"}, {"id": "52887", "name": "Kedgeree", "category": "Seafood", "area": "British", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/utxqpt1511639216.jpg", "local_image": "52887.jpg", "ingredients": [{"ingredient": "Smoked Haddock", "measure": "300g"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Milk", "measure": "300ml"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Coriander", "measure": "1 tsp"}, {"ingredient": "Curry Powder", "measure": "2 tsp"}, {"ingredient": "Rice", "measure": "300g"}], "instructions": "For the rice, heat the oil in a large, lidded pan, add the onion, then gently fry for 5 mins until softened but not coloured. Add the spices, season with salt, then continue to fry until the mix start to go brown and fragrant; about 3 mins.\r\nAdd the rice and stir in well. Add 600ml water, stir, then bring to the boil. Reduce to a simmer, then cover for 10 mins. Take off the heat and leave to stand, covered, for 10-15 mins more. The rice will be perfectly cooked if you do not lift the lid before the end of the cooking.\r\nMeanwhile, put the haddock and bay leaves in a frying pan, cover with the milk, then poach for 10 mins until the flesh flakes. Remove from the milk, peel away the skin, then flake the flesh into thumbsize pieces. Place the eggs in a pan, cover with water, bring to the boil, then reduce to a simmer. Leave for 4½-5 mins, plunge into cold water, then peel and cut the eggs into quarters. Gently mix the fish, eggs, parsley, coriander and rice together in the pan. Serve hot, sprinkled with a few extra herbs.", "equipment_tags": [], "portions": 3, "prep_minutes": 48, "prep_minutes_source": "explicit", "kcal": 717, "protein_g": 38.4, "carbs_g": 92.0, "fat_g": 21.2, "total_kcal": 2151, "total_protein_g": 115.2, "total_carbs_g": 276.0, "total_fat_g": 63.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the onion and spices for the rice", "instruction": "Heat the oil in a large lidded pan, fry the onion until softened, then add the spices and fry until fragrant.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Cook the rice", "instruction": "Add the rice, stir in, add water, bring to the boil, then reduce to a simmer, cover, and cook without lifting the lid, then leave to stand covered.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Poach the haddock", "instruction": "Meanwhile, put the haddock and bay leaves in a frying pan, cover with milk, and poach until the flesh flakes, then remove, skin and flake into pieces.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Boil the eggs", "instruction": "Place the eggs in a pan, cover with water, bring to the boil, then reduce to a simmer, cook, plunge into cold water, peel and quarter.", "timer_seconds": 290, "background": false}, {"step": 5, "label": "Combine and serve", "instruction": "Gently mix the fish, eggs, parsley, coriander and rice together in the pan. Serve hot, sprinkled with extra herbs.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_Pw1I1-SItE"}, {"id": "52888", "name": "Eccles Cakes", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wtqrqw1511639627.jpg", "local_image": "52888.jpg", "ingredients": [{"ingredient": "Butter", "measure": "250g"}, {"ingredient": "Plain Flour", "measure": "350g"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Currants", "measure": "200g"}, {"ingredient": "Mixed Peel", "measure": "50g"}, {"ingredient": "Muscovado Sugar", "measure": "100g"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Eggs", "measure": "1 beaten"}, {"ingredient": "Sugar", "measure": "spinkling"}], "instructions": "To make the pastry, dice the butter and put it in the freezer to go really hard. Tip flour into the bowl of a food processor with half the butter and pulse to the texture of breadcrumbs. Pour in the lemon juice and 100ml iced water, and pulse to a dough. Tip in the rest of the butter and pulse a few times until the dough is heavily flecked with butter. It is important that you don’t overdo this as the flecks of butter are what makes the pastry flaky.\r\nOn a floured surface roll the pastry out to a neat rectangle about 20 x 30cm. Fold the two ends of the pastry into the middle (See picture 1), then fold in half (pic 2). Roll the pastry out again and refold the same way 3 more times resting the pastry for at least 15 mins each time between roll and fold, then leave to rest in the fridge for at least 30 mins before using.\r\nTo make the filling, melt the butter in a large saucepan. Take it off the heat and stir in all the other ingredients until completely mixed, then set aside.\r\nTo make the cakes, roll the pastry out until it’s just a little thicker than a £1 coin and cut out 8 rounds about 12cm across. Re-roll the trimming if needed. Place a good heaped tablespoon of mixture in the middle of each round, brush the edges of the rounds with water, then gather the pastry around the filling and squeeze it together (pic 3). Flip them over so the smooth top is upwards and pat them into a smooth round. Flatten each round with a rolling pin to an oval until the fruit just starts to poke through, then place on a baking tray. Cut 2 little slits in each Eccles cakes, brush generously with egg white and sprinkle with the sugar (pic 4).\r\nHeat the oven to 220C/200C fan/gas 8. Bake the Eccles cakes for 15-20 mins until just past golden brown and sticky. Leave to cool on a rack and enjoy while still warm or cold with a cup of tea. If you prefer, Eccles cakes also go really well served with a wedge of hard, tangy British cheese such as Lancashire or cheddar.", "equipment_tags": ["FoodProcessor"], "portions": 8, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 569, "protein_g": 6.6, "carbs_g": 73.5, "fat_g": 29.1, "total_kcal": 4551, "total_protein_g": 52.9, "total_carbs_g": 588.0, "total_fat_g": 232.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the rough puff pastry", "instruction": "Dice the butter and freeze until hard. Pulse the flour with half the butter to breadcrumbs, add lemon juice and iced water and pulse to a dough, then pulse in the rest of the butter until flecked.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Laminate the pastry", "instruction": "Roll into a rectangle, fold the ends into the middle then fold in half, and repeat the roll-and-fold 3 more times, resting between each, then chill.", "timer_seconds": 2700, "background": true}, {"step": 3, "label": "Make the filling", "instruction": "Melt the butter, take off the heat, and stir in the remaining filling ingredients until combined; set aside.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fill and shape the cakes", "instruction": "Roll the pastry out and cut 8 rounds. Place filling in the centre of each, gather the pastry around it and squeeze together, flip and flatten into an oval until fruit starts to show.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Glaze and bake", "instruction": "Cut slits in each cake, brush with egg white, sprinkle with sugar, and bake until just past golden brown and sticky.", "timer_seconds": 1050, "background": true}, {"step": 6, "label": "Serve", "instruction": "Cool on a rack and enjoy warm or cold, with a wedge of hard cheese if you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=xV0QCJ0GD5w"}, {"id": "52889", "name": "Summer Pudding", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rsqwus1511640214.jpg", "local_image": "52889.jpg", "ingredients": [{"ingredient": "Strawberries", "measure": "300g"}, {"ingredient": "Blackberries", "measure": "250g"}, {"ingredient": "Redcurrants", "measure": "100g"}, {"ingredient": "Raspberries", "measure": "500g"}, {"ingredient": "Caster Sugar", "measure": "175g"}, {"ingredient": "Bread", "measure": "7 Slices"}], "instructions": "Bring out the juices: Wash fruit and gently dry on kitchen paper – keep strawberries separate. Put sugar and 3 tbsp water into a large pan. Gently heat until sugar dissolves – stir a few times. Bring to a boil for 1 min, then tip in the fruit (not strawberries). Cook for 3 mins over a low heat, stirring 2-3 times. The fruit will be softened, mostly intact and surrounded by dark red juice. Put a sieve over a bowl and tip in the fruit and juice.\r\nLine the bowl with cling film and prepare the bread: Line the 1.25-litre basin with cling film as this will help you to turn out the pudding. Overlap two pieces of cling film in the middle of the bowl as it’s easier than trying to get one sheet to stick to all of the curves. Let the edges overhang by about 15cm. Cut the crusts off the bread. Cut 4 pieces of bread in half, a little on an angle, to give 2 lopsided rectangles per piece. Cut 2 slices into 4 triangles each and leave the final piece whole.\r\nBuild the pud: Dip the whole piece of bread into the juice for a few secs just to coat. Push this into the bottom of the basin. Now dip the wonky rectangular pieces one at a time and press around the basin’s sides so that they fit together neatly, alternately placing wide and narrow ends up. If you can’t quite fit the last piece of bread in it doesn’t matter, just trim into a triangle, dip in juice and slot in. Now spoon in the softened fruit, adding the strawberries here and there as you go.\r\nLet flavours mingle then serve: Dip the bread triangles in juice and place on top – trim off overhang with scissors. Keep leftover juice for later. Bring cling film up and loosely seal. Put a side plate on top and weight down with cans. Chill for 6 hrs or overnight. To serve, open out cling film then put a serving plate upside-down on top and flip over. serve with leftover juice, any extra berries and cream.", "equipment_tags": [], "portions": 10, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 166, "protein_g": 2.9, "carbs_g": 38.2, "fat_g": 1.1, "total_kcal": 1660, "total_protein_g": 28.8, "total_carbs_g": 381.6, "total_fat_g": 11.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the fruit", "instruction": "Wash and dry the fruit, keeping strawberries separate. Dissolve the sugar in water in a large pan, bring to a boil, then add the fruit (not strawberries) and cook gently, stirring, until softened.", "timer_seconds": 240, "background": false}, {"step": 2, "label": "Strain the juice", "instruction": "Tip the fruit and juice into a sieve set over a bowl to separate.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Prep the bread and bowl", "instruction": "Line a basin with cling film. Cut the crusts off the bread and cut pieces into rectangles and triangles to fit the basin.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Build the pudding", "instruction": "Dip the bread pieces in the juice and line the basin, placing the fruit inside as you go, adding strawberries throughout.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Top and chill", "instruction": "Dip the remaining bread triangles in juice, place on top, trim overhang, seal with cling film, weigh down with a plate and cans, and chill.", "timer_seconds": 21600, "background": true}, {"step": 6, "label": "Turn out and serve", "instruction": "Unwrap, invert onto a serving plate, and serve with the reserved juice, extra berries and cream.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=akJIO6UhXtA"}, {"id": "52890", "name": "Jam Roly-Poly", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ysqupp1511640538.jpg", "local_image": "52890.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Vanilla", "measure": "1 small"}, {"ingredient": "Suet", "measure": "50g"}, {"ingredient": "Milk", "measure": "150ml"}, {"ingredient": "Raspberry Jam", "measure": "100g"}, {"ingredient": "Custard", "measure": "to serve"}], "instructions": "Put a deep roasting tin onto the bottom shelf of the oven, and make sure that there’s another shelf directly above it. Pull the roasting tin out on its shelf, fill two-thirds with boiling water from the kettle, then carefully slide it back in. Heat oven to 180C/160C fan/gas 4. Tear off a large sheet of foil and greaseproof paper (about 30 x 40cm). Sit the greaseproof on top of the foil and butter it.\r\nTip butter, flour and vanilla seeds into a food processor; pulse until the butter has disappeared. Tip into a mixing bowl. Stir through the suet, pour in the milk and work together with a cutlery knife until you get a sticky dough. You may need a drop more milk, depending on your flour.\r\nTip the dough out onto a floured surface, quickly pat together to smooth, then roll out to a square roughly 25 x 25cm. Spread the jam all over, leaving a gap along one edge, then roll up from the opposite edge. Pinch the jam-free edge into the dough where it meets, and pinch the ends roughly, too. Carefully lift onto the greased paper, join-side down (you might find a flat baking sheet helpful for this), loosely bring up the paper and foil around it, then scrunch together along the edges and ends to seal. The roly-poly will puff quite a bit during cooking so don’t wrap it tightly. Lift the parcel directly onto the rack above the tin and cook for 1 hr.\r\nLet the pudding sit for 5 mins before unwrapping, then carefully open the foil and paper, and thickly slice to serve.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 180, "protein_g": 2.6, "carbs_g": 23.4, "fat_g": 8.0, "total_kcal": 2157, "total_protein_g": 31.4, "total_carbs_g": 280.8, "total_fat_g": 96.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Put a roasting tin with boiling water on the bottom oven shelf. Heat the oven to 180°C/160°C fan/gas 4. Prepare foil and buttered greaseproof paper.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the dough", "instruction": "Pulse the butter, flour and vanilla seeds in a food processor until the butter disappears, tip into a bowl, stir through the suet, then add the milk and work into a sticky dough.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Roll and fill", "instruction": "Roll the dough into a square, spread with jam leaving a gap at one edge, then roll up from the opposite edge and pinch to seal.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Wrap and bake", "instruction": "Lift onto the greased paper, wrap loosely in the paper and foil, and cook on the rack above the water-filled tin.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Rest and serve", "instruction": "Let sit before unwrapping, then thickly slice and serve.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=5ZYWVQ8imVA"}, {"id": "52891", "name": "Blackberry Fool", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg", "local_image": "52891.jpg", "ingredients": [{"ingredient": "Hazlenuts", "measure": "50g"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Caster Sugar", "measure": "150g"}, {"ingredient": "Lemon", "measure": "Grated"}, {"ingredient": "Plain Flour", "measure": "150g"}, {"ingredient": "Baking Powder", "measure": "½ tsp"}, {"ingredient": "Blackberries", "measure": "600g"}, {"ingredient": "Sugar", "measure": "75g"}, {"ingredient": "Caster Sugar", "measure": "2 tbs"}, {"ingredient": "Lemon Juice", "measure": "1 tbs"}, {"ingredient": "Double Cream", "measure": "300ml"}, {"ingredient": "Yogurt", "measure": "100ml"}, {"ingredient": "Mint", "measure": "Garnish with"}], "instructions": "For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment. Scatter the nuts over a baking tray and roast in the oven for 6-8 minutes, or until golden-brown. Watch them carefully so that they don’t have a chance to burn. Remove from the oven, tip onto a board and leave to cool.\r\nPut the butter and sugar in a large bowl and beat with a wooden spoon until light and creamy. Roughly chop the cooled nuts and add to the creamed butter and sugar, along with the lemon zest, flour and baking powder. Stir well until the mixture comes together and forms a ball – you may need to use your hands.\r\nDivide the biscuit dough into 24 even pieces and roll into small balls. Place the balls the prepared baking trays, spaced well apart to allow for spreading.\r\nPress the biscuits to flatten to around 1cm/½in thick. Bake the biscuits, one tray at a time, for 12 minutes or until very pale golden-brown. Leave to cool on the trays. They will be very soft when you take them out of the oven, but will crisp as they cool.\r\nStore in an airtight tin and eat within five days.\r\nFor the fool, rinse the blackberries in a colander to wash away any dust or dirt. Put the blackberries in a non-stick saucepan and sprinkle over the caster sugar.\r\nStir in the lemon juice and heat gently for two minutes, or until the blackberries begin to soften and release their juices. Remove and reserve 12 blackberries for decoration and continue cooking the rest.\r\nSimmer the blackberries very gently for 15 minutes, stirring regularly until very soft and squidgy. Remove from the heat and press the berries and juice through a sieve over a bowl, using the bottom of a ladle to help you extract as much of the purée as possible. Leave the purée to cool and discard the seeds. You should end up with around 325ml/11fl oz of purée.\r\nPut the cream and yoghurt in a large bowl and whip with an electric whisk until soft peaks form when the whisk is removed from the bowl – the acidity of the fruit will thicken the cream further, so don’t take it too far.\r\nWhen the purée is completely cold, adjust the sweetness to taste by adding more sugar if needed. Pour it into the bowl with the whipped cream and yoghurt and stir just once or twice until very lightly combined.\r\nSpoon the blackberry fool into individual wide, glass dishes – or one large, single bowl. It should look quite marbled, so don’t over-stir it. Scatter a few tiny mint leaves on top and decorate with the reserved blackberries. Sprinkle with a little sugar if you like and serve with the hazelnut biscuits.", "equipment_tags": [], "portions": 11, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 402, "protein_g": 4.1, "carbs_g": 41.0, "fat_g": 25.8, "total_kcal": 4418, "total_protein_g": 45.5, "total_carbs_g": 450.6, "total_fat_g": 283.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the nuts", "instruction": "Preheat the oven to 200°C/180°C fan/gas 6 and line two trays. Roast the nuts until golden-brown, watching closely, then cool.", "timer_seconds": 420, "background": true}, {"step": 2, "label": "Make the biscuit dough", "instruction": "Beat the butter and sugar until light and creamy, chop the cooled nuts and add with lemon zest, flour and baking powder, and stir into a dough.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Shape and bake the biscuits", "instruction": "Divide into 24 balls, place on the trays, flatten slightly, and bake one tray at a time until pale golden-brown, then cool.", "timer_seconds": 720, "background": true}, {"step": 4, "label": "Cook the blackberries", "instruction": "Rinse the blackberries, put in a saucepan with the sugar and lemon juice, and heat gently until softening. Reserve 12 for decoration and continue simmering the rest until very soft.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Purée and cool", "instruction": "Press the berries and juice through a sieve to extract the purée, discard the seeds, and leave to cool.", "timer_seconds": null, "background": true}, {"step": 6, "label": "Whip the cream", "instruction": "Whip the cream and yoghurt together until soft peaks form.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Combine and serve", "instruction": "Adjust the sweetness of the cooled purée, fold lightly into the whipped cream, and spoon into glasses. Decorate with the reserved blackberries and mint, and serve with the biscuits.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=kniRGjDLFrQ"}, {"id": "52892", "name": "Treacle Tart", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wprvrw1511641295.jpg", "local_image": "52892.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "250g"}, {"ingredient": "Butter", "measure": "135g"}, {"ingredient": "Golden Syrup", "measure": "400g"}, {"ingredient": "Breadcrumbs", "measure": "150g"}, {"ingredient": "Lemons", "measure": "Zest of 2"}, {"ingredient": "Eggs", "measure": "1 beaten"}], "instructions": "First make the short crust pastry: measure the flour into a large bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs (alternatively, this can be done in a food processor). Add about three tablespoons of cold water and mix to a firm dough, wrap in cling film and chill in the fridge for about 20 minutes.\r\nPreheat the oven to 200C/400F/Gas 6 and put a heavy baking tray in the oven to heat up. Grease a deep 18cm/7in loose-bottomed fluted flan tin with butter.\r\nRemove about 150g/5½oz of pastry from the main ball and set aside for the lattice top.\r\nRoll the rest of the pastry out thinly on a lightly floured work surface and line the prepared flan tin with the pastry.\r\nPrick the base with a fork, to stop the base rising up during baking.\r\nPlace the reserved pastry for the lattice top on cling film and roll out thinly. Egg wash the pastry and set aside to chill in the fridge (the cling film makes it easier to move about). Do not cut into strips at this stage. Do not egg wash the strips once they are on the tart as it will drip into the treacle mixture.\r\nTo make the filling, heat the syrup gently in a large pan but do not boil.\r\nOnce melted, add the breadcrumbs, lemon juice and zest to the syrup. (You can add less lemon if you would prefer less citrus taste.) If the mixture looks runny, add a few more breadcrumbs.\r\nPour the syrup mixture into the lined tin and level the surface.\r\nRemove the reserved pastry from the fridge and cut into long strips, 1cm/½in wide. Make sure they are all longer than the edges of the tart tin.\r\nEgg wash the edge of the pastry in the tin, and start to make the woven laying lattice pattern over the mixture, leave the strips hanging over the edge of the tin.\r\nOnce the lattice is in place, use the tin edge to cut off the strips by pressing down with your hands, creating a neat finish.\r\nBake on the pre-heated baking tray in the hot oven for about 10 minutes until the pastry has started to colour, and then reduce the oven temperature to 180C/350F/Gas 4. If at this stage the lattice seems to be getting too dark brown, cover the tart with tin foil.\r\nBake for a further 25-30 minutes until the pastry is golden-brown and the filling set.\r\nRemove the tart from the oven and leave to firm up in the tin. Serve warm or cold.", "equipment_tags": ["FoodProcessor"], "portions": 7, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 550, "protein_g": 7.5, "carbs_g": 88.2, "fat_g": 17.9, "total_kcal": 3851, "total_protein_g": 52.5, "total_carbs_g": 617.5, "total_fat_g": 125.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and chill the pastry", "instruction": "Rub the butter into the flour until it resembles breadcrumbs, add cold water to form a dough, wrap and chill.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Line the tin", "instruction": "Preheat the oven to 200°C/400°F/gas 6 with a baking tray inside. Grease a flan tin. Set aside pastry for the lattice, roll out the rest, and line the tin, pricking the base.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Prep the lattice", "instruction": "Roll out the reserved pastry on cling film, egg wash it, and chill.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Make the filling", "instruction": "Heat the syrup gently without boiling, then stir in the breadcrumbs, lemon juice and zest.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fill and lattice", "instruction": "Pour the syrup mixture into the lined tin, cut the chilled lattice pastry into strips, egg wash the tart edge, weave the lattice over the filling, and trim.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake", "instruction": "Bake on the preheated tray, then reduce the oven temperature and continue baking until golden-brown and set, covering with foil if browning too fast.", "timer_seconds": 2100, "background": true}, {"step": 7, "label": "Cool and serve", "instruction": "Leave to firm up in the tin, then serve warm or cold.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=YMmgKCNcqwI"}, {"id": "52893", "name": "Apple & Blackberry Crumble", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xvsurr1511719182.jpg", "local_image": "52893.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "120g"}, {"ingredient": "Caster Sugar", "measure": "60g"}, {"ingredient": "Butter", "measure": "60g"}, {"ingredient": "Braeburn Apples", "measure": "300g"}, {"ingredient": "Butter", "measure": "30g"}, {"ingredient": "Demerara Sugar", "measure": "30g"}, {"ingredient": "Blackberries", "measure": "120g"}, {"ingredient": "Cinnamon", "measure": "¼ teaspoon"}, {"ingredient": "Ice Cream", "measure": "to serve"}], "instructions": "Heat oven to 190C/170C fan/gas 5. Tip the flour and sugar into a large bowl. Add the butter, then rub into the flour using your fingertips to make a light breadcrumb texture. Do not overwork it or the crumble will become heavy. Sprinkle the mixture evenly over a baking sheet and bake for 15 mins or until lightly coloured.\r\nMeanwhile, for the compote, peel, core and cut the apples into 2cm dice. Put the butter and sugar in a medium saucepan and melt together over a medium heat. Cook for 3 mins until the mixture turns to a light caramel. Stir in the apples and cook for 3 mins. Add the blackberries and cinnamon, and cook for 3 mins more. Cover, remove from the heat, then leave for 2-3 mins to continue cooking in the warmth of the pan.\r\nTo serve, spoon the warm fruit into an ovenproof gratin dish, top with the crumble mix, then reheat in the oven for 5-10 mins. Serve with vanilla ice cream.", "equipment_tags": [], "portions": 5, "prep_minutes": 37, "prep_minutes_source": "explicit", "kcal": 341, "protein_g": 3.3, "carbs_g": 48.6, "fat_g": 15.7, "total_kcal": 1703, "total_protein_g": 16.5, "total_carbs_g": 243.0, "total_fat_g": 78.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the crumble", "instruction": "Heat the oven to 190°C/170°C fan/gas 5. Rub the butter into the flour and sugar to a light breadcrumb texture, spread on a baking sheet, and bake until lightly coloured.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Make the compote", "instruction": "Peel and dice the apples. Melt the butter and sugar in a pan until light caramel, then cook in the apples, followed by the blackberries and cinnamon.", "timer_seconds": 540, "background": false}, {"step": 3, "label": "Rest the compote", "instruction": "Cover, remove from the heat, and leave to continue cooking in the pan's warmth.", "timer_seconds": 180, "background": true}, {"step": 4, "label": "Assemble and reheat", "instruction": "Spoon the warm fruit into a gratin dish, top with the crumble, and reheat in the oven.", "timer_seconds": 480, "background": true}, {"step": 5, "label": "Serve", "instruction": "Serve with vanilla ice cream.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=4vhcOwVBDO4"}, {"id": "52894", "name": "Battenberg Cake", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg", "local_image": "52894.jpg", "ingredients": [{"ingredient": "Butter", "measure": "175g"}, {"ingredient": "Caster Sugar", "measure": "175g"}, {"ingredient": "Self-raising Flour", "measure": "140g"}, {"ingredient": "Almonds", "measure": "50g"}, {"ingredient": "Baking Powder", "measure": "½ tsp"}, {"ingredient": "Eggs", "measure": "3 Medium"}, {"ingredient": "Vanilla Extract", "measure": "½ tsp"}, {"ingredient": "Almond Extract", "measure": "¼ teaspoon"}, {"ingredient": "Butter", "measure": "175g"}, {"ingredient": "Caster Sugar", "measure": "175g"}, {"ingredient": "Self-raising Flour", "measure": "140g"}, {"ingredient": "Almonds", "measure": "50g"}, {"ingredient": "Baking Powder", "measure": "½ tsp"}, {"ingredient": "Eggs", "measure": "3 Medium"}, {"ingredient": "Vanilla Extract", "measure": "½ tsp"}, {"ingredient": "Almond Extract", "measure": "¼ teaspoon"}, {"ingredient": "Pink Food Colouring", "measure": "½ tsp"}, {"ingredient": "Apricot", "measure": "200g"}, {"ingredient": "Marzipan", "measure": "1kg"}, {"ingredient": "Icing Sugar", "measure": "Dusting"}], "instructions": "Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over the base). To make the almond sponge, put the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract in a large bowl. Beat with an electric whisk until the mix comes together smoothly. Scrape into the tin, spreading to the corners, and bake for 25-30 mins – when you poke in a skewer, it should come out clean. Cool in the tin for 10 mins, then transfer to a wire rack to finish cooling while you make the second sponge.\r\nFor the pink sponge, line the tin as above. Mix all the ingredients together as above, but don’t add the almond extract. Fold in some pink food colouring. Then scrape it all into the tin and bake as before. Cool.\r\nTo assemble, heat the jam in a small pan until runny, then sieve. Barely trim two opposite edges from the almond sponge, then well trim a third edge. Roughly measure the height of the sponge, then cutting from the well-trimmed edge, use a ruler to help you cut 4 slices each the same width as the sponge height. Discard or nibble leftover sponge. Repeat with pink cake.\r\nTake 2 x almond slices and 2 x pink slices and trim so they are all the same length. Roll out one marzipan block on a surface lightly dusted with icing sugar to just over 20cm wide, then keep rolling lengthways until the marzipan is roughly 0.5cm thick. Brush with apricot jam, then lay a pink and an almond slice side by side at one end of the marzipan, brushing jam in between to stick sponges, and leaving 4cm clear marzipan at the end. Brush more jam on top of the sponges, then sandwich remaining 2 slices on top, alternating colours to give a checkerboard effect. Trim the marzipan to the length of the cakes.\r\nCarefully lift up the marzipan and smooth over the cake with your hands, but leave a small marzipan fold along the bottom edge before you stick it to the first side. Trim opposite side to match size of fold, then crimp edges using fingers and thumb (or, more simply, press with prongs of fork). If you like, mark the 10 slices using the prongs of a fork.\r\nAssemble second Battenberg and keep in an airtight box or well wrapped in cling film for up to 3 days. Can be frozen for up to a month.", "equipment_tags": [], "portions": 12, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 1022, "protein_g": 14.4, "carbs_g": 127.1, "fat_g": 52.3, "total_kcal": 12262, "total_protein_g": 172.6, "total_carbs_g": 1525.7, "total_fat_g": 627.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Bake the almond sponge", "instruction": "Heat the oven to 180°C/160°C fan/gas 4 and line a square tin. Beat the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract together until smooth. Spread in the tin and bake, then cool.", "timer_seconds": 1650, "background": true}, {"step": 2, "label": "Bake the pink sponge", "instruction": "Line the tin again, mix the second batch of ingredients without almond extract, fold in pink food colouring, and bake as before, then cool.", "timer_seconds": 1650, "background": true}, {"step": 3, "label": "Cut the sponges", "instruction": "Heat and sieve the jam. Trim the edges of the almond sponge and cut into 4 equal-width slices; repeat with the pink sponge.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Assemble the checkerboard", "instruction": "Roll out a marzipan block, brush with jam, lay a pink and almond slice side by side, brushing jam between and on top, then stack two more slices in alternating colours.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Wrap and shape", "instruction": "Wrap the marzipan around the cake, trim the seams, and crimp the edges.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Store", "instruction": "Keep in an airtight box or wrapped in cling film for up to 3 days, or freeze for up to a month.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=aB41Q7kDZQ0"}, {"id": "52895", "name": "English Breakfast", "category": "Breakfast", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/utxryw1511721587.jpg", "local_image": "52895.jpg", "ingredients": [{"ingredient": "Sausages", "measure": "2"}, {"ingredient": "Bacon", "measure": "3"}, {"ingredient": "Mushrooms", "measure": "2"}, {"ingredient": "Tomatoes", "measure": "2"}, {"ingredient": "Black Pudding", "measure": "1 Slice"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Bread", "measure": "1 Slice"}], "instructions": "Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\r\nCook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.\r\nSnip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.\r\nFor the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.\r\nFor the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green 'eye'. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.\r\nFor the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.\r\nFor 'proper' fried bread it's best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.\r\nFor the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.\r\nOnce all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 485, "protein_g": 30.8, "carbs_g": 11.1, "fat_g": 35.3, "total_kcal": 1455, "total_protein_g": 92.4, "total_carbs_g": 33.3, "total_fat_g": 106.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the sausages", "instruction": "Heat a grill plate over low heat with a little oil. Add the sausages and cook slowly, turning occasionally, until golden, increasing the heat to medium after the first 10 minutes.", "timer_seconds": 1200, "background": false}, {"step": 2, "label": "Cook the bacon", "instruction": "Snip cuts into the bacon fat and fry on the grill plate on each side until crisp to your liking.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Cook the mushrooms", "instruction": "Trim and season the mushrooms, drizzle with oil, and cook stalk-side up, then turn and cook further.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Cook the tomatoes", "instruction": "Halve the tomatoes, remove the eye, season and oil, then cook cut-side down without moving, turn, and cook further until tender but holding shape.", "timer_seconds": 240, "background": false}, {"step": 5, "label": "Cook the black pudding", "instruction": "Slice the black pudding, remove the skin, and cook on the grill until slightly crispy on each side.", "timer_seconds": 210, "background": false}, {"step": 6, "label": "Fry the bread and eggs", "instruction": "Fry the bread in a separate pan with oil until crispy and golden on each side. Crack the egg into the same pan, baste with butter, and cook to your preferred stage.", "timer_seconds": 240, "background": false}, {"step": 7, "label": "Serve", "instruction": "Serve everything on warm plates with ketchup or brown sauce.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FXjYU2Ensck"}, {"id": "52896", "name": "Full English Breakfast", "category": "Breakfast", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sqrtwu1511721265.jpg", "local_image": "52896.jpg", "ingredients": [{"ingredient": "Sausages", "measure": "4"}, {"ingredient": "Bacon", "measure": "4"}, {"ingredient": "Mushrooms", "measure": "4"}, {"ingredient": "Tomatoes", "measure": "3"}, {"ingredient": "Black Pudding", "measure": "2 sliced"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Bread", "measure": "1 Slice"}, {"ingredient": "Baked Beans", "measure": "100g"}], "instructions": "Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\r\nCook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.\r\nSnip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.\r\nFor the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.\r\nFor the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green 'eye'. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.\r\nFor the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.\r\nFor 'proper' fried bread it's best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.\r\nFor the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.\r\nOnce all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 478, "protein_g": 28.9, "carbs_g": 14.1, "fat_g": 34.1, "total_kcal": 2388, "total_protein_g": 144.3, "total_carbs_g": 70.5, "total_fat_g": 170.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the sausages", "instruction": "Heat a grill plate over low heat with a little oil. Add the sausages and cook slowly, turning occasionally, until golden, increasing the heat to medium after the first 10 minutes.", "timer_seconds": 1200, "background": false}, {"step": 2, "label": "Cook the bacon", "instruction": "Snip cuts into the bacon fat and fry on the grill plate on each side until crisp to your liking.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Cook the mushrooms", "instruction": "Trim and season the mushrooms, drizzle with oil, and cook stalk-side up, then turn and cook further.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Cook the tomatoes and black pudding", "instruction": "Halve and season the tomatoes and cook cut-side down, then turn. Slice the black pudding and cook on the grill until slightly crispy.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Fry the bread and eggs", "instruction": "Fry the bread in a separate pan with oil until crispy and golden, then crack in the egg and cook to your preferred stage.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Heat the beans and serve", "instruction": "Warm the baked beans and serve everything together on warm plates.", "timer_seconds": 180, "background": false}], "video": "https://www.youtube.com/watch?v=FXjYU2Ensck"}, {"id": "52897", "name": "Carrot Cake", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vrspxv1511722107.jpg", "local_image": "52897.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "450ml"}, {"ingredient": "Plain Flour", "measure": "400g"}, {"ingredient": "Bicarbonate Of Soda", "measure": "2 tsp"}, {"ingredient": "Sugar", "measure": "550ml"}, {"ingredient": "Eggs", "measure": "5"}, {"ingredient": "Salt", "measure": "½ tsp"}, {"ingredient": "Cinnamon", "measure": "2 tsp"}, {"ingredient": "Carrots", "measure": "500g grated"}, {"ingredient": "Walnuts", "measure": "150g"}, {"ingredient": "Cream Cheese", "measure": "200g"}, {"ingredient": "Caster Sugar", "measure": "150g"}, {"ingredient": "Butter", "measure": "100g"}], "instructions": "For the carrot cake, preheat the oven to 160C/325F/Gas 3. Grease and line a 26cm/10in springform cake tin.\r\nMix all of the ingredients for the carrot cake, except the carrots and walnuts, together in a bowl until well combined. Stir in the carrots and walnuts.\r\nSpoon the mixture into the cake tin and bake for 1 hour 15 minutes, or until a skewer inserted into the middle comes out clean. Remove the cake from the oven and set aside to cool for 10 minutes, then carefully remove the cake from the tin and set aside to cool completely on a cooling rack.\r\nMeanwhile, for the icing, beat the cream cheese, caster sugar and butter together in a bowl until fluffy. Spread the icing over the top of the cake with a palette knife.", "equipment_tags": [], "portions": 12, "prep_minutes": 85, "prep_minutes_source": "explicit", "kcal": 592, "protein_g": 9.4, "carbs_g": 84.3, "fat_g": 25.8, "total_kcal": 7108, "total_protein_g": 112.8, "total_carbs_g": 1011.5, "total_fat_g": 309.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep the tin", "instruction": "Preheat the oven to 160°C/325°F/gas 3 and grease and line a springform tin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Mix the batter", "instruction": "Mix all the cake ingredients except the carrots and walnuts together until well combined, then stir in the carrots and walnuts.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Spoon into the tin and bake until a skewer comes out clean.", "timer_seconds": 4500, "background": true}, {"step": 4, "label": "Cool", "instruction": "Cool in the tin briefly, then remove and cool completely on a rack.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Ice and serve", "instruction": "Beat the cream cheese, sugar and butter together until fluffy, then spread over the top of the cooled cake.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=asjZ7iTrGKA"}, {"id": "52898", "name": "Chelsea Buns", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vqpwrv1511723001.jpg", "local_image": "52898.jpg", "ingredients": [{"ingredient": "White Flour", "measure": "500g"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Yeast", "measure": "7g"}, {"ingredient": "Milk", "measure": "300ml"}, {"ingredient": "Butter", "measure": "40g"}, {"ingredient": "Eggs", "measure": "1"}, {"ingredient": "Vegetable Oil", "measure": "Dash"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Brown Sugar", "measure": "75g"}, {"ingredient": "Cinnamon", "measure": "2 tsp"}, {"ingredient": "Dried Fruit", "measure": "150g"}, {"ingredient": "Milk", "measure": "2 tbs"}, {"ingredient": "Caster Sugar", "measure": "2 tbs"}], "instructions": "Sift the flour and salt into a large bowl. Make a well in the middle and add the yeast.\r\nMeanwhile, warm the milk and butter in a saucepan until the butter melts and the mixture is lukewarm.\r\nAdd the milk mixture and egg to the flour mixture and stir until the contents of the bowl come together as a soft dough. (You may need to add a little extra flour.)\r\nTip the dough onto a generously floured work surface. Knead for five minutes, adding more flour if necessary, until the dough is smooth and elastic and no longer feels sticky.\r\nLightly oil a bowl with a little of the vegetable oil. Place the dough into the bowl and turn until it is covered in the oil. Cover the bowl with cling film and set aside in a warm place for one hour, or until the dough has doubled in size.\r\nLightly grease a baking tray.\r\nFor the filling, knock the dough back to its original size and turn out onto a lightly floured work surface. Roll the dough out into a rectangle 0.5cm/¼in thick. Brush all over with the melted butter, then sprinkle over the brown sugar, cinnamon and dried fruit.\r\nRoll the dough up into a tight cylinder , cut ten 4cm/1½in slice and place them onto a lightly greased baking sheet, leaving a little space between each slice. Cover with a tea towel and set aside to rise for 30 minutes.\r\nPreheat oven to 190C/375F/Gas 5.\r\nBake the buns in the oven for 20-25 minutes, or until risen and golden-brown.\r\nMeanwhile, for the glaze, heat the milk and sugar in a saucepan until boiling. Reduce the heat and simmer for 2-3 minutes.\r\nRemove the buns from the oven and brush with the glaze, then set aside to cool on a wire rack.", "equipment_tags": [], "portions": 8, "prep_minutes": 58, "prep_minutes_source": "explicit", "kcal": 427, "protein_g": 9.3, "carbs_g": 76.1, "fat_g": 9.5, "total_kcal": 3419, "total_protein_g": 74.6, "total_carbs_g": 608.4, "total_fat_g": 75.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Sift the flour and salt into a bowl and add the yeast. Warm the milk and butter until lukewarm, then mix into the flour with the egg to form a soft dough.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Knead", "instruction": "Knead on a floured surface until smooth and elastic.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "First rise", "instruction": "Place in an oiled bowl, cover, and set aside in a warm place until doubled in size.", "timer_seconds": 3600, "background": true}, {"step": 4, "label": "Fill and roll", "instruction": "Knock back the dough, roll into a rectangle, brush with melted butter, and sprinkle with brown sugar, cinnamon and dried fruit.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Shape and second rise", "instruction": "Roll into a cylinder, cut into 10 slices, place on a greased tray with space between, cover, and leave to rise.", "timer_seconds": 1800, "background": true}, {"step": 6, "label": "Bake", "instruction": "Preheat the oven to 190°C/375°F/gas 5 and bake until risen and golden-brown.", "timer_seconds": 1350, "background": true}, {"step": 7, "label": "Glaze", "instruction": "Meanwhile heat the milk and sugar until boiling, then simmer to make the glaze. Brush over the warm buns and cool on a rack.", "timer_seconds": 150, "background": false}], "video": "https://www.youtube.com/watch?v=i_zemP3yBKw"}, {"id": "52899", "name": "Dundee cake", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wxyvqq1511723401.jpg", "local_image": "52899.jpg", "ingredients": [{"ingredient": "Almonds", "measure": "100g"}, {"ingredient": "Butter", "measure": "180g"}, {"ingredient": "Muscovado Sugar", "measure": "180g"}, {"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Apricot Jam", "measure": "3 tbs"}, {"ingredient": "Plain Flour", "measure": "225g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Eggs", "measure": "3 Large"}, {"ingredient": "Ground Almonds", "measure": "100g"}, {"ingredient": "Milk", "measure": "2 tbs"}, {"ingredient": "Dried Fruit", "measure": "500g"}, {"ingredient": "Glace Cherry", "measure": "100g"}, {"ingredient": "Milk", "measure": "1 tbs"}, {"ingredient": "Caster Sugar", "measure": "2 tsp"}], "instructions": "Put the almonds into a small bowl and pour over boiling water to just cover. Leave for 5 mins then drain in a sieve and leave to dry.\r\nPreheat the oven to 180C/160 C fan/Gas Mark 4. Line a deep loose-based 20cm cake tin with baking parchment.\r\nPut the butter in a large bowl and beat well until soft. Add the sugar and beat until light and fluffy. Stir in the orange zest and apricot jam.\r\nSieve together the flour and baking powder. Add the eggs to the creamed butter and sugar, a little at a time, beating well between each addition. If the mixture starts to curdle, stir in a little flour.\r\nAdd the remaining flour and ground almonds and mix well. Mix in the milk and then add the dried fruit and cherries and mix gently together.\r\nSpoon the mixture into the prepared tin and spread level using the back of a spoon. Arrange the whole almonds close together in neat circles on the top of the cake. Bake in the oven for 45 mins.\r\nLower the oven temperature to 160C/140 C fan/Gas Mark 3 and cook for a further 60–80 minutes. Check the cake after 50 minutes by inserting a wooden or metal skewer into the cake. When it’s done it should have just a few crumbs attached. Check every 10 minutes - it’s important not to overcook this cake so the centre will be a little soft.\r\nWhen cooked, remove the cake briefly from the oven, put the milk and sugar into a small pan and heat gently until the sugar has dissolved. Brush over the top of the cake and return the cake to the oven for 2-3 mins. Remove and allow the cake to cool in the tin. When quite cold remove from the tin and wrap in foil and keep for at least 2 days before cutting.", "equipment_tags": [], "portions": 11, "prep_minutes": 193, "prep_minutes_source": "explicit", "kcal": 542, "protein_g": 9.2, "carbs_g": 75.6, "fat_g": 24.3, "total_kcal": 5965, "total_protein_g": 100.8, "total_carbs_g": 831.9, "total_fat_g": 267.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the almonds", "instruction": "Soak the almonds in boiling water, then drain and dry.", "timer_seconds": 300, "background": true}, {"step": 2, "label": "Preheat and cream the butter", "instruction": "Preheat the oven to 180°C/160°C fan/gas 4 and line a cake tin. Beat the butter until soft, add the sugar and beat until light and fluffy, then stir in the orange zest and apricot jam.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Add the eggs and dry ingredients", "instruction": "Sieve the flour and baking powder. Beat the eggs into the creamed mixture a little at a time, then fold in the remaining flour and ground almonds, followed by the milk, dried fruit and cherries.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Top and bake", "instruction": "Spoon into the tin, level, and arrange the whole almonds on top in circles. Bake, then lower the oven temperature and continue baking until just a few crumbs cling to a skewer.", "timer_seconds": 6600, "background": true}, {"step": 5, "label": "Glaze and cool", "instruction": "Heat the milk and sugar until dissolved, brush over the cake, and return to the oven briefly, then cool in the tin.", "timer_seconds": 150, "background": false}, {"step": 6, "label": "Rest before serving", "instruction": "Once cold, wrap in foil and keep for at least 2 days before cutting.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=4hEXsfpeMQE"}, {"id": "52900", "name": "Madeira Cake", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/urtqut1511723591.jpg", "local_image": "52900.jpg", "ingredients": [{"ingredient": "Butter", "measure": "175g"}, {"ingredient": "Caster Sugar", "measure": "175g"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Milk", "measure": "3 tbs"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Mixed Peel", "measure": "To Glaze"}], "instructions": "Pre-heat the oven to 180C/350F/Gas 4. Grease an 18cm/7in round cake tin, line the base with greaseproof paper and grease the paper.\r\nCream the butter and sugar together in a bowl until pale and fluffy. Beat in the eggs, one at a time, beating the mixture well between each one and adding a tablespoon of the flour with the last egg to prevent the mixture curdling.\r\nSift the flour and gently fold in, with enough milk to give a mixture that falls slowly from the spoon. Fold in the lemon zest.\r\nSpoon the mixture into the prepared tin and lightly level the top. Bake on the middle shelf of the oven for 30-40 minutes, or until golden-brown on top and a skewer inserted into the centre comes out clean.\r\nRemove from the oven and set aside to cool in the tin for 10 minutes, then turn it out on to a wire rack and leave to cool completely.\r\nTo serve, decorate the cake with the candied peel.", "equipment_tags": [], "portions": 6, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 514, "protein_g": 7.8, "carbs_g": 65.5, "fat_g": 26.8, "total_kcal": 3083, "total_protein_g": 46.7, "total_carbs_g": 392.9, "total_fat_g": 160.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Preheat the oven to 180°C/350°F/gas 4 and grease and line a round cake tin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cream and add eggs", "instruction": "Cream the butter and sugar until pale and fluffy, then beat in the eggs one at a time, adding a spoonful of flour with the last egg.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fold in flour", "instruction": "Sift and gently fold in the flour with enough milk to give a slow-dropping consistency, then fold in the lemon zest.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Spoon into the tin, level the top, and bake until golden-brown and a skewer comes out clean.", "timer_seconds": 2100, "background": true}, {"step": 5, "label": "Cool and serve", "instruction": "Cool in the tin, then turn out onto a rack to cool completely. Decorate with candied peel to serve.", "timer_seconds": 600, "background": true}], "video": "https://www.youtube.com/watch?v=-YDh4WEmK_E"}, {"id": "52901", "name": "Rock Cakes", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tqrrsq1511723764.jpg", "local_image": "52901.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "225g"}, {"ingredient": "Caster Sugar", "measure": "75g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Dried Fruit", "measure": "150g"}, {"ingredient": "Eggs", "measure": "1"}, {"ingredient": "Milk", "measure": "1 tbs"}, {"ingredient": "Vanilla Extract", "measure": "2 tsp"}], "instructions": "Preheat oven to 180C/350F/Gas 4 and line a baking tray with baking parchment.\r\nMix the flour, sugar and baking powder in a bowl and rub in the cubed butter until the mixture looks like breadcrumbs, then mix in the dried fruit.\r\nIn a clean bowl, beat the egg and milk together with the vanilla extract.\r\nAdd the egg mixture to the dry ingredients and stir with a spoon until the mixture just comes together as a thick, lumpy dough. Add a teaspoon more milk if you really need it to make the mixture stick together.\r\nPlace golfball-sized spoons of the mixture onto the prepared baking tray. Leave space between them as they will flatten and spread out to double their size during baking.\r\nBake for 15-20 minutes, until golden-brown. Remove from the oven, allow to cool for a couple of minutes then turn them out onto a wire rack to cool.", "equipment_tags": [], "portions": 4, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 615, "protein_g": 8.3, "carbs_g": 88.6, "fat_g": 27.4, "total_kcal": 2461, "total_protein_g": 33.2, "total_carbs_g": 354.3, "total_fat_g": 109.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and mix dry ingredients", "instruction": "Preheat the oven to 180°C/350°F/gas 4 and line a tray. Mix the flour, sugar and baking powder, rub in the butter to breadcrumbs, then mix in the dried fruit.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Mix the wet ingredients", "instruction": "Beat the egg, milk and vanilla together in a separate bowl.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Combine", "instruction": "Stir the egg mixture into the dry ingredients until a thick, lumpy dough forms.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Shape and bake", "instruction": "Spoon golfball-sized mounds onto the tray, spaced apart, and bake until golden-brown.", "timer_seconds": 1050, "background": true}, {"step": 5, "label": "Cool and serve", "instruction": "Cool briefly then transfer to a wire rack.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=tY3taZO3Aro"}, {"id": "52902", "name": "Parkin Cake", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qxuqtt1511724269.jpg", "local_image": "52902.jpg", "ingredients": [{"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Egg", "measure": "1 large"}, {"ingredient": "Milk", "measure": "4 tbs"}, {"ingredient": "Golden Syrup", "measure": "200g"}, {"ingredient": "Black Treacle", "measure": "85g"}, {"ingredient": "Brown Sugar", "measure": "85g"}, {"ingredient": "Oatmeal", "measure": "100g"}, {"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Ground Ginger", "measure": "1 tbs"}], "instructions": "Heat oven to 160C/140C fan/gas 3. Grease a deep 22cm/9in square cake tin and line with baking parchment. Beat the egg and milk together with a fork.\r\n\r\nGently melt the syrup, treacle, sugar and butter together in a large pan until the sugar has dissolved. Remove from the heat. Mix together the oatmeal, flour and ginger and stir into the syrup mixture, followed by the egg and milk.\r\n\r\nPour the mixture into the tin and bake for 50 mins - 1 hr until the cake feels firm and a little crusty on top. Cool in the tin then wrap in more parchment and foil and keep for 3-5 days before eating if you can – it’ll become softer and stickier the longer you leave it, up to 2 weeks.\r\n", "equipment_tags": [], "portions": 7, "prep_minutes": 110, "prep_minutes_source": "explicit", "kcal": 571, "protein_g": 7.6, "carbs_g": 81.6, "fat_g": 25.6, "total_kcal": 3998, "total_protein_g": 53.3, "total_carbs_g": 571.0, "total_fat_g": 179.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Heat the oven to 160°C/140°C fan/gas 3 and grease and line a square tin. Beat the egg and milk together.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Melt the syrup mixture", "instruction": "Gently melt the syrup, treacle, sugar and butter together until the sugar has dissolved, then remove from heat.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Combine", "instruction": "Mix the oatmeal, flour and ginger, stir into the syrup mixture, then stir in the egg and milk.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Pour into the tin and bake until firm and a little crusty on top.", "timer_seconds": 3300, "background": true}, {"step": 5, "label": "Rest before eating", "instruction": "Cool in the tin, then wrap in parchment and foil and keep for a few days before eating for the best texture.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=k1lG4vk2MQA"}, {"id": "52903", "name": "French Onion Soup", "category": "Side", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xvrrux1511783685.jpg", "local_image": "52903.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Onion", "measure": "1 kg"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Garlic Clove", "measure": "4 sliced"}, {"ingredient": "Plain Flour", "measure": "2 tbs"}, {"ingredient": "Dry White Wine", "measure": "250ml"}, {"ingredient": "Beef Stock", "measure": "1L"}, {"ingredient": "Bread", "measure": "4 sliced"}, {"ingredient": "Gruyère", "measure": "140g"}], "instructions": "Melt the butter with the oil in a large heavy-based pan. Add the onions and fry with the lid on for 10 mins until soft. Sprinkle in the sugar and cook for 20 mins more, stirring frequently, until caramelised. The onions should be really golden, full of flavour and soft when pinched between your fingers. Take care towards the end to ensure that they don’t burn.\r\nAdd the garlic for the final few mins of the onions’ cooking time, then sprinkle in the flour and stir well. Increase the heat and keep stirring as you gradually add the wine, followed by the hot stock. Cover and simmer for 15-20 mins.\r\nTo serve, turn on the grill, and toast the bread. Ladle the soup into heatproof bowls. Put a slice or two of toast on top of the bowls of soup, and pile on the cheese. Grill until melted. Alternatively, you can complete the toasts under the grill, then serve them on top.", "equipment_tags": ["Grill"], "portions": 12, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 193, "protein_g": 6.4, "carbs_g": 18.4, "fat_g": 9.0, "total_kcal": 2320, "total_protein_g": 77.0, "total_carbs_g": 221.2, "total_fat_g": 107.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Caramelise the onions", "instruction": "Melt the butter with the oil in a large pan, add the onions, and fry with the lid on until soft, then sprinkle in the sugar and cook, stirring frequently, until caramelised and golden.", "timer_seconds": 1800, "background": false}, {"step": 2, "label": "Build the soup base", "instruction": "Add the garlic for the final minutes, then sprinkle in the flour and stir well. Gradually add the wine, then the hot stock.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Simmer", "instruction": "Cover and simmer.", "timer_seconds": 1050, "background": true}, {"step": 4, "label": "Serve", "instruction": "Toast the bread under the grill, ladle the soup into heatproof bowls, top with toast and cheese, and grill until melted.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=-DLDMQucqDI"}, {"id": "52904", "name": "Beef Bourguignon", "category": "Beef", "area": "France", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/vtqxtu1511784197.jpg", "local_image": "52904.jpg", "ingredients": [{"ingredient": "Goose Fat", "measure": "3 tsp"}, {"ingredient": "Beef Shin", "measure": "600g"}, {"ingredient": "Bacon", "measure": "100g"}, {"ingredient": "Challots", "measure": "350g"}, {"ingredient": "Chestnut Mushroom", "measure": "250g"}, {"ingredient": "Garlic Clove", "measure": "2 sliced"}, {"ingredient": "Bouquet Garni", "measure": "1"}, {"ingredient": "Tomato Puree", "measure": "1 tbs"}, {"ingredient": "Red Wine", "measure": "750 ml"}, {"ingredient": "Celeriac", "measure": "600g"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Thyme", "measure": "sprigs of fresh"}, {"ingredient": "Rosemary", "measure": "sprigs of fresh"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Cardamom", "measure": "4"}], "instructions": "Heat a large casserole pan and add 1 tbsp goose fat. Season the beef and fry until golden brown, about 3-5 mins, then turn over and fry the other side until the meat is browned all over, adding more fat if necessary. Do this in 2-3 batches, transferring the meat to a colander set over a bowl when browned.\r\nIn the same pan, fry the bacon, shallots or pearl onions, mushrooms, garlic and bouquet garni until lightly browned. Mix in the tomato purée and cook for a few mins, stirring into the mixture. This enriches the bourguignon and makes a great base for the stew. Then return the beef and any drained juices to the pan and stir through.\r\nPour over the wine and about 100ml water so the meat bobs up from the liquid, but isn’t completely covered. Bring to the boil and use a spoon to scrape the caramelised cooking juices from the bottom of the pan – this will give the stew more flavour.\r\nHeat oven to 150C/fan 130C/gas 2. Make a cartouche: tear off a square of foil slightly larger than the casserole, arrange it in the pan so it covers the top of the stew and trim away any excess foil. Then cook for 3 hrs. If the sauce looks watery, remove the beef and veg with a slotted spoon, and set aside. Cook the sauce over a high heat for a few mins until the sauce has thickened a little, then return the beef and vegetables to the pan.\r\nTo make the celeriac mash, peel the celeriac and cut into cubes. Heat the olive oil in a large frying pan. Tip in the celeriac and fry for 5 mins until it turns golden. Season well with salt and pepper. Stir in the rosemary, thyme, bay and cardamom pods, then pour over 200ml water, enough to nearly cover the celeriac. Turn the heat to low, partially cover the pan and leave to simmer for 25-30 mins.\r\nAfter 25-30 mins, the celeriac should be soft and most of the water will have evaporated. Drain away any remaining water, then remove the herb sprigs, bay and cardamom pods. Lightly crush with a potato masher, then finish with a glug of olive oil and season to taste. Spoon the beef bourguignon into serving bowls and place a large spoonful of the celeriac mash on top. Garnish with one of the bay leaves, if you like.", "equipment_tags": [], "portions": 6, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 559, "protein_g": 31.4, "carbs_g": 29.2, "fat_g": 26.1, "total_kcal": 3352, "total_protein_g": 188.6, "total_carbs_g": 175.0, "total_fat_g": 156.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "Heat a large casserole with goose fat, season the beef, and fry in batches until browned all over, transferring to a colander over a bowl.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Brown the aromatics", "instruction": "In the same pan, fry the bacon, shallots, mushrooms, garlic and bouquet garni until lightly browned, then stir in the tomato purée and cook a few minutes.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Deglaze and simmer", "instruction": "Return the beef and juices to the pan, pour over the wine and water, bring to the boil, scraping the pan, then cover with a cartouche.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Braise", "instruction": "Heat the oven to 150°C/fan 130°C/gas 2 and cook the stew, covered with the cartouche.", "timer_seconds": 10800, "background": true}, {"step": 5, "label": "Reduce if needed", "instruction": "If the sauce looks watery, remove the beef and veg and reduce the sauce over high heat, then return them to the pan.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Make the celeriac mash", "instruction": "Cube the celeriac and fry in olive oil until golden, season, add the herbs and cardamom, pour over water to nearly cover, and simmer, partially covered, until soft.", "timer_seconds": 1650, "background": true}, {"step": 7, "label": "Finish the mash", "instruction": "Drain any remaining water, discard the herbs, bay and cardamom, and lightly crush with a masher, finishing with olive oil and seasoning.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Serve", "instruction": "Spoon the beef bourguignon into bowls and top with the celeriac mash, garnished with a bay leaf.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=SQnr4Z-7rok"}, {"id": "52905", "name": "Chocolate Souffle", "category": "Dessert", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/twspvx1511784937.jpg", "local_image": "52905.jpg", "ingredients": [{"ingredient": "Single Cream", "measure": "142ml"}, {"ingredient": "Caster Sugar", "measure": "25g"}, {"ingredient": "Dark Chocolate", "measure": "100g"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Butter", "measure": "drizzle"}, {"ingredient": "Caster Sugar", "measure": "50g"}, {"ingredient": "Dark Chocolate", "measure": "175g"}, {"ingredient": "Double Cream", "measure": "2 tbs"}, {"ingredient": "Egg Yolks", "measure": "4"}, {"ingredient": "Egg White", "measure": "5"}, {"ingredient": "Double Cream", "measure": "2 tbs"}, {"ingredient": "Icing Sugar", "measure": "to serve"}], "instructions": "Heat oven to 220C/fan 200C/gas 7 and place a baking tray on the top shelf. For the sauce, heat the cream and sugar until boiling. Remove from the heat, stir in the chocolate and butter until melted, then keep warm.\r\nBrush 6 x 150ml ramekins with melted butter, sprinkle with the 2 tbsp caster sugar, then tip out any excess. Melt the chocolate and cream in a bowl over a pan of simmering water, cool, then mix in the egg yolks. Whisk the egg whites until they hold their shape, then add the sugar, 1 tbsp at a time, whisking back to the same consistency. Mix a spoonful into the chocolate, then gently fold in the rest.\r\nWorking quickly, fill the ramekins, wipe the rims clean and run your thumb around the edges. Turn oven down to 200C/fan 180C/gas 6, place the ramekins onto the baking tray, then bake for 8-10 mins until risen with a slight wobble. Don’t open the oven door too early as this may make them collapse.\r\nOnce the soufflés are ready, dust with icing sugar, scoop a small hole from their tops, then pour in some of the hot chocolate sauce. Replace the lids and serve straight away.", "equipment_tags": [], "portions": 7, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 518, "protein_g": 12.4, "carbs_g": 41.4, "fat_g": 34.3, "total_kcal": 3623, "total_protein_g": 87.0, "total_carbs_g": 289.5, "total_fat_g": 240.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the sauce", "instruction": "Heat the oven to 220°C/fan 200°C/gas 7 with a tray on the top shelf. Heat the cream and sugar until boiling, remove from heat, stir in the chocolate and butter until melted, and keep warm.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Prep the ramekins", "instruction": "Brush 6 ramekins with melted butter, sprinkle with caster sugar, and tip out the excess.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the base", "instruction": "Melt the chocolate and cream together over a pan of simmering water, cool, then mix in the egg yolks.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Whip and fold the whites", "instruction": "Whisk the egg whites to soft peaks, add the sugar gradually while whisking, then fold a spoonful into the chocolate base before gently folding in the rest.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Fill the ramekins, wipe the rims clean, reduce the oven to 200°C/fan 180°C/gas 6, and bake on the tray until risen with a slight wobble, without opening the door early.", "timer_seconds": 570, "background": true}, {"step": 6, "label": "Finish and serve", "instruction": "Dust with icing sugar, scoop a small hole in the top, pour in hot chocolate sauce, and serve straight away.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FWqfkUEWOTg"}, {"id": "52906", "name": "Flamiche", "category": "Vegetarian", "area": "France", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wssvvs1511785879.jpg", "local_image": "52906.jpg", "ingredients": [{"ingredient": "Butter", "measure": "75g"}, {"ingredient": "Leek", "measure": "1kg"}, {"ingredient": "Salt", "measure": "½ tsp"}, {"ingredient": "Creme Fraiche", "measure": "300ml"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Egg Yolks", "measure": "3"}, {"ingredient": "Nutmeg", "measure": "¼ teaspoon"}, {"ingredient": "Plain Flour", "measure": "225g"}, {"ingredient": "Salt", "measure": "½ tsp"}, {"ingredient": "Butter", "measure": "60g"}, {"ingredient": "Lard", "measure": "60g"}, {"ingredient": "Cheddar Cheese", "measure": "50g"}, {"ingredient": "Water", "measure": "2 tbs"}], "instructions": "For the pastry, sift the flour and salt into the bowl of a food processor, add the butter and lard, then whizz together briefly until the mixture looks like fine breadcrumbs. Tip the mixture into a bowl, then stir in the cheese and enough of the water for the mixture to come together. Tip out onto a lightly floured surface and knead briefly until smooth. Roll out thinly and line a 23cm x 4cm loose-?bottomed fluted flan tin. Prick the base with a fork. Chill for 20 minutes.\r\n02.Melt the 75g butter in a saucepan over a low heat, then add the leeks and the salt. Cover and cook for ?10 minutes until soft. Uncover the pan, increase the heat and cook ?for 2 minutes, stirring occasionally, until the liquid has evaporated. Spoon onto a plate and leave to cool.\r\n03.Preheat the oven to 200°C/fan180°C/gas 6. Line the pastry case with baking paper and baking beans or rice and blind bake for 15-20 minutes until the edges are biscuit-coloured. Remove the paper and beans/rice and return the case to the oven for 7-10 minutes until the base is crisp and lightly golden. Remove and set aside. Reduce the oven temperature to 190°C/fan170°C/gas 5.\r\n04.Put the crème fraîche into a bowl with the whole egg, egg yolks and nutmeg. Lightly beat together, then season. Stir in the leeks. Spoon ?the mixture into the tart case and bake for 35-40 minutes until set ?and lightly golden. Remove from ?the oven and leave for 10 minutes. Take out of the tin and serve.", "equipment_tags": ["FoodProcessor"], "portions": 4, "prep_minutes": 112, "prep_minutes_source": "explicit", "kcal": 1144, "protein_g": 22.2, "carbs_g": 82.1, "fat_g": 81.8, "total_kcal": 4576, "total_protein_g": 89.0, "total_carbs_g": 328.5, "total_fat_g": 327.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and chill the pastry", "instruction": "Blend the flour, salt, butter and lard in a food processor to fine breadcrumbs, stir in the cheese and enough water to bring together, knead briefly, then roll out and line a flan tin. Prick the base and chill.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Cook the leeks", "instruction": "Melt the butter, add the leeks and salt, cover and cook until soft, then uncover and cook further until the liquid evaporates. Cool.", "timer_seconds": 720, "background": false}, {"step": 3, "label": "Blind bake the case", "instruction": "Preheat the oven to 200°C/fan180°C/gas 6. Line the pastry with paper and beans and blind-bake, then remove and bake further until crisp and golden. Reduce the oven temperature.", "timer_seconds": 1500, "background": true}, {"step": 4, "label": "Fill and bake", "instruction": "Beat the crème fraîche, egg, egg yolks and nutmeg together, season, stir in the leeks, spoon into the tart case, and bake until set and lightly golden.", "timer_seconds": 2250, "background": true}, {"step": 5, "label": "Rest and serve", "instruction": "Leave to rest before taking out of the tin and serving.", "timer_seconds": 600, "background": true}], "video": "https://www.youtube.com/watch?v=vT0q5c880Rg"}, {"id": "52907", "name": "Duck Confit", "category": "Miscellaneous", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wvpvsu1511786158.jpg", "local_image": "52907.jpg", "ingredients": [{"ingredient": "Sea Salt", "measure": "Handful"}, {"ingredient": "Bay Leaf", "measure": "4"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Thyme", "measure": "Handful"}, {"ingredient": "Duck Legs", "measure": "4"}, {"ingredient": "White Wine", "measure": "100ml"}], "instructions": "The day before you want to make the dish, scatter half the salt, half the garlic and half of the herbs over the base of a small shallow dish. Lay the duck legs, skin-side up, on top, then scatter over the remaining salt, garlic and herbs. Cover the duck and refrigerate overnight. This can be done up to 2 days ahead.\r\nPour the wine into a saucepan that will snugly fit the duck legs in a single layer. Brush the salt off the duck legs and place them, skin-side down, in the wine. Cover the pan with a lid and place over a medium heat. As soon as the wine starts to bubble, turn the heat down to the lowest setting and cook for 2 hours, checking occasionally that the liquid is just barely simmering. (If you own a heat diffuser, it would be good to use it here.) After 2 hours, the duck legs should be submerged in their own fat and the meat should feel incredibly tender when prodded. Leave to cool.\r\nThe duck legs are now cooked and can be eaten immediately – or you can follow the next step if you like them crisp. If you are preparing ahead, pack the duck legs tightly into a plastic container or jar and pour over the fat, but not the liquid at the bottom of the pan. Cover and leave in the fridge for up to a month, or freeze for up to 3 months. The liquid you are left with makes a tasty gravy, which can be chilled or frozen until needed.\r\nTo reheat and crisp up the duck legs, heat oven to 220C/fan 200C/gas 7. Remove the legs from the fat and place them, skin-side down, in an ovenproof frying pan. Roast for 30-40 mins, turning halfway through, until brown and crisp. Serve with the reheated gravy, a crisp salad and some crisp golden ptoatoes.", "equipment_tags": [], "portions": 1, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 808, "protein_g": 40.6, "carbs_g": 14.7, "fat_g": 56.7, "total_kcal": 808, "total_protein_g": 40.6, "total_carbs_g": 14.7, "total_fat_g": 56.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Salt and rest overnight", "instruction": "Scatter half the salt, garlic and herbs in a dish, lay the duck legs skin-side up on top, scatter the rest over, cover, and refrigerate overnight.", "timer_seconds": 43200, "background": true}, {"step": 2, "label": "Confit the duck", "instruction": "Brush the salt off the duck legs, place skin-side down in wine in a snug saucepan, bring to a bubble, then turn to the lowest heat and cook until the meat is very tender.", "timer_seconds": 7200, "background": true}, {"step": 3, "label": "Cool and store", "instruction": "Leave to cool. The legs can be eaten now or packed into a container covered in their fat and refrigerated or frozen for later.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Crisp and serve", "instruction": "To crisp, heat the oven to 220°C/fan 200°C/gas 7, place the legs skin-side down in an ovenproof pan, and roast, turning halfway, until brown and crisp. Serve with gravy, salad and potatoes.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=MHhLJqghY-o"}, {"id": "52908", "name": "Ratatouille", "category": "Vegetarian", "area": "France", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/wrpwuu1511786491.jpg", "local_image": "52908.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "2 large"}, {"ingredient": "Courgettes", "measure": "4"}, {"ingredient": "Yellow Pepper", "measure": "2"}, {"ingredient": "Tomato", "measure": "4 large"}, {"ingredient": "Olive Oil", "measure": "5 tbs"}, {"ingredient": "Basil", "measure": "Bunch"}, {"ingredient": "Onion", "measure": "1 medium"}, {"ingredient": "Garlic Clove", "measure": "3 finely chopped"}, {"ingredient": "Red Wine Vinegar", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}], "instructions": "Cut the aubergines in half lengthways. Place them on the board, cut side down, slice in half lengthways again and then across into 1.5cm chunks. Cut off the courgettes ends, then across into 1.5cm slices. Peel the peppers from stalk to bottom. Hold upright, cut around the stalk, then cut into 3 pieces. Cut away any membrane, then chop into bite-size chunks.\r\nScore a small cross on the base of each tomato, then put them into a heatproof bowl. Pour boiling water over the tomatoes, leave for 20 secs, then remove. Pour the water away, replace the tomatoes and cover with cold water. Leave to cool, then peel the skin away. Quarter the tomatoes, scrape away the seeds with a spoon, then roughly chop the flesh.\r\nSet a sauté pan over medium heat and when hot, pour in 2 tbsp olive oil. Brown the aubergines for 5 mins on each side until the pieces are soft. Set them aside and fry the courgettes in another tbsp oil for 5 mins, until golden on both sides. Repeat with the peppers. Don’t overcook the vegetables at this stage, as they have some more cooking left in the next step.\r\nTear up the basil leaves and set aside. Cook the onion in the pan for 5 mins. Add the garlic and fry for a further min. Stir in the vinegar and sugar, then tip in the tomatoes and half the basil. Return the vegetables to the pan with some salt and pepper and cook for 5 mins. Serve with basil.", "equipment_tags": [], "portions": 2, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 413, "protein_g": 4.9, "carbs_g": 23.4, "fat_g": 35.5, "total_kcal": 825, "total_protein_g": 9.8, "total_carbs_g": 46.7, "total_fat_g": 71.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the vegetables", "instruction": "Cut the aubergines and courgettes into chunks. Peel and cut the peppers into bite-size pieces.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Peel the tomatoes", "instruction": "Score the tomatoes, blanch in boiling water briefly, then cool in cold water, peel, quarter, deseed and chop.", "timer_seconds": 20, "background": false}, {"step": 3, "label": "Brown the vegetables", "instruction": "Brown the aubergines in oil in a sauté pan until soft, then fry the courgettes until golden, then the peppers, in separate batches.", "timer_seconds": 900, "background": false}, {"step": 4, "label": "Build the base", "instruction": "Cook the onion in the pan, add the garlic and fry a minute, then stir in the vinegar and sugar, followed by the tomatoes and half the basil.", "timer_seconds": 360, "background": false}, {"step": 5, "label": "Combine and finish", "instruction": "Return the browned vegetables to the pan with salt and pepper and cook together.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve scattered with the remaining basil.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=BFdQUgAFtGU"}, {"id": "52909", "name": "Tarte Tatin", "category": "Dessert", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ryspuw1511786688.jpg", "local_image": "52909.jpg", "ingredients": [{"ingredient": "Puff Pastry", "measure": "300g"}, {"ingredient": "Plain Flour", "measure": "Dusting"}, {"ingredient": "Braeburn Apples", "measure": "6"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Butter", "measure": "85g"}, {"ingredient": "Creme Fraiche", "measure": "to serve"}], "instructions": "Roll the pastry to a 3mm-thick round on a lightly floured surface and cut a 24cm circle, using a plate as a guide. Lightly prick all over with a fork, wrap in cling film on a baking sheet and freeze while preparing the apples.\r\nHeat oven to 180C/160C fan/gas 4. Peel, quarter and core the apples. Put the sugar in a flameproof 20cm ceramic Tatin dish or a 20cm ovenproof heavy-based frying pan and place over a medium-high heat. Cook the sugar for 5-7 mins to a dark amber caramel syrup that’s starting to smoke, then turn off the heat and stir in the 60g diced chilled butter.\r\nTo assemble the Tarte Tatin, arrange the apple quarters very tightly in a circle around the edge of the dish first, rounded-side down, then fill in the middle in a similar fashion. Gently press with your hands to ensure there are no gaps. Brush the fruit with the melted butter.\r\nBake in the oven for 30 mins, then remove and place the disc of frozen puff pastry on top – it will quickly defrost. Tuck the edges down the inside of the dish and, with a knife, prick a few holes in the pastry to allow steam to escape. Bake for a further 40-45 mins until the pastry is golden brown and crisp.\r\nAllow to cool to room temperature for 1 hr before running a knife around the edge of the dish and inverting it onto a large serving plate that is deep enough to contain the juices. Serve with crème fraîche or vanilla ice cream.", "equipment_tags": [], "portions": 8, "prep_minutes": 142, "prep_minutes_source": "explicit", "kcal": 546, "protein_g": 7.5, "carbs_g": 72.8, "fat_g": 25.3, "total_kcal": 4370, "total_protein_g": 60.4, "total_carbs_g": 582.1, "total_fat_g": 202.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep and freeze the pastry", "instruction": "Roll the pastry to a 3mm-thick round, cut a 24cm circle, prick with a fork, wrap in cling film, and freeze while preparing the apples.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Make the caramel", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Peel, quarter and core the apples. Heat the sugar in an ovenproof frying pan until a dark amber caramel, then stir in the chilled butter off the heat.", "timer_seconds": 420, "background": false}, {"step": 3, "label": "Arrange the apples", "instruction": "Arrange the apple quarters tightly in a circle around the edge and fill the middle, pressing to avoid gaps, then brush with the melted butter.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake the apples", "instruction": "Bake in the oven.", "timer_seconds": 1800, "background": true}, {"step": 5, "label": "Top with pastry and bake", "instruction": "Place the frozen pastry disc on top, tuck the edges down inside the dish, prick a few steam holes, and bake until golden-brown and crisp.", "timer_seconds": 2550, "background": true}, {"step": 6, "label": "Cool, invert and serve", "instruction": "Allow to cool to room temperature, run a knife around the edge, and invert onto a deep serving plate. Serve with crème fraîche or vanilla ice cream.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=8xDM8U6h9Pw"}, {"id": "52910", "name": "Chinon Apple Tarts", "category": "Dessert", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qtqwwu1511792650.jpg", "local_image": "52910.jpg", "ingredients": [{"ingredient": "Puff Pastry", "measure": "320g"}, {"ingredient": "Dark Brown Soft Sugar", "measure": "4 tbs"}, {"ingredient": "Braeburn Apples", "measure": "3"}, {"ingredient": "Red Wine Jelly", "measure": "4 tbs"}, {"ingredient": "Creme Fraiche", "measure": "100ml"}, {"ingredient": "Icing Sugar", "measure": "1 tbs"}, {"ingredient": "Cardamom", "measure": "3"}], "instructions": "To make the red wine jelly, put the red wine, jam sugar, star anise, clove, cinnamon stick, allspice, split vanilla pod and seeds in a medium saucepan. Stir together, then heat gently to dissolve the sugar. Turn up the heat and boil for 20 mins until reduced and syrupy. Strain into a small, sterilised jam jar and leave to cool completely. Will keep in the fridge for up to 1 month.\r\n\r\nTake the pastry out of the fridge and leave at room temperature for 10 mins, then unroll. Heat the grill to high and heat the oven to 180C/160C fan/gas 4. Cut out 2 x 13cm circles of pastry, using a plate as a guide, and place on a non-stick baking sheet. Sprinkle each circle with 1 tbsp sugar and grill for 5 mins to caramelise, watching carefully so that the sugar doesn’t burn. Remove from the grill. Can be done a few hours ahead, and left, covered, out of the fridge.\r\n\r\nPeel, quarter and core the apples, cut into 2mm-thin slices and arrange on top of the pastry. Sprinkle over the remaining sugar and pop in the oven for 20-25 mins until the pastry is cooked through and golden, and the apples are softened. Remove and allow to cool slightly. Warm 3 tbsp of the red wine jelly in a small pan over a low heat with 1 tsp water to make it a little more runny, then brush over the top of the tarts.\r\n\r\nTip the crème fraîche into a bowl, sift over the icing sugar and cardamom, and mix together. Carefully lift the warm tarts onto serving plates and serve with the cardamom crème fraîche.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 491, "protein_g": 4.4, "carbs_g": 46.9, "fat_g": 31.7, "total_kcal": 2457, "total_protein_g": 22.2, "total_carbs_g": 234.4, "total_fat_g": 158.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the red wine jelly", "instruction": "Put the red wine, jam sugar and spices in a saucepan, heat gently to dissolve the sugar, then boil until reduced and syrupy. Strain into a jar and leave to cool completely.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Caramelise the pastry rounds", "instruction": "Bring the pastry to room temperature, then heat the grill and oven. Cut out 2 pastry circles, sprinkle with sugar, and grill to caramelise, watching closely.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Top with apples and bake", "instruction": "Peel, quarter and thinly slice the apples, arrange on the caramelised pastry, sprinkle with remaining sugar, and bake until the pastry is cooked and golden and the apples softened.", "timer_seconds": 1350, "background": true}, {"step": 4, "label": "Glaze the tarts", "instruction": "Cool slightly, then warm some red wine jelly with water until runny and brush over the tarts.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Make the cardamom cream and serve", "instruction": "Mix the crème fraîche with sifted icing sugar and cardamom, then serve alongside the warm tarts.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=5dAW9HQgtCk"}, {"id": "52911", "name": "Summer Pistou", "category": "Vegetarian", "area": "France", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/rqtxvr1511792990.jpg", "local_image": "52911.jpg", "ingredients": [{"ingredient": "Rapeseed Oil", "measure": "1 tbs"}, {"ingredient": "Leek", "measure": "2 finely chopped"}, {"ingredient": "Courgettes", "measure": "1 large"}, {"ingredient": "Vegetable Stock", "measure": "1L"}, {"ingredient": "Cannellini Beans", "measure": "400g"}, {"ingredient": "Green Beans", "measure": "200g"}, {"ingredient": "Tomatoes", "measure": "3 chopped"}, {"ingredient": "Garlic Clove", "measure": "3 chopped"}, {"ingredient": "Basil", "measure": "Small pack"}, {"ingredient": "Parmesan", "measure": "40g"}], "instructions": "Heat the oil in a large pan and fry the leeks and courgette for 5 mins to soften. Pour in the stock, add three-quarters of the haricot beans with the green beans, half the tomatoes, and simmer for 5-8 mins until the vegetables are tender.\r\nMeanwhile, blitz the remaining beans and tomatoes, the garlic and basil in a food processor (or in a bowl with a stick blender) until smooth, then stir in the Parmesan. Stir the sauce into the soup, cook for 1 min, then ladle half into bowls or pour into a flask for a packed lunch. Chill the remainder. Will keep for a couple of days.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 4, "prep_minutes": 14, "prep_minutes_source": "explicit", "kcal": 265, "protein_g": 16.2, "carbs_g": 36.2, "fat_g": 7.5, "total_kcal": 1058, "total_protein_g": 64.9, "total_carbs_g": 144.9, "total_fat_g": 30.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the vegetables", "instruction": "Heat the oil in a large pan and fry the leeks and courgette to soften.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Simmer the soup", "instruction": "Pour in the stock, add three-quarters of the beans with the green beans and half the tomatoes, and simmer until the vegetables are tender.", "timer_seconds": 420, "background": true}, {"step": 3, "label": "Make the pistou", "instruction": "Meanwhile, blitz the remaining beans and tomatoes with the garlic and basil until smooth, then stir in the Parmesan.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Stir the pistou sauce into the soup and cook briefly, then serve half and chill the rest for later.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=fyeqZJKEXp0"}, {"id": "52912", "name": "Three-cheese souffles", "category": "Miscellaneous", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sxwquu1511793428.jpg", "local_image": "52912.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Parmesan", "measure": "25g"}, {"ingredient": "Milk", "measure": "300ml"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Plain Flour", "measure": "5 tbs"}, {"ingredient": "English Mustard", "measure": "½ tsp"}, {"ingredient": "Cayenne Pepper", "measure": "Pod of"}, {"ingredient": "Gruyère", "measure": "140g"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Goats Cheese", "measure": "8 slices"}, {"ingredient": "Double Cream", "measure": "150ml"}, {"ingredient": "Spinach", "measure": "to serve"}], "instructions": "Heat oven to 200C/180C fan/ gas 6 and butter 4 small (about 200ml) ramekins. Sprinkle the Parmesan into the ramekins, turning until all sides are covered. Place the milk and bay leaves in a large saucepan over a gentle heat and bring to the boil. Turn off the heat and leave to infuse for 15 mins.\r\nDiscard the bay leaves, add the butter and flour, and return to a low heat. Very gently simmer, stirring continuously with a balloon whisk, for about 6 mins until you get a smooth, thick white sauce. Make sure that you get right into the corners of the pan to stop the sauce from catching or becoming lumpy.\r\nOnce thickened, transfer the sauce to a large bowl and stir in the mustard powder, cayenne pepper, Gruyère and egg yolks until fully combined.\r\nIn a spotlessly clean bowl and with a clean whisk, beat the egg whites just until peaks begin to form.\r\nCarefully fold the egg whites into the cheese sauce in three stages making sure you fold, rather than stir, to keep the egg whites light and airy. Fill the prepared ramekins with the soufflé mix.\r\nTop each soufflé with a slice of goat’s cheese, then place on a baking tray. Bake for 20-25 mins or until springy and well risen but cooked through.\r\nLeave to cool, then run a knife around the edge of each dish and remove the soufflés. If preparing in advance, place soufflés upside down (for neat presentation), on a tray. Cover tray in cling film. Chill for a few days or freeze for up to 1 month.\r\nWhen ready to re-bake, heat oven to 200C/180C fan/gas 6. Place the upside-down soufflés in a shallow baking dish, top with the remaining goat’s cheese slices and pour over the cream (this stops them from drying out when baked for the second time). Cook for 8-10 mins until golden. Serve immediately alongside some simply dressed salad.", "equipment_tags": [], "portions": 2, "prep_minutes": 56, "prep_minutes_source": "explicit", "kcal": 1487, "protein_g": 68.5, "carbs_g": 28.8, "fat_g": 123.1, "total_kcal": 2974, "total_protein_g": 137.0, "total_carbs_g": 57.6, "total_fat_g": 246.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the ramekins and infuse the milk", "instruction": "Heat the oven to 200°C/180°C fan/gas 6, butter 4 ramekins and coat with Parmesan. Bring the milk and bay leaves to the boil, then turn off the heat and leave to infuse.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Make the white sauce", "instruction": "Discard the bay leaves, add the butter and flour, and gently simmer, whisking continuously, until you get a smooth, thick sauce.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Finish the base", "instruction": "Transfer to a bowl and stir in the mustard, cayenne, Gruyère and egg yolks until combined.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Whisk and fold the whites", "instruction": "Beat the egg whites in a clean bowl until peaks begin to form, then fold into the cheese sauce in three stages.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Fill the ramekins, top with a slice of goat's cheese, and bake until springy and well risen but cooked through.", "timer_seconds": 1350, "background": true}, {"step": 6, "label": "Cool and unmould", "instruction": "Leave to cool, then run a knife around the edge to remove each soufflé.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Re-bake and serve", "instruction": "Place the soufflés upside down in a dish, top with remaining goat's cheese, pour over the cream, and bake again until golden. Serve immediately with a simply dressed salad.", "timer_seconds": 540, "background": true}], "video": "https://www.youtube.com/watch?v=mS_gbQpBvZo"}, {"id": "52913", "name": "Brie wrapped in prosciutto & brioche", "category": "Side", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qqpwsy1511796276.jpg", "local_image": "52913.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "375g"}, {"ingredient": "Caster Sugar", "measure": "50g"}, {"ingredient": "Yeast", "measure": "7g"}, {"ingredient": "Milk", "measure": "75g"}, {"ingredient": "Eggs", "measure": "3 Large"}, {"ingredient": "Eggs", "measure": "To Glaze"}, {"ingredient": "Butter", "measure": "180g"}, {"ingredient": "Brie", "measure": "250g"}, {"ingredient": "Prosciutto", "measure": "8 slices"}], "instructions": "Mix the flour, 1 tsp salt, caster sugar, yeast, milk and eggs together in a mixer using the dough attachment for 5 mins until the dough is smooth. Add the butter and mix for a further 4 mins on medium speed. Scrape the dough bowl and mix again for 1 min. Place the dough in a container, cover with cling film and leave in the fridge for at least 6 hrs before using.\r\nWrap the Brie in the prosciutto and set aside. Turn out the dough onto a lightly floured surface. Roll into a 25cm circle. Place the wrapped Brie in the middle of the circle and fold the edges in neatly. Put the parcel onto a baking tray lined with baking parchment and brush with beaten egg. Chill in the fridge for 30 mins, then brush again with beaten egg and chill for a further 30 mins. Leave to rise for 1 hr at room temperature. Heat oven to 200C/180C fan/gas 6, then bake for 22 mins. Serve warm.", "equipment_tags": [], "portions": 7, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 649, "protein_g": 24.3, "carbs_g": 49.4, "fat_g": 39.5, "total_kcal": 4544, "total_protein_g": 170.2, "total_carbs_g": 345.9, "total_fat_g": 276.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix and knead the dough", "instruction": "Mix the flour, salt, sugar, yeast, milk and eggs in a stand mixer with the dough hook until smooth, then add the butter and mix further until incorporated.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Rest the dough", "instruction": "Place in a container, cover, and leave in the fridge for at least 6 hours.", "timer_seconds": 21600, "background": true}, {"step": 3, "label": "Wrap the brie", "instruction": "Wrap the Brie in the prosciutto slices and set aside.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Wrap the dough around the brie", "instruction": "Roll the dough into a circle, place the wrapped Brie in the middle, and fold the edges in neatly to enclose it.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Glaze and chill", "instruction": "Put on a lined tray, brush with beaten egg, chill, brush with egg again, and chill once more.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Prove and bake", "instruction": "Leave to rise at room temperature, then heat the oven to 200°C/180°C fan/gas 6 and bake.", "timer_seconds": 4920, "background": true}, {"step": 7, "label": "Serve", "instruction": "Serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FzNPPD8lbWg"}, {"id": "52914", "name": "Boulangère Potatoes", "category": "Side", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qywups1511796761.jpg", "local_image": "52914.jpg", "ingredients": [{"ingredient": "Onions", "measure": "2 finely chopped"}, {"ingredient": "Thyme", "measure": "sprigs of fresh"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Potatoes", "measure": "1.5kg"}, {"ingredient": "Vegetable Stock", "measure": "425g"}], "instructions": "Heat oven to 200C/fan 180C/gas 6. Fry the onions and thyme sprigs in the oil until softened and lightly coloured (about 5 mins).\r\nSpread a layer of potatoes over the base of a 1.5-litre oiled gratin dish. Sprinkle over a few onions (see picture, above) and continue layering, finishing with a layer of potatoes. Pour over the stock and bake for 50-60 mins until the potatoes are cooked and the top is golden and crisp.", "equipment_tags": [], "portions": 12, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 126, "protein_g": 2.9, "carbs_g": 23.2, "fat_g": 2.5, "total_kcal": 1510, "total_protein_g": 34.7, "total_carbs_g": 278.9, "total_fat_g": 29.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onions", "instruction": "Heat the oven to 200°C/fan 180°C/gas 6. Fry the onions and thyme sprigs in the oil until softened and lightly coloured.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Layer the potatoes", "instruction": "Layer the potatoes and onions in an oiled gratin dish, finishing with a layer of potatoes.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Pour over the stock and bake until the potatoes are cooked and the top is golden and crisp.", "timer_seconds": 3300, "background": true}], "video": "https://www.youtube.com/watch?v=gcXPruv1Mjg"}, {"id": "52915", "name": "French Omelette", "category": "Miscellaneous", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yvpuuy1511797244.jpg", "local_image": "52915.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Butter", "measure": "2 knobs"}, {"ingredient": "Parmesan", "measure": "1 tsp"}, {"ingredient": "Tarragon Leaves", "measure": "3 chopped"}, {"ingredient": "Parsley", "measure": "1 tbs chopped"}, {"ingredient": "Chives", "measure": "1 tbs chopped"}, {"ingredient": "Gruyère", "measure": "4 tbs"}], "instructions": "Get everything ready. Warm a 20cm (measured across the top) non-stick frying pan on a medium heat. Crack the eggs into a bowl and beat them with a fork so they break up and mix, but not as completely as you would for scrambled egg. With the heat on medium-hot, drop one knob of butter into the pan. It should bubble and sizzle, but not brown. Season the eggs with the Parmesan and a little salt and pepper, and pour into the pan.\r\nLet the eggs bubble slightly for a couple of seconds, then take a wooden fork or spatula and gently draw the mixture in from the sides of the pan a few times, so it gathers in folds in the centre. Leave for a few seconds, then stir again to lightly combine uncooked egg with cooked. Leave briefly again, and when partly cooked, stir a bit faster, stopping while there’s some barely cooked egg left. With the pan flat on the heat, shake it back and forth a few times to settle the mixture. It should slide easily in the pan and look soft and moist on top. A quick burst of heat will brown the underside.\r\nGrip the handle underneath. Tilt the pan down away from you and let the omelette fall to the edge. Fold the side nearest to you over by a third with your fork, and keep it rolling over, so the omelette tips onto a plate – or fold it in half, if that’s easier. For a neat finish, cover the omelette with a piece of kitchen paper and plump it up a bit with your fingers. Rub the other knob of butter over to glaze. Serve immediately.", "equipment_tags": [], "portions": 1, "prep_minutes": 64, "prep_minutes_source": "estimated", "kcal": 712, "protein_g": 40.2, "carbs_g": 3.9, "fat_g": 60.2, "total_kcal": 712, "total_protein_g": 40.2, "total_carbs_g": 3.9, "total_fat_g": 60.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep and beat the eggs", "instruction": "Warm a non-stick frying pan over medium heat. Crack the eggs into a bowl and beat with a fork so they mix but aren't fully smooth.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the omelette", "instruction": "Melt a knob of butter in the pan, season the eggs with Parmesan, salt and pepper, and pour in. Draw the egg in from the sides a few times to fold, then let it settle until soft and moist on top, with a quick burst of heat to brown the underside.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Fold and serve", "instruction": "Tilt the pan, fold the omelette over with a fork, and tip onto a plate. Rub with the remaining butter to glaze and serve immediately.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=qXPhVYpQLPA"}, {"id": "52916", "name": "Pear Tarte Tatin", "category": "Dessert", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rxvxrr1511797671.jpg", "local_image": "52916.jpg", "ingredients": [{"ingredient": "Pears", "measure": "8"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Star Anise", "measure": "2"}, {"ingredient": "Cardamom", "measure": "3 Pods"}, {"ingredient": "Cinnamon", "measure": "1 large"}, {"ingredient": "Brandy", "measure": "2 tbs"}, {"ingredient": "Puff Pastry", "measure": "500g"}], "instructions": "Core the pears, then peel as neatly as possible and halve. If you like, they can be prepared up to a day ahead and kept in the fridge, uncovered, so that they dry out.\r\nTip the sugar, butter, star anise, cardamom and cinnamon into an ovenproof frying pan, about 20cm wide, and place over a high heat until bubbling. Shake the pan and stir the buttery sauce until it separates and the sugar caramelises to a toffee colour.\r\nLay the pears in the pan, then cook in the sauce for 10-12 mins, tossing occasionally, until completely caramelised. Don’t worry about them burning – they won’t – but you want to caramelise them as much as possible. Splash in the brandy and let it flambé, then set the pears aside.\r\nHeat oven to 200C/fan 180C/gas 6. Roll the pastry out to the thickness of a £1 coin. Using a plate slightly larger than the top of the pan, cut out a circle, then press the edges of the circle of pastry to thin them out.\r\nWhen the pears have cooled slightly, arrange them in the pan, cut side up, in a floral shape, with the pears around the edge pointing inwards. Rest the cinnamon stick on the top in the centre, with the cardamom pods scattered around.\r\nDrape the pastry over the pears, then tuck the edges down the pan sides and under the fruit (see Gordon’s guide). Pierce the pastry a few times, then bake for 15 mins. If a lot of juice bubbles up the side of the pan, pour it off at this stage (see guide). Reduce oven to 180C/fan 160C/gas 4 and bake for 15 mins more until the pastry is golden. Leave the tart to stand for 10 mins, then invert it carefully onto a serving dish.", "equipment_tags": [], "portions": 8, "prep_minutes": 52, "prep_minutes_source": "explicit", "kcal": 525, "protein_g": 4.1, "carbs_g": 48.4, "fat_g": 35.2, "total_kcal": 4200, "total_protein_g": 32.8, "total_carbs_g": 387.1, "total_fat_g": 281.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the pears", "instruction": "Core, peel and halve the pears.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the caramel", "instruction": "Heat the sugar, butter, star anise, cardamom and cinnamon in an ovenproof frying pan over high heat until bubbling and caramelised to a toffee colour.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Caramelise the pears", "instruction": "Lay the pears in the pan and cook in the sauce, tossing occasionally, until completely caramelised, then splash in the brandy and flambé.", "timer_seconds": 660, "background": false}, {"step": 4, "label": "Prep the pastry", "instruction": "Heat the oven to 200°C/fan 180°C/gas 6. Roll the pastry and cut a circle slightly larger than the pan, thinning the edges.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Arrange and top", "instruction": "Arrange the cooled pears cut-side up in a floral pattern in the pan, rest the cinnamon stick in the centre, then drape the pastry over, tucking the edges under, and pierce a few times.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake", "instruction": "Bake, pouring off excess juice if needed, then reduce the oven temperature and bake further until the pastry is golden.", "timer_seconds": 1800, "background": true}, {"step": 7, "label": "Rest and invert", "instruction": "Leave to stand, then invert carefully onto a serving dish.", "timer_seconds": 600, "background": true}], "video": "https://www.youtube.com/watch?v=8U1tKWKDeWA"}, {"id": "52917", "name": "White chocolate creme brulee", "category": "Dessert", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uryqru1511798039.jpg", "local_image": "52917.jpg", "ingredients": [{"ingredient": "Double Cream", "measure": "568ml"}, {"ingredient": "White Chocolate Chips", "measure": "100g"}, {"ingredient": "Vanilla", "measure": "Pod of"}, {"ingredient": "Egg Yolks", "measure": "6"}, {"ingredient": "Caster Sugar", "measure": "2 tbs"}, {"ingredient": "Caster Sugar", "measure": "Top"}], "instructions": "Heat the cream, chocolate and vanilla pod in a pan until the chocolate has melted. Take off the heat and allow to infuse for 10 mins, scraping the pod seeds into the cream. If using the vanilla extract, add straight away. Heat oven to 160C/fan 140C/gas 3.\r\nBeat yolks and sugar until pale. stir in the chocolate cream. Strain into a jug and pour into ramekins. Place in a deep roasting tray and pour boiling water halfway up the sides. Bake for 15-20 mins until just set with a wobbly centre. Chill in the fridge for at least 4 hrs.\r\nTo serve, sprinkle some sugar on top of the brûlées and caramelise with a blowtorch or briefly under a hot grill. Leave caramel to harden, then serve.", "equipment_tags": ["Grill"], "portions": 7, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 622, "protein_g": 10.0, "carbs_g": 20.6, "fat_g": 55.1, "total_kcal": 4357, "total_protein_g": 69.8, "total_carbs_g": 144.4, "total_fat_g": 385.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Infuse the cream", "instruction": "Heat the cream, chocolate and vanilla pod until the chocolate melts, then take off the heat and let infuse, scraping the pod seeds into the cream. Heat the oven to 160°C/fan 140°C/gas 3.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Make the custard base", "instruction": "Beat the yolks and sugar until pale, then stir in the chocolate cream and strain into a jug.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake in a water bath", "instruction": "Pour into ramekins, place in a roasting tray, pour boiling water halfway up the sides, and bake until just set with a wobbly centre.", "timer_seconds": 1050, "background": true}, {"step": 4, "label": "Chill", "instruction": "Chill in the fridge for at least 4 hours.", "timer_seconds": 14400, "background": true}, {"step": 5, "label": "Caramelise and serve", "instruction": "Sprinkle sugar on top and caramelise with a blowtorch or under a hot grill. Let the caramel harden, then serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=LmJ0lsPLHDc"}, {"id": "52918", "name": "Fish Stew with Rouille", "category": "Seafood", "area": "France", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/vptqpw1511798500.jpg", "local_image": "52918.jpg", "ingredients": [{"ingredient": "Prawns", "measure": "6 large"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Dry White Wine", "measure": "150ml"}, {"ingredient": "Fish Stock", "measure": "200ml"}, {"ingredient": "Fennel", "measure": "1 small finely diced"}, {"ingredient": "Onion", "measure": "1 small finely diced"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Potatoes", "measure": "1 large"}, {"ingredient": "Orange", "measure": "1"}, {"ingredient": "Star Anise", "measure": "1"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Harissa Spice", "measure": "1 1/2 tsp"}, {"ingredient": "Tomato Puree", "measure": "2 tbs"}, {"ingredient": "Chopped Tomatoes", "measure": "400g"}, {"ingredient": "Mussels", "measure": "Handful"}, {"ingredient": "White Fish", "measure": "200g"}, {"ingredient": "Thyme", "measure": "2"}, {"ingredient": "Bread", "measure": "to serve"}], "instructions": "Twist the heads from the prawns, then peel away the legs and shells, but leave the tails intact. Devein each prawn. Fry the shells in 1 tbsp oil for 5 mins, until dark pink and golden in patches. Add the wine, boil down by two thirds, then pour in the stock. Strain into a jug, discarding the shells.\r\nHeat the rest of the oil in a deep frying pan or casserole. Add the fennel, onion and garlic, season, then cover and gently cook for 10 mins until softened. Meanwhile, peel the potato and cut into 2cm-ish chunks. Put into a pan of cold water, bring to the boil and cook for 5 mins until almost tender. Drain in a colander.\r\nPeel a strip of zest from the orange. Put the zest, star anise, bay and ½ tsp harissa into the pan. Fry gently, uncovered, for 5-10 mins, until the vegetables are soft, sweet and golden.\r\nStir in the tomato purée, cook for 2 mins, then add the tomatoes and stock. Simmer for 10 mins until the sauce thickens slightly. Season to taste. The sauce can be made ahead, then reheated later in the day. Meantime, scrub the mussels or clams and pull away any stringy beards. Any that are open should be tapped sharply on the worktop – if they don’t close after a few seconds, discard them.\r\nReheat the sauce if necessary, then stir the potato, chunks of fish and prawns very gently into the stew. Bring back to the boil, then cover and gently simmer for 3 mins. Scatter the mussels or clams over the stew, then cover and cook for 2 mins more or until the shells have opened wide. Discard any that remain closed. The chunks of fish should flake easily and the prawns should be pink through. Scatter with the thyme leaves.\r\nTo make the quick rouille, stir the rest of the harissa through the mayonnaise. Serve the stew in bowls, topped with spoonfuls of rouille, which will melt into the sauce and enrich it. Have some good bread ready, as you’ll definitely want to mop up the juices.", "equipment_tags": [], "portions": 4, "prep_minutes": 47, "prep_minutes_source": "explicit", "kcal": 375, "protein_g": 30.3, "carbs_g": 32.5, "fat_g": 12.5, "total_kcal": 1498, "total_protein_g": 121.3, "total_carbs_g": 129.8, "total_fat_g": 50.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the shellfish stock", "instruction": "Twist off the prawn heads and peel, leaving tails intact, then devein. Fry the shells in a little oil until golden, add the wine and boil to reduce by two thirds, then add the fish stock. Strain into a jug, discarding the shells.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Soften the vegetables", "instruction": "Heat the rest of the oil in a deep pan, add the fennel, onion and garlic, season, cover, and cook gently until softened.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Par-cook the potato", "instruction": "Meanwhile, peel and chunk the potato, boil in cold water until almost tender, then drain.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Build the sauce base", "instruction": "Add the orange zest, star anise, bay and harissa to the softened vegetables and fry gently, uncovered, until soft, sweet and golden.", "timer_seconds": 450, "background": false}, {"step": 5, "label": "Simmer the sauce", "instruction": "Stir in the tomato purée, cook briefly, then add the tomatoes and stock and simmer until slightly thickened. Season to taste.", "timer_seconds": 600, "background": true}, {"step": 6, "label": "Prep the mussels", "instruction": "While the sauce simmers, scrub the mussels or clams, remove any beards, and discard any that don't close when tapped.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Cook the fish and shellfish", "instruction": "Reheat the sauce, stir in the potato, fish and prawns gently, bring to the boil, cover and simmer briefly, then scatter the mussels over, cover and cook until the shells open. Discard any that stay closed.", "timer_seconds": 300, "background": false}, {"step": 8, "label": "Make the rouille and serve", "instruction": "Scatter the stew with thyme leaves. Stir the remaining harissa through the mayonnaise and serve the stew topped with rouille, with bread on the side.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=fp9Lqx2EUco"}, {"id": "52919", "name": "Fennel Dauphinoise", "category": "Side", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ytttsv1511798734.jpg", "local_image": "52919.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "225g"}, {"ingredient": "Fennel", "measure": "1 small"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Milk", "measure": "75 ml"}, {"ingredient": "Double Cream", "measure": "100ml"}, {"ingredient": "Butter", "measure": "For Greasing"}, {"ingredient": "Parmesan Cheese", "measure": "to serve"}], "instructions": "Heat oven to 180C/160C fan/gas 4. Put potatoes, fennel, and garlic in a medium non-stick pan. Pour in milk and double cream, season well and simmer gently, covered, for 10 mins, stirring halfway through, until potatoes are just tender.\r\nDivide the mixture between 2 small (about 150ml) buttered ramekins and scatter with Parmesan. Bake for 40 mins until the potatoes are golden and tender when pierced with a knife. Snip the reserved fennel fronds over before serving.", "equipment_tags": [], "portions": 3, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 344, "protein_g": 7.4, "carbs_g": 16.8, "fat_g": 27.9, "total_kcal": 1032, "total_protein_g": 22.2, "total_carbs_g": 50.5, "total_fat_g": 83.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the base", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Put the potatoes, fennel and garlic in a pan with the milk and cream, season, and simmer gently, covered, stirring halfway, until the potatoes are just tender.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Bake", "instruction": "Divide between buttered ramekins, scatter with Parmesan, and bake until golden and tender when pierced.", "timer_seconds": 2400, "background": true}, {"step": 3, "label": "Serve", "instruction": "Snip the reserved fennel fronds over before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=tXBzZm2kkh8"}, {"id": "52920", "name": "Chicken Marengo", "category": "Chicken", "area": "France", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/qpxvuq1511798906.jpg", "local_image": "52920.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Mushrooms", "measure": "300g"}, {"ingredient": "Chicken Legs", "measure": "4"}, {"ingredient": "Passata", "measure": "500g"}, {"ingredient": "Chicken Stock Cube", "measure": "1"}, {"ingredient": "Black Olives", "measure": "100g"}, {"ingredient": "Parsley", "measure": "Chopped"}], "instructions": "Heat the oil in a large flameproof casserole dish and stir-fry the mushrooms until they start to soften. Add the chicken legs and cook briefly on each side to colour them a little.\r\nPour in the passata, crumble in the stock cube and stir in the olives. Season with black pepper – you shouldn’t need salt. Cover and simmer for 40 mins until the chicken is tender. Sprinkle with parsley and serve with pasta and a salad, or mash and green veg, if you like.", "equipment_tags": [], "portions": 2, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 388, "protein_g": 30.6, "carbs_g": 25.3, "fat_g": 20.2, "total_kcal": 776, "total_protein_g": 61.2, "total_carbs_g": 50.6, "total_fat_g": 40.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the mushrooms and chicken", "instruction": "Heat the oil in a large casserole and stir-fry the mushrooms until softening. Add the chicken legs and cook briefly on each side to colour.", "timer_seconds": 420, "background": false}, {"step": 2, "label": "Simmer", "instruction": "Pour in the passata, crumble in the stock cube, stir in the olives, and season with pepper. Cover and simmer until the chicken is tender.", "timer_seconds": 2400, "background": true}, {"step": 3, "label": "Serve", "instruction": "Sprinkle with parsley and serve with pasta and salad, or mash and green veg.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=U33HYUr-0Fw"}, {"id": "52921", "name": "Provençal Omelette Cake", "category": "Vegetarian", "area": "France", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/qwtrtp1511799242.jpg", "local_image": "52921.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "10"}, {"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Courgettes", "measure": "2 finely chopped"}, {"ingredient": "Spring Onions", "measure": "3 finely chopped"}, {"ingredient": "Red Pepper", "measure": "4"}, {"ingredient": "Garlic Clove", "measure": "1 clove peeled crushed"}, {"ingredient": "Red Chilli", "measure": "1"}, {"ingredient": "Cream Cheese", "measure": "300g"}, {"ingredient": "Milk", "measure": "6 tblsp"}, {"ingredient": "Chives", "measure": "4 tbs"}, {"ingredient": "Basil", "measure": "2 tbs"}, {"ingredient": "Rocket", "measure": "to serve"}, {"ingredient": "Parmesan", "measure": "to serve"}], "instructions": "Break the eggs into two bowls, five in each. Whisk lightly and season with salt and pepper. Heat the oil in a pan, add the courgettes and spring onions, then fry gently for about 10 mins until softened. Cool, then stir into one bowl of eggs with a little salt and pepper. Add the roasted peppers to the other bowl of eggs with the garlic, chilli, salt and pepper.\r\nHeat a little oil in a 20-23cm frying pan, preferably non-stick. Pour the eggs with courgette into a measuring jug, then pourabout one-third of the mixture into the pan, swirling it to cover the base of the pan. Cook until the egg is set and lightly browned underneath, then cover the pan with a plate and invert the omelette onto it. Slide it back into the pan to cook the other side. Repeat with the remaining mix to make two more omelettes, adding a little oil to the pan each time. Stack the omelettes onto a plate. Make three omelettes in the same way with the red pepper mixture, then stack them on a separate plate.\r\nNow make the filling. Beat the cheese to soften it, then beat in the milk to make a spreadable consistency. Stir in the herbs, salt and pepper. Line a deep, 20-23cm round cake tin with cling film (use a tin the same size as the frying pan). Select the best red pepper omelette and place in the tin, prettiest side down. Spread with a thin layer of cheese filling, then cover with a courgette omelette. Repeat, alternating the layers, until all the omelettes and filling are in the tin, finishing with an omelette. Flip the cling film over the omelette, then chill for up to 24 hrs.\r\nTo serve, invert the omelette cake onto a serving plate and peel off the cling film. Pile rocket on the top and scatter over the cheese, a drizzle of olive oil and a little freshly ground black pepper. Serve cut into wedges.", "equipment_tags": [], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 742, "protein_g": 36.4, "carbs_g": 20.1, "fat_g": 59.8, "total_kcal": 2227, "total_protein_g": 109.3, "total_carbs_g": 60.4, "total_fat_g": 179.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the courgette omelettes", "instruction": "Whisk 5 eggs and season. Fry the courgettes and spring onions in oil until softened, cool, and stir into the eggs. Cook in a pan in batches to make three omelettes, flipping each with a plate.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Cook the pepper omelettes", "instruction": "Whisk the remaining 5 eggs with the roasted peppers, garlic and chilli, season, and cook in the same way to make three more omelettes.", "timer_seconds": 900, "background": false}, {"step": 3, "label": "Make the filling", "instruction": "Beat the cheese to soften, beat in the milk to a spreadable consistency, then stir in the herbs and seasoning.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Layer the cake", "instruction": "Line a deep round tin with cling film. Layer the pepper and courgette omelettes with the cheese filling between each, finishing with an omelette.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Chill", "instruction": "Flip the cling film over the top and chill.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Turn out and serve", "instruction": "Invert onto a serving plate, peel off the cling film, pile rocket on top with cheese shavings, olive oil and black pepper, and cut into wedges to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=B7isFo2uP2k"}, {"id": "52922", "name": "Prawn & Fennel Bisque", "category": "Side", "area": "France", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rtwwvv1511799504.jpg", "local_image": "52922.jpg", "ingredients": [{"ingredient": "Tiger Prawns", "measure": "450g"}, {"ingredient": "Olive Oil", "measure": "4 tbs"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Fennel", "measure": "1 large"}, {"ingredient": "Carrots", "measure": "2 chopped"}, {"ingredient": "Dry White Wine", "measure": "150ml"}, {"ingredient": "Brandy", "measure": "1 tbs"}, {"ingredient": "Chopped Tomatoes", "measure": "400g"}, {"ingredient": "Fish Stock", "measure": "1L"}, {"ingredient": "Paprika", "measure": "2 pinches"}, {"ingredient": "Double Cream", "measure": "150ml"}, {"ingredient": "Prawns", "measure": "8"}], "instructions": "Shell the prawns, then fry the shells in the oil in a large pan for about 5 mins. Add the onion, fennel and carrots and cook for about 10 mins until the veg start to soften. Pour in the wine and brandy, bubble hard for about 1 min to drive off the alcohol, then add the tomatoes, stock and paprika. Cover and simmer for 30 mins. Meanwhile, chop the prawns.\r\nBlitz the soup as finely as you can with a stick blender or food processor, then press through a sieve into a bowl. Spend a bit of time really working the mixture through the sieve as this will give the soup its velvety texture.\r\nTip back into a clean pan, add the prawns and cook for 10 mins, then blitz again until smooth. You can make and chill this a day ahead or freeze it for 1 month. Thaw ovenight in the fridge. To serve, gently reheat in a pan with the cream. If garnishing, cook the 8 prawns in a little butter. Spoon into small bowls and top with the prawns and snipped fennel fronds.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 12, "prep_minutes": 56, "prep_minutes_source": "explicit", "kcal": 190, "protein_g": 15.5, "carbs_g": 4.9, "fat_g": 11.2, "total_kcal": 2275, "total_protein_g": 186.0, "total_carbs_g": 58.7, "total_fat_g": 133.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Build the bisque base", "instruction": "Shell the prawns and fry the shells in oil for about 5 minutes, then add the onion, fennel and carrots and cook until softening.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Deglaze and simmer", "instruction": "Pour in the wine and brandy, bubble hard to drive off the alcohol, then add the tomatoes, stock and paprika. Cover and simmer.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Blend and sieve", "instruction": "Blitz the soup finely, then press through a sieve into a bowl, working the mixture through for a velvety texture.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Add prawns and finish", "instruction": "Return to a clean pan, add the chopped prawns and cook, then blitz again until smooth.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Reheat and serve", "instruction": "Gently reheat with the cream. Cook the whole prawns in butter if garnishing, then spoon the soup into bowls, top with prawns and fennel fronds.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=4thpMbDakgM"}, {"id": "52923", "name": "Canadian Butter Tarts", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wpputp1511812960.jpg", "local_image": "52923.jpg", "ingredients": [{"ingredient": "Shortcrust Pastry", "measure": "375g"}, {"ingredient": "Eggs", "measure": "2 large"}, {"ingredient": "Muscovado Sugar", "measure": "175g"}, {"ingredient": "Raisins", "measure": "100g"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Single Cream", "measure": "4 tsp"}, {"ingredient": "Walnuts", "measure": "50g"}], "instructions": "Preheat the oven to fan 170C/ conventional 190C/gas 5. Roll out the pastry on a lightly floured surface so it’s slightly thinner than straight from the pack. Then cut out 18-20 rounds with a 7.5cm fluted cutter, re-rolling the trimmings. Use the rounds to line two deep 12-hole tart tins (not muffin tins). If you only have a regular-sized, 12-hole tart tin you will be able to make a few more slightly shallower tarts.\r\nBeat the eggs in a large bowl and combine with the rest of the ingredients except the walnuts. Tip this mixture into a pan and stir continuously for 3-4 minutes until the butter melts, and the mixture bubbles and starts to thicken. It should be thick enough to coat the back of a wooden spoon. Don’t overcook, and be sure to stir all the time as the mixture can easily burn. Remove from the heat and stir in the nuts.\r\nSpoon the filling into the unbaked tart shells so it’s level with the pastry. Bake for 15-18 minutes until set and pale golden. Leave in the tin to cool for a few minutes before lifting out on to a wire rack. Serve warm or cold.", "equipment_tags": [], "portions": 6, "prep_minutes": 22, "prep_minutes_source": "explicit", "kcal": 589, "protein_g": 7.8, "carbs_g": 71.5, "fat_g": 32.1, "total_kcal": 3533, "total_protein_g": 47.1, "total_carbs_g": 428.9, "total_fat_g": 192.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Line the tart tins", "instruction": "Preheat the oven to fan 170°C/190°C/gas 5. Roll out the pastry thinly, cut rounds with a fluted cutter, and line two deep 12-hole tart tins.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the filling", "instruction": "Beat the eggs and combine with the sugar, raisins, vanilla and butter, cream, then stir continuously in a pan until the butter melts and the mixture thickens enough to coat a spoon.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Finish the filling", "instruction": "Remove from the heat and stir in the walnuts.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fill and bake", "instruction": "Spoon the filling into the unbaked tart shells level with the pastry, and bake until set and pale golden.", "timer_seconds": 990, "background": true}, {"step": 5, "label": "Cool and serve", "instruction": "Cool in the tin briefly before lifting onto a rack. Serve warm or cold.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=WUpaOGghOdo"}, {"id": "52924", "name": "Nanaimo Bars", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vwuprt1511813703.jpg", "local_image": "52924.jpg", "ingredients": [{"ingredient": "Custard", "measure": "125g"}, {"ingredient": "Caster Sugar", "measure": "50g"}, {"ingredient": "Cocoa", "measure": "5 tbs"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Digestive Biscuits", "measure": "200g shredded"}, {"ingredient": "Desiccated Coconut", "measure": "100g"}, {"ingredient": "Almonds", "measure": "50g"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Double Cream", "measure": "4 tbs"}, {"ingredient": "Custard Powder", "measure": "3 tbs"}, {"ingredient": "Icing Sugar", "measure": "250g"}, {"ingredient": "Dark Chocolate", "measure": "150g"}, {"ingredient": "Butter", "measure": "50g"}], "instructions": "Start by making the biscuit base. In a bowl, over a pan of simmering water, melt the butter with the sugar and cocoa powder, stirring occasionally until smooth. Whisk in the egg for 2 to 3 mins until the mixture has thickened. Remove from heat and mix in the biscuit crumbs, coconut and almonds if using, then press into the base of a lined 20cm square tin. Chill for 10 mins.\r\nFor the middle layer, make the custard icing; whisk together the butter, cream and custard powder until light and fluffy, then gradually add the icing sugar until fully incorporated. Spread over the bottom layer and chill in the fridge for at least 10 mins until the custard is no longer soft.\r\nMelt the chocolate and butter together in the microwave, then spread over the chilled bars and put back in the fridge. Leave until the chocolate has fully set (about 2 hrs). Take the mixture out of the tin and slice into squares to serve.", "equipment_tags": [], "portions": 9, "prep_minutes": 143, "prep_minutes_source": "explicit", "kcal": 640, "protein_g": 7.9, "carbs_g": 74.4, "fat_g": 38.7, "total_kcal": 5759, "total_protein_g": 71.5, "total_carbs_g": 669.2, "total_fat_g": 348.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the biscuit base", "instruction": "Melt the butter, sugar and cocoa together over a pan of simmering water, whisk in the egg until thickened, then mix in the biscuit crumbs, coconut and almonds.", "timer_seconds": 180, "background": false}, {"step": 2, "label": "Press and chill the base", "instruction": "Press into a lined square tin and chill.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Make the custard layer", "instruction": "Whisk the butter, cream and custard powder until light and fluffy, then gradually add the icing sugar.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Spread and chill the custard layer", "instruction": "Spread over the base and chill until firm.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Top with chocolate", "instruction": "Melt the chocolate and butter together, spread over the chilled bars, and chill until fully set.", "timer_seconds": 7200, "background": true}, {"step": 6, "label": "Slice and serve", "instruction": "Take the mixture out of the tin and slice into squares.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=MMrE4I1ZtWo"}, {"id": "52925", "name": "Split Pea Soup", "category": "Side", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xxtsvx1511814083.jpg", "local_image": "52925.jpg", "ingredients": [{"ingredient": "Ham", "measure": "1kg"}, {"ingredient": "Peas", "measure": "200g (soaked overnight)"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Carrots", "measure": "2 chopped"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Celery", "measure": "1 chopped"}, {"ingredient": "Frozen Peas", "measure": "300g"}, {"ingredient": "Bread", "measure": "to serve"}], "instructions": "Put the gammon in a very large pan with 2 litres water and bring to the boil. Remove from the heat and drain off the water – this helps to get rid of some of the saltiness. Recover with 2 litres cold water and bring to the boil again. Put everything but the frozen peas into the pan and bring to the boil. Reduce to a simmer and cook for 1½-2½ hrs, topping up the water as and when you need to, to a similar level it started at. As the ham cooks and softens, you can halve it if you want, so it is all submerged under the liquid. When the ham is tender enough to pull into shreds, it is ready.\r\nLift out the ham, peel off and discard the skin. While it is still hot (wear a clean pair of rubber gloves), shred the meat. Remove bay from the soup and stir in the frozen peas. Simmer for 1 min, then blend until smooth. Add a splash of water if too thick, and return to the pan to heat through if it has cooled, or if you are making ahead.\r\nWhen you are ready to serve, mix the hot soup with most of the ham – gently reheat if made ahead. Serve in bowls with the remaining ham scattered on top, and eat with crusty bread and butter.", "equipment_tags": ["Blender"], "portions": 11, "prep_minutes": 1, "prep_minutes_source": "explicit", "kcal": 189, "protein_g": 22.1, "carbs_g": 12.2, "fat_g": 5.8, "total_kcal": 2082, "total_protein_g": 243.6, "total_carbs_g": 134.1, "total_fat_g": 63.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Blanch the ham", "instruction": "Put the ham in a large pan with water, bring to the boil, then drain to remove some saltiness. Cover with fresh cold water and bring to the boil again.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Simmer the soup base", "instruction": "Add everything except the frozen peas, bring to the boil, then reduce to a simmer and cook, topping up water as needed, until the ham is tender enough to shred.", "timer_seconds": 7200, "background": true}, {"step": 3, "label": "Shred the ham", "instruction": "Lift out the ham, discard the skin, and shred the meat while hot.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Blend the soup", "instruction": "Remove the bay leaves, stir in the frozen peas, simmer briefly, then blend until smooth, thinning with water if too thick.", "timer_seconds": 60, "background": false}, {"step": 5, "label": "Combine and serve", "instruction": "Mix most of the shredded ham into the hot soup, reheating if needed. Serve in bowls topped with the remaining ham, with crusty bread and butter.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=qdhWz7qAaCU"}, {"id": "52926", "name": "Tourtiere", "category": "Pork", "area": "Canadian", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/ytpstt1511814614.jpg", "local_image": "52926.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1 medium"}, {"ingredient": "Sunflower Oil", "measure": "1 tsp"}, {"ingredient": "Minced Pork", "measure": "500g"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Garlic Clove", "measure": "1 finely chopped"}, {"ingredient": "Cinnamon", "measure": "¼ tsp"}, {"ingredient": "Allspice", "measure": "¼ tsp"}, {"ingredient": "Nutmeg", "measure": "¼ tsp"}, {"ingredient": "Vegetable Stock", "measure": "100ml"}, {"ingredient": "Shortcrust Pastry", "measure": "400g"}, {"ingredient": "Egg", "measure": "To Glaze"}], "instructions": "Heat oven to 200C/180C fan/gas 6. Boil the potato until tender, drain and mash, then leave to cool. Heat the oil in a non-stick pan, add the mince and onion and quickly fry until browned. Add the garlic, spices, stock, plenty of pepper and a little salt and mix well. Remove from the heat, stir into the potato and leave to cool.\r\nRoll out half the pastry and line the base of a 20-23cm pie plate or flan tin. Fill with the pork mixture and brush the edges of the pastry with water. Roll out the remaining dough and cover the pie. Press the edges of the pastry to seal, trimming off the excess. Prick the top of the pastry case to allow steam to escape and glaze the top with the beaten egg.\r\nBake for 30 mins until the pastry is crisp and golden. Serve cut into wedges with a crisp green salad. Leftovers are good cold for lunch the next day, served with a selection of pickles.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 960, "protein_g": 44.5, "carbs_g": 74.6, "fat_g": 53.5, "total_kcal": 2881, "total_protein_g": 133.4, "total_carbs_g": 223.7, "total_fat_g": 160.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and cook the potato", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Boil the potato until tender, drain, mash, and leave to cool.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Cook the pork filling", "instruction": "Heat the oil in a pan, add the mince and onion, and fry quickly until browned. Add the garlic, spices, stock and seasoning and mix well.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Combine and cool", "instruction": "Remove from the heat, stir into the mashed potato, and leave to cool.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Assemble the pie", "instruction": "Line a pie plate with half the pastry, fill with the pork mixture, brush the edges with water, and cover with the remaining pastry, sealing and trimming the edges. Prick the top and glaze with egg.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake and serve", "instruction": "Bake until crisp and golden, then serve cut into wedges with a crisp green salad.", "timer_seconds": 1800, "background": true}], "video": "https://www.youtube.com/watch?v=A96hbwobKKs"}, {"id": "52927", "name": "Montreal Smoked Meat", "category": "Beef", "area": "Canadian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/uttupv1511815050.jpg", "local_image": "52927.jpg", "ingredients": [{"ingredient": "Beef Brisket", "measure": "1"}, {"ingredient": "Salt", "measure": "3 tbs"}, {"ingredient": "Black Pepper", "measure": "3 tbs"}, {"ingredient": "Coriander", "measure": "1 tbs"}, {"ingredient": "Sugar", "measure": "1 tbs"}, {"ingredient": "Bay Leaf", "measure": "1 tsp"}, {"ingredient": "Cloves", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "3 tbs"}, {"ingredient": "Coriander", "measure": "1 tbs"}, {"ingredient": "Paprika", "measure": "1 tbs"}, {"ingredient": "Garlic", "measure": "1 tbs"}, {"ingredient": "Onion", "measure": "1 tbs"}, {"ingredient": "Dill", "measure": "1 tbs"}, {"ingredient": "English Mustard", "measure": "1 tsp"}, {"ingredient": "Celery Salt", "measure": "1 tbs"}, {"ingredient": "Red Pepper Flakes", "measure": "1 tsp"}], "instructions": "To make the cure, in a small bowl mix together salt, pink salt, black pepper, coriander, sugar, bay leaf, and cloves. Coat entire brisket with the cure and place in an extra-large resealable plastic bag. Place in the coldest part of the refrigerator and cure for 4 days, flipping brisket twice a day.\r\nRemove brisket from bag and wash as much cure off as possible under cold running water. Place brisket in a large container and fill with water and let soak for 2 hours, replacing water every 30 minutes. Remove from water and pat dry with paper towels.\r\nTo make the rub, mix together black pepper, coriander, paprika, garlic powder, onion powder, dill weed, mustard, celery seed, and crushed red papper in a small bowl. Coat entire brisket with the rub.\r\nFire up smoker or grill to 225 degrees, adding chunks of smoking wood chunks when at temperature. When wood is ignited and producing smoke, place brisket in, fat side up, and smoke until an instant read thermometer registers 165 degrees when inserted into thickest part of the brisket, about 6 hours.\r\nTransfer brisket to large roasting pan with V-rack. Place roasting pan over two burners on stovetop and fill with 1-inch of water. Bring water to a boil over high heat, reduce heat to medium, cover roasting pan with aluminum foil, and steam brisket until an instant read thermometer registers 180 degrees when inserted into thickest part of the meat, 1 to 2 hours, adding more hot water as needed.\r\nTransfer brisket to cutting board and let cool slightly. Slice and serve, preferably on rye with mustard.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 486, "protein_g": 24.4, "carbs_g": 95.0, "fat_g": 12.1, "total_kcal": 486, "total_protein_g": 24.4, "total_carbs_g": 95.0, "total_fat_g": 12.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cure the brisket", "instruction": "Mix the salt, pink salt, black pepper, coriander, sugar, bay leaf and cloves, coat the brisket, seal in a bag, and refrigerate, flipping twice a day.", "timer_seconds": 345600, "background": true}, {"step": 2, "label": "Soak out the cure", "instruction": "Wash off the cure, then soak the brisket in a container of water, changing the water every 30 minutes, then pat dry.", "timer_seconds": 7200, "background": true}, {"step": 3, "label": "Coat with the rub", "instruction": "Mix the rub ingredients together and coat the entire brisket.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Smoke the brisket", "instruction": "Fire up the smoker to 225°F and smoke the brisket, fat side up, until it reaches an internal temperature of 165°F.", "timer_seconds": 21600, "background": true}, {"step": 5, "label": "Steam the brisket", "instruction": "Transfer to a roasting pan with a V-rack over boiling water, cover with foil, and steam until it reaches an internal temperature of 180°F, adding more hot water as needed.", "timer_seconds": 5400, "background": true}, {"step": 6, "label": "Rest, slice and serve", "instruction": "Let cool slightly on a board, then slice and serve, preferably on rye with mustard.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=g5oCDoyxbBk"}, {"id": "52928", "name": "BeaverTails", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ryppsv1511815505.jpg", "local_image": "52928.jpg", "ingredients": [{"ingredient": "Water", "measure": "1/2 cup"}, {"ingredient": "Yeast", "measure": "2 parts"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Milk", "measure": "1/2 cup"}, {"ingredient": "Butter", "measure": "6 tblsp"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Salt", "measure": "1 ½ tsp"}, {"ingredient": "Flour", "measure": "2-1/2 cups"}, {"ingredient": "Oil", "measure": "for frying"}, {"ingredient": "Lemon", "measure": "garnish"}, {"ingredient": "Sugar", "measure": "garnish"}, {"ingredient": "Cinnamon", "measure": "garnish"}], "instructions": "In the bowl of a stand mixer, add warm water, a big pinch of sugar and yeast. Allow to sit until frothy.\r\nInto the same bowl, add 1/2 cup sugar, warm milk, melted butter, eggs and salt, and whisk until combined.\r\nPlace a dough hook on the mixer, add the flour with the machine on, until a smooth but slightly sticky dough forms.\r\nPlace dough in a bowl, cover with plastic wrap, and allow to proof for 1 1/2 hours.\r\nCut dough into 12 pieces, and roll out into long oval-like shapes about 1/4 inch thick that resemble a beaver’s tail.\r\nIn a large, deep pot, heat oil to 350 degrees. Gently place beavertail dough into hot oil and cook for 30 to 45 seconds on each side until golden brown.\r\nDrain on paper towels, and garnish as desired. Toss in cinnamon sugar, in white sugar with a squeeze of lemon, or with a generous slathering of Nutella and a handful of toasted almonds. Enjoy!", "equipment_tags": [], "portions": 6, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 385, "protein_g": 11.3, "carbs_g": 43.3, "fat_g": 20.4, "total_kcal": 2312, "total_protein_g": 68.0, "total_carbs_g": 259.5, "total_fat_g": 122.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Activate the yeast", "instruction": "In a stand mixer bowl, combine warm water, a pinch of sugar and the yeast, and let sit until frothy.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Mix the dough", "instruction": "Add the remaining sugar, warm milk, melted butter, eggs and salt, and whisk until combined, then add the flour with a dough hook until a smooth, slightly sticky dough forms.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Proof the dough", "instruction": "Cover and let proof.", "timer_seconds": 5400, "background": true}, {"step": 4, "label": "Shape the beavertails", "instruction": "Cut into 12 pieces and roll each into a long oval shape about 1/4 inch thick.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fry", "instruction": "Heat oil to 350°F and fry the dough pieces until golden brown on each side.", "timer_seconds": 60, "background": false}, {"step": 6, "label": "Garnish and serve", "instruction": "Drain on paper towels and toss in cinnamon sugar, lemon sugar, or Nutella and toasted almonds.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=2G07UOqU2e8"}, {"id": "52929", "name": "Timbits", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/txsupu1511815755.jpg", "local_image": "52929.jpg", "ingredients": [{"ingredient": "Flour", "measure": "2 cups"}, {"ingredient": "Sugar", "measure": "1/3 cup"}, {"ingredient": "Baking Powder", "measure": "3 tsp"}, {"ingredient": "Salt", "measure": "½ tsp"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Milk", "measure": "¾ cup"}, {"ingredient": "Oil", "measure": "3 tbs"}, {"ingredient": "Oil", "measure": "for frying"}, {"ingredient": "Icing Sugar", "measure": "garnish"}], "instructions": "Sift together dry ingredients.\r\nMix together wet ingredients and incorporate into dry. Stir until smooth.\r\nDrop by teaspoonfuls(no bigger) into hot oil (365 degrees, no hotter), turning after a few moments until golden brown on all sides.\r\nRemove and drain.\r\nRoll in cinnamon sugar while still warm and serve.", "equipment_tags": [], "portions": 4, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 532, "protein_g": 9.4, "carbs_g": 76.2, "fat_g": 21.2, "total_kcal": 2126, "total_protein_g": 37.7, "total_carbs_g": 304.7, "total_fat_g": 84.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix the batter", "instruction": "Sift the dry ingredients together. Mix the wet ingredients separately, then incorporate into the dry ingredients and stir until smooth.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fry", "instruction": "Drop teaspoonfuls into hot oil at 365°F, turning until golden brown on all sides.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Drain and finish", "instruction": "Remove and drain, then roll in cinnamon sugar while still warm and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=fFLn1h80AGQ"}, {"id": "52930", "name": "Pate Chinois", "category": "Beef", "area": "Canadian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/yyrrxr1511816289.jpg", "local_image": "52930.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "4 cups"}, {"ingredient": "Butter", "measure": "60ml"}, {"ingredient": "Milk", "measure": "½ cup"}, {"ingredient": "Minced Beef", "measure": "450g"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Creamed Corn", "measure": "500ml"}, {"ingredient": "Paprika", "measure": "to taste"}, {"ingredient": "Parsley", "measure": "to taste"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Pepper", "measure": "Dash"}], "instructions": "In a large pot of salted water, cook the potatoes until they are very tender. Drain.\r\nWith a masher, coarsely crush the potatoes with at least 30 ml (2 tablespoons) of butter. With an electric mixer, purée with the milk. Season with salt and pepper. Set aside.\r\nWith the rack in the middle position, preheat the oven to 190 °C (375 °F).\r\nIn a large skillet, brown the onion in the remaining butter. Add the meat and cook until golden brown. Season with salt and pepper. Remove from the heat.\r\nLightly press the meat at the bottom of a 20-cm (8-inch) square baking dish. Cover with the corn and the mashed potatoes. Sprinkle with paprika and parsley.\r\nBake for about 30 minutes. Finish cooking under the broiler. Let cool for 10 minutes.", "equipment_tags": [], "portions": 12, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 234, "protein_g": 9.4, "carbs_g": 22.5, "fat_g": 12.0, "total_kcal": 2803, "total_protein_g": 112.5, "total_carbs_g": 270.5, "total_fat_g": 144.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook and mash the potatoes", "instruction": "Cook the potatoes in a large pot of salted water until very tender, then drain and coarsely mash with some of the butter. Purée with the milk using an electric mixer and season.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Preheat the oven", "instruction": "Preheat the oven to 190°C/375°F.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Brown the beef", "instruction": "Brown the onion in the remaining butter in a skillet, add the meat and cook until golden brown, then season and remove from heat.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Layer and bake", "instruction": "Press the meat into a square baking dish, cover with the corn, then the mashed potatoes, and sprinkle with paprika and parsley. Bake, then finish under the broiler.", "timer_seconds": 1800, "background": true}, {"step": 5, "label": "Rest and serve", "instruction": "Let cool briefly before serving.", "timer_seconds": 600, "background": false}], "video": "https://www.youtube.com/watch?v=QRFqnLkEv3I"}, {"id": "52931", "name": "Sugar Pie", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yrstur1511816601.jpg", "local_image": "52931.jpg", "ingredients": [{"ingredient": "Brown Sugar", "measure": "2 cups"}, {"ingredient": "Butter", "measure": "¼ cup"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Plain Flour", "measure": "½ cup"}, {"ingredient": "Milk", "measure": "1 1/2 cups"}], "instructions": "Preheat oven to 350 degrees F (175 degrees C). Grease a 9-inch pie dish.\r\nPlace the brown sugar and butter in a mixing bowl, and beat them together with an electric mixer until creamy and very well combined, without lumps. Beat in eggs, one at a time, incorporating the first egg before adding the next one. Add the vanilla extract and salt; beat the flour in, a little at a time, and then the milk, making a creamy batter. Pour the batter into the prepared pie dish.\r\nBake in the preheated oven for 35 minutes; remove pie, and cover the rim with aluminum foil to prevent burning. Return to oven, and bake until the middle sets and the top forms a crusty layer, about 15 more minutes. Let the pie cool to room temperature, then refrigerate for at least 1 hour before serving.", "equipment_tags": [], "portions": 7, "prep_minutes": 95, "prep_minutes_source": "explicit", "kcal": 367, "protein_g": 4.5, "carbs_g": 66.7, "fat_g": 9.9, "total_kcal": 2572, "total_protein_g": 31.4, "total_carbs_g": 467.2, "total_fat_g": 69.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Preheat the oven to 175°C/350°F and grease a pie dish.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the batter", "instruction": "Beat the brown sugar and butter together until creamy, then beat in the eggs one at a time. Add the vanilla and salt, then beat in the flour and milk to make a creamy batter.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Pour into the dish and bake, then cover the rim with foil and continue baking until the middle sets and a crusty layer forms on top.", "timer_seconds": 3000, "background": true}, {"step": 4, "label": "Cool and chill", "instruction": "Cool to room temperature, then refrigerate before serving.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=uVQ66jiL-Dc"}, {"id": "52932", "name": "Pouding chomeur", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yqqqwu1511816912.jpg", "local_image": "52932.jpg", "ingredients": [{"ingredient": "Butter", "measure": "½ cup"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Flour", "measure": "2 cups"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Milk", "measure": "1 1/4 cup"}, {"ingredient": "Maple Syrup", "measure": "1 1/2 cup"}, {"ingredient": "Brown Sugar", "measure": "1 1/2 cup"}, {"ingredient": "Single Cream", "measure": "1 1/2 cup"}, {"ingredient": "Butter", "measure": "1/3 cup"}], "instructions": "In a large bowl, with an electric mixer, mix the butter and sugar till the mix is light.\r\nAdd eggs and vanilla and mix.\r\nIn another bowl, mix flour and baking powder.\r\nAlternate flour mix and milk to the butter mix.\r\nPour into a 13 inch by 9 inch greased pan.\r\nMAPLE SAUCE.\r\nIn a large casserole, bring to boil the syrup, brown sugar, cream and butter and constantly stir.\r\nReduce heat and and gently cook 2 minutes or till sauce has reduced a little bit.\r\nPour sauce gently over cake.\r\nBake at 325°f (160°c) about 35 minutes or till cake is light brown and when toothpick inserted comes out clean.", "equipment_tags": [], "portions": 12, "prep_minutes": 37, "prep_minutes_source": "explicit", "kcal": 551, "protein_g": 5.0, "carbs_g": 89.0, "fat_g": 20.5, "total_kcal": 6610, "total_protein_g": 59.5, "total_carbs_g": 1068.1, "total_fat_g": 246.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and cream the butter", "instruction": "Preheat the oven and grease a 13x9 pan. Cream the butter and sugar until light, then add the eggs and vanilla and mix.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Combine and pour", "instruction": "Mix the flour and baking powder in a separate bowl, then alternate adding the flour mix and milk to the butter mixture. Pour into the prepared pan.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the maple sauce", "instruction": "In a large casserole, bring the maple syrup, brown sugar, cream and butter to the boil, stirring constantly, then reduce heat and cook gently until slightly reduced.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Pour and bake", "instruction": "Pour the sauce gently over the cake batter and bake at 160°C/325°F until light brown and a toothpick comes out clean.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=WFvj71RZYPc"}, {"id": "52933", "name": "Rappie Pie", "category": "Chicken", "area": "Canadian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/ruwpww1511817242.jpg", "local_image": "52933.jpg", "ingredients": [{"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Chicken Stock", "measure": "4 qt"}, {"ingredient": "Chicken Breast", "measure": "1.5kg"}, {"ingredient": "Potatoes", "measure": "4kg"}, {"ingredient": "Salt", "measure": "2 tbs"}, {"ingredient": "Black Pepper", "measure": "1tbsp"}], "instructions": "Preheat oven to 400 degrees F (200 degrees C). Grease a 10x14x2-inch baking pan.\r\nHeat margarine in a skillet over medium heat; stir in onion. Cook and stir until onion has softened and turned translucent, about 5 minutes. Reduce heat to low and continue to cook and stir until onion is very tender and dark brown, about 40 minutes more.\r\nBring chicken broth to a boil in a large pot; stir in chicken breasts, reduce heat, and simmer until chicken is no longer pink at the center, about 20 minutes. Remove from heat. Remove chicken breasts to a plate using a slotted spoon; reserve broth.\r\nJuice potatoes with an electric juicer; place dry potato flesh into a bowl and discard juice. Stir salt and pepper into potatoes; stir in enough reserved broth to make the mixture the consistency of oatmeal. Set remaining broth aside.\r\nSpread half of potato mixture evenly into the prepared pan. Lay cooked chicken breast evenly over potatoes; scatter caramelized onion evenly over chicken. Spread remaining potato mixture over onions and chicken to cover.\r\nBake in the preheated oven until golden brown, about 1 hour. Reheat chicken broth; pour over individual servings as desired.", "equipment_tags": [], "portions": 12, "prep_minutes": 125, "prep_minutes_source": "explicit", "kcal": 435, "protein_g": 35.2, "carbs_g": 59.3, "fat_g": 5.6, "total_kcal": 5222, "total_protein_g": 422.7, "total_carbs_g": 711.5, "total_fat_g": 67.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and caramelise the onions", "instruction": "Preheat the oven to 200°C/400°F and grease a baking pan. Heat margarine in a skillet, add onion, and cook until translucent, then reduce heat and continue cooking until very tender and dark brown.", "timer_seconds": 2700, "background": false}, {"step": 2, "label": "Poach the chicken", "instruction": "Bring the chicken broth to the boil, add the chicken breasts, reduce heat, and simmer until cooked through. Remove the chicken, reserving the broth.", "timer_seconds": 1200, "background": false}, {"step": 3, "label": "Prep the potatoes", "instruction": "Juice the potatoes, discard the liquid, and season the potato flesh with salt and pepper, stirring in enough reserved broth to reach an oatmeal-like consistency.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Layer and bake", "instruction": "Spread half the potato mixture in the pan, layer the chicken and caramelised onion on top, then cover with the remaining potato mixture. Bake until golden brown.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Serve", "instruction": "Reheat the reserved chicken broth and pour over individual servings.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Ys2kZnTVXAM"}, {"id": "52934", "name": "Chicken Basquaise", "category": "Chicken", "area": "France", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/wruvqv1511880994.jpg", "local_image": "52934.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1.5kg"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Olive Oil", "measure": "6 tblsp"}, {"ingredient": "Red Onions", "measure": "2 sliced"}, {"ingredient": "Red Pepper", "measure": "3 Large"}, {"ingredient": "Chorizo", "measure": "130g"}, {"ingredient": "Sun-Dried Tomatoes", "measure": "8"}, {"ingredient": "Garlic", "measure": "6 cloves sliced"}, {"ingredient": "Basmati Rice", "measure": "300g"}, {"ingredient": "Tomato Puree", "measure": "drizzle"}, {"ingredient": "Paprika", "measure": "½ tsp"}, {"ingredient": "Bay Leaves", "measure": "4"}, {"ingredient": "Thyme", "measure": "Handful"}, {"ingredient": "Chicken Stock", "measure": "350ml"}, {"ingredient": "Dry White Wine", "measure": "180g"}, {"ingredient": "Lemons", "measure": "2"}, {"ingredient": "Black Olives", "measure": "100g"}, {"ingredient": "Salt", "measure": "to serve"}, {"ingredient": "Pepper", "measure": "to serve"}], "instructions": "Preheat the oven to 180°C/Gas mark 4. Have the chicken joints ready to cook. Heat the butter and 3 tbsp olive oil in a flameproof casserole or large frying pan. Brown the chicken pieces in batches on both sides, seasoning them with salt and pepper as you go. Don't crowd the pan - fry the chicken in small batches, removing the pieces to kitchen paper as they are done.\r\n\r\nAdd a little more olive oil to the casserole and fry the onions over a medium heat for 10 minutes, stirring frequently, until softened but not browned. Add the rest of the oil, then the peppers and cook for another 5 minutes.\r\n\r\nAdd the chorizo, sun-dried tomatoes and garlic and cook for 2-3 minutes. Add the rice, stirring to ensure it is well coated in the oil. Stir in the tomato paste, paprika, bay leaves and chopped thyme. Pour in the stock and wine. When the liquid starts to bubble, turn the heat down to a gentle simmer. Press the rice down into the liquid if it isn't already submerged and place the chicken on top. Add the lemon wedges and olives around the chicken.\r\n\r\nCover and cook in the oven for 50 minutes. The rice should be cooked but still have some bite, and the chicken should have juices that run clear when pierced in the thickest part with a knife. If not, cook for another 5 minutes and check again.", "equipment_tags": [], "portions": 8, "prep_minutes": 73, "prep_minutes_source": "explicit", "kcal": 923, "protein_g": 61.8, "carbs_g": 93.7, "fat_g": 36.1, "total_kcal": 7383, "total_protein_g": 494.4, "total_carbs_g": 749.4, "total_fat_g": 288.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the chicken", "instruction": "Preheat the oven to 180°C/gas 4. Heat the butter and some olive oil in a flameproof casserole and brown the chicken pieces in batches, seasoning as you go.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Soften the onions and peppers", "instruction": "Add more oil and fry the onions until softened, then add the peppers and cook further.", "timer_seconds": 900, "background": false}, {"step": 3, "label": "Build the rice base", "instruction": "Add the chorizo, sun-dried tomatoes and garlic and cook briefly, then stir in the rice to coat, followed by the tomato paste, paprika, bay leaves and thyme.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Add liquid and chicken", "instruction": "Pour in the stock and wine, bring to a bubble, then reduce to a simmer. Press the rice into the liquid, top with the chicken, and add lemon wedges and olives.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Cover and cook in the oven until the rice is cooked with some bite and the chicken juices run clear.", "timer_seconds": 3000, "background": true}], "video": "https://www.youtube.com/watch?v=emfm6TwsVhg"}, {"id": "52935", "name": "Steak Diane", "category": "Beef", "area": "France", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/vussxq1511882648.jpg", "local_image": "52935.jpg", "ingredients": [{"ingredient": "Canola Oil", "measure": "2 tbs"}, {"ingredient": "Beef Fillet", "measure": "4"}, {"ingredient": "Beef Stock", "measure": "1 1/2 cup"}, {"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Challots", "measure": "1 medium finely diced"}, {"ingredient": "Mushrooms", "measure": "4 oz"}, {"ingredient": "Brandy", "measure": "¼ cup"}, {"ingredient": "Heavy Cream", "measure": "¼ cup"}, {"ingredient": "Dijon Mustard", "measure": "1 tbs"}, {"ingredient": "Worcestershire Sauce", "measure": "1 tbs"}, {"ingredient": "Tabasco Sauce", "measure": "Dash"}, {"ingredient": "Parsley", "measure": "1 tbs minced"}, {"ingredient": "Chives", "measure": "1 tbs minced"}, {"ingredient": "Salt", "measure": "to taste"}, {"ingredient": "Pepper", "measure": "to taste"}], "instructions": "Heat oil in a 12\" skillet over medium-high heat. Season steaks with salt and pepper, and add to skillet; cook, turning once, until browned on both sides and cooked to desired doneness, about 4 to 5 minutes for medium-rare. Transfer steaks to a plate, and set aside.\r\nReturn skillet to high heat, and add stock; cook until reduced until to 1⁄2 cup, about 10 minutes. Pour into a bowl, and set aside. Return skillet to heat, and add butter; add garlic and shallots, and cook, stirring, until soft, about 2 minutes. Add mushrooms, and cook, stirring, until they release any liquid and it evaporates and mushrooms begin to brown, about 2 minutes. Add cognac, and light with a match to flambée; cook until flame dies down. Stir in reserved stock, cream, Dijon, Worcestershire, and hot sauce, and then return steaks to skillet; cook, turning in sauce, until warmed through and sauce is thickened, about 4 minutes. Transfer steak to serving plates and stir parsley and chives into sauce; pour sauce over steaks to serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 687, "protein_g": 43.5, "carbs_g": 8.1, "fat_g": 49.1, "total_kcal": 2060, "total_protein_g": 130.6, "total_carbs_g": 24.3, "total_fat_g": 147.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sear the steaks", "instruction": "Heat oil in a large skillet over medium-high heat, season the steaks, and cook, turning once, until browned and to desired doneness. Set aside.", "timer_seconds": 270, "background": false}, {"step": 2, "label": "Reduce the stock", "instruction": "Return the skillet to high heat, add the stock, and cook until reduced by about two thirds.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Cook the aromatics", "instruction": "Add butter to the skillet, then the garlic and shallots, and cook until soft. Add the mushrooms and cook until browned.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Flambé and build the sauce", "instruction": "Add the brandy and flambé, then cook until the flame dies down. Stir in the reserved stock, cream, mustard, Worcestershire sauce and hot sauce.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Finish and serve", "instruction": "Return the steaks to the skillet, turning in the sauce, until warmed through and the sauce has thickened. Transfer to plates, stir the herbs into the sauce, and pour over the steaks.", "timer_seconds": 240, "background": false}], "video": "https://www.youtube.com/watch?v=9rWZNHkrsNg"}, {"id": "52936", "name": "Saltfish and Ackee", "category": "Seafood", "area": "Jamaican", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/vytypy1511883765.jpg", "local_image": "52936.jpg", "ingredients": [{"ingredient": "Salt Cod", "measure": "450g"}, {"ingredient": "Ackee", "measure": "400g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Curry Powder", "measure": "2 tsp"}, {"ingredient": "Jerusalem Artichokes", "measure": "2 tsp"}, {"ingredient": "Hotsauce", "measure": "1 tsp"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Yellow Pepper", "measure": "1 sliced"}, {"ingredient": "Tomatoes", "measure": "200g"}, {"ingredient": "Salt", "measure": "to taste"}, {"ingredient": "Pepper", "measure": "to taste"}, {"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Suet", "measure": "30g"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Olive Oil", "measure": "for frying"}], "instructions": "For the saltfish, soak the salt cod overnight, changing the water a couple of times.\r\nDrain, then put the cod in a large pan of fresh water and bring to the boil. Drain again, add fresh water and bring to the boil again.\r\nSimmer for about five minutes, or until cooked through, then drain and flake the fish into large pieces. Discard any skin or bones.\r\nFor the dumplings, mix the flour and suet with a pinch of salt and 250ml/9fl oz water to make a dough.\r\nWrap the mixture in clingfilm and leave in the fridge to rest.\r\nOpen the can of ackee, drain and rinse, then set aside.\r\nHeat a tablespoon of olive oil in a pan and fry the onion until softened but not brown.\r\nAdd the spices, seasoning, pepper sauce and sliced peppers and continue to fry until the peppers are tender.\r\nAdd the chopped tomatoes, then the salt cod and mix together. Lastly stir in the ackee very gently and leave to simmer until ready to serve.\r\nWhen you’re almost ready to eat, heat about 1cm/½in vegetable oil in a frying pan and heat until just smoking.\r\nShape the dumpling mix into plum-size balls and shallow-fry until golden-brown. (CAUTION: hot oil can be dangerous. Do not leave the pan unattended.)\r\nDrain the dumplings on kitchen paper and serve with the saltfish and ackee.", "equipment_tags": [], "portions": 3, "prep_minutes": 64, "prep_minutes_source": "estimated", "kcal": 696, "protein_g": 13.9, "carbs_g": 84.5, "fat_g": 41.4, "total_kcal": 2088, "total_protein_g": 41.6, "total_carbs_g": 253.6, "total_fat_g": 124.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the salt cod", "instruction": "Soak the salt cod overnight, changing the water a couple of times.", "timer_seconds": 43200, "background": true}, {"step": 2, "label": "Cook the cod", "instruction": "Drain and boil the cod in fresh water, drain, then boil again in fresh water and simmer until cooked through. Drain and flake, discarding skin and bones.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Make the dumpling dough", "instruction": "Mix the flour and suet with a pinch of salt and water to make a dough. Wrap and rest in the fridge.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Build the ackee sauce", "instruction": "Drain and rinse the ackee. Fry the onion in oil until softened, add the spices, seasoning, pepper sauce and peppers, and fry until the peppers are tender.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Combine and simmer", "instruction": "Add the tomatoes, then the salt cod, and mix together. Gently stir in the ackee and leave to simmer until ready to serve.", "timer_seconds": 600, "background": true}, {"step": 6, "label": "Fry the dumplings", "instruction": "Heat oil in a frying pan until just smoking. Shape the dumpling mix into balls and shallow-fry until golden-brown.", "timer_seconds": 420, "background": false}, {"step": 7, "label": "Serve", "instruction": "Drain the dumplings and serve with the saltfish and ackee.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=nbfNyZbdn2I"}, {"id": "52937", "name": "Jerk chicken with rice & peas", "category": "Chicken", "area": "Jamaican", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/tytyxu1515363282.jpg", "local_image": "52937.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "12"}, {"ingredient": "Lime", "measure": "1/2"}, {"ingredient": "Spring Onions", "measure": "1  bunch"}, {"ingredient": "Ginger", "measure": "1 tbs chopped"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Onion", "measure": "1/2"}, {"ingredient": "Red Chilli", "measure": "3 chopped"}, {"ingredient": "Thyme", "measure": "1/2 teaspoon"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Brown Sugar", "measure": "3 tbs"}, {"ingredient": "Allspice", "measure": "1 tbs"}, {"ingredient": "Basmati Rice", "measure": "200g"}, {"ingredient": "Coconut Milk", "measure": "400g"}, {"ingredient": "Spring Onions", "measure": "1  bunch"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Allspice", "measure": "1 tbs"}, {"ingredient": "Kidney Beans", "measure": "800g"}], "instructions": "To make the jerk marinade, combine all the ingredients in a food processor along with 1 tsp salt, and blend to a purée. If you’re having trouble getting it to blend, just keep turning off the blender, stirring the mixture, and trying again. Eventually it will start to blend up – don’t be tempted to add water, as you want a thick paste.\r\n\r\nTaste the jerk mixture for seasoning – it should taste pretty salty, but not unpleasantly, puckering salty. You can now throw in more chillies if it’s not spicy enough for you. If it tastes too salty and sour, try adding in a bit more brown sugar until the mixture tastes well balanced.\r\n\r\nMake a few slashes in the chicken thighs and pour the marinade over the meat, rubbing it into all the crevices. Cover and leave to marinate overnight in the fridge.\r\n\r\nIf you want to barbecue your chicken, get the coals burning 1 hr or so before you’re ready to cook. Authentic jerked meats are not exactly grilled as we think of grilling, but sort of smoke-grilled. To get a more authentic jerk experience, add some wood chips to your barbecue, and cook your chicken over slow, indirect heat for 30 mins. To cook in the oven, heat to 180C/160C fan/gas 4. Put the chicken pieces in a roasting tin with the lime halves and cook for 45 mins until tender and cooked through.\r\n\r\nWhile the chicken is cooking, prepare the rice & peas. Rinse the rice in plenty of cold water, then tip it into a large saucepan with all the remaining ingredients except the kidney beans. Season with salt, add 300ml cold water and set over a high heat. Once the rice begins to boil, turn it down to a medium heat, cover and cook for 10 mins.\r\n\r\nAdd the beans to the rice, then cover with a lid. Leave off the heat for 5 mins until all the liquid is absorbed. Squeeze the roasted lime over the chicken and serve with the rice & peas, and some hot sauce if you like it really spicy.", "equipment_tags": ["Blender", "FoodProcessor", "Grill"], "portions": 5, "prep_minutes": 150, "prep_minutes_source": "explicit", "kcal": 802, "protein_g": 45.1, "carbs_g": 92.1, "fat_g": 30.6, "total_kcal": 4008, "total_protein_g": 225.6, "total_carbs_g": 460.3, "total_fat_g": 153.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the jerk marinade", "instruction": "Combine the marinade ingredients with salt in a food processor and blend to a thick paste, stopping to stir as needed. Adjust seasoning to taste.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the chicken", "instruction": "Slash the chicken thighs, rub the marinade in well, cover and marinate in the fridge overnight.", "timer_seconds": 43200, "background": true}, {"step": 3, "label": "Cook the chicken", "instruction": "Heat the oven to 180°C/160°C fan/gas 4, put the chicken in a roasting tin with the lime halves, and cook until tender and cooked through.", "timer_seconds": 2700, "background": true}, {"step": 4, "label": "Cook the rice and peas", "instruction": "Rinse the rice and put in a saucepan with the remaining rice ingredients except the kidney beans. Season, add water, bring to the boil, then reduce heat, cover and cook.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Finish the rice", "instruction": "Add the beans, cover, and leave off the heat until the liquid is absorbed.", "timer_seconds": 300, "background": true}, {"step": 6, "label": "Serve", "instruction": "Squeeze the roasted lime over the chicken and serve with the rice and peas, and hot sauce if you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=qfchrS2D_v4"}, {"id": "52938", "name": "Jamaican Beef Patties", "category": "Beef", "area": "Jamaican", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/wsqqsw1515364068.jpg", "local_image": "52938.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "4 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Curry Powder", "measure": "1 tsp"}, {"ingredient": "Butter", "measure": "250g"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Minced Beef", "measure": "900g"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1/2 tsp"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Onions", "measure": "1 cup"}, {"ingredient": "Red Pepper", "measure": "Ground"}, {"ingredient": "Garlic", "measure": "2 tsp ground"}, {"ingredient": "Thyme", "measure": "1 tbs"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Tomato Ketchup", "measure": "2 tbs"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Onions", "measure": "1/2 cup"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Water", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "1/4 cup"}], "instructions": "Make the Pastry Dough\r\n\r\nTo a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly.\r\nRub shortening into flour until there are small pieces of shortening completely covered with flour.\r\nPour in 1/2 cup of the ice water and mix with your hands to bring the dough together. Keep adding ice water 2 to 3 tablespoons at a time until the mixture forms a dough.\r\nAt this stage, you can cut the dough into 2 large pieces, wrap in plastic and refrigerate for 30 minutes before using it.\r\nAlternatively, cut the dough into 10 to 12 equal pieces, place on a platter or baking sheet, cover securely with plastic wrap and let chill for 30 minutes while you make the filling.\r\nMake the Filling\r\n\r\nAdd ground beef to a large bowl. Sprinkle in allspice and black pepper. Mix together and set aside.\r\nHeat oil in a skillet until hot.\r\nAdd onions and sauté until translucent. Add hot pepper, garlic and thyme and continue to sauté for another minute. Add 1/4 teaspoon salt.\r\nAdd seasoned ground beef and toss to mix, breaking up any clumps, and let cook until the meat is no longer pink.\r\nAdd ketchup and more salt to taste.\r\nPour in 2 cups of water and stir. Bring the mixture to a boil then reduce heat and let simmer until most of the liquid has evaporated and whatever is remaining has reduced to a thick sauce.\r\nFold in green onions. Remove from heat and let cool completely.\r\nAssemble the Patties\r\n\r\nBeat the egg and water together to make an egg wash. Set aside.\r\nNow you can prepare the dough in two ways.\r\nFirst Method: Flour the work surface and rolling pin. If you had cut it into 2 large pieces, then take one of the large pieces and roll it out into a very large circle. Take a bowl with a wide rim (about 5 inches) and cut out three circles.\r\n\r\nPlace about 3 heaping tablespoons of the filling onto 1/2 of each circle. Dip a finger into the water and moisten the edges of the pastry. Fold over the other half and press to seal. \r\n\r\nTake a fork and crimp the edges. Cut off any extra to make it look neat and uniform. Place on a parchment-lined baking sheet and continue to work until you have rolled all the dough and filled the patties.\r\nSecond Method: If you had pre-cut the dough into individual pieces, work with one piece of dough at a time. Roll it out on a floured surface into a 5-inch circle or a little larger. Don’t worry if the edges are not perfect.\r\n\r\nPlace 3 heaping tablespoons of the filling on one side of the circle. Dip a finger into the water and moisten the edges of the pastry. Fold over the other half and press to seal.\r\n\r\nTake a fork and crimp the edges. Cut off any extra to make it look neat and uniform. Place on a parchment-lined baking sheet and continue work until you have rolled all the dough and filled the patties.\r\n\r\nFrying and Serving the Patties\r\n\r\nAfter forming the patties, place the pans in the refrigerator while you heat the oven to 350 F.\r\nJust before adding the pans with the patties to the oven, brush the patties with egg wash.\r\nBake patties for 30 minutes or until golden brown.\r\nCool on wire racks.\r\nServe warm.", "equipment_tags": [], "portions": 12, "prep_minutes": 90, "prep_minutes_source": "explicit", "kcal": 538, "protein_g": 18.3, "carbs_g": 36.4, "fat_g": 35.2, "total_kcal": 6461, "total_protein_g": 219.6, "total_carbs_g": 437.1, "total_fat_g": 422.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Mix the flour, salt and curry powder, rub in the butter until covered in small pieces, then mix in ice water until a dough forms.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Chill the dough", "instruction": "Divide, wrap in plastic, and chill.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Cook the filling", "instruction": "Mix the ground beef with allspice and pepper. Heat oil, sauté the onions, then add pepper, garlic and thyme and sauté further. Add the seasoned beef and cook until no longer pink.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Simmer the filling", "instruction": "Add ketchup and more salt to taste, pour in water, bring to a boil, then reduce heat and simmer until reduced to a thick sauce.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Finish and cool the filling", "instruction": "Fold in the green onions, remove from heat, and let cool completely.", "timer_seconds": null, "background": true}, {"step": 6, "label": "Assemble the patties", "instruction": "Roll out the dough and cut circles. Place filling on half of each circle, moisten the edges, fold over and seal, then crimp with a fork and trim.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Chill and bake", "instruction": "Chill the assembled patties while the oven heats to 350°F, brush with egg wash, and bake until golden brown.", "timer_seconds": 1800, "background": true}, {"step": 8, "label": "Cool and serve", "instruction": "Cool on wire racks and serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ypQjoiZiTac"}, {"id": "52939", "name": "Callaloo Jamaican Style", "category": "Miscellaneous", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ussyxw1515364536.jpg", "local_image": "52939.jpg", "ingredients": [{"ingredient": "Kale", "measure": "1  bunch"}, {"ingredient": "Bacon", "measure": "2 strips"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Onion", "measure": "1 medium"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}, {"ingredient": "Thyme", "measure": "1 Sprig"}, {"ingredient": "Tomato", "measure": "1"}, {"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Banana", "measure": "4"}, {"ingredient": "Vegetable Oil", "measure": "Splash"}], "instructions": "Cut leaves and soft stems from the kale branches, them soak in a bowl of cold water for about 5-10 minutes or until finish with prep.\r\nProceed to slicing the onions, mincing the garlic and dicing the tomatoes. Set aside\r\nRemove kale from water cut in chunks.\r\nPlace bacon on saucepan and cook until crispy. Then add onions, garlic, thyme, stir for about a minute or more\r\nAdd tomatoes; scotch bonnet pepper, smoked paprika. Sauté for about 2-3 more minutes.\r\nFinally add vegetable, salt, mix well, and steamed for about 6-8 minutes or until leaves are tender. Add a tiny bit of water as needed. Adjust seasonings and turn off the heat.\r\nUsing a sharp knife cut both ends off the plantain. This will make it easy to grab the skin of the plantains. Slit a shallow line down the long seam of the plantain; peel only as deep as the peel. Remove plantain peel by pulling it back.\r\nSlice the plantain into medium size lengthwise slices and set aside.\r\nCoat a large frying pan with cooking oil spray. Spray the tops of the plantains with a generous layer of oil spray and sprinkle with salt, freshly ground pepper.\r\nLet the plantains \"fry\" on medium heat, shaking the frying pan to redistribute them every few minutes.\r\nAs the plantains brown, continue to add more cooking oil spray, salt and pepper (if needed) until they have reached the desired color and texture.\r\nRemove and serve with kale", "equipment_tags": [], "portions": 12, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 79, "protein_g": 3.6, "carbs_g": 5.8, "fat_g": 4.9, "total_kcal": 951, "total_protein_g": 43.7, "total_carbs_g": 69.0, "total_fat_g": 58.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the kale", "instruction": "Cut leaves and soft stems from the kale, then soak in cold water while prepping the other ingredients.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Cook the bacon and aromatics", "instruction": "Slice the onions, mince the garlic, dice the tomatoes. Cook the bacon in a saucepan until crispy, then add the onions, garlic and thyme and stir.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Build the base", "instruction": "Drain the kale and chop. Add the tomatoes, scotch bonnet pepper and smoked paprika to the pan and sauté.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Steam the kale", "instruction": "Add the kale and salt, mix well, and steam until the leaves are tender, adding a little water if needed.", "timer_seconds": 480, "background": true}, {"step": 5, "label": "Fry the plantain", "instruction": "Peel and slice the plantain lengthwise, coat a frying pan with oil, and fry on medium heat, shaking to redistribute, until golden, seasoning with salt and pepper.", "timer_seconds": 600, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve the fried plantain alongside the kale.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=bCr3GasJWwE"}, {"id": "52940", "name": "Brown Stew Chicken", "category": "Chicken", "area": "Jamaican", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/sypxpx1515365095.jpg", "local_image": "52940.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1 whole"}, {"ingredient": "Tomato", "measure": "1 chopped"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Garlic Clove", "measure": "2 chopped"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "1 chopped"}, {"ingredient": "Lime", "measure": "1"}, {"ingredient": "Thyme", "measure": "2 tsp"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Cornstarch", "measure": "2 tsp"}, {"ingredient": "Coconut Milk", "measure": "2 cups"}, {"ingredient": "Vegetable Oil", "measure": "1 tbs"}], "instructions": "Squeeze lime over chicken and rub well. Drain off excess lime juice.\r\nCombine tomato, scallion, onion, garlic, pepper, thyme, pimento and soy sauce in a large bowl with the chicken pieces. Cover and marinate at least one hour.\r\nHeat oil in a dutch pot or large saucepan. Shake off the seasonings as you remove each piece of chicken from the marinade. Reserve the marinade for sauce.\r\nLightly brown the chicken a few pieces at a time in very hot oil. Place browned chicken pieces on a plate to rest while you brown the remaining pieces.\r\nDrain off excess oil and return the chicken to the pan. Pour the marinade over the chicken and add the carrots. Stir and cook over medium heat for 10 minutes.\r\nMix flour and coconut milk and add to stew, stirring constantly. Turn heat down to minimum and cook another 20 minutes or until tender.", "equipment_tags": [], "portions": 5, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 713, "protein_g": 62.6, "carbs_g": 16.6, "fat_g": 44.3, "total_kcal": 3564, "total_protein_g": 313.1, "total_carbs_g": 83.1, "total_fat_g": 221.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the chicken", "instruction": "Squeeze lime over the chicken and rub well, draining off excess juice. Combine with the tomato, scallion, onion, garlic, pepper, thyme, pimento and soy sauce, cover and marinate.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Brown the chicken", "instruction": "Heat oil in a large saucepan, shake off the marinade from each piece (reserving it), and lightly brown the chicken in batches.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Simmer", "instruction": "Drain excess oil, return the chicken to the pan, pour over the reserved marinade, add the carrots, and cook over medium heat.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Thicken and finish", "instruction": "Mix flour with coconut milk and stir into the stew. Turn heat down low and cook until tender.", "timer_seconds": 1200, "background": true}], "video": "https://www.youtube.com/watch?v=_gFB1fkNhXs"}, {"id": "52941", "name": "Red Peas Soup", "category": "Beef", "area": "Jamaican", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/sqpqtp1515365614.jpg", "local_image": "52941.jpg", "ingredients": [{"ingredient": "Kidney Beans", "measure": "2 cups"}, {"ingredient": "Carrots", "measure": "1 large"}, {"ingredient": "Spring Onions", "measure": "2 chopped"}, {"ingredient": "Thyme", "measure": "4 sprigs"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Black Pepper", "measure": "1/2 tsp"}, {"ingredient": "Red Pepper", "measure": "2 chopped"}, {"ingredient": "Garlic Clove", "measure": "4 Mashed"}, {"ingredient": "Allspice", "measure": "1 tbs"}, {"ingredient": "Beef", "measure": "2 Lbs"}, {"ingredient": "Water", "measure": "2L"}, {"ingredient": "Potatoes", "measure": "4"}, {"ingredient": "Plain Flour", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1/4 cup"}, {"ingredient": "Coconut Milk", "measure": "1 cup"}], "instructions": "Wash and rinse the dried kidney beans.. then cover with water in a deep bowl. Remember as they soak they will expand to at least triple the size they were originally so add a lot of water to the bowl. Soak them overnight or for at least 2 hrs to make the cooking step go quicker. I tossed out the water they were soaked in after it did the job.\r\n\r\nHave your butcher cut the salted pigtail into 2 inch pieces as it will be very difficult to cut with an ordinary kitchen knife. Wash, then place a deep pot with water and bring to a boil. Cook for 20 minutes, then drain + rinse and repeat (boil again in water). The goal is to make the pieces of pig tails tender and to remove most of the salt it was cured in.\r\n\r\nTime to start the soup. Place everything in the pot (except the flour and potato), then cover with water and place on a high flame to bring to a boil. As it comes to a boil, skim off any scum/froth at the top and discard. Reduce the heat to a gentle boil and allow it to cook for 1 hr and 15 mins.. basically until the beans are tender and start falling apart.\r\n\r\nIt’s now time to add the potato (and Yams etc if you’re adding it) as well as the coconut milk and continue cooking for 15 minutes.\r\n\r\nNow is a good time to start making the basic dough for the spinner dumplings. Mix the flour and water (add a pinch of salt if you want) until you have a soft/smooth dough. allow it to rest for 5 minutes, then pinch of a tablespoon at a time and roll between your hands to form a cigarette shape.\r\n\r\nAdd them to the pot, stir well and continue cooking for another 15 minutes on a rolling boil.\r\n\r\nYou’ll notice that I didn’t add any salt to the pot as the remaining salt from the salted pigtails will be enough to properly season this dish. However you can taste and adjust accordingly. Lets recap the timing part of things so you’re not confused. Cook the base of the soup for 1 hr and 15 minute or until tender, then add the potatoes and cook for 15 minutes, then add the dumplings and cook for a further 15 minutes. Keep in mind that this soup will thicken quite a bit as it cools.\r\n\r\nWhile this is not a traditional recipe to any one specific island, versions of this soup (sometimes called stewed peas) can be found throughout the Caribbean, Latin America and Africa. A hearty bowl of this soup will surely give you the sleepies (some may call it ethnic fatigue). You can certainly freeze the leftovers and heat it up another day.", "equipment_tags": [], "portions": 10, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 398, "protein_g": 26.2, "carbs_g": 38.2, "fat_g": 16.4, "total_kcal": 3976, "total_protein_g": 262.4, "total_carbs_g": 381.9, "total_fat_g": 163.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the beans", "instruction": "Rinse the kidney beans and soak in plenty of water overnight or for at least 2 hours.", "timer_seconds": 7200, "background": true}, {"step": 2, "label": "Blanch the salted meat", "instruction": "Boil the salted pigtail or beef pieces in water, drain, and repeat to remove excess salt.", "timer_seconds": 1200, "background": false}, {"step": 3, "label": "Simmer the soup base", "instruction": "Combine everything except the flour and potato in a pot, cover with water, bring to the boil, skim off any scum, then reduce to a gentle boil and cook until the beans are tender.", "timer_seconds": 4500, "background": true}, {"step": 4, "label": "Add potatoes", "instruction": "Add the potato and coconut milk and continue cooking.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Make the dumplings", "instruction": "Mix the flour and water into a soft dough, rest, then roll pieces into cigarette shapes.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Finish and serve", "instruction": "Add the dumplings to the pot and cook on a rolling boil, then taste and adjust seasoning before serving.", "timer_seconds": 900, "background": true}], "video": "https://www.youtube.com/watch?v=1ogCfDXotMw"}, {"id": "52942", "name": "Roast fennel and aubergine paella", "category": "Vegan", "area": "Spanish", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/1520081754.jpg", "local_image": "52942.jpg", "ingredients": [{"ingredient": "Baby Aubergine", "measure": "6 small"}, {"ingredient": "Fennel", "measure": "4 small"}, {"ingredient": "Red Pepper", "measure": "1 thinly sliced"}, {"ingredient": "Courgettes", "measure": "1 medium"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Paella Rice", "measure": "300g"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Saffron", "measure": "pinch"}, {"ingredient": "White Wine", "measure": "200ml"}, {"ingredient": "Vegetable Stock", "measure": "700ml"}, {"ingredient": "Frozen Peas", "measure": "100g"}, {"ingredient": "Lemon", "measure": "1 chopped"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Black Pepper", "measure": "pinch"}], "instructions": "1 Put the fennel, aubergine, pepper and courgette in a roasting tray. Add a glug of olive oil, season with salt and pepper and toss around to coat the veggies in the oil. Roast in the oven for 20 minutes, turning a couple of times until the veg are pretty much cooked through and turning golden.\r\n\r\n2 Meanwhile, heat a paella pan or large frying pan over a low– medium heat and add a glug of olive oil. Sauté the onion for 8–10 minutes until softened. Increase the heat to medium and stir in the rice, paprika and saffron. Cook for around 1 minute to start toasting the rice, then add the white wine. Reduce by about half before stirring in two-thirds of the stock. Reduce to a simmer and cook for 10 minutes without a lid, stirring a couple of times.\r\n\r\n3 Stir in the peas, add some seasoning, then gently mix in the roasted veg. Pour over the remaining stock, arrange the lemon wedges on top and cover with a lid or some aluminium foil. Cook for a further 10 minutes.\r\n\r\n4 To ensure you get the classic layer of toasted rice at the bottom of the pan, increase the heat to high until you hear a slight crackle. Remove from the heat and sit for 5 minutes before sprinkling over the parsley and serving.", "equipment_tags": [], "portions": 4, "prep_minutes": 56, "prep_minutes_source": "explicit", "kcal": 402, "protein_g": 10.0, "carbs_g": 79.8, "fat_g": 1.4, "total_kcal": 1610, "total_protein_g": 40.0, "total_carbs_g": 319.4, "total_fat_g": 5.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the vegetables", "instruction": "Put the fennel, aubergine, pepper and courgette in a roasting tray, toss with oil and seasoning, and roast until mostly cooked through and golden.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Toast the rice", "instruction": "Meanwhile, heat a paella pan with oil, sauté the onion until softened, then stir in the rice, paprika and saffron and toast briefly.", "timer_seconds": 660, "background": false}, {"step": 3, "label": "Simmer the rice", "instruction": "Add the white wine and reduce by half, then stir in two thirds of the stock and simmer without a lid, stirring occasionally.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Combine and finish", "instruction": "Stir in the peas, season, gently mix in the roasted vegetables, pour over the remaining stock, arrange the lemon on top, cover and cook.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Crisp the base", "instruction": "Increase the heat to high until you hear a slight crackle from the toasted rice at the bottom.", "timer_seconds": 60, "background": false}, {"step": 6, "label": "Rest and serve", "instruction": "Remove from heat, sit for 5 minutes, then sprinkle with parsley and serve.", "timer_seconds": 300, "background": true}], "video": "https://www.youtube.com/watch?v=H5SmjR-fxUs"}, {"id": "52943", "name": "Oxtail with broad beans", "category": "Beef", "area": "Jamaican", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/1520083578.jpg", "local_image": "52943.jpg", "ingredients": [{"ingredient": "Oxtail", "measure": "450g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Spring Onions", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Scotch Bonnet", "measure": "1 chopped"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Fresh Thyme", "measure": "1 chopped"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Water", "measure": "350ml"}, {"ingredient": "Broad Beans", "measure": "200g"}, {"ingredient": "Corn Flour", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "2 tbs"}], "instructions": "Toss the oxtail with the onion, spring onion, garlic, ginger, chilli, soy sauce, thyme, salt and pepper. Heat the vegetable oil in a large frying pan over medium-high heat. Brown the oxtail in the pan until browned all over, about 10 minutes. Place into a pressure cooker, and pour in 375ml water. Cook at pressure for 25 minutes, then remove from heat, and remove the lid according to manufacturer's directions.\r\nAdd the broad beans and pimento berries, and bring to a simmer over medium-high heat. Dissolve the cornflour in 2 tablespoons water, and stir into the simmering oxtail. Cook and stir a few minutes until the sauce has thickened, and the broad beans are tender.", "equipment_tags": [], "portions": 3, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 566, "protein_g": 37.0, "carbs_g": 23.2, "fat_g": 37.1, "total_kcal": 1699, "total_protein_g": 111.0, "total_carbs_g": 69.7, "total_fat_g": 111.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the oxtail", "instruction": "Toss the oxtail with the onion, spring onion, garlic, ginger, chilli, soy sauce, thyme, salt and pepper.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Brown the oxtail", "instruction": "Heat the oil in a large frying pan over medium-high heat and brown the oxtail all over.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Pressure cook", "instruction": "Transfer to a pressure cooker, add water, and cook at pressure, then release according to the manufacturer's directions.", "timer_seconds": 1500, "background": true}, {"step": 4, "label": "Finish", "instruction": "Add the broad beans and pimento berries and bring to a simmer. Dissolve the cornflour in water and stir in, cooking until the sauce thickens and beans are tender.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=DIhxk-98Hz8"}, {"id": "52944", "name": "Escovitch Fish", "category": "Seafood", "area": "Jamaican", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/1520084413.jpg", "local_image": "52944.jpg", "ingredients": [{"ingredient": "Red Snapper", "measure": "2 Pounds"}, {"ingredient": "Vegetable Oil", "measure": "1/2 cup"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Ginger", "measure": "1/2 tsp"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Red Pepper", "measure": "0.5"}, {"ingredient": "Yellow Pepper", "measure": "0.5"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Carrots", "measure": "1 chopped"}, {"ingredient": "Sugar", "measure": "1 tbs"}, {"ingredient": "Allspice", "measure": "1/2 tsp"}, {"ingredient": "Worcestershire Sauce", "measure": "1 tsp"}, {"ingredient": "Scotch Bonnet", "measure": "1"}, {"ingredient": "Lime", "measure": "1"}, {"ingredient": "Malt Vinegar", "measure": "3/4 cup"}, {"ingredient": "Pepper", "measure": "pinch"}], "instructions": "Rinse fish; rub with lemon or lime, seasoned with salt and pepper or use your favorite seasoning. I used creole seasoning. Set aside or place in the oven to keep it warm until sauce is ready.\r\n\r\nIn large skillet heat oil over medium heat, until hot, add the fish, cook each side- for about 5-7 minutes until cooked through and crispy on both sides. Remove fish and set aside. Drain oil and leave about 2-3 tablespoons of oil\r\nAdd, bay leave, garlic and ginger, stir-fry for about a minute making sure the garlic does not burn\r\nThen add onion, bell peppers, thyme, scotch bonnet, sugar, all spice-continue stirring for about 2-3 minutes. Add vinegar, mix an adjust salt and pepper according to preference. Let it simmer for about 2 more minutes. \r\n\r\nDiscard bay leave, thyme spring and serve over fish with a side of this bammy. You may make the sauce about 2 days in advance.", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 700, "protein_g": 61.8, "carbs_g": 16.1, "fat_g": 42.3, "total_kcal": 2100, "total_protein_g": 185.4, "total_carbs_g": 48.3, "total_fat_g": 126.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Season the fish", "instruction": "Rinse the fish and rub with lime, salt and pepper or your favourite seasoning. Set aside or keep warm in the oven until the sauce is ready.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fry the fish", "instruction": "Heat oil in a large skillet, add the fish, and cook on each side until cooked through and crispy. Remove and set aside, draining most of the oil.", "timer_seconds": 720, "background": false}, {"step": 3, "label": "Fry the aromatics", "instruction": "Add the bay leaf, garlic and ginger to the pan and stir-fry briefly, taking care not to burn the garlic.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Build the escovitch sauce", "instruction": "Add the onion, peppers, thyme, scotch bonnet, sugar and allspice, and stir continuously. Add the vinegar, adjust seasoning, and simmer.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Serve", "instruction": "Discard the bay leaf and thyme sprig, and serve the sauce over the fish with bammy on the side.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=nF6DOtGE6k8"}, {"id": "52945", "name": "Kung Pao Chicken", "category": "Chicken", "area": "Chinese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/1525872624.jpg", "local_image": "52945.jpg", "ingredients": [{"ingredient": "Sake", "measure": "2 tbs"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tbs"}, {"ingredient": "Corn Flour", "measure": "2 tbs"}, {"ingredient": "Water", "measure": "2 tbs"}, {"ingredient": "Chicken", "measure": "500g"}, {"ingredient": "Chilli Powder", "measure": "1 tbs"}, {"ingredient": "Rice Vinegar", "measure": "1 tsp"}, {"ingredient": "Brown Sugar", "measure": "1 tbs"}, {"ingredient": "Spring Onions", "measure": "4 Chopped"}, {"ingredient": "Garlic Clove", "measure": "6 cloves"}, {"ingredient": "Water Chestnut", "measure": "220g"}, {"ingredient": "Peanuts", "measure": "100g"}], "instructions": "Combine the sake or rice wine, soy sauce, sesame oil and cornflour dissolved in water. Divide mixture in half.\r\nIn a glass dish or bowl, combine half of the sake mixture with the chicken pieces and toss to coat. Cover dish and place in refrigerator for about 30 minutes.\r\nIn a medium frying pan, combine remaining sake mixture, chillies, vinegar and sugar. Mix together and add spring onion, garlic, water chestnuts and peanuts. Heat sauce slowly over medium heat until aromatic.\r\nMeanwhile, remove chicken from marinade and sauté in a large frying pan until juices run clear. When sauce is aromatic, add sautéed chicken and let simmer together until sauce thickens.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 646, "protein_g": 48.2, "carbs_g": 30.5, "fat_g": 37.5, "total_kcal": 1937, "total_protein_g": 144.6, "total_carbs_g": 91.5, "total_fat_g": 112.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the sauce mix", "instruction": "Combine the sake, soy sauce, sesame oil and cornflour dissolved in water. Divide the mixture in half.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the chicken", "instruction": "Combine half the sake mixture with the chicken, toss to coat, cover, and refrigerate.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Build the sauce", "instruction": "In a frying pan, combine the remaining sake mixture with the chillies, vinegar and sugar. Add the spring onion, garlic, water chestnuts and peanuts, and heat slowly until aromatic.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Cook the chicken and finish", "instruction": "Remove the chicken from the marinade and sauté in a separate pan until the juices run clear, then add to the aromatic sauce and simmer together until the sauce thickens.", "timer_seconds": 480, "background": false}], "video": "https://www.youtube.com/watch?v=QqdcCHQlOe0"}, {"id": "52946", "name": "Kung Po Prawns", "category": "Seafood", "area": "Chinese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/1525873040.jpg", "local_image": "52946.jpg", "ingredients": [{"ingredient": "Prawns", "measure": "400g"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Tomato Puree", "measure": "1 tsp"}, {"ingredient": "Corn Flour", "measure": "1 tsp"}, {"ingredient": "Caster Sugar", "measure": "1 tsp"}, {"ingredient": "Sunflower Oil", "measure": "1 tsp"}, {"ingredient": "Peanuts", "measure": "85g"}, {"ingredient": "Chilli", "measure": "3 Large"}, {"ingredient": "Brown Sugar", "measure": "1 tbs"}, {"ingredient": "Garlic Clove", "measure": "6 cloves"}, {"ingredient": "Water Chestnut", "measure": "450g"}, {"ingredient": "Ginger", "measure": "to taste"}], "instructions": "Mix the cornflour and 1 tbsp soy sauce, toss in the prawns and set aside for 10 mins. Stir the vinegar, remaining soy sauce, tomato purée, sugar and 2 tbsp water together to make a sauce.\r\n\r\nWhen you’re ready to cook, heat a large frying pan or wok until very hot, then add 1 tbsp oil. Fry the prawns until they are golden in places and have opened out– then tip them out of the pan.\r\n\r\nHeat the remaining oil and add the peanuts, chillies and water chestnuts. Stir-fry for 2 mins or until the peanuts start to colour, then add the ginger and garlic and fry for 1 more min. Tip in the prawns and sauce and simmer for 2 mins until thickened slightly. Serve with rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 14, "prep_minutes_source": "explicit", "kcal": 523, "protein_g": 54.4, "carbs_g": 27.8, "fat_g": 24.6, "total_kcal": 1045, "total_protein_g": 108.7, "total_carbs_g": 55.6, "total_fat_g": 49.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the prawns", "instruction": "Mix the cornflour with a tablespoon of soy sauce, toss in the prawns, and set aside. Stir the vinegar, remaining soy sauce, tomato purée, sugar and water together to make the sauce.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Fry the prawns", "instruction": "Heat a wok until very hot, add oil, and fry the prawns until golden in places and opened out, then remove.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Cook the peanuts and aromatics", "instruction": "Heat the remaining oil, add the peanuts, chillies and water chestnuts, and stir-fry until the peanuts start to colour, then add the ginger and garlic and fry a minute more.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Finish and serve", "instruction": "Tip the prawns and sauce back into the wok and simmer until thickened slightly. Serve with rice.", "timer_seconds": 120, "background": false}], "video": "https://www.youtube.com/watch?v=ysiuZm9FIxs"}, {"id": "52947", "name": "Ma Po Tofu", "category": "Beef", "area": "Chinese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/1525874812.jpg", "local_image": "52947.jpg", "ingredients": [{"ingredient": "Tofu", "measure": "450g"}, {"ingredient": "Minced Beef", "measure": "100g"}, {"ingredient": "Sesame Seed Oil", "measure": "1/2 tbs"}, {"ingredient": "Doubanjiang", "measure": "1 1/2 tsp"}, {"ingredient": "Fermented Black Beans", "measure": "1/2 tsp"}, {"ingredient": "Pepper", "measure": "1 tbs"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Sichuan pepper", "measure": "1/2 tsp"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "400ml"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Scallions", "measure": "2 chopped"}, {"ingredient": "Spring Onions", "measure": "4"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Ginger", "measure": "4 sliced"}, {"ingredient": "Water", "measure": "2 1/2 tbs"}, {"ingredient": "Cornstarch", "measure": "1 tbs"}], "instructions": "Add a small pinch of salt and sesame oil to minced beef. Mix well and set aside.\r\nMix 1 tablespoon of cornstarch with 2 and ½ tablespoons of water in a small bowl to make water starch.\r\nCut tofu into square cubes (around 2cms). Bring a large amount of water to a boil and then add a pinch of salt. Slide the tofu in and cook for 1 minute. Move out and drain.\r\nGet a wok and heat up around 2 tablespoons of oil, fry the minced meat until crispy. Transfer out beef out and leave the oil in.\r\nFry doubanjiang for 1 minute over slow fire and then add garlic, scallion white, ginger and fermented black beans to cook for 30 seconds until aroma. Then mix pepper flakes in.\r\nAdd water to the seasonings and bring to boil over high fire. Gently slide the tofu cubes. Add light soy sauce and beef.Slow the heat after boiling and then simmer for 6-8 minutes. Then add chopped garlic greens.\r\nStir the water starch and then pour half of the mixture to the simmering pot. Wait for around 30 seconds and then pour the other half. You can slightly taste the tofu and add pinch of salt if not salty enough. By the way, if you feel it is too spicy, add some sugar can milder the taste. But be carefully as the broth is very hot at this point.\r\nTransfer out when almost all the seasonings stick to tofu cubes. Sprinkle Szechuan peppercorn powder (to taste)and chopped garlic greens if using.\r\nServe immediately with steamed rice.", "equipment_tags": [], "portions": 4, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 340, "protein_g": 17.6, "carbs_g": 28.3, "fat_g": 19.9, "total_kcal": 1362, "total_protein_g": 70.4, "total_carbs_g": 113.0, "total_fat_g": 79.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Season the beef", "instruction": "Add a pinch of salt and sesame oil to the minced beef, mix well and set aside. Mix the cornstarch with water to make a slurry.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Blanch the tofu", "instruction": "Cut the tofu into cubes, bring a large pot of salted water to the boil, slide in the tofu, and cook briefly, then drain.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Fry the beef", "instruction": "Heat oil in a wok and fry the minced beef until crispy, then remove, leaving the oil.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Build the sauce", "instruction": "Fry the doubanjiang over low heat, then add the garlic, scallion whites, ginger and fermented black beans and cook until aromatic. Mix in the pepper flakes.", "timer_seconds": 90, "background": false}, {"step": 5, "label": "Simmer the tofu", "instruction": "Add water to the seasonings and bring to a boil, gently slide in the tofu, add soy sauce and the fried beef, then reduce heat and simmer.", "timer_seconds": 420, "background": true}, {"step": 6, "label": "Thicken and finish", "instruction": "Add the chopped garlic greens, then stir in the water starch in two additions, waiting between each, until the sauce thickens and clings to the tofu.", "timer_seconds": 60, "background": false}, {"step": 7, "label": "Serve", "instruction": "Sprinkle with Sichuan peppercorn powder and extra garlic greens, and serve immediately with steamed rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=IhwPQL9dFYc"}, {"id": "52948", "name": "Wontons", "category": "Pork", "area": "Chinese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/1525876468.jpg", "local_image": "52948.jpg", "ingredients": [{"ingredient": "Pork", "measure": "1lb"}, {"ingredient": "Garlic Clove", "measure": "3 chopped"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tsp"}, {"ingredient": "Carrots", "measure": "3 finely chopped"}, {"ingredient": "Celery", "measure": "3 finely chopped"}, {"ingredient": "Spring Onions", "measure": "6 chopped"}, {"ingredient": "Wonton Skin", "measure": "1 Packet"}, {"ingredient": "Oil", "measure": "Fry"}, {"ingredient": "Water", "measure": "Bottle"}], "instructions": "Combine pork, garlic, ginger, soy sauce, sesame oil, and vegetables in a bowl.\r\nSeparate wonton skins.\r\nPlace a heaping teaspoon of filling in the center of the wonton.\r\nBrush water on 2 borders of the skin, covering 1/4 inch from the edge.\r\nFold skin over to form a triangle, sealing edges.\r\nPinch the two long outside points together.\r\nHeat oil to 450 degrees and fry 4 to 5 at a time until golden.\r\nDrain and serve with sauce.", "equipment_tags": [], "portions": 3, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 549, "protein_g": 38.4, "carbs_g": 43.4, "fat_g": 25.0, "total_kcal": 1646, "total_protein_g": 115.1, "total_carbs_g": 130.3, "total_fat_g": 75.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the filling", "instruction": "Combine the pork, garlic, ginger, soy sauce, sesame oil and vegetables in a bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fill and shape the wontons", "instruction": "Place a heaping teaspoon of filling in the centre of each wonton skin, brush two borders with water, fold into a triangle to seal, then pinch the two long outer points together.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fry", "instruction": "Heat oil to 450°F and fry the wontons in batches of 4 to 5 until golden.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Serve", "instruction": "Drain and serve with your choice of dipping sauce.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=9h9No18ZyCI"}, {"id": "52949", "name": "Sweet and Sour Pork", "category": "Pork", "area": "Chinese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/1529442316.jpg", "local_image": "52949.jpg", "ingredients": [{"ingredient": "Pork", "measure": "200g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Water", "measure": "Dash"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Soy Sauce", "measure": "10g"}, {"ingredient": "Starch", "measure": "10g"}, {"ingredient": "Tomato Puree", "measure": "30g"}, {"ingredient": "Vinegar", "measure": "10g"}, {"ingredient": "Coriander", "measure": "Dash"}], "instructions": "Preparation\r\n1. Crack the egg into a bowl. Separate the egg white and yolk.\r\n\r\nSweet and Sour Pork\r\n2. Slice the pork tenderloin into strips.\r\n\r\n3. Prepare the marinade using a pinch of salt, one teaspoon of starch, two teaspoons of light soy sauce, and an egg white.\r\n\r\n4. Marinade the pork strips for about 20 minutes.\r\n\r\n5. Put the remaining starch in a bowl. Add some water and vinegar to make a starchy sauce.\r\n\r\nSweet and Sour Pork\r\nCooking Instructions\r\n1. Pour the cooking oil into a wok and heat to 190°C (375°F). Add the marinated pork strips and fry them until they turn brown. Remove the cooked pork from the wok and place on a plate.\r\n\r\n2. Leave some oil in the wok. Put the tomato sauce and white sugar into the wok, and heat until the oil and sauce are fully combined.\r\n\r\n3. Add some water to the wok and thoroughly heat the sweet and sour sauce before adding the pork strips to it.\r\n\r\n4. Pour in the starchy sauce. Stir-fry all the ingredients until the pork and sauce are thoroughly mixed together.\r\n\r\n5. Serve on a plate and add some coriander for decoration.", "equipment_tags": [], "portions": 1, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 478, "protein_g": 48.6, "carbs_g": 20.2, "fat_g": 21.2, "total_kcal": 478, "total_protein_g": 48.6, "total_carbs_g": 20.2, "total_fat_g": 21.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the marinade and pork", "instruction": "Separate the egg white and yolk. Slice the pork into strips and marinate in a pinch of salt, starch, light soy sauce and the egg white.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Make the starchy slurry", "instruction": "Mix the remaining starch with water and vinegar to make a starchy sauce.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fry the pork", "instruction": "Heat oil in a wok to 190°C/375°F, add the marinated pork strips, and fry until browned. Remove to a plate.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Build the sauce", "instruction": "Leave some oil in the wok, add the tomato sauce and sugar, and heat until fully combined. Add water and heat through, then add the pork back in.", "timer_seconds": 120, "background": false}, {"step": 5, "label": "Thicken and serve", "instruction": "Pour in the starchy sauce and stir-fry until everything is thoroughly mixed and glossy. Serve garnished with coriander.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=mdaBIhgEAMo"}, {"id": "52950", "name": "Szechuan Beef", "category": "Beef", "area": "Chinese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/1529443236.jpg", "local_image": "52950.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1/2 lb"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1 pinch"}, {"ingredient": "Egg White", "measure": "1"}, {"ingredient": "Starch", "measure": "3 tbs"}, {"ingredient": "Oil", "measure": "4 tbs"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Garlic", "measure": "1 tsp"}, {"ingredient": "Onion", "measure": "3/4 cup"}, {"ingredient": "Carrots", "measure": "1/2 cup"}, {"ingredient": "Green Pepper", "measure": "3/4 cup"}, {"ingredient": "Celery", "measure": "1 cup"}, {"ingredient": "Mushrooms", "measure": "1 cup"}, {"ingredient": "Cooking wine", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Oyster Sauce", "measure": "1 tbs"}, {"ingredient": "Hotsauce", "measure": "1/2 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}], "instructions": "STEP 1 - MARINATING THE BEEF\r\nIn a bowl, add the beef, salt, sesame seed oil, white pepper, egg white, 2 Tablespoon of corn starch and 1 Tablespoon of oil.\r\nSTEP 2 - STIR FRY\r\nFirst Cook the beef by adding 2 Tablespoon of oil until the beef is golden brown.\r\nSet the beef aside\r\nIn a wok add 1 Tablespoon of oil, minced ginger, minced garlic and stir-fry for few seconds.\r\nNext add all of the vegetables and then add sherry cooking wine and 1 cup of water.\r\nTo make the sauce add oyster sauce, hot pepper sauce, and sugar.\r\nadd the cooked beef and 1 spoon of soy sauce\r\nTo thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your stir-fry until it's the right thickness.", "equipment_tags": [], "portions": 3, "prep_minutes": 40, "prep_minutes_source": "estimated", "kcal": 480, "protein_g": 22.2, "carbs_g": 34.5, "fat_g": 29.0, "total_kcal": 1440, "total_protein_g": 66.7, "total_carbs_g": 103.4, "total_fat_g": 87.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the beef", "instruction": "In a bowl, combine the beef with salt, sesame oil, white pepper, egg white, 2 tbsp of the cornstarch and 1 tbsp oil.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Sear the beef", "instruction": "Cook the beef in 2 tbsp of oil in a wok until golden brown, then set aside.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Cook the aromatics and vegetables", "instruction": "Add 1 tbsp of oil to the wok with the minced ginger and garlic, stir-fry briefly, then add all the vegetables with the cooking wine and water.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Build the sauce", "instruction": "Add the oyster sauce, hot sauce and sugar to make the sauce, then return the cooked beef to the wok with a spoon of soy sauce.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Thicken and serve", "instruction": "Whisk the remaining cornstarch with water and slowly add to the stir-fry until it reaches the right thickness.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=SQGZqZYz7Ms"}, {"id": "52951", "name": "General Tsos Chicken", "category": "Chicken", "area": "Chinese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/1529444113.jpg", "local_image": "52951.jpg", "ingredients": [{"ingredient": "Chicken Breast", "measure": "1 1/2"}, {"ingredient": "Plain Flour", "measure": "3/4 cup"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Starch", "measure": "2 tbs"}, {"ingredient": "Baking Powder", "measure": "1 tbs"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Onion Salt", "measure": "1/2 tsp"}, {"ingredient": "Garlic Powder", "measure": "1/4 tsp"}, {"ingredient": "Water", "measure": "3/4 cup"}, {"ingredient": "Chicken Stock", "measure": "1/2 cup"}, {"ingredient": "Duck Sauce", "measure": "1/4 cup"}, {"ingredient": "Soy Sauce", "measure": "3 tbs"}, {"ingredient": "Honey", "measure": "2 tbs"}, {"ingredient": "Rice Vinegar", "measure": "1 tbs"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tbs"}, {"ingredient": "Gochujang", "measure": "1/2 tbs"}, {"ingredient": "Starch", "measure": "2 tbs"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Spring Onions", "measure": "2 chopped"}, {"ingredient": "Ginger", "measure": "1 tsp"}], "instructions": "DIRECTIONS:\r\nSTEP 1 - SAUCE\r\nIn a bowl, add 2 Cups of water, 2 Tablespoon soy sauce, 2 Tablespoon white vinegar, sherry cooking wine, 1/4 Teaspoon white pepper, minced ginger, minced garlic, hot pepper, ketchup, hoisin sauce, and sugar.\r\nMix together well and set aside.\r\nSTEP 2 - MARINATING THE CHICKEN\r\nIn a bowl, add the chicken, 1 pinch of salt, 1 pinch of white pepper, 2 egg whites, and 3 Tablespoon of corn starch\r\nSTEP 3 - DEEP FRY THE CHICKEN\r\nDeep fry the chicken at 350 degrees for 3-4 minutes or until it is golden brown and loosen up the chicken so that they don't stick together.\r\nSet the chicken aside.\r\nSTEP 4 - STIR FRY\r\nAdd the sauce to the wok and then the broccoli and wait until it is boiling.\r\nTo thicken the sauce, whisk together 2 Tablespoon of cornstarch and 4 Tablespoon of water in a bowl and slowly add to your stir-fry until it's the right thickness.\r\nNext add in the chicken and stir-fry for a minute and serve on a plate", "equipment_tags": [], "portions": 2, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 814, "protein_g": 43.7, "carbs_g": 95.5, "fat_g": 28.7, "total_kcal": 1628, "total_protein_g": 87.3, "total_carbs_g": 191.0, "total_fat_g": 57.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the sauce", "instruction": "In a bowl, mix water, soy sauce, white vinegar, cooking wine, white pepper, ginger, garlic, hot pepper, ketchup, hoisin sauce and sugar together and set aside.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the chicken", "instruction": "Combine the chicken with a pinch of salt, white pepper, egg whites and cornstarch.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Deep-fry the chicken", "instruction": "Deep-fry the chicken at 350°F until golden brown, loosening the pieces so they don't stick together, then set aside.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Cook the sauce with broccoli", "instruction": "Add the sauce to the wok with the broccoli and bring to a boil.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Thicken and finish", "instruction": "Whisk cornstarch with water and slowly add to thicken the sauce, then add the chicken and stir-fry to coat. Serve on a plate.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=wWGwz0iBmvU"}, {"id": "52952", "name": "Beef Lo Mein", "category": "Beef", "area": "Chinese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/1529444830.jpg", "local_image": "52952.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1/2 lb"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}, {"ingredient": "Egg", "measure": "1/2"}, {"ingredient": "Starch", "measure": "3 tbs"}, {"ingredient": "Oil", "measure": "5 tbs"}, {"ingredient": "Noodles", "measure": "1/4 lb"}, {"ingredient": "Onion", "measure": "1/2 cup"}, {"ingredient": "Minced Garlic", "measure": "1 tsp"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Bean Sprouts", "measure": "1 cup"}, {"ingredient": "Mushrooms", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Oyster Sauce", "measure": "1 tbs"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Soy Sauce", "measure": "1 tsp"}], "instructions": "STEP 1 - MARINATING THE BEEF\r\nIn a bowl, add the beef, salt, 1 pinch white pepper, 1 Teaspoon sesame seed oil, 1/2 egg, corn starch,1 Tablespoon of oil and mix together.\r\nSTEP 2 - BOILING THE THE NOODLES\r\nIn a 6 qt pot add your noodles to boiling water until the noodles are submerged and boil on high heat for 10 seconds. After your noodles is done boiling strain and cool with cold water.\r\nSTEP 3 - STIR FRY\r\nAdd 2 Tablespoons of oil, beef and cook on high heat untill beef is medium cooked.\r\nSet the cooked beef aside\r\nIn a wok add 2 Tablespoon of oil, onions, minced garlic, minced ginger, bean sprouts, mushrooms, peapods and 1.5 cups of water or until the vegetables are submerged in water.\r\nAdd the noodles to wok\r\nTo make the sauce, add oyster sauce, 1 pinch white pepper, 1 teaspoon sesame seed oil, sugar, and 1 Teaspoon of soy sauce.\r\nNext add the beef to wok and stir-fry", "equipment_tags": [], "portions": 3, "prep_minutes": 49, "prep_minutes_source": "estimated", "kcal": 558, "protein_g": 23.6, "carbs_g": 37.4, "fat_g": 36.5, "total_kcal": 1675, "total_protein_g": 70.9, "total_carbs_g": 112.1, "total_fat_g": 109.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the beef", "instruction": "Combine the beef with salt, white pepper, sesame oil, egg, cornstarch and oil, and mix together.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Boil the noodles", "instruction": "Add the noodles to a large pot of boiling water and boil briefly until submerged and just cooked, then strain and cool with cold water.", "timer_seconds": 10, "background": false}, {"step": 3, "label": "Cook the beef", "instruction": "Add oil to a wok and cook the beef on high heat until medium done, then set aside.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Cook the vegetables", "instruction": "In the wok, add oil, onions, minced garlic and ginger, bean sprouts, mushrooms, peapods and water until the vegetables are submerged.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Combine and finish", "instruction": "Add the noodles to the wok. Make the sauce with oyster sauce, white pepper, sesame oil, sugar and soy sauce, then add the beef back in and stir-fry together.", "timer_seconds": 180, "background": false}], "video": "https://www.youtube.com/watch?v=ZT9LSsNXXe0"}, {"id": "52953", "name": "Shrimp Chow Fun", "category": "Seafood", "area": "Chinese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/1529445434.jpg", "local_image": "52953.jpg", "ingredients": [{"ingredient": "Rice Stick Noodles", "measure": "1/2 bag"}, {"ingredient": "Prawns", "measure": "8 oz"}, {"ingredient": "Egg", "measure": "1/2"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}, {"ingredient": "Cornstarch", "measure": "2 tbs"}, {"ingredient": "Oil", "measure": "4 tbs"}, {"ingredient": "Minced Garlic", "measure": "1 tsp"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Onion", "measure": "1/2 cup"}, {"ingredient": "Bean Sprouts", "measure": "1 cup"}, {"ingredient": "Spring Onions", "measure": "1/2 cup"}, {"ingredient": "Cooking wine", "measure": "1 tbs"}, {"ingredient": "Oyster Sauce", "measure": "1 tbs"}, {"ingredient": "Sugar", "measure": "1/2 tbs"}, {"ingredient": "Vinegar", "measure": "1/2 tbs"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}], "instructions": "STEP 1 - SOAK THE RICE NOODLES\r\nSoak the rice noodles overnight untill they are soft\r\nSTEP 2 - BOIL THE RICE NOODLES\r\nBoil the noodles for 10-15 minutes and then rinse with cold water to stop the cooking process of the noodles.\r\nSTEP 3 -MARINATING THE SHRIMP\r\nIn a bowl add the shrimp, egg, 1 pinch of white pepper, 1 Teaspoon of sesame seed oil, 1 Tablespoon corn starch and 1 tablespoon of oil\r\nMix together well\r\nSTEP 4 - STIR FRY\r\nIn a wok add 2 Tablespoons of oil, shrimp and stir fry them until it is golden brown\r\nSet the shrimp aside\r\nAdd 1 Tablespoon of oil to the work and then add minced garlic, ginger and all of the vegetables.\r\nAdd the noodles to the wok\r\nNext add sherry cooking wine, oyster sauce, sugar, vinegar, sesame seed oil, 1 pinch white pepper, and soy sauce\r\nAdd back in the shrimp\r\nTo thicken the sauce, whisk together 1 Tablespoon of corn starch and 2 Tablespoon of water in a bowl and slowly add to your stir-fry until it's the right thickness.", "equipment_tags": [], "portions": 2, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 569, "protein_g": 30.7, "carbs_g": 37.3, "fat_g": 34.6, "total_kcal": 1139, "total_protein_g": 61.3, "total_carbs_g": 74.6, "total_fat_g": 69.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the noodles", "instruction": "Soak the rice noodles until soft.", "timer_seconds": 28800, "background": true}, {"step": 2, "label": "Boil the noodles", "instruction": "Boil the soaked noodles, then rinse with cold water to stop cooking.", "timer_seconds": 900, "background": false}, {"step": 3, "label": "Marinate the shrimp", "instruction": "Combine the shrimp with egg, white pepper, sesame oil, cornstarch and oil, and mix well.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the shrimp", "instruction": "Stir-fry the shrimp in oil in a wok until golden brown, then set aside.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Cook the vegetables", "instruction": "Add oil to the wok with the minced garlic, ginger and all the vegetables, and stir-fry.", "timer_seconds": 180, "background": false}, {"step": 6, "label": "Combine and season", "instruction": "Add the noodles, then the cooking wine, oyster sauce, sugar, vinegar, sesame oil, white pepper and soy sauce, and add the shrimp back in.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Thicken and serve", "instruction": "Whisk cornstarch with water and slowly add to the stir-fry until it reaches the right thickness.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=wzaTcpoFEaY"}, {"id": "52954", "name": "Hot and Sour Soup", "category": "Pork", "area": "Chinese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/1529445893.jpg", "local_image": "52954.jpg", "ingredients": [{"ingredient": "Mushrooms", "measure": "1/3 cup"}, {"ingredient": "Wood Ear Mushrooms", "measure": "1/3 cup"}, {"ingredient": "Tofu", "measure": "2/3 Cup"}, {"ingredient": "Pork", "measure": "1/2 cup"}, {"ingredient": "Chicken Stock", "measure": "2-1/2 cups"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Sugar", "measure": "1/4 tsp"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1/4 tsp"}, {"ingredient": "Hotsauce", "measure": "1/2 tsp"}, {"ingredient": "Vinegar", "measure": "1-½ cups"}, {"ingredient": "Soy Sauce", "measure": "1 tsp"}, {"ingredient": "Cornstarch", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "2 tbs"}, {"ingredient": "Spring Onions", "measure": "1/4 cup"}], "instructions": "STEP 1 - MAKING THE SOUP\r\nIn a wok add chicken broth and wait for it to boil.\r\nNext add salt, sugar, sesame seed oil, white pepper, hot pepper sauce, vinegar and soy sauce and stir for few seconds.\r\nAdd Tofu, mushrooms, black wood ear mushrooms to the wok.\r\nTo thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your soup until it's the right thickness.\r\nNext add 1 egg slightly beaten with a knife or fork and add it to the soup and stir for 8 seconds\r\nServe the soup in a bowl and add the bbq pork and sliced green onions on top.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 490, "protein_g": 43.9, "carbs_g": 29.4, "fat_g": 22.7, "total_kcal": 490, "total_protein_g": 43.9, "total_carbs_g": 29.4, "total_fat_g": 22.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Start the broth", "instruction": "Bring the chicken broth to a boil in a wok, then add salt, sugar, sesame oil, white pepper, hot sauce, vinegar and soy sauce, and stir.", "timer_seconds": 180, "background": false}, {"step": 2, "label": "Add the solids", "instruction": "Add the tofu, mushrooms and wood ear mushrooms to the wok.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Thicken", "instruction": "Whisk cornstarch with water and slowly add to the soup until it reaches the right thickness.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Add the egg", "instruction": "Beat the egg lightly, add to the soup slowly, and stir.", "timer_seconds": 10, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve the soup in bowls topped with the bbq pork and sliced green onions.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=KgV9Zq3aSTo"}, {"id": "52955", "name": "Egg Drop Soup", "category": "Vegetarian", "area": "Chinese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/1529446137.jpg", "local_image": "52955.jpg", "ingredients": [{"ingredient": "Chicken Stock", "measure": "3 cups"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Sugar", "measure": "1/4 tsp"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tsp"}, {"ingredient": "Peas", "measure": "1/3 cup"}, {"ingredient": "Mushrooms", "measure": "1/3 cup"}, {"ingredient": "Cornstarch", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "2 tbs"}, {"ingredient": "Spring Onions", "measure": "1/4 cup"}], "instructions": "In a wok add chicken broth and wait for it to boil.\r\nNext add salt, sugar, white pepper, sesame seed oil.\r\nWhen the chicken broth is boiling add the vegetables to the wok.\r\nTo thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your soup until it's the right thickness.\r\nNext add 1 egg slightly beaten with a knife or fork and add it to the soup slowly and stir for 8 seconds\r\nServe the soup in a bowl and add the green onions on top.", "equipment_tags": [], "portions": 2, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 120, "protein_g": 5.8, "carbs_g": 19.1, "fat_g": 3.0, "total_kcal": 241, "total_protein_g": 11.6, "total_carbs_g": 38.3, "total_fat_g": 6.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Season the broth", "instruction": "Bring the chicken broth to a boil in a wok, then add salt, sugar, white pepper and sesame oil.", "timer_seconds": 180, "background": false}, {"step": 2, "label": "Add the vegetables", "instruction": "Once boiling, add the peas and mushrooms to the wok.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Thicken", "instruction": "Whisk cornstarch with water and slowly add to the soup until it reaches the right thickness.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Add the egg", "instruction": "Beat the egg lightly, pour slowly into the soup, and stir.", "timer_seconds": 10, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve the soup in bowls with green onions on top.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=9XpzHm9QpZg"}, {"id": "52956", "name": "Chicken Congee", "category": "Chicken", "area": "Chinese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/1529446352.jpg", "local_image": "52956.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "8 oz"}, {"ingredient": "Salt", "measure": "pinch"}, {"ingredient": "Pepper", "measure": "pinch"}, {"ingredient": "Ginger Cordial", "measure": "1 tsp"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Spring Onions", "measure": "1 tbs"}, {"ingredient": "Rice", "measure": "1/2 cup"}, {"ingredient": "Water", "measure": "8 cups"}, {"ingredient": "Coriander", "measure": "2 oz"}], "instructions": "STEP 1 - MARINATING THE CHICKEN\r\nIn a bowl, add chicken, salt, white pepper, ginger juice and then mix it together well.\r\nSet the chicken aside.\r\nSTEP 2 - RINSE THE WHITE RICE\r\nRinse the rice in a metal bowl or pot a couple times and then drain the water.\r\nSTEP 2 - BOILING THE WHITE RICE\r\nNext add 8 cups of water and then set the stove on high heat until it is boiling. Once rice porridge starts to boil, set the stove on low heat and then stir it once every 8-10 minutes for around 20-25 minutes.\r\nAfter 25 minutes, this is optional but you can add a little bit more water to make rice porridge to make it less thick or to your preference.\r\nNext add the marinated chicken to the rice porridge and leave the stove on low heat for another 10 minutes.\r\nAfter an additional 10 minutes add the green onions, sliced ginger, 1 pinch of salt, 1 pinch of white pepper and stir for 10 seconds.\r\nServe the rice porridge in a bowl\r\nOptional: add Coriander on top of the rice porridge.", "equipment_tags": [], "portions": 5, "prep_minutes": 80, "prep_minutes_source": "explicit", "kcal": 148, "protein_g": 11.3, "carbs_g": 17.4, "fat_g": 3.2, "total_kcal": 740, "total_protein_g": 56.6, "total_carbs_g": 86.9, "total_fat_g": 15.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the chicken", "instruction": "Combine the chicken with salt, white pepper and ginger juice, mix well, and set aside.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Rinse the rice", "instruction": "Rinse the rice a couple of times and drain.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the congee", "instruction": "Add the rice and water to a pot, bring to a boil, then reduce to low heat and stir every 8-10 minutes until thickened.", "timer_seconds": 1500, "background": true}, {"step": 4, "label": "Add the chicken and finish", "instruction": "Add the marinated chicken and leave on low heat further, then add green onions, sliced ginger, salt and white pepper, and stir.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Serve", "instruction": "Serve the congee in a bowl, optionally topped with coriander.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=kqEfk801E94"}, {"id": "52957", "name": "Fruit and Cream Cheese Breakfast Pastries", "category": "Breakfast", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1543774956.jpg", "local_image": "52957.jpg", "ingredients": [{"ingredient": "Cream Cheese", "measure": "1 1/4 oz"}, {"ingredient": "Sugar", "measure": "1 1/4 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 teaspoon"}, {"ingredient": "Flour", "measure": ""}, {"ingredient": "Puff Pastry", "measure": "2"}, {"ingredient": "Strawberries", "measure": ""}, {"ingredient": "Raspberries", "measure": ""}, {"ingredient": "Blackberries", "measure": ""}], "instructions": "Preheat oven to 400ºF (200ºC), and prepare two cookie sheets with parchment paper. In a bowl, mix cream cheese, sugar, and vanilla until fully combined. Lightly flour the surface and roll out puff pastry on top to flatten. Cut each sheet of puff pastry into 9 equal squares. On the top right and bottom left of the pastry, cut an L shape approximately ½ inch (1 cm) from the edge.\r\nNOTE: This L shape should reach all the way down and across the square, however both L shapes should not meet at the ends. Your pastry should look like a picture frame with two corners still intact.\r\nTake the upper right corner and fold down towards the inner bottom corner. You will now have a diamond shape.\r\nPlace 1 to 2 teaspoons of the cream cheese filling in the middle, then place berries on top.\r\nRepeat with the remaining pastry squares and place them onto the parchment covered baking sheet.\r\nBake for 15-20 minutes or until pastry is golden brown and puffed.\r\nEnjoy!\r\n", "equipment_tags": [], "portions": 1, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 1588, "protein_g": 6.6, "carbs_g": 302.0, "fat_g": 42.4, "total_kcal": 1588, "total_protein_g": 6.6, "total_carbs_g": 302.0, "total_fat_g": 42.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and make the filling", "instruction": "Preheat the oven to 400°F/200°C and line two baking sheets. Mix the cream cheese, sugar and vanilla until fully combined.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cut and shape the pastry", "instruction": "Roll out the puff pastry on a floured surface, cut into 9 squares per sheet, and cut an L shape near two opposite corners of each square as described, keeping the ends unattached.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fold into diamonds", "instruction": "Fold the upper right corner down towards the inner bottom corner to form a diamond shape.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fill and top with fruit", "instruction": "Place 1-2 teaspoons of the cream cheese filling in the middle of each pastry, then top with berries. Repeat for the remaining squares and arrange on the baking sheets.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Bake until golden brown and puffed.", "timer_seconds": 1050, "background": true}], "video": null}, {"id": "52958", "name": "Peanut Butter Cookies", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1544384070.jpg", "local_image": "52958.jpg", "ingredients": [{"ingredient": "Peanut Butter", "measure": "1 cup"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Egg", "measure": "1"}], "instructions": "Preheat oven to 350ºF (180ºC).\r\nIn a large bowl, mix together the peanut butter, sugar, and egg.\r\nScoop out a spoonful of dough and roll it into a ball. Place the cookie balls onto a nonstick baking sheet.\r\nFor extra decoration and to make them cook more evenly, flatten the cookie balls by pressing a fork down on top of them, then press it down again at a 90º angle to make a criss-cross pattern.\r\nBake for 8-10 minutes or until the bottom of the cookies are golden brown.\r\nRemove from baking sheet and cool.\r\nEnjoy!", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 706, "protein_g": 2.9, "carbs_g": 34.3, "fat_g": 63.9, "total_kcal": 2118, "total_protein_g": 8.6, "total_carbs_g": 102.8, "total_fat_g": 191.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and mix", "instruction": "Preheat the oven to 350°F/180°C. Mix together the peanut butter, sugar and egg in a large bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Shape the cookies", "instruction": "Scoop dough into balls, place on a nonstick baking sheet, then flatten with a fork in a criss-cross pattern.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Bake until the bottoms are golden brown.", "timer_seconds": 540, "background": true}, {"step": 4, "label": "Cool", "instruction": "Remove from the baking sheet and cool before serving.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52959", "name": "Baked salmon with fennel & tomatoes", "category": "Seafood", "area": "British", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/1548772327.jpg", "local_image": "52959.jpg", "ingredients": [{"ingredient": "Fennel", "measure": "2 medium"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Cherry Tomatoes", "measure": "175g"}, {"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Salmon", "measure": "350g"}, {"ingredient": "Black Olives", "measure": "to serve"}], "instructions": "Heat oven to 180C/fan 160C/gas 4. Trim the fronds from the fennel and set aside. Cut the fennel bulbs in half, then cut each half into 3 wedges. Cook in boiling salted water for 10 mins, then drain well. Chop the fennel fronds roughly, then mix with the parsley and lemon zest.\r\n\r\nSpread the drained fennel over a shallow ovenproof dish, then add the tomatoes. Drizzle with olive oil, then bake for 10 mins. Nestle the salmon among the veg, sprinkle with lemon juice, then bake 15 mins more until the fish is just cooked. Scatter over the parsley and serve.", "equipment_tags": [], "portions": 1, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 966, "protein_g": 74.2, "carbs_g": 20.6, "fat_g": 63.5, "total_kcal": 966, "total_protein_g": 74.2, "total_carbs_g": 20.6, "total_fat_g": 63.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the fennel", "instruction": "Heat the oven to 180°C/fan 160°C/gas 4. Trim the fronds from the fennel, cut into wedges, and cook in boiling salted water until tender, then drain well.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Prep the herb mix", "instruction": "Chop the fennel fronds and mix with the parsley and lemon zest.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake the vegetables", "instruction": "Spread the drained fennel in a shallow ovenproof dish, add the tomatoes, drizzle with oil, and bake.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Add the salmon and finish baking", "instruction": "Nestle the salmon among the vegetables, sprinkle with lemon juice, and bake until the fish is just cooked.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Serve", "instruction": "Scatter with the parsley mix and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=xvPR2Tfw5k0"}, {"id": "52960", "name": "Salmon Avocado Salad", "category": "Seafood", "area": "British", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/1549542994.jpg", "local_image": "52960.jpg", "ingredients": [{"ingredient": "Salmon", "measure": "400g"}, {"ingredient": "Avocado", "measure": "3"}, {"ingredient": "Cucumber", "measure": "1"}, {"ingredient": "Spinach", "measure": "400g"}, {"ingredient": "Mint", "measure": "4 tbs"}, {"ingredient": "Lime", "measure": "zest and juice of 1"}, {"ingredient": "Honey", "measure": "2 tsp"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}], "instructions": "Season the salmon, then rub with oil. Mix the dressing ingredients together. Halve, stone, peel and slice the avocados. Halve and quarter the cucumber lengthways, then cut into slices. Divide salad, avocado and cucumber between four plates, then drizzle with half the dressing.\r\n\r\nHeat a non-stick pan. Add the salmon and fry for 3-4 mins on each side until crisp but still moist inside. Put a salmon fillet on top of each salad and drizzle over the remaining dressing. Serve warm.", "equipment_tags": [], "portions": 9, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 180, "protein_g": 10.8, "carbs_g": 5.4, "fat_g": 13.1, "total_kcal": 1616, "total_protein_g": 97.5, "total_carbs_g": 48.9, "total_fat_g": 117.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the salad", "instruction": "Season the salmon and rub with oil. Mix the dressing ingredients. Halve, stone, peel and slice the avocados, and slice the cucumber.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Plate the base", "instruction": "Divide the spinach, avocado and cucumber between four plates, then drizzle with half the dressing.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the salmon", "instruction": "Heat a non-stick pan, add the salmon, and fry on each side until crisp outside but still moist inside.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Serve", "instruction": "Put a salmon fillet on top of each salad, drizzle with the remaining dressing, and serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FJiu2S0Xap0"}, {"id": "52961", "name": "Budino Di Ricotta", "category": "Dessert", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1549542877.jpg", "local_image": "52961.jpg", "ingredients": [{"ingredient": "Ricotta", "measure": "500g"}, {"ingredient": "Eggs", "measure": "4 large"}, {"ingredient": "Flour", "measure": "3 tbs"}, {"ingredient": "Sugar", "measure": "250g"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Lemons", "measure": "Grated Zest of 2"}, {"ingredient": "Dark Rum", "measure": "5 tbs"}, {"ingredient": "Icing Sugar", "measure": "sprinking"}], "instructions": "Mash the ricotta and beat well with the egg yolks, stir in the flour, sugar, cinnamon, grated lemon rind and the rum and mix well. You can do this in a food processor. Beat the egg whites until stiff, fold in and pour into a buttered and floured 25cm cake tin. Bake in the oven at 180ºC/160ºC fan/gas 4 for about 40 minutes, or until it is firm.\r\n\r\nServe hot or cold dusted with icing sugar.", "equipment_tags": ["FoodProcessor"], "portions": 7, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 360, "protein_g": 12.2, "carbs_g": 46.0, "fat_g": 12.2, "total_kcal": 2521, "total_protein_g": 85.4, "total_carbs_g": 322.2, "total_fat_g": 85.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the batter", "instruction": "Mash the ricotta and beat with the egg yolks, then stir in the flour, sugar, cinnamon, lemon zest and rum.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fold in the egg whites", "instruction": "Beat the egg whites until stiff, then fold into the ricotta mixture.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Pour into a buttered and floured cake tin and bake at 180°C/160°C fan/gas 4 until firm.", "timer_seconds": 2400, "background": true}, {"step": 4, "label": "Serve", "instruction": "Serve hot or cold, dusted with icing sugar.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=6dzd6Ra6sb4"}, {"id": "52962", "name": "Salmon Eggs Eggs Benedict", "category": "Breakfast", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1550440197.jpg", "local_image": "52962.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "4"}, {"ingredient": "White Wine Vinegar", "measure": "2 tbs"}, {"ingredient": "English Muffins", "measure": "2"}, {"ingredient": "Butter", "measure": "To serve"}, {"ingredient": "Smoked Salmon", "measure": "8 slices"}, {"ingredient": "Lemon Juice", "measure": "2 tsp"}, {"ingredient": "White Wine Vinegar", "measure": "2 tsp"}, {"ingredient": "Egg", "measure": "3 Yolkes"}, {"ingredient": "Unsalted Butter", "measure": "125g"}], "instructions": "First make the Hollandaise sauce. Put the lemon juice and vinegar in a small bowl, add the egg yolks and whisk with a balloon whisk until light and frothy. Place the bowl over a pan of simmering water and whisk until mixture thickens. Gradually add the butter, whisking constantly until thick – if it looks like it might be splitting, then whisk off the heat for a few mins. Season and keep warm.\r\n\r\nTo poach the eggs, bring a large pan of water to the boil and add the vinegar. Lower the heat so that the water is simmering gently. Stir the water so you have a slight whirlpool, then slide in the eggs one by one. Cook each for about 4 mins, then remove with a slotted spoon.\r\n\r\nLightly toast and butter the muffins, then put a couple of slices of salmon on each half. Top each with an egg, spoon over some Hollandaise and garnish with chopped chives.", "equipment_tags": [], "portions": 3, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 695, "protein_g": 30.5, "carbs_g": 16.6, "fat_g": 57.1, "total_kcal": 2085, "total_protein_g": 91.5, "total_carbs_g": 49.9, "total_fat_g": 171.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the hollandaise", "instruction": "Whisk the lemon juice, vinegar and egg yolks in a bowl over a pan of simmering water until thickened, then gradually whisk in the butter until thick, whisking off the heat if it looks like splitting.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Season and keep warm", "instruction": "Season the hollandaise and keep warm.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Poach the eggs", "instruction": "Bring a pan of water to the boil with the vinegar, lower to a simmer, create a whirlpool, then slide in the eggs one by one and poach.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Assemble", "instruction": "Toast and butter the muffins, top with salmon slices, then an egg, then spoon over the hollandaise and garnish with chives.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Woiiet4vQ58"}, {"id": "52963", "name": "Shakshuka", "category": "Vegetarian", "area": "Egyptian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/g373701551450225.jpg", "local_image": "52963.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Red Onions", "measure": "2 chopped"}, {"ingredient": "Red Chilli", "measure": "1 finely chopped"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Coriander", "measure": "Chopped"}, {"ingredient": "Cherry Tomatoes", "measure": "800g"}, {"ingredient": "Caster Sugar", "measure": "1 tbs"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Feta", "measure": "Spinkling"}], "instructions": "Heat the oil in a frying pan that has a lid, then soften the onions, chilli, garlic and coriander stalks for 5 mins until soft. Stir in the tomatoes and sugar, then bubble for 8-10 mins until thick. Can be frozen for 1 month.\r\n\r\nUsing the back of a large spoon, make 4 dips in the sauce, then crack an egg into each one. Put a lid on the pan, then cook over a low heat for 6-8 mins, until the eggs are done to your liking. Scatter with the coriander leaves and serve with crusty bread.", "equipment_tags": [], "portions": 3, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 267, "protein_g": 13.9, "carbs_g": 24.8, "fat_g": 14.1, "total_kcal": 800, "total_protein_g": 41.6, "total_carbs_g": 74.4, "total_fat_g": 42.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the aromatics", "instruction": "Heat the oil in a lidded frying pan and soften the onions, chilli, garlic and coriander stalks.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Simmer the sauce", "instruction": "Stir in the tomatoes and sugar, then bubble until thick.", "timer_seconds": 540, "background": true}, {"step": 3, "label": "Add and cook the eggs", "instruction": "Make dips in the sauce with a spoon, crack an egg into each, cover, and cook over low heat until the eggs are done to your liking.", "timer_seconds": 420, "background": false}, {"step": 4, "label": "Serve", "instruction": "Scatter with coriander leaves and serve with crusty bread.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=C-3_jYrfdBU"}, {"id": "52964", "name": "Smoked Haddock Kedgeree", "category": "Breakfast", "area": "India", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1550441275.jpg", "local_image": "52964.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Cardamom", "measure": "3 Pods"}, {"ingredient": "Turmeric", "measure": "1/4 tsp"}, {"ingredient": "Cinnamon Stick", "measure": "1 small"}, {"ingredient": "Bay Leaf", "measure": "Sprigs of fresh"}, {"ingredient": "Basmati Rice", "measure": "450g"}, {"ingredient": "Chicken Stock", "measure": "1 Litre"}, {"ingredient": "Smoked Haddock", "measure": "750g"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Parsley", "measure": "3 tblsp chopped"}, {"ingredient": "Lemon", "measure": "1 chopped"}], "instructions": "Melt 50g butter in a large saucepan (about 20cm across), add 1 finely chopped medium onion and cook gently over a medium heat for 5 minutes, until softened but not browned.\r\n\r\nStir in 3 split cardamom pods, ¼ tsp turmeric, 1 small cinnamon stick and 2 bay leaves, then cook for 1 minute.\r\n\r\nTip in 450g basmati rice and stir until it is all well coated in the spicy butter.\r\n\r\nPour in 1 litre chicken or fish stock, add ½ teaspoon salt and bring to the boil, stir once to release any rice from the bottom of the pan. Cover with a close-fitting lid, reduce the heat to low and leave to cook very gently for 12 minutes.\r\n\r\nMeanwhile, bring some water to the boil in a large shallow pan. Add 750g un-dyed smoked haddock fillet and simmer for 4 minutes, until the fish is just cooked. Lift it out onto a plate and leave until cool enough to handle.\r\n\r\nHard-boil 3 eggs for 8 minutes.\r\n\r\nFlake the fish, discarding any skin and bones. Drain the eggs, cool slightly, then peel and chop. \r\n\r\nUncover the rice and remove the bay leaves, cinnamon stick and cardamom pods if you wish to. Gently fork in the fish and the chopped eggs, cover again and return to the heat for 2-3 minutes, or until the fish has heated through.\r\n\r\nGently stir in almost all the 3 tbsp chopped fresh parsley, and season with a little salt and black pepper to taste. Serve scattered with the remaining parsley and garnished with 1 lemon, cut into wedges.", "equipment_tags": [], "portions": 10, "prep_minutes": 33, "prep_minutes_source": "explicit", "kcal": 294, "protein_g": 20.0, "carbs_g": 38.5, "fat_g": 6.5, "total_kcal": 2943, "total_protein_g": 199.8, "total_carbs_g": 385.4, "total_fat_g": 65.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Melt the butter in a large saucepan, add the onion, and cook gently until softened but not browned.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Add spices", "instruction": "Stir in the cardamom, turmeric, cinnamon stick and bay leaves, and cook briefly.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Toast the rice", "instruction": "Add the rice and stir until well coated in the spicy butter.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the rice", "instruction": "Pour in the stock and salt, bring to the boil, stir once, cover, and cook gently on low heat without lifting the lid.", "timer_seconds": 720, "background": true}, {"step": 5, "label": "Poach the haddock", "instruction": "Meanwhile, bring water to the boil in a shallow pan, add the smoked haddock, and simmer until just cooked, then leave to cool.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Boil the eggs", "instruction": "Hard-boil the eggs.", "timer_seconds": 480, "background": false}, {"step": 7, "label": "Flake and chop", "instruction": "Flake the fish, discarding skin and bones. Peel and chop the eggs.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Combine and finish", "instruction": "Uncover the rice, remove the whole spices, fork in the fish and eggs, cover and return to the heat until the fish is heated through, then stir in most of the parsley and season.", "timer_seconds": 150, "background": true}, {"step": 9, "label": "Serve", "instruction": "Serve scattered with the remaining parsley and garnished with lemon wedges.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=QqdzDCWS4gQ"}, {"id": "52965", "name": "Breakfast Potatoes", "category": "Breakfast", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1550441882.jpg", "local_image": "52965.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "3 Medium"}, {"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Bacon", "measure": "2 strips"}, {"ingredient": "Garlic Clove", "measure": "Minced"}, {"ingredient": "Maple Syrup", "measure": "1 tbs"}, {"ingredient": "Parsley", "measure": "Garnish"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Allspice", "measure": "To taste"}], "instructions": "Before you do anything, freeze your bacon slices that way when you're ready to prep, it'll be so much easier to chop!\r\nWash the potatoes and cut medium dice into square pieces. To prevent any browning, place the already cut potatoes in a bowl filled with water.\r\nIn the meantime, heat 1-2 tablespoons of oil in a large skillet over medium-high heat. Tilt the skillet so the oil spreads evenly.\r\nOnce the oil is hot, drain the potatoes and add to the skillet. Season with salt, pepper, and Old Bay as needed.\r\nCook for 10 minutes, stirring the potatoes often, until brown. If needed, add a tablespoon more of oil.\r\nChop up the bacon and add to the potatoes. The bacon will start to render and the fat will begin to further cook the potatoes. Toss it up a bit! The bacon will take 5-6 minutes to crisp.\r\nOnce the bacon is cooked, reduce the heat to medium-low, add the minced garlic and toss. Season once more. Add dried or fresh parsley. Control heat as needed.\r\nLet the garlic cook until fragrant, about one minute.\r\nJust before serving, drizzle over the maple syrup and toss. Let that cook another minute, giving the potatoes a caramelized effect.\r\nServe in a warm bowl with a sunny side up egg!", "equipment_tags": [], "portions": 3, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 375, "protein_g": 16.1, "carbs_g": 35.1, "fat_g": 18.9, "total_kcal": 1126, "total_protein_g": 48.3, "total_carbs_g": 105.4, "total_fat_g": 56.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the potatoes", "instruction": "Wash the potatoes and cut into medium dice, placing them in water to prevent browning.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the potatoes", "instruction": "Heat oil in a large skillet over medium-high heat, drain the potatoes, add to the skillet, season, and cook, stirring often, until brown.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Add the bacon", "instruction": "Chop the bacon and add to the potatoes, tossing as it renders and crisps.", "timer_seconds": 360, "background": false}, {"step": 4, "label": "Add garlic and herbs", "instruction": "Reduce the heat to medium-low, add the minced garlic and toss, season again, and add parsley, cooking until the garlic is fragrant.", "timer_seconds": 60, "background": false}, {"step": 5, "label": "Finish and serve", "instruction": "Drizzle with maple syrup, toss, and cook a minute more for a caramelised effect. Serve in a warm bowl with a sunny-side-up egg.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=BoD0TIO9nE4"}, {"id": "52966", "name": "Chocolate Caramel Crispy", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1550442508.jpg", "local_image": "52966.jpg", "ingredients": [{"ingredient": "Mars Bar", "measure": "6 chopped"}, {"ingredient": "Butter", "measure": "150g"}, {"ingredient": "Rice Krispies", "measure": "120g"}, {"ingredient": "Milk Chocolate", "measure": "150g"}], "instructions": "Grease and line a 20 x 20cm/8\" x 8\" baking tin with parchment paper.\r\nPut the mars bars and butter in a heat proof bowl and place over a pan of barely simmering water. Mixing with a whisk, melt until the mixture is smooth.\r\nPour over the rice krispies in a mixing bowl and mix until all the ingredients are evenly combined. Press evenly into the prepare baking tin and set aside.\r\nMelt the milk chocolate in the microwave or over a pan of barely simmering water.\r\nSpread the melted chocolate over the rice krispie mixture and leave to set in a cool place. Once set slice into squares and serve!", "equipment_tags": [], "portions": 5, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 596, "protein_g": 5.0, "carbs_g": 63.1, "fat_g": 35.7, "total_kcal": 2978, "total_protein_g": 25.2, "total_carbs_g": 315.8, "total_fat_g": 178.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the tin", "instruction": "Grease and line a square baking tin with parchment paper.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Melt the Mars bar mixture", "instruction": "Melt the Mars bars and butter together in a heatproof bowl over a pan of barely simmering water, whisking until smooth.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Combine and press in", "instruction": "Pour over the rice krispies and mix until evenly combined, then press into the prepared tin.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Melt and spread the chocolate", "instruction": "Melt the milk chocolate, then spread over the rice krispie mixture.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Set and serve", "instruction": "Leave to set in a cool place, then slice into squares to serve.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=qsk_At_gjv0"}, {"id": "52967", "name": "Home-made Mandazi", "category": "Breakfast", "area": "Kenyan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/thazgm1555350962.jpg", "local_image": "52967.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "750g"}, {"ingredient": "Sugar", "measure": "6 tablespoons"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Milk", "measure": "1 cup"}], "instructions": "This is one recipe a lot of people have requested and I have tried to make it as simple as possible and I hope it will work for you. Make sure you use the right flour which is basically one with raising agents. Adjust the amount of sugar to your taste and try using different flavours to have variety whenever you have them.\r\nYou can use Coconut milk instead of regular milk, you can also add desiccated coconut to the dry flour or other spices like powdered cloves or cinnamon.\r\nFor “healthy looking” mandazis do not roll the dough too thin before frying and use the procedure I have indicated above.\r\n\r\n1. Mix the flour,cinnamon and sugar in a suitable bowl.\r\n2. In a separate bowl whisk the egg into the milk\r\n3. Make a well at the centre of the flour and add the milk and egg mixture and slowly mix to form a dough.\r\n4. Knead the dough for 3-4 minutes or until it stops sticking to the sides of the bowl and you have a smooth surface.\r\n5. Cover the dough with a damp cloth  and allow to rest for 15 minutes.\r\n6. Roll the dough on a lightly floured surface into a 1cm thick piece.\r\n7. Using a sharp small knife, cut the dough into the desired size setting aside ready for deep frying.\r\n8. Heat your oil in a suitable pot and gently dip the mandazi pieces to cook until light brown on the first side then turn to cook on the second side.\r\n9. Serve them warm or cold", "equipment_tags": [], "portions": 5, "prep_minutes": 19, "prep_minutes_source": "explicit", "kcal": 612, "protein_g": 18.4, "carbs_g": 133.3, "fat_g": 5.1, "total_kcal": 3060, "total_protein_g": 91.9, "total_carbs_g": 666.6, "total_fat_g": 25.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix dry and wet ingredients", "instruction": "Mix the flour, cinnamon and sugar in a bowl. In a separate bowl, whisk the egg into the milk.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the dough", "instruction": "Make a well in the flour, add the milk and egg mixture, and mix slowly to form a dough.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Knead", "instruction": "Knead the dough until it stops sticking to the bowl and is smooth.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Rest the dough", "instruction": "Cover with a damp cloth and let rest.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Roll and cut", "instruction": "Roll the dough out on a floured surface to about 1cm thick, then cut into the desired size for frying.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Fry", "instruction": "Heat oil and gently fry the mandazi pieces until light brown on the first side, then turn to cook the second side.", "timer_seconds": 300, "background": false}, {"step": 7, "label": "Serve", "instruction": "Serve warm or cold.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52968", "name": "Mbuzi Choma (Roasted Goat)", "category": "Goat", "area": "Kenyan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/cuio7s1555492979.jpg", "local_image": "52968.jpg", "ingredients": [{"ingredient": "Goat Meat", "measure": "1 kg"}, {"ingredient": "Corn Flour", "measure": "1 kg"}, {"ingredient": "Tomatoes", "measure": "2"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Coriander Leaves", "measure": "1  bunch"}], "instructions": "1. Steps for the Meat: \r\n Roast meat over medium heat for 50 minutes and salt it as you turn it.\r\n\r\n2. Steps for Ugali:\r\nBring the water and salt to a boil in a heavy-bottomed saucepan. Stir in the cornmeal slowly, letting it fall through the fingers of your hand.\r\n\r\n3. Reduce heat to medium-low and continue stirring regularly, smashing any lumps with a spoon, until the mush pulls away from the sides of the pot and becomes very thick, about 10 minutes.\r\n\r\n4.Remove from heat and allow to cool.\r\n\r\n5. Place the ugali into a large serving bowl. Wet your hands with water, form a ball and serve.\r\n\r\n6. Steps for Kachumbari: Mix the tomatoes, onions, chili and coriander leaves in a bowl.\r\n\r\n7. Serve and enjoy!\r\n\r\n", "equipment_tags": [], "portions": 5, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 1069, "protein_g": 55.5, "carbs_g": 186.7, "fat_g": 6.4, "total_kcal": 5347, "total_protein_g": 277.6, "total_carbs_g": 933.6, "total_fat_g": 31.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the goat meat", "instruction": "Roast the meat over medium heat, salting it as you turn it.", "timer_seconds": 3000, "background": true}, {"step": 2, "label": "Start the ugali", "instruction": "Bring water and salt to a boil in a heavy-bottomed saucepan, then stir in the cornmeal slowly, letting it fall through your fingers.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the ugali", "instruction": "Reduce to medium-low heat and stir regularly, smashing lumps, until the mush pulls away from the sides and becomes thick.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Shape and rest the ugali", "instruction": "Remove from heat and let cool slightly, then wet your hands, form into a ball, and place in a serving bowl.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Make the kachumbari", "instruction": "Mix the tomatoes, onions, chilli and coriander leaves together in a bowl.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve the roasted goat with the ugali and kachumbari.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52969", "name": "Chakchouka ", "category": "Miscellaneous", "area": "Tunisian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/gpz67p1560458984.jpg", "local_image": "52969.jpg", "ingredients": [{"ingredient": "Tomatoes", "measure": "4"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Green Pepper", "measure": "1 sliced"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "3/4 teaspoon"}, {"ingredient": "Chili Powder", "measure": "1/2 teaspoon"}, {"ingredient": "Eggs", "measure": "4"}], "instructions": "In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat. Add the onion and sauté for 2-3 minutes, until softened. Add the peppers and garlic, and sauté for an additional 3-5 minutes. Add the tomatoes, cumin, paprika, salt, and chili powder. Mix well and bring the mixture to a simmer. Reduce the heat to medium low and continue to simmer, uncovered, 10-15 minutes until the mixture has thickened to your desired consistency. (Taste the sauce at this point and adjust for salt and spice, as desired.) Using the back of a spoon, make four craters in the mixture, large enough to hold an egg. Crack one egg into each of the craters. Cover the skillet and simmer for 5-7 minutes, until the eggs have set. Serve immediately with crusty bread or pita.", "equipment_tags": [], "portions": 2, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 350, "protein_g": 16.7, "carbs_g": 18.6, "fat_g": 25.3, "total_kcal": 700, "total_protein_g": 33.3, "total_carbs_g": 37.3, "total_fat_g": 50.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Build the sauce", "instruction": "Heat the oil in a large skillet over medium-high heat, add the onion, and sauté until softened. Add the peppers and garlic and sauté further.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Simmer the sauce", "instruction": "Add the tomatoes, cumin, paprika, salt and chilli powder, bring to a simmer, then reduce heat and simmer uncovered until thickened to your liking.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Add and cook the eggs", "instruction": "Make four craters in the sauce, crack an egg into each, cover, and simmer until the eggs have set.", "timer_seconds": 360, "background": false}, {"step": 4, "label": "Serve", "instruction": "Serve immediately with crusty bread or pita.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=EHKNu93MSx4"}, {"id": "52970", "name": "Tunisian Orange Cake", "category": "Dessert", "area": "Tunisian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/y4jpgq1560459207.jpg", "local_image": "52970.jpg", "ingredients": [{"ingredient": "Orange", "measure": "1 large"}, {"ingredient": "Caster Sugar", "measure": "300g"}, {"ingredient": "Olive Oil", "measure": "75 ml"}, {"ingredient": "Flour", "measure": "280g"}, {"ingredient": "Baking Powder", "measure": "1 tbs"}, {"ingredient": "Eggs", "measure": "4 large"}, {"ingredient": "Vanilla Extract", "measure": "2 tsp"}], "instructions": "Preheat oven to 190 C / Gas 5. Grease a 23cm round springform tin.\r\nCut off the hard bits from the top and bottom of the orange. Slice the orange and remove all seeds. Puree the orange with its peel in a food processor. Add one third of the sugar and the olive oil and continue to mix until well combined.\r\nSieve together flour and baking powder.\r\nBeat the eggs and the remaining sugar with an electric hand mixer for at least five minutes until very fluffy. Fold in half of the flour mixture, then the orange and the vanilla, then fold in the remaining flour. Mix well but not for too long.\r\nPour cake mixture into prepared tin and smooth out. Bake in preheated oven for 20 minutes. Reduce the oven temperature to 160 C / Gas 2 and bake again for 30 minutes Bake until the cake is golden brown and a skewer comes out clean. Cool on a wire cake rack.", "equipment_tags": ["FoodProcessor"], "portions": 7, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 453, "protein_g": 7.9, "carbs_g": 76.6, "fat_g": 13.1, "total_kcal": 3174, "total_protein_g": 55.2, "total_carbs_g": 536.1, "total_fat_g": 91.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep the tin", "instruction": "Preheat the oven to 190°C/gas 5 and grease a springform tin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Purée the orange", "instruction": "Trim the orange, slice and deseed, then purée in a food processor with a third of the sugar and the olive oil.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Whip the eggs", "instruction": "Sieve together the flour and baking powder. Beat the eggs and remaining sugar with an electric mixer until very fluffy.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Fold together", "instruction": "Fold in half the flour mixture, then the orange purée and vanilla, then fold in the remaining flour.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Pour into the tin and bake, then reduce the oven temperature and continue baking until golden brown and a skewer comes out clean.", "timer_seconds": 3000, "background": true}, {"step": 6, "label": "Cool and serve", "instruction": "Cool on a wire rack before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=rCUxg866Ea4"}, {"id": "52971", "name": "Kafteji", "category": "Vegetarian", "area": "Tunisian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/1bsv1q1560459826.jpg", "local_image": "52971.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "5 Large"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Green Pepper", "measure": "1"}, {"ingredient": "Onions", "measure": "5"}, {"ingredient": "Ras el hanout", "measure": "1 tbs"}, {"ingredient": "Pumpkin", "measure": "500g"}, {"ingredient": "Eggs", "measure": "24 Skinned"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "Peel potatoes and cut into 5cm cubes.\r\nPour 1-2 cm of olive oil into a large pan and heat up very hot. Fry potatoes until golden brown for 20 minutes, turning from time to time. Place on kitchen paper to drain.\r\nCut the peppers in half and remove seeds. Rub a little olive oil on them and place the cut side down on a baking tray. Place them under the grill. Grill until the skin is dark and bubbly. While the peppers are still hot, put them into a plastic sandwich bag and seal it. Take them out after 15 minutes and remove skins.\r\nIn the meantime, heat more olive oil another pan. Peel the onions and cut into thin rings. Fry for 15 minutes until golden brown, turning them often. Add the Ras el hanout at the end.\r\nCut the pumpkin into 5cm cubes and fry in the same pan you used for the potatoes for 10-15 minutes until it is soft and slightly browned. Place on kitchen paper.\r\nPour the remaining olive oil out of the pan and put all the cooked vegetables into the pan and mix. Whisk eggs and pour them over the vegetables. Put the lid on the pan so that the eggs cook. Put the contents of the pan onto a large chopping board, add salt and pepper and chopped and mix everything with a big knife.", "equipment_tags": ["Grill"], "portions": 6, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 502, "protein_g": 31.0, "carbs_g": 42.1, "fat_g": 25.2, "total_kcal": 3011, "total_protein_g": 185.9, "total_carbs_g": 252.5, "total_fat_g": 151.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Fry the potatoes", "instruction": "Peel and cube the potatoes. Heat plenty of oil in a large pan and fry the potatoes until golden brown, turning occasionally, then drain on kitchen paper.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Grill the peppers", "instruction": "Halve and deseed the peppers, rub with oil, and grill cut-side down until the skin is dark and bubbly. Seal in a bag to steam, then peel.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Fry the onions", "instruction": "Meanwhile, heat more oil, peel and thinly slice the onions, and fry until golden brown, adding the ras el hanout at the end.", "timer_seconds": 900, "background": false}, {"step": 4, "label": "Fry the pumpkin", "instruction": "Cube the pumpkin and fry in the same pan used for the potatoes until soft and slightly browned, then drain.", "timer_seconds": 900, "background": false}, {"step": 5, "label": "Combine with eggs", "instruction": "Combine all the cooked vegetables in the pan. Whisk the eggs and pour over the vegetables, then cover with a lid so the eggs cook.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Finish and serve", "instruction": "Turn the contents onto a chopping board, season with salt and pepper, and chop and mix everything together with a large knife.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=-TFf-Zu-xQU"}, {"id": "52972", "name": "Tunisian Lamb Soup", "category": "Lamb", "area": "Tunisian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/t8mn9g1560460231.jpg", "local_image": "52972.jpg", "ingredients": [{"ingredient": "Lamb Mince", "measure": "500g"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Spinach", "measure": "300g"}, {"ingredient": "Tomato Puree", "measure": "3 tbs"}, {"ingredient": "Cumin", "measure": "1 tbs"}, {"ingredient": "Chicken Stock", "measure": "1 Litre"}, {"ingredient": "Harissa Spice", "measure": "3 tsp"}, {"ingredient": "Chickpeas", "measure": "400g"}, {"ingredient": "Lemon Juice", "measure": "1/2"}, {"ingredient": "Macaroni", "measure": "150g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "Add the lamb to a casserole and cook over high heat. When browned, remove from the heat and set aside.\r\nKeep a tablespoon of fat in the casserole and discard the rest. Reduce to medium heat then add the garlic, onion and spinach and cook until the onion is translucent and the spinach wilted or about 5 minutes.\r\nReturn the lamb to the casserole with the onion-spinach mixture, add the tomato puree, cumin, harissa, chicken, chickpeas, lemon juice, salt and pepper in the pan. Simmer over low heat for about 20 minutes.\r\nAdd the pasta and cook for 15 minutes or until pasta is cooked.", "equipment_tags": [], "portions": 5, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 582, "protein_g": 34.1, "carbs_g": 54.2, "fat_g": 25.9, "total_kcal": 2912, "total_protein_g": 170.6, "total_carbs_g": 271.1, "total_fat_g": 129.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the lamb", "instruction": "Add the lamb to a casserole and cook over high heat until browned, then remove and set aside.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Cook the aromatics", "instruction": "Keep a tablespoon of fat in the casserole, reduce to medium heat, add the garlic, onion and spinach, and cook until the onion is translucent and spinach wilted.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the soup", "instruction": "Return the lamb to the pan with the onion-spinach mixture, add the tomato purée, cumin, harissa, stock, chickpeas, lemon juice, salt and pepper, and simmer.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Cook the pasta and finish", "instruction": "Add the macaroni and cook until tender.", "timer_seconds": 900, "background": false}], "video": "https://www.youtube.com/watch?v=w1qgTQmLRe4"}, {"id": "52973", "name": "Leblebi Soup", "category": "Vegetarian", "area": "Tunisian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/x2fw9e1560460636.jpg", "local_image": "52973.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 medium finely diced"}, {"ingredient": "Chickpeas", "measure": "250g"}, {"ingredient": "Vegetable Stock", "measure": "1.5L"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Garlic", "measure": "5 cloves"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Harissa Spice", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Lime", "measure": "1/2"}], "instructions": "Heat the oil in a large pot. Add the onion and cook until translucent.\r\nDrain the soaked chickpeas and add them to the pot together with the vegetable stock. Bring to the boil, then reduce the heat and cover. Simmer for 30 minutes.\r\nIn the meantime toast the cumin in a small ungreased frying pan, then grind them in a mortar. Add the garlic and salt and pound to a fine paste.\r\nAdd the paste and the harissa to the soup and simmer until the chickpeas are tender, about 30 minutes.\r\nSeason to taste with salt, pepper and lemon juice and serve hot.", "equipment_tags": [], "portions": 4, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 208, "protein_g": 8.3, "carbs_g": 25.3, "fat_g": 9.3, "total_kcal": 831, "total_protein_g": 33.3, "total_carbs_g": 101.0, "total_fat_g": 37.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Heat the oil in a large pot and cook the onion until translucent.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Simmer the chickpeas", "instruction": "Drain the soaked chickpeas and add to the pot with the vegetable stock, bring to a boil, then reduce heat, cover, and simmer.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Make the spice paste", "instruction": "Meanwhile, toast the cumin in a dry pan, grind in a mortar, then add the garlic and salt and pound to a fine paste.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Simmer further", "instruction": "Add the spice paste and harissa to the soup and simmer until the chickpeas are tender.", "timer_seconds": 1800, "background": true}, {"step": 5, "label": "Serve", "instruction": "Season to taste with salt, pepper and lemon juice, then serve hot.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=BgRifcCwinY"}, {"id": "52974", "name": "Keleya Zaara", "category": "Lamb", "area": "Tunisian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8x09hy1560460923.jpg", "local_image": "52974.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "4 tbs"}, {"ingredient": "Lamb", "measure": "750g"}, {"ingredient": "Saffron", "measure": "1 1/2 tsp"}, {"ingredient": "Onion", "measure": "1 Large Chopped"}, {"ingredient": "Water", "measure": "25 ml"}, {"ingredient": "Parsley", "measure": "30g"}, {"ingredient": "Butter", "measure": "1 tbs"}, {"ingredient": "Lemon", "measure": "1"}], "instructions": "Heat the vegetable oil in a large frying pan over medium-high heat. Add the lamb and cook until browned on all sides, about 5 minutes. Season with saffron, salt and pepper to taste; stir in all but 4 tablespoons of the onion, and pour in the water. Bring to the boil, then cover, reduce heat to medium-low, and simmer until the lamb is tender, about 15 minutes.\r\nUncover the pan, stir in the butter and allow the sauce reduce 5 to 10 minutes to desired consistency. Season to taste with salt and pepper, then pour into a serving dish. Sprinkle with the remaining chopped onions and parsley. Garnish with lemon wedges to serve.\r\n", "equipment_tags": [], "portions": 2, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 1446, "protein_g": 95.6, "carbs_g": 11.3, "fat_g": 112.7, "total_kcal": 2892, "total_protein_g": 191.3, "total_carbs_g": 22.6, "total_fat_g": 225.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the lamb", "instruction": "Heat the oil in a large frying pan over medium-high heat, add the lamb, and cook until browned on all sides.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Simmer", "instruction": "Season with saffron, salt and pepper, stir in most of the onion, pour in the water, bring to the boil, then cover, reduce heat, and simmer until the lamb is tender.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Reduce the sauce", "instruction": "Uncover, stir in the butter, and let the sauce reduce to the desired consistency.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Serve", "instruction": "Season to taste, pour into a serving dish, sprinkle with the remaining onions and parsley, and garnish with lemon wedges.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=u_OSIChzuL0"}, {"id": "52975", "name": "Tuna and Egg Briks", "category": "Seafood", "area": "Tunisian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/2dsltq1560461468.jpg", "local_image": "52975.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Spring Onions", "measure": "8"}, {"ingredient": "Spinach", "measure": "200g"}, {"ingredient": "Filo Pastry", "measure": "4"}, {"ingredient": "Tuna", "measure": "1 can"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Hotsauce", "measure": "Dash"}, {"ingredient": "Tomatoes", "measure": "4 Chopped"}, {"ingredient": "Cucumber", "measure": "1/4"}, {"ingredient": "Lemon Juice", "measure": "1 tbs"}, {"ingredient": "Apricot Jam", "measure": "4 tbs"}], "instructions": "Heat 2 tsp of the oil in a large saucepan and cook the spring onions over a low heat for 3 minutes or until beginning to soften. Add the spinach, cover with a tight-fitting lid and cook for a further 2–3 minutes or until tender and wilted, stirring once or twice. Tip the mixture into a sieve or colander and leave to drain and cool.\r\nUsing a saucer as a guide, cut out 24 rounds about 12.5 cm (5 in) in diameter from the filo pastry, cutting 6 rounds from each sheet. Stack the filo rounds in a pile, then cover with cling film to prevent them from drying out.\r\nWhen the spinach mixture is cool, squeeze out as much excess liquid as possible, then transfer to a bowl. Add the tuna, eggs, hot pepper sauce, and salt and pepper to taste. Mix well.\r\nPreheat the oven to 200°C (400°F, gas mark 6). Take one filo round and very lightly brush with some of the remaining oil. Top with a second round and brush with a little oil, then place a third round on top and brush with oil.\r\nPlace a heaped tbsp of the filling in the middle of the round, then fold the pastry over to make a half-moon shape. Fold in the edges, twisting them to seal, and place on a non-stick baking sheet. Repeat with the remaining pastry and filling to make 8 briks in all.\r\nLightly brush the briks with the remaining oil. Bake for 12–15 minutes or until the pastry is crisp and golden brown.\r\nMeanwhile, combine the tomatoes and cucumber in a bowl and sprinkle with the lemon juice and seasoning to taste. Serve the briks hot with this salad and the chutney.", "equipment_tags": [], "portions": 5, "prep_minutes": 21, "prep_minutes_source": "explicit", "kcal": 399, "protein_g": 29.8, "carbs_g": 42.5, "fat_g": 13.4, "total_kcal": 1997, "total_protein_g": 149.2, "total_carbs_g": 212.3, "total_fat_g": 67.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the spring onions and spinach", "instruction": "Heat the oil in a saucepan and cook the spring onions gently until beginning to soften, then add the spinach, cover and cook until tender and wilted.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Drain and cool", "instruction": "Tip the mixture into a sieve or colander to drain and cool.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Cut the pastry rounds", "instruction": "Cut 24 rounds from the filo sheets and stack, covering with cling film to prevent drying.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the filling", "instruction": "Squeeze out excess liquid from the cooled spinach, then mix with the tuna, eggs, hot pepper sauce, salt and pepper.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Assemble the briks", "instruction": "Preheat the oven to 200°C/400°F/gas 6. Layer and brush 3 filo rounds with oil, add filling in the middle, fold into a half-moon and seal by twisting the edges. Repeat to make 8 briks.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake", "instruction": "Brush the briks with the remaining oil and bake until crisp and golden brown.", "timer_seconds": 810, "background": true}, {"step": 7, "label": "Serve", "instruction": "Meanwhile combine the tomatoes and cucumber with lemon juice and seasoning. Serve the briks hot with the salad and chutney.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=C5n1fN8TGHs"}, {"id": "52976", "name": "Cashew Ghoriba Biscuits", "category": "Dessert", "area": "Tunisian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/t3r3ka1560461972.jpg", "local_image": "52976.jpg", "ingredients": [{"ingredient": "Cashew Nuts", "measure": "250g"}, {"ingredient": "Icing Sugar", "measure": "100g"}, {"ingredient": "Egg Yolks", "measure": "2"}, {"ingredient": "Orange Blossom Water", "measure": "2 tbs"}, {"ingredient": "Icing Sugar", "measure": "To Glaze"}, {"ingredient": "Almonds", "measure": "100g"}], "instructions": "Preheat the oven at 180 C / Gas 4. Line a baking tray with greaseproof paper.\r\nIn a bowl, mix the cashews and icing sugar. Add the egg yolks and orange blossom water and mix to a smooth homogeneous paste.\r\nTake lumps of the cashew paste and shape into small balls. Roll the balls in icing sugar and transfer to the baking tray. Push an almond in the centre of each ghribia.\r\nBake until the biscuits are lightly golden, about 20 minutes. Keep an eye on them, they burn quickly.", "equipment_tags": [], "portions": 4, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 701, "protein_g": 20.6, "carbs_g": 58.5, "fat_g": 46.8, "total_kcal": 2803, "total_protein_g": 82.3, "total_carbs_g": 234.2, "total_fat_g": 187.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Preheat the oven to 180°C/gas 4 and line a baking tray.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the paste", "instruction": "Mix the cashews and icing sugar in a bowl, add the egg yolks and orange blossom water, and mix into a smooth paste.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Shape the biscuits", "instruction": "Shape lumps of the paste into small balls, roll in icing sugar, place on the tray, and press an almond into the centre of each.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Bake until lightly golden, watching closely as they burn quickly.", "timer_seconds": 1200, "background": true}], "video": "https://www.youtube.com/watch?v=IqXEZUk4hWI"}, {"id": "52977", "name": "Corba", "category": "Side", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/58oia61564916529.jpg", "local_image": "52977.jpg", "ingredients": [{"ingredient": "Lentils", "measure": "1 cup"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Carrots", "measure": "1 large"}, {"ingredient": "Tomato Puree", "measure": "1 tbs"}, {"ingredient": "Cumin", "measure": "2 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Mint", "measure": "1/2 tsp"}, {"ingredient": "Thyme", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Red Pepper Flakes", "measure": "1/4 tsp"}, {"ingredient": "Vegetable Stock", "measure": "4 cups"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Sea Salt", "measure": "Pinch"}], "instructions": "Pick through your lentils for any foreign debris, rinse them 2 or 3 times, drain, and set aside.  Fair warning, this will probably turn your lentils into a solid block that you’ll have to break up later\r\nIn a large pot over medium-high heat, sauté the olive oil and the onion with a pinch of salt for about 3 minutes, then add the carrots and cook for another 3 minutes.\r\nAdd the tomato paste and stir it around for around 1 minute. Now add the cumin, paprika, mint, thyme, black pepper, and red pepper as quickly as you can and stir for 10 seconds to bloom the spices. Congratulate yourself on how amazing your house now smells.\r\nImmediately add the lentils, water, broth, and salt. Bring the soup to a (gentle) boil.\r\nAfter it has come to a boil, reduce heat to medium-low, cover the pot halfway, and cook for 15-20 minutes or until the lentils have fallen apart and the carrots are completely cooked.\r\nAfter the soup has cooked and the lentils are tender, blend the soup either in a blender or simply use a hand blender to reach the consistency you desire. Taste for seasoning and add more salt if necessary.\r\nServe with crushed-up crackers, torn up bread, or something else to add some extra thickness.  You could also use a traditional thickener (like cornstarch or flour), but I prefer to add crackers for some texture and saltiness.  Makes great leftovers, stays good in the fridge for about a week.", "equipment_tags": ["Blender"], "portions": 9, "prep_minutes": 27, "prep_minutes_source": "explicit", "kcal": 52, "protein_g": 3.5, "carbs_g": 9.2, "fat_g": 0.6, "total_kcal": 466, "total_protein_g": 31.7, "total_carbs_g": 82.6, "total_fat_g": 5.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the lentils", "instruction": "Pick over the lentils for debris, rinse a couple of times, and drain.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the onion and carrots", "instruction": "Sauté the onion in oil with a pinch of salt, then add the carrots and cook further.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Add spices", "instruction": "Add the tomato paste and stir, then add the cumin, paprika, mint, thyme, black pepper and red pepper and stir briefly to bloom the spices.", "timer_seconds": 70, "background": false}, {"step": 4, "label": "Simmer the soup", "instruction": "Add the lentils, water, broth and salt, bring to a gentle boil, then reduce heat, cover halfway, and cook until the lentils have fallen apart and carrots are tender.", "timer_seconds": 1050, "background": true}, {"step": 5, "label": "Blend and serve", "instruction": "Blend the soup to your desired consistency, adjust seasoning, and serve with crackers or bread.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=VVnZd8A84z4"}, {"id": "52978", "name": "Kumpir", "category": "Side", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/mlchx21564916997.jpg", "local_image": "52978.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "2 large"}, {"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Cheese", "measure": "150g"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Red Pepper", "measure": "1 large"}, {"ingredient": "Red Chilli Flakes", "measure": "Pinch"}], "instructions": "If you order kumpir in Turkey, the standard filling is first, lots of butter mashed into the potato, followed by cheese. There’s then a row of other toppings that you can just point at to your heart’s content – sweetcorn, olives, salami, coleslaw, Russian salad, allsorts – and you walk away with an over-stuffed potato because you got ever-excited by the choices on offer.\r\n\r\nGrate (roughly – you can use as much as you like) 150g of cheese.\r\nFinely chop one onion and one sweet red pepper.\r\nPut these ingredients into a large bowl with a good sprinkling of salt and pepper, chilli flakes (optional).", "equipment_tags": [], "portions": 4, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 259, "protein_g": 11.1, "carbs_g": 17.8, "fat_g": 16.4, "total_kcal": 1038, "total_protein_g": 44.3, "total_carbs_g": 71.2, "total_fat_g": 65.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Bake the potatoes", "instruction": "Bake the potatoes until soft all the way through.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Prep the fillings", "instruction": "Grate the cheese and finely chop the onion and red pepper. Combine in a bowl with a good sprinkling of salt, pepper and chilli flakes if using.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fill and serve", "instruction": "Split open the baked potatoes, mash a generous amount of butter into the flesh, then top with the cheese followed by the onion and pepper mixture and any other toppings you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=IEDEtZ4UVtI"}, {"id": "52979", "name": "Bitterballen (Dutch meatballs)", "category": "Beef", "area": "Netherlands", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/lhqev81565090111.jpg", "local_image": "52979.jpg", "ingredients": [{"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Flour", "measure": "150g"}, {"ingredient": "Beef Stock", "measure": "700ml"}, {"ingredient": "Onion", "measure": "30g"}, {"ingredient": "Parsley", "measure": "1 tbs"}, {"ingredient": "Beef", "measure": "400g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Nutmeg", "measure": "Pinch"}, {"ingredient": "Flour", "measure": "50g"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Breadcrumbs", "measure": "50g"}], "instructions": "Melt the butter in a skillet or pan. When melted, add the flour little by little and stir into a thick paste. Slowly stir in the stock, making sure the roux absorbs the liquid. Simmer for a couple of minutes on a low heat while you stir in the onion, parsley and the shredded meat. The mixture should thicken and turn into a heavy, thick sauce.\r\n\r\nPour the mixture into a shallow container, cover and refrigerate for several hours, or until the sauce has solidified.\r\n\r\nTake a heaping tablespoon of the cold, thick sauce and quickly roll it into a small ball. Roll lightly through the flour, then the egg and finally the breadcrumbs. Make sure that the egg covers the whole surface of the bitterbal. When done, refrigerate the snacks while the oil in your fryer heats up to 190C (375F). Fry four bitterballen at a time, until golden.\r\n\r\nServe on a plate with a nice grainy or spicy mustard. \r\n", "equipment_tags": [], "portions": 3, "prep_minutes": 46, "prep_minutes_source": "estimated", "kcal": 854, "protein_g": 41.6, "carbs_g": 66.1, "fat_g": 46.9, "total_kcal": 2562, "total_protein_g": 124.8, "total_carbs_g": 198.4, "total_fat_g": 140.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the roux and stock base", "instruction": "Melt the butter in a skillet, add the flour a little at a time, and stir into a thick paste, then slowly stir in the stock.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Add the meat and simmer", "instruction": "Simmer on low heat while stirring in the onion, parsley and shredded meat, until thickened into a heavy sauce.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Chill", "instruction": "Pour into a shallow container, cover and refrigerate until solidified.", "timer_seconds": 14400, "background": true}, {"step": 4, "label": "Shape and coat", "instruction": "Roll tablespoons of the cold sauce into balls, then coat in flour, egg and breadcrumbs, making sure the egg covers the whole surface.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Chill and fry", "instruction": "Refrigerate the coated balls while the oil heats to 190°C/375°F, then fry a few at a time until golden.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve with grainy or spicy mustard.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=q8AKfYUtDuM"}, {"id": "52980", "name": "Stamppot", "category": "Pork", "area": "Netherlands", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/hyarod1565090529.jpg", "local_image": "52980.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1.5kg"}, {"ingredient": "Bay Leaf", "measure": "2 leaves"}, {"ingredient": "Shallots", "measure": "2"}, {"ingredient": "Butter", "measure": "3 tbs"}, {"ingredient": "Kale", "measure": "750g"}, {"ingredient": "Sausages", "measure": "2"}, {"ingredient": "Milk", "measure": "500ml"}, {"ingredient": "Nutmeg", "measure": "Grated"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "\r\nWash and peel the potatoes and cut into similarly sized pieces for even cooking.\r\n\r\nIn a large soup pot, boil the potatoes and the bay leaves in salted water for 20 minutes. Discard the bay leaves.\r\n\r\nIf you're not using a bag of ready-cut curly kale, wash the bunches thoroughly under cool running water to get rid of all soil—you wouldn't want that gritty texture in your finished dish. Trim any coarse stems and discard any brown leaves. With a sharp knife, cut the curly kale into thin strips.\r\n\r\nPeel and chop the shallots.\r\n\r\nIn a frying pan or skillet, melt 1 tbsp. of butter and saute the shallots for a few minutes before adding the curly kale and 2 tbsp. of water. Season and cook for about 10 minutes, or until tender.\r\n\r\nWarm the milk on the stove or in the microwave.\r\n\r\nDrain, shake and dry the potatoes with kitchen towels before mashing with a potato masher or ricer. Working quickly, add the warm milk and the remaining butter. Season to taste with nutmeg, salt, and pepper. \r\n\r\nMix the cooked curly kale through the cooked mashed potato mixture.\r\n\r\nTop with slices of the smoked sausage and serve hot with your favorite mustard or gravy.\r\n\r\nServe and enjoy!", "equipment_tags": [], "portions": 6, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 420, "protein_g": 15.7, "carbs_g": 61.0, "fat_g": 14.4, "total_kcal": 2518, "total_protein_g": 94.3, "total_carbs_g": 366.1, "total_fat_g": 86.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil the potatoes", "instruction": "Wash and peel the potatoes, cut into even pieces, and boil with bay leaves in salted water until tender, then discard the bay leaves.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Prep the kale", "instruction": "Wash and trim the kale, discarding coarse stems and brown leaves, and cut into thin strips.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the kale", "instruction": "Sauté the chopped shallots in butter, then add the kale and a splash of water, season, and cook until tender.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Mash the potatoes", "instruction": "Warm the milk. Drain and dry the potatoes, mash, then add the warm milk and remaining butter, seasoning with nutmeg, salt and pepper.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Combine and serve", "instruction": "Mix the cooked kale through the mashed potato, top with sliced sausage, and serve hot with mustard or gravy.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=hTrSXryX31A"}, {"id": "52981", "name": "Snert (Dutch Split Pea Soup)", "category": "Side", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/9ptx0a1565090843.jpg", "local_image": "52981.jpg", "ingredients": [{"ingredient": "Water", "measure": "2L"}, {"ingredient": "Peas", "measure": "300g"}, {"ingredient": "Pork", "measure": "100g"}, {"ingredient": "Vegetable Stock Cube", "measure": "1"}, {"ingredient": "Celery", "measure": "2"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Potatoes", "measure": "1 large"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Leek", "measure": "1 small"}, {"ingredient": "Celeriac", "measure": "1 cup"}, {"ingredient": "Sausages", "measure": "1 pound"}], "instructions": "Gather the ingredients.\r\n\r\nIn a large soup pot, bring water, split peas, pork belly or bacon, pork chop, and bouillon cube to a boil. Reduce the heat to a simmer, cover and let cook for 45 minutes, stirring occasionally and skimming off any foam that rises to the top. \r\n\r\nRemove the pork chop, debone, and thinly slice the meat. Set aside.\r\n\r\nAdd the celery, carrots, potato, onion, leek, and celeriac to the soup. Return to the boil, reduce the heat to a simmer and let cook, uncovered, for another 30 minutes, adding a little extra water if the ingredients start to stick to the bottom of the pot.\r\n\r\nAdd the smoked sausage for the last 15 minutes of cooking time. When the vegetables are tender, remove the bacon and smoked sausage, slice thinly and set aside.\r\n\r\nIf you prefer a smooth consistency, purée the soup with a stick blender. Season to taste with salt and pepper. Add the meat back to the soup, setting some slices of rookworst aside.\r\n\r\nServe in heated bowls or soup plates, garnished with slices of rookworst and chopped celery leaf.\r\n\r\nEnjoy!", "equipment_tags": ["Blender"], "portions": 12, "prep_minutes": 90, "prep_minutes_source": "explicit", "kcal": 178, "protein_g": 8.8, "carbs_g": 11.6, "fat_g": 10.7, "total_kcal": 2138, "total_protein_g": 106.2, "total_carbs_g": 139.2, "total_fat_g": 128.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Start the soup", "instruction": "In a large pot, bring the water, split peas, pork and bouillon cube to a boil, then reduce to a simmer, cover, and cook, stirring occasionally and skimming foam.", "timer_seconds": 2700, "background": true}, {"step": 2, "label": "Debone the pork", "instruction": "Remove the pork, debone, and thinly slice, then set aside.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Add the vegetables", "instruction": "Add the celery, carrots, potato, onion, leek and celeriac, return to the boil, then reduce to a simmer and cook uncovered, adding water if it sticks.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Add the sausage", "instruction": "Add the smoked sausage for the last part of cooking, then remove the pork and sausage, slice thinly, and set aside once the vegetables are tender.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Purée and finish", "instruction": "If you prefer a smooth soup, purée with a stick blender. Season to taste and stir the meat back in, reserving some sausage slices for garnish.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve in heated bowls garnished with sausage slices and chopped celery leaf.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=5YV0sJLtLt8"}, {"id": "52982", "name": "Spaghetti alla Carbonara", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/llcbn01574260722.jpg", "local_image": "52982.jpg", "ingredients": [{"ingredient": "Spaghetti", "measure": "320g"}, {"ingredient": "Egg Yolks", "measure": "6"}, {"ingredient": "Salt", "measure": "As required"}, {"ingredient": "Bacon", "measure": "150g"}, {"ingredient": "Pecorino", "measure": "50g"}, {"ingredient": "Black Pepper", "measure": "As required"}], "instructions": "STEP 1\r\nPut a large saucepan of water on to boil.\r\n\r\nSTEP 2\r\nFinely chop the 100g pancetta, having first removed any rind. Finely grate 50g pecorino cheese and 50g parmesan and mix them together.\r\n\r\nSTEP 3\r\nBeat the 3 large eggs in a medium bowl and season with a little freshly grated black pepper. Set everything aside.\r\n\r\nSTEP 4\r\nAdd 1 tsp salt to the boiling water, add 350g spaghetti and when the water comes back to the boil, cook at a constant simmer, covered, for 10 minutes or until al dente (just cooked).\r\n\r\nSTEP 5\r\nSquash 2 peeled plump garlic cloves with the blade of a knife, just to bruise it.\r\n\r\nSTEP 6\r\nWhile the spaghetti is cooking, fry the pancetta with the garlic. Drop 50g unsalted butter into a large frying pan or wok and, as soon as the butter has melted, tip in the pancetta and garlic.\r\n\r\nSTEP 7\r\nLeave to cook on a medium heat for about 5 minutes, stirring often, until the pancetta is golden and crisp. The garlic has now imparted its flavour, so take it out with a slotted spoon and discard.\r\n\r\nSTEP 8\r\nKeep the heat under the pancetta on low. When the pasta is ready, lift it from the water with a pasta fork or tongs and put it in the frying pan with the pancetta. Don’t worry if a little water drops in the pan as well (you want this to happen) and don’t throw the pasta water away yet.\r\n\r\nSTEP 9\r\nMix most of the cheese in with the eggs, keeping a small handful back for sprinkling over later.\r\n\r\nSTEP 10\r\nTake the pan of spaghetti and pancetta off the heat. Now quickly pour in the eggs and cheese. Using the tongs or a long fork, lift up the spaghetti so it mixes easily with the egg mixture, which thickens but doesn’t scramble, and everything is coated.\r\n\r\nSTEP 11\r\nAdd extra pasta cooking water to keep it saucy (several tablespoons should do it). You don’t want it wet, just moist. Season with a little salt, if needed.\r\n\r\nSTEP 12\r\nUse a long-pronged fork to twist the pasta on to the serving plate or bowl. Serve immediately with a little sprinkling of the remaining cheese and a grating of black pepper. If the dish does get a little dry before serving, splash in some more hot pasta water and the glossy sauciness will be revived.", "equipment_tags": [], "portions": 6, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 527, "protein_g": 26.4, "carbs_g": 42.6, "fat_g": 27.3, "total_kcal": 3163, "total_protein_g": 158.2, "total_carbs_g": 255.3, "total_fat_g": 163.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil water for pasta", "instruction": "Put a large saucepan of water on to boil.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Prep the pancetta and cheese", "instruction": "Finely chop the pancetta, and finely grate the pecorino and parmesan, mixing them together.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Prep the eggs", "instruction": "Beat the eggs in a bowl and season with black pepper. Set aside.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the spaghetti", "instruction": "Add salt to the boiling water, add the spaghetti, and cook at a constant simmer, covered, until al dente.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Fry the pancetta", "instruction": "Meanwhile, bruise the garlic. Melt the butter in a large frying pan, add the pancetta and garlic, and cook, stirring often, until golden and crisp, discarding the garlic once it has flavoured the fat.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Combine pasta and pancetta", "instruction": "Lift the cooked spaghetti into the pan with the pancetta, along with a little pasta water.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Mix cheese into eggs", "instruction": "Mix most of the cheese into the eggs, keeping some back for serving.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Emulsify off the heat", "instruction": "Take the pan off the heat, pour in the eggs and cheese, and toss the spaghetti so the mixture thickens without scrambling, coating everything.", "timer_seconds": null, "background": false}, {"step": 9, "label": "Loosen and serve", "instruction": "Add extra pasta water to keep it saucy, season if needed, then plate and serve immediately with the remaining cheese and black pepper.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_T6jkRvhlkk"}, {"id": "52987", "name": "Lasagna Sandwiches", "category": "Pasta", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xr0n4r1576788363.jpg", "local_image": "52987.jpg", "ingredients": [{"ingredient": "Sour Cream", "measure": "1/4 cup"}, {"ingredient": "Chopped Onion", "measure": "2 tbs"}, {"ingredient": "Dried Oregano", "measure": "1/2 tbs"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Bread", "measure": "8 slices"}, {"ingredient": "Bacon", "measure": "8 slices"}, {"ingredient": "Tomato", "measure": "8 slices"}, {"ingredient": "Mozzarella", "measure": "4 slices"}, {"ingredient": "Butter", "measure": "2 1/2 Tbs"}], "instructions": "1. In a small bowl, combine the first four ingredients; spread on four slices of bread. Layer with bacon, tomato and cheese; top with remaining bread.\r\n\r\n2. In a large skillet or griddle, melt 2 tablespoons butter. Toast sandwiches until lightly browned on both sides and cheese is melted, adding butter if necessary.\r\n\r\nNutrition Facts\r\n1 sandwich: 445 calories, 24g fat (12g saturated fat), 66mg cholesterol, 1094mg sodium, 35g carbohydrate (3g sugars, 2g fiber), 21g protein.", "equipment_tags": [], "portions": 6, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 389, "protein_g": 20.8, "carbs_g": 20.4, "fat_g": 24.8, "total_kcal": 2337, "total_protein_g": 124.6, "total_carbs_g": 122.5, "total_fat_g": 148.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the spread and assemble", "instruction": "Combine the sour cream, onion, oregano and salt in a small bowl, and spread on four slices of bread. Layer with bacon, tomato and cheese, then top with the remaining bread.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Grill the sandwiches", "instruction": "Melt butter in a large skillet or griddle and toast the sandwiches until lightly browned on both sides and the cheese is melted, adding more butter as needed.", "timer_seconds": 480, "background": false}], "video": null}, {"id": "52988", "name": "Classic Christmas pudding", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1d85821576790598.jpg", "local_image": "52988.jpg", "ingredients": [{"ingredient": "Almonds", "measure": "50g"}, {"ingredient": "Bramley Apples", "measure": "2 large"}, {"ingredient": "Candied Peel", "measure": "200g"}, {"ingredient": "Nutmeg", "measure": "1 whole"}, {"ingredient": "Raisins", "measure": "1kg"}, {"ingredient": "Plain Flour", "measure": "140g"}, {"ingredient": "Breadcrumbs", "measure": "100g"}, {"ingredient": "Muscovado Sugar", "measure": "100g"}, {"ingredient": "Eggs", "measure": "3 Large"}, {"ingredient": "Brandy", "measure": "2 tbs"}, {"ingredient": "Butter", "measure": "250g"}], "instructions": "Get everything for the pudding prepared. Chop the almonds coarsely. Peel, core and chop the cooking apples. Sharpen your knife and chop the candied peel. (You can chop the almonds and apples in a food processor, but the peel must be done by hand.) Grate three quarters of the nutmeg (sounds a lot but it's correct).\r\n\r\nMix the almonds, apples, candied peel, nutmeg, raisins, flour, breadcrumbs, light muscovado sugar, eggs and 2 tbsp brandy or cognac in a large bowl. \r\n\r\nHolding the butter in its wrapper, grate a quarter of it into the bowl, then stir everything together. Repeat until all the butter is grated, then stir for 3-4 mins – the mixture is ready when it subsides slightly after each stir. Ask the family to stir too, and get everyone to make a wish. \r\n\r\nGenerously butter two 1.2 litre bowls and put a circle of baking parchment in the bottom of each. Pack in the pudding mixture. Cover with a double layer of baking parchment, pleating it to allow for expansion, then tie with string (keep the paper in place with a rubber band while tying). Trim off any excess paper. \r\n\r\nNow stand each bowl on a large sheet of foil and bring the edges up over the top, then put another sheet of foil over the top and bring it down underneath to make a double package (this makes the puddings watertight). Tie with more string, and make a handle for easy lifting in and out of the pan. Watch our video to see how to tie up a pudding correctly.\r\n\r\nBoil or oven steam the puddings for 8 hrs, topping up with water as necessary. Remove from the pans and leave to cool overnight. When cold, discard the messy wrappings and re-wrap in new baking parchment, foil and string. Store in a cool, dry place until Christmas. \r\n\r\nTo make the brandy butter, cream the butter with the orange zest and icing sugar. Gradually beat in the brandy or cognac and chopped stem ginger. Put in a small bowl, fork the top attractively and put in the fridge to set. The butter will keep for a week in the fridge, or it can be frozen for up to six weeks. \r\n\r\nOn Christmas Day, boil or oven steam for 1 hr. Unwrap and turn out. To flame, warm 3-4 tbsp brandy in a small pan, pour it over the pudding and set light to it.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 600, "protein_g": 7.6, "carbs_g": 101.5, "fat_g": 21.3, "total_kcal": 7198, "total_protein_g": 91.6, "total_carbs_g": 1217.8, "total_fat_g": 255.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the ingredients", "instruction": "Chop the almonds coarsely, peel, core and chop the apples, chop the candied peel by hand, and grate three quarters of the nutmeg.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Mix the dry mixture", "instruction": "Mix the almonds, apples, candied peel, nutmeg, raisins, flour, breadcrumbs, sugar, eggs and brandy in a large bowl.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Grate in the butter", "instruction": "Grate the butter into the bowl a quarter at a time, stirring well between additions until the mixture subsides slightly with each stir.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Pack into bowls", "instruction": "Butter two pudding bowls, line the bottoms with parchment, pack in the mixture, cover with pleated parchment, tie with string, and wrap in a double layer of foil.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Steam", "instruction": "Boil or oven steam the puddings, topping up the water as needed.", "timer_seconds": 28800, "background": true}, {"step": 6, "label": "Cool and store", "instruction": "Remove from the pans and leave to cool overnight, then re-wrap in fresh parchment, foil and string and store in a cool, dry place until Christmas.", "timer_seconds": null, "background": true}, {"step": 7, "label": "Make the brandy butter", "instruction": "Cream the butter with orange zest and icing sugar, gradually beat in the brandy and stem ginger, then chill until set.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Reheat and flame to serve", "instruction": "On the day, boil or oven steam the pudding again, unwrap and turn out. To flame, warm brandy in a small pan, pour over the pudding, and light it.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=Pb_lJxL1vtk"}, {"id": "52989", "name": "Christmas Pudding Trifle", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/r33cud1576791081.jpg", "local_image": "52989.jpg", "ingredients": [{"ingredient": "Orange", "measure": "3"}, {"ingredient": "Demerara Sugar", "measure": "1 tbs"}, {"ingredient": "Grand Marnier", "measure": "2 tbs"}, {"ingredient": "Christmas Pudding", "measure": "300g"}, {"ingredient": "Custard", "measure": "500g"}, {"ingredient": "Mascarpone", "measure": "250g"}, {"ingredient": "Double Cream", "measure": "284ml"}, {"ingredient": "Flaked Almonds", "measure": "Handful"}, {"ingredient": "Dark Chocolate", "measure": "Grated"}], "instructions": "Peel the oranges using a sharp knife, ensuring all the pith is removed. Slice as thinly as possible and arrange over a dinner plate. Sprinkle with the demerara sugar followed by the Grand Marnier and set aside.\r\n\r\nCrumble the Christmas pudding into large pieces and scatter over the bottom of a trifle bowl. Lift the oranges onto the pudding in a layer and pour over any juices.\r\n\r\nBeat the mascarpone until smooth, then stir in the custard. Spoon the mixture over the top of the oranges.\r\n\r\nLightly whip the cream and spoon over the custard. Sprinkle with the flaked almonds and grated chocolate. You can make this a day in advance if you like, chill until ready to serve.", "equipment_tags": [], "portions": 12, "prep_minutes": 40, "prep_minutes_source": "estimated", "kcal": 378, "protein_g": 5.1, "carbs_g": 30.1, "fat_g": 26.6, "total_kcal": 4542, "total_protein_g": 61.4, "total_carbs_g": 361.3, "total_fat_g": 319.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the oranges", "instruction": "Peel the oranges removing all pith, slice thinly, and arrange on a plate. Sprinkle with demerara sugar and Grand Marnier, then set aside.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Layer the base", "instruction": "Crumble the Christmas pudding into a trifle bowl, top with the orange slices, and pour over any juices.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the custard layer", "instruction": "Beat the mascarpone until smooth, stir in the custard, then spoon over the oranges.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Top and chill", "instruction": "Lightly whip the cream and spoon over the custard, then sprinkle with flaked almonds and grated chocolate. Chill until ready to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=jRfyNQs5qhU"}, {"id": "52990", "name": "Christmas cake", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ldnrm91576791881.jpg", "local_image": "52990.jpg", "ingredients": [{"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Muscovado Sugar", "measure": "200g"}, {"ingredient": "Plain Flour", "measure": "200g"}, {"ingredient": "Eggs", "measure": "4 Beaten"}, {"ingredient": "Ground Almonds", "measure": "50g"}, {"ingredient": "Sherry", "measure": "100ml"}, {"ingredient": "Candied Peel", "measure": "85g"}, {"ingredient": "Glace Cherry", "measure": "85g"}, {"ingredient": "Raisins", "measure": "250g"}, {"ingredient": "Currants", "measure": "250g"}, {"ingredient": "Pecan Nuts", "measure": "100g"}, {"ingredient": "Lemon", "measure": "Grated zest of 1"}, {"ingredient": "Mixed Spice", "measure": "1 ½ tbsp"}, {"ingredient": "Rose water", "measure": "1 ½ tbsp"}, {"ingredient": "Vanilla Extract", "measure": "1/2 tsp"}, {"ingredient": "Baking Powder", "measure": "1/2 tsp"}], "instructions": "Heat oven to 160C/fan 140C/gas 3. Line the base and sides of a 20 cm round, 7.5 cm deep cake tin. Beat the butter and sugar with an electric hand mixer for 1-2 mins until very creamy and pale in colour, scraping down the sides of the bowl half way through. Stir in a spoonful of the flour, then stir in the beaten egg and the rest of the flour alternately, a quarter at a time, beating well each time with a wooden spoon. Stir in the almonds.\r\n\r\nMix in the sherry (the mix will look curdled), then add the peel, cherries, raisins, cherries, nuts, lemon zest, spice, rosewater and vanilla. Beat together to mix, then stir in the baking powder.\r\n\r\nSpoon mixture into the tin and smooth the top, making a slight dip in the centre. Bake for 30 mins, then lower temperature to 150C/fan 130C/gas 2 and bake a further 2-2¼ hrs, until a skewer insterted in the middle comes out clean. Leave to cool in the tin, then take out of the tin and peel off the lining paper. When completely cold, wrap well in cling film and foil to store until ready to decorate. The cake will keep for several months.", "equipment_tags": [], "portions": 12, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 532, "protein_g": 7.5, "carbs_g": 76.3, "fat_g": 24.0, "total_kcal": 6386, "total_protein_g": 89.6, "total_carbs_g": 915.7, "total_fat_g": 287.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep the tin", "instruction": "Heat the oven to 160°C/fan 140°C/gas 3 and line a round cake tin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cream and build the batter", "instruction": "Beat the butter and sugar until creamy and pale. Stir in a spoonful of flour, then alternate adding the beaten egg and remaining flour, beating well, then stir in the almonds.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Add the fruit", "instruction": "Mix in the sherry, then add the peel, cherries, raisins, currants, nuts, lemon zest, spice and rosewater, beat together, then stir in the baking powder.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Spoon into the tin, smooth the top with a slight dip in the centre, and bake, then lower the temperature and continue baking until a skewer comes out clean.", "timer_seconds": 9600, "background": true}, {"step": 5, "label": "Cool and store", "instruction": "Leave to cool in the tin, then remove and peel off the lining paper. When cold, wrap well and store until ready to decorate.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=34yeL8TstO0"}, {"id": "52991", "name": "Mince Pies", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qe8pf51576795532.jpg", "local_image": "52991.jpg", "ingredients": [{"ingredient": "Butter", "measure": "225g"}, {"ingredient": "Plain Flour", "measure": "350g"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Mincemeat", "measure": "280g"}, {"ingredient": "Egg", "measure": "1 small"}, {"ingredient": "Icing Sugar", "measure": "Topping"}], "instructions": "To make the pastry, rub 225g cold, diced butter into 350g plain flour, then mix in 100g golden caster sugar and a pinch of salt.\r\n\r\nCombine the pastry into a ball – don’t add liquid – and knead it briefly. The dough will be fairly firm, like shortbread dough. You can use the dough immediately, or chill for later.\r\n\r\nPreheat the oven to 200C/gas 6/fan 180C. Line 18 holes of two 12-hole patty tins, by pressing small walnut-sized balls of pastry into each hole.\r\n\r\nSpoon 280g mincemeat into the pies.\r\n\r\nTake slightly smaller balls of pastry than before and pat them out between your hands to make round lids, big enough to cover the pies. \r\n\r\nTop the pies with their lids, pressing the edges gently together to seal – you don’t need to seal them with milk or egg as they will stick on their own. (The pies may now be frozen for up to 1 month).\r\n\r\nBeat 1 small egg and brush the tops of the pies. Bake for 20 mins until golden. Leave to cool in the tin for 5 mins, then remove to a wire rack.\r\n\r\nTo serve, lightly dust with icing sugar.", "equipment_tags": [], "portions": 7, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 607, "protein_g": 6.8, "carbs_g": 80.7, "fat_g": 28.8, "total_kcal": 4246, "total_protein_g": 47.7, "total_carbs_g": 564.8, "total_fat_g": 201.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the pastry", "instruction": "Rub the cold diced butter into the flour, then mix in the sugar and a pinch of salt. Combine into a ball without adding liquid, and knead briefly.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Rest if needed", "instruction": "Use immediately or chill for later.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Line the tins", "instruction": "Preheat the oven to 200°C/gas 6/fan 180°C. Press small balls of pastry into the holes of two patty tins.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fill and top", "instruction": "Spoon in the mincemeat, then top with slightly smaller pastry rounds, pressing the edges to seal.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Glaze and bake", "instruction": "Brush the tops with beaten egg and bake until golden.", "timer_seconds": 1200, "background": true}, {"step": 6, "label": "Cool and serve", "instruction": "Leave to cool in the tin briefly, then remove to a wire rack. Dust with icing sugar to serve.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=PnXft7lQNJE"}, {"id": "52992", "name": "Soy-Glazed Meatloaves with Wasabi Mashed Potatoes & Roasted Carrots", "category": "Beef", "area": "United States", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/o2wb6p1581005243.jpg", "local_image": "52992.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "5"}, {"ingredient": "Carrots", "measure": "12 ounces"}, {"ingredient": "Scallions", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Bread", "measure": "1 Slice"}, {"ingredient": "Garlic Powder", "measure": "1"}, {"ingredient": "Soy Sauce", "measure": "2"}, {"ingredient": "Ground Beef", "measure": "1"}, {"ingredient": "Vegetable Oil", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Butter", "measure": "2 tbsp"}], "instructions": "1. Preheat oven to 425 degrees. Wash and dry all produce. Dice potatoes into 1/2-inch pieces. Trim, peel, and cut carrots on a diagonal into 1/2-inch-thick pieces. Trim and thinly slice scallions, separating whites from greens; finely chop whites. Peel and finely chop garlic.\r\n\r\n2. In a medium bowl, soak bread with 2 TBSP water (4 TBSP for 4 servings); break up with your hands until pasty. Stir in beef, sriracha, scallion whites, half the garlic, salt (we used 3/4 tsp kosher salt; 11/2 tsp for 4), and pepper. Form into two 1-inch-tall loaves (four loaves for 4). Place on one side of a baking sheet. Toss carrots on empty side of same sheet with a drizzle of oil, salt, and pepper. (For 4, spread meatloaves out across whole sheet and add carrots to a second sheet.) Bake for 20 minutes (we'll glaze the meatloaves then).\r\n\r\n3. Meanwhile, place potatoes in a medium pot with enough salted water to cover by 2 inches. Bring to a boil and cook until very\r\ntender, 12-15 minutes. Reserve 1/2 cup potato cooking liquid, then drain. While potatoes cook, in a small bowl, combine soy sauce, garlic powder, 1/4 cup ketchup (1/2 cup for 4 servings), and 2 tsp sugar (4 tsp for 4).\r\n\r\n4. Once meatloaves and carrots have baked 20 minutes, remove from oven. Spoon half the ketchup glaze over meatloaves (save\r\nthe rest for serving); return to oven until carrots are browned and tender, meatloaves are cooked through, and glaze is tacky, 4-5 minutes more.\r\n\r\n5. Meanwhile, melt 2 TBSP butter (4 TBSP for 4 servings) in pot used for potatoes over medium heat. Add remaining garlic and cook\r\nuntil fragrant, 30 seconds. Add potatoes and 1/4 tsp wasabi. Mash, adding splashes of reserved potato cooking liquid as necessary until smooth. Season with salt and pepper. (If you like things spicy, stir in more wasabi!)\r\n\r\n6. Divide meatloaves, mashed potatoes, and roasted carrots between plates. Sprinkle with scallion greens and serve with remaining ketchup glaze on the side for dipping.", "equipment_tags": [], "portions": 3, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 473, "protein_g": 14.5, "carbs_g": 75.4, "fat_g": 13.7, "total_kcal": 1420, "total_protein_g": 43.6, "total_carbs_g": 226.3, "total_fat_g": 41.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the vegetables", "instruction": "Preheat the oven to 425°F. Dice the potatoes, cut the carrots on a diagonal, and thinly slice the scallions, separating whites from greens. Finely chop the garlic.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the meatloaf mixture", "instruction": "Soak the bread with water and break up until pasty, then stir in the beef, sriracha, scallion whites, half the garlic, salt and pepper. Form into loaves and place on a baking sheet with the carrots tossed in oil, salt and pepper on the other side.", "timer_seconds": null, "background": false}, {"step": 3, "label": "First bake", "instruction": "Bake the meatloaves and carrots.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Cook the potatoes and make the glaze", "instruction": "Meanwhile, boil the potatoes in salted water until very tender, reserving some cooking liquid before draining. Combine the soy sauce, garlic powder, ketchup and sugar for the glaze.", "timer_seconds": 900, "background": false}, {"step": 5, "label": "Glaze and finish baking", "instruction": "Spoon half the glaze over the meatloaves and return to the oven with the carrots until browned, tender and cooked through.", "timer_seconds": 270, "background": true}, {"step": 6, "label": "Make the wasabi mash", "instruction": "Melt the butter in the potato pot, add the remaining garlic and cook until fragrant, then add the potatoes and wasabi and mash, adding reserved cooking liquid as needed. Season.", "timer_seconds": 30, "background": false}, {"step": 7, "label": "Serve", "instruction": "Divide the meatloaves, mashed potatoes and carrots between plates, sprinkle with scallion greens, and serve with the remaining glaze on the side.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52993", "name": "Honey Balsamic Chicken with Crispy Broccoli & Potatoes", "category": "Chicken", "area": "United States", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/kvbotn1581012881.jpg", "local_image": "52993.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "5"}, {"ingredient": "Broccoli", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Chicken Breast", "measure": "2"}, {"ingredient": "Balsamic Vinegar", "measure": ""}, {"ingredient": "Honey", "measure": ""}, {"ingredient": "Chicken Stock", "measure": ""}, {"ingredient": "Butter", "measure": "1 tbsp"}, {"ingredient": "Vegetable Oil", "measure": "1 tbsp"}, {"ingredient": "Olive Oil", "measure": "1 tbsp"}], "instructions": "2 Servings\r\n\r\n1. Preheat oven to 425 degrees. Wash and dry all produce. Cut potatoes into 1/2-inch-thick wedges. Toss on one side of a baking sheet with a drizzle of oil, salt, and pepper. (For 4 servings, spread potatoes out across entire sheet.) Roast on top rack for 5 minutes (we'll add the broccoli then). \r\n\r\n2. Meanwhile, cut broccoli florets into bite-size pieces, if necessary. Peel and finely chop garlic. In a small microwave-safe bowl, combine 1 TBSP olive oil (2 TBSP for 4 servings) and half the garlic. Microwave until garlic sizzles, 30 seconds. \r\n\r\n3. Once potatoes have roasted 5 minutes, remove sheet from oven and add broccoli to empty side; carefully toss with garlic oil, salt, and pepper. (For 4 servings, add broccoli to a second sheet.) Continue roasting until potatoes and broccoli are browned and crispy, 15-20 minutes more. \r\n\r\n4. While veggies roast, pat chicken dry with paper towels; season all over with salt and pepper. Heat a drizzle of oil in a large pan over medium-high heat. Add chicken and cook until browned and cooked through, 5-6 minutes per side. (If chicken browns too quickly, reduce heat to medium.) Turn off heat; set chicken aside to rest. Wash out pan. \r\n\r\n5. Heat pan used for chicken over medium-high heat. Add a drizzle of oil and remaining garlic; cook until fragrant, 30 seconds. Stir in vinegar, honey, stock concentrate, and 1/4 cup water (1/3 cup for 4 servings). Simmer until thick and glossy, 2-3 minutes. Remove from heat and stir in 1 TBSP butter (2 TBSP for 4). Season with salt and pepper. \r\n\r\n6. Return chicken to pan and turn to coat in glaze. Divide chicken, broccoli, and potatoes between plates. Spoon any remaining glaze over chicken and serve. ", "equipment_tags": [], "portions": 3, "prep_minutes": 39, "prep_minutes_source": "explicit", "kcal": 464, "protein_g": 28.8, "carbs_g": 50.3, "fat_g": 16.0, "total_kcal": 1391, "total_protein_g": 86.4, "total_carbs_g": 150.8, "total_fat_g": 48.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the potatoes", "instruction": "Preheat the oven to 425°F. Cut the potatoes into wedges and toss on a baking sheet with oil, salt and pepper. Roast on the top rack.", "timer_seconds": 300, "background": true}, {"step": 2, "label": "Make the garlic oil", "instruction": "Meanwhile, cut broccoli into bite-size pieces and chop the garlic. Combine half the garlic with olive oil and microwave until sizzling.", "timer_seconds": 30, "background": false}, {"step": 3, "label": "Roast the broccoli with the potatoes", "instruction": "Remove the sheet from the oven, add the broccoli to the empty side, toss with garlic oil, salt and pepper, and continue roasting until both are browned and crispy.", "timer_seconds": 1050, "background": true}, {"step": 4, "label": "Cook the chicken", "instruction": "While the vegetables roast, season the chicken and cook in an oiled pan over medium-high heat until browned and cooked through, then set aside to rest.", "timer_seconds": 660, "background": false}, {"step": 5, "label": "Make the glaze", "instruction": "In the same pan, cook the remaining garlic until fragrant, then stir in vinegar, honey, stock concentrate and water, and simmer until thick and glossy. Stir in the butter and season.", "timer_seconds": 150, "background": false}, {"step": 6, "label": "Serve", "instruction": "Return the chicken to the pan to coat in the glaze. Divide chicken, broccoli and potatoes between plates, spooning over any remaining glaze.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52994", "name": "Skillet Apple Pork Chops with Roasted Sweet Potatoes & Zucchini", "category": "Pork", "area": "United States", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/h3ijwo1581013377.jpg", "local_image": "52994.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "2"}, {"ingredient": "Apples", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Lemon", "measure": "1"}, {"ingredient": "Pork", "measure": "2"}, {"ingredient": "Zucchini", "measure": "1"}, {"ingredient": "Chicken Stock", "measure": "1"}, {"ingredient": "Vegetable Oil", "measure": "1 tbsp"}, {"ingredient": "Sugar", "measure": "1 1/2 tsp"}, {"ingredient": "Butter", "measure": "2 tbsp"}], "instructions": "\r\nServes 2\r\n\r\n\r\n1. \r\n\r\nAdjust racks to top and middle positions and preheat oven to 450 degrees. Wash and dry all produce. Dice sweet potatoes into 1/2-inch pieces. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast on top rack for 12 minutes (we'll roast the zucchini then). \r\n\r\n\r\n2. \r\n\r\nMeanwhile, halve and core apple; thinly slice into half-moons. Peel and finely chop garlic. Quarter lemon. Trim and halve zucchini lengthwise; cut crosswise into 1/2-inch-thick half-moons. Toss on a second baking sheet with a drizzle of oil and a pinch of salt and pepper. Set aside. \r\n\r\n\r\n3. \r\n\r\nPat pork dry with paper towels and season all over with salt and pepper. Heat a drizzle of oil in a large pan over medium-high heat. Add pork and cook until browned and cooked through, 4-5 minutes per side. Turn off heat; transfer to a plate. \r\n\r\n\r\n4. \r\n\r\nOnce sweet potatoes have roasted 12 minutes, transfer baking sheet with zucchini to middle rack and continue roasting until both veggies are browned and softened, 12-15 minutes more. \r\n\r\n\r\n5. \r\n\r\nMeanwhile, melt 1 TBSP butter (2 TBSP for 4 servings) in pan used for pork over medium-high heat. Add apple and season with salt and pepper. Cook, scraping up any browned bits from bottom of pan, until apple is slightly softened, 2-3 minutes. Add garlic; cook until fragrant, 30 seconds. Add 1/z cup water (3/4 cup for 4), stock concentrate, and 11/2 tsp sugar (3 tsp for 4). Cook, stirring, until sauce has thickened and apple is very tender, 3-5 minutes. Season with salt and pepper. \r\n\r\n\r\n6. \r\n\r\nRemove pan with apple from heat; stir in 1 TBSP butter (2 TBSP for 4 servings) and a squeeze of lemon juice. Divide pork, zucchini, and sweet potatoes between plates. Top pork with glazed apple sauce. Top zucchini with a squeeze of lemon juice. ", "equipment_tags": [], "portions": 1, "prep_minutes": 52, "prep_minutes_source": "explicit", "kcal": 838, "protein_g": 29.1, "carbs_g": 80.7, "fat_g": 46.0, "total_kcal": 838, "total_protein_g": 29.1, "total_carbs_g": 80.7, "total_fat_g": 46.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the sweet potatoes", "instruction": "Preheat the oven to 450°F. Dice the sweet potatoes and toss on a baking sheet with oil, salt and pepper. Roast on the top rack.", "timer_seconds": 720, "background": true}, {"step": 2, "label": "Prep the rest", "instruction": "Meanwhile, halve and slice the apple, chop the garlic, quarter the lemon, and cut the zucchini into half-moons, tossing the zucchini on a second sheet with oil, salt and pepper.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the pork", "instruction": "Season the pork and cook in an oiled pan over medium-high heat until browned and cooked through, then transfer to a plate.", "timer_seconds": 540, "background": false}, {"step": 4, "label": "Roast the zucchini", "instruction": "Once the sweet potatoes have roasted 12 minutes, add the zucchini sheet to the oven and continue roasting both until browned and softened.", "timer_seconds": 810, "background": true}, {"step": 5, "label": "Make the apple sauce", "instruction": "Melt butter in the pork pan, add the apple, season, and cook, scraping up browned bits, until slightly softened. Add garlic, then water, stock concentrate and sugar, and cook, stirring, until thickened and the apple is tender.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Finish and serve", "instruction": "Off the heat, stir in butter and a squeeze of lemon juice into the apple sauce. Divide pork, zucchini and sweet potatoes between plates, topping pork with the glazed apple and zucchini with lemon juice.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52995", "name": "BBQ Pork Sloppy Joes", "category": "Pork", "area": "United States", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/atd5sh1583188467.jpg", "local_image": "52995.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "2"}, {"ingredient": "Red Onions", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Lime", "measure": "1"}, {"ingredient": "Bread", "measure": "2"}, {"ingredient": "Pork", "measure": "1 lb"}, {"ingredient": "Barbeque Sauce", "measure": ""}, {"ingredient": "Hotsauce", "measure": ""}, {"ingredient": "Tomato Ketchup", "measure": ""}, {"ingredient": "Sugar", "measure": ""}, {"ingredient": "Vegetable Oil", "measure": ""}, {"ingredient": "Salt", "measure": ""}, {"ingredient": "Pepper", "measure": ""}], "instructions": "1\r\n\r\nPreheat oven to 450 degrees. Wash and dry all produce. Cut sweet potatoes into ½-inch-thick wedges. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 20-25 minutes.\r\n\r\n2\r\n\r\nMeanwhile, halve and peel onion. Slice as thinly as possible until you have ¼ cup (½ cup for 4 servings); finely chop remaining onion. Peel and finely chop garlic. Halve lime; squeeze juice into a small bowl. Halve buns. Add 1 TBSP butter (2 TBSP for 4) to a separate small microwave-safe bowl; microwave until melted, 30 seconds. Brush onto cut sides of buns.\r\n\r\n3\r\n\r\nTo bowl with lime juice, add sliced onion, ¼ tsp sugar (½ tsp for 4 servings), and a pinch of salt. Stir to combine; set aside to quick-pickle.\r\n\r\n4\r\n\r\nHeat a drizzle of oil in a large pan over medium-high heat. Add chopped onion and season with salt and pepper. Cook, stirring, until softened, 4-5 minutes. Add garlic and cook until fragrant, 30 seconds more. Add pork and season with salt and pepper. Cook, breaking up meat into pieces, until browned and cooked through, 4-6 minutes.\r\n\r\n5\r\n\r\nWhile pork cooks, in a third small bowl, combine BBQ sauce, pickling liquid from onion, 3 TBSP ketchup (6 TBSP for 4 servings), ½ tsp sugar (1 tsp for 4), and ¼ cup water (⅓ cup for 4). Once pork is cooked through, add BBQ sauce mixture to pan. Cook, stirring, until sauce is thickened, 2-3 minutes. Taste and season with salt and pepper.\r\n\r\n6\r\n\r\nMeanwhile, toast buns in oven or toaster oven until golden, 3-5 minutes. Divide toasted buns between plates and fill with as much BBQ pork as you’d like. Top with pickled onion and hot sauce. Serve with sweet potato wedges on the side.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 44, "prep_minutes_source": "explicit", "kcal": 672, "protein_g": 54.4, "carbs_g": 64.4, "fat_g": 20.6, "total_kcal": 1344, "total_protein_g": 108.7, "total_carbs_g": 128.8, "total_fat_g": 41.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the sweet potatoes", "instruction": "Preheat the oven to 450°F. Cut the sweet potatoes into wedges, toss on a baking sheet with oil, salt and pepper, and roast until browned and tender.", "timer_seconds": 1350, "background": true}, {"step": 2, "label": "Prep the onions and buns", "instruction": "Meanwhile, thinly slice some onion and finely chop the rest. Chop the garlic, squeeze the lime, halve the buns and brush the cut sides with melted butter.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Quick-pickle the onion", "instruction": "Combine the sliced onion with lime juice, sugar and a pinch of salt, and set aside to quick-pickle.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Cook the pork", "instruction": "Heat oil in a large pan, cook the chopped onion until softened, add garlic and cook until fragrant, then add the pork and cook, breaking it up, until browned and cooked through.", "timer_seconds": 480, "background": false}, {"step": 5, "label": "Build the sauce", "instruction": "Combine BBQ sauce, pickling liquid, ketchup, sugar and water, add to the pan, and cook, stirring, until thickened. Season to taste.", "timer_seconds": 150, "background": false}, {"step": 6, "label": "Toast and serve", "instruction": "Toast the buns until golden, fill with the BBQ pork, top with pickled onion and hot sauce, and serve with the sweet potato wedges.", "timer_seconds": 240, "background": false}], "video": null}, {"id": "52996", "name": "French Onion Chicken with Roasted Carrots & Mashed Potatoes", "category": "Chicken", "area": "United States", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/b5ft861583188991.jpg", "local_image": "52996.jpg", "ingredients": [{"ingredient": "Chicken Breasts", "measure": "2"}, {"ingredient": "Carrots", "measure": "12 ounces"}, {"ingredient": "Potatoes", "measure": "5"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Beef Stock", "measure": "1"}, {"ingredient": "Mozzarella", "measure": "1 1/2 cup"}, {"ingredient": "Sour Cream", "measure": "2 tbsp"}, {"ingredient": "Butter", "measure": ""}, {"ingredient": "Sugar", "measure": ""}, {"ingredient": "Vegetable Oil", "measure": ""}, {"ingredient": "Salt", "measure": ""}, {"ingredient": "Pepper", "measure": ""}], "instructions": "1\r\n\r\nPreheat oven to 425 degrees. Wash and dry all produce. Trim, peel, and cut carrots on a diagonal into ¼-inch-thick pieces. Dice potatoes into ½-inch pieces. Halve, peel, and thinly slice onion.\r\n\r\n2\r\n\r\nToss carrots on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 15-20 minutes.\r\n\r\n3\r\n\r\nMeanwhile, place potatoes in a medium pot with enough salted water to cover by 2 inches. Bring to a boil and cook until tender, 12-15 minutes. Drain and return potatoes to pot; cover to keep warm.\r\n\r\n4\r\n\r\nWhile potatoes cook, heat a drizzle of oil in a large pan over medium-high heat. Add onion and cook, stirring occasionally, until lightly browned and softened, 8-10 minutes. Sprinkle with 1 tsp sugar (2 tsp for 4 servings). Stir in stock concentrate and 2 TBSP water (¼ cup for 4); season with salt and pepper. Cook until jammy, 2-3 minutes more. Turn off heat; transfer to a small bowl. Wash out pan.\r\n\r\n5\r\n\r\nPat chicken dry with paper towels; season all over with salt and pepper. Heat a drizzle of oil in pan used for onion over medium-high heat. Add chicken and cook until browned and cooked through, 5-6 minutes per side. In the last 1-2 minutes of cooking, top with caramelized onion and cheese. Cover pan until cheese melts. (If your pan doesn’t have a lid, cover with a baking sheet!)\r\n\r\n6\r\n\r\nHeat pot with drained potatoes over low heat; mash with sour cream, 2 TBSP butter (4 TBSP for 4 servings), salt, pepper, and a splash of water (or milk, for extra richness) until smooth. Divide chicken, roasted carrots, and mashed potatoes between plates.", "equipment_tags": [], "portions": 4, "prep_minutes": 56, "prep_minutes_source": "explicit", "kcal": 573, "protein_g": 47.7, "carbs_g": 50.8, "fat_g": 19.6, "total_kcal": 2290, "total_protein_g": 190.7, "total_carbs_g": 203.3, "total_fat_g": 78.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the vegetables", "instruction": "Preheat the oven to 425°F. Cut the carrots on a diagonal, dice the potatoes, and thinly slice the onion.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Roast the carrots", "instruction": "Toss the carrots on a baking sheet with oil, salt and pepper, and roast until browned and tender.", "timer_seconds": 1050, "background": true}, {"step": 3, "label": "Boil the potatoes", "instruction": "Meanwhile, cover the potatoes with salted water, bring to a boil, and cook until tender, then drain and keep warm.", "timer_seconds": 810, "background": true}, {"step": 4, "label": "Caramelise the onion", "instruction": "Heat oil in a large pan, cook the onion until lightly browned and softened, sprinkle with sugar, stir in stock concentrate and water, season, and cook until jammy.", "timer_seconds": 660, "background": false}, {"step": 5, "label": "Cook the chicken", "instruction": "Season the chicken and cook in the same pan (wiped out) over medium-high heat until browned and cooked through, topping with the caramelised onion and cheese in the last couple minutes and covering until the cheese melts.", "timer_seconds": 420, "background": false}, {"step": 6, "label": "Mash the potatoes and serve", "instruction": "Mash the drained potatoes with sour cream, butter, salt, pepper and a splash of water or milk until smooth. Divide chicken, carrots and mashed potatoes between plates.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52997", "name": "Beef Banh Mi Bowls with Sriracha Mayo, Carrot & Pickled Cucumber", "category": "Beef", "area": "Vietnamese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/z0ageb1583189517.jpg", "local_image": "52997.jpg", "ingredients": [{"ingredient": "Rice", "measure": "White"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Lime", "measure": "1"}, {"ingredient": "Garlic Clove", "measure": "3"}, {"ingredient": "Cucumber", "measure": "1"}, {"ingredient": "Carrots", "measure": "3 oz"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Soy Sauce", "measure": "2 oz"}], "instructions": "Add'l ingredients: mayonnaise, siracha\r\n\r\n1\r\n\r\nPlace rice in a fine-mesh sieve and rinse until water runs clear. Add to a small pot with 1 cup water (2 cups for 4 servings) and a pinch of salt. Bring to a boil, then cover and reduce heat to low. Cook until rice is tender, 15 minutes. Keep covered off heat for at least 10 minutes or until ready to serve.\r\n\r\n2\r\n\r\nMeanwhile, wash and dry all produce. Peel and finely chop garlic. Zest and quarter lime (for 4 servings, zest 1 lime and quarter both). Trim and halve cucumber lengthwise; thinly slice crosswise into half-moons. Halve, peel, and medium dice onion. Trim, peel, and grate carrot.\r\n\r\n3\r\n\r\nIn a medium bowl, combine cucumber, juice from half the lime, ¼ tsp sugar (½ tsp for 4 servings), and a pinch of salt. In a small bowl, combine mayonnaise, a pinch of garlic, a squeeze of lime juice, and as much sriracha as you’d like. Season with salt and pepper.\r\n\r\n4\r\n\r\nHeat a drizzle of oil in a large pan over medium-high heat. Add onion and cook, stirring, until softened, 4-5 minutes. Add beef, remaining garlic, and 2 tsp sugar (4 tsp for 4 servings). Cook, breaking up meat into pieces, until beef is browned and cooked through, 4-5 minutes. Stir in soy sauce. Turn off heat; taste and season with salt and pepper.\r\n\r\n5\r\n\r\nFluff rice with a fork; stir in lime zest and 1 TBSP butter. Divide rice between bowls. Arrange beef, grated carrot, and pickled cucumber on top. Top with a squeeze of lime juice. Drizzle with sriracha mayo.", "equipment_tags": [], "portions": 2, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 706, "protein_g": 43.6, "carbs_g": 29.0, "fat_g": 45.9, "total_kcal": 1412, "total_protein_g": 87.2, "total_carbs_g": 58.0, "total_fat_g": 91.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the rice", "instruction": "Rinse the rice until the water runs clear, then add to a pot with water and a pinch of salt, bring to a boil, cover, reduce to low, and cook until tender. Keep covered off heat.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Prep the vegetables", "instruction": "Meanwhile, chop the garlic, zest and quarter the lime, slice the cucumber into half-moons, dice the onion, and grate the carrot.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Quick-pickle and make the sauce", "instruction": "Combine cucumber with lime juice, sugar and salt to pickle. In a separate bowl, combine mayonnaise, garlic, lime juice and sriracha, and season.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Cook the beef", "instruction": "Heat oil in a large pan, cook the onion until softened, add the beef, remaining garlic and sugar, and cook, breaking up the meat, until browned and cooked through. Stir in soy sauce and season.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Serve", "instruction": "Fluff the rice with lime zest and butter, divide between bowls, and top with beef, grated carrot and pickled cucumber. Finish with a squeeze of lime juice and a drizzle of sriracha mayo.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52998", "name": "Corned Beef and Cabbage", "category": "Beef", "area": "Irish", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/xb97a81583266727.jpg", "local_image": "52998.jpg", "ingredients": [{"ingredient": "Beef Brisket", "measure": "3 Lbs"}, {"ingredient": "Small Potatoes", "measure": "10"}, {"ingredient": "Carrots", "measure": "5"}, {"ingredient": "Cabbage", "measure": "1 head"}], "instructions": "1\r\n\r\nPlace corned beef in large pot or Dutch oven and cover with water. Add the spice packet that came with the corned beef. Cover pot and bring to a boil, then reduce to a simmer. Simmer approximately 50 minutes per pound or until tender.\r\n\r\n2\r\n\r\nAdd whole potatoes and peeled and cut carrots, and cook until the vegetables are almost tender. Add cabbage and cook for 15 more minutes. Remove meat and let rest 15 minutes.\r\n\r\n3\r\n\r\nPlace vegetables in a bowl and cover. Add as much broth (cooking liquid reserved in the Dutch oven or large pot) as you want. Slice meat across the grain.", "equipment_tags": [], "portions": 7, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 556, "protein_g": 44.2, "carbs_g": 46.0, "fat_g": 21.7, "total_kcal": 3894, "total_protein_g": 309.5, "total_carbs_g": 321.9, "total_fat_g": 152.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Simmer the corned beef", "instruction": "Place the corned beef in a large pot with the spice packet, cover with water, bring to a boil, then reduce to a simmer and cook until tender.", "timer_seconds": 9000, "background": true}, {"step": 2, "label": "Add the vegetables", "instruction": "Add whole potatoes and cut carrots, and cook until the vegetables are almost tender.", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Add the cabbage", "instruction": "Add the cabbage and cook further, then remove the meat and let it rest.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Serve", "instruction": "Place the vegetables in a bowl and cover with as much broth as you like. Slice the meat across the grain and serve.", "timer_seconds": null, "background": false}], "video": null}, {"id": "52999", "name": "Crispy Sausages and Greens", "category": "Pork", "area": "Irish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/st1ifa1583267248.jpg", "local_image": "52999.jpg", "ingredients": [{"ingredient": "Kale", "measure": "1  bunch"}, {"ingredient": "Italian Fennel Sausages", "measure": "8"}, {"ingredient": "Cabbage", "measure": "1 Head chopped"}, {"ingredient": "Garlic Clove", "measure": "8"}, {"ingredient": "Onion", "measure": "Sliced"}, {"ingredient": "Shiitake Mushrooms", "measure": "Sliced"}, {"ingredient": "Chicken Stock", "measure": "1 cup"}, {"ingredient": "Salt", "measure": ""}, {"ingredient": "Pepper", "measure": ""}], "instructions": "Preheat the oven to 350°. Remove the stems from one bunch of Tuscan kale and tear the leaves into 1\" pieces (mustard greens, collards, spinach, and chard are great, too). Coarsely chop half a head of green cabbage. Combine the greens in a large baking dish and add 4 cloves of thinly sliced garlic. Adding some sliced onions and shiitake mushrooms at this point is optional, but highly recommended (I'll sauté the onions and mushrooms in a cast iron baking dish right on the stove before adding to the greens). Coat the greens with some olive oil and pour ½ cup chicken stock or broth over everything. Cover the dish with foil and bake until the greens are wilted, about 15 minutes. Remove foil and season with salt and pepper. Continue to bake until cabbage is tender, about 20-25 minutes more.\r\n\r\nMeanwhile, heat a little olive oil in a large skillet over medium-high. Prick four sweet Italian sausages with a fork and cook until browned on all sides and cooked through, 10 to 12 minutes. When the greens are done, slice the sausage and toss into the greens with a splash of your favorite vinegar (I like sherry or red wine).", "equipment_tags": [], "portions": 2, "prep_minutes": 52, "prep_minutes_source": "explicit", "kcal": 629, "protein_g": 28.2, "carbs_g": 11.7, "fat_g": 52.3, "total_kcal": 1259, "total_protein_g": 56.4, "total_carbs_g": 23.3, "total_fat_g": 104.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep and bake the greens", "instruction": "Preheat the oven to 350°F. Tear the kale into pieces and chop the cabbage, combining in a baking dish with sliced garlic (and sautéed onions and mushrooms if using). Coat with oil, pour over the chicken stock, cover with foil, and bake until wilted.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Continue baking the greens", "instruction": "Remove the foil, season with salt and pepper, and continue baking until the cabbage is tender.", "timer_seconds": 1350, "background": true}, {"step": 3, "label": "Cook the sausages", "instruction": "Meanwhile, heat oil in a large skillet and cook the sausages, pricked with a fork, until browned all over and cooked through.", "timer_seconds": 660, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Slice the sausages and toss into the greens with a splash of vinegar once the greens are done.", "timer_seconds": null, "background": false}], "video": null}, {"id": "53000", "name": "Vegetable Shepherds Pie", "category": "Beef", "area": "Irish", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/w8umt11583268117.jpg", "local_image": "53000.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "3 Lbs"}, {"ingredient": "Small Potatoes", "measure": "3 Lbs"}, {"ingredient": "Salted Butter", "measure": "1/2 cup"}, {"ingredient": "Mushrooms", "measure": "1 oz"}, {"ingredient": "Brown Lentils", "measure": "3/4 cup"}, {"ingredient": "Garlic", "measure": "6 cloves"}, {"ingredient": "Kosher Salt", "measure": "1 tsp"}, {"ingredient": "Onion", "measure": "3 cups"}, {"ingredient": "Tomato Puree", "measure": "2 tbsp"}, {"ingredient": "Bay Leaves", "measure": ""}, {"ingredient": "Olive Oil", "measure": ""}, {"ingredient": "Dry White Wine", "measure": "2 cups"}, {"ingredient": "Vegetable Stock", "measure": "8 cups"}, {"ingredient": "Cornstarch", "measure": "2 tbsp"}, {"ingredient": "Soy Sauce", "measure": "2 tsp"}, {"ingredient": "Rosemary", "measure": "2 sprigs"}, {"ingredient": "Parsley", "measure": ""}, {"ingredient": "Sage", "measure": ""}, {"ingredient": "Chives", "measure": ""}], "instructions": "Add Ingredients:\r\n\r\n12 cups chopped mixed vegetables\r\n1   cup chopped fresh mushrooms \r\n1   cup pearl onions\r\n\r\nTOPPING:\r\n\r\nPreheat oven to 450°. Bake potatoes on a foil-lined baking sheet until tender, about 45 minutes. Let cool slightly, then peel. Press potatoes through a ricer, food mill, or colander into a large bowl. Add butter; stir until well blended. Stir in milk. Season to taste with salt.\r\n\r\nFILLING:\r\n\r\nSoak dried porcini in 3 cups hot water; set aside. Combine lentils, 1 garlic clove, 1 tsp. salt, and 4 cups water in a medium saucepan. Bring to a boil; reduce heat and simmer, stirring occasionally, until lentils are tender but not mushy, 15–20 minutes. Drain lentils and discard garlic.\r\n\r\nHeat 3 Tbsp. oil in a large heavy pot over medium heat. Add onions and cook, stirring occasionally, until soft, about 12 minutes. Add chopped garlic and cook for 1 minute. Stir in tomato paste. Cook, stirring constantly, until tomato paste is caramelized, 2–3 minutes.\r\n\r\nAdd bay leaves and wine; stir, scraping up any browned bits. Stir in porcini, slowly pouring porcini soaking liquid into pan but leaving any sediment behind. Bring to a simmer and cook until liquid is reduced by half, about 10 minutes. Stir in broth and cook, stirring occasionally, until reduced by half, about 45 minutes.\r\n\r\nStrain mixture into a large saucepan and bring to a boil; discard solids in strainer. Stir cornstarch and 2 Tbsp. water in a small bowl to dissolve. Add cornstarch mixture; simmer until thickened, about 5 minutes. Whisk in miso. Season sauce with salt and pepper. Set aside.\r\n\r\nPreheat oven to 450°. Toss vegetables and pearl onions with remaining 2 Tbsp. oil, 5 garlic cloves, and rosemary sprigs in a large bowl; season with salt and pepper. Divide between 2 rimmed baking sheets. Roast, stirring once, until tender, 20–25 minutes. Transfer garlic cloves to a small bowl; mash well with a fork and stir into sauce. Discard rosemary. DO AHEAD: Lentils, sauce, and vegetables can be made 1 day ahead. Cover separately; chill.\r\nArrange lentils in an even layer in a 3-qt. baking dish; set dish on a foil-lined rimmed baking sheet. Toss roasted vegetables with fresh mushrooms and chopped herbs; layer on top of lentils. Pour sauce over vegetables. Spoon potato mixture evenly over.\r\n\r\nBake until browned and bubbly, about 30 minutes. Let stand for 15 minutes before serving.", "cook_steps": [{"step": 1, "label": "Preheat & prep", "instruction": "Preheat the oven to 450°F (230°C). Get two baking sheets and a foil liner ready.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bake the potatoes", "instruction": "Bake the potatoes whole on a foil-lined sheet until fork-tender.", "timer_seconds": 2700, "background": true}, {"step": 3, "label": "Simmer the lentils", "instruction": "While the potatoes bake, soak the dried porcini in hot water. Simmer the lentils with a garlic clove and salt until just tender, then drain and discard the garlic.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Build the sauce base", "instruction": "Heat oil in a large pot. Cook the onions until soft, add the chopped garlic, then stir in the tomato paste until it caramelizes.", "timer_seconds": 900, "background": false}, {"step": 5, "label": "Reduce the sauce", "instruction": "Add the bay leaves and wine, then the porcini and its soaking liquid (leave the sediment behind). Stir in the stock and simmer until reduced by half — this can run in the background while you roast the vegetables and finish the potato topping.", "timer_seconds": 2700, "background": true}, {"step": 6, "label": "Roast the vegetables", "instruction": "Toss the mixed vegetables and pearl onions with oil, garlic, and rosemary sprigs. Divide between two sheets and roast until tender, stirring once.", "timer_seconds": 1350, "background": true}, {"step": 7, "label": "Finish the potato topping", "instruction": "Once the potatoes are cool enough to handle, peel and press through a ricer. Stir in butter and milk, then season with salt.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Thicken the sauce", "instruction": "Strain the sauce and bring to a boil. Stir in the cornstarch slurry and simmer until thickened, then season with salt and pepper.", "timer_seconds": 300, "background": false}, {"step": 9, "label": "Layer the pie", "instruction": "Spread the lentils in an even layer in the baking dish. Toss the roasted vegetables with the fresh mushrooms and chopped herbs, layer on top, then pour over the sauce.", "timer_seconds": null, "background": false}, {"step": 10, "label": "Top and bake", "instruction": "Spoon the potato topping evenly over the filling. Bake until browned and bubbly.", "timer_seconds": 1800, "background": true}, {"step": 11, "label": "Rest before serving", "instruction": "Let the pie stand so it sets before slicing and serving.", "timer_seconds": 900, "background": false}], "equipment_tags": [], "portions": 12, "prep_minutes": 211, "prep_minutes_source": "explicit", "kcal": 342, "protein_g": 7.9, "carbs_g": 52.9, "fat_g": 8.4, "total_kcal": 4106, "total_protein_g": 94.3, "total_carbs_g": 634.3, "total_fat_g": 101.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53005", "name": "Strawberry Rhubarb Pie", "category": "Dessert", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/178z5o1585514569.jpg", "local_image": "53005.jpg", "ingredients": [{"ingredient": "Flour", "measure": "350g"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "2 tbs"}, {"ingredient": "Butter", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1/2 cup"}, {"ingredient": "Rhubarb", "measure": "450g"}, {"ingredient": "Strawberries", "measure": "450g"}, {"ingredient": "Cornstarch", "measure": "3 tbs"}, {"ingredient": "Sugar", "measure": "150g"}, {"ingredient": "Cinnamon", "measure": "1/4 tsp"}, {"ingredient": "Lemon Juice", "measure": "1 tsp"}, {"ingredient": "Unsalted Butter", "measure": "2 tbs"}, {"ingredient": "Milk", "measure": "2 tbs"}, {"ingredient": "Sugar", "measure": "Spinkling"}], "instructions": "Pie Crust:  In a food processor, place the flour, salt, and sugar and process until combined. Add the butter and process until the mixture resembles coarse\r\n\r\nmeal (about 15 seconds). Pour 1/4 cup (60 ml) water in a slow, steady stream, through the feed tube until the dough just holds together when pinched. If necessary, add more water. Do not process more than 30 seconds.\r\nTurn the dough onto your work surface and gather into a ball. Divide the dough in half, flattening each half into a disk, cover with plastic wrap, and refrigerate for about one hour before using. This will chill the butter and relax the gluten in the flour. \r\n\r\nAfter the dough has chilled sufficiently, remove one portion of the dough from the fridge and place it on a lightly floured surface.  Roll the pastry into a 12 inch (30 cm) circle. (To prevent the pastry from sticking to the counter and to ensure uniform thickness, keep lifting up and turning the pastry a quarter turn as you roll (always roll from the center of the pastry outwards).)  Fold the dough in half and gently transfer to a 9 inch (23 cm) pie pan. Brush off any excess flour and trim any overhanging pastry to an edge of 1/2 inch (1.5 cm). Refrigerate the pastry, covered with plastic wrap, while you make the filling. \r\n\r\nRemove the second round of pastry and roll it into a 13 inch (30 cm) circle. Using a pastry wheel or pizza cutter, cut the pastry into about 3/4 inch (2 cm) strips. Place the strips of pastry on a parchment paper-lined baking sheet, cover with plastic wrap, and place in the refrigerator for about 10 minutes. \r\n\r\nMake the Strawberry Rhubarb Filling: Place the cut strawberries and rhubarb in a large bowl. In a small bowl mix together the cornstarch, sugar, and ground cinnamon. \r\n\r\nRemove the chilled pie crust from the fridge. Sprinkle about 2 tablespoons of the sugar mixture over the bottom of the pastry crust. Add the remaining sugar mixture to the strawberries and rhubarb and gently toss to combine. Pour the fruit mixture into the prepared pie shell. Sprinkle the fruit with about 1 teaspoon of lemon juice and dot with 2 tablespoons of butter.\r\n\r\nRemove the lattice pastry from the refrigerator and, starting at the center with the longest strips and working outwards, place half the strips, spacing about 1 inch (2.5 cm) apart, on top of the filling. (Use the shortest pastry strips at the outer edges.) Then, gently fold back, about halfway, every other strip of pastry. Take another strip of pastry and place it perpendicular on top of the first strips of pastry. Unfold the bottom strips of pastry and then fold back the strips that weren't folded back the first time. Lay another strip of pastry perpendicular on top of the filling and then continue with the remaining strips. Trim the edges of the pastry strips, leaving a 1 inch (2.5 cm) overhang. Seal the edges of the pastry strips by folding them under the bottom pastry crust and flute the edges of the pastry. Brush the lattice pastry with milk and sprinkle with a little sugar. Cover and place in the refrigerator while you preheat the oven to 400 degrees F (205 degrees C) and place the oven rack in the lower third of the oven. Put a baking sheet, lined with aluminum foil, on the oven rack (to catch any spills.)\r\n\r\nPlace the pie plate on the hot baking sheet and bake the pie for about 35 minutes and then, if the edges of the pie are browning too much, cover with a foil ring. Continue to bake the pie for about another 10 minutes or until the crust is a golden brown color and the fruit juices begin to bubble.\r\n\r\nRemove the pie from the oven and place on a wire rack to cool for several hours. Serve at room temperature with softly whipped cream or vanilla ice cream. Leftovers can be stored in the refrigerator for about 3 days. Reheat before serving. This pie can be frozen.\r\n\r\nMakes one 9 inch (23 cm) pie.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 363, "protein_g": 3.8, "carbs_g": 47.5, "fat_g": 18.1, "total_kcal": 4360, "total_protein_g": 45.7, "total_carbs_g": 570.4, "total_fat_g": 216.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the pastry", "instruction": "Process the flour, salt and sugar in a food processor, add the butter and process until it resembles coarse meal, then add water in a slow stream until the dough just holds together.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Chill the pastry", "instruction": "Gather into a ball, divide in half, flatten into discs, wrap and refrigerate.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Line the pie tin", "instruction": "Roll one portion into a 12-inch circle and transfer to a 9-inch pie pan, trimming the overhang. Refrigerate while making the filling.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Prep the lattice strips", "instruction": "Roll the second portion into a circle and cut into strips, then chill on a lined baking sheet.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Make the filling", "instruction": "Combine the strawberries and rhubarb in a bowl. Mix the cornstarch, sugar and cinnamon in a separate bowl.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Fill the crust", "instruction": "Sprinkle some of the sugar mixture over the pastry base, toss the rest with the fruit, and pour into the pie shell. Sprinkle with lemon juice and dot with butter.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Lattice the top", "instruction": "Weave the chilled pastry strips over the filling to form a lattice, trim, seal and flute the edges, then brush with milk and sprinkle with sugar. Chill while preheating the oven to 400°F.", "timer_seconds": null, "background": true}, {"step": 8, "label": "Bake", "instruction": "Place on a foil-lined baking sheet in the oven and bake, covering the edges with foil if browning too fast, until golden and the juices bubble.", "timer_seconds": 2700, "background": true}, {"step": 9, "label": "Cool and serve", "instruction": "Cool on a wire rack for several hours before serving with whipped cream or ice cream.", "timer_seconds": null, "background": true}], "video": "https://www.youtube.com/watch?v=tGw5Pwm4YA0"}, {"id": "53006", "name": "Moussaka", "category": "Beef", "area": "Greek", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/ctg8jd1585563097.jpg", "local_image": "53006.jpg", "ingredients": [{"ingredient": "Beef", "measure": "500g"}, {"ingredient": "Aubergine", "measure": "1 large"}, {"ingredient": "Greek Yogurt", "measure": "150g"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Parmesan", "measure": "3 tbs"}, {"ingredient": "Tomato", "measure": "400g"}, {"ingredient": "Tomato Puree", "measure": "4 tbs"}, {"ingredient": "Potatoes", "measure": "350g"}], "instructions": "Heat the grill to high. Brown the beef in a deep ovenproof frying pan over a high heat for 5 mins. Meanwhile, prick the aubergine with a fork, then microwave on High for 3-5 mins until soft. Mix the yogurt, egg and parmesan together, then add a little seasoning.\r\n\r\nStir the tomatoes, purée and potatoes in with the beef with some seasoning and heat through. Smooth the surface of the beef mixture with the back of a spoon, then slice the cooked aubergine and arrange on top. Pour the yogurt mixture over the aubergines, smooth out evenly, then grill until the topping has set and turned golden.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 571, "protein_g": 50.3, "carbs_g": 32.6, "fat_g": 27.4, "total_kcal": 1714, "total_protein_g": 150.8, "total_carbs_g": 97.9, "total_fat_g": 82.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "Heat the grill to high. Brown the beef in a deep ovenproof frying pan over high heat.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Soften the aubergine", "instruction": "Meanwhile, prick the aubergine with a fork and microwave until soft.", "timer_seconds": 240, "background": true}, {"step": 3, "label": "Make the topping", "instruction": "Mix the yogurt, egg and parmesan together, then season.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Build the base", "instruction": "Stir the tomatoes, purée and potatoes into the beef, season, and heat through, then smooth the surface.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Top and grill", "instruction": "Slice the cooked aubergine and arrange on top, pour over the yogurt mixture, smooth out, and grill until set and golden.", "timer_seconds": 480, "background": false}], "video": "https://www.youtube.com/watch?v=8U_29i9Qp5U"}, {"id": "53007", "name": "Honey Yogurt Cheesecake", "category": "Dessert", "area": "Greek", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/y2irzl1585563479.jpg", "local_image": "53007.jpg", "ingredients": [{"ingredient": "Digestive Biscuits", "measure": "100g"}, {"ingredient": "Almonds", "measure": "85g"}, {"ingredient": "Butter", "measure": "85g"}, {"ingredient": "Greek Yogurt", "measure": "250ml"}, {"ingredient": "Mascarpone", "measure": "750g"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Honey", "measure": "250ml"}, {"ingredient": "Fruit Mix", "measure": "To serve"}], "instructions": "Heat oven to 160C/140C fan/gas 3. Crush the biscuits and most of the almonds inside a plastic food bag using a rolling pin. Mix with the butter, then press into the bottom of a deep, oval, 23cm dish (or something similar in size – a roasting tin, baking dish or cake tin will work). Bake for 10 mins until crisp.\r\n\r\nStir or mash together the yogurt and mascarpone, then whisk in the eggs, one at a time. Stir in the lemon and orange zests, then stir in most of the honey, reserving about 3 tbsp. Spread over the biscuit base, cover loosely with foil and cook for 1 hr. Remove the foil and cook for 15 mins more until lightly golden and the top is firm with just the slightest wobble in the middle. Leave to cool. Can be kept in the fridge for up to 2 days.\r\n\r\nTo serve, scatter with almonds, drizzle over the remaining honey, and hand around fresh fruit to go with it.", "equipment_tags": [], "portions": 12, "prep_minutes": 85, "prep_minutes_source": "explicit", "kcal": 525, "protein_g": 8.3, "carbs_g": 36.3, "fat_g": 40.4, "total_kcal": 6296, "total_protein_g": 99.2, "total_carbs_g": 435.9, "total_fat_g": 485.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and make the base", "instruction": "Heat the oven to 160°C/140°C fan/gas 3. Crush the biscuits and most of the almonds, mix with the butter, and press into a deep dish.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bake the base", "instruction": "Bake until crisp.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Make the filling", "instruction": "Mash together the yogurt and mascarpone, whisk in the eggs one at a time, then stir in the lemon and orange zests and most of the honey.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake covered", "instruction": "Spread the filling over the biscuit base, cover loosely with foil, and bake.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Finish baking", "instruction": "Remove the foil and bake further until lightly golden and just barely wobbling in the middle.", "timer_seconds": 900, "background": true}, {"step": 6, "label": "Cool and serve", "instruction": "Leave to cool, then scatter with almonds, drizzle with the remaining honey, and serve with fresh fruit.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=JE8crtueXs8"}, {"id": "53008", "name": "Stuffed Lamb Tomatoes", "category": "Lamb", "area": "Greek", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/u55lbp1585564013.jpg", "local_image": "53008.jpg", "ingredients": [{"ingredient": "Tomatoes", "measure": "4 large"}, {"ingredient": "Sugar", "measure": "Pinch"}, {"ingredient": "Olive Oil", "measure": "4 tbs"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic Clove", "measure": "2 finely chopped"}, {"ingredient": "Lamb", "measure": "200g"}, {"ingredient": "Cinnamon", "measure": "1 tbs"}, {"ingredient": "Tomato Puree", "measure": "2 tbs chopped"}, {"ingredient": "Rice", "measure": "50g"}, {"ingredient": "Chicken Stock", "measure": "100ml"}, {"ingredient": "Dill", "measure": "4 tbs"}, {"ingredient": "Chopped Parsley", "measure": "2 tbs"}, {"ingredient": "Mint", "measure": "1 tbs"}], "instructions": "Heat oven to 180C/160C fan/gas 4. Slice the tops off the tomatoes and reserve. Scoop out most of the pulp with a teaspoon, being careful not to break the skin. Finely chop the pulp, and keep any juices. Sprinkle the insides of the tomatoes with a little sugar to take away the acidity, then place them on a baking tray.\r\n\r\nHeat 2 tbsp olive oil in a large frying pan, add the onion and garlic, then gently cook for about 10 mins until soft but not coloured. Add the lamb, cinnamon and tomato purée, turn up the heat, then fry until the meat is browned. Add the tomato pulp and juice, the rice and the stock. Season generously. Bring to the boil, then simmer for 15 mins or until the rice is tender and the liquid has been absorbed. Set aside to cool a little, then stir in the herbs.\r\n\r\nStuff the tomatoes up to the brim, top tomatoes with their lids, drizzle with 2 tbsp more olive oil, sprinkle 3 tbsp water into the tray, then bake for 35 mins. Serve with salad and crusty bread, hot or cold.", "equipment_tags": [], "portions": 2, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 748, "protein_g": 32.4, "carbs_g": 47.1, "fat_g": 50.0, "total_kcal": 1495, "total_protein_g": 64.7, "total_carbs_g": 94.2, "total_fat_g": 99.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the tomatoes", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Slice the tops off the tomatoes, scoop out the pulp, chop it finely reserving the juices, and sprinkle the insides with sugar. Place on a baking tray.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the filling", "instruction": "Heat oil in a large frying pan, cook the onion and garlic gently until soft. Add the lamb, cinnamon and tomato purée, and fry until the meat is browned.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Simmer the rice filling", "instruction": "Add the tomato pulp and juice, rice and stock, season, bring to the boil, then simmer until the rice is tender and the liquid absorbed.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Cool and add herbs", "instruction": "Set aside to cool a little, then stir in the herbs.", "timer_seconds": null, "background": true}, {"step": 5, "label": "Stuff and bake", "instruction": "Stuff the tomatoes, top with their lids, drizzle with oil, sprinkle water into the tray, and bake.", "timer_seconds": 2100, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve with salad and crusty bread, hot or cold.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=KfJp-QfrCz4"}, {"id": "53009", "name": "Lamb and Lemon Souvlaki", "category": "Lamb", "area": "Greek", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rjhf741585564676.jpg", "local_image": "53009.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Sea Salt", "measure": "2 tsp"}, {"ingredient": "Olive Oil", "measure": "4 tbs"}, {"ingredient": "Lemon", "measure": "Zest and juice of 1"}, {"ingredient": "Dill", "measure": "1 tbs"}, {"ingredient": "Lamb Leg", "measure": "750g"}, {"ingredient": "Pita Bread", "measure": "To serve"}], "instructions": "Pound the garlic with sea salt in a pestle and mortar (or use a small food processor), until the garlic forms a paste. Whisk together the oil, lemon juice, zest, dill and garlic. Mix in the lamb and combine well. Cover and marinate for at least 2 hrs or overnight in the fridge. If you’re going to use bamboo skewers, soak them in cold water.\r\n\r\nIf you’ve prepared the lamb the previous day, take it out of the fridge 30 mins before cooking. Thread the meat onto the soaked or metal skewers. Heat the grill to high or have a hot griddle pan or barbecue ready. Cook the skewers for 2-3 mins on each side, basting with the remaining marinade. Heat the pitta or flatbreads briefly, then stuff with the souvlaki. Add Greek salad (see 'Goes well with', right) and Tzatziki (below), if you like.", "equipment_tags": ["FoodProcessor", "Grill"], "portions": 2, "prep_minutes": 153, "prep_minutes_source": "explicit", "kcal": 1398, "protein_g": 95.7, "carbs_g": 10.3, "fat_g": 107.0, "total_kcal": 2797, "total_protein_g": 191.4, "total_carbs_g": 20.5, "total_fat_g": 213.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the marinade", "instruction": "Pound the garlic with sea salt into a paste, then whisk together with the oil, lemon juice, zest and dill.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the lamb", "instruction": "Mix the lamb into the marinade, cover, and marinate in the fridge. Soak bamboo skewers if using.", "timer_seconds": 7200, "background": true}, {"step": 3, "label": "Skewer and grill", "instruction": "Thread the lamb onto skewers, then grill or griddle on each side, basting with the remaining marinade.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Serve", "instruction": "Warm the pita briefly, then stuff with the souvlaki and serve with salad and tzatziki.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=krR4rhjR75Y"}, {"id": "53010", "name": "Lamb Tzatziki Burgers", "category": "Lamb", "area": "Greek", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/k420tj1585565244.jpg", "local_image": "53010.jpg", "ingredients": [{"ingredient": "Bulgur Wheat", "measure": "25g"}, {"ingredient": "Lamb Mince", "measure": "500g"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Olive Oil", "measure": "For frying"}, {"ingredient": "Bun", "measure": "4"}, {"ingredient": "Cucumber", "measure": "Grated"}, {"ingredient": "Greek Yogurt", "measure": "200g"}, {"ingredient": "Mint", "measure": "2 tbs"}], "instructions": "Tip the bulghar into a pan, cover with water and boil for 10 mins. Drain really well in a sieve, pressing out any excess water.\r\n\r\nTo make the tzatziki, squeeze and discard the juice from the cucumber, then mix into the yogurt with the chopped mint and a little salt.\r\n\r\nWork the bulghar into the lamb with the spices, garlic (if using) and seasoning, then shape into 4 burgers. Brush with a little oil and fry or barbecue for about 5 mins each side until cooked all the way through. Serve in the buns (toasted if you like) with the tzatziki, tomatoes, onion and a few mint leaves.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 1255, "protein_g": 68.6, "carbs_g": 66.3, "fat_g": 79.2, "total_kcal": 2511, "total_protein_g": 137.2, "total_carbs_g": 132.7, "total_fat_g": 158.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the bulgur", "instruction": "Cover the bulgur with water in a pan and boil, then drain well, pressing out excess water.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Make the tzatziki", "instruction": "Squeeze and discard the juice from the cucumber, then mix with the yogurt, mint and a little salt.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Shape the burgers", "instruction": "Work the bulgur into the lamb with the spices, garlic and seasoning, then shape into 4 burgers.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the burgers", "instruction": "Brush with oil and fry or barbecue until cooked all the way through.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve in buns with the tzatziki, tomatoes, onion and mint leaves.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=s7_TF4ZHjPc"}, {"id": "53011", "name": "Chicken Quinoa Greek Salad", "category": "Chicken", "area": "Greek", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/k29viq1585565980.jpg", "local_image": "53011.jpg", "ingredients": [{"ingredient": "Quinoa", "measure": "225g"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Chicken Breast", "measure": "400g"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Black Olives", "measure": "Handful"}, {"ingredient": "Red Onions", "measure": "1 chopped"}, {"ingredient": "Feta", "measure": "100g"}, {"ingredient": "Mint", "measure": "Chopped"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}], "instructions": "Cook the quinoa following the pack instructions, then rinse in cold water and drain thoroughly.\r\n\r\nMeanwhile, mix the butter, chilli and garlic into a paste. Toss the chicken fillets in 2 tsp of the olive oil with some seasoning. Lay in a hot griddle pan and cook for 3-4 mins each side or until cooked through. Transfer to a plate, dot with the spicy butter and set aside to melt.\r\n\r\nNext, tip the tomatoes, olives, onion, feta and mint into a bowl. Toss in the cooked quinoa. Stir through the remaining olive oil, lemon juice and zest, and season well. Serve with the chicken fillets on top, drizzled with any buttery chicken juices.", "equipment_tags": [], "portions": 8, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 265, "protein_g": 17.5, "carbs_g": 21.4, "fat_g": 12.1, "total_kcal": 2120, "total_protein_g": 139.8, "total_carbs_g": 171.0, "total_fat_g": 96.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the quinoa", "instruction": "Cook the quinoa following pack instructions, then rinse in cold water and drain thoroughly.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Cook the chicken", "instruction": "Meanwhile, mix the butter, chilli and garlic into a paste. Toss the chicken in olive oil and seasoning, then griddle until cooked through, transfer to a plate, and dot with the spicy butter.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Assemble the salad", "instruction": "Combine the tomatoes, olives, onion, feta and mint in a bowl, then toss in the cooked quinoa with the remaining olive oil, lemon juice and zest, and season.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Serve the salad with the chicken fillets on top, drizzled with the buttery pan juices.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=akcrkXYr61M"}, {"id": "53012", "name": "Gigantes Plaki", "category": "Vegetarian", "area": "Greek", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/b79r6f1585566277.jpg", "local_image": "53012.jpg", "ingredients": [{"ingredient": "Butter Beans", "measure": "400g"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic Clove", "measure": "2 chopped"}, {"ingredient": "Tomato Puree", "measure": "2 tbs"}, {"ingredient": "Tomatoes", "measure": "800g"}, {"ingredient": "Sugar", "measure": "1 tbs"}, {"ingredient": "Dried Oregano", "measure": "1 tbs"}, {"ingredient": "Cinnamon", "measure": "Pinch"}, {"ingredient": "Chopped Parsley", "measure": "2 tbs"}], "instructions": "Soak the beans overnight in plenty of water. Drain, rinse, then place in a pan covered with water. Bring to the boil, reduce the heat, then simmer for approx 50 mins until slightly tender but not soft. Drain, then set aside.\r\n\r\nHeat oven to 180C/160C fan/gas 4. Heat the olive oil in a large frying pan, tip in the onion and garlic, then cook over a medium heat for 10 mins until softened but not browned. Add the tomato purée, cook for a further min, add remaining ingredients, then simmer for 2-3 mins. Season generously, then stir in the beans. Tip into a large ovenproof dish, then bake for approximately 1 hr, uncovered and without stirring, until the beans are tender. The beans will absorb all the fabulous flavours and the sauce will thicken. Allow to cool, then scatter with parsley and drizzle with a little more olive oil to serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 123, "prep_minutes_source": "explicit", "kcal": 399, "protein_g": 15.7, "carbs_g": 55.2, "fat_g": 15.4, "total_kcal": 1197, "total_protein_g": 47.2, "total_carbs_g": 165.7, "total_fat_g": 46.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the beans", "instruction": "Soak the beans overnight in plenty of water.", "timer_seconds": 43200, "background": true}, {"step": 2, "label": "Simmer the beans", "instruction": "Drain and rinse the beans, cover with water in a pan, bring to a boil, reduce heat, then simmer until slightly tender but not soft. Drain and set aside.", "timer_seconds": 3000, "background": true}, {"step": 3, "label": "Build the sauce", "instruction": "Heat the oven to 180°C/160°C fan/gas 4. Heat the oil in a large pan, cook the onion and garlic until softened. Add the tomato purée and cook briefly, then add the remaining ingredients and simmer.", "timer_seconds": 780, "background": false}, {"step": 4, "label": "Bake", "instruction": "Season generously, stir in the beans, tip into an ovenproof dish, and bake uncovered without stirring until the beans are tender and the sauce has thickened.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Cool and serve", "instruction": "Allow to cool, then scatter with parsley and drizzle with olive oil to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=e-2K2iyPASA"}, {"id": "53013", "name": "Big Mac", "category": "Beef", "area": "United States", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/urzj1d1587670726.jpg", "local_image": "53013.jpg", "ingredients": [{"ingredient": "Minced Beef", "measure": "400g"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Sesame Seed Burger Buns", "measure": "2"}, {"ingredient": "Onion", "measure": "Chopped"}, {"ingredient": "Iceberg Lettuce", "measure": "1/4"}, {"ingredient": "Cheese", "measure": "2 sliced"}, {"ingredient": "Dill Pickles", "measure": "2 large"}, {"ingredient": "Mayonnaise", "measure": "1 cup"}, {"ingredient": "White Wine Vinegar", "measure": "2 tsp"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Mustard", "measure": "2 tsp"}, {"ingredient": "Onion Salt", "measure": "1 1/2 tsp"}, {"ingredient": "Garlic Powder", "measure": "1 1/2 tsp"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}], "instructions": "For the Big Mac sauce, combine all the ingredients in a bowl, season with salt and chill until ready to use.\r\n2. To make the patties, season the mince with salt and pepper and form into 4 balls using about 1/3 cup mince each. Place each onto a square of baking paper and flatten to form into four x 15cm circles. Heat oil in a large frypan over high heat. In 2 batches, cook beef patties for 1-2 minutes each side until lightly charred and cooked through. Remove from heat and keep warm. Repeat with remaining two patties.\r\n3. Carefully slice each burger bun into three acrossways, then lightly toast.\r\n4. To assemble the burgers, spread a little Big Mac sauce over the bottom base. Top with some chopped onion, shredded lettuce, slice of cheese, beef patty and some pickle slices. Top with the middle bun layer, and spread with more Big Mac sauce, onion, lettuce, pickles, beef patty and then finish with more sauce. Top with burger lid to serve.\r\n5. After waiting half an hour for your food to settle, go for a jog.", "equipment_tags": [], "portions": 2, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 1951, "protein_g": 58.9, "carbs_g": 22.1, "fat_g": 183.7, "total_kcal": 3903, "total_protein_g": 117.8, "total_carbs_g": 44.2, "total_fat_g": 367.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the sauce", "instruction": "Combine all the Big Mac sauce ingredients in a bowl, season with salt, and chill until ready to use.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Shape the patties", "instruction": "Season the mince and form into 4 balls, then flatten each into 15cm circles on baking paper.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the patties", "instruction": "Heat oil in a large frying pan over high heat, and cook the patties in batches until lightly charred and cooked through.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Prep the buns", "instruction": "Slice each burger bun into three across, then lightly toast.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Assemble", "instruction": "Spread sauce on the bottom bun, top with onion, lettuce, cheese, a patty and pickles, add the middle bun layer with more toppings and sauce, and top with the bun lid.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=C5J39YnnPsg"}, {"id": "53014", "name": "Pizza Express Margherita", "category": "Miscellaneous", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/x0lk931587671540.jpg", "local_image": "53014.jpg", "ingredients": [{"ingredient": "Water", "measure": "150ml"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Yeast", "measure": "15g"}, {"ingredient": "Plain Flour", "measure": "225g"}, {"ingredient": "Salt", "measure": "1 1/2 tsp"}, {"ingredient": "Olive Oil", "measure": "Drizzle"}, {"ingredient": "Passata", "measure": "80g"}, {"ingredient": "Mozzarella", "measure": "70g"}, {"ingredient": "Oregano", "measure": "Peeled and Sliced"}, {"ingredient": "Basil", "measure": "Leaves"}, {"ingredient": "Black Pepper", "measure": "Pinch"}], "instructions": "1 Preheat the oven to 230°C.\r\n\r\n2 Add the sugar and crumble the fresh yeast into warm water.\r\n\r\n3 Allow the mixture to stand for 10 – 15 minutes in a warm place (we find a windowsill on a sunny day works best) until froth develops on the surface.\r\n\r\n4 Sift the flour and salt into a large mixing bowl, make a well in the middle and pour in the yeast mixture and olive oil.\r\n\r\n5 Lightly flour your hands, and slowly mix the ingredients together until they bind.\r\n\r\n6 Generously dust your surface with flour.\r\n\r\n7 Throw down the dough and begin kneading for 10 minutes until smooth, silky and soft.\r\n\r\n8 Place in a lightly oiled, non-stick baking tray (we use a round one, but any shape will do!)\r\n\r\n9 Spread the passata on top making sure you go to the edge.\r\n\r\n10 Evenly place the mozzarella (or other cheese) on top, season with the oregano and black pepper, then drizzle with a little olive oil.\r\n\r\n11 Cook in the oven for 10 – 12 minutes until the cheese slightly colours.\r\n\r\n12 When ready, place the basil leaf on top and tuck in!", "equipment_tags": [], "portions": 1, "prep_minutes": 37, "prep_minutes_source": "explicit", "kcal": 1439, "protein_g": 51.7, "carbs_g": 206.3, "fat_g": 46.6, "total_kcal": 1439, "total_protein_g": 51.7, "total_carbs_g": 206.3, "total_fat_g": 46.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and activate the yeast", "instruction": "Preheat the oven to 230°C. Add sugar and crumbled fresh yeast to warm water and let stand until frothy.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Make the dough", "instruction": "Sift the flour and salt into a bowl, make a well, pour in the yeast mixture and olive oil, and mix together with floured hands.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Knead", "instruction": "Turn onto a floured surface and knead until smooth, silky and soft.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Shape and top", "instruction": "Place on an oiled baking tray, spread with passata to the edges, top with mozzarella, season with oregano and black pepper, and drizzle with olive oil.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake and serve", "instruction": "Bake until the cheese slightly colours, then top with a basil leaf and serve.", "timer_seconds": 660, "background": true}], "video": "https://www.youtube.com/watch?v=Mt5lgUZRoUg"}, {"id": "53015", "name": "Krispy Kreme Donut", "category": "Dessert", "area": "United States", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/4i5cnx1587672171.jpg", "local_image": "53015.jpg", "ingredients": [{"ingredient": "Yeast", "measure": "1/4 ounce"}, {"ingredient": "Water", "measure": "1/4 cup"}, {"ingredient": "Water", "measure": "1 1/2 cups"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Shortening", "measure": "1/3 cup"}, {"ingredient": "Flour", "measure": "5 drops"}, {"ingredient": "Canola Oil", "measure": "Sprinking"}, {"ingredient": "Milk", "measure": "1/2 cup"}, {"ingredient": "Sugar", "measure": "2 cups"}, {"ingredient": "Vanilla", "measure": "1 1/2 cups"}, {"ingredient": "Boiling Water", "measure": "6 tablespoons"}, {"ingredient": "Butter", "measure": "1/3 cup"}], "instructions": "Dissolve yeast in warm water in 2 1/2-quart bowl. Add milk, sugar, salt, eggs, shortening and 2 cups flour. Beat on low for 30 seconds, scraping bowl constantly. Beat on medium speed for 2 minutes, scraping bowl occasionally. Stir in remaining flour until smooth. Cover and let rise until double, 50-60 minutes. (Dough is ready when indentation remains when touched.) Turn dough onto floured surface; roll around lightly to coat with flour. Gently roll dough 1/2-inch thick with floured rolling pin. Cut with floured doughnut cutter. Cover and let rise until double, 30-40 minutes.\r\nHeat vegetable oil in deep fryer to 350°. Slide doughnuts into hot oil with wide spatula. Turn doughnuts as they rise to the surface. Fry until golden brown, about 1 minute on each side. Remove carefully from oil (do not prick surface); drain. Dip the doughnuts into creamy glaze set on rack.\r\n\r\n\r\nGlaze: \r\nHeat butter until melted. Remove from heat. Stir in powdered sugar and vanilla until smooth. Stir in water, 1 tablespoon at a time, until desired consistency.", "equipment_tags": [], "portions": 12, "prep_minutes": 103, "prep_minutes_source": "explicit", "kcal": 474, "protein_g": 3.8, "carbs_g": 63.0, "fat_g": 15.8, "total_kcal": 5683, "total_protein_g": 45.7, "total_carbs_g": 755.6, "total_fat_g": 189.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Dissolve the yeast in warm water, then add milk, sugar, salt, eggs, shortening and part of the flour. Beat on low, then medium speed, then stir in the remaining flour until smooth.", "timer_seconds": 150, "background": false}, {"step": 2, "label": "First rise", "instruction": "Cover and let rise until doubled.", "timer_seconds": 3300, "background": true}, {"step": 3, "label": "Roll and cut", "instruction": "Turn onto a floured surface, roll to 1/2-inch thickness, and cut with a floured doughnut cutter.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Second rise", "instruction": "Cover and let rise until doubled again.", "timer_seconds": 2100, "background": true}, {"step": 5, "label": "Fry", "instruction": "Heat oil in a deep fryer to 350°F, and fry the doughnuts, turning as they rise, until golden brown on each side.", "timer_seconds": 120, "background": false}, {"step": 6, "label": "Make the glaze and finish", "instruction": "Melt the butter, remove from heat, stir in powdered sugar and vanilla until smooth, then thin with water to the desired consistency. Dip the warm doughnuts in the glaze.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=SamYg6IUGOI"}, {"id": "53016", "name": "Chick-Fil-A Sandwich", "category": "Chicken", "area": "United States", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/sbx7n71587673021.jpg", "local_image": "53016.jpg", "ingredients": [{"ingredient": "Chicken Breast", "measure": "1"}, {"ingredient": "Pickle Juice", "measure": "1/4 cup"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Milk", "measure": "1/4 cup"}, {"ingredient": "Flour", "measure": "1/2 cup"}, {"ingredient": "Icing Sugar", "measure": "1 tbs"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Garlic Powder", "measure": "1/4 tsp"}, {"ingredient": "Celery Salt", "measure": "1/4 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 tsp"}, {"ingredient": "Olive Oil", "measure": "1 cup"}, {"ingredient": "Sesame Seed Burger Buns", "measure": "1"}], "instructions": "Wrap the chicken loosely between plastic wrap and pound gently with the flat side of a meat tenderizer until about 1/2 inch thick all around.\r\nCut into two pieces, as even as possible.\r\nMarinate in the pickle juice for 30 minutes to one hour (add a teaspoon of Tabasco sauce now for a spicy sandwich).\r\nBeat the egg with the milk in a bowl.\r\nCombine the flour, sugar, and spices in another bowl.\r\nDip the chicken pieces each into the egg on both sides, then coat in flour on both sides.\r\nHeat the oil in a skillet (1/2 inch deep) to about 345-350.\r\nFry each cutlet for 2 minutes on each side, or until golden and cooked through.\r\nBlot on paper and serve on toasted buns with pickle slices.", "equipment_tags": [], "portions": 1, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 1039, "protein_g": 58.6, "carbs_g": 81.2, "fat_g": 55.0, "total_kcal": 1039, "total_protein_g": 58.6, "total_carbs_g": 81.2, "total_fat_g": 55.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep and marinate the chicken", "instruction": "Pound the chicken to about 1/2 inch thick, cut into two pieces, and marinate in the pickle juice (adding Tabasco for spice if you like).", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Prep the coatings", "instruction": "Beat the egg with the milk in one bowl, and combine the flour, sugar and spices in another.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Coat the chicken", "instruction": "Dip the chicken into the egg, then coat in the flour mixture on both sides.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fry", "instruction": "Heat the oil to 345-350°F and fry each cutlet until golden and cooked through.", "timer_seconds": 240, "background": false}, {"step": 5, "label": "Serve", "instruction": "Blot on paper towel and serve on toasted buns with pickle slices.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=1WDesu7bUDM"}, {"id": "53017", "name": "Paszteciki (Polish Pasties)", "category": "Beef", "area": "Polish", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/c9a3l31593261890.jpg", "local_image": "53017.jpg", "ingredients": [{"ingredient": "Flour", "measure": "1 cup"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Egg", "measure": "1 Yolk"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Butter", "measure": "5 tbs"}, {"ingredient": "Butter", "measure": "6 tblsp"}, {"ingredient": "Onion", "measure": "1/3 cup"}, {"ingredient": "Swede", "measure": "1/2 cup"}, {"ingredient": "Beef Brisket", "measure": "1/2 lb"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1/4 tsp"}], "instructions": "Sift flour and salt into a large mixing bowl.\r\nUse a spoon to push the egg yolk through a fine sieve into the flour.\r\nAdd the raw egg and mix well.\r\nBeat in butter 1 tablespoon at a time.\r\nPlace dough on a floured surface and knead until smooth and elastic, then wrap in waxed paper and refrigerate until firm (at least 30 minutes).\r\nIn a heavy skillet, melt 2 tablespoons butter over medium heat; saute the onion and rutabaga until the onion is soft and transparent (5 minutes).\r\nPut the onions, rutabaga, and beef through a meat grinder twice if you have one, if not just chop them up as fine as possible.\r\nMelt the remaining 4 tablespoons butter over medium heat, and add the meat mixture.\r\nCook over low heat, stirring occasionally, until all of the liquid has evaporated and the mixture is thick enough to hold its shape.\r\nRemove from heat and let cool, then stir in 1 egg, and season with salt and pepper.\r\nPreheat oven to 350°F.\r\nOn a lightly floured surface, roll the dough out into a 13x8\" rectangle (1/8\" thick).\r\nSpoon the filling down the center of the rectangle lengthwise, leaving about an inch of space on each end.\r\nLightly brush the long sides with cold water, then fold one of the long sides over the filling and the other side over the top of that.\r\nBrush the short ends with cold water and fold them over the top, enclosing the filling.\r\nPlace pastry seam side down on a baking sheet and brush the top evenly with the remaining scrambled egg.\r\nBake in preheated oven until rich golden brown (30 minutes).\r\nSlice pastry diagonally into 1.5\" long pieces and serve as an appetizer or with soup.", "equipment_tags": [], "portions": 2, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 1186, "protein_g": 43.9, "carbs_g": 58.5, "fat_g": 87.4, "total_kcal": 2373, "total_protein_g": 87.8, "total_carbs_g": 117.0, "total_fat_g": 174.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the pastry", "instruction": "Sift the flour and salt, push the egg yolk through a sieve into the flour, add the raw egg, and mix well, then beat in the butter a tablespoon at a time.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Chill the dough", "instruction": "Knead until smooth and elastic, wrap, and refrigerate until firm.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Cook the onion and rutabaga", "instruction": "Melt butter in a skillet and sauté the onion and rutabaga until the onion is soft and transparent.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Grind and cook the filling", "instruction": "Grind or finely chop the onion, rutabaga and beef together, then cook in the remaining melted butter over low heat, stirring, until the liquid has evaporated and the mixture holds its shape.", "timer_seconds": 900, "background": false}, {"step": 5, "label": "Finish the filling", "instruction": "Remove from heat, cool, stir in an egg, and season with salt and pepper.", "timer_seconds": null, "background": true}, {"step": 6, "label": "Assemble", "instruction": "Preheat the oven to 350°F. Roll the dough into a rectangle, spoon the filling down the centre, brush the long sides with water, fold over to seal, then fold the short ends over.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Bake", "instruction": "Place seam-side down on a baking sheet, brush with beaten egg, and bake until golden brown.", "timer_seconds": 1800, "background": true}, {"step": 8, "label": "Serve", "instruction": "Slice diagonally into pieces and serve as an appetizer or with soup.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=qANmR6BBJpQ"}, {"id": "53018", "name": "Bigos (Hunters Stew)", "category": "Pork", "area": "Polish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/md8w601593348504.jpg", "local_image": "53018.jpg", "ingredients": [{"ingredient": "Bacon", "measure": "2 sliced"}, {"ingredient": "Kielbasa", "measure": "1 lb"}, {"ingredient": "Pork", "measure": "1 lb"}, {"ingredient": "Flour", "measure": "1/4 cup"}, {"ingredient": "Garlic", "measure": "3 chopped"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Mushrooms", "measure": "1 1/2 cup"}, {"ingredient": "Cabbage", "measure": "4 cups"}, {"ingredient": "Sauerkraut", "measure": "1 Jar"}, {"ingredient": "Red Wine", "measure": "1/4 cup"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Basil", "measure": "1 tsp"}, {"ingredient": "Marjoram", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tbs"}, {"ingredient": "Caraway Seed", "measure": "1/8 teaspoon"}, {"ingredient": "Hotsauce", "measure": "1 dash"}, {"ingredient": "Beef Stock", "measure": "5 Cups"}, {"ingredient": "Tomato Puree", "measure": "2 tbs"}, {"ingredient": "Diced Tomatoes", "measure": "1 cup"}, {"ingredient": "Worcestershire Sauce", "measure": "1 dash"}], "instructions": "Preheat the oven to 350 degrees F (175 degrees C).\r\n\r\nHeat a large pot over medium heat. Add the bacon and kielbasa; cook and stir until the bacon has rendered its fat and sausage is lightly browned. Use a slotted spoon to remove the meat and transfer to a large casserole or Dutch oven.\r\n\r\nCoat the cubes of pork lightly with flour and fry them in the bacon drippings over medium-high heat until golden brown. Use a slotted spoon to transfer the pork to the casserole. Add the garlic, onion, carrots, fresh mushrooms, cabbage and sauerkraut. Reduce heat to medium; cook and stir until the carrots are soft, about 10 minutes. Do not let the vegetables brown.\r\n\r\nDeglaze the pan by pouring in the red wine and stirring to loosen all of the bits of food and flour that are stuck to the bottom. Season with the bay leaf, basil, marjoram, paprika, salt, pepper, caraway seeds and cayenne pepper; cook for 1 minute.\r\n\r\nMix in the dried mushrooms, hot pepper sauce, Worcestershire sauce, beef stock, tomato paste and tomatoes. Heat through just until boiling. Pour the vegetables and all of the liquid into the casserole dish with the meat. Cover with a lid.\r\n\r\nBake in the preheated oven for 2 1/2 to 3 hours, until meat is very tender.", "equipment_tags": [], "portions": 9, "prep_minutes": 191, "prep_minutes_source": "explicit", "kcal": 402, "protein_g": 27.1, "carbs_g": 23.8, "fat_g": 22.7, "total_kcal": 3622, "total_protein_g": 243.7, "total_carbs_g": 214.2, "total_fat_g": 203.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and brown the meats", "instruction": "Preheat the oven to 350°F/175°C. Cook the bacon and kielbasa in a large pot until the bacon renders and the sausage browns, then transfer to a casserole dish.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Brown the pork", "instruction": "Coat the pork cubes in flour and fry in the bacon drippings until golden brown, then transfer to the casserole.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Cook the vegetables", "instruction": "Add the garlic, onion, carrots, mushrooms, cabbage and sauerkraut to the pan and cook, stirring, until the carrots are soft without browning the vegetables.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Deglaze and season", "instruction": "Deglaze with the red wine, scraping up the bits, then season with bay leaf, basil, marjoram, paprika, salt, pepper, caraway and cayenne, and cook briefly.", "timer_seconds": 60, "background": false}, {"step": 5, "label": "Build the braise", "instruction": "Stir in the dried mushrooms, hot sauce, Worcestershire sauce, beef stock, tomato paste and tomatoes, and heat until just boiling.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Combine and braise", "instruction": "Pour the vegetables and liquid into the casserole with the meat, cover, and bake until the meat is very tender.", "timer_seconds": 9900, "background": true}], "video": "https://www.youtube.com/watch?v=Oqg_cO4s8ik"}, {"id": "53019", "name": "Pierogi (Polish Dumplings)", "category": "Side", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/45xxr21593348847.jpg", "local_image": "53019.jpg", "ingredients": [{"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Chopped Onion", "measure": "1/3 cup"}, {"ingredient": "Sauerkraut", "measure": "1 1/2 cups"}, {"ingredient": "Butter", "measure": "3 tbs"}, {"ingredient": "Chopped Onion", "measure": "1/2 cup"}, {"ingredient": "Potatoes", "measure": "2 cups"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Sour Cream", "measure": "1 pot"}, {"ingredient": "Flour", "measure": "3 cups"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tbs"}], "instructions": "To prepare the sauerkraut filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Add the drained sauerkraut and cook for an additional 5 minutes. Season to taste with salt and pepper, then remove to a plate to cool.\r\n\r\nFor the mashed potato filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Stir into the mashed potatoes, and season with salt and white pepper.\r\n\r\nTo make the dough, beat together the eggs and sour cream until smooth. Sift together the flour, salt, and baking powder; stir into the sour cream mixture until dough comes together. Knead the dough on a lightly floured surface until firm and smooth. Divide the dough in half, then roll out one half to 1/8 inch thickness. Cut into 3 inch rounds using a biscuit cutter.\r\n\r\nPlace a small spoonful of the mashed potato filling into the center of each round. Moisten the edges with water, fold over, and press together with a fork to seal. Repeat procedure with the remaining dough and the sauerkraut filling.\r\n\r\nBring a large pot of lightly salted water to a boil. Add perogies and cook for 3 to 5 minutes or until pierogi float to the top. Remove with a slotted spoon.", "equipment_tags": [], "portions": 9, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 305, "protein_g": 8.3, "carbs_g": 46.0, "fat_g": 9.7, "total_kcal": 2745, "total_protein_g": 74.5, "total_carbs_g": 413.9, "total_fat_g": 87.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the sauerkraut filling", "instruction": "Melt the butter in a skillet, cook the onion until translucent, add the drained sauerkraut, and cook a few minutes more. Season and cool.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Make the potato filling", "instruction": "Melt butter in a skillet, cook onion until translucent, then stir into mashed potatoes and season.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Make the dough", "instruction": "Beat the eggs and sour cream until smooth, sift in the flour, salt and baking powder, and mix until a dough forms, then knead until firm and smooth.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Roll and cut", "instruction": "Divide the dough in half, roll one half thin, and cut into rounds with a biscuit cutter.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fill and seal", "instruction": "Place a spoonful of filling into each round, moisten the edges, fold over and press to seal with a fork. Repeat with the remaining dough and both fillings.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Boil and serve", "instruction": "Boil the pierogi in salted water until they float to the top, then remove with a slotted spoon.", "timer_seconds": 240, "background": false}], "video": "https://www.youtube.com/watch?v=lyqDmUroZrI"}, {"id": "53020", "name": "Rosol (Polish Chicken Soup)", "category": "Chicken", "area": "Polish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/lx1kkj1593349302.jpg", "local_image": "53020.jpg", "ingredients": [{"ingredient": "Chicken Legs", "measure": "4 Chopped"}, {"ingredient": "Onions", "measure": "2 large"}, {"ingredient": "Carrots", "measure": "5 chopped"}, {"ingredient": "Leek", "measure": "1 chopped"}, {"ingredient": "Celery", "measure": "1 small"}, {"ingredient": "Cabbage", "measure": "1/4"}, {"ingredient": "Cloves", "measure": "1 whole"}, {"ingredient": "Allspice", "measure": "1tsp"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Parsley", "measure": "4 sprigs"}, {"ingredient": "Dill", "measure": "4 sprigs"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tbs"}], "instructions": "Add chicken to a large Dutch oven or stock pot \r\nCover with water\r\nBring to a boil and simmer for 2 to 2 1/2 hours, skimming any impurities off the top to insure a clear broth\r\nIf your pot is big enough, add the vegetables and spices for the last hour of the cooking time\r\nMy Dutch oven wasn’t big enough to hold everything, just the chicken and other bones filled the pot, so I cooked the meat/bones for the full cooking time, then removed them, and cooked the vegetables and spices separately\r\nStrain everything out of the broth\r\nBone the chicken, pulling the meat into large chunks\r\nSlice the carrots\r\nReturn the chicken and carrots to the broth\r\nCook noodles according to package instructions if you’re using them\r\nAdd noodles to bowl and then top with hot soup", "equipment_tags": [], "portions": 2, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 297, "protein_g": 25.0, "carbs_g": 35.0, "fat_g": 7.6, "total_kcal": 595, "total_protein_g": 49.9, "total_carbs_g": 70.0, "total_fat_g": 15.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Simmer the chicken", "instruction": "Add the chicken to a large pot, cover with water, bring to a boil, then simmer, skimming impurities off the top.", "timer_seconds": 7500, "background": true}, {"step": 2, "label": "Add the vegetables", "instruction": "For the last hour of cooking, add the vegetables and spices to the pot (or cook them separately if the pot isn't big enough).", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Strain and bone the chicken", "instruction": "Strain everything out of the broth, then bone the chicken, pulling the meat into large chunks, and slice the carrots.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Combine and cook noodles", "instruction": "Return the chicken and carrots to the broth. Cook noodles separately according to package instructions if using.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Serve", "instruction": "Add noodles to a bowl and top with the hot soup.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=AU60fxyxXGw"}, {"id": "53021", "name": "Golabki (cabbage roll)", "category": "Beef", "area": "Polish", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/q8sp3j1593349686.jpg", "local_image": "53021.jpg", "ingredients": [{"ingredient": "Cabbage", "measure": "1"}, {"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Ground Pork", "measure": "1/2 lb"}, {"ingredient": "Rice", "measure": "1 1/2 cups"}, {"ingredient": "Garlic", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Tomato Puree", "measure": "3 cans"}], "instructions": "Bring a large pot of lightly salted water to a boil. Place cabbage head into water, cover pot, and cook until cabbage leaves are slightly softened enough to remove from head, 3 minutes. Remove cabbage from pot and let cabbage sit until leaves are cool enough to handle, about 10 minutes.\r\n\r\nRemove 18 whole leaves from the cabbage head, cutting out any thick tough center ribs. Set whole leaves aside. Chop the remainder of the cabbage head and spread it in the bottom of a casserole dish.\r\n\r\nMelt butter in a large skillet over medium-high heat. Cook and stir onion in hot butter until tender, 5 to 10 minutes. Cool.\r\n\r\nStir onion, beef, pork, rice, garlic, 1 teaspoon salt, and 1/4 teaspoon pepper together in a large bowl.\r\n\r\nPreheat oven to 350 degrees F (175 degrees C).\r\n\r\nPlace about 1/2 cup beef mixture on a cabbage leaf. Roll cabbage around beef mixture, tucking in sides to create an envelope around the meat. Repeat with remaining leaves and meat mixture. Place cabbage rolls in a layer atop the chopped cabbage in the casserole dish; season rolls with salt and black pepper.\r\n\r\nWhisk tomato soup, tomato juice, and ketchup together in a bowl. Pour tomato soup mixture over cabbage rolls and cover dish wish aluminum foil.\r\n\r\nBake in the preheated oven until cabbage is tender and meat is cooked through, about 1 hour.", "equipment_tags": [], "portions": 5, "prep_minutes": 83, "prep_minutes_source": "explicit", "kcal": 778, "protein_g": 39.7, "carbs_g": 97.7, "fat_g": 28.1, "total_kcal": 3890, "total_protein_g": 198.4, "total_carbs_g": 488.4, "total_fat_g": 140.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the cabbage", "instruction": "Bring a large pot of salted water to a boil, add the whole cabbage head, cover, and cook until the leaves soften enough to remove.", "timer_seconds": 180, "background": false}, {"step": 2, "label": "Prep the leaves", "instruction": "Let the cabbage cool, then remove 18 whole leaves, cutting out thick ribs, and chop the remainder into the bottom of a casserole dish.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Cook the onion", "instruction": "Melt butter in a skillet and cook the onion until tender, then cool.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Make the filling", "instruction": "Combine the onion, beef, pork, rice, garlic, salt and pepper in a bowl.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Assemble the rolls", "instruction": "Preheat the oven to 350°F/175°C. Place filling on each cabbage leaf, roll up tucking in the sides, and arrange over the chopped cabbage in the dish, seasoning with salt and pepper.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Sauce and bake", "instruction": "Whisk the tomato soup, tomato juice and ketchup together, pour over the rolls, cover with foil, and bake until the cabbage is tender and meat cooked through.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=rBrTkDdoPYg"}, {"id": "53022", "name": "Polskie Nalesniki (Polish Pancakes)", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/58bkyo1593350017.jpg", "local_image": "53022.jpg", "ingredients": [{"ingredient": "Flour", "measure": "1 cup"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Water", "measure": "3/4 cup"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Butter", "measure": "3 tbs"}], "instructions": "Add flour, eggs, milk, water, and salt in a large bowl then mix with a hand mixer until you have a smooth, lump-free batter.\r\nAt this point, mix in the butter or the vegetable oil. Alternatively, you can use them to grease the pan before frying each pancake.\r\nHeat a non-stick pan over medium heat, then pour in the batter, swirling the pan to help it spread.\r\nWhen the pancake starts pulling away a bit from the sides, and the top is no longer wet, flip it and cook shortly on the other side as well.\r\nTransfer to a plate. Cook the remaining batter until all used up.\r\nServe warm, with the filling of your choice.", "equipment_tags": [], "portions": 5, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 216, "protein_g": 6.8, "carbs_g": 22.7, "fat_g": 10.8, "total_kcal": 1079, "total_protein_g": 33.8, "total_carbs_g": 113.6, "total_fat_g": 54.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the batter", "instruction": "Combine the flour, eggs, milk, water and salt and mix with a hand mixer until smooth and lump-free, then mix in the butter or use it to grease the pan.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the pancakes", "instruction": "Heat a non-stick pan over medium heat, pour in batter, swirling to spread, and cook until it pulls away from the sides and the top is dry, then flip and cook briefly on the other side.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Serve", "instruction": "Transfer to a plate and repeat with the remaining batter. Serve warm with the filling of your choice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=EZS4ev2crHc"}, {"id": "53023", "name": "Sledz w Oleju (Polish Herrings)", "category": "Seafood", "area": "Polish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/7ttta31593350374.jpg", "local_image": "53023.jpg", "ingredients": [{"ingredient": "Herring", "measure": "8"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Olive Oil", "measure": "1/2 cup"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Bay Leaf", "measure": "1"}], "instructions": "Soak herring in cold water for at least 1 hour. If very salty, repeat, changing the water each time.\r\n\r\nDrain thoroughly and slice herring into bite-size pieces.\r\n\r\nPlace in a jar large enough to accommodate the pieces and cover with oil, allspice, peppercorns, and bay leaf. Close the jar.\r\n\r\nRefrigerate for 2 to 3 days before eating. This will keep refrigerated up to 2 weeks.\r\n\r\nServe with finely chopped onion or onion slices, lemon, and parsley or dill.", "equipment_tags": [], "portions": 1, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 1679, "protein_g": 74.0, "carbs_g": 17.3, "fat_g": 147.1, "total_kcal": 1679, "total_protein_g": 74.0, "total_carbs_g": 17.3, "total_fat_g": 147.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the herring", "instruction": "Soak the herring in cold water, changing the water and repeating if very salty.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Slice", "instruction": "Drain thoroughly and slice the herring into bite-size pieces.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Pack and cover", "instruction": "Place the pieces in a jar and cover with oil, allspice, peppercorns and bay leaf, then close the jar.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Marinate", "instruction": "Refrigerate for 2 to 3 days before eating.", "timer_seconds": 216000, "background": true}, {"step": 5, "label": "Serve", "instruction": "Serve with chopped onion, lemon and parsley or dill.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=v6I3GZlBkOM"}, {"id": "53024", "name": "Rogaliki (Polish Croissant Cookies)", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/7mxnzz1593350801.jpg", "local_image": "53024.jpg", "ingredients": [{"ingredient": "Butter", "measure": "1 cup"}, {"ingredient": "Egg Yolks", "measure": "3"}, {"ingredient": "Cream Cheese", "measure": "8 oz"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Flour", "measure": "3 cups"}, {"ingredient": "Jam", "measure": "1 Jar"}], "instructions": "In a medium bowl mix egg yolks, philly cheese and baking powder using a hand held mixer. Carefully start adding the flour. When the mixture will not be mixing well, and will look like wood chips, put away the blending mixer and using your hands knead the dough.\r\nCreate a roll and cover in foil and freeze for 15 minutes. At this time preheat the oven to 375.\r\nTake the dough out and separate into two. Roll and cut out 3 inch trangles.\r\nMake as many as you can and on centre of each put a small spoon of jam. Roll them into a croissant shape.\r\nPlace the croissants onto a greased cookie sheet, and bake for 10-12 minutes or until golden.\r\nRepeat with the rest of the dough.\r\nWhen you take them out, put aside and sprinkle with powdered sugar on top.\r\nThis makes about 3 batches of 20 cookies each.\r\nTotal count about 60 cookies.", "equipment_tags": [], "portions": 8, "prep_minutes": 27, "prep_minutes_source": "explicit", "kcal": 625, "protein_g": 9.9, "carbs_g": 59.8, "fat_g": 38.5, "total_kcal": 4997, "total_protein_g": 78.8, "total_carbs_g": 478.6, "total_fat_g": 308.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Mix the egg yolks, cream cheese and baking powder with a hand mixer, then gradually add the flour, kneading by hand once it becomes crumbly.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Chill and preheat", "instruction": "Form into a roll, wrap in foil, and freeze while preheating the oven to 375°F.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Shape the cookies", "instruction": "Separate the dough in two, roll out, and cut into 3-inch triangles. Place a small spoon of jam in the centre of each and roll into a croissant shape.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Place on a greased cookie sheet and bake until golden, repeating with the rest of the dough.", "timer_seconds": 660, "background": true}, {"step": 5, "label": "Finish", "instruction": "Set aside to cool, then sprinkle with powdered sugar.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=VAR10T9mfhU"}, {"id": "53025", "name": "Ful Medames", "category": "Vegetarian", "area": "Egyptian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/lvn2d51598732465.jpg", "local_image": "53025.jpg", "ingredients": [{"ingredient": "Broad Beans", "measure": "2 cups"}, {"ingredient": "Parsley", "measure": "1/3 cup"}, {"ingredient": "Olive Oil", "measure": "Dash"}, {"ingredient": "Lemons", "measure": "3"}, {"ingredient": "Garlic Clove", "measure": "4"}, {"ingredient": "Cumin", "measure": "Sprinking"}], "instructions": "As the cooking time varies depending on the quality and age of the beans, it is good to cook them in advance and to reheat them when you are ready to serve. Cook the drained beans in a fresh portion of unsalted water in a large saucepan with the lid on until tender, adding water to keep them covered, and salt when the beans have softened. They take 2–2 1/2 hours of gentle simmering. When the beans are soft, let the liquid reduce. It is usual to take out a ladle or two of the beans and to mash them with some of the cooking liquid, then stir this back into the beans. This is to thicken the sauce.\r\nServe the beans in soup bowls sprinkled with chopped parsley and accompanied by Arab bread.\r\nPass round the dressing ingredients for everyone to help themselves: a bottle of extra-virgin olive oil, the quartered lemons, salt and pepper, a little saucer with the crushed garlic, one with chili-pepper flakes, and one with ground cumin.\r\nThe beans are eaten gently crushed with the fork, so that they absorb the dressing.\r\nOptional Garnishes\r\nPeel hard-boiled eggs—1 per person—to cut up in the bowl with the beans.\r\nTop the beans with a chopped cucumber-and-tomato salad and thinly sliced mild onions or scallions. Otherwise, pass round a good bunch of scallions and quartered tomatoes and cucumbers cut into sticks.\r\nServe with tahina cream sauce (page 65) or salad (page 67), with pickles and sliced onions soaked in vinegar for 30 minutes.\r\nAnother way of serving ful medames is smothered in a garlicky tomato sauce (see page 464).\r\nIn Syria and Lebanon, they eat ful medames with yogurt or feta cheese, olives, and small cucumbers.\r\nVariations\r\nA traditional way of thickening the sauce is to throw a handful of red lentils (1/4 cup) into the water at the start of the cooking.\r\nIn Iraq, large brown beans are used instead of the small Egyptian ones, in a dish called badkila, which is also sold for breakfast in the street.", "equipment_tags": [], "portions": 1, "prep_minutes": 150, "prep_minutes_source": "explicit", "kcal": 441, "protein_g": 31.5, "carbs_g": 78.7, "fat_g": 5.3, "total_kcal": 441, "total_protein_g": 31.5, "total_carbs_g": 78.7, "total_fat_g": 5.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Simmer the beans", "instruction": "Cook the drained beans in fresh unsalted water with the lid on until tender, adding water to keep them covered and salting once softened.", "timer_seconds": 8100, "background": true}, {"step": 2, "label": "Thicken", "instruction": "Once soft, reduce the liquid, then mash a couple ladles of beans with some cooking liquid and stir back in to thicken the sauce.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Serve", "instruction": "Serve in bowls sprinkled with chopped parsley alongside Arab bread, with olive oil, lemon wedges, garlic, chilli flakes and cumin passed around for everyone to season to taste.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ixpCabILuxw"}, {"id": "53026", "name": "Tamiya", "category": "Vegetarian", "area": "Egyptian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/n3xxd91598732796.jpg", "local_image": "53026.jpg", "ingredients": [{"ingredient": "Broad Beans", "measure": "3 cups"}, {"ingredient": "Spring Onions", "measure": "6"}, {"ingredient": "Garlic Clove", "measure": "4"}, {"ingredient": "Parsley", "measure": "1/4 cup"}, {"ingredient": "Cumin", "measure": "2 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 tsp"}, {"ingredient": "Flour", "measure": "Spinkling"}, {"ingredient": "Vegetable Oil", "measure": "As required"}], "instructions": "oak the beans in water to cover overnight.Drain. If skinless beans are unavailable, rub to loosen the skins, then discard the skins. Pat the beans dry with a towel.\r\nGrind the beans in a food mill or meat grinder.If neither appliance is available, process them in a food processor but only until the beans form a paste. (If blended too smoothly, the batter tends to fall apart during cooking.) Add the scallions, garlic, cilantro, cumin, baking powder, cayenne, salt, pepper, and coriander, if using.  Refrigerate for at least 30 minutes.\r\nShape the bean mixture into 1-inch balls.Flatten slightly and coat with flour.\r\nHeat at least 1½-inches of oil over medium heat to 365 degrees.\r\nFry the patties in batches, turning once, until golden brown on all sides, about 5 minutes.Remove with a wire mesh skimmer or slotted spoon. Serve as part of a meze or in pita bread with tomato-cucumber salad and tahina sauce.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 392, "protein_g": 19.7, "carbs_g": 55.5, "fat_g": 13.0, "total_kcal": 1175, "total_protein_g": 59.1, "total_carbs_g": 166.6, "total_fat_g": 39.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak and prep the beans", "instruction": "Soak the beans overnight, then drain, rub to loosen skins if needed, discard skins, and pat dry.", "timer_seconds": 43200, "background": true}, {"step": 2, "label": "Grind and season", "instruction": "Grind the beans into a paste, then add scallions, garlic, parsley, cumin, baking powder, cayenne, salt and pepper.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Chill", "instruction": "Refrigerate the mixture.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Shape", "instruction": "Shape the mixture into 1-inch balls, flatten slightly, and coat with flour.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fry", "instruction": "Heat oil to 365°F and fry the patties in batches, turning once, until golden brown on all sides.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve as part of a meze or in pita bread with tomato-cucumber salad and tahina sauce.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=mulqW-J3Yy4"}, {"id": "53027", "name": "Koshari", "category": "Vegetarian", "area": "Egyptian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/4er7mj1598733193.jpg", "local_image": "53027.jpg", "ingredients": [{"ingredient": "Brown Lentils", "measure": "1 1/2 cups"}, {"ingredient": "Rice", "measure": "1 1/2 cups"}, {"ingredient": "Coriander", "measure": "1/2 tsp"}, {"ingredient": "Macaroni", "measure": "2 cups"}, {"ingredient": "Chickpeas", "measure": "Can"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Salt", "measure": "Sprinking"}, {"ingredient": "Vegetable Oil", "measure": "1/2 cup"}], "instructions": "Cook the lentils. Bring lentils and 4 cups of water to a boil in a medium pot or saucepan over high heat. Reduce the heat to low and cook until lentils are just tender (15-17 minutes). Drain from water and season with a little salt. (Note: when the lentils are ready, they should not be fully cooked. They should be only par-cooked and still have a bite to them as they need to finish cooking with the rice).\r\nNow, for the rice. Drain the rice from its soaking water. Combine the par-cooked lentils and the rice in the saucepan over medium-high heat with 1 tbsp cooking oil, salt, pepper, and coriander. Cook for 3 minutes, stirring regularly. Add warm water to cover the rice and lentil mixture by about 1 1/2 inches (you’ll probably use about 3 cups of water here). Bring to a boil; the water should reduce a bit. Now cover and cook until all the liquid has been absorbed and both the rice and lentils are well cooked through (about 20 minutes).  Keep covered and undisturbed for 5 minutes or so.\r\nNow make the pasta. While the rice and lentils are cooking, make the pasta according to package instructions by adding the elbow pasta to boiling water with a dash of salt and a little oil. Cook until the pasta is al dente. Drain.\r\nCover the chickpeas and warm in the microwave briefly before serving.\r\n\r\nMake the crispy onion topping. \r\n\r\nSprinkle the onion rings with salt, then toss them in the flour to coat. Shake off excess flour.\r\nIn a large skillet, heat the cooking oil over medium-high heat, cook the onion rings, stirring often, until they turn a nice caramelized brown. Onions must be crispy, but not burned (15-20 minutes).", "equipment_tags": [], "portions": 4, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 1248, "protein_g": 38.3, "carbs_g": 199.2, "fat_g": 32.9, "total_kcal": 4992, "total_protein_g": 153.4, "total_carbs_g": 796.7, "total_fat_g": 131.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the lentils", "instruction": "Bring the lentils and water to a boil, then reduce heat and cook until just tender but still with a bite, then drain and season.", "timer_seconds": 1000, "background": true}, {"step": 2, "label": "Cook rice and lentils together", "instruction": "Combine the par-cooked lentils and drained rice in a saucepan with oil, salt, pepper and coriander, cook briefly, then add warm water to cover, bring to a boil, cover, and cook until absorbed and tender.", "timer_seconds": 1380, "background": true}, {"step": 3, "label": "Rest", "instruction": "Keep covered and undisturbed for a few minutes.", "timer_seconds": 300, "background": true}, {"step": 4, "label": "Cook the pasta", "instruction": "Meanwhile, cook the elbow pasta in boiling salted water with a little oil until al dente, then drain.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Warm the chickpeas", "instruction": "Warm the chickpeas briefly in the microwave.", "timer_seconds": 60, "background": false}, {"step": 6, "label": "Fry the crispy onions", "instruction": "Toss the onion rings in salt and flour, shaking off excess, then fry in hot oil, stirring often, until caramelised and crispy but not burned.", "timer_seconds": 1050, "background": false}, {"step": 7, "label": "Serve", "instruction": "Layer the rice and lentils, pasta, chickpeas and crispy onions to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=y0d2ZMZBW4Y"}, {"id": "53028", "name": "Shawarma", "category": "Chicken", "area": "Egyptian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/kcv6hj1598733479.jpg", "local_image": "53028.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "1 kg"}, {"ingredient": "Coriander", "measure": "1 tbs"}, {"ingredient": "Cumin", "measure": "1 tbs"}, {"ingredient": "Cardamom", "measure": "1 tbs"}, {"ingredient": "Cayenne Pepper", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "2 tsp"}, {"ingredient": "Lemon Juice", "measure": "2 tbs"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Greek Yogurt", "measure": "1 cup"}, {"ingredient": "Garlic Clove", "measure": "1"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Lemon Juice", "measure": "Splash"}, {"ingredient": "Lettuce", "measure": "Sliced"}, {"ingredient": "Tomato", "measure": "Sliced"}, {"ingredient": "Pita Bread", "measure": "6"}], "instructions": "Combine the marinade ingredients in a large ziplock bag (or bowl).\r\nAdd the chicken and use your hands to make sure each piece is coated. If using a ziplock bag, I find it convenient to close the bag then massage the bag to disperse the rub all over each chicken piece.\r\nMarinate overnight or up to 24 hours.\r\nCombine the Yoghurt Sauce ingredients in a bowl and mix. Cover and put in the fridge until required (it will last for 3 days in the fridge).\r\nHeat grill/BBQ (or large heavy based pan on stove) on medium high. You should not need to oil it because the marinade has oil in it and also thigh fillets have fat. But if you are worried then oil your hotplate/grill. (See notes for baking)\r\nPlace chicken on the grill and cook the first side for 4 to 5 minutes until nicely charred, then turn and cook the other side for 3 to 4 minutes (the 2nd side takes less time).\r\nRemove chicken from the grill and cover loosely with foil. Set aside to rest for 5 minutes.\r\nTO SERVE\r\nSlice chicken and pile onto platter alongside flatbreads, Salad and the Yoghurt Sauce.\r\nTo make a wrap, get a piece of flatbread and smear with Yoghurt Sauce. Top with a bit of lettuce and tomato and Chicken Shawarma. Roll up and enjoy!", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 925, "protein_g": 85.7, "carbs_g": 63.4, "fat_g": 35.0, "total_kcal": 2776, "total_protein_g": 257.1, "total_carbs_g": 190.2, "total_fat_g": 104.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the chicken", "instruction": "Combine the marinade ingredients in a bag or bowl, add the chicken, and coat each piece well.", "timer_seconds": 43200, "background": true}, {"step": 2, "label": "Make the yogurt sauce", "instruction": "Combine the yogurt sauce ingredients, mix, cover, and refrigerate until needed.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Grill the chicken", "instruction": "Heat a grill or pan to medium-high and cook the chicken on the first side until nicely charred, then turn and cook the other side.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "Rest", "instruction": "Remove from the grill, cover loosely with foil, and rest.", "timer_seconds": 300, "background": true}, {"step": 5, "label": "Serve", "instruction": "Slice the chicken and serve alongside flatbreads, salad and yogurt sauce, or wrap it up with lettuce, tomato and sauce in flatbread.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=3lxUIeKDgic"}, {"id": "53029", "name": "Mulukhiyah", "category": "Beef", "area": "Egyptian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/x372ug1598733932.jpg", "local_image": "53029.jpg", "ingredients": [{"ingredient": "Mulukhiyah", "measure": "800g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Beef", "measure": "300g"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1 Litre"}, {"ingredient": "Garlic Clove", "measure": "1"}, {"ingredient": "Olive Oil", "measure": "1/2 cup"}], "instructions": "Saute the onions in the 3-4 tablespoons olive oil\r\nAdd the beef cubes or the chicken cutlets, sear for 3-4 min on each side\r\nAdd 1 liter of water or just enough to cover the meat\r\nCook over medium heat until the meat is done (I usually do this in the pressure cooker and press them for 5 min)\r\n\r\nAdd the frozen mulukhyia and stir until it thaws completely and then comes to a boil\r\n\r\nIn another pan add the 1/4 to 1/2 cup of olive oil and the cloves of garlic and cook over medium low heat until you can smell the garlic (don’t brown it, it will become bitter)\r\n\r\nAdd the oil and garlic to the mulukhyia and lower the heat and simmer for 5-10 minutes\r\nAdd salt to taste\r\n\r\nServe with a generous amount of lemon juice.\r\n\r\nYou can serve it with some short grain rice or some pita bread", "equipment_tags": [], "portions": 5, "prep_minutes": 19, "prep_minutes_source": "explicit", "kcal": 366, "protein_g": 19.5, "carbs_g": 10.2, "fat_g": 29.3, "total_kcal": 1828, "total_protein_g": 97.4, "total_carbs_g": 51.2, "total_fat_g": 146.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sauté the onion", "instruction": "Sauté the onions in olive oil.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Sear the beef", "instruction": "Add the beef cubes and sear on each side.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Simmer the meat", "instruction": "Add water to cover the meat and cook over medium heat until the meat is done.", "timer_seconds": 3600, "background": true}, {"step": 4, "label": "Add the mulukhiyah", "instruction": "Add the mulukhiyah and stir until it thaws completely and comes to a boil.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Make the garlic oil", "instruction": "In another pan, cook the garlic in olive oil over medium-low heat until fragrant, without browning.", "timer_seconds": 120, "background": false}, {"step": 6, "label": "Combine and simmer", "instruction": "Add the garlic oil to the mulukhiyah, lower the heat, and simmer. Season with salt.", "timer_seconds": 600, "background": true}, {"step": 7, "label": "Serve", "instruction": "Serve with a generous amount of lemon juice, alongside rice or pita bread.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=vWc5JzgAkIQ"}, {"id": "53030", "name": "Feteer Meshaltet", "category": "Side", "area": "Egyptian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/9f4z6v1598734293.jpg", "local_image": "53030.jpg", "ingredients": [{"ingredient": "Flour", "measure": "4 cups"}, {"ingredient": "Water", "measure": "1 1/2 cups"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Unsalted Butter", "measure": "1 cup"}, {"ingredient": "Olive Oil", "measure": "1/4 cup"}], "instructions": "Mix the flour and salt then pour one cup of water and start kneading.\r\nIf you feel the dough is still not coming together or too dry, gradually add the remaining water until you get a dough that is very elastic so that when you pull it and it won’t be torn.\r\nLet the dough rest for just 10 minutes then divide the dough into 6-8 balls depending on the size you want for your feteer.\r\nWarm up the butter/ghee or oil you are using and pour into a deep bowl.\r\nImmerse the dough balls into the warm butter. Let it rest for 15 to 20 minutes.\r\nPreheat oven to 550F.\r\nStretch the first ball with your hands on a clean countertop. Stretch it as thin as you can, the goal here is to see your countertop through the dough.\r\nFold the dough over itself to form a square brushing in between folds with the butter mixture.\r\nSet aside and start making the next ball.\r\nStretch the second one thin as we have done for the first ball.\r\nPlace the previous one on the middle seam side down. Fold the outer one over brushing with more butter mixture as you fold. Set aside.\r\nKeep doing this for the third and fourth balls. Now we have one ready, place on a 10 inch baking/pie dish seam side down and brush the top with more butter.\r\nRepeat for the remaining 4 balls to make a second one. With your hands lightly press the folded feteer to spread it on the baking dish.\r\nPlace in preheated oven for 10 minutes when the feteer starts puffing turn on the broiler to brown the top.\r\nWhen it is done add little butter on top and cover so it won’t get dry.", "equipment_tags": [], "portions": 6, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 665, "protein_g": 8.8, "carbs_g": 64.5, "fat_g": 41.2, "total_kcal": 3992, "total_protein_g": 53.0, "total_carbs_g": 386.9, "total_fat_g": 246.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Mix the flour and salt, pour in water gradually, and knead until very elastic and it won't tear when pulled.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Rest and divide", "instruction": "Let the dough rest, then divide into 6-8 balls.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Soak in butter", "instruction": "Warm the butter and pour into a deep bowl, then immerse the dough balls and let rest.", "timer_seconds": 1050, "background": true}, {"step": 4, "label": "Preheat", "instruction": "Preheat the oven to 550°F.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Stretch and fold", "instruction": "Stretch each ball as thin as possible on a clean counter, fold over itself brushing with butter between folds, and layer successive balls on top, folding and brushing, until you've built up a stack.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Assemble and bake", "instruction": "Place the folded feteer seam-side down in a baking dish, brush the top with butter, repeat for a second one if desired, then press to spread and bake until puffing, finishing under the broiler to brown the top.", "timer_seconds": 600, "background": true}, {"step": 7, "label": "Finish", "instruction": "Add a little butter on top and cover so it stays moist.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=-mW1unsVhFU"}, {"id": "53031", "name": "Egyptian Fatteh", "category": "Beef", "area": "Egyptian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/rlwcc51598734603.jpg", "local_image": "53031.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1lb"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Chicken Stock Cube", "measure": "1"}, {"ingredient": "Tomatoes", "measure": "2"}, {"ingredient": "Garlic Clove", "measure": "4"}, {"ingredient": "Tomato Puree", "measure": "1 tbs"}, {"ingredient": "Rice", "measure": "2 cups"}, {"ingredient": "Noodles", "measure": "1/4 cup"}, {"ingredient": "Butter", "measure": "1/4 cup"}, {"ingredient": "Olive Oil", "measure": "2 cups"}, {"ingredient": "Pita Bread", "measure": "1"}, {"ingredient": "Cumin", "measure": "1 tbs"}, {"ingredient": "White Wine Vinegar", "measure": "3 tbs"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "To prepare bread for bottom of dish: Take pita bread and rip into bite size pieces. In a frying pan, add about a 1/4 stick of butter, add bread pieces and fry until golden brown and crisp. Put these pieces in a glass baking dish, preferably a square sized dish. Set aside.\r\nThen add to same pan, a little more butter, salt, approximately 2 cloves of crushed fresh garlic, and a teaspoon or so of cumin stir around a bit until you can smell aroma, then add fried bread pieces to this mixture, stir to coat bread and put back into glass baking dish. Set aside.\r\nTo prepare meat: put some butter in a pot, stir fry meat until brown, add 1 onion quartered, salt & pepper, 1 cube of chicken bouillon and water to cover meat. Bring to a boil, turn down to simmer, cover and cook until tender, approximately 2 hours. After meat has cooled, take out chunks of meat and put in a bowl, set aside. Reserve soup from the meat separately.\r\nTo prepare the rice: Put some butter into a pot, add shareya (fideo noodles) like a handful or so, keep stirring until golden brown, not too dark, but very golden. Then add two cups of rice, stir a little bit until some of the rice turns an opaque white. Add 2-1/4 cups of water and salt to taste. Bring to a boil, cover and turn down to simmer, cook until tender. Test the rice tenderness after about 35 minutes.\r\nNow take some of the soup from meat and add to the top of the bread pieces in baking dish to saturate.Add cooked rice on top of bread pieces. Slowly spoon remainder of soup onto rice, looking at glass dish sides to see level of soup, should reach just to top of rice, don’t worry, this doesn’t have to be exact. Now you’re ready to make the sauce and fry the meat to put on top.\r\nTo prepare red sauce: In a pan, add a little oil or butter, crushed tomato, a half teaspoon of tomato paste, salt & pepper, 2 cloves of fresh crushed garlic and cumin. Add also approximately 3 tablespoons of vinegar, stir this until you smell aroma and it is a bit smooth. It should be a bit thick, not watery, but if too thick you can add a bit of water. Spread with a wooden spoon atop the rice to cover.\r\nTo fry meat: In a pan add a bit of butter or oil, the meat, just a touch of tomato paste, about a tablespoon of fresh crushed garlic, salt & pepper, a teaspoon of cumin. Cook until meat is golden fried.\r\nSpoon this atop the rice and serve. Enjoy!", "equipment_tags": [], "portions": 3, "prep_minutes": 155, "prep_minutes_source": "explicit", "kcal": 1136, "protein_g": 44.7, "carbs_g": 131.6, "fat_g": 47.2, "total_kcal": 3409, "total_protein_g": 134.1, "total_carbs_g": 394.9, "total_fat_g": 141.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Fry the bread", "instruction": "Rip the pita into pieces and fry in butter until golden and crisp, then place in a glass baking dish.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Season the bread", "instruction": "Add more butter, salt, crushed garlic and cumin to the pan, stir until fragrant, then coat the fried bread pieces and return to the dish.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Cook the meat", "instruction": "Stir-fry the meat in butter until browned, add the quartered onion, salt, pepper, bouillon cube and water to cover, bring to a boil, then simmer covered until tender.", "timer_seconds": 7200, "background": true}, {"step": 4, "label": "Set aside the meat", "instruction": "Once cooled, remove the meat chunks and set aside, reserving the soup separately.", "timer_seconds": null, "background": true}, {"step": 5, "label": "Cook the rice", "instruction": "Toast the noodles in butter until golden, add the rice and stir until some grains turn opaque, then add water and salt, bring to a boil, cover, and simmer until tender.", "timer_seconds": 2100, "background": true}, {"step": 6, "label": "Layer the dish", "instruction": "Saturate the bread with some of the meat soup, top with the cooked rice, then spoon over more soup to just reach the top of the rice.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Make the red sauce", "instruction": "In a pan, cook crushed tomato, tomato paste, salt, pepper, garlic and cumin with oil, add vinegar, and stir until fragrant and slightly thick, adding water if too thick.", "timer_seconds": 300, "background": false}, {"step": 8, "label": "Fry the meat topping", "instruction": "In another pan, fry the meat with a touch of tomato paste, garlic, salt, pepper and cumin until golden fried.", "timer_seconds": 300, "background": false}, {"step": 9, "label": "Assemble and serve", "instruction": "Spread the red sauce over the rice, then spoon the fried meat on top and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=WLuOHkDE4A4"}, {"id": "53032", "name": "Tonkatsu pork", "category": "Pork", "area": "Japanese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/lwsnkl1604181187.jpg", "local_image": "53032.jpg", "ingredients": [{"ingredient": "Pork Chops", "measure": "4"}, {"ingredient": "Flour", "measure": "100g"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Breadcrumbs", "measure": "100g"}, {"ingredient": "Vegetable Oil", "measure": "Fry"}, {"ingredient": "Tomato Ketchup", "measure": "2 tbs"}, {"ingredient": "Worcestershire Sauce", "measure": "2 tbs"}, {"ingredient": "Oyster Sauce", "measure": "1 tbs"}, {"ingredient": "Caster Sugar", "measure": "2 tblsp"}], "instructions": "STEP 1\r\nRemove the large piece of fat on the edge of each pork loin, then bash each of the loins between two pieces of baking parchment until around 1cm in thickness – you can do this using a meat tenderiser or a rolling pin. Once bashed, use your hands to reshape the meat to its original shape and thickness – this step will ensure the meat is as succulent as possible.\r\n\r\nSTEP 2\r\nPut the flour, eggs and panko breadcrumbs into three separate wide-rimmed bowls. Season the meat, then dip first in the flour, followed by the eggs, then the breadcrumbs.\r\n\r\nSTEP 3\r\nIn a large frying or sauté pan, add enough oil to come 2cm up the side of the pan. Heat the oil to 180C – if you don’t have a thermometer, drop a bit of panko into the oil and if it sinks a little then starts to fry, the oil is ready. Add two pork chops and cook for 1 min 30 secs on each side, then remove and leave to rest on a wire rack for 5 mins. Repeat with the remaining pork chops.\r\n\r\nSTEP 4\r\nWhile the pork is resting, make the sauce by whisking the ingredients together, adding a splash of water if it’s particularly thick. Slice the tonkatsu and serve drizzled with the sauce.", "equipment_tags": [], "portions": 1, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 1588, "protein_g": 78.5, "carbs_g": 183.3, "fat_g": 58.6, "total_kcal": 1588, "total_protein_g": 78.5, "total_carbs_g": 183.3, "total_fat_g": 58.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the pork", "instruction": "Trim the fat from the pork loins, then bash between baking parchment to about 1cm thick, reshaping with your hands afterward.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bread the pork", "instruction": "Set up flour, beaten eggs and panko breadcrumbs in three bowls. Season the meat, then dip in flour, egg, then breadcrumbs.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fry", "instruction": "Heat oil to 180°C in a large pan, add two chops and fry on each side, then rest on a wire rack. Repeat with the remaining chops.", "timer_seconds": 180, "background": false}, {"step": 4, "label": "Rest", "instruction": "Leave the pork to rest.", "timer_seconds": 300, "background": true}, {"step": 5, "label": "Make the sauce and serve", "instruction": "Whisk the sauce ingredients together, thinning with water if needed. Slice the tonkatsu and serve drizzled with sauce.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=aASr5x0d3Ys"}, {"id": "53033", "name": "Japanese gohan rice", "category": "Side", "area": "Japanese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/kw92t41604181871.jpg", "local_image": "53033.jpg", "ingredients": [{"ingredient": "Sushi Rice", "measure": "300g"}, {"ingredient": "Mirin", "measure": "1 tbs"}, {"ingredient": "Pickle Juice", "measure": "Garnish"}, {"ingredient": "Spring Onions", "measure": "Garnish"}], "instructions": "STEP 1\r\nRinsing and soaking your rice is key to achieving the perfect texture. Measure the rice into a bowl, cover with cold water, then use your fingers to massage the grains of rice – the water will become cloudy. Drain and rinse again with fresh water. Repeat five more times until the water stays clear.\r\n\r\nSTEP 2\r\nTip the rinsed rice into a saucepan with 400ml water, or 200ml dashi and 200ml water, bring to the boil, then turn down the heat to a low simmer, cover with a tight-fitting lid with a steam hole and cook for 15 mins. Remove from the heat and leave to sit for another 15 mins, then stir through the mirin. Remove the lid and give it a good stir. Serve with any or all of the optional toppings.", "equipment_tags": [], "portions": 2, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 571, "protein_g": 11.0, "carbs_g": 124.6, "fat_g": 1.1, "total_kcal": 1142, "total_protein_g": 22.0, "total_carbs_g": 249.2, "total_fat_g": 2.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Rinse and soak the rice", "instruction": "Rinse and massage the rice in cold water, draining and repeating until the water stays clear.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the rice", "instruction": "Tip the rice into a saucepan with water (or dashi and water), bring to a boil, reduce to a low simmer, cover with a lid with a steam hole, and cook.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Rest and season", "instruction": "Remove from heat and leave to sit, then stir through the mirin and give it a good stir.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Serve", "instruction": "Serve with any or all of the optional toppings.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=rZO86_-MIp0"}, {"id": "53034", "name": "Japanese Katsudon", "category": "Pork", "area": "Japanese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/d8f6qx1604182128.jpg", "local_image": "53034.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tbs"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Pork", "measure": "1 chopped"}, {"ingredient": "Vegetable Stock", "measure": "150ml"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}, {"ingredient": "Mirin", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Sushi Rice", "measure": "200g"}, {"ingredient": "Chives", "measure": "Chopped"}], "instructions": "STEP 1\r\nHeat the oil in a pan, fry the sliced onion until golden brown, then add the tonkatsu (see recipe here), placing it in the middle of the pan. Mix the dashi, soy, mirin and sugar together and tip three-quarters of the mixture around the tonkatsu. Sizzle for a couple of mins so the sauce thickens a little and the tonkatsu reheats.\r\n\r\nSTEP 2\r\nTip the beaten eggs around the tonkatsu and cook for 2-3 mins until the egg is cooked through but still a little runny. Divide the rice between two bowls, then top each with half the egg and tonkatsu mix, sprinkle over the chives and serve immediately, drizzling with a little more soy if you want an extra umami kick.", "equipment_tags": [], "portions": 1, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 1171, "protein_g": 41.4, "carbs_g": 180.8, "fat_g": 29.8, "total_kcal": 1171, "total_protein_g": 41.4, "total_carbs_g": 180.8, "total_fat_g": 29.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the onion and tonkatsu", "instruction": "Heat oil in a pan and fry the sliced onion until golden brown, then add the tonkatsu, placing it in the middle of the pan.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Add the sauce", "instruction": "Mix the dashi, soy, mirin and sugar together and pour three-quarters of it around the tonkatsu, letting it sizzle until it thickens slightly and the tonkatsu reheats.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Cook the egg", "instruction": "Pour the beaten eggs around the tonkatsu and cook until just set but still a little runny.", "timer_seconds": 150, "background": false}, {"step": 4, "label": "Serve", "instruction": "Divide the rice between bowls, top with the egg and tonkatsu mixture, sprinkle with chives, and serve, drizzling with extra soy if you like.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=voE-MBJqBVk"}, {"id": "53035", "name": "Ham hock colcannon", "category": "Pork", "area": "Irish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/n41ny81608588066.jpg", "local_image": "53035.jpg", "ingredients": [{"ingredient": "Floury Potatoes", "measure": "800g"}, {"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Garlic Clove", "measure": "3 chopped"}, {"ingredient": "Cabbage", "measure": "1 chopped"}, {"ingredient": "Spring Onions", "measure": "8"}, {"ingredient": "Double Cream", "measure": "100ml"}, {"ingredient": "Mustard", "measure": "2 tbs"}, {"ingredient": "Ham", "measure": "180g"}, {"ingredient": "Eggs", "measure": "4"}], "instructions": "STEP 1\r\nPeel and cut the potatoes into even, medium-sized chunks. Put in a large pan filled with cold salted water, bring to the boil and cook for 10-15 mins until a knife can be inserted into the potatoes easily.\r\n\r\nSTEP 2\r\nMeanwhile, melt the butter in a large sauté pan over a medium heat. Add the garlic, cabbage, spring onions and some seasoning. Stir occasionally until the cabbage is wilted but still retains a little bite, then set aside.\r\n\r\nSTEP 3\r\nDrain the potatoes, leave to steam-dry for a couple of mins, then mash with the cream, mustard and seasoning in the same saucepan. Stir in the cabbage and ham hock. Keep warm over a low heat.\r\n\r\nSTEP 4\r\nReheat the pan you used to cook the cabbage (no need to wash first), add a splash of oil, crack in the eggs and fry to your liking. To serve, divide the colcannon between bowls and top each with a fried egg.", "equipment_tags": [], "portions": 5, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 460, "protein_g": 20.3, "carbs_g": 43.1, "fat_g": 24.6, "total_kcal": 2298, "total_protein_g": 101.4, "total_carbs_g": 215.5, "total_fat_g": 122.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil the potatoes", "instruction": "Cut the potatoes into chunks, cover with cold salted water, bring to a boil, and cook until a knife slides in easily.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Cook the cabbage", "instruction": "Meanwhile, melt butter in a large pan, add the garlic, cabbage, spring onions and seasoning, and cook, stirring occasionally, until the cabbage is wilted but still with bite.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Mash the potatoes", "instruction": "Drain the potatoes, let steam-dry briefly, then mash with cream, mustard and seasoning. Stir in the cabbage and ham hock, and keep warm on low heat.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fry the eggs and serve", "instruction": "Reheat the cabbage pan, add oil, crack in the eggs, and fry to your liking. Divide the colcannon between bowls and top each with a fried egg.", "timer_seconds": 240, "background": false}], "video": "https://www.youtube.com/watch?v=aQJAU2iJ730"}, {"id": "53036", "name": "Boxty Breakfast", "category": "Pork", "area": "Irish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/naqyel1608588563.jpg", "local_image": "53036.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "4 large"}, {"ingredient": "Spring Onions", "measure": "1  bunch"}, {"ingredient": "Plain Flour", "measure": "100g"}, {"ingredient": "Egg White", "measure": "1"}, {"ingredient": "Milk", "measure": "150ml"}, {"ingredient": "Bicarbonate Of Soda", "measure": "1 tsp"}, {"ingredient": "Butter", "measure": "3 tbs"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Cherry Tomatoes", "measure": "6"}, {"ingredient": "Bacon", "measure": "12"}, {"ingredient": "Egg", "measure": "6"}], "instructions": "STEP 1\r\nBefore you start, put your oven on its lowest setting, ready to keep things warm. Peel the potatoes, grate 2 of them, then set aside. Cut the other 2 into large chunks, then boil for 10-15 mins or until tender. Meanwhile, squeeze as much of the liquid from the grated potatoes as you can using a clean tea towel. Mash the boiled potatoes, then mix with the grated potato, spring onions and flour.\r\n\r\nSTEP 2\r\nWhisk the egg white in a large bowl until it holds soft peaks. Fold in the buttermilk, then add the bicarbonate of soda. Fold into the potato mix.\r\n\r\nSTEP 3\r\nHeat a large non-stick frying pan over a medium heat, then add 1 tbsp butter and some of the oil. Drop 3-4 spoonfuls of the potato mixture into the pan, then gently cook for 3-5 mins on each side until golden and crusty. Keep warm on a plate in the oven while you cook the next batch, adding more butter and oil to the pan before you do so. You will get 16 crumpet-size boxty from the mix. Can be made the day ahead, drained on kitchen paper, then reheated in a low oven for 20 mins.\r\n\r\nSTEP 4\r\nHeat the grill to medium and put the tomatoes in a heavy-based pan. Add a good knob of butter and a little oil, then fry for about 5 mins until softened. Grill the bacon, then pile onto a plate and keep warm. Stack up the boxty, bacon and egg, and serve the tomatoes on the side.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 1070, "protein_g": 60.2, "carbs_g": 47.3, "fat_g": 70.5, "total_kcal": 5351, "total_protein_g": 301.2, "total_carbs_g": 236.5, "total_fat_g": 352.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the potatoes", "instruction": "Set the oven to its lowest setting to keep food warm. Grate 2 potatoes and set aside, cutting the other 2 into chunks and boiling until tender.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Combine the potato mix", "instruction": "Squeeze the liquid from the grated potato, mash the boiled potatoes, and mix with the grated potato, spring onions and flour.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the batter", "instruction": "Whisk the egg white to soft peaks, fold in the buttermilk and bicarbonate of soda, then fold into the potato mix.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the boxty", "instruction": "Heat a non-stick pan with butter and oil, drop in spoonfuls of the mixture, and cook gently on each side until golden and crusty, keeping cooked batches warm in the oven.", "timer_seconds": 480, "background": false}, {"step": 5, "label": "Cook the tomatoes and bacon", "instruction": "Fry the tomatoes in butter and oil until softened, and grill the bacon, keeping both warm.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Serve", "instruction": "Stack the boxty with bacon and egg, and serve the tomatoes on the side.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=80W0mCFDIP0"}, {"id": "53037", "name": "Coddled pork with cider", "category": "Pork", "area": "Irish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/7vpsfp1608588991.jpg", "local_image": "53037.jpg", "ingredients": [{"ingredient": "Butter", "measure": "Knob"}, {"ingredient": "Pork Chops", "measure": "2"}, {"ingredient": "Bacon", "measure": "4"}, {"ingredient": "Potatoes", "measure": "2"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "Swede", "measure": "1/2"}, {"ingredient": "Cabbage", "measure": "1/2"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Cider", "measure": "100ml"}, {"ingredient": "Chicken Stock", "measure": "100g"}], "instructions": "STEP 1\r\nHeat the butter in a casserole dish until sizzling, then fry the pork for 2-3 mins on each side until browned. Remove from the pan.\r\n\r\nSTEP 2\r\nTip the bacon, carrot, potatoes and swede into the pan, then gently fry until slightly coloured. Stir in the cabbage, sit the chops back on top, add the bay leaf, then pour over the cider and stock. Cover the pan, then leave everything to gently simmer for 20 mins until the pork is cooked through and the vegetables are tender.\r\n\r\nSTEP 3\r\nServe at the table spooned straight from the dish.", "equipment_tags": [], "portions": 2, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 842, "protein_g": 51.8, "carbs_g": 37.8, "fat_g": 51.4, "total_kcal": 1683, "total_protein_g": 103.6, "total_carbs_g": 75.5, "total_fat_g": 102.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the pork", "instruction": "Heat butter in a casserole dish and fry the pork on each side until browned, then remove.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Cook the vegetables", "instruction": "Add the bacon, carrot, potatoes and swede to the pan and fry gently until slightly coloured.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Braise", "instruction": "Stir in the cabbage, sit the chops back on top, add the bay leaf, pour over the cider and stock, cover, and simmer gently until the pork is cooked through and vegetables tender.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Serve", "instruction": "Serve at the table spooned straight from the dish.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ftn_4mc-65o"}, {"id": "53038", "name": "Mustard champ", "category": "Side", "area": "Irish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/o7p9581608589317.jpg", "local_image": "53038.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1kg"}, {"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Mustard", "measure": "2 tbs"}, {"ingredient": "Spring Onions", "measure": "Bunch"}, {"ingredient": "Spring Onions", "measure": "Bunch"}], "instructions": "STEP 1\r\nBoil the potatoes for 15 mins or until tender. Drain, then mash.\r\n\r\nSTEP 2\r\nHeat the milk and half the butter in the corner of the pan, then beat into the mash, along with the wholegrain mustard.\r\n\r\nSTEP 3\r\nGently fry the spring onions in the remaining butter for 2 mins until just soft but still a perky green. Fold into the mash and serve. Great with gammon or to top a fish pie.", "equipment_tags": [], "portions": 7, "prep_minutes": 17, "prep_minutes_source": "explicit", "kcal": 184, "protein_g": 4.2, "carbs_g": 26.5, "fat_g": 7.0, "total_kcal": 1289, "total_protein_g": 29.2, "total_carbs_g": 185.8, "total_fat_g": 49.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil and mash the potatoes", "instruction": "Boil the potatoes until tender, then drain and mash.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Enrich the mash", "instruction": "Heat the milk and half the butter, then beat into the mash with the mustard.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the spring onions and finish", "instruction": "Gently fry the spring onions in the remaining butter until just soft but still green, then fold into the mash and serve.", "timer_seconds": 120, "background": false}], "video": "https://www.youtube.com/watch?v=_iKllHSC978"}, {"id": "53039", "name": "Piri-piri chicken and slaw", "category": "Chicken", "area": "Portuguese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/hglsbl1614346998.jpg", "local_image": "53039.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1.5kg"}, {"ingredient": "Red Chilli", "measure": "3 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Dried Oregano", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tbs"}, {"ingredient": "Oil", "measure": "2 tbs"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Beetroot", "measure": "1"}, {"ingredient": "Cabbage", "measure": "4 leaves"}, {"ingredient": "Mayonnaise", "measure": "2 tbs"}, {"ingredient": "Greek Yogurt", "measure": "2 tbs"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tbs"}, {"ingredient": "Cumin Seeds", "measure": "1 tsp"}], "instructions": "STEP 1\r\n\r\nWhizz together all of the marinade ingredients in a small food processor. Rub the marinade onto the chicken and leave for 1 hour at room temperature.\r\n\r\nSTEP 2\r\n\r\nHeat the oven to 190C/fan 170C/gas 5. Put the chicken in a roasting tray and cook for 1 hour 20 minutes. Rest under loose foil for 20 minutes. While the chicken is resting, mix together the slaw ingredients and season. Serve the chicken with slaw, fries and condiments.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 160, "prep_minutes_source": "explicit", "kcal": 248, "protein_g": 27.2, "carbs_g": 4.5, "fat_g": 12.7, "total_kcal": 2973, "total_protein_g": 326.6, "total_carbs_g": 54.1, "total_fat_g": 152.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the chicken", "instruction": "Blend the marinade ingredients in a food processor, rub onto the chicken, and leave at room temperature.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Roast the chicken", "instruction": "Heat the oven to 190°C/fan 170°C/gas 5, put the chicken in a roasting tray, and cook.", "timer_seconds": 4800, "background": true}, {"step": 3, "label": "Rest the chicken", "instruction": "Rest under loose foil.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Make the slaw and serve", "instruction": "While the chicken rests, mix the slaw ingredients and season. Serve the chicken with slaw, fries and condiments.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_RKwKjskopk"}, {"id": "53040", "name": "Spring onion and prawn empanadas", "category": "Seafood", "area": "Portuguese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/1c5oso1614347493.jpg", "local_image": "53040.jpg", "ingredients": [{"ingredient": "Spring Onions", "measure": "1  bunch"}, {"ingredient": "Olive Oil", "measure": "Dash"}, {"ingredient": "Red Chilli", "measure": "1 finely sliced"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Prawns", "measure": "350g"}, {"ingredient": "Feta", "measure": "75g"}, {"ingredient": "Butter", "measure": "15g"}, {"ingredient": "Plain Flour", "measure": "250g"}, {"ingredient": "Egg", "measure": "1 Seperated"}, {"ingredient": "White Wine Vinegar", "measure": "1/2 tsp"}], "instructions": "STEP 1\r\n\r\nTo make the dough, rub the butter into the flour and then add the egg white and half the yolk (keep the rest), vinegar, a pinch of salt and enough cold water to make a soft dough. Knead on a floured surface until smooth and then wrap and rest for 30 minutes.\r\n\r\nSTEP 2\r\n\r\nHeat the oven to 180c/fan 160c/gas 4. Trim the green ends of the spring onions and then finely slice the rest. Heat a little oil in a pan and fry them gently until soft but not browned. Add the chilli and garlic, stir and then add the prawns and cook until they are opaque. Season well. Scoop out the prawns and bubble the juices until they thicken, then add back the prawns.\r\n\r\nSTEP 3\r\n\r\nDivide the empanada dough into eight balls and roll out to thin circles on a floured surface. Put some filling on one half of the dough, sprinkle the feta on top and fold the other half over. Trim the edge and then fold and crimp the dough together so the empanada is tightly sealed, put it on an oiled baking sheet either on its side or sitting on its un-crimped edge like a cornish pasty. Repeat with the remaining dough and mixture. Mix the leftover egg yolk with a splash of water and brush the top of the empanadas.\r\n\r\nSTEP 4\r\n\r\nBake for 30 minutes or until golden and slightly crisp around the edges.", "equipment_tags": [], "portions": 2, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 814, "protein_g": 56.9, "carbs_g": 101.0, "fat_g": 19.2, "total_kcal": 1628, "total_protein_g": 113.8, "total_carbs_g": 202.0, "total_fat_g": 38.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and rest the dough", "instruction": "Rub the butter into the flour, add the egg white and half the yolk, vinegar, salt and cold water to make a soft dough. Knead until smooth, wrap and rest.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Cook the prawn filling", "instruction": "Preheat the oven to 180°C/fan 160°C/gas 4. Fry the sliced spring onions gently until soft, add the chilli and garlic, then the prawns, and cook until opaque. Season, then scoop out the prawns and reduce the juices before returning them.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Assemble the empanadas", "instruction": "Divide the dough into 8 balls and roll into thin circles. Fill one half with the prawn mixture and feta, fold over, trim and crimp to seal, and place on an oiled baking sheet.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Glaze and bake", "instruction": "Brush with the reserved egg yolk mixed with water, and bake until golden and slightly crisp.", "timer_seconds": 1800, "background": true}], "video": "https://www.youtube.com/watch?v=Q24haJU-1dI"}, {"id": "53041", "name": "Grilled Portuguese sardines", "category": "Seafood", "area": "Portuguese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/lpd4wy1614347943.jpg", "local_image": "53041.jpg", "ingredients": [{"ingredient": "Sardines", "measure": "8"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Paprika", "measure": "1 tbs"}, {"ingredient": "Lemon", "measure": "1/2"}, {"ingredient": "Rosemary", "measure": "4 sprigs"}, {"ingredient": "Red Chilli", "measure": "1"}], "instructions": "STEP 1\r\n\r\nPut all of the ingredients, except the sardines, into a bowl and mix together with some seasoning. Pour into a baking dish, add the sardines and toss really well. Cover and chill for a few hours.\r\n\r\nSTEP 2\r\n\r\nHeat a BBQ or griddle pan until hot. Cook the sardines for 4-5 minutes on each side or until really caramelised and charred. Put onto a serving plate, drizzle with oil, sprinkle with a little more paprika and squeeze over the lemon wedges.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 1171, "protein_g": 102.6, "carbs_g": 20.0, "fat_g": 76.3, "total_kcal": 1171, "total_protein_g": 102.6, "total_carbs_g": 20.0, "total_fat_g": 76.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the marinade", "instruction": "Mix all the ingredients except the sardines in a bowl with seasoning, pour into a baking dish, add the sardines, and toss well.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate", "instruction": "Cover and chill.", "timer_seconds": 7200, "background": true}, {"step": 3, "label": "Grill", "instruction": "Heat a barbecue or griddle pan until hot and cook the sardines on each side until really caramelised and charred.", "timer_seconds": 540, "background": false}, {"step": 4, "label": "Serve", "instruction": "Plate up, drizzle with oil, sprinkle with paprika, and squeeze over lemon wedges.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=JYtMjKa6cdY"}, {"id": "53042", "name": "Portuguese prego with green piri-piri", "category": "Beef", "area": "Portuguese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/ewcikl1614348364.jpg", "local_image": "53042.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Beef Fillet", "measure": "2 small"}, {"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Vinegar", "measure": "1 tbs"}, {"ingredient": "Parsley", "measure": "Leaves"}, {"ingredient": "Ciabatta", "measure": "2"}, {"ingredient": "Rocket", "measure": "2 handfulls"}, {"ingredient": "Basil Leaves", "measure": "Small bunch"}, {"ingredient": "Parsley", "measure": "Small bunch"}, {"ingredient": "Jalapeno", "measure": "1"}, {"ingredient": "Vinegar", "measure": "1 tbs"}, {"ingredient": "Spring Onions", "measure": "2 chopped"}, {"ingredient": "Garlic", "measure": "1/2"}, {"ingredient": "Caster Sugar", "measure": "1/2 tsp"}], "instructions": "STEP 1\r\n\r\nRub the garlic over the steaks then put in a sandwich bag and tip in the olive oil, sherry vinegar and parsley stalks. Smoosh everything together, then use a rolling pin to bash the steaks a few times. Leave for 1-2 hours.\r\n\r\nSTEP 2\r\n\r\nTo make the sauce, put all the ingredients into a blender with 1 tbsp water and whizz until as smooth as possible. This will make more than you’ll need for the recipe but will keep for a week in an airtight jar.\r\n\r\nSTEP 3\r\n\r\nHeat a griddle or frying pan to high. Brush away the garlic and parsley stalks from the steaks and season well. Sear the steaks for 2 minutes on each side then rest on a plate. Put the ciabatta halves onto the plate, toasted-side down, to soak up any juices.\r\n\r\nSTEP 4\r\n\r\nSlice the steaks then stuff into the rolls with the green sauce and rocket.", "equipment_tags": ["Blender"], "portions": 2, "prep_minutes": 122, "prep_minutes_source": "explicit", "kcal": 619, "protein_g": 39.8, "carbs_g": 44.1, "fat_g": 32.8, "total_kcal": 1238, "total_protein_g": 79.7, "total_carbs_g": 88.2, "total_fat_g": 65.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the steaks", "instruction": "Rub garlic over the steaks, then put in a bag with olive oil, vinegar and parsley stalks. Bash with a rolling pin.", "timer_seconds": 5400, "background": true}, {"step": 2, "label": "Make the sauce", "instruction": "Blend all the sauce ingredients with water until as smooth as possible.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Sear the steaks", "instruction": "Heat a griddle or pan to high, brush away the garlic and parsley from the steaks, season, and sear on each side, then rest. Toast the ciabatta halves in the pan juices.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Assemble and serve", "instruction": "Slice the steaks and stuff into the rolls with the green sauce and rocket.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=FbIKfcDEPLA"}, {"id": "53043", "name": "Fish fofos", "category": "Seafood", "area": "Portuguese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/a15wsa1614349126.jpg", "local_image": "53043.jpg", "ingredients": [{"ingredient": "Haddock", "measure": "600g"}, {"ingredient": "Potatoes", "measure": "300g"}, {"ingredient": "Green Chilli", "measure": "1 chopped"}, {"ingredient": "Coriander", "measure": "3 tbs"}, {"ingredient": "Cumin Seeds", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1/2 tsp"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Ginger", "measure": "2 pieces"}, {"ingredient": "Flour", "measure": "2 tbs"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Breadcrumbs", "measure": "75g"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "STEP 1\r\n\r\nPut the fish into a lidded pan and pour over enough water to cover. Bring to a simmer and gently poach for 10 minutes over a low heat with the lid on. Drain and flake the fish.\r\n\r\nSTEP 2\r\n\r\nPut the fish, potato, green chilli, coriander, cumin, black pepper, garlic and ginger in a large bowl. Season, add the rice flour, mix well and break in 1 egg. Stir the mixture and divide into 15, then form into small logs. Break the remaining eggs into a bowl and whisk lightly. Put the breadcrumbs into another bowl. Dip each fofo in the beaten egg followed by the breadcrumb mixture. Chill for 20 minutes.\r\n\r\nSTEP 3\r\n\r\nHeat 1cm of oil in a large frying pan over a medium heat. Fry the fofos in batches for 2 minutes on each side, turning gently to get an even golden brown colour all over. Drain on kitchen paper and repeat with the remaining fofos.\r\n\r\nSTEP 4\r\n\r\nFor the onion salad, mix together the onion, coriander and lemon juice with a pinch of salt. Serve with the fofos and mango chutney.", "equipment_tags": [], "portions": 3, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 569, "protein_g": 50.1, "carbs_g": 49.9, "fat_g": 18.8, "total_kcal": 1706, "total_protein_g": 150.3, "total_carbs_g": 149.7, "total_fat_g": 56.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Poach the fish", "instruction": "Cover the fish with water in a lidded pan, bring to a simmer, and gently poach, then drain and flake.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Make the fofo mixture", "instruction": "Combine the fish, potato, chilli, coriander, cumin, pepper, garlic and ginger in a bowl, season, add flour, mix, and break in an egg. Divide into 15 and shape into small logs.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Coat and chill", "instruction": "Whisk the remaining eggs, dip each fofo in egg then breadcrumbs, and chill.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Fry", "instruction": "Heat 1cm of oil in a large frying pan and fry the fofos in batches, turning gently, until evenly golden brown, then drain.", "timer_seconds": 240, "background": false}, {"step": 5, "label": "Serve", "instruction": "Mix the onion salad ingredients with lemon juice and salt, and serve with the fofos and mango chutney.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=YXUZHK2PrV8"}, {"id": "53044", "name": "Portuguese barbecued pork (Febras assadas)", "category": "Pork", "area": "Portuguese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/cybyue1614349443.jpg", "local_image": "53044.jpg", "ingredients": [{"ingredient": "Pork", "measure": "2"}, {"ingredient": "White Wine", "measure": "200ml"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}, {"ingredient": "Lemon", "measure": "2"}, {"ingredient": "Lemon Juice", "measure": "1/2"}, {"ingredient": "Olive Oil", "measure": "Dash"}, {"ingredient": "Mayonnaise", "measure": "To serve"}, {"ingredient": "Potatoes", "measure": "1 kg"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "STEP 1\r\n\r\nCut the tenderloins into 5 equal-size pieces leaving the tail ends a little longer. Take a clear plastic bag and slip one of the pieces in. Bash it into an escalope the size of a side-plate with a rolling pin and repeat with the remaining pieces.\r\n\r\nSTEP 2\r\n\r\nPut the wine, paprika, some salt and pepper and the juice of ½ a lemon in a bowl and add the pork. Leave to marinate for 20-30 minutes, while you get your barbecue to the stage where the coals are glowing but there are no flames.\r\n\r\nSTEP 3\r\n\r\nTo make the chips, fill a basin with cool water and cut the potatoes into 3cm-thick chips. Soak them in the water for 5 minutes and then change the water. Leave for 5 more minutes. Drain and then pat dry on a towel or with kitchen paper.\r\n\r\nSTEP 4\r\n\r\nHeat the oil in a deep fryer or a deep heavy-based pan with a lid to 130C and lower the chips into the oil (in batches). Blanch for 8-10 minutes. Remove from the oil and drain well. Place on a tray to cool. Reheat the oil to 180C (make sure it’s hot or your chips will be soggy) and lower the basket of chips into the oil (again, do this in batches). Leave to cook for 2 minutes and then give them a little shake. Cook for another minute or so until they are well coloured and crisp to the touch. Drain well for a few minutes, tip into a bowl and sprinkle with sea salt.\r\n\r\nSTEP 5\r\n\r\nThe pork will cook quickly so do it in 2 batches. Take the pieces out of the marinade, rub them with oil, and drop them onto the barbecue (you could also use a chargrill). Cook for 1 minute on each side – they may flare up as you do so. This should really be enough time as they will keep on cooking. Take them off the barbecue and pile onto a plate. Repeat with the remaining batch.\r\n\r\nSTEP 6\r\n\r\nServe by piling a plate with chips, drop the pork on top of each pile and pouring the juices from the plate over so the chips take up the flavours. Top with a spoon of mayonnaise and a wedge of lemon.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 48, "prep_minutes_source": "explicit", "kcal": 540, "protein_g": 14.1, "carbs_g": 63.4, "fat_g": 21.1, "total_kcal": 1620, "total_protein_g": 42.3, "total_carbs_g": 190.2, "total_fat_g": 63.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the pork", "instruction": "Cut the tenderloins into pieces and bash into escalopes inside a plastic bag with a rolling pin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the pork", "instruction": "Combine the wine, paprika, seasoning and lemon juice in a bowl, add the pork, and leave to marinate while heating the barbecue.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Prep the chips", "instruction": "Cut the potatoes into chips, soak in water, changing the water once, then drain and pat dry.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Blanch the chips", "instruction": "Heat the oil to 130°C and blanch the chips in batches, then drain and let cool.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Fry the chips crisp", "instruction": "Reheat the oil to 180°C and fry the chips in batches until well coloured and crisp, then drain and sprinkle with sea salt.", "timer_seconds": 240, "background": false}, {"step": 6, "label": "Grill the pork", "instruction": "Rub the pork with oil and grill on the barbecue in batches, briefly on each side, then pile onto a plate.", "timer_seconds": 240, "background": false}, {"step": 7, "label": "Serve", "instruction": "Pile the plates with chips, top with pork, pour over the resting juices, and top with mayonnaise and a lemon wedge.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=tVpsZaejyYU"}, {"id": "53045", "name": "Portuguese fish stew (Caldeirada de peixe)", "category": "Seafood", "area": "Portuguese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/do7zps1614349775.jpg", "local_image": "53045.jpg", "ingredients": [{"ingredient": "Onions", "measure": "2 finely chopped"}, {"ingredient": "Red Pepper", "measure": "1 Diced"}, {"ingredient": "Coriander", "measure": "Small bunch"}, {"ingredient": "Red Chilli", "measure": "1 small"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Dry White Wine", "measure": "400ml"}, {"ingredient": "Saffron", "measure": "Pinch"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Potatoes", "measure": "300g"}, {"ingredient": "Plum Tomatoes", "measure": "400g"}, {"ingredient": "Cod", "measure": "600g"}, {"ingredient": "Squid", "measure": "300g"}, {"ingredient": "Tiger Prawns", "measure": "8"}, {"ingredient": "Clams", "measure": "500g"}, {"ingredient": "Mussels", "measure": "500g"}, {"ingredient": "Baguette", "measure": "1 sliced"}], "instructions": "STEP 1\r\n\r\nHeat a drizzle of oil in a large, deep-sided frying pan, and fry the onion and pepper on a medium heat until softened but not browned. Finely chop the coriander stalks (keep the leaves for later), and add to the pan with the chilli and chopped garlic. Fry for another few minutes. Add the wine, saffron and bay leaf and let it simmer until reduced by half.\r\n\r\nSTEP 2\r\n\r\nAdd the potatoes, tomatoes, and 300ml water and bring to a gentle boil. Break up the tomatoes with a spoon on the side of the pan and simmer for 20-25 minutes until the potatoes are just tender, and the tomatoes have broken down.\r\n\r\nSTEP 3\r\n\r\nSeason well, then gently push the fish into the sauce, and arrange the squid, prawns, clams and mussels on the surface. Put the lid on and cook for 6-8 minutes until the mussel and clam shells have opened, the prawns are cooked and the fish is flaky. Toast the bread, rub lightly with the halved garlic clove and drizzle with olive oil. Serve the stew scatted with chopped coriander leaves, and the toasts for dunking.", "equipment_tags": [], "portions": 8, "prep_minutes": 33, "prep_minutes_source": "explicit", "kcal": 351, "protein_g": 47.2, "carbs_g": 21.8, "fat_g": 3.6, "total_kcal": 2805, "total_protein_g": 378.0, "total_carbs_g": 174.8, "total_fat_g": 29.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the aromatics", "instruction": "Heat oil in a large deep frying pan and cook the onion and pepper until softened. Add the coriander stalks, chilli and garlic, and fry a few minutes more.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Reduce the wine", "instruction": "Add the wine, saffron and bay leaf, and simmer until reduced by half.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the base", "instruction": "Add the potatoes, tomatoes and water, bring to a gentle boil, breaking up the tomatoes, and simmer until the potatoes are tender and tomatoes broken down.", "timer_seconds": 1350, "background": true}, {"step": 4, "label": "Cook the seafood", "instruction": "Season, push the fish into the sauce, arrange the squid, prawns, clams and mussels on top, cover, and cook until the shells open, prawns are cooked and fish is flaky.", "timer_seconds": 420, "background": false}, {"step": 5, "label": "Serve", "instruction": "Toast the bread, rub with garlic and drizzle with oil. Serve the stew scattered with coriander leaves alongside the toasts.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=utv-GpSJypk"}, {"id": "53046", "name": "Portuguese custard tarts", "category": "Dessert", "area": "Portuguese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vmz7gl1614350221.jpg", "local_image": "53046.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "2 tbs"}, {"ingredient": "Icing Sugar", "measure": "2 tbs"}, {"ingredient": "Puff Pastry", "measure": "375g"}, {"ingredient": "Caster Sugar", "measure": "250g"}, {"ingredient": "Lemon Zest", "measure": "2 strips"}, {"ingredient": "Cinnamon", "measure": "1 Stick"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Egg Yolks", "measure": "4"}, {"ingredient": "Corn Flour", "measure": "50g"}, {"ingredient": "Whole Milk", "measure": "500ml"}, {"ingredient": "Vanilla", "measure": "Pod of"}, {"ingredient": "Cinnamon", "measure": "To serve"}], "instructions": "STEP 1\r\nRoll the pastry\r\nMix the flour and icing sugar, and use this to dust the work surface. Roll the pastry out to make a 45 x 30cm rectangle. Roll up lengthways to create a long sausage shape.\r\n\r\nSTEP 2\r\nCutting pastry into rounds\r\nCut the pastry into 24 wheels, about 1-2cm thick.\r\n\r\nSTEP 3\r\nRoll out each pastry portion\r\nRoll each wheel lightly with the rolling pin to fit 2 x 12-hole non-stick fairy cake tins.\r\n\r\nSTEP 4\r\nPress pastry into the tin\r\nPress the pastry circles into the tins and mould into the tins to make thin cases. Chill until needed.\r\n\r\nSTEP 5\r\nMake the infused syrup\r\nHeat the oven to 220C/fan 200C/gas 7. Make a sugar syrup by bringing the sugar, 200ml water, lemon zest and cinnamon stick to the boil. Reduce until syrupy, allow to cool, then remove the cinnamon and lemon. Whisk the eggs, egg yolks and cornflour until smooth in another large pan.\r\n\r\nSTEP 6\r\nMaking custard\r\nHeat the milk and vanilla pod seeds in a separate pan until just below the boil. Gradually pour the hot milk over the eggs and cornflour, then cook on a low heat, continually whisking.\r\n\r\nSTEP 7\r\nAdd syrup to custard\r\nAdd the cooled sugar syrup to the custard and whisk until thickened slightly.\r\n\r\nSTEP 8\r\nPour custard into the tins\r\nPour the custard through a sieve. Pour into the pastry cases and bake for 15 minutes until the pastry is golden and the custard has darkened.\r\n\r\nSTEP 9\r\ncool and dust with icing sugar\r\nCool completely in the tins then sift over icing sugar and ground cinnamon to serve.\r\n\r\n\r\n\r\n ", "equipment_tags": [], "portions": 11, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 421, "protein_g": 7.9, "carbs_g": 50.4, "fat_g": 21.0, "total_kcal": 4636, "total_protein_g": 86.8, "total_carbs_g": 554.0, "total_fat_g": 231.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roll the pastry", "instruction": "Dust the surface with flour and icing sugar, roll the pastry into a rectangle, and roll up lengthways into a sausage shape.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cut and line", "instruction": "Cut into 24 wheels, roll each to fit fairy cake tins, and press in to make thin cases.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Chill the cases", "instruction": "Chill until needed.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Make the sugar syrup", "instruction": "Heat the oven to 220°C/fan 200°C/gas 7. Bring the sugar, water, lemon zest and cinnamon stick to the boil, reduce until syrupy, cool, then remove the cinnamon and lemon.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Make the custard base", "instruction": "Whisk the eggs, egg yolks and cornflour until smooth. Heat the milk and vanilla seeds until just below boiling, then gradually pour over the eggs, whisking, and cook on low heat, continually whisking.", "timer_seconds": 480, "background": false}, {"step": 6, "label": "Combine and fill", "instruction": "Add the cooled syrup to the custard, whisk until slightly thickened, then pour through a sieve into the pastry cases.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Bake", "instruction": "Bake until the pastry is golden and the custard darkened.", "timer_seconds": 900, "background": true}, {"step": 8, "label": "Cool and serve", "instruction": "Cool completely in the tins, then dust with icing sugar and cinnamon to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=lWLCxui1Mw8"}, {"id": "53047", "name": "Moroccan Carrot Soup", "category": "Vegetarian", "area": "Moroccan", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/jcr46d1614763831.jpg", "local_image": "53047.jpg", "ingredients": [{"ingredient": "Carrots", "measure": "6 chopped"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Garlic Clove", "measure": "4"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Coriander", "measure": "1/2 tsp"}, {"ingredient": "Olive Oil", "measure": "1 tbs"}, {"ingredient": "Garam Masala", "measure": "1/4 tsp"}, {"ingredient": "Lemon Juice", "measure": "1 tsp"}], "instructions": "Step 1\r\nPreheat oven to 180° C.\r\nStep 2\r\nCombine carrots, onion, garlic, cumin seeds, coriander seeds, salt and olive oil in a bowl and mix well. Transfer on a baking tray.\r\nStep 3\r\nPut the baking tray in preheated oven and roast for 10-12 minutes or till carrots soften. Remove from heat and cool.\r\nStep 4\r\nGrind the baked carrot mixture along with some water to make a smooth paste and strain in a bowl.\r\nStep 5\r\nHeat the carrot mixture in a non-stick pan. Add two cups of water and bring to a boil. Add garam masala powder and mix. Add salt and mix well.\r\nStep 6\r\nRemove from heat, add lemon juice and mix well.\r\nStep 7\r\nServe hot.", "equipment_tags": [], "portions": 1, "prep_minutes": 12, "prep_minutes_source": "explicit", "kcal": 340, "protein_g": 5.7, "carbs_g": 49.8, "fat_g": 15.9, "total_kcal": 340, "total_protein_g": 5.7, "total_carbs_g": 49.8, "total_fat_g": 15.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the carrots", "instruction": "Preheat the oven to 180°C. Combine carrots, onion, garlic, cumin, coriander, salt and oil on a baking tray and roast until the carrots soften.", "timer_seconds": 660, "background": true}, {"step": 2, "label": "Blend the vegetables", "instruction": "Cool, then grind the roasted mixture with some water into a smooth paste and strain.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Simmer the soup", "instruction": "Heat the carrot mixture in a non-stick pan, add water, bring to a boil, stir in garam masala and salt.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Finish and serve", "instruction": "Remove from heat, add lemon juice, mix well, and serve hot.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=7tDWOpnIhok"}, {"id": "53048", "name": "Mee goreng mamak", "category": "Seafood", "area": "Malaysian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/xquakq1619787532.jpg", "local_image": "53048.jpg", "ingredients": [{"ingredient": "Peanuts", "measure": "50g"}, {"ingredient": "Chilli", "measure": "15g"}, {"ingredient": "Prawns", "measure": "10g"}, {"ingredient": "Oil", "measure": "5 tbs"}, {"ingredient": "Water", "measure": "750 ml"}, {"ingredient": "Tamarind Paste", "measure": "1/2 tbs"}, {"ingredient": "Potatoes", "measure": "250g"}, {"ingredient": "Red Onions", "measure": "2"}, {"ingredient": "Garlic Clove", "measure": "4"}, {"ingredient": "Cabbage", "measure": "30g"}, {"ingredient": "Chinese Broccoli", "measure": "30g"}, {"ingredient": "Tofu", "measure": "1"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}, {"ingredient": "Noodles", "measure": "4"}, {"ingredient": "Egg", "measure": "1"}], "instructions": "Heat oil in a pan at medium heat. Then, add peanuts, dried chilies, dried shrimps and dhal. Fry the aromatics until fragrant. Remove from pan and leave aside.\r\n\r\nBlend fried ingredients with tamarind paste and water until fine. Then, sauté the blended ingredients in oil heated over low heat. Continue cooking until the oil separates from the paste and turns a darker shade.\r\n\r\nSkin and cut potatoes into small chunks and boil them in a pot of water until knife-tender. Once ready, remove them from the pot and leave aside. Discard water.\r\n\r\nSlice onion and fried tofu, mince garlic, cut some cabbage and Chinese flowering cabbage (choi sam). Prepare prawn fritters and cut them. Boil noodles to soften them if bought dried. Also mix black soy sauce with water.\r\n\r\nTo fry one portion of mee goreng mamak, heat oil and add 1/4 of the following ingredients in this order: garlic, onion, paste. Sauté until fragrant. Optionally, add prawns.\r\n\r\nAdd in 1/4 amount of tofu, boiled potatoes, cabbage, Chinese flowering cabbage and prawn fritters. Sauté for another 30 seconds.\r\n\r\nAdd noodles to the wok. Add 3 tablespoons of dark soy sauce mixture. Mix evenly for the next 1 minute. Then, move the noodles to the side of the wok. Stir in an egg. Garnish with a slice of lime and slices of green chilies. To cook another plate of noodles, repeat from step 5 onwards.", "equipment_tags": [], "portions": 3, "prep_minutes": 1, "prep_minutes_source": "explicit", "kcal": 540, "protein_g": 15.0, "carbs_g": 44.5, "fat_g": 35.3, "total_kcal": 1619, "total_protein_g": 44.9, "total_carbs_g": 133.4, "total_fat_g": 105.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Fry the aromatics", "instruction": "Heat oil and fry the peanuts, dried chillies, dried shrimp and dhal until fragrant, then set aside.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Blend and cook the paste", "instruction": "Blend the fried ingredients with tamarind paste and water, then sauté the paste over low heat until the oil separates and it darkens.", "timer_seconds": 900, "background": false}, {"step": 3, "label": "Boil the potatoes", "instruction": "Cut the potatoes into chunks and boil until knife-tender, then drain and set aside.", "timer_seconds": 900, "background": false}, {"step": 4, "label": "Prep the rest", "instruction": "Slice the onion and tofu, mince the garlic, chop the cabbage and Chinese broccoli, prepare the prawn fritters, boil the noodles if dried, and mix soy sauce with water.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fry the aromatics for one portion", "instruction": "Heat oil, sauté garlic, onion and paste until fragrant, adding prawns if desired.", "timer_seconds": 120, "background": false}, {"step": 6, "label": "Add the rest", "instruction": "Add the tofu, boiled potatoes, cabbage, Chinese broccoli and prawn fritters, and sauté briefly.", "timer_seconds": 30, "background": false}, {"step": 7, "label": "Finish with noodles and egg", "instruction": "Add the noodles and soy sauce mixture, mix evenly, then push to the side and stir in an egg. Garnish with lime and green chilli slices.", "timer_seconds": 60, "background": false}], "video": "https://www.youtube.com/watch?v=pOJEmDBgtSk"}, {"id": "53049", "name": "Apam balik", "category": "Dessert", "area": "Malaysian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/adxcbq1619787919.jpg", "local_image": "53049.jpg", "ingredients": [{"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "Oil", "measure": "60ml"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Flour", "measure": "1600g"}, {"ingredient": "Baking Powder", "measure": "3 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Unsalted Butter", "measure": "25g"}, {"ingredient": "Sugar", "measure": "45g"}, {"ingredient": "Peanut Butter", "measure": "3 tbs"}], "instructions": "Mix milk, oil and egg together. Sift flour, baking powder and salt into the mixture. Stir well until all ingredients are combined evenly.\r\n\r\nSpread some batter onto the pan. Spread a thin layer of batter to the side of the pan. Cover the pan for 30-60 seconds until small air bubbles appear.\r\n\r\nAdd butter, cream corn, crushed peanuts and sugar onto the pancake. Fold the pancake into half once the bottom surface is browned.\r\n\r\nCut into wedges and best eaten when it is warm.", "equipment_tags": [], "portions": 12, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 604, "protein_g": 15.0, "carbs_g": 106.3, "fat_g": 11.9, "total_kcal": 7248, "total_protein_g": 180.0, "total_carbs_g": 1276.0, "total_fat_g": 143.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the batter", "instruction": "Mix the milk, oil and egg together, then sift in the flour, baking powder and salt and stir until combined.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the pancake base", "instruction": "Spread a thin layer of batter onto the pan and cover until small air bubbles appear.", "timer_seconds": 45, "background": true}, {"step": 3, "label": "Add fillings and fold", "instruction": "Add butter, cream corn, crushed peanuts and sugar, and fold the pancake in half once the bottom is browned.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Cut into wedges and serve warm.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=6R8ffRRJcrg"}, {"id": "53050", "name": "Ayam Percik", "category": "Chicken", "area": "Malaysian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/020z181619788503.jpg", "local_image": "53050.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "6"}, {"ingredient": "Challots", "measure": "16"}, {"ingredient": "Ginger", "measure": "1 1/2"}, {"ingredient": "Garlic Clove", "measure": "6"}, {"ingredient": "Cayenne Pepper", "measure": "8"}, {"ingredient": "Turmeric", "measure": "2 tbs"}, {"ingredient": "Cumin", "measure": "1 1/2"}, {"ingredient": "Coriander", "measure": "1 1/2"}, {"ingredient": "Fennel", "measure": "1 1/2"}, {"ingredient": "Tamarind Paste", "measure": "2 tbs"}, {"ingredient": "Coconut Milk", "measure": "1 can"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1 cup"}], "instructions": "In a blender, add the ingredients for the spice paste and blend until smooth.\r\nOver medium heat, pour the spice paste in a skillet or pan and fry for 10 minutes until fragrant. Add water or oil 1 tablespoon at a time if the paste becomes too dry. Don't burn the paste. Lower the fire slightly if needed.\r\nAdd the cloves, cardamom, tamarind pulp, coconut milk, water, sugar and salt. Turn the heat up and bring the mixture to boil. Turn the heat to medium low and simmer for 10 minutes. Stir occasionally. It will reduce slightly. This is the marinade/sauce, so taste and adjust seasoning if necessary. Don't worry if it's slightly bitter. It will go away when roasting.\r\nWhen the marinade/sauce has cooled, pour everything over the chicken and marinate overnight to two days.\r\nPreheat the oven to 425 F.\r\nRemove the chicken from the marinade. Spoon the marinade onto a greased (or aluminum lined) baking sheet. Lay the chicken on top of the sauce (make sure the chicken covers the sauce and the sauce isn't exposed or it'll burn) and spread the remaining marinade on the chicken. Roast for 35-45 minutes or until internal temp of the thickest part of chicken is at least 175 F.\r\nLet chicken rest for 5 minutes. Brush the chicken with some of the oil. Serve chicken with the sauce over steamed rice (or coconut rice).", "equipment_tags": ["Blender"], "portions": 4, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 536, "protein_g": 24.3, "carbs_g": 55.6, "fat_g": 27.4, "total_kcal": 2144, "total_protein_g": 97.1, "total_carbs_g": 222.6, "total_fat_g": 109.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Blend the spice paste", "instruction": "Blend the spice paste ingredients in a blender until smooth.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fry the paste", "instruction": "Fry the spice paste over medium heat until fragrant, adding water or oil if it dries out.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Make the marinade sauce", "instruction": "Add cloves, cardamom, tamarind, coconut milk, water, sugar and salt, bring to a boil, then reduce to medium-low and simmer, stirring occasionally.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Marinate the chicken", "instruction": "Once the sauce has cooled, pour over the chicken and marinate.", "timer_seconds": 43200, "background": true}, {"step": 5, "label": "Roast", "instruction": "Preheat the oven to 425°F. Spoon the marinade onto a baking sheet, lay the chicken on top covering the sauce, spread remaining marinade over, and roast until cooked through.", "timer_seconds": 2400, "background": true}, {"step": 6, "label": "Rest and serve", "instruction": "Rest, brush with oil, and serve with the sauce over steamed rice.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=9ytR28QK6I8"}, {"id": "53051", "name": "Nasi lemak", "category": "Seafood", "area": "Malaysian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/wai9bw1619788844.jpg", "local_image": "53051.jpg", "ingredients": [{"ingredient": "Coconut Milk", "measure": "2 cups"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Ginger Paste", "measure": "1/4 tsp"}, {"ingredient": "Ginger", "measure": "1"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Rice", "measure": "2 cups"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Cucumber", "measure": "1"}, {"ingredient": "Peanuts", "measure": "1 cup"}, {"ingredient": "Anchovy Fillet", "measure": "4 oz"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Shallots", "measure": "3"}, {"ingredient": "Chilli Powder", "measure": "2 tsp"}, {"ingredient": "Anchovy Fillet", "measure": "4 oz"}, {"ingredient": "Sugar", "measure": "3 tbs"}, {"ingredient": "Tamarind Paste", "measure": "1/3 cup"}], "instructions": "In a medium saucepan over medium heat, stir together coconut milk, water, ground ginger, ginger root, salt, bay leaf, and rice. Cover, and bring to a boil. Reduce heat, and simmer for 20 to 30 minutes, or until done.\r\n\r\n Step 2\r\nPlace eggs in a saucepan, and cover with cold water. Bring water to a boil, and immediately remove from heat. Cover, and let eggs stand in hot water for 10 to 12 minutes. Remove eggs from hot water, cool, peel and slice in half. Slice cucumber.\r\n\r\n Step 3\r\nMeanwhile, in a large skillet or wok, heat 1 cup vegetable oil over medium-high heat. Stir in peanuts and cook briefly, until lightly browned. Remove peanuts with a slotted spoon and place on paper towels to soak up excess grease. Return skillet to stove. Stir in the contents of one package anchovies; cook briefly, turning, until crisp. Remove with a slotted spoon and place on paper towels. Discard oil. Wipe out skillet.\r\n\r\n Step 4\r\nHeat 2 tablespoons oil in the skillet. Stir in the onion, garlic, and shallots; cook until fragrant, about 1 or 2 minutes. Mix in the chile paste, and cook for 10 minutes, stirring occasionally. If the chile paste is too dry, add a small amount of water. Stir in remaining anchovies; cook for 5 minutes. Stir in salt, sugar, and tamarind juice; simmer until sauce is thick, about 5 minutes.\r\n\r\n Step 5\r\nServe the onion and garlic sauce over the warm rice, and top with peanuts, fried anchovies, cucumbers, and eggs.", "equipment_tags": [], "portions": 5, "prep_minutes": 64, "prep_minutes_source": "explicit", "kcal": 1109, "protein_g": 40.9, "carbs_g": 107.3, "fat_g": 61.7, "total_kcal": 5543, "total_protein_g": 204.6, "total_carbs_g": 536.3, "total_fat_g": 308.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the coconut rice", "instruction": "Stir together the coconut milk, water, ginger, bay leaf and rice in a saucepan, cover, bring to a boil, then reduce heat and simmer until done.", "timer_seconds": 1500, "background": true}, {"step": 2, "label": "Boil the eggs", "instruction": "Cover the eggs with cold water, bring to a boil, remove from heat, cover, and let stand, then cool, peel and halve. Slice the cucumber.", "timer_seconds": 660, "background": false}, {"step": 3, "label": "Fry the peanuts and anchovies", "instruction": "Heat oil in a wok, fry the peanuts until lightly browned, then drain. Fry the anchovies until crisp, then drain. Discard the oil and wipe out the wok.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Build the sambal", "instruction": "Heat fresh oil, cook the onion, garlic and shallots until fragrant, mix in the chilli paste, and cook, adding water if too dry.", "timer_seconds": 720, "background": false}, {"step": 5, "label": "Finish the sambal", "instruction": "Stir in the remaining anchovies, cook further, then stir in salt, sugar and tamarind and simmer until thick.", "timer_seconds": 600, "background": false}, {"step": 6, "label": "Serve", "instruction": "Serve the sambal over the warm rice, topped with peanuts, fried anchovies, cucumber and eggs.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=IUIs4C86Ilo"}, {"id": "53052", "name": "Roti john", "category": "Beef", "area": "Malaysian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/hx335q1619789561.jpg", "local_image": "53052.jpg", "ingredients": [{"ingredient": "Minced Beef", "measure": "1/4 lb"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Chilli", "measure": "1 tbs"}, {"ingredient": "Baguette", "measure": "1/2"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Mayonnaise", "measure": "Top"}], "instructions": "Mix all the ingredients in a bowl.\r\nHeat a pan or griddle with a little vegetable oil.\r\nPour the mixture onto the pan and place a piece of open-faced baguette on top.\r\nPress on the bread with a spatula and grill for 2 minutes.\r\nTurn the bread over to make it a little crispy.\r\nRemove from pan and cut the bread into small portions.\r\nAdd mayonnaise and/or Sambal before cutting the sandwich (optional).", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 827, "protein_g": 42.9, "carbs_g": 27.6, "fat_g": 60.9, "total_kcal": 827, "total_protein_g": 42.9, "total_carbs_g": 27.6, "total_fat_g": 60.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix the filling", "instruction": "Mix the beef, onion, eggs and chilli together in a bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook with the bread", "instruction": "Heat oil in a pan, pour in the mixture, and place a piece of open-faced baguette on top, pressing with a spatula.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Flip and finish", "instruction": "Turn the bread over to crisp the other side.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Serve", "instruction": "Remove from the pan, cut into portions, and add mayonnaise or sambal before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=cl4YH8wblRs"}, {"id": "53053", "name": "Beef Rendang", "category": "Beef", "area": "Malaysian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/bc8v651619789840.jpg", "local_image": "53053.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1lb"}, {"ingredient": "Vegetable Oil", "measure": "5 tbs"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Cloves", "measure": "3"}, {"ingredient": "Star Anise", "measure": "3"}, {"ingredient": "Cardamom", "measure": "3"}, {"ingredient": "Coconut Cream", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Tamarind Paste", "measure": "2 tbs"}, {"ingredient": "Lime", "measure": "6"}, {"ingredient": "Sugar", "measure": "1 tbs"}, {"ingredient": "Challots", "measure": "5"}], "instructions": "Chop the spice paste ingredients and then blend it in a food processor until fine.\r\nHeat the oil in a stew pot, add the spice paste, cinnamon, cloves, star anise, and cardamom and stir-fry until aromatic. Add the beef and the pounded lemongrass and stir for 1 minute. Add the coconut milk, tamarind juice, water, and simmer on medium heat, stirring frequently until the meat is almost cooked. Add the kaffir lime leaves, kerisik (toasted coconut), sugar or palm sugar, stirring to blend well with the meat.\r\nLower the heat to low, cover the lid, and simmer for 1 to 1 1/2 hours or until the meat is really tender and the gravy has dried up. Add more salt and sugar to taste. Serve immediately with steamed rice and save some for overnight.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 121, "prep_minutes_source": "explicit", "kcal": 1160, "protein_g": 39.4, "carbs_g": 62.8, "fat_g": 92.5, "total_kcal": 3481, "total_protein_g": 118.3, "total_carbs_g": 188.4, "total_fat_g": 277.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Blend the spice paste", "instruction": "Chop the spice paste ingredients and blend in a food processor until fine.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fry the paste", "instruction": "Heat oil in a stew pot, add the spice paste, cinnamon, cloves, star anise and cardamom, and stir-fry until aromatic. Add the beef and lemongrass and stir.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Simmer", "instruction": "Add coconut milk, tamarind juice and water, and simmer, stirring frequently, until the meat is almost cooked.", "timer_seconds": 2700, "background": true}, {"step": 4, "label": "Finish", "instruction": "Add lime leaves, toasted coconut and sugar, and blend well with the meat.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Reduce", "instruction": "Lower the heat, cover, and simmer until the meat is really tender and the gravy has dried up.", "timer_seconds": 4500, "background": true}, {"step": 6, "label": "Serve", "instruction": "Adjust salt and sugar to taste and serve immediately with steamed rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Ot-dmfBaZrA"}, {"id": "53054", "name": "Seri muka kuih", "category": "Dessert", "area": "Malaysian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/6ut2og1619790195.jpg", "local_image": "53054.jpg", "ingredients": [{"ingredient": "Rice", "measure": "400g"}, {"ingredient": "Coconut Milk", "measure": "150ml"}, {"ingredient": "Water", "measure": "100ml"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Corn Flour", "measure": "5 tbs"}, {"ingredient": "Flour", "measure": "3 tbs"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Coconut Cream", "measure": "200ml"}, {"ingredient": "Sugar", "measure": "140g"}], "instructions": "Soak glutinous rice with water for at least 1 ½ hours prior to using. Drain.\r\nPrepare a 9-inch round or square cake pan and spray with cooking spray or line with plastic wrap.\r\nMix coconut milk, water, salt and the rice. Pour it into cake pan, topped with the pandan knots.\r\nSteam for 30 minutes.\r\nAfter 30 minutes, fluff up the rice and remove pandan knots. Then, using a greased spatula, flatten the steamed rice. Make sure there are no holes/air bubbles and gaps in the rice, especially the sides.\r\nSteam for another 10 minutes.\r\n\r\nCombine pandan juice, coconut milk, all purpose flour, cornflour, and sugar. Mix well.\r\nAdd eggs and whisk well then strain into a medium sized metal bowl or pot.\r\nPlace pandan mixture over simmering water (double boiler or bain-marie)\r\nStir continuously and cook till custard starts to thicken. (15 minutes)\r\nPour pandan custard into glutinous rice layer, give it a little tap (for air bubbles) and continue to steam for 30 minutes.\r\nRemove kuih seri muka from the steamer and allow to cool completely before cutting into rectangles or diamond shapes.", "equipment_tags": [], "portions": 8, "prep_minutes": 115, "prep_minutes_source": "explicit", "kcal": 515, "protein_g": 8.5, "carbs_g": 71.5, "fat_g": 23.0, "total_kcal": 4120, "total_protein_g": 67.7, "total_carbs_g": 572.2, "total_fat_g": 184.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the rice", "instruction": "Soak the glutinous rice in water, then drain.", "timer_seconds": 5400, "background": true}, {"step": 2, "label": "Prep the pan", "instruction": "Prepare a 9-inch cake pan lined with plastic wrap.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Steam the rice base", "instruction": "Mix coconut milk, water, salt and rice, pour into the pan, top with pandan knots, and steam.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Flatten and steam again", "instruction": "Fluff the rice, remove the pandan knots, flatten with a greased spatula ensuring no gaps, then steam further.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Make the pandan custard", "instruction": "Combine pandan juice, coconut milk, flour, cornflour and sugar, whisk in the eggs, and strain into a metal bowl.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Cook the custard", "instruction": "Place over simmering water and stir continuously until it starts to thicken.", "timer_seconds": 900, "background": false}, {"step": 7, "label": "Layer and steam", "instruction": "Pour the custard over the rice layer, tap to remove air bubbles, and continue steaming.", "timer_seconds": 1800, "background": true}, {"step": 8, "label": "Cool and cut", "instruction": "Remove from the steamer, cool completely, then cut into rectangles or diamonds.", "timer_seconds": null, "background": true}], "video": "https://www.youtube.com/watch?v=_NJtCfqgaBo"}, {"id": "53055", "name": "Cevapi Sausages", "category": "Beef", "area": "Croatian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/vc08jn1628769553.jpg", "local_image": "53055.jpg", "ingredients": [{"ingredient": "Minced Beef", "measure": "500g"}, {"ingredient": "Minced Pork", "measure": "250g"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Parsley", "measure": "3 tblsp chopped"}, {"ingredient": "Paprika", "measure": "1 tbs"}, {"ingredient": "Baking Powder", "measure": "3/4 teaspoon"}, {"ingredient": "Breadcrumbs", "measure": "2 tbs"}, {"ingredient": "Water", "measure": "3 tbs"}, {"ingredient": "Vegetable Stock Cube", "measure": "1"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1 tsp"}], "instructions": "Place the ground meat in a bowl. Chop the onion very finely and grate the garlic cloves. Add to the bowl. Add the chopped parsley, all sorts of paprika, baking soda, dried breadcrumbs, water, Vegeta, salt, and pepper.\r\nMix well with the hand mixer fitted with the dough hooks. Cover the bowl with cling film/ plastic foil and leave to rest for 1 or 2 hours in the refrigerator.\r\nTake portions of the meat mixture, about 50-55 g/ 1.7-1.9 oz/ ¼ cup portions, and form the cevapi. The rolls should be about as thick as your thumb and about 7-10 cm/ 3-4 inches long. I had 18 sausages. The recipe can be easily doubled.\r\nGrill the cevapcici on the hot grill pan or on the barbecue for about 12-14 minutes, turning them several times in between, or until brown and cooked through. I checked by cutting one in the middle and then grilling the following batches for the same period of time.\r\nServe hot as suggested above. The cevapcici can be reheated in the oven at 180 degrees Celsius/ 350 degrees Fahrenheit for about 10 minutes or until heated through. Check one, if it is not hot enough, give the sausages a few more minutes.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 144, "prep_minutes_source": "explicit", "kcal": 963, "protein_g": 72.5, "carbs_g": 25.7, "fat_g": 62.2, "total_kcal": 1926, "total_protein_g": 145.1, "total_carbs_g": 51.3, "total_fat_g": 124.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix the meat", "instruction": "Combine the ground meat, finely chopped onion, grated garlic, parsley, paprika, baking powder, breadcrumbs, water, stock, salt and pepper in a bowl and mix well with a hand mixer.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Rest the mixture", "instruction": "Cover and leave to rest in the fridge.", "timer_seconds": 5400, "background": true}, {"step": 3, "label": "Shape the sausages", "instruction": "Take portions of the mixture and roll into thumb-thick sausages about 7-10cm long.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Grill", "instruction": "Grill on a hot grill pan or barbecue, turning several times, until browned and cooked through.", "timer_seconds": 780, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve hot, or reheat in the oven at 180°C if needed.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_MpSxSgS7f8"}, {"id": "53056", "name": "Croatian lamb peka", "category": "Beef", "area": "Croatian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/pn59o51628769837.jpg", "local_image": "53056.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "600g"}, {"ingredient": "Courgettes", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "1 chopped"}, {"ingredient": "Green Pepper", "measure": "1 chopped"}, {"ingredient": "Aubergine", "measure": "1 small"}, {"ingredient": "Onion", "measure": "1 Large Chopped"}, {"ingredient": "Lamb Shoulder", "measure": "800g"}, {"ingredient": "Garlic Sauce", "measure": "1 tbs"}, {"ingredient": "Tomato Puree", "measure": "1 tbs"}, {"ingredient": "Olive Oil", "measure": "80 ml"}, {"ingredient": "Thyme", "measure": "Sprinking"}, {"ingredient": "White Wine", "measure": "250ml"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "Preheat oven to 200°C fan / 220°C / 425°F / Gas mark 7\r\nIf you have not bought diced lamb, cut your lamb shoulder or leg into large chunks and place to one side.\r\nChunks of chopped lamb of a red chopping board\r\nMake oil marinade -\r\nMix 80ml of olive oil in a bowl with garlic puree, sundried tomato puree ,black pepper and salt.\r\nolive oil, gia sundried tomato puree and gia garlic puree and black pepper mixed together in a silver bowl to make Croatian peka\r\nAdd potatoes and vegetables into a large lidded casserole dish.\r\nChopped up vegetables which consist of chopped up red onion, courgette, potatoes red peppers in a cast iron pan\r\nPlace diced lamb on top of the vegetables, pour the marinade and wine over the top.\r\nChunks of lamb covered in in a sundried tomato oil sauce which is on top of chopped red onion, aubergine, courgette and potatoes in a cast iron pan\r\nAdd the rosemary, thyme and sage, trying to keep the herbs on top.\r\nSo you can easily remove the herb stalks once cooked.\r\nChunks of lamb coated in a sundried tomato oil sauce and covered with thyme, rosemary and sage which is on top of chopped red onion, aubergine, courgette and potatoes in a cast iron pan\r\nPlace lid on the casserole dish and cook for 1hr 30 minute\r\nIf you do not have a lid cover very well with kitchen foil\r\nCast iron dish with lid on in the oven\r\nTake the lid off, remove any thick herb stems. Stir in 2 tbsp of olive oil.\r\nCook for a further 20-30 mins.\r\nCooked Croatian Lamb Peka in a cast iron pan in the oven\r\nServe with fresh homemade bread to dip into the juices.", "equipment_tags": [], "portions": 4, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 956, "protein_g": 54.6, "carbs_g": 36.2, "fat_g": 60.8, "total_kcal": 3826, "total_protein_g": 218.4, "total_carbs_g": 144.6, "total_fat_g": 243.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Preheat the oven to 220°C/425°F. Cut the lamb into large chunks if not already diced.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the marinade", "instruction": "Mix the olive oil with garlic purée, tomato purée, black pepper and salt.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Layer the casserole", "instruction": "Add the potatoes and vegetables to a large lidded casserole dish, place the lamb on top, and pour over the marinade and wine.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Top with herbs and braise", "instruction": "Add the herbs on top so they're easy to remove later. Cover with the lid (or foil) and cook.", "timer_seconds": 5400, "background": true}, {"step": 5, "label": "Finish uncovered", "instruction": "Remove the lid, take out the herb stems, stir in more olive oil, and continue cooking.", "timer_seconds": 1500, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve with fresh homemade bread to dip into the juices.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=K0ipnz4fwJI"}, {"id": "53057", "name": "Traditional Croatian Goulash", "category": "Beef", "area": "Croatian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/n1hcou1628770088.jpg", "local_image": "53057.jpg", "ingredients": [{"ingredient": "Beef", "measure": "500g"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Carrots", "measure": "2 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Red Wine", "measure": "200ml"}, {"ingredient": "Water", "measure": "2 Litres"}, {"ingredient": "Mustard", "measure": "3 tbs"}, {"ingredient": "Salt", "measure": "1tbsp"}, {"ingredient": "Pepper", "measure": "1/2 tsp"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}, {"ingredient": "Vegetable Oil", "measure": "2 tbs"}], "instructions": "Clean the meat from the veins if there are some and cut it into smaller pieces, 3 × 3 cm. Marinate the meat in the mustard and spices and let it sit in the refrigerator for one hour\r\nHeat one tablespoon of pork fat or vegetable oil in a pot and fry the meat on all sides until it gets browned. Once the meat is cooked, transfer it to a plate and add another tablespoon of fat to the pot\r\nCut the onions very fine, peel the carrots and shred it using a grater. Cook the onions and carrots over low heat for 15 minutes. You can salt the vegetables a little to make them soften faster\r\nOnce the vegetables have browned and become slightly mushy, add the meat and bay leaves and garlic. Pour over with wine and simmer for 10-15 minutes to allow the alcohol to evaporate. Now is the right time to add 2/3 the amount of liquid\r\nCover the pot and cook over low heat for an hour, stirring occasionally. After the first hour, pour over the rest of the water or stock and cook for another 30-45 minutes\r\nAllow the stew to cool slightly and serve it with a sprinkle of chopped parsley and few slices of fresh hot pepper if you like to spice it up a bit\r\nSlice ​​some fresh bread, season the salad and simply enjoying these wonderful flavors", "equipment_tags": [], "portions": 6, "prep_minutes": 75, "prep_minutes_source": "explicit", "kcal": 251, "protein_g": 17.8, "carbs_g": 7.6, "fat_g": 14.2, "total_kcal": 1505, "total_protein_g": 106.7, "total_carbs_g": 45.7, "total_fat_g": 85.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the beef", "instruction": "Cut the meat into pieces and marinate in the mustard and spices in the fridge.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Brown the beef", "instruction": "Heat fat in a pot and fry the meat on all sides until browned, then transfer to a plate.", "timer_seconds": 480, "background": false}, {"step": 3, "label": "Cook the vegetables", "instruction": "Finely chop the onions and shred the carrots, then cook over low heat until softened, salting a little to help them soften.", "timer_seconds": 900, "background": false}, {"step": 4, "label": "Build the stew", "instruction": "Once the vegetables are browned and slightly mushy, add the meat, bay leaves and garlic. Pour in the wine and simmer to evaporate the alcohol, then add most of the water.", "timer_seconds": 900, "background": false}, {"step": 5, "label": "First simmer", "instruction": "Cover and cook over low heat, stirring occasionally.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Finish cooking", "instruction": "Add the remaining water or stock and cook further.", "timer_seconds": 2400, "background": true}, {"step": 7, "label": "Serve", "instruction": "Cool slightly and serve sprinkled with parsley and fresh hot pepper if you like, with bread and salad.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ipEz5u2T7KM"}, {"id": "53058", "name": "Croatian Bean Stew", "category": "Beef", "area": "Croatian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/tnwy8m1628770384.jpg", "local_image": "53058.jpg", "ingredients": [{"ingredient": "Cannellini Beans", "measure": "2 cans"}, {"ingredient": "Vegetable Oil", "measure": "3 tbs"}, {"ingredient": "Tomatoes", "measure": "2 cups"}, {"ingredient": "Challots", "measure": "5"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Parsley", "measure": "Pinch"}, {"ingredient": "Chorizo", "measure": "1/2 kg chopped"}], "instructions": "Heat the oil in a pan. Add the chopped vegetables and sauté until tender. Take a pot, empty the beans together with the vegetables into it, put the sausages inside and cook for further 20 minutes on a low heat. Or, put it in an oven and bake it at a temperature of 180ºC/350ºF for 30 minutes. This dish is even better reheated the next day.", "equipment_tags": [], "portions": 4, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 983, "protein_g": 50.1, "carbs_g": 63.7, "fat_g": 59.2, "total_kcal": 3932, "total_protein_g": 200.6, "total_carbs_g": 254.6, "total_fat_g": 236.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sauté the vegetables", "instruction": "Heat the oil in a pan, add the chopped vegetables, and sauté until tender.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Combine and simmer", "instruction": "Combine the beans, sautéed vegetables and sausages in a pot and cook on low heat (or bake at 180°C/350°F).", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Serve", "instruction": "Serve hot; this dish is even better reheated the next day.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=mrjnQal3S1A"}, {"id": "53059", "name": "Mushroom soup with buckwheat", "category": "Side", "area": "Croatian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1ngcbf1628770793.jpg", "local_image": "53059.jpg", "ingredients": [{"ingredient": "Mushrooms", "measure": "150g"}, {"ingredient": "Buckwheat", "measure": "50g"}, {"ingredient": "Vegetable Oil", "measure": "4 tbs"}, {"ingredient": "Onion", "measure": "40g"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Vegetable Stock Cube", "measure": "1tbsp"}, {"ingredient": "Sour Cream", "measure": "50 ml"}, {"ingredient": "White Wine Vinegar", "measure": "Dash"}, {"ingredient": "Parsley", "measure": "Top"}], "instructions": "Chop the onion and garlic, slice the mushrooms and wash the buckwheat. Heat the oil and lightly sauté the onion. Add the mushrooms and the garlic and continue to sauté. Add the salt, vegetable seasoning, buckwheat and the bay leaf and cover with water. Simmer gently and just before it is completely cooked, add pepper, sour cream mixed with flour, the chopped parsley and vinegar to taste.", "equipment_tags": [], "portions": 2, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 415, "protein_g": 7.1, "carbs_g": 25.5, "fat_g": 33.6, "total_kcal": 829, "total_protein_g": 14.3, "total_carbs_g": 50.9, "total_fat_g": 67.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep and sauté the onion", "instruction": "Chop the onion and garlic, slice the mushrooms, wash the buckwheat, then heat the oil and lightly sauté the onion.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Add the mushrooms and garlic", "instruction": "Add the mushrooms and garlic and continue to sauté.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Simmer the soup", "instruction": "Add salt, seasoning, buckwheat and bay leaf, cover with water, and simmer gently.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Finish", "instruction": "Just before it's completely cooked, add pepper, sour cream mixed with flour, chopped parsley and vinegar to taste.", "timer_seconds": 180, "background": false}], "video": "https://www.youtube.com/watch?v=M1ok7mG9-Qc"}, {"id": "53060", "name": "Burek", "category": "Side", "area": "Croatian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tkxquw1628771028.jpg", "local_image": "53060.jpg", "ingredients": [{"ingredient": "Filo Pastry", "measure": "1 Packet"}, {"ingredient": "Minced Beef", "measure": "150g"}, {"ingredient": "Onion", "measure": "150g"}, {"ingredient": "Oil", "measure": "40g"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Pepper", "measure": "Dash"}], "instructions": "Fry the finely chopped onions and minced meat in oil. Add the salt and pepper. Grease a round baking tray and put a layer of pastry in it. Cover with a thin layer of filling and cover this with another layer of filo pastry which must be well coated in oil. Put another layer of filling and cover with pastry. When you have five or six layers, cover with filo pastry, bake at 200ºC/392ºF for half an hour and cut in quarters and serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 549, "protein_g": 18.1, "carbs_g": 36.3, "fat_g": 36.6, "total_kcal": 1097, "total_protein_g": 36.2, "total_carbs_g": 72.6, "total_fat_g": 73.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the filling", "instruction": "Fry the finely chopped onion and minced meat in oil, seasoning with salt and pepper.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Layer the burek", "instruction": "Grease a round baking tray, layer filo pastry brushed with oil, add a thin layer of filling, and continue layering pastry and filling for five or six layers, finishing with pastry.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake and serve", "instruction": "Bake at 200°C/392°F until golden, then cut into quarters and serve.", "timer_seconds": 1800, "background": true}], "video": "https://www.youtube.com/watch?v=YsJXZwE5pdY"}, {"id": "53061", "name": "Fresh sardines", "category": "Side", "area": "Croatian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/nv5lf31628771380.jpg", "local_image": "53061.jpg", "ingredients": [{"ingredient": "Sardines", "measure": "500g"}, {"ingredient": "Vegetable Oil", "measure": "Dash"}, {"ingredient": "Flour", "measure": "To Glaze"}, {"ingredient": "Salt", "measure": "Dash"}], "instructions": "Wash the fish under the cold tap. Roll in the flour and deep fry in oil until crispy. Lay on kitchen towel to get rid of the excess oil and serve hot or cold with a slice of lemon.", "equipment_tags": [], "portions": 3, "prep_minutes": 19, "prep_minutes_source": "estimated", "kcal": 386, "protein_g": 42.0, "carbs_g": 7.6, "fat_g": 19.6, "total_kcal": 1158, "total_protein_g": 126.0, "total_carbs_g": 22.8, "total_fat_g": 58.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the fish", "instruction": "Wash the sardines under cold water and roll in flour.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fry", "instruction": "Deep fry in oil until crispy.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Serve", "instruction": "Drain on kitchen towel and serve hot or cold with a slice of lemon.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=DDaZoXP1Mdc"}, {"id": "53062", "name": "Walnut Roll Gužvara", "category": "Dessert", "area": "Croatian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/u9l7k81628771647.jpg", "local_image": "53062.jpg", "ingredients": [{"ingredient": "Flour", "measure": "450g"}, {"ingredient": "Caster Sugar", "measure": "55g"}, {"ingredient": "Yeast", "measure": "2 parts"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Milk", "measure": "6 oz"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Butter", "measure": "30g"}, {"ingredient": "Walnuts", "measure": "140g"}, {"ingredient": "Butter", "measure": "85g"}, {"ingredient": "Brown Sugar", "measure": "85g"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Milk", "measure": "To Glaze"}, {"ingredient": "Icing Sugar", "measure": "To Glaze"}], "instructions": "Mix all the ingredients for the dough together and knead well. Cover the dough and put to rise until doubled in size which should take about 2 hours. Knock back the dough and knead lightly.\r\n\r\nDivide the dough into two equal pieces; roll each piece into an oblong about 12 inches by 8 inches. Mix the filling ingredients together and divide between the dough, spreading over each piece. Roll up the oblongs as tightly as possible to give two 12 inch sausages. Place these side by side, touching each other, on a greased baking sheet. Cover and leave to rise for about 40 minutes. Heat oven to 200ºC (425ºF). Bake for 30-35 minutes until well risen and golden brown. Bread should sound hollow when the base is tapped.\r\n\r\nRemove from oven and brush the hot bread top with milk. Sift with a generous covering of icing sugar.", "equipment_tags": [], "portions": 9, "prep_minutes": 195, "prep_minutes_source": "explicit", "kcal": 515, "protein_g": 14.1, "carbs_g": 65.1, "fat_g": 23.7, "total_kcal": 4633, "total_protein_g": 126.6, "total_carbs_g": 585.8, "total_fat_g": 212.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make and rise the dough", "instruction": "Mix all the dough ingredients together and knead well, then cover and let rise until doubled.", "timer_seconds": 7200, "background": true}, {"step": 2, "label": "Knock back", "instruction": "Knock back the dough and knead lightly.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fill and roll", "instruction": "Divide the dough in two, roll each into an oblong, mix the filling ingredients and spread over each, then roll up tightly into two sausages.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Second rise", "instruction": "Place the rolls side by side on a greased baking sheet, cover and leave to rise.", "timer_seconds": 2400, "background": true}, {"step": 5, "label": "Bake", "instruction": "Heat the oven to 200°C/425°F and bake until well risen, golden brown, and the base sounds hollow when tapped.", "timer_seconds": 1950, "background": true}, {"step": 6, "label": "Glaze and serve", "instruction": "Brush the hot bread top with milk and sift over a generous covering of icing sugar.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=Q_akngSJVrQ"}, {"id": "53063", "name": "Chivito uruguayo", "category": "Beef", "area": "Uruguayan", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/n7qnkb1630444129.jpg", "local_image": "53063.jpg", "ingredients": [{"ingredient": "Beef Brisket", "measure": "2"}, {"ingredient": "Bread", "measure": "2"}, {"ingredient": "Lettuce", "measure": "1"}, {"ingredient": "Tomato", "measure": "1"}, {"ingredient": "Ham", "measure": "100g"}, {"ingredient": "Mozzarella", "measure": "100g"}, {"ingredient": "Bacon", "measure": "100g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Pepper", "measure": "1"}], "instructions": "Crush the meat so that it is finite and we put it on a griddle to brown. Put the eggs, bacon and ham to fry.\r\nCut the bread in half, put the beef brisket, the fried eggs, the bacon, the ham, the mozzarella, the tomato and the lettuce. Cover with the other half of the bread and serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 22, "prep_minutes_source": "estimated", "kcal": 777, "protein_g": 62.2, "carbs_g": 35.9, "fat_g": 42.3, "total_kcal": 1555, "total_protein_g": 124.4, "total_carbs_g": 71.8, "total_fat_g": 84.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the beef and eggs", "instruction": "Crush the meat thin and brown it on a griddle. Fry the eggs, bacon and ham in a separate pan.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Assemble and serve", "instruction": "Cut the bread in half, layer the beef, fried egg, bacon, ham, mozzarella, tomato and lettuce, and cover with the other half of the bread.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=0PXbbL1QdaA&ab_channel=D%C3%ADadeCocina"}, {"id": "53064", "name": "Fettuccine Alfredo", "category": "Pasta", "area": "Italian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0jv5gx1661040802.jpg", "local_image": "53064.jpg", "ingredients": [{"ingredient": "Fettuccine", "measure": "1 lb"}, {"ingredient": "Heavy Cream", "measure": "1/2 cup"}, {"ingredient": "Butter", "measure": "1/2 cup"}, {"ingredient": "Parmesan", "measure": "1/2 cup"}, {"ingredient": "Parsley", "measure": "2 tbsp"}, {"ingredient": "Black Pepper", "measure": ""}], "instructions": "Cook pasta according to package instructions in a large pot of boiling water and salt. Add heavy cream and butter to a large skillet over medium heat until the cream bubbles and the butter melts. Whisk in parmesan and add seasoning (salt and black pepper). Let the sauce thicken slightly and then add the pasta and toss until coated in sauce. Garnish with parsley, and it's ready.", "equipment_tags": [], "portions": 6, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 596, "protein_g": 18.3, "carbs_g": 58.5, "fat_g": 32.1, "total_kcal": 3578, "total_protein_g": 110.0, "total_carbs_g": 351.0, "total_fat_g": 192.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the pasta", "instruction": "Cook the pasta according to package instructions in a large pot of boiling salted water.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Make the sauce", "instruction": "Add cream and butter to a large skillet over medium heat until the cream bubbles and the butter melts.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Finish the sauce", "instruction": "Whisk in the parmesan and season with salt and black pepper, letting the sauce thicken slightly.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Add the pasta and toss until coated in sauce. Garnish with parsley and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=LPPcNPdq_j4"}, {"id": "53065", "name": "Sushi", "category": "Seafood", "area": "Japanese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/g046bb1663960946.jpg", "local_image": "53065.jpg", "ingredients": [{"ingredient": "Sushi Rice", "measure": "300ml"}, {"ingredient": "Rice wine", "measure": "100ml"}, {"ingredient": "Caster Sugar", "measure": "2 tbs"}, {"ingredient": "Mayonnaise", "measure": "3 tbs"}, {"ingredient": "Rice wine", "measure": "1 tbs"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}, {"ingredient": "Cucumber", "measure": "1"}], "instructions": "STEP 1\r\nTO MAKE SUSHI ROLLS: Pat out some rice. Lay a nori sheet on the mat, shiny-side down. Dip your hands in the vinegared water, then pat handfuls of rice on top in a 1cm thick layer, leaving the furthest edge from you clear.\r\n\r\nSTEP 2\r\nSpread over some Japanese mayonnaise. Use a spoon to spread out a thin layer of mayonnaise down the middle of the rice.\r\n\r\nSTEP 3\r\nAdd the filling. Get your child to top the mayonnaise with a line of their favourite fillings – here we’ve used tuna and cucumber.\r\n\r\nSTEP 4\r\nRoll it up. Lift the edge of the mat over the rice, applying a little pressure to keep everything in a tight roll.\r\n\r\nSTEP 5\r\nStick down the sides like a stamp. When you get to the edge without any rice, brush with a little water and continue to roll into a tight roll.\r\n\r\nSTEP 6\r\nWrap in cling film. Remove the mat and roll tightly in cling film before a grown-up cuts the sushi into thick slices, then unravel the cling film.\r\n\r\nSTEP 7\r\nTO MAKE PRESSED SUSHI: Layer over some smoked salmon. Line a loaf tin with cling film, then place a thin layer of smoked salmon inside on top of the cling film.\r\n\r\nSTEP 8\r\nCover with rice and press down. Press about 3cm of rice over the fish, fold the cling film over and press down as much as you can, using another tin if you have one.\r\n\r\nSTEP 9\r\nTip it out like a sandcastle. Turn block of sushi onto a chopping board. Get a grown-up to cut into fingers, then remove the cling film.\r\n\r\nSTEP 10\r\nTO MAKE SUSHI BALLS: Choose your topping. Get a small square of cling film and place a topping, like half a prawn or a small piece of smoked salmon, on it. Use damp hands to roll walnut-sized balls of rice and place on the topping.\r\n\r\nSTEP 11\r\nMake into tight balls. Bring the corners of the cling film together and tighten into balls by twisting it up, then unwrap and serve.", "equipment_tags": [], "portions": 4, "prep_minutes": 90, "prep_minutes_source": "estimated", "kcal": 427, "protein_g": 6.8, "carbs_g": 77.7, "fat_g": 9.1, "total_kcal": 1708, "total_protein_g": 27.0, "total_carbs_g": 310.9, "total_fat_g": 36.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the rice on the nori", "instruction": "Lay a nori sheet shiny-side down on a mat, dip your hands in vinegared water, and pat rice into a thin layer, leaving the far edge clear.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Add mayonnaise and filling", "instruction": "Spread a thin line of mayonnaise down the middle of the rice, then top with your chosen fillings such as tuna and cucumber.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Roll and seal", "instruction": "Lift the mat edge over the rice to roll tightly, then brush the clear edge with water and continue rolling to seal, wrapping tightly in cling film.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Slice", "instruction": "Cut the sushi into thick slices, then unwrap.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Make pressed sushi", "instruction": "Line a loaf tin with cling film, layer smoked salmon in the base, cover with a layer of rice, press down firmly with the cling film folded over.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Turn out and slice", "instruction": "Turn the block onto a chopping board, cut into fingers, and remove the cling film.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Make sushi balls", "instruction": "Place a topping on a square of cling film, add a walnut-sized ball of rice on top, then bring the corners together and twist to form tight balls before unwrapping.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ub68OxEypaY"}, {"id": "53067", "name": "Stuffed Bell Peppers with Quinoa and Black Beans", "category": "Vegetarian", "area": "Mexican", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/b66myb1683207208.jpg", "local_image": "53067.jpg", "ingredients": [{"ingredient": "Green Pepper", "measure": "4 whole"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 small finely diced"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Quinoa", "measure": "1 cups"}, {"ingredient": "Black Beans", "measure": "1 can"}, {"ingredient": "Sweetcorn", "measure": "1 cup"}, {"ingredient": "Diced Tomatoes", "measure": "1 can"}, {"ingredient": "Cumin", "measure": "1 teaspoon"}, {"ingredient": "Chili Powder", "measure": "½ tsp"}, {"ingredient": "Smoked Paprika", "measure": "½ tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Shredded Mexican Cheese", "measure": "1 1/2 cup"}, {"ingredient": "Cilantro", "measure": "Chopped"}], "instructions": "1. Preheat your oven to 375°F (190°C). Lightly grease a 9x13-inch baking dish or a similar-sized casserole dish.\r\n2. Place the bell pepper halves in the prepared baking dish, cut side up. Bake for 15-20 minutes, or until slightly softened.\r\n3. While the bell peppers are baking, prepare the filling. In a large skillet, heat the olive oil over medium heat. Add the chopped onion, and cook for 3-4 minutes, until softened. Add the garlic, and cook for another 1 minute, until fragrant.\r\n4. Stir in the cooked quinoa, black beans, corn, diced tomatoes, ground cumin, chili powder, smoked paprika, salt, and pepper. Cook for 5-7 minutes, until heated through. Remove the skillet from heat, and stir in 1 cup of the shredded cheese, if using.\r\n5. Remove the bell peppers from the oven, and carefully stuff each pepper half with the quinoa and black bean mixture. Top the stuffed peppers with the remaining 1/2 cup of shredded cheese, if using.\r\n6. Return the stuffed peppers to the oven, and bake for another 15-20 minutes, until the cheese is melted and the peppers are tender.\r\n7. Remove from the oven, and allow the stuffed peppers to cool for 5 minutes before serving. Garnish with fresh chopped cilantro.", "equipment_tags": [], "portions": 4, "prep_minutes": 57, "prep_minutes_source": "explicit", "kcal": 792, "protein_g": 42.8, "carbs_g": 83.9, "fat_g": 34.3, "total_kcal": 3167, "total_protein_g": 171.0, "total_carbs_g": 335.6, "total_fat_g": 137.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and par-bake the peppers", "instruction": "Preheat the oven to 375°F/190°C. Place the pepper halves cut-side up in a greased baking dish and bake until slightly softened.", "timer_seconds": 1050, "background": true}, {"step": 2, "label": "Cook the filling base", "instruction": "Heat olive oil in a skillet, cook the onion until softened, then add garlic and cook until fragrant.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Build the filling", "instruction": "Stir in the cooked quinoa, black beans, corn, tomatoes, cumin, chilli powder, smoked paprika, salt and pepper, and cook until heated through. Remove from heat and stir in a cup of cheese.", "timer_seconds": 420, "background": false}, {"step": 4, "label": "Stuff and top", "instruction": "Stuff each pepper half with the filling and top with the remaining cheese.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake", "instruction": "Return to the oven and bake until the cheese is melted and the peppers are tender.", "timer_seconds": 1050, "background": true}, {"step": 6, "label": "Serve", "instruction": "Cool briefly and garnish with fresh cilantro before serving.", "timer_seconds": 300, "background": false}], "video": null}, {"id": "53068", "name": "Beef Mechado", "category": "Beef", "area": "Filipino", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/cgl60b1683206581.jpg", "local_image": "53068.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Beef", "measure": "2 Lbs"}, {"ingredient": "Tomato Puree", "measure": "8 ounces"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Lemon", "measure": "1 Slice"}, {"ingredient": "Potatoes", "measure": "1 large"}, {"ingredient": "Soy Sauce", "measure": "1/4 cup"}, {"ingredient": "Black Pepper", "measure": "1/2 tsp"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "0.\tMake the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bowl. Mix well.\r\n1.\tAdd the cubed beef tenderloin to the bowl with the beef tenderloin marinade. Gently toss to coat the beef. Let it stay for 1 hour.\r\n2.\tUsing a metal or bamboo skewer, assemble the beef kebob by skewering the vegetables and marinated beef tenderloin.\r\n3.\tHeat-up the grill and start grilling the beef kebobs for 3 minutes per side. This will give you a medium beef that is juicy and tender on the inside. Add more time if you want your beef well done, but it will be less tender.\r\n4.\tTransfer to a serving plate. Serve with Saffron rice.\r\n5.\tShare and enjoy!\r\n", "equipment_tags": ["Grill"], "portions": 4, "prep_minutes": 63, "prep_minutes_source": "explicit", "kcal": 605, "protein_g": 50.4, "carbs_g": 23.1, "fat_g": 35.8, "total_kcal": 2420, "total_protein_g": 201.7, "total_carbs_g": 92.5, "total_fat_g": 143.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the marinade", "instruction": "Combine soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt and black pepper in a bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate the beef", "instruction": "Toss the cubed beef in the marinade and let it sit.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Skewer", "instruction": "Skewer the vegetables and marinated beef onto metal or bamboo skewers.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Grill", "instruction": "Grill the skewers, turning, for a juicy medium result, or longer for well done.", "timer_seconds": 360, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve with saffron rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=jxW3Lj8VjyE"}, {"id": "53069", "name": "Bistek", "category": "Beef", "area": "Filipino", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/4pqimk1683207418.jpg", "local_image": "53069.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1 lb"}, {"ingredient": "Soy Sauce", "measure": "5 tablespoons"}, {"ingredient": "Lemon", "measure": "1"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Onion", "measure": "3 parts"}, {"ingredient": "Olive Oil", "measure": "4 tbs"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Salt", "measure": "1 pinch"}], "instructions": "0.\tMarinate beef in soy sauce, lemon (or calamansi), and ground black pepper for at least 1 hour. Note: marinate overnight for best result\r\n1.\tHeat the cooking oil in a pan then pan-fry half of the onions until the texture becomes soft. Set aside\r\n2.\tDrain the marinade from the beef. Set it aside. Pan-fry the beef on the same pan where the onions were fried for 1 minute per side. Remove from the pan. Set aside\r\n3.\tAdd more oil if needed. Saute garlic and remaining raw onions until onion softens.\r\n4.\tPour the remaining marinade and water. Bring to a boil.\r\n5.\tAdd beef. Cover the pan and simmer until the meat is tender. Note: Add water as needed.\r\n6.\tSeason with ground black pepper and salt as needed. Top with pan-fried onions.\r\n7.\tTransfer to a serving plate. Serve hot. Share and Enjoy!\r\n", "equipment_tags": [], "portions": 2, "prep_minutes": 61, "prep_minutes_source": "explicit", "kcal": 754, "protein_g": 50.8, "carbs_g": 21.5, "fat_g": 53.1, "total_kcal": 1507, "total_protein_g": 101.6, "total_carbs_g": 42.9, "total_fat_g": 106.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the beef", "instruction": "Marinate the beef in soy sauce, lemon and black pepper, ideally overnight.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Fry the onions", "instruction": "Heat oil and pan-fry half the onions until soft, then set aside.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Sear the beef", "instruction": "Drain the marinade (reserving it), then pan-fry the beef briefly on each side in the same pan, and remove.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Sauté aromatics", "instruction": "Add more oil if needed, and sauté the garlic and remaining raw onions until softened.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Simmer", "instruction": "Pour in the reserved marinade and water, bring to a boil, add the beef, cover, and simmer until tender.", "timer_seconds": 1800, "background": true}, {"step": 6, "label": "Serve", "instruction": "Season with pepper and salt, top with the fried onions, and serve hot.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=xOQON5_S7as"}, {"id": "53070", "name": "Beef Caldereta", "category": "Beef", "area": "Filipino", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/41cxjh1683207682.jpg", "local_image": "53070.jpg", "ingredients": [{"ingredient": "Beef", "measure": "2kg cut cubes"}, {"ingredient": "Beef Stock", "measure": "1"}, {"ingredient": "Soy Sauce", "measure": "1 tbs"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Green Pepper", "measure": "1 sliced"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Potatoes", "measure": "1 sliced"}, {"ingredient": "Carrots", "measure": "1 sliced"}, {"ingredient": "Tomato Puree", "measure": "8 ounces"}, {"ingredient": "Peanut Butter", "measure": "3  tablespoons"}, {"ingredient": "Chilli Powder", "measure": "5"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "5 cloves"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}], "instructions": "0.\tHeat oil in a cooking pot. Saute onion and garlic until onion softens\r\n1.\tAdd beef. Saute until the outer part turns light brown.\r\n2.\tAdd soy sauce. Pour tomato sauce and water. Let boil.\r\n3.\tAdd Knorr Beef Cube. Cover the pressure cooker. Cook for 30 minutes.\r\n4.\tPan-fry carrot and potato until it browns. Set aside.\r\n5.\tAdd chili pepper, liver spread and peanut butter. Stir.\r\n6.\tAdd bell peppers, fried potato and carrot. Cover the pot. Continue cooking for 5 to 7 minutes.\r\n7.\tSeason with salt and ground black pepper. Serve.\r\n", "equipment_tags": [], "portions": 6, "prep_minutes": 37, "prep_minutes_source": "explicit", "kcal": 783, "protein_g": 69.6, "carbs_g": 15.8, "fat_g": 49.7, "total_kcal": 4697, "total_protein_g": 417.9, "total_carbs_g": 94.9, "total_fat_g": 298.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sauté the aromatics", "instruction": "Heat oil in a cooking pot and sauté the onion and garlic until the onion softens.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Brown the beef", "instruction": "Add the beef and sauté until the outer part turns light brown.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Build the stew", "instruction": "Add soy sauce, tomato sauce and water, and let boil, then add the stock cube.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Pressure cook", "instruction": "Cover and cook in a pressure cooker.", "timer_seconds": 1800, "background": true}, {"step": 5, "label": "Fry the vegetables", "instruction": "Pan-fry the carrot and potato until browned, then set aside.", "timer_seconds": 480, "background": false}, {"step": 6, "label": "Finish the sauce", "instruction": "Add chilli pepper, liver spread and peanut butter to the stew and stir.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Combine and finish cooking", "instruction": "Add the bell peppers, fried potato and carrot, cover, and continue cooking.", "timer_seconds": 420, "background": true}, {"step": 8, "label": "Serve", "instruction": "Season with salt and black pepper and serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=yI7hTz0ft5k"}, {"id": "53071", "name": "Beef Asado", "category": "Beef", "area": "Filipino", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/pkopc31683207947.jpg", "local_image": "53071.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1.5kg"}, {"ingredient": "Beef Stock Concentrate", "measure": "1"}, {"ingredient": "Tomato Puree", "measure": "8 ounces"}, {"ingredient": "Water", "measure": "3 cups"}, {"ingredient": "Soy Sauce", "measure": "6 tablespoons"}, {"ingredient": "White Wine Vinegar", "measure": "1 tbs"}, {"ingredient": "Pepper", "measure": "2 tbs"}, {"ingredient": "Bay Leaf", "measure": "4"}, {"ingredient": "Lemon", "measure": "1/2"}, {"ingredient": "Tomato Sauce", "measure": "2 tbs"}, {"ingredient": "Butter", "measure": "3 tbs"}, {"ingredient": "Olive Oil", "measure": "1/2 cup"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "4 cloves"}], "instructions": "0.\tCombine beef, crushed peppercorn, soy sauce, vinegar, dried bay leaves, lemon, and tomato sauce. Mix well. Marinate beef for at least 30 minutes.\r\n1.\tPut the marinated beef in a cooking pot along with remaining marinade. Add water. Let boil.\r\n2.\tAdd Knorr Beef Cube. Stir. Cover the pot and cook for 40 minutes in low heat.\r\n3.\tTurn the beef over. Add tomato paste. Continue cooking until beef tenderizes. Set aside.\r\n4.\tHeat oil in a pan. Fry the potato until it browns. Turn over and continue frying the opposite side. Remove from the pan and place on a clean plate. Do the same with the carrots.\r\n5.\tSave 3 tablespoons of cooking oil from the pan where the potato was fried. Saute onion and garlic until onion softens.\r\n6.\tPour-in the sauce from the beef stew. Let boil. Add the beef. Cook for 2 minutes.\r\n7.\tAdd butter and let it melt. Continue cooking until the sauce reduces to half.", "equipment_tags": [], "portions": 6, "prep_minutes": 72, "prep_minutes_source": "explicit", "kcal": 739, "protein_g": 54.3, "carbs_g": 15.1, "fat_g": 52.7, "total_kcal": 4432, "total_protein_g": 325.5, "total_carbs_g": 90.9, "total_fat_g": 316.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the beef", "instruction": "Combine the beef, crushed peppercorn, soy sauce, vinegar, bay leaves, lemon and tomato sauce, mix well, and marinate.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Simmer", "instruction": "Put the beef and marinade in a pot with water, bring to a boil, add stock cube, cover, and cook over low heat.", "timer_seconds": 2400, "background": true}, {"step": 3, "label": "Continue cooking", "instruction": "Turn the beef over, add tomato paste, and continue cooking until the beef tenderises.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Fry the potatoes and carrots", "instruction": "Heat oil in a pan and fry the potato until browned on both sides, then remove. Repeat with the carrots.", "timer_seconds": 480, "background": false}, {"step": 5, "label": "Sauté the aromatics", "instruction": "Using reserved oil from the pan, sauté the onion and garlic until softened.", "timer_seconds": 180, "background": false}, {"step": 6, "label": "Combine and finish", "instruction": "Pour in the sauce from the beef stew, bring to a boil, add the beef, and cook briefly.", "timer_seconds": 120, "background": false}, {"step": 7, "label": "Finish with butter", "instruction": "Add butter and let it melt, then continue cooking until the sauce reduces by half.", "timer_seconds": 600, "background": false}], "video": "https://www.youtube.com/watch?v=lNlK8DVhXXA"}, {"id": "53072", "name": "Crispy Eggplant", "category": "Vegetarian", "area": "Filipino", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/c7lzrl1683208757.jpg", "local_image": "53072.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "1 large"}, {"ingredient": "Breadcrumbs", "measure": "1 cup"}, {"ingredient": "Sesame Seed", "measure": "50g"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "Slice eggplant into 1 cm (0.4-inch) slices. Place them in a bowl and sprinkle them with salt. allow them to sit for 30 minutes to render some of their liquid and bitterness.\r\n2. After 30 minutes wash eggplant slices from salt and pat dry with a kitchen towel.\r\n3. In a large bowl/plate place breadcrumbs and sesame seeds. In another bowl beat 2 eggs with pinch salt and pepper.\r\n4. Heal oil in a large skillet over high heat.\r\n5. Dip eggplant slices in egg, then in crumbs, and place in hot oil. Fry 2 to 3 minutes on each side, or until golden brown. Drain on a paper towel. \r\n", "equipment_tags": [], "portions": 1, "prep_minutes": 63, "prep_minutes_source": "explicit", "kcal": 1717, "protein_g": 59.8, "carbs_g": 186.6, "fat_g": 83.2, "total_kcal": 1717, "total_protein_g": 59.8, "total_carbs_g": 186.6, "total_fat_g": 83.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Salt the eggplant", "instruction": "Slice the eggplant, place in a bowl, sprinkle with salt, and let sit to draw out liquid and bitterness.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Rinse and dry", "instruction": "Wash off the salt and pat the slices dry with a kitchen towel.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Set up the coating", "instruction": "Combine breadcrumbs and sesame seeds on a plate, and beat the eggs with a pinch of salt and pepper in a bowl.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Heat the oil", "instruction": "Heat oil in a large skillet over high heat.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fry", "instruction": "Dip the eggplant slices in egg, then in the breadcrumb mixture, and fry until golden brown on each side, then drain on paper towel.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=4mINk5d2hto"}, {"id": "53073", "name": "Eggplant Adobo", "category": "Vegetarian", "area": "Filipino", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/y7h0lq1683208991.jpg", "local_image": "53073.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "1 lb"}, {"ingredient": "Sugar", "measure": "2 tbs"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Garlic", "measure": "1 whole"}, {"ingredient": "Olive Oil", "measure": "3 tbs"}, {"ingredient": "Ground Pork", "measure": "4 oz"}, {"ingredient": "Rice Vinegar", "measure": "3 tbs"}, {"ingredient": "Soy Sauce", "measure": "2 tbs"}, {"ingredient": "Bay Leaf", "measure": "2"}], "instructions": "1.\tSlice 1 lb. small Japanese or Italian eggplant (about 3) into quarters lengthwise, then cut crosswise into 2\"-wide pieces. Place in a medium bowl. Add 1 Tbsp. sugar, 1 tsp. Diamond Crystal or ½ tsp. Morton kosher salt, and ½ tsp. freshly ground black pepper. Toss to evenly coat eggplant and let sit at room temperature at least 20 minutes and up to 2 hours.\r\n2.\tPeel and thinly slice 8 garlic cloves. Add 3 Tbsp. vegetable oil and half of garlic to a medium Dutch oven or other heavy pot. Cook over medium-high heat, stirring constantly with a wooden spoon, until light golden and crisp, about 5 minutes. Using a slotted spoon, transfer garlic chips to a plate; season lightly with salt.\r\n3. Place 4 oz. ground pork in same pot and break up into small pieces with wooden spoon. Season with ¼ tsp. Diamond Crystal or Morton kosher salt and cook, undisturbed, until deeply browned underneath, about 5 minutes. Using a slotted spoon, transfer to another plate, leaving fat behind in the pot.\r\n4. Place eggplant on a clean kitchen towel and blot away any moisture the salt has drawn out.\r\n5. Working in batches and adding more oil if needed, cook eggplant in the same pot until lightly browned, about 3 minutes per side. Transfer to a plate with pork.\r\n6. Pour 1½ cups of water into the pot and scrape up browned bits from the bottom with a wooden spoon. Add remaining garlic, 3 Tbsp. coconut vinegar or unseasoned rice vinegar, 2 Tbsp. soy sauce, 2 bay leaves, 1 tsp. freshly ground black pepper, and remaining 1 Tbsp. sugar. Bring to a simmer, then return pork and eggplant to pot. Reduce heat to medium-low, partially cover, and simmer until eggplant is tender and silky and sauce is reduced by half, 20–25 minutes. Taste and season with more salt and pepper and add a little more sugar if needed.\r\n7. Top with garlic chips and serve with cooked white rice.\r\n", "equipment_tags": [], "portions": 2, "prep_minutes": 178, "prep_minutes_source": "explicit", "kcal": 703, "protein_g": 43.9, "carbs_g": 26.1, "fat_g": 48.2, "total_kcal": 1406, "total_protein_g": 87.8, "total_carbs_g": 52.3, "total_fat_g": 96.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Season the eggplant", "instruction": "Slice the eggplant, toss with sugar, salt and pepper, and let sit at room temperature.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Fry the garlic chips", "instruction": "Slice the garlic. Cook half in oil in a heavy pot over medium-high heat, stirring, until light golden and crisp, then transfer to a plate and season.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Brown the pork", "instruction": "Add the ground pork to the same pot, break up, season, and cook undisturbed until deeply browned, then transfer to a plate.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Blot and cook the eggplant", "instruction": "Blot the moisture from the eggplant, then cook in batches in the same pot until lightly browned on each side, adding oil as needed, and transfer to the plate with the pork.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Build the sauce", "instruction": "Pour water into the pot and scrape up the browned bits. Add the remaining garlic, vinegar, soy sauce, bay leaves, pepper and sugar, and bring to a simmer.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Combine and simmer", "instruction": "Return the pork and eggplant to the pot, reduce heat, partially cover, and simmer until the eggplant is tender and the sauce reduced by half.", "timer_seconds": 1350, "background": true}, {"step": 7, "label": "Serve", "instruction": "Season to taste, top with garlic chips, and serve with white rice.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=pKXACYjwMns"}, {"id": "53074", "name": "Grilled eggplant with coconut milk", "category": "Vegetarian", "area": "Filipino", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/bopa2i1683209167.jpg", "local_image": "53074.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "6"}, {"ingredient": "Coconut Milk", "measure": "1 can"}, {"ingredient": "Lemon Juice", "measure": "1 tbs"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Red Pepper Flakes", "measure": "To taste"}, {"ingredient": "Onions", "measure": "4 Sticks"}], "instructions": ".  Prepare the eggplants for grilling by pricking them all over with a fork.  This is so it won’t burst during the grilling process as the natural water in it heats up.\r\n2.  Grill the eggplants, turning them over frequently to ensure even cooking.  Grill until the skins are dark brown, even black and the eggplant is soft when you touch it.\r\n3.  Soak the grilled eggplant in a bowl of water to cool it down.  Peel the skin off the eggplant.  Place the whole eggplants in a shallow dish (my mom actually cuts the eggplant into small, bite-sized pieces).\r\n 4.  In a small mixing bowl, mix together the coconut milk or cream, lemon powder, salt and hot pepper.  Mix until the lemon powder and salt dissolve.  Taste, then adjust the amount of lemon powder, salt and hot pepper to your liking.  Pour the mixture over the eggplant.  Sprinkle the green onions over the eggplant and coconut milk.  Stir gently to combine. \r\n", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 58, "prep_minutes_source": "estimated", "kcal": 1361, "protein_g": 48.5, "carbs_g": 28.3, "fat_g": 126.1, "total_kcal": 1361, "total_protein_g": 48.5, "total_carbs_g": 28.3, "total_fat_g": 126.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the eggplants", "instruction": "Prick the eggplants all over with a fork so they don't burst.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Grill", "instruction": "Grill the eggplants, turning frequently, until the skins are dark and the eggplant is soft.", "timer_seconds": 900, "background": false}, {"step": 3, "label": "Cool and peel", "instruction": "Soak the grilled eggplants in water to cool, then peel off the skin.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Make the dressing", "instruction": "Mix the coconut milk, lemon powder, salt and hot pepper until dissolved, adjusting to taste.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Combine and serve", "instruction": "Pour the coconut mixture over the eggplants, sprinkle with green onions, and stir gently to combine.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ourC5IhljB4"}, {"id": "53075", "name": "Tortang Talong", "category": "Vegetarian", "area": "Filipino", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/va668f1683209318.jpg", "local_image": "53075.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "4"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "4 tsp"}], "instructions": "0.\tGrill the eggplant until the color of skin turns almost black\r\n1.\tLet the eggplant cool for a while then peel off the skin. Set aside.\r\n2.\tCrack the eggs and place in a bowl\r\n3.\tAdd salt and beat\r\n4.\tPlace the eggplant on a flat surface and flatten using a fork.\r\n5.\tDip the flattened eggplant in the beaten egg mixture\r\n6.\tHeat the pan and pour the cooking oil\r\n7.\tFry the eggplant (that was dipped in the beaten mixture). Make sure that both sides are cooked. Frying time will take you about 3 to 4 minutes per side on medium heat. \r\n", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 592, "protein_g": 39.0, "carbs_g": 3.3, "fat_g": 48.4, "total_kcal": 592, "total_protein_g": 39.0, "total_carbs_g": 3.3, "total_fat_g": 48.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Grill the eggplant", "instruction": "Grill the eggplant until the skin turns almost black.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Peel", "instruction": "Let the eggplant cool, then peel off the skin.", "timer_seconds": 300, "background": true}, {"step": 3, "label": "Make the egg wash", "instruction": "Crack the eggs into a bowl, add salt, and beat.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Flatten and dip", "instruction": "Flatten the eggplant on a flat surface using a fork, then dip in the beaten egg mixture.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fry", "instruction": "Heat oil in a pan and fry the egg-dipped eggplant on both sides until cooked.", "timer_seconds": 420, "background": false}], "video": "https://www.youtube.com/watch?v=eLl8ekOu1MM"}, {"id": "53076", "name": "Bread omelette", "category": "Breakfast", "area": "India", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/hqaejl1695738653.jpg", "local_image": "53076.jpg", "ingredients": [{"ingredient": "Bread", "measure": "2"}, {"ingredient": "Egg", "measure": "2"}, {"ingredient": "Salt", "measure": "0.5"}], "instructions": "Make and enjoy", "equipment_tags": [], "portions": 2, "prep_minutes": 13, "prep_minutes_source": "estimated", "kcal": 204, "protein_g": 11.0, "carbs_g": 25.1, "fat_g": 6.6, "total_kcal": 408, "total_protein_g": 22.0, "total_carbs_g": 50.1, "total_fat_g": 13.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the omelette", "instruction": "Beat the eggs with salt, cook into an omelette, and layer with bread. Make and enjoy.", "timer_seconds": 300, "background": false}], "video": null}, {"id": "53077", "name": "Cabbage Soup (Shchi)", "category": "Vegetarian", "area": "Russian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/60oc3k1699009846.jpg", "local_image": "53077.jpg", "ingredients": [{"ingredient": "Unsalted Butter", "measure": "3 tbs"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Cabbage", "measure": "1 medium"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "Celery", "measure": "1"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Vegetable Stock", "measure": "8 cups"}, {"ingredient": "Potatoes", "measure": "2 large"}, {"ingredient": "Tomatoes", "measure": "2 large"}, {"ingredient": "Sour Cream", "measure": "Garnish"}, {"ingredient": "Dill", "measure": "Garnish"}], "instructions": "Add the butter to a large Dutch oven or other heavy-duty pot over medium heat. When the butter has melted, add the onion and sauté until translucent.\r\nAdd the cabbage, carrot, and celery. Sauté until the vegetables begin to soften, stirring frequently, about 3 minutes.\r\nAdd the bay leaf and vegetable stock and bring to a boil over high heat. Reduce the heat to low and simmer, covered, until the vegetables are crisp-tender, about 15 minutes.\r\nAdd the potatoes and bring it back to a boil over high heat. Reduce the heat to low and simmer, covered, until the potatoes are tender, about 10 minutes.\r\nAdd the tomatoes (or undrained canned tomatoes) and bring the soup back to a boil over high heat. Reduce the heat to low and simmer, uncovered, for 5 minutes. Season to taste with salt and pepper.\r\nemove and discard the bay leaf from the pot.\r\nServe topped with fresh sour cream and fresh dill.", "equipment_tags": [], "portions": 6, "prep_minutes": 33, "prep_minutes_source": "explicit", "kcal": 144, "protein_g": 3.9, "carbs_g": 17.2, "fat_g": 7.3, "total_kcal": 866, "total_protein_g": 23.1, "total_carbs_g": 103.4, "total_fat_g": 44.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Melt the butter in a large pot over medium heat, add the onion, and sauté until translucent.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Add the vegetables", "instruction": "Add the cabbage, carrot and celery, and sauté, stirring frequently, until beginning to soften.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Simmer the base", "instruction": "Add the bay leaf and stock, bring to a boil, then reduce heat and simmer, covered, until the vegetables are crisp-tender.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Add the potatoes", "instruction": "Add the potatoes, bring back to a boil, then reduce and simmer, covered, until tender.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Add the tomatoes", "instruction": "Add the tomatoes, bring back to a boil, then simmer uncovered. Season to taste.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Serve", "instruction": "Discard the bay leaf and serve topped with sour cream and fresh dill.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=lTjlbqGc_Y8"}, {"id": "53078", "name": "Beetroot Soup (Borscht)", "category": "Vegetarian", "area": "Ukrainian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/zadvgb1699012544.jpg", "local_image": "53078.jpg", "ingredients": [{"ingredient": "Beetroot", "measure": "3"}, {"ingredient": "Olive Oil", "measure": "4 tbs"}, {"ingredient": "Chicken Stock Cube", "measure": "1"}, {"ingredient": "Water", "measure": "6 cups"}, {"ingredient": "Potatoes", "measure": "3"}, {"ingredient": "Cannellini Beans", "measure": "1 can"}, {"ingredient": "Dill", "measure": "Garnish"}], "instructions": "Chop the beetroot, add water and stock cube and cook for 15mins. Add the other ingredients and boil until soft. Finally add the beans and cook for 5mins. Serve in the soup pot.", "equipment_tags": [], "portions": 5, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 294, "protein_g": 9.7, "carbs_g": 39.1, "fat_g": 11.7, "total_kcal": 1469, "total_protein_g": 48.7, "total_carbs_g": 195.3, "total_fat_g": 58.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the beetroot", "instruction": "Chop the beetroot, add water and stock cube, and cook.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Add the rest and simmer", "instruction": "Add the remaining ingredients except the beans and boil until soft.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Finish and serve", "instruction": "Add the beans and cook a few minutes more, then serve in the soup pot.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=6CXgPVw_-0g"}, {"id": "53079", "name": "Fish Soup (Ukha)", "category": "Seafood", "area": "Russian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/7n8su21699013057.jpg", "local_image": "53079.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Carrots", "measure": "2 medium"}, {"ingredient": "Fish Stock", "measure": "3 cups"}, {"ingredient": "Water", "measure": "3 cups"}, {"ingredient": "Potatoes", "measure": "4 large"}, {"ingredient": "Bay Leaf", "measure": "3"}, {"ingredient": "Cod", "measure": "1"}, {"ingredient": "Salmon", "measure": "1"}], "instructions": "In a medium pot, heat the olive oil over medium-high heat. Add the onions and cook, stirring occasionally until the onions start to caramelize. Add the carrots and cook until the carrots start to soften, about 4 more minutes.\r\nAdd the stock, water, potatoes, bay leaves, and black peppercorns. Season with salt and bring to a boil. Reduce heat, cover and cook for 10 minutes. Add the millet and cook for 15 more minutes until millet and potatoes are cooked.\r\nGently add the fish cubes. Stir and bring the soup to a simmer. The fish will cook through very fast, so make sure to not overcook them. They are done when the flesh is opaque and flakes easily.\r\nGarnish the soup with chopped fresh dill or parsley before serving.", "equipment_tags": [], "portions": 5, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 209, "protein_g": 7.7, "carbs_g": 28.7, "fat_g": 7.3, "total_kcal": 1045, "total_protein_g": 38.6, "total_carbs_g": 143.5, "total_fat_g": 36.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onions and carrots", "instruction": "Heat the olive oil over medium-high heat. Add the onions and cook, stirring occasionally, until they start to caramelize. Add the carrots and cook until they begin to soften, about 4 more minutes.", "timer_seconds": 240, "background": false}, {"step": 2, "label": "Simmer the broth", "instruction": "Add the stock, water, potatoes, bay leaves and peppercorns. Season with salt, bring to a boil, then reduce the heat, cover and cook for 10 minutes.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Cook the millet", "instruction": "Add the millet and cook for 15 more minutes, until the millet and potatoes are cooked through.", "timer_seconds": 900, "background": true}, {"step": 4, "label": "Add the fish", "instruction": "Gently add the fish cubes, stir, and bring back to a simmer. Fish cooks fast, so watch closely — it's done once the flesh is opaque and flakes easily.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Garnish and serve", "instruction": "Garnish the soup with chopped fresh dill or parsley before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=cS3Yn-y5uVg"}, {"id": "53080", "name": "Blini Pancakes", "category": "Side", "area": "Russian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0206h11699013358.jpg", "local_image": "53080.jpg", "ingredients": [{"ingredient": "Buckwheat", "measure": "1/2 cup"}, {"ingredient": "Flour", "measure": "2/3 Cup"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Yeast", "measure": "1 tsp"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Egg", "measure": "1 Seperated"}], "instructions": "In a large bowl, whisk together 1/2 cup buckwheat flour, 2/3 cup all-purpose flour, 1/2 teaspoon salt, and 1 teaspoon yeast.\r\n\r\nMake a well in the center and pour in 1 cup warm milk, whisking until the batter is smooth.\r\n\r\nCover the bowl and let the batter rise until doubled, about 1 hour.\r\n\r\nEnrich and Rest the Batter\r\nStir 2 tablespoons melted butter and 1 egg yolk into the batter.\r\n\r\nIn a separate bowl, whisk 1 egg white until stiff, but not dry.\r\n\r\nFold the whisked egg white into the batter.\r\n\r\nCover the bowl and let the batter stand 20 minutes.\r\n\r\nPan-Fry the Blini\r\nHeat butter in a large nonstick skillet over medium heat.\r\n\r\nDrop quarter-sized dollops of batter into the pan, being careful not to overcrowd the pan. Cook for about 1 minute or until bubbles form.\r\n\r\nTurn and cook for about 30 additional seconds.\r\n\r\nRemove the finished blini onto a plate and cover them with a clean kitchen towel to keep warm. Add more butter to the pan and repeat the frying process with the remaining batter.", "equipment_tags": [], "portions": 3, "prep_minutes": 81, "prep_minutes_source": "explicit", "kcal": 387, "protein_g": 13.6, "carbs_g": 54.8, "fat_g": 13.9, "total_kcal": 1161, "total_protein_g": 40.8, "total_carbs_g": 164.4, "total_fat_g": 41.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix the batter", "instruction": "Whisk together the buckwheat flour, all-purpose flour, salt and yeast in a large bowl. Make a well in the centre and pour in the warm milk, whisking until smooth.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Let the batter rise", "instruction": "Cover the bowl and let the batter rise until doubled, about 1 hour.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Enrich the batter", "instruction": "Stir the melted butter and egg yolk into the batter. In a separate bowl, whisk the egg white until stiff but not dry, then fold it into the batter.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Rest the batter", "instruction": "Cover the bowl and let the batter stand for 20 minutes.", "timer_seconds": 1200, "background": true}, {"step": 5, "label": "Fry the blini", "instruction": "Heat butter in a large nonstick skillet over medium heat. Drop quarter-sized dollops of batter into the pan, not overcrowding it, and cook for about 1 minute until bubbles form.", "timer_seconds": 60, "background": false}, {"step": 6, "label": "Flip and finish", "instruction": "Turn and cook for about 30 more seconds. Keep finished blini warm under a clean kitchen towel, adding more butter and repeating with the remaining batter.", "timer_seconds": 30, "background": false}], "video": "https://www.youtube.com/watch?v=GsB8ZI5vREA"}, {"id": "53081", "name": "Potato Salad (Olivier Salad)", "category": "Vegetarian", "area": "Russian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ebvuir1699013665.jpg", "local_image": "53081.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "4"}, {"ingredient": "Carrots", "measure": "3"}, {"ingredient": "Salt", "measure": "1 tbs"}, {"ingredient": "White Wine Vinegar", "measure": "1/2 tbs"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Sausages", "measure": "7 oz"}, {"ingredient": "Dill", "measure": "4 oz"}, {"ingredient": "Peas", "measure": "1 can"}, {"ingredient": "Onions", "measure": "4"}, {"ingredient": "Mayonnaise", "measure": "1 cup"}], "instructions": "Cut the potatoes and carrots into small uniform cubes.\r\nPlace them in a large pot and fill with water.\r\nAdd salt and vinegar. Bring it to a boil over medium high heat, and then reduce the heat to medium and continue to cook until the potatoes are cooked through, about 15 minutes. Drain the potatoes and let it cool to room temperature.\r\nMeanwhile, cut the sausage and pickles into small cubes, and chop the green onions.\r\nCut the hard-boiled eggs into small cubes as well.\r\nIf using fresh dill, chop them as well.\r\nIn a large bowl, combine potatoes, carrots, sausage, pickles, peas and green onions.\r\nAdd mayo and dill and mix until well combined.\r\nSalt and pepper to taste. Cover with a plastic wrap and refrigerate for at least 1 hour before serving.", "equipment_tags": [], "portions": 12, "prep_minutes": 75, "prep_minutes_source": "explicit", "kcal": 305, "protein_g": 8.3, "carbs_g": 20.9, "fat_g": 21.3, "total_kcal": 3661, "total_protein_g": 99.8, "total_carbs_g": 250.2, "total_fat_g": 255.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil the potatoes and carrots", "instruction": "Cube the potatoes and carrots and place in a large pot with water, salt and vinegar. Bring to a boil, then reduce to medium and cook until the potatoes are cooked through, about 15 minutes.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Cool the potatoes", "instruction": "Drain the potatoes and carrots and let them cool to room temperature.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Prep the rest", "instruction": "Meanwhile, cube the sausage and pickles, chop the green onions, cube the hard-boiled eggs, and chop the dill if using.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Combine", "instruction": "In a large bowl, combine the potatoes, carrots, sausage, pickles, peas and green onions.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Dress and chill", "instruction": "Add the mayo and dill and mix until well combined. Season with salt and pepper, cover, and refrigerate for at least 1 hour before serving.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=RnsWwHcpKiY"}, {"id": "53082", "name": "Strawberries Romanoff", "category": "Dessert", "area": "Russian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/oe8rg51699014028.jpg", "local_image": "53082.jpg", "ingredients": [{"ingredient": "Strawberries", "measure": "2 pint"}, {"ingredient": "Sugar", "measure": "4 tbs"}, {"ingredient": "Grand Marnier", "measure": "4 tbs"}, {"ingredient": "Cream", "measure": "1 cup"}, {"ingredient": "Sour Cream", "measure": "1/4 cup"}], "instructions": "In a medium bowl, combine hulled and quartered strawberries, 4 Tbsp sugar and 4 Tbsp liqueur, stir to combine then cover and refrigerate at least 1 hour and up to 2 hours, stirring once or twice.\r\n\r\nTwo photos of cut strawberries in a bowl with one having sugar being added to the bowl Two photos of cut up strawberries for Strawberry Romanoff \r\n\r\nJust before serving, in a large mixing bowl, combine 1 cup cold heavy cream and 1/4 cup powdered sugar, and beat with an electric mixer until stiff peaks form. Using a spatula, fold in 1/4 cup sour cream just until well blended.\r\n\r\nTo serve, stir strawberries then divide between 6 serving glasses or bowls. You can spoon a little syrup over the berries if you like. You can also use this syrup to soak a cake. Spoon cream over strawberries, dividing evenly. You can also use an ice cream scoop with trigger release for a nice rounded puff of cream. Serve right away or chill and enjoy within 2 hours of assembly.\r\n\r\n", "equipment_tags": [], "portions": 10, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 132, "protein_g": 1.6, "carbs_g": 16.6, "fat_g": 6.0, "total_kcal": 1316, "total_protein_g": 15.9, "total_carbs_g": 166.0, "total_fat_g": 60.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Macerate the strawberries", "instruction": "Combine the hulled, quartered strawberries with the sugar and liqueur. Cover and refrigerate for at least 1 hour and up to 2, stirring once or twice.", "timer_seconds": 7200, "background": true}, {"step": 2, "label": "Whip the cream", "instruction": "Just before serving, beat the cold heavy cream and powdered sugar with an electric mixer until stiff peaks form.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fold in the sour cream", "instruction": "Using a spatula, fold in the sour cream just until well blended.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Assemble and serve", "instruction": "Stir the strawberries, then divide between serving glasses. Spoon over the cream, and serve right away or chill and enjoy within 2 hours.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=ybWHc4Vi-xU"}, {"id": "53083", "name": "Lamb Pilaf (Plov)", "category": "Lamb", "area": "Russian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/kos9av1699014767.jpg", "local_image": "53083.jpg", "ingredients": [{"ingredient": "Lamb", "measure": "50g"}, {"ingredient": "Prunes", "measure": "120g"}, {"ingredient": "Lemon Juice", "measure": "1 tbs"}, {"ingredient": "Butter", "measure": "2 tbs"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Lamb", "measure": "450g"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Vegetable Stock", "measure": "600ml"}, {"ingredient": "Rice", "measure": "2 cups"}, {"ingredient": "Saffron", "measure": "Pinch"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "Place the raisins and prunes into a small bowl and pour over enough water to cover. Add lemon juice and let soak for at least 1 hour. Drain. Roughly chop the prunes.\r\n\r\nMeanwhile, heat the butter in a large pan, add the onion, and cook for 5 minutes. Add cubed lamb, ground lamb, and crushed garlic cloves. Fry for 5 minutes, stirring constantly until browned.\r\n\r\nPour 2/3 cup (150 milliliters) of stock into the pan. Bring to a boil, then lower the heat, cover, and simmer for 1 hour, or until the lamb is tender.\r\n\r\nAdd the remaining stock and bring to a boil. Add rinsed long-grain white rice and a large pinch of saffron. Stir, then cover, and simmer for 15 minutes, or until the rice is tender.\r\n\r\nAdd the drained raisins, drained chopped prunes, and salt and pepper to taste. Heat through for a few minutes, then turn out onto a warmed serving dish and garnish with sprigs of flat-leaf parsley.", "equipment_tags": [], "portions": 4, "prep_minutes": 145, "prep_minutes_source": "explicit", "kcal": 888, "protein_g": 40.6, "carbs_g": 105.7, "fat_g": 33.2, "total_kcal": 3552, "total_protein_g": 162.5, "total_carbs_g": 422.9, "total_fat_g": 132.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the dried fruit", "instruction": "Place the raisins and prunes in a small bowl, cover with water, add the lemon juice, and let soak for at least 1 hour. Drain, then roughly chop the prunes.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Brown the lamb", "instruction": "Meanwhile, heat the butter in a large pan, add the onion, and cook for 5 minutes. Add the cubed lamb, ground lamb and crushed garlic, and fry for 5 minutes, stirring constantly, until browned.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the lamb", "instruction": "Pour in the stock, bring to a boil, then lower the heat, cover, and simmer for 1 hour, or until the lamb is tender.", "timer_seconds": 3600, "background": true}, {"step": 4, "label": "Cook the rice", "instruction": "Add the remaining stock and bring to a boil. Add the rinsed rice and saffron, stir, cover, and simmer for 15 minutes, or until the rice is tender.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Finish and serve", "instruction": "Add the drained raisins and prunes, season with salt and pepper, heat through for a few minutes, then garnish with parsley to serve.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=rllQsUw1hFQ"}, {"id": "53086", "name": "Migas", "category": "Miscellaneous", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xd9aj21740432378.jpg", "local_image": "53086.jpg", "ingredients": [{"ingredient": "Bread", "measure": "1 large"}, {"ingredient": "Olive Oil", "measure": "1 1/2 L"}, {"ingredient": "Garlic", "measure": "Half"}, {"ingredient": "Pork", "measure": "1 Handfull"}], "instructions": "Crumble the bread into small pieces. Sprinkle with cold water, cover with a damp cloth and leave for 30 minutes.\r\nHeat 2 tsp of olive oil in a deep pan. Add the garlic cloves separated, skins on; just make a small cut with a knife to open them and keep frying for 5 minutes. Set the garlic aside.\r\nIn the same oil, where we fried everything, simmer the bread, stirring constantly for 15 minutes and add a grinding of black pepper.\r\nAdd the garlic, continue stirring for about 20 minutes. It will be ready when the bread is soft and golden.", "equipment_tags": [], "portions": 1, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 1226, "protein_g": 16.1, "carbs_g": 32.8, "fat_g": 116.1, "total_kcal": 1226, "total_protein_g": 16.1, "total_carbs_g": 32.8, "total_fat_g": 116.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soak the bread", "instruction": "Crumble the bread into small pieces, sprinkle with cold water, cover with a damp cloth, and leave for 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Fry the garlic", "instruction": "Heat the oil in a deep pan. Add the garlic cloves, skins on and cut open, and fry for 5 minutes. Set the garlic aside.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the bread", "instruction": "In the same oil, cook the bread, stirring constantly, for 15 minutes, with a grinding of black pepper.", "timer_seconds": 900, "background": false}, {"step": 4, "label": "Finish", "instruction": "Add the garlic back in and continue stirring for about 20 minutes, until the bread is soft and golden.", "timer_seconds": 1200, "background": false}], "video": "https://www.youtube.com/watch?v=GSvFVBpqMKI"}, {"id": "53089", "name": "Syrian Bread", "category": "Miscellaneous", "area": "Syrian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/54xzk31760524666.jpg", "local_image": "53089.jpg", "ingredients": [{"ingredient": "Water", "measure": "1 and 1/8 cup"}, {"ingredient": "Vegetable Oil", "measure": "2 tblsp"}, {"ingredient": "Sugar", "measure": "1/2 teaspoon"}, {"ingredient": "Salt", "measure": "1 1/2 tsp"}, {"ingredient": "Flour", "measure": "3 Cups"}, {"ingredient": "Yeast", "measure": "1 1/2 tsp"}], "instructions": "Place ingredients in the pan of the bread machine in the order recommended by the manufacturer. Select Dough cycle; press Start.\r\n\r\nWhen the Dough cycle is almost complete, preheat the oven to 475 degrees F (245 degrees C).\r\n\r\nTurn dough out onto a lightly floured surface. Divide into eight equal pieces and form into rounds. Cover the rounds with a damp cloth and let rest.\r\n\r\nRoll dough into thin flat circles, about 8 inches in diameter. Cook two at a time on preheated baking sheets or a baking stone until puffed up and golden brown, about 5 minutes. Repeat for remaining loaves.", "equipment_tags": [], "portions": 5, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 333, "protein_g": 8.2, "carbs_g": 59.0, "fat_g": 6.4, "total_kcal": 1666, "total_protein_g": 41.2, "total_carbs_g": 295.2, "total_fat_g": 32.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Start the dough", "instruction": "Place the ingredients in the bread machine pan in the order recommended by the manufacturer. Select the Dough cycle and press Start.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Preheat the oven", "instruction": "When the Dough cycle is almost complete, preheat the oven to 475°F (245°C).", "timer_seconds": null, "background": false}, {"step": 3, "label": "Shape the dough", "instruction": "Turn the dough onto a lightly floured surface, divide into eight equal pieces, and form into rounds. Cover with a damp cloth and let rest.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Roll and bake", "instruction": "Roll the dough into thin, 8-inch circles. Cook two at a time on preheated baking sheets or a baking stone until puffed and golden brown, about 5 minutes. Repeat for the remaining loaves.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=Pjzj0dws0Yk"}, {"id": "53091", "name": "Falafel Pita Sandwich with Tahini Sauce", "category": "Vegetarian", "area": "Syrian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ae6clc1760524712.jpg", "local_image": "53091.jpg", "ingredients": [{"ingredient": "Falafel", "measure": "12"}, {"ingredient": "Tahini", "measure": "1/4 cup"}, {"ingredient": "Water", "measure": "1/4 cup"}, {"ingredient": "Lemon Juice", "measure": "2 tablespoons"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Paprika", "measure": "1/4 tsp"}, {"ingredient": "Pita Bread", "measure": "6"}, {"ingredient": "Lettuce", "measure": "1"}, {"ingredient": "Tomato", "measure": "1"}, {"ingredient": "Cucumber", "measure": "1/2"}, {"ingredient": "Dill Pickles", "measure": "1"}, {"ingredient": "Red Onions", "measure": "1/4"}, {"ingredient": "Harissa Spice", "measure": "3 tsp"}], "instructions": "Preheat the oven to 450 degrees F (230 degrees C). Place falafel on a baking sheet.\r\n\r\nBake in the preheated oven until heated through, 8 to 10 minutes.\r\n\r\nWhile falafel bake, whisk tahini, water, lemon juice, garlic, and paprika together in a bowl.\r\n\r\nCut about 1 inch from the top of each pita to form a pocket. Add 2 falafel to each pita with equal amounts lettuce, tomato, cucumber, pickle, and red onion. Drizzle each with about 1 tablespoon tahini sauce and some harissa.", "equipment_tags": [], "portions": 12, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 271, "protein_g": 10.2, "carbs_g": 30.8, "fat_g": 12.6, "total_kcal": 3247, "total_protein_g": 122.0, "total_carbs_g": 370.1, "total_fat_g": 151.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Bake the falafel", "instruction": "Preheat the oven to 450°F (230°C). Place the falafel on a baking sheet and bake until heated through, 8 to 10 minutes.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Make the tahini sauce", "instruction": "While the falafel bakes, whisk the tahini, water, lemon juice, garlic and paprika together in a bowl.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Assemble the sandwiches", "instruction": "Cut about an inch from the top of each pita to form a pocket. Fill with falafel, lettuce, tomato, cucumber, pickle and red onion, then drizzle with the tahini sauce and some harissa.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=wt8nApxP5fE"}, {"id": "53092", "name": "Fasoliyyeh Bi Z-Zayt (Syrian Green Beans with Olive Oil)", "category": "Vegan", "area": "Syrian", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/21yc5s1760524759.jpg", "local_image": "53092.jpg", "ingredients": [{"ingredient": "Green Beans", "measure": "16 ounces"}, {"ingredient": "Olive Oil", "measure": "1/4 cup"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Cilantro", "measure": "1/4 cup"}], "instructions": "Place the green beans into a large pot, and drizzle with olive oil. Season with salt to taste, and put the lid on the pot. Cook over medium-high heat, stirring occasionally, until beans are cooked to your desired doneness. Syrians like it cooked until the green beans are turning brownish in color. The idea is not to saute them, but to let them steam in the moisture released by the ice crystals.\r\n\r\nAdd cilantro and garlic to the beans, and continue to cook just until the cilantro has started to wilt. Eat as a main course by scooping up with warm pita bread or serve as a side dish.", "equipment_tags": [], "portions": 1, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 647, "protein_g": 9.6, "carbs_g": 35.0, "fat_g": 56.4, "total_kcal": 647, "total_protein_g": 9.6, "total_carbs_g": 35.0, "total_fat_g": 56.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the beans", "instruction": "Place the green beans in a large pot, drizzle with olive oil, and season with salt. Cover and cook over medium-high heat, stirring occasionally, until cooked to your desired doneness.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Finish with garlic", "instruction": "Add the cilantro and garlic, and cook just until the cilantro starts to wilt. Serve as a main scooped up with warm pita, or as a side dish.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=_EadiEPxQI0"}, {"id": "53093", "name": "Syrian Spaghetti", "category": "Pasta", "area": "Syrian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5fu4ew1760524857.jpg", "local_image": "53093.jpg", "ingredients": [{"ingredient": "Spaghetti", "measure": "16 ounces"}, {"ingredient": "Tomato Sauce", "measure": "8 ounces"}, {"ingredient": "Tomato Puree", "measure": "6 oz"}, {"ingredient": "Cinnamon", "measure": "1 teaspoon"}, {"ingredient": "Vegetable Oil", "measure": "1/4 cup"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Pepper", "measure": "Dash"}], "instructions": "Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13 inch baking dish.\r\n\r\nBring a large pot of lightly salted water to a boil. Add spaghetti and cook for 8 to 10 minutes or until al dente; drain and stir in tomato sauce, tomato paste, cinnamon, oil, salt and pepper. Transfer to prepared dish.\r\n\r\nBake in preheated oven for 1 hour, or until top is crunchy.", "equipment_tags": [], "portions": 6, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 394, "protein_g": 11.4, "carbs_g": 64.3, "fat_g": 10.6, "total_kcal": 2366, "total_protein_g": 68.6, "total_carbs_g": 386.1, "total_fat_g": 63.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Preheat and prep", "instruction": "Preheat the oven to 350°F (175°C) and grease a 9x13-inch baking dish.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Boil the spaghetti", "instruction": "Bring a large pot of lightly salted water to a boil. Add the spaghetti and cook for 8 to 10 minutes, until al dente, then drain.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Mix and transfer", "instruction": "Stir the tomato sauce, tomato paste, cinnamon, oil, salt and pepper into the drained spaghetti, then transfer to the prepared dish.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Bake in the preheated oven for 1 hour, or until the top is crunchy.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=MGmaX9Uv_Gs"}, {"id": "53094", "name": "Baba Ghanoush", "category": "Side", "area": "Syrian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/dlmh401760524897.jpg", "local_image": "53094.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "4 large"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Kosher Salt", "measure": "2 teaspoons"}, {"ingredient": "Lemon", "measure": "1"}, {"ingredient": "Tahini", "measure": "3  tablespoons"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Greek Yogurt", "measure": "2 tablespoons"}, {"ingredient": "Cayenne Pepper", "measure": "1 pinch"}, {"ingredient": "Mint", "measure": "1 Leaf"}, {"ingredient": "Parsley", "measure": "2 tablespoons"}], "instructions": "Preheat an outdoor grill for medium-high heat and lightly oil the grate. Prick the surface of the skin of eggplants several times with the tip of a knife.\r\n\r\nPlace eggplants directly on grill. Turn frequently with tongs while skin chars. Cook until eggplants have collapsed and are very soft, 25 to 30 minutes. Transfer to a bowl and cover tightly with aluminum foil and allow to cool, about 15 minutes.\r\n\r\nWhen eggplants are cool enough to handle, split them in half and scrape flesh into a colander placed over a bowl. Drain 5 or 10 minutes.\r\n\r\nTransfer eggplant to mixing bowl. Add crushed garlic and salt; mash until creamy but with a little texture, about 5 minutes. Whisk in lemon juice, tahini, olive oil, and cayenne pepper. Stir in yogurt.\r\n\r\nCover bowl with plastic wrap and refrigerate until completely chilled. Stir in mint and parsley, and taste to adjust seasonings before serving.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 494, "protein_g": 19.2, "carbs_g": 11.3, "fat_g": 43.9, "total_kcal": 988, "total_protein_g": 38.4, "total_carbs_g": 22.6, "total_fat_g": 87.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Char the eggplants", "instruction": "Preheat an outdoor grill to medium-high and prick the skin of the eggplants a few times. Grill, turning frequently, until collapsed and very soft, 25 to 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Cool and steam", "instruction": "Transfer the eggplants to a bowl, cover tightly with foil, and let cool for about 15 minutes.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Scoop and drain", "instruction": "Once cool enough to handle, split the eggplants in half and scrape the flesh into a colander set over a bowl. Drain for 5 to 10 minutes.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Mash with garlic", "instruction": "Transfer the eggplant to a mixing bowl, add the crushed garlic and salt, and mash until creamy but with a little texture, about 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Season", "instruction": "Whisk in the lemon juice, tahini, olive oil and cayenne pepper, then stir in the yogurt.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Chill and garnish", "instruction": "Cover and refrigerate until completely chilled. Stir in the mint and parsley and adjust the seasoning before serving.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/shorts/Mz-ZVfOA_ig"}, {"id": "53095", "name": "Syrian Rice with Meat", "category": "Miscellaneous", "area": "Syrian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/zg2b9l1760524940.jpg", "local_image": "53095.jpg", "ingredients": [{"ingredient": "Butter", "measure": "1/4 cup"}, {"ingredient": "Ground Beef", "measure": "2 Pounds"}, {"ingredient": "Salt", "measure": "2 teaspoons"}, {"ingredient": "Allspice", "measure": "1/2 teaspoon"}, {"ingredient": "Cinnamon", "measure": "1/2 teaspoon"}, {"ingredient": "Black Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Chicken Stock", "measure": "5 Cups"}, {"ingredient": "Rice", "measure": "2 cups"}, {"ingredient": "Butter", "measure": "2 tablespoons"}, {"ingredient": "Pine Nuts", "measure": "1/2 cup"}], "instructions": "Heat 1/4 cup butter in a large saucepan over medium-high heat. Add ground beef and season with salt, allspice, cinnamon, and black pepper. Cook and stir until beef is browned and crumbly, 7 to 10 minutes.\r\n\r\nStir chicken broth and rice into beef in the saucepan; bring to a boil. Reduce heat to low, cover, and cook until liquid is absorbed, about 20 minutes.\r\n\r\nMeanwhile, melt 2 tablespoons butter in a small skillet over medium heat. Cook and stir pine nuts in hot butter until lightly browned, 3 to 5 minutes.\r\n\r\nMix pine nuts into beef-rice mixture before serving.", "equipment_tags": [], "portions": 5, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 1060, "protein_g": 41.5, "carbs_g": 71.2, "fat_g": 67.5, "total_kcal": 5300, "total_protein_g": 207.3, "total_carbs_g": 355.9, "total_fat_g": 337.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "Heat the butter in a large saucepan over medium-high heat. Add the ground beef, season with salt, allspice, cinnamon and black pepper, and cook, stirring, until browned and crumbly, 7 to 10 minutes.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Cook the rice", "instruction": "Stir the chicken broth and rice into the beef and bring to a boil. Reduce the heat to low, cover, and cook until the liquid is absorbed, about 20 minutes.", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Toast the pine nuts", "instruction": "Meanwhile, melt the remaining butter in a small skillet and cook the pine nuts, stirring, until lightly browned, 3 to 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Finish", "instruction": "Mix the pine nuts into the beef-rice mixture before serving.", "timer_seconds": null, "background": false}], "video": null}, {"id": "53096", "name": "Corned Beef Hash", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/vz94r81760534692.jpg", "local_image": "53096.jpg", "ingredients": [{"ingredient": "Unsalted Butter", "measure": "3  tablespoons"}, {"ingredient": "Onion", "measure": "1 medium chopped"}, {"ingredient": "Corned Beef", "measure": "3 Cups"}, {"ingredient": "Potatoes", "measure": "3 chopped"}, {"ingredient": "Kosher Salt", "measure": "Dash"}, {"ingredient": "Black Pepper", "measure": "Dash"}, {"ingredient": "Freshly Chopped Parsley", "measure": "Chopped"}], "instructions": "Sauté the onions:\r\nHeat butter in a large skillet (preferably cast iron) on medium heat. Add the onion and cook a few minutes, until translucent.\r\n\r\nAdd the potatoes and corned beef:\r\nMix in the chopped corned beef and potatoes. Spread out evenly over the pan. Increase the heat to high or medium high and press down on the mixture with a metal spatula.\r\n\r\n\r\nCook until browned and then flip:\r\nDo not stir the potatoes and corned beef, but let them brown. If you hear them sizzling, this is good.\r\n\r\nUse a metal spatula to peek underneath and see if they are browning. If nicely browned, use the spatula to flip sections over in the pan so that they brown on the other side. Press down again with the spatula.\r\n\r\nIf there is too much sticking, you can add a little more butter to the pan. Continue to cook in this manner until the potatoes and the corned beef are nicely browned.\r\n\r\nStir in the parsley and season:\r\nRemove from heat, stir in chopped parsley. Add plenty of freshly ground black pepper, and add salt to taste.", "equipment_tags": [], "portions": 3, "prep_minutes": 64, "prep_minutes_source": "estimated", "kcal": 685, "protein_g": 52.3, "carbs_g": 33.2, "fat_g": 38.4, "total_kcal": 2056, "total_protein_g": 156.8, "total_carbs_g": 99.5, "total_fat_g": 115.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Sauté the onions", "instruction": "Heat the butter in a large skillet over medium heat. Add the onion and cook for a few minutes until translucent.", "timer_seconds": 180, "background": false}, {"step": 2, "label": "Add the potatoes and corned beef", "instruction": "Mix in the chopped corned beef and potatoes, spread evenly over the pan, increase the heat to medium-high, and press down firmly with a metal spatula.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Brown, then flip", "instruction": "Let the mixture brown without stirring — a sizzling sound is a good sign. Peek underneath with the spatula, and once nicely browned, flip sections over to brown the other side, pressing down again. Add a little more butter if it sticks.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Finish", "instruction": "Remove from the heat, stir in the chopped parsley, and season with plenty of black pepper and salt to taste.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=SPr_UnCrYPg"}, {"id": "53097", "name": "Yorkshire Puddings", "category": "Miscellaneous", "area": "British", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/x5qz5k1761595900.jpg", "local_image": "53097.jpg", "ingredients": [{"ingredient": "Flour", "measure": "140g"}, {"ingredient": "Egg", "measure": "4"}, {"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "Sunflower Oil", "measure": "Drizzle"}], "instructions": "step 1\r\nHeat oven to 230C/fan 210C/gas 8.\r\n\r\nstep 2\r\nDrizzle a little sunflower oil evenly into two 4-hole Yorkshire pudding tins or two 12-hole non-stick muffin tins and place in the oven to heat through.\r\n\r\nstep 3\r\nTo make the batter, tip 140g plain flour into a bowl and beat in 4 eggs until smooth.\r\n\r\nstep 4\r\nGradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper.\r\n\r\nstep 5\r\nPour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes.\r\n\r\nstep 6\r\nPlace the tins back in the oven and leave undisturbed for 20-25 mins until the puddings have puffed up and browned.\r\n\r\nstep 7\r\nServe immediately. You can now cool them and freeze for up to 1 month.", "equipment_tags": [], "portions": 1, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 1183, "protein_g": 46.4, "carbs_g": 118.2, "fat_g": 58.0, "total_kcal": 1183, "total_protein_g": 46.4, "total_carbs_g": 118.2, "total_fat_g": 58.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Heat the oven", "instruction": "Heat the oven to 230°C/fan 210°C/gas 8.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Heat the tins", "instruction": "Drizzle a little sunflower oil evenly into the Yorkshire pudding or muffin tins and place them in the oven to heat through.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Make the batter", "instruction": "Tip the flour into a bowl and beat in the eggs until smooth.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Loosen the batter", "instruction": "Gradually add the milk, beating until completely lump-free. Season with salt and pepper.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Pour and bake", "instruction": "Pour the batter into a jug, carefully remove the hot tins from the oven, and evenly pour in the batter. Return to the oven and bake undisturbed for 20 to 25 minutes, until puffed up and browned.", "timer_seconds": 1500, "background": true}, {"step": 6, "label": "Serve", "instruction": "Serve immediately, or cool and freeze for up to a month.", "timer_seconds": null, "background": false}], "video": "https://www.bing.com/videos/riverview/relatedvideo?q=yorkshire+pudding+pecipe+youtune&&mid=8A37CC95703100D3C8E58A37CC95703100D3C8E5&mcid=757E2787DB13499281255AD4321A912C&FORM=VAMGZC"}, {"id": "53098", "name": "Cumberland Pie", "category": "Beef", "area": "British", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/pvfkz61761595976.jpg", "local_image": "53098.jpg", "ingredients": [{"ingredient": "Celery", "measure": "2"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "2 large"}, {"ingredient": "Bay Leaves", "measure": "5"}, {"ingredient": "Thyme", "measure": "3"}, {"ingredient": "Vegetable Oil", "measure": "2 tblsp"}, {"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Flour", "measure": "2 tablespoons"}, {"ingredient": "Tomato Puree", "measure": "2 tblsp"}, {"ingredient": "Worcestershire Sauce", "measure": "2 tablespoons"}, {"ingredient": "Beef Stock Cubes", "measure": "2"}, {"ingredient": "Feather blade beef", "measure": "800g"}, {"ingredient": "Potatoes", "measure": "800g"}, {"ingredient": "Mature Cheddar", "measure": "25g"}, {"ingredient": "Parmesan Cheese", "measure": "25g"}], "instructions": "step 1\r\nHeat oven to 160C/140C fan/gas 3. Soften the celery, onion, carrots, bay and 1 thyme sprig in a casserole with 1 tbsp oil and the butter for 10 mins. Stir in the flour, followed by the purée, Worcestershire sauce and stock cubes.\r\n\r\nstep 2\r\nGradually stir in 600ml hot water, then tip in the beef and bring to a gentle simmer. Cover and cook in the oven for 2 hrs 30 mins, then uncover and cook for 30 mins -1 hr more until the meat is really tender and sauce thickened.\r\n\r\nstep 3\r\nMeanwhile, cook potatoes in a pan of boiling water until they’re not done but about ¾ of the way there.\r\n\r\nstep 4\r\nTransfer meat to a baking dish. Slice spuds into 1cm thick rounds and gently toss with seasoning, the remaining oil and thyme leaves. Layer on the beef, scattering with the cheese as you layer. You can cover and chill the pie now for 1 day, or freeze for up to 3 months.\r\n\r\nstep 5\r\nIncrease oven to 200C/180C fan/gas 6 and bake for 30-40 mins until golden and crispy, and sauce bubbling if the dish went in cold. Serve with peas.", "equipment_tags": [], "portions": 5, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 647, "protein_g": 43.3, "carbs_g": 48.7, "fat_g": 31.8, "total_kcal": 3233, "total_protein_g": 216.3, "total_carbs_g": 243.4, "total_fat_g": 159.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Build the base", "instruction": "Heat the oven to 160°C/140°C fan/gas 3. Soften the celery, onion, carrots, bay and thyme sprig in a casserole with the oil and butter for 10 minutes. Stir in the flour, then the purée, Worcestershire sauce and stock cubes.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Simmer in the oven", "instruction": "Gradually stir in the hot water, add the beef, and bring to a gentle simmer. Cover and cook in the oven for 2 hours 30 minutes, then uncover and cook 30 minutes to 1 hour more, until the meat is tender and the sauce thickened.", "timer_seconds": 9000, "background": true}, {"step": 3, "label": "Parboil the potatoes", "instruction": "Meanwhile, cook the potatoes in a pan of boiling water until about three-quarters done.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Layer the pie", "instruction": "Transfer the meat to a baking dish. Slice the potatoes and toss with seasoning, the remaining oil and thyme leaves, then layer over the beef, scattering with cheese as you go. Can be chilled for a day or frozen for up to 3 months at this point.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Bake until golden", "instruction": "Increase the oven to 200°C/180°C fan/gas 6 and bake for 30 to 40 minutes, until golden and crispy and the sauce is bubbling. Serve with peas.", "timer_seconds": 2400, "background": true}], "video": "https://www.youtube.com/watch?v=r1lnsOTNjws"}, {"id": "53099", "name": "Aussie Burgers", "category": "Beef", "area": "Australian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/44bzep1761848278.jpg", "local_image": "53099.jpg", "ingredients": [{"ingredient": "Lean Minced Steak", "measure": "500g"}, {"ingredient": "Cooked Beetroot", "measure": "100g"}, {"ingredient": "Naan Bread", "measure": "2 small"}, {"ingredient": "Rocket", "measure": "50g"}, {"ingredient": "Soured cream and chive dip", "measure": "4 tablespoons"}], "instructions": "step 1\r\nMake the burgers: Tip the meat into a bowl and sprinkle over 1 tsp salt and a good grinding of black pepper.Work with wet hands to mix in the seasoning. Divide into four with your hands and shape into burgers. (It can be frozen at this stage.)\r\n\r\nstep 2\r\nSort out your ingredients: Slice the beetroot and split the naan breads.\r\n\r\nstep 3\r\nToast the naans: Heat a griddle pan or barbecue. Griddle the naans on both sides until lightly toasted and set aside. Add the burgers to the grill or barbecue and cook for 2-3 minutes, then turn and cook the other side for a further 2-3 minutes.\r\n\r\nstep 4\r\nAssemble the dish: Set half a toasted naan on each serving plate and put a pile of rocket on each. Top with a burger, then a few slices of beetroot and a dollop of soured cream. Sprinkle with salt and freshly ground black pepper and serve immediately with a big green salad and chips. A glass of red wine wouldn’t go amiss, either.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 621, "protein_g": 56.8, "carbs_g": 31.9, "fat_g": 28.2, "total_kcal": 1242, "total_protein_g": 113.7, "total_carbs_g": 63.9, "total_fat_g": 56.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Shape the burgers", "instruction": "Season the meat with salt and a good grinding of black pepper. Mix in with wet hands, divide into four, and shape into burgers. (Can be frozen at this stage.)", "timer_seconds": null, "background": false}, {"step": 2, "label": "Prep the toppings", "instruction": "Slice the beetroot and split the naan breads.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Grill the naans and burgers", "instruction": "Heat a griddle pan or barbecue. Griddle the naans on both sides until lightly toasted, then set aside. Cook the burgers for 2 to 3 minutes per side.", "timer_seconds": 360, "background": false}, {"step": 4, "label": "Assemble", "instruction": "Set half a toasted naan on each plate, top with rocket, a burger, a few beetroot slices and a dollop of soured cream. Season and serve with a green salad and chips.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=pSupybydA_U"}, {"id": "53100", "name": "Blueberry & lemon friands", "category": "Dessert", "area": "Australian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/e756bf1761848342.jpg", "local_image": "53100.jpg", "ingredients": [{"ingredient": "Unsalted Butter", "measure": "100g"}, {"ingredient": "Icing Sugar", "measure": "125g"}, {"ingredient": "Flour", "measure": "25g"}, {"ingredient": "Almonds", "measure": "85g"}, {"ingredient": "Egg White", "measure": "3"}, {"ingredient": "Unwaxed Lemon", "measure": "1"}, {"ingredient": "Blackberries", "measure": "85g"}], "instructions": "step 1\r\nPreheat the oven to fan 180C/conventional 200C/gas 6. Generously butter six non-stick friand or muffin tins. Melt the butter and set aside to cool.\r\n\r\nstep 2\r\nSift the icing sugar and flour into a bowl. Add the almonds and mix everything between your fingers.\r\n\r\nstep 3\r\nWhisk the egg whites in another bowl until they form a light, floppy foam. Make a well in the centre of the dry ingredients, tip in the egg whites and lemon rind, then lightly stir in the butter to form a soft batter.\r\n\r\nstep 4\r\nDivide the batter among the tins, a large serving spoon is perfect for this job. Sprinkle a handful of blueberries over each cake and bake for 15-20 minutes until just firm to the touch and golden brown.\r\n\r\nstep 5\r\nCool in the tins for 5 minutes, then turn out and cool on a wire rack. To serve, dust lightly with icing sugar.", "equipment_tags": [], "portions": 4, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 480, "protein_g": 9.9, "carbs_g": 44.4, "fat_g": 31.2, "total_kcal": 1918, "total_protein_g": 39.6, "total_carbs_g": 177.6, "total_fat_g": 124.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the tins", "instruction": "Preheat the oven to fan 180°C/200°C/gas 6 and generously butter six friand or muffin tins. Melt the butter and set aside to cool.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Mix the dry ingredients", "instruction": "Sift the icing sugar and flour into a bowl. Add the almonds and mix through with your fingers.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Whisk and fold", "instruction": "Whisk the egg whites to a light, floppy foam. Make a well in the dry ingredients, tip in the egg whites and lemon rind, then lightly stir in the butter to form a soft batter.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Divide the batter among the tins, sprinkle blueberries over each, and bake for 15 to 20 minutes, until just firm to the touch and golden brown.", "timer_seconds": 1200, "background": true}, {"step": 5, "label": "Cool and serve", "instruction": "Cool in the tins for 5 minutes, then turn out onto a wire rack. Dust lightly with icing sugar to serve.", "timer_seconds": 300, "background": false}], "video": "https://www.youtube.com/watch?v=7tq5JvO88E0"}, {"id": "53101", "name": "Chocolate Coconut Squares", "category": "Dessert", "area": "Australian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8oupz51761848432.jpg", "local_image": "53101.jpg", "ingredients": [{"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Egg", "measure": "2"}, {"ingredient": "Self-raising Flour", "measure": "140g"}, {"ingredient": "Baking Powder", "measure": "1 teaspoon"}, {"ingredient": "Cocoa Powder", "measure": "2 tablespoons"}, {"ingredient": "Milk", "measure": "2 tablespoons"}, {"ingredient": "Plain Chocolate", "measure": "100g"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Icing Sugar", "measure": "100g"}, {"ingredient": "Desiccated Coconut", "measure": "100g"}], "instructions": "step 1\r\nHeat oven to 180C/fan 160C/gas 4. Butter and line the base of a 20cm square baking tin. Beat together the butter and sugar until pale and creamy, then beat in the eggs. Add 1 tbsp of the flour if the mix starts to curdle.\r\n\r\nstep 2\r\nSieve in the flour, baking powder and cocoa and fold in with a metal spoon. Stir in the milk. Scrape mix into the tin and level the top. Bake for 18-20 mins or until the cake springs back when pressed. Allow to cool in the tin.\r\n\r\nstep 3\r\nTo make the icing, put the chocolate, butter and 4 tbsp water in a pan and gently heat until melted. Allow to cool slightly, then beat in the icing sugar.\r\n\r\nstep 4\r\nRemove cake from tin and peel away paper. Cut into 16 squares. Dip the squares into the icing, then roll in the coconut. Allow to set on cooling rack.", "equipment_tags": [], "portions": 6, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 595, "protein_g": 8.2, "carbs_g": 69.0, "fat_g": 35.6, "total_kcal": 3573, "total_protein_g": 49.1, "total_carbs_g": 414.3, "total_fat_g": 213.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cream the butter and sugar", "instruction": "Heat the oven to 180°C/fan 160°C/gas 4. Butter and line the base of a 20cm square tin. Beat the butter and sugar until pale and creamy, then beat in the eggs (add a spoonful of flour if the mix starts to curdle).", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fold and bake", "instruction": "Sieve in the flour, baking powder and cocoa and fold in with a metal spoon. Stir in the milk, scrape into the tin, level the top, and bake for 18 to 20 minutes, until it springs back when pressed. Cool in the tin.", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Make the icing", "instruction": "Gently heat the chocolate, butter and water in a pan until melted. Cool slightly, then beat in the icing sugar.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Dip and set", "instruction": "Remove the cake from the tin, cut into 16 squares, dip each in the icing, then roll in the coconut. Allow to set on a cooling rack.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=8TzqUo8PCLg"}, {"id": "53102", "name": "Squid, chickpea & chorizo salad", "category": "Seafood", "area": "Australian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/wsu0rc1761848482.jpg", "local_image": "53102.jpg", "ingredients": [{"ingredient": "Red Pepper", "measure": "4"}, {"ingredient": "Can of chickpeas", "measure": "2 400g Cans"}, {"ingredient": "Parsley", "measure": "Bunch"}, {"ingredient": "Red Chilli", "measure": "1"}, {"ingredient": "Garlic Clove", "measure": "2"}, {"ingredient": "Olive Oil", "measure": "100 ml"}, {"ingredient": "Squid", "measure": "600g"}, {"ingredient": "Chorizo", "measure": "200g"}, {"ingredient": "Lemon", "measure": "Juice/zest of one"}], "instructions": "step 1\r\nCook the peppers whole under a grill, on a barbecue or griddle, until completely charred. Place the peppers in a bowl, cover with a plate until cool enough to handle, then peel, deseed and finely slice. In a large bowl mix the peppers and any juices with the chickpeas, parsley, chilli and garlic. Set aside.\r\n\r\nstep 2\r\nHeat a large frying pan until smoking. Working quickly and carefully, add a splash of oil to the pan, then the squid. Stir-fry for about 30 secs. Scatter the chorizo over the squid, continue to cook for 30 secs more, then tip into the bowl with the peppers. Season everything with salt and pepper, then dress with the remaining oil, lemon juice and lemon zest. Mix together, pile onto a platter and let everyone help themselves.", "equipment_tags": ["Grill"], "portions": 11, "prep_minutes": 46, "prep_minutes_source": "estimated", "kcal": 271, "protein_g": 16.3, "carbs_g": 13.0, "fat_g": 17.0, "total_kcal": 2980, "total_protein_g": 179.8, "total_carbs_g": 143.2, "total_fat_g": 187.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Char and dress the peppers", "instruction": "Grill or griddle the peppers whole until completely charred. Cover in a bowl until cool enough to handle, then peel, deseed and slice. Mix with the chickpeas, parsley, chilli and garlic.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Sear the squid and chorizo", "instruction": "Heat a large frying pan until smoking. Add a splash of oil, then the squid, and stir-fry for about 30 seconds. Scatter over the chorizo, cook 30 seconds more, then tip into the bowl with the peppers.", "timer_seconds": 60, "background": false}, {"step": 3, "label": "Dress and serve", "instruction": "Season everything, dress with the remaining oil, lemon juice and zest, mix together, and pile onto a platter to serve.", "timer_seconds": null, "background": false}], "video": "https://www.bbcgoodfood.com/recipes/squid-chickpea-chorizo-salad"}, {"id": "53103", "name": "Barramundi with Moroccan spices", "category": "Seafood", "area": "Australian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/4o4wh11761848573.jpg", "local_image": "53103.jpg", "ingredients": [{"ingredient": "barramundi", "measure": "2 x 400g"}, {"ingredient": "Ground Cumin", "measure": "1/2 teaspoon"}, {"ingredient": "Coriander", "measure": "1/2 tsp"}, {"ingredient": "Paprika", "measure": "Pinch"}, {"ingredient": "Chili Powder", "measure": "Pinch"}, {"ingredient": "Garlic Clove", "measure": "2"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Olive Oil", "measure": "5 tablespoons"}, {"ingredient": "Coriander", "measure": "Bunch"}], "instructions": "step 1\r\nTip all the dressing ingredients into a food processor with a pinch of salt and blitz to a dressing. Slash the fish three times on each side, coat with half of the dressing, then set aside to marinate for about 30 mins.\r\n\r\nstep 2\r\nHeat oven to 220C/fan 200C/gas 7. Place the fish on a roasting tray, then cook in the oven for 20 mins until the flesh is firm and the eyes have turned white. Serve the fish with the rest of the dressing and steamed couscous or rice.\r\n\r\nstep 3\r\nKNOW HOW: HOW TO COOK IT: Cooking barramundi on the bone, as we have done here, has its advantages – it will stay more moist during cooking, and some would say that the flavour is enhanced, too. If you want to take out the bones they are easy to locate and less likely to be lodged in the fillet if the fish is cooked whole. Fillets can be simply pan-fried or grilled. If you like trout, you will really enjoy the flavour of barramundi, which lends itself to similar ingredients and cooking methods – citrus flavours are particularly good, as are garlic and wild mushrooms. Simply roasting the fish with some fresh herbs, olive oil and seasoning is delicious, and in the summer months you could barbecue it, too. One thing that you mustn’t miss are the cheeks or ‘pearls’ of the fish, these are simply lovely, moist and really sweet – well worth leaving the head on for!", "equipment_tags": ["FoodProcessor", "Grill"], "portions": 1, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 1103, "protein_g": 78.0, "carbs_g": 7.6, "fat_g": 85.2, "total_kcal": 1103, "total_protein_g": 78.0, "total_carbs_g": 7.6, "total_fat_g": 85.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the marinade", "instruction": "Blitz the dressing ingredients with a pinch of salt in a food processor. Slash the fish three times on each side and coat with half the dressing.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate", "instruction": "Set the fish aside to marinate for about 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Roast the fish", "instruction": "Heat the oven to 220°C/fan 200°C/gas 7. Place the fish on a roasting tray and cook for 20 minutes, until the flesh is firm and the eyes have turned white.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Serve", "instruction": "Serve the fish with the rest of the dressing and steamed couscous or rice.", "timer_seconds": null, "background": false}], "video": null}, {"id": "53104", "name": "Lamingtons", "category": "Dessert", "area": "Australian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/j2n7vg1761848636.jpg", "local_image": "53104.jpg", "ingredients": [{"ingredient": "Salted Butter", "measure": "125g"}, {"ingredient": "Golden Caster Sugar", "measure": "250g"}, {"ingredient": "Egg", "measure": "3 Large"}, {"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Milk", "measure": "3  tablespoons"}, {"ingredient": "Salt", "measure": "1/2 teaspoon"}, {"ingredient": "Double Cream", "measure": "250ml"}, {"ingredient": "Icing Sugar", "measure": "2 tblsp"}, {"ingredient": "Raspberry Jam", "measure": "200g"}, {"ingredient": "Desiccated Coconut", "measure": "350g"}, {"ingredient": "Unsalted Butter", "measure": "80g"}, {"ingredient": "Milk", "measure": "250ml"}, {"ingredient": "Cocoa Powder", "measure": "50g"}, {"ingredient": "Icing Sugar", "measure": "400g"}], "instructions": "step 1\r\nHeat the oven to 200C/180C fan/gas 6. Butter and line a 20 x 30cm rectangle tin.\r\n\r\nstep 2\r\nBeat the butter and sugar in a free-standing mixer until pale and fluffy. Add the eggs one at a time and beat well. Beat through the flour, milk and salt until fully combined, then spoon into the tin. Bake in the oven for 25 mins or until golden and firm to the touch. Set aside to cool completely.\r\n\r\nstep 3\r\nSlice the sponge horizontally to create two halves. Trim the edges to make perfect corners. Cut the sponge into 18 squares. Lightly whip the cream with the icing sugar until it reaches soft peaks. Spread a little of the jam on half of the sponge squares then pipe or spread over a little of the cream. Sandwich each one with a second square of sponge then set aside in the fridge to chill.\r\n\r\nstep 4\r\nTo make the icing, whisk together the melted butter and milk in a bowl. Sieve the cocoa powder and icing sugar together in a seperate bowl. Gradually add the cocoa and sugar to the butter and milk mixture, whisking continuously to ensure there are no lumps. If it gets lumpy, whizz with a hand blender until smooth.\r\n\r\nstep 5\r\nDivide the coconut between three shallow bowls (this keeps it from getting coated in too much chocolate whilst you’re dipping).\r\n\r\nstep 6\r\nDip each lamington in the icing until completely covered. Roll in the coconut and set on a wire rack. Repeat with the remaining sponges. Chill for a minimum of 1 hr.", "equipment_tags": ["Blender"], "portions": 12, "prep_minutes": 85, "prep_minutes_source": "explicit", "kcal": 785, "protein_g": 8.0, "carbs_g": 95.1, "fat_g": 45.7, "total_kcal": 9414, "total_protein_g": 96.5, "total_carbs_g": 1141.8, "total_fat_g": 548.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the tin", "instruction": "Heat the oven to 200°C/180°C fan/gas 6. Butter and line a 20 x 30cm rectangular tin.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bake the sponge", "instruction": "Beat the butter and sugar until pale and fluffy, adding the eggs one at a time. Beat in the flour, milk and salt until combined, spoon into the tin, and bake for 25 minutes, until golden and firm to the touch. Cool completely.", "timer_seconds": 1500, "background": true}, {"step": 3, "label": "Fill and sandwich", "instruction": "Slice the sponge horizontally, trim the edges, and cut into 18 squares. Whip the cream with the icing sugar to soft peaks. Spread jam and cream over half the squares and sandwich with the rest, then chill.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the icing", "instruction": "Whisk the melted butter and milk together. Separately sieve the cocoa and icing sugar, then gradually whisk into the butter mixture until smooth.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Dip and coat", "instruction": "Divide the coconut between three shallow bowls. Dip each lamington in the icing until completely covered, roll in the coconut, and set on a wire rack. Repeat with the rest, then chill for at least 1 hour.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=CbHWqzw4Qxg"}, {"id": "53105", "name": "Spiced smoky barbecued chicken", "category": "Chicken", "area": "Australian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/a08uqk1761848682.jpg", "local_image": "53105.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Lemon", "measure": "Juice/zest of one"}, {"ingredient": "Curry Powder", "measure": "2 tblsp"}, {"ingredient": "Chilli Flakes", "measure": "Pinch"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Chicken Thighs", "measure": "12"}, {"ingredient": "Rosemary", "measure": "Bunch"}, {"ingredient": "Rosemary", "measure": "Bunch"}, {"ingredient": "Thyme", "measure": "Bunch"}, {"ingredient": "Thyme", "measure": "Bunch"}, {"ingredient": "Bay Leaves", "measure": "2"}], "instructions": "step 1\r\nMake the marinade. Smash the garlic with a little salt using a pestle and mortar. Add the lemon zest and juice, the spice mix, chilli, oil and a good grinding of black pepper. Mix to a paste. This can be done in a mini food processor.\r\n\r\nstep 2\r\nToss the chicken in the marinade and set aside while you light the barbecue. When the barbecue’s hot, lay the bunches of herbs on the grid and put the chicken, skin side up, on top. Close the lid, if your barbecue has one, and cook the chicken on the smouldering herbs for about 10 minutes until the meat starts to colour. Turn the chicken and continue to cook for a further 20-30 minutes, turning as necessary, until it is slightly charred from the burnt herbs and cooked through to the bone.", "equipment_tags": ["FoodProcessor", "Grill"], "portions": 2, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 668, "protein_g": 65.2, "carbs_g": 24.4, "fat_g": 35.4, "total_kcal": 1336, "total_protein_g": 130.4, "total_carbs_g": 48.8, "total_fat_g": 70.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the marinade", "instruction": "Smash the garlic with a little salt. Add the lemon zest and juice, spice mix, chilli, oil and black pepper, and mix to a paste.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Marinate and light the barbecue", "instruction": "Toss the chicken in the marinade and set aside while you light the barbecue.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Barbecue the chicken", "instruction": "Lay the herb bunches on the grid and place the chicken skin-side up on top. Close the lid and cook on the smouldering herbs for about 10 minutes until it starts to colour, then turn and cook 20 to 30 minutes more, until charred and cooked through to the bone.", "timer_seconds": 1800, "background": true}], "video": null}, {"id": "53106", "name": "Warm roast asparagus salad", "category": "Pork", "area": "Australian", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/ktsws11761998344.jpg", "local_image": "53106.jpg", "ingredients": [{"ingredient": "Asparagus", "measure": "500g"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tbsp"}, {"ingredient": "Tomato", "measure": "4"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "1 tbsp"}, {"ingredient": "Streaky Bacon", "measure": "12"}, {"ingredient": "Clear Honey", "measure": "1 teaspoon"}, {"ingredient": "Jersey Royal Potatoes", "measure": "16"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Dijon Mustard", "measure": "1 teaspoon"}, {"ingredient": "Rocket", "measure": "100g"}], "instructions": "step 1\r\nPreheat the oven to 200C/Gas 6/fan 180C. Snap off the woody ends of the asparagus and discard. Arrange the asparagus in a single layer in a baking tray with sides. Cut the tomatoes in half widthways, nestle them in with the asparagus, season with sea salt and pepper and drizzle with olive oil. Roll each bacon rasher into a tight roll (if large, first cut in half crosswise), and arrange in the tray. Drizzle the bacon rolls with the honey and bake for 20 minutes until the tomatoes are soft and the bacon is crisp.\r\n\r\nstep 2\r\nIn the meantime, boil the potatoes until tender. Whisk the vinegar, olive oil, mustard, some sea salt and pepper in a large bowl until blended. Toss the rocket or spinach leaves in half of the dressing, and arrange on a large serving platter.\r\n\r\nstep 3\r\nDrain the potatoes and cut in half. Gently toss them in the rest of the dressing, and arrange on the platter with the asparagus. Tuck in the tomatoes and bacon.", "equipment_tags": [], "portions": 12, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 494, "protein_g": 24.5, "carbs_g": 43.0, "fat_g": 24.9, "total_kcal": 5934, "total_protein_g": 293.8, "total_carbs_g": 515.8, "total_fat_g": 298.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Roast the tray", "instruction": "Preheat the oven to 200°C/gas 6/fan 180°C. Trim the asparagus and arrange in a baking tray with the halved tomatoes, seasoned and drizzled with oil. Roll the bacon rashers and nestle them in, drizzle with honey, and bake for 20 minutes, until the tomatoes are soft and the bacon crisp.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Boil the potatoes", "instruction": "Meanwhile, boil the potatoes until tender. Whisk the vinegar, oil and mustard with seasoning for the dressing, and toss the salad leaves in half of it on a serving platter.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Assemble", "instruction": "Drain and halve the potatoes, toss in the rest of the dressing, and arrange on the platter with the asparagus, tomatoes and bacon.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=pR_ZfbTxwms"}, {"id": "53107", "name": "Avocado dip with new potatoes", "category": "Vegetarian", "area": "Australian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/flrajf1762341295.jpg", "local_image": "53107.jpg", "ingredients": [{"ingredient": "Avocado", "measure": "3 Large"}, {"ingredient": "Natural Yoghurt", "measure": "200g"}, {"ingredient": "Lime", "measure": "Zest and juice of 1"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Baby New Potatoes", "measure": "1.25kg"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Hot Chilli Powder", "measure": "1 teaspoon"}, {"ingredient": "Cumin Seeds", "measure": "1 teaspoon"}, {"ingredient": "Tortillas", "measure": "200g"}], "instructions": "step 1\r\nWhizz half the avocado flesh with the yogurt, lime and lemon juice and seasoning. Dice the remaining avocado, then gently stir into the whizzed mix with most of the lime zest. Cover, then chill until ready to serve.\r\n\r\nstep 2\r\nBoil potatoes for 6 mins, then drain well and toss with olive oil, chilli powder and cumin seeds. Now set aside until half an hour before your guests arrive.\r\n\r\nstep 3\r\nHeat oven to 200C/180C fan/gas 6, then roast potatoes for about 30 mins, shaking the tray halfway, until golden and tender. Transfer the dip to one or two bowls, scatter with the remaining lime zest and serve with the hot potatoes, and tortilla chips for dipping.", "equipment_tags": [], "portions": 12, "prep_minutes": 36, "prep_minutes_source": "explicit", "kcal": 171, "protein_g": 4.0, "carbs_g": 27.9, "fat_g": 5.4, "total_kcal": 2055, "total_protein_g": 48.5, "total_carbs_g": 334.6, "total_fat_g": 65.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the dip", "instruction": "Whizz half the avocado with the yogurt, lime and lemon juice and seasoning. Dice the rest and stir it in with most of the lime zest. Cover and chill until ready to serve.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Parboil the potatoes", "instruction": "Boil the potatoes for 6 minutes, drain well, and toss with the olive oil, chilli powder and cumin seeds. Set aside until half an hour before your guests arrive.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Roast the potatoes", "instruction": "Heat the oven to 200°C/180°C fan/gas 6 and roast the potatoes for about 30 minutes, shaking the tray halfway, until golden and tender.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Serve", "instruction": "Transfer the dip to bowls, scatter with the remaining lime zest, and serve with the hot potatoes and tortilla chips.", "timer_seconds": null, "background": false}], "video": null}, {"id": "53108", "name": "Quick salt & pepper squid", "category": "Seafood", "area": "Australian", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/cp74zo1762341241.jpg", "local_image": "53108.jpg", "ingredients": [{"ingredient": "Squid", "measure": "400g"}, {"ingredient": "Oil", "measure": "3  tablespoons"}, {"ingredient": "Chinese five spice powder", "measure": "1/2 teaspoon"}, {"ingredient": "Sesame Seed Oil", "measure": "Dash"}, {"ingredient": "Coriander", "measure": "Sprigs of fresh"}, {"ingredient": "sweet chilli sauce", "measure": "Drizzle"}], "instructions": "step 1\r\nAsk the fishmonger to clean the squid; little ones often come ready-cleaned. Using kitchen scissors, cut open the body and open out. Wash well, then pat dry. If you have a large squid, cut the body into four portions, roughly square. Small squid can just be opened up.\r\n\r\nstep 2\r\nUsing the tip of a very sharp knife, score the top in a neat criss-cross. Brush with oil and set aside while you heat the barbecue or griddle until ready to cook.\r\n\r\nstep 3\r\nMix together 2 tsp sea salt, Chinese five-spice and 1 tsp freshly ground black pepper. Sprinkle on both sides of the squid just before cooking, according to taste. You may not need it all. Heat the griddle pan to hot and cook about 1 min each side, until it starts to curl. Remove with tongs to a serving plate and drizzle with a little sesame oil. To serve, garnish with coriander leaves and serve with small bowls of sweet chilli sauce to dip into.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 1, "prep_minutes_source": "explicit", "kcal": 763, "protein_g": 63.2, "carbs_g": 16.7, "fat_g": 48.3, "total_kcal": 763, "total_protein_g": 63.2, "total_carbs_g": 16.7, "total_fat_g": 48.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Clean the squid", "instruction": "Cut open the body and open it out flat. Wash well and pat dry. Cut large squid into four roughly square portions; small ones can just be opened up.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Score and oil", "instruction": "Score the top in a neat criss-cross with the tip of a sharp knife. Brush with oil and set aside while the barbecue or griddle heats up.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Season and cook", "instruction": "Mix the sea salt, five-spice and pepper, and sprinkle over both sides of the squid just before cooking. Cook on a hot griddle for about 1 minute each side, until it starts to curl.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Serve", "instruction": "Remove to a serving plate, drizzle with a little sesame oil, garnish with coriander, and serve with sweet chilli sauce for dipping.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=CxHTj_6sU_A"}, {"id": "53109", "name": "Mini chilli beef pies", "category": "Beef", "area": "Australian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/6sarfo1762340107.jpg", "local_image": "53109.jpg", "ingredients": [{"ingredient": "Ready rolled shortcrust pastry", "measure": "450g"}, {"ingredient": "Sunflower Oil", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Hot Chilli Powder", "measure": "2 tsp"}, {"ingredient": "Ground Cumin", "measure": "2 tsp"}, {"ingredient": "Minced Beef", "measure": "250g"}, {"ingredient": "Tomato Puree", "measure": "85g"}, {"ingredient": "Beef Stock", "measure": "150ml"}, {"ingredient": "Ground Cinnamon", "measure": "Pinch"}, {"ingredient": "Kidney Beans", "measure": "200g"}, {"ingredient": "Potatoes", "measure": "1 large"}, {"ingredient": "Sour Cream", "measure": "3  tablespoons"}, {"ingredient": "Chopped Chive", "measure": "2 tablespoons"}], "instructions": "step 1\r\nTo make chilli, heat oil in a pan and fry onion for 5 mins until soft. Add spices; fry for 1 min. Stir in beef and cook for a few mins. Add tomato purée, stock and cinnamon. Give it a stir, bring to the boil, then simmer for 15-20 mins until very little liquid is left. Add beans 5 mins before the end of cooking. Check seasoning and cool.\r\n\r\nstep 2\r\nHeat oven to 200C/fan 180C/gas 6. Using a 7cm pastry cutter, stamp out 12 circles from the pastry. Use to line a 12-hole mini muffin tray, prick the base of the pastry with a fork, and bake for 10 mins. Remove from oven and cool on a wire tray. Repeat with remaining pastry.\r\n\r\nstep 3\r\nMeanwhile, cook the potato in boiling water until tender. Drain, mash with soured cream and seasoning, then stir through chives. Spoon 1-2 tsp of chilli mix into the pastry cases and top with a tsp of mash. Ruffle mash with a fork; return to the oven for 15 mins or until golden.", "equipment_tags": [], "portions": 3, "prep_minutes": 56, "prep_minutes_source": "explicit", "kcal": 1151, "protein_g": 33.7, "carbs_g": 105.9, "fat_g": 68.0, "total_kcal": 3453, "total_protein_g": 101.1, "total_carbs_g": 317.6, "total_fat_g": 204.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the chilli", "instruction": "Fry the onion in oil for 5 minutes until soft. Add the spices and fry for 1 minute, then stir in the beef and cook for a few minutes. Add the tomato purée, stock and cinnamon, bring to the boil, then simmer for 15 to 20 minutes until very little liquid is left. Stir in the beans for the final 5 minutes, then cool.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Line and bake the pastry cases", "instruction": "Heat the oven to 200°C/fan 180°C/gas 6. Stamp out 12 pastry circles and use to line a mini muffin tray. Prick the bases and bake for 10 minutes, then cool on a wire rack. Repeat with the remaining pastry.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Mash the potato", "instruction": "Meanwhile, cook the potato in boiling water until tender. Drain, mash with soured cream and seasoning, then stir through the chives.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fill and finish", "instruction": "Spoon the chilli into the pastry cases and top with the mash. Ruffle with a fork and return to the oven for 15 minutes, until golden.", "timer_seconds": 900, "background": true}], "video": "https://www.youtube.com/watch?v=PHuU1L92-Ns"}, {"id": "53110", "name": "Sticky Chicken", "category": "Chicken", "area": "Australian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/cj56fs1762340001.jpg", "local_image": "53110.jpg", "ingredients": [{"ingredient": "Chicken drumsticks", "measure": "8"}, {"ingredient": "Soy Sauce", "measure": "2 tblsp"}, {"ingredient": "Honey", "measure": "1 tablespoon"}, {"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Tomato Puree", "measure": "1 teaspoon"}, {"ingredient": "Dijon Mustard", "measure": "1 tbsp"}], "instructions": "step 1\r\nMake 3 slashes on each of the drumsticks. Mix together the soy, honey, oil, tomato purée and mustard. Pour this mixture over the chicken and coat thoroughly. Leave to marinate for 30 mins at room temperature or overnight in the fridge. Heat oven to 200C/fan 180C/gas 6.\r\n\r\nstep 2\r\nTip the chicken into a shallow roasting tray and cook for 35 mins, turning occasionally, until the chicken is tender and glistening with the marinade.", "equipment_tags": [], "portions": 1, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 264, "protein_g": 11.3, "carbs_g": 20.8, "fat_g": 15.9, "total_kcal": 264, "total_protein_g": 11.3, "total_carbs_g": 20.8, "total_fat_g": 15.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Marinate the chicken", "instruction": "Make 3 slashes in each drumstick. Mix the soy, honey, oil, tomato purée and mustard, pour over the chicken, and coat thoroughly. Leave to marinate for 30 minutes at room temperature or overnight in the fridge. Heat the oven to 200°C/fan 180°C/gas 6.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Roast", "instruction": "Tip the chicken into a shallow roasting tray and cook for 35 minutes, turning occasionally, until tender and glistening with the marinade.", "timer_seconds": 2100, "background": true}], "video": "https://www.youtube.com/watch?v=o8tz2BOltTg"}, {"id": "53111", "name": "Anzac biscuits", "category": "Dessert", "area": "Australian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/q47rkb1762324620.jpg", "local_image": "53111.jpg", "ingredients": [{"ingredient": "Porridge oats", "measure": "85g"}, {"ingredient": "Desiccated Coconut", "measure": "85g"}, {"ingredient": "Plain Flour", "measure": "100g"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Golden Syrup", "measure": "1 tblsp"}, {"ingredient": "Bicarbonate Of Soda", "measure": "1 teaspoon"}], "instructions": "step 1\r\nHeat oven to 180C/fan 160C/gas 4. Put the oats, coconut, flour and sugar in a bowl. Melt the butter in a small pan and stir in the golden syrup. Add the bicarbonate of soda to 2 tbsp boiling water, then stir into the golden syrup and butter mixture.\r\n\r\nstep 2\r\nMake a well in the middle of the dry ingredients and pour in the butter and golden syrup mixture. Stir gently to incorporate the dry ingredients.\r\n\r\nstep 3\r\nPut dessertspoonfuls of the mixture on to buttered baking sheets, about 2.5cm/1in apart to allow room for spreading. Bake in batches for 8-10 mins until golden. Transfer to a wire rack to cool.", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 809, "protein_g": 10.4, "carbs_g": 89.7, "fat_g": 47.7, "total_kcal": 2428, "total_protein_g": 31.2, "total_carbs_g": 269.2, "total_fat_g": 143.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Mix the dry ingredients and syrup", "instruction": "Heat the oven to 180°C/fan 160°C/gas 4. Put the oats, coconut, flour and sugar in a bowl. Melt the butter and stir in the golden syrup, then dissolve the bicarbonate of soda in the boiling water and stir into the butter mixture.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Combine", "instruction": "Make a well in the dry ingredients, pour in the butter mixture, and stir gently to combine.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Spoon dessertspoonfuls onto buttered baking sheets, spaced apart, and bake in batches for 8 to 10 minutes, until golden. Transfer to a wire rack to cool.", "timer_seconds": 600, "background": true}], "video": "https://www.youtube.com/watch?v=1nAVbfQVWRQ"}, {"id": "53112", "name": "Kenyan Beef Curry", "category": "Beef", "area": "Kenyan", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/lqampv1762325397.jpg", "local_image": "53112.jpg", "ingredients": [{"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Sirloin Steak tips", "measure": "2 Lbs"}, {"ingredient": "Garlic Clove", "measure": "4"}, {"ingredient": "Ground Ginger", "measure": "2 teaspoons"}, {"ingredient": "Oil", "measure": "2 tblsp"}, {"ingredient": "Red Onions", "measure": "2 medium"}, {"ingredient": "Tomato", "measure": "4"}, {"ingredient": "Paprika", "measure": "2 tblsp"}, {"ingredient": "Black Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Curry Powder", "measure": "2 teaspoons"}, {"ingredient": "Tomato Puree", "measure": "4 tablespoons"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Chilli", "measure": "1"}, {"ingredient": "Cilantro", "measure": "Leaves"}], "instructions": "Bring the 4 cups of water to a boil in a Dutch oven or soup pot. Add the beef, garlic, and ginger, and stir well. Bring to a gentle simmer, cover, and cook, stirring occasionally, for 20 minutes. If you get any foamy scum on the top, not to worry, simply spoon it away or stir it back in.\r\nRemove from the heat, and drain, but reserve the excess water for later.\r\nReturn the pot or Dutch oven to medium heat with the 2 tablespoons of cooking oil. Once the oil is shimmering, add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.\r\nAdd the tomatoes to the onions, and continue cooking, stirring occasionally, until the tomatoes are falling apart, 3 to 5 minutes.\r\nAdd the drained beef to the tomato and onion mixture, and stir well. Continue cooking over medium heat for 5 minutes, stirring occasionally.\r\nAdd the paprika, pepper, curry powder, tomato paste, and salt to taste, and stir well.\r\nAdd back the excess water that was used for cooking the beef, along with enough extra water to cover. Bring to a boil, reduce heat, and simmer, uncovered, stirring occasionally, for about 1 hour, or until the meat is tender and the sauce is thickened. Add additional water if your beef curry begins to dry and stick, or if would like your curry to have more of a soupy consistency.\r\nWhen the beef curry is ready, remove from the heat, give it a taste, and adjust the seasonings as desired. Garnish with fresh chilis and cilantro.", "equipment_tags": [], "portions": 5, "prep_minutes": 97, "prep_minutes_source": "explicit", "kcal": 413, "protein_g": 39.6, "carbs_g": 16.6, "fat_g": 21.5, "total_kcal": 2065, "total_protein_g": 197.9, "total_carbs_g": 82.8, "total_fat_g": 107.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Simmer the beef", "instruction": "Bring the water to a boil, add the beef, garlic and ginger, and stir well. Bring to a gentle simmer, cover, and cook, stirring occasionally, for 20 minutes, skimming off any foam.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Drain and reserve", "instruction": "Remove from the heat and drain, reserving the excess water for later.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook the onions", "instruction": "Return the pot to medium heat with the oil. Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.", "timer_seconds": 420, "background": false}, {"step": 4, "label": "Add the tomatoes", "instruction": "Add the tomatoes and continue cooking, stirring occasionally, until they're falling apart, 3 to 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 5, "label": "Combine and season", "instruction": "Add the drained beef, stir well, and cook for 5 minutes. Add the paprika, pepper, curry powder, tomato paste and salt to taste.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Simmer to finish", "instruction": "Add back the reserved water plus enough extra to cover. Bring to a boil, reduce the heat, and simmer uncovered, stirring occasionally, for about 1 hour, until the meat is tender and the sauce thickened.", "timer_seconds": 3600, "background": true}, {"step": 7, "label": "Garnish and serve", "instruction": "Taste and adjust the seasoning, then garnish with fresh chillies and cilantro.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=NxrOueTLiqA"}, {"id": "53113", "name": "Sukuma Wiki", "category": "Vegetarian", "area": "Kenyan", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/60o82j1762341177.jpg", "local_image": "53113.jpg", "ingredients": [{"ingredient": "Oil", "measure": "2 tablespoons"}, {"ingredient": "Red Onions", "measure": "2 medium"}, {"ingredient": "Kale", "measure": "1 lb"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Double Cream", "measure": "1 cup"}], "instructions": "Heat the 2 tablespoons of oil in a large skillet or pot over medium heat until shimmering. Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.\r\nAdd the shredded kale to the onions and mix well. Turn the heat to medium-low, cover and cook for 5 minutes.\r\nAfter 5 minutes, remove the lid, add salt to taste, and stir in the cream. Continue cooking for another 5 minutes, uncovered, stirring occasionally. The cream will thicken slightly, making for a deliciously rich creamed kale and onions. Yumm!\r\nServe it up with your favorite Kenyan stew, and a side of ugali!", "equipment_tags": [], "portions": 2, "prep_minutes": 22, "prep_minutes_source": "explicit", "kcal": 816, "protein_g": 14.3, "carbs_g": 33.4, "fat_g": 73.6, "total_kcal": 1632, "total_protein_g": 28.6, "total_carbs_g": 66.9, "total_fat_g": 147.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Soften the onions", "instruction": "Heat the oil in a large skillet or pot over medium heat. Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.", "timer_seconds": 420, "background": false}, {"step": 2, "label": "Wilt the kale", "instruction": "Add the shredded kale, mix well, turn the heat to medium-low, cover, and cook for 5 minutes.", "timer_seconds": 300, "background": true}, {"step": 3, "label": "Finish with cream", "instruction": "Remove the lid, season with salt, stir in the cream, and continue cooking uncovered for another 5 minutes, stirring occasionally, until slightly thickened.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Serve", "instruction": "Serve alongside your favourite Kenyan stew and a side of ugali.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=02hHtPDAxOs"}, {"id": "53114", "name": "Ugali – Kenyan cornmeal", "category": "Breakfast", "area": "Kenyan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/smoa3h1762341142.jpg", "local_image": "53114.jpg", "ingredients": [{"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "White Cornmeal", "measure": "1 1/2 cups"}], "instructions": "Bring the water to a boil in a medium saucepan.\r\nReduce the heat to low, and stirring constantly with a whisk, slowly add the cornmeal to the boiling water. The ugali will begin to thicken quite quickly.\r\nContinue cooking on low heat, stirring constantly with a sturdy wooden spoon, until the ugali begins to pull away from the sides of the pan, hold together, and takes on the aroma of roasted corn. Turn it out immediately onto a serving plate. If you would like, using a spoon or spatula, quickly shape it into a thick disk or round.\r\nThe ugali will continue to firm as it cools and will be thick enough to cut with a knife (similar to firm polenta).", "equipment_tags": [], "portions": 3, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 444, "protein_g": 9.7, "carbs_g": 94.8, "fat_g": 4.3, "total_kcal": 1332, "total_protein_g": 29.2, "total_carbs_g": 284.4, "total_fat_g": 13.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil the water", "instruction": "Bring the water to a boil in a medium saucepan.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Whisk in the cornmeal", "instruction": "Reduce the heat to low and, whisking constantly, slowly add the cornmeal. It will begin to thicken quickly.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Cook and stir", "instruction": "Continue cooking on low heat, stirring constantly with a sturdy wooden spoon, until the ugali pulls away from the sides of the pan, holds together, and smells of roasted corn.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Shape and rest", "instruction": "Turn out immediately onto a serving plate, shaping into a thick disk if you like. It will firm up further as it cools.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=yjue2KTETdE"}, {"id": "53115", "name": "Red onion pickle", "category": "Vegan", "area": "Norway", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/ppodrp1762325183.jpg", "local_image": "53115.jpg", "ingredients": [{"ingredient": "Red Onions", "measure": "3 Large"}, {"ingredient": "Sea Salt", "measure": "2 tsp"}, {"ingredient": "Cider Vinegar", "measure": "200ml"}, {"ingredient": "Granulated Sugar", "measure": "50g"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Bay Leaves", "measure": "4"}], "instructions": "Peel the onions, cut them in half from top to bottom and finely slice into half-moon pieces. Put in a colander placed over a bowl and sprinkle with salt, lightly turning over the onion pieces with your hands so the surfaces are all covered. Set aside for an hour or so to brine.\r\n\r\nMeanwhile put the vinegar, 50ml/2fl oz water and the sugar in a saucepan. Bring to a simmer, stirring to help the sugar dissolve, and cook for a couple of minutes. Set aside.\r\n\r\nPack the onions into the sterilised jars, sprinkling in a little pepper as you go. Cover with the warm vinegar and finish by tucking a couple of bay leaves down the side of the jars. Seal. The onions are best kept in the fridge and used within to 4 weeks.", "equipment_tags": [], "portions": 1, "prep_minutes": 40, "prep_minutes_source": "estimated", "kcal": 378, "protein_g": 4.2, "carbs_g": 85.6, "fat_g": 0.6, "total_kcal": 378, "total_protein_g": 4.2, "total_carbs_g": 85.6, "total_fat_g": 0.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Brine the onions", "instruction": "Peel, halve and finely slice the onions into half-moons. Place in a colander over a bowl, sprinkle with salt, and toss to coat. Set aside to brine for about an hour.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Make the pickling liquid", "instruction": "Meanwhile, put the vinegar, water and sugar in a saucepan, bring to a simmer, stirring to dissolve the sugar, and cook for a couple of minutes. Set aside.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Pack the jars", "instruction": "Pack the onions into sterilised jars with a little pepper, cover with the warm vinegar, tuck in the bay leaves, and seal.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=3z2jTcsL28g"}, {"id": "53116", "name": "Cinnamon buns", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/as88dq1762772486.jpg", "local_image": "53116.jpg", "ingredients": [{"ingredient": "Unsalted Butter", "measure": "100g"}, {"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "Salt", "measure": "1 teaspoon"}, {"ingredient": "Flour", "measure": "250g"}, {"ingredient": "Strong White Flour", "measure": "250g"}, {"ingredient": "Fast action yeast", "measure": "1 1/2 tsp"}, {"ingredient": "Cardamom", "measure": "1 teaspoon"}, {"ingredient": "Caster Sugar", "measure": "1 tblsp"}, {"ingredient": "Egg", "measure": "2"}, {"ingredient": "Olive Oil", "measure": "Dash"}, {"ingredient": "Unsalted Butter", "measure": "75g"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Cinnamon", "measure": "2 tbsp"}, {"ingredient": "Egg", "measure": "1"}], "instructions": "In a small saucepan heat the butter, milk and salt until the butter is melted. Allow the mixture to cool until it is lukewarm.\r\n\r\nIn a large bowl, stir together the flours, yeast, cardamom and sugar until combined.\r\n\r\nMake a well in the centre and crack in the eggs. Pour in the lukewarm milk mixture and stir everything together to form a sticky dough. You may have to use your hands as the dough becomes stiffer.\r\n\r\nOil the work surface with a teaspoon of olive oil. Turn the dough out onto the oiled surface and knead vigorously for 5–8 minutes, using a plastic scraper as needed to prise the dough from the work surface. Don’t be tempted to add flour, as this will make the buns dry and tough. Keep kneading until the dough is considerably less sticky, smoother and more elastic.\r\n\r\nShape into a ball, and put into a large, greased bowl. Cover the bowl with a clean tea towel and set aside in a warm place to prove for an hour, or until doubled in size.\r\n\r\nMeanwhile, for the filling and topping, mix the softened butter in a bowl with half the sugar and 1 tablespoon cinnamon. Use a fork to mix the sugar and spice into the butter until it is completely combined.\r\n\r\nMix the remaining sugar and cinnamon in a separate bowl and set aside.\r\n\r\nWhen the dough has risen, turn out onto a floured work surface and gently roll out into a 36x24cm/14x9½in rectangle. Spread the cinnamon-sugar-butter evenly over the dough with a table or palette knife.\r\n\r\nWith the longest edge closest to you, roll the dough up into a cylinder. Cut into 12 even slices.\r\n\r\nPlace each slice onto a flattened out paper cupcake case on a baking tray, or into a greased muffin tin. (Baking in a muffin tin will make your cinnamon buns taller and domed.)\r\n\r\nCover with a clean tea towel and set aside to prove again for 30–45 minutes, or until risen.\r\n\r\nPreheat the oven to 200C/180C Fan/Gas 6.\r\n\r\nBrush the tops of the buns with beaten egg and dust liberally with the cinnamon sugar. Bake for 12 minutes until the buns are dark golden-brown. Enjoy warm with a cup of coffee.", "equipment_tags": [], "portions": 8, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 496, "protein_g": 10.3, "carbs_g": 66.9, "fat_g": 21.3, "total_kcal": 3970, "total_protein_g": 82.2, "total_carbs_g": 534.9, "total_fat_g": 170.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Warm the milk mixture", "instruction": "Heat the butter, milk and salt in a small saucepan until the butter melts. Let cool until lukewarm.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Mix the dough", "instruction": "Stir the flours, yeast, cardamom and sugar together in a large bowl. Make a well, crack in the eggs, pour in the milk mixture, and stir to a sticky dough.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Knead", "instruction": "Oil the work surface and knead the dough vigorously for 5 to 8 minutes, until less sticky, smoother and elastic.", "timer_seconds": 480, "background": false}, {"step": 4, "label": "First prove", "instruction": "Shape into a ball, place in a greased bowl, cover, and leave in a warm place to prove for about an hour, or until doubled in size.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Make the filling", "instruction": "Meanwhile, mix the softened butter with half the sugar and the cinnamon. Set the remaining sugar and cinnamon aside separately.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Fill and roll", "instruction": "Roll the risen dough into a 36 x 24cm rectangle and spread over the cinnamon butter. Roll up from the longest edge into a cylinder and cut into 12 slices.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Second prove", "instruction": "Place the slices in cupcake cases or a greased muffin tin, cover, and leave to prove again for 30 to 45 minutes, until risen.", "timer_seconds": 2700, "background": true}, {"step": 8, "label": "Bake", "instruction": "Preheat the oven to 200°C/180°C fan/gas 6. Brush the buns with beaten egg, dust with the cinnamon sugar, and bake for 12 minutes, until dark golden-brown.", "timer_seconds": 720, "background": true}], "video": "https://www.youtube.com/watch?v=wNiyp89pTi0"}, {"id": "53117", "name": "Nordic smørrebrød with asparagus and horseradish cream", "category": "Vegetarian", "area": "Norway", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/8a8fu01762772651.jpg", "local_image": "53117.jpg", "ingredients": [{"ingredient": "Creme Fraiche", "measure": "150ml"}, {"ingredient": "Horseradish", "measure": "2 tblsp"}, {"ingredient": "Lemon Juice", "measure": "1 teaspoon"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Vegetable Oil", "measure": "Dash"}, {"ingredient": "Shallots", "measure": "2"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "White Asparagus", "measure": "8"}, {"ingredient": "Asparagus", "measure": "8"}, {"ingredient": "Rye Bread", "measure": "4 slices"}, {"ingredient": "Butter", "measure": "1 tblsp"}, {"ingredient": "västerbottensost cheese", "measure": "100g"}, {"ingredient": "Dill", "measure": "Sprinking"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Black Pepper", "measure": "Pinch"}], "instructions": "To make the horseradish cream, mix the crème fraîche, grated horseradish, lemon juice, salt and white pepper in a bowl. Refrigerate until serving.\r\n\r\nTo make the crispy shallots, heat some vegetable oil in a frying pan over a medium heat. Add the sliced shallots and fry until golden brown and crispy.\r\n\r\nRemove with a slotted spoon and drain on a plate lined with kitchen paper. Season with a pinch of salt.\r\n\r\nTo make the open sandwich, bring a large saucepan of salted water to the boil, then blanch half of the asparagus (four white and four green) until tender-crisp, about 2–3 minutes.\r\n\r\nAdd ice to a bowl of cold water. Use a slotted spoon to remove the asparagus from the boiling water and immediately transfer to the iced water to stop cooking. Thinly slice the remaining asparagus lengthwise to serve raw.\r\n\r\nPre-heat the grill until hot. Spread the rye bread with butter and grill until golden and crisp.\r\n\r\nTo serve, place the grilled bread slices on serving plates. Arrange both the blanched and raw asparagus on the bread. Drizzle with horseradish cream, then sprinkle grated cheese over the top. Garnish with the crispy shallots and some fresh dill to finish.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 476, "protein_g": 19.5, "carbs_g": 36.9, "fat_g": 30.1, "total_kcal": 1428, "total_protein_g": 58.4, "total_carbs_g": 110.6, "total_fat_g": 90.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Make the horseradish cream", "instruction": "Mix the crème fraîche, grated horseradish, lemon juice, salt and white pepper. Refrigerate until serving.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Fry the shallots", "instruction": "Heat oil in a frying pan over medium heat. Add the sliced shallots and fry until golden brown and crispy.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Drain the shallots", "instruction": "Remove with a slotted spoon, drain on kitchen paper, and season with a pinch of salt.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Blanch the asparagus", "instruction": "Bring salted water to the boil and blanch half the asparagus until tender-crisp, 2 to 3 minutes, then plunge into iced water to stop cooking. Thinly slice the remaining asparagus to serve raw.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Grill the bread", "instruction": "Preheat the grill. Spread the rye bread with butter and grill until golden and crisp.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Assemble", "instruction": "Place the bread on serving plates, arrange the blanched and raw asparagus on top, drizzle with horseradish cream, sprinkle with grated cheese, and garnish with the crispy shallots and dill.", "timer_seconds": null, "background": false}], "video": null}, {"id": "53118", "name": "Rømmegrøt – Norwegian Sour Cream Porridge", "category": "Breakfast", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/hyk47c1762772689.jpg", "local_image": "53118.jpg", "ingredients": [{"ingredient": "Full fat sour cream", "measure": "2 cups"}, {"ingredient": "Flour", "measure": "3/4 cup"}, {"ingredient": "Milk", "measure": "2 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "Sprinkling"}, {"ingredient": "Cinnamon", "measure": "Sprinkling"}, {"ingredient": "Butter", "measure": "To taste"}], "instructions": "▢\r\nCook the sour cream in a covered saucepan on medium heat for about 5 minutes.\r\n▢\r\nTurn down the heat and add half of the flour and stir well with a whisk. Once the flour is fully incorporated, let the mixture continue to cook, stirring occasionally, until fat starts to release. Use a spoon to gather as much of the fat as you can in a small bowl, saving for later. (Don't worry if you can't get any fat – in that case you can add butter later.)\r\n▢\r\nWhisk in the rest of the flour and then slowly add the milk, whisking constantly to avoid lumps. Let the porridge continue to cook on low heat for 5 minutes and then add salt.\r\n▢\r\nServe with sugar, cinnamon, and the fat from the porridge. If you're using lower fat sour cream you can top the rømmegrøt with some butter instead.", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 281, "protein_g": 8.6, "carbs_g": 42.7, "fat_g": 8.3, "total_kcal": 842, "total_protein_g": 25.9, "total_carbs_g": 128.1, "total_fat_g": 24.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the sour cream", "instruction": "Cook the sour cream in a covered saucepan over medium heat for about 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Add the flour", "instruction": "Turn down the heat, whisk in half the flour, and let it cook, stirring occasionally, until fat starts to release. Skim the fat into a small bowl and reserve.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Whisk in the milk", "instruction": "Whisk in the rest of the flour, then slowly add the milk, whisking constantly to avoid lumps. Cook on low heat for 5 minutes, then add salt.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Serve", "instruction": "Serve with sugar, cinnamon and the reserved fat (or butter instead, if using lower-fat sour cream).", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=v4rIJOWXM3w"}, {"id": "53119", "name": "Tall Skoleboller", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xihiu41762773169.jpg", "local_image": "53119.jpg", "ingredients": [{"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Instant Yeast", "measure": "3 tsp"}, {"ingredient": "Granulated Sugar", "measure": "1-⅓ cups"}, {"ingredient": "Cardamom", "measure": "1 tsp"}, {"ingredient": "Vanilla Extract", "measure": "1 teaspoon"}, {"ingredient": "Flour", "measure": "2 1/4 cups"}, {"ingredient": "Butter", "measure": "5 tblsp"}, {"ingredient": "Milk", "measure": "1 1/4 cup"}, {"ingredient": "Granulated Sugar", "measure": "1-⅓ cups"}, {"ingredient": "Egg Yolks", "measure": "3"}, {"ingredient": "Cornstarch", "measure": "2 tblsp"}, {"ingredient": "vanilla pod", "measure": "1"}, {"ingredient": "Powdered Sugar", "measure": "2 cups"}, {"ingredient": "Water", "measure": "3  tablespoons"}, {"ingredient": "Shredded Coconut", "measure": "1 cup"}], "instructions": "▢\r\nHeat the milk until it's lukewarm. Add the yeast and dissolve.\r\n▢\r\nAdd the sugar, cardamom, vanilla, and about 2/3 of the flour.\r\n▢\r\nMix the dough together either by hand or in a mixer with a dough hook, slowly adding the rest of the flour. You might need a bit more or less flour to form dough that isn't too sticky to knead. When the dough forms a nice ball, add the softened butter and continue to knead the dough for about ten minutes.\r\n▢\r\nRoll the dough into a cylinder and cut into six equal parts. Roll each piece into a round bun and set them in a greased muffin/cake tin. Cover and let rise until doubled in size (about an hour).", "equipment_tags": [], "portions": 12, "prep_minutes": 49, "prep_minutes_source": "estimated", "kcal": 521, "protein_g": 7.8, "carbs_g": 71.5, "fat_g": 23.1, "total_kcal": 6257, "total_protein_g": 93.8, "total_carbs_g": 858.3, "total_fat_g": 277.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Start the dough", "instruction": "Heat the milk until lukewarm, then add the yeast and dissolve.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Add sugar and flour", "instruction": "Add the sugar, cardamom, vanilla and about two-thirds of the flour.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Knead", "instruction": "Mix the dough by hand or with a dough hook, gradually adding the rest of the flour. Once it forms a smooth ball, add the softened butter and knead for about 10 minutes.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Shape and prove", "instruction": "Roll into a cylinder and cut into six pieces. Roll each into a round bun in a greased tin, cover, and let rise until doubled in size, about an hour.", "timer_seconds": 3600, "background": true}], "video": "https://www.youtube.com/watch?v=3LvxDuZuPkU"}, {"id": "53121", "name": "Norwegian Potato Lefse", "category": "Side", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/hxcuj01762772827.jpg", "local_image": "53121.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "3 Lbs"}, {"ingredient": "Salt", "measure": "1 teaspoon"}, {"ingredient": "Sugar", "measure": "1 teaspoon"}, {"ingredient": "Melted Butter", "measure": "1/4 cup"}, {"ingredient": "Heavy Cream", "measure": "1/4 cup"}, {"ingredient": "All purpose flour", "measure": "1 1/2 cups"}, {"ingredient": "Flour", "measure": "1/2 cup"}, {"ingredient": "Butter", "measure": "14 tablespoons"}, {"ingredient": "Granulated Sugar", "measure": "3/4 cup"}, {"ingredient": "Heavy Cream", "measure": "1 tablespoon"}], "instructions": "Boil the potatoes. Peel the potatoes while still warm and run them through a potato ricer twice.\r\n▢\r\nLet the potatoes cool in an uncovered bowl in the fridge.\r\n▢\r\nStir the salt, sugar, melted butter, and cream into the riced potatoes.\r\n▢\r\nSlowly add the flour and knead by hand until you get a good consistency. Don't add more flour than necessary! Roll the dough into a long sausage and divide into about 7 or 8 pieces if using an 18 inch griddle. If using a smaller griddle or frying pan, divide the dough into 10 – 12 pieces.\r\n▢\r\nRoll each piece into a ball and then press into a flat circle, using the edges of your hands to form the dough into a nice circle shape without any cracks. This is important, otherwise you won't get round lefser.\r\n▢\r\nHeat up your griddle on medium/high heat.\r\n▢\r\nFlour your rolling surface and roll the lefse dough into a large circle slightly smaller than your griddle or frying pan. Begin rolling with a smooth rolling pin, then switch to a corrugated rolling pin as the lefse gets thinner. Don't use too much flour, as then the edges can become hard.\r\n▢\r\nRoll the lefse onto your lefse stick and then gently unroll it onto your griddle. After a minute or two check the underside of the lefse for brown spots and then use the lefse stick to flip the lefse and cook on the other side.\r\n▢\r\nUse the lefse stick to remove the lefse from the griddle and place it in a folded damp sheet or tablecloth.", "equipment_tags": [], "portions": 12, "prep_minutes": 82, "prep_minutes_source": "estimated", "kcal": 398, "protein_g": 4.8, "carbs_g": 48.7, "fat_g": 20.8, "total_kcal": 4778, "total_protein_g": 57.1, "total_carbs_g": 584.2, "total_fat_g": 249.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Boil and rice the potatoes", "instruction": "Boil the potatoes, peel while still warm, and pass through a potato ricer twice.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cool", "instruction": "Let the potatoes cool in an uncovered bowl in the fridge.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Mix the dough", "instruction": "Stir the salt, sugar, melted butter and cream into the riced potatoes, then slowly add the flour and knead by hand to a good consistency.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Divide and shape", "instruction": "Roll into a long sausage and divide into 7 to 8 pieces for an 18-inch griddle (10 to 12 for a smaller one). Roll each into a ball and press into a flat, crack-free circle.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Heat the griddle", "instruction": "Heat your griddle to medium-high.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Roll thin", "instruction": "Flour your surface and roll each piece into a large circle slightly smaller than the griddle, starting with a smooth rolling pin and switching to a corrugated one as it thins.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Cook", "instruction": "Roll the lefse onto a lefse stick and unroll onto the griddle. Check the underside for brown spots after a minute or two, then flip and cook the other side.", "timer_seconds": null, "background": false}, {"step": 8, "label": "Rest", "instruction": "Remove with the lefse stick and stack in a folded damp cloth.", "timer_seconds": null, "background": false}], "video": "https://www.bing.com/videos/riverview/relatedvideo?q=Norwegian+Potato+Lefse+youtube&mid=72F7D5C128519ADD66CA72F7D5C128519ADD66CA&mcid=A586185F283B4580BF51AB66165F8D94&FORM=VIRE"}, {"id": "53122", "name": "Fiskesuppe (Creamy Norwegian Fish Soup)", "category": "Seafood", "area": "Norway", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/raqjbj1762773035.jpg", "local_image": "53122.jpg", "ingredients": [{"ingredient": "Fish fillet", "measure": "1 lb"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Potatoes", "measure": "2 medium"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Leek", "measure": "1"}, {"ingredient": "Butter", "measure": "3  tablespoons"}, {"ingredient": "Flour", "measure": "5 tablespoons"}, {"ingredient": "Fish Stock", "measure": "4 cups"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Creme Fraiche", "measure": "1 1/4 cup"}, {"ingredient": "Shrimp", "measure": "1 cup"}, {"ingredient": "Chives", "measure": "1 tablespoon"}], "instructions": "▢\r\nCut the fish fillets in cubes or strips. Crush or chop the garlic. Rinse the vegetables and cut into thin strips.\r\n▢\r\nHeat the butter in a pot and add the garlic. Once the garlic starts to turn golden add the flour, whisking well.\r\n▢\r\nAdd the fish stock and continue to whisk until there are no lumps.\r\n▢\r\nAdd the vegetables and milk and bring to a boil. Cook for about 10 minutes.\r\n▢\r\nAdd the crème fraîche (or sour cream). Bring the soup back to a simmer and once the soup begins to bubble again turn off the heat. Keep the soup on the burner and add the fish. Let the fish cook in the hot soup for 5 minutes. If using shrimp, add right before serving.\r\n▢\r\nSprinkle with chives (or dill or parsley) before serving.", "equipment_tags": [], "portions": 6, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 418, "protein_g": 27.9, "carbs_g": 22.9, "fat_g": 23.9, "total_kcal": 2510, "total_protein_g": 167.5, "total_carbs_g": 137.6, "total_fat_g": 143.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep the fish and veg", "instruction": "Cut the fish into cubes or strips, crush or chop the garlic, and cut the vegetables into thin strips.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the roux", "instruction": "Heat the butter in a pot, add the garlic, and once golden, whisk in the flour.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Add the stock", "instruction": "Add the fish stock, whisking until there are no lumps.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Simmer the vegetables", "instruction": "Add the vegetables and milk and bring to a boil. Cook for about 10 minutes.", "timer_seconds": 600, "background": true}, {"step": 5, "label": "Add the fish", "instruction": "Stir in the crème fraîche and bring back to a simmer. Once it begins to bubble, turn off the heat, add the fish, and let it cook in the hot soup for 5 minutes (add shrimp just before serving, if using).", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Serve", "instruction": "Sprinkle with chives, dill or parsley before serving.", "timer_seconds": null, "background": false}], "video": "https://www.bing.com/videos/riverview/relatedvideo?&q=Fiskesuppe+(Creamy+Norwegian+Fish+Soup)+youtube&qpvt=Fiskesuppe+(Creamy+Norwegian+Fish+Soup)+youtube&mid=BA1D06D0C6BB703F9960BA1D06D0C6BB703F9960&&mcid=1B82C46C54684D60AEB9F663316D725F&FORM=VRDGAR"}, {"id": "53123", "name": "Fårikål (Norwegian National Dish)", "category": "Lamb", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ttfxxn1762773067.jpg", "local_image": "53123.jpg", "ingredients": [{"ingredient": "Lamb", "measure": "3 Lbs"}, {"ingredient": "White Cabbage", "measure": "1 head"}, {"ingredient": "Whole black peppercorns", "measure": "3  tablespoons"}, {"ingredient": "Salt", "measure": "3 tsp"}, {"ingredient": "Water", "measure": "1 1/2 cups"}, {"ingredient": "Flour", "measure": "5 tablespoons"}], "instructions": "▢\r\nCut the lamb into large pieces.\r\n▢\r\nSlice the cabbage into large wedges, keeping the core attached.\r\n▢\r\nAdd a layer of lamb pieces to the bottom of a large pot, fatty side down. Sprinkle with peppercorns and salt. Add a layer of cabbage wedges on top. Repeat with more layers of lamb, peppercorns, and cabbage, ending with cabbage on top.\r\n▢\r\nOptional: Sprinkle a couple of tablespoons on top of the lamb for a thicker stew.\r\n▢\r\nAdd water to the pot and bring to a boil. Cover and reduce heat. Cook on low heat for 2 – 3 hours, until the lamb gently falls away from the bone.\r\n▢\r\nServe with boiled potatoes and fresh parsley, covering generously with the fårikål broth.", "equipment_tags": [], "portions": 4, "prep_minutes": 180, "prep_minutes_source": "explicit", "kcal": 1068, "protein_g": 87.3, "carbs_g": 15.5, "fat_g": 71.9, "total_kcal": 4271, "total_protein_g": 349.3, "total_carbs_g": 61.9, "total_fat_g": 287.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Prep", "instruction": "Cut the lamb into large pieces and slice the cabbage into large wedges, keeping the core attached.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Layer the pot", "instruction": "Layer lamb, peppercorns and salt in the bottom of a large pot, then a layer of cabbage. Repeat, ending with cabbage on top.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Simmer", "instruction": "Add water, bring to a boil, cover, reduce the heat, and cook on low for 2 to 3 hours, until the lamb falls away from the bone.", "timer_seconds": 10800, "background": true}, {"step": 4, "label": "Serve", "instruction": "Serve with boiled potatoes and fresh parsley, spooning over plenty of the fårikål broth.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/shorts/2mMT71Knp8E"}, {"id": "53124", "name": "Raspeballer (Norwegian Potato Dumplings)", "category": "Pork", "area": "Norway", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/hhm7xy1763075871.jpg", "local_image": "53124.jpg", "ingredients": [{"ingredient": "Pork knuckle", "measure": "1"}, {"ingredient": "Sausages", "measure": "1"}, {"ingredient": "Potatoes", "measure": "1 lb"}, {"ingredient": "Red Potatoes", "measure": "2 Lbs"}, {"ingredient": "Flour", "measure": "1 1/4 cup"}, {"ingredient": "All purpose flour", "measure": "2 tblsp"}, {"ingredient": "Salt", "measure": "1 teaspoon"}, {"ingredient": "Bouillon Cubes", "measure": "4"}, {"ingredient": "Freshly Chopped Parsley", "measure": "Pinch"}, {"ingredient": "Swede", "measure": "1"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Cream", "measure": "1/4 cup"}, {"ingredient": "Butter", "measure": "1 tblsp"}, {"ingredient": "Nutmeg", "measure": "1 teaspoon"}], "instructions": "Raspeballer & (Optional) Salted Meat\r\n▢\r\nIf you're making pork knuckle, cook it in simmering water for about 3 hours, until the meat falls from the bone. Remove the pork and save the broth to cook the raspeballer.\r\n▢\r\nBoil the boiled potatoes and peel once cooled. Also peel the raw potatoes, and then grate them or run them through a food processor. Use a paper towel to remove some of the moisture from the grated potatoes.\r\n▢\r\nMash the boiled potatoes in a potato ricer or with a masher. Make sure there are no lumps. Add the grated raw potatoes to the mashed potatoes in a large mixing bowl and stir together. Add the barley flour, all purpose flour, and salt and mix together with your hands until the mixture is fully blended.\r\n▢\r\nYou can cook the raspeballer in either vegetable or beef broth, or if you're making pork knuckle, cook them in the broth from the pork knuckle. Bring the broth to a very light simmer – you don't want it to fully boil because then the raspeballer might break apart.\r\n▢\r\nUse a tablespoon dipped in cold water to shape each raspeball in your hand. Try to make them as smooth as possible and then gently drop them into the simmering broth. Dip the tablespoon in a bowl of cold water between each raspeball.\r\n▢\r\nLet the raspeballer simmer for about 30 minutes. If you're making smoked sausage, you can heat the sausage in the same pot with the raspeballer. Top with fresh chopped parsley.\r\n\r\nMashed Rutabaga\r\n▢\r\nPeel the rutabaga and carrots and cut into small pieces. Boil in water for about 30 minutes, or until tender. Then drain the water, add the cream/milk, butter and nutmeg and mash until smooth.\r\n▢\r\nServe alongside the raspeballer and meat.", "equipment_tags": ["FoodProcessor"], "portions": 4, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 682, "protein_g": 21.2, "carbs_g": 106.7, "fat_g": 17.3, "total_kcal": 2729, "total_protein_g": 84.9, "total_carbs_g": 426.9, "total_fat_g": 69.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step": 1, "label": "Cook the pork knuckle (optional)", "instruction": "If using, simmer the pork knuckle in water for about 3 hours, until the meat falls from the bone. Remove the pork and reserve the broth.", "timer_seconds": 10800, "background": true}, {"step": 2, "label": "Prep the potatoes", "instruction": "Boil and peel the potatoes. Peel and grate the raw potatoes, pressing out excess moisture with a paper towel.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the dough", "instruction": "Mash the boiled potatoes until smooth, mix in the grated raw potatoes, then add the barley flour, flour and salt, mixing by hand until fully blended.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Simmer the broth", "instruction": "Bring the broth (vegetable, beef, or the reserved pork broth) to a very light simmer — not a full boil, or the dumplings may break apart.", "timer_seconds": null, "background": true}, {"step": 5, "label": "Shape and cook", "instruction": "Shape each dumpling with a tablespoon dipped in cold water and drop gently into the simmering broth, dipping the spoon between each one. Simmer for about 30 minutes (adding smoked sausage to heat through, if using), then top with parsley.", "timer_seconds": 1800, "background": true}, {"step": 6, "label": "Make the mashed rutabaga", "instruction": "Peel and cube the rutabaga and carrots, and boil for about 30 minutes until tender. Drain, add the cream/milk, butter and nutmeg, and mash until smooth.", "timer_seconds": 1800, "background": true}, {"step": 7, "label": "Serve", "instruction": "Serve the dumplings and meat alongside the mashed rutabaga.", "timer_seconds": null, "background": false}], "video": "https://www.youtube.com/watch?v=2NFNabRkF04"}, {"id": "53125", "name": "Karbonader (Lean Beef Patties) with Caramelized Onions", "category": "Beef", "area": "Norway", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/0bpjb11763075817.jpg", "local_image": "53125.jpg", "ingredients": [{"ingredient": "Onion", "measure": "2"}, {"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Salt", "measure": "1/2 teaspoon"}, {"ingredient": "Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Nutmeg", "measure": "1/2 teaspoon"}, {"ingredient": "Cornstarch", "measure": "1/2 tbs"}, {"ingredient": "Water", "measure": "50 ml"}, {"ingredient": "Butter", "measure": "2 tblsp"}], "instructions": "Grate half an onion and set aside. Slice the rest of the onions and fry in butter on low/medium heat until caramelized.\r\n▢\r\nIn a bowl, mix together ground beef, grated onion, salt, pepper, nutmeg, potato/corn starch, and water.\r\n▢\r\nForm into a sausage and cut 6 patties. Using a knife make a light grid pattern in each patty.\r\n▢\r\nBrown both sides of the karbonader in butter on high heat, then turn down to low heat and fry for another 2 – 3 minutes.\r\n▢\r\nServe the karbonader and onions with potatoes, stewed peas, and brown sauce for dinner, or on a slice of bread for lunch or a snack.", "equipment_tags": [], "portions": 2, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 799, "protein_g": 40.2, "carbs_g": 15.1, "fat_g": 63.5, "total_kcal": 1598, "total_protein_g": 80.3, "total_carbs_g": 30.2, "total_fat_g": 126.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=HDWgGMJqvgw", "cook_steps": [{"step": 1, "label": "Caramelize the onions", "instruction": "Grate half an onion and set aside. Slice the rest and fry in butter over low/medium heat until caramelized.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Mix the patty mixture", "instruction": "In a bowl, mix together the ground beef, grated onion, salt, pepper, nutmeg, potato/corn starch and water.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Shape the patties", "instruction": "Form into a sausage and cut into 6 patties, scoring a light grid pattern in each with a knife.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fry the patties", "instruction": "Brown both sides of the patties in butter over high heat, then turn down to low and fry for another 2 to 3 minutes.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Serve", "instruction": "Serve the karbonader and onions with potatoes, stewed peas and brown sauce for dinner, or on a slice of bread for lunch or a snack.", "timer_seconds": null, "background": false}]}, {"id": "53126", "name": "Brun Lapskaus (Norwegian Beef Vegetable Stew)", "category": "Beef", "area": "Norway", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/6vi2cv1763075785.jpg", "local_image": "53126.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Beef", "measure": "2 Lbs"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Beef Stock", "measure": "3 Cups"}, {"ingredient": "Swede", "measure": "1 small"}, {"ingredient": "Celery", "measure": "1"}, {"ingredient": "Carrots", "measure": "4"}, {"ingredient": "Parsley", "measure": "4"}, {"ingredient": "Potatoes", "measure": "1 lb"}, {"ingredient": "Leek", "measure": "1/2"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "▢\r\nHeat olive oil in a large pot. Cut beef into 1 inch (2.5 cm) cubes and brown in oil.\r\n▢\r\nDice the onion and add to browning beef. Add the stock and bring to a boil, then lower the heat, cover, and let simmer for about 30 minutes.\r\n▢\r\nPeel and cut the rutabaga and celery root into 1 inch (2.5 cm) cubes. Add to the pot, cover, and continue simmering for another 30 minutes.\r\n▢\r\nPeel and chop the rest of the vegetables into 1 inch (2.5 cm) cubes and add to the pot. Slice the leek into rings. Cover and continue simmering for about 20 minutes. Stir as little as possible.\r\n▢\r\nTop with fresh parsley.", "equipment_tags": [], "portions": 6, "prep_minutes": 80, "prep_minutes_source": "explicit", "kcal": 422, "protein_g": 34.3, "carbs_g": 23.3, "fat_g": 21.9, "total_kcal": 2529, "total_protein_g": 205.7, "total_carbs_g": 139.9, "total_fat_g": 131.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=VuLnP0Yu84o", "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "Heat the olive oil in a large pot. Cut the beef into 1-inch (2.5cm) cubes and brown in the oil.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Start the stew", "instruction": "Dice the onion and add to the browning beef. Add the stock, bring to a boil, then lower the heat, cover, and simmer for about 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Add the root vegetables", "instruction": "Peel and cut the rutabaga and celery root into 1-inch cubes. Add to the pot, cover, and continue simmering for another 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Add the rest", "instruction": "Peel and chop the remaining vegetables into 1-inch cubes and add to the pot. Slice the leek into rings. Cover and continue simmering for about 20 minutes, stirring as little as possible.", "timer_seconds": 1200, "background": true}, {"step": 5, "label": "Serve", "instruction": "Top with fresh parsley.", "timer_seconds": null, "background": false}]}, {"id": "53127", "name": "Authentic Norwegian Kransekake", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yk78uc1763075719.jpg", "local_image": "53127.jpg", "ingredients": [{"ingredient": "Almonds", "measure": "3 Cups"}, {"ingredient": "Egg White", "measure": "4"}, {"ingredient": "Powdered Sugar", "measure": "4 cups"}, {"ingredient": "Powdered Sugar", "measure": "2 cups"}, {"ingredient": "Egg White", "measure": "1"}, {"ingredient": "Lemon Juice", "measure": "1/2 teaspoon"}], "instructions": "Grind almonds in an almond grinder or food processor.\r\n▢\r\nMix almonds and powdered sugar together in a large mixing bowl. Add three of the egg whites and knead the dough together with your hands until it comes together in a ball. Wrap in cling film and leave in the fridge for at least an hour, preferably until the next day.\r\n▢\r\nGrease the kransekake forms thoroughly and coat with semolina, flour, or bread crumbs.\r\n▢\r\nPreheat oven to 210°C (410°F) top and bottom heat. Divide the dough into six sections.\r\n▢\r\nSlowly add the remaining egg white to the dough and knead it until you can roll it into long sausages about as thick as your index finger. Fill the forms with the dough sausages, pinching the ends together to make rings.\r\n▢\r\nSet the forms on a baking sheet and back in the middle of the oven for about 10 – 12 minutes, until the tops are golden brown.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 12, "prep_minutes_source": "explicit", "kcal": 753, "protein_g": 14.9, "carbs_g": 115.4, "fat_g": 30.0, "total_kcal": 9036, "total_protein_g": 178.7, "total_carbs_g": 1384.3, "total_fat_g": 360.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=fE85ioKQ7ew", "cook_steps": [{"step": 1, "label": "Grind the almonds", "instruction": "Grind the almonds in an almond grinder or food processor.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the dough", "instruction": "Mix the ground almonds and powdered sugar in a large bowl. Add three of the egg whites and knead with your hands until it comes together in a ball. Wrap in cling film and chill for at least an hour, preferably overnight.", "timer_seconds": 3600, "background": true}, {"step": 3, "label": "Prep the forms", "instruction": "Grease the kransekake forms thoroughly and coat with semolina, flour or breadcrumbs.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Preheat and divide", "instruction": "Preheat the oven to 210°C (410°F). Divide the dough into six sections.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Shape the rings", "instruction": "Slowly add the remaining egg white to the dough and knead until you can roll it into long, finger-thick sausages. Fill the forms with the dough, pinching the ends together to make rings.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Bake", "instruction": "Set the forms on a baking sheet and bake in the middle of the oven for about 10 to 12 minutes, until golden brown on top.", "timer_seconds": 720, "background": true}]}, {"id": "53128", "name": "Kvæfjord Cake “Verdens Beste” (World’s Best Cake)", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/gdn1ot1763075684.jpg", "local_image": "53128.jpg", "ingredients": [{"ingredient": "Egg Yolks", "measure": "2 large"}, {"ingredient": "Cornstarch", "measure": "2 tblsp"}, {"ingredient": "Granulated Sugar", "measure": "1/4 cup"}, {"ingredient": "Heavy Cream", "measure": "2/3 Cup"}, {"ingredient": "Milk", "measure": "3/4 cup"}, {"ingredient": "vanilla pod", "measure": "1"}, {"ingredient": "Butter", "measure": "2/3 Cup"}, {"ingredient": "Granulated Sugar", "measure": "3/4 cup"}, {"ingredient": "Egg Yolks", "measure": "5 Large"}, {"ingredient": "Flour", "measure": "1 1/4 cup"}, {"ingredient": "Baking Powder", "measure": "1.5 tsp"}, {"ingredient": "Milk", "measure": "1/2 cup"}, {"ingredient": "Egg White", "measure": "7"}, {"ingredient": "Granulated Sugar", "measure": "1 1/2 cups"}, {"ingredient": "Almonds", "measure": "Sliced"}, {"ingredient": "Whipping Cream", "measure": "1 1/4 cup"}], "instructions": "Vanilla custard\r\n▢\r\nSeparate the egg yolks and set aside the whites to use in the meringue.\r\n▢\r\nWhisk together the egg yolks, cornstarch and sugar in a bowl.\r\n▢\r\nHeat the cream and milk in a saucepan. Split open the vanilla pod and add the beans to the saucepan. Once the milk begins to bubble pour about half of it into the bowl with the egg mixture, whisking constantly. Then return the saucepan to the heat and pour the egg mixture back into the saucepan with remaining milk, whisking constantly. Once the mixture thickens lower the heat and continue whisking for about 30 seconds.\r\n▢\r\nPour the custard into a clean bowl and cover with plastic wrap, placing the plastic directly on the top layer of the custard. Chill in the fridge.\r\nCake\r\n▢\r\nMix together butter and sugar until light and fluffy. Add egg yolks one at a time, setting aside the egg whites for the meringue. Add the flour mixed with baking powder. Stir in the milk, beating until smooth (you can use an electric mixer if you prefer).\r\n▢\r\nPreheat oven to 320°F (160°C). Cover a baking sheet with baking paper and spread out the batter into a large, even rectangle.\r\nMeringue topping\r\n▢\r\nWhisk together the egg whites and sugar until you get glossy, stiff peaks. The meringue should hold its form – if it still melts continue whisking.\r\n▢\r\nSpread out the meringue on top of the cake batter. Use a spatula to form light waves with the meringue. Sprinkle almonds on top of the meringue. Bake for about 30 minutes, until the meringue and almonds are golden.\r\nCream filling\r\n▢\r\nWhisk the cream into stiff peaks. Carefully fold in the vanilla custard.\r\nAssembly\r\n▢\r\nOnce the cake has cooled, cut it in half. You can use scissors for this, or a knife on a cutting board, slicing through the baking paper as well.\r\n▢\r\nPlace half of the cake on a serving platter with the meringue side down and peel off the baking paper.\r\n▢\r\nSpread the cream filling across the cake. Then carefully remove the other half of the cake from the baking paper and place it over the cream filling, meringue side up.\r\n▢\r\nServe with fresh berries.\r\n\r\n", "equipment_tags": [], "portions": 12, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 606, "protein_g": 11.5, "carbs_g": 59.6, "fat_g": 35.5, "total_kcal": 7276, "total_protein_g": 137.6, "total_carbs_g": 715.0, "total_fat_g": 425.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=FjQRhFS3aZU", "cook_steps": [{"step": 1, "label": "Make the custard base", "instruction": "Separate the egg yolks, reserving the whites for the meringue, and whisk the yolks with the cornstarch and sugar in a bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the custard", "instruction": "Heat the cream and milk with the split vanilla pod. Once bubbling, whisk half into the egg mixture, then return everything to the pan and whisk over the heat until thickened, about 30 seconds more.", "timer_seconds": 30, "background": false}, {"step": 3, "label": "Chill the custard", "instruction": "Pour into a clean bowl, cover with plastic wrap directly on the surface, and chill in the fridge.", "timer_seconds": null, "background": true}, {"step": 4, "label": "Make the cake batter", "instruction": "Mix the butter and sugar until light and fluffy, add the egg yolks one at a time (reserving the whites for the meringue), then beat in the flour mixed with baking powder and the milk until smooth.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Spread and preheat", "instruction": "Preheat the oven to 320°F (160°C). Spread the batter into a large, even rectangle on a lined baking sheet.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Make the meringue", "instruction": "Whisk the reserved egg whites and sugar to glossy, stiff peaks.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Top and bake", "instruction": "Spread the meringue over the cake batter, forming light waves with a spatula, and sprinkle with almonds. Bake for about 30 minutes, until the meringue and almonds are golden.", "timer_seconds": 1800, "background": true}, {"step": 8, "label": "Whip the cream filling", "instruction": "Whisk the cream to stiff peaks, then carefully fold in the chilled vanilla custard.", "timer_seconds": null, "background": false}, {"step": 9, "label": "Assemble", "instruction": "Once the cake has cooled, cut it in half. Place one half meringue-side down on a platter and peel off the baking paper.", "timer_seconds": null, "background": false}, {"step": 10, "label": "Fill and finish", "instruction": "Spread the cream filling over the cake, then place the other half on top, meringue-side up. Serve with fresh berries.", "timer_seconds": null, "background": false}]}, {"id": "53129", "name": "Norwegian Krumkake", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/z9g8011763075640.jpg", "local_image": "53129.jpg", "ingredients": [{"ingredient": "Egg", "measure": "3 Large"}, {"ingredient": "Sugar", "measure": "3/4 cup"}, {"ingredient": "Butter", "measure": "2/3 Cup"}, {"ingredient": "Cardamom", "measure": "1 teaspoon"}, {"ingredient": "Nutmeg", "measure": "1 pinch"}, {"ingredient": "Salt", "measure": "1/2 teaspoon"}, {"ingredient": "Flour", "measure": "1 1/4 cup"}, {"ingredient": "Water", "measure": "Splash"}], "instructions": "▢\r\nWhisk the egg and sugar until the mixture thickens.\r\n▢\r\nMelt the butter and let it cool slightly, then add the butter to the egg mixture.\r\n▢\r\nMix in spices and then slowly add the flour while stirring to avoid lumps. \r\n▢\r\nLet the batter rest for at least 30 minutes. This improves the texture of the krumkaker.\r\n▢\r\nSpoon about one heaping tablespoon of batter onto iron and bake. If the batter is too thick, add some water to it.\r\n▢\r\nWhile still hot, shape the krumkake with a wooden krumkake roller or over a cup (if using a cup, make them a bit thicker). The krumkaker harden quickly, so you can just let them sit on the roller/cup until the next krumkake is ready to be shaped. \r\n▢\r\nAfter completely cooled, store the krumkaker in a metal or glass tin lined with paper towels at the bottom. You can also freeze them!", "equipment_tags": [], "portions": 4, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 626, "protein_g": 9.3, "carbs_g": 69.8, "fat_g": 35.4, "total_kcal": 2505, "total_protein_g": 37.4, "total_carbs_g": 279.3, "total_fat_g": 141.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=7JXuI2V2MLg", "cook_steps": [{"step": 1, "label": "Make the batter", "instruction": "Whisk the egg and sugar until thickened. Melt the butter, let it cool slightly, then stir into the egg mixture.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Finish the batter", "instruction": "Mix in the spices, then slowly stir in the flour to avoid lumps.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Rest the batter", "instruction": "Let the batter rest for at least 30 minutes — this improves the texture of the krumkaker.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Bake", "instruction": "Spoon about a heaping tablespoon of batter onto the iron and bake, thinning the batter with a little water if it's too thick.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Shape while hot", "instruction": "While still hot, shape the krumkake around a wooden roller or over a cup. They harden quickly, so leave each on the roller/cup until the next one is ready to shape.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Store", "instruction": "Once completely cooled, store in a metal or glass tin lined with paper towels, or freeze.", "timer_seconds": null, "background": false}]}, {"id": "53130", "name": "Suksessterte (Norwegian almond “success cake”)", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/de83k51763075604.jpg", "local_image": "53130.jpg", "ingredients": [{"ingredient": "Almonds", "measure": "2 cups"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Granulated Sugar", "measure": "1 1/4 cup"}, {"ingredient": "Flour", "measure": "2 tblsp"}, {"ingredient": "Baking Powder", "measure": "1 teaspoon"}, {"ingredient": "Egg Yolks", "measure": "5"}, {"ingredient": "Heavy Cream", "measure": "1/2 cup"}, {"ingredient": "Granulated Sugar", "measure": "1/3 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 teaspoon"}, {"ingredient": "Butter", "measure": "100g"}], "instructions": "Almond base\r\n▢\r\nPreheat oven to 345°F (175°C) and grease cake form (I use a 27 cm spring form) – you can line the bottom with baking paper if you like.\r\n▢\r\nGrind almonds in an almond grinder or food processor. I like to keep them a bit coarse.\r\n▢\r\nGently whisk the eggs and sugar together until combined (no longer). Stir in the ground almonds, flour, and baking powder.\r\n▢\r\nPour batter into cake form and bake for about 45 – 50 minutes, monitoring to make sure the top doesn't burn.\r\nYellow egg cream\r\n▢\r\nAdd egg yolks, heavy cream, sugar, and vanilla to a saucepan. Heat over low/medium heat while stirring constantly until the mixture thickens – about 15 minutes. Turn up the heat if the mixture doesn't thicken, but be careful not to boil.\r\n▢\r\nLet the mixture cool to room temperature and then add the butter. You can use an electric mixer for a fluffy egg cream.\r\nAssembly\r\n▢\r\nWait for the cake to cool completely before removing from form and frosting.", "equipment_tags": ["FoodProcessor"], "portions": 10, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 638, "protein_g": 16.6, "carbs_g": 45.7, "fat_g": 46.1, "total_kcal": 6379, "total_protein_g": 166.2, "total_carbs_g": 456.7, "total_fat_g": 461.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=LgIQXxkOrMM", "cook_steps": [{"step": 1, "label": "Prep the tin", "instruction": "Preheat the oven to 345°F (175°C) and grease your cake tin (a 27cm springform works well).", "timer_seconds": null, "background": false}, {"step": 2, "label": "Grind the almonds", "instruction": "Grind the almonds in an almond grinder or food processor, keeping them a little coarse.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Mix the batter", "instruction": "Gently whisk the eggs and sugar together just until combined, then stir in the ground almonds, flour and baking powder.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake the base", "instruction": "Pour the batter into the tin and bake for about 45 to 50 minutes, checking that the top doesn't burn.", "timer_seconds": 3000, "background": true}, {"step": 5, "label": "Make the egg cream", "instruction": "Add the egg yolks, cream, sugar and vanilla to a saucepan and heat over low/medium heat, stirring constantly, until thickened, about 15 minutes (raise the heat a little if it won't thicken, but don't let it boil).", "timer_seconds": 900, "background": false}, {"step": 6, "label": "Finish the cream", "instruction": "Let the mixture cool to room temperature, then beat in the butter — an electric mixer gives a fluffier cream.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Assemble", "instruction": "Wait for the cake to cool completely before removing it from the tin and frosting with the egg cream.", "timer_seconds": null, "background": false}]}, {"id": "53131", "name": "Fyrstekake – Norwegian Prince Cake", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/9zqrod1763075574.jpg", "local_image": "53131.jpg", "ingredients": [{"ingredient": "Granulated Sugar", "measure": "3/4 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 teaspoon"}, {"ingredient": "Butter", "measure": "2/3 Cup"}, {"ingredient": "Egg Yolks", "measure": "4"}, {"ingredient": "Flour", "measure": "2 cups"}, {"ingredient": "Baking Powder", "measure": "1 teaspoon"}, {"ingredient": "Almonds", "measure": "1 1/2 cups"}, {"ingredient": "Brown Sugar", "measure": "3/4 cup"}, {"ingredient": "Melted Butter", "measure": "2 tbsp"}, {"ingredient": "Egg", "measure": "2 medium"}, {"ingredient": "Brandy", "measure": "2 tablespoons"}, {"ingredient": "Almond Extract", "measure": "5 drops"}, {"ingredient": "Egg", "measure": "1"}], "instructions": "Crust\r\n▢\r\nMix together sugar, vanilla and butter until light and fluffy. Mix in the egg yolks. Add in the flour and baking powder and knead with hands until the dough is smooth.\r\n▢\r\nPack the dough in plastic wrap and chill in refrigerator for at least 30 minutes.\r\n\r\nAlmond filling\r\n▢\r\nRun the almonds and sugar together in a food processor until the almonds are finely ground (you can decide for yourself how coarse or fine you want them).\r\n▢\r\nStir in the butter, egg, cognac and/or almond extract (if using).\r\nAssembly\r\n▢\r\nLine the bottom of your cake form with baking paper and grease the sides of the form.\r\n▢\r\nPreheat oven to 350°F (175°C).\r\n▢\r\nCut 2/3 of the crust dough into slices and press down into the cake form. Cover the bottom of the cake form with the dough and bring the dough 2-3 cm (1 inch) up the sides of the form, pressing until even.\r\n▢\r\nScoop the almond filling on top of the crust, spreading it evenly across the cake form.\r\n▢\r\nRoll out of the rest of the dough and slice into long strips. Lay the strips of dough across the cake in a grid. Don't worry of the strips break – simply press them back together on the cake.\r\n▢\r\nGently brush the dough with egg wash.\r\n▢\r\nBake for about 45 minutes. The top of the cake should be golden brown while the almond filling will remain soft.", "equipment_tags": ["FoodProcessor"], "portions": 10, "prep_minutes": 75, "prep_minutes_source": "explicit", "kcal": 645, "protein_g": 15.4, "carbs_g": 58.7, "fat_g": 39.9, "total_kcal": 6454, "total_protein_g": 154.2, "total_carbs_g": 587.2, "total_fat_g": 399.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=MBh7sQcdzwo", "cook_steps": [{"step": 1, "label": "Make the crust dough", "instruction": "Mix the sugar, vanilla and butter until light and fluffy, then mix in the egg yolks. Add the flour and baking powder and knead by hand until smooth.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Chill the dough", "instruction": "Wrap in plastic and chill in the fridge for at least 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Make the almond filling", "instruction": "Process the almonds and sugar together until finely ground, then stir in the butter, egg, and cognac and/or almond extract if using.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Line the tin", "instruction": "Line the base of your cake tin with baking paper and grease the sides. Preheat the oven to 350°F (175°C).", "timer_seconds": null, "background": false}, {"step": 5, "label": "Build the base", "instruction": "Slice two-thirds of the crust dough and press into the tin, bringing it 2 to 3cm up the sides.", "timer_seconds": null, "background": false}, {"step": 6, "label": "Fill and lattice", "instruction": "Spread the almond filling evenly over the crust. Roll out the rest of the dough, slice into strips, and lay across the cake in a grid — don't worry if they break, just press back together.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Glaze and bake", "instruction": "Gently brush the dough with egg wash and bake for about 45 minutes, until the top is golden brown and the filling still soft.", "timer_seconds": 2700, "background": true}]}, {"id": "53132", "name": "Mazariner – Scandinavian Almond Tartlets", "category": "Dessert", "area": "Norway", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uh1n5u1763075545.jpg", "local_image": "53132.jpg", "ingredients": [{"ingredient": "Flour", "measure": "3 Cups"}, {"ingredient": "Powdered Sugar", "measure": "1 1/4 cup"}, {"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Powdered Sugar", "measure": "1 1/4 cup"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Vanilla Extract", "measure": "2 teaspoons"}, {"ingredient": "Flour", "measure": "2 tblsp"}, {"ingredient": "Almond Flour", "measure": "2 cups"}, {"ingredient": "Almond Extract", "measure": "1 teaspoon"}, {"ingredient": "Powdered Sugar", "measure": "2 cups"}, {"ingredient": "Heavy Cream", "measure": "3  tablespoons"}, {"ingredient": "Almond Extract", "measure": "1/4 tsp"}], "instructions": "Shells\r\n▢\r\nCombine the flour and powdered sugar in a food processor. Add the butter and pulse until it's evenly distributed. Add the egg and pulse until the dough comes together.\r\n▢\r\nRoll out the dough on a floured surface. Cut the dough in circles with a large mug. Press the circles down into a greased muffin pan. Put the pan of shells in the fridge while you prepare the almond filling.\r\nAlmond filling\r\n▢\r\nPreheat oven to 355°F (180°C).\r\n▢\r\nWhisk the egg and powdered sugar together until thick and airy. Melt the butter and stir it into the egg mixture. Stir in the vanilla, flour, and almond extract. Stir in the almond flour.\r\n▢\r\nPipe or spoon the almond filling onto the shells, filling the shells about 3/4 full.\r\n▢\r\nBake the mazariner for 20 – 25 minutes, until light golden brown. Cool on a wire rack.\r\nGlaze\r\n▢\r\nMix together the powdered sugar and liquid until you get a spreadable glaze. Spread the glaze on top of the mazariner and if you wish, decorate with sprinkles, or anything you like.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 718, "protein_g": 7.9, "carbs_g": 118.3, "fat_g": 24.3, "total_kcal": 8611, "total_protein_g": 95.2, "total_carbs_g": 1419.1, "total_fat_g": 291.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=ZpZ_8mcmNLI", "cook_steps": [{"step": 1, "label": "Make the shells", "instruction": "Combine the flour and powdered sugar in a food processor, add the butter and pulse until distributed, then add the egg and pulse until the dough comes together.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Shape the shells", "instruction": "Roll out the dough and cut into circles with a large mug. Press into a greased muffin pan and chill while you make the filling.", "timer_seconds": null, "background": true}, {"step": 3, "label": "Preheat", "instruction": "Preheat the oven to 355°F (180°C).", "timer_seconds": null, "background": false}, {"step": 4, "label": "Make the filling", "instruction": "Whisk the egg and powdered sugar until thick and airy. Melt the butter and stir it in, then stir in the vanilla, flour, almond extract and almond flour.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Fill and bake", "instruction": "Pipe or spoon the filling into the shells, filling about three-quarters full, and bake for 20 to 25 minutes until light golden brown. Cool on a wire rack.", "timer_seconds": 1500, "background": true}, {"step": 6, "label": "Glaze", "instruction": "Mix the powdered sugar and liquid to a spreadable glaze, spread over the mazariner, and decorate as you like.", "timer_seconds": null, "background": false}]}, {"id": "53133", "name": "Asado", "category": "Beef", "area": "Argentina", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/kgfh3q1763075438.jpg", "local_image": "53133.jpg", "ingredients": [{"ingredient": "Mixed Beef Cuts", "measure": "2kg"}, {"ingredient": "Chorizo", "measure": "4"}, {"ingredient": "Morcilla", "measure": "2"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "Prepare the Fire: Start a wood fire in your grill and let it burn down to coals.\r\nSeason the Meat: Generously salt the beef cuts.\r\nGrill the Meat: Place the beef on the grill, starting with the thickest cuts farthest from the coals. Add chorizo and morcilla after the beef has been cooking for a while.\r\nCook to Perfection: Cook the meat, turning occasionally, until it reaches your desired doneness. Typically, ribs may take up to 2 hours; thinner cuts will cook faster.\r\nRest and Serve: Let the meat rest for about 10 minutes before slicing. Serve with chimichurri sauce and grilled vegetables.\r\nPro Tips:\r\n\r\nUse a mix of wood and charcoal for a consistent heat source. Wood adds flavor, while charcoal maintains temperature.\r\nSeason the meat just before grilling to ensure it retains its moisture and flavor.\r\nServing Suggestions:\r\n\r\nServe with a side of chimichurri sauce, a fresh tomato salad, and crusty bread. Pair with a robust Malbec wine to complement the rich flavors of the meat.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 130, "prep_minutes_source": "explicit", "kcal": 963, "protein_g": 92.6, "carbs_g": 3.8, "fat_g": 63.6, "total_kcal": 4815, "total_protein_g": 463.0, "total_carbs_g": 18.8, "total_fat_g": 318.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=q5f6Z6i1hQ8", "cook_steps": [{"step": 1, "label": "Prepare the fire", "instruction": "Start a wood fire in your grill and let it burn down to coals.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Season the meat", "instruction": "Generously salt the beef cuts.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Grill the meat", "instruction": "Place the beef on the grill, starting with the thickest cuts farthest from the coals. Add the chorizo and morcilla once the beef has been cooking for a while.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook to perfection", "instruction": "Cook the meat, turning occasionally, until it reaches your desired doneness — ribs can take up to 2 hours, thinner cuts will cook faster.", "timer_seconds": 7200, "background": true}, {"step": 5, "label": "Rest and serve", "instruction": "Let the meat rest for about 10 minutes before slicing. Serve with chimichurri sauce and grilled vegetables.", "timer_seconds": 600, "background": false}]}, {"id": "53134", "name": "Empanadas", "category": "Beef", "area": "Argentina", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/q99te31763075494.jpg", "local_image": "53134.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "500g"}, {"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Water", "measure": "120ml"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Ground Beef", "measure": "500g"}, {"ingredient": "Onion", "measure": "2 chopped"}, {"ingredient": "Egg", "measure": "4 Chopped"}, {"ingredient": "Green Olives", "measure": "100g"}, {"ingredient": "Cumin", "measure": "1 teaspoon"}, {"ingredient": "Paprika", "measure": "1 teaspoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Make the Dough: Mix flour and salt in a large bowl. Add butter, using your fingers to blend into a crumbly texture. Gradually add water, mixing until a dough forms. Wrap and chill for 30 minutes.\r\nPrepare the Filling: Cook onions in a pan until translucent. Add ground beef, cooking until browned. Stir in spices, then remove from heat. Once cooled, mix in eggs and olives.\r\nAssemble: Roll out the dough and cut into circles. Place a spoonful of filling in each, fold over, and seal the edges.\r\nCook: Bake at 200°C (400°F) for 20-25 minutes, or until golden.\r\nPro Tips:\r\n\r\nFor a flakier crust, incorporate a tablespoon of vinegar into the dough mixture. This helps prevent gluten formation.\r\nSeal the edges of the empanadas with a fork to ensure they do not open during baking or frying.", "equipment_tags": [], "portions": 4, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 1270, "protein_g": 42.0, "carbs_g": 103.0, "fat_g": 76.0, "total_kcal": 5078, "total_protein_g": 167.9, "total_carbs_g": 412.2, "total_fat_g": 304.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=RRNVLC6IAv4", "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Mix the flour and salt in a large bowl. Blend in the butter with your fingers to a crumbly texture, then gradually add water, mixing until a dough forms. Wrap and chill for 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Prepare the filling", "instruction": "Cook the onions until translucent, add the ground beef and cook until browned, then stir in the spices and remove from the heat. Once cooled, mix in the eggs and olives.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Assemble", "instruction": "Roll out the dough and cut into circles. Place a spoonful of filling in each, fold over, and seal the edges.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Bake", "instruction": "Bake at 200°C (400°F) for 20 to 25 minutes, or until golden.", "timer_seconds": 1500, "background": true}]}, {"id": "53135", "name": "Milanesa", "category": "Beef", "area": "Argentina", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/wdfa171763065079.jpg", "local_image": "53135.jpg", "ingredients": [{"ingredient": "Beef Cutlet", "measure": "4"}, {"ingredient": "Egg", "measure": "2 Beaten"}, {"ingredient": "Breadcrumbs", "measure": "200g"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Season the Cutlets: Salt and pepper the cutlets.\r\nBread the Cutlets: Dip each cutlet in egg, then coat with a mixture of breadcrumbs, parsley, and garlic.\r\nFry: Heat oil in a large pan over medium heat. Fry the cutlets until golden and cooked through, about 3-4 minutes per side.\r\nServe: Serve hot with lemon wedges or a side salad.\r\nPro Tips:\r\n\r\nFor an extra crispy crust, use panko breadcrumbs mixed with finely grated Parmesan cheese.\r\nGently pound the cutlets to an even thickness for uniform cooking.", "equipment_tags": [], "portions": 1, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 1315, "protein_g": 80.4, "carbs_g": 149.6, "fat_g": 43.3, "total_kcal": 1315, "total_protein_g": 80.4, "total_carbs_g": 149.6, "total_fat_g": 43.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=_G3cyucbB3o", "cook_steps": [{"step": 1, "label": "Season the cutlets", "instruction": "Salt and pepper the cutlets.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bread the cutlets", "instruction": "Dip each cutlet in egg, then coat with a mixture of breadcrumbs, parsley and garlic.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fry", "instruction": "Heat oil in a large pan over medium heat and fry the cutlets until golden and cooked through, about 3 to 4 minutes per side.", "timer_seconds": 240, "background": false}, {"step": 4, "label": "Serve", "instruction": "Serve hot with lemon wedges or a side salad.", "timer_seconds": null, "background": false}]}, {"id": "53136", "name": "Choripán", "category": "Pork", "area": "Argentina", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/5i25sg1763075353.jpg", "local_image": "53136.jpg", "ingredients": [{"ingredient": "Chorizo", "measure": "4"}, {"ingredient": "Crusty Bread", "measure": "4"}, {"ingredient": "Chimichurri sauce", "measure": "Drizzle"}], "instructions": "Grill the Chorizos: Cook the chorizos on a grill or pan until fully cooked, about 10-15 minutes.\r\nPrepare the Rolls: Slice the rolls and toast them lightly on the grill or in a pan.\r\nAssemble: Slice each chorizo lengthwise and place in a roll. Top with a generous amount of chimichurri sauce.\r\nServe: Enjoy immediately while hot.\r\nPro Tips:\r\n\r\nGrill the chorizo slowly on medium heat to prevent the skin from bursting and to ensure it cooks evenly throughout.\r\nToast the bread on the grill to absorb some of the chorizo's flavors.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 1524, "protein_g": 66.3, "carbs_g": 103.0, "fat_g": 91.1, "total_kcal": 1524, "total_protein_g": 66.3, "total_carbs_g": 103.0, "total_fat_g": 91.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=FNrU5mQKFOE", "cook_steps": [{"step": 1, "label": "Grill the chorizos", "instruction": "Cook the chorizos on a grill or pan until fully cooked, about 10 to 15 minutes.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Prepare the rolls", "instruction": "Slice the rolls and toast lightly on the grill or in a pan.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Assemble", "instruction": "Slice each chorizo lengthwise and place in a roll. Top with a generous amount of chimichurri sauce.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Enjoy immediately while hot.", "timer_seconds": null, "background": false}]}, {"id": "53137", "name": "Dulce de Leche", "category": "Dessert", "area": "Argentina", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/jyjlhj1763075323.jpg", "local_image": "53137.jpg", "ingredients": [{"ingredient": "Milk", "measure": "1 Litre"}, {"ingredient": "Sugar", "measure": "300g"}, {"ingredient": "Baking Powder", "measure": "1/4 tsp"}, {"ingredient": "Vanilla Extract", "measure": "1 teaspoon"}], "instructions": "Combine Ingredients: In a large, heavy-bottomed pot, mix the milk, sugar, and baking soda. Cook over low heat, stirring constantly to prevent burning.\r\nThicken: Continue to cook, stirring frequently, until the mixture becomes thick and caramel-colored, about 1-2 hours.\r\nFlavor: Stir in the vanilla extract.\r\nCool: Let the dulce de leche cool, then transfer to a jar. It will thicken further as it cools.\r\nPro Tips:\r\n\r\nStir continuously and keep the heat low to prevent the milk from burning and sticking to the bottom of the pan.\r\nA drop of vanilla extract added at the end of cooking enhances the flavor.", "equipment_tags": [], "portions": 9, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 198, "protein_g": 3.6, "carbs_g": 38.8, "fat_g": 3.7, "total_kcal": 1786, "total_protein_g": 32.0, "total_carbs_g": 349.0, "total_fat_g": 33.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=2J0ICGYsBL4", "cook_steps": [{"step": 1, "label": "Combine", "instruction": "In a large, heavy-bottomed pot, mix the milk, sugar and baking soda. Cook over low heat, stirring constantly to prevent burning.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Thicken", "instruction": "Continue cooking, stirring frequently, until the mixture becomes thick and caramel-colored, about 1 to 2 hours.", "timer_seconds": 7200, "background": false}, {"step": 3, "label": "Flavor", "instruction": "Stir in the vanilla extract.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cool", "instruction": "Let the dulce de leche cool, then transfer to a jar — it will thicken further as it cools.", "timer_seconds": null, "background": true}]}, {"id": "53138", "name": "Alfajores", "category": "Dessert", "area": "Argentina", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/a4kgf21763075288.jpg", "local_image": "53138.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "300g"}, {"ingredient": "Cornstarch", "measure": "200g"}, {"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Sugar", "measure": "100g"}, {"ingredient": "Egg Yolks", "measure": "2"}, {"ingredient": "Lemon Zest", "measure": "1 teaspoon"}, {"ingredient": "Dulce de leche", "measure": ""}, {"ingredient": "Desiccated Coconut", "measure": "Sprinkling"}], "instructions": "Make the Dough: Cream butter and sugar. Add egg yolks and lemon zest. Gradually mix in flour and cornstarch to form a dough. Chill for 1 hour.\r\nBake the Cookies: Roll out the dough, cut into circles, and bake at 180°C (350°F) for 12-15 minutes. Let cool.\r\nAssemble: Spread dulce de leche on one cookie, then sandwich with another. Roll the edges in coconut flakes.\r\nPro Tips:\r\n\r\nChill the dough before rolling it out to make it easier to handle and to prevent the cookies from spreading too much while baking.\r\nDip the alfajores in melted chocolate and let them set on a wire rack for an extra decadent treat.", "equipment_tags": [], "portions": 6, "prep_minutes": 75, "prep_minutes_source": "explicit", "kcal": 700, "protein_g": 8.4, "carbs_g": 87.0, "fat_g": 35.3, "total_kcal": 4200, "total_protein_g": 50.6, "total_carbs_g": 522.0, "total_fat_g": 211.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=9WR40GHpsyo", "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Cream the butter and sugar, add the egg yolks and lemon zest, then gradually mix in the flour and cornstarch to form a dough. Chill for 1 hour.", "timer_seconds": 3600, "background": true}, {"step": 2, "label": "Bake the cookies", "instruction": "Roll out the dough, cut into circles, and bake at 180°C (350°F) for 12 to 15 minutes. Let cool.", "timer_seconds": 900, "background": true}, {"step": 3, "label": "Assemble", "instruction": "Spread dulce de leche on one cookie, then sandwich with another. Roll the edges in coconut flakes.", "timer_seconds": null, "background": false}]}, {"id": "53139", "name": "Fainá", "category": "Side", "area": "Argentina", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/849jd81763075251.jpg", "local_image": "53139.jpg", "ingredients": [{"ingredient": "Chickpea Flour", "measure": "200g"}, {"ingredient": "Water", "measure": "600ml"}, {"ingredient": "Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Prepare the Batter: Whisk together chickpea flour, water, salt, and pepper. Let sit for at least 4 hours.\r\nBake: Preheat the oven to 220°C (430°F). Pour olive oil into a round baking dish and heat in the oven. Pour in the batter and bake for 25-30 minutes, until golden.\r\nServe: Slice and serve hot, optionally with black pepper on top.\r\nPro Tips:\r\n\r\nLet the batter rest for at least 2 hours, or overnight in the refrigerator, to ensure the chickpea flour fully hydrates and the flavors meld.\r\nFor a crispy edge, preheat the baking pan with oil in the oven before adding the batter.", "equipment_tags": [], "portions": 5, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 244, "protein_g": 4.0, "carbs_g": 30.5, "fat_g": 11.4, "total_kcal": 1218, "total_protein_g": 20.1, "total_carbs_g": 152.6, "total_fat_g": 57.2, "macro_confidence": 1.0, "is_new": false, "video": null, "cook_steps": [{"step": 1, "label": "Prepare the batter", "instruction": "Whisk together the chickpea flour, water, salt and pepper. Let sit for at least 4 hours.", "timer_seconds": 14400, "background": true}, {"step": 2, "label": "Bake", "instruction": "Preheat the oven to 220°C (430°F). Pour olive oil into a round baking dish and heat in the oven, then pour in the batter and bake for 25 to 30 minutes, until golden.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Serve", "instruction": "Slice and serve hot, optionally with black pepper on top.", "timer_seconds": null, "background": false}]}, {"id": "53140", "name": "Matambre a la Pizza", "category": "Beef", "area": "Argentina", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/wf49qs1763075222.jpg", "local_image": "53140.jpg", "ingredients": [{"ingredient": "Beef Flank Steak", "measure": "1 kg"}, {"ingredient": "Tomato Sauce", "measure": "200g"}, {"ingredient": "Mozzarella", "measure": "200g"}, {"ingredient": "Oregano", "measure": "1 tbsp"}, {"ingredient": "Green Olives", "measure": "100g"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Prepare the Steak: Season the steak with salt and pepper. Grill one side until half-cooked.\r\nAdd Toppings: Spread tomato sauce over the cooked side, then add cheese, oregano, and olives.\r\nFinish Grilling: Grill until the cheese is melted and bubbly.\r\nServe: Slice and serve hot.\r\nPro Tips:\r\n\r\nTenderize the matambre by scoring it lightly on both sides. This helps it cook more evenly and absorb the flavors.\r\nPrecook the matambre on the grill before adding the toppings to ensure it's fully cooked without burning the cheese.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 788, "protein_g": 86.8, "carbs_g": 9.6, "fat_g": 43.4, "total_kcal": 2363, "total_protein_g": 260.3, "total_carbs_g": 28.8, "total_fat_g": 130.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=X5UxDaNHD30", "cook_steps": [{"step": 1, "label": "Prepare the steak", "instruction": "Season the steak with salt and pepper. Grill one side until half-cooked.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Add toppings", "instruction": "Spread tomato sauce over the cooked side, then add cheese, oregano and olives.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Finish grilling", "instruction": "Grill until the cheese is melted and bubbly.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Serve", "instruction": "Slice and serve hot.", "timer_seconds": null, "background": false}]}, {"id": "53141", "name": "Carbonada Criolla", "category": "Beef", "area": "Argentina", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/8b2msz1763074897.jpg", "local_image": "53141.jpg", "ingredients": [{"ingredient": "Beef", "measure": "500g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "2 chopped"}, {"ingredient": "Potatoes", "measure": "2 chopped"}, {"ingredient": "Pumpkin", "measure": "1 small"}, {"ingredient": "Dried Apricots", "measure": "100g"}, {"ingredient": "Beef Stock", "measure": "2 Litres"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Brown the Beef: In a large pot, brown the beef cubes. Remove and set aside.\r\nSauté Vegetables: In the same pot, cook the onion until translucent. Add carrots, potatoes, and pumpkin, cooking for a few minutes.\r\nSimmer: Return the beef to the pot. Add broth and dried apricots. Season with salt and pepper. Simmer for 1-2 hours, until the beef is tender.\r\nServe: Enjoy hot, with a crusty piece of bread.\r\nPro Tips:\r\n\r\nBrown the beef in batches to ensure it gets a good sear, which adds depth to the stew's flavor.\r\nAdding the fruits towards the end of cooking preserves their texture and adds a subtle sweetness to the dish.", "equipment_tags": [], "portions": 6, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 269, "protein_g": 20.5, "carbs_g": 26.9, "fat_g": 9.7, "total_kcal": 1612, "total_protein_g": 123.1, "total_carbs_g": 161.2, "total_fat_g": 58.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=MSyvKDBXuKQ", "cook_steps": [{"step": 1, "label": "Brown the beef", "instruction": "In a large pot, brown the beef cubes, then remove and set aside.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Sauté the vegetables", "instruction": "In the same pot, cook the onion until translucent, then add the carrots, potatoes and pumpkin and cook for a few minutes.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Simmer", "instruction": "Return the beef to the pot, add the broth and dried apricots, season with salt and pepper, and simmer for 1 to 2 hours, until the beef is tender.", "timer_seconds": 7200, "background": true}, {"step": 4, "label": "Serve", "instruction": "Enjoy hot, with a crusty piece of bread.", "timer_seconds": null, "background": false}]}, {"id": "53142", "name": "Spiced tortilla", "category": "Vegetarian", "area": "Spanish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/7b862e1763194846.jpg", "local_image": "53142.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "1 tbsp"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Red Chilli", "measure": "1"}, {"ingredient": "Curry Powder", "measure": "2 teaspoon"}, {"ingredient": "Cherry Tomatoes", "measure": "300g"}, {"ingredient": "Potatoes", "measure": "500g"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Egg", "measure": "8"}], "instructions": "step 1\r\nHeat the oil in a large frying pan. Fry the onion and half the chilli for 5 mins until softened. Tip in the spices, fry for 1 min more, then add the cherry tomatoes, potatoes and coriander stalks to the pan. Season the eggs well, pour over the top of the veg and leave to cook gently for 8-10 mins until almost set.\r\n\r\nstep 2\r\nHeat the grill and flash the tortilla underneath for 1-2 mins until the top is set. Scatter the coriander leaves and remaining chilli over the top, slice into wedges and serve with a green salad.", "equipment_tags": ["Grill"], "portions": 3, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 412, "protein_g": 23.0, "carbs_g": 40.8, "fat_g": 18.9, "total_kcal": 1236, "total_protein_g": 68.9, "total_carbs_g": 122.5, "total_fat_g": 56.8, "macro_confidence": 1.0, "is_new": false, "video": null, "cook_steps": [{"step": 1, "label": "Cook the vegetables", "instruction": "Heat the oil in a large frying pan. Fry the onion and half the chilli for 5 minutes until softened, then add the spices and fry 1 minute more. Add the cherry tomatoes, potatoes and coriander stalks.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Set the eggs", "instruction": "Season the eggs, pour over the vegetables, and leave to cook gently for 8 to 10 minutes until almost set.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Finish under the grill", "instruction": "Heat the grill and flash the tortilla underneath for 1 to 2 minutes until the top is set. Scatter with the coriander leaves and remaining chilli, slice into wedges, and serve with a green salad.", "timer_seconds": 120, "background": false}]}, {"id": "53143", "name": "Easy Spanish chicken", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/kzxflc1763194887.jpg", "local_image": "53143.jpg", "ingredients": [{"ingredient": "Extra Virgin Olive Oil", "measure": "2 tbsp"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Chorizo", "measure": "150g"}, {"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Yellow Pepper", "measure": "1"}, {"ingredient": "sweet smoked paprika", "measure": "1 teaspoon"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Green Olives", "measure": "150g"}, {"ingredient": "Butter Beans", "measure": "400g"}, {"ingredient": "Chicken Thighs", "measure": "8"}, {"ingredient": "Parsley", "measure": "1 Handfull"}], "instructions": "step 1\r\nHeat the oven to 200C/180C fan/gas 6. Heat the olive oil in a large ovenproof frying pan over a medium heat and fry the onion, chorizo and peppers along with a pinch of salt and pepper for 15 mins until the veg has softened and the chorizo has released its oils. Add the paprika and garlic, and cook for another few minutes until fragrant.\r\n\r\nstep 2\r\nTip in the chopped tomatoes, olives and butter beans, stir to combine and season. Nestle in the chicken thighs and season well. Transfer to the oven and bake for 40 mins until the chicken skin is crisp and the meat cooked through and tender. Scatter with the parsley and serve.\r\n\r\nWatch after ad (0.04):\r\n3 Budget Egg Ideas\r\n\r\n", "equipment_tags": [], "portions": 3, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 766, "protein_g": 53.4, "carbs_g": 45.4, "fat_g": 41.6, "total_kcal": 2297, "total_protein_g": 160.2, "total_carbs_g": 136.1, "total_fat_g": 124.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=EusTpzrqYK4", "cook_steps": [{"step": 1, "label": "Soften the veg", "instruction": "Heat the oven to 200C/180C fan/gas 6. Heat the oil in a large ovenproof frying pan and fry the onion, chorizo and peppers with salt and pepper for 15 minutes, until softened and the chorizo has released its oils. Add the paprika and garlic and cook a few minutes more until fragrant.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "Build the base", "instruction": "Tip in the chopped tomatoes, olives and butter beans, stir to combine, and season. Nestle in the chicken thighs and season well.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Bake", "instruction": "Transfer to the oven and bake for 40 minutes, until the chicken skin is crisp and the meat is cooked through. Scatter with parsley and serve.", "timer_seconds": 2400, "background": true}]}, {"id": "53144", "name": "Gambas al ajillo", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/ze8uwg1763196123.jpg", "local_image": "53144.jpg", "ingredients": [{"ingredient": "Raw King Prawns", "measure": "12"}, {"ingredient": "Garlic Clove", "measure": "3"}, {"ingredient": "Olive Oil", "measure": "100 ml"}, {"ingredient": "Cayenne Pepper", "measure": "3"}, {"ingredient": "Parsley", "measure": "1 tablespoon chopped"}], "instructions": "step 1\r\nPeel the prawns, leaving the tails intact, and, using a cocktail stick, remove the digestive tracts. Or, if you are using a frying pan rather than a terracotta pot, you can cook the prawns in their shells. Season with a little sea salt.\r\n\r\nstep 2\r\nPut the garlic, olive oil and chillies in a flameproof terracotta pot or frying pan and set over a high heat. When the garlic starts to turn golden, add the prawns and cook for 1-2 mins on each side until just pink. Sprinkle over the chopped parsley and some freshly cracked black pepper, and serve immediately. If using a terracotta pot, you can take that straight to the table, but be careful with it as the oil and terracotta will remain hot for several minutes.", "equipment_tags": [], "portions": 1, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 1345, "protein_g": 121.1, "carbs_g": 5.7, "fat_g": 95.3, "total_kcal": 1345, "total_protein_g": 121.1, "total_carbs_g": 5.7, "total_fat_g": 95.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=2tZlO8vNMtk", "cook_steps": [{"step": 1, "label": "Prep the prawns", "instruction": "Peel the prawns, leaving the tails intact, and remove the digestive tracts with a cocktail stick (or cook in their shells if using a frying pan). Season with a little sea salt.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook", "instruction": "Put the garlic, olive oil and chillies in a flameproof pot or frying pan over high heat. Once the garlic starts to turn golden, add the prawns and cook 1 to 2 minutes on each side, until just pink.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Serve", "instruction": "Sprinkle with chopped parsley and black pepper, and serve immediately — the pot stays hot for several minutes, so take care.", "timer_seconds": null, "background": false}]}, {"id": "53145", "name": "Jamon & wild garlic croquetas", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/zc9cwz1763196177.jpg", "local_image": "53145.jpg", "ingredients": [{"ingredient": "Wild Garlic Leaves", "measure": "150g"}, {"ingredient": "Milk", "measure": "350g"}, {"ingredient": "Olive Oil", "measure": "45g"}, {"ingredient": "Flour", "measure": "65g"}, {"ingredient": "manchego", "measure": "35g"}, {"ingredient": "jamón ibérico", "measure": "80g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Breadcrumbs", "measure": "75g"}, {"ingredient": "Vegetable Oil", "measure": "1 L"}], "instructions": "step 1\r\nWash the wild garlic leaves well in a colander, then pour over boiling water from the kettle until just wilted. Immediately rinse under cold running water, then squeeze out the excess water and finely chop.\r\n\r\nstep 2\r\nWarm the milk in a pan over a low heat until just steaming. Heat the oil or butter in a second pan and, once warm or melted, stir in the flour for a couple of minutes until it starts to brown a little. Gradually add the warm milk, a little at a time, until you have a thick, silky sauce. Bubble for a minute or two, stirring to make sure all the flour has cooked out. Season.\r\n\r\nstep 3\r\nAdd the manchego, jamón and wild garlic to the pan, and beat to combine. Tip out onto a lightly oiled baking tray or plate, spread out then cover and chill for at least 1 hr. Will keep chilled for up to 24 hrs.\r\n\r\nstep 4\r\nLightly oil your hands and shape the mixture into 18-20 even-sized balls. Arrange on a baking tray and freeze for 30 mins to firm up.\r\n\r\nstep 5\r\nBeat the egg in a shallow dish with a little seasoning. Tip the panko into a second dish. Dip each of the croquetas in the egg, then turn to coat in the breadcrumbs. At this point, the raw croquetas can be frozen for up to three months. Pour the oil into a large, deep pan ensuring it is no more than a third full and heat to 170C, or until a cube of bread browns lightly in 30 seconds. Fry the croquetas in batches for 2-3 mins until deeply golden. To cook from frozen, fry at 160C for a few minutes longer until they’re piping hot inside. Remove to a sheet of kitchen paper using a slotted spoon and leave to drain. Serve warm with a glass of sherry.", "equipment_tags": [], "portions": 12, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 202, "protein_g": 6.5, "carbs_g": 14.2, "fat_g": 13.5, "total_kcal": 2423, "total_protein_g": 78.2, "total_carbs_g": 170.3, "total_fat_g": 161.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=YFMDkUsMazw", "cook_steps": [{"step": 1, "label": "Wilt the wild garlic", "instruction": "Wash the wild garlic leaves, pour over boiling water until just wilted, then rinse under cold water, squeeze out the excess, and finely chop.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Make the sauce", "instruction": "Warm the milk in a pan until just steaming. In a second pan, heat the oil or butter, stir in the flour for a couple of minutes until it browns slightly, then gradually whisk in the warm milk until thick and silky. Bubble for a minute or two and season.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Add the filling", "instruction": "Add the manchego, jamón and wild garlic, and beat to combine. Spread onto an oiled tray, cover, and chill for at least 1 hour (up to 24 hours).", "timer_seconds": 3600, "background": true}, {"step": 4, "label": "Shape and freeze", "instruction": "Lightly oil your hands and shape the mixture into 18 to 20 even balls. Arrange on a tray and freeze for 30 minutes to firm up.", "timer_seconds": 1800, "background": true}, {"step": 5, "label": "Coat and fry", "instruction": "Dip each croqueta in beaten egg, then in panko. Heat the oil to 170°C in a large, deep pan no more than a third full, and fry in batches for 2 to 3 minutes until deeply golden. Drain on kitchen paper and serve warm.", "timer_seconds": 180, "background": false}]}, {"id": "53146", "name": "Locro", "category": "Miscellaneous", "area": "Argentina", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5sgsob1763196284.jpg", "local_image": "53146.jpg", "ingredients": [{"ingredient": "Dried white corn", "measure": "500g"}, {"ingredient": "Dried white beans", "measure": "200g"}, {"ingredient": "Pumpkin", "measure": "300g"}, {"ingredient": "Potatoes", "measure": "200g"}, {"ingredient": "Beef", "measure": "300g"}, {"ingredient": "Pork", "measure": "200g"}, {"ingredient": "Chorizo", "measure": "1"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Paprika", "measure": "1 teaspoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Soak: Soak corn and beans overnight in water.\r\nCook Meats: In a large pot, brown the beef and pork. Add onions and spices, cooking until translucent.\r\nSimmer the Stew: Add soaked corn and beans, pumpkin, potato, and enough water to cover. Simmer for 2-3 hours, until thick.\r\nServe: Enjoy hot, with bread on the side.\r\nPro Tips:\r\n\r\nToasting the corn slightly before adding it to the stew enhances its flavor.\r\nAdd a spoonful of paprika or a dash of cumin for an extra layer of warmth and complexity", "equipment_tags": [], "portions": 4, "prep_minutes": 180, "prep_minutes_source": "explicit", "kcal": 968, "protein_g": 54.0, "carbs_g": 139.9, "fat_g": 23.6, "total_kcal": 3871, "total_protein_g": 216.0, "total_carbs_g": 559.5, "total_fat_g": 94.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=vX0KYKAkBTU", "cook_steps": [{"step": 1, "label": "Soak", "instruction": "Soak the corn and beans overnight in water.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Cook the meats", "instruction": "In a large pot, brown the beef and pork, then add the onions and spices and cook until translucent.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Simmer the stew", "instruction": "Add the soaked corn and beans, pumpkin, potato, and enough water to cover. Simmer for 2 to 3 hours, until thick.", "timer_seconds": 10800, "background": true}, {"step": 4, "label": "Serve", "instruction": "Enjoy hot, with bread on the side.", "timer_seconds": null, "background": false}]}, {"id": "53147", "name": "Arroz con gambas y calamar", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/jc6oub1763196663.jpg", "local_image": "53147.jpg", "ingredients": [{"ingredient": "Raw King Prawns", "measure": "24"}, {"ingredient": "Olive Oil", "measure": "2 tbsp"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Saffron", "measure": "1 pinch"}, {"ingredient": "Paella Rice", "measure": "450g"}, {"ingredient": "Tomato Puree", "measure": "2 teaspoons"}, {"ingredient": "White Wine", "measure": "200ml"}, {"ingredient": "Seafood stock", "measure": "650ml"}, {"ingredient": "Squid", "measure": "3 Medium"}], "instructions": "step 1\r\nPeel and devein most of the prawns (a fishmonger should be able to do this for you), keeping a few whole for decoration, if you like. Heat the olive oil in a large frying pan or shallow flameproof casserole over a medium-low heat and fry the onion for 5 mins until softened. Add the bay leaf, saffron, rice and tomato purée, and cook for 1-2 mins more, stirring.\r\n\r\nstep 2\r\nPour in the wine and bubble for 1-2 mins, then pour in the seafood stock and 150ml water. Cook for 5 mins, then add the squid, season well and stir to combine. Bring to the boil, then cover and reduce the heat to a gentle simmer. Cook for 12 mins more, adding a little more water if the mixture starts to look dry.\r\n\r\nstep 3\r\nUncover the pan and stir through the peeled prawns, then arrange any whole prawns on top of the rice mixture. Cover again and simmer for a further 5-6 mins until the prawns are pink and cooked through. Leave to stand for a couple of minutes before serving from the pan.", "equipment_tags": [], "portions": 6, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 549, "protein_g": 50.1, "carbs_g": 64.9, "fat_g": 6.6, "total_kcal": 3296, "total_protein_g": 300.5, "total_carbs_g": 389.5, "total_fat_g": 39.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=nFFp0ebOlOo", "cook_steps": [{"step": 1, "label": "Start the sofrito", "instruction": "Peel and devein most of the prawns, keeping a few whole for decoration if you like. Heat the oil in a large pan and fry the onion for 5 minutes until softened. Add the bay leaf, saffron, rice and tomato purée, and cook for 1 to 2 minutes, stirring.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Add the liquid", "instruction": "Pour in the wine and bubble for 1 to 2 minutes, then add the seafood stock and water. Cook for 5 minutes, add the squid, season, and stir.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Simmer the rice", "instruction": "Bring to the boil, then cover and reduce to a gentle simmer. Cook for 12 minutes more, adding a little water if it looks dry.", "timer_seconds": 720, "background": true}, {"step": 4, "label": "Add the prawns", "instruction": "Uncover, stir through the peeled prawns, and arrange any whole prawns on top. Cover and simmer for a further 5 to 6 minutes, until the prawns are pink and cooked through.", "timer_seconds": 360, "background": false}, {"step": 5, "label": "Rest and serve", "instruction": "Leave to stand for a couple of minutes before serving from the pan.", "timer_seconds": 120, "background": false}]}, {"id": "53148", "name": "Crema Catalana", "category": "Dessert", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/x73ll91763247842.jpg", "local_image": "53148.jpg", "ingredients": [{"ingredient": "Milk", "measure": "400ml"}, {"ingredient": "Double Cream", "measure": "150ml"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Orange Zest", "measure": "1"}, {"ingredient": "Lemon Zest", "measure": "1"}, {"ingredient": "Egg Yolks", "measure": "7"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Caster Sugar", "measure": "6 tablespoons"}, {"ingredient": "Corn Flour", "measure": "45g"}], "instructions": "step 1\r\nPut the milk, cream, cinnamon stick and all the citrus zest in a saucepan set over a medium heat. Cook, stirring often, until the milk is just steaming but not boiling, about 3-5 mins. Remove from the heat, cover with a plate and leave to infuse for at least 30 mins.\r\n\r\nstep 2\r\nWhen the cream mixture has infused, whisk the egg yolks, sugar and cornflour together in a separate bowl for 3-5 mins, or until light and pale in colour. Pour the infused milk through a sieve into the egg mixture, whisking continuously. Return the mixture to the saucepan.\r\n\r\nstep 3\r\nPut the saucepan over a medium-high heat and whisk for around 10-12 mins. The mixture should start thickening to a custard-like consistency – you can tell it’s ready by dipping a wooden spoon in the mixture, then running a finger through the mixture on the back of the spoon. If the line holds, it's ready. Sieve the mixture into a jug to remove any froth.\r\n\r\nstep 4\r\nDivide the custard between six 150ml ramekins or small terracotta dishes, then leave to cool for 1 hr at room temperature until set with a slight wobble. Chill overnight.\r\n\r\nstep 5\r\nJust before serving, sprinkle 1 tbsp caster sugar over the top of each ramekin and caramelise using a kitchen blowtorch. Alternatively, slide the ramekins under a hot grill until the sugar turns golden and starts to bubble. Serve straightaway.", "equipment_tags": ["Grill"], "portions": 9, "prep_minutes": 112, "prep_minutes_source": "explicit", "kcal": 332, "protein_g": 8.4, "carbs_g": 30.9, "fat_g": 20.0, "total_kcal": 2990, "total_protein_g": 75.2, "total_carbs_g": 278.5, "total_fat_g": 180.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=5aw5Ba0PCa0", "cook_steps": [{"step": 1, "label": "Infuse the cream", "instruction": "Put the milk, cream, cinnamon stick and citrus zest in a saucepan over medium heat. Cook, stirring often, until just steaming, about 3 to 5 minutes. Remove from the heat, cover, and leave to infuse for at least 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Make the egg mixture", "instruction": "Whisk the egg yolks, sugar and cornflour together for 3 to 5 minutes, until light and pale. Pour the infused milk through a sieve into the eggs, whisking constantly, then return to the pan.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Cook the custard", "instruction": "Whisk over medium-high heat for around 10 to 12 minutes, until it thickens to a custard consistency — it's ready when a line holds on the back of a coated spoon. Sieve into a jug to remove any froth.", "timer_seconds": 720, "background": false}, {"step": 4, "label": "Chill", "instruction": "Divide between six ramekins, leave to cool for 1 hour at room temperature until set with a slight wobble, then chill overnight.", "timer_seconds": 3600, "background": true}, {"step": 5, "label": "Caramelize and serve", "instruction": "Just before serving, sprinkle sugar over each ramekin and caramelise with a blowtorch, or under a hot grill until golden and bubbling. Serve straightaway.", "timer_seconds": null, "background": false}]}, {"id": "53149", "name": "Ensaimada", "category": "Dessert", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1ugsho1763248007.jpg", "local_image": "53149.jpg", "ingredients": [{"ingredient": "Yeast", "measure": "5g"}, {"ingredient": "Caster Sugar", "measure": "200g"}, {"ingredient": "Egg", "measure": "2 medium"}, {"ingredient": "Strong white bread flour", "measure": "600g"}, {"ingredient": "Vegetable Oil", "measure": "Drizzle"}, {"ingredient": "Lard", "measure": "100g"}], "instructions": "step 1\r\nPour 230ml lukewarm water into a bowl and add the yeast. Leave to stand for 3 mins, then add the caster sugar, eggs, flour and 1 tsp sea salt flakes. Mix together to form a dough, then knead for 10 mins in stand mixer using a dough hook (or 15 mins by hand) until the dough is elastic enough to be almost see-through when stretched. Cover and set aside to rest for 30 mins, then cut into four equal pieces. Transfer to a baking tray lined with baking parchment. Leave to rest for another 30 mins.\r\n\r\nstep 2\r\nOil the work surface and a rolling pin with vegetable oil. Working with one portion of dough at a time, flatten it against the surface using the palm of your hand, then roll it out into a thin rectangle, about 30 x 50cm. Let it rest for 2 mins while you spread a quarter of the lard over the top. (If you want to fill your pastry with sobrasada de Mallorca, mix 50g lard with the sobrasada, and spread this over the dough instead.) Pull one corner of the flattened dough and stretch it out as far as it will go without breaking. Repeat every 10cm or so around the dough rectangle in every direction until it reaches about 50 x 70cm.\r\n\r\nstep 3\r\nCut a strip from each of the shorter sides and lay these beside each other along one of the longer sides of the rectangle; this is what we call the heart of the ensaimada. From there, begin rolling the dough until you have a long pastry snake. Repeat with the remaining portions of dough.\r\n\r\nstep 4\r\nTake the first roll of dough and stretch it until it is over a metre long. Then, roll it up into a spiral, leaving 1cm between each turn of the spiral so the dough can expand. Flatten a little and transfer to a baking sheet lined with baking parchment. Repeat with the remaining dough. Leave to rise in a warm place for at least 12 hrs, or ideally 24 hrs.\r\n\r\nstep 5\r\nHeat the oven to 200C/180C fan/gas 6. Put the ensaimadas in the top third of the oven and immediately reduce the temperature to 180C/160C fan/gas 4. Bake for 18 mins until dark golden. Leave to cool on a wire rack. To fill your ensaimada with whipped cream, slice and open, then spread over the cream and close. Dust with a generous amount of icing sugar, if you like and cut into pieces to serve.\r\n\r\n", "equipment_tags": [], "portions": 7, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 612, "protein_g": 10.7, "carbs_g": 94.2, "fat_g": 20.9, "total_kcal": 4284, "total_protein_g": 75.0, "total_carbs_g": 659.1, "total_fat_g": 146.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=_Quo9Tgxih4", "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Pour the lukewarm water into a bowl and add the yeast. Leave to stand for 3 minutes, then add the sugar, eggs, flour and salt. Mix to a dough, then knead for 10 minutes (stand mixer) or 15 minutes (by hand), until elastic and almost see-through when stretched.", "timer_seconds": 900, "background": false}, {"step": 2, "label": "First rest", "instruction": "Cover and set aside to rest for 30 minutes, then cut into four pieces and transfer to a lined tray. Leave to rest for another 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Roll and stretch", "instruction": "Oil the surface and rolling pin. Flatten and roll one portion into a thin rectangle, about 30 x 50cm. Rest 2 minutes, spread with a quarter of the lard, then stretch the corners out repeatedly until it reaches about 50 x 70cm.", "timer_seconds": 120, "background": false}, {"step": 4, "label": "Shape the snake", "instruction": "Cut a strip from each short side and lay them beside each other along one long side (the \"heart\"), then roll the dough up into a long pastry snake. Repeat with the remaining portions.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Coil and prove", "instruction": "Stretch each roll to over a metre long, then coil into a spiral with 1cm gaps, flatten slightly, and transfer to a lined tray. Leave to rise in a warm place for at least 12 hours, ideally 24.", "timer_seconds": 43200, "background": true}, {"step": 6, "label": "Bake", "instruction": "Heat the oven to 200C/180C fan/gas 6, then reduce immediately to 180C/160C fan/gas 4 once the ensaimadas go in. Bake for 18 minutes until dark golden, then cool on a wire rack. Fill with whipped cream if you like, and dust generously with icing sugar to serve.", "timer_seconds": 1080, "background": true}]}, {"id": "53150", "name": "Padron peppers", "category": "Vegan", "area": "Spanish", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/0ljvc51763248075.jpg", "local_image": "53150.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Padron peppers", "measure": "500g"}], "instructions": "step 1\r\nHeat the olive oil in a large frying pan over a high heat, or if using an air-fryer, heat to 205C for 3 mins. Fry the peppers, stirring frequently, for 5 mins until blistered and wilted. The peppers should be soft and slightly charred.\r\n\r\nstep 2\r\nTransfer the peppers to a serving plate and season with some sea salt. Serve with dips or as part of a tapas spread, if you like.", "equipment_tags": [], "portions": 1, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 1377, "protein_g": 50.0, "carbs_g": 320.0, "fat_g": 30.3, "total_kcal": 1377, "total_protein_g": 50.0, "total_carbs_g": 320.0, "total_fat_g": 30.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=wD6NE3cMKBY", "cook_steps": [{"step": 1, "label": "Fry the peppers", "instruction": "Heat the olive oil in a large frying pan over high heat (or an air-fryer to 205C for 3 minutes). Fry the peppers, stirring frequently, for 5 minutes, until blistered, wilted and slightly charred.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Serve", "instruction": "Transfer to a serving plate, season with sea salt, and serve with dips or as part of a tapas spread.", "timer_seconds": null, "background": false}]}, {"id": "53151", "name": "Paella", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/9bl20p1763248192.jpg", "local_image": "53151.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "3 tablespoons"}, {"ingredient": "Raw tiger prawns", "measure": "10"}, {"ingredient": "Parsley", "measure": "Bunch"}, {"ingredient": "Dry sherry", "measure": "100 ml"}, {"ingredient": "Mussels", "measure": "500g"}, {"ingredient": "Saffron", "measure": "Pinch"}, {"ingredient": "Chorizo", "measure": "150g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Squid", "measure": "1 medium"}, {"ingredient": "Tomato", "measure": "2"}, {"ingredient": "Paella Rice", "measure": "250g"}, {"ingredient": "Broad Beans", "measure": "100g"}, {"ingredient": "Lemon Zest", "measure": "1"}], "instructions": "step 1\r\nHeat 1 tbsp of the oil in a wide, shallow pan. Add the prawn heads and parsley stalks and sizzle until the heads turn pink, then mash with a potato masher. Pour over the sherry or wine and 300ml water, season with salt and simmer for 10 mins to make a stock, mashing the prawn heads as they cook.\r\n\r\nstep 2\r\nScatter the mussels into the pan, cover the pan loosely with a lid or tea towel, then put over a high heat for 3-4 mins until the mussels just open. Stir to release the mussel juices, then pour the contents of the pan into a colander set over a large bowl containing the saffron. Let the saffron steep in the stock – you will need 700ml in total, so top up with water if needed and give everything a good stir. Pick the mussels out from the colander, then set aside.\r\n\r\nstep 3\r\nWipe out the pan and add the rest of the olive oil. Sizzle the chorizo until it releases its oil, then add the onion and garlic and cook until softened. Add the squid and turn over until it turns white. Add the tomatoes and cook down for a minute, then pour over most of the stock, give everything a good stir and bring to the boil. Scatter the rice over the stock, stir well once, then boil vigorously for 5 mins. Reduce the heat to the lowest setting and slowly simmer for 10 mins without stirring until the rice has absorbed most of the liquid.\r\n\r\nstep 4\r\nTuck the prawn tails into the rice and simmer for 5 mins, turning them over until cooked through. Stir through the mussels and broad beans or peas. Taste the rice – if it is still a little raw but the pan is dry, add a splash more stock and continue to cook; if it’s too soupy, then increase the heat to cook off the last of the stock.\r\n\r\nstep 5\r\nOnce the rice is just cooked, turn off the heat and cover with a tea towel for a few minutes. Scatter over the parsley leaves and lemon zest, then season with smoked salt if you like. Stir everything once, then serve straight from the pan, with lemon wedges on the side.", "equipment_tags": [], "portions": 4, "prep_minutes": 34, "prep_minutes_source": "explicit", "kcal": 794, "protein_g": 58.1, "carbs_g": 67.3, "fat_g": 29.0, "total_kcal": 3175, "total_protein_g": 232.5, "total_carbs_g": 269.4, "total_fat_g": 116.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=vNBuXsTY15E", "cook_steps": [{"step": 1, "label": "Make the prawn stock", "instruction": "Heat 1 tbsp oil in a wide, shallow pan. Sizzle the prawn heads and parsley stalks until pink, then mash with a potato masher. Add the sherry or wine and water, season, and simmer for 10 minutes to make a stock.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Steam the mussels", "instruction": "Scatter the mussels into the pan, cover loosely, and cook over high heat for 3 to 4 minutes, until they open. Strain the stock over the saffron to steep (topping up to 700ml with water), and set the mussels aside.", "timer_seconds": 240, "background": false}, {"step": 3, "label": "Build the sofrito", "instruction": "Wipe out the pan, add the rest of the oil, and sizzle the chorizo until it releases its oil. Add the onion and garlic and cook until softened, then the squid until it turns white, then the tomatoes and cook down for a minute.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Cook the rice", "instruction": "Pour in most of the stock, stir well, and bring to the boil. Scatter over the rice, stir once, then boil vigorously for 5 minutes. Reduce to the lowest setting and simmer for 10 minutes without stirring.", "timer_seconds": 900, "background": true}, {"step": 5, "label": "Add the prawns", "instruction": "Tuck the prawn tails into the rice and simmer for 5 minutes, turning until cooked through. Stir through the mussels and broad beans or peas, adjusting with more stock or heat as needed.", "timer_seconds": 300, "background": false}, {"step": 6, "label": "Rest and serve", "instruction": "Turn off the heat, cover with a tea towel for a few minutes, then scatter with parsley and lemon zest. Serve straight from the pan with lemon wedges.", "timer_seconds": null, "background": false}]}, {"id": "53152", "name": "Pan-fried hake, white bean & chorizo broth", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/4yjart1763248459.jpg", "local_image": "53152.jpg", "ingredients": [{"ingredient": "Dried white beans", "measure": "450g"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Thyme", "measure": "1 teaspoon"}, {"ingredient": "Olive Oil", "measure": "6 tablespoons"}, {"ingredient": "Bread", "measure": "100g"}, {"ingredient": "Chorizo", "measure": "100g"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Paprika", "measure": "3 tsp"}, {"ingredient": "Chicken Stock", "measure": "1 L"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Hake", "measure": "6"}], "instructions": "step 1\r\nDrain the beans, then tip into a large pan with 2 litres of water. Simmer with the whole garlic cloves, bay leaves and thyme for 30 mins or until cooked and tender. Remove from the heat and set aside.\r\n\r\nstep 2\r\nMeanwhile, heat 2 tbsp oil in a frying pan. Fry the bread with the remaining garlic clove. When golden and crisp, scoop out and drain on kitchen paper. Add the chorizo to the pan, fry until crisp, tip out and keep warm with the bread.\r\n\r\nstep 3\r\nAdd another 2 tbsp oil and the onion to the pan, and cook for 5 mins until softened. Stir in the paprika. Drain the beans and add to the onions with the chicken stock and 2 tsp salt. Cook for 5-10 mins. Stir through the parsley and keep warm.\r\n\r\nstep 4\r\nSeason the hake and heat the remaining 2 tbsp oil in the frying pan. Put the hake, skin-side down, in the pan and cook for 3-5 mins over a mediumhigh heat to crisp up the skin. Flip the fish over and cook for a further 3-5 mins until cooked through. Spoon the white bean mix into bowls, place the hake on top and finish with the fried bread, chorizo and a little more thyme.", "equipment_tags": [], "portions": 4, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 842, "protein_g": 51.3, "carbs_g": 88.4, "fat_g": 33.3, "total_kcal": 3368, "total_protein_g": 205.3, "total_carbs_g": 353.7, "total_fat_g": 133.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=6hcNBBob_xI", "cook_steps": [{"step": 1, "label": "Simmer the beans", "instruction": "Drain the beans and tip into a large pan with water. Simmer with the whole garlic cloves, bay leaves and thyme for 30 minutes, until tender.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Fry the bread and chorizo", "instruction": "Meanwhile, heat oil in a frying pan and fry the bread with a garlic clove until golden and crisp, then drain. Add the chorizo to the pan and fry until crisp, then keep warm with the bread.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Build the broth", "instruction": "Add more oil and the onion to the pan and cook for 5 minutes until softened. Stir in the paprika, then the drained beans, chicken stock and salt. Cook for 5 to 10 minutes, then stir through the parsley.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Pan-fry the hake", "instruction": "Season the hake and heat the remaining oil. Cook skin-side down for 3 to 5 minutes to crisp the skin, then flip and cook a further 3 to 5 minutes until cooked through.", "timer_seconds": 600, "background": false}, {"step": 5, "label": "Serve", "instruction": "Spoon the white bean mix into bowls, top with the hake, and finish with the fried bread, chorizo and a little more thyme.", "timer_seconds": null, "background": false}]}, {"id": "53153", "name": "Churros", "category": "Dessert", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/nxnny61763250596.jpg", "local_image": "53153.jpg", "ingredients": [{"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Vanilla Extract", "measure": "1/2 teaspoon"}, {"ingredient": "Plain Flour", "measure": "250g"}, {"ingredient": "Baking Powder", "measure": "1 teaspoon"}, {"ingredient": "Sunflower Oil", "measure": "1 L"}, {"ingredient": "Bread", "measure": "2 chopped"}, {"ingredient": "Dark Chocolate", "measure": "200g"}, {"ingredient": "Double Cream", "measure": "100 ml"}, {"ingredient": "Milk", "measure": "100 ml"}, {"ingredient": "Golden Syrup", "measure": "3  tablespoons"}, {"ingredient": "Vanilla Extract", "measure": "1/2 teaspoon"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Cinnamon", "measure": "2 teaspoon"}], "instructions": "step 1\r\nBoil the kettle, then measure 300ml boiling water into a jug and add the melted butter and vanilla extract. Sift the flour and baking powder into a big mixing bowl with a big pinch of salt. Make a well in the centre, then pour in the contents of the jug and very quickly beat into the flour with a wooden spoon until lump-free. Rest for 10-15 mins while you make the sauce.\r\n\r\nstep 2\r\nPut all the sauce ingredients into a pan and gently melt together, stirring occasionally until you have a smooth shiny sauce. Keep warm on a low heat.\r\n\r\nstep 3\r\nFill a large deep saucepan one-third full of oil. Cooking with hot oil can be dangerous – before you start, read up on how to deep-fry safely to avoid accidents in the kitchen. Heat until a cube of bread browns in 45 seconds to 1 min. Cover a tray with kitchen paper and mix the caster sugar and cinnamon together.\r\n\r\nstep 4\r\nFit a star nozzle to a piping bag – 1.5-2cm wide is a good size. Fill with the rested dough, then pipe 2-3 strips directly into the pan, snipping off each dough strip with a pair of kitchen scissors. Fry until golden brown and crisp. Be very careful here – if air bubbles form in the churros they can explode, especially if the oil overheats or you use old flour. Cooking with hot oil can be dangerous – before you start, read up on how to deep-fry safely to avoid accidents in the kitchen. Keep children out of the kitchen and protect yourself by wearing long sleeves and eye protection, and keeping your face away from the pan.\r\n\r\nstep 5\r\nOnce the churros are crisp and golden brown, remove them from the oil with a slotted spoon and drain on the kitchen paper-lined tray. Carry on cooking the rest of the dough in batches, sprinkling the cooked churros with some cinnamon sugar as you go. When you’ve cooked all the churros, toss with any remaining cinnamon sugar and serve with the chocolate sauce, for dipping.\r\nTo see a video of how to prepare churros, take a look at our churros ice cream sandwich recipe.", "equipment_tags": [], "portions": 7, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 631, "protein_g": 8.1, "carbs_g": 75.5, "fat_g": 33.3, "total_kcal": 4420, "total_protein_g": 56.5, "total_carbs_g": 528.5, "total_fat_g": 233.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=453mpKHVaBs", "cook_steps": [{"step": 1, "label": "Make the dough", "instruction": "Measure the boiling water into a jug with the melted butter and vanilla. Sift the flour, baking powder and salt into a bowl, make a well, pour in the liquid, and quickly beat until lump-free. Rest for 10 to 15 minutes while you make the sauce.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Make the chocolate sauce", "instruction": "Put all the sauce ingredients into a pan and gently melt together, stirring occasionally, until smooth and shiny. Keep warm on a low heat.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Heat the oil", "instruction": "Fill a large deep saucepan one-third full of oil and heat until a cube of bread browns in 45 seconds to 1 minute. Line a tray with kitchen paper and mix the caster sugar and cinnamon.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Pipe and fry", "instruction": "Fit a star nozzle to a piping bag and fill with the rested dough. Pipe 2 to 3 strips directly into the hot oil, snipping off with scissors, and fry until golden brown and crisp.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Drain and coat", "instruction": "Remove with a slotted spoon and drain on the paper-lined tray. Cook the rest in batches, sprinkling with cinnamon sugar as you go, then toss with any remaining sugar and serve with the chocolate sauce for dipping.", "timer_seconds": null, "background": false}]}, {"id": "53154", "name": "Clam, chorizo & white bean stew", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/92wbmf1763252334.jpg", "local_image": "53154.jpg", "ingredients": [{"ingredient": "Chorizo", "measure": "50g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic Clove", "measure": "1"}, {"ingredient": "Parsley", "measure": "Bunch"}, {"ingredient": "Vegetable Stock", "measure": "200ml"}, {"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Butter Beans", "measure": "400g"}, {"ingredient": "Sherry vinegar", "measure": "1 teaspoon"}, {"ingredient": "Clams", "measure": "600g"}, {"ingredient": "Crusty Bread", "measure": "To serve"}], "instructions": "step 1\r\nFry the chorizo in a large frying pan with a lid, over a medium heat until it is starting to crisp up and release its oil. Add the onion and cook for 5 mins until starting to soften. Then add the garlic and finely chopped parsley, and fry for 1 min more.\r\n\r\nstep 2\r\nPour on the stock and tomatoes. Bring to the boil, reduce the heat, then add the beans and sherry vinegar. Simmer for 10 mins until the liquid is slightly reduced.\r\n\r\nstep 3\r\nScatter over the clams, cover with the lid and steam for 2-4 mins, shaking the pan occasionally until the clams are open. Have a little taste before seasoning, as the clams can be quite salty. Then scatter over the chopped parsley. Eat with lots of crusty bread.", "equipment_tags": [], "portions": 4, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 350, "protein_g": 33.3, "carbs_g": 38.1, "fat_g": 7.3, "total_kcal": 1401, "total_protein_g": 133.2, "total_carbs_g": 152.6, "total_fat_g": 29.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=IoRuT7TxDAo", "cook_steps": [{"step": 1, "label": "Fry the chorizo", "instruction": "Fry the chorizo in a large lidded pan over medium heat until starting to crisp and release its oil. Add the onion and cook for 5 minutes until softening, then add the garlic and parsley and fry 1 minute more.", "timer_seconds": 360, "background": false}, {"step": 2, "label": "Simmer the base", "instruction": "Pour in the stock and tomatoes, bring to the boil, reduce the heat, then add the beans and sherry vinegar. Simmer for 10 minutes, until slightly reduced.", "timer_seconds": 600, "background": true}, {"step": 3, "label": "Steam the clams", "instruction": "Scatter over the clams, cover, and steam for 2 to 4 minutes, shaking the pan occasionally, until they open. Taste before seasoning, as the clams can be salty, then scatter with parsley. Eat with crusty bread.", "timer_seconds": 240, "background": false}]}, {"id": "53155", "name": "Spanish chicken pie", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/8ovxf41763253962.jpg", "local_image": "53155.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1 kg"}, {"ingredient": "Paprika", "measure": "3 tsp"}, {"ingredient": "Olive Oil", "measure": "2 teaspoons"}, {"ingredient": "Onion", "measure": "2 sliced"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Tinned Tomatos", "measure": "800g"}, {"ingredient": "Chicken", "measure": "300g"}, {"ingredient": "Roasted pepper", "measure": "140g"}, {"ingredient": "Green Olives", "measure": "Handful"}], "instructions": "step 1\r\nHeat oven to 200C/fan 180C/gas 6. Boil the potatoes for 15-20 mins until tender. Drain, return to the pan, then mash with some seasoning and 2 tsp of the paprika.\r\n\r\nstep 2\r\nMeanwhile, heat the oil in a large pan, then fry the onions and garlic for a few mins until softened. Stir in the remaining paprika for 1 min, add the tomatoes , then, bring to a simmer. Tip into a large ovenproof dish, then stir in the chicken, peppers, olives and some seasoning.\r\n\r\nstep 3\r\nSpoon over the mash, then bake for 15 mins until the mash is golden on top and the sauce is bubbling.", "equipment_tags": [], "portions": 5, "prep_minutes": 36, "prep_minutes_source": "explicit", "kcal": 334, "protein_g": 19.4, "carbs_g": 48.3, "fat_g": 7.7, "total_kcal": 1671, "total_protein_g": 96.8, "total_carbs_g": 241.3, "total_fat_g": 38.4, "macro_confidence": 1.0, "is_new": false, "video": null, "cook_steps": [{"step": 1, "label": "Boil and mash the potatoes", "instruction": "Heat the oven to 200C/fan 180C/gas 6. Boil the potatoes for 15 to 20 minutes until tender, drain, then mash with seasoning and half the paprika.", "timer_seconds": 1200, "background": true}, {"step": 2, "label": "Make the sauce", "instruction": "Meanwhile, heat the oil and fry the onions and garlic for a few minutes until softened. Stir in the remaining paprika, add the tomatoes, and simmer. Tip into an ovenproof dish and stir in the chicken, peppers, olives and seasoning.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Top and bake", "instruction": "Spoon over the mash and bake for 15 minutes, until golden on top and the sauce is bubbling.", "timer_seconds": 900, "background": true}]}, {"id": "53156", "name": "Arroz al horno (baked rice)", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/qt4i0n1763256454.jpg", "local_image": "53156.jpg", "ingredients": [{"ingredient": "Extra Virgin Olive Oil", "measure": "2 tbsp"}, {"ingredient": "Pork belly slices", "measure": "800g"}, {"ingredient": "Black Pudding", "measure": "150g"}, {"ingredient": "Bacon lardon", "measure": "100g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Red Pepper", "measure": "2"}, {"ingredient": "Plum Tomatoes", "measure": "1 chopped"}, {"ingredient": "Garlic Clove", "measure": "8"}, {"ingredient": "Paprika", "measure": "4 teaspoons"}, {"ingredient": "Chilli Flakes", "measure": "1/2 teaspoon"}, {"ingredient": "Dried white beans", "measure": "200g"}, {"ingredient": "Chicken Stock", "measure": "1 1/2 L"}, {"ingredient": "Thyme", "measure": "6 parts"}, {"ingredient": "Paella Rice", "measure": "375g"}, {"ingredient": "Lemon Juice", "measure": "1"}], "instructions": "step 1\r\nHeat oven to 200C/180C/gas 6. Heat half the oil in a deep frying or sauté pan (or shallow casserole dish) measuring around 30cm in diameter. Over a high heat, colour the pork belly slices on each side in several batches, then transfer to a bowl. Add the remaining oil to the pan and lower the heat to medium, then add the black pudding and bacon and fry all over for several mins. Remove with a slotted spoon. Fry the onion and peppers for around 10 mins until soft and pale gold, then add the tomato and cook until soft. Add the garlic, smoked paprika and chilli flakes and cook for another 2 mins, then put the pork, black pudding and bacon back in the pan. Add the beans, stock and whichever herb you're using, and bring everything to the boil.\r\n\r\nstep 2\r\nSprinkle the rice around the pork belly, pushing it underneath the stock. Let the stock come to the boil again, season well, then transfer to the oven (leave it uncovered). Cook for 20 mins without stirring, then check to see how the rice is doing. The rice should be tender and the stock absorbed. If it’s not ready, put back in the oven for another 5 mins, then check again. Taste for seasoning.\r\n\r\nstep 3\r\nSqueeze lemon juice over the top and drizzle over some extra virgin olive oil just before serving, if you like.", "equipment_tags": [], "portions": 7, "prep_minutes": 37, "prep_minutes_source": "explicit", "kcal": 996, "protein_g": 34.0, "carbs_g": 79.4, "fat_g": 61.2, "total_kcal": 6974, "total_protein_g": 238.1, "total_carbs_g": 556.1, "total_fat_g": 428.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=f-waAIrn2iA", "cook_steps": [{"step": 1, "label": "Brown the meats", "instruction": "Heat the oven to 200C/180C/gas 6. Heat half the oil in a wide pan and colour the pork belly slices on each side in batches; set aside. Add the rest of the oil, fry the black pudding and bacon, then remove.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Build the sofrito", "instruction": "Fry the onion and peppers for around 10 minutes until soft and pale gold, then add the tomato and cook until soft. Add the garlic, smoked paprika and chilli flakes and cook 2 minutes more, then return the pork, black pudding and bacon to the pan. Add the beans, stock and herb, and bring to the boil.", "timer_seconds": 600, "background": false}, {"step": 3, "label": "Bake the rice", "instruction": "Sprinkle the rice around the pork belly, pushing it under the stock. Bring back to the boil, season, then transfer uncovered to the oven for 20 minutes, checking and adding 5 more minutes if needed until the rice is tender and stock absorbed.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Finish", "instruction": "Squeeze over lemon juice and drizzle with extra virgin olive oil just before serving.", "timer_seconds": null, "background": false}]}, {"id": "53157", "name": "Chorizo & soft-boiled egg salad", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/v8eaed1763257313.jpg", "local_image": "53157.jpg", "ingredients": [{"ingredient": "Baby New Potatoes", "measure": "500g"}, {"ingredient": "Egg", "measure": "4"}, {"ingredient": "Green Beans", "measure": "225g"}, {"ingredient": "Chorizo", "measure": "225g"}, {"ingredient": "Garlic Clove", "measure": "1 sliced"}, {"ingredient": "Sherry vinegar", "measure": "2 tbsp"}, {"ingredient": "Parsley", "measure": "2 tbsp chopped"}], "instructions": "step 1\r\nCook the potatoes in a large pan of boiling salted water for 12 mins, adding the eggs after 6 mins, and the beans for the final 2 mins. Drain everything and cool the eggs under cold running water.\r\n\r\nstep 2\r\nMeanwhile fry chorizo slices for 1-2 mins, until beginning to crisp. Remove from the pan with a slotted spoon and set aside, leaving the oil from the chorizo in the pan. Add the garlic to the pan and cook gently for 1 min.\r\n\r\nstep 3\r\nRemove the pan from the heat, stir in the vinegar and parsley, then toss with the potatoes, beans, chorizo and seasoning. Shell the eggs, cut into quarters and add to the salad.", "equipment_tags": [], "portions": 9, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 198, "protein_g": 10.6, "carbs_g": 12.2, "fat_g": 11.9, "total_kcal": 1785, "total_protein_g": 95.1, "total_carbs_g": 110.2, "total_fat_g": 106.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=PfAjfn5dYHE", "cook_steps": [{"step": 1, "label": "Cook the potatoes, eggs and beans", "instruction": "Cook the potatoes in a large pan of boiling salted water for 12 minutes, adding the eggs after 6 minutes and the beans for the final 2 minutes. Drain everything and cool the eggs under cold running water.", "timer_seconds": 720, "background": true}, {"step": 2, "label": "Fry the chorizo", "instruction": "Meanwhile, fry the chorizo slices for 1 to 2 minutes, until beginning to crisp, then remove with a slotted spoon, leaving the oil in the pan. Add the garlic and cook gently for 1 minute.", "timer_seconds": 120, "background": false}, {"step": 3, "label": "Toss and serve", "instruction": "Off the heat, stir in the vinegar and parsley, then toss with the potatoes, beans, chorizo and seasoning. Shell the eggs, quarter, and add to the salad.", "timer_seconds": null, "background": false}]}, {"id": "53158", "name": "Air fryer patatas bravas", "category": "Vegetarian", "area": "Spanish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/3m8yae1763257951.jpg", "local_image": "53158.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "900g"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Paprika", "measure": "1 tblsp"}, {"ingredient": "Tomato Puree", "measure": "1 tblsp"}, {"ingredient": "Tinned Tomatos", "measure": "225g"}, {"ingredient": "Basil Leaves", "measure": "To serve"}], "instructions": "step 1\r\nSoak the potatoes in just-boiled water for 30 mins, then drain and leave to air-dry for 5 mins. Heat the air fryer to 200C. Tip the potatoes into a bowl and drizzle over 1 tbsp of the oil and add 1/2 tsp each of salt and freshly ground black pepper. Mix to coat the potatoes all over, then tip into the air fryer basket and cook for 20-30 mins until crisp and golden.\r\n\r\nstep 2\r\nMeanwhile, heat the remaining oil in a small pan over a medium-low heat and fry the onion for 8-10 mins until softened but not golden. Stir in the garlic and cook for a minute before adding the paprika and cooking for 30 seconds more. Stir in the tomato purée, cook for 1 min, then tip in the chopped tomatoes. Cook for 5-10 mins over a medium heat until thickened slightly.\r\n\r\nstep 3\r\nOnce the potatoes are cooked, tip out onto a platter and pour over the tomato sauce. Sprinkle with the basil leaves, then serve.", "equipment_tags": ["AirFryer"], "portions": 3, "prep_minutes": 86, "prep_minutes_source": "explicit", "kcal": 403, "protein_g": 8.4, "carbs_g": 61.6, "fat_g": 15.0, "total_kcal": 1209, "total_protein_g": 25.1, "total_carbs_g": 184.8, "total_fat_g": 45.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=kzLaw6PG2UY", "cook_steps": [{"step": 1, "label": "Soak the potatoes", "instruction": "Soak the potatoes in just-boiled water for 30 minutes, then drain and air-dry for 5 minutes.", "timer_seconds": 1800, "background": true}, {"step": 2, "label": "Air-fry the potatoes", "instruction": "Heat the air fryer to 200C. Toss the potatoes with oil, salt and pepper, then cook in the air fryer basket for 20 to 30 minutes, until crisp and golden.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Make the sauce", "instruction": "Meanwhile, heat the remaining oil and fry the onion for 8 to 10 minutes until softened. Stir in the garlic, then the paprika, then the tomato purée, then the chopped tomatoes, and cook for 5 to 10 minutes until slightly thickened.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Serve", "instruction": "Tip the cooked potatoes onto a platter, pour over the tomato sauce, sprinkle with basil, and serve.", "timer_seconds": null, "background": false}]}, {"id": "53159", "name": "Chorizo, potato & cheese omelette", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/0y6uvc1763258983.jpg", "local_image": "53159.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1 small"}, {"ingredient": "Olive Oil", "measure": "1 teaspoon"}, {"ingredient": "Chorizo", "measure": "50g"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Parsley", "measure": "Chopped"}, {"ingredient": "Cheddar Cheese", "measure": "25g"}], "instructions": "step 1\r\nCook the potato in boiling water for 8-10 mins or until tender. Drain and allow to steam-dry. Heat oil in an omelette pan, add chorizo and cook for 2 mins. Add the potato and cook for a further 5 mins until the potato starts to crisp. Spoon pan contents out, wipe pan and cook a 2 or 3-egg omelette in the same pan. When almost cooked, scatter with the chorizo and potato, parsley and cheese. Fold the omelette in the pan and cook for 1 min more to melt the cheese.", "equipment_tags": [], "portions": 1, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 725, "protein_g": 42.0, "carbs_g": 33.7, "fat_g": 47.3, "total_kcal": 725, "total_protein_g": 42.0, "total_carbs_g": 33.7, "total_fat_g": 47.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=K2Ba5BWYXUU", "cook_steps": [{"step": 1, "label": "Cook the potato", "instruction": "Cook the potato in boiling water for 8 to 10 minutes until tender, then drain and steam-dry.", "timer_seconds": 600, "background": false}, {"step": 2, "label": "Fry the chorizo and potato", "instruction": "Heat oil in an omelette pan, add the chorizo and cook for 2 minutes, then add the potato and cook a further 5 minutes until crisping. Spoon out and wipe the pan.", "timer_seconds": 420, "background": false}, {"step": 3, "label": "Cook the omelette", "instruction": "Cook a 2 to 3 egg omelette in the same pan. When almost set, scatter over the chorizo, potato, parsley and cheese, fold, and cook 1 minute more to melt the cheese.", "timer_seconds": 60, "background": false}]}, {"id": "53160", "name": "Pisto con huevos", "category": "Vegetarian", "area": "Spanish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/0nswfe1763279040.jpg", "local_image": "53160.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Onion", "measure": "2"}, {"ingredient": "Garlic Clove", "measure": "4 Chopped"}, {"ingredient": "Mixed peppers", "measure": "5"}, {"ingredient": "Oregano", "measure": "1 teaspoon"}, {"ingredient": "Thyme", "measure": "Sprigs of fresh"}, {"ingredient": "Bay Leaves", "measure": "4 leaves"}, {"ingredient": "Courgettes", "measure": "2 chopped"}, {"ingredient": "Aubergine", "measure": "1 chopped"}, {"ingredient": "Tomato", "measure": "4 large"}, {"ingredient": "Egg", "measure": "4 large"}, {"ingredient": "Parsley", "measure": "Handful"}], "instructions": "step 1\r\nHeat the oil in a large flameproof casserole dish or a cast-iron skillet over a low heat. Add the onions and a sprinkle of salt, cover and cook gently for 15 mins, stirring occasionally. Add the garlic and cook for another 2 mins.\r\n\r\nstep 2\r\nNext, throw in the peppers and cook over a medium heat, covered, for about 5 mins, stirring every so often, until the peppers are just tender.\r\n\r\nstep 3\r\nMix in the oregano, thyme, bay leaves, some black pepper and a little salt, if needed. Tip in the courgettes and aubergine, combine thoroughly, and cook over a medium heat, covered, for 10 mins. Stir in the tomatoes, cover and cook for 20 mins, stirring occasionally.\r\n\r\nstep 4\r\nCarefully crack the eggs over the pisto – try not to break the yolks. Cook in the sauce on a medium heat for 5-6 mins until the eggs are cooked through but still a little soft, then scatter with parsley before serving", "equipment_tags": [], "portions": 2, "prep_minutes": 58, "prep_minutes_source": "explicit", "kcal": 377, "protein_g": 17.7, "carbs_g": 26.0, "fat_g": 24.8, "total_kcal": 753, "total_protein_g": 35.4, "total_carbs_g": 52.1, "total_fat_g": 49.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/T43aUS9bG_0", "cook_steps": [{"step": 1, "label": "Soften the onions", "instruction": "Heat the oil in a large casserole or skillet over low heat. Add the onions and a pinch of salt, cover, and cook gently for 15 minutes, stirring occasionally. Add the garlic and cook 2 minutes more.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Cook the peppers", "instruction": "Add the peppers and cook over medium heat, covered, for about 5 minutes, stirring occasionally, until just tender.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Add the rest of the vegetables", "instruction": "Stir in the oregano, thyme, bay leaves and seasoning. Add the courgettes and aubergine, combine, and cook covered over medium heat for 10 minutes. Stir in the tomatoes, cover, and cook for 20 minutes, stirring occasionally.", "timer_seconds": 1200, "background": true}, {"step": 4, "label": "Poach the eggs", "instruction": "Crack the eggs over the pisto, taking care not to break the yolks. Cook in the sauce over medium heat for 5 to 6 minutes until just set, then scatter with parsley before serving.", "timer_seconds": 360, "background": false}]}, {"id": "53161", "name": "Chicken & chorizo rice pot", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/fk80jp1763280767.jpg", "local_image": "53161.jpg", "ingredients": [{"ingredient": "Oil", "measure": "1 tblsp"}, {"ingredient": "Chicken", "measure": "1 whole"}, {"ingredient": "Onion", "measure": "1 Large Chopped"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Chorizo", "measure": "225g"}, {"ingredient": "Tomato Puree", "measure": "1 tblsp"}, {"ingredient": "Thyme", "measure": "1 tablespoon chopped"}, {"ingredient": "White Wine", "measure": "150ml"}, {"ingredient": "Chicken Stock", "measure": "800ml"}, {"ingredient": "Rice", "measure": "400g"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}], "instructions": "step 1\r\nHeat the oil in a large flameproof casserole dish and brown the chicken pieces on all sides – you may have to do this in batches. Remove from the dish and put to one side.\r\n\r\nstep 2\r\nLower the heat, add the onion and pepper, and gently cook for 10 mins until softened. Add the garlic and chorizo, and cook for a further 2 mins until the chorizo has released some of its oils into the dish. Stir in the tomato purée and cook for 1 min more.\r\n\r\nstep 3\r\nReturn the chicken pieces to the dish along with the thyme, white wine and stock. Bring the liquid to a boil, cover the dish with a tight-fitting lid and lower the heat. Cook for 30 mins.\r\n\r\nstep 4\r\nTip in the rice and stir everything together. Cover, set over a low heat and cook for a further 15 mins, or until the rice is cooked and has absorbed most of the cooking liquid. Remove from the heat and leave the dish to sit for 10 mins to absorb any remaining liquid. Season to taste and scatter with parsley to serve.", "equipment_tags": [], "portions": 6, "prep_minutes": 68, "prep_minutes_source": "explicit", "kcal": 827, "protein_g": 64.1, "carbs_g": 59.2, "fat_g": 32.4, "total_kcal": 4965, "total_protein_g": 384.7, "total_carbs_g": 355.4, "total_fat_g": 194.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=CiY6ZOYRMI4", "cook_steps": [{"step": 1, "label": "Brown the chicken", "instruction": "Heat the oil in a large flameproof casserole and brown the chicken pieces on all sides, in batches if needed. Remove and set aside.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Build the base", "instruction": "Lower the heat, add the onion and pepper, and cook gently for 10 minutes until softened. Add the garlic and chorizo and cook 2 minutes more, then stir in the tomato purée and cook 1 minute.", "timer_seconds": 720, "background": false}, {"step": 3, "label": "Braise the chicken", "instruction": "Return the chicken to the dish with the thyme, wine and stock. Bring to the boil, cover with a tight lid, lower the heat, and cook for 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Cook the rice", "instruction": "Tip in the rice and stir together. Cover and cook over low heat for a further 15 minutes, until the rice is cooked and has absorbed most of the liquid. Remove from the heat and let sit for 10 minutes before seasoning and scattering with parsley.", "timer_seconds": 900, "background": true}]}, {"id": "53162", "name": "Pollo en pepitoria", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/li30ck1763281992.jpg", "local_image": "53162.jpg", "ingredients": [{"ingredient": "Saffron", "measure": "Pinch"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "4 tbsp"}, {"ingredient": "Garlic Clove", "measure": "6"}, {"ingredient": "Almonds", "measure": "35g"}, {"ingredient": "Stale bread", "measure": "30g"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}, {"ingredient": "Chicken Thighs", "measure": "8"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "1 chopped"}, {"ingredient": "Celery", "measure": "1 chopped"}, {"ingredient": "Dry sherry", "measure": "250ml"}, {"ingredient": "Chicken Stock", "measure": "350ml"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Cloves", "measure": "Pinch"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Egg", "measure": "2"}, {"ingredient": "Almonds", "measure": "2 tblsp"}], "instructions": "step 1\r\nPut the saffron in a small bowl with 75ml of just-boiled water. Stir and set aside. Heat 2 tbsp of the oil in a broad, shallow casserole dish. Cook the garlic until pale gold in colour, then add the blanched almonds and bread, and continue to fry until everything is golden. Tip into a food processor with some salt and pepper and the parsley, and whizz together.\r\n\r\nstep 2\r\nHeat 2 more tbsp of the oil in the pan and brown the chicken all over, seasoning as you cook. Put in a bowl and set aside.\r\n\r\nstep 3\r\nRemove all but about 2 tbsp of chicken fat from the pan and cook the onion, carrot and celery until golden. Add the sherry, stirring to dislodge any brown bits that have stuck to the pan. Pour in the stock and the saffron (with its water), and bring to the boil, then turn the heat down to a simmer. Add the spices and bay leaves, and put the chicken back in the pan with any juices. Season and gently cook the chicken for about 40 mins with the lid on.\r\n\r\nstep 4\r\nTransfer the chicken to a bowl again, leaving the sauce in the pan, and cover with foil to keep warm. Remove the yolks from the eggs and roughly chop the whites. Mash the egg yolks in a small bowl and gradually mix in a couple of tbsp of the sauce. Bring the remaining sauce to the boil to reduce a bit (you want it to just coat the chicken), then turn the heat down. Remove the bay and cinnamon stick. Add the egg yolks and cook for a few mins until the mixture has thickened. Stir in the almond mixture that you made earlier (this will thicken the sauce, too). Put the chicken back in the pan and heat it for about 3 mins, spooning the sauce over it. Season to taste.\r\n\r\nstep 5\r\nScatter over the extra parsley, the almonds pieces and the chopped egg whites (if you’re going to use them). You can serve this straight from the dish with some rice, if you like.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 43, "prep_minutes_source": "explicit", "kcal": 660, "protein_g": 38.2, "carbs_g": 23.4, "fat_g": 37.8, "total_kcal": 1981, "total_protein_g": 114.7, "total_carbs_g": 70.2, "total_fat_g": 113.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=dam5k5HCE1Y", "cook_steps": [{"step": 1, "label": "Make the picada", "instruction": "Soak the saffron in just-boiled water. Heat 2 tbsp oil in a casserole dish, cook the garlic until pale gold, then add the almonds and bread and fry until golden. Blitz in a food processor with salt, pepper and parsley.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Brown the chicken", "instruction": "Heat 2 more tbsp oil and brown the chicken all over, seasoning as you go. Remove and set aside.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Build the sauce", "instruction": "Remove most of the fat from the pan and cook the onion, carrot and celery until golden. Add the sherry, scraping up any bits, then the stock and saffron water, and bring to the boil. Add the spices and bay leaves, return the chicken with its juices, and simmer gently with the lid on for about 40 minutes.", "timer_seconds": 2400, "background": true}, {"step": 4, "label": "Thicken with the egg yolks", "instruction": "Remove the chicken and keep warm, leaving the sauce in the pan. Mash the egg yolks with a couple of tbsp of the sauce, then stir in. Reduce the remaining sauce slightly, remove the bay and cinnamon, then add the egg yolk mixture and cook a few minutes until thickened. Stir in the almond picada, return the chicken, and heat through for about 3 minutes, spooning over the sauce.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Serve", "instruction": "Scatter over the extra parsley, almonds and chopped egg whites. Serve straight from the dish with rice, if you like.", "timer_seconds": null, "background": false}]}, {"id": "53163", "name": "Spanish fig & almond balls", "category": "Dessert", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/si2rty1763282314.jpg", "local_image": "53163.jpg", "ingredients": [{"ingredient": "Almonds", "measure": "100g"}, {"ingredient": "Figs", "measure": "500g"}, {"ingredient": "Dried Apricots", "measure": "85g"}, {"ingredient": "Dried cranberries", "measure": "50g"}, {"ingredient": "Brandy", "measure": "1 tablespoon"}, {"ingredient": "Clear Honey", "measure": "1 tblsp"}, {"ingredient": "Cloves", "measure": "1 teaspoon"}, {"ingredient": "Sesame Seed", "measure": "100g"}], "instructions": "step 1\r\nWhizz the almonds in a food processor until most are finely chopped, then tip into a large bowl. Roughly chop the figs, then whizz to a smooth sticky paste. Scrape onto the almonds then, using your hands, mix together well with the dried fruit, brandy, honey and cloves.\r\n\r\nstep 2\r\nDivide the mixture into 6 and roll into balls. Tip the sesame seeds onto a tray, then roll the balls in them until covered. Cover the tray loosely with a clean tea towel, then leave the fig balls to dry for a week before packaging. Will keep in a cool place for 2 months.", "equipment_tags": ["FoodProcessor"], "portions": 6, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 334, "protein_g": 7.7, "carbs_g": 42.7, "fat_g": 17.2, "total_kcal": 2002, "total_protein_g": 46.3, "total_carbs_g": 256.3, "total_fat_g": 103.3, "macro_confidence": 1.0, "is_new": false, "video": null, "cook_steps": [{"step": 1, "label": "Make the paste", "instruction": "Whizz the almonds in a food processor until mostly finely chopped, then tip into a bowl. Roughly chop the figs and whizz to a smooth, sticky paste, then scrape onto the almonds and mix well with the dried fruit, brandy, honey and cloves.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Shape and coat", "instruction": "Divide the mixture into 6 and roll into balls. Roll in sesame seeds until covered.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Dry", "instruction": "Cover loosely with a clean tea towel and leave to dry for a week before packaging. Will keep in a cool place for 2 months.", "timer_seconds": null, "background": true}]}, {"id": "53164", "name": "Spanish Chicken", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/pqulvm1763282839.jpg", "local_image": "53164.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "8"}, {"ingredient": "Onion", "measure": "3 sliced thinly"}, {"ingredient": "Paprika", "measure": "2 teaspoons"}, {"ingredient": "Lemon", "measure": "Zest and juice of 1"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Chicken Stock", "measure": "150ml"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}], "instructions": "step 1\r\nHeat oven to 190C/170C fan/gas 5. Put all the ingredients into a large, wide ovenproof dish. Mix everything together with your hands and season.\r\n\r\nstep 2\r\nBake for 45 mins, stirring the onions after 20 mins, until the chicken is golden and the onions tender. Serve with rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 393, "protein_g": 43.5, "carbs_g": 20.9, "fat_g": 14.7, "total_kcal": 785, "total_protein_g": 87.0, "total_carbs_g": 41.8, "total_fat_g": 29.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=fKqSOn5NCrk", "cook_steps": [{"step": 1, "label": "Mix everything together", "instruction": "Heat the oven to 190C/170C fan/gas 5. Put all the ingredients into a large, wide ovenproof dish, mix together with your hands, and season.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Bake", "instruction": "Bake for 45 minutes, stirring the onions after 20 minutes, until the chicken is golden and the onions tender. Serve with rice.", "timer_seconds": 2700, "background": true}]}, {"id": "53165", "name": "Torrijas with sherry", "category": "Breakfast", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/f3ee3y1763309332.jpg", "local_image": "53165.jpg", "ingredients": [{"ingredient": "Egg", "measure": "2 medium"}, {"ingredient": "Double Cream", "measure": "2 tbsp"}, {"ingredient": "Milk", "measure": "2 tblsp"}, {"ingredient": "Golden Caster Sugar", "measure": "3 tsp"}, {"ingredient": "Sweet Sherry", "measure": "3  tablespoons"}, {"ingredient": "Bread", "measure": "4 thick slices"}, {"ingredient": "Olive Oil", "measure": "For frying"}, {"ingredient": "Icing Sugar", "measure": "To serve"}, {"ingredient": "Creme Fraiche", "measure": "To serve"}], "instructions": "step 1\r\nIn a wide, shallow bowl, beat the eggs with the cream, milk, golden caster sugar and sherry. Cut each slice of bread in two and dip them into the egg mix, turning to make sure they get a good coating on either side. Soak bread in egg mixture for 10 mins to absorb the liquid (carefully turn them over from time to time and make sure they don’t get too soggy).\r\n\r\nstep 2\r\nHeat 1½ tbsp olive oil in a large frying pan and cook the bread for about 3 mins on each side until dark golden and crisp on the edge. Keep the slices warm in a low oven as you cook the rest.\r\n\r\nstep 3\r\nDivide the torrijas between plates and dust with the icing sugar. Serve with crème fraîche or Greek yogurt on the side.", "equipment_tags": [], "portions": 2, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 699, "protein_g": 16.8, "carbs_g": 73.7, "fat_g": 35.4, "total_kcal": 1398, "total_protein_g": 33.6, "total_carbs_g": 147.4, "total_fat_g": 70.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=RGUp1N5KAGY", "cook_steps": [{"step": 1, "label": "Soak the bread", "instruction": "In a wide, shallow bowl, beat the eggs with the cream, milk, sugar and sherry. Cut each slice of bread in two and dip into the egg mix, turning to coat both sides. Soak for 10 minutes to absorb the liquid, turning occasionally so it doesn't get too soggy.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Fry the bread", "instruction": "Heat the olive oil in a large frying pan and cook the bread for about 3 minutes on each side, until dark golden and crisp at the edges. Keep warm in a low oven as you cook the rest.", "timer_seconds": 360, "background": false}, {"step": 3, "label": "Serve", "instruction": "Divide between plates and dust with icing sugar. Serve with crème fraîche or Greek yogurt on the side.", "timer_seconds": null, "background": false}]}, {"id": "53166", "name": "Chickpea, chorizo & spinach stew", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/xvnx8j1763287209.jpg", "local_image": "53166.jpg", "ingredients": [{"ingredient": "Extra Virgin Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Carrots", "measure": "1 Diced"}, {"ingredient": "Celery", "measure": "1 Diced"}, {"ingredient": "Thyme", "measure": "3"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Chorizo", "measure": "200g"}, {"ingredient": "Cinnamon", "measure": "1/4 tsp"}, {"ingredient": "Paprika", "measure": "1 teaspoon"}, {"ingredient": "Chickpeas", "measure": "800g"}, {"ingredient": "Sherry vinegar", "measure": "2 tblsp"}, {"ingredient": "Spinach", "measure": "400g"}], "instructions": "step 1\r\nHeat the oil in a large pan, then gently fry the onion for 3-4 mins until it begins to soften. Stir in the carrot, celery, thyme and bay leaves. Season, then cook for 2-3 mins, stirring occasionally. Add the garlic, chorizo, cinnamon and smoked paprika. Gently fry until the vegetables soften and the chorizo starts to release its oils and crisp up.\r\n\r\nstep 2\r\nStir in the chickpeas, vinegar and 150ml water, then bring to a simmer for 1-2 mins until the chickpeas have heated up. Add the spinach, then stir through the chickpeas until it wilts a little. Remove from the heat, season to taste, then serve warm with crusty bread.", "equipment_tags": [], "portions": 4, "prep_minutes": 9, "prep_minutes_source": "explicit", "kcal": 766, "protein_g": 35.6, "carbs_g": 74.3, "fat_g": 39.3, "total_kcal": 3063, "total_protein_g": 142.5, "total_carbs_g": 297.4, "total_fat_g": 157.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=nI2Sm4B3gWU", "cook_steps": [{"step": 1, "label": "Build the base", "instruction": "Heat the oil in a large pan and gently fry the onion for 3 to 4 minutes until softening. Stir in the carrot, celery, thyme and bay leaves, season, and cook for 2 to 3 minutes, stirring occasionally. Add the garlic, chorizo, cinnamon and smoked paprika, and fry gently until the vegetables soften and the chorizo starts to crisp.", "timer_seconds": 420, "background": false}, {"step": 2, "label": "Simmer and wilt the spinach", "instruction": "Stir in the chickpeas, vinegar and water, then bring to a simmer for 1 to 2 minutes until the chickpeas are heated through. Add the spinach and stir until wilted, then season to taste and serve warm with crusty bread.", "timer_seconds": 120, "background": false}]}, {"id": "53167", "name": "Seafood rice", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/5r5rvx1763287943.jpg", "local_image": "53167.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tbsp"}, {"ingredient": "Leek", "measure": "1 sliced"}, {"ingredient": "Chorizo", "measure": "110g"}, {"ingredient": "Turmeric", "measure": "1 teaspoon"}, {"ingredient": "Rice", "measure": "300g"}, {"ingredient": "Fish Stock", "measure": "1 L"}, {"ingredient": "Peas", "measure": "200g"}, {"ingredient": "Frozen Seafood mix", "measure": "400g"}], "instructions": "step 1\r\nHeat the oil in a deep frying pan, then soften the leek for 5 mins without browning. Add the chorizo and fry until it releases its oils. Stir in the turmeric and rice until coated by the oils, then pour in the stock. Bring to the boil, then simmer for 15 mins, stirring occasionally.\r\n\r\nstep 2\r\nTip in the peas and cook for 5 mins, then stir in the seafood to heat through for a final 1-2 mins cooking or until rice is cooked. Check for seasoning and serve immediately with lemon wedges.", "equipment_tags": [], "portions": 4, "prep_minutes": 27, "prep_minutes_source": "explicit", "kcal": 579, "protein_g": 31.2, "carbs_g": 72.9, "fat_g": 16.5, "total_kcal": 2316, "total_protein_g": 124.7, "total_carbs_g": 291.4, "total_fat_g": 65.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=Dr8Nsod20yg", "cook_steps": [{"step": 1, "label": "Cook the rice", "instruction": "Heat the oil in a deep frying pan and soften the leek for 5 minutes without browning. Add the chorizo and fry until it releases its oils. Stir in the turmeric and rice until coated, then pour in the stock, bring to the boil, and simmer for 15 minutes, stirring occasionally.", "timer_seconds": 900, "background": true}, {"step": 2, "label": "Finish", "instruction": "Tip in the peas and cook for 5 minutes, then stir in the seafood to heat through for a final 1 to 2 minutes, or until the rice is cooked. Check the seasoning and serve immediately with lemon wedges.", "timer_seconds": 300, "background": false}]}, {"id": "53168", "name": "Chorizo & chickpea soup", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/kggfo91763288633.jpg", "local_image": "53168.jpg", "ingredients": [{"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Chorizo", "measure": "110g"}, {"ingredient": "Savoy Cabbage", "measure": "140g"}, {"ingredient": "Chilli Flakes", "measure": "Sprinkling"}, {"ingredient": "Chickpeas", "measure": "400g can"}, {"ingredient": "Chicken Stock", "measure": "1"}, {"ingredient": "Crusty Bread", "measure": "To serve"}], "instructions": "step 1\r\nPut a medium pan on the heat and tip in the tomatoes, followed by a can of water. While the tomatoes are heating, quickly chop the chorizo into chunky pieces (removing any skin) and shred the cabbage.\r\n\r\nstep 2\r\nPile the chorizo and cabbage into the pan with the chilli flakes and chickpeas, then crumble in the stock cube. Stir well, cover and leave to bubble over a high heat for 6 mins or until the cabbage is just tender. Ladle into bowls and eat with crusty or garlic bread.", "equipment_tags": [], "portions": 2, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 679, "protein_g": 35.5, "carbs_g": 76.6, "fat_g": 27.1, "total_kcal": 1358, "total_protein_g": 70.9, "total_carbs_g": 153.2, "total_fat_g": 54.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=I_oZ8r6VxL4", "cook_steps": [{"step": 1, "label": "Start the base", "instruction": "Put a medium pan on the heat with the tomatoes and a can of water. While it heats, chop the chorizo into chunky pieces, removing any skin, and shred the cabbage.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Simmer", "instruction": "Add the chorizo and cabbage to the pan with the chilli flakes and chickpeas, crumble in the stock cube, stir well, cover, and let bubble over high heat for 6 minutes, until the cabbage is just tender. Ladle into bowls and eat with crusty or garlic bread.", "timer_seconds": 360, "background": true}]}, {"id": "53169", "name": "Ajo blanco", "category": "Starter", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5jdtie1763289302.jpg", "local_image": "53169.jpg", "ingredients": [{"ingredient": "White bread", "measure": "150g"}, {"ingredient": "Almonds", "measure": "200g"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "50 ml"}, {"ingredient": "Garlic Clove", "measure": "1"}, {"ingredient": "Red Wine Vinegar", "measure": "1 ½ tbsp"}], "instructions": "step 1\r\nTip the bread into a bowl and pour over 350ml water. Leave to soak for 10 mins.\r\n\r\nstep 2\r\nBlend the ingredients together with 350ml water and 1 tsp salt.\r\n\r\nstep 3\r\nLet the soup cool in the fridge for 1 hr or so, then serve with a drizzle of oil and some black pepper.", "equipment_tags": [], "portions": 3, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 659, "protein_g": 18.6, "carbs_g": 39.6, "fat_g": 50.3, "total_kcal": 1976, "total_protein_g": 55.7, "total_carbs_g": 118.7, "total_fat_g": 150.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=AS2mSRtWyW0", "cook_steps": [{"step": 1, "label": "Soak the bread", "instruction": "Tip the bread into a bowl and pour over the water. Leave to soak for 10 minutes.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Blend", "instruction": "Blend the ingredients together with the remaining water and salt.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Chill and serve", "instruction": "Let the soup cool in the fridge for about 1 hour, then serve with a drizzle of oil and some black pepper.", "timer_seconds": 3600, "background": true}]}, {"id": "53170", "name": "Chocolate churros with chocolate & salted caramel sauce", "category": "Dessert", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/erzs951763296201.jpg", "local_image": "53170.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "For frying"}, {"ingredient": "Ice Cream", "measure": "To serve"}, {"ingredient": "Muscovado Sugar", "measure": "120g"}, {"ingredient": "Butter", "measure": "60g"}, {"ingredient": "Double Cream", "measure": "250ml"}, {"ingredient": "Dark Chocolate", "measure": "100g"}, {"ingredient": "Golden Caster Sugar", "measure": "100g"}, {"ingredient": "Cinnamon", "measure": "2 teaspoon"}, {"ingredient": "Plain Flour", "measure": "200g"}, {"ingredient": "Cocoa Powder", "measure": "50g"}, {"ingredient": "Baking Powder", "measure": "1 teaspoon"}, {"ingredient": "Vanilla Extract", "measure": "1 teaspoon"}, {"ingredient": "Melted Butter", "measure": "50g"}], "instructions": "step 1\r\nTo make the sauce, tip the sugar and butter into a saucepan and bring to a simmer until the sugar has melted, then stir in the cream and simmer until you have a smooth sauce, about 2-3 mins. Remove from the heat, stir through a pinch of sea salt and the chocolate, and continue to stir for 2-3 mins, or until it has completely melted. Keep warm or leave to cool for reheating later. For the coating, mix the sugar with the cinnamon and a small pinch of fine sea salt and set aside.\r\n\r\nstep 2\r\nFor the churros, tip the flour, cocoa, baking powder and a large pinch of salt into a bowl. Add the vanilla extract and melted butter, then carefully pour in 250-300ml boiling water and whisk to make a smooth, very thick batter. Leave to cool for a few minutes, then scrape the mixture into a piping bag fitted with a medium star nozzle.\r\n\r\nstep 3\r\nTip sunflower oil into a deep-fat fryer following the manufacturer’s instructions, or a heavy-based pan, ensuring it is no more than a third full. Heat to 170C, or until a cube of bread dropped in browns in 30 seconds. Pipe 12-15cm lengths of dough into the oil, snipping off the end of each one with a pair of scissors as you go. Pipe four or five at a time and cook for around 4 mins, or until golden and crisp, turning them with tongs or a slotted spoon as they cook. Remove from the oil and place on a wire rack. Repeat with the rest of the dough. Leave to cool if reheating later, otherwise roll the churros in the cinnamon sugar and serve immediately with the warm chocolate sauce and ice cream. To reheat the churros, put on a tray and bake for 5-8 mins, then roll in the sugar coating. Meanwhile, warm the sauce in a pan and serve alongside for dipping.", "equipment_tags": [], "portions": 12, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 376, "protein_g": 3.9, "carbs_g": 40.3, "fat_g": 23.5, "total_kcal": 4511, "total_protein_g": 47.2, "total_carbs_g": 483.8, "total_fat_g": 282.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=J45Y5olZCuo", "cook_steps": [{"step": 1, "label": "Make the caramel sauce", "instruction": "Melt the sugar and butter together in a saucepan until simmering, then stir in the cream and simmer until smooth, about 2 to 3 minutes. Remove from the heat, stir through the sea salt and chocolate, and keep stirring for 2 to 3 minutes until fully melted. Keep warm, or cool for reheating later.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Mix the coating", "instruction": "Mix the sugar with the cinnamon and a small pinch of salt for the coating, and set aside.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Make the churro batter", "instruction": "Tip the flour, cocoa, baking powder and salt into a bowl. Add the vanilla and melted butter, then carefully pour in the boiling water and whisk to a smooth, thick batter. Leave to cool for a few minutes, then scrape into a piping bag fitted with a star nozzle.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Fry the churros", "instruction": "Heat the oil to 170°C in a deep-fat fryer or heavy pan no more than a third full. Pipe 12 to 15cm lengths into the oil, snipping off with scissors, and fry 4 to 5 at a time for around 4 minutes until golden and crisp, turning as they cook.", "timer_seconds": 240, "background": false}, {"step": 5, "label": "Coat and serve", "instruction": "Remove and drain on a wire rack, then roll in the cinnamon sugar and serve immediately with the warm chocolate sauce and ice cream.", "timer_seconds": null, "background": false}]}, {"id": "53171", "name": "Salt cod tortilla", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/njj1681763297231.jpg", "local_image": "53171.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "4 tbsp"}, {"ingredient": "Onion", "measure": "1 Large Chopped"}, {"ingredient": "Jersey Royal Potatoes", "measure": "300g"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Egg", "measure": "8"}, {"ingredient": "Parsley", "measure": "2 1/2 Tbs"}, {"ingredient": "Salt Cod", "measure": "300g"}], "instructions": "step 1\r\nHeat half the oil in a frying pan, and sauté the onion over a medium heat until soft and pale gold – this will take about 8 mins. Remove from the pan, set aside, and add the potatoes to the pan. Cook until they are tender but not falling apart, carefully turning every so often. Cover the pan some of the time to help the slices cook through. Add the onions back to the pan along with the garlic and cook for another 4 mins. Tip into a bowl with the eggs, parsley and some seasoning and mix together. Leave to sit for half an hour.\r\n\r\nstep 2\r\nMeanwhile, put the cod in a saucepan and cover with water. Bring up to a simmer. Remove from the heat, cover and leave for 10 mins. Drain, leave to cool and remove the skin and any bones. Break into large flakes and add to the potato and egg mixture.\r\n\r\nstep 3\r\nHeat the rest of the oil in a non-stick frying pan. Pour in the tortilla mix and cook over a medium-low heat until it is just set and coming away from the sides of the pan. You might need to cover it to help the centre set. Be careful not to overcook it. Put a spatula underneath the tortilla every so often to make sure it isn’t sticking. Slide the tortilla onto a plate, then put the pan on top and flip the tortilla into it, uncooked side-down. Cook over a low heat until golden, or grill until just set. Leave to cool a little before serving.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 22, "prep_minutes_source": "explicit", "kcal": 679, "protein_g": 30.4, "carbs_g": 35.0, "fat_g": 48.0, "total_kcal": 1357, "total_protein_g": 60.7, "total_carbs_g": 70.0, "total_fat_g": 95.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=ga7YoAjGgnA", "cook_steps": [{"step": 1, "label": "Cook the potatoes and onion", "instruction": "Heat half the oil and sauté the onion until soft and pale gold, about 8 minutes. Remove and set aside, then cook the potatoes in the same pan until tender but not falling apart, turning occasionally and covering part of the time to help them cook through. Return the onions with the garlic and cook 4 minutes more.", "timer_seconds": 720, "background": false}, {"step": 2, "label": "Mix and rest", "instruction": "Tip into a bowl with the eggs, parsley and seasoning and mix together. Leave to sit for half an hour.", "timer_seconds": 1800, "background": true}, {"step": 3, "label": "Poach the cod", "instruction": "Meanwhile, put the cod in a saucepan, cover with water, and bring to a simmer. Remove from the heat, cover, and leave for 10 minutes. Drain, cool, remove the skin and bones, and flake into the potato and egg mixture.", "timer_seconds": 600, "background": true}, {"step": 4, "label": "Cook the tortilla", "instruction": "Heat the rest of the oil in a non-stick pan. Pour in the tortilla mix and cook over medium-low heat until just set and coming away from the sides, covering if needed to set the centre. Flip onto a plate and back into the pan, uncooked side down, and cook over low heat until golden, or finish under the grill.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Rest and serve", "instruction": "Leave to cool a little before serving.", "timer_seconds": null, "background": false}]}, {"id": "53172", "name": "Patatas bravas", "category": "Vegetarian", "area": "Spanish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/bvg8sn1763298713.jpg", "local_image": "53172.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Onion", "measure": "1 small finely diced"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Tinned Tomatos", "measure": "225g"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Paprika", "measure": "2 teaspoon"}, {"ingredient": "Chilli Powder", "measure": "Pinch"}, {"ingredient": "Sugar", "measure": "Pinch"}, {"ingredient": "Parsley", "measure": "Chopped"}, {"ingredient": "Potatoes", "measure": "900g"}, {"ingredient": "Olive Oil", "measure": "2 tbsp"}], "instructions": "step 1\r\nHeat the oil in a pan and fry the onion for about 5 mins until softened. Add the garlic, chopped tomatoes, tomato purée, sweet paprika, chilli powder, sugar and a pinch of salt, then bring to the boil, stirring occasionally. Lower to a simmer and cook for 10 mins until pulpy. Can be kept chilled for up to 24 hrs.\r\n\r\nstep 2\r\nHeat oven to 200C/180C fan/gas 6. Pat the potatoes dry with kitchen paper, then tip into a roasting tin and toss in the olive oil and some seasoning. Roast for 40-50 mins until crisp and golden. Tip the potatoes into serving dishes and spoon over the tomato sauce. Sprinkle with some fresh parsley to serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 484, "protein_g": 8.2, "carbs_g": 61.6, "fat_g": 24.1, "total_kcal": 1451, "total_protein_g": 24.6, "total_carbs_g": 184.9, "total_fat_g": 72.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=2Hup2nypG2w", "cook_steps": [{"step": 1, "label": "Make the sauce", "instruction": "Heat the oil and fry the onion for about 5 minutes until softened. Add the garlic, chopped tomatoes, tomato purée, paprika, chilli powder, sugar and a pinch of salt, bring to the boil, then simmer for 10 minutes until pulpy. Can be kept chilled for up to 24 hours.", "timer_seconds": 600, "background": true}, {"step": 2, "label": "Roast the potatoes", "instruction": "Heat the oven to 200C/180C fan/gas 6. Pat the potatoes dry, toss in the olive oil and seasoning in a roasting tin, and roast for 40 to 50 minutes, until crisp and golden.", "timer_seconds": 3000, "background": true}, {"step": 3, "label": "Serve", "instruction": "Spoon the tomato sauce over the potatoes and sprinkle with fresh parsley to serve.", "timer_seconds": null, "background": false}]}, {"id": "53173", "name": "Quick gazpacho", "category": "Starter", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/h5qmn31763304965.jpg", "local_image": "53173.jpg", "ingredients": [{"ingredient": "Passata", "measure": "250g"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Sherry vinegar", "measure": "1 teaspoon"}, {"ingredient": "Lime", "measure": "Juice of 1/2"}], "instructions": "step 1\r\nIn a blender (or with a stick blender), whizz together the passata, red pepper, chilli, garlic, sherry vinegar and lime juice until smooth. Season to taste, then serve with ice cubes", "equipment_tags": ["Blender"], "portions": 2, "prep_minutes": 19, "prep_minutes_source": "estimated", "kcal": 57, "protein_g": 2.7, "carbs_g": 12.6, "fat_g": 0.5, "total_kcal": 115, "total_protein_g": 5.4, "total_carbs_g": 25.1, "total_fat_g": 1.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=sJzHIxlDTHc", "cook_steps": [{"step": 1, "label": "Blend and serve", "instruction": "Blend the passata, red pepper, chilli, garlic, sherry vinegar and lime juice together until smooth. Season to taste and serve with ice cubes.", "timer_seconds": null, "background": false}]}, {"id": "53174", "name": "Prawns with Romesco sauce", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/u03xhi1763308917.jpg", "local_image": "53174.jpg", "ingredients": [{"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Garlic Clove", "measure": "3 Large"}, {"ingredient": "Red Chilli", "measure": "1 large"}, {"ingredient": "Tomato", "measure": "1 large"}, {"ingredient": "Shelled Hazelnuts", "measure": "10"}, {"ingredient": "Almonds", "measure": "10"}, {"ingredient": "Parsley", "measure": "3 sprigs"}, {"ingredient": "Bread", "measure": "1 sliced"}, {"ingredient": "Olive Oil", "measure": "120ml"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tblsp"}, {"ingredient": "Tiger Prawns", "measure": "400g"}], "instructions": "step 1\r\nPrepare ahead - halve the pepper lengthways and remove the seeds and stalk. Line a grill pan with foil and put the pepper halves, skin side up, on the grill pan with the whole garlic cloves, chilli and tomato. Grill for 2 minutes, turn the tomato, then grill for a further 2 minutes. Remove the tomato with a large spoon, then peel, quarter and remove the seeds. Then chop the tomato roughly.\r\n\r\nstep 2\r\nContinue grilling the pepper, chilli and garlic for 4-5 minutes, until the pepper and chilli skins have blackened and the garlic is starting to soften (the garlic skin will start to split when it is ready). When cool enough to handle, peel and halve the chilli, and scrape out and discard the seeds. Peel the pepper and roughly chop both the pepper and chilli.\r\n\r\nstep 3\r\nSpread nuts over the foil and grill until toasted. Finely chop the nuts and parsley in a food processor. Tip into a small bowl.\r\n\r\nstep 4\r\nHeat 3 tablespoons of oil in a frying pan, add the pepper, garlic and chilli and fry for 3 minutes. Tear up the bread and add to the pan, turning it in the oil until lightly browned. Pulse in food processor with the tomatoes, salt, vinegar and oil until roughly chopped. Tip into a bowl. Leave to cool and store in fridge for up to 3 days.\r\n\r\nstep 5\r\nOn the day add the nuts and parsley to the sauce and mix. Serve in a small bowl on a plate with the peeled prawns. Supply cocktail sticks for spearing the prawns.", "equipment_tags": ["FoodProcessor", "Grill"], "portions": 2, "prep_minutes": 12, "prep_minutes_source": "explicit", "kcal": 826, "protein_g": 45.7, "carbs_g": 21.0, "fat_g": 63.9, "total_kcal": 1653, "total_protein_g": 91.4, "total_carbs_g": 41.9, "total_fat_g": 127.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=miqfHkE6rJY", "cook_steps": [{"step": 1, "label": "Grill the tomato", "instruction": "Halve the pepper lengthways, deseed, and place skin-side up on a foil-lined grill pan with the whole garlic cloves, chilli and tomato. Grill for 2 minutes, turn the tomato, then grill 2 minutes more. Remove the tomato, peel, quarter, deseed and roughly chop.", "timer_seconds": 240, "background": false}, {"step": 2, "label": "Grill the pepper, chilli and garlic", "instruction": "Continue grilling for 4 to 5 minutes, until the skins have blackened and the garlic is softening. Once cool enough to handle, peel and chop the pepper and chilli.", "timer_seconds": 300, "background": false}, {"step": 3, "label": "Toast the nuts", "instruction": "Spread the nuts over the foil and grill until toasted, then finely chop with the parsley in a food processor.", "timer_seconds": null, "background": false}, {"step": 4, "label": "Build the sauce", "instruction": "Heat oil in a frying pan, add the pepper, garlic and chilli, and fry for 3 minutes. Tear in the bread and turn in the oil until lightly browned. Pulse in a food processor with the tomatoes, salt, vinegar and oil until roughly chopped. Cool, and store in the fridge for up to 3 days.", "timer_seconds": 180, "background": false}, {"step": 5, "label": "Finish and serve", "instruction": "Add the nuts and parsley to the sauce and mix. Serve in a small bowl alongside the peeled prawns, with cocktail sticks for spearing.", "timer_seconds": null, "background": false}]}, {"id": "53175", "name": "Spanish-style slow-cooked lamb shoulder & beans", "category": "Lamb", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/9kwatm1763327074.jpg", "local_image": "53175.jpg", "ingredients": [{"ingredient": "Lamb Shoulder", "measure": "2.5kg"}, {"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Onion", "measure": "2 chopped"}, {"ingredient": "Carrots", "measure": "4 Chopped"}, {"ingredient": "Garlic Bulb", "measure": "1"}, {"ingredient": "Chicken Stock", "measure": "500ml"}, {"ingredient": "Butter Beans", "measure": "1200g"}, {"ingredient": "Roasted pepper", "measure": "450g"}, {"ingredient": "Black Olives", "measure": "300g"}, {"ingredient": "Parsley", "measure": "4 tablespoons"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Hot smoked paprika", "measure": "1 tablespoon"}, {"ingredient": "Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Rosemary", "measure": "1/2 teaspoon"}], "instructions": "step 1\r\nTo make the spice mix, combine all of the ingredients together with a large pinch of salt. Slash the lamb shoulder all over with a sharp knife and rub in. If you have the time, marinate for up to 24 hrs, but this is not essential.\r\n\r\nstep 2\r\nHeat the oven to 150C/130C fan/gas 2. Heat the oil in a large flameproof casserole dish or roasting tin over a medium-high heat, add the onions, carrots and garlic and sizzle for 5 mins until the onions and carrots are softened. Pour over the stock, then bring to the boil. Nestle the lamb in the pan and cover, then transfer to the oven and roast for 2 hrs.\r\n\r\nstep 3\r\nUncover and transfer the lamb to a plate using tongs. Stir the beans, peppers and olives through the stock in the pan, sit the lamb back on top and return to the oven, uncovered, for 1 hr 30 mins until the lamb is cooked through. Transfer the lamb to a board and shred using two forks. Stir the parsley through the braised beans before serving.", "equipment_tags": [], "portions": 11, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 940, "protein_g": 68.3, "carbs_g": 36.3, "fat_g": 58.0, "total_kcal": 10339, "total_protein_g": 751.3, "total_carbs_g": 399.4, "total_fat_g": 638.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=D35ByGgKNaY", "cook_steps": [{"step": 1, "label": "Rub the lamb", "instruction": "Combine the spice mix ingredients with a large pinch of salt. Slash the lamb shoulder all over and rub in the spice mix. Marinate for up to 24 hours if you have time, though it's not essential.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Braise the lamb", "instruction": "Heat the oven to 150C/130C fan/gas 2. Heat the oil in a large casserole or roasting tin, add the onions, carrots and garlic, and sizzle for 5 minutes until softening. Pour over the stock, bring to the boil, nestle in the lamb, cover, and roast for 2 hours.", "timer_seconds": 7200, "background": true}, {"step": 3, "label": "Add the beans", "instruction": "Uncover and transfer the lamb to a plate. Stir the beans, peppers and olives through the stock, sit the lamb back on top, and return to the oven uncovered for 1 hour 30 minutes, until the lamb is cooked through.", "timer_seconds": 5400, "background": true}, {"step": 4, "label": "Shred and serve", "instruction": "Transfer the lamb to a board and shred with two forks. Stir the parsley through the braised beans before serving.", "timer_seconds": null, "background": false}]}, {"id": "53176", "name": "Spanish tomato bread with jamón Serrano", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/hsp1fo1763327867.jpg", "local_image": "53176.jpg", "ingredients": [{"ingredient": "Tomato", "measure": "4 Chopped"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Baguette", "measure": "20 slices"}, {"ingredient": "Serrano Ham", "measure": "5 Slices"}], "instructions": "step 1\r\nMix together the chopped tomatoes, garlic clove, olive oil, salt and pepper. Keep in the fridge until needed.\r\n\r\nstep 2\r\nTo serve, toast 20 slices of baguette. Spoon a little tomato topping on to each piece of toast. Tear 5-6 slices of jamón Serrano into pieces and put one piece on each slice of bread.", "equipment_tags": [], "portions": 12, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 165, "protein_g": 6.3, "carbs_g": 23.6, "fat_g": 5.0, "total_kcal": 1975, "total_protein_g": 75.1, "total_carbs_g": 283.8, "total_fat_g": 59.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=OG9zuXJht7I", "cook_steps": [{"step": 1, "label": "Make the topping", "instruction": "Mix the chopped tomatoes, garlic, olive oil, salt and pepper. Keep in the fridge until needed.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Assemble", "instruction": "Toast the baguette slices. Spoon a little tomato topping onto each, tear the jamón Serrano into pieces, and top each slice with a piece.", "timer_seconds": null, "background": false}]}, {"id": "53177", "name": "Spaghetti with Spanish flavours", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/vpcqn01763335688.jpg", "local_image": "53177.jpg", "ingredients": [{"ingredient": "Chorizo", "measure": "80g"}, {"ingredient": "Spaghetti", "measure": "300g"}, {"ingredient": "Parsley", "measure": "20g"}, {"ingredient": "Red Pepper", "measure": "2"}, {"ingredient": "Olive Oil", "measure": "2 tbsp"}, {"ingredient": "Parmesan Cheese", "measure": "50g"}], "instructions": "step 1\r\nPut a pan of water on over a high heat to boil. Meanwhile, snip the chorizo into strips with scissors, and chop the parsley and peppers (check for stray seeds first).\r\n\r\nstep 2\r\nWhen the water is boiling briskly, add the spaghetti with a good measure of salt, stir and return to the boil. Cook for 3 minutes.\r\n\r\nstep 3\r\nIn a large frying pan, heat the oil, add the chorizo and peppers and plenty of black pepper. Cook for a minute or so, until heated through and the juices are stained red from the paprika in the chorizo. Scoop half a mugful of pasta water from the pan, drain the remainder and tip the spaghetti into the frying pan.\r\n\r\nstep 4\r\nAdd the parsley and parmesan, toss well and splash in the pasta water, to moisten. Hand round extra parmesan at the table.", "equipment_tags": [], "portions": 3, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 648, "protein_g": 25.9, "carbs_g": 76.6, "fat_g": 25.7, "total_kcal": 1944, "total_protein_g": 77.8, "total_carbs_g": 229.9, "total_fat_g": 77.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=BukrisTBv00", "cook_steps": [{"step": 1, "label": "Boil the water and prep", "instruction": "Put a pan of water on to boil. Meanwhile, snip the chorizo into strips, and chop the parsley and peppers.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Cook the spaghetti", "instruction": "Once boiling briskly, add the spaghetti with plenty of salt, stir, return to the boil, and cook for 3 minutes.", "timer_seconds": 180, "background": false}, {"step": 3, "label": "Cook the chorizo", "instruction": "In a large frying pan, heat the oil, add the chorizo and peppers with plenty of black pepper, and cook for a minute or so, until heated through and stained red from the chorizo's paprika.", "timer_seconds": 60, "background": false}, {"step": 4, "label": "Combine and serve", "instruction": "Scoop out half a mugful of pasta water, drain the rest, and tip the spaghetti into the frying pan. Add the parsley and parmesan, toss well, and splash in the pasta water to moisten. Hand round extra parmesan at the table.", "timer_seconds": null, "background": false}]}, {"id": "53178", "name": "Fried calamari", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/yhi46r1763330279.jpg", "local_image": "53178.jpg", "ingredients": [{"ingredient": "Squid", "measure": "300g"}, {"ingredient": "Plain Flour", "measure": "200g"}, {"ingredient": "Capers", "measure": "2 tblsp"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Mayonnaise", "measure": "5 tblsp"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Lemon", "measure": "To serve"}], "instructions": "step 1\r\nCut the squid into rings about ½cm thick. Tip the flour into a freezer bag and season well. Add the capers, then give everything a good shake to mix together. Tip the squid into the bag, then shake again until all the rings are well coated. Mix together the garlic and mayonnaise, then place in a serving bowl.\r\n\r\nstep 2\r\nPour some oil into a large pan until it comes about 7cm up the sides, but the pan is no more than a third full. Place over a medium heat and let the oil warm up. To test that the oil is ready, place a small piece of bread in the pan – it should sizzle when it touches the oil.\r\n\r\nstep 3\r\nRemove a handful of squid from the flour and shake off any excess. Gently drop into the oil, then cook for about 3 mins until crisp. Remove with a slotted spoon and place on kitchen paper. Repeat with the remaining squid. Serve straight away with the mayonnaise and lemon wedges.", "equipment_tags": [], "portions": 1, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 1799, "protein_g": 68.8, "carbs_g": 167.7, "fat_g": 92.8, "total_kcal": 1799, "total_protein_g": 68.8, "total_carbs_g": 167.7, "total_fat_g": 92.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=VcxMq33G-Do", "cook_steps": [{"step": 1, "label": "Coat the squid", "instruction": "Cut the squid into rings about half a centimetre thick. Season the flour in a freezer bag, add the capers, and shake to mix. Add the squid and shake until well coated. Mix the garlic and mayonnaise in a serving bowl.", "timer_seconds": null, "background": false}, {"step": 2, "label": "Heat the oil", "instruction": "Pour oil into a large pan until it comes about 7cm up the sides, no more than a third full, and heat until a piece of bread sizzles on contact.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Fry", "instruction": "Shake the excess flour off a handful of squid, gently drop into the oil, and cook for about 3 minutes until crisp. Remove with a slotted spoon and drain on kitchen paper; repeat with the rest. Serve straight away with the mayonnaise and lemon wedges.", "timer_seconds": 180, "background": false}]}, {"id": "53179", "name": "Ham croquetas", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/6dpa7m1763331105.jpg", "local_image": "53179.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "75g"}, {"ingredient": "Egg", "measure": "2 large"}, {"ingredient": "Breadcrumbs", "measure": "75g"}, {"ingredient": "Sunflower Oil", "measure": "For frying"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "4 tbsp"}, {"ingredient": "Leek", "measure": "1/2"}, {"ingredient": "jamón ibérico", "measure": "70g"}, {"ingredient": "Plain Flour", "measure": "60g"}, {"ingredient": "Vegetable Stock", "measure": "75 ml"}, {"ingredient": "Milk", "measure": "330ml"}, {"ingredient": "Nutmeg", "measure": "Grated"}], "instructions": "step 1\r\nTo make the filling, heat the olive oil in a pan until it starts to shimmer. Add the leek and sauté until soft but not coloured. Stir in the ham with a wooden spoon, fry for 1 min, then stir in the flour and fry over a medium heat, stirring occasionally, until the mixture is golden but not burnt – this will take about 5 mins.\r\n\r\nstep 2\r\nMeanwhile, combine the stock and milk in a small pan and heat until steaming but not boiling. Season with a few scrapes of nutmeg. Gradually add the liquid, a few tbsp at a time, stirring constantly.\r\n\r\nstep 3\r\nOnce you’ve incorporated all the milk stock, continue to cook the filling over a medium heat for about 10 mins or until it thickens and leaves the sides of the pan when you stir it.\r\n\r\nstep 4\r\nSeason with black pepper, taste and adjust the salt if necessary – the ham can be very salty to start with. The filling is now done: it has to be really thick because you don’t want the croquetas to turn into pancakes.\r\n\r\nstep 5\r\nSmooth the mixture onto a baking tray (30 x 20cm is fine). Once it has stopped steaming, cover with cling film to stop it drying out. Leave to cool before putting it in the fridge for 1 hr.\r\n\r\nstep 6\r\nWhen you're ready for the next stage, line up three bowls: the first filled with the flour, the second with beaten egg and the third with breadcrumbs. Take the ham mixture out of the fridge. Put a little bit of olive oil on your hands to make it easier to roll the croquetas.\r\n\r\nstep 7\r\nRoll a spoonful of the mixture between your palms. The size and shape of the croquetas is up to you, but the easiest is a walnut-sized ball. Then begin coating as follows.\r\n\r\nstep 8\r\nDunk the croquetas into the flour – you want a dusting – followed by the egg, then the breadcrumbs. Put them on a tray and, when you’ve used up all the mixture, place in the fridge for 30 mins.\r\n\r\nstep 9\r\nIf you have a deep-fat fryer, heat the oil to 180C and fry for a couple of mins. If not, heat the oil in a deep, heavy-bottomed saucepan until it starts to shimmer. Then add 5-6 croquetas at a time and fry until golden all over. Once cooked, drain on kitchen paper and eat straight away.", "equipment_tags": [], "portions": 2, "prep_minutes": 106, "prep_minutes_source": "explicit", "kcal": 1039, "protein_g": 35.0, "carbs_g": 89.0, "fat_g": 60.2, "total_kcal": 2078, "total_protein_g": 70.0, "total_carbs_g": 178.1, "total_fat_g": 120.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/nT8MGiWldHk", "cook_steps": [{"step": 1, "label": "Cook the roux", "instruction": "Heat the olive oil until shimmering. Add the leek and sauté until soft but not coloured. Stir in the ham, fry 1 minute, then stir in the flour and fry over medium heat, stirring occasionally, until golden but not burnt, about 5 minutes.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Warm the milk", "instruction": "Meanwhile, combine the stock and milk in a small pan and heat until steaming but not boiling. Season with a few scrapes of nutmeg.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Build the filling", "instruction": "Gradually add the warm milk mixture to the roux, a few tablespoons at a time, stirring constantly, then continue cooking over medium heat for about 10 minutes, until thick and pulling away from the sides of the pan.", "timer_seconds": 600, "background": false}, {"step": 4, "label": "Season", "instruction": "Season with black pepper, tasting and adjusting the salt — the ham can already be quite salty. The filling needs to be really thick so the croquetas hold their shape.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Chill", "instruction": "Smooth the mixture onto a baking tray. Once it stops steaming, cover with cling film and leave to cool, then chill in the fridge for 1 hour.", "timer_seconds": 3600, "background": true}, {"step": 6, "label": "Shape", "instruction": "Line up bowls of flour, beaten egg and breadcrumbs. Oil your hands and roll spoonfuls of the chilled mixture into walnut-sized balls.", "timer_seconds": null, "background": false}, {"step": 7, "label": "Coat and chill again", "instruction": "Dunk each croqueta in the flour, then the egg, then the breadcrumbs. Place on a tray and chill for 30 minutes.", "timer_seconds": 1800, "background": true}, {"step": 8, "label": "Fry", "instruction": "Heat the oil to 180°C in a deep-fat fryer, or a deep, heavy-bottomed pan until shimmering. Fry 5 to 6 croquetas at a time until golden all over, then drain on kitchen paper and eat straight away.", "timer_seconds": 180, "background": false}]}, {"id": "53180", "name": "Garlicky prawns with sherry", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/u2lhqb1763331899.jpg", "local_image": "53180.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Prawns", "measure": "400g"}, {"ingredient": "Dry sherry", "measure": "2 tbsp"}, {"ingredient": "Parsley", "measure": "Handful"}], "instructions": "step 1\r\nHeat the olive oil in a large frying pan. Tip in the garlic slices and cook for a few secs. Then stir through the prawns and cook for a couple of mins until they start to turn pink.\r\n\r\nstep 2\r\nPour over the sherry and cook for a few mins more, just until the prawns are cooked through. Sprinkle with parsley before serving.", "equipment_tags": [], "portions": 1, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 766, "protein_g": 81.5, "carbs_g": 7.2, "fat_g": 43.7, "total_kcal": 766, "total_protein_g": 81.5, "total_carbs_g": 7.2, "total_fat_g": 43.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=2hf2xltFbxQ", "cook_steps": [{"step": 1, "label": "Cook the garlic and prawns", "instruction": "Heat the olive oil in a large frying pan, add the garlic slices, and cook for a few seconds. Stir through the prawns and cook a couple of minutes until they start to turn pink.", "timer_seconds": 120, "background": false}, {"step": 2, "label": "Add the sherry", "instruction": "Pour over the sherry and cook a few minutes more, until the prawns are just cooked through. Sprinkle with parsley before serving.", "timer_seconds": 180, "background": false}]}, {"id": "53181", "name": "Spanish beans with chicken & chorizo", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/bpkxtw1763332446.jpg", "local_image": "53181.jpg", "ingredients": [{"ingredient": "Pinto Beans", "measure": "300g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Paprika", "measure": "1 tablespoon"}, {"ingredient": "Thyme", "measure": "Sprigs of fresh"}, {"ingredient": "Bay Leaves", "measure": "Pinch"}, {"ingredient": "Parsley", "measure": "Bunch"}, {"ingredient": "Chicken Thighs", "measure": "4"}, {"ingredient": "Jersey Royal Potatoes", "measure": "250g"}, {"ingredient": "Chorizo", "measure": "250g"}, {"ingredient": "Spinach", "measure": "100g"}], "instructions": "step 1\r\nSoak the beans for at least 4 hrs or overnight in a large bowl with plenty of water to cover. Next day, rinse and drain, then put in a large heavy based pan with the onion, paprika, herb bundle and chicken. Pour over enough water or stock to cover, bring to the boil, then reduce the heat, cover and simmer for 45 mins.\r\n\r\nstep 2\r\nRemove the chicken to a plate, then add the potatoes and chorizo to the pan. Continue cooking for 30 mins until the beans and potatoes are tender.\r\n\r\nstep 3\r\nDiscard the skin and bones from the chicken and tear into large chunks. Return the chicken to the pan with the spinach and simmer for 5 mins.", "equipment_tags": [], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 691, "protein_g": 46.1, "carbs_g": 46.8, "fat_g": 35.4, "total_kcal": 2073, "total_protein_g": 138.4, "total_carbs_g": 140.3, "total_fat_g": 106.3, "macro_confidence": 0.9, "is_new": false, "video": null, "cook_steps": [{"step": 1, "label": "Soak the beans", "instruction": "Soak the beans for at least 4 hours or overnight in plenty of water.", "timer_seconds": null, "background": true}, {"step": 2, "label": "Simmer the chicken", "instruction": "The next day, rinse and drain the beans and put in a large pan with the onion, paprika, herb bundle and chicken. Cover with water or stock, bring to the boil, then reduce the heat, cover, and simmer for 45 minutes.", "timer_seconds": 2700, "background": true}, {"step": 3, "label": "Add potatoes and chorizo", "instruction": "Remove the chicken to a plate, add the potatoes and chorizo to the pan, and continue cooking for 30 minutes, until the beans and potatoes are tender.", "timer_seconds": 1800, "background": true}, {"step": 4, "label": "Finish", "instruction": "Discard the chicken skin and bones and tear the meat into large chunks. Return to the pan with the spinach and simmer for 5 minutes.", "timer_seconds": 300, "background": false}]}, {"id": "53182", "name": "Spanish seafood rice", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/c6ghxm1763335584.jpg", "local_image": "53182.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Yellow Pepper", "measure": "1"}, {"ingredient": "Garlic Clove", "measure": "2 sliced"}, {"ingredient": "Paella Rice", "measure": "250g"}, {"ingredient": "Vegetable Stock", "measure": "800ml"}, {"ingredient": "Saffron", "measure": "Pinch"}, {"ingredient": "Frozen Seafood mix", "measure": "400g"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Parsley", "measure": "Handful"}], "instructions": "step 1\r\nHeat the oil in a large saucepan and soften the onion for 6-7 mins. Add the pepper and garlic, cook for 2 mins more, then stir in the paella rice and cook for 1 min, stirring to coat.\r\n\r\nstep 2\r\nPour in the stock, add the saffron and bring to the boil. Cook, uncovered, at a gentle bubble, for 20 mins, stirring occasionally until the rice is tender.\r\n\r\nstep 3\r\nStir in the seafood and lemon juice and cook for 2 mins or until piping hot and completely cooked through. Serve in warm bowls scattered with the parsley.", "equipment_tags": [], "portions": 3, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 497, "protein_g": 28.2, "carbs_g": 75.8, "fat_g": 7.6, "total_kcal": 1491, "total_protein_g": 84.7, "total_carbs_g": 227.5, "total_fat_g": 22.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=jA-G6k1wT9M", "cook_steps": [{"step": 1, "label": "Soften the onion", "instruction": "Heat the oil in a large saucepan and soften the onion for 6 to 7 minutes. Add the pepper and garlic and cook 2 minutes more, then stir in the rice and cook for 1 minute, coating it in the oil.", "timer_seconds": 480, "background": false}, {"step": 2, "label": "Cook the rice", "instruction": "Pour in the stock, add the saffron, and bring to the boil. Cook uncovered at a gentle bubble for 20 minutes, stirring occasionally, until the rice is tender.", "timer_seconds": 1200, "background": true}, {"step": 3, "label": "Add the seafood", "instruction": "Stir in the seafood and lemon juice and cook for 2 minutes, until piping hot and cooked through. Serve in warm bowls scattered with parsley.", "timer_seconds": 120, "background": false}]}, {"id": "53183", "name": "Spanish meatballs with clams, chorizo & squid", "category": "Miscellaneous", "area": "Spanish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/2wt8721763334199.jpg", "local_image": "53183.jpg", "ingredients": [{"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Shallots", "measure": "3 diced"}, {"ingredient": "Smoked Paprika", "measure": "1 teaspoon"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Dry sherry", "measure": "2 tblsp"}, {"ingredient": "Breadcrumbs", "measure": "50g"}, {"ingredient": "Pork", "measure": "300g"}, {"ingredient": "Egg Yolks", "measure": "1"}, {"ingredient": "Olive Oil", "measure": "50 ml"}, {"ingredient": "Chorizo", "measure": "300g"}, {"ingredient": "Squid", "measure": "300g"}, {"ingredient": "White Wine", "measure": "100 ml"}, {"ingredient": "Tomato", "measure": "300g"}, {"ingredient": "Clams", "measure": "400g"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "Drizzle"}], "instructions": "step 1\r\nMelt the butter in a heavy-based casserole, then soften the shallots for 5 mins. Add the paprika and crushed garlic and cook for 1 min until the paprika becomes fragrant. Splash in the sherry, then pour the whole lot into a bowl with the breadcrumbs. Season and cool.\r\n\r\nstep 2\r\nAdd the pork mince and the egg yolk to the bowl, then beat well. Shape into 18 small meatballs. Wipe the pan, put on a medium-high heat, then add the oil. Fry the meatballs for 5 mins, just to colour, then lift onto a plate, but keep the oil in the pan. Sizzle the chorizo with the sliced garlic. Add the squid and fry to give a little colour. Now tip in the white wine and bring to the boil, scraping the bottom. Stir in the pulped tomatoes, bring to the boil, then add the meatballs and the clams. Cover and cook for 5 mins until the clam shells open. Discard any that stay shut. Sprinkle with the chopped parsley, drizzle with the extra virgin oil, then serve with crusty bread.", "equipment_tags": [], "portions": 4, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 986, "protein_g": 63.4, "carbs_g": 27.9, "fat_g": 65.1, "total_kcal": 3944, "total_protein_g": 253.5, "total_carbs_g": 111.8, "total_fat_g": 260.4, "macro_confidence": 1.0, "is_new": false, "video": null, "cook_steps": [{"step": 1, "label": "Make the meatball base", "instruction": "Melt the butter in a heavy casserole and soften the shallots for 5 minutes. Add the paprika and crushed garlic and cook 1 minute until fragrant. Splash in the sherry, then pour into a bowl with the breadcrumbs. Season and cool.", "timer_seconds": 300, "background": false}, {"step": 2, "label": "Shape the meatballs", "instruction": "Add the pork mince and egg yolk to the bowl and beat well. Shape into 18 small meatballs.", "timer_seconds": null, "background": false}, {"step": 3, "label": "Brown the meatballs", "instruction": "Wipe the pan, heat the oil over medium-high heat, and fry the meatballs for 5 minutes just to colour, then lift onto a plate, keeping the oil in the pan.", "timer_seconds": 300, "background": false}, {"step": 4, "label": "Cook the chorizo and squid", "instruction": "Sizzle the chorizo with the sliced garlic, add the squid, and fry to give a little colour.", "timer_seconds": null, "background": false}, {"step": 5, "label": "Simmer everything together", "instruction": "Tip in the white wine and bring to the boil, scraping up the bottom. Stir in the pulped tomatoes and bring back to the boil, then add the meatballs and clams. Cover and cook for 5 minutes until the clam shells open, discarding any that stay shut.", "timer_seconds": 300, "background": true}, {"step": 6, "label": "Finish and serve", "instruction": "Sprinkle with chopped parsley, drizzle with extra virgin oil, and serve with crusty bread.", "timer_seconds": null, "background": false}]}, {"id": "53184", "name": "Spanish rice & prawn one-pot", "category": "Seafood", "area": "Spanish", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/sl6vqv1763335988.jpg", "local_image": "53184.jpg", "ingredients": [{"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Green Pepper", "measure": "1 sliced"}, {"ingredient": "Chorizo", "measure": "50g"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Basmati Rice", "measure": "250g"}, {"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Prawns", "measure": "200g"}], "instructions": "step 1\r\nBoil the kettle. In a non-stick frying or shallow pan with a lid, fry the onion, peppers, chorizo and garlic in the oil over a high heat for 3 mins. Stir in the rice and chopped tomatoes with 500ml boiling water, cover, then cook over a high heat for 12 mins.\r\n\r\nstep 2\r\nUncover, then stir – the rice should be almost tender. Stir in the prawns, with a splash more water if the rice is looking dry, then cook for another min until the prawns are just pink and rice tender.", "equipment_tags": [], "portions": 2, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 767, "protein_g": 38.6, "carbs_g": 112.1, "fat_g": 18.1, "total_kcal": 1535, "total_protein_g": 77.2, "total_carbs_g": 224.3, "total_fat_g": 36.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=fhz1QjO1tB0", "cook_steps": [{"step": 1, "label": "Start the rice", "instruction": "Boil the kettle. In a lidded pan, fry the onion, peppers, chorizo and garlic in the oil over high heat for 3 minutes. Stir in the rice and chopped tomatoes with the boiling water, cover, and cook over high heat for 12 minutes.", "timer_seconds": 720, "background": true}, {"step": 2, "label": "Finish with the prawns", "instruction": "Uncover and stir — the rice should be almost tender. Stir in the prawns, with a splash more water if it looks dry, and cook for another minute until the prawns are just pink and the rice tender.", "timer_seconds": 60, "background": false}]}, {"id": "53185", "name": "Chorizo & tomato salad", "category": "Pork", "area": "Spanish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/6cskio1763338156.jpg", "local_image": "53185.jpg", "ingredients": [{"ingredient": "Beef tomatoes", "measure": "3"}, {"ingredient": "Red Onions", "measure": "1/2"}, {"ingredient": "Thyme", "measure": "Sprigs of fresh"}, {"ingredient": "Sherry vinegar", "measure": "1 tablespoon"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Chorizo", "measure": "100g"}], "instructions": "step 1\r\nPut the tomatoes in a bowl with the onion and thyme. Season, then drizzle with the vinegar and oil. Let the flavours mingle while you cook the chorizo.\r\n\r\nstep 2\r\nIn a hot, dry pan, fry the chorizo slices until browned on both sides. Serve the tomatoes with the fried chorizo, drizzled with a little oil from the pan.", "equipment_tags": [], "portions": 4, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 195, "protein_g": 6.9, "carbs_g": 4.8, "fat_g": 16.6, "total_kcal": 780, "total_protein_g": 27.4, "total_carbs_g": 19.3, "total_fat_g": 66.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Dress the tomatoes","instruction":"Put the tomatoes in a bowl with the onion and thyme, season, and drizzle with the vinegar and oil. Set aside to let the flavours mingle while you cook the chorizo.","timer_seconds":null,"background":true},{"step":2,"label":"Fry the chorizo","instruction":"Fry the chorizo slices in a hot, dry pan until browned on both sides. Serve the tomatoes with the fried chorizo, drizzled with a little of the pan oil.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=RFlENguMJNA"}, {"id": "53186", "name": "Chicken with saffron, raisins & pine nuts", "category": "Chicken", "area": "Spanish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/4mhr3u1763481087.jpg", "local_image": "53186.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1.25kg"}, {"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Saffron", "measure": "Pinch"}, {"ingredient": "Dry sherry", "measure": "125ml"}, {"ingredient": "Chicken Stock", "measure": "200ml"}, {"ingredient": "Thyme", "measure": "1 tbsp"}, {"ingredient": "Raisins", "measure": "50g"}, {"ingredient": "Pine Nuts", "measure": "2 tbsp"}, {"ingredient": "Parsley", "measure": "Handful"}], "instructions": "step 1\r\nHeat a large frying pan on a high heat and season the chicken. Add the olive oil to the pan, then the chicken. Brown for about 5 mins on each side, remove onto a plate, then set aside.\r\n\r\nstep 2\r\nLower the heat to medium. In the remaining fat, fry the onions for 3 mins, then add the garlic and saffron. Cook for 3-4 mins more. Add the sherry, then simmer for 3-5 mins until syrupy.\r\n\r\nstep 3\r\nPut the chicken leg pieces back into the pan, tip in the stock, thyme and raisins, cover, then gently cook on a low heat for 20 mins. Add the breast meat and any juices left on the plate. Simmer for 10 mins more until cooked through and the sauce in the pan has reduced.\r\n\r\nstep 4\r\nWhile the chicken is cooking, heat oven to 200C/180C fan/gas 6. Scatter the pine nuts over a baking sheet, then roast for 10 mins until golden and toasted. Once the chicken has cooked through, season to taste, scatter with pine nuts and parsley, then serve with rice.", "equipment_tags": [], "portions": 3, "prep_minutes": 57, "prep_minutes_source": "explicit", "kcal": 890, "protein_g": 90.6, "carbs_g": 19.9, "fat_g": 43.4, "total_kcal": 2669, "total_protein_g": 271.7, "total_carbs_g": 59.8, "total_fat_g": 130.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Brown the chicken","instruction":"Season the chicken and brown in hot olive oil for about 5 minutes on each side, then remove to a plate.","timer_seconds":600,"background":false},{"step":2,"label":"Build the sauce","instruction":"Lower the heat and fry the onions in the remaining fat for 3 minutes, then add the garlic and saffron and cook for 3 to 4 minutes more. Add the sherry and simmer for 3 to 5 minutes until syrupy.","timer_seconds":300,"background":false},{"step":3,"label":"Braise the chicken","instruction":"Return the chicken to the pan with the stock, thyme and raisins, cover, and cook gently on low heat for 20 minutes. Add the breast meat and any juices, then simmer 10 minutes more until cooked through and the sauce has reduced.","timer_seconds":1800,"background":true},{"step":4,"label":"Toast the pine nuts","instruction":"Meanwhile, heat the oven to 200°C/180°C fan/gas 6 and roast the pine nuts on a baking sheet for 10 minutes until golden.","timer_seconds":600,"background":true},{"step":5,"label":"Serve","instruction":"Season to taste, scatter with pine nuts and parsley, and serve with rice.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=uKWjI2DNq0Q"}, {"id": "53187", "name": "Šúĺlance s Makom", "category": "Dessert", "area": "Slovakia", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/d6o4nu1763362422.jpg", "local_image": "53187.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "700g"}, {"ingredient": "All purpose flour", "measure": "300g"}, {"ingredient": "Semolina", "measure": "100g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Ground Poppy seeds", "measure": "150g"}, {"ingredient": "Powdered Sugar", "measure": "100g"}, {"ingredient": "Butter", "measure": "100g"}], "instructions": "1. Prepare the Potatoes\r\n\r\nBoil the potatoes with their skins on until tender.\r\nLet them cool completely (preferably overnight), then peel and mash them finely.\r\n2. Make the Dough\r\n\r\nIn a bowl, combine mashed potatoes, flour, semolina, and salt.\r\nKnead the mixture until you get a smooth, non-sticky dough.\r\n3. Shape the Šúĺlance\r\n\r\nDivide the dough into portions and roll each into a thin rope (about 1.5 cm in diameter).\r\nCut into 3 cm-long pieces and roll between your palms to shape small dumplings.\r\n4. Cook the Dumplings\r\n\r\nBring a pot of salted water to a boil.\r\nDrop in the dumplings in batches and cook until they float to the surface (about 2-3 minutes).\r\nDrain and transfer to a bowl.\r\n5. Prepare the Topping\r\n\r\nIn a separate bowl, mix ground poppy seeds and powdered sugar.\r\nMelt the butter and keep it ready.\r\n6. Assemble the Dish\r\n\r\nDrizzle the cooked dumplings with melted butter.\r\nToss them in the poppy seed-sugar mixture until evenly coated.\r\n7. Serve and Enjoy\r\n\r\nServe warm, optionally with a dusting of extra powdered sugar or a drizzle of honey.", "equipment_tags": [], "portions": 10, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 388, "protein_g": 8.5, "carbs_g": 56.2, "fat_g": 14.9, "total_kcal": 3882, "total_protein_g": 84.6, "total_carbs_g": 561.9, "total_fat_g": 148.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Boil and mash the potatoes","instruction":"Boil the potatoes with their skins on until tender, then let them cool completely, preferably overnight, before peeling and finely mashing.","timer_seconds":null,"background":true},{"step":2,"label":"Make the dough","instruction":"Combine the mashed potatoes with the flour, semolina and salt, and knead until smooth and no longer sticky.","timer_seconds":null,"background":false},{"step":3,"label":"Shape the dumplings","instruction":"Divide the dough into portions and roll each into a thin rope. Cut into short lengths and roll between your palms into small dumplings.","timer_seconds":null,"background":false},{"step":4,"label":"Cook the dumplings","instruction":"Bring a pot of salted water to the boil and cook the dumplings in batches until they float to the surface, about 2 to 3 minutes. Drain and transfer to a bowl.","timer_seconds":180,"background":true},{"step":5,"label":"Make the topping","instruction":"Mix the ground poppy seeds with powdered sugar, and melt the butter.","timer_seconds":null,"background":false},{"step":6,"label":"Assemble","instruction":"Drizzle the dumplings with melted butter, then toss in the poppy seed and sugar mixture until evenly coated.","timer_seconds":null,"background":false},{"step":7,"label":"Serve","instruction":"Serve warm, with an extra dusting of powdered sugar or a drizzle of honey if you like.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/shorts/gUS-__P4nW0"}, {"id": "53188", "name": "Fašírky", "category": "Pork", "area": "Slovakia", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/gtpvwp1763363947.jpg", "local_image": "53188.jpg", "ingredients": [{"ingredient": "Ground Pork", "measure": "500g"}, {"ingredient": "Onion", "measure": "1 medium chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Bread", "measure": "2 sliced"}, {"ingredient": "Milk", "measure": "1 shot"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Salt", "measure": "1 teaspoon"}, {"ingredient": "Black Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Marjoram", "measure": "1 teaspoon"}, {"ingredient": "Mustard", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "1 tablespoon chopped"}, {"ingredient": "Flour", "measure": "1/2 cup"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Breadcrumbs", "measure": "1 cup"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "1. Prepare the Bread Mixture\r\nSoak the bread slices in milk or water until soft.\r\nSqueeze out excess liquid and mash into small crumbs.\r\n2. Mix the Ingredients\r\nIn a large bowl, combine ground meat, chopped onions, garlic, soaked bread, egg, and seasonings.\r\nMix well until evenly combined.\r\n3. Shape the Meat Patties\r\nTake portions of the mixture and shape them into palm-sized patties.\r\nFlatten slightly to help with even cooking.\r\n4. Coat the Patties\r\nLightly dust each patty with flour.\r\nDip into beaten egg, then coat with breadcrumbs for a crispy finish.\r\n5. Fry the Fašírky\r\nHeat vegetable oil in a pan over medium heat.\r\nFry the patties for 4-5 minutes per side until golden brown and fully cooked.\r\nTransfer to a paper towel-lined plate to drain excess oil.\r\n6. Serve and Enjoy\r\nServe Fašírky hot with mashed potatoes, cabbage salad, or fresh bread.\r\nEnjoy with mustard, pickles, or garlic sauce for extra flavor.", "equipment_tags": [], "portions": 2, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 1382, "protein_g": 82.2, "carbs_g": 145.9, "fat_g": 49.8, "total_kcal": 2765, "total_protein_g": 164.3, "total_carbs_g": 291.7, "total_fat_g": 99.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the bread","instruction":"Soak the bread in milk or water until soft, then squeeze out the excess liquid and mash into crumbs.","timer_seconds":null,"background":false},{"step":2,"label":"Mix the patty mixture","instruction":"Combine the ground meat, chopped onion, garlic, soaked bread, egg and seasonings in a large bowl, and mix well.","timer_seconds":null,"background":false},{"step":3,"label":"Shape the patties","instruction":"Shape the mixture into palm-sized patties, flattening slightly for even cooking.","timer_seconds":null,"background":false},{"step":4,"label":"Coat the patties","instruction":"Dust each patty with flour, dip in beaten egg, then coat with breadcrumbs.","timer_seconds":null,"background":false},{"step":5,"label":"Fry","instruction":"Heat oil in a pan and fry the patties for 4 to 5 minutes per side until golden brown and cooked through. Drain on kitchen paper.","timer_seconds":600,"background":false},{"step":6,"label":"Serve","instruction":"Serve hot with mashed potatoes, cabbage salad or bread.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=ecBMVy3p6Ns"}, {"id": "53189", "name": "Zemiakové Placky", "category": "Side", "area": "Slovakia", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0umm891763364625.jpg", "local_image": "53189.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "1 kg"}, {"ingredient": "Onion", "measure": "1 medium chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Egg", "measure": "4 large"}, {"ingredient": "All purpose flour", "measure": "4 tablespoons"}, {"ingredient": "Marjoram", "measure": "1 teaspoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Black Pepper", "measure": "To taste"}, {"ingredient": "Oil", "measure": "For frying"}], "instructions": "1. Prepare the Potatoes\r\nStart by peeling and finely grating the potatoes. To ensure extra crispiness, use a clean kitchen towel to squeeze out as much moisture as possible.\r\n\r\n2. Mix the Ingredients\r\nIn a large mixing bowl, combine the grated potatoes, chopped onion, minced garlic, eggs, flour, marjoram, salt, and black pepper. Stir well until the mixture forms a thick, consistent batter.\r\n\r\n3. Heat the Oil\r\nIn a large frying pan, heat a generous amount of oil over medium heat. The oil should be hot but not smoking.\r\n\r\n4. Fry the Pancakes\r\nSpoon portions of the batter into the pan, flattening each into a thin pancake. Fry until golden brown and crispy on one side, then flip and cook the other side until equally golden and crispy.\r\n\r\n5. Drain & Serve\r\nTransfer the cooked pancakes onto a plate lined with paper towels to remove excess oil. Serve immediately while hot, with sour cream, garlic dip, or as a side dish.", "equipment_tags": [], "portions": 8, "prep_minutes": 70, "prep_minutes_source": "estimated", "kcal": 188, "protein_g": 6.4, "carbs_g": 26.5, "fat_g": 6.5, "total_kcal": 1506, "total_protein_g": 51.5, "total_carbs_g": 212.2, "total_fat_g": 51.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Grate the potatoes","instruction":"Peel and finely grate the potatoes, then squeeze out as much moisture as possible using a clean kitchen towel.","timer_seconds":null,"background":false},{"step":2,"label":"Mix the batter","instruction":"Combine the grated potatoes with the chopped onion, garlic, eggs, flour, marjoram, salt and pepper, and stir into a thick batter.","timer_seconds":null,"background":false},{"step":3,"label":"Heat the oil","instruction":"Heat a generous amount of oil in a large frying pan over medium heat until hot but not smoking.","timer_seconds":null,"background":false},{"step":4,"label":"Fry the pancakes","instruction":"Spoon portions of the batter into the pan, flatten into thin pancakes, and fry until golden and crispy on both sides.","timer_seconds":null,"background":false},{"step":5,"label":"Drain and serve","instruction":"Drain on paper towels and serve hot with sour cream or a garlic dip.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=WfpE70EIw2w"}, {"id": "53190", "name": "Bryndzové Halušky", "category": "Pork", "area": "Slovakia", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/g33c901763365484.jpg", "local_image": "53190.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "500g"}, {"ingredient": "Plain Flour", "measure": "200g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Salt", "measure": "1 teaspoon"}, {"ingredient": "Bryndza cheese", "measure": "250g"}, {"ingredient": "Bacon", "measure": "200g"}, {"ingredient": "Chives", "measure": "Garnish"}], "instructions": "1. Prepare the Dough\r\nGrate the potatoes finely using a hand grater or food processor. Place the grated potatoes in a bowl and mix them with flour, egg, and salt until a sticky dough forms. The consistency should be thick but pliable.\r\n\r\n2. Cook the Dumplings\r\nBring a large pot of salted water to a boil. Using a halušky maker (similar to a spaetzle maker), press the dough directly into the boiling water. If you don’t have one, use a tilted cutting board and a knife to scrape small pieces of dough into the water.\r\n\r\nLet the dumplings cook until they float to the surface, usually within 2-3 minutes. Scoop them out with a slotted spoon and set aside in a large bowl.\r\n\r\n3. Prepare the Toppings\r\nChop the bacon into small pieces and fry in a skillet over medium heat until crispy. If using a bryndza substitute, mix crumbled feta with a dollop of sour cream to mimic the tangy flavour of traditional Slovak sheep cheese.\r\n\r\n4. Assemble the Dish\r\nToss the cooked dumplings with the bryndza cheese (or substitute) until they’re well-coated and creamy. Top with the crispy bacon and its drippings. Garnish with chopped chives or parsley for an extra touch of colour and flavour.", "equipment_tags": ["FoodProcessor"], "portions": 2, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 1575, "protein_g": 85.7, "carbs_g": 123.3, "fat_g": 80.9, "total_kcal": 3150, "total_protein_g": 171.5, "total_carbs_g": 246.7, "total_fat_g": 161.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dough","instruction":"Finely grate the potatoes, then mix with the flour, egg and salt into a sticky but pliable dough.","timer_seconds":null,"background":false},{"step":2,"label":"Cook the dumplings","instruction":"Bring a large pot of salted water to the boil. Press the dough through a halušky maker, or scrape small pieces off a tilted board with a knife, directly into the water, and cook until the dumplings float to the surface, about 2 to 3 minutes. Scoop out with a slotted spoon.","timer_seconds":180,"background":true},{"step":3,"label":"Fry the bacon","instruction":"Meanwhile, chop the bacon and fry in a skillet over medium heat until crispy. If using a bryndza substitute, mix crumbled feta with a dollop of sour cream.","timer_seconds":null,"background":false},{"step":4,"label":"Assemble","instruction":"Toss the cooked dumplings with the bryndza cheese until well coated and creamy, then top with the crispy bacon and its drippings. Garnish with chives or parsley.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/shorts/IPF_VpH7FzI"}, {"id": "53191", "name": "Pad Thai", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/rg9ze01763479093.jpg", "local_image": "53191.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "125g"}, {"ingredient": "Lime", "measure": "Juice of 3"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Muscovado Sugar", "measure": "2 teaspoons"}, {"ingredient": "Fish Sauce", "measure": "2 tablespoons"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Tiger Prawns", "measure": "200g"}, {"ingredient": "Spring Onions", "measure": "4 finely sliced"}, {"ingredient": "Bean Sprouts", "measure": "140g"}, {"ingredient": "Peanuts", "measure": "25g"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Lime", "measure": "2"}, {"ingredient": "sweet chilli sauce", "measure": "To serve"}], "instructions": "step 1\r\nPut the noodles in a large heatproof bowl, pour boiling water over them and leave for 4 minutes, then drain and refresh under cold running water.\r\n\r\nstep 2\r\nPut the lime juice, cayenne, sugar and fish sauce in a bowl and mix well. Have all the other ingredients ready by the cooker.\r\n\r\nstep 3\r\nHeat the oil and fry the prawns until warmed through. Add the spring onions and noodles and toss around. Tip in the lime juice mixture, then stir in the beansprouts and half the peanuts and coriander. Cook for 1 minute until everything is heated through.\r\n\r\nstep 4\r\nPile into a large dish, scatter with the rest of the peanuts and coriander, and serve with lime wedges and sweet chilli sauce.", "equipment_tags": [], "portions": 2, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 657, "protein_g": 35.2, "carbs_g": 91.0, "fat_g": 21.9, "total_kcal": 1314, "total_protein_g": 70.3, "total_carbs_g": 182.0, "total_fat_g": 43.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the noodles","instruction":"Put the noodles in a heatproof bowl, pour over boiling water, and leave for 4 minutes, then drain and refresh under cold water.","timer_seconds":240,"background":true},{"step":2,"label":"Mix the sauce","instruction":"Mix the lime juice, cayenne, sugar and fish sauce together in a bowl. Have all the other ingredients ready by the cooker.","timer_seconds":null,"background":false},{"step":3,"label":"Stir-fry","instruction":"Heat the oil and fry the prawns until warmed through. Add the spring onions and noodles and toss, then stir in the lime juice mixture, beansprouts and half the peanuts and coriander. Cook for 1 minute until heated through.","timer_seconds":60,"background":false},{"step":4,"label":"Serve","instruction":"Pile into a dish, scatter with the remaining peanuts and coriander, and serve with lime wedges and sweet chilli sauce.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=F86GfZIph8o"}, {"id": "53192", "name": "Panang chicken curry (kaeng panang gai)", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/0dhtwr1763371444.jpg", "local_image": "53192.jpg", "ingredients": [{"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Panang Curry Paste", "measure": "1-2tbsp"}, {"ingredient": "Chicken Breast", "measure": "200g"}, {"ingredient": "Green Beans", "measure": "100g"}, {"ingredient": "Fish Sauce", "measure": "2-3 tbsp"}, {"ingredient": "Brown Sugar", "measure": "1-2tbsp"}, {"ingredient": "makrut lime leaves", "measure": "2"}, {"ingredient": "Basil Leaves", "measure": "Handful"}, {"ingredient": "Jasmine Rice", "measure": "Boiled"}, {"ingredient": "Red Chilli", "measure": "6"}, {"ingredient": "Dried Red Chillies", "measure": "4"}, {"ingredient": "Shrimp Paste", "measure": "1 teaspoon"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Galangal", "measure": "1 tblsp"}, {"ingredient": "Lemongrass", "measure": "1 tblsp"}, {"ingredient": "Lime", "measure": "Zest of 2"}, {"ingredient": "Ground Nutmeg", "measure": "1 teaspoon"}, {"ingredient": "Ground Coriander", "measure": "1 tsp"}, {"ingredient": "Ground Cumin", "measure": "1 teaspoon"}, {"ingredient": "Peanuts", "measure": "2 tblsp"}], "instructions": "step 1\r\nFirst, make the curry paste. Use a pestle and mortar to pound together the dried and fresh chillies, shrimp paste, garlic, galangal, lemongrass, lime zest, white pepper, coriander, cumin, nutmeg and peanuts, plus 1 tsp salt. You should have a rough paste. Alternatively, add all the ingredients to a food processor along with 2-3 tbsp of coconut milk and pulse until you have a paste. Store in a lidded jar in the fridge. Will keep for up to two weeks.\r\n\r\nstep 2\r\nAdd 2-3 tbsp of the thick part of the coconut milk into a saucepan over a medium-high heat. When the coconut milk starts bubbling, add 1-2 tbsp of the curry paste and stir well for about 1 min, until fragrant.\r\n\r\nstep 3\r\nStir in the chicken and let it cook for about 3-4 mins until beginning to brown all over. Follow with the French beans and stir well.\r\n\r\nstep 4\r\nSeason with the fish sauce and sugar, then add the rest of coconut milk. Mix well, add half the makrut lime leaves and simmer for 3-5 mins until the chicken is cooked through. Taste and add more sugar or fish sauce if necessary – it should be salty and nutty, and the sweetness should come through. Add the Thai basil leaves, give it a quick mix and take off the heat. Serve with steamed jasmine rice, garnished with the sliced chilli and the rest of the makrut lime leaves.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 684, "protein_g": 28.7, "carbs_g": 60.3, "fat_g": 41.3, "total_kcal": 2052, "total_protein_g": 86.2, "total_carbs_g": 180.9, "total_fat_g": 123.8, "macro_confidence": 0.95, "is_new": false, "cook_steps": [{"step":1,"label":"Make the curry paste","instruction":"Pound the dried and fresh chillies, shrimp paste, garlic, galangal, lemongrass, lime zest, white pepper, coriander, cumin, nutmeg, peanuts and salt into a rough paste using a pestle and mortar, or blitz in a food processor with a little coconut milk. Can be stored in the fridge for up to two weeks.","timer_seconds":null,"background":false},{"step":2,"label":"Cook the paste","instruction":"Heat the thick part of the coconut milk in a saucepan until bubbling, then stir in the curry paste for about 1 minute until fragrant.","timer_seconds":60,"background":false},{"step":3,"label":"Brown the chicken","instruction":"Stir in the chicken and cook for 3 to 4 minutes until it starts to brown, then add the French beans.","timer_seconds":240,"background":false},{"step":4,"label":"Simmer","instruction":"Season with the fish sauce and sugar, add the rest of the coconut milk and half the lime leaves, and simmer for 3 to 5 minutes until the chicken is cooked through. Adjust the seasoning to taste.","timer_seconds":240,"background":false},{"step":5,"label":"Finish","instruction":"Stir in the Thai basil leaves and take off the heat. Serve with steamed jasmine rice, garnished with sliced chilli and the remaining lime leaves.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=dYZHzK7YfYI"}, {"id": "53193", "name": "Drunken noodles (pad kee mao)", "category": "Beef", "area": "Thai", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/2wx8cm1763373419.jpg", "local_image": "53193.jpg", "ingredients": [{"ingredient": "Flat Rice Noodles", "measure": "200g"}, {"ingredient": "Vegetable Oil", "measure": "2 tblsp"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Birds-eye Chillies", "measure": "3 chopped"}, {"ingredient": "Sirloin steak", "measure": "225g"}, {"ingredient": "Broccoli", "measure": "100g"}, {"ingredient": "Basil Leaves", "measure": "Handful"}, {"ingredient": "Soy Sauce", "measure": "4 tbsp"}, {"ingredient": "Oyster Sauce", "measure": "4 tbsp"}, {"ingredient": "Fish Sauce", "measure": "1 teaspoon"}, {"ingredient": "Sugar", "measure": "1 tblsp"}], "instructions": "step 1\r\nPrepare the noodles following pack instructions, then drain and set aside. Combine all the ingredients for the sauce in a small bowl or jug, and set aside.\r\n\r\nstep 2\r\nHeat the oil in a large wok or frying pan over a high heat and stir-fry the garlic and chilli for 20 seconds until just starting to turn golden. Add the steak and stir-fry for 1 minute until seared and starting to brown. Add the broccoli and stir-fry for another minute, then tip in the noodles and add the sauce. Stir-fry for another 1-2 mins until well combined and piping hot.\r\n\r\nstep 3\r\nStir through the basil and turn off the heat. Serve immediately to avoid overcooking.", "equipment_tags": [], "portions": 2, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 778, "protein_g": 35.0, "carbs_g": 106.4, "fat_g": 24.3, "total_kcal": 1555, "total_protein_g": 70.1, "total_carbs_g": 212.8, "total_fat_g": 48.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the noodles and sauce","instruction":"Cook the noodles following the pack instructions, drain and set aside. Combine all the sauce ingredients in a small bowl.","timer_seconds":null,"background":false},{"step":2,"label":"Stir-fry","instruction":"Heat the oil in a wok over high heat and stir-fry the garlic and chilli for 20 seconds until golden. Add the steak and stir-fry for 1 minute until seared, then add the broccoli and stir-fry a minute more. Tip in the noodles and sauce, and stir-fry for 1 to 2 minutes until piping hot.","timer_seconds":180,"background":false},{"step":3,"label":"Finish","instruction":"Stir through the basil and serve immediately to avoid overcooking.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=eJ3w2iJB4x8"}, {"id": "53194", "name": "Tom yum soup with prawns", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/l50vz41763422681.jpg", "local_image": "53194.jpg", "ingredients": [{"ingredient": "Onion", "measure": "200g"}, {"ingredient": "Tomato", "measure": "150g"}, {"ingredient": "Red Chilli", "measure": "20g"}, {"ingredient": "Galangal", "measure": "15g"}, {"ingredient": "Lemongrass Stalks", "measure": "2"}, {"ingredient": "Raw King Prawns", "measure": "250g"}, {"ingredient": "Chicken Stock Cube", "measure": "1"}, {"ingredient": "Oyster Mushrooms", "measure": "120g"}, {"ingredient": "makrut lime leaves", "measure": "8"}, {"ingredient": "Fish Sauce", "measure": "25 ml"}, {"ingredient": "Lime juice", "measure": "25 ml"}, {"ingredient": "Coconut Milk", "measure": "70 ml"}, {"ingredient": "Thai Chilli Jam", "measure": "1 tblsp"}, {"ingredient": "Coriander", "measure": "Handful"}], "instructions": "step 1\r\nPour 1.3 litres water into a large saucepan over a high heat. Add the onion, tomato, chilli, galangal, lemongrass, prawn heads and chicken stock cube. Stir and bring to a boil, then reduce the heat to medium and simmer for 20 mins until the liquid has reduced.\r\n\r\nstep 2\r\nCarefully strain the hot broth into a large heatproof bowl or jug, then discard the prawn heads. Return the strained veg and herb mixture to the saucepan and pour over the broth. Stir through the mushrooms and lime leaves, then cook for 3 mins until the mushrooms are tender.\r\n\r\nstep 3\r\nAdd 1 tbsp sugar, the fish sauce, lime juice, coconut milk and prawns. Bring to the boil and cook until the prawns are cooked through, about 1-2 mins. Remove from the heat. Remove the lemongrass, then stir in the Thai chilli jam, if using. Scatter over the coriander to finish, if you like, and serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 339, "protein_g": 32.1, "carbs_g": 37.2, "fat_g": 10.0, "total_kcal": 678, "total_protein_g": 64.3, "total_carbs_g": 74.3, "total_fat_g": 20.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the broth","instruction":"Bring the water to the boil with the onion, tomato, chilli, galangal, lemongrass, prawn heads and stock cube, then reduce the heat and simmer for 20 minutes until reduced.","timer_seconds":1200,"background":true},{"step":2,"label":"Strain and finish the broth","instruction":"Strain the hot broth into a bowl, discarding the prawn heads. Return the strained vegetables and herbs to the pan, pour over the broth, and stir in the mushrooms and lime leaves. Cook for 3 minutes until the mushrooms are tender.","timer_seconds":180,"background":false},{"step":3,"label":"Add the prawns","instruction":"Add the sugar, fish sauce, lime juice, coconut milk and prawns. Bring to the boil and cook until the prawns are just cooked through, 1 to 2 minutes.","timer_seconds":120,"background":false},{"step":4,"label":"Serve","instruction":"Remove from the heat, discard the lemongrass, and stir in the Thai chilli jam if using. Scatter with coriander to serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=fvLcZg9gNnE"}, {"id": "53195", "name": "Thai curry noodle soup", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/118oj61763423896.jpg", "local_image": "53195.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 teaspoon"}, {"ingredient": "Thai Green Curry Paste", "measure": "1 tbsp"}, {"ingredient": "Stir-fry Vegetables", "measure": "220g"}, {"ingredient": "Raw King Prawns", "measure": "150g"}, {"ingredient": "Coconut Milk", "measure": "150ml"}, {"ingredient": "Vegetable Stock", "measure": "225ml"}, {"ingredient": "Udon Noodles", "measure": "250g"}, {"ingredient": "Coriander", "measure": "10g"}, {"ingredient": "Basil", "measure": "10g"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Spring Onions", "measure": "1 sliced"}], "instructions": "step 1\r\nHeat the oil in a saucepan over a medium heat and cook the curry paste for 1 min before adding the stir-fry veg and prawns. Cook for 3 mins until the prawns are mostly pink, then add the coconut milk, veg stock and noodles.\r\n\r\nstep 2\r\nBring to the boil, then reduce the heat to a simmer and cook for 5 mins until the noodles are cooked through and the veg is tender but still has a bite. Divide between two bowls and sprinkle over the herbs, chilli and spring onion.", "equipment_tags": [], "portions": 2, "prep_minutes": 9, "prep_minutes_source": "explicit", "kcal": 492, "protein_g": 25.6, "carbs_g": 52.0, "fat_g": 22.2, "total_kcal": 984, "total_protein_g": 51.2, "total_carbs_g": 104.0, "total_fat_g": 44.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the curry base","instruction":"Heat the oil and cook the curry paste for 1 minute, then add the stir-fry veg and prawns and cook for 3 minutes until the prawns are mostly pink.","timer_seconds":180,"background":false},{"step":2,"label":"Simmer","instruction":"Add the coconut milk, stock and noodles, bring to the boil, then reduce to a simmer and cook for 5 minutes until the noodles are cooked and the veg still has a bite.","timer_seconds":300,"background":true},{"step":3,"label":"Serve","instruction":"Divide between bowls and sprinkle with the herbs, chilli and spring onion.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=FN8tcugjCFs"}, {"id": "53196", "name": "Tom yum (hot & sour) soup with prawns", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/9c5nlx1763424766.jpg", "local_image": "53196.jpg", "ingredients": [{"ingredient": "Chicken Stock", "measure": "700ml"}, {"ingredient": "Lemongrass", "measure": "1"}, {"ingredient": "Galangal", "measure": "5 Slices"}, {"ingredient": "Coriander", "measure": "6"}, {"ingredient": "makrut lime leaves", "measure": "3"}, {"ingredient": "King Prawns", "measure": "6"}, {"ingredient": "Fish Sauce", "measure": "3  tablespoons"}, {"ingredient": "Green Chilli", "measure": "6 small"}, {"ingredient": "Lime juice", "measure": "4 tablespoons"}], "instructions": "step 1\r\nBring the stock to a boil in a medium-sized saucepan. Add the lemongrass, galangal, coriander roots and lime leaves, then simmer for 2 mins.\r\n\r\nstep 2\r\nAdd the prawns, fish sauce, chillies and lime juice, then return to the boil. Taste and adjust the seasoning with either more lime juice or fish sauce, then garnish with coriander leaves and serve.", "equipment_tags": [], "portions": 4, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 168, "protein_g": 20.4, "carbs_g": 22.4, "fat_g": 1.6, "total_kcal": 672, "total_protein_g": 81.5, "total_carbs_g": 89.6, "total_fat_g": 6.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Simmer the aromatics","instruction":"Bring the stock to the boil, add the lemongrass, galangal, coriander roots and lime leaves, and simmer for 2 minutes.","timer_seconds":120,"background":false},{"step":2,"label":"Finish","instruction":"Add the prawns, fish sauce, chillies and lime juice, and return to the boil. Adjust the seasoning with more lime juice or fish sauce, then garnish with coriander to serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=FJer_Cutb2I"}, {"id": "53197", "name": "Thai pork & peanut curry", "category": "Pork", "area": "Thai", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/snmtd61763426568.jpg", "local_image": "53197.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Spring Onions", "measure": "Bunch"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Pork Tenderloin", "measure": "400g"}, {"ingredient": "Thai Red Curry Paste", "measure": "4 tablespoons"}, {"ingredient": "Peanut Butter", "measure": "4 tablespoons"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Soy Sauce", "measure": "1 tbsp"}, {"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Sweetcorn", "measure": "175g"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Jasmine Rice", "measure": "Steamed"}], "instructions": "step 1\r\nHeat the oil in a large saucepan or flameproof casserole. Add the spring onions and coriander stalks and cook for 1 min. Add the pork slices and cook for 5 mins until starting to brown.\r\n\r\nstep 2\r\nStir in the curry paste and peanut butter. After 30 secs, add the sugar, soy and coconut milk, plus ½ can of water. Mix well, put a lid on and leave to simmer for 15 mins, stirring occasionally.\r\n\r\nstep 3\r\nRemove the lid, add the baby corn and increase the heat. Bubble for 3 mins until the corn is cooked and the sauce has thickened a little. Stir in the lime juice and check the seasoning. Can now be frozen for up to 2 months. To cook from frozen: thoroughly defrost, then heat in a pan on the hob until curry is hot all the way through. Serve scattered with the coriander leaves and rice.", "equipment_tags": [], "portions": 3, "prep_minutes": 24, "prep_minutes_source": "explicit", "kcal": 834, "protein_g": 34.0, "carbs_g": 36.0, "fat_g": 64.6, "total_kcal": 2503, "total_protein_g": 102.0, "total_carbs_g": 108.1, "total_fat_g": 193.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Brown the pork","instruction":"Heat the oil, cook the spring onions and coriander stalks for 1 minute, then add the pork and cook for 5 minutes until starting to brown.","timer_seconds":300,"background":false},{"step":2,"label":"Simmer the curry","instruction":"Stir in the curry paste and peanut butter, then after 30 seconds add the sugar, soy and coconut milk plus half a can of water. Cover and simmer for 15 minutes, stirring occasionally.","timer_seconds":900,"background":true},{"step":3,"label":"Finish","instruction":"Add the baby corn, increase the heat, and bubble for 3 minutes until the corn is cooked and the sauce has thickened. Stir in the lime juice and check the seasoning. Can be frozen for up to 2 months.","timer_seconds":180,"background":false},{"step":4,"label":"Serve","instruction":"Serve scattered with coriander leaves and rice.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=cxryD8ZHCdQ"}, {"id": "53198", "name": "Thai fried rice with prawns & peas", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/hblwvg1763478203.jpg", "local_image": "53198.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "2 tbsp"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Garlic Clove", "measure": "2 sliced"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Raw King Prawns", "measure": "250g"}, {"ingredient": "Brown Rice", "measure": "140g"}, {"ingredient": "Frozen Peas", "measure": "75g"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Egg", "measure": "4 large"}, {"ingredient": "Hotsauce", "measure": "To serve"}], "instructions": "step 1\r\nHeat 1 tbsp of the oil in a wok, add the onion, garlic and chilli, and cook for 2-3 mins until golden. Add the prawns and cook for 1 min. Tip in the rice and peas, and keep tossing until very hot. Add the soy and fish sauce, then stir through the chopped coriander. Keep warm while you fry the eggs.\r\n\r\nstep 2\r\nHeat the remaining oil in a frying pan and fry the eggs with some seasoning. Divide the fried rice mix between 4 bowls and top each with a fried egg. Serve scattered with coriander, with chilli sauce, if you like.", "equipment_tags": [], "portions": 2, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 705, "protein_g": 47.7, "carbs_g": 72.3, "fat_g": 25.4, "total_kcal": 1411, "total_protein_g": 95.4, "total_carbs_g": 144.5, "total_fat_g": 50.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Stir-fry the rice","instruction":"Heat oil in a wok, cook the onion, garlic and chilli for 2 to 3 minutes until golden. Add the prawns and cook for 1 minute, then tip in the rice and peas and toss until very hot. Add the soy and fish sauce, then stir through the coriander. Keep warm.","timer_seconds":180,"background":false},{"step":2,"label":"Fry the eggs and serve","instruction":"Fry the eggs in the remaining oil with seasoning. Divide the rice between bowls, top each with a fried egg, and scatter with coriander and chilli sauce if you like.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=9wZAYbPcF-I"}, {"id": "53199", "name": "Thai beef stir-fry", "category": "Beef", "area": "Thai", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/kyuxew1763479470.jpg", "local_image": "53199.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "2 tbsp"}, {"ingredient": "Beef", "measure": "400g"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Oyster Sauce", "measure": "2 tblsp"}, {"ingredient": "Basil Leaves", "measure": "Handful"}], "instructions": "step 1\r\nHeat a wok or large frying pan until smoking hot. Pour in the oil and swirl around the pan, then tip in the beef strips and chilli. Cook, stirring all the time, until the meat is lightly browned, about 3 mins, then pour over the oyster sauce. Cook until heated through and the sauce coats the meat. stir in the basil leaves and serve with plain rice.", "equipment_tags": [], "portions": 1, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 1006, "protein_g": 82.3, "carbs_g": 8.6, "fat_g": 72.1, "total_kcal": 1006, "total_protein_g": 82.3, "total_carbs_g": 8.6, "total_fat_g": 72.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Stir-fry","instruction":"Heat a wok until smoking, add the oil, then the beef strips and chilli. Stir-fry for about 3 minutes until lightly browned, then pour over the oyster sauce and cook until heated through and coating the meat. Stir in the basil leaves and serve with rice.","timer_seconds":180,"background":false}], "video": "https://www.youtube.com/watch?v=N3OI_7zu5sA"}, {"id": "53200", "name": "Prawn stir-fry", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/96lt871763480970.jpg", "local_image": "53200.jpg", "ingredients": [{"ingredient": "Raw tiger prawns", "measure": "200g"}, {"ingredient": "Green Chilli", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Coriander", "measure": "1  bunch"}, {"ingredient": "Caster Sugar", "measure": "1 tblsp"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Fish Sauce", "measure": "3 tbsp"}, {"ingredient": "Ground Nut Oil", "measure": "2 tablespoons"}, {"ingredient": "Ginger", "measure": "3cm piece"}, {"ingredient": "Spring Onions", "measure": "8 slices"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Water Chestnut", "measure": "85g"}, {"ingredient": "Bean Sprouts", "measure": "100g"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Rice Noodles", "measure": "To serve"}, {"ingredient": "Lime", "measure": "To serve"}], "instructions": "step 1\r\nPut the prawns in a bowl. Put the chilli, garlic, coriander stalks (snip these up using scissors first) and caster sugar in a spice grinder or small food processor and whizz together. Add half of the lime juice and the fish sauce, then pour this over the prawns.\r\n\r\nstep 2\r\nHeat 1 tbsp oil in a wok, add the ginger and spring onions and fry for 1 min. Add the red pepper and fry for 1 min, until the pepper starts to soften. Add the water chestnuts and bean sprouts, and toss together until the bean sprouts start to wilt. Add the soy sauce and a really good grind of black pepper, then tip the lot into a serving dish.\r\n\r\nstep 3\r\nHeat the remaining oil in the wok and add the prawns, lifting them out of their juices. Toss for 1-2 mins until they turn pink, add the marinade and swirl the wok quickly, then tip the lot onto the veg. Snip over the coriander leaves and sprinkle on the remaining lime. Serves over noodles with extra lime for squeezing over.", "equipment_tags": ["FoodProcessor"], "portions": 2, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 434, "protein_g": 28.6, "carbs_g": 51.6, "fat_g": 15.6, "total_kcal": 869, "total_protein_g": 57.1, "total_carbs_g": 103.2, "total_fat_g": 31.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Marinate the prawns","instruction":"Blitz the chilli, garlic, coriander stalks and sugar in a small food processor. Add half the lime juice and the fish sauce, then pour over the prawns.","timer_seconds":null,"background":false},{"step":2,"label":"Cook the vegetables","instruction":"Heat oil in a wok, fry the ginger and spring onions for 1 minute, then add the red pepper and fry a minute more. Add the water chestnuts and bean sprouts and toss until the sprouts start to wilt. Add the soy sauce and black pepper, then tip into a serving dish.","timer_seconds":180,"background":false},{"step":3,"label":"Cook the prawns","instruction":"Heat the remaining oil in the wok, add the prawns lifted from their marinade, and toss for 1 to 2 minutes until pink. Add the marinade and swirl quickly, then tip onto the vegetables.","timer_seconds":120,"background":false},{"step":4,"label":"Serve","instruction":"Snip over the coriander leaves and sprinkle with the remaining lime. Serve over noodles with extra lime.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=DddM8OGb4Jc"}, {"id": "53201", "name": "Stir-fried chicken with chillies & basil", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/el64dy1763483009.jpg", "local_image": "53201.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Chicken", "measure": "450g"}, {"ingredient": "Garlic", "measure": "3 tblsp chopped"}, {"ingredient": "Shallots", "measure": "3 tblsp chopped"}, {"ingredient": "Red Chilli", "measure": "3"}, {"ingredient": "Fish Sauce", "measure": "2 tablespoons"}, {"ingredient": "Soy Sauce", "measure": "2 tsp"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Basil Leaves", "measure": "Handful"}], "instructions": "Heat a wok or large frying pan until it is very hot, then add 1 tbsp of the oil. When it is very hot, add the chicken and stir-fry over a high heat for 8-10 minutes, until browned all over. Using a slotted spoon, take the chicken from the pan and set aside.\r\n\r\nstep 2\r\nReheat the wok and add the remaining oil. Toss in the garlic and shallots and stir fry for 3 minutes, until golden brown.\r\n\r\nstep 3\r\nReturn the chicken to the wok and add the chillies, fish sauce, dark soy sauce and sugar. Stir fry over a high heat for a further 8-10 minutes or until the chicken is cooked through. Stir in the basil leaves and serve at once.", "equipment_tags": [], "portions": 2, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 567, "protein_g": 52.3, "carbs_g": 23.4, "fat_g": 29.0, "total_kcal": 1134, "total_protein_g": 104.6, "total_carbs_g": 46.8, "total_fat_g": 58.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Brown the chicken","instruction":"Heat a wok until very hot, add half the oil, then the chicken, and stir-fry over high heat for 8 to 10 minutes until browned all over. Remove with a slotted spoon and set aside.","timer_seconds":540,"background":false},{"step":2,"label":"Fry the aromatics","instruction":"Reheat the wok with the remaining oil, add the garlic and shallots, and stir-fry for 3 minutes until golden.","timer_seconds":180,"background":false},{"step":3,"label":"Finish","instruction":"Return the chicken to the wok with the chillies, fish sauce, dark soy sauce and sugar. Stir-fry over high heat for 8 to 10 minutes more until the chicken is cooked through. Stir in the basil leaves and serve at once.","timer_seconds":540,"background":false}], "video": "https://www.youtube.com/watch?v=fF4GpyiZL8Q"}, {"id": "53202", "name": "Thai-style steamed fish", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/yx8j1i1763484612.jpg", "local_image": "53202.jpg", "ingredients": [{"ingredient": "Trout", "measure": "2"}, {"ingredient": "Ginger", "measure": "Knob"}, {"ingredient": "Garlic Clove", "measure": "1 small finely diced"}, {"ingredient": "Red Chilli", "measure": "1 small finely diced"}, {"ingredient": "Lime", "measure": "Juice/zest of one"}, {"ingredient": "Baby Pak Koi", "measure": "3"}, {"ingredient": "Soy Sauce", "measure": "2 tblsp"}], "instructions": "step 1\r\nNestle the fish fillets side by side on a large square of foil and scatter the ginger, garlic, chilli and lime zest over them. Drizzle the lime juice on top and then scatter the pieces of pak choi around and on top of the fish. Pour the soy sauce over the pak choi and loosely seal the foil to make a package, making sure you leave space at the top for the steam to circulate as the fish cooks.\r\n\r\nstep 2\r\nSteam for 15 minutes. (If you haven’t got a steamer, put the parcel on a heatproof plate over a pan of gently simmering water, cover with a lid and steam.)", "equipment_tags": [], "portions": 1, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 436, "protein_g": 16.5, "carbs_g": 50.5, "fat_g": 20.6, "total_kcal": 436, "total_protein_g": 16.5, "total_carbs_g": 50.5, "total_fat_g": 20.6, "macro_confidence": 0.71, "is_new": false, "cook_steps": [{"step":1,"label":"Assemble the parcel","instruction":"Lay the fish fillets on a large square of foil and scatter over the ginger, garlic, chilli and lime zest. Drizzle with the lime juice, scatter the pak choi around and on top, and pour over the soy sauce. Loosely seal the foil, leaving space for steam to circulate.","timer_seconds":null,"background":false},{"step":2,"label":"Steam","instruction":"Steam for 15 minutes, or place the parcel on a heatproof plate over a pan of gently simmering water, cover, and steam.","timer_seconds":900,"background":true}], "video": "https://www.youtube.com/watch?v=KQ-dl8fuBlQ"}, {"id": "53203", "name": "Thai rice noodle salad", "category": "Vegetarian", "area": "Thai", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/6g3rso1763486069.jpg", "local_image": "53203.jpg", "ingredients": [{"ingredient": "Vermicelli Rice Noodles", "measure": "1/2 bag"}, {"ingredient": "Bean Sprouts", "measure": "200g"}, {"ingredient": "Lime", "measure": "Zest and juice of 2"}, {"ingredient": "Fish Sauce", "measure": "2-3 tbsp"}, {"ingredient": "Muscovado Sugar", "measure": "1 tsp"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Lettuce", "measure": "2 small"}, {"ingredient": "Minced Pork", "measure": "500g"}, {"ingredient": "Ginger", "measure": "Knob"}, {"ingredient": "Cayenne Pepper", "measure": "Pinch"}, {"ingredient": "Sunflower Oil", "measure": "1 tsp"}, {"ingredient": "Sesame Seed", "measure": "2 tblsp"}, {"ingredient": "Oil", "measure": "1 tsp"}, {"ingredient": "Sirloin steak", "measure": "4"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}], "instructions": "step 1\r\nPlace the noodles and beansprouts in a heatproof bowl and cover with boiling water. Leave for 4 mins, or until the noodles are tender. Drain, then cool under cold running water and drain again. Return to the bowl.\r\n\r\nstep 2\r\nStir together the lime zest and juice, fish or soy sauce and sugar. Stir into the noodles with the red onion and lettuce.\r\n\r\nstep 3\r\nTo make with mince, heat a little oil in a non-stick frying pan and stir-fry 500g minced pork, a small knob of grated ginger and pinch cayenne pepper or chilli powder for 10 mins, until the mince is browned and cooked through. Mix into the noodles, divide between four bowls and serve warm.\r\n\r\nstep 4\r\nTo make with steak, make the rice noodle salad. Heat 1 tsp sunflower oil in a frying pan. Tip 2 tbsp sesame seeds onto a plate. Rub 1 tsp oil into 4 x 175g sirloin steaks and press into sesame seeds. Fry for 5 mins for medium rare, turning halfway. Leave to rest for 5 mins, then thinly slice. Toss 1 deseeded and shredded red chilli, and a handful mint leaves into noodles. Top with steak to serve.", "equipment_tags": [], "portions": 10, "prep_minutes": 24, "prep_minutes_source": "explicit", "kcal": 159, "protein_g": 16.1, "carbs_g": 5.1, "fat_g": 8.1, "total_kcal": 1586, "total_protein_g": 160.6, "total_carbs_g": 51.4, "total_fat_g": 81.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the noodles","instruction":"Place the noodles and beansprouts in a heatproof bowl, cover with boiling water, and leave for 4 minutes until tender. Drain, cool under cold water, and drain again.","timer_seconds":240,"background":true},{"step":2,"label":"Dress the salad","instruction":"Stir together the lime zest and juice, fish or soy sauce and sugar, then stir into the noodles with the red onion and lettuce.","timer_seconds":null,"background":false},{"step":3,"label":"Cook the mince (optional)","instruction":"For a mince version, stir-fry the minced pork with grated ginger and cayenne pepper or chilli powder for 10 minutes until browned and cooked through, then mix into the noodles.","timer_seconds":600,"background":false},{"step":4,"label":"Cook the steak (optional)","instruction":"For a steak version, press the oiled steaks into sesame seeds and fry for 5 minutes for medium rare, turning halfway. Rest for 5 minutes, then slice thinly, toss chilli and mint into the noodles, and top with the steak to serve.","timer_seconds":300,"background":false}], "video": null}, {"id": "53204", "name": "Red curry chicken kebabs", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/prjve31763486864.jpg", "local_image": "53204.jpg", "ingredients": [{"ingredient": "Chicken Breasts", "measure": "2"}, {"ingredient": "Thai Red Curry Paste", "measure": "2 tblsp"}, {"ingredient": "Coconut Milk", "measure": "2 tblsp"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Courgettes", "measure": "1 chopped"}, {"ingredient": "Red Onions", "measure": "1 cut thin wedges"}, {"ingredient": "Lime", "measure": "To serve"}], "instructions": "step 1\r\nFire up the barbecue or heat a griddle pan to high. Tip chicken, curry paste and coconut milk into a bowl, then mix well until the chicken is evenly coated. Thread vegetables and chicken onto skewers. Cook the skewers on the barbecue or griddle for 5-8 mins, turning every so often, until the chicken is cooked through and charred. Serve with herby rice, salad and a lime half to squeeze over.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 524, "protein_g": 71.1, "carbs_g": 21.3, "fat_g": 16.5, "total_kcal": 524, "total_protein_g": 71.1, "total_carbs_g": 21.3, "total_fat_g": 16.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Marinate and skewer","instruction":"Heat the barbecue or a griddle pan to high. Mix the chicken with the curry paste and coconut milk until evenly coated, then thread onto skewers with the vegetables.","timer_seconds":null,"background":false},{"step":2,"label":"Grill","instruction":"Cook the skewers for 5 to 8 minutes, turning every so often, until the chicken is cooked through and charred. Serve with herby rice, salad and a lime half to squeeze over.","timer_seconds":480,"background":false}], "video": "https://www.youtube.com/watch?v=XJscdFRT8_8"}, {"id": "53205", "name": "Thai prawn curry", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/qqlwv91763501559.jpg", "local_image": "53205.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tbls"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Thai Red Curry Paste", "measure": "2 tsp"}, {"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Coconut Cream", "measure": "50g"}, {"ingredient": "Raw Frozen Prawns", "measure": "400g"}, {"ingredient": "Coriander", "measure": "Chopped"}], "instructions": "step 1\r\nHeat the oil in a medium saucepan. Tip in the onion and ginger, then cook for a few mins until softened. Stir in the curry paste, then cook for 1 min more. Pour over the chopped tomatoes and coconut cream. Bring to the boil, then leave to simmer for 5 mins, adding a little boiling water if the mixture gets too thick.\r\n\r\nstep 2\r\nTip in the prawns, then cook for 5-10 mins more, depending on how large they are. Serve alongside some plain rice and sprinkle with a little chopped coriander, if you like.", "equipment_tags": [], "portions": 2, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 625, "protein_g": 44.6, "carbs_g": 21.1, "fat_g": 43.0, "total_kcal": 1250, "total_protein_g": 89.3, "total_carbs_g": 42.1, "total_fat_g": 86.0, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Build the sauce","instruction":"Heat the oil, cook the onion and ginger for a few minutes until softened, then stir in the curry paste for 1 minute more. Pour over the chopped tomatoes and coconut cream, bring to the boil, then simmer for 5 minutes, adding a splash of boiling water if it gets too thick.","timer_seconds":300,"background":false},{"step":2,"label":"Cook the prawns","instruction":"Add the prawns and cook for 5 to 10 minutes depending on size. Serve with plain rice and a scattering of coriander.","timer_seconds":600,"background":false}], "video": "https://www.youtube.com/watch?v=dEMPVKQXSYA"}, {"id": "53206", "name": "Thai chicken cakes with sweet chilli sauce", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/6s3i3p1763488540.jpg", "local_image": "53206.jpg", "ingredients": [{"ingredient": "Chicken Breast", "measure": "2 large"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Ginger", "measure": "1 small"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Coriander", "measure": "4 tbs"}, {"ingredient": "Green Chilli", "measure": "1 chopped"}, {"ingredient": "Olive Oil", "measure": "2 tblsp"}, {"ingredient": "sweet chilli sauce", "measure": "To serve"}, {"ingredient": "Lime", "measure": "To serve"}, {"ingredient": "Spring Onions", "measure": "Chopped"}, {"ingredient": "Red Chilli", "measure": "Chopped"}], "instructions": "step 1\r\nToss the chicken, garlic, ginger, onion, coriander and chilli into a food processor and season well. Blitz until the chicken is finely ground and everything is well mixed. Use your hands to shape six small cakes.\r\n\r\nstep 2\r\nHeat the oil in a frying pan, then fry the cakes over a medium heat for about 6-8 mins, turning once. Serve hot, with sweet chilli sauce, lime wedges, coriander, shredded spring onion and red chilli.", "equipment_tags": ["FoodProcessor"], "portions": 1, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 769, "protein_g": 73.9, "carbs_g": 37.8, "fat_g": 36.8, "total_kcal": 769, "total_protein_g": 73.9, "total_carbs_g": 37.8, "total_fat_g": 36.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Blitz the mixture","instruction":"Blitz the chicken, garlic, ginger, onion, coriander and chilli in a food processor until finely ground and combined. Shape into six small cakes.","timer_seconds":null,"background":false},{"step":2,"label":"Fry","instruction":"Heat the oil and fry the cakes over medium heat for 6 to 8 minutes, turning once. Serve hot with sweet chilli sauce, lime wedges, coriander, spring onion and red chilli.","timer_seconds":420,"background":false}], "video": "https://www.youtube.com/watch?v=pT0WoqUZXw0"}, {"id": "53207", "name": "Tom kha gai", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/ol2xxt1763582263.jpg", "local_image": "53207.jpg", "ingredients": [{"ingredient": "Chicken Stock", "measure": "800ml"}, {"ingredient": "Coconut Milk", "measure": "800g"}, {"ingredient": "Galangal Paste", "measure": "2 tablespoons"}, {"ingredient": "Lemongrass Stalks", "measure": "2"}, {"ingredient": "Lime Leaves", "measure": "8"}, {"ingredient": "Chicken Thighs", "measure": "500g"}, {"ingredient": "Oyster Mushrooms", "measure": "300g"}, {"ingredient": "Birds-eye Chillies", "measure": "6"}, {"ingredient": "Caster Sugar", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "5 tablespoons"}, {"ingredient": "Lime", "measure": "Juice of 3"}, {"ingredient": "Coriander Leaves", "measure": "To serve"}, {"ingredient": "Rice", "measure": "To serve"}], "instructions": "step 1\r\nPour the chicken stock and coconut milk into a large saucepan set over a medium heat. Tip in the galangal, lemongrass and lime leaves, and bring to a gentle simmer, around 6-8 mins. Keeping at a gentle simmer, add the chicken. Cook for 8-10 mins until tender and cooked through.\r\n\r\nstep 2\r\nStir in the mushrooms and chillies, and simmer for a further 3-5 mins until everything is cooked through. Sprinkle in the sugar and 3 tbsp each of the fish sauce and lime juice. Taste and add the remaining if required.\r\n\r\nstep 3\r\nRemove the galangal, lemongrass and lime leaves before serving using a slotted spoon. Ladle into bowls and serve with coriander leaves sprinkled over and steamed rice on the side. Will keep chilled for up to three days. Leave to cool first.", "equipment_tags": [], "portions": 6, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 501, "protein_g": 24.5, "carbs_g": 27.7, "fat_g": 35.5, "total_kcal": 3006, "total_protein_g": 146.8, "total_carbs_g": 166.4, "total_fat_g": 213.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Infuse the broth","instruction":"Bring the chicken stock and coconut milk to a gentle simmer with the galangal, lemongrass and lime leaves, about 6 to 8 minutes. Add the chicken and cook for 8 to 10 minutes until tender and cooked through.","timer_seconds":600,"background":true},{"step":2,"label":"Add the rest","instruction":"Stir in the mushrooms and chillies and simmer for 3 to 5 minutes more. Sprinkle in the sugar and 3 tablespoons each of fish sauce and lime juice, adjusting to taste.","timer_seconds":240,"background":false},{"step":3,"label":"Serve","instruction":"Remove the galangal, lemongrass and lime leaves with a slotted spoon. Ladle into bowls with coriander leaves and steamed rice. Keeps chilled for up to three days once cooled.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=2BbIZwmIP7Q"}, {"id": "53208", "name": "Thai coconut & veg broth", "category": "Vegetarian", "area": "Thai", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/4k8nzy1763583384.jpg", "local_image": "53208.jpg", "ingredients": [{"ingredient": "Thai Red Curry Paste", "measure": "1 ½ tbsp"}, {"ingredient": "Vegetable Oil", "measure": "1 tsp"}, {"ingredient": "Vegetable Stock", "measure": "1 L"}, {"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Brown Sugar", "measure": "2 tsp"}, {"ingredient": "Egg Noodles", "measure": "175g"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Chinese Leaf", "measure": "1/2"}, {"ingredient": "Bean Sprouts", "measure": "150g"}, {"ingredient": "Cherry Tomatoes", "measure": "6"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Spring Onions", "measure": "3 sliced thinly"}, {"ingredient": "Coriander", "measure": "Handful"}], "instructions": "step 1\r\nPlace the curry paste in a large saucepan or wok with the oil. Fry for 1 min until fragrant. Tip in the vegetable stock, coconut milk and brown sugar. Simmer for 3 mins.\r\n\r\nstep 2\r\nAdd the noodles, carrots and Chinese leaf and simmer for 4-6 mins, until all are tender. Mix in beansprouts and tomatoes. Add lime juice to taste and some extra seasoning, if you like. Spoon into bowls and sprinkle with spring onions and coriander.", "equipment_tags": [], "portions": 6, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 277, "protein_g": 6.9, "carbs_g": 26.9, "fat_g": 18.3, "total_kcal": 1663, "total_protein_g": 41.3, "total_carbs_g": 161.5, "total_fat_g": 109.7, "macro_confidence": 0.92, "is_new": false, "cook_steps": [{"step":1,"label":"Fry the paste","instruction":"Fry the curry paste in the oil for 1 minute until fragrant, then add the vegetable stock, coconut milk and brown sugar and simmer for 3 minutes.","timer_seconds":180,"background":false},{"step":2,"label":"Finish","instruction":"Add the noodles, carrots and Chinese leaf and simmer for 4 to 6 minutes until tender. Stir in the beansprouts and tomatoes, adjust with lime juice and seasoning, then spoon into bowls and sprinkle with spring onions and coriander.","timer_seconds":300,"background":false}], "video": "https://www.youtube.com/watch?v=1OeM2sdLOPk"}, {"id": "53209", "name": "Spicy Thai prawn noodles", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/568t931763584227.jpg", "local_image": "53209.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "200g"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tablespoon"}, {"ingredient": "Egg", "measure": "2 Beaten"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Ginger", "measure": "3cm piece"}, {"ingredient": "Prawns", "measure": "450g"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Mint", "measure": "1/2 handful"}, {"ingredient": "Lime", "measure": "Zest and juice of 1"}, {"ingredient": "Peanuts", "measure": "Handful"}], "instructions": "step 1\r\nCook the noodles following the pack instructions, drain and set aside for later. Heat the oil in a large frying pan and pour in the beaten egg. Swirl around the pan to make a thin omelette, cook for 1-2 mins, then flip over and cook the other side for 1 min. Tip out and slice into thin strips.\r\n\r\nstep 2\r\nAdd the chilli and ginger to the pan, fry for 1-2 mins then tip in the noodles, prawns and egg. Splash in the soy sauce and stir-fry for 1 min more. Throw in the chopped herbs and pour over the lime juice and zest, then sprinkle over the chopped peanuts and serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 858, "protein_g": 64.5, "carbs_g": 105.4, "fat_g": 21.9, "total_kcal": 1716, "total_protein_g": 129.1, "total_carbs_g": 210.7, "total_fat_g": 43.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the noodles and omelette","instruction":"Cook the noodles following the pack instructions, drain and set aside. Heat the oil and pour in the beaten egg, swirling to make a thin omelette. Cook 1 to 2 minutes, flip, and cook the other side 1 minute, then slice into strips.","timer_seconds":180,"background":false},{"step":2,"label":"Stir-fry and serve","instruction":"Fry the chilli and ginger for 1 to 2 minutes, then add the noodles, prawns and egg strips. Add the soy sauce and stir-fry for 1 minute more. Stir through the herbs, lime juice and zest, and sprinkle with chopped peanuts.","timer_seconds":120,"background":false}], "video": null}, {"id": "53210", "name": "Thai pumpkin soup", "category": "Vegetarian", "area": "Thai", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/1brbso1763585098.jpg", "local_image": "53210.jpg", "ingredients": [{"ingredient": "Pumpkin", "measure": "1.5kg"}, {"ingredient": "Sunflower Oil", "measure": "4 tsp"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Ginger", "measure": "1 tbsp grated"}, {"ingredient": "Lemongrass", "measure": "1"}, {"ingredient": "Thai Red Curry Paste", "measure": "4 tablespoons"}, {"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Vegetable Stock", "measure": "800ml"}, {"ingredient": "Lime juice", "measure": "To taste"}, {"ingredient": "Sugar", "measure": "To taste"}, {"ingredient": "Red Chilli", "measure": "To serve"}], "instructions": "step 1\r\nHeat oven to 200C/180C fan/gas 6. Toss the pumpkin or squash in a roasting tin with half the oil and seasoning, then roast for 30 mins until golden and tender.\r\n\r\nstep 2\r\nMeanwhile, put the remaining oil in a pan with the onion, ginger and lemongrass. Gently cook for 8-10 mins until softened. Stir in the curry paste for 1 min, followed by the roasted pumpkin, all but 3 tbsp of the coconut milk and the stock. Bring to a simmer, cook for 5 mins, then fish out the lemongrass. Cool for a few mins, then whizz until smooth with a hand blender, or in a large blender in batches. Return to the pan to heat through, seasoning with salt, pepper, lime juice and sugar, if it needs it. Serve drizzled with the remaining coconut milk and scattered with chilli, if you like.", "equipment_tags": ["Blender"], "portions": 6, "prep_minutes": 46, "prep_minutes_source": "explicit", "kcal": 285, "protein_g": 5.5, "carbs_g": 28.9, "fat_g": 20.0, "total_kcal": 1710, "total_protein_g": 33.1, "total_carbs_g": 173.5, "total_fat_g": 119.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Roast the pumpkin","instruction":"Heat the oven to 200°C/180°C fan/gas 6. Toss the pumpkin in half the oil with seasoning and roast for 30 minutes until golden and tender.","timer_seconds":1800,"background":true},{"step":2,"label":"Cook the aromatics","instruction":"Meanwhile, cook the onion, ginger and lemongrass in the remaining oil for 8 to 10 minutes until softened, then stir in the curry paste for 1 minute.","timer_seconds":540,"background":true},{"step":3,"label":"Simmer and blend","instruction":"Add the roasted pumpkin, most of the coconut milk and the stock, bring to a simmer, cook for 5 minutes, then remove the lemongrass. Cool briefly and blend until smooth.","timer_seconds":300,"background":false},{"step":4,"label":"Serve","instruction":"Reheat, season with salt, pepper, lime juice and sugar to taste, then serve drizzled with the remaining coconut milk and scattered with chilli if you like.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=X3BxTRAhgTc"}, {"id": "53211", "name": "Lemongrass beef stew with noodles", "category": "Beef", "area": "Thai", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/ntafxw1763586291.jpg", "local_image": "53211.jpg", "ingredients": [{"ingredient": "Ginger", "measure": "1 tablespoon chopped"}, {"ingredient": "Garlic Clove", "measure": "2 chopped"}, {"ingredient": "Lemongrass Stalks", "measure": "3"}, {"ingredient": "Coriander Leaves", "measure": "2 tblsp"}, {"ingredient": "Red Chilli", "measure": "2 sliced"}, {"ingredient": "Vegetable Oil", "measure": "2 tblsp"}, {"ingredient": "Beef", "measure": "250g"}, {"ingredient": "Soy Sauce", "measure": "2 tblsp"}, {"ingredient": "Five Spice Powder", "measure": "1 tsp"}, {"ingredient": "Brown Sugar", "measure": "1 tsp"}, {"ingredient": "Beef Stock", "measure": "400ml"}, {"ingredient": "Rice Noodles", "measure": "100g"}, {"ingredient": "Lime", "measure": "To serve"}], "instructions": "step 1\r\nPut the ginger, garlic, lemongrass, coriander and 1 chilli in a food processor, then pulse until puréed. Heat the oil in a pan over a low heat. Add the purée and cook for 5 mins. Stir in the beef, soy, five-spice, sugar and stock. Put on a lid and bring to the boil, then lower heat and simmer for 1 hr 15 mins. Remove the lid and cook for a further 15 mins until the beef is tender.\r\n\r\nstep 2\r\nJust before serving, prepare noodles following pack instructions. Drain well, then divide between 2 bowls and spoon over the beef stew. Serve sprinkled with the remaining chilli and coriander leaves, with lime wedges for squeezing over.", "equipment_tags": ["FoodProcessor"], "portions": 2, "prep_minutes": 95, "prep_minutes_source": "explicit", "kcal": 690, "protein_g": 33.8, "carbs_g": 78.9, "fat_g": 29.2, "total_kcal": 1379, "total_protein_g": 67.5, "total_carbs_g": 157.8, "total_fat_g": 58.3, "macro_confidence": 0.92, "is_new": false, "cook_steps": [{"step":1,"label":"Make the purée","instruction":"Purée the ginger, garlic, lemongrass, coriander and one chilli in a food processor.","timer_seconds":null,"background":false},{"step":2,"label":"Simmer the stew","instruction":"Heat the oil, cook the purée for 5 minutes, then stir in the beef, soy, five-spice, sugar and stock. Cover, bring to the boil, then simmer for 1 hour 15 minutes. Uncover and cook a further 15 minutes until the beef is tender.","timer_seconds":5400,"background":true},{"step":3,"label":"Serve","instruction":"Just before serving, cook the noodles following pack instructions, drain, and divide between bowls. Spoon over the beef stew and serve with the remaining chilli, coriander and lime wedges.","timer_seconds":null,"background":false}], "video": null}, {"id": "53212", "name": "Thai drumsticks", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/ittake1763586925.jpg", "local_image": "53212.jpg", "ingredients": [{"ingredient": "sweet chilli sauce", "measure": "2 tablespoons"}, {"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Orange", "measure": "2 tblsp"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Thai Red Curry Paste", "measure": "1 tblsp"}, {"ingredient": "Chicken drumsticks", "measure": "8"}], "instructions": "step 1\r\nHeat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Mix the chilli sauce with the orange zest and juice, garlic, curry paste and ¼ tsp salt. Add the chicken and coat really well.\r\n\r\nstep 2\r\nArrange the drumsticks on the foil, spaced apart. Coat the chicken with any marinade left in the bowl, then roast for 35-40 mins until tender. Wrap in foil or pack into a food container.", "equipment_tags": [], "portions": 1, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 109, "protein_g": 9.8, "carbs_g": 13.1, "fat_g": 2.2, "total_kcal": 109, "total_protein_g": 9.8, "total_carbs_g": 13.1, "total_fat_g": 2.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Marinate","instruction":"Heat the oven to 200°C/180°C fan/gas 6 and line a tray with foil. Mix the chilli sauce with the orange zest and juice, garlic, curry paste and salt, then coat the chicken well.","timer_seconds":null,"background":true},{"step":2,"label":"Roast","instruction":"Arrange the drumsticks on the foil with any remaining marinade, and roast for 35 to 40 minutes until tender.","timer_seconds":2250,"background":true}], "video": "https://www.youtube.com/watch?v=lv1tj9FK3f0"}, {"id": "53213", "name": "Thai-style fish broth with greens", "category": "Seafood", "area": "Thai", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/a2ec961763587756.jpg", "local_image": "53213.jpg", "ingredients": [{"ingredient": "Brown Rice Noodle", "measure": "100g"}, {"ingredient": "Chicken Stock", "measure": "500ml"}, {"ingredient": "Thai Red Curry Paste", "measure": "1 tblsp"}, {"ingredient": "Lime Leaves", "measure": "4"}, {"ingredient": "Fish Sauce", "measure": "1 tblsp"}, {"ingredient": "White Fish", "measure": "200g"}, {"ingredient": "Raw King Prawns", "measure": "100g"}, {"ingredient": "Pak Choi", "measure": "2"}, {"ingredient": "Coriander Leaves", "measure": "Handful"}], "instructions": "step 1\r\nCook the noodles following pack instructions. Refresh in cold water and drain well.\r\n\r\nstep 2\r\nPut the stock in a large saucepan and stir in the curry paste, lime leaves, fish sauce and 250ml cold water. Bring to a simmer and cook for 5 mins.\r\n\r\nstep 3\r\nCut the fish into roughly 3cm cubes and add to the pan. Return to a simmer, then cook for 2 mins uncovered.\r\n\r\nstep 4\r\nStir in the noodles, prawns and pak choi, and simmer for 2-3 mins or until the fish and prawns are just cooked. Serve in bowls scattered with coriander.", "equipment_tags": [], "portions": 2, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 341, "protein_g": 34.5, "carbs_g": 45.0, "fat_g": 2.0, "total_kcal": 681, "total_protein_g": 68.9, "total_carbs_g": 89.9, "total_fat_g": 4.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the noodles","instruction":"Cook the noodles following pack instructions, refresh in cold water, and drain well.","timer_seconds":null,"background":false},{"step":2,"label":"Build the broth","instruction":"Stir the curry paste, lime leaves, fish sauce and water into the stock, bring to a simmer, and cook for 5 minutes.","timer_seconds":300,"background":false},{"step":3,"label":"Add the fish","instruction":"Cut the fish into cubes, add to the pan, and simmer uncovered for 2 minutes.","timer_seconds":120,"background":false},{"step":4,"label":"Finish","instruction":"Stir in the noodles, prawns and pak choi, and simmer for 2 to 3 minutes until the fish and prawns are just cooked. Serve scattered with coriander.","timer_seconds":180,"background":false}], "video": "https://www.youtube.com/watch?v=rRwnwCd5om8"}, {"id": "53214", "name": "Thai green chicken soup", "category": "Chicken", "area": "Thai", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/7kb44y1763589084.jpg", "local_image": "53214.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "2 tblsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Chicken Thighs", "measure": "500g"}, {"ingredient": "Garlic Clove", "measure": "4 sliced"}, {"ingredient": "Thai Green Curry Paste", "measure": "280g"}, {"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Chicken Stock", "measure": "2 Litres"}, {"ingredient": "Lime Leaves", "measure": "5"}, {"ingredient": "Fish Sauce", "measure": "2 tblsp"}, {"ingredient": "Spring Onions", "measure": "1  bunch"}, {"ingredient": "Green Beans", "measure": "280g"}, {"ingredient": "Bamboo Shoot", "measure": "150g"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Basil", "measure": "Bunch"}], "instructions": "step 1\r\nHeat the oil in your largest pan, add the onion and fry for 3 mins to soften. Add the chicken and garlic, and cook until the chicken changes colour.\r\n\r\nstep 2\r\nAdd the curry paste, coconut milk, stock, lime leaves and fish sauce, then simmer for 12 mins. Add the chopped onion tops, green beans and bamboo shoots and cook for 4-6 mins, until the beans are just tender.\r\n\r\nstep 3\r\nMeanwhile, put the lime juice and basil in a narrow jug and blitz with a hand blender to make a smooth green paste. Pour into the soup with the sliced spring onion and heat through. Serve with lime wedges for a light lunch or supper or as a make-ahead starter.", "equipment_tags": ["Blender"], "portions": 8, "prep_minutes": 21, "prep_minutes_source": "explicit", "kcal": 296, "protein_g": 17.6, "carbs_g": 15.3, "fat_g": 19.4, "total_kcal": 2370, "total_protein_g": 141.0, "total_carbs_g": 122.0, "total_fat_g": 155.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the chicken","instruction":"Heat the oil, fry the onion for 3 minutes to soften, then add the chicken and garlic and cook until the chicken changes colour.","timer_seconds":180,"background":false},{"step":2,"label":"Simmer","instruction":"Add the curry paste, coconut milk, stock, lime leaves and fish sauce, then simmer for 12 minutes. Add the chopped onion tops, green beans and bamboo shoots and cook 4 to 6 minutes until the beans are just tender.","timer_seconds":720,"background":true},{"step":3,"label":"Finish","instruction":"Meanwhile, blitz the lime juice and basil into a smooth green paste with a hand blender. Stir into the soup with the sliced spring onion and heat through. Serve with lime wedges.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=3s4Yitd546w"}, {"id": "53215", "name": "Shakshouka", "category": "Miscellaneous", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/crd1jz1763592990.jpg", "local_image": "53215.jpg", "ingredients": [{"ingredient": "Tomato", "measure": "250g"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "40 ml"}, {"ingredient": "Egg", "measure": "4"}, {"ingredient": "Garlic Clove", "measure": "4 sliced"}, {"ingredient": "Black Pepper", "measure": "To taste"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "1\r\nFirst, pan fry the black pepper and garlic over a dry medium heat until fragrant.\r\n2\r\nAdd a good amount of extra virgin olive oil and infuse for a minute.\r\n3\r\nOnce the oil heats up, add the tomatoes and salt, and cover with a lid. Simmer for 5 minutes.\r\n4\r\nRemove the lid and mash the tomatoes. Reduce until you reach the desired consistency of choice.\r\n5\r\nMake craters for the eggs and lower the heat. Carefully crack the eggs into the craters, making sure it touches the pan and not the tomato sauce.\r\n6\r\nCover the eggs and leave it for 5 minutes without lifting the lid.\r\n7\r\nRemove from the heat and let the residual heat steam the eggs for 1-2 minutes.\r\n8\r\nServe with flatbread. Enjoy!", "equipment_tags": [], "portions": 1, "prep_minutes": 12, "prep_minutes_source": "explicit", "kcal": 660, "protein_g": 28.4, "carbs_g": 12.9, "fat_g": 57.3, "total_kcal": 660, "total_protein_g": 28.4, "total_carbs_g": 12.9, "total_fat_g": 57.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Toast the aromatics","instruction":"Pan-fry the black pepper and garlic in a dry pan over medium heat until fragrant.","timer_seconds":null,"background":false},{"step":2,"label":"Infuse the oil","instruction":"Add a generous amount of olive oil and let it infuse for a minute.","timer_seconds":60,"background":false},{"step":3,"label":"Simmer the tomatoes","instruction":"Add the tomatoes and salt, cover, and simmer for 5 minutes.","timer_seconds":300,"background":true},{"step":4,"label":"Reduce","instruction":"Remove the lid and mash the tomatoes, reducing to your desired consistency.","timer_seconds":null,"background":false},{"step":5,"label":"Make craters for the eggs","instruction":"Lower the heat, make craters in the sauce, and carefully crack the eggs into them so they touch the pan rather than the sauce.","timer_seconds":null,"background":false},{"step":6,"label":"Cover and cook","instruction":"Cover and cook for 5 minutes without lifting the lid.","timer_seconds":300,"background":true},{"step":7,"label":"Rest","instruction":"Remove from the heat and let the residual heat steam the eggs for 1 to 2 minutes more.","timer_seconds":90,"background":true},{"step":8,"label":"Serve","instruction":"Serve with flatbread.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=618QsMaVXp8"}, {"id": "53216", "name": "Knafeh", "category": "Dessert", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/76nffj1763593933.jpg", "local_image": "53216.jpg", "ingredients": [{"ingredient": "Knafeh", "measure": "400g"}, {"ingredient": "Unsalted Butter", "measure": "6 tablespoons"}, {"ingredient": "Yellow Food Colouring", "measure": "1 pinch"}, {"ingredient": "Mozzarella", "measure": "1 cup"}, {"ingredient": "Cream Cheese", "measure": "1/4 cup"}, {"ingredient": "Milk", "measure": "1 1/2 cup"}, {"ingredient": "Sugar", "measure": "4 tablespoons"}, {"ingredient": "Corn Flour", "measure": "2 tablespoons"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Rose water", "measure": "1 tsp"}, {"ingredient": "Lemon Juice", "measure": "1/2 teaspoon"}], "instructions": "1\r\nTake kanfhe in a bowl and roughly cut them. Pour melted butter, yellow food color and mix well with your hands.\r\nIn a separate bowl mix milk, cream cheese, sugar, cornstarch well.\r\n2\r\nTurn on the flame and boil the liquid, when it gets thick turn off the flame let it cool down a little bit.\r\nAdd mozzarella in it and mix it well.\r\nNow make a base with half of the kanfhe in a dish, gently press it to level the dough well.\r\nPour the cheese mixture on the top and level it with a spoon.\r\n3\r\nCover it with the other half of the kanfhe.\r\nPut the dish in a preheated oven at 200 degree for about 20-25 minutes.\r\nIt's ready when kunafa is golden and crunchy in the surface.\r\n4\r\nBoil water in a pan and dissolve sugar in it for 4–5 minutes. OR cook it until slightly thicken and keep on stirring. Add lemon juice with rose water, mix well.\r\nEvenly pour the syrup over the kunafa as soon as it comes out of the oven.\r\nYour kunafa is ready to serve.", "equipment_tags": [], "portions": 11, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 306, "protein_g": 9.4, "carbs_g": 32.4, "fat_g": 15.9, "total_kcal": 3364, "total_protein_g": 103.2, "total_carbs_g": 356.8, "total_fat_g": 175.1, "macro_confidence": 0.92, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the kunafa pastry","instruction":"Roughly cut the kunafa, pour over melted butter and yellow food colouring, and mix well by hand.","timer_seconds":null,"background":false},{"step":2,"label":"Make the cheese filling","instruction":"In a separate bowl, mix the milk, cream cheese, sugar and cornstarch.","timer_seconds":null,"background":false},{"step":3,"label":"Cook the filling","instruction":"Bring the liquid to a boil, stirring, until it thickens, then let it cool slightly and stir in the mozzarella.","timer_seconds":null,"background":false},{"step":4,"label":"Build the base","instruction":"Press half of the kunafa into a dish to form an even base, then pour over the cheese mixture and level with a spoon.","timer_seconds":null,"background":false},{"step":5,"label":"Top and bake","instruction":"Cover with the other half of the kunafa and bake in a preheated oven at 200°C for 20 to 25 minutes, until golden and crunchy on top.","timer_seconds":1350,"background":true},{"step":6,"label":"Make the syrup","instruction":"Meanwhile, dissolve sugar in boiling water and cook for 4 to 5 minutes until slightly thickened, then stir in the lemon juice and rose water.","timer_seconds":300,"background":false},{"step":7,"label":"Serve","instruction":"Pour the syrup evenly over the kunafa as soon as it comes out of the oven, and serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=3EF_R7__xu4"}, {"id": "53217", "name": "Shawarma chuck roast wrap", "category": "Beef", "area": "Saudi Arabian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/swo87v1763595282.jpg", "local_image": "53217.jpg", "ingredients": [{"ingredient": "Chuck Roast", "measure": "1kg"}, {"ingredient": "Beef Stock", "measure": "1 cup"}, {"ingredient": "Lemon Juice", "measure": "3  tablespoons"}, {"ingredient": "Ground Cumin", "measure": "1 tablespoon"}, {"ingredient": "Paprika", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Ground Ginger", "measure": "1 tsp"}, {"ingredient": "Turmeric", "measure": "1 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Cinnamon", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Coriander", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Clove", "measure": "1/4 tsp"}], "instructions": "1\r\nIn a dutch oven or slow cooker, add all the spices, beef broth and lemon juice. Stir to combine..\r\n2\r\nAdd the beef and turn to coat, spoon some sauce over the top.\r\n3\r\nCover and cook on low for 8-10 hours.\r\n4\r\nAfter cooking, remove beef and use two forks to shred. Discard any excess fat.\r\n5\r\nSkim fat off of the top of the liquid remaining.\r\n6\r\nMix shredded beef into sauce. Keep warm until you are ready to serve.\r\n7\r\nBuild wrap by spreading garlic sauce on the pita. Top with beef and add garnishes to your liking.\r\n8\r\nFold it burrito style.\r\n9\r\nHeat a grill pan and grill the wrap.", "equipment_tags": ["SlowCooker", "Grill"], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 552, "protein_g": 19.0, "carbs_g": 59.3, "fat_g": 28.7, "total_kcal": 1657, "total_protein_g": 56.9, "total_carbs_g": 178.0, "total_fat_g": 86.0, "macro_confidence": 0.92, "is_new": false, "cook_steps": [{"step":1,"label":"Combine the braising liquid","instruction":"Combine all the spices, beef broth and lemon juice in a Dutch oven or slow cooker.","timer_seconds":null,"background":false},{"step":2,"label":"Add the beef","instruction":"Add the beef, turning to coat, and spoon some sauce over the top.","timer_seconds":null,"background":false},{"step":3,"label":"Slow-cook","instruction":"Cover and cook on low for 8 to 10 hours.","timer_seconds":32400,"background":true},{"step":4,"label":"Shred","instruction":"Remove the beef and shred with two forks, discarding any excess fat.","timer_seconds":null,"background":false},{"step":5,"label":"Finish the sauce","instruction":"Skim the fat from the top of the remaining liquid, then mix the shredded beef back into the sauce and keep warm.","timer_seconds":null,"background":false},{"step":6,"label":"Build the wrap","instruction":"Spread garlic sauce on the pita, top with the beef, and add garnishes to taste. Fold burrito-style.","timer_seconds":null,"background":false},{"step":7,"label":"Grill","instruction":"Heat a grill pan and grill the wrap until warmed through.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/shorts/YLhyRjyLkcE"}, {"id": "53218", "name": "Chicken Shawarma with homemade garlic herb yoghurt sauce", "category": "Chicken", "area": "Saudi Arabian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/hcg6l91763596970.jpg", "local_image": "53218.jpg", "ingredients": [{"ingredient": "Chicken Breast", "measure": "1kg"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Ground Coriander", "measure": "1 tblsp"}, {"ingredient": "Ground Cumin", "measure": "1 tblsp"}, {"ingredient": "Ground Cardomom", "measure": "1 tblsp"}, {"ingredient": "Cayenne Pepper", "measure": "1 tsp"}, {"ingredient": "Smoked Paprika", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "2 tsp"}, {"ingredient": "Lemon Juice", "measure": "2 tblsp"}, {"ingredient": "Olive Oil", "measure": "3 tablespoons"}, {"ingredient": "Greek Yogurt", "measure": "1 cup"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Lemon Juice", "measure": "Splash"}], "instructions": "1\r\nStart by cutting your chicken up into reasonably small slices. Grab your ziplock bag and dump the freshly sliced chicken inside.\r\n2\r\nAdd garlic, coriander, cumin, cardomom, cayenne pepper, paprika, salt, pepper, lemon juice and olive oil to the bag. Close the bag and mix thoroughly. Place in fridge for 10-12 hours (shorter is fine but longer is better).\r\n3\r\nOnce ready to cook, heat your fry pan to medium-high and add a tiny bit of olive oil. Fry one side of all of your flatbreads until slightly toasty. Remove from pan, add enough oil to coat the fry pan. Put crumble fries into air fryer on 180 for 15 minutes shaking occasionally.\r\n4\r\nThe pan should be pretty hot by now, add the chicken in 2 batches (unless you have a big fry pan) to avoid overcrowding. The chicken should get a nice sear and darker colour which is perfect. Cook for a further 5-8 minutes or until cooked through. Repeat with next chicken batch.\r\n5\r\nWhile chicken is cooking, place your Greek yoghurt into a bowl. Combine garlic, finely chopped mint and parsley, squeeze or so of lemon and cumin. Combine and add salt to taste. In a small bowl, combine 1tsp garlic powder, paprika, cumin, onion powder, oregano, dried parsley, cayenne pepper (optional) mix and leave aside for fries.\r\n6\r\nSeason fries immediately once cooked and add salt to taste. Once the chicken is complete, serve immediately by laying out your flatbread, spreading the sauce evenly over the bread, add lettuce, onion, tomato, fries, chicken, feta and more sauce on top. Serve immediately.", "equipment_tags": ["AirFryer"], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 664, "protein_g": 85.0, "carbs_g": 14.5, "fat_g": 29.1, "total_kcal": 1991, "total_protein_g": 254.9, "total_carbs_g": 43.5, "total_fat_g": 87.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Marinate the chicken","instruction":"Slice the chicken and place in a resealable bag with the garlic, coriander, cumin, cardamom, cayenne, paprika, salt, pepper, lemon juice and olive oil. Mix well and marinate in the fridge for 10 to 12 hours.","timer_seconds":39600,"background":true},{"step":2,"label":"Prep the flatbreads and fries","instruction":"Once ready to cook, toast one side of the flatbreads in a hot pan, then set aside. Cook the crumbled fries in an air fryer at 180°C for 15 minutes, shaking occasionally.","timer_seconds":900,"background":true},{"step":3,"label":"Cook the chicken","instruction":"Cook the chicken in the hot pan in batches to avoid overcrowding, searing until deeply coloured and cooked through, about 5 to 8 minutes.","timer_seconds":480,"background":false},{"step":4,"label":"Make the sauce and seasoning","instruction":"Meanwhile, mix the Greek yoghurt with garlic, chopped mint and parsley, lemon juice and cumin, and season. Separately mix garlic powder, paprika, cumin, onion powder, oregano, dried parsley and cayenne for the fries.","timer_seconds":null,"background":false},{"step":5,"label":"Assemble","instruction":"Season the fries with the spice mix and salt. Lay out the flatbread, spread with sauce, and top with lettuce, onion, tomato, fries, chicken, feta and more sauce. Serve immediately.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=TROZvPHqP1g"}, {"id": "53219", "name": "Shakshuka Feta Cheese", "category": "Miscellaneous", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wpkfin1763597958.jpg", "local_image": "53219.jpg", "ingredients": [{"ingredient": "Egg", "measure": "4 large"}, {"ingredient": "Tomato Sauce", "measure": "3  tablespoons"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Shallots", "measure": "1 chopped"}, {"ingredient": "Celery", "measure": "1"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Spinach", "measure": "1 cup"}, {"ingredient": "Feta", "measure": "1/2 cup"}, {"ingredient": "Red Pepper", "measure": "1/2"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/2 teaspoon"}, {"ingredient": "Black Pepper", "measure": "1/2 teaspoon"}], "instructions": "1\r\nIn a pan heat the oil medium to high heat, with a tablespoon of olive oil\r\n2\r\nAdd the chopped vegetables as onions, garlic, celery and red pepper. Stir all together for 5 mins.\r\n3\r\nAdd the cumin powder and salt and pepper and the tomato sauce and let it cook for another 7 mins.\r\n4\r\nAdd the eggs, cover and leave to coo for 8 mins. Add the fresh spinach and feta cheese at the end.\r\n5\r\nServe with fresh bread.", "equipment_tags": [], "portions": 1, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 862, "protein_g": 53.1, "carbs_g": 32.3, "fat_g": 61.4, "total_kcal": 862, "total_protein_g": 53.1, "total_carbs_g": 32.3, "total_fat_g": 61.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soften the vegetables","instruction":"Heat the oil in a pan over medium-high heat. Add the chopped onion, garlic, celery and red pepper, and stir for 5 minutes.","timer_seconds":300,"background":false},{"step":2,"label":"Build the sauce","instruction":"Add the cumin, salt, pepper and tomato sauce, and cook for 7 minutes more.","timer_seconds":420,"background":true},{"step":3,"label":"Poach the eggs","instruction":"Add the eggs, cover, and cook for 8 minutes. Stir in the fresh spinach and feta at the end.","timer_seconds":480,"background":true},{"step":4,"label":"Serve","instruction":"Serve with fresh bread.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=xaBo3BxKzp8"}, {"id": "53220", "name": "kabse", "category": "Chicken", "area": "Saudi Arabian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/utqnjv1763598650.jpg", "local_image": "53220.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "400g"}, {"ingredient": "Rice", "measure": "1 cup"}, {"ingredient": "Green Pepper", "measure": "1"}, {"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Mushrooms", "measure": "2"}, {"ingredient": "Sweetcorn", "measure": "1"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Raisins", "measure": "Handful"}, {"ingredient": "Turmeric", "measure": "1 tsp"}, {"ingredient": "Kabse Spice", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Black Pepper", "measure": "Pinch"}], "instructions": "1\r\nCaramelize the chicken with olive oil then add a maggi cube and boil it for around 30 minutes.\r\n2\r\nIn another pot, add all the veggies and caramelize them till they are soft.\r\n3\r\nOnce everything is done, add the rice, raisins & spices to the veggies and add 2 and a half cups of water for the rice to cook.\r\n4\r\nOnce the rice is done put everything in the oven.", "equipment_tags": [], "portions": 2, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 790, "protein_g": 53.1, "carbs_g": 109.1, "fat_g": 14.7, "total_kcal": 1580, "total_protein_g": 106.3, "total_carbs_g": 218.2, "total_fat_g": 29.4, "macro_confidence": 0.92, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the chicken","instruction":"Caramelize the chicken in olive oil, then add a stock cube and boil for around 30 minutes.","timer_seconds":1800,"background":true},{"step":2,"label":"Cook the vegetables","instruction":"Meanwhile, in another pot, caramelize all the vegetables until soft.","timer_seconds":null,"background":true},{"step":3,"label":"Cook the rice","instruction":"Add the rice, raisins and spices to the vegetables with water, and cook until the rice is done.","timer_seconds":null,"background":true},{"step":4,"label":"Bake","instruction":"Once everything is cooked, combine and finish in the oven.","timer_seconds":null,"background":true}], "video": "https://www.youtube.com/watch?v=lrcUixJEPK0"}, {"id": "53221", "name": "Mamoul (Eid biscuits)", "category": "Dessert", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/35kejr1763599712.jpg", "local_image": "53221.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "300g"}, {"ingredient": "Semolina", "measure": "200g"}, {"ingredient": "Sunflower Oil", "measure": "25g"}, {"ingredient": "Unsalted Butter", "measure": "250g"}, {"ingredient": "Milk", "measure": "50 ml"}, {"ingredient": "Icing Sugar", "measure": "60g"}], "instructions": "1\r\nMix butter with sugar until creamy.\r\n2\r\nAdd oil flour and semolina and mix.\r\n3\r\nAdd warm milk and don't knead too much\r\n4\r\nCover and leave aside for an hour or less until you prepare the filling\r\n5\r\nFor the dates filling, fry some sesame in a pan then add butter. Add the dates paste and mixed well with sesame and butter. Then add a little bit of water until it's mushy. Be careful don't make it too mushy.\r\n6\r\nTake it of the pan, put in a plate until it's cool. Then start to shape balls that weigh 15 gm.\r\n7\r\nRefrigerate for 1/2 an hour.\r\n8\r\nGet back to the dough and shape it as balls that weigh 30 gm.\r\n9\r\nTake the date filling out of the fridge and start to stuff each dough ball with dates ball.\r\nThen use the mamoul mould to give it this shape.\r\n10\r\nIn a preheated oven 180 degrees, put it for 20 minutes until golden from below and little bit golden from above.", "equipment_tags": [], "portions": 6, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 682, "protein_g": 9.9, "carbs_g": 72.7, "fat_g": 39.1, "total_kcal": 4089, "total_protein_g": 59.2, "total_carbs_g": 436.2, "total_fat_g": 234.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dough","instruction":"Mix the butter with the sugar until creamy, then add the oil, flour and semolina and mix. Add the warm milk without over-kneading.","timer_seconds":null,"background":false},{"step":2,"label":"Rest the dough","instruction":"Cover and set aside for up to an hour while you prepare the filling.","timer_seconds":3600,"background":true},{"step":3,"label":"Make the date filling","instruction":"Fry the sesame in a pan, then add the butter and dates paste, mixing well. Add a little water until mushy but not too wet.","timer_seconds":null,"background":false},{"step":4,"label":"Shape the date balls","instruction":"Cool the filling, then shape into balls weighing about 15g each.","timer_seconds":null,"background":false},{"step":5,"label":"Chill","instruction":"Refrigerate the date balls for about 30 minutes.","timer_seconds":1800,"background":true},{"step":6,"label":"Stuff and shape","instruction":"Shape the dough into 30g balls, stuff each with a date ball, and press into the mamoul mould.","timer_seconds":null,"background":false},{"step":7,"label":"Bake","instruction":"Bake in a preheated oven at 180°C for 20 minutes, until golden underneath and lightly golden on top.","timer_seconds":1200,"background":true}], "video": "https://www.youtube.com/watch?v=RqBeOaXvqGM"}, {"id": "53222", "name": "Vegetarian Shakshuka", "category": "Vegetarian", "area": "Saudi Arabian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/eo0yfb1763600916.jpg", "local_image": "53222.jpg", "ingredients": [{"ingredient": "Red Onions", "measure": "1/2"}, {"ingredient": "Red Pepper", "measure": "1/2"}, {"ingredient": "Tomato", "measure": "400g"}, {"ingredient": "Cumin", "measure": "1/2 teaspoon"}, {"ingredient": "Garlic Granules", "measure": "1/2 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Egg", "measure": "2"}, {"ingredient": "Parsley", "measure": "Garnish"}, {"ingredient": "Chilli Flakes", "measure": "Garnish"}, {"ingredient": "Toast", "measure": "2 sliced"}], "instructions": "1\r\nFry onion and pepper together on medium heat until onion is soft\r\n2\r\nAdd garlic granules, cook for a minute\r\n3\r\nAdd chopped tomatoes and remaining spices, stir well\r\n4\r\nSimmer for about 20 minutes\r\n5\r\nMake indents for in the sauce and crack an egg into each one\r\n6\r\nOnce egg whites are cooked through, garnish and serve with toast", "equipment_tags": [], "portions": 1, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 445, "protein_g": 25.3, "carbs_g": 47.5, "fat_g": 20.9, "total_kcal": 445, "total_protein_g": 25.3, "total_carbs_g": 47.5, "total_fat_g": 20.9, "macro_confidence": 0.91, "is_new": false, "cook_steps": [{"step":1,"label":"Soften the vegetables","instruction":"Fry the onion and pepper over medium heat until the onion is soft.","timer_seconds":null,"background":false},{"step":2,"label":"Add the garlic","instruction":"Add the garlic granules and cook for a minute.","timer_seconds":60,"background":false},{"step":3,"label":"Simmer the sauce","instruction":"Add the chopped tomatoes and remaining spices, stir well, and simmer for about 20 minutes.","timer_seconds":1200,"background":true},{"step":4,"label":"Poach the eggs","instruction":"Make indents in the sauce and crack an egg into each. Cook until the egg whites are set through, then garnish and serve with toast.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=ZNEos6ybryg"}, {"id": "53223", "name": "Mutabbaq", "category": "Miscellaneous", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/i5o2b61763739053.jpg", "local_image": "53223.jpg", "ingredients": [{"ingredient": "Mincemeat", "measure": "500g"}, {"ingredient": "Garlic", "measure": "1.5 tbs minced"}, {"ingredient": "Ginger", "measure": "1.5 tbs minced"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Tomato", "measure": "1 large"}, {"ingredient": "Spring Onions", "measure": "4"}, {"ingredient": "Filo Pastry", "measure": "12"}, {"ingredient": "Melted Butter", "measure": "1 1/2 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Turmeric", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}], "instructions": "1\r\nHeat the frying pan and add in some oil. Fry the mashed garlic and ginger first and then add in the minced meat and all seasoning. When the meat is cooked, set aside to cool down.\r\n2\r\nGet another big bowl. Add in egg, chopped tomato, chopped spring onion and minced meat.\r\n3\r\nGet one 2 sheets of filo pastry or 1 sheet spring roll wrap. Brush it with some butter and then put some filling in the middle. Fold the pastry and brush more butter on the seal part.\r\n4\r\nHeat a frying pan and add in some oil to cook the parcel until its both sides and 4 edges all turn into golden brown. (Or brush melted butter all over the parcel and bake it in 180°C oven for 10-15 minutes)\r\n5\r\nEnjoy \r\n\r\n", "equipment_tags": [], "portions": 4, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 1513, "protein_g": 21.2, "carbs_g": 178.9, "fat_g": 81.7, "total_kcal": 6050, "total_protein_g": 84.7, "total_carbs_g": 715.7, "total_fat_g": 326.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the filling","instruction":"Fry the mashed garlic and ginger in oil, then add the minced meat and seasoning. Cook until the meat is done, then set aside to cool.","timer_seconds":null,"background":false},{"step":2,"label":"Mix the filling","instruction":"In a bowl, combine the egg, chopped tomato, chopped spring onion and cooked minced meat.","timer_seconds":null,"background":false},{"step":3,"label":"Fold the parcels","instruction":"Brush a sheet of filo pastry, or a spring roll wrapper, with butter, spoon the filling into the middle, fold to enclose, and brush the seal with more butter.","timer_seconds":null,"background":false},{"step":4,"label":"Cook","instruction":"Fry the parcels in a little oil until both sides and all edges are golden brown, or brush with melted butter and bake at 180°C for 10 to 15 minutes.","timer_seconds":900,"background":true}], "video": "https://www.youtube.com/watch?v=xzu8XswXqcs"}, {"id": "53224", "name": "Pistachio Kunafa Chocolate Cake and Cupcakes", "category": "Dessert", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/yh3sg71763741307.jpg", "local_image": "53224.jpg", "ingredients": [{"ingredient": "White Chocolate", "measure": "6 tablespoons"}, {"ingredient": "Unsalted Pistachio", "measure": "1 cup"}, {"ingredient": "Condensed Milk", "measure": "3  tablespoons"}, {"ingredient": "Milk", "measure": "5 tablespoons"}, {"ingredient": "Oreo Cream Biscuits", "measure": "25"}, {"ingredient": "Milk", "measure": "1/2 cup"}, {"ingredient": "Baking Powder", "measure": "1/2 teaspoon"}, {"ingredient": "Vinegar", "measure": "1/2 teaspoon"}, {"ingredient": "Salt", "measure": "1 pinch"}, {"ingredient": "Sevaiiya", "measure": "150g"}, {"ingredient": "Ghee", "measure": "1 tablespoon"}, {"ingredient": "Dark Chocolate", "measure": "120ml"}, {"ingredient": "Malai", "measure": "4 tablespoons"}], "instructions": "1\r\nFor Chocolate Cake:Ready all the ingredients. Powder the oreo biscuits, pinch salt and mix warm milk as needed and make a cake batter. Add in baking powder and vinegar and mix.\r\n2\r\nGrease a loose bottomed tin. Pour a 1cm thick layer of the batter.\r\n3\r\nBake in a preheated oven @160°C for 7-8 minutes or until the knife comes out clean. Cool on wire rack.\r\n4\r\nFor Homemade Pistachio Paste:Ready all the pistachio paste ingredients. Slightly melt white chocolate on a double boiler.(else the mixer blade may break) Coarsely powder the pistachio in mixer. Add in condensed milk.\r\n5\r\nAdd in slightly warmed and slightly melted white chocolate and milk as required and crush to a smooth paste.(Green food colour can be add. I haven't.)\r\n6\r\nFor Kunafa: In a kadhaai take ghee and roast the sevaiiya on slow gas. Keep stirring until a pleasant roasted aroma releases. Cool it. Add in the Homemade pistachio paste.Mix well.\r\n7\r\nLip smacking Kunafa is ready. Spread a 2 cm layer on the cooled chocolate cake.\r\n8\r\nMelt dark chocolate and strained malai and prepare the chocolate ganache. Cool and pour on the Kunafa layer.\r\n9\r\nGarnish Pistachio Kunafa Chocolate Cake with chopped pistachio and silver balls. Keep in fridge for 2-3 hours. Then unmould the Kunafa Cake.\r\n10\r\nI also prepared Kunafa cupcakes. Cut and enjoy. The cake looked so pretty that we could either save it or have it!! ☺\r\n11\r\nCross sectional view of the Pistachio Kunafa Chocolate Cake.\r\n12\r\nEnjoy with a new sweet delicacy this festive season with family and friends. ", "equipment_tags": [], "portions": 12, "prep_minutes": 188, "prep_minutes_source": "explicit", "kcal": 460, "protein_g": 9.6, "carbs_g": 24.2, "fat_g": 37.6, "total_kcal": 5520, "total_protein_g": 114.6, "total_carbs_g": 291.0, "total_fat_g": 451.2, "macro_confidence": 0.85, "is_new": false, "cook_steps": [{"step":1,"label":"Make the cake batter","instruction":"Powder the Oreo biscuits, add a pinch of salt and enough warm milk to make a batter, then mix in the baking powder and vinegar.","timer_seconds":null,"background":false},{"step":2,"label":"Bake the cake","instruction":"Grease a loose-bottomed tin and pour in a 1cm layer of batter. Bake at 160°C for 7 to 8 minutes, until a knife comes out clean, then cool on a wire rack.","timer_seconds":480,"background":true},{"step":3,"label":"Make the pistachio paste","instruction":"Melt the white chocolate over a double boiler. Coarsely grind the pistachios, then mix in the condensed milk and the melted white chocolate and milk until smooth.","timer_seconds":null,"background":false},{"step":4,"label":"Make the kunafa layer","instruction":"Roast the sevaiiya (kunafa strands) in ghee over low heat until fragrant, then cool and mix in the pistachio paste.","timer_seconds":null,"background":false},{"step":5,"label":"Layer","instruction":"Spread a 2cm layer of the kunafa mixture over the cooled cake.","timer_seconds":null,"background":false},{"step":6,"label":"Make the ganache","instruction":"Melt the dark chocolate with the strained cream to make a ganache, then cool slightly and pour over the kunafa layer.","timer_seconds":null,"background":false},{"step":7,"label":"Chill and garnish","instruction":"Garnish with chopped pistachio and silver balls, then chill for 2 to 3 hours before unmoulding.","timer_seconds":9000,"background":true},{"step":8,"label":"Serve","instruction":"Slice and serve, or bake as cupcakes instead.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=vINcKAS7Ig8"}, {"id": "53225", "name": "Yemeni Lahsa (Elite Shakshuka)", "category": "Breakfast", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/30s7vf1763741844.jpg", "local_image": "53225.jpg", "ingredients": [{"ingredient": "Egg", "measure": "5"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Tomato", "measure": "1 Diced"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Allspice", "measure": "1/4 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Liquid Cheese", "measure": "3  tablespoons"}], "instructions": "1\r\nFirst, On medium heat, heat the olive oil and add the diced onion until it wethers. Next, add the tomatoes and cook for another 4-5 min. Lastly, add the all spice, salt, and cracked pepper.\r\n2\r\nAdd the eggs and mix throughly for 2 minutes and cover to cook 5-6 minutes until top is solidified. Lastly, spread the liquid cheese and have it covered for a minute.\r\n3\r\nI served mine Mediterranean style with hash-browns, Egyptian fava beans, Turkish salami and olives, cheese wedges, and greek feta.", "equipment_tags": [], "portions": 2, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 414, "protein_g": 22.8, "carbs_g": 9.7, "fat_g": 32.8, "total_kcal": 827, "total_protein_g": 45.6, "total_carbs_g": 19.5, "total_fat_g": 65.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the base","instruction":"Heat the olive oil over medium heat and cook the diced onion until softened. Add the tomatoes and cook for 4 to 5 minutes, then season with allspice, salt and pepper.","timer_seconds":300,"background":false},{"step":2,"label":"Cook the eggs","instruction":"Add the eggs, mix through for 2 minutes, then cover and cook for 5 to 6 minutes until the top is set.","timer_seconds":360,"background":true},{"step":3,"label":"Finish","instruction":"Spread the liquid cheese over the top and cover for a minute more before serving.","timer_seconds":60,"background":false},{"step":4,"label":"Serve","instruction":"Serve Mediterranean-style with hash browns, fava beans, salami, olives and feta.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/shorts/1QX-KBX6tmM"}, {"id": "53226", "name": "Shawarma bread", "category": "Side", "area": "Saudi Arabian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/i8l2fu1763742525.jpg", "local_image": "53226.jpg", "ingredients": [{"ingredient": "Flour", "measure": "1 cup"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "1/2 tsp"}, {"ingredient": "Baking Powder", "measure": "1/2 tsp"}, {"ingredient": "Oil", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "Splash"}], "instructions": "1\r\nSieve flour and add baking powder,salt,sugar,oil nd mix together\r\n2\r\nAdd water nd knead the dough for like 10mins\r\n3\r\nCover the mixture and allow it to rise\r\n4\r\nAfter it rised transfer it to a work surface and form a round (you can use a plate or pot's lid)\r\n5\r\nHeat ur pan and put it\r\n6\r\nIt'll start puffing then you turn it\r\n7\r\nAnd lastly put it in in a warm place, then you'll see it has pocket", "equipment_tags": [], "portions": 2, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 297, "protein_g": 6.4, "carbs_g": 49.7, "fat_g": 7.5, "total_kcal": 595, "total_protein_g": 12.7, "total_carbs_g": 99.5, "total_fat_g": 15.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Mix the dough","instruction":"Sieve the flour and add the baking powder, salt, sugar and oil, mixing together.","timer_seconds":null,"background":false},{"step":2,"label":"Knead","instruction":"Add water and knead the dough for about 10 minutes.","timer_seconds":600,"background":false},{"step":3,"label":"Prove","instruction":"Cover the dough and let it rise.","timer_seconds":null,"background":true},{"step":4,"label":"Shape","instruction":"Once risen, transfer to a work surface and shape into a round using a plate or lid as a guide.","timer_seconds":null,"background":false},{"step":5,"label":"Cook","instruction":"Heat a pan and cook the bread until it puffs up, then flip and cook the other side.","timer_seconds":null,"background":false},{"step":6,"label":"Rest and serve","instruction":"Keep in a warm place afterwards — it will develop a pocket inside.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=ndkTbgsTCeI"}, {"id": "53227", "name": "Rice paper dumplings", "category": "Pork", "area": "Vietnamese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/sfahy01763752319.jpg", "local_image": "53227.jpg", "ingredients": [{"ingredient": "White Cabbage", "measure": "1/4"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "Shiitake Mushrooms", "measure": "100g"}, {"ingredient": "Ground Pork", "measure": "400g"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Ginger", "measure": "20g"}, {"ingredient": "Soy Sauce", "measure": "2 tsp"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}, {"ingredient": "Spring Onions", "measure": "3 sliced thinly"}, {"ingredient": "Rice Paper Sheets", "measure": "20"}, {"ingredient": "Vegetable Oil", "measure": "75 ml"}, {"ingredient": "Soy Sauce", "measure": "2 tablespoons"}, {"ingredient": "Rice Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Sesame Seed", "measure": "1/2 tbs"}, {"ingredient": "Spring Onions", "measure": "2 sliced"}], "instructions": "step 1\r\nTip the cabbage into a food processor and blitz until finely chopped. Season with ½ tsp salt, toss well and set aside for 15 mins. Tip into a clean tea towel and squeeze out as much water as you can. Tip into a bowl with the carrot, mushrooms, pork mince, garlic, ginger, soy sauce, sesame oil and spring onions. Season with black pepper. Scrunch everything together using your hands, mixing well until everything is combined.\r\n\r\nstep 2\r\nSoak the spring roll sheets for a couple of seconds in a shallow dish of warm water, then transfer to an oiled chopping board. Working with one sheet at a time, spoon 1 heaped tbsp of the filling into the middle, then fold the bottom up and over the filling. Fold down the top of the sheet, then the sides to fully encase and make a neat square. If the dumpling feels a little fragile, soak another sheet and wrap it again. Repeat with the remaining sheets and filling, transferring the dumplings to an oiled plate as you go.\r\n\r\nstep 3\r\nHeat the oil in a large, non-stick frying pan (ensuring it is no more than a third full) over a medium-high heat and fry the dumplings for 3-5 mins until golden brown. Use a slotted spoon or spider to turn them, then cover with a lid and cook for another 3-4 mins until golden. Remove the lid and cook for 1-2 mins.\r\n\r\nstep 4\r\nMeanwhile, combine all the dipping sauce ingredients in small bowl. Serve the dumplings with the dipping sauce on the side.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 26, "prep_minutes_source": "explicit", "kcal": 672, "protein_g": 35.4, "carbs_g": 46.5, "fat_g": 38.9, "total_kcal": 2016, "total_protein_g": 106.1, "total_carbs_g": 139.5, "total_fat_g": 116.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the cabbage","instruction":"Blitz the cabbage in a food processor until finely chopped. Season with salt, toss, and set aside for 15 minutes, then squeeze out the water in a clean tea towel.","timer_seconds":900,"background":true},{"step":2,"label":"Mix the filling","instruction":"Combine the cabbage with the carrot, mushrooms, pork mince, garlic, ginger, soy sauce, sesame oil and spring onions. Season with black pepper and mix well by hand.","timer_seconds":null,"background":false},{"step":3,"label":"Wrap the dumplings","instruction":"Soak the spring roll sheets briefly in warm water, then transfer to an oiled board. Spoon filling into the middle of each, fold to enclose in a neat square, and transfer to an oiled plate.","timer_seconds":null,"background":false},{"step":4,"label":"Fry","instruction":"Heat the oil in a large pan, no more than a third full, and fry the dumplings for 3 to 5 minutes until golden, then cover and cook a further 3 to 4 minutes. Uncover and cook for 1 to 2 minutes more.","timer_seconds":600,"background":false},{"step":5,"label":"Serve","instruction":"Meanwhile, combine the dipping sauce ingredients. Serve the dumplings with the sauce on the side.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/shorts/YU09jIusxo4"}, {"id": "53228", "name": "Vietnamese caramel trout", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/p02vq41763754350.jpg", "local_image": "53228.jpg", "ingredients": [{"ingredient": "Golden Caster Sugar", "measure": "50g"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Ginger", "measure": "large piece"}, {"ingredient": "Rainbow Trout", "measure": "2"}, {"ingredient": "Bok Choi", "measure": "2 heads"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Coriander", "measure": "Sprigs of fresh"}, {"ingredient": "Rice", "measure": "Steamed"}], "instructions": "step 1\r\nPut the sugar in a large shallow pan, along with a small splash of water. Heat gently, swirling the pan, until the sugar has dissolved. Increase the heat and bubble the syrup until it turns a dark amber colour. Add the fish sauce, most of the chilli and ginger, then splash in 1 tbsp water to dilute. Boil again until syrupy, then add the fish fillets, skin-side down, and the bok choi, cut-side down.\r\n\r\nstep 2\r\nCover the pan with a lid and simmer for 4-5 mins until the fish is cooked and the bok choi has wilted. Turn off the heat, squeeze over the lemon and scatter with the remaining chilli, ginger and the coriander sprigs. Serve with rice.", "equipment_tags": [], "portions": 1, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 661, "protein_g": 14.7, "carbs_g": 117.3, "fat_g": 16.8, "total_kcal": 661, "total_protein_g": 14.7, "total_carbs_g": 117.3, "total_fat_g": 16.8, "macro_confidence": 0.78, "is_new": false, "cook_steps": [{"step":1,"label":"Make the caramel","instruction":"Heat the sugar with a small splash of water, swirling the pan, until dissolved, then increase the heat and bubble until dark amber.","timer_seconds":null,"background":false},{"step":2,"label":"Build the sauce","instruction":"Add the fish sauce, most of the chilli and ginger, and a splash of water to dilute. Boil again until syrupy, then add the fish fillets skin-side down and the bok choi cut-side down.","timer_seconds":null,"background":false},{"step":3,"label":"Simmer","instruction":"Cover and simmer for 4 to 5 minutes until the fish is cooked and the bok choi has wilted.","timer_seconds":300,"background":true},{"step":4,"label":"Serve","instruction":"Turn off the heat, squeeze over the lemon, and scatter with the remaining chilli, ginger and coriander sprigs. Serve with rice.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=3MBbvrUtn74"}, {"id": "53229", "name": "Steak & Vietnamese noodle salad", "category": "Beef", "area": "Vietnamese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/st9shl1763755808.jpg", "local_image": "53229.jpg", "ingredients": [{"ingredient": "Brown Rice Noodle", "measure": "85g"}, {"ingredient": "Rapeseed Oil", "measure": "1 tsp"}, {"ingredient": "Fillet Of Steak", "measure": "250g"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Chinese Cabbage", "measure": "1/2"}, {"ingredient": "Spring Onions", "measure": "4 finely sliced"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Brown Sugar", "measure": "2 tsp"}, {"ingredient": "Rice Vinegar", "measure": "1 tsp"}, {"ingredient": "Garlic Clove", "measure": "1 chopped"}, {"ingredient": "Fish Sauce", "measure": "1/2 tbs"}], "instructions": "step 1\r\nMix all the ingredients for the dressing together in a bowl with 1 tbsp water until the sugar has dissolved.\r\n\r\nstep 2\r\nCook the noodles following pack instructions, then plunge into a bowl of cold water to cool completely. Drain the noodles, then add the carrot, cabbage, spring onion and dressing, and toss to combine.\r\n\r\nstep 3\r\nHeat the oil in a frying pan over a high heat. Season the steak, then cook to your liking; 2-3 mins on each side for medium rare. Leave to rest for 5 mins, then slice. Divide the salad and steak slices between bowls and scatter over some coriander to serve.", "equipment_tags": [], "portions": 8, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 127, "protein_g": 8.5, "carbs_g": 16.5, "fat_g": 3.3, "total_kcal": 1018, "total_protein_g": 67.7, "total_carbs_g": 132.1, "total_fat_g": 26.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dressing","instruction":"Mix all the dressing ingredients together with a splash of water until the sugar has dissolved.","timer_seconds":null,"background":false},{"step":2,"label":"Prep the noodle salad","instruction":"Cook the noodles following pack instructions, then plunge into cold water to cool. Drain and toss with the carrot, cabbage, spring onion and dressing.","timer_seconds":null,"background":false},{"step":3,"label":"Cook the steak","instruction":"Heat the oil in a frying pan over high heat, season the steak, and cook to your liking, about 2 to 3 minutes each side for medium rare. Rest for 5 minutes, then slice.","timer_seconds":480,"background":false},{"step":4,"label":"Serve","instruction":"Divide the salad and steak between bowls and scatter with coriander.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=Lo4_GdyetEU"}, {"id": "53230", "name": "Purple sprouting broccoli tempura with nuoc cham", "category": "Miscellaneous", "area": "Vietnamese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xnv4wf1763756529.jpg", "local_image": "53230.jpg", "ingredients": [{"ingredient": "Corn Flour", "measure": "50g"}, {"ingredient": "Plain Flour", "measure": "100g"}, {"ingredient": "Sesame Seed", "measure": "1 tablespoon"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Soda Water", "measure": "250ml"}, {"ingredient": "Purple Sprouting Broccoli", "measure": "200g"}, {"ingredient": "Fish Sauce", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Birds-eye Chillies", "measure": "1 chopped"}, {"ingredient": "Sugar", "measure": "2 tablespoons"}], "instructions": "step 1\r\nFor the nuoc cham, whisk together all of the ingredients with 5 tbsp hot water in a small bowl. Set aside while you make the tempura.\r\n\r\nstep 2\r\nWhisk the cornflour, plain flour, sesame seeds (if using) and a large pinch of salt together. Fill a large, deep pan no more than a third full with the vegetable oil and heat until it reaches 180C or a cube of bread dropped in browns in 20 seconds.\r\n\r\nstep 3\r\nQuickly whisk the soda water into the flour mixture, being careful not to overmix, then dunk in the broccoli using tongs. Carefully lower into the hot oil and cook for 2-3 mins until crisp. Drain on kitchen paper, then serve with the nuoc cham on the side for dipping.", "equipment_tags": [], "portions": 2, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 556, "protein_g": 10.6, "carbs_g": 86.7, "fat_g": 19.8, "total_kcal": 1112, "total_protein_g": 21.1, "total_carbs_g": 173.3, "total_fat_g": 39.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the nuoc cham","instruction":"Whisk together all the nuoc cham ingredients with hot water in a small bowl, then set aside.","timer_seconds":null,"background":false},{"step":2,"label":"Prep the batter and oil","instruction":"Whisk the cornflour, plain flour, sesame seeds and salt together. Heat the oil in a deep pan, no more than a third full, to 180°C, or until a cube of bread browns in 20 seconds.","timer_seconds":null,"background":false},{"step":3,"label":"Fry the broccoli","instruction":"Whisk the soda water into the flour mixture without overmixing, dunk in the broccoli, and carefully lower into the hot oil. Fry for 2 to 3 minutes until crisp.","timer_seconds":180,"background":false},{"step":4,"label":"Serve","instruction":"Drain on kitchen paper and serve with the nuoc cham for dipping.","timer_seconds":null,"background":false}], "video": null}, {"id": "53231", "name": "Vietnamese lamb shanks with sweet potatoes", "category": "Lamb", "area": "Vietnamese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/7xte3u1763757761.jpg", "local_image": "53231.jpg", "ingredients": [{"ingredient": "Ground Nut Oil", "measure": "2 tablespoons"}, {"ingredient": "Lamb Shanks", "measure": "4"}, {"ingredient": "Onion", "measure": "2"}, {"ingredient": "Ginger", "measure": "2 tbs chopped"}, {"ingredient": "Garlic Clove", "measure": "3 sliced thinly"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Brown Sugar", "measure": "1 tsp"}, {"ingredient": "Star Anise", "measure": "3"}, {"ingredient": "Lemongrass Stalks", "measure": "2"}, {"ingredient": "Lamb Stock", "measure": "1L"}, {"ingredient": "Tomato Puree", "measure": "1 ½ tbsp"}, {"ingredient": "Sweet Potatoes", "measure": "4"}, {"ingredient": "Fish Sauce", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Basil Leaves", "measure": "Handful"}], "instructions": "step 1\r\nHeat oven to 160C/140C fan/gas 3. Heat 1 tbsp oil in a heavy-bottomed casserole, season the shanks, then brown them 2 at a time on all sides, adding the remaining oil for the second batch. Remove the lamb and add the onions. Fry them quite briskly, about 30 secs, add the ginger, garlic and chopped chilli, then turn the heat down and cook for 1 min. Add 1 tbsp sugar, stir, then add the star anise, lemongrass, stock, purée and seasoning. Bring to the boil.\r\n\r\nstep 2\r\nCover and cook in the oven for 1½ hrs, then add the sweet potatoes and cook for 1 hr more. The lamb should be completely tender and almost falling off the bones. Stir in the fish sauce, lime juice and 1 tsp sugar to just lift the flavour, then scatter with the mint, basil and the sliced chilli to serve.", "equipment_tags": [], "portions": 5, "prep_minutes": 61, "prep_minutes_source": "explicit", "kcal": 966, "protein_g": 65.4, "carbs_g": 49.6, "fat_g": 56.6, "total_kcal": 4831, "total_protein_g": 326.8, "total_carbs_g": 248.1, "total_fat_g": 282.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Brown the shanks","instruction":"Heat the oven to 160°C/140°C fan/gas 3. Season the shanks and brown them in batches in the oil in a casserole, then remove.","timer_seconds":null,"background":false},{"step":2,"label":"Build the braising liquid","instruction":"Fry the onions briskly for about 30 seconds, add the ginger, garlic and chilli, then turn down the heat and cook for 1 minute. Add the sugar, star anise, lemongrass, stock, purée and seasoning, and bring to the boil.","timer_seconds":90,"background":false},{"step":3,"label":"Braise the lamb","instruction":"Return the shanks to the pot, cover, and cook in the oven for 1½ hours.","timer_seconds":5400,"background":true},{"step":4,"label":"Add the sweet potatoes","instruction":"Add the sweet potatoes and cook for 1 hour more, until the lamb is tender and almost falling off the bone.","timer_seconds":3600,"background":true},{"step":5,"label":"Finish","instruction":"Stir in the fish sauce, lime juice and a little more sugar to lift the flavour, then scatter with mint, basil and sliced chilli to serve.","timer_seconds":null,"background":false}], "video": "https://www.tiktok.com/@shanice_and_lima/video/7280471655959383297"}, {"id": "53232", "name": "Vietnamese chicken salad", "category": "Chicken", "area": "Vietnamese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/pk8wtn1763758591.jpg", "local_image": "53232.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "140g"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "Cucumber", "measure": "1/2"}, {"ingredient": "Chicken Breasts", "measure": "2"}, {"ingredient": "Radish", "measure": "50g"}, {"ingredient": "Red Onions", "measure": "1/2"}, {"ingredient": "Mint", "measure": "Bunch"}, {"ingredient": "Peanuts", "measure": "25g"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Lime", "measure": "Zest and juice of 1"}, {"ingredient": "Fish Sauce", "measure": "1 ½ tbsp"}, {"ingredient": "Soy Sauce", "measure": "1 ½ tbsp"}, {"ingredient": "Sesame Seed Oil", "measure": "1 ½ tbsp"}], "instructions": "step 1\r\nTo make the dressing, whisk all the ingredients together in a large serving bowl. Cook the noodles following pack instructions, then drain and add to the bowl with the dressing.\r\n\r\nstep 2\r\nPeel the carrot into long strips using a vegetable peeler. Do the same for the cucumber, until you reach the seeds (discard them). Add the carrot and cucumber to the noodle mixture along with the shredded chicken, radishes, red onion and mint. Toss well to coat in the dressing, scatter over the peanuts and serve.", "equipment_tags": [], "portions": 7, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 228, "protein_g": 13.3, "carbs_g": 21.2, "fat_g": 10.3, "total_kcal": 1598, "total_protein_g": 92.9, "total_carbs_g": 148.5, "total_fat_g": 71.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dressing","instruction":"Whisk all the dressing ingredients together in a large serving bowl.","timer_seconds":null,"background":false},{"step":2,"label":"Cook the noodles","instruction":"Cook the noodles following pack instructions, then drain and add to the dressing.","timer_seconds":null,"background":false},{"step":3,"label":"Assemble","instruction":"Peel the carrot and cucumber into long strips, discarding the cucumber seeds, then add to the noodles with the shredded chicken, radishes, red onion and mint. Toss well, scatter with peanuts, and serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=behSkhzKpHI"}, {"id": "53233", "name": "Salt & pepper squid", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/yxiilf1763759428.jpg", "local_image": "53233.jpg", "ingredients": [{"ingredient": "Corn Flour", "measure": "85g"}, {"ingredient": "Plain Flour", "measure": "85g"}, {"ingredient": "Black Pepper", "measure": "2 tsp"}, {"ingredient": "Szechuan Peppercorns", "measure": "2 tsp"}, {"ingredient": "Sunflower Oil", "measure": "For frying"}, {"ingredient": "Squid", "measure": "400g"}, {"ingredient": "Spring Onions", "measure": "Sliced"}, {"ingredient": "Green Chilli", "measure": "Sliced"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Cucumber", "measure": "1/2"}, {"ingredient": "Red Onions", "measure": "1 chopped"}, {"ingredient": "Rice Vinegar", "measure": "100 ml"}, {"ingredient": "Caster Sugar", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "2 tsp"}], "instructions": "step 1\r\nTo make the dipping sauce, mix all the ingredients in a small bowl until the sugar has dissolved, then set aside. Mix the cornflour and plain flour with both peppers and 2 tsp sea salt in a large bowl, then set aside. Line a tray with kitchen paper and make sure you have more salt to sprinkle with.\r\n\r\nstep 2\r\nHeat about 7cm of oil to 180C in a deep fryer, wok or deep pan. If you don’t have a thermometer, you can test it with a cube of bread – it should brown in 20 secs. Coat the squid well with the flour mix and fry in batches for about 2 mins each or until crisp. Use a slotted spoon to lift out the squid, then drain on the kitchen paper and sprinkle with a little more salt. Serve the squid scattered with the spring onion and chilli, with the dipping sauce on the side.", "equipment_tags": [], "portions": 2, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 735, "protein_g": 38.5, "carbs_g": 100.2, "fat_g": 18.8, "total_kcal": 1471, "total_protein_g": 76.9, "total_carbs_g": 200.3, "total_fat_g": 37.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dipping sauce and coating","instruction":"Mix the dipping sauce ingredients in a small bowl until the sugar dissolves. Mix the cornflour, plain flour, both peppers and sea salt in a large bowl. Line a tray with kitchen paper.","timer_seconds":null,"background":false},{"step":2,"label":"Fry the squid","instruction":"Heat about 7cm of oil to 180°C. Coat the squid in the flour mix and fry in batches for about 2 minutes each until crisp.","timer_seconds":120,"background":false},{"step":3,"label":"Serve","instruction":"Drain on kitchen paper, sprinkle with a little more salt, and serve scattered with spring onion and chilli, with the dipping sauce on the side.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=l1Ik6k22s1I"}, {"id": "53234", "name": "Salmon noodle soup", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/ikizdm1763760862.jpg", "local_image": "53234.jpg", "ingredients": [{"ingredient": "Chicken Stock", "measure": "1 L"}, {"ingredient": "Thai Red Curry Paste", "measure": "2 tsp"}, {"ingredient": "Rice Noodles", "measure": "100g"}, {"ingredient": "Shiitake Mushrooms", "measure": "150g"}, {"ingredient": "Sweetcorn", "measure": "125g"}, {"ingredient": "Salmon", "measure": "2"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Brown Sugar", "measure": "Pinch"}, {"ingredient": "Coriander", "measure": "Bunch"}], "instructions": "step 1\r\nPour the stock into a large pan, bring to the boil, then stir in the curry paste. Add the noodles and cook for 8 mins. Tip in the mushrooms and corn and cook for 2 mins more.\r\n\r\nstep 2\r\nAdd the salmon to the pan and cook for 3 mins or until cooked through. Remove from the heat and stir in the lime juice, soy sauce and a pinch of sugar. Ladle into 4 bowls and sprinkle over the coriander just before you serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 266, "protein_g": 14.0, "carbs_g": 41.9, "fat_g": 5.8, "total_kcal": 799, "total_protein_g": 42.1, "total_carbs_g": 125.8, "total_fat_g": 17.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Build the broth","instruction":"Bring the stock to the boil and stir in the curry paste. Add the noodles and cook for 8 minutes, then add the mushrooms and corn and cook 2 minutes more.","timer_seconds":600,"background":true},{"step":2,"label":"Add the salmon","instruction":"Add the salmon and cook for 3 minutes until cooked through.","timer_seconds":180,"background":false},{"step":3,"label":"Finish","instruction":"Remove from the heat, stir in the lime juice, soy sauce and a pinch of sugar. Ladle into bowls and sprinkle with coriander just before serving.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=__Kh1sizUAM"}, {"id": "53235", "name": "Vietnamese-style caramel pork", "category": "Pork", "area": "Vietnamese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/4mzt101763761546.jpg", "local_image": "53235.jpg", "ingredients": [{"ingredient": "Ground Nut Oil", "measure": "1 ½ tbsp"}, {"ingredient": "Pork Shoulder Steaks", "measure": "500g"}, {"ingredient": "Shallots", "measure": "2 chopped"}, {"ingredient": "Ground Ginger", "measure": "1 tablespoon"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Brown Sugar", "measure": "75g"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Chilli Sauce", "measure": "2 tsp"}, {"ingredient": "Spring Onions", "measure": "4"}, {"ingredient": "Rice", "measure": "Steamed"}, {"ingredient": "Pak Choi", "measure": "To serve"}], "instructions": "step 1\r\nHeat 1 tbsp of the oil in a wok over a high heat and stir-fry the pork in batches until browned all over. Remove with a slotted spoon and set aside.\r\n\r\nstep 2\r\nTurn the heat right down and add the remaining oil, then stir in the shallots, ginger and chilli. Cook over a low heat for a couple of mins until just starting to soften. Add the sugar, fish sauce and 200ml water to the pan and stir everything together. Bring to the boil, stirring, so that the sugar dissolves, then return the pork to the pan. Bubble vigorously for 8-10 mins until the sauce thickens to coat the meat and become glossy. Taste and stir in a little more fish sauce, if needed, along with the chilli sauce. Sprinkle with the spring onions and serve with steamed rice and pak choi.", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 641, "protein_g": 38.7, "carbs_g": 54.6, "fat_g": 30.7, "total_kcal": 1923, "total_protein_g": 116.2, "total_carbs_g": 163.7, "total_fat_g": 92.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Brown the pork","instruction":"Heat half the oil in a wok over high heat and stir-fry the pork in batches until browned all over. Remove with a slotted spoon and set aside.","timer_seconds":null,"background":false},{"step":2,"label":"Build the caramel sauce","instruction":"Turn the heat right down, add the remaining oil, and stir in the shallots, ginger and chilli. Cook over low heat for a couple of minutes until just softening. Add the sugar, fish sauce and water, and bring to the boil, stirring, until the sugar dissolves.","timer_seconds":null,"background":false},{"step":3,"label":"Glaze the pork","instruction":"Return the pork to the pan and bubble vigorously for 8 to 10 minutes until the sauce thickens to coat the meat and turns glossy. Adjust with a little more fish sauce or chilli sauce to taste.","timer_seconds":540,"background":true},{"step":4,"label":"Serve","instruction":"Sprinkle with the spring onions and serve with steamed rice and pak choi.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=qmQe0Qxvyzc"}, {"id": "53236", "name": "Vietnamese-style veggie hotpot", "category": "Vegetarian", "area": "Vietnamese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/4uje7l1763762276.jpg", "local_image": "53236.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "2 tsp"}, {"ingredient": "Ginger", "measure": "4cm finely chopped"}, {"ingredient": "Garlic Clove", "measure": "2 chopped"}, {"ingredient": "Butternut Squash", "measure": "1/2"}, {"ingredient": "Soy Sauce", "measure": "2 tsp"}, {"ingredient": "Brown Sugar", "measure": "2 tsp"}, {"ingredient": "Vegetable Stock", "measure": "200ml"}, {"ingredient": "Green Beans", "measure": "100g shredded"}, {"ingredient": "Spring Onions", "measure": "4 sliced"}, {"ingredient": "Coriander Leaves", "measure": "To serve"}, {"ingredient": "Jasmine Rice", "measure": "To serve"}], "instructions": "step 1\r\nHeat the oil in a medium-size, lidded saucepan. Add the ginger and garlic, then stir-fry for about 5 mins. Add the squash, soy sauce, sugar and stock. Cover, then simmer for 10 mins. Remove the lid, add the green beans, then cook for 3 mins more until the squash and beans are tender. Stir the spring onions through at the last minute, then sprinkle with coriander and serve with rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 296, "protein_g": 9.3, "carbs_g": 57.1, "fat_g": 6.3, "total_kcal": 593, "total_protein_g": 18.5, "total_carbs_g": 114.2, "total_fat_g": 12.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Fry the aromatics","instruction":"Heat the oil in a medium, lidded saucepan. Add the ginger and garlic and stir-fry for about 5 minutes.","timer_seconds":300,"background":false},{"step":2,"label":"Simmer the squash","instruction":"Add the squash, soy sauce, sugar and stock. Cover and simmer for 10 minutes.","timer_seconds":600,"background":true},{"step":3,"label":"Add the beans","instruction":"Remove the lid, add the green beans, and cook for 3 minutes more until the squash and beans are tender.","timer_seconds":180,"background":false},{"step":4,"label":"Serve","instruction":"Stir through the spring onions at the last minute, sprinkle with coriander, and serve with rice.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=OR6jC9gw_Hw"}, {"id": "53237", "name": "Vietnamese pork salad", "category": "Pork", "area": "Vietnamese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/g7jomp1763763994.jpg", "local_image": "53237.jpg", "ingredients": [{"ingredient": "Golden Caster Sugar", "measure": "1 tsp"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Pork Tenderloin", "measure": "500g"}, {"ingredient": "Vegetable Oil", "measure": "For brushing"}, {"ingredient": "White Cabbage", "measure": "1/4"}, {"ingredient": "Cucumber", "measure": "1 chopped"}, {"ingredient": "Celery", "measure": "5 chopped"}, {"ingredient": "Spring Onions", "measure": "3 sliced thinly"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Lemongrass Stalks", "measure": "2 chopped"}, {"ingredient": "Lime", "measure": "Zest of 1"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Mint", "measure": "Handful"}], "instructions": "step 1\r\nThe day before: make the dressing. Put the sugar and lime juice in a pan with 1 tbsp water and bring to the boil to dissolve the sugar. Add the chilli and coriander and stir well, then pulse in a blender until smooth. Tip into a bowl, then stir in the sesame oil, fish sauce, soy sauce and sesame seeds to make a dressing. Cover and chill until needed.\r\n\r\nstep 2\r\nTwo hours before serving: heat a griddle pan. Preheat the oven to 200C/gas 6/fan 180C. Brush the pork with oil and griddle on all sides for a few minutes until seared. Transfer to a baking tray and put in the oven for about 10-12 minutes until cooked through. Cool, thinly slice against the grain of the meat. Tip into a bowl and pour over half the dressing.\r\n\r\nstep 3\r\nTo serve: toss the remaining salad ingredients in a bowl with the remaining dressing. Pile on to a platter, top with the pork slices and spoon over any juices.", "equipment_tags": ["Blender"], "portions": 12, "prep_minutes": 12, "prep_minutes_source": "explicit", "kcal": 131, "protein_g": 9.8, "carbs_g": 7.5, "fat_g": 7.2, "total_kcal": 1577, "total_protein_g": 117.0, "total_carbs_g": 90.3, "total_fat_g": 86.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dressing (the day before)","instruction":"Bring the sugar and lime juice to the boil in a pan with a splash of water to dissolve the sugar. Add the chilli and coriander, then blitz in a blender until smooth. Stir in the sesame oil, fish sauce, soy sauce and sesame seeds, cover, and chill until needed.","timer_seconds":null,"background":true},{"step":2,"label":"Griddle the pork","instruction":"About two hours before serving, heat a griddle pan and preheat the oven to 200°C/gas 6/fan 180°C. Brush the pork with oil and griddle on all sides for a few minutes until seared.","timer_seconds":null,"background":false},{"step":3,"label":"Roast the pork","instruction":"Transfer the pork to a baking tray and roast for about 10 to 12 minutes until cooked through. Cool, then thinly slice against the grain and toss with half the dressing.","timer_seconds":660,"background":true},{"step":4,"label":"Serve","instruction":"Toss the remaining salad ingredients with the rest of the dressing, pile onto a platter, top with the pork slices, and spoon over any juices.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=_DCJNrNTTB4"}, {"id": "53238", "name": "Beef pho", "category": "Beef", "area": "Vietnamese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg", "local_image": "53238.jpg", "ingredients": [{"ingredient": "Beef Stock", "measure": "1 L"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Ginger", "measure": "1 Large Chopped"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Star Anise", "measure": "2"}, {"ingredient": "Coriander Seeds", "measure": "1 tsp"}, {"ingredient": "Cloves", "measure": "1/2 teaspoon"}, {"ingredient": "Sirloin steak", "measure": "225g"}, {"ingredient": "Palm Sugar", "measure": "1 tsp"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Soy Sauce", "measure": "1 ½ tbsp"}, {"ingredient": "Rice Noodles", "measure": "200g"}, {"ingredient": "Spring Onions", "measure": "2 sliced"}, {"ingredient": "Birds-eye Chillies", "measure": "1 small"}, {"ingredient": "Basil", "measure": "Handful"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Lime", "measure": "1"}], "instructions": "step 1\r\nTip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill). Once charred, add to the beef stock. In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well. Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining.\r\n\r\nstep 2\r\nMeanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge.\r\n\r\nstep 3\r\nTaste the beef stock and use the palm sugar, fish sauce and soy to season. Cook the noodles according to package instructions and split between two bowls, topping each with the sliced beef. Bring the stock to the boil and then pour into the bowls (the heat will cook the beef). Top each with the spring onions, chilli slices and herbs. Serve with the lime wedges to squeeze over.", "equipment_tags": ["Grill"], "portions": 4, "prep_minutes": 53, "prep_minutes_source": "explicit", "kcal": 354, "protein_g": 19.1, "carbs_g": 59.0, "fat_g": 5.7, "total_kcal": 1415, "total_protein_g": 76.5, "total_carbs_g": 236.0, "total_fat_g": 22.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Char the aromatics","instruction":"Char the onion and ginger in a hot frying pan (or under the grill) on all sides, about 3 to 5 minutes, then add them to the beef stock and water in a large saucepan.","timer_seconds":240,"background":false},{"step":2,"label":"Toast the spices and simmer the stock","instruction":"In the same pan, toast the spices for 2 to 3 minutes until fragrant, then add them to the stock. Bring to the boil, then simmer for 30 minutes before straining.","timer_seconds":1800,"background":true},{"step":3,"label":"Chill the steak","instruction":"Meanwhile, trim the fat from the steak, wrap in cling film, and freeze for 15 minutes to make it easier to slice thinly. Slice, then rewrap and keep in the fridge.","timer_seconds":900,"background":true},{"step":4,"label":"Assemble and serve","instruction":"Season the strained stock with palm sugar, fish sauce and soy. Cook the noodles following pack instructions and divide between bowls, topping with the sliced beef. Bring the stock back to the boil and pour into the bowls so the heat cooks the beef, then top with spring onions, chilli and herbs, and serve with lime wedges.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=WlosNFMCnE4"}, {"id": "53239", "name": "Bang bang prawn salad", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/4xcfai1763765676.jpg", "local_image": "53239.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "140g"}, {"ingredient": "Peanut Butter", "measure": "3 tablespoons"}, {"ingredient": "Coconut Milk", "measure": "4 tablespoons"}, {"ingredient": "sweet chilli sauce", "measure": "3  tablespoons"}, {"ingredient": "Spring Onions", "measure": "3 sliced thinly"}, {"ingredient": "Cucumber", "measure": "1 sliced"}, {"ingredient": "Bean Sprouts", "measure": "300g"}, {"ingredient": "Prawns", "measure": "200g"}], "instructions": "step 1\r\nCook the noodles following pack instructions, then rinse under cold water and drain thoroughly. In a small saucepan melt together the peanut butter, coconut milk, sweet chilli sauce and half the spring onions, adding 1-2 tbsp of water to loosen the mixture to a drizzling consistency.\r\n\r\nstep 2\r\nMix the noodles, cucumber and beansprouts in a serving dish. Top with the prawns, drizzle over the peanut sauce and scatter over the remaining spring onions.", "equipment_tags": [], "portions": 9, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 150, "protein_g": 7.4, "carbs_g": 18.7, "fat_g": 5.9, "total_kcal": 1348, "total_protein_g": 66.3, "total_carbs_g": 167.9, "total_fat_g": 52.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the noodles and sauce","instruction":"Cook the noodles following pack instructions, then rinse under cold water and drain thoroughly. Melt the peanut butter, coconut milk, sweet chilli sauce and half the spring onions together in a small saucepan, loosening with a splash of water to a drizzling consistency.","timer_seconds":null,"background":false},{"step":2,"label":"Assemble","instruction":"Mix the noodles, cucumber and beansprouts in a serving dish. Top with the prawns, drizzle over the peanut sauce, and scatter over the remaining spring onions.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=Na-6-lzs2wU"}, {"id": "53240", "name": "Tofu, greens & cashew stir-fry", "category": "Vegetarian", "area": "Vietnamese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/minfsc1763766806.jpg", "local_image": "53240.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Broccoli", "measure": "1 head"}, {"ingredient": "Garlic Clove", "measure": "4 sliced"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Spring Onions", "measure": "1  bunch"}, {"ingredient": "Soya Bean", "measure": "140g"}, {"ingredient": "Pak Choi", "measure": "2 heads"}, {"ingredient": "Marinated Tofu", "measure": "300g"}, {"ingredient": "Hoisin Sauce", "measure": "1 ½ tbsp"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Cashew Nuts", "measure": "25g"}], "instructions": "step 1\r\nHeat the oil in a non-stick wok. Add the broccoli, then fry on a high heat for 5 mins or until just tender, adding a little water if it begins to catch. Add the garlic and chilli, fry for 1 min, then toss through the spring onions, soya beans, pak choi and tofu. Stir-fry for 2-3 mins. Add the hoisin, soy and nuts to warm through.", "equipment_tags": [], "portions": 2, "prep_minutes": 9, "prep_minutes_source": "explicit", "kcal": 422, "protein_g": 29.2, "carbs_g": 23.3, "fat_g": 27.3, "total_kcal": 844, "total_protein_g": 58.4, "total_carbs_g": 46.5, "total_fat_g": 54.6, "macro_confidence": 0.91, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the broccoli","instruction":"Heat the oil in a non-stick wok and fry the broccoli over high heat for 5 minutes, or until just tender, adding a splash of water if it begins to catch.","timer_seconds":300,"background":false},{"step":2,"label":"Add the aromatics","instruction":"Add the garlic and chilli and fry for 1 minute, then toss through the spring onions, soya beans, pak choi and tofu, and stir-fry for 2 to 3 minutes.","timer_seconds":150,"background":false},{"step":3,"label":"Finish","instruction":"Add the hoisin, soy and nuts and toss briefly to warm through.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=l8wuWeNy3J4"}, {"id": "53241", "name": "Vietnamese veg parcels", "category": "Vegetarian", "area": "Vietnamese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/f698g91763768731.jpg", "local_image": "53241.jpg", "ingredients": [{"ingredient": "Rice Flour Pancakes", "measure": "100g"}, {"ingredient": "Rice Noodles", "measure": "50g"}, {"ingredient": "Chicken Breast", "measure": "1"}, {"ingredient": "Carrots", "measure": "1 sliced"}, {"ingredient": "Cucumber", "measure": "1 sliced"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Lettuce", "measure": "To serve"}, {"ingredient": "Coriander", "measure": "To serve"}, {"ingredient": "Mint", "measure": "To serve"}, {"ingredient": "Fish Sauce", "measure": "4 tablespoons"}, {"ingredient": "Rice Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "Juice of 1/2"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}], "instructions": "step 1\r\nSoak the rice fl our pancakes according to pack instructions or in boiling water for 30 secs. Remove and cool on kitchen paper. Soak the rice noodles according to pack instructions, then drain and cut them into 2cm strips.\r\n\r\nstep 2\r\nLay a rice pancake on a board and arrange some rice noodles, chicken, vegetables and herb leaves about a third of the way up, leaving a 1cm edge at the side. Fold the sides over the vegetables and then roll up lengthways to make a cigar. Store in the fridge, covered with moist kitchen paper for up to 1 day.\r\n\r\nstep 3\r\nMix together the ingredients for the dipping sauce and put into a bowl. To serve, arrange the rolls on a plate along with the leaves and herbs. To eat, wrap each roll in a piece of lettuce with a herb sprig and dunk into the sauce.", "equipment_tags": [], "portions": 1, "prep_minutes": 46, "prep_minutes_source": "estimated", "kcal": 838, "protein_g": 54.0, "carbs_g": 139.9, "fat_g": 6.1, "total_kcal": 838, "total_protein_g": 54.0, "total_carbs_g": 139.9, "total_fat_g": 6.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the wrappers and noodles","instruction":"Soak the rice flour pancakes following pack instructions, or in boiling water for 30 seconds, then cool on kitchen paper. Soak the rice noodles following pack instructions, drain, and cut into short strips.","timer_seconds":30,"background":false},{"step":2,"label":"Roll the parcels","instruction":"Lay a rice pancake on a board and arrange some noodles, chicken, vegetables and herb leaves a third of the way up, leaving an edge at the side. Fold the sides over the filling, then roll up lengthways into a cigar shape. Can be kept covered with moist kitchen paper in the fridge for up to a day.","timer_seconds":null,"background":true},{"step":3,"label":"Serve","instruction":"Mix the dipping sauce ingredients and put into a bowl. Arrange the rolls on a plate with the leaves and herbs, and dunk each roll, wrapped in a lettuce leaf, into the sauce to eat.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=k3ciVdNBuK0"}, {"id": "53242", "name": "Barbecue pork buns", "category": "Pork", "area": "Vietnamese", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/tzsy461763769901.jpg", "local_image": "53242.jpg", "ingredients": [{"ingredient": "Sugar", "measure": "85g"}, {"ingredient": "White Bread Mix", "measure": "500g"}, {"ingredient": "Sunflower Oil", "measure": "1 tablespoon"}, {"ingredient": "Bacon", "measure": "12"}, {"ingredient": "Ginger", "measure": "Knob"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Soy Sauce", "measure": "2 tablespoons"}, {"ingredient": "Clear Honey", "measure": "3  tablespoons"}, {"ingredient": "Tomato Puree", "measure": "3  tablespoons"}, {"ingredient": "Egg", "measure": "1 beaten"}], "instructions": "step 1\r\nHeat the oven to 200C/fan 180C/gas. Mix the sugar into the bread mix in a large bowl, then add water as instructed on the pack. Bring the dough together with a wooden spoon, then knead on a lightly floured surface for 5 mins until smooth. Put into a large bowl, cover with oiled cling film then leave in a warm place until doubled in size.\r\n\r\nstep 2\r\nMeanwhile, heat the oil in a pan, then fry the bacon until crisp, about 5 mins. Add the ginger and garlic and fry for 1 min until soft, then tip in the soy, honey and tomato purée and stir well. Can be made up to 3 days ahead.\r\n\r\nstep 3\r\nTurn out the dough and knead briefly, then pull into 12 even-sized balls. Flatten with your hands, then put a teaspoon-size blob of the filling in the middle. Draw the dough up and pinch it closed like a purse, then turn the bun over and sit it on a large baking sheet. Cover with oiled cling film and leave to rise for about 30 mins until the dough feels pillowy. Brush with egg and bake for 20 mins until golden. Serve warm with dipping sauce. Can be frozen after second rise for up to 1 month or baked up to a day ahead and re-warmed.", "equipment_tags": [], "portions": 3, "prep_minutes": 61, "prep_minutes_source": "explicit", "kcal": 1787, "protein_g": 92.9, "carbs_g": 135.3, "fat_g": 95.8, "total_kcal": 5361, "total_protein_g": 278.7, "total_carbs_g": 406.0, "total_fat_g": 287.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make and prove the dough","instruction":"Heat the oven to 200°C/fan 180°C/gas 6. Mix the sugar into the bread mix, add water as instructed on the pack, and bring together with a wooden spoon. Knead on a floured surface for 5 minutes until smooth, then cover and leave in a warm place until doubled in size.","timer_seconds":300,"background":true},{"step":2,"label":"Make the filling","instruction":"Meanwhile, fry the bacon until crisp, about 5 minutes. Add the ginger and garlic and fry for 1 minute until soft, then stir in the soy, honey and tomato purée. Can be made up to 3 days ahead.","timer_seconds":360,"background":false},{"step":3,"label":"Shape and fill the buns","instruction":"Turn out the dough, knead briefly, then divide into 12 even balls. Flatten each, add a teaspoon of filling to the middle, and draw the dough up and pinch closed like a purse. Turn over and place on a baking sheet.","timer_seconds":null,"background":false},{"step":4,"label":"Second prove","instruction":"Cover with oiled cling film and leave to rise for about 30 minutes until the dough feels pillowy.","timer_seconds":1800,"background":true},{"step":5,"label":"Bake","instruction":"Brush with egg and bake for 20 minutes until golden. Serve warm with dipping sauce. Can be frozen after the second rise for up to a month, or baked up to a day ahead and re-warmed.","timer_seconds":1200,"background":true}], "video": "https://www.youtube.com/watch?v=T3mBULRIcY8"}, {"id": "53243", "name": "Vietnamese prawn spiralized rolls", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/9r2xrg1763771238.jpg", "local_image": "53243.jpg", "ingredients": [{"ingredient": "Lime", "measure": "Juice of 1/2"}, {"ingredient": "Rice Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Palm Sugar", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "3  tablespoons"}, {"ingredient": "Birds-eye Chillies", "measure": "1 chopped"}, {"ingredient": "Rice Paper Sheets", "measure": "6"}, {"ingredient": "Mint", "measure": "Small bunch"}, {"ingredient": "Coriander", "measure": "Small bunch"}, {"ingredient": "King Prawns", "measure": "12"}, {"ingredient": "Carrots", "measure": "1 large"}, {"ingredient": "Courgettes", "measure": "1"}], "instructions": "step 1\r\nMix all the ingredients for the dipping sauce along with 50ml water in a bowl and set aside to allow the sugar to dissolve and flavour to infuse.\r\n\r\nstep 2\r\nTo assemble the rolls, fill a wide bowl with warm water and grab a clean damp tea towel to work on. Dip a rice paper wrapper into the water for a few seconds until it softens then carefully place onto the tea towel.\r\n\r\nstep 3\r\nPut a few mint and coriander leaves in the centre of the wrapper then top with two prawns and a small handful of the spiralized veg, which may need to be cut up if the spirals are too long.\r\n\r\nstep 4\r\nFold the sides of the wrapper into the centre, over the filling, then fold in the edges, so that the filling is completely encased, then tightly roll. Repeat until all of the wrappers and filling have been used. To serve, slice on a diagonal and eat with the dipping sauce.", "equipment_tags": [], "portions": 2, "prep_minutes": 43, "prep_minutes_source": "estimated", "kcal": 386, "protein_g": 64.2, "carbs_g": 29.3, "fat_g": 2.1, "total_kcal": 771, "total_protein_g": 128.5, "total_carbs_g": 58.7, "total_fat_g": 4.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dipping sauce","instruction":"Mix all the dipping sauce ingredients with water in a bowl and set aside to allow the sugar to dissolve and the flavours to infuse.","timer_seconds":null,"background":true},{"step":2,"label":"Soften the wrappers","instruction":"Fill a wide bowl with warm water and have a clean, damp tea towel ready. Dip a rice paper wrapper into the water for a few seconds until it softens, then lay it on the tea towel.","timer_seconds":null,"background":false},{"step":3,"label":"Fill the rolls","instruction":"Put a few mint and coriander leaves in the centre of the wrapper, then top with two prawns and a small handful of the spiralized veg, cutting the spirals shorter if needed.","timer_seconds":null,"background":false},{"step":4,"label":"Roll and serve","instruction":"Fold the sides of the wrapper into the centre over the filling, then fold in the edges to fully encase, and roll up tightly. Repeat with the remaining wrappers and filling. Slice on a diagonal and serve with the dipping sauce.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=lNU0LKVtHC4"}, {"id": "53244", "name": "Prawn & noodle salad with crispy shallots", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/0iryz91763778419.jpg", "local_image": "53244.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "200g"}, {"ingredient": "Prawns", "measure": "200g"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Cucumber", "measure": "1 sliced"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Roasted Peanut", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "Juice of 3"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "2 tsp"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Shallots", "measure": "5 Slices"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Flour", "measure": "Sprinkling"}], "instructions": "step 1\r\nFor the crispy shallots, heat 5cm of oil until hot in a wok. You will know the oil is hot enough when one piece of shallot sizzles as soon as it’s dropped in. Toss the shallot slices with flour, shake off excess and fry in the oil until golden. They fry quickly, about 1 min. Drain on kitchen paper, sprinkle with salt and set aside.\r\n\r\nstep 2\r\nTo make the dressing, mix the lime juice, sugar, fish sauce and garlic and set aside. In a large mixing bowl, pour boiling water over the noodles. Leave them for 2 mins or until they are just cooked, then rinse under cold water. Drain well, shaking the sieve numerous times to get out the excess water, then place back in the bowl. Add prawns, onion, chilli, cucumber and herbs. Pour the dressing over, mix, then sprinkle with the shallots and peanuts.", "equipment_tags": [], "portions": 7, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 242, "protein_g": 10.1, "carbs_g": 36.3, "fat_g": 6.9, "total_kcal": 1695, "total_protein_g": 70.5, "total_carbs_g": 253.8, "total_fat_g": 48.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Fry the crispy shallots","instruction":"Heat oil in a wok until a piece of shallot sizzles as soon as it's dropped in. Toss the shallot slices with flour, shake off the excess, and fry until golden, about 1 minute. Drain on kitchen paper and sprinkle with salt.","timer_seconds":60,"background":false},{"step":2,"label":"Make the dressing","instruction":"Mix the lime juice, sugar, fish sauce and garlic together and set aside.","timer_seconds":null,"background":false},{"step":3,"label":"Soak the noodles","instruction":"Pour boiling water over the noodles in a large bowl and leave for 2 minutes, or until just cooked, then rinse under cold water and drain well.","timer_seconds":120,"background":true},{"step":4,"label":"Assemble","instruction":"Add the prawns, onion, chilli, cucumber and herbs to the noodles. Pour over the dressing, mix, then sprinkle with the crispy shallots and peanuts.","timer_seconds":null,"background":false}], "video": null}, {"id": "53245", "name": "Noodle bowl salad", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/zry07j1763779321.jpg", "local_image": "53245.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "125g"}, {"ingredient": "Sugar Snap Peas", "measure": "200g"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}, {"ingredient": "Spring Onions", "measure": "4 sliced"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Hot Smoked Flaked Salmon", "measure": "150g"}, {"ingredient": "Pretzels", "measure": "To serve"}, {"ingredient": "Soy Sauce", "measure": "3  tablespoons"}, {"ingredient": "Clear Honey", "measure": "1 tablespoon"}, {"ingredient": "Lemon Juice", "measure": "1 tablespoon"}, {"ingredient": "Ground Nut Oil", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Ginger", "measure": "Knob"}], "instructions": "step 1\r\nDrop the noodles into a large bowl, then pour over enough boiling water to cover. Tip in the sliced sugar snaps and leave for 4 minutes. Drain in a colander, put under cold running water to cool off, then drain again. Tip into a bowl and toss in the sesame oil.\r\n\r\nstep 2\r\nMix the dressing ingredients. Pile spring onions, coriander and salmon onto the noodles, pour over the dressing and toss everything together. Serve with a pretzel or bread roll.", "equipment_tags": [], "portions": 8, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 264, "protein_g": 6.7, "carbs_g": 48.1, "fat_g": 5.7, "total_kcal": 2114, "total_protein_g": 53.2, "total_carbs_g": 385.1, "total_fat_g": 45.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the noodles","instruction":"Drop the noodles into a large bowl with the sliced sugar snaps, cover with boiling water, and leave for 4 minutes. Drain, cool under cold running water, drain again, then toss with the sesame oil.","timer_seconds":240,"background":true},{"step":2,"label":"Assemble and serve","instruction":"Mix the dressing ingredients. Pile the spring onions, coriander and salmon onto the noodles, pour over the dressing, and toss everything together. Serve with a pretzel or bread roll.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=7EAdKeikJ9o"}, {"id": "53246", "name": "Tangy carrot, cabbage & onion salad", "category": "Vegetarian", "area": "Vietnamese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/dbazbg1763779999.jpg", "local_image": "53246.jpg", "ingredients": [{"ingredient": "Carrots", "measure": "4 sliced"}, {"ingredient": "Red Cabbage", "measure": "1/2"}, {"ingredient": "Red Onions", "measure": "2 sliced"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Coriander Leaves", "measure": "Handful"}, {"ingredient": "Roasted Peanut", "measure": "Handful"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Ground Nut Oil", "measure": "1 tablespoon"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}], "instructions": "step 1\r\nTip the carrots, cabbage and onions into a bowl. Make the dressing by stirring the ingredients together until the sugar has dissolved. Pour over salad, tossing the vegetables in the dressing. Add the herbs, toss again, then scatter over the peanuts.", "equipment_tags": [], "portions": 5, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 118, "protein_g": 3.0, "carbs_g": 15.2, "fat_g": 6.0, "total_kcal": 588, "total_protein_g": 15.0, "total_carbs_g": 76.1, "total_fat_g": 30.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Toss the salad","instruction":"Tip the carrots, cabbage and onions into a bowl. Stir the dressing ingredients together until the sugar has dissolved, then pour over the vegetables and toss.","timer_seconds":null,"background":false},{"step":2,"label":"Finish","instruction":"Add the herbs, toss again, then scatter over the peanuts to serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=-BJWMkJMIns"}, {"id": "53247", "name": "Sea bass with sizzled ginger, chilli & spring onions", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/tqd7s21763780609.jpg", "local_image": "53247.jpg", "ingredients": [{"ingredient": "Sea Bass Fillets", "measure": "6"}, {"ingredient": "Sunflower Oil", "measure": "3  tablespoons"}, {"ingredient": "Ginger", "measure": "Knob"}, {"ingredient": "Garlic Clove", "measure": "3 sliced thinly"}, {"ingredient": "Red Chilli", "measure": "3 Large"}, {"ingredient": "Spring Onions", "measure": "Bunch"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}], "instructions": "step 1\r\nSeason 6 sea bass fillets with salt and pepper, then slash the skin 3 times.\r\n\r\nstep 2\r\nHeat a heavy-based frying pan and add 1 tbsp sunflower oil.\r\n\r\nstep 3\r\nOnce hot, fry the sea bass fillets, skin-side down, for 5 mins or until the skin is very crisp and golden. The fish will be almost cooked through.\r\n\r\nstep 4\r\nTurn over, cook for another 30 seconds - 1 minute, then transfer to a serving plate and keep warm. You’ll need to fry the sea bass fillets in 2 batches.\r\n\r\nstep 5\r\nHeat 2 tbsp sunflower oil, then fry the large knob of peeled ginger, cut into matchsticks, 3 thinly sliced garlic cloves and 3 thinly shredded red chillies for about 2 mins until golden.\r\n\r\nstep 6\r\nTake off the heat and toss in the bunch of shredded spring onions. Splash the fish with 1 tbsp soy sauce and spoon over the contents of the pan.", "equipment_tags": [], "portions": 2, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 909, "protein_g": 25.2, "carbs_g": 78.5, "fat_g": 57.2, "total_kcal": 1819, "total_protein_g": 50.4, "total_carbs_g": 157.1, "total_fat_g": 114.3, "macro_confidence": 0.86, "is_new": false, "cook_steps": [{"step":1,"label":"Score the fish","instruction":"Season the sea bass fillets with salt and pepper, then slash the skin three times on each.","timer_seconds":null,"background":false},{"step":2,"label":"Sear the fish","instruction":"Heat a heavy-based frying pan with a little oil. Once hot, fry the fillets skin-side down for 5 minutes, or until the skin is very crisp and golden and the fish is almost cooked through.","timer_seconds":300,"background":false},{"step":3,"label":"Finish the fish","instruction":"Turn over and cook for a further 30 seconds to 1 minute, then transfer to a serving plate and keep warm. Fry in two batches.","timer_seconds":60,"background":false},{"step":4,"label":"Sizzle the aromatics","instruction":"Heat more oil and fry the ginger matchsticks, sliced garlic and shredded chillies for about 2 minutes until golden.","timer_seconds":120,"background":false},{"step":5,"label":"Serve","instruction":"Off the heat, toss in the shredded spring onions. Splash the fish with soy sauce and spoon over the sizzled aromatics.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=xzDYKZl50FQ"}, {"id": "53248", "name": "Salmon noodle wraps", "category": "Seafood", "area": "Vietnamese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/prrirc1763781360.jpg", "local_image": "53248.jpg", "ingredients": [{"ingredient": "Rice Noodles", "measure": "100g"}, {"ingredient": "Spring Onions", "measure": "3 sliced thinly"}, {"ingredient": "Petit Pois", "measure": "50g"}, {"ingredient": "Chilli", "measure": "85g"}, {"ingredient": "Coriander", "measure": "85g"}, {"ingredient": "Lime", "measure": "85g"}, {"ingredient": "Salmon", "measure": "300g"}], "instructions": "step 1\r\nHeat oven to 200C/fan 180C/gas 6. Put the noodles in a bowl and pour over enough boiling water to just cover them. Leave for 2 mins, until they are bendable, but not too soft, then drain well. Return to the bowl with the spring onions, petit pois, salt and pepper and a third of the butter. Mix well until the butter has melted.\r\n\r\nstep 2\r\nPile the noodles and vegetables onto two large squares of baking parchment, then sit the salmon on top. Slice the remaining butter and arrange over the top of the salmon. Bring the ends of the paper over the fish, fold them together to seal, then tuck the ends of the paper underneath so there are no gaps. Put the parcels on a baking sheet and bake for 15-20 mins. Transfer to dinner plates and serve without delay.", "equipment_tags": [], "portions": 2, "prep_minutes": 22, "prep_minutes_source": "explicit", "kcal": 624, "protein_g": 39.2, "carbs_g": 67.4, "fat_g": 22.6, "total_kcal": 1248, "total_protein_g": 78.4, "total_carbs_g": 134.7, "total_fat_g": 45.2, "macro_confidence": 0.86, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the noodles","instruction":"Heat the oven to 200°C/fan 180°C/gas 6. Cover the noodles with boiling water and leave for 2 minutes, until bendable but not too soft, then drain well.","timer_seconds":120,"background":true},{"step":2,"label":"Mix the noodle base","instruction":"Return the noodles to the bowl with the spring onions, petit pois, seasoning and a third of the butter, and mix until the butter melts.","timer_seconds":null,"background":false},{"step":3,"label":"Assemble the parcels","instruction":"Pile the noodles and vegetables onto two large squares of baking parchment, sit the salmon on top, and arrange the remaining sliced butter over it. Fold the paper over the fish to seal, tucking the ends underneath.","timer_seconds":null,"background":false},{"step":4,"label":"Bake","instruction":"Put the parcels on a baking sheet and bake for 15 to 20 minutes. Serve straight from the parcels without delay.","timer_seconds":1050,"background":true}], "video": "https://www.youtube.com/watch?v=9j2qftITN-Y"}, {"id": "53249", "name": "Turkey Bánh mì", "category": "Miscellaneous", "area": "Vietnamese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1wj8w31763781990.jpg", "local_image": "53249.jpg", "ingredients": [{"ingredient": "Baguette", "measure": "2 small"}, {"ingredient": "Chicken Liver", "measure": "50g"}, {"ingredient": "Cucumber", "measure": "1/4"}, {"ingredient": "Turkey", "measure": "140g"}, {"ingredient": "Mayonnaise", "measure": "1 tablespoon"}, {"ingredient": "Red Chilli", "measure": "1 sliced"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Carrots", "measure": "2 small"}, {"ingredient": "Red Cabbage", "measure": "75g"}, {"ingredient": "Ground Ginger", "measure": "1/4 tsp"}, {"ingredient": "Rice Vinegar", "measure": "½ tablespoon"}, {"ingredient": "Golden Caster Sugar", "measure": "1/2 teaspoon"}], "instructions": "step 1\r\nTo make the pickled slaw, tip the carrots and cabbage into a large bowl. In a small bowl, combine the ginger, rice vinegar, sugar and a few pinches of salt. Pour over the vegetables and toss together. Set aside for at least 15 mins.\r\n\r\nstep 2\r\nHalve the baguettes lengthways and spread the pâté over the bottom half. Top with the pickled slaw, cucumber and turkey. Mix the mayonnaise with the chopped chilli and dollop over the top. Scatter over the mint leaves and sliced chilli. Sandwich together and dig in.", "equipment_tags": [], "portions": 1, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 737, "protein_g": 52.7, "carbs_g": 81.9, "fat_g": 22.7, "total_kcal": 737, "total_protein_g": 52.7, "total_carbs_g": 81.9, "total_fat_g": 22.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Pickle the slaw","instruction":"Tip the carrots and cabbage into a bowl. Combine the ginger, rice vinegar, sugar and salt, pour over the vegetables, toss, and set aside for at least 15 minutes.","timer_seconds":900,"background":true},{"step":2,"label":"Assemble","instruction":"Halve the baguettes lengthways and spread the pâté over the bottom halves. Top with the pickled slaw, cucumber and turkey. Mix the mayonnaise with the chopped chilli and dollop on top, then scatter with mint leaves and sliced chilli. Sandwich together and serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=L-ItzFfVgos"}, {"id": "53250", "name": "Vegan banh mi", "category": "Vegan", "area": "Vietnamese", "diet_tag": "Vegan", "image": "https://www.themealdb.com/images/media/meals/sonirb1763782831.jpg", "local_image": "53250.jpg", "ingredients": [{"ingredient": "Raw Vegetables", "measure": "150g"}, {"ingredient": "Vegan White Wine Vinegar", "measure": "3  tablespoons"}, {"ingredient": "Golden Caster Sugar", "measure": "1 tsp"}, {"ingredient": "Baguette", "measure": "1 large"}, {"ingredient": "Hummus", "measure": "100g"}, {"ingredient": "Tempeh", "measure": "175g"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Hotsauce", "measure": "To serve"}], "instructions": "step 1\r\nPut the shredded veg in a bowl and add the vinegar, sugar and 1 tsp salt. Toss everything together, then set aside to pickle quickly while you prepare the rest of the sandwich.\r\n\r\nstep 2\r\nHeat oven to 180C/160C fan/gas 4. Cut the baguette into four, then slice each piece horizontally in half. Put the baguette pieces in the oven for 5 mins until lightly toasted and warm. Spread each piece with a layer of hummus, then top four pieces with the tempeh slices and pile the pickled veg on top. To serve, sprinkle over the herbs and squeeze over some hot sauce, then top with the other baguette pieces to make sandwiches.", "equipment_tags": [], "portions": 1, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 657, "protein_g": 26.2, "carbs_g": 82.8, "fat_g": 25.5, "total_kcal": 657, "total_protein_g": 26.2, "total_carbs_g": 82.8, "total_fat_g": 25.5, "macro_confidence": 0.78, "is_new": false, "cook_steps": [{"step":1,"label":"Quick-pickle the vegetables","instruction":"Toss the shredded vegetables with the vinegar, sugar and salt in a bowl, then set aside to pickle quickly while you prepare the rest of the sandwich.","timer_seconds":null,"background":true},{"step":2,"label":"Toast the baguette","instruction":"Heat the oven to 180°C/160°C fan/gas 4. Cut the baguette into four, slice each piece horizontally, and toast in the oven for 5 minutes until lightly warm.","timer_seconds":300,"background":true},{"step":3,"label":"Assemble","instruction":"Spread each piece with hummus, then top four pieces with the tempeh slices and pile the pickled veg on top. Sprinkle with herbs, squeeze over hot sauce, and top with the other baguette pieces to make sandwiches.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=i0_C3eRTbgg"}, {"id": "53251", "name": "Turkish lahmacun", "category": "Beef", "area": "Vietnamese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/tqd3ac1763786065.jpg", "local_image": "53251.jpg", "ingredients": [{"ingredient": "Strong white bread flour", "measure": "500g"}, {"ingredient": "Fast action yeast", "measure": "10g"}, {"ingredient": "Corn Flour", "measure": "Sprinkling"}, {"ingredient": "Tomato", "measure": "2"}, {"ingredient": "Green Chilli", "measure": "2"}, {"ingredient": "Spring Onions", "measure": "4 Chopped"}, {"ingredient": "Parsley", "measure": "Bunch"}, {"ingredient": "Ground Beef", "measure": "250g"}, {"ingredient": "Chilli Flakes", "measure": "2 tsp"}, {"ingredient": "Ground Cumin", "measure": "Pinch"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Lemon", "measure": "1/2"}, {"ingredient": "Red Onions", "measure": "1"}], "instructions": "step 1\r\nSift the flour into a large bowl, make a well in the middle and sprinkle in the yeast. Pour 125ml water over the yeast, then flick flour over the liquid to create a layer. Cover and leave to rise in a warm place for 15 mins until cracks appear on the surface of that layer.\r\n\r\nstep 2\r\nUse your hands to mix in 250ml more water along with 1 tsp salt and knead the dough for about 10 mins until elastic and no longer sticky. Add a little more flour if you need to. Cover and leave to rise again in a warm place for 30 mins until doubled in size.\r\n\r\nstep 3\r\nHeat the oven to as high as it will go (about 240C/220C fan/gas 9) and sprinkle one or two baking trays thinly with cornmeal.\r\n\r\nstep 4\r\nPour boiling water from the kettle over the tomatoes, leave to stand briefly, then drain and slip off the skins. Cut the tomatoes in half, cut out the stalks, scoop out the seeds and discard, then chop the flesh.\r\n\r\nstep 5\r\nHalve the chillies lengthways, cut out the stalks, seeds and white inner membrane, then rinse. Cut lengthwise into fine strips, then crosswise into fine dice.\r\n\r\nstep 6\r\nPut the tomatoes, chillies, spring onions, finely chopped parsley, beef mince, spices, 1 tsp salt and ½ tsp freshly ground black pepper into a bowl and mix well.\r\n\r\nstep 7\r\nTake the dough and knead it briefly, then divide into four pieces and shape each into a ball. Roll each ball into a thin circle, place on the prepared baking trays. Spread with a thin layer of the meat mixture.\r\n\r\nstep 8\r\nBake each flatbread for 10-15 mins until the edges begin to darken. After removing from the oven, sprinkle the lahmacun with the roughly chopped parsley and sliced onion, then squeeze over a few drops of lemon juice. Serve straightaway.", "equipment_tags": [], "portions": 3, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 1048, "protein_g": 37.1, "carbs_g": 160.0, "fat_g": 28.7, "total_kcal": 3145, "total_protein_g": 111.2, "total_carbs_g": 480.0, "total_fat_g": 86.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Start the dough","instruction":"Sift the flour into a bowl, make a well, and sprinkle in the yeast. Pour water over the yeast, flick a little flour over the top to cover, then cover the bowl and leave in a warm place for 15 minutes until cracks appear in the flour layer.","timer_seconds":900,"background":true},{"step":2,"label":"Knead and prove","instruction":"Mix in the rest of the water and the salt, and knead for about 10 minutes until elastic and no longer sticky. Cover and leave to rise again in a warm place for 30 minutes until doubled in size.","timer_seconds":1800,"background":true},{"step":3,"label":"Preheat and prep the tomatoes","instruction":"Heat the oven as high as it will go, about 240°C/220°C fan/gas 9, and sprinkle baking trays with cornmeal. Blanch the tomatoes in boiling water, then peel, deseed and chop the flesh.","timer_seconds":null,"background":false},{"step":4,"label":"Prep the chillies","instruction":"Halve the chillies lengthways, remove the stalks, seeds and membrane, rinse, then finely dice.","timer_seconds":null,"background":false},{"step":5,"label":"Make the topping","instruction":"Mix the tomatoes, chillies, spring onions, parsley, beef mince, spices and seasoning together in a bowl.","timer_seconds":null,"background":false},{"step":6,"label":"Shape and top the flatbreads","instruction":"Knead the dough briefly, divide into four, and roll each into a thin circle on the prepared trays. Spread a thin layer of the meat mixture over each.","timer_seconds":null,"background":false},{"step":7,"label":"Bake","instruction":"Bake each flatbread for 10 to 15 minutes until the edges begin to darken.","timer_seconds":750,"background":true},{"step":8,"label":"Serve","instruction":"Sprinkle with roughly chopped parsley and sliced onion, squeeze over a little lemon juice, and serve straightaway.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=8HTa64s8RK8"}, {"id": "53252", "name": "Turkish rice (vermicelli rice)", "category": "Miscellaneous", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xw1ruy1763786501.jpg", "local_image": "53252.jpg", "ingredients": [{"ingredient": "Rice", "measure": "300g"}, {"ingredient": "Vegetable Oil", "measure": "3  tablespoons"}, {"ingredient": "Vermicelli Pasta", "measure": "70g"}, {"ingredient": "Unsalted Butter", "measure": "30g"}, {"ingredient": "Chicken Stock", "measure": "600ml"}], "instructions": "step 1\r\nPour the rice into a very large bowl under cold running water and carefully drain the water out of the bowl through a sieve. Repeat a few times until the water in the bowl is clear, then fill the bowl up with cold water and leave rice to soak for 10 mins while you cook the vermicelli.\r\n\r\nstep 2\r\nPut the oil into a medium pan over medium heat. Add the vermicelli and stir continuously until the strands turn a rich golden brown, 2-3 mins. Remove from the heat, stir through the butter until it melts and allow the vermicelli to cool for 1-2 mins.\r\n\r\nstep 3\r\nDrain the rice thoroughly through a sieve. Add the rice to the pan and stir well. Pour the hot stock into the pan, sprinkle in ½ tsp salt, stir well then return the pan to the hob over a high heat. Bring to the boil, then reduce the heat to the lowest it will go, put the lid on the pan and simmer for 7-9 mins. Remove the pan from the heat, cover with a couple of sheets of kitchen paper or a light tea towel and the pan lid, and let the rice sit in the pan for 10 mins. Fluff up with a fork before serving.", "equipment_tags": [], "portions": 2, "prep_minutes": 34, "prep_minutes_source": "explicit", "kcal": 983, "protein_g": 16.8, "carbs_g": 148.4, "fat_g": 34.7, "total_kcal": 1966, "total_protein_g": 33.7, "total_carbs_g": 296.7, "total_fat_g": 69.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Rinse and soak the rice","instruction":"Rinse the rice under cold running water in a large bowl, draining and repeating until the water runs clear. Fill with cold water and leave to soak for 10 minutes while you cook the vermicelli.","timer_seconds":600,"background":true},{"step":2,"label":"Toast the vermicelli","instruction":"Heat the oil in a medium pan over medium heat, add the vermicelli, and stir continuously until golden brown, 2 to 3 minutes. Remove from the heat, stir through the butter until melted, and let cool for a minute or two.","timer_seconds":150,"background":false},{"step":3,"label":"Cook the rice","instruction":"Drain the rice well and add to the pan with the vermicelli. Pour in the hot stock, season with salt, and bring to the boil. Reduce the heat to the lowest setting, cover, and simmer for 7 to 9 minutes.","timer_seconds":480,"background":true},{"step":4,"label":"Rest and serve","instruction":"Remove from the heat, cover with kitchen paper or a light tea towel and the lid, and let the rice sit for 10 minutes. Fluff up with a fork before serving.","timer_seconds":600,"background":true}], "video": "https://www.youtube.com/watch?v=gY6PZzjO53M"}, {"id": "53253", "name": "Imam bayildi with BBQ lamb & tzatziki", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ampz9v1763787134.jpg", "local_image": "53253.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "3"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Tomato", "measure": "8"}, {"ingredient": "Parsley", "measure": "Bunch"}, {"ingredient": "Lamb Loin Chops", "measure": "12"}, {"ingredient": "Paprika", "measure": "Pinch"}, {"ingredient": "Lemon", "measure": "1"}, {"ingredient": "Greek Yogurt", "measure": "150g"}, {"ingredient": "Cucumber", "measure": "1/2"}, {"ingredient": "Mint", "measure": "2 tbs chopped"}], "instructions": "step 1\r\nHeat oven to 190C/170C fan/gas 5. Halve the aubergines lengthways and score the flesh side deeply, brush with a good layer of olive oil and put on a baking sheet. Roast for 20 mins or until the flesh is soft enough to scoop out.\r\n\r\nstep 2\r\nFry the onion in a little oil until soft, add the garlic and cinnamon and fry for 1 min. Once the aubergines are cool enough to handle, scoop out the centres. Roughly chop the flesh and add it to the onions. Halve the tomatoes, scoop the seeds and juice into a sieve set over a bowl, then chop the flesh. Add the chopped tomatoes to the pan and cook everything for 10 mins until nice and soft. Add a little more oil if you need to. Stir in the parsley, leaving a little for scattering at the end.\r\n\r\nstep 3\r\nLay the aubergine halves in a baking dish and divide the tomato mixture between them. Pour over the juice from the tomatoes, drizzle with more olive oil and bake for 30 mins until the aubergines have collapsed.\r\n\r\nstep 4\r\nMeanwhile, mix the tzatziki ingredients together and put in a small serving bowl.\r\n\r\nstep 5\r\nSeason the lamb with salt, black pepper and a pinch of paprika. Griddle, grill or barbecue for 3 mins on each side or until the fat is nicely browned, then put in a serving dish and squeeze over the lemon halves. Scatter the aubergines with parsley, then serve with the lamb and tzatziki.", "equipment_tags": ["Grill"], "portions": 4, "prep_minutes": 64, "prep_minutes_source": "explicit", "kcal": 612, "protein_g": 44.2, "carbs_g": 18.4, "fat_g": 41.0, "total_kcal": 2447, "total_protein_g": 176.9, "total_carbs_g": 73.6, "total_fat_g": 163.9, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Roast the aubergines","instruction":"Heat the oven to 190°C/170°C fan/gas 5. Halve the aubergines lengthways, score the flesh deeply, brush with olive oil, and roast for 20 minutes until soft enough to scoop out.","timer_seconds":1200,"background":true},{"step":2,"label":"Cook the filling","instruction":"Meanwhile, fry the onion until soft, add the garlic and cinnamon and fry for 1 minute. Scoop out the cooled aubergine centres, chop, and add to the onions with the chopped tomatoes (juice reserved). Cook for 10 minutes until soft, then stir in most of the parsley.","timer_seconds":600,"background":false},{"step":3,"label":"Fill and bake","instruction":"Lay the aubergine halves in a baking dish, divide the tomato mixture between them, pour over the reserved tomato juice, drizzle with more oil, and bake for 30 minutes until collapsed.","timer_seconds":1800,"background":true},{"step":4,"label":"Make the tzatziki","instruction":"Meanwhile, mix the tzatziki ingredients together and put in a small serving bowl.","timer_seconds":null,"background":true},{"step":5,"label":"Grill the lamb","instruction":"Season the lamb with salt, pepper and a pinch of paprika. Griddle, grill or barbecue for 3 minutes on each side until nicely browned, then squeeze over the lemon.","timer_seconds":360,"background":false},{"step":6,"label":"Serve","instruction":"Scatter the aubergines with the remaining parsley and serve with the lamb and tzatziki.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=k8ZMZtdu6Ac"}, {"id": "53254", "name": "Ezme", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/pb6mj11763788331.jpg", "local_image": "53254.jpg", "ingredients": [{"ingredient": "Tomato", "measure": "3 Large"}, {"ingredient": "Romano Pepper", "measure": "1 medium"}, {"ingredient": "Green Chilli", "measure": "1 medium"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Parsley", "measure": "25g"}, {"ingredient": "Red Pepper Paste", "measure": "2 tablespoons"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Pomegranate Molasses", "measure": "2 tablespoons"}, {"ingredient": "Pul Biber", "measure": "1 tablespoon"}, {"ingredient": "Sumac", "measure": "2 tsp"}, {"ingredient": "Dried Mint", "measure": "1 tablespoon"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "60 ml"}], "instructions": "step 1\r\nPut the tomatoes and all of the peppers in a food processor and blitz until finely chopped. Tip out into a sieve, set over a bowl and leave to strain. Add the onions, garlic and parsley to the food processor and blitz until finely chopped, then set aside.\r\n\r\nstep 2\r\nAdd red pepper paste, tomato purée, pomegranate molasses, pul biber, sumac, dried mint and most of the extra virgin olive oil to a serving bowl and whisk well so everything comes together as a sauce. Tip in the blitzed onion mixture and the strained pepper mixture along with 1 tsp flaky sea salt . Stir well, then drizzle with the remaining extra virgin olive oil to serve.", "equipment_tags": ["FoodProcessor"], "portions": 1, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 799, "protein_g": 9.9, "carbs_g": 68.0, "fat_g": 59.5, "total_kcal": 799, "total_protein_g": 9.9, "total_carbs_g": 68.0, "total_fat_g": 59.5, "macro_confidence": 0.92, "is_new": false, "cook_steps": [{"step":1,"label":"Blitz and strain","instruction":"Blitz the tomatoes and all the peppers in a food processor until finely chopped, then tip into a sieve set over a bowl to strain. Blitz the onions, garlic and parsley separately until finely chopped, and set aside.","timer_seconds":null,"background":true},{"step":2,"label":"Build the sauce","instruction":"Whisk the red pepper paste, tomato purée, pomegranate molasses, pul biber, sumac, dried mint and most of the olive oil together in a serving bowl until combined.","timer_seconds":null,"background":false},{"step":3,"label":"Finish and serve","instruction":"Stir in the blitzed onion mixture, the strained pepper mixture and the sea salt, then drizzle with the remaining olive oil to serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=Z1mX-C2fAuc"}, {"id": "53255", "name": "Grilled aubergines with spicy chickpeas & walnut sauce", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ctw3ba1763788978.jpg", "local_image": "53255.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Ginger", "measure": "2cm piece"}, {"ingredient": "Ground Cumin", "measure": "1/2 teaspoon"}, {"ingredient": "Chickpeas", "measure": "400g"}, {"ingredient": "Tomato", "measure": "200g"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Aubergine", "measure": "2"}, {"ingredient": "Greek Yogurt", "measure": "200g"}, {"ingredient": "Garlic Clove", "measure": "1"}, {"ingredient": "Walnuts", "measure": "25g"}, {"ingredient": "Coriander", "measure": "Handful"}], "instructions": "step 1\r\nHeat 2 tbsp oil in a pan, add the onion and fry until soft and lightly browned, about 10 mins. Add the chilli, ginger and spices and mix well. Stir in the chickpeas, tomatoes and 5 tbsp water, bring to the boil, then simmer for 10 mins. Add a little salt and pepper and the lemon juice.\r\n\r\nstep 2\r\nArrange the aubergines over a grill pan. Brush lightly with oil, sprinkle with salt and pepper, then grill until golden. Flip them over, brush again with oil, season and grill again until tender and golden.\r\n\r\nstep 3\r\nMix the yogurt with the garlic, most of the walnuts and coriander and a little salt and pepper. Arrange the aubergine slices over a warm platter and spoon over the chickpea mix. Drizzle with the walnut sauce and scatter with the remaining walnuts and coriander.", "equipment_tags": ["Grill"], "portions": 12, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 145, "protein_g": 5.5, "carbs_g": 14.5, "fat_g": 7.9, "total_kcal": 1736, "total_protein_g": 65.7, "total_carbs_g": 173.6, "total_fat_g": 94.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53256", "name": "Cacik", "category": "Side", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/16zbeu1763789342.jpg", "local_image": "53256.jpg", "ingredients": [{"ingredient": "Natural Yoghurt", "measure": "500g"}, {"ingredient": "Lemon Juice", "measure": "2 tsp"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Dried Mint", "measure": "1 tablespoon"}, {"ingredient": "Cucumber", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}], "instructions": "step 1\r\nPut a sieve over a large bowl, line it with a thick sheet of non-dyed kitchen paper or a clean muslin cloth, and spoon in the yogurt. Cover with another sheet of kitchen paper and leave to strain in the fridge for a minimum of 12 hrs.\r\n\r\nstep 2\r\nAdd the lemon juice, most of the olive oil and the dried mint to a bowl and stir well for the dried mint to soften and soak up the juices. Mix in the strained yogurt, then pour away the strained yogurt liquid and leave that bowl to one side.\r\n\r\nstep 3\r\nHalve the cucumber(s) lengthways and remove the seeds by running a teaspoon from the top to the bottom of the flesh, halve the cucumbers widthways to make them shorter and easier to handle, then coarsely grate each one into the bowl the yogurt was straining over. Using clean hands (or a clean muslin cloth), squeeze as much of the liquid out of the cucumber as possible.\r\n\r\nstep 4\r\nAdd the strained, grated cucumber, garlic and ¾ tsp flaky salt to the rest of the ingredients and mix well. Garnish with a drizzle of extra virgin olive oil and a sprinkling of dried mint.", "equipment_tags": [], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 151, "protein_g": 6.3, "carbs_g": 9.7, "fat_g": 10.2, "total_kcal": 452, "total_protein_g": 18.8, "total_carbs_g": 29.2, "total_fat_g": 30.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=eIDgcvpAvf8"}, {"id": "53257", "name": "kofta burgers", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/lgmnff1763789847.jpg", "local_image": "53257.jpg", "ingredients": [{"ingredient": "Lamb", "measure": "1kg"}, {"ingredient": "Onion", "measure": "2"}, {"ingredient": "Garlic Bulb", "measure": "1"}, {"ingredient": "Garam Masala", "measure": "6 tablespoons"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Chilli Sauce", "measure": "1 tablespoon"}, {"ingredient": "Pita Bread", "measure": "8"}, {"ingredient": "Tomato", "measure": "4 sliced"}, {"ingredient": "Red Cabbage", "measure": "1/2"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Yogurt", "measure": "Small pack"}], "instructions": "step 1\r\nTip the mince into a large bowl (use a clean washing-up bowl if you don’t have anything big enough) with all the other burger ingredients and a good pinch of salt. Roll up your sleeves, get your hands into the mix and squelch everything together through your fingers until completely mixed. Pat the mix into 16 small burgers. These may now be frozen for up to 1 month or chilled up to a day ahead.\r\n\r\nstep 2\r\nTo cook, heat grill to its highest setting and lay the burgers in a single layer on a baking tray (you may need to do this in batches, depending on how big your tray is). Grill on the highest shelf for 5-6 mins on each side until browned and cooked through. Pile burgers onto a platter and serve with all the accompaniments, so everyone can construct their own sandwich.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 922, "protein_g": 62.3, "carbs_g": 61.8, "fat_g": 47.6, "total_kcal": 4608, "total_protein_g": 311.3, "total_carbs_g": 309.1, "total_fat_g": 238.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/4OsDpyaTKk0"}, {"id": "53258", "name": "Hot cumin lamb wrap with crunchy slaw & spicy mayo", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/jyylmo1763790808.jpg", "local_image": "53258.jpg", "ingredients": [{"ingredient": "Lamb Leg", "measure": "4 small"}, {"ingredient": "Olive Oil", "measure": "2 tsp"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "White Wine Vinegar", "measure": "3  tablespoons"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Spring Onions", "measure": "2 sliced"}, {"ingredient": "White Cabbage", "measure": "400g"}, {"ingredient": "Sweet Peppadew Peppers", "measure": "5"}, {"ingredient": "Mayonnaise", "measure": "3  tablespoons"}, {"ingredient": "Pita Bread", "measure": "4 large"}], "instructions": "step 1\r\nHeat a griddle pan. Rub the lamb steaks with the oil, cumin and some seasoning. Griddle for about 3-4 mins on each side or until cooked to your liking. Place to one side on a plate to rest.\r\n\r\nstep 2\r\nIn a large bowl, stir the sugar into the vinegar until dissolved. Add the carrots, spring onions, cabbage and some seasoning, and toss together.\r\n\r\nstep 3\r\nBlitz the whole peppers and the mayo in a food processor. Add a heap of the salad to each flatbread. Slice the lamb, trimming off any excess fat and lay on top of the salad, drizzling with the resting juices. Spoon over the mayo and scatter with a few of the sliced peppers. Roll up and eat. If using pitta, split and stuff. Serve any extra salad on the side.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 150, "protein_g": 6.6, "carbs_g": 13.8, "fat_g": 7.8, "total_kcal": 1804, "total_protein_g": 79.7, "total_carbs_g": 165.7, "total_fat_g": 93.6, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53259", "name": "Smoked aubergine purée", "category": "Side", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8c8m4q1763791156.jpg", "local_image": "53259.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "2 medium"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Yogurt", "measure": "150ml"}, {"ingredient": "Dill", "measure": "Bunch"}], "instructions": "step 1\r\nHeat grill to very hot. Slice the aubergines in half lengthways, then grill for 25 mins, turning occasionally, until soft – the skin will remain firm, but the flesh will soften. Lift the aubergines off the grill and leave until cool enough to handle.\r\n\r\nstep 2\r\nUsing a sharp knife, score the grilled flesh and scoop out the flesh with a spoon. Tip into a bowl and mash with a fork until you get a thick pulp. Beat in the lemon juice and garlic. Add the yogurt and dill, and season. Serve while still warm.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 76, "protein_g": 4.1, "carbs_g": 10.5, "fat_g": 2.8, "total_kcal": 152, "total_protein_g": 8.2, "total_carbs_g": 20.9, "total_fat_g": 5.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=JOXBWo37wWU"}, {"id": "53260", "name": "Slow-roast lamb with cinnamon, fennel & citrus", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/gr4lo51763791826.jpg", "local_image": "53260.jpg", "ingredients": [{"ingredient": "Lamb Leg", "measure": "1"}, {"ingredient": "Lemon", "measure": "Zest and juice of 1"}, {"ingredient": "Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Clear Honey", "measure": "2 tablespoons"}, {"ingredient": "Cinnamon", "measure": "1 tablespoon"}, {"ingredient": "Fennel Seeds", "measure": "1 tablespoon"}, {"ingredient": "Ground Cumin", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}], "instructions": "step 1\r\nPut the lamb into a large food bag with all the juice and marinate overnight.\r\n\r\nstep 2\r\nThe next day, take the lamb out of the fridge 1 hr before you want to cook it. Heat oven to 220C/200C fan/gas 7. Take the lamb out of the marinade (reserve remaining marinade) and pat dry. Rub with half the oil and roast for 15-20 mins until browned. Remove lamb and reduce oven to 160C/140C fan/gas 3.\r\n\r\nstep 3\r\nMix the zests, remaining oil, honey, spices and garlic with plenty of seasoning. Lay a large sheet of baking parchment on a large sheet of foil. Sit the lamb leg on top, rub all over with the paste and pull up the sides of the foil. Drizzle marinade into base, and scrunch foil to seal.\r\n\r\nstep 4\r\nRoast for 4 hrs, until very tender. Rest, still wrapped, for 30 mins. Unwrap and serve with juices.", "equipment_tags": [], "portions": 1, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 932, "protein_g": 19.2, "carbs_g": 67.2, "fat_g": 71.6, "total_kcal": 932, "total_protein_g": 19.2, "total_carbs_g": 67.2, "total_fat_g": 71.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=4_mbvxabtJc"}, {"id": "53261", "name": "Chicken wings with cumin, lemon & garlic", "category": "Chicken", "area": "Turkish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/4hzyvq1763792564.jpg", "local_image": "53261.jpg", "ingredients": [{"ingredient": "Chicken Wings", "measure": "12"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Lemon", "measure": "Zest and juice of 1"}, {"ingredient": "Cumin Seeds", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Honey", "measure": "1 tablespoon"}], "instructions": "step 1\r\nUsing a pair of sharp kitchen scissors, cut each wing at the knuckle into two pieces. Mix the garlic, lemon zest and juice, cumin and oil with plenty of seasoning, then tip into a dish with the chicken wings and toss to coat. Cover and put in the fridge to marinate for at least 1 hr, or overnight if you have time.\r\n\r\nstep 2\r\nHeat oven to 200C/180C fan/gas 6, or heat an outdoor barbecue. Bake the chicken wings on an oven tray for 45-50 mins until crisp, or barbecue for 20 mins, drizzling over the honey for the final 10 mins of each method. Serve on a platter with plenty of paper napkins. Fill small bowls with olives, pistachios or almonds, dates and pickled chillies and flatbreads to serve alongside, along with the dishes below.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 140, "prep_minutes_source": "explicit", "kcal": 1563, "protein_g": 112.1, "carbs_g": 24.4, "fat_g": 112.2, "total_kcal": 1563, "total_protein_g": 112.1, "total_carbs_g": 24.4, "total_fat_g": 112.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=hmJPOVzMvK4"}, {"id": "53262", "name": "Adana kebab", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/04axct1763793018.jpg", "local_image": "53262.jpg", "ingredients": [{"ingredient": "Romano Pepper", "measure": "2 large"}, {"ingredient": "Lamb Mince", "measure": "800g"}, {"ingredient": "Red Pepper Paste", "measure": "3  tablespoons"}, {"ingredient": "Pul Biber", "measure": "1 tablespoon"}, {"ingredient": "Sunflower Oil", "measure": "3  tablespoons"}], "instructions": "step 1\r\nFinely chop the peppers in a food processor, then tip them in a sieve and press into the sieve so that the peppers release all of their juices. Tip into a bowl along with the mince, red pepper paste, pul biber, 1½ tsp flaky sea salt, and 2 tbsp of the oil. Mix together, kneading well for at least 2-3 mins. If you need to, wet your hands with cold water to prevent the mixture from sticking. The mixture should be sticky when ready. Cover and chill for at least 2 hrs, or up to 12 hrs.\r\n\r\nstep 2\r\nWhen ready to cook, heat the grill to high or an oven to 220C/200C fan/gas 6. Divide the mixture into 12 equal portions, around 85g each. If you’d like to skewer them, divide into 8 equal portions and roll into balls. Using wet hands, thread the balls onto the end of the skewers, massaging the mixture down the skewers in between the palms of your hands, until evenly distributed. Ensure that the mixture is fully wrapped tightly around the skewers without any exposed metal. Alternatively, lay them on a large baking tray lined with parchment paper if cooking in the oven, or foil if cooking under the grill. Shape into 20cm-long köfte. Wet your fingers with a little cold water and make indents all along the köfte for the traditional shape.\r\n\r\nstep 3\r\nGently brush each köfte with the remaining 1 tbsp oil and cook under the grill, on the top shelf for 10-12 mins, turning regularly, or cook in the oven for 16-18 mins, until crispy on the outside and juicy in the middle", "equipment_tags": ["FoodProcessor", "Grill"], "portions": 2, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 1340, "protein_g": 77.2, "carbs_g": 5.4, "fat_g": 109.8, "total_kcal": 2681, "total_protein_g": 154.3, "total_carbs_g": 10.8, "total_fat_g": 219.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=Wj7sXu9B_ME"}, {"id": "53263", "name": "Turkish lamb pilau", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/cr2kyr1763793839.jpg", "local_image": "53263.jpg", "ingredients": [{"ingredient": "Pine Nuts", "measure": "Handful"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 Large Chopped"}, {"ingredient": "Cinnamon", "measure": "2"}, {"ingredient": "Lamb", "measure": "500g"}, {"ingredient": "Basmati Rice", "measure": "250g"}, {"ingredient": "Lamb Stock", "measure": "1"}, {"ingredient": "Dried Apricots", "measure": "12"}, {"ingredient": "Mint", "measure": "Handful"}], "instructions": "step 1\r\nDry-fry the pine nuts or almonds in a large pan until lightly toasted, then tip onto a plate. Add the oil to the pan, then fry the onion and cinnamon together until starting to turn golden. Turn up the heat, stir in the lamb, fry until the meat changes colour, then tip in the rice and cook for 1 min, stirring all the time.\r\n\r\nstep 2\r\nPour in 500ml boiling water, crumble in the stock cube, add the apricots, then season to taste. Turn the heat down, cover and simmer for 12 mins until the rice is tender and the stock has been absorbed. Toss in the pine nuts and mint and serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 1446, "protein_g": 61.5, "carbs_g": 196.8, "fat_g": 51.5, "total_kcal": 4337, "total_protein_g": 184.5, "total_carbs_g": 590.5, "total_fat_g": 154.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=FXaQK06pMBI"}, {"id": "53264", "name": "Smoky chicken skewers", "category": "Chicken", "area": "Turkish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/3um6il1763794322.jpg", "local_image": "53264.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "6"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Fennel Seeds", "measure": "1 tsp"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "sweet smoked paprika", "measure": "1 tsp"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Red Wine Vinegar", "measure": "1 tsp"}, {"ingredient": "Smoky Aïoli", "measure": "To serve"}], "instructions": "step 1\r\nYou need 15 skewers: if wooden, soak in water for 10 mins. Cut chicken into 3cm pieces and place in a bowl. Add 1 tbsp olive oil, the spices, garlic and vinegar, toss well and season. You can do this up to a day before and refrigerate.\r\n\r\nstep 2\r\nThread 2-3 pieces on each skewer. Pour remaining oil in a frying pan or rub onto a griddle pan. Get the pan hot and sear the chicken for 3-4 mins on each side – you may have to do this in batches, keeping the cooked skewers warm in a low oven. Serve with smoky aïoli if you like.", "equipment_tags": [], "portions": 1, "prep_minutes": 14, "prep_minutes_source": "explicit", "kcal": 701, "protein_g": 64.1, "carbs_g": 13.0, "fat_g": 42.7, "total_kcal": 701, "total_protein_g": 64.1, "total_carbs_g": 13.0, "total_fat_g": 42.7, "macro_confidence": 0.88, "is_new": false, "video": "https://www.youtube.com/watch?v=vNDTGF4ppu8"}, {"id": "53265", "name": "Chilli ginger lamb chops", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8xuvhj1763794991.jpg", "local_image": "53265.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Ginger", "measure": "1 tblsp"}, {"ingredient": "Lemon Juice", "measure": "1 tblsp"}, {"ingredient": "Olive Oil", "measure": "1 tblsp"}, {"ingredient": "Chili Powder", "measure": "1/2 tsp"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Lamb Loin Chops", "measure": "8"}], "instructions": "step 1\r\nPut the garlic in a bowl with the ginger, lemon juice, oil, spices and seasoning. Blitz with a hand blender until smooth, then use to coat the lamb chops on both sides. Leave to marinate in the fridge for a couple of hours or overnight.\r\n\r\nstep 2\r\nHeat a barbecue until hot. Barbecue the chops over the coals for 3 mins on each side until cooked but still pink and juicy in the centre.", "equipment_tags": ["Blender", "Grill"], "portions": 1, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 1357, "protein_g": 102.3, "carbs_g": 11.1, "fat_g": 99.5, "total_kcal": 1357, "total_protein_g": 102.3, "total_carbs_g": 11.1, "total_fat_g": 99.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=MNrNHToyvtI"}, {"id": "53266", "name": "Falafel", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/u5e9qq1763795441.jpg", "local_image": "53266.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Chickpeas", "measure": "400g"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "Ground Coriander", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Egg", "measure": "1 beaten"}], "instructions": "step 1\r\nHeat 1 tbsp oil in a large pan, then fry the onion and garlic over a low heat for 5 mins until softened. Tip into a large mixing bowl with the chickpeas and spices, then mash together with a fork or potato masher until the chickpeas are totally broken down. Stir in the parsley or dried herbs, with seasoning to taste. Add the egg, then squish the mixture together with your hands.\r\n\r\nstep 2\r\nMould the mix into 6 balls, then flatten into patties. Heat the remaining oil in the pan, then fry the falafels on a medium heat for 3 mins on each side, until golden brown and firm. Serve hot or cold with couscous, pitta bread or salad.", "equipment_tags": [], "portions": 1, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 1051, "protein_g": 45.4, "carbs_g": 125.6, "fat_g": 44.5, "total_kcal": 1051, "total_protein_g": 45.4, "total_carbs_g": 125.6, "total_fat_g": 44.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=NZcWedPKysk"}, {"id": "53267", "name": "Aubergine couscous salad", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/02s6gc1763799560.jpg", "local_image": "53267.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "1 sliced"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Couscous", "measure": "140g"}, {"ingredient": "Vegetable Stock", "measure": "225g"}, {"ingredient": "Cherry Tomatoes", "measure": "200g"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Goats Cheese", "measure": "100g"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}], "instructions": "step 1\r\nHeat grill to high. Put the aubergine on a baking sheet, brush with oil and season. Grill for about 15 mins, turning and brushing with more oil halfway, until browned and softened.\r\n\r\nstep 2\r\nMeanwhile, tip the couscous into a large bowl, pour over the stock, then cover and leave for 10 mins. Mix the tomatoes, mint, goat’s cheese and remaining oil together. Fluff the couscous up with a fork, then stir in the aubergines, tomato mixture and lemon juice.", "equipment_tags": ["Grill"], "portions": 6, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 221, "protein_g": 7.8, "carbs_g": 21.2, "fat_g": 11.9, "total_kcal": 1324, "total_protein_g": 47.1, "total_carbs_g": 127.5, "total_fat_g": 71.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/8ws2Ohy__CQ"}, {"id": "53268", "name": "Roasted chicken with creamy walnut sauce", "category": "Chicken", "area": "Turkish", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/ro8mzj1763800655.jpg", "local_image": "53268.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "8"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Pita Bread", "measure": "6"}, {"ingredient": "Chicken Stock", "measure": "150ml"}, {"ingredient": "Walnuts", "measure": "175g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Single Cream", "measure": "50 ml"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Coriander", "measure": "Handful"}], "instructions": "step 1\r\nHeat oven to 200C/180C fan/gas 6. In a roasting tin, toss together the chicken, cumin, paprika, 1 tbsp olive oil and seasoning. Cook for 40 mins until the chicken is crisp and cooked through.\r\n\r\nstep 2\r\nMeanwhile, tear up 1 pitta bread and place in a small bowl. Pour over a couple of tbsp chicken stock and leave to soak. Dry-fry the walnuts in a frying pan for about 3 mins until golden and toasted. Set aside. Heat the remaining oil in the pan and cook the onion and garlic until softened. Place the softened pitta bread, onion mixture and most of the nuts into a blender. Pour over the rest of the chicken stock and whizz together until a rough paste forms. Return the mixture to the pan. Add the cream and lemon juice, season and keep warm.\r\n\r\nstep 3\r\nWhen the chicken is cooked, arrange on a platter. Stir the coriander through the sauce and spoon into a bowl. Roughly chop the remaining walnuts and scatter over the chicken. Toast the pittas, cut into wedges and serve alongside", "equipment_tags": ["Blender"], "portions": 3, "prep_minutes": 43, "prep_minutes_source": "explicit", "kcal": 953, "protein_g": 46.4, "carbs_g": 64.8, "fat_g": 58.7, "total_kcal": 2859, "total_protein_g": 139.1, "total_carbs_g": 194.4, "total_fat_g": 176.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=e8Bn3V3kmpM"}, {"id": "53269", "name": "Hummus", "category": "Side", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/gpon5u1763801180.jpg", "local_image": "53269.jpg", "ingredients": [{"ingredient": "Chickpeas", "measure": "400g"}, {"ingredient": "Tahini Paste", "measure": "1 tablespoon"}, {"ingredient": "Garlic Clove", "measure": "1 large"}, {"ingredient": "Greek Yogurt", "measure": "3  tablespoons"}, {"ingredient": "Lemon", "measure": "Juice of half"}], "instructions": "step 1\r\nDrain the chickpeas into a sieve set over a bowl or jug to catch the liquid. Tip the chickpeas, tahini, garlic and yogurt into a food processor or blender and whizz to smooth.\r\n\r\nstep 2\r\nWhizz in a tbsp of the chickpea liquid at a time until you have a nice consistency, then scrape into a bowl.\r\n\r\nstep 3\r\nStir in a squeeze of lemon juice and season to taste.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 3, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 267, "protein_g": 14.2, "carbs_g": 39.4, "fat_g": 7.0, "total_kcal": 802, "total_protein_g": 42.7, "total_carbs_g": 118.3, "total_fat_g": 20.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=EsZFJEjANiA"}, {"id": "53270", "name": "Turkish-style lamb", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0p7l6b1763813981.jpg", "local_image": "53270.jpg", "ingredients": [{"ingredient": "Lamb Leg", "measure": "4"}, {"ingredient": "Seasoning", "measure": "2 tsp"}, {"ingredient": "Dried Oregano", "measure": "1 tsp"}, {"ingredient": "Mint", "measure": "Bunch"}, {"ingredient": "Yogurt", "measure": "300g"}, {"ingredient": "Pita Bread", "measure": "4"}, {"ingredient": "Iceberg Lettuce", "measure": "1/2"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Lemon", "measure": "1"}], "instructions": "step 1\r\nHeat grill to high. Season the lamb, then grill for 2 mins on each side until browned, but still very rare. Meanwhile, mix the seasoning, oregano and half of the mint into one of the tubs of yogurt, smother this over the lamb, then return to the grill for another 2-3 mins or until the yogurt is blistered and the meat is cooked to your liking.\r\n\r\nstep 2\r\nLeave the meat to rest on a board for a few mins while you toast the pittas, shred the lettuce and thinly slice the red onion. Stir the rest of the mint into the second tub of yogurt. Thickly slice the meat and stuff into the pitta bread with the salad and minted yogurt. Squeeze over lemon juice before tucking in, if you like.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 710, "protein_g": 41.7, "carbs_g": 69.8, "fat_g": 29.9, "total_kcal": 1421, "total_protein_g": 83.3, "total_carbs_g": 139.6, "total_fat_g": 59.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=RSXfGtom4RQ"}, {"id": "53271", "name": "Walnut, date & honey cake", "category": "Dessert", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/towo9c1763814590.jpg", "local_image": "53271.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "225g"}, {"ingredient": "Ground Cinnamon", "measure": "1/2 teaspoon"}, {"ingredient": "Butter", "measure": "175g"}, {"ingredient": "Muscovado Sugar", "measure": "100g"}, {"ingredient": "Clear Honey", "measure": "3  tablespoons"}, {"ingredient": "Egg", "measure": "2 Beaten"}, {"ingredient": "Banana", "measure": "2 medium"}, {"ingredient": "Stoned Dates", "measure": "100g"}, {"ingredient": "Walnuts", "measure": "50g"}], "instructions": "step 1\r\nPreheat the oven to 160C/Gas 3/fan oven 140C. Line the base and long sides of a 900g/2lb loaf tin with greaseproof paper, buttering the tin and paper.\r\n\r\nstep 2\r\nTip the flour, cinnamon, butter, sugar, 2 tablespoons of the honey and the eggs into a large mixing bowl. Mash the bananas and chop the dates (kitchen scissors are easiest for this) and add to the bowl. Beat the mixture for 2-3 minutes, using a wooden spoon or hand-held mixer, until well blended.\r\n\r\nstep 3\r\nSpoon into the prepared tin and level the top. Scatter the walnut pieces over. Bake for 1 hour, then lightly press the top – it will feel firm if cooked. If not, bake for a further 10 minutes.\r\n\r\nstep 4\r\nCool for 15 minutes, then lift out of the tin using the paper. When cold, drizzle the remaining honey over. Cut into thick slices.", "equipment_tags": [], "portions": 6, "prep_minutes": 88, "prep_minutes_source": "explicit", "kcal": 548, "protein_g": 8.3, "carbs_g": 62.0, "fat_g": 32.5, "total_kcal": 3287, "total_protein_g": 49.8, "total_carbs_g": 371.9, "total_fat_g": 194.8, "macro_confidence": 0.89, "is_new": false, "video": "https://www.youtube.com/watch?v=ivR-YRcQk08"}, {"id": "53272", "name": "Griddled flatbreads", "category": "Side", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8825lo1763815264.jpg", "local_image": "53272.jpg", "ingredients": [{"ingredient": "Strong Wholemeal Flour", "measure": "250g"}, {"ingredient": "Strong white bread flour", "measure": "250g"}, {"ingredient": "Yeast", "measure": "15g"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}], "instructions": "step 1\r\nTip the flours into a food processor. Add the yeast, sugar and 1tsp salt, then mix well. Pour in 350ml warm water and the oil, then process to a soft dough. Mix for 1 min, then leave until doubled in size, about 1 hour.\r\n\r\nstep 2\r\nPulse the dough a couple of times just to knock out the air, then tip onto a floured surface. Cut the dough in half and roll out one half to a rectangle about 20 x 40cm. Trim the edges using a large sharp knife, then cut into eight 10cm squares. Line a large tray or two baking sheets with non-stick paper and arrange the bread rectangles over the tray in one layer. Repeat with the other half of the dough. Leave in a warm place for about 30 mins until the dough is just starting to rise.\r\n\r\nstep 3\r\nPlace bread directly onto the BBQ racks and cook for a couple of mins until they puff up, then flip over and cook on the other side. Tip into a basket and serve with the dips.", "equipment_tags": ["FoodProcessor", "Grill"], "portions": 5, "prep_minutes": 91, "prep_minutes_source": "explicit", "kcal": 426, "protein_g": 11.2, "carbs_g": 78.1, "fat_g": 6.7, "total_kcal": 2129, "total_protein_g": 56.0, "total_carbs_g": 390.4, "total_fat_g": 33.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=s_ilia2LZ4U"}, {"id": "53273", "name": "Roast aubergine with goat's cheese & toasted flatbread", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/iydbwy1763816111.jpg", "local_image": "53273.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "2 sliced"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Cherry Tomatoes", "measure": "12"}, {"ingredient": "Pita Bread", "measure": "1"}, {"ingredient": "Balsamic Vinegar", "measure": "3  tablespoons"}, {"ingredient": "Mint", "measure": "Handful"}, {"ingredient": "Shallots", "measure": "1 chopped"}, {"ingredient": "Shallots", "measure": "1 sliced"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Goats Cheese", "measure": "50g"}, {"ingredient": "Rocket", "measure": "Handful"}], "instructions": "step 1\r\nHeat oven to 200C/180C fan/gas 6. Brush the aubergine slices with 1 tbsp of the oil, then season. Arrange on a baking tray or sheet and roast for 20 mins until browned, popping the tomatoes on the tray for the final 5 mins. Tear the flatbread into pieces and place on a separate baking sheet. Brown in the oven for 8 mins, or until crisp, then remove.\r\n\r\nstep 2\r\nFor the dressing, in a small bowl, mix the vinegar, mint, chopped shallots, chilli, remaining oil and some salt and pepper.\r\n\r\nstep 3\r\nScatter the aubergine slices, tomatoes, sliced shallot and crisp flatbread into a serving bowl. Pour over the dressing, sprinkle with the goat’s cheese and scatter over a little rocket.", "equipment_tags": [], "portions": 12, "prep_minutes": 33, "prep_minutes_source": "explicit", "kcal": 86, "protein_g": 2.8, "carbs_g": 8.6, "fat_g": 5.0, "total_kcal": 1035, "total_protein_g": 33.7, "total_carbs_g": 103.4, "total_fat_g": 60.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53274", "name": "Griddled aubergines with sesame dressing", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/yoj48r1763817100.jpg", "local_image": "53274.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "2 large"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Greek Yogurt", "measure": "250g"}, {"ingredient": "Tahini Paste", "measure": "3  tablespoons"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Coriander", "measure": "Handful"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Mint", "measure": "Handful"}], "instructions": "step 1\r\nBrush each aubergine slice with some oil, then season. Heat a griddle pan or barbecue. When hot, griddle the aubergine slices for 2-3 mins on each side until golden brown and tender.\r\n\r\nstep 2\r\nMix the yogurt with the tahini, garlic, lemon juice and herbs, then season. Top the aubergines with the dressing and scatter over extra herb leaves.", "equipment_tags": ["Grill"], "portions": 12, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 69, "protein_g": 2.9, "carbs_g": 2.9, "fat_g": 5.4, "total_kcal": 823, "total_protein_g": 34.3, "total_carbs_g": 34.8, "total_fat_g": 65.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=332VIeW67VM"}, {"id": "53275", "name": "Sweet potato salad", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/z458v91763817681.jpg", "local_image": "53275.jpg", "ingredients": [{"ingredient": "Sweet Potatoes", "measure": "1200g"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Shallots", "measure": "2"}, {"ingredient": "Spring Onions", "measure": "4 sliced"}, {"ingredient": "Chives", "measure": "Bunch"}, {"ingredient": "Sherry vinegar", "measure": "5 tablespoons"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Honey", "measure": "2 tablespoons"}], "instructions": "step 1\r\nHeat oven to 200C/180C fan/gas 6. Toss the sweet potato chunks with the olive oil and some seasoning, and spread on a baking parchment-lined baking sheet. Roast for 30 - 35 mins until tender and golden. Cool at room temperature.\r\n\r\nstep 2\r\nWhen just about cool whisk together all the dressing ingredients with a little more seasoning and gently toss through the potato chunks – use your hands to avoid breaking them up.", "equipment_tags": [], "portions": 12, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 147, "protein_g": 2.6, "carbs_g": 27.1, "fat_g": 3.6, "total_kcal": 1763, "total_protein_g": 30.7, "total_carbs_g": 325.5, "total_fat_g": 43.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=RkiKSO0IuVQ"}, {"id": "53276", "name": "Apricot & Turkish delight mess", "category": "Dessert", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/p277uc1764109195.jpg", "local_image": "53276.jpg", "ingredients": [{"ingredient": "Mascarpone", "measure": "100g"}, {"ingredient": "Greek Yogurt", "measure": "50g"}, {"ingredient": "Icing Sugar", "measure": "25g"}, {"ingredient": "Orange Blossom Water", "measure": "2 tablespoons"}, {"ingredient": "Meringue Nests", "measure": "1"}, {"ingredient": "Apricot", "measure": "3"}, {"ingredient": "Turkish Delight", "measure": "2 pieces"}, {"ingredient": "Almonds", "measure": "25g"}, {"ingredient": "Mint", "measure": "4"}], "instructions": "step 1\r\nPlace the mascarpone, yogurt, sugar and orange flower water into a large bowl and whisk until thickened. Fold the remaining ingredients through, then divide the mix between 2 dessert glasses or bowls and decorate with extra mint, if you like.", "equipment_tags": [], "portions": 5, "prep_minutes": 19, "prep_minutes_source": "estimated", "kcal": 248, "protein_g": 6.4, "carbs_g": 27.1, "fat_g": 13.8, "total_kcal": 1238, "total_protein_g": 32.1, "total_carbs_g": 135.4, "total_fat_g": 69.0, "macro_confidence": 0.89, "is_new": false, "video": null}, {"id": "53277", "name": "Lamb & apricot meatballs", "category": "Lamb", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/72fgzj1764109947.jpg", "local_image": "53277.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Red Onions", "measure": "2 chopped"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Ground Cumin", "measure": "2 tsp"}, {"ingredient": "Ground Coriander", "measure": "2 tsp"}, {"ingredient": "Tinned Tomatos", "measure": "400g"}, {"ingredient": "Sugar", "measure": "1/2 teaspoon"}, {"ingredient": "Mint", "measure": "10g"}, {"ingredient": "Lamb Mince", "measure": "500g"}, {"ingredient": "Dried Apricots", "measure": "8"}, {"ingredient": "Breadcrumbs", "measure": "50g"}, {"ingredient": "Pita Bread", "measure": "To serve"}], "instructions": "step 1\r\nHeat 2 tsp oil in a pan and soften the onions for 5 mins. Add the garlic and spices and cook for a few mins more. Spoon half the onion mixture into a bowl and set aside to cool. Add the tomatoes, sugar and seasoning to the remaining onions in the pan and simmer for about 10 mins until reduced.\r\n\r\nstep 2\r\nMeanwhile, add the mint, lamb, apricots and breadcrumbs to the cooled onions, season and mix well with your hands. Shape into little meatballs.\r\n\r\nstep 3\r\nHeat the rest of the oil in a non-stick pan and fry the meatballs until golden (in batches if you need to). Stir in the sauce with a splash of water and gently cook everything for a few mins until the meatballs are cooked through. Serve with pitta bread and salad.", "equipment_tags": [], "portions": 3, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 1042, "protein_g": 42.3, "carbs_g": 116.8, "fat_g": 48.9, "total_kcal": 3125, "total_protein_g": 127.0, "total_carbs_g": 350.5, "total_fat_g": 146.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=o0UbzRZw-GQ"}, {"id": "53278", "name": "Aubergine & hummus grills", "category": "Vegetarian", "area": "Turkish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/zub3s91764110535.jpg", "local_image": "53278.jpg", "ingredients": [{"ingredient": "Aubergine", "measure": "2"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Bread", "measure": "3 sliced thinly"}, {"ingredient": "Hummus", "measure": "300g"}, {"ingredient": "Walnuts", "measure": "100g"}, {"ingredient": "Parsley", "measure": "40g"}, {"ingredient": "Cherry Tomatoes", "measure": "200g"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "Splash"}], "instructions": "step 1\r\nLay the aubergine out in one layer on a large baking sheet. Brush sparingly with vegetable oil, then season generously. Grill for 15 mins, turning twice and brushing with oil until the slices are softened and cooked through. Meanwhile, whizz the bread into crumbs. Add 2 tsp oil and whizz briefly again, to coat.\r\n\r\nstep 2\r\nSpread a couple of tsps of hummus on top of each slice of aubergine. Tip the breadcrumbs onto a large plate, then press the hummus side of the aubergines into the crumbs to coat. Grill again, crumb-side up, for about 3 mins until golden.\r\n\r\nstep 3\r\nToss the walnuts, parsley and cherry tomatoes in a bowl, season, then add the lemon juice and olive oil and toss again. Serve the grills with the salad, a dollop more hummus and some pitta bread.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 1005, "protein_g": 28.3, "carbs_g": 74.8, "fat_g": 71.1, "total_kcal": 2010, "total_protein_g": 56.5, "total_carbs_g": 149.5, "total_fat_g": 142.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=P5LD03XptB8"}, {"id": "53279", "name": "Baklava with spiced nuts, ricotta & chocolate", "category": "Dessert", "area": "Turkish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ytme8t1764111401.jpg", "local_image": "53279.jpg", "ingredients": [{"ingredient": "Sugar", "measure": "500g"}, {"ingredient": "Lemon Juice", "measure": "To taste"}, {"ingredient": "Walnuts", "measure": "300g"}, {"ingredient": "Pecan Nuts", "measure": "200g"}, {"ingredient": "Almonds", "measure": "100g"}, {"ingredient": "Ground Cinnamon", "measure": "2 tablespoons"}, {"ingredient": "Ground Cardomom", "measure": "1 tablespoon"}, {"ingredient": "Ricotta", "measure": "500g"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Vanilla Bean Paste", "measure": "1 tablespoon"}, {"ingredient": "Unsalted Butter", "measure": "250g"}, {"ingredient": "Filo Pastry", "measure": "500g"}, {"ingredient": "Ground Pistachios", "measure": "100g"}], "instructions": "step 1\r\nFirst, make the syrup. Tip the sugar into a large saucepan with 650ml water. Stir over a low heat until the sugar has dissolved, then turn up the heat and bring to the boil. Reduce the heat to a simmer and cook for 15 mins, then squeeze in a few drops of lemon juice and simmer for a further 5 mins. Remove from the heat and leave to cool. Meanwhile, for assembling the baklava later, melt the butter in a small pan over a low heat for 5 mins, skimming and discarding any froth that rises to the surface.\r\n\r\nstep 2\r\nFor the filling, crush all of the nuts in a pestle and mortar, or blitz in a food processor – you want a mixture of finely ground nuts with a few chunky pieces. Tip into a bowl, stir through the spices and set aside.\r\n\r\nstep 3\r\nIn a separate bowl, mix the ricotta with the lemon and orange zests and vanilla. Heat the oven to 180C/160C fan/gas 4. Brush the bottom of a large baking tray (about 35 x 47cm) with some of the melted butter. Working with one sheet of filo at a time (covering the rest with a damp tea towel to prevent it drying out), lay the sheet out on a board so one of the short ends is facing you. Sprinkle 30g of the nut mixture evenly over the whole sheet, then spoon 1 tbsp of the ricotta mixture across the end closest to you. Fold this end over to enclose the filling, then lay a long, thin skewer next to the folded edge and roll the pastry around it to create a long roll. When it’s fully rolled up, it should be roughly the thickness of a chipolata sausage. While holding one end of the rolling pin or skewer, gently scrunch the filo roll like an accordion and carefully push it off the skewer and onto the prepared tray. Repeat with the rest of the filo and fillings – you should get about 12 rolls. Cut each roll into four to make 48 large baklava, or eight to make 96 mini.\r\n\r\nstep 4\r\nBrush with the remaining melted butter. Bake for 20-25 mins until evenly golden, turning the tray around halfway through. While still hot, immediately pour over 5-6 ladlefuls of the syrup. You should hear the syrup sizzle as it hits the hot baklava. Set aside to cool and absorb.\r\n\r\nstep 5\r\nMelt the dark chocolate in a heatproof bowl set over a pan of simmering water, ensuring the bowl doesn’t touch the water, or in the microwave in short bursts. Drizzle this over the cooled baklava and sprinkle with the ground pistachios.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 897, "protein_g": 17.6, "carbs_g": 80.7, "fat_g": 59.8, "total_kcal": 10767, "total_protein_g": 211.6, "total_carbs_g": 968.1, "total_fat_g": 718.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=yK_sSFDvsT0"}, {"id": "53280", "name": "Poulet Roti a l'Algerienne (Algerian Roast Chicken)", "category": "Chicken", "area": "Algerian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/nlxald1764112200.jpg", "local_image": "53280.jpg", "ingredients": [{"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Olive Oil", "measure": "5 tablespoons"}, {"ingredient": "Balsamic Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Dijon Mustard", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Chicken", "measure": "1"}], "instructions": "Preheat oven to 350 degrees F (175 degrees C).\r\n\r\nMix water, onion, olive oil, balsamic vinegar, Dijon mustard, garlic, black pepper, cayenne pepper, and salt together in a roasting dish. Add chicken; turn until well coated with mixture.\r\n\r\nBake in the preheated oven until an instant-read thermometer inserted into the thickest part of the thigh, near the bone, reads 165 degrees F (74 degrees C), about 1 hour 30 minutes.", "equipment_tags": [], "portions": 1, "prep_minutes": 90, "prep_minutes_source": "explicit", "kcal": 786, "protein_g": 14.0, "carbs_g": 20.2, "fat_g": 73.9, "total_kcal": 786, "total_protein_g": 14.0, "total_carbs_g": 20.2, "total_fat_g": 73.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=78O6Sv7HNO0"}, {"id": "53281", "name": "Algerian Kefta (Meatballs)", "category": "Beef", "area": "Algerian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/8rfd4q1764112993.jpg", "local_image": "53281.jpg", "ingredients": [{"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Onion", "measure": "1/2 cup"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Plum Tomatoes", "measure": "3"}, {"ingredient": "Parsley", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1/2 cup"}], "instructions": "Combine ground beef with 1/2 of the minced garlic and 1 tablespoon chopped onion in a large bowl. Mix with your hands until fully incorporated. Shape meat mixture into 1 1/2-inch oblong patties; you should have 12 to 14 meatballs.\r\n\r\nHeat a large skillet over medium-high heat. Brown patties in batches in the hot skillet until crispy on both sides and no longer pink in the center, about 10 minutes. Set meatballs aside in a rimmed serving dish.\r\n\r\nReduce heat to medium and stir remaining chopped onion into drippings in the skillet. Season with salt and pepper. Cook, stirring constantly, until onion has softened and turned translucent, about 5 minutes. Stir in remaining garlic and cook for 30 seconds. Stir in Roma tomatoes, dried parsley, and ras el hanout. Pour in water. Cook until tomatoes are soft, about 5 minutes.\r\n\r\nPour tomato sauce over meatballs to serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 638, "protein_g": 41.1, "carbs_g": 13.9, "fat_g": 45.8, "total_kcal": 1276, "total_protein_g": 82.2, "total_carbs_g": 27.8, "total_fat_g": 91.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=IRadJQNLvPs"}, {"id": "53282", "name": "Algerian Carrots", "category": "Side", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/o2cd4r1764113576.jpg", "local_image": "53282.jpg", "ingredients": [{"ingredient": "Water", "measure": "1 1/2 cup"}, {"ingredient": "Carrots", "measure": "2 Lbs"}, {"ingredient": "Olive Oil", "measure": "5 tablespoons"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Cinnamon", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Cumin", "measure": "1/2 teaspoon"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Thyme", "measure": "1/2 teaspoon"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Lemon Juice", "measure": "1 tsp"}], "instructions": "Place a steamer insert into a saucepan, and fill with 1 1/2 cups of water, or just below the bottom of the steamer. Cover, and bring the water to a boil over high heat. Add the sliced carrots, reduce the heat to medium, and cover the pan again. Steam until tender but not mushy, 4 to 6 minutes depending on the thickness of the slices. Reserve 1/2 cup of the cooking liquid.\r\n\r\nHeat the olive oil in a skillet over medium heat. Reduce the heat to low and stir in the salt, pepper, cinnamon, cumin, garlic, and thyme. Cook the spices and garlic, stirring frequently, until fragrant, about 10 minutes. Add the 1/2 cup reserved cooking liquid and the bay leaf, cover, and simmer for 20 minutes.\r\n\r\nStir in the carrots, tossing well to coat with the spice mixture, and cook until heated through, about 2 to 3 minutes. Sprinkle with lemon juice and remove the bay leaf before serving.", "equipment_tags": [], "portions": 8, "prep_minutes": 39, "prep_minutes_source": "explicit", "kcal": 128, "protein_g": 1.2, "carbs_g": 12.4, "fat_g": 9.0, "total_kcal": 1022, "total_protein_g": 9.7, "total_carbs_g": 99.6, "total_fat_g": 71.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=mF2ND56szUQ"}, {"id": "53283", "name": "Chtitha Batata (Algerian Potato Stew)", "category": "Vegetarian", "area": "Algerian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/q8pu1k1764114334.jpg", "local_image": "53283.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Red Chilli", "measure": "1 small"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 teaspoon"}, {"ingredient": "Black Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 teaspoon"}, {"ingredient": "Salt", "measure": "1/2 teaspoon"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "New Potatoes", "measure": "2 Lbs"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "Boiled"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "Combine garlic, chile pepper, cumin, paprika, black pepper, cayenne, and salt in a mortar; grind with a pestle until it forms a paste. Add olive oil and mix dersa well.\r\n\r\nHeat a large saucepan over medium heat and stir-fry dersa until fragrant, 2 to 4 minutes. Add potato halves and stir to combine with the dersa. Stir in tomato paste. Pour in enough water to just cover the potatoes and bring to a boil. Reduce heat and simmer until potatoes are tender, about 40 minutes.\r\n\r\nLadle potatoes into a serving bowl. Spoon any remaining sauce over the potatoes.", "equipment_tags": [], "portions": 2, "prep_minutes": 44, "prep_minutes_source": "explicit", "kcal": 520, "protein_g": 11.3, "carbs_g": 86.7, "fat_g": 15.6, "total_kcal": 1040, "total_protein_g": 22.7, "total_carbs_g": 173.5, "total_fat_g": 31.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=kpsZQTVVjdk"}, {"id": "53284", "name": "Algerian Bouzgene Berber Bread with Roasted Pepper Sauce", "category": "Side", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/se5vhk1764114880.jpg", "local_image": "53284.jpg", "ingredients": [{"ingredient": "Red Pepper", "measure": "2"}, {"ingredient": "Tomato", "measure": "4"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Jalapeno", "measure": "1 chopped"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Semolina", "measure": "2 Lbs"}, {"ingredient": "Salt", "measure": "1 1/2 tsp"}, {"ingredient": "Water", "measure": "3 Cups"}, {"ingredient": "Olive Oil", "measure": "4 tablespoons"}, {"ingredient": "Olive Oil", "measure": "6 tablespoons"}], "instructions": "Preheat your oven's broiler. Place red bell peppers and tomatoes on a baking sheet, and roast under the broiler for about 8 minutes, turning occasionally. This should blacken the skin and help it peel off more easily. Cool, then scrape the skins off of the tomatoes and peppers, and place them in a large bowl. Remove cores and seeds from the bell peppers.\r\n\r\nHeat 1 tablespoon of olive oil in a skillet over medium heat. Add the jalapenos and garlic, and cook until tender, stirring frequently. Remove from heat, and transfer the garlic and jalapeno to the bowl with the tomatoes and red peppers. Using two sharp steak knives (one in each hand), cut up the tomatoes and peppers to a coarse and soupy consistency. Stir, and set sauce aside.\r\n\r\nPlace the semolina in a large bowl, and stir in salt and 4 tablespoons of olive oil. Gradually add water while mixing and squeezing with your hand until the dough holds together without being sticky or dry, and molds easily with the hand. Divide into 6 pieces and form into balls.\r\n\r\nFor each round, heat 1 tablespoon of olive oil in a large heavy skillet over medium heat. Roll out dough one round at a time, to no thicker than 1/4 inch. Fry in the hot skillet until dark brown spots appear on the surface, and they are crispy. Remove from the skillet, and wrap in a clean towel while preparing the remaining flat breads.\r\n\r\nTo eat the bread and sauce, break off pieces of the bread, and scoop them into the sauce. It will slide off, but just keep reaching in!", "equipment_tags": [], "portions": 12, "prep_minutes": 8, "prep_minutes_source": "explicit", "kcal": 393, "protein_g": 10.0, "carbs_g": 56.9, "fat_g": 13.6, "total_kcal": 4713, "total_protein_g": 120.0, "total_carbs_g": 683.3, "total_fat_g": 162.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53285", "name": "Dziriat (Algerian Almond Tarts)", "category": "Dessert", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ne5wzp1764115568.jpg", "local_image": "53285.jpg", "ingredients": [{"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Lemon Juice", "measure": "1 tsp"}, {"ingredient": "Orange Blossom Water", "measure": "2 tablespoons"}, {"ingredient": "All purpose flour", "measure": "2 cups"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Lemon Juice", "measure": "1/2 teaspoon"}, {"ingredient": "Salt", "measure": "1 pinch"}, {"ingredient": "Orange Blossom Water", "measure": "1 tablespoon"}, {"ingredient": "Almonds", "measure": "4 cups"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Baking Powder", "measure": "1/2 teaspoon"}, {"ingredient": "Vanilla", "measure": "1 tsp"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Orange Blossom Water", "measure": "2 tablespoons"}, {"ingredient": "Cornstarch", "measure": "Sprinkling"}, {"ingredient": "Pine Nuts", "measure": "To serve"}], "instructions": "Prepare the almonds the day before. Bring 6 cups of water to a boil. Remove from heat, and add the almonds. Let the almonds soak in water for about 5 minutes, then drain and peel. Spread the almonds on baking sheets, and bake at 200 degrees F(95 degrees C) until completely dry and toasted. This takes several hours, and needs to be prepared ahead. Be careful not to burn the nuts, as this will give a bitter taste to the filling.\r\n\r\nCombine 1 cup sugar and 1 cup water in a saucepan, and bring to a boil. Add 1 teaspoon lemon juice, reduce heat to low, and let it simmer until syrupy, about 30 to 40 minutes. Stir in orange blossom water, and remove from heat. Set sugar syrup aside.\r\n\r\nCombine flour and salt in a large mixing bowl. Make a hole in the center, and pour oil, egg, 1/2 teaspoon lemon juice, and 1 tablespoon orange blossom water into the center. Mix with fingers until the dough resembles coarse crumbs. Gradually sprinkle with warm water while mixing until the dough becomes soft and pliable. Divide into 4 equal portions. Cover dough with a wet cloth, and set aside.\r\n\r\nIn a food processor, finely grind the almonds. Measure 3 cups of the finely ground almonds into a mixing bowl, and stir together with 1 cup sugar, baking powder, vanilla powder, lemon zest, and 2 tablespoons orange flower water. Mix in three eggs one at a time, stirring constantly; mix until you get a sticky, paste-like mixture.\r\n\r\nSprinkle cornstarch on the rolling surface to prevent sticking. Roll each portion of dough very thinly, 1 to 2 millimeters (1/16 inch). Cut the rolled dough into circles of about 10 centimeters (4 inches) in diameter each. Lightly wipe the surface of each circle with cornstarch, and fit into a tart mold, cornstarch side down to prevent sticking. Gently press the dough onto the sides and bottom of the mold, and trim extra dough from around the rim. Fill three quarters of each mold with the almond filling.\r\n\r\nBake on the top shelf at 350 degrees F (175 degrees C) for 20 to 25 minutes, or until the surface of the tart is golden and the dough is firm. Remove the tarts from the molds as soon as they come out of the oven. Dip each tart in the sugar syrup while still hot. Stick a pine nut into the middle of each tart for decoration. Place on a wire rack to drain.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 70, "prep_minutes_source": "explicit", "kcal": 748, "protein_g": 21.5, "carbs_g": 71.6, "fat_g": 45.9, "total_kcal": 8971, "total_protein_g": 258.4, "total_carbs_g": 859.6, "total_fat_g": 550.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the almonds (day ahead)","instruction":"Boil water, add the almonds, soak, then drain, peel and spread on baking sheets. Bake at low heat until completely dry and toasted.","timer_seconds":10800,"background":true},{"step":2,"label":"Make the sugar syrup","instruction":"Bring sugar and water to a boil, add lemon juice, and simmer until syrupy, then stir in orange blossom water and set aside.","timer_seconds":2100,"background":true},{"step":3,"label":"Make the pastry dough","instruction":"Combine flour and salt, add oil, egg, lemon juice and orange blossom water in the centre, and mix into coarse crumbs, gradually adding warm water until soft and pliable. Divide into 4 portions and cover.","timer_seconds":null,"background":false},{"step":4,"label":"Make the almond filling","instruction":"Grind the toasted almonds, mix with sugar, baking powder, vanilla, lemon zest and orange blossom water, then mix in the eggs one at a time until a sticky paste forms.","timer_seconds":null,"background":false},{"step":5,"label":"Line the moulds","instruction":"Roll each dough portion very thinly, cut into circles, fit into tart moulds using cornstarch to prevent sticking, and trim the edges.","timer_seconds":null,"background":false},{"step":6,"label":"Fill and bake","instruction":"Fill three-quarters of each mould with the almond filling, then bake on the top shelf until golden and firm.","timer_seconds":1350,"background":true},{"step":7,"label":"Glaze and serve","instruction":"Remove from moulds while hot and dip each tart in the sugar syrup, then decorate with a pine nut and drain on a wire rack.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=koPyA-HO8Q4"}, {"id": "53286", "name": "Khobz el Dar (Algerian Semolina Bread)", "category": "Side", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5u37fy1764116774.jpg", "local_image": "53286.jpg", "ingredients": [{"ingredient": "Semolina Flour", "measure": "1/2 cup"}, {"ingredient": "Semolina Flour", "measure": "2 tablespoons"}, {"ingredient": "Sesame Seed", "measure": "3  tablespoons"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Yeast", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "3/4 teaspoon"}, {"ingredient": "Vegetable Oil", "measure": "1/4 cup"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "All purpose flour", "measure": "3 Cups"}, {"ingredient": "All purpose flour", "measure": "2 tablespoons"}, {"ingredient": "Water", "measure": "1 tsp"}], "instructions": "Mix 1/2 cup plus 2 tablespoons semolina, 2 tablespoons sesame seeds, sugar, yeast, and salt together in a large bowl. Whisk in oil, egg, and egg white. Stir in warm milk slowly until a liquid dough forms.\r\n\r\nCover the bowl with a plate or plastic wrap; let stand at room temperature until frothy, about 1 hour.\r\n\r\nStir in 2 3/4 cups flour with a wooden spoon until a sticky dough forms. Cover again and allow to rest for 30 minutes.\r\n\r\nLine a baking sheet with parchment paper or a baking mat.\r\n\r\nSprinkle 1 tablespoon flour over the dough and your hands. Mix dough, adding flour as needed, 1 tablespoon at a time, until it pulls away from the sides of the bowl. Shape into a round loaf and place on the prepared baking sheet. Cover loosely with a towel and let rise for 1 hour in a warm place until loaf doubles in volume.\r\n\r\nPreheat oven to 400 degrees F (200 degrees C).\r\n\r\nBeat egg yolk and water in a bowl with a fork; brush over the entire surface of the loaf. Sprinkle 1 tablespoon sesame seeds on top.\r\n\r\nBake in the preheated oven until loaf is golden brown, about 20 to 25 minutes.", "equipment_tags": [], "portions": 9, "prep_minutes": 175, "prep_minutes_source": "explicit", "kcal": 315, "protein_g": 9.0, "carbs_g": 44.2, "fat_g": 11.2, "total_kcal": 2834, "total_protein_g": 80.6, "total_carbs_g": 397.7, "total_fat_g": 100.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the leaven and dough","instruction":"Mix semolina, sesame seeds, sugar, yeast and salt, whisk in oil, egg and egg white, then stir in warm milk to form a liquid dough.","timer_seconds":null,"background":false},{"step":2,"label":"First rest","instruction":"Cover and let stand at room temperature until frothy.","timer_seconds":3600,"background":true},{"step":3,"label":"Add flour and rest again","instruction":"Stir in flour to form a sticky dough, cover, and rest.","timer_seconds":1800,"background":true},{"step":4,"label":"Shape and rise","instruction":"Knead in more flour until it pulls away from the bowl, shape into a round loaf, place on a lined tray, cover, and let rise until doubled.","timer_seconds":3600,"background":true},{"step":5,"label":"Glaze and bake","instruction":"Preheat the oven to 200°C/400°F. Brush the loaf with egg yolk wash and sprinkle with sesame seeds, then bake until golden brown.","timer_seconds":1350,"background":true}], "video": "https://www.youtube.com/watch?v=-BzhiwgfAOQ"}, {"id": "53287", "name": "Tajine de Poulet aux Carottes et Patates Douces (Chicken and Sweet Potato Tagine)", "category": "Chicken", "area": "Algerian", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/d8bfyg1764117503.jpg", "local_image": "53287.jpg", "ingredients": [{"ingredient": "Onion", "measure": "2 sliced"}, {"ingredient": "Celery", "measure": "2 sliced"}, {"ingredient": "Cilantro", "measure": "1/2 bag"}, {"ingredient": "Parsley", "measure": "1/2 bag"}, {"ingredient": "Turmeric", "measure": "1/2 tsp"}, {"ingredient": "Ground Cumin", "measure": "1/2 tsp"}, {"ingredient": "Paprika", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Ginger", "measure": "1/4 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1/4 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Black Pepper", "measure": "To taste"}, {"ingredient": "Chicken Thighs", "measure": "4"}, {"ingredient": "Olive Oil", "measure": "Drizzle"}, {"ingredient": "Raisins", "measure": "1/4 cup"}, {"ingredient": "Chicken Stock", "measure": "1 cup"}, {"ingredient": "Sweet Potatoes", "measure": "1 large"}, {"ingredient": "Carrots", "measure": "3 sliced thinly"}, {"ingredient": "Prunes", "measure": "1/4 cup"}], "instructions": "Combine onions, celery, cilantro, and parsley in a large pot. Stir in turmeric, cumin, paprika, ginger, cayenne pepper, salt, and pepper. Place chicken thighs on top. Drizzle olive oil over chicken. Cover and simmer over low heat until chicken is tender, about 40 minutes.\r\n\r\nPlace raisins in a small bowl and cover with hot water; let soak for 10 minutes. Drain.\r\n\r\nPreheat oven to 400 degrees F (200 degrees C).\r\n\r\nTransfer chicken mixture into an oven-safe tagine or casserole dish. Add sweet potato and carrots. Cover with lid or aluminum foil.\r\n\r\nBake in the preheated oven until sweet potato is soft, about 40 minutes. Add drained raisins and prunes. Continue baking, covered, until raisins and prunes are heated through, about 10 minutes.", "equipment_tags": [], "portions": 3, "prep_minutes": 100, "prep_minutes_source": "explicit", "kcal": 399, "protein_g": 17.8, "carbs_g": 56.5, "fat_g": 13.3, "total_kcal": 1198, "total_protein_g": 53.3, "total_carbs_g": 169.4, "total_fat_g": 39.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Build and simmer the base","instruction":"Combine onions, celery, cilantro and parsley in a large pot with the spices, top with chicken, drizzle with oil, cover, and simmer over low heat until the chicken is tender.","timer_seconds":2400,"background":true},{"step":2,"label":"Soak the raisins","instruction":"Cover the raisins with hot water and soak, then drain.","timer_seconds":600,"background":true},{"step":3,"label":"Transfer and bake","instruction":"Preheat the oven to 200°C/400°F. Transfer the chicken mixture to an oven-safe dish, add sweet potato and carrots, cover, and bake until the sweet potato is soft.","timer_seconds":2400,"background":true},{"step":4,"label":"Finish","instruction":"Add the drained raisins and prunes and continue baking, covered, until heated through.","timer_seconds":600,"background":true}], "video": "https://www.youtube.com/watch?v=thf-JDXoTVg"}, {"id": "53288", "name": "Algerian Flafla (Bell Pepper Salad)", "category": "Vegetarian", "area": "Algerian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/tbj1bs1764118062.jpg", "local_image": "53288.jpg", "ingredients": [{"ingredient": "Green Pepper", "measure": "3"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Red Onions", "measure": "1 tablespoon chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Plum Tomatoes", "measure": "1 Diced"}], "instructions": "Preheat an oven to 450 degrees F (230 degrees C). Place the whole peppers on aluminum foil. Bake until the skin is spotted black and the peppers are soft, 30 to 45 minutes, turning the peppers once if necessary.\r\n\r\nRemove peppers from the oven and set aside to cool for 10 minutes. Peel off the skin and remove the stem and seeds. Chop the roasted peppers into half-inch pieces.\r\n\r\nHeat the olive oil in a skillet over medium heat. Stir in the onion and cook, stirring frequently, until the onion has softened and turned translucent, about 5 minutes. Add the garlic, salt, and pepper; stir in the chopped peppers and tomato. Cook over medium heat, stirring occasionally, until the tomato is soft and the mixture is well incorporated, about 5 minutes.", "equipment_tags": [], "portions": 1, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 153, "protein_g": 1.4, "carbs_g": 7.0, "fat_g": 14.1, "total_kcal": 153, "total_protein_g": 1.4, "total_carbs_g": 7.0, "total_fat_g": 14.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Roast the peppers","instruction":"Preheat the oven to 230°C/450°F. Place the whole peppers on foil and bake, turning once if needed, until the skin is spotted black and soft.","timer_seconds":2250,"background":true},{"step":2,"label":"Peel and chop","instruction":"Cool the peppers, peel off the skin, remove stem and seeds, and chop into pieces.","timer_seconds":600,"background":true},{"step":3,"label":"Cook the onion","instruction":"Heat oil in a skillet and cook the onion, stirring, until softened and translucent.","timer_seconds":300,"background":false},{"step":4,"label":"Finish","instruction":"Add garlic, salt, pepper, chopped peppers and tomato, and cook, stirring occasionally, until the tomato is soft and everything combined.","timer_seconds":300,"background":false}], "video": "https://www.youtube.com/watch?v=JXrS1doDnNg"}, {"id": "53289", "name": "Chorba Hamra bel Frik (Algerian Lamb, Tomato, and Freekeh Soup)", "category": "Lamb", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/p9tebp1764118792.jpg", "local_image": "53289.jpg", "ingredients": [{"ingredient": "Freekeh", "measure": "1 cup"}, {"ingredient": "Lamb", "measure": "12 ounces"}, {"ingredient": "Onion", "measure": "1 finely chopped"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Vegetable Oil", "measure": "3  tablespoons"}, {"ingredient": "Cilantro", "measure": "1  bunch"}, {"ingredient": "Mint", "measure": "1  bunch"}, {"ingredient": "Celery", "measure": "1"}, {"ingredient": "Chickpeas", "measure": "14 oz jar"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Zucchini", "measure": "1 Diced"}, {"ingredient": "Carrots", "measure": "1 Diced"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Tomato", "measure": "3 Medium"}, {"ingredient": "Potatoes", "measure": "1 Diced"}], "instructions": "Place freekeh in a small bowl and cover with cold water. Set aside.\r\n\r\nCombine lamb, onion, black pepper, paprika, cinnamon, and salt in a pot. Stir in oil, 1/2 the cilantro, 1/2 the mint, and celery stalk until combined. Simmer over low heat for 15 minutes. Stir in chickpeas; pour in just enough water to cover, and return to a simmer. Stir in zucchini, carrot, and tomato paste.\r\n\r\nSet a steamer over the pot; add tomatoes. Cover and steam tomatoes until soft, about 5 minutes. Crush tomatoes using a wooden spoon, so pulp drips into soup. Remove the steamer and discard leftover tomato peels.\r\n\r\nAdd potato to soup and just enough water to cover. Simmer until potato is soft, about 10 minutes.\r\n\r\nDrain freekeh and add to soup. Simmer until soft, about 15 minutes. Remove celery stalk and discard. Sprinkle soup with remaining 1/2 cilantro and remaining 1/2 mint before serving.", "equipment_tags": [], "portions": 6, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 453, "protein_g": 24.2, "carbs_g": 36.8, "fat_g": 24.2, "total_kcal": 2718, "total_protein_g": 145.0, "total_carbs_g": 221.1, "total_fat_g": 144.9, "macro_confidence": 0.94, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the freekeh","instruction":"Cover the freekeh with cold water and set aside.","timer_seconds":null,"background":true},{"step":2,"label":"Start the soup","instruction":"Combine lamb, onion, black pepper, paprika, cinnamon and salt in a pot, stir in oil, half the cilantro, half the mint and celery, and simmer over low heat.","timer_seconds":900,"background":true},{"step":3,"label":"Add chickpeas and vegetables","instruction":"Stir in chickpeas with water to cover, return to a simmer, then stir in zucchini, carrot and tomato paste.","timer_seconds":null,"background":false},{"step":4,"label":"Steam the tomatoes","instruction":"Set a steamer over the pot, add tomatoes, cover, and steam until soft, then crush into the soup and discard the peels.","timer_seconds":300,"background":false},{"step":5,"label":"Add the potato","instruction":"Add potato and enough water to cover, and simmer until the potato is soft.","timer_seconds":600,"background":true},{"step":6,"label":"Add the freekeh and serve","instruction":"Drain the freekeh and add to the soup, simmer until soft, remove the celery stalk, then sprinkle with remaining cilantro and mint before serving.","timer_seconds":900,"background":true}], "video": "https://www.youtube.com/watch?v=2z6IldJl_lQ"}, {"id": "53290", "name": "Cheese Borek", "category": "Side", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/oal8x31764119345.jpg", "local_image": "53290.jpg", "ingredients": [{"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Parsley", "measure": "1  bunch"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Red Pepper", "measure": "3/4 teaspoon"}, {"ingredient": "Gouda Cheese", "measure": "6 oz"}, {"ingredient": "Emmentaler Cheese", "measure": "6 oz"}, {"ingredient": "Phyllo Dough", "measure": "12"}, {"ingredient": "Unsalted Butter", "measure": "1 1/2 cups"}], "instructions": "In a medium bowl, whisk together egg, parsley, garlic and crushed red pepper. Mix in Gouda and Emmentaler.\r\n\r\nOne sheet at a time, place phyllo dough on a flat surface and brush with about 1 tablespoon butter. Cut lengthwise into 4 strips. Place a rounded teaspoon of the egg mixture at one end of each strip. Fold corner of strip over the filling, forming a triangular fold. Continue folding the length of the strip in triangular folds to form a small stuffed triangle. Repeat with remaining phyllo dough.\r\n\r\nPreheat oven to 350 degrees F (175 degrees C). Lightly butter a large baking sheet.\r\n\r\nArrange stuffed phyllo triangles in a single layer on the prepared baking sheet. Bake in the preheated oven 30 minutes, or until lightly browned. Serve warm", "equipment_tags": [], "portions": 8, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 583, "protein_g": 15.3, "carbs_g": 12.7, "fat_g": 53.6, "total_kcal": 4661, "total_protein_g": 122.6, "total_carbs_g": 101.8, "total_fat_g": 428.5, "macro_confidence": 0.88, "is_new": false, "cook_steps": [{"step":1,"label":"Make the filling","instruction":"Whisk together egg, parsley, garlic and crushed red pepper, then mix in the Gouda and Emmentaler.","timer_seconds":null,"background":false},{"step":2,"label":"Assemble the triangles","instruction":"Brush a phyllo sheet with butter, cut into 4 strips, place filling at one end of each strip, and fold in triangles to form small stuffed triangles. Repeat with remaining phyllo.","timer_seconds":null,"background":false},{"step":3,"label":"Bake","instruction":"Preheat the oven to 175°C/350°F. Arrange the triangles on a buttered baking sheet and bake until lightly browned.","timer_seconds":1800,"background":true},{"step":4,"label":"Serve","instruction":"Serve warm.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=UphcO5hC9rU"}, {"id": "53291", "name": "Cornes de Gazelle (Gazelle Horns)", "category": "Dessert", "area": "Algerian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0h1b7m1764120235.jpg", "local_image": "53291.jpg", "ingredients": [{"ingredient": "Almonds", "measure": "2 cups"}, {"ingredient": "Sugar", "measure": "3/4 cup"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Ground Cinnamon", "measure": "1/4 tsp"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Orange Blossom Water", "measure": "1 tablespoon"}, {"ingredient": "All purpose flour", "measure": "2 cups"}, {"ingredient": "Unsalted Butter", "measure": "1/2 cup"}, {"ingredient": "Salt", "measure": "1 pinch"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Vegetable Oil", "measure": "3  tablespoons"}, {"ingredient": "Orange Blossom Water", "measure": "1 ½ tbsp"}, {"ingredient": "Pistachio", "measure": "3  tablespoons"}], "instructions": "Preheat oven to 300 degrees F (150 degrees C). Line a baking sheet with parchment paper. Spread almonds over the baking sheet.\r\n\r\nBake in the preheated oven until almonds are fragrant and roasted, 20 to 25 minutes.\r\n\r\nPrepare pastry dough while almonds are roasting. Combine flour, 1/2 cup plus 1 tablespoon butter, and salt in a bowl and rub together until the mixture resembles breadcrumbs. Add egg, oil, and 1 1/2 tablespoons orange blossom water; knead everything into a smooth pastry dough. Add a little water, 1 teaspoon at a time, if dough is too dry. Shape pastry dough into a ball, wrap in plastic wrap, and set aside for 30 minutes.\r\n\r\nRemove almonds from oven and cool slightly, about 5 minutes. Place almonds in the bowl of a food processor; process until finely and evenly ground. Add 3/4 cup plus 1 tablespoon sugar, cinnamon, egg, and 1 tablespoon orange blossom water in that order to the food processor, pulsing after each addition until mixture is evenly combined and resembles a paste.\r\n\r\nRemove small walnut-sized portions of filling with greased hands. Roll them into small logs with thin ends. Set aside.\r\n\r\nPreheat oven to 325 degrees F (165 degrees C). Line a baking sheet with parchment paper.\r\n\r\nRoll out half of the pastry dough on a lightly floured surface until very thin. Place one of the almond paste logs on the edge of the pastry, fold pastry over the filling, covering it completely, and seal the edges. Mold with your fingers into a crescent shape. Using a pastry cutter, cut around the crescent, and transfer to the prepared baking sheet. Repeat with remaining dough and filling.\r\n\r\nBake in the preheated oven until gazelle horns are lightly golden and baked through, about 20 minutes. They should not get too dark. Let cool slightly, about 3 minutes.\r\n\r\nHeat honey in a small saucepan over low-medium heat. Remove from heat and stir in 1 tablespoon orange blossom water. Dip gazelle horns into the honey and place on a serving plate. Sprinkle with crushed pistachios.", "equipment_tags": ["FoodProcessor"], "portions": 9, "prep_minutes": 83, "prep_minutes_source": "explicit", "kcal": 667, "protein_g": 16.7, "carbs_g": 55.2, "fat_g": 45.3, "total_kcal": 6005, "total_protein_g": 150.6, "total_carbs_g": 496.9, "total_fat_g": 407.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Roast the almonds","instruction":"Preheat the oven to 150°C/300°F, spread almonds on a lined baking sheet, and bake until fragrant and roasted.","timer_seconds":1350,"background":true},{"step":2,"label":"Make the pastry","instruction":"While the almonds roast, rub the flour, butter and salt together to breadcrumbs, add egg, oil and orange blossom water, and knead into a smooth dough.","timer_seconds":null,"background":false},{"step":3,"label":"Rest the dough","instruction":"Shape into a ball, wrap, and set aside.","timer_seconds":1800,"background":true},{"step":4,"label":"Make the almond filling","instruction":"Cool the almonds slightly, grind finely in a food processor, then add sugar, cinnamon, egg and orange blossom water, pulsing until it forms a paste.","timer_seconds":null,"background":false},{"step":5,"label":"Shape the filling","instruction":"Roll walnut-sized portions of filling into small logs with thin ends.","timer_seconds":null,"background":false},{"step":6,"label":"Wrap and shape the horns","instruction":"Preheat the oven to 165°C/325°F. Roll out half the pastry thinly, wrap a filling log inside, seal, and mould into a crescent shape. Cut around it and transfer to a lined tray. Repeat with remaining dough and filling.","timer_seconds":null,"background":false},{"step":7,"label":"Bake","instruction":"Bake until lightly golden, watching so they don't get too dark.","timer_seconds":1200,"background":true},{"step":8,"label":"Glaze and serve","instruction":"Cool slightly, heat honey with orange blossom water, dip each horn in the honey, and sprinkle with crushed pistachios.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=KVnfEBh-rUk"}, {"id": "53292", "name": "Piernik (Polish gingerbread)", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/kwmdk41764120884.jpg", "local_image": "53292.jpg", "ingredients": [{"ingredient": "Unsalted Butter", "measure": "140g"}, {"ingredient": "Clear Honey", "measure": "300g"}, {"ingredient": "Brown Sugar", "measure": "100g"}, {"ingredient": "Self-raising Flour", "measure": "375g"}, {"ingredient": "Ground Ginger", "measure": "3 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "1 tsp"}, {"ingredient": "Ground Clove", "measure": "1/2 teaspoon"}, {"ingredient": "Ground Nutmeg", "measure": "1/4 tsp"}, {"ingredient": "Pepper", "measure": "1/4 tsp"}, {"ingredient": "Egg", "measure": "3 Large"}, {"ingredient": "Plum Jam", "measure": "200g"}, {"ingredient": "Double Cream", "measure": "225ml"}, {"ingredient": "Dark Chocolate", "measure": "140g"}, {"ingredient": "Clear Honey", "measure": "3  tablespoons"}], "instructions": "Heat oven to 160C/140C fan/gas 3. Grease and line the base and sides of a deep 20cm cake tin with baking parchment. Put the honey, sugar and butter in a medium saucepan and cook over a medium heat until fully melted. Remove from the heat and allow to cool. Put the flour and spices in a large bowl and mix everything together.\r\n\r\nstep 2\r\nOnce the liquid ingredients have cooled, whisk in the eggs. Pour over the dry ingredients, whisking them together to form a smooth batter – be careful not to overmix as this can lead to a dry cake. Pour into the prepared tin and bake for 50-55 mins or until risen and a skewer inserted into the middle of the cake comes out clean. Allow the cake to cool in the pan for 20 mins before turning out onto a wire rack to cool completely.\r\n\r\nstep 3\r\nOnce cooled, use a large serrated knife to slice the cake into 3 layers. Spread the jam across the 2 bottom cake layers, then reassemble the cake and set aside while you make the glaze. Put the cream, chocolate and honey in a medium pan and cook over a low-medium heat until the chocolate is melted and you have a smooth, pourable mixture. Put the cake on a wire rack set over a parchment-lined baking tray and pour over the glaze, making sure to cover the entire cake. Use a fish slice to carefully transfer the cake to a serving plate and allow the glaze to set. To decorate, dust with a little edible gold powder, if you like. Uniced, this cake will keep for up to 5 days. Once iced, enjoy within 3 days – just keep in the fridge, but remove before serving and eat at room temperature.", "equipment_tags": [], "portions": 12, "prep_minutes": 75, "prep_minutes_source": "explicit", "kcal": 529, "protein_g": 6.4, "carbs_g": 77.8, "fat_g": 23.8, "total_kcal": 6352, "total_protein_g": 77.4, "total_carbs_g": 934.2, "total_fat_g": 285.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Melt the wet ingredients","instruction":"Heat the oven to 160°C/140°C fan/gas 3 and line a deep cake tin. Melt honey, sugar and butter together in a saucepan, then cool. Mix flour and spices in a large bowl.","timer_seconds":null,"background":false},{"step":2,"label":"Make the batter and bake","instruction":"Whisk eggs into the cooled liquid, pour over the dry ingredients, and whisk into a smooth batter without overmixing. Pour into the tin and bake until risen and a skewer comes out clean.","timer_seconds":3150,"background":true},{"step":3,"label":"Cool","instruction":"Cool in the pan, then turn out onto a wire rack to cool completely.","timer_seconds":1200,"background":true},{"step":4,"label":"Layer with jam","instruction":"Slice the cake into 3 layers, spread jam across the two bottom layers, then reassemble.","timer_seconds":null,"background":false},{"step":5,"label":"Make the glaze and finish","instruction":"Cook cream, chocolate and honey over low-medium heat until smooth, then pour over the cake set on a rack, and allow the glaze to set before serving.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=SGkMAlrTu6g"}, {"id": "53293", "name": "Pistachio cake", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xvgpng1764121726.jpg", "local_image": "53293.jpg", "ingredients": [{"ingredient": "Butter", "measure": "250g"}, {"ingredient": "Pistachio", "measure": "200g"}, {"ingredient": "Plain Flour", "measure": "80g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Caster Sugar", "measure": "225g"}, {"ingredient": "Egg", "measure": "4"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Icing Sugar", "measure": "100g"}, {"ingredient": "Mascarpone", "measure": "250g"}, {"ingredient": "Double Cream", "measure": "200ml"}, {"ingredient": "Pistachio Paste", "measure": "100g"}, {"ingredient": "Raspberries", "measure": "400g"}, {"ingredient": "Unwaxed Lime", "measure": "1"}], "instructions": "Heat the oven to 180C/160C fan/gas 4. Butter and line a 23cm springform cake tin. Tip 150g of the pistachios into a food processor and blitz until finely ground. Tip into a bowl and mix in the flour, baking powder and pinch of salt. Beat the butter and sugar in a separate bowl until fluffy and pale, around 5 mins. Crack in the eggs one at a time, beating well for 1 min after each addition, until they have all been added. Beat in the vanilla, then fold in the flour mixture gently. Carefully spoon into the prepared tin and bake for 35-40 mins until a skewer inserted into the middle comes out clean. Set aside to cool completely on a wire rack in the tin.\r\n\r\nstep 2\r\nMeanwhile, sift the icing sugar into a bowl, then tip in the mascarpone, double cream and pistachio paste. Beat until well combined, then set aside in the fridge for 20-30 mins to thicken to a spooning consistency.\r\n\r\nstep 3\r\nCut the cooled cake in half horizontally using a serrated knife, so you have two layers. Put the bottom layer on a plate or cake stand and spread over a generous spoonful of the pistachio cream. Top with a generous handful of the raspberries so the cake is covered. Top with the other sponge half, then cover the top and sides of the cake with the remaining cream. Scatter over the last of the raspberries, the remaining pistachios and the lime zest to serve. Will keep chilled in an airtight container for two days.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 76, "prep_minutes_source": "explicit", "kcal": 627, "protein_g": 9.9, "carbs_g": 45.6, "fat_g": 47.3, "total_kcal": 7526, "total_protein_g": 119.4, "total_carbs_g": 547.4, "total_fat_g": 567.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep and mix the batter","instruction":"Heat the oven to 180°C/160°C fan/gas 4 and line a springform tin. Blitz 150g pistachios finely and mix with flour, baking powder and salt. Beat butter and sugar until fluffy, add eggs one at a time, then beat in vanilla and fold in the flour mixture.","timer_seconds":null,"background":false},{"step":2,"label":"Bake","instruction":"Spoon into the tin and bake until a skewer comes out clean.","timer_seconds":2250,"background":true},{"step":3,"label":"Cool","instruction":"Cool completely in the tin on a wire rack.","timer_seconds":null,"background":true},{"step":4,"label":"Make the cream filling","instruction":"Sift icing sugar into a bowl, add mascarpone, cream and pistachio paste, and beat until combined, then chill to thicken.","timer_seconds":1500,"background":true},{"step":5,"label":"Assemble and serve","instruction":"Halve the cooled cake horizontally, spread the bottom layer with pistachio cream, top with raspberries, then the other sponge half. Cover with remaining cream, and scatter with raspberries, pistachios and lime zest.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=ACpikfieDP0"}, {"id": "53294", "name": "Zapiekanki", "category": "Pork", "area": "Polish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/72lmpt1764122511.jpg", "local_image": "53294.jpg", "ingredients": [{"ingredient": "Baguette", "measure": "2"}, {"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Vegetable Oil", "measure": "2 tsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Mushrooms", "measure": "300g"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Mayonnaise", "measure": "1 tablespoon"}, {"ingredient": "Cheddar Cheese", "measure": "50g"}, {"ingredient": "Ham", "measure": "75g"}, {"ingredient": "Polish Kabanos", "measure": "75g"}, {"ingredient": "Mozzarella", "measure": "50g"}, {"ingredient": "Dill", "measure": "2"}, {"ingredient": "Chives", "measure": "1 tablespoon"}, {"ingredient": "Tomato Ketchup", "measure": "Drizzle"}], "instructions": "step 1\r\nHeat the oven to 200C/180C fan/gas 6. Bake the baguettes on a baking tray for 8-10 mins, then leave to cool.\r\n\r\nstep 2\r\nHeat 2 tsp of the butter and 1 tsp of the oil in a pan over a low heat and cook the chopped onion for 5 mins until soft. Stir in the mushrooms, turn the heat to medium and cook for 5-10 mins more until the veg is soft and the mushroom liquid has evaporated. Stir in the garlic and cook for 1-2 mins until soft. Season, then stir in the mayonnaise and remove from the heat.\r\n\r\nstep 3\r\nHalve the baguettes lengthways, then return to the baking tray, cut-side up and spread over the mushroom mixture, then sprinkle over the cheddar, ham, kabanos and mozzarella. Bake for 8-10 mins, or until the cheese has melted and turned golden.\r\n\r\nstep 4\r\nMeanwhile, heat the remaining butter and oil in a pan over a medium heat and fry the sliced onions for 5 mins until golden and soft. Remove from the heat and set aside. Once the pizzas are cooked, top with the caramelised onions, dill pickles (if using), the chives and a zig-zag drizzle of ketchup.", "equipment_tags": [], "portions": 2, "prep_minutes": 42, "prep_minutes_source": "explicit", "kcal": 643, "protein_g": 35.1, "carbs_g": 48.9, "fat_g": 36.0, "total_kcal": 1286, "total_protein_g": 70.2, "total_carbs_g": 97.8, "total_fat_g": 71.9, "macro_confidence": 0.93, "is_new": false, "cook_steps": [{"step":1,"label":"Toast the baguettes","instruction":"Heat the oven to 200°C/180°C fan/gas 6, bake the baguettes, then leave to cool.","timer_seconds":540,"background":true},{"step":2,"label":"Cook the mushroom filling","instruction":"Heat butter and oil, cook the onion until soft, add mushrooms and cook until soft and evaporated, then add garlic and cook briefly. Season and stir in mayonnaise.","timer_seconds":900,"background":false},{"step":3,"label":"Top and bake","instruction":"Halve the baguettes, spread with the mushroom mixture, sprinkle with cheddar, ham, kabanos and mozzarella, and bake until melted and golden.","timer_seconds":540,"background":true},{"step":4,"label":"Caramelise the onions and finish","instruction":"Fry sliced onions in the remaining butter and oil until golden and soft, then top the finished pizzas with the onions, pickles, chives and a drizzle of ketchup.","timer_seconds":300,"background":false}], "video": "https://www.youtube.com/watch?v=uely-neGHLM"}, {"id": "53295", "name": "Polish chocolate & walnut cake", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/e8ihjp1764123021.jpg", "local_image": "53295.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "150g"}, {"ingredient": "Coco Sugar", "measure": "50g"}, {"ingredient": "Egg", "measure": "8"}, {"ingredient": "Caster Sugar", "measure": "200g"}, {"ingredient": "Egg White", "measure": "5"}, {"ingredient": "Caster Sugar", "measure": "200g"}, {"ingredient": "Walnuts", "measure": "250g"}, {"ingredient": "Plain Flour", "measure": "1 tablespoon"}, {"ingredient": "Potato Starch", "measure": "1 tablespoon"}, {"ingredient": "Double Cream", "measure": "100g"}, {"ingredient": "Chocolate Chips", "measure": "100g"}], "instructions": "Heat the oven to 170C/150C fan/gas 3½. Line a 30 x 22cm shallow baking tin with baking parchment. Sift the flour and mix it with cocoa, then set aside. Beat the egg whites until stiff, then add the sugar to them in small batches. Add the egg yolks, one by one, whisking constantly. Tip in the flour mixture and gently fold everything together with a spatula. Pour the prepared batter into the lined tin and bake for 35 mins. Cool for 5 mins, remove from the tin and re-line the tin with baking parchment.\r\n\r\nstep 2\r\nTo make the meringue, whisk the whites until stiff, then gradually whisk in the sugar, one tablespoon at a time. When you have a stiff and shiny meringue, fold in the finely chopped walnuts, flour and startch. Spread the mixture into the re-lined tin and cook for 40 mins on the same heat. Remove from the oven and leave to cool.\r\n\r\nstep 3\r\nFor the chocolate glaze, heat the cream over low heat, then remove from the heat, pour the chopped chocolate into it and mix it until it melts and becomes shiny.\r\n\r\nstep 4\r\nCut the cooled chocolate sponge cake and meringue into two layers. Put the nut meringue on top of the bottom layer of sponge and sprinkle on some of the reserved walnuts. Add another layer of meringue and then the upper layer of chocolate sponge cake and cover the top with chocolate glaze. Decorate with walnuts. Put the finished cake in the fridge for 1-2 hrs before serving.", "equipment_tags": [], "portions": 11, "prep_minutes": 200, "prep_minutes_source": "explicit", "kcal": 509, "protein_g": 12.8, "carbs_g": 61.5, "fat_g": 25.4, "total_kcal": 5594, "total_protein_g": 140.4, "total_carbs_g": 676.4, "total_fat_g": 279.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the sponge batter","instruction":"Heat the oven to 170°C/150°C fan/gas 3½ and line a tin. Sift flour with cocoa. Whisk egg whites to stiff peaks, add sugar gradually, then whisk in the egg yolks. Fold in the flour mixture.","timer_seconds":null,"background":false},{"step":2,"label":"Bake the sponge","instruction":"Pour into the tin and bake, then cool and re-line the tin.","timer_seconds":2100,"background":true},{"step":3,"label":"Make and bake the meringue","instruction":"Whisk egg whites to stiff peaks, gradually whisk in sugar, then fold in chopped walnuts, flour and starch. Spread in the tin and bake on the same heat, then cool.","timer_seconds":2400,"background":true},{"step":4,"label":"Make the glaze","instruction":"Heat the cream, remove from heat, add chopped chocolate, and stir until melted and shiny.","timer_seconds":null,"background":false},{"step":5,"label":"Assemble and chill","instruction":"Cut the sponge and meringue into two layers each, layer with walnuts between, cover with chocolate glaze, decorate with walnuts, and chill.","timer_seconds":5400,"background":true}], "video": null}, {"id": "53296", "name": "Sauerkraut pierogi", "category": "Vegetarian", "area": "Polish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ckbx1h1764123606.jpg", "local_image": "53296.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "1 tablespoon"}, {"ingredient": "Shallots", "measure": "2"}, {"ingredient": "Sauerkraut", "measure": "150g"}, {"ingredient": "Hispi (sweetheart) Cabbage", "measure": "150g"}, {"ingredient": "Egg", "measure": "1 large"}, {"ingredient": "Vegetable Oil", "measure": "1/2 tbs"}, {"ingredient": "Plain Flour", "measure": "350g"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Shallots", "measure": "2"}, {"ingredient": "Plain Flour", "measure": "Dusting"}, {"ingredient": "Butter", "measure": "45g"}, {"ingredient": "Sour Cream", "measure": "60 ml"}], "instructions": "step 1\r\nFirst, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour and deep-fry for 1 min or until light golden and crispy. Drain on kitchen paper. Can be made up to two days before and kept in an airtight container.\r\n\r\nstep 2\r\nTo make the filling, heat the oil in a medium non-stick frying pan and gently fry the shallots for 10 mins until starting to turn golden.\r\n\r\nstep 3\r\nAdd the sauerkraut and cabbage, and cook for 5-10 mins until the cabbage has softened. Taste and add a little salt if under-seasoned, or sugar if stringent. Scrape into a bowl and leave to cool completely.\r\n\r\nstep 4\r\nTo make the dough, mix the eggs and oil with 125ml water, then gradually add in the flour, mixing well with your hands. Knead it on a well-floured surface until the dough stops sticking to your hands. You should end up with firm, elastic dough. Wrap it in cling film and rest in the fridge for at least 30 mins, or overnight.\r\n\r\nstep 5\r\nFlour your work surface generously. Roll out the dough to a 40cm circle or until the dough is as thick as £1 coin.\r\n\r\nstep 6\r\nUsing a 9cm cookie cutter, cut out discs in the dough – you should end up with about 25 discs. Do not throw away the off-cuts – we throw them in with the pierogi when boiling to minimise any waste.\r\n\r\nstep 7\r\nHave a well-floured tray ready. Put 1 tsp of the filling into the centre of each disc. In your hand, fold in half around the filling and seal to create half-moon shapes. Put them on the floured tray, making sure they don’t touch each other.\r\n\r\nstep 8\r\nBring a large saucepan of salted water to the boil and carefully lower the pierogi in. Boil them for 2 mins or until they float to the top.\r\n\r\nstep 9\r\nDrain and serve with a knob of butter and some soured cream. Finish by sprinkling the crispy shallots on top to serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 53, "prep_minutes_source": "explicit", "kcal": 1300, "protein_g": 30.5, "carbs_g": 207.4, "fat_g": 37.2, "total_kcal": 3901, "total_protein_g": 91.6, "total_carbs_g": 622.1, "total_fat_g": 111.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Fry the crispy shallots","instruction":"Heat oil to 180°C, toss shallots in flour, and deep-fry until light golden and crispy, then drain.","timer_seconds":60,"background":false},{"step":2,"label":"Cook the filling","instruction":"Heat oil in a pan and gently fry the shallots until starting to turn golden, then add sauerkraut and cabbage and cook until softened.","timer_seconds":900,"background":false},{"step":3,"label":"Cool the filling","instruction":"Scrape into a bowl and leave to cool completely.","timer_seconds":null,"background":true},{"step":4,"label":"Make and rest the dough","instruction":"Mix eggs and oil with water, gradually add flour, and knead until firm and elastic. Wrap and rest in the fridge.","timer_seconds":1800,"background":true},{"step":5,"label":"Roll and cut","instruction":"Roll the dough into a large circle and cut into discs with a cookie cutter.","timer_seconds":null,"background":false},{"step":6,"label":"Fill and seal","instruction":"Put filling in the centre of each disc, fold in half, and seal into half-moon shapes, keeping them on a floured tray without touching.","timer_seconds":null,"background":false},{"step":7,"label":"Boil","instruction":"Boil the pierogi in salted water until they float to the top.","timer_seconds":120,"background":false},{"step":8,"label":"Serve","instruction":"Drain and serve with butter and soured cream, sprinkled with the crispy shallots.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=eVWBJt2jaPU"}, {"id": "53297", "name": "Pomegranate salad", "category": "Vegetarian", "area": "Polish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/fqpqml1764359125.jpg", "local_image": "53297.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "60 ml"}, {"ingredient": "Lemon Juice", "measure": "2 tablespoons"}, {"ingredient": "Honey", "measure": "1 tablespoon"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Baby Lettuce Leaves", "measure": "100g"}, {"ingredient": "Cherry Tomatoes", "measure": "250g"}, {"ingredient": "Spring Onions", "measure": "3 chopped"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Pomegranate", "measure": "1"}, {"ingredient": "Feta", "measure": "50g"}], "instructions": "step 1\r\nCombine the olive oil, lemon juice, honey and thyme leaves in a large bowl. Season well, then tip in the lettuce, tomatoes, spring onions and chilli, and toss to combine.\r\n\r\nstep 2\r\nScoop out the pomegranate seeds over a bowl and remove any white membrane. Arrange the dressed salad on a platter, then scatter over the pomegranate seeds and feta.", "equipment_tags": [], "portions": 7, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 137, "protein_g": 2.9, "carbs_g": 10.2, "fat_g": 10.2, "total_kcal": 956, "total_protein_g": 20.4, "total_carbs_g": 71.3, "total_fat_g": 71.4, "macro_confidence": 0.9, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dressing and toss the salad","instruction":"Combine olive oil, lemon juice, honey and thyme in a bowl, season, then tip in lettuce, tomatoes, spring onions and chilli, and toss.","timer_seconds":null,"background":false},{"step":2,"label":"Assemble and serve","instruction":"Scoop out pomegranate seeds, arrange the dressed salad on a platter, and scatter with pomegranate seeds and feta.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=wTqashUAid8"}, {"id": "53298", "name": "Polish doughnuts (Pączki)", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/x6jqog1764359857.jpg", "local_image": "53298.jpg", "ingredients": [{"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "Caster Sugar", "measure": "1 tsp"}, {"ingredient": "Flour", "measure": "1 tablespoon"}, {"ingredient": "Milk", "measure": "125ml"}, {"ingredient": "Egg Yolks", "measure": "7"}, {"ingredient": "Sugar", "measure": "15g"}, {"ingredient": "Caster Sugar", "measure": "10g"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Flour", "measure": "500g"}, {"ingredient": "Double Cream", "measure": "200ml"}, {"ingredient": "Butter", "measure": "15g"}, {"ingredient": "Jam", "measure": "125ml"}, {"ingredient": "Ground Almonds", "measure": "10g"}, {"ingredient": "Oil", "measure": "For frying"}, {"ingredient": "Icing Sugar", "measure": "75g"}, {"ingredient": "Lemon", "measure": "Juice of 1/2"}, {"ingredient": "Almond Essence", "measure": "Dash"}, {"ingredient": "Almonds", "measure": "50g"}], "instructions": "step 1\r\nTo make the leaven, mix the yeast with the sugar and flour, and stir in the warm milk. Set aside in a warm place for 30 minutes.\r\n\r\nstep 2\r\nFor the dough, put egg yolks into a heatproof bowl and add the sugar and vanilla sugar. Set the bowl over a pan of simmering water and whisk until smooth and thick.\r\n\r\nstep 3\r\nSift the flour into the bowl of a stand mixer, add the beaten yolks and the warm cream, mix thoroughly, then add a pinch of salt and the leaven. Bring together to make a dough and knead for 10 minutes (or 15-20 if doing this by hand).\r\n\r\nstep 4\r\nWhen the dough stops sticking to your hands, pour in the cooled melted butter and knead for a few more minutes. Cover with a cloth and leave in a warm place to rise for at least 1 hr-1 hr 30 mins.\r\n\r\nstep 5\r\nMix the jam with the ground almonds and spoon into a piping bag or jam syringe. Divide the dough into 16 pieces and shape them into doughnuts. Cover and leave to rise for 30 mins.\r\n\r\nstep 6\r\nFill a deep pan or a deep fat fryer one third full of oil or melted lard and heat it until it is 180C – if you don’t have a thermometer, drop in a small chunk of bread. The oil is ready when it browns in about 30 secs. Add the doughnuts and fry, turning them once for about 1-2 mins on each side (a thin lighter ring should form in the middle). After removing, drain the doughnuts of excess fat on some kitchen paper.", "equipment_tags": [], "portions": 10, "prep_minutes": 222, "prep_minutes_source": "explicit", "kcal": 548, "protein_g": 13.4, "carbs_g": 62.1, "fat_g": 27.3, "total_kcal": 5481, "total_protein_g": 134.0, "total_carbs_g": 621.4, "total_fat_g": 272.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the leaven","instruction":"Mix yeast with sugar and flour, stir in warm milk, and set aside in a warm place until frothy.","timer_seconds":1800,"background":true},{"step":2,"label":"Cook the egg base","instruction":"Whisk egg yolks, sugar and vanilla sugar over a pan of simmering water until smooth and thick.","timer_seconds":null,"background":false},{"step":3,"label":"Make the dough","instruction":"Sift flour into a stand mixer bowl, add the yolks, warm cream, salt and leaven, and knead into a dough.","timer_seconds":600,"background":false},{"step":4,"label":"Enrich and rise","instruction":"Knead in the cooled melted butter, then cover and leave to rise in a warm place.","timer_seconds":5400,"background":true},{"step":5,"label":"Shape and second rise","instruction":"Mix jam with ground almonds for piping. Divide the dough into 16 pieces, shape into doughnuts, cover, and leave to rise.","timer_seconds":1800,"background":true},{"step":6,"label":"Fry","instruction":"Heat oil or lard to 180°C and fry the doughnuts, turning once, until a light ring forms in the middle, then drain.","timer_seconds":150,"background":false},{"step":7,"label":"Fill and finish","instruction":"Pipe the jam-almond filling into each doughnut, then dust with a lemon-almond icing sugar glaze.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=17jL5nZrgPw"}, {"id": "53299", "name": "Polish patties (kotlety)", "category": "Side", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vvn5f71764360273.jpg", "local_image": "53299.jpg", "ingredients": [{"ingredient": "Bread Rolls", "measure": "1"}, {"ingredient": "Milk", "measure": "120ml"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Vegetable Oil", "measure": "100 ml"}, {"ingredient": "Ground Beef", "measure": "500g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Garlic Clove", "measure": "1"}, {"ingredient": "Marjoram", "measure": "Pinch"}, {"ingredient": "Breadcrumbs", "measure": "75g"}], "instructions": "step 1\r\nSoak the bread roll in the milk so it softens completely. Meanwhile, fry the onion in the oil for around 8 mins or until soft and golden. Add the fried onion to the beef mince along with the egg, garlic, marjoram and some seasoning. Squeeze the excess milk from the bread roll and add it to the mince mixture. Mix everything together and season well.\r\n\r\nstep 2\r\nDivide the meat into 8 patties. Tip the dried breadcrumbs into a shallow bowl and coat the patties in it, all over. Heat some oil in a deep frying pan and fry the patties in batches on both sides until browned and cooked through, about 6-7 mins on each side.", "equipment_tags": [], "portions": 6, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 451, "protein_g": 18.5, "carbs_g": 16.1, "fat_g": 34.5, "total_kcal": 2707, "total_protein_g": 111.1, "total_carbs_g": 96.3, "total_fat_g": 206.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the bread and fry the onion","instruction":"Soak the bread roll in milk until soft. Fry the onion in oil until soft and golden.","timer_seconds":480,"background":false},{"step":2,"label":"Mix the patty mixture","instruction":"Combine the mince with the fried onion, egg, garlic, marjoram and seasoning, squeeze the excess milk from the bread and add it, and mix well.","timer_seconds":null,"background":false},{"step":3,"label":"Shape and coat","instruction":"Divide into 8 patties and coat all over in dried breadcrumbs.","timer_seconds":null,"background":false},{"step":4,"label":"Fry","instruction":"Heat oil in a deep frying pan and fry the patties in batches on both sides until browned and cooked through.","timer_seconds":780,"background":false}], "video": "https://www.youtube.com/shorts/0XrToCi-U1c"}, {"id": "53300", "name": "Bigos (Polish hunter's stew)", "category": "Beef", "area": "Polish", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/fl4brj1764361323.jpg", "local_image": "53300.jpg", "ingredients": [{"ingredient": "White Cabbage", "measure": "1 sliced"}, {"ingredient": "Beef Stock", "measure": "250ml"}, {"ingredient": "Mushrooms", "measure": "100g"}, {"ingredient": "Lard", "measure": "2 tablespoons"}, {"ingredient": "German Sausages", "measure": "400g"}, {"ingredient": "Bacon", "measure": "250g"}, {"ingredient": "Onion", "measure": "2 chopped"}, {"ingredient": "Beef", "measure": "750g"}, {"ingredient": "Prunes", "measure": "200g"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Cloves", "measure": "2"}, {"ingredient": "Peppercorns", "measure": "12"}, {"ingredient": "Juniper Berries", "measure": "4"}, {"ingredient": "Allspice Berries", "measure": "4"}, {"ingredient": "Red Wine", "measure": "90 ml"}, {"ingredient": "Tomato Puree", "measure": "2 tablespoons"}], "instructions": "step 1\r\nPut the cabbage in a heavy casserole dish, add the stock and cook over a low heat for about 50 mins, until tender.\r\n\r\nstep 2\r\nCut the soaked mushrooms into strips and save the soaking water. Heat the lard and fry the sausages and bacon, then scoop out, leaving the fat in the pan. Fry the onion in the same pan for 5-8 mins until lightly browned.\r\n\r\nstep 3\r\nAdd the mushrooms and their liquid along with all the cooked meat, onions and prunes, then cover and cook for 20 mins. Add the spices, red wine and tomato purée and bring to a simmer, then cover and cook for 1 hr. Season well and leave to cool. Will keep covered and chilled for up to two days. Bigos improves in flavour over a couple of days. Leave to cool first. Reheat until piping hot before serving.", "equipment_tags": [], "portions": 5, "prep_minutes": 138, "prep_minutes_source": "explicit", "kcal": 1042, "protein_g": 63.6, "carbs_g": 43.1, "fat_g": 68.0, "total_kcal": 5212, "total_protein_g": 318.2, "total_carbs_g": 215.5, "total_fat_g": 340.2, "macro_confidence": 0.94, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the cabbage","instruction":"Put the cabbage in a heavy casserole with the stock and cook over low heat until tender.","timer_seconds":3000,"background":true},{"step":2,"label":"Fry the meats","instruction":"Cut soaked mushrooms into strips, saving the liquid. Heat lard, fry the sausages and bacon, scoop out, then fry the onion in the same pan until lightly browned.","timer_seconds":480,"background":false},{"step":3,"label":"Combine and simmer","instruction":"Add mushrooms and liquid, all the cooked meat, onions and prunes, cover, and cook, then add spices, wine and tomato purée, bring to a simmer, and cook covered.","timer_seconds":4800,"background":true},{"step":4,"label":"Rest and serve","instruction":"Season well and leave to cool; reheat until piping hot before serving, ideally after resting a day or two for improved flavour.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=Oqg_cO4s8ik"}, {"id": "53301", "name": "Pork & sauerkraut goulash", "category": "Pork", "area": "Polish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/cyuhwp1764362103.jpg", "local_image": "53301.jpg", "ingredients": [{"ingredient": "Lard", "measure": "3  tablespoons"}, {"ingredient": "Onion", "measure": "4 Chopped"}, {"ingredient": "Cumin Seeds", "measure": "1 tablespoon"}, {"ingredient": "Pork Shoulder", "measure": "800g"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Plain Flour", "measure": "2 tablespoons"}, {"ingredient": "Paprika", "measure": "2 tablespoons"}, {"ingredient": "Beef Stock", "measure": "1 1/2 L"}, {"ingredient": "Bay Leaves", "measure": "4"}, {"ingredient": "White Sauerkraut", "measure": "400g"}, {"ingredient": "Whipping Cream", "measure": "200ml"}, {"ingredient": "Sour Cream", "measure": "4 tablespoons"}], "instructions": "step 1\r\nHeat the lard in a saucepan over a medium heat and fry the finely chopped onion until golden, around 5-8 mins. Tip in the cumin and pork, and fry for 10 mins all over until browned. Add the garlic, season well and scatter over the flour. Cook for about a minute, then add the paprika and cook for 1 min more.\r\n\r\nstep 2\r\nPour in half of the stock, add the bay leaves, and simmer with the lid on over a low heat for 30 mins.\r\n\r\nstep 3\r\nAdd the sauerkraut, remaining stock and a drizzle of the sauerkraut pickling juices. Simmer with the lid for 30 mins, stirring occasionally, until the meat is tender. Stir in the cream and simmer for 5 mins to combine the flavours. Season to taste, the serve garnished with a spoonful of soured cream.\r\n\r\nThis recipe has been provided by Apetit Online and not been re-tested by us.", "equipment_tags": [], "portions": 7, "prep_minutes": 84, "prep_minutes_source": "explicit", "kcal": 432, "protein_g": 27.3, "carbs_g": 16.7, "fat_g": 28.6, "total_kcal": 3022, "total_protein_g": 190.9, "total_carbs_g": 117.1, "total_fat_g": 200.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Brown the pork","instruction":"Heat lard and fry the finely chopped onion until golden, add cumin and pork, and fry until browned all over.","timer_seconds":900,"background":false},{"step":2,"label":"Add garlic and flour","instruction":"Add garlic, season, scatter over the flour, cook briefly, then add paprika and cook further.","timer_seconds":120,"background":false},{"step":3,"label":"First simmer","instruction":"Pour in half the stock, add bay leaves, and simmer with the lid on.","timer_seconds":1800,"background":true},{"step":4,"label":"Add sauerkraut and finish","instruction":"Add sauerkraut, remaining stock and pickling juices, simmer with the lid until the meat is tender, then stir in cream and simmer to combine.","timer_seconds":2100,"background":true},{"step":5,"label":"Serve","instruction":"Season to taste and serve garnished with soured cream.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=91FM8lHEGbQ"}, {"id": "53302", "name": "Slow-roasted ham with lemon, garlic & sage", "category": "Pork", "area": "Polish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/w36ets1764362474.jpg", "local_image": "53302.jpg", "ingredients": [{"ingredient": "Garlic", "measure": "5 chopped cloves"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Salt", "measure": "15g"}, {"ingredient": "Black Pepper", "measure": "10g"}, {"ingredient": "Vegetable Oil", "measure": "50 ml"}, {"ingredient": "Pork Shoulder", "measure": "2kg"}, {"ingredient": "Dry White Wine", "measure": "500ml"}], "instructions": "step 1\r\nHeat the oven to 200C/180C fan/gas 6. Bash the garlic, sage, lemon zest, salt and pepper together using a pestle and mortar until the mixture becomes a paste. Stir in the oil, then spread the mixture over the pork shoulder, avoiding the skin on top. Score the skin using a sharp knife, then rub a large pinch of salt into the skin. Tie the pork together using kitchen string.\r\n\r\nstep 2\r\nLine a large baking tray with a double layer of foil and put the pork on top, skin-side up. Bring the sides of the foil up around the pork to create a parcel, then pour the wine into the tray around the sides. Transfer to the oven and reduce the temperature to 140C/120C fan/gas 1. Roast for 4-5 hrs, or until a meat thermometer inserted into the thickest part of the pork reads 70C.\r\n\r\nstep 3\r\nTurn the oven up to 240C/220C fan/gas 9. Carefully spoon the pork roasting juices from the pan into a saucepan and cook over a medium heat for 10-15 mins, or until reduced by a third. Season to taste.\r\n\r\nstep 4\r\nMeanwhile, arrange the foil around the meat so only the skin is exposed, then return to the oven for 10-15 mins until the skin is puffed up and browned all over. Leave to rest for 20 mins before slicing. Serve with the sauce drizzled over.", "equipment_tags": [], "portions": 6, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 737, "protein_g": 69.6, "carbs_g": 17.4, "fat_g": 34.6, "total_kcal": 4423, "total_protein_g": 417.8, "total_carbs_g": 104.7, "total_fat_g": 207.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the paste and coat","instruction":"Heat the oven to 200°C/180°C fan/gas 6. Pound garlic, sage, lemon zest, salt and pepper into a paste, stir in oil, and spread over the pork, avoiding the skin. Score the skin and rub with salt, then tie with string.","timer_seconds":null,"background":false},{"step":2,"label":"Wrap and roast","instruction":"Wrap the pork skin-side up in foil with wine poured around, reduce the oven temperature, and roast until a thermometer reads 70°C.","timer_seconds":16200,"background":true},{"step":3,"label":"Reduce the sauce","instruction":"Turn the oven up. Spoon the roasting juices into a saucepan and reduce by a third.","timer_seconds":750,"background":false},{"step":4,"label":"Crisp the skin","instruction":"Expose the skin and return to the hot oven until puffed up and browned all over.","timer_seconds":750,"background":true},{"step":5,"label":"Rest and serve","instruction":"Rest before slicing and serve with the sauce drizzled over.","timer_seconds":1200,"background":true}], "video": null}, {"id": "53303", "name": "Raspberry mousse", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/v5jrnn1764362830.jpg", "local_image": "53303.jpg", "ingredients": [{"ingredient": "Gelatine Leafs", "measure": "2"}, {"ingredient": "Raspberries", "measure": "350g"}, {"ingredient": "Caster Sugar", "measure": "60g"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Whipping Cream", "measure": "500ml"}], "instructions": "step 1\r\nPut the gelatine leaves in a bowl, cover with warm water and leave to soak for 5 mins. Drain and squeeze out any excess water.\r\n\r\nstep 2\r\nTip the raspberries into a pan over a medium-low heat along with the sugar and lemon juice. Cook for 5-6 mins until the berries have completely broken down. Push the mixture through a sieve set over a bowl, discarding the seeds. Stir in the gelatine leaves until dissolved (if they don’t dissolve, pour the mixture into a clean saucepan and heat gently until dissolved). Set aside to cool for 15 mins.\r\n\r\nstep 3\r\nWhip the cream to soft peaks using an electric whisk, then gently fold this into the raspberry mixture. Spoon into the ramekins or moulds and chill overnight, or for at least 6 hrs. Serve with raspberries scattered over the top.", "equipment_tags": [], "portions": 6, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 350, "protein_g": 2.6, "carbs_g": 20.0, "fat_g": 29.6, "total_kcal": 2100, "total_protein_g": 15.5, "total_carbs_g": 119.8, "total_fat_g": 177.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Soak the gelatine","instruction":"Cover the gelatine leaves with warm water and soak, then drain and squeeze out excess water.","timer_seconds":300,"background":true},{"step":2,"label":"Cook and strain the raspberries","instruction":"Cook the raspberries with sugar and lemon juice over medium-low heat until broken down, then push through a sieve, discarding seeds.","timer_seconds":360,"background":false},{"step":3,"label":"Dissolve the gelatine and cool","instruction":"Stir in the gelatine until dissolved, then set aside to cool.","timer_seconds":900,"background":true},{"step":4,"label":"Fold and set","instruction":"Whip the cream to soft peaks, fold into the raspberry mixture, spoon into moulds, and chill until set.","timer_seconds":21600,"background":true},{"step":5,"label":"Serve","instruction":"Serve with raspberries scattered over the top.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=YbFsvvwcSCw"}, {"id": "53304", "name": "Mini bundt cakes", "category": "Dessert", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tzt3it1764363293.jpg", "local_image": "53304.jpg", "ingredients": [{"ingredient": "Butter", "measure": "150g"}, {"ingredient": "Plain Flour", "measure": "175g"}, {"ingredient": "Caster Sugar", "measure": "125g"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Cocoa Powder", "measure": "2 tsp"}, {"ingredient": "Milk", "measure": "3  tablespoons"}, {"ingredient": "Icing Sugar", "measure": "1 tablespoon"}], "instructions": "step 1\r\nHeat the oven to 180C/160C fan/gas 4. Melt 25g butter and generously brush into the holes of a mini bundt tins. Tip a little flour into each hole and shake to coat, then tip out the excess. Beat the butter, caster sugar and a pinch of salt together using an electric whisk. Add the eggs, one at a time, beating well after each addition. Combine the flour and baking powder in a separate bowl, then sift this into the wet ingredients and stir until smooth. Combine the cocoa powder and milk in a small bowl until smooth.\r\n\r\nstep 2\r\nSpoon 1 tbsp of the plain batter into each hole of the bundt tin. Mix the remaining plain batter with the cocoa powder mixture, then divide this between the holes. Bake for 15-18 mins, or until a skewer inserted into the cakes comes out clean. Leave to cool in the tin for 5 mins, then turn out onto a wire rack and leave to cool completely. Dust with icing sugar to serve.\r\n\r\nstep 3\r\nPour 1 tablespoon of light batter into each mold. Mix the remaining batter with the stirred cocoa mixture and then fill the molds with a tablespoon.\r\n\r\nstep 4\r\nBake the mini Bundt cakes in the preheated oven for 15-18 minutes , depending on the size of the molds. After 15 minutes of baking time, use a toothpick to test with a skewer and, if necessary, bake for another 3 minutes. Let the mini Bundt cakes cool down completely in the tin. Then carefully remove from the mold. Dust with some icing sugar and serve. Enjoy your meal!", "equipment_tags": [], "portions": 4, "prep_minutes": 59, "prep_minutes_source": "explicit", "kcal": 628, "protein_g": 10.4, "carbs_g": 70.5, "fat_g": 35.3, "total_kcal": 2513, "total_protein_g": 41.8, "total_carbs_g": 281.9, "total_fat_g": 141.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the tins and batter","instruction":"Heat the oven to 180°C/160°C fan/gas 4, brush bundt tins with melted butter and dust with flour. Beat butter, sugar and salt, add eggs one at a time, then fold in sifted flour and baking powder.","timer_seconds":null,"background":false},{"step":2,"label":"Make the cocoa portion","instruction":"Mix cocoa powder and milk together, then divide the batter and mix half with the cocoa mixture.","timer_seconds":null,"background":false},{"step":3,"label":"Fill and bake","instruction":"Spoon plain batter into each mould, top with the cocoa batter, and bake until a skewer comes out clean.","timer_seconds":1000,"background":true},{"step":4,"label":"Cool and serve","instruction":"Cool in the tin, turn out, and dust with icing sugar to serve.","timer_seconds":300,"background":true}], "video": "https://www.youtube.com/watch?v=4agkoGMcL2w"}, {"id": "53305", "name": "Braised stuffed cabbage", "category": "Vegetarian", "area": "Polish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/z267f71764364072.jpg", "local_image": "53305.jpg", "ingredients": [{"ingredient": "Cabbage Leaves", "measure": "6 large"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Rosemary", "measure": "2 tsp"}, {"ingredient": "Celery", "measure": "1 chopped"}, {"ingredient": "Basmati Rice", "measure": "140g"}, {"ingredient": "Cooked Chestnut", "measure": "140g"}, {"ingredient": "Cranberry", "measure": "50g"}, {"ingredient": "Vegetable Stock", "measure": "300ml"}, {"ingredient": "Balsamic Vinegar", "measure": "1 tablespoon"}, {"ingredient": "Clear Honey", "measure": "1 tsp"}], "instructions": "step 1\r\nHeat oven to 180C/fan 160C/gas 4. Remove the tough central stalk from the cabbage leaves. Bring a large pan of salted water to the boil, add the cabbage, then cook for just 1-2 mins until the leaves are starting to wilt. Drain and refresh under cold running water. Drain well, then pat dry with a tea towel.\r\n\r\nstep 2\r\nHeat the oil in a pan, add the onion, then fry for 5 mins until slightly browned. Add the rosemary and celery, then cook for 8 mins more. Stir in the rice, then cook for a min or so until the grains are glistening. Remove from the heat, stir in the chestnuts and cranberries, then season.\r\n\r\nstep 3\r\nSpoon a little stuffing onto a cabbage leaf, roll up and fold in the sides to enclose the filling. Put in a single layer in a large, oiled, shallow ovenproof dish with the join underneath. Fill the remaining leaves in the same way. Mix the stock, vinegar and honey, then pour over the cabbage. Cover the dish tightly with foil, bake for 1 hr, uncover, then cook for a further 15 mins.", "equipment_tags": [], "portions": 2, "prep_minutes": 90, "prep_minutes_source": "explicit", "kcal": 867, "protein_g": 22.6, "carbs_g": 83.3, "fat_g": 51.8, "total_kcal": 1734, "total_protein_g": 45.1, "total_carbs_g": 166.6, "total_fat_g": 103.5, "macro_confidence": 0.82, "is_new": false, "cook_steps": [{"step":1,"label":"Blanch the cabbage leaves","instruction":"Heat the oven to 180°C/fan 160°C/gas 4. Remove the tough stalk from the leaves, blanch briefly in boiling salted water, then drain and pat dry.","timer_seconds":120,"background":false},{"step":2,"label":"Cook the stuffing","instruction":"Fry the onion until browned, add rosemary and celery and cook further, then stir in rice and cook briefly. Remove from heat and stir in chestnuts and cranberries.","timer_seconds":780,"background":false},{"step":3,"label":"Roll the parcels","instruction":"Spoon stuffing onto each cabbage leaf, roll up and fold in the sides, and place join-down in an oiled dish.","timer_seconds":null,"background":false},{"step":4,"label":"Bake","instruction":"Mix stock, vinegar and honey, pour over, cover with foil, and bake, then uncover and cook further.","timer_seconds":4500,"background":true}], "video": "https://www.youtube.com/watch?v=RNrZpQaj5us"}, {"id": "53306", "name": "Pork rib bortsch", "category": "Pork", "area": "Polish", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/om5hsl1764364721.jpg", "local_image": "53306.jpg", "ingredients": [{"ingredient": "Pork Back Ribs", "measure": "1kg"}, {"ingredient": "Bay Leaves", "measure": "2"}, {"ingredient": "Dried white beans", "measure": "1 tablespoon"}, {"ingredient": "Carrots", "measure": "1 large"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Garlic Clove", "measure": "3 sliced thinly"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Red Chilli", "measure": "2 chopped"}, {"ingredient": "Beetroot", "measure": "2"}, {"ingredient": "Potatoes", "measure": "3 chopped"}, {"ingredient": "Tomato Puree", "measure": "3  tablespoons"}, {"ingredient": "White Cabbage", "measure": "1/2"}, {"ingredient": "Parsley", "measure": "Handful"}, {"ingredient": "Dill", "measure": "Handful"}, {"ingredient": "Sour Cream", "measure": "300g"}], "instructions": "step 1\r\nCut the meat into large pieces, put in your largest saucepan and cover with 5 litres water. Bring to the boil over a high heat, skimming away any foam that rises to the surface. Add the bay leaves. Season. Turn the heat down to a simmer and cook for 1 hr, or until the meat is soft and falls off the bone. Add the beans if using dried.\r\n\r\nstep 2\r\nTurn the heat up. Bring back to the boil, then reduce the heat and simmer for another 20 mins – the beans should still be slightly raw. Add the carrots, onions, garlic and pepper. Stir well, then add the chillies, if using. Cook for 15 mins more.\r\n\r\nstep 3\r\nStir in the beetroot and cook for 10 mins before adding the potatoes. After 15 mins, add the tomato purée to taste and beans, if using canned, and bring to the boil. Cook for 5 mins, add the cabbage and cook for 5 mins more. Season, then garnish with the parsley and dill. Turn off the heat and leave to stand for 5 mins. Serve with soured cream on the side.", "equipment_tags": [], "portions": 5, "prep_minutes": 135, "prep_minutes_source": "explicit", "kcal": 574, "protein_g": 46.2, "carbs_g": 32.4, "fat_g": 27.9, "total_kcal": 2871, "total_protein_g": 231.1, "total_carbs_g": 162.2, "total_fat_g": 139.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Simmer the ribs","instruction":"Cut the meat into pieces, cover with water, bring to the boil, skim, add bay leaves, season, then reduce to a simmer and cook until the meat is soft.","timer_seconds":3600,"background":true},{"step":2,"label":"Cook the beans and vegetables","instruction":"Bring back to the boil, then simmer, add carrots, onions, garlic and pepper, stirring well, then add chillies and cook further.","timer_seconds":2100,"background":true},{"step":3,"label":"Add beetroot and potato","instruction":"Stir in beetroot and cook, then add potatoes.","timer_seconds":600,"background":true},{"step":4,"label":"Finish","instruction":"Add tomato purée and beans, bring to the boil, cook, then add cabbage and cook further. Season and garnish with parsley and dill.","timer_seconds":600,"background":true},{"step":5,"label":"Serve","instruction":"Let stand briefly, then serve with soured cream on the side.","timer_seconds":300,"background":false}], "video": "https://www.youtube.com/watch?v=SqRP4xYS6wA"}, {"id": "53307", "name": "Beetroot & red cabbage sauerkraut", "category": "Vegetarian", "area": "Polish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ra2k8a1764365055.jpg", "local_image": "53307.jpg", "ingredients": [{"ingredient": "Beetroot", "measure": "320g"}, {"ingredient": "Red Cabbage", "measure": "450g"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Caraway Seed", "measure": "2 tsp"}, {"ingredient": "Sea Salt", "measure": "1 tsp"}], "instructions": "step 1\r\nTip all the ingredients into a large bowl, add 1-1½ tsp freshly ground black pepper, then scrunch it all together with your hands for 5 mins. You might want to wear gloves to avoid staining your skin with the beetroot juices.\r\n\r\nstep 2\r\nPress the veg down in the bowl with your hands, then cover the surface and up the side of the bowl with a large sheet of compostable cling film or something reusable like a beeswax wrap. Now place another similar-sized bowl on top. Press down hard and add anything heavy (packs of rice or cans work well) to weigh it down so the juices rise to cover the surface. Cover again.\r\n\r\nstep 3\r\nLeave to ferment at room temperature for at least five days, but for maximum flavour, leave for one-five weeks (until the bubbling subsides).\r\n\r\nstep 4\r\nCheck the sauerkraut. After a few days, you will see bubbles that have built up as it ferments. Give it a stir, then cover and weigh it down again as before. The cabbage will become increasingly sour the longer it’s fermented, so taste it now and again. When you like the flavour, transfer it to sterilised jars and keep chilled. Will keep chilled for up to six months.", "equipment_tags": [], "portions": 2, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 164, "protein_g": 7.1, "carbs_g": 36.7, "fat_g": 1.3, "total_kcal": 327, "total_protein_g": 14.2, "total_carbs_g": 73.3, "total_fat_g": 2.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Mix and massage","instruction":"Combine all the ingredients in a large bowl with pepper, and scrunch together with your hands.","timer_seconds":300,"background":false},{"step":2,"label":"Weigh down","instruction":"Press the vegetables down, cover the surface, place another bowl on top, and weigh down so the juices rise to cover the surface.","timer_seconds":null,"background":false},{"step":3,"label":"Ferment","instruction":"Leave to ferment at room temperature for at least five days, up to five weeks, until bubbling subsides.","timer_seconds":432000,"background":true},{"step":4,"label":"Check and store","instruction":"Stir occasionally, tasting for sourness, then transfer to sterilised jars and keep chilled once you like the flavour.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=ly1UeAjydEg"}, {"id": "53308", "name": "Rye bread", "category": "Side", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/lmc6r51764365554.jpg", "local_image": "53308.jpg", "ingredients": [{"ingredient": "Rye", "measure": "200g"}, {"ingredient": "Strong white bread flour", "measure": "200g"}, {"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Honey", "measure": "1 tablespoon"}, {"ingredient": "Caraway Seed", "measure": "1 tsp"}], "instructions": "step 1\r\nTip the flours, yeast and salt into a bowl. In a jug, mix the honey with 250ml warm water, pour the liquid into the bowl and mix to form a dough. Rye flour can be quite dry and absorbs lots of water, if the dough looks too dry add more warm water until you have a soft dough Tip out onto your work surface and knead for 10 mins until smooth. Rye contains less gluten than white flour so the dough will not feel as springy as a conventional white loaf.\r\n\r\nstep 2\r\nPlace the dough in a well oiled bowl, cover with cling film and leave to rise in a warm place for 1-2 hrs, or until roughly doubled in size. Dust a 2lb/900g loaf tin with flour.\r\n\r\nstep 3\r\nTip the dough back onto your work surface and knead briefly to knock out any air bubbles. If using caraway seeds work these in to the dough. Shape into a smooth oval loaf and pop into your tin. Cover the tin with oiled cling film and leave to rise somewhere warm for a further 1 – 1.5 hr, or until doubled in size.\r\n\r\nstep 4\r\nHeat oven to 220C/200C fan/gas 7. Remove the cling film and dust the surface of the loaf with rye flour. Slash a few incisions on an angle then bake for 30 mins until dark brown and hollow sounding when tapped. Transfer to a wire cooling rack and leave to cool for at least 20 mins before serving", "equipment_tags": [], "portions": 4, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 285, "protein_g": 8.8, "carbs_g": 51.5, "fat_g": 4.9, "total_kcal": 1142, "total_protein_g": 35.1, "total_carbs_g": 206.1, "total_fat_g": 19.5, "macro_confidence": 0.83, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dough","instruction":"Mix rye flour, white flour, yeast and salt in a bowl, mix honey with warm water, pour in, and mix to form a dough, adding water if too dry.","timer_seconds":null,"background":false},{"step":2,"label":"Knead","instruction":"Knead the dough on the work surface until smooth.","timer_seconds":600,"background":false},{"step":3,"label":"First rise","instruction":"Place in an oiled bowl, cover, and leave to rise in a warm place until roughly doubled.","timer_seconds":5400,"background":true},{"step":4,"label":"Shape and second rise","instruction":"Knock back, work in caraway seeds if using, shape into an oval loaf, place in a tin, cover, and leave to rise again.","timer_seconds":4500,"background":true},{"step":5,"label":"Bake","instruction":"Heat the oven to 220°C/200°C fan/gas 7, dust the loaf, slash the top, and bake until dark brown and hollow-sounding.","timer_seconds":1800,"background":true},{"step":6,"label":"Cool","instruction":"Transfer to a wire rack and cool before serving.","timer_seconds":1200,"background":true}], "video": "https://www.youtube.com/watch?v=bP7m7xx0GpM"}, {"id": "53309", "name": "Cucumber & fennel salad", "category": "Vegetarian", "area": "Polish", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ei21r61764365935.jpg", "local_image": "53309.jpg", "ingredients": [{"ingredient": "Cucumber", "measure": "1 large"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Fennel Bulb", "measure": "1 sliced"}, {"ingredient": "Sour Cream", "measure": "150ml"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "White Wine Vinegar", "measure": "1 tablespoon"}, {"ingredient": "Dill", "measure": "Bunch"}], "instructions": "step 1\r\nPut cucumber in a sieve. Sprinkle with 1 tsp salt and the sugar, then leave for 10 mins. Add fennel.\r\n\r\nstep 2\r\nMix soured cream, lemon juice, vinegar and dill, then season with black pepper and add to fennel mix.", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 120, "protein_g": 2.0, "carbs_g": 7.2, "fat_g": 9.7, "total_kcal": 361, "total_protein_g": 5.9, "total_carbs_g": 21.5, "total_fat_g": 29.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Salt the cucumber","instruction":"Put the cucumber in a sieve, sprinkle with salt and sugar, and leave to drain, then add fennel.","timer_seconds":600,"background":true},{"step":2,"label":"Dress and serve","instruction":"Mix soured cream, lemon juice, vinegar and dill, season with pepper, and add to the cucumber and fennel.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=gfNjne0AMb0"}, {"id": "53310", "name": "Challah", "category": "Side", "area": "Polish", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/fm01ky1764366365.jpg", "local_image": "53310.jpg", "ingredients": [{"ingredient": "Strong white bread flour", "measure": "500g"}, {"ingredient": "Caster Sugar", "measure": "70g"}, {"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "Egg", "measure": "2 Beaten"}, {"ingredient": "Sunflower Oil", "measure": "70 ml"}, {"ingredient": "Poppy Seeds", "measure": "1 tablespoon"}], "instructions": "step 1\r\nCombine the yeast, a pinch of the sugar and a couple tablespoons of lukewarm water in a small bowl. Stir to dissolve the yeast, then leave for 10 mins until foamy.\r\n\r\nstep 2\r\nMeanwhile, combine the flour, the remaining sugar and 2 tsp fine salt in a large bowl. Make a well in the centre, then add half the beaten egg, the yeast mixture and the oil. Pour in 200ml lukewarm water (it should feel slightly warm to the touch) and stir with a spoon, then mix using one hand, keeping the other clean while you bring the dough together. If there are a lot of very dry bits, gradually add a little water to just bring it together – you don't want it to get too wet and sticky. The dough should be moist, but not soggy.\r\n\r\nstep 3\r\nOnce the dough has come together, turn it out onto a lightly floured surface. Knead using both hands for 10 mins until smooth and a bit springy. If it gets very sticky, add a very small amount of flour – as little as possible. A dough scraper is useful if the dough is sticking to the work surface. Stretch the sides of the dough down and pull together to form a ball. Lightly oil a bowl, then lightly roll the dough ball around the bowl so it's coated in the oil. Cover with a clean tea towel and leave in a warm place for 1 hr, or until dough has doubled in size.\r\n\r\nstep 4\r\nLine a baking sheet with baking parchment. Turn the dough out onto a clean work surface and divide into three equal pieces, weighing for accuracy, if you like. Roll each piece into a long sausage shape about 25cm long, tapering them slightly at both ends. Lay the pieces out in front of you, parallel to one another with a couple centimetres between each. Bring the sausages together at the top end, then plait them down the length, tucking in the ends when you reach the bottom. Carefully transfer the loaf to the prepared baking sheet and loosely cover with a clean tea towel. Leave to rise until puffy and billowy, about 40 mins.\r\n\r\nstep 5\r\nMeanwhile, heat the oven to 200C/180C fan/gas 6. Gently brush the rest of the beaten egg all over the challah, getting it into all the crevices, and sprinkle with the poppy or sesame seeds, if using. Bake on a middle shelf of the oven for 25-30 mins, until the loaf is golden brown underneath and sounds hollow when tapped. Check after about 15 mins – if the top of the loaf has started to get too dark, cover it with foil. Leave to cool on a wire rack, then serve.", "equipment_tags": [], "portions": 4, "prep_minutes": 165, "prep_minutes_source": "explicit", "kcal": 729, "protein_g": 17.4, "carbs_g": 114.9, "fat_g": 21.6, "total_kcal": 2914, "total_protein_g": 69.7, "total_carbs_g": 459.4, "total_fat_g": 86.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Activate the yeast","instruction":"Combine yeast, a pinch of sugar and lukewarm water, stir, and leave until foamy.","timer_seconds":600,"background":true},{"step":2,"label":"Make the dough","instruction":"Combine flour, remaining sugar and salt, make a well, add half the egg, the yeast mixture, oil and lukewarm water, and stir into a dough.","timer_seconds":null,"background":false},{"step":3,"label":"Knead and rise","instruction":"Knead until smooth and springy, shape into a ball, oil, cover, and leave to rise until doubled.","timer_seconds":3600,"background":true},{"step":4,"label":"Plait","instruction":"Divide the dough into three, roll into sausages, and plait them together, tucking in the ends.","timer_seconds":null,"background":false},{"step":5,"label":"Second rise","instruction":"Cover loosely and leave to rise until puffy.","timer_seconds":2400,"background":true},{"step":6,"label":"Glaze and bake","instruction":"Heat the oven to 200°C/180°C fan/gas 6. Brush with the remaining egg, sprinkle with seeds, and bake until golden brown and hollow-sounding, covering with foil if browning too fast.","timer_seconds":1650,"background":true},{"step":7,"label":"Cool","instruction":"Leave to cool on a wire rack before serving.","timer_seconds":null,"background":true}], "video": "https://www.youtube.com/watch?v=RAYv3n4q-Wc"}, {"id": "53311", "name": "Borsch", "category": "Beef", "area": "Ukrainian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/804v1j1764367088.jpg", "local_image": "53311.jpg", "ingredients": [{"ingredient": "Beef Shin", "measure": "1kg"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Potatoes", "measure": "2.5kg"}, {"ingredient": "Sunflower Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Carrots", "measure": "1"}, {"ingredient": "Beetroot", "measure": "200g"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Tinned Tomatos", "measure": "200g"}, {"ingredient": "Prunes", "measure": "6"}, {"ingredient": "White Cabbage", "measure": "1/2"}, {"ingredient": "Kidney Beans", "measure": "400g"}, {"ingredient": "Creme Fraiche", "measure": "100 ml"}, {"ingredient": "Dill", "measure": "Bunch"}, {"ingredient": "Crusty Bread", "measure": "To serve"}], "instructions": "step 1\r\nTo make the stock, put the meat, whole onion, bay leaf and 2 litres of lightly salted cold water in a large saucepan. Cook over a very low heat for 1 hr 30 mins or until the beef shin is soft and falls apart easily – this can take up to 3 hrs. Skim off the scum with a spoon from time to time. Break up any larger pieces of beef into the broth, remove the whole onion and discard.\r\n\r\nstep 2\r\nAdd the potatoes to the borscht, season well with salt and pepper and cook for 10-15 mins until tender. Meanwhile, heat the sunflower oil in a large, deep frying pan. Add the diced onion and carrot, and cook over a medium heat, stirring, until the carrot is soft and is about to start caramelising.\r\n\r\nstep 3\r\nAdd the beetroot and cook for around 5 mins, stirring occasionally. Add the red pepper, if using, and cook for another 2 mins, then add the tomatoes and prunes, stir, then increase the heat and boil to reduce slightly, before adding everything to the borscht.\r\n\r\nstep 4\r\nAdd the shredded cabbage and the kidney beans, and cook for 7-10 mins or until tender. Serve with a dollop of sour cream or crème fraîche, lots of chopped dill and some crusty bread.", "equipment_tags": [], "portions": 10, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 582, "protein_g": 30.6, "carbs_g": 78.4, "fat_g": 17.6, "total_kcal": 5823, "total_protein_g": 305.9, "total_carbs_g": 784.4, "total_fat_g": 175.8, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the stock","instruction":"Put the meat, whole onion, bay leaf and water in a large pot and cook over very low heat until the beef is soft and falls apart, skimming occasionally.","timer_seconds":5400,"background":true},{"step":2,"label":"Break up and discard","instruction":"Break up any larger pieces of beef into the broth and discard the whole onion.","timer_seconds":null,"background":false},{"step":3,"label":"Cook the potatoes","instruction":"Add potatoes, season, and cook until tender.","timer_seconds":900,"background":true},{"step":4,"label":"Cook the vegetable base","instruction":"Meanwhile, heat oil in a frying pan, cook diced onion and carrot until the carrot is soft, then add beetroot and cook, then red pepper, tomatoes and prunes, boil to reduce, and add to the borscht.","timer_seconds":720,"background":false},{"step":5,"label":"Finish","instruction":"Add cabbage and kidney beans and cook until tender.","timer_seconds":540,"background":false},{"step":6,"label":"Serve","instruction":"Serve with sour cream or crème fraîche, chopped dill and crusty bread.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=6CXgPVw_-0g"}, {"id": "53312", "name": "Tangy cabbage slaw", "category": "Vegetarian", "area": "Ukrainian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/e2g2r21764367568.jpg", "local_image": "53312.jpg", "ingredients": [{"ingredient": "Mayonnaise", "measure": "250ml"}, {"ingredient": "Lemon", "measure": "Zest and juice of 1"}, {"ingredient": "Cider Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Wholegrain Mustard", "measure": "2 tablespoons"}, {"ingredient": "Celery Salt", "measure": "1 tsp"}, {"ingredient": "White Cabbage", "measure": "1/4"}, {"ingredient": "Red Cabbage", "measure": "1/4"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Celery", "measure": "2 sliced"}], "instructions": "step 1\r\nWhisk together mayonnaise, lemon zest and juice, vinegar, mustard and celery salt in a small bowl, then season generously.\r\n\r\nstep 2\r\nAdd cabbage, carrots, onion and celery. Mix well and refrigerate. Can be made up to 1 day ahead.", "equipment_tags": [], "portions": 7, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 264, "protein_g": 1.1, "carbs_g": 5.0, "fat_g": 27.0, "total_kcal": 1850, "total_protein_g": 7.5, "total_carbs_g": 35.2, "total_fat_g": 189.2, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dressing","instruction":"Whisk together mayonnaise, lemon zest and juice, vinegar, mustard and celery salt, and season generously.","timer_seconds":null,"background":false},{"step":2,"label":"Combine and chill","instruction":"Add cabbage, carrots, onion and celery, mix well, and refrigerate.","timer_seconds":null,"background":true}], "video": "https://www.youtube.com/watch?v=oVuAky9HTlM"}, {"id": "53313", "name": "Beetroot latkes", "category": "Vegetarian", "area": "Ukrainian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/qwicc91764368097.jpg", "local_image": "53313.jpg", "ingredients": [{"ingredient": "Rapeseed Oil", "measure": "1 tablespoon"}, {"ingredient": "Greek Yogurt", "measure": "4 tablespoons"}, {"ingredient": "Mint", "measure": "1/2 bag"}, {"ingredient": "Rocket", "measure": "150g"}, {"ingredient": "Cherry Tomatoes", "measure": "130g"}, {"ingredient": "Beetroot", "measure": "400g"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Plain Flour", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Caraway Seed", "measure": "1 tsp"}, {"ingredient": "Ground Cumin", "measure": "1/2 teaspoon"}, {"ingredient": "Lemon", "measure": "Zest of 1"}], "instructions": "step 1\r\nHeat the oven to 180C/160C fan/gas 4. Make the latkes by combining all of the ingredients.\r\n\r\nstep 2\r\nHeat the oil in a large non-stick pan. Spoon in the mixture to make six round latkes. Fry for 4-5 mins on each side, then transfer to a baking sheet and bake for 10 mins.\r\n\r\nstep 3\r\nCombine the yogurt and mint in a small bowl. Toss the salad leaves and tomatoes together, then serve the latkes with the mint yogurt and salad.", "equipment_tags": [], "portions": 2, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 277, "protein_g": 13.1, "carbs_g": 33.5, "fat_g": 12.7, "total_kcal": 553, "total_protein_g": 26.2, "total_carbs_g": 67.1, "total_fat_g": 25.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make and shape the latkes","instruction":"Heat the oven to 180°C/160°C fan/gas 4. Combine all the latke ingredients and shape into six patties.","timer_seconds":null,"background":false},{"step":2,"label":"Fry and bake","instruction":"Heat oil in a pan and fry the latkes on each side, then transfer to a baking sheet and bake.","timer_seconds":1200,"background":true},{"step":3,"label":"Serve","instruction":"Combine yogurt and mint, toss the salad leaves and tomatoes, and serve the latkes with the mint yogurt and salad.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=pRLuLYQnPiM"}, {"id": "53314", "name": "Sauerkraut pierogii", "category": "Vegetarian", "area": "Ukrainian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/gqlxgc1764368767.jpg", "local_image": "53314.jpg", "ingredients": [{"ingredient": "Sunflower Oil", "measure": "1 tablespoon"}, {"ingredient": "Shallots", "measure": "2 chopped"}, {"ingredient": "Sauerkraut", "measure": "150g"}, {"ingredient": "Hispi (sweetheart) Cabbage", "measure": "150g"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Vegetable Oil", "measure": "1/2 tbs"}, {"ingredient": "Plain Flour", "measure": "350g"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Shallots", "measure": "2 sliced"}, {"ingredient": "Plain Flour", "measure": "Dusting"}, {"ingredient": "Butter", "measure": "45g"}, {"ingredient": "Sour Cream", "measure": "60 ml"}], "instructions": "step 1\r\nFirst, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour and deep-fry for 1 min or until light golden and crispy. Drain on kitchen paper. Can be made up to two days before and kept in an airtight container.\r\n\r\nstep 2\r\nTo make the filling, heat the oil in a medium non-stick frying pan and gently fry the shallots for 10 mins until starting to turn golden.\r\n\r\nstep 3\r\nAdd the sauerkraut and cabbage, and cook for 5-10 mins until the cabbage has softened. Taste and add a little salt if under-seasoned, or sugar if stringent. Scrape into a bowl and leave to cool completely.\r\n\r\nstep 4\r\nTo make the dough, mix the eggs and oil with 125ml water, then gradually add in the flour, mixing well with your hands. Knead it on a well-floured surface until the dough stops sticking to your hands. You should end up with firm, elastic dough. Wrap it in cling film and rest in the fridge for at least 30 mins, or overnight.\r\n\r\nstep 5\r\nFlour your work surface generously. Roll out the dough to a 40cm circle or until the dough is as thick as £1 coin.\r\n\r\nstep 6\r\nUsing a 9cm cookie cutter, cut out discs in the dough – you should end up with about 25 discs. Do not throw away the off-cuts – we throw them in with the pierogi when boiling to minimise any waste.\r\n\r\nstep 7\r\nHave a well-floured tray ready. Put 1 tsp of the filling into the centre of each disc. In your hand, fold in half around the filling and seal to create half-moon shapes. Put them on the floured tray, making sure they don’t touch each other.\r\n\r\nstep 8\r\nBring a large saucepan of salted water to the boil and carefully lower the pierogi in. Boil them for 2 mins or until they float to the top.\r\n\r\nstep 9\r\nDrain and serve with a knob of butter and some soured cream. Finish by sprinkling the crispy shallots on top to serve.", "equipment_tags": [], "portions": 3, "prep_minutes": 53, "prep_minutes_source": "explicit", "kcal": 1300, "protein_g": 30.5, "carbs_g": 207.4, "fat_g": 37.2, "total_kcal": 3901, "total_protein_g": 91.6, "total_carbs_g": 622.1, "total_fat_g": 111.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Fry the crispy shallots","instruction":"Heat oil to 180°C, toss shallots in flour, and deep-fry until light golden and crispy, then drain.","timer_seconds":60,"background":false},{"step":2,"label":"Cook the filling","instruction":"Heat oil in a pan and gently fry the shallots until starting to turn golden, then add sauerkraut and cabbage and cook until softened.","timer_seconds":900,"background":false},{"step":3,"label":"Cool the filling","instruction":"Scrape into a bowl and leave to cool completely.","timer_seconds":null,"background":true},{"step":4,"label":"Make and rest the dough","instruction":"Mix eggs and oil with water, gradually add flour, and knead until firm and elastic. Wrap and rest in the fridge.","timer_seconds":1800,"background":true},{"step":5,"label":"Roll and cut","instruction":"Roll the dough into a large circle and cut into discs with a cookie cutter.","timer_seconds":null,"background":false},{"step":6,"label":"Fill and seal","instruction":"Put filling in the centre of each disc, fold in half, and seal into half-moon shapes, keeping them on a floured tray without touching.","timer_seconds":null,"background":false},{"step":7,"label":"Boil","instruction":"Boil the pierogi in salted water until they float to the top.","timer_seconds":120,"background":false},{"step":8,"label":"Serve","instruction":"Drain and serve with butter and soured cream, sprinkled with the crispy shallots.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=eVWBJt2jaPU"}, {"id": "53315", "name": "Rosemary braised red cabbage with kabanos", "category": "Pork", "area": "Ukrainian", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/s1jxzl1764369317.jpg", "local_image": "53315.jpg", "ingredients": [{"ingredient": "Red Cabbage", "measure": "1/2"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Butter", "measure": "Knob"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Red Wine Vinegar", "measure": "125ml"}, {"ingredient": "Brown Sugar", "measure": "140g"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Rosemary", "measure": "2 sprigs"}, {"ingredient": "Bramley Apples", "measure": "1 chopped"}, {"ingredient": "Kabanos Sausages", "measure": "8"}], "instructions": "step 1\r\nHalve the cabbage, remove the tough stem and thinly slice. Place in a large pan with all the other ingredients apart from the sausages, then mix in 300ml water and some salt and pepper.\r\n\r\nstep 2\r\nBring to a simmer, then reduce the heat, cover with a well-fitting lid and gently cook for 1½ hrs, stirring frequently. If too dry, you can add a little more water.\r\n\r\nstep 3\r\nAdd the kabanos to the cabbage mixture, place a lid on the pan and gently simmer for 20 mins. Remove the lid and cook for a further 10 mins. Serve alongside some simple mash or boiled potatoes.", "equipment_tags": [], "portions": 2, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 1043, "protein_g": 27.5, "carbs_g": 86.9, "fat_g": 65.3, "total_kcal": 2086, "total_protein_g": 54.9, "total_carbs_g": 173.7, "total_fat_g": 130.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Combine and simmer","instruction":"Slice the cabbage, place in a pan with all other ingredients except the sausages, add water and seasoning, bring to a simmer, then cover and cook gently, stirring frequently.","timer_seconds":5400,"background":true},{"step":2,"label":"Add the sausages","instruction":"Add the kabanos, cover, and simmer, then uncover and cook further.","timer_seconds":1800,"background":true},{"step":3,"label":"Serve","instruction":"Serve alongside mash or boiled potatoes.","timer_seconds":null,"background":false}], "video": null}, {"id": "53316", "name": "Beetroot pancakes", "category": "Dessert", "area": "Ukrainian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xlqqhw1764369924.jpg", "local_image": "53316.jpg", "ingredients": [{"ingredient": "Beetroot", "measure": "3"}, {"ingredient": "Milk", "measure": "50 ml"}, {"ingredient": "Self-raising Flour", "measure": "200g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Maple Syrup", "measure": "2 tablespoons"}, {"ingredient": "Vanilla Extract", "measure": "1/2 teaspoon"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Frozen Mixed Berries", "measure": "200g"}, {"ingredient": "Blackcurrant Jam", "measure": "2 tablespoons"}, {"ingredient": "Greek Yogurt", "measure": "100g"}], "instructions": "step 1\r\nPut the beetroot in a jug with the milk and blend with a stick blender until smooth. Pour into a bowl with the rest of the pancake ingredients and whisk until smooth and vibrant purple.\r\n\r\nstep 2\r\nPut a small knob of butter in a large non-stick frying pan and heat over a medium-low heat until melted and foamy. Now create 3 or 4 pancakes each made from 2 tbsp of the batter. Cook for 2-3 mins then flip over and cook for a further minute until cooked through. Repeat with any remaining batter. Heat oven to lowest setting and keep the pancakes warm in there until needed.\r\n\r\nstep 3\r\nServe with your favourite pancake toppings or make a simple compote by simmering frozen berries in with 1 tbsp blackcurrant jam until bubbling and syrupy (about 5-10 mins). In a small bowl stir together the remaining jam and the yogurt. Stack the cooked pancakes with the yogurt and pour the warm berry compote over the top.", "equipment_tags": ["Blender"], "portions": 6, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 291, "protein_g": 10.3, "carbs_g": 42.9, "fat_g": 10.0, "total_kcal": 1748, "total_protein_g": 61.8, "total_carbs_g": 257.6, "total_fat_g": 60.2, "macro_confidence": 0.91, "is_new": false, "cook_steps": [{"step":1,"label":"Blend the batter","instruction":"Blend the beetroot with milk until smooth, then whisk in the remaining pancake ingredients until smooth.","timer_seconds":null,"background":false},{"step":2,"label":"Cook the pancakes","instruction":"Melt butter in a pan and cook pancakes from spoonfuls of batter, flipping once, keeping cooked ones warm in a low oven.","timer_seconds":240,"background":false},{"step":3,"label":"Make the compote and serve","instruction":"Simmer frozen berries with jam until bubbling and syrupy. Stir remaining jam into yogurt. Stack the pancakes with yogurt and pour over the warm compote.","timer_seconds":480,"background":false}], "video": "https://www.youtube.com/watch?v=HzQT0rHKCWM"}, {"id": "53317", "name": "Beef Empanadas", "category": "Beef", "area": "Uruguayan", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/dxpc7j1764370714.jpg", "local_image": "53317.jpg", "ingredients": [{"ingredient": "Lard", "measure": "60g"}, {"ingredient": "Water", "measure": "340g"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "All purpose flour", "measure": "600g"}, {"ingredient": "Tomato", "measure": "3"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Red Onions", "measure": "1 large"}, {"ingredient": "Spring Onions", "measure": "Bunch"}, {"ingredient": "Sirloin steak", "measure": "750g"}, {"ingredient": "Dried Oregano", "measure": "1 tablespoon"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Red Pepper Flakes", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Egg Wash", "measure": "Splash"}, {"ingredient": "Chimichurri sauce", "measure": "Drizzle"}], "instructions": "For the dough place lard, warm water and salt in a large kneading bowl and stir. Add flour and oregano and either knead five miutes by hand or with the kneading function of your machine. Let rest covered for at least half an hour or overnight in the fridge.\r\n\r\n2\r\nFor the filling place tomatoes for about 30 seconds in boiling water, then cool with cold water and peel of skin and cut into cubes. Press garlic through garlic press, cut onions into cubes. Simmer garlic and onions in some olive oil until translucent. Take out onions and garlic and brown the meat at high heat from all sides. Season with all herbs and add the onions, garlic and tomatoes. Let simmer for a few minutes, add salt, pepper and additional spices to taste. You can prepare the meat the night before, chill in fridge if doing so. Boil eggs and also cut into cubes and mix with prepared meat.\r\n\r\n3\r\nCut dough into half and roll out one half thinnly on floured surface. Cut out circles about 12-15cm in diameter. Mine have a diameter of 12.5 cm. Place about 2-4 teaspoons of filling on one circle, put a bit of water all around the edges and fold over the other half so that you get half moons. Be sure to seal the edges with a fork. Repeat until you have no dough and filling left.\r\n\r\n4\r\nMeanwhile preheat oven to 200 degrees Celsius. Brush empanadas with egg wash and bake about 8 empanadas on a baking sheet lined with parchment paper for about 25min or until golden. Serve warm with chimichurri sauce.", "equipment_tags": [], "portions": 5, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 880, "protein_g": 47.7, "carbs_g": 99.7, "fat_g": 30.7, "total_kcal": 4402, "total_protein_g": 238.7, "total_carbs_g": 498.4, "total_fat_g": 153.4, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dough","instruction":"Combine lard, warm water and salt, add flour and oregano, and knead into a dough.","timer_seconds":300,"background":false},{"step":2,"label":"Rest the dough","instruction":"Let rest covered.","timer_seconds":1800,"background":true},{"step":3,"label":"Make the filling","instruction":"Blanch and peel the tomatoes, then cube. Sauté onions and garlic until translucent, remove, then brown the meat, season with herbs, and add back the onions, garlic and tomatoes, simmering briefly.","timer_seconds":600,"background":false},{"step":4,"label":"Boil eggs and combine","instruction":"Boil eggs, cube, and mix with the prepared meat.","timer_seconds":600,"background":false},{"step":5,"label":"Assemble","instruction":"Roll out dough and cut into circles. Place filling on each, moisten edges, fold into half moons, and seal with a fork.","timer_seconds":null,"background":false},{"step":6,"label":"Bake","instruction":"Preheat the oven to 200°C. Brush with egg wash and bake until golden.","timer_seconds":1500,"background":true},{"step":7,"label":"Serve","instruction":"Serve warm with chimichurri sauce.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=RRNVLC6IAv4"}, {"id": "53318", "name": "Torta de fiambre", "category": "Pork", "area": "Uruguayan", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/okl9cm1764371087.jpg", "local_image": "53318.jpg", "ingredients": [{"ingredient": "Cheddar Cheese", "measure": "150g"}, {"ingredient": "Ham", "measure": "200g"}, {"ingredient": "Egg", "measure": "3"}, {"ingredient": "Vegetable Oil", "measure": "100g"}, {"ingredient": "Milk", "measure": "240g"}, {"ingredient": "All purpose flour", "measure": "120g"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Dried Oregano", "measure": "To taste"}], "instructions": "Line the bottom of a springform of 20-2cm (8-9inches) with parchment paper, I usually leave some overhang as the batter is very liquid and may spill a bit. Preheat oven to 220 degrees Celsius.\r\n\r\n2\r\nGrate the cheese and take out the ham.\r\n\r\n3\r\nMix all remaining ingredients in a large bowl for about one to two minutes.\r\n\r\n4\r\nPour half the batter into the prepared pan, it is going to be very liquid. Then place ham and cheese on top and pour the remaining batter on top.\r\n\r\n5\r\nBake for about 20-25 minutes or until top is golden. Wait for a few minutes before releasing from the pan and enjoy either hot or cold with some fresh herbs.", "equipment_tags": [], "portions": 2, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 1291, "protein_g": 59.4, "carbs_g": 56.4, "fat_g": 92.8, "total_kcal": 2583, "total_protein_g": 118.8, "total_carbs_g": 112.8, "total_fat_g": 185.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prep and preheat","instruction":"Line a springform pan with parchment. Preheat the oven to 220°C. Grate the cheese and prepare the ham.","timer_seconds":null,"background":false},{"step":2,"label":"Mix the batter","instruction":"Mix all remaining ingredients in a bowl for one to two minutes.","timer_seconds":90,"background":false},{"step":3,"label":"Layer and pour","instruction":"Pour half the batter into the pan, add the ham and cheese on top, then pour over the remaining batter.","timer_seconds":null,"background":false},{"step":4,"label":"Bake and serve","instruction":"Bake until the top is golden, then wait a few minutes before releasing from the pan and serve hot or cold with fresh herbs.","timer_seconds":1350,"background":true}], "video": "https://www.youtube.com/watch?v=JIDdt3XPi9U"}, {"id": "53319", "name": "Chivito sandwich", "category": "Beef", "area": "Uruguayan", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg", "local_image": "53319.jpg", "ingredients": [{"ingredient": "Milk", "measure": "80g"}, {"ingredient": "Butter", "measure": "60g"}, {"ingredient": "Molasses", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "220g"}, {"ingredient": "Egg", "measure": "9"}, {"ingredient": "Bread Flour", "measure": "500g"}, {"ingredient": "Salt", "measure": "10g"}, {"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "Egg Wash", "measure": "Splash"}, {"ingredient": "Sesame Seed", "measure": "Sprinkling"}, {"ingredient": "Onion", "measure": "4"}, {"ingredient": "Sirloin steak", "measure": "8"}, {"ingredient": "Garlic", "measure": "To serve"}, {"ingredient": "Bacon", "measure": "8"}, {"ingredient": "Ham", "measure": "8 slices"}, {"ingredient": "Mozzarella", "measure": "8 slices"}, {"ingredient": "Tomato", "measure": "4"}, {"ingredient": "Lettuce", "measure": "1/4"}, {"ingredient": "Mustard", "measure": "To serve"}, {"ingredient": "Chimichurri sauce", "measure": "To serve"}], "instructions": "For the brioche buns heat the milk with the butter and molasses until the butter has melted. Add the cold water and egg to this mix.\r\n\r\n2\r\nIn a large bowl place flour, salt and yeast and mix. Then add the milk and water mix and stir with a wooden spoon until combined. You don't have to knead the dough, it is perfectly fine to do this by hand with a wooden spoon, this doesn't need to be very thorough. Cover with a damp towel and stick in the fridge overnight.\r\n\r\n3\r\nThe next morning knead dough on a generously floured surface for a little and cut into eight equal pieces. Shape these into balls and place on a baking sheet lined with parchment paper. Cover again with damp towel and let rise for about an hour or until double in size.\r\n\r\n4\r\nHeat oven to 220 degrees Celsius. Brush the buns with either milk, heavy cream or egg wash and sprinkle with sesame seeds, if desired. Bake for about 15-20min or until golden. Let cool.\r\n\r\n5\r\nFor the toppings chop the onions and sauté in a bit of butter, let caramelize, this may take ten to 15 minutes, stir occasionally. Rub the steaks with a bit of garlic and then grill or fry the steaks, the bacon, and eggs with salt and pepper, toast the buns after having cut in half. Spread mustard on one bun half, layer each chivito with steak, a slice of ham, a slice of cheese, one bacon stripe, a tomato slice, and some lettuce. Place fried egg on top and sprinkle generously with chimichurri and some onions right before serving.", "equipment_tags": ["Grill"], "portions": 7, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 1037, "protein_g": 65.9, "carbs_g": 70.8, "fat_g": 53.7, "total_kcal": 7256, "total_protein_g": 461.1, "total_carbs_g": 495.8, "total_fat_g": 375.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the dough base","instruction":"Heat milk with butter and molasses until the butter melts, then add cold water and egg.","timer_seconds":null,"background":false},{"step":2,"label":"Mix the dough","instruction":"Combine flour, salt and yeast in a bowl, add the milk mixture, and stir with a wooden spoon until combined. Cover and refrigerate overnight.","timer_seconds":43200,"background":true},{"step":3,"label":"Shape and rise","instruction":"Knead the dough briefly, cut into eight pieces, shape into balls, place on a lined tray, cover, and let rise until doubled.","timer_seconds":3600,"background":true},{"step":4,"label":"Bake the buns","instruction":"Heat the oven to 220°C. Brush the buns with egg wash, sprinkle with sesame seeds, and bake until golden. Let cool.","timer_seconds":1050,"background":true},{"step":5,"label":"Caramelise the onions","instruction":"Chop and sauté the onions in butter until caramelized.","timer_seconds":750,"background":false},{"step":6,"label":"Cook the meats and eggs","instruction":"Rub the steaks with garlic, then grill or fry the steaks, bacon and eggs with seasoning. Toast the halved buns.","timer_seconds":480,"background":false},{"step":7,"label":"Assemble and serve","instruction":"Spread mustard on one bun half, layer with steak, ham, cheese, bacon, tomato and lettuce, top with the fried egg, sprinkle with chimichurri and onions, and serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=tX3fN9AG_ik"}, {"id": "53320", "name": "Chocolate alfajores", "category": "Dessert", "area": "Uruguayan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/k9o0xr1764373018.jpg", "local_image": "53320.jpg", "ingredients": [{"ingredient": "Butter", "measure": "150g"}, {"ingredient": "Sugar", "measure": "70g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Honey", "measure": "25g"}, {"ingredient": "All purpose flour", "measure": "175g"}, {"ingredient": "Cornstarch", "measure": "80g"}, {"ingredient": "Unsweetened Cocoa", "measure": "30g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Dulce de leche", "measure": "400g"}, {"ingredient": "Milk Chocolate", "measure": "500g"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Orange", "measure": "Zest of 1"}], "instructions": "For the cookies cream the butter with the sugar for a few minutes. Then add the egg and honey and mix well. Add flour, cornstarch, cocoa, baking soda and baking powder and mix until you get a dough. Wrap in plastic wrap and chill for at least half an hour or overnight.\r\n\r\n2\r\nLine two baking sheets with parchment paper, preheat oven to 200 degrees Celsius.\r\n\r\n3\r\nDivide dough into two parts, put one part back in the fridge before using. Roll out second part to about 2 millimeters and cut out round cookies with 5-6 centimeters in diameter. This can be done with a cookie cutter or glass. You should get 30 cookies in total or even more, I get about 40. Bake one baking sheet at the time for about 8-10min. Let cookies cool.\r\n\r\n4\r\nFor the filling look for two cookies of the same size and place about one teaspoon of dulce de leche onto the bottom one before sandwiching together.\r\n\r\n5\r\nChop semi-sweet chocolate and melt with butter and orange zest on low heat. Dunk each sandwich cookie into the chocolate and let cool off on parchment paper before serving.", "equipment_tags": [], "portions": 11, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 437, "protein_g": 7.0, "carbs_g": 51.4, "fat_g": 23.8, "total_kcal": 4806, "total_protein_g": 76.8, "total_carbs_g": 564.9, "total_fat_g": 262.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the cookie dough","instruction":"Cream the butter with sugar, add egg and honey and mix well, then add flour, cornstarch, cocoa, baking soda and baking powder and mix into a dough.","timer_seconds":null,"background":false},{"step":2,"label":"Chill","instruction":"Wrap and chill.","timer_seconds":1800,"background":true},{"step":3,"label":"Roll and cut","instruction":"Preheat the oven to 200°C and line two baking sheets. Roll out half the dough to 2mm and cut into rounds, keeping the rest chilled.","timer_seconds":null,"background":false},{"step":4,"label":"Bake","instruction":"Bake the cookies one sheet at a time until pale, then cool.","timer_seconds":540,"background":true},{"step":5,"label":"Fill and coat","instruction":"Sandwich pairs of cookies with dulce de leche. Melt chocolate with butter and orange zest, dunk each sandwich cookie in the chocolate, and let cool on parchment.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=ucBoYab5tXY"}, {"id": "53321", "name": "Vanilla alfajores", "category": "Dessert", "area": "Uruguayan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/3wnyvh1764373818.jpg", "local_image": "53321.jpg", "ingredients": [{"ingredient": "Dulce de leche", "measure": "150g"}, {"ingredient": "Coconut Flakes", "measure": "50g"}, {"ingredient": "Butter", "measure": "100g"}, {"ingredient": "Sugar", "measure": "100g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Egg Yolks", "measure": "1"}, {"ingredient": "Cornstarch", "measure": "200g"}, {"ingredient": "All purpose flour", "measure": "100g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Dulce de leche", "measure": "150g"}, {"ingredient": "Coconut Flakes", "measure": "50g"}], "instructions": "For the sandwich cookie cream the soft butter for about a minute, then add the sugar and cream for another two minutes. Incorporate the egg fully before mixing in the egg yolk. Once everything is nicely combined, add all remaining ingredients and mix one more time. Form dough into a ball and wrap in plastic wrap. Chill for at least half an hour or overnight.\r\n\r\n2\r\nPreheat oven to 180 degrees Celsius and line two baking sheets with parchment paper.\r\n\r\n3\r\nDivide dough in half, put one back in the fridge and roll out the other thickly on a lightly floured surface. Cut out cookies with either the bottom of a glass or a cookie cutter around 6cm in diameter. Repeat with all the dough.\r\n\r\n4\r\nBake for about 8-10min, the cookies will look very pale. Let cool off before filling half with each a teaspoon of dulce de leche. Place other half of cookies on top and roll the sides of each cookie in the coconut flakes (it helps if the dulce de leche was pressed down to the sides of the cookie). Enjoy.", "equipment_tags": [], "portions": 7, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 584, "protein_g": 7.7, "carbs_g": 78.8, "fat_g": 27.1, "total_kcal": 4085, "total_protein_g": 53.9, "total_carbs_g": 551.5, "total_fat_g": 189.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the cookie dough","instruction":"Cream the soft butter for a minute, add sugar and cream further, then incorporate the egg and egg yolk. Add the remaining ingredients and mix.","timer_seconds":180,"background":false},{"step":2,"label":"Chill","instruction":"Form into a ball, wrap, and chill.","timer_seconds":1800,"background":true},{"step":3,"label":"Roll and cut","instruction":"Preheat the oven to 180°C and line two baking sheets. Roll out half the dough thickly and cut out cookies, keeping the rest chilled.","timer_seconds":null,"background":false},{"step":4,"label":"Bake","instruction":"Bake until pale, then let cool.","timer_seconds":570,"background":true},{"step":5,"label":"Fill and coat","instruction":"Fill half the cookies with dulce de leche, sandwich with the other half, and roll the sides in coconut flakes.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=9MncGG2cH_g"}, {"id": "53322", "name": "Flan", "category": "Dessert", "area": "Uruguayan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0s80wo1764374393.jpg", "local_image": "53322.jpg", "ingredients": [{"ingredient": "Sugar", "measure": "100g"}, {"ingredient": "Milk", "measure": "350g"}, {"ingredient": "Sugar", "measure": "45g"}, {"ingredient": "vanilla pod", "measure": "1"}, {"ingredient": "Egg Yolks", "measure": "4"}, {"ingredient": "Egg", "measure": "2"}, {"ingredient": "Dulce de leche", "measure": "To taste"}], "instructions": "For the caramel place 100 grams of sugar in a frying pan without any fat and melt on medium heat. Try not to stir with a spoon, but swirl the pan itself. Let melt until you have an amber color and sugar is fully melted. Fill the bottom of four flan containers with it. Caramel will harden immediately, so you need to be fast. My containers yield about 120 milliliters each.\r\n\r\n2\r\nPreheat oven to 150 degrees Celsius and look for a casserole or container all your four flan containers fit into.\r\n\r\n3\r\nHeat milk with 45 grams of sugar and the cut and scraped out vanilla pod. The milk does not need to boil, just needs to be heated. Take out vanilla pod after a few minutes. Meanwhile stir the egg yolks and eggs gently, try not to incorporate any air in it. Them pour milk-mix into egg-mix and again only stir very gently. Pour into prepared flan containers and place these into your casserole or container. Boil water and pour the water into the large casserole. Be sure not to touch the flan mixture. Place on middle rack in the oven and let bake for about 35-40 minutes. An inserted toothpick should come out clean.\r\n\r\n4\r\nLet cool inside the container for an hour before transferring to the fridge. Chill overnight. The next day gently release the rim and then turn upside down on a plate. Serve with some dulce de leche on the side.", "equipment_tags": [], "portions": 6, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 285, "protein_g": 9.4, "carbs_g": 29.5, "fat_g": 12.6, "total_kcal": 1709, "total_protein_g": 56.3, "total_carbs_g": 177.0, "total_fat_g": 75.7, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Make the caramel","instruction":"Melt sugar in a dry frying pan over medium heat, swirling the pan, until amber and fully melted, then quickly pour into the flan containers.","timer_seconds":300,"background":false},{"step":2,"label":"Preheat","instruction":"Preheat the oven to 150°C and find a casserole dish to fit the flan containers.","timer_seconds":null,"background":false},{"step":3,"label":"Make the custard","instruction":"Heat milk with sugar and vanilla pod until warm, remove the pod, gently stir eggs and yolks, then pour the milk into the eggs, stirring gently.","timer_seconds":null,"background":false},{"step":4,"label":"Bake in a water bath","instruction":"Pour into the caramel-lined containers, place in the casserole, add boiling water around them, and bake until a toothpick comes out clean.","timer_seconds":2250,"background":true},{"step":5,"label":"Cool and chill","instruction":"Let cool in the container for an hour, then chill overnight.","timer_seconds":3600,"background":true},{"step":6,"label":"Unmould and serve","instruction":"Release the rim and turn upside down onto a plate, serving with dulce de leche on the side.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=rpv_PXIoysE"}, {"id": "53323", "name": "Postre Chajá", "category": "Dessert", "area": "Uruguayan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wii0591764375062.jpg", "local_image": "53323.jpg", "ingredients": [{"ingredient": "Egg", "measure": "5"}, {"ingredient": "Sugar", "measure": "100g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "All purpose flour", "measure": "75g"}, {"ingredient": "Cornstarch", "measure": "30g"}, {"ingredient": "Egg White", "measure": "1"}, {"ingredient": "Sugar", "measure": "50g"}, {"ingredient": "Dulce de leche", "measure": "200g"}, {"ingredient": "Heavy Cream", "measure": "400g"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "40g"}, {"ingredient": "Peaches", "measure": "500g"}, {"ingredient": "Peach Juice", "measure": "50 ml"}, {"ingredient": "Cornstarch", "measure": "1 tsp"}], "instructions": "For the sponge cake preheat oven to 180 degrees Celsius and prepare either one or two 20cm/8 inch cake pan(s). Line bottom with parchment paper. Then divide the eggs into egg white and egg yolks. Use a bigger bowl for the egg yolks. If you have a glass or metal bowl, use that one for the egg whites. Be sure that bowl is free of fat/grease and that your mixer was properly cleaned. First beat the egg whites on medium speed with a pinch of salt until soft peaks form. Set aside. Without cleaning our mixer, beat the egg yolks with the sugar. Beat until the color becomes much paler and you have a creamy consistency. This usually takes several minutes.\r\n\r\n2\r\nGently pour one third of the egg whites on top of the mixed egg yolks and sift the flour and cornstarch on top. Don't skip this step. It is important that the flour mix was sifted. Gently mix all ingredients with a spatula. Try to incorperate the flour mix and egg whites without losing volume. Add the last two thirds of beaten egg whites and gently fold the mixture. Don't overmix. Put batter into the prepared cake pans and immediately bake. Don't let the batter sit for too long as it will quickly lose volume. Bake for 35 minutes if using one springform or 25 minutes if using two. Let cool a little before gently getting them out of the form. Tip: if making the day before, wrap in cling wrap, it is much easier to cut in half once cold.\r\n\r\n3\r\nFor the meringue beat egg white until soft peaks form, add pinch of salt and continue beating on high while adding the sugar. Beat for at least three more minutes until glossy and shiny. Pipe small stars or other shapes with the meringue on a baking sheet lined with parchment paper. Dry for about 45min at 100 degrees Celsius in the oven. Keep in airtight container until further use.\r\n\r\n4\r\nFor the filling beat heavy cream, vanilla extract and sugar until stiff peaks form, slice peaches in thin slices. Cut cake in four layers, this is much easier done once the cake layers are cold. Brush cake layer with some of the peach juice left, then pipe thin layer of whipped cream around the edges, place the peach slices in the middle on first layer on cake, on the second layer only spread the dulce de leche. Repeat layer with brushed peach juice, whipped cream and peaches for the third and final layer. Be sure to reserve enough peach slices for the top. Spread thin layer of whipped cream on the sides of the cake and pipe on some roses around the edges if desired. Heat the peach juice and mix the cornstarch with a bit of water until you see no lumps. Once juice is hot, add the cornstarch and stir until glaze thickenes. Pour over peaches of the top layer cake. Crush the meringue and pat around the sides. Serve immediately.\r\n\r\n", "equipment_tags": [], "portions": 12, "prep_minutes": 105, "prep_minutes_source": "explicit", "kcal": 352, "protein_g": 6.6, "carbs_g": 38.5, "fat_g": 19.6, "total_kcal": 4224, "total_protein_g": 79.7, "total_carbs_g": 462.3, "total_fat_g": 235.6, "macro_confidence": 0.93, "is_new": false, "cook_steps": [{"step":1,"label":"Whip the eggs for the sponge","instruction":"Preheat the oven to 180°C and prepare cake pans. Whisk egg whites with salt to soft peaks, set aside, then beat egg yolks with sugar until pale and creamy.","timer_seconds":300,"background":false},{"step":2,"label":"Fold and bake","instruction":"Fold a third of the egg whites into the yolks with the sifted flour and cornstarch, then fold in the rest of the whites gently. Bake immediately until done.","timer_seconds":1500,"background":true},{"step":3,"label":"Cool the cake","instruction":"Let cool a little before removing from the pans.","timer_seconds":600,"background":true},{"step":4,"label":"Make the meringue","instruction":"Whisk egg white to soft peaks with salt, then beat in sugar on high until glossy. Pipe shapes onto a lined sheet and dry in a low oven.","timer_seconds":2700,"background":true},{"step":5,"label":"Make the filling","instruction":"Beat cream, vanilla and sugar to stiff peaks, and slice the peaches.","timer_seconds":null,"background":false},{"step":6,"label":"Assemble","instruction":"Cut the cake into four layers, brush each with peach juice, pipe whipped cream, layer with peaches on the first layer and dulce de leche on the second, and repeat.","timer_seconds":null,"background":false},{"step":7,"label":"Glaze and finish","instruction":"Heat peach juice, thicken with a cornstarch slurry, pour over the top peaches, crush the meringue and pat around the sides, then serve immediately.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=-O6MsNm39Yw"}, {"id": "53324", "name": "Chocolate empanadas", "category": "Dessert", "area": "Uruguayan", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/u9ezi21764375474.jpg", "local_image": "53324.jpg", "ingredients": [{"ingredient": "Condensed Milk", "measure": "400g"}, {"ingredient": "All purpose flour", "measure": "250g"}, {"ingredient": "Unsweetened Cocoa", "measure": "25g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Milk", "measure": "3  tablespoons"}, {"ingredient": "Butter", "measure": "30g"}, {"ingredient": "Sugar", "measure": "30g"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}], "instructions": "For the filling place the can in a large pot and cover completely with water. Boil for two and a half hours, occassionally adding water. Let cool before opening. For further tips, please check here.\r\n\r\n2\r\nFor the dough combine the flour, cocoa powder, and salt in a large bowl. Add the cold butter in small pieces and rub into crumbs with your fingers Add the egg and work into a dough. You may have to add milk, a tablespoon at a time if it still is to dry. Wrap and chill for at least half an hour or overnight.\r\n\r\n3\r\nLine a baking sheeet with parchment paper and preheat the oven to 180 degrees Celsius.\r\n\r\n4\r\nRoll out the dough on a lightly floured surface, it should be thin. Cut out circles of 12cm either with a cookie cutter or with a smaller plate/dish. Put two to three teaspoons of the dulce de leche in the middle of each circle. Brush the edges with milk, I do this with my pinkie. Fold each circle in half so that you have a half moon and press down the edges with a fork. You can also turn the edges about half a centimeter inwards every centimeter or so to create a pattern.\r\n\r\n5\r\nPlace the prepared empanadas on the baking sheet and brush with egg wash. Bake for about 20-25min.\r\n\r\n6\r\nTowards the end of the baking time, melt the remaining butter and mix the sugar and cinnamon in a small bowl. Once you take the empanadas out, immediately brush with the butter and sprinkle with the sugar mix. Empanadas can be enjoyed either still warm or cold. If eating warm, be careful not to burn yourself with hot filling!", "equipment_tags": [], "portions": 6, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 425, "protein_g": 8.7, "carbs_g": 43.4, "fat_g": 25.2, "total_kcal": 2550, "total_protein_g": 52.3, "total_carbs_g": 260.6, "total_fat_g": 151.3, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Prepare the dulce de leche","instruction":"Boil the unopened can of condensed milk fully submerged in water, occasionally topping up, then let cool before opening.","timer_seconds":9000,"background":true},{"step":2,"label":"Make the dough","instruction":"Combine flour, cocoa and salt, rub in cold butter, add egg and work into a dough, adding milk if too dry.","timer_seconds":null,"background":false},{"step":3,"label":"Chill","instruction":"Wrap and chill.","timer_seconds":1800,"background":true},{"step":4,"label":"Preheat","instruction":"Line a baking sheet and preheat the oven to 180°C.","timer_seconds":null,"background":false},{"step":5,"label":"Roll and fill","instruction":"Roll out the dough thinly and cut circles, place dulce de leche in the middle of each, brush edges with milk, fold into half moons, and seal with a fork.","timer_seconds":null,"background":false},{"step":6,"label":"Bake","instruction":"Brush with egg wash and bake.","timer_seconds":1350,"background":true},{"step":7,"label":"Finish and serve","instruction":"Melt butter, mix sugar and cinnamon, brush the warm empanadas with butter, and sprinkle with the cinnamon sugar. Serve warm or cold.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=Cdo14aXSHrA"}, {"id": "53325", "name": "Venezuelan Arepas", "category": "Side", "area": "Venezuela", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/3hcy191764376285.jpg", "local_image": "53325.jpg", "ingredients": [{"ingredient": "Cornmeal", "measure": "2 cups"}, {"ingredient": "Water", "measure": "2 1/2 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}], "instructions": "Preheat oven to 410° F.\r\nPour the water into a large bowl. Make sure it is room temperature.\r\nAdd the salt. Blend well with a mixer, fork or spatula to make sure it dissolves well.\r\nWhile you continue to beat the mixture, slowly add the corn meal—a little bit at a time.\r\nOnce all the flour is added, keep mixing until the corn meal, water and salt are thoroughly blended and dissolved.\r\nSet aside the masa in its bowl. Let it rest for 5 minutes so that the flour is thoroughly hydrated. This type of corn flour does not have any gluten, so it doesn’t need to be kneaded. The masa should be smooth, firm yet malleable.\r\nWhile waiting for the 5 minutes’ rest, heat your budare (or comal, griddle, cast-iron pan or non-stick pan) over medium heat. Coat with a little bit of the oil.\r\nFill a small bowl with water to wet your hands to make the arepas.\r\nTake about 2 Tbsp of the masa in your damp hands. The masa should fit easily in your palm so that it is easy to shape into a small ball.\r\n\r\nCross your hands, so that one is on top of the other, with the masa ball between them. Rotate your right hand in a circle, so that you are at the same time both pressing the masa into a flat disc and keeping its round shape.\r\narepa making\r\nThe last step in shaping your arepa is to quickly pass and lightly press the masa disc from one hand to the other until it is about ¾ of an inch thick and 4 inches wide. Smooth the edges with your fingertips (quickly dip them into the water bowl first) so that they stay as round as possible and without cracks.\r\narepa making\r\nPlace your arepas in batches on the preheated surface of your budare griddle or nonstick pan. Let each side turn golden, about 4 to 5 minutes per side. Check them often so that they don’t burn.\r\nOnce they are nicely browned on both sides, place the arepas on a baking sheet in your preheated oven for 10 minutes. They should be somewhat puffy, so that if you tap an arepa lightly on top, it will sound like you are tapping an empty box.\r\nServe arepas hot, whether you stuff with them with your choice of fillings or serve solo to accompany your favorite Venezuelan guiso or stew.", "equipment_tags": [], "portions": 6, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 316, "protein_g": 6.5, "carbs_g": 63.2, "fat_g": 5.2, "total_kcal": 1898, "total_protein_g": 38.9, "total_carbs_g": 379.2, "total_fat_g": 31.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Preheat","instruction":"Preheat the oven to 210°C/410°F.","timer_seconds":null,"background":false},{"step":2,"label":"Make the masa","instruction":"Dissolve salt in room-temperature water, then gradually beat in the cornmeal until thoroughly blended.","timer_seconds":null,"background":false},{"step":3,"label":"Rest the masa","instruction":"Let the masa rest so the flour hydrates.","timer_seconds":300,"background":true},{"step":4,"label":"Heat the griddle","instruction":"Heat a griddle or pan over medium heat and coat with oil.","timer_seconds":null,"background":false},{"step":5,"label":"Shape the arepas","instruction":"With damp hands, shape portions of masa into balls, then flatten between your palms into discs about ¾ inch thick and 4 inches wide, smoothing the edges.","timer_seconds":null,"background":false},{"step":6,"label":"Cook on the griddle","instruction":"Cook the arepas in batches on the griddle until golden on each side.","timer_seconds":540,"background":false},{"step":7,"label":"Finish in the oven","instruction":"Transfer to a baking sheet and bake until they sound hollow when tapped.","timer_seconds":600,"background":true},{"step":8,"label":"Serve","instruction":"Serve hot, stuffed with fillings or alongside a stew.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=kbvh5XaBpJk"}, {"id": "53326", "name": "Venezuelan Sancocho", "category": "Beef", "area": "Venezuela", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/8859m71764377470.jpg", "local_image": "53326.jpg", "ingredients": [{"ingredient": "Hind Shank", "measure": "2 Lbs"}, {"ingredient": "Onion", "measure": "2 small"}, {"ingredient": "Pepper", "measure": "1/2"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Leek", "measure": "1"}, {"ingredient": "Beef Stock", "measure": "8 cups"}, {"ingredient": "Sweet Red Peppers", "measure": "1/2 cup"}, {"ingredient": "Scallions", "measure": "1/2 cup"}, {"ingredient": "Sweetcorn", "measure": "2"}, {"ingredient": "Cassaba", "measure": "1/2 lb"}, {"ingredient": "Yautia", "measure": "1/2 lb"}, {"ingredient": "White Yam", "measure": "1/2 lb"}, {"ingredient": "Butternut Squash", "measure": "1/2 lb"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Cilantro", "measure": "Chopped"}], "instructions": "Add hind shank, 1 halved small onion, halved bell pepper, 4 whole garlic cloves, the dark green leaves of the leek, and stock to a large stockpot. Cook for 45-60 minutes until the meat is fork-tender. NOTE: the meat can take a bit longer to be fork-tender; that is okay, just add more cooking time if necessary.\r\nWhen the meat is tender, remove the big pieces of vegetables and bones. Discard.\r\nAdd diced onion, 2 minced garlic, mini sweet peppers, sliced leeks (light green part), scallions, yucca, and corn; Mix and simmer covered over medium heat for 5- 8 minutes, until the yucca is starting to soften. NOTE: the yuca can take a bit longer to start softening; that is okay, just add more cooking time if necessary.\r\nAdd yautia, white yam, and butternut squash. Mix to combine. Simmer covered over medium heat for 5 – 6 minutes, until all the root vegetables are tender. NOTE: Do not cook too much, or they will fall apart.\r\nTaste and add salt to your taste, if necessary. Add cilantro and the remaining 2 minced garlic cloves. Mix and let simmer for 2 more minutes.\r\nServe hot in large soup bowls, dividing the meat and vegetables evenly. Add a squish of lime juice and/or hot sauce, if desired. Serve along with arepas and or casabe (cassava bread).", "equipment_tags": [], "portions": 9, "prep_minutes": 74, "prep_minutes_source": "explicit", "kcal": 318, "protein_g": 11.5, "carbs_g": 37.8, "fat_g": 14.7, "total_kcal": 2864, "total_protein_g": 103.4, "total_carbs_g": 340.2, "total_fat_g": 131.9, "macro_confidence": 0.76, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the meat","instruction":"Add hind shank, half an onion, halved pepper, whole garlic cloves, leek greens and stock to a large pot, and cook until the meat is fork-tender.","timer_seconds":3000,"background":true},{"step":2,"label":"Discard aromatics","instruction":"Remove the large vegetable pieces and bones and discard.","timer_seconds":null,"background":false},{"step":3,"label":"Add the first vegetables","instruction":"Add diced onion, minced garlic, mini peppers, leeks, scallions, yucca and corn, mix, and simmer covered until the yucca starts to soften.","timer_seconds":420,"background":true},{"step":4,"label":"Add root vegetables","instruction":"Add yautia, white yam and butternut squash, mix, and simmer covered until tender without falling apart.","timer_seconds":330,"background":true},{"step":5,"label":"Finish and serve","instruction":"Taste and season with salt, add cilantro and remaining garlic, simmer briefly, then serve hot with lime juice or hot sauce and arepas.","timer_seconds":120,"background":false}], "video": "https://www.youtube.com/watch?v=w6KNOKkcRBs"}, {"id": "53327", "name": "Venezuelan Coconut Chicken", "category": "Chicken", "area": "Venezuela", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/z2sw3o1764378271.jpg", "local_image": "53327.jpg", "ingredients": [{"ingredient": "Chicken Breasts", "measure": "2"}, {"ingredient": "Onion", "measure": "2 chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Bay Leaves", "measure": "4"}, {"ingredient": "Black Pepper", "measure": "Pinch"}, {"ingredient": "Turmeric", "measure": "Pinch"}, {"ingredient": "Cumin", "measure": "Pinch"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Tomato", "measure": "3"}, {"ingredient": "Ginger Paste", "measure": "1 tablespoon"}, {"ingredient": "Olive Oil", "measure": "1/3 cup"}, {"ingredient": "Coconut Milk", "measure": "1 Can"}, {"ingredient": "Water", "measure": "1/2 cup"}], "instructions": "Cut the chicken up into bite size pieces. Peel and cut the onions, mince the garlic.\r\nAssemble the rest of the ingredients and you are ready to start cooking.\r\nMake the Dish\r\nHeat up a fry pan over medium heat. Add the oil and when hot, sauté the onion until translucent. Remove from pan and transfer to a blender or food processor.\r\nAdd tomatoes, garlic, turmeric, cumin, sugar, ginger paste, coconut milk, water and blend smooth.\r\nIn the same pan you cooked the onion, add the chicken and brown all sides. This should take about 3 minutes.\r\nAdd the blender ingredients and bay leaves to the pan, bring to a simmer and cook until the chicken is white inside and the liquid is creamy. (15 to 20 minutes)\r\nRemove the bay leaves and serve with white rice.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 3, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 716, "protein_g": 27.5, "carbs_g": 24.1, "fat_g": 59.5, "total_kcal": 2147, "total_protein_g": 82.6, "total_carbs_g": 72.4, "total_fat_g": 178.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Sauté the onion","instruction":"Heat oil in a frying pan and sauté the onion until translucent, then transfer to a blender.","timer_seconds":300,"background":false},{"step":2,"label":"Blend the sauce","instruction":"Add tomatoes, garlic, turmeric, cumin, sugar, ginger paste, coconut milk and water to the blender and blend smooth.","timer_seconds":null,"background":false},{"step":3,"label":"Brown the chicken","instruction":"In the same pan, add the chicken and brown all sides.","timer_seconds":180,"background":false},{"step":4,"label":"Simmer","instruction":"Add the blended sauce and bay leaves, bring to a simmer, and cook until the chicken is cooked through and the sauce creamy.","timer_seconds":1050,"background":true},{"step":5,"label":"Serve","instruction":"Remove the bay leaves and serve with white rice.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=32rCc85rZJA"}, {"id": "53328", "name": "Venezuelan Shredded Beef", "category": "Beef", "area": "Venezuela", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/mq27gf1764436795.jpg", "local_image": "53328.jpg", "ingredients": [{"ingredient": "Skirty Steak", "measure": "2 Lbs"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Tomato", "measure": "3 sliced thinly"}, {"ingredient": "Beef Stock", "measure": "4 cups"}, {"ingredient": "Worcestershire Sauce", "measure": "2 tsp"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Tomato Ketchup", "measure": "1/4 cup"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}], "instructions": "Season beef with salt, pepper and minced garlic\r\nChop 1 onion in 4 big wedges\r\nPlace in the beef pressure cooker with the 4 wedges of onion and the stock\r\nPressure cook for 20 minutes\r\nRelease the pressure and open the lid\r\nRemove the beef and SAVE 2 cups of stock in another container\r\nWith 2 forks, shred the beef. Beef should be tender enough to so easily. If not, cook for another 10 minutes\r\nPress the saute button of the Instant pot. Add the olive oil\r\nWhen the machine beeps, add the sliced onion, pepper and tomatoes. Cook until tender\r\nAdd the shredded beef back in the pot and mix\r\nPour in 1 1/2 cups of the saved stock, the Worcestershire sauce, tomato paste, ketchup and cumin. Mix\r\nIf sauce seems to dry, add a tad more of stock\r\nSeason with salt and pepper\r\nServe!", "equipment_tags": [], "portions": 5, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 361, "protein_g": 38.8, "carbs_g": 10.2, "fat_g": 17.9, "total_kcal": 1807, "total_protein_g": 193.9, "total_carbs_g": 50.9, "total_fat_g": 89.5, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Season and pressure cook","instruction":"Season the beef with salt, pepper and minced garlic. Add to a pressure cooker with onion wedges and stock, and pressure cook.","timer_seconds":1200,"background":true},{"step":2,"label":"Shred the beef","instruction":"Release the pressure, remove the beef reserving 2 cups of stock, and shred with two forks.","timer_seconds":null,"background":false},{"step":3,"label":"Sauté the vegetables","instruction":"Sauté the sliced onion, pepper and tomatoes in olive oil until tender.","timer_seconds":300,"background":false},{"step":4,"label":"Combine and finish","instruction":"Add the shredded beef back in, pour in the reserved stock, Worcestershire sauce, tomato paste, ketchup and cumin, and mix, adding more stock if too dry.","timer_seconds":null,"background":false},{"step":5,"label":"Serve","instruction":"Season with salt and pepper and serve.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=TPn1BKS5Eio"}, {"id": "53329", "name": "Arepa pelua", "category": "Beef", "area": "Venezuela", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/jgl9qq1764437635.jpg", "local_image": "53329.jpg", "ingredients": [{"ingredient": "Beef", "measure": "500g"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Red Pepper", "measure": "1"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Oregano", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Beef Stock", "measure": "1 L"}, {"ingredient": "Water", "measure": "2 1/2 cups"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Cheese", "measure": "200g"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "Pinch"}], "instructions": "Cook the meat: Place the flank steak in a pot with broth or water and salt. Cook over low heat for about 2 hours, until tender and easy to shred.\r\nShred the meat: Once cooked, drain and shred the meat using two forks.\r\nPrepare the vegetables: Sauté chopped onion, bell pepper, and garlic in a little oil. Add cumin, oregano, paprika, and salt. Stir in the meat and cook for a few minutes until the flavors are well combined.\r\nMake the dough: In a bowl, mix the cornmeal with warm water and salt until a soft dough forms. Let it rest for 5 minutes.\r\nForm the arepas: Divide the dough into 6 portions, shape into balls, and flatten into thick discs.\r\nCook: Cook the arepas on a griddle or skillet over medium heat for 2–3 minutes on each side until golden. You can then bake them for a few minutes if you prefer them crispier.\r\nFill: Slice the arepas open on one side, fill with the hot shredded beef, and top with grated cheese.", "equipment_tags": [], "portions": 5, "prep_minutes": 128, "prep_minutes_source": "explicit", "kcal": 351, "protein_g": 31.3, "carbs_g": 6.3, "fat_g": 22.9, "total_kcal": 1754, "total_protein_g": 156.6, "total_carbs_g": 31.6, "total_fat_g": 114.6, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Simmer the meat","instruction":"Place the flank steak in a pot with broth or water and salt, and cook over low heat until tender and easy to shred.","timer_seconds":7200,"background":true},{"step":2,"label":"Shred","instruction":"Drain and shred the meat using two forks.","timer_seconds":null,"background":false},{"step":3,"label":"Sauté and combine","instruction":"Sauté chopped onion, pepper and garlic in oil, add cumin, oregano, paprika and salt, then stir in the meat and cook until combined.","timer_seconds":480,"background":false},{"step":4,"label":"Make the arepa dough","instruction":"Mix cornmeal with warm water and salt into a soft dough and let it rest.","timer_seconds":300,"background":true},{"step":5,"label":"Shape and cook the arepas","instruction":"Divide the dough into 6 balls, flatten into thick discs, and cook on a griddle or skillet on each side until golden, baking further if you prefer them crispier.","timer_seconds":300,"background":false},{"step":6,"label":"Fill and serve","instruction":"Slice the arepas open, fill with the hot shredded beef, and top with grated cheese.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=bSWoRyWI6Fo"}, {"id": "53330", "name": "Cassava pizza", "category": "Pork", "area": "Venezuela", "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/lrfdwz1764438393.jpg", "local_image": "53330.jpg", "ingredients": [{"ingredient": "Casabe", "measure": "6 cut thick slices"}, {"ingredient": "Tomato Sauce", "measure": "450g"}, {"ingredient": "Chorizo", "measure": "225g"}, {"ingredient": "Turkey Ham", "measure": "225g"}, {"ingredient": "Sweetcorn", "measure": "75g"}, {"ingredient": "Green Olives", "measure": "40g"}, {"ingredient": "Paprika", "measure": "55g"}, {"ingredient": "Mozzarella", "measure": "50g"}], "instructions": "Preheat the oven to 200ºC.\r\nCut the bacon or chorizo into medium pieces and the paprika into strips.\r\nSpread a little tomato sauce and mozzarella cheese on each portion of cassava.\r\nAdd the bacon or chorizo, corn, turkey ham, some olives and paprika.\r\nBake for 7 to 10 minutes.\r\nRemove from the oven and enjoy.", "equipment_tags": [], "portions": 3, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 759, "protein_g": 49.1, "carbs_g": 37.9, "fat_g": 47.7, "total_kcal": 2276, "total_protein_g": 147.2, "total_carbs_g": 113.8, "total_fat_g": 143.1, "macro_confidence": 0.88, "is_new": false, "cook_steps": [{"step":1,"label":"Preheat and prep toppings","instruction":"Preheat the oven to 200°C. Cut the chorizo into pieces and the paprika into strips.","timer_seconds":null,"background":false},{"step":2,"label":"Build the pizzas","instruction":"Spread tomato sauce and mozzarella on each cassava slice, then top with chorizo, corn, turkey ham, olives and paprika.","timer_seconds":null,"background":false},{"step":3,"label":"Bake and serve","instruction":"Bake until heated through and the cheese has melted, then serve.","timer_seconds":510,"background":true}], "video": "https://www.youtube.com/watch?v=3fK4zsa2AYM"}, {"id": "53331", "name": "Oatmeal pancakes", "category": "Breakfast", "area": "Venezuela", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/c400ok1764439058.jpg", "local_image": "53331.jpg", "ingredients": [{"ingredient": "Egg", "measure": "1 medium"}, {"ingredient": "Milk", "measure": "80 ml"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Vanilla Extract", "measure": "1 dash"}, {"ingredient": "Ground Oats", "measure": "150g"}, {"ingredient": "Butter", "measure": "150g"}, {"ingredient": "Sugar Syrup", "measure": "1 tablespoon"}, {"ingredient": "Strawberries", "measure": "3"}], "instructions": "Place all the ingredients in the glass and beat.\r\nLet the mixture stand for 10 minutes.\r\nGrease a hot frying pan with a little butter and pour a little of the mixture.\r\nWhen it starts to bubble on the surface, turn over with a spatula. Cook over medium-low heat so that they do not burn.\r\nFinally, add the caramel and strawberries.", "equipment_tags": [], "portions": 2, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 982, "protein_g": 18.5, "carbs_g": 75.2, "fat_g": 70.0, "total_kcal": 1963, "total_protein_g": 37.0, "total_carbs_g": 150.4, "total_fat_g": 140.1, "macro_confidence": 1.0, "is_new": false, "cook_steps": [{"step":1,"label":"Blend the batter","instruction":"Place all the batter ingredients in a blender and beat together.","timer_seconds":null,"background":false},{"step":2,"label":"Rest","instruction":"Let the mixture stand.","timer_seconds":600,"background":true},{"step":3,"label":"Cook the pancakes","instruction":"Grease a hot pan with butter, pour in a little batter, and cook over medium-low heat, flipping when bubbles form on the surface.","timer_seconds":240,"background":false},{"step":4,"label":"Serve","instruction":"Top with caramel and strawberries.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=kkrRFWN4LG4"}, {"id": "53332", "name": "Venezuelan turnovers", "category": "Side", "area": "Venezuela", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/zjtfp31764440795.jpg", "local_image": "53332.jpg", "ingredients": [{"ingredient": "Ground Beef", "measure": "450g"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Ground Cumin", "measure": "Pinch"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 cup"}, {"ingredient": "Green Pepper", "measure": "1/2 cup"}, {"ingredient": "Red Pepper", "measure": "1/2 cup"}, {"ingredient": "Garlic Powder", "measure": "1 tsp"}, {"ingredient": "Capers", "measure": "1/4 cup"}, {"ingredient": "Tomato Sauce", "measure": "1 Can"}, {"ingredient": "Sazon", "measure": "1 Can"}, {"ingredient": "Yellow Masarepa", "measure": "2"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "Season meat with Adobo. In skillet, heat oil on medium high. Cook meat until pink is gone. Stir in onion, pepper, garlic, alcaparras, tomato sauce and Sazón. Cook, stirring often until most of the liquid has evaporated (about 20 minutes). Cool.\r\nPrepared dough should be moist and should hold together, but it should not stick to your fingers. Start with about ½ cup of dough and roll into a ball between palms of your hands. Working on a sheet of non-stick parchment paper, form the ball into a 5-inch circle about ⅛ inch thick. Place a generous tbsp. of filling on one half of circle and using parchment paper close dough over to form a semi-circle. To seal and trim edges of the empanada, press lip of inverted bowl over semi-circle shaped patty. Repeat for all the Empanadas.\r\nIn large skillet on medium high, heat ½ inch of oil until hot but not smoking. Cook empanadas in batches, turning once or twice until lightly browned. Drain on paper towel. Do not over crowd skillet or let oil get too hot.", "equipment_tags": [], "portions": 11, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 230, "protein_g": 10.2, "carbs_g": 11.9, "fat_g": 16.0, "total_kcal": 2534, "total_protein_g": 111.9, "total_carbs_g": 130.8, "total_fat_g": 176.1, "macro_confidence": 0.85, "is_new": false, "cook_steps": [{"step":1,"label":"Cook the filling","instruction":"Season the meat and cook in a hot skillet until no longer pink. Stir in onion, pepper, garlic, capers, tomato sauce and sazón, and cook, stirring, until most of the liquid has evaporated.","timer_seconds":1200,"background":true},{"step":2,"label":"Cool","instruction":"Cool the filling.","timer_seconds":null,"background":true},{"step":3,"label":"Shape the empanadas","instruction":"Roll dough into balls, flatten into circles, add filling to one half, and fold over to seal, trimming edges with an inverted bowl.","timer_seconds":null,"background":false},{"step":4,"label":"Fry","instruction":"Heat oil in a large skillet and cook the empanadas in batches, turning, until lightly browned, then drain on paper towel.","timer_seconds":480,"background":false}], "video": "https://www.youtube.com/watch?v=OfuQf6sCycU"}, {"id": "53333", "name": "Passion fruit mousse", "category": "Dessert", "area": "Venezuela", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/gkcdpl1764441325.jpg", "local_image": "53333.jpg", "ingredients": [{"ingredient": "Unflavoured Gelatin", "measure": "1 ½ tbsp"}, {"ingredient": "Passion Fruit Pulp", "measure": "1"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Condensed Milk", "measure": "1 Can"}, {"ingredient": "Egg White", "measure": "6"}, {"ingredient": "Mint", "measure": "1 Sprig"}], "instructions": "Add gelatin and ¼ cup room-temperature water to small bowl; let sit until gelatin softens, about 5 minutes. In medium saucepan over medium-high heat, stir together passion fruit pulp, sugar and gelatin mixture. Cook, stirring occasionally, until mixture is thoroughly combined and smooth (mixture should not come to a boil). Remove from heat; cool completely. Stir in condensed milk.\r\nMeanwhile, in clean mixing bowl, using electric mixer, beat egg whites until stiff (peaks of egg whites will not droop, and egg whites will not move when bowl is tilted).\r\nStir 1/3 egg whites into cooled passion fruit mixture until combined. Using spatula, gently fold in remaining egg whites until combined. Divide mousse evenly among clear glass serving cups; cover. Refrigerate mousse until well chilled, at least 2 hrs.\r\nServe chilled. Garnish with mint, if desired.", "equipment_tags": [], "portions": 9, "prep_minutes": 125, "prep_minutes_source": "explicit", "kcal": 202, "protein_g": 7.4, "carbs_g": 32.5, "fat_g": 5.1, "total_kcal": 1818, "total_protein_g": 66.2, "total_carbs_g": 292.5, "total_fat_g": 45.9, "macro_confidence": 0.67, "is_new": false, "cook_steps": [{"step":1,"label":"Soften the gelatine","instruction":"Add gelatine to room-temperature water and let sit until softened.","timer_seconds":300,"background":true},{"step":2,"label":"Cook the passion fruit base","instruction":"Stir together passion fruit pulp, sugar and gelatine mixture over medium-high heat until combined and smooth, without boiling.","timer_seconds":300,"background":false},{"step":3,"label":"Cool and add condensed milk","instruction":"Remove from heat, cool completely, then stir in condensed milk.","timer_seconds":null,"background":true},{"step":4,"label":"Whip the egg whites","instruction":"Beat egg whites until stiff peaks form.","timer_seconds":null,"background":false},{"step":5,"label":"Fold and chill","instruction":"Stir a third of the egg whites into the passion fruit mixture, then gently fold in the rest. Divide among serving cups, cover, and refrigerate until well chilled.","timer_seconds":7200,"background":true},{"step":6,"label":"Serve","instruction":"Serve chilled, garnished with mint.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/watch?v=x5SRhOq3vfs"}, {"id": "53334", "name": "Arepa Pabellón", "category": "Beef", "area": "Venezuela", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/13fg4j1764441982.jpg", "local_image": "53334.jpg", "ingredients": [{"ingredient": "Corn Arepa Filled With Mozarella Cheese", "measure": "2"}, {"ingredient": "Fried Ripe Bananas", "measure": "1"}, {"ingredient": "Black Beans", "measure": "1 Can"}, {"ingredient": "Pico De Gallo Sauce", "measure": "1"}, {"ingredient": "Shredded Meat", "measure": "2kg"}, {"ingredient": "Tomato", "measure": "1 chopped"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "Prepare the meat in a skillet and add salt and pepper to taste, heat the beans over medium heat in a pan, fry or grill the ripe plantains as indicated on its package and cut the tomato into small cubes. Reserve these ingredients until filling. \r\nPreheat the grill or pan and grill the arepa, putting it once on each side until they are golden brown. \r\nWith the help of a knife, open it by the edge through the middle, creating a space to fill it with the ripe plantain, the beans, meat and chopped tomato. \r\nServe with a little pico de gallo or guacamole dip sauce. ", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 997, "protein_g": 92.4, "carbs_g": 23.7, "fat_g": 54.5, "total_kcal": 4987, "total_protein_g": 462.1, "total_carbs_g": 118.5, "total_fat_g": 272.4, "macro_confidence": 0.75, "is_new": false, "cook_steps": [{"step":1,"label":"Prep the fillings","instruction":"Season the meat with salt and pepper and heat through. Heat the beans, fry or grill the ripe plantains, and cube the tomato.","timer_seconds":480,"background":false},{"step":2,"label":"Grill the arepas","instruction":"Preheat the grill or pan and cook the arepas on each side until golden brown.","timer_seconds":300,"background":false},{"step":3,"label":"Fill and serve","instruction":"Open the arepas through the middle and fill with plantain, beans, meat and tomato. Serve with pico de gallo or guacamole.","timer_seconds":null,"background":false}], "video": "https://www.youtube.com/shorts/Tb1PPOyqthA"}, {"id": "53335", "name": "Jiggs Dinner", "category": "Beef", "area": "Canadian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/z1tfnw1764443171.jpg", "local_image": "53335.jpg", "ingredients": [{"ingredient": "Beef", "measure": "2 Lbs"}, {"ingredient": "Yellow Split Peas", "measure": "1 cup"}, {"ingredient": "Cabbage", "measure": "1 head"}, {"ingredient": "Carrots", "measure": "6"}, {"ingredient": "Turnips", "measure": "1 large"}, {"ingredient": "Potatoes", "measure": "8"}, {"ingredient": "Butter", "measure": "3  tablespoons"}, {"ingredient": "Black Pepper", "measure": "To taste"}], "instructions": "The night before, break salt beef into big chunks and soak in water overnight, at least 8-10 hours. Put split peas into a bowl and cover with water to soak overnight.\r\nDrain the salt beef and place it into a large stockpot. Cover with fresh water, at least 6-7 litres. Place the split peas into a pease pudding canvas bag or triple layer of cheesecloth and tie, making sure to leave room for peas to expand inside the bag.\r\nPut the bag inside the pot, tying the strings to the outside handle so it doesn't stick to the bottom of the pot with the salt beef. Bring to a boil, then lower the heat and simmer for 2 hours.\r\nRemove the peas pudding bag and empty contents into a bowl, mixing with butter and pepper for taste. Set aside.\r\nAdd your cabbage to the pot and boil for 20 more minutes. Then add turnip, carrots and potatoes then boil for 20 more, or until vegetables are tender.\r\nRemove salt beef and vegetables from the pot and put them on a platter.\r\nUse the cooking liquid in two ways; as a pot liquor which some people like to drink or reduce it to make a jus or gravy to pour over the meal.", "equipment_tags": [], "portions": 6, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 560, "protein_g": 37.7, "carbs_g": 51.3, "fat_g": 23.0, "total_kcal": 3361, "total_protein_g": 226.4, "total_carbs_g": 307.6, "total_fat_g": 138.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=w-rVGvZXVfs"}, {"id": "53336", "name": "Molasses Baked Beans", "category": "Vegetarian", "area": "Canadian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/9tddhg1764443699.jpg", "local_image": "53336.jpg", "ingredients": [{"ingredient": "Dried White Navy Beans", "measure": "2 cups"}, {"ingredient": "Bacon", "measure": "1/2 lb"}, {"ingredient": "Onion", "measure": "1 medium"}, {"ingredient": "Molasses", "measure": "1/2 cup"}, {"ingredient": "Brown Sugar", "measure": "1/4 cup"}, {"ingredient": "Cider Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Mustard", "measure": "Ground"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Place the dried beans into a Dutch oven with 6 cups (1.5 L) of water. Soak overnight.\r\nDrain and pour beans back into the pot with enough water to cover the beans by a couple of inches, cook for 30 minutes until they are tender but still firm. Drain beans, making sure to reserve cooking liquid, set aside.\r\nPreheat the oven to 325 °F (160 °C). While the oven is preheating, cook pork over medium-high heat in the Dutch Oven until fat is rendered and pork is beginning to brown, then add the onion cooking until tender.\r\nAdd the beans back to the pot, along with molasses, brown sugar, apple cider vinegar, ground mustard, salt and pepper and 3 cups (750 mL) of reserved bean water.\r\nBake uncovered for 3 to 5 hours until the beans are tender, and the sauce has thickened, and the edges of the pot get sticky.\r\n(Note: if beans get dry, add another cup of water.)", "equipment_tags": [], "portions": 2, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 1225, "protein_g": 64.2, "carbs_g": 132.7, "fat_g": 49.4, "total_kcal": 2450, "total_protein_g": 128.3, "total_carbs_g": 265.3, "total_fat_g": 98.8, "macro_confidence": 0.89, "is_new": false, "video": "https://www.youtube.com/watch?v=60tmFXd4uoI"}, {"id": "53337", "name": "Saskatoon Pie", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5xdrkw1764444472.jpg", "local_image": "53337.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "6 cups"}, {"ingredient": "Salt", "measure": "2 tsp"}, {"ingredient": "Unsalted Butter", "measure": "1 cup"}, {"ingredient": "Vegetable Shortening", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "1 large"}, {"ingredient": "Vinegar", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "Splash"}, {"ingredient": "Saskatoon Berries", "measure": "5 Cups"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Cornstarch", "measure": "3  tablespoons"}, {"ingredient": "Unsalted Butter", "measure": "2 tablespoons"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Water", "measure": "1 tablespoon"}], "instructions": "To make the pastry, place the flour and salt in a large bowl. Mix well. Add the cubes of butter and shortening and mix them in (I like to use my hands to mix the fat into the flour, but you can use a pastry blender) just until it looks like coarse oatmeal with some pea-sized bits remaining. Place the egg in a 2-cup measure and beat it with a fork. Beat in the vinegar and just enough ice-cold water to bring it to the 1-cup mark. Stir this into the flour mixture, just until the dough clings together. I like to use my hands for this part as well, but a wooden spoon would also work. Try not to overmix it.\r\nOn a lightly floured surface, gather the dough into a ball and divide it into 5 evenly sized portions. Shape each portion into a disc and wrap tightly in plastic. Chill 2 of these discs for 1 hour. Freeze the other 3 in a resealable freezer bag for future use. The pastry keeps well in the freezer for up to 2 months.\r\nPreheat the oven to 350°F. Place the rack in the lower third of the oven. Line a baking sheet with aluminum foil to catch drippings.\r\nOn a lightly floured surface, roll out 1 disc of pastry into a 12-inch circle, or thereabouts. Place it in the bottom of a 9-inch pie plate, with the pastry overhanging the edges of the pie plate.\r\nTo make the filling, place the saskatoon berries in a large bowl and stir in the 1/2 cup sugar and the cornstarch until well combined. Pour the berry mixture into the bottom of the pie. Dot with the butter. On a lightly floured surface, roll out the pastry in another 12-inch circle for the top crust. Use a ruler to guide you when cutting the pastry into 6 wide, long strips to keep the edges straight. Save the 2 end pieces in case you need to do any patching. I like wide strips, but if you like a thinner look, feel free to cut thin strips of pastry. Weave the pastry strips, going over and under, making sure they connect with the edges of the pie crust. Fold over the edges of the bottom crust, tucking in the lattice ends. This will help to trap the juices and give a rustic look.\r\nIf you prefer a cleaner, tidier look, you can trim the overhanging pieces and crimp the edges with a fork. Brush the top of the pie with the egg wash. Sprinkle with the remaining Tbsp sugar. Place the pie on the prepared baking sheet and bake it for about 90 – 100 minutes, until it’s golden brown and bubbling. Remove the pie from the oven and place it on a wire rack to cool.\r\nServe the pie warm or at room temperature with whipped cream or ice cream. Makes 6 servings. This keeps well if covered with plastic and refrigerated for up to 4 days.", "equipment_tags": ["Blender"], "portions": 12, "prep_minutes": 160, "prep_minutes_source": "explicit", "kcal": 614, "protein_g": 12.6, "carbs_g": 76.4, "fat_g": 28.6, "total_kcal": 7367, "total_protein_g": 151.8, "total_carbs_g": 917.2, "total_fat_g": 342.8, "macro_confidence": 0.93, "is_new": false, "video": "https://www.youtube.com/watch?v=wla0ijWVLCs"}, {"id": "53338", "name": "Date squares", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/u4scbo1764446514.jpg", "local_image": "53338.jpg", "ingredients": [{"ingredient": "Pitted Dates", "measure": "2 1/2 cups"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Vanilla", "measure": "1 1/2 cup"}, {"ingredient": "Oats", "measure": "2 cups"}, {"ingredient": "All purpose flour", "measure": "1 cup"}, {"ingredient": "Brown Sugar", "measure": "1 cup"}, {"ingredient": "Baking Powder", "measure": "1/2 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Unsalted Butter", "measure": "1 cup"}], "instructions": "Preheat oven to 350°F (180°C). Grease an 8-inch (20 cm) square baking pan.\r\nTo make the date filing: Combine the dates and water in a medium saucepan over high heat and bring to a boil. Reduce heat to low and simmer gently, stirring occasionally until the mixture thickens, around 6 to 8 minutes. Remove from heat, stir in vanilla and let cool. Set aside.\r\nCombine rolled oats, flour, sugar, baking soda and salt in a food processor. Pulse 3 times (careful not to overmix, you don’t want the mixture to be powdery, just combined). Add butter and pulse again until the mixture is crumbly in pea-sized clumps. Transfer to a mixing bowl to thoroughly mix in the butter.\r\nSpread half of the oat mixture on the bottom of the prepared baking pan, pressing down to make a flat, equal bottom later. Add the date mixture over the crust and then spread evenly. Layer with the remaining oat mixture and press down to flatten the top layer.\r\nBake in the centre of the oven until the top is golden brown, 30 to 35 minutes. Let cool completely in the pan before cutting and serving. Date Squares keep well, covered in the refrigerator for up to a week, and frozen for 2 to 3 months.", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 43, "prep_minutes_source": "explicit", "kcal": 558, "protein_g": 10.6, "carbs_g": 62.5, "fat_g": 22.5, "total_kcal": 6696, "total_protein_g": 126.8, "total_carbs_g": 750.0, "total_fat_g": 269.9, "macro_confidence": 0.89, "is_new": false, "video": "https://www.youtube.com/watch?v=E0bOy1FWkXA"}, {"id": "53339", "name": "Jam jam cookies", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sktequ1764447186.jpg", "local_image": "53339.jpg", "ingredients": [{"ingredient": "Egg", "measure": "1"}, {"ingredient": "Butter", "measure": "1 cup"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Molasses", "measure": "1/2 cup"}, {"ingredient": "Vanilla", "measure": "1 tsp"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Water", "measure": "3  tablespoons"}, {"ingredient": "Baking Powder", "measure": "2 tablespoons"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "2 tsp"}, {"ingredient": "Flour", "measure": "4 cups"}, {"ingredient": "Jam", "measure": "2 cups"}], "instructions": "Preheat the oven to 350 °F (180 °C) and line a large baking sheet with parchment paper.\r\nIn a stand mixer with the paddle attachment, cream the butter, white sugar and egg until combined, then add the molasses and vanilla and mix until smooth.\r\nOnce combined, add the baking soda water mixture and mix for another minute to combine.\r\nCombine dry ingredients; mix baking powder, cinnamon, flour and salt in a separate bowl then add to the wet ingredients a little at a time, mixing on low until fully combined and scraping down the sides to ensure everything is incorporated. The dough should be easily shaped.\r\nPortion dough with a small spoon, roll them into balls and place them on the lined cookie sheet, press them into flat discs using a floured glass or your moistened palm.\r\nPlace cookies on parchment-lined baking sheets and bake for 10-12 mins. Remove from the oven and let them cool for at least 10 minutes.\r\nOnce cooled the cookie sandwiches by spreading at least two teaspoons of your favourite jam between the two cookies. Repeat and enjoy with a cup of tea.", "equipment_tags": [], "portions": 12, "prep_minutes": 22, "prep_minutes_source": "explicit", "kcal": 508, "protein_g": 5.1, "carbs_g": 85.7, "fat_g": 16.4, "total_kcal": 6095, "total_protein_g": 61.6, "total_carbs_g": 1028.6, "total_fat_g": 197.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=8dh7HmkBLCI"}, {"id": "53340", "name": "Hodge Podge", "category": "Vegetarian", "area": "Canadian", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/xihv0c1764447887.jpg", "local_image": "53340.jpg", "ingredients": [{"ingredient": "New Potatoes", "measure": "1 lb"}, {"ingredient": "Carrots", "measure": "1 lb"}, {"ingredient": "Green Beans", "measure": "1 cup"}, {"ingredient": "Peas", "measure": "1/2 cup"}, {"ingredient": "Dill", "measure": "1 tablespoon"}, {"ingredient": "Chives", "measure": "1 tablespoon"}, {"ingredient": "Milk", "measure": "3 Cups"}, {"ingredient": "Heavy Cream", "measure": "1/2 cup"}, {"ingredient": "Butter", "measure": "1/2 cup"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}], "instructions": "First, cook your vegetables. Bring a large pot of salted water to boil. Par-cook carrots and potatoes for five minutes until carrots and potatoes are fork tender, then blanch the peas and beans for about a minute in the same pot. Strain vegetables and set aside.\r\nIn a heavy-bottomed pot or Dutch oven, melt butter over medium heat, add vegetables, and cook to warm through.\r\nAdd milk and cream and bring the soup to a boil. Turn the heat down to low and season with salt and pepper.\r\nAdd dill and chives and let simmer for at least 10 minutes. Serve warm.", "equipment_tags": [], "portions": 5, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 505, "protein_g": 10.5, "carbs_g": 39.3, "fat_g": 35.5, "total_kcal": 2525, "total_protein_g": 52.5, "total_carbs_g": 196.5, "total_fat_g": 177.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53341", "name": "Flapper Pie", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/6ht8141764786479.jpg", "local_image": "53341.jpg", "ingredients": [{"ingredient": "Graham Cracker Crumbs", "measure": "1 1/2 cups"}, {"ingredient": "Melted Butter", "measure": "6 tablespoons"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Ground Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Milk", "measure": "2 1/2 cups"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Cornstarch", "measure": "1/4 cup"}, {"ingredient": "Egg Yolks", "measure": "3"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Egg White", "measure": "3"}, {"ingredient": "Sugar", "measure": "1/4 cup"}, {"ingredient": "Cream Of Tartar", "measure": "1/4 tsp"}], "instructions": "Preheat the oven to 350˚F.\r\nMix all the crust ingredients (graham cracker crumbs, melted butter, granulated sugar and ground cinnamon) in a medium bowl. Set aside about 2 Tbsp (30 mL) for later and press the mixture into a 9-inch deep-dish pie plate in the bottom and up the sides. Bake crust for 10 minutes, it will only brown slightly.\r\nCombine the vanilla custard filling ingredients (milk, granulated sugar, cornstarch, egg yolks, vanilla extract and salt together) and cook on medium heat, stirring constantly, until it bubbles and thickens to the texture of pudding. Set aside to cool while you make the meringue topping.\r\nIn the bowl of a stand mixer fitted with the beater attachment or in a large bowl using an electric mixer beat the meringue ingredients (egg whites, granulated sugar, cream of tartar) together until it holds stiff and glossy peaks.\r\nTo assemble the pie, pour the filling into the crust and top with a thick layer of the meringue, making little spikes that will brown on top. Sprinkle the reserved crumb over the top and place it into the preheated oven.\r\nBake until the meringue browns, around 10 minutes, making sure to watch it carefully.\r\nChill in the fridge and eat within a few hours of baking. This pie is best eaten the same day as the meringue will soften and liquify.", "equipment_tags": [], "portions": 11, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 340, "protein_g": 8.5, "carbs_g": 47.6, "fat_g": 12.9, "total_kcal": 3739, "total_protein_g": 93.2, "total_carbs_g": 524.1, "total_fat_g": 142.4, "macro_confidence": 0.92, "is_new": false, "video": "https://www.youtube.com/watch?v=ALTeJItoxHg"}, {"id": "53342", "name": "Figgy Duff", "category": "Dessert", "area": "Canadian", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/kzi6p51764787198.jpg", "local_image": "53342.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "2 cups"}, {"ingredient": "Brown Sugar", "measure": "1/2 cup"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Ginger", "measure": "1 tsp"}, {"ingredient": "Allspice", "measure": "1 tsp"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}, {"ingredient": "Raisins", "measure": "1 cup"}, {"ingredient": "Melted Butter", "measure": "1/3 cup"}, {"ingredient": "Molasses", "measure": "1/2 cup"}, {"ingredient": "Water", "measure": "1 tablespoon"}], "instructions": "In a medium bowl, whisk together flour, brown sugar, baking powder, and spices.\r\nAdd raisins and stir well, making sure to coat the raisins in the flour mixture.\r\nAdd melted butter, molasses and water and mix with a wooden spoon. Form a ball with the spoon or your hands and put the dough ball in a cotton pudding bag. Tie the bag, leaving at least 1 inch of room to allow the pudding to expand while cooking.\r\nBoil pudding for 1.5 hours. (In NL, this is typically done in the pot along with Jiggs Dinner, but it can be done independently.)\r\nWhen the duff is firm, remove it from the boiling water and let it cool slightly before removing it from the pudding bag.\r\nSlice pudding like a cake and serve with the warm sauce of your choice: rum butter sauce, warmed molasses or Molasses Coady sauce (1 cup (250 mL) molasses, 1/4 cup (60 mL) butter, 1/4 cup (60 mL) water) is common in Newfoundland.\r\n", "equipment_tags": [], "portions": 6, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 494, "protein_g": 5.7, "carbs_g": 97.4, "fat_g": 11.1, "total_kcal": 2965, "total_protein_g": 34.2, "total_carbs_g": 584.3, "total_fat_g": 66.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=b2bF5gZyYDA"}, {"id": "53343", "name": "Classic Tourtière", "category": "Beef", "area": "Canadian", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/0sd7ac1764787957.jpg", "local_image": "53343.jpg", "ingredients": [{"ingredient": "Canola Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Ground Pork", "measure": "1 lb"}, {"ingredient": "Dried Leaves Of Summer Savoury", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Ground Clove", "measure": "1/2 tsp"}, {"ingredient": "Ground Nutmeg", "measure": "1/2 tsp"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Beef Stock", "measure": "1 cup"}, {"ingredient": "Russet Potato", "measure": "1 small"}, {"ingredient": "Shortcrust Pastry", "measure": "4"}, {"ingredient": "Egg", "measure": "1 beaten"}], "instructions": "Heat oil on medium-high heat in a large sauté pan or skillet, then sauté the onion and garlic until softened, about 5 minutes. Add the ground beef, pork, and spices and cook until the meat is browned.\r\nAdd the beef broth and bring it up to a simmer then reduce heat to medium low. Add the grated potato and stir it in. Cook until liquid is almost absorbed, about 15 min. Remove the bay leaves and add salt to taste. Remove the pan from the heat and let the mixture cool completely — it bakes best if the filling is chilled.\r\nPreheat the oven to 375 °F (190 °C). On a lightly floured surface, roll out one disc of the pie dough to less than the 1/4-inch thickness and line the 9-inch pie plate. Fill this with the cooled tourtière mixture and spread out evenly. Roll out the remaining dough to the same thickness, cut a hole in the centre (for steam to escape) and place on top of the filling. Trim the dough to 1/2-inch beyond the edge of the pie plate and pinch the edges of the crust together. Brush the crust with the egg wash.\r\nBake tourtière for about 45 minutes or until the pastry is a rich golden brown. Let cool for 15 minutes before slicing to serve.\r\nServes: 8-10 (makes 2 9-inch pies)", "equipment_tags": [], "portions": 3, "prep_minutes": 80, "prep_minutes_source": "explicit", "kcal": 1109, "protein_g": 64.4, "carbs_g": 46.8, "fat_g": 72.6, "total_kcal": 3326, "total_protein_g": 193.3, "total_carbs_g": 140.5, "total_fat_g": 217.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=PM9TZPUJTiU"}, {"id": "53344", "name": "Jamaican Sweet Potato Pudding", "category": "Dessert", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xj9sa81764788866.jpg", "local_image": "53344.jpg", "ingredients": [{"ingredient": "Sweet Potatoes", "measure": "2 Lbs"}, {"ingredient": "Coconut Milk", "measure": "1 1/2 cup"}, {"ingredient": "Brown Sugar", "measure": "1 1/2 cup"}, {"ingredient": "All purpose flour", "measure": "1/2 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 tablespoon"}, {"ingredient": "Allspice", "measure": "1 teaspoon"}, {"ingredient": "Ground Cinnamon", "measure": "1 tsp"}, {"ingredient": "Ground Nutmeg", "measure": "1 tsp"}, {"ingredient": "Ground Ginger", "measure": "1/2 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Raisins", "measure": "1/2 cup"}, {"ingredient": "Coconut Milk", "measure": "3/4 cup"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Ground Cinnamon", "measure": "1/8 teaspoon"}, {"ingredient": "Ground Nutmeg", "measure": "1/8 teaspoon"}], "instructions": "Preheat oven to 350°F (175°C). Grease and line a 9-inch round pan or loaf pan with parchment paper.\r\nPlace your cut sweet potatoes in the bowl of a food processor and process until finely grated. In a small bowl, toss raisins in 2 teaspoons flour from the ½ cup. Set aside.\r\nIn a large bowl, combine grated sweet potatoes, light brown sugar, all-purpose flour, vanilla extract, allspice, cinnamon, nutmeg, ginger, and salt. Stir in 1½ cups of coconut milk until a batter forms. Fold in the raisins that were tossed in the flour.\r\nPour the batter into the prepared pan and smooth the top. Bake uncovered for 1 hour 30 minutes, until mostly set but still slightly soft in the center", "equipment_tags": ["FoodProcessor"], "portions": 12, "prep_minutes": 90, "prep_minutes_source": "explicit", "kcal": 328, "protein_g": 3.2, "carbs_g": 56.8, "fat_g": 11.2, "total_kcal": 3932, "total_protein_g": 38.1, "total_carbs_g": 681.2, "total_fat_g": 134.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=8W8hZeGuiOc"}, {"id": "53345", "name": "Jamaican Curry Chicken Recipe", "category": "Chicken", "area": "Jamaican", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/o5fuq51764789643.jpg", "local_image": "53345.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "2 Lbs"}, {"ingredient": "Curry Powder", "measure": "2 1/2 Tbs"}, {"ingredient": "All-purpose Seasoning", "measure": "1 tsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Spring Onions", "measure": "3 chopped"}, {"ingredient": "Green Pepper", "measure": "1/2"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Scotch Bonnet", "measure": "1 chopped"}, {"ingredient": "Thyme", "measure": "3 sprigs"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Water", "measure": "1/4 cup"}, {"ingredient": "Russet Potato", "measure": "1 large"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Equipment\r\n\r\nDutch Oven\r\n\r\nInstructions\r\n \r\nAdd chicken thighs, all-purpose seasoning, 1 tablespoon of curry powder, onion, green onions, green pepper, garlic cloves, scotch bonnet pepper (if using), and thyme to a large bowl and combine, making sure all chicken pieces are covered with the seasoning. Cover and refrigerate for at least 1 hour or up to overnight.\r\nOne the chicken is done marinating, remove onions, peppers, and garlic cloves from chicken and set aside.\r\nHeat olive oil in a large heavy bottom pot over medium heat. Add remaining curry powder and stir, cooking for about 20-30 seconds. Add onions, green pepper, garlic cloves, thyme, and scotch bonnet pepper (if using) to pot and stir until onions have softened, about 3-5 minutes. If your onions and peppers are looking dry, add about 1 tablespoon of water.\r\nAdd chicken and ¼ cup of water to the pot. Cover and reduce heat to medium low. Cook, stirring occasionally, for 30-35 minutes.\r\nWhen there is about 15 minutes remaining, stir in potato and continue to cook covered.\r\nOnce chicken is cooked and potatoes are softened, remove from heat. Salt and pepper to taste.", "equipment_tags": [], "portions": 12, "prep_minutes": 115, "prep_minutes_source": "explicit", "kcal": 159, "protein_g": 16.7, "carbs_g": 8.1, "fat_g": 6.6, "total_kcal": 1909, "total_protein_g": 200.0, "total_carbs_g": 97.2, "total_fat_g": 79.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53346", "name": "Grape Nut Ice Cream", "category": "Dessert", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/1xscby1764790242.jpg", "local_image": "53346.jpg", "ingredients": [{"ingredient": "Heavy Cream", "measure": "2 cups"}, {"ingredient": "Condensed Milk", "measure": "1 1/4 oz"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Grape Nut Cereal", "measure": "1 cup"}], "instructions": "In a large bowl, use an electric mixer to whip the cold heavy cream until stiff peaks form. Gently fold in the sweetened condensed milk and vanilla extract until well combined.\r\nFold in the cereal and stir until evenly distributed throughout the mixture.\r\nPour the mixture into a freezer-safe container (such as a loaf pan). Lay plastic wrap on top of the ice cream to avoid freezer burn. Cover the container and freeze for at least 6 hours or until solid.\r\nOnce frozen, let the ice cream sit at room temperature for a few minutes to soften slightly before scooping and serving.", "equipment_tags": [], "portions": 5, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 713, "protein_g": 12.3, "carbs_g": 12.4, "fat_g": 70.1, "total_kcal": 3566, "total_protein_g": 61.7, "total_carbs_g": 61.9, "total_fat_g": 350.6, "macro_confidence": 0.75, "is_new": false, "video": "https://www.youtube.com/watch?v=ZxKA2bGkIa8"}, {"id": "53347", "name": "No-Churn Rum Raisin Ice Cream", "category": "Dessert", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/s9qyzd1764790772.jpg", "local_image": "53347.jpg", "ingredients": [{"ingredient": "Dark Rum", "measure": "1/2 cup"}, {"ingredient": "Raisins", "measure": "1 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Condensed Milk", "measure": "14 oz jar"}, {"ingredient": "Brown Sugar", "measure": "2 tablespoons"}, {"ingredient": "Ground Cinnamon", "measure": "1/4 tsp"}, {"ingredient": "Allspice", "measure": "1/8 teaspoon"}, {"ingredient": "Heavy Cream", "measure": "2 cups"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "Heat the rum in a small saucepan over medium heat until warm (do not boil). Remove from heat and stir in the raisins and vanilla extract. Let the mixture sit for at least 30 minutes. After soaking, drain off the extra rum, but keep ¼ cup of the rum and reserve it to mix into your ice cream base.\r\nIn a large bowl, whisk together the sweetened condensed milk, dark brown sugar, cinnamon, allspice, salt, and reserved rum (¼ cup). Stir until the brown sugar is fully dissolved.\r\nIn a separate bowl, whip the cold heavy cream with an electric mixer until stiff peaks form.\r\nGently fold the whipped cream into the condensed milk mixture until fully combined, being careful not to deflate the cream. Fold in the drained rum-soaked raisins to distribute them evenly.\r\nPour the mixture into a loaf pan or freezer-safe container. Smooth the top and cover with plastic wrap or an airtight lid. Freeze for at least 6 hours, or until firm.\r\nLet the ice cream sit at room temperature for 5–10 minutes before scooping for the best texture.", "equipment_tags": [], "portions": 8, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 439, "protein_g": 4.2, "carbs_g": 31.1, "fat_g": 30.6, "total_kcal": 3508, "total_protein_g": 33.7, "total_carbs_g": 248.7, "total_fat_g": 244.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=6WpzVZrOwIs"}, {"id": "53348", "name": "Jamaican Spice Bun Recipe", "category": "Dessert", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/08c5f41764791918.jpg", "local_image": "53348.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "380g"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Egg", "measure": "1 large"}, {"ingredient": "Brown Sugar", "measure": "150g"}, {"ingredient": "Beer", "measure": "250g"}, {"ingredient": "Milk", "measure": "1/3 cup"}, {"ingredient": "Honey", "measure": "1/4 cup"}, {"ingredient": "Unsalted Butter", "measure": "4 tablespoons"}, {"ingredient": "Molasses", "measure": "1 tablespoon"}, {"ingredient": "Caramelized Sugar Sauce", "measure": "1 tsp"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Dried cranberries", "measure": "1/2 cup"}, {"ingredient": "Raisins", "measure": "1/2 cup"}, {"ingredient": "Dried Cherries", "measure": "1/2 cup"}], "instructions": "Soak the craisins, raisins, and cherries in the 1 cup of beer. Set aside and allow to soak for 30 minutes.\r\nPreheat the oven to 325 degrees Fahrenheit. Grease an 8x4 loaf pan. Set aside.\r\nCombine all-purpose flour, baking powder, ground cinnamon, salt, in a large bowl and set aside.\r\nIn another bowl, combine brown sugar, egg, milk, honey, melted butter, molasses, browning, vanilla extract, and the beer that’s soaking the fruit. Do not pour the fruit in at this time, just the beer. Mix to combine.\r\nRemove 2 tablespoon of flour from the flour mixture and toss the fruit in it. Set aside.\r\nMake a well in the middle of the bowl of dry ingredients and pour in wet mixture, stirring until fully combined. And the fruits to the mixture and stir until incpororated.\r\nPour mixture into prepared loaf pan and bake in the preheated oven for 50-60 minutes or until a toothpick comes out clean.\r\nCool for 5 minutes in the pan and then move to a cooling rack to finish cooling. Serve with slices of cheddar cheese.", "equipment_tags": [], "portions": 12, "prep_minutes": 95, "prep_minutes_source": "explicit", "kcal": 324, "protein_g": 4.9, "carbs_g": 63.1, "fat_g": 5.8, "total_kcal": 3886, "total_protein_g": 59.3, "total_carbs_g": 757.3, "total_fat_g": 70.1, "macro_confidence": 0.94, "is_new": false, "video": null}, {"id": "53349", "name": "Jamaican Pepper Shrimp", "category": "Seafood", "area": "Jamaican", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/bx07m71764792853.jpg", "local_image": "53349.jpg", "ingredients": [{"ingredient": "Shrimp", "measure": "1 lb"}, {"ingredient": "Scotch Bonnet", "measure": "2 chopped"}, {"ingredient": "All-purpose Seasoning", "measure": "1 tablespoon"}, {"ingredient": "Ground Annatto", "measure": "2 tsp"}, {"ingredient": "Allspice", "measure": "2 tsp"}, {"ingredient": "Shrimp Stock", "measure": "3/4 cup"}, {"ingredient": "Onion", "measure": "1/4 cup"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "White Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Thyme", "measure": "3 sprigs"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "\r\nIn a medium bowl, combine shrimp with minced Scotch Bonnet peppers, all-purpose seasoning, ground annatto, and grounf allspice. Toss well to coat evenly and let marinate for 10 minutes.\r\nHeat a large pan over medium heat. Add the shrimp stock and bring to a gentle simmer. Stir in the diced onion and garlic, cooking until softened and fragrant, about 2 minutes.\r\nAdd the seasoned shrimp and thyme sprigs, spreading the shrimp in the pan. Cover and cook for about 5–7 minutes, stirring occasionally, until the shrimp turn bright orange and are cooked through.\r\nAdd the white vinegar, stir, and cook for another minute. Taste; add salt to taste. Using a slotted spoon, transfer the shrimp to a plate. Serve hot with some cooking liquid drizzled on top.", "equipment_tags": [], "portions": 12, "prep_minutes": 19, "prep_minutes_source": "explicit", "kcal": 59, "protein_g": 11.1, "carbs_g": 3.0, "fat_g": 0.6, "total_kcal": 706, "total_protein_g": 132.6, "total_carbs_g": 35.6, "total_fat_g": 6.6, "macro_confidence": 0.91, "is_new": false, "video": "https://www.youtube.com/watch?v=ILCmxtCp8jc"}, {"id": "53350", "name": "Corned Beef and Cabbage – Jamaican Style", "category": "Beef", "area": "Jamaican", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/kdz63q1764793442.jpg", "local_image": "53350.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Cabbage", "measure": "1/2"}, {"ingredient": "Green Pepper", "measure": "1 chopped"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Corned Beef", "measure": "12 ounces"}, {"ingredient": "Plum Tomatoes", "measure": "2 chopped"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Tomato Ketchup", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Heat olive oil in a skillet or Dutch pot over medium-high heat. Add onion and green pepper and sauté for about 3-5 minutes.\r\nAdd garlic and stir for about 1 minute.\r\nAdd shredded cabbage and stir. Cook for about about 3-5 minutes, stirring often until softened.\r\nAdd corned beef, Roma tomatoes, and thyme and stir. Add ketchup and scotch bonnet pepper sauce and stir. Reduce heat and cook on medium for about 3-5 minutes, until the corned beef is heated through. Remove from heat.\r\nServe with white rice, bread, or on its own.", "equipment_tags": [], "portions": 12, "prep_minutes": 16, "prep_minutes_source": "explicit", "kcal": 70, "protein_g": 6.0, "carbs_g": 2.0, "fat_g": 4.3, "total_kcal": 839, "total_protein_g": 72.2, "total_carbs_g": 23.7, "total_fat_g": 51.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=Bxjz-q2hioA"}, {"id": "53351", "name": "Jamaican Banana Fritters", "category": "Dessert", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ul2uy31764794321.jpg", "local_image": "53351.jpg", "ingredients": [{"ingredient": "Banana", "measure": "3 Medium"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Nutmeg", "measure": "1/4 tsp"}, {"ingredient": "Brown Sugar", "measure": "3  tablespoons"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "All purpose flour", "measure": "1 cup"}, {"ingredient": "Oil", "measure": "For frying"}], "instructions": "Mash bananas with fork in bowl.\r\nAdd brown sugar, vanilla, extract, cinnamon, nutmeg and a pinch of salt. Sift in flour and stir with spoon until fully combined.\r\nAdd oil to a 10 inch skillet over medium-high heat. Once oil is hot, drop banana fritter batter in oil by the spoonful. Once one side is golden and bubbles appear on the top, flip fritter and cook until the other side is browned as well.\r\nRemove fritters and drain on paper towels. Enjoy", "equipment_tags": [], "portions": 12, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 86, "protein_g": 1.2, "carbs_g": 14.3, "fat_g": 2.7, "total_kcal": 1034, "total_protein_g": 14.5, "total_carbs_g": 171.9, "total_fat_g": 32.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/I3wZ04FgW0I"}, {"id": "53352", "name": "Jamaican Instant Pot Rice and Beans", "category": "Vegetarian", "area": "Jamaican", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/11bvtm1764795135.jpg", "local_image": "53352.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Spring Onions", "measure": "2 chopped"}, {"ingredient": "Rice", "measure": "2 cups"}, {"ingredient": "Coconut Milk", "measure": "3/4 cup"}, {"ingredient": "Water", "measure": "3/4 cup"}, {"ingredient": "Salt", "measure": "1 1/2 tsp"}, {"ingredient": "Allspice", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Kidney Beans", "measure": "450g"}, {"ingredient": "Thyme", "measure": "2 sprigs"}], "instructions": "Instructions\r\n \r\nSet Instant Pot to \"Sauté.\" Once Hot, add olive oil. Then add yellow onion and stir until softened, about 3 minutes. Add garlic and green onions and stir for about 30 more seconds.\r\nPress “Cancel” on the Instant Pot. Add rice, coconut milk, water, salt, allspice, and black pepper and stir.\r\nPour undrained kidney beans on top of the rice mixture. Do not stir. Lay sprigs of thyme on top. Cover the Instant Pot, ensuring the valve is set to “Sealing.”\r\nPress “Manual” or “Pressure Cook” on the Instant Pot and set for High pressure for 6 minutes.\r\nOnce the pressure cooking time is done, allow it to natural release for 10 minutes, then quick release any remaining pressure by moving valve to \"Venting\"\r\nOpen lid and remove thyme sprigs. Fluff rice with fork and Enjoy!\r\n\r\nStove Top Instructions\r\nHeat olive oil in a large pot over medium heat. Add yellow onion and stir until softened, about 3 minutes. Add garlic and green onions and stir for about 30 more seconds.\r\nAdd rice, undrained kidney beans, coconut milk, water, salt, allspice, and black pepper and stir until combined. Lay thyme on top. Bring mixture to a simmer.\r\nCover with a lid and reduce heat to low. Allow to cook for 18 minutes over low heat, then remove from heat. Leave the lid on for an additional 5 minutes.\r\nOpen the lid and remove the thyme. Fluff rice with fork. Enjoy.", "equipment_tags": [], "portions": 12, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 227, "protein_g": 6.5, "carbs_g": 39.1, "fat_g": 5.2, "total_kcal": 2729, "total_protein_g": 78.1, "total_carbs_g": 469.7, "total_fat_g": 63.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=iJm1F-TE8Sk"}, {"id": "53353", "name": "Jamaican Boiled Dumplings", "category": "Side", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tsdbcq1764795636.jpg", "local_image": "53353.jpg", "ingredients": [{"ingredient": "Water", "measure": "8 cups"}, {"ingredient": "Salt", "measure": "1/2 tbs"}, {"ingredient": "All purpose flour", "measure": "2 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1/2 cup"}], "instructions": "Instructions\r\n \r\nIn a large pot, bring water and salt to a boil to boil the dumplings.\r\nIn a large mixing bowl, combine the all-purpose flour and salt, stirring to distribute the salt evenly throughout the flour. Gradually add water to the flour mixture, mixing with your hands until a dough forms.\r\nDivide the dough into equal-sized pieces, rolling each into a smooth ball. Flatten each ball slightly with the palm of your hand to form a round, circular dumpling. It should look like a thick disk.\r\nCarefully drop the dumplings into the boiling water, one at a time, ensuring that they don't stick together. You can use a wooden spoon to stir the dumplings in the water.\r\nBoil the dumplings for 15-20 minutes, or until they are cooked through and have risen to the surface of the water. Stir occasionally to prevent sticking.\r\nUse a slotted spoon to remove the cooked dumplings from the pot, allowing any excess water to drain.\r\nServe with your favorite recipes.", "equipment_tags": [], "portions": 12, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 77, "protein_g": 2.1, "carbs_g": 16.1, "fat_g": 0.2, "total_kcal": 926, "total_protein_g": 25.4, "total_carbs_g": 193.3, "total_fat_g": 2.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=RhUxdkYIHPY"}, {"id": "53354", "name": "Jamaican Curry Goat", "category": "Goat", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uc9qp11764796575.jpg", "local_image": "53354.jpg", "ingredients": [{"ingredient": "Goat Meat", "measure": "3 Lbs"}, {"ingredient": "Jamaican Curry Powder", "measure": "2.5 tbsp"}, {"ingredient": "Ground Ginger", "measure": "1/2 tsp"}, {"ingredient": "All-purpose Seasoning", "measure": "1/2 tsp"}, {"ingredient": "Allspice", "measure": "1/4 tsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "6 cloves sliced"}, {"ingredient": "Thyme", "measure": "3 sprigs"}, {"ingredient": "Oil", "measure": "2 tablespoons"}, {"ingredient": "Water", "measure": "1 1/4 cup"}, {"ingredient": "Scotch Bonnet", "measure": "1"}, {"ingredient": "Russet Potato", "measure": "1 large"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Equipment\r\n\r\n6QT Pressure cooker\r\n\r\nInstructions\r\n \r\nRinse goat meat with vinegar and water.\r\nSeason goat meat with 1 ½ tablespoon curry powder, all-purpose seasoning, ground ginger, allspice, onion, garlic cloves, and thyme. Marinate for at least 4 hours or up to overnight.\r\nRemove onion and garlic from goat and set aside.\r\nSet an electric pressure cooker, like an Instant Pot, on high sauté and add oil. Add goat meat and brown, about 2-3 minutes per side. Remove goat from insert and add 1 tablespoon oil and remaining curry powder and sauté for about 10 seconds. Then add onions and garlic and sauté until softened. About 4 minutes. If the onions look dry, add a little water and continue to sauté.\r\nAdd goat and water to the pressure cooker and cover the pressure cooker. Cook for 40 minutes on high pressure. Allow to naturally release for 10 minutes, then release the remaining pressure.\r\nOnce all the pressure has been released, open the pressure cooker. Place on sauté for 10-15 minutes, add potatoes and a whole scotch bonnet pepper. Cook until potatoes have softened. Remove scotch bonnet pepper.", "equipment_tags": [], "portions": 12, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 213, "protein_g": 31.7, "carbs_g": 6.4, "fat_g": 6.2, "total_kcal": 2561, "total_protein_g": 380.5, "total_carbs_g": 76.5, "total_fat_g": 74.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=SrX2KMsWbF4"}, {"id": "53355", "name": "Jamaican Festival (Sweet Dumpling)", "category": "Side", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/g6xb8m1764875029.jpg", "local_image": "53355.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "1 1/2 cups"}, {"ingredient": "Cornmeal", "measure": "1/2 cup"}, {"ingredient": "Sugar", "measure": "6 tablespoons"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Milk", "measure": "3/4 cup"}, {"ingredient": "Oil", "measure": "For frying"}], "instructions": "Heat a heavy bottom pot of oil that has at least 3 inches of oil in it or use a deep fryer if you have one. Turn the heat over medium heat until the temperature reaches 350 degrees Fahrenheit.\r\nAdd the all-purpose flour, cornmeal, granulated sugar, baking powder, and salt to a large bowl and stir to combine.\r\nAdd the vanilla extract and milk and stir until the dough comes together. Then use your hands to lightly form the mixture into a ball.\r\nPinch off pieces of dough and roll them into long oval shapes. Make about 12 dumplings.\r\nOnce the oil has reached the temperature of 350 degrees Fahrenheit, fry the dough on all sides, until golden brown. This should take about 4-6 minutes.\r\nRemove dough and drain off any excess grease. Serve and enjoy.", "equipment_tags": [], "portions": 12, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 152, "protein_g": 2.9, "carbs_g": 27.4, "fat_g": 3.5, "total_kcal": 1829, "total_protein_g": 34.6, "total_carbs_g": 328.4, "total_fat_g": 42.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=N270k22MPWk"}, {"id": "53356", "name": "Jamaican Fried Dumplings", "category": "Side", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/dd7t4d1764877271.jpg", "local_image": "53356.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "2 cups"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Milk", "measure": "3/4 cup"}, {"ingredient": "Oil", "measure": "1 1/2 cup"}], "instructions": "Add flour, baking powder, and salt in a large bowl and stir to combine. Pour in the milk and stir until combined. Then roll the mixture into a ball and lightly knead until it comes together.\r\nBreak off about 10 pieces of dough and form them into balls. Set them aside.\r\nIn a 10-inch skillet, heat enough oil over medium heat to fry the dumplings, until the oil is about 350 degrees.\r\nOnce the dumplings are browned on one side, flip them and cook until both sides are browned, about 2-3 minutes each.\r\nOnce done, remove the dumplings from the oil and place them on paper towels or a cooling rack to drain off any excess oil.\r\nServe and enjoy.\r\n", "equipment_tags": [], "portions": 12, "prep_minutes": 3, "prep_minutes_source": "explicit", "kcal": 106, "protein_g": 2.6, "carbs_g": 17.1, "fat_g": 2.9, "total_kcal": 1275, "total_protein_g": 31.2, "total_carbs_g": 204.8, "total_fat_g": 35.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=W5AJhsW-X44"}, {"id": "53357", "name": "Jamaican Rice and Peas", "category": "Vegetarian", "area": "Jamaican", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/pkyvrn1764878267.jpg", "local_image": "53357.jpg", "ingredients": [{"ingredient": "Rice", "measure": "2 cups"}, {"ingredient": "Coconut Milk", "measure": "380g"}, {"ingredient": "Kidney Beans", "measure": "450g"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Kosher Salt", "measure": "2 tsp"}, {"ingredient": "Ground Allspice", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Spring Onions", "measure": "3"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Scotch Bonnet", "measure": "1"}], "instructions": "Equipment\r\nDutch oven\r\n\r\nAdd rice, coconut milk, kidney beans, water, kosher salt, allspice, and black pepper to a large pot and stir until combined. Lay green onions, thyme and Scotch bonnet pepper on top. Bring mixture to a boil.\r\nOnce boiling, reduce heat to low and cover with a lid. Allow to cook covered for 18 minutes over low heat, then remove from heat. Leave the lid on for an additional 5 minutes.\r\nOpen the lid and remove the green onion, Scotch bonnet pepper, and thyme. Fluff the rice and peas with a fork. Serve and enjoy.", "equipment_tags": [], "portions": 12, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 256, "protein_g": 7.0, "carbs_g": 40.2, "fat_g": 8.1, "total_kcal": 3074, "total_protein_g": 84.2, "total_carbs_g": 482.0, "total_fat_g": 97.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=swVY-6tUK5g"}, {"id": "53358", "name": "Chicken Mandi", "category": "Chicken", "area": "India", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/er4d081765186828.jpg", "local_image": "53358.jpg", "ingredients": [{"ingredient": "Chicken", "measure": "1"}, {"ingredient": "Basmati Rice", "measure": "2 cups"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Green Chilli", "measure": "2"}, {"ingredient": "Salt", "measure": "1 ½ tsp"}, {"ingredient": "Oil", "measure": "3 tablespoons"}, {"ingredient": "Turmeric Powder", "measure": "1 tablespoon"}, {"ingredient": "Coriander", "measure": "1 teaspoon"}, {"ingredient": "Cardamom", "measure": "½ tbsp"}, {"ingredient": "Cloves", "measure": "¼ teaspoon"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Bay Leaf", "measure": "2"}], "instructions": "1. Clean and cut the chicken; marinate briefly with salt, turmeric and a little oil.\r\n2. Rinse and soak basmati rice 20–30 minutes.\r\n3. In a large pot, heat ghee/oil. Fry chopped onion until golden. Add minced garlic and green chillies and fry 1–2 min.\r\n4. Add whole spices (cardamom, cloves, cinnamon, bay leaves) and ground spices (coriander, cumin). Stir until fragrant.\r\n5. Add chicken pieces, brown lightly and add enough water/chicken stock to cover. Simmer until chicken is nearly cooked.\r\n6. Remove chicken; measure remaining liquid and add soaked rice. Bring to a boil, then reduce heat, cover and cook rice until almost done.\r\n7. Return the chicken to the rice pot on top, cover tightly and steam on low for 10–15 min so flavors meld.\r\n8. (Optional) For authentic smoky aroma: heat a small charcoal until red hot, place it on a small foil cup in the centre of the pot, add a tsp of butter/oil on the coal then cover immediately to trap smoke for 5–10 minutes. Remove coal.\r\n9. Garnish with fried onions, chopped coriander and serve with chutney or raita.\r\n", "equipment_tags": [], "portions": 4, "prep_minutes": 57, "prep_minutes_source": "explicit", "kcal": 523, "protein_g": 12.5, "carbs_g": 90.8, "fat_g": 12.3, "total_kcal": 2091, "total_protein_g": 50.1, "total_carbs_g": 363.3, "total_fat_g": 49.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53359", "name": "Beef Mandi", "category": "Beef", "area": "India", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/1nalo51765188375.jpg", "local_image": "53359.jpg", "ingredients": [{"ingredient": "Basmati Rice", "measure": "1 kg"}, {"ingredient": "Beef Stock", "measure": "5 Cups"}, {"ingredient": "Onion", "measure": "2 medium"}, {"ingredient": "Garlic", "measure": "5 chopped cloves"}, {"ingredient": "Green Chilli", "measure": "2"}, {"ingredient": "Tomato", "measure": "1 small"}, {"ingredient": "Salt", "measure": "2 1/2 Tsp"}, {"ingredient": "Oil", "measure": "3  tablespoons"}, {"ingredient": "Turmeric Powder", "measure": "1 ½ tsp"}, {"ingredient": "Cardamom", "measure": "1/2 tsp"}, {"ingredient": "Cloves", "measure": "1/2 tsp"}, {"ingredient": "Bay Leaf", "measure": "1/2 tsp"}], "instructions": "1. Wash the beef and cut into large pieces. Season lightly with salt and turmeric.\r\n2. Heat ghee/oil in a large pot. Add sliced onions and sauté until light golden.\r\n3. Add garlic, green chilies, and tomato; cook until softened.\r\n4. Add the mandi spice mix: coriander, cumin, black pepper, cinnamon, cardamom, cloves, and bay leaves.\r\n5. Add beef pieces and stir on medium heat until the meat is well coated with spices.\r\n6. Pour in water or beef stock. Cover and simmer until beef is tender (about 1.5–2 hours depending on cut).\r\n7. Remove beef carefully and set aside. Strain and measure the broth.\r\n8. Add washed, soaked basmati rice to the broth (usually 1 cup rice = 1.5–2 cups liquid). Adjust seasoning and bring to a boil.\r\n9. Lower heat, cover, and cook the rice until fluffy.\r\n10. Place the beef pieces over the rice and steam on low heat for 10 minutes so flavors combine.\r\n11. Optional: For smoky flavor, place a small hot charcoal on foil in the pot, add 1 tsp butter/oil, immediately cover for 5 minutes. Remove coal before serving.\r\n12. Fluff rice and serve beef mandi with salad or chutney.\r\n", "equipment_tags": [], "portions": 6, "prep_minutes": 135, "prep_minutes_source": "explicit", "kcal": 755, "protein_g": 18.0, "carbs_g": 151.7, "fat_g": 8.6, "total_kcal": 4530, "total_protein_g": 107.9, "total_carbs_g": 910.1, "total_fat_g": 51.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53360", "name": "Caribbean Tamarind balls", "category": "Dessert", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/z1hz7z1765316430.jpg", "local_image": "53360.jpg", "ingredients": [{"ingredient": "Tamarind Pulp", "measure": "16 ounces"}, {"ingredient": "Sugar", "measure": "1 1/2 cups"}], "instructions": "Add tamarind pulp and 1 cup granulated sugar to a bowl and mash together with a spoon or fork. Take small amounts of the tamarind and sugar mix and shape them into small balls by rolling them in your hands. Make them the size of a marble or slightly bigger, as you like.\r\nAdd the remaining sugar to a flat surface, like a plate or a sheet pan. Roll the tamarind balls in granulated sugar until they're well-coated.\r\nYou can eat the tamarind balls immediately, or you can let them set for a few hours or overnight. Allowing them to set will give them a firmer texture and more crystallized sugar coating. Enjoy.", "equipment_tags": [], "portions": 5, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 454, "protein_g": 2.5, "carbs_g": 117.9, "fat_g": 0.5, "total_kcal": 2268, "total_protein_g": 12.7, "total_carbs_g": 589.5, "total_fat_g": 2.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=adRA-90CHUE"}, {"id": "53361", "name": "Callaloo and SaltFish", "category": "Side", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/73o3vq1765317873.jpg", "local_image": "53361.jpg", "ingredients": [{"ingredient": "Salt Cod", "measure": "1/2 lb"}, {"ingredient": "Bacon", "measure": "4"}, {"ingredient": "Callaloo", "measure": "525g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Spring Onions", "measure": "2 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Scotch Bonnet", "measure": "1 chopped"}, {"ingredient": "Plum Tomatoes", "measure": "2 chopped"}, {"ingredient": "Thyme", "measure": "2 sprigs"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}], "instructions": "Soak salted fish in water overnight. Next, heat salted fish in water on stove until water boils. You should see a foam on top. Remove from heat and drain. Set aside and shred salted fish once it cools.\r\nCook bacon in skillet over medium heat until crispy. Remove bacon from heat and drain the majority of the bacon grease, leaving about 1 tablespoon in the skillet. \r\nAdd yellow onion, green onion, scotch bonnet pepper, and garlic to the skillet and stir. Cook for about 2 minutes or until onions soften. Add salted fish to skillet and stir. Cook for about a minute. \r\nNext, add callaloo, roma tomatoes, thyme, and black pepper. Stir to combine and cook until heated through, about 2 minutes.\r\nEnjoy ", "equipment_tags": [], "portions": 9, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 157, "protein_g": 10.9, "carbs_g": 7.3, "fat_g": 9.7, "total_kcal": 1416, "total_protein_g": 98.4, "total_carbs_g": 66.1, "total_fat_g": 87.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=n1fRCk-zTRM"}, {"id": "53362", "name": "Jamaican Curry Shrimp Recipe", "category": "Seafood", "area": "Jamaican", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/n7h5zs1765318909.jpg", "local_image": "53362.jpg", "ingredients": [{"ingredient": "Jumbo Shrimp", "measure": "1 lb"}, {"ingredient": "Jamaican Curry Powder", "measure": "2.5 tbsp"}, {"ingredient": "All-purpose Seasoning", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Green Pepper", "measure": "1 sliced"}, {"ingredient": "Scotch Bonnet", "measure": "1 sliced"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Unsweetened Coconut Milk", "measure": "380g"}, {"ingredient": "Tomato Ketchup", "measure": "1/2 tbs"}, {"ingredient": "Thyme", "measure": "4 sprigs"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Season shrimp with 1 Tablespoon of curry powder and all-purpose seasoning and set aside for about 10 minutes while you prepare the other ingredients like chopping your onions, peppers, and garlic.\r\nHeat 2 Tablespoons of olive oil in a large skillet over medium heat. Add sliced yellow onion, red bell pepper, green bell pepper, scotch bonnet pepper, if using, and chopped garlic and stir for 5 minutes, until peppers are slightly softened.\r\nAdd 1.5 Tablespoons of curry powder to the skillet and stir for an additional minute.\r\nThen add coconut milk, seasoned shrimp, ketchup, and thyme, making sure the shrimp is covered in the sauce.\r\nAllow the sauce to come to a simmer and continue to cook over medium heat, stirring occasionally and flipping the shrimp halfway, until the shrimp is fully cooked on both sides. This should take about 5-6 minutes. Salt and pepper to taste.", "equipment_tags": [], "portions": 12, "prep_minutes": 21, "prep_minutes_source": "explicit", "kcal": 144, "protein_g": 9.1, "carbs_g": 5.5, "fat_g": 10.6, "total_kcal": 1729, "total_protein_g": 108.7, "total_carbs_g": 65.9, "total_fat_g": 127.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=Lnaj4duQ7hs"}, {"id": "53363", "name": "Jamaican Cornmeal Porridge", "category": "Breakfast", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sng9bm1765320170.jpg", "local_image": "53363.jpg", "ingredients": [{"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Coconut Milk", "measure": "380g"}, {"ingredient": "Fine Yellow Cornmeal", "measure": "1 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 1/2 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Ground Nutmeg", "measure": "1/2 tsp"}, {"ingredient": "Ground Allspice", "measure": "1/4 tsp"}, {"ingredient": "Sweetened Condensed Milk", "measure": "1/2 cup"}], "instructions": "Add 2 ½ cups water, 1 can coconut milk to a 4 QT heavy bottomed pot. Bring to a boil over medium-high heat.\r\nMeanwhile, add 1 cup cornmeal and 1 ½ cup water to a large mixing cup and whisk until smooth.\r\nOnce the pot begins to boil, whisk in cornmeal mixture and continue to whisk for about 1 minute, ensuring there are no lumps. Reduce heat to low and cover with a tight fitting lid.\r\nCook over low heat for 15-20 minutes, stirring occasionally. When there is about 5 minutes left, stir in vanilla extract, cinnamon, nutmeg, and all-spice. Remove from heat and sweeten with condensed milk.\r\nServe and enjoy.", "equipment_tags": [], "portions": 12, "prep_minutes": 26, "prep_minutes_source": "explicit", "kcal": 157, "protein_g": 2.7, "carbs_g": 18.4, "fat_g": 8.7, "total_kcal": 1879, "total_protein_g": 32.3, "total_carbs_g": 221.4, "total_fat_g": 104.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=NACm9tDACRc"}, {"id": "53364", "name": "Jamaican Steamed Cabbage", "category": "Side", "area": "Jamaican", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/paejva1765321314.jpg", "local_image": "53364.jpg", "ingredients": [{"ingredient": "Cabbage", "measure": "1/2"}, {"ingredient": "Carrots", "measure": "2 sliced"}, {"ingredient": "Plum Tomatoes", "measure": "1 chopped"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Spring Onions", "measure": "4 Chopped"}, {"ingredient": "Thyme", "measure": "4 sprigs"}, {"ingredient": "Scotch Bonnet", "measure": "1/2"}, {"ingredient": "Water", "measure": "2 tablespoons"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Unsalted Butter", "measure": "4 tablespoons"}, {"ingredient": "Kosher Salt", "measure": "2 tsp"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}], "instructions": "Add all the ingredients to a large pan over medium heat and cover with a lid.\r\nCook on medium heat for 10 minutes, stirring occasionally.\r\nAfter 10 minutes, reduce the heat to low and continue to cook for an additional 5 minutes, until the cabbage is soft and tender. Remove from the heat and remove the stalks of thyme before serving.", "equipment_tags": [], "portions": 12, "prep_minutes": 25, "prep_minutes_source": "explicit", "kcal": 80, "protein_g": 1.2, "carbs_g": 5.9, "fat_g": 6.3, "total_kcal": 964, "total_protein_g": 14.1, "total_carbs_g": 71.1, "total_fat_g": 76.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=amEkrC9rzgM"}, {"id": "53365", "name": "Chinese Orange Chicken", "category": "Chicken", "area": "Chinese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/s73ytv1765567838.jpg", "local_image": "53365.jpg", "ingredients": [{"ingredient": "Orange", "measure": "Zest of 1"}, {"ingredient": "Orange Juice", "measure": "1/4 cup"}, {"ingredient": "Soy Sauce", "measure": "1/4 cup"}, {"ingredient": "Water", "measure": "1/4 cup"}, {"ingredient": "Rice Vinegar", "measure": "1/3 cup"}, {"ingredient": "Cornstarch", "measure": "1 tablespoon"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tablespoon"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Chicken Thighs", "measure": "650g"}, {"ingredient": "Egg", "measure": "2 large"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Cornstarch", "measure": "1/2 cup"}, {"ingredient": "All purpose flour", "measure": "1/2 cup"}, {"ingredient": "Vegetable Oil", "measure": "2 cups"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Shallots", "measure": "1 chopped"}, {"ingredient": "Scallions", "measure": "Sliced"}, {"ingredient": "Sesame Seed", "measure": "Garnish"}, {"ingredient": "Rice", "measure": "To serve"}], "instructions": "Make the orange sauce:\r\nWhisk together sauce ingredients in a medium bowl. Set aside.\r\n\r\n\r\nPrep the chicken:\r\nCut chicken into about 1-inch cubes. Whisk eggs with salt and black pepper in a bowl and add chicken. Stir together.\r\n\r\nIn a separate bowl, whisk together flour and cornstarch. Remove chicken from eggs with a slotted spoon or tongs, letting excess egg drain off, then transfer to cornstarch mixture and coat well.\r\n\r\n\r\nFry the chicken:\r\nAdd oil to a large 10- to 12-inch skillet. Heat over medium-high heat until it reaches 350°F. If you don’t have a thermometer, you can also test the temperature by sprinkling in some flour. If the oil is hot enough, it should fizzle immediately.\r\n\r\nOnce oil is hot, fry the chicken in two batches. The oil might not completely cover the chicken—that’s okay. Cook for 3 to 4 minutes. Flip the chicken pieces and cook until the chicken is cooked through, about 3 to 4 more minutes. Total cook time is about 6 to 8 minutes.\r\n\r\nRemove fried chicken cubes and transfer to a plate lined with paper towels, so the chicken can drain. Repeat until all the chicken is cooked.\r\n\r\n\r\nSimmer the chicken in the sauce:\r\nOnce chicken is done, pour out hot oil and wipe pan clean. Add a fresh tablespoon of oil along with chopped garlic and shallot. Cook for a minute and then add the sauce. Simmer the sauce until it starts to thicken.\r\n\r\nOnce the sauce is lightly bubbling, add fried chicken and toss together to coat. The sauce should continue to thicken and stick to the chicken. Let simmer for a minute or two more. Serve orange chicken over cooked white rice, garnished with sesame seeds and fresh scallions.\r\n\r\nDid you love this recipe? Let us know with a rating and review!\r\n\r\n\r\nLEFTOVERS! The orange chicken keeps well in the fridge for 5 days. Reheat in a skillet with a splash of water over low heat. Freeze the orange chicken for up to 3 months, but be sure to thaw it before reheating so the chicken doesn’t clump together.", "equipment_tags": [], "portions": 3, "prep_minutes": 12, "prep_minutes_source": "explicit", "kcal": 972, "protein_g": 55.0, "carbs_g": 110.7, "fat_g": 32.6, "total_kcal": 2915, "total_protein_g": 165.1, "total_carbs_g": 332.2, "total_fat_g": 97.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=-222Dutomek"}, {"id": "53366", "name": "Beef and Broccoli Stir-Fry", "category": "Beef", "area": "Chinese", "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/m0p0j81765568742.jpg", "local_image": "53366.jpg", "ingredients": [{"ingredient": "Soy Sauce", "measure": "1 tsp"}, {"ingredient": "Dry sherry", "measure": "1 tsp"}, {"ingredient": "Cornstarch", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/8 teaspoon"}, {"ingredient": "Sirloin steak", "measure": "1 lb"}, {"ingredient": "Oyster Sauce", "measure": "2 tablespoons"}, {"ingredient": "Dry sherry", "measure": "1 tsp"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Chicken Stock", "measure": "1/4 cup"}, {"ingredient": "Broccoli", "measure": "1 lb"}, {"ingredient": "High Heat Cooking Oil", "measure": "2 tablespoons"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Cornstarch", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1 tablespoon"}], "instructions": "Marinate the beef:\r\nStir together the beef marinade ingredients (1 teaspoon soy sauce, 1 teaspoon Chinese rice wine, 1/2 teaspoon cornstarch, 1/8 teaspoon black pepper) in a medium bowl.\r\n\r\nAdd the beef slices and stir until coated. Let stand for 10 minutes.\r\n\r\nPrepare the sauce:\r\nStir together the sauce ingredients (2 tablespoons oyster sauce, 1 teaspoon Chinese rice wine, 1 teaspoon soy sauce, 1/4 cup chicken broth) in a small bowl. Set aside.\r\n\r\nBlanch or steam the broccoli:\r\nBring a pot of water to a boil. Add the broccoli and cook until crisp-tender, about 2 minutes. Drain thoroughly.\r\n\r\nStir-fry the beef:\r\nHeat a large frying pan or wok over high heat until a bead of water sizzles and instantly evaporates upon contact. Add the cooking oil and swirl to coat.\r\n\r\nAdd the beef and immediately spread it out all over the surface of the wok or pan in a single layer (preferably not touching).\r\n\r\nLet the beef fry undisturbed for 1 minute. Flip the beef slices over, add the garlic to the pan, and fry for an additional 30 seconds to 1 minute until no longer pink.\r\n\r\nAdd the sauce, cornstarch, and broccoli:\r\nPour in the sauce and the cornstarch slurry (1 teaspoon cornstarch dissolved in 1 tablespoon of water). Stir until the sauce boils and thickens, about 30 seconds. Stir in the broccoli.\r\n\r\nServe immediately, with steamed rice or on its own.", "equipment_tags": [], "portions": 2, "prep_minutes": 14, "prep_minutes_source": "explicit", "kcal": 597, "protein_g": 53.1, "carbs_g": 23.1, "fat_g": 33.0, "total_kcal": 1195, "total_protein_g": 106.2, "total_carbs_g": 46.2, "total_fat_g": 66.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=BBABeZjlRM8"}, {"id": "53367", "name": "Chicken Fried Rice", "category": "Chicken", "area": "Chinese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/wuyd2h1765655837.jpg", "local_image": "53367.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "1 lb"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Canola Oil", "measure": "3  tablespoons"}, {"ingredient": "Egg", "measure": "3 Large"}, {"ingredient": "Onion", "measure": "2/3 Cup"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Ground Ginger", "measure": "2 tsp"}, {"ingredient": "Carrots", "measure": "1 large"}, {"ingredient": "Peas", "measure": "2/3 Cup"}, {"ingredient": "Jasmine Rice", "measure": "4 cups"}, {"ingredient": "Scallions", "measure": "2 sliced"}, {"ingredient": "Chinese five spice powder", "measure": "1/2 tsp"}, {"ingredient": "Soy Sauce", "measure": "2.5 tbsp"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tsp"}], "instructions": "Fried rice is best made with leftover rice that's at least a day old. Otherwise it becomes gummy in the skillet.\r\nIf you don’t have any leftover rice from the night before, cook a batch of rice and spread it on a large baking sheet or several large plates. Let the rice dry out for about 1 to 2 hours before using it for fried rice.\r\n\r\nRice sticks to the pan very easily, so make sure to use a wok or pan that doesn’t have a sticky surface. I usually cook stir-fries in my seasoned carbon steel wok, but cast iron or nonstick pans work well, too. You might need to add a little more oil if things aren’t releasing easily.\r\n\r\nPrepare the chicken:\r\nChop the chicken into small 1/4-inch to 1/2-inch cubes. Sprinkle 1/2 teaspoon of salt over the chicken and mix to combine. Set the chicken aside for about 10 minutes (I usually use this time to chop all the vegetables).\r\n\r\nScramble the egg:\r\nHeat a wok or large sauté pan over medium-high heat. Swirl in a tablespoon of oil and add the whisked eggs. Use a spatula to quickly scramble the eggs, breaking the curds into smaller pieces as they come together. Transfer the eggs to a plate.\r\n\r\nCook the chicken:\r\nAdd another tablespoon of oil in the wok or pan. Add the chicken and cook for 4 to 5 minutes, stirring occasionally. Turn off the heat and transfer the cooked chicken to a plate.\r\n\r\nUsing your spatula, scrape off any chicken bits that are still stuck to the wok so they don't burn during the next step. You can also use paper towels to wipe down your wok or pan.\r\n\r\nCook the vegetables:\r\nSwirl 1 tablespoon of oil into the wok over medium-high heat. Add the diced onions and cook them for 1 minute, until they start to soften. Mix in the minced garlic and ginger and cook until fragrant, about 30 seconds. Add the diced carrots and cook for 2 minutes, stirring frequently. Add 1/2 teaspoon salt and the peas, and stir to incorporate.\r\n\r\nCook the rice:\r\nAdd the rice to the wok or pan on top of the vegetables and stir to combine. Using the back of your spatula, smash any large chunks of rice to break them apart. Add the white and green parts of the sliced scallions (save the dark green parts) and five-spice powder. Stir to incorporate. If the rice starts to stick to the pan, stir in a little more oil.\r\n\r\nDrizzle the soy sauce and sesame oil over the rice and stir to incorporate. Stir in the cooked chicken, scrambled eggs, and the dark parts of the scallions. Stir briefly to bring it together, and cook for another 1 to 2 minutes.\r\n\r\nServe:\r\nTaste, and add more soy sauce if necessary. Serve immediately.", "equipment_tags": [], "portions": 4, "prep_minutes": 140, "prep_minutes_source": "explicit", "kcal": 1115, "protein_g": 46.3, "carbs_g": 179.4, "fat_g": 21.0, "total_kcal": 4459, "total_protein_g": 185.4, "total_carbs_g": 717.4, "total_fat_g": 84.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=mUr-7wjhHuU"}, {"id": "53368", "name": "Singapore Noodles with Shrimp", "category": "Seafood", "area": "Chinese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/f3cxnc1765656994.jpg", "local_image": "53368.jpg", "ingredients": [{"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}, {"ingredient": "Soy Sauce", "measure": "2 tablespoons"}, {"ingredient": "Seasoned Rice Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Vermicelli Rice Noodles", "measure": "6 oz"}, {"ingredient": "Egg", "measure": "2 large"}, {"ingredient": "Ground Ginger", "measure": "2 tblsp"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Carrots", "measure": "2"}, {"ingredient": "Jalapeno", "measure": "1 sliced"}, {"ingredient": "Onion", "measure": "1/2"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Ham", "measure": "4 oz"}, {"ingredient": "Napa Cabbage", "measure": "1/2"}, {"ingredient": "Scallions", "measure": "4"}, {"ingredient": "Red Pepper", "measure": "1/2"}, {"ingredient": "Curry Powder", "measure": "2 tsp"}, {"ingredient": "Shrimp", "measure": "1/2 lb"}, {"ingredient": "Cilantro Leaves", "measure": "2 tablespoons"}], "instructions": "For the sweet onion, look for Vidalia, OSO Sweet, or Walla Walla. The super-sweet varieties are more suited to this stir-fry because at the end of cooking, the onion still has a slight crunch.\r\n\r\nMake the sauce:\r\nIn a bowl, combine the sesame oil, soy sauce, and rice vinegar.\r\n\r\nCook the rice noodles:\r\nBring a large saucepan of water to a boil, add the noodles, and use tongs to turn them so they are submerged. Cook for 2 minutes, or until they are tender but still have some bite (they will cook a little more once you add them to the skillet).\r\n\r\nDrain, rinse with cold water, and use scissors to snip the noodles several times to break them up into shorter lengths.\r\n\r\nScramble the eggs:\r\nIn a small bowl whisk together the eggs. Heat the skillet or Dutch oven over medium heat. Add 1 tablespoon of the peanut or canola oil. Add the eggs and scramble them for 2 minutes, or until they form large, soft curds. Transfer them from the pan to a plate or bowl.\r\n\r\nCook the vegetables:\r\nAdd 1 tablespoon of the remaining oil to the pan. When it is hot, add the ginger, garlic, carrots, jalapeño, onion, and salt. Cook, stirring constantly, for 2 minutes or until the vegetables start to soften.\r\n\r\nAdd the remaining ingredients:\r\nSprinkle the vegetable mixture with the remaining 1 tablespoon peanut or canola oil. When the oil is hot, add the ham, cabbage, scallions, red pepper, and curry powder to the pan. Cook, stirring constantly, for 1 minute.\r\n\r\nAdd the shrimp and cook, stirring, for 3 more minutes or until the shrimp are bright pink and cooked through.\r\n\r\nAdd the noodles in batches:\r\nAdd the eggs, the sauce mixture, and half the noodles to the pan. Toss for 1 minute.\r\n\r\nAdd the remaining noodles and continue tossing for 1 minute more until they are thoroughly combined and the mixture is heated through.\r\n\r\nServe:\r\nTaste for seasoning and add more salt or soy sauce, if you like. Sprinkle with cilantro leaves and serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 9, "prep_minutes_source": "explicit", "kcal": 761, "protein_g": 52.9, "carbs_g": 105.7, "fat_g": 16.0, "total_kcal": 1522, "total_protein_g": 105.8, "total_carbs_g": 211.5, "total_fat_g": 32.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=DiFUyPAGoug"}, {"id": "53369", "name": "Silken Tofu with Sesame Soy Sauce", "category": "Vegetarian", "area": "Chinese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/j9nray1765657692.jpg", "local_image": "53369.jpg", "ingredients": [{"ingredient": "Silken Tofu", "measure": "16 ounces"}, {"ingredient": "Soy Sauce", "measure": "3  tablespoons"}, {"ingredient": "Chinese Sesame Sauce", "measure": "2 tablespoons"}, {"ingredient": "Scallions", "measure": "1 sliced"}, {"ingredient": "Sesame Seed", "measure": "2 tsp"}], "instructions": "Prepare the tofu: \r\nDrain the tofu and gently remove it from its packaging onto a large plate. Carefully slice the tofu into 1/2-inch slabs widthwise. With the palm of your hands, gently push the sliced tofu sidewise so that they fan out over the plate.\r\n\r\nGarnish with toppings and serve:\r\nDrizzle the soy sauce and sesame sauce on top. Then garnish it with scallions and sesame seeds, and serve.\r\n\r\nTightly cover leftovers and refrigerate for up to 2 days. You can enjoy it cold straight out of the fridge or you can reheat it by microwaving in 30-second increments until warmed through", "equipment_tags": [], "portions": 10, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 37, "protein_g": 3.2, "carbs_g": 1.9, "fat_g": 2.0, "total_kcal": 374, "total_protein_g": 31.8, "total_carbs_g": 19.0, "total_fat_g": 20.2, "macro_confidence": 0.8, "is_new": false, "video": "https://www.youtube.com/shorts/bSLv5vFn5Z0"}, {"id": "53370", "name": "Egg Foo Young", "category": "Seafood", "area": "Chinese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/47y6ii1765658818.jpg", "local_image": "53370.jpg", "ingredients": [{"ingredient": "Unsalted Beef Stock", "measure": "1 cup"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Shaoxing Wine", "measure": "1 tablespoon"}, {"ingredient": "Oyster Sauce", "measure": "1 tablespoon"}, {"ingredient": "Pepper", "measure": "1/2 tsp"}, {"ingredient": "Cornstarch", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "1 tablespoon"}, {"ingredient": "Cornstarch", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "1 tablespoon"}, {"ingredient": "Egg", "measure": "8 large"}, {"ingredient": "Kosher Salt", "measure": "1/2 tsp"}, {"ingredient": "Sugar", "measure": "1/4 tsp"}, {"ingredient": "Spring Onions", "measure": "1"}, {"ingredient": "Mung Bean Sprouts", "measure": "1 cup"}, {"ingredient": "Shrimp", "measure": "20"}, {"ingredient": "Vegetable Oil", "measure": "3 Cups"}, {"ingredient": "Jasmine Rice", "measure": "2 cups"}], "instructions": "Make the gravy:\r\nIn a small saucepan, add the beef stock, soy sauce, Shaoxing wine, oyster sauce, and white pepper powder over medium heat. Whisk together and bring to a simmer. \r\n\r\nCombine the cornstarch and water in a small bowl and whisk to dissolve. Add to the saucepan and whisk until the gravy thickens and coats the back of the spoon, 2 to 3 minutes. Cover the saucepan with a lid and keep it warm on the lowest possible heat.\r\n\r\nMake the egg foo young batter:\r\nIn a medium bowl, whisk together the cornstarch and water until dissolved. Add the eggs, salt, and sugar. Whisk until well combined and there are no more egg white clumps. \r\n\r\nAdd the green onion, bean sprouts, and shrimp. Stir until everything is evenly coated.\r\n\r\nFry the egg foo young:\r\nAdd the vegetable oil to a large wok; it should reach about 2 inches up the sides. Heat the oil over medium-high heat to 350°F, or until vigorous bubbles form around an inserted wooden chopstick. \r\n\r\nWith a ladle, gently and slowly add 1/4 of the omelet batter. Egg foo young should immediately bubble and puff up like magic. Fry until golden brown and crispy on each side, about 2 minutes per side. If there are any light spots, use a ladle to gently baste it with hot oil.\r\n\r\nTip\r\nEgg foo young can be a bit tricky to flip. The easiest method is to put a tool in each hand (a spider, slotted spoon, tongs, and large chopsticks are all good candidates) and gently coax the omelet over, pulling up on one side and pushing down and around on the other.\r\n\r\nRemove the omelet and place it on a paper towel-lined baking sheet. Let it cool for 5 minutes. Meanwhile, repeat with the remaining batter to make 4 omelets. If needed, add more oil to the pan between batches.\r\n\r\nServe and enjoy:\r\nPlate each egg foo young over a bed of rice. Spoon the warm gravy over the top and serve immediately. ", "equipment_tags": [], "portions": 5, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 730, "protein_g": 58.6, "carbs_g": 77.9, "fat_g": 20.4, "total_kcal": 3652, "total_protein_g": 293.1, "total_carbs_g": 389.6, "total_fat_g": 102.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=XVTJrkgW304"}, {"id": "53371", "name": "Sichuan Style Stir-Fried Chinese Long Beans", "category": "Vegetarian", "area": "Chinese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/i0610h1765659464.jpg", "local_image": "53371.jpg", "ingredients": [{"ingredient": "Chinese Long Beans", "measure": "1/2 lb"}, {"ingredient": "Peanut Oil", "measure": "1 tablespoon"}, {"ingredient": "Dried Chillies", "measure": "6"}, {"ingredient": "Sichuan Pepper", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Sugar", "measure": "1/2 tsp"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tablespoon"}, {"ingredient": "Soy Sauce", "measure": "Splash"}], "instructions": "Chinese long beans can be found in both green and purple varieties. Both have similar flavors and textures, and either kind can be used for this recipe.\r\nIf you don't have a wok, use a sturdy, large sauté pan that has at least a two-inch lip.", "equipment_tags": [], "portions": 1, "prep_minutes": 19, "prep_minutes_source": "estimated", "kcal": 681, "protein_g": 27.1, "carbs_g": 84.8, "fat_g": 30.2, "total_kcal": 681, "total_protein_g": 27.1, "total_carbs_g": 84.8, "total_fat_g": 30.2, "macro_confidence": 0.88, "is_new": false, "video": "https://www.youtube.com/watch?v=7mzLphZJ3xc"}, {"id": "53372", "name": "Chinese Tomato Egg Stir Fry", "category": "Vegetarian", "area": "Chinese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/rwvw8q1765660071.jpg", "local_image": "53372.jpg", "ingredients": [{"ingredient": "Plum Tomatoes", "measure": "1 lb"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Eggs", "measure": "5 Large"}, {"ingredient": "Sesame Seed Oil", "measure": "1 tsp"}, {"ingredient": "Chicken Bouillon Powder", "measure": "2 tsp"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Pepper", "measure": "1/2 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Spring Onions", "measure": "1"}, {"ingredient": "Jasmine Rice", "measure": "2 cups"}], "instructions": "You can use chicken broth in place of the chicken bouillon powder. Add 1/4 cup of broth followed by 2 teaspoons of cornstarch dissolved in 1 tablespoPrepare the tomatoes:\r\nSlice the tomatoes in half. Remove the tough stem from each half that connects to the vine. Cut each half into equal thirds (you’ll get 6 slices from each tomato).\r\n\r\nMake the soft scrambled eggs:\r\nIn a cold, 8 to 10-inch nonstick skillet, add the vegetable oil and beaten eggs. Turn the heat to medium. Once a thin layer of eggs is just beginning to cook on the bottom, push the eggs in one direction to create layers of scrambled eggs.\r\n\r\nCook, gently stirring the whole time, until the scramble eggs are mostly set but still slightly wet and shiny, 2 to 5 minutes. Remove the eggs to a plate and, if needed, wipe out the pan.\r\n\r\nStir-fry the tomatoes and seasonings:\r\nAdd the sesame oil to the pan followed by the tomatoes and stir-fry over medium heat until the tomatoes are softened but not mushy, about 3 minutes. Add the chicken bouillon powder, sugar, and white pepper. Toss until combined and the sugar and bouillon have dissolved, about 1 minute.\r\n\r\nAdd eggs, stir-fry, and garnish:\r\nAdd the eggs back to the pan with the tomatoes. Stir-fry for about 2 minutes to heat through and combine. Taste, adding salt only if needed. Sprinkle with the green onions and serve with steamed rice.on of water, plus salt to taste.", "equipment_tags": [], "portions": 3, "prep_minutes": 11, "prep_minutes_source": "explicit", "kcal": 727, "protein_g": 23.3, "carbs_g": 121.7, "fat_g": 16.0, "total_kcal": 2180, "total_protein_g": 69.9, "total_carbs_g": 365.0, "total_fat_g": 48.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=Wn8ox93Qhus"}, {"id": "53373", "name": "Air Fryer Egg Rolls", "category": "Side", "area": "Chinese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/grhn401765687086.jpg", "local_image": "53373.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Ground Pork", "measure": "1 lb"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Ginger", "measure": "1 tablespoon"}, {"ingredient": "Carrots", "measure": "1 medium"}, {"ingredient": "Scallions", "measure": "3 chopped"}, {"ingredient": "Cabbage", "measure": "3 Cups"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Rice Vinegar", "measure": "1 tablespoon"}, {"ingredient": "Egg Roll Wrappers", "measure": "12"}, {"ingredient": "Oil", "measure": "For brushing"}, {"ingredient": "Duck Sauce", "measure": "To serve"}, {"ingredient": "Plum Sauce", "measure": "To serve"}, {"ingredient": "Soy Sauce", "measure": "To serve"}], "instructions": "Alternative Pan Fry Method: If you don’t have access to an air fryer, you can make these egg rolls using a traditional pan fry method. Add enough oil to a medium skillet with high walls so the oil is about 1/2 inch up the side of the skillet. Heat oil on medium high heat until it reaches 350°F. Add egg rolls and fry for 3 to 4 minutes, flip, and fry for another 3 to 4 minutes until golden brown. Remove and let them drain and cool on a few paper towels.\r\n\r\nCook the filling:\r\nIn a large skillet over medium heat, add the olive oil along with the ground pork or chicken. Break apart the meat with a spatula or wooden spoon as it cooks. Cook until the meat is cooked through, 6 to 8 minutes.\r\n\r\nAdd garlic, ginger, carrot, scallions, and cabbage. Continue to cook until cabbage wilts down and is soft, another 3 to 4 minutes, stirring regularly. Season the filling with soy sauce and rice wine vinegar, and take off the heat to cool. (This filling can be made in advance.)\r\n\r\nAssemble the egg rolls:\r\nPlace a single egg roll wrapper on a dry surface with one point of the square facing you (like a diamond). Place about 1/4 cup of the egg roll filling mixture in the middle of the wrapper.\r\n\r\nDip your fingers in water and run around the edges of the wrapper. Then fold the edges of the wrapper over the center and start rolling the egg roll away from you to form a tight cylinder. Place on a plate and repeat until you are out of filling. You should get at least a dozen egg rolls.\r\n\r\nAir fry the egg rolls:\r\nPlace the egg rolls in the basket of your air fryer. Spray or brush them lightly with oil. Add as many as you can without stacking the egg rolls, making sure they don’t touch. Air needs to circulate around them. Brush the egg rolls lightly with oil.\r\n\r\nPlace the basket in the air fryer and turn the air fryer to 350°F. Cook for 6 to 7 minutes, then flip the egg rolls, spray or brush with oil a second time on the bottom side, and cook for another 4 to 5 minutes.\r\n\r\nFinished egg rolls should be golden brown and crispy! Serve immediately.", "equipment_tags": ["AirFryer"], "portions": 12, "prep_minutes": 32, "prep_minutes_source": "explicit", "kcal": 200, "protein_g": 16.0, "carbs_g": 6.2, "fat_g": 12.6, "total_kcal": 2394, "total_protein_g": 191.7, "total_carbs_g": 74.9, "total_fat_g": 151.2, "macro_confidence": 0.93, "is_new": false, "video": "https://www.youtube.com/watch?v=XnA-wcVb4l0"}, {"id": "53374", "name": "Sichuan Eggplant", "category": "Vegetarian", "area": "Chinese", "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/1oz4nb1765687990.jpg", "local_image": "53374.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "1.5 pounds sliced"}, {"ingredient": "Peanut Oil", "measure": "2 tablespoons"}, {"ingredient": "Chicken Stock", "measure": "1/4 cup"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Soy Sauce", "measure": "1/2 tsp"}, {"ingredient": "Chilli Bean Paste", "measure": "1 ½ tbsp"}, {"ingredient": "Sichuan Pepper", "measure": "2 tsp"}, {"ingredient": "Ginger", "measure": "2 tsp"}, {"ingredient": "Garlic", "measure": "5 cloves"}, {"ingredient": "Cornstarch", "measure": "1 tsp"}, {"ingredient": "Apple Cider Vinegar", "measure": "2 tsp"}, {"ingredient": "Scallions", "measure": "4 Chopped"}, {"ingredient": "Cilantro", "measure": "Garnish"}], "instructions": "This recipe calls for asian eggplants, or Japanese eggplants. They are long and thin compared to a European or globe eggplant, and much more tender and delicate. If you can't find them you can substitute globe eggplant, but the dish is really best with the asian eggplant.\r\n\r\n*A lot of grocery stores have Asian ingredient aisles now. You should be able to find chili-bean paste, a mixture of preserved chilies mixed with mashed soybeans, there or at any Asian market. (Do not confuse with black bean paste or chili-garlic paste.)\r\n\r\n**Sichuan peppercorns are available at some stores and online for quite cheap. They aren't spicy like other peppers but rather have a citrusy flavor and induce a tingly, numbing sensation like a carbonated drink.\r\n\r\nPrep eggplant, chili sauce, cornstarch slurry, vinegar and scallions:\r\nBegin your mise en place. Quarter the eggplant lengthwise and chop into large batons and set aside.\r\n\r\nIn a small bowl, mix together the chicken stock, sugar, and soy sauce and set it aside.\r\n\r\nIn a second bowl, mix together the chili bean paste, garlic, ginger, and sichuan peppercorns and set it aside.\r\n\r\nIn a third bowl, mix together the cornstarch with a tablespoon of water and set it aside.\r\n\r\nLastly, in a fourth bowl, mix together the scallions and vinegar and set it aside.\r\n\r\nSauté eggplant:\r\nPlace the oil in a wok or large sauté pan over medium-high heat until the oil is almost smoking. Add the eggplant and sauté, allowing it to sit for a few seconds each time you move it to allow it to brown and blister. If the eggplant absorbs all the oil and some pieces don't get any then add a little more oil.\r\n\r\nAdd the chili bean paste, garlic, ginger, and sichuan peppercorns and sauté:\r\nuntil fragrant, about 30 seconds.\r\n\r\nAdd the chicken stock mixture:\r\nturn the heat to medium-low and simmer for 90 seconds.\r\n\r\nAdd the cornstarch mixture:\r\nand stir together until the sauce thickens a bit.\r\n\r\nAdd the scallions and vinegar:\r\nand cook for 15 seconds to diffuse their harsh flavors a bit.\r\n\r\nGarnish with cilantro and serve.", "equipment_tags": [], "portions": 2, "prep_minutes": 90, "prep_minutes_source": "estimated", "kcal": 711, "protein_g": 48.1, "carbs_g": 27.2, "fat_g": 48.5, "total_kcal": 1421, "total_protein_g": 96.3, "total_carbs_g": 54.5, "total_fat_g": 97.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=j54Af9gBmzo"}, {"id": "53375", "name": "Shrimp With Snow Peas", "category": "Seafood", "area": "Chinese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/fpl3mv1766433431.jpg", "local_image": "53375.jpg", "ingredients": [{"ingredient": "Cornstarch", "measure": "2 tsp"}, {"ingredient": "Dry sherry", "measure": "1 tablespoon"}, {"ingredient": "Kosher Salt", "measure": "1/2 tsp"}, {"ingredient": "Shrimp", "measure": "1 lb"}, {"ingredient": "Peanut Oil", "measure": "2 tablespoons"}, {"ingredient": "Ground Ginger", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Snow Peas", "measure": "1/2 lb"}, {"ingredient": "Soy Sauce", "measure": "2 tsp"}, {"ingredient": "Chicken Stock", "measure": "1/4 cup"}, {"ingredient": "Scallions", "measure": "4"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}], "instructions": "You can also use sugar snap peas for this recipe. Save prep time by prepping the peas, ginger, and garlic while the shrimp is marinating.\r\n\r\nMarinate the shrimp:\r\nMix all marinade ingredients in a large bowl, then add the shrimp. Toss to coat. Let sit for 15 to 20 minutes while you prep the peas, ginger, and garlic.\r\n\r\nStir-fry the ginger and garlic:\r\nHeat a wok or large sauté pan over high heat for 1 minute. Add the peanut oil and let it get hot, about 30 seconds. Add the ginger and garlic and toss to combine. Stir-fry for about 30 seconds.\r\n\r\nAdd the shrimp, snow peas, soy sauce, stock:\r\nAdd the shrimp and all the marinade to the pan (scrape out all the marinade with a rubber spatula). Add the snow peas, soy sauce and chicken stock. Stir-fry until the shrimp turns pink, about 2 minutes.\r\n\r\nAdd the scallions and finish with sesame oil:\r\nAdd the scallions and stir-fry 1 more minute. Turn off the heat and add the sesame oil. Toss to combine once more and serve with steamed rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 23, "prep_minutes_source": "explicit", "kcal": 543, "protein_g": 54.8, "carbs_g": 35.8, "fat_g": 20.6, "total_kcal": 1086, "total_protein_g": 109.6, "total_carbs_g": 71.6, "total_fat_g": 41.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=RmbTaEqabN4"}, {"id": "53376", "name": "Sweet and Sour Chicken", "category": "Chicken", "area": "Chinese", "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/arzs741766434335.jpg", "local_image": "53376.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "1 lb"}, {"ingredient": "Egg White", "measure": "1 large"}, {"ingredient": "Kosher Salt", "measure": "1 tsp"}, {"ingredient": "Cornstarch", "measure": "2 tsp"}, {"ingredient": "Pineapple Chunks", "measure": "10 oz"}, {"ingredient": "Pineapple Juice", "measure": "1/4 cup"}, {"ingredient": "White Vinegar", "measure": "1/4 cup"}, {"ingredient": "Tomato Ketchup", "measure": "1/4 cup"}, {"ingredient": "Brown Sugar", "measure": "3  tablespoons"}, {"ingredient": "Oil", "measure": "4 tsp"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Yellow Pepper", "measure": "1 chopped"}, {"ingredient": "Ginger", "measure": "1 tsp"}], "instructions": "Coat the chicken with egg white:\r\nIn a bowl, combine the chicken with the egg white, 1/2 teaspoon kosher salt, and cornstarch. Stir to coat the chicken evenly. Let sit for 15 minutes at room temperature or up to overnight in the refrigerator.\r\n\r\nMake the sweet and sour sauce:\r\nWhisk together the pineapple juice, vinegar, ketchup, 1/2 teaspoon kosher salt, and brown sugar.\r\n\r\nStir-fry the chicken over high heat:\r\nHeat a large frying pan or wok over high heat until a bead of water instantly sizzles and evaporates. Pour in 1 tablespoon of cooking oil and swirl to coat. It's important that the pan is very hot.\r\n\r\nAdd the chicken and spread the pieces out in one layer. Let the chicken fry untouched for 1 minute, until the bottoms are browned.\r\n\r\nFlip and fry the other side for 1 minute. The chicken should still be pinkish in the middle. Dish out the chicken onto a clean plate, leaving as much oil in the pan as possible.\r\n\r\nStir-fry the bell pepper and ginger:\r\nReduce the heat to medium and add the remaining 1 teaspoon of cooking oil. Let the oil heat up before adding the bell pepper chunks and ginger. Fry for 1 minute.\r\n\r\nAdd the pineapple, sauce, and then, the chicken:\r\nAdd the pineapple chunks and the sweet and sour sauce. Turn up the heat to high. When the sauce is simmering, add the chicken pieces back in.\r\n\r\nLet simmer for 1 to 2 minutes, until the chicken is cooked through. Timing depends on how thick you've cut your chicken. The best way to tell if the chicken is done is to take a piece out and cut into it. If it's pink, add another minute to the cooking.\r\n\r\nAdjust the seasoning and serve:\r\nTaste the sauce and add more brown sugar or vinegar to suit your tastes, if you’d like.\r\n\r\nServe hot with steamed white or brown rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 556, "protein_g": 49.4, "carbs_g": 47.9, "fat_g": 17.2, "total_kcal": 1112, "total_protein_g": 98.7, "total_carbs_g": 95.8, "total_fat_g": 34.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=cblsP5S9PhU"}, {"id": "53377", "name": "Napa Cabbage with Dried Shrimp", "category": "Seafood", "area": "Chinese", "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/9nh4dl1766435484.jpg", "local_image": "53377.jpg", "ingredients": [{"ingredient": "Dried Shrimp", "measure": "2 tablespoons"}, {"ingredient": "Boiling Water", "measure": "3/4 cup"}, {"ingredient": "Napa Cabbage", "measure": "1 head"}, {"ingredient": "Peanut Oil", "measure": "2 tablespoons"}, {"ingredient": "Scallions", "measure": "4 Chopped"}, {"ingredient": "Ginger", "measure": "1 tablespoon"}, {"ingredient": "Soy Sauce", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "1 tablespoon"}, {"ingredient": "Cornstarch", "measure": "2 tsp"}, {"ingredient": "Kosher Salt", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1/2 tsp"}], "instructions": "Dried shrimp gives this Chinese dish a punch of salty umami flavor. You can find it at an Asian grocery store in the frozen or refrigerated section. Look for small-sized dried shrimp, about a 1/4-inch in size. If you use medium or large dried shrimp, hydrate the shrimp with more water (1 cup for medium-sized shrimp, 1 1/4 cup for large) and for longer time (45 to 60 minutes), then chop it up into smaller 1/4-inch chunks. To make this recipe vegetarian, omit the dried shrimp and use four or five dried shiitake mushrooms, rehydrated, and sliced thin.\r\n\r\nRehydrate the dried shrimp:\r\nPlace the dried shrimp in a small bowl and pour the boiling water over it. Cover with a small plate and let sit for 30 minutes so the shrimp can rehydrate. The shrimp will be lighter in color and plump up slightly.\r\n\r\nPrep the cabbage:\r\nMeanwhile, split the napa cabbage in half lengthwise. Rinse the cabbage and shake it dry. Cut out the core of the cabbage and discard.\r\n\r\nSet out two large bowls. Cut the remaining cabbage into 1-inch pieces, putting the thicker white pieces at the bottom of the cabbage into one bowl and the top thinner leafy green pieces into the other bowl.\r\n\r\nDrain the shrimp:\r\nOnce the shrimp has rehydrated, drain it and discard the liquid.\r\n\r\nCook the shrimp and cabbage:\r\nIn a large wok or skillet over high heat add the peanut oil, swirling it around to coat the pan.\r\n\r\nHeat until the oil looks shimmering hot, then carefully add the scallions, ginger, and rehydrated shrimp, paying specially attention as the wet ingredients may cause the hot oil to splatter. Toss with a spatula until the scallions are bright green and the entire mixture is fragrant, about 1 minute.\r\n\r\nAdd the thicker white part of the napa cabbage to the pan and lower the heat to medium high. Continue to cook and stir for 3 to 4 minutes, or until the edges of the cabbage pieces start to look slightly translucent but the center of the cabbage pieces are still opaque white.\r\n\r\nReduce the heat to medium low and add the leafy green pieces of cabbage into the pan. Cook until the leaves are wilted, about 2 minutes.\r\n\r\nMake a cornstarch slurry:\r\nIn a small bowl, combine the soy sauce, cold water, and cornstarch, stirring to make a slurry. Then pour over the cabbage and continue to cook and stir until a sauce has thickened slightly to the consistency of whole milk.\r\n\r\nSeason the stir fry:\r\nSeason the stir fry with salt and pepper, then taste and add more salt and pepper if you wish. The cabbage will be translucent and silky looking, with specks of dried shrimp all over.", "equipment_tags": [], "portions": 1, "prep_minutes": 97, "prep_minutes_source": "explicit", "kcal": 410, "protein_g": 12.0, "carbs_g": 31.7, "fat_g": 28.5, "total_kcal": 410, "total_protein_g": 12.0, "total_carbs_g": 31.7, "total_fat_g": 28.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=Fj0JALB4_5k"}, {"id": "53378", "name": "Sesame Cucumber Salad", "category": "Side", "area": "Chinese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/93iok31766436070.jpg", "local_image": "53378.jpg", "ingredients": [{"ingredient": "Cucumber", "measure": "2 medium"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Sesame Seed Oil", "measure": "2 tsp"}, {"ingredient": "Rice Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Basil Leaves", "measure": "6"}, {"ingredient": "Red Chilli Flakes", "measure": "1/2 tsp"}, {"ingredient": "Sesame Seed", "measure": "2 tsp"}], "instructions": "Prep the cucumbers:\r\nPeel the cucumbers. Cut them into quarters, lengthwise. (If the seeds are bitter, scrape out the seeds and discard.) Cut the cucumbers again, crosswise, into 1/2-inch thick pieces.\r\n\r\nToss the salad:\r\nPlace cucumbers into a serving bowl. Sprinkle with salt. Toss with sesame oil, seasoned rice vinegar, basil (if using), and chili flakes. Sprinkle with toasted sesame seeds if using.", "equipment_tags": [], "portions": 1, "prep_minutes": 40, "prep_minutes_source": "estimated", "kcal": 160, "protein_g": 2.6, "carbs_g": 6.3, "fat_g": 14.3, "total_kcal": 160, "total_protein_g": 2.6, "total_carbs_g": 6.3, "total_fat_g": 14.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=q37qn81lg5c"}, {"id": "53379", "name": "Dutch poffertjes (mini pancakes)", "category": "Breakfast", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/oaqz9f1766593912.jpg", "local_image": "53379.jpg", "ingredients": [{"ingredient": "Flour", "measure": "125g"}, {"ingredient": "Buckwheat Flour", "measure": "125g"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Butter", "measure": "1 knob"}, {"ingredient": "Milk", "measure": "300ml"}, {"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "vanilla sugar", "measure": "1tsp"}, {"ingredient": "Butter", "measure": "To serve"}, {"ingredient": "Icing Sugar", "measure": "To serve"}], "instructions": "Mix the dry yeast with some of the luke warm milk en stir until dissolved.\r\nPlace buckwheat and the flour together in a bowl and make a small circle in the middle. Add the yeast mixture into it. Add the milk and stir until you have a smooth batter.\r\nAdd the eggs, salt and vanille sugar and stir through. Leave to stand and rise for about 45 minutes.\r\nHeat the poffertjespan and add a bit of butter into each hole. Fill halfway with batter and first bake one side until you can see the top dry out a little. Turn the poffertjes around with a small fork and bake the other side until cooked and golden brown.\r\nServe the poffertjes with butter and icing sugar", "equipment_tags": [], "portions": 3, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 565, "protein_g": 18.7, "carbs_g": 78.2, "fat_g": 20.9, "total_kcal": 1694, "total_protein_g": 56.0, "total_carbs_g": 234.6, "total_fat_g": 62.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=gK1b5gymAUY"}, {"id": "53380", "name": "Apple cake", "category": "Dessert", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/c0gmo31766594751.jpg", "local_image": "53380.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Sugar", "measure": "200g"}, {"ingredient": "Self-raising Flour", "measure": "200g"}, {"ingredient": "Melted Butter", "measure": "200g"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "1 tsp"}, {"ingredient": "Apples", "measure": "3"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Ground Sugar", "measure": "Sprinkling"}], "instructions": "Preheat the oven to 180°C. (350˚F) Grease a cake pan and line it with baking paper.\r\nIn a large bowl, break the four eggs with the sugar and beat until they have tripled in volume and become fluffy.\r\nSift the self-rising baking flour and add it to your egg mixture. Fold this over, preserving as much air as possible. Add the melted (and slightly cooled) butter and mix until combined.\r\nAdd cinnamon, pinch of salt and vanilla extract.\r\nAdd the diced apple to the batter and gently fold them into the batter so that the apple pieces are evenly distributed. You can roll the apple pieces through some more cinnamon.\r\nPour the batter into the prepared cake pan and smooth the top with a spatula.\r\nPlace the apple slices on top of the batter and press lightly. Sprinkle optionally with some almond shavings.\r\nBake the apple cake in the preheated oven for about 45-50 minutes, or until a wooden skewer comes out clean when inserted into the center of the cake.\r\nRemove the cake from the oven and let it cool in the mold for a few minutes. Then carefully remove the cake from the mold and let cool completely on a wire rack.\r\nSprinkle the cooled apple cake with powdered sugar", "equipment_tags": [], "portions": 7, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 482, "protein_g": 6.8, "carbs_g": 58.9, "fat_g": 26.3, "total_kcal": 3375, "total_protein_g": 47.5, "total_carbs_g": 412.1, "total_fat_g": 184.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=vZy-7UyPdjM"}, {"id": "53381", "name": "Gevulde speculaas", "category": "Dessert", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/rw64di1766595573.jpg", "local_image": "53381.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "300g"}, {"ingredient": "Brown Sugar", "measure": "150g"}, {"ingredient": "Speculaas Spice Mix", "measure": "10g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Milk", "measure": "10 tblsp"}, {"ingredient": "Almond Paste", "measure": "300g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Milk", "measure": "For brushing"}, {"ingredient": "Almonds", "measure": "Garnish"}], "instructions": "Mix the self-rising flour, sugar, speculaas spice mix and salt. Add the butter and milk and knead into a firm ball of dough. Start with 6 tablespoons of milk, if the dough is too stiff you can add more milk.\r\nWrap the dough in plastic wrap and refrigerate overnight. You can process and bake it immediately, but the flavor will be much better if you let it rest.\r\nMix the almond paste with half of the beaten egg and knead well. This makes it easier to work with and gives it a better and tastier texture.\r\nTake half of the dough and roll it out to 20 x 20 cm. Place in a baking pan lined with parchment paper. Spread the almond paste mixture evenly. Roll out the remaining dough and place on top of the almond paste.\r\nBrush the top with the remaining beaten egg. Garnish with almonds and top with another layer of egg wash.\r\nBake the filled speculaas for 40 minutes at 180°C/350℉ (conventional oven) or until done.", "equipment_tags": [], "portions": 8, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 389, "protein_g": 6.9, "carbs_g": 54.4, "fat_g": 17.9, "total_kcal": 3109, "total_protein_g": 55.2, "total_carbs_g": 435.4, "total_fat_g": 143.0, "macro_confidence": 0.8, "is_new": false, "video": "https://www.youtube.com/watch?v=1BYSZIkLOHc"}, {"id": "53382", "name": "Dutch stroopwafel", "category": "Dessert", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8cvkcz1766596315.jpg", "local_image": "53382.jpg", "ingredients": [{"ingredient": "Milk", "measure": "15 ml"}, {"ingredient": "Instant Yeast", "measure": "10g"}, {"ingredient": "All purpose flour", "measure": "250g"}, {"ingredient": "Unsalted Butter", "measure": "120g"}, {"ingredient": "Sugar", "measure": "80g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Dutch Stroop", "measure": "200g"}, {"ingredient": "Brown Sugar", "measure": "120g"}, {"ingredient": "Unsalted Butter", "measure": "80g"}, {"ingredient": "Cinnamon", "measure": "1 tsp"}], "instructions": "Combine milk and yeast in a bowl. Let stand for a moment to allow the yeast to dissolve.\r\nIn another bowl, combine flour, butter, sugar, egg, and salt. Pour in the yeast mixture and knead until smooth. Cover the bowl and let the dough rise for one hour.\r\nWhen the dough is almost ready, make the stroop filling. Combine all the ingredients in a saucepan and stir until the butter is melted and the sugar is dissolved. Let it simmer for a while. The stroop will continue to thicken as it cools.\r\nShape the dough into balls weighing about 35 grams each. Make a total of 14. Turn your stroopwafel iron on the highest setting.\r\nPlace a ball of dough in the iron and close the iron. Don’t flatten the waffle too much; you should still be able to cut through it. Bake for 1-2 minutes until the waffle is nicely golden brown.\r\nWhen the waffle is done, work quickly. Remove the waffle from the iron and immediately use a round cutter to cut out a nice circle of about 8 to 9 cm (3 to 3.5 inches).\r\nPlace the hot waffle on a cutting board and cut horizontally with a sharp knife. The stroopwafel is very hot, so use an oven mitt to hold it in place.\r\nTake half a waffle and spread the (hot!) stroop on it. Place the other half on top, pressing gently if necessary, and place the waffle on a wire rack to cool. Repeat for all the balls.", "equipment_tags": [], "portions": 6, "prep_minutes": 2, "prep_minutes_source": "explicit", "kcal": 589, "protein_g": 8.0, "carbs_g": 71.2, "fat_g": 31.1, "total_kcal": 3535, "total_protein_g": 48.0, "total_carbs_g": 427.2, "total_fat_g": 186.8, "macro_confidence": 0.91, "is_new": false, "video": "https://www.youtube.com/watch?v=3zCrERE0kbc"}, {"id": "53383", "name": "Ramen Noodles with Boiled Egg", "category": "Miscellaneous", "area": "Chinese", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ip5xtp1769779958.jpg", "local_image": "53383.jpg", "ingredients": [{"ingredient": "Noodles", "measure": "1 Packet"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Egg", "measure": "1 large"}, {"ingredient": "Soy Sauce", "measure": "1 tbsp"}, {"ingredient": "Chilli Sauce", "measure": "1/2 tsp"}, {"ingredient": "Spring Onions", "measure": "1 tbls"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Pepper", "measure": "1/2 tbs"}], "instructions": "Boil: Bring water to a boil, gently add eggs, and cook for exactly 6½ to 7 minutes.\r\nIce Bath: Immediately transfer the eggs to a bowl of ice water for 3–5 minutes to stop cooking.\r\nMarinate (Optional but recommended): Peel the eggs and marinate in a mix of 2 tbsp soy sauce, 2 tbsp mirin, 1 tsp sugar, and 4 tbsp water for at least 4 hours (or overnight).\r\nServe: Slice in half, letting the yolk flow into the broth", "equipment_tags": [], "portions": 2, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 136, "protein_g": 7.5, "carbs_g": 19.7, "fat_g": 3.8, "total_kcal": 272, "total_protein_g": 15.0, "total_carbs_g": 39.3, "total_fat_g": 7.6, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=AbJNVnkndS4"}, {"id": "53385", "name": "Boterkoek (Dutch Butter Cake)", "category": "Dessert", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tkwxmv1777540463.jpg", "local_image": "53385.jpg", "ingredients": [{"ingredient": "Butter", "measure": "200g"}, {"ingredient": "Sugar", "measure": "200g"}, {"ingredient": "All purpose flour", "measure": "250g"}, {"ingredient": "Salt", "measure": "1"}, {"ingredient": "Dulce de leche", "measure": "200g"}, {"ingredient": "Dark Chocolate", "measure": "75g"}, {"ingredient": "Egg", "measure": "1 beaten"}], "instructions": "Preheat the oven to 180°C/350˚F (conventional oven).\r\n\r\nPlace the softened butter and sugar in the bowl of a stand mixer and whisk until creamy.\r\nAdd the flour and salt and knead by hand until you have a smooth dough. Divide into two pieces.\r\nLine the base of a square or round cake tin with baking parchment (not a springform tin) and place the first half of the pastry on top. Flatten with your fingers and a spoon.\r\nUsing a teaspoon, sprinkle dollops of dulce de leche over the base. Sprinkle with the chopped chocolate and cover with the second half of the pastry.\r\nThis is a bit trickier, but if you don’t get it right, don’t worry, it’ll be fine once it’s baked! Brush the pastry with the beaten egg.\r\nBake in the oven for about 30 minutes or until golden brown. It will be wobbly. That's because butter cake only firms up when it cools.\r\nCut into small pieces when it has cooled completely!\r\nNotes\r\nStoring: Store in an airtight container outside of the fridge for about 2-3 days or in the fridge for 5 days. Freeze for up to three months.", "equipment_tags": [], "portions": 7, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 604, "protein_g": 7.6, "carbs_g": 78.1, "fat_g": 29.8, "total_kcal": 4229, "total_protein_g": 53.1, "total_carbs_g": 546.5, "total_fat_g": 208.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=IwAfFVjPVl4"}, {"id": "53386", "name": "Dutch Apple Pie", "category": "Dessert", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/zy4fs51777540384.jpg", "local_image": "53386.jpg", "ingredients": [{"ingredient": "Butter", "measure": "175g"}, {"ingredient": "Egg Yolks", "measure": "2"}, {"ingredient": "Flour", "measure": "300g"}, {"ingredient": "Sugar", "measure": "200g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Cinnamon", "measure": "1"}, {"ingredient": "Raisins", "measure": "100g"}, {"ingredient": "Apples", "measure": "6"}, {"ingredient": "Cold Water", "measure": "1 tablespoon"}], "instructions": "Add the flour, 150 gr of the sugar, pinch of salt and 1 egg yolk in the bowl of a food processor. Cut the butter into small cubes and add to the bowl. Turn this into a firm dough. Don't over process, you do not want the dough to turn warm. Check if it sticks by pinching it between your fingers.\r\nTurn out onto a piece of plastic wrap. Make a round ball of it by using your hands and roll it into the plastic. Place into the fridge for half an hour to cool.\r\nTake a round baking tin of 22 cm diameter and cover this with baking paper. Brush the sides with butter.\r\nPreheat the oven to 170˚C (340˚F)\r\nCut the apple into cubes and mix this with the raisins, the left over sugar and the cinnamon.\r\nPlace the cooled dough on a flat surface sprinkled with flour and roll out into a thin sheet. Place this into the baking tin and cover the bottom and the sides well. I usually just press it into the tin without rolling it out. I find that the easiest way but it is less smooth. Just do whatever works for you.\r\nMake sure you keep 1/4 of the dough separate to form the strips on the top.\r\n\r\nOnce the bottom and sides are covered with the dough, take the rusks and crumble them over the bottom. You can use breadcrumbs for this as well. Shake it a bit so it is divided equally across the bottom.\r\nAdd the apple mixture and divide well over the tin. Rol out the rest of the dough and cut into strips. Place that over the top of the pie in a diamond shaped pattern. Brush the strokes and sides with the other egg yolk and place in the preaheated oven.\r\nBake the apple pie for about 1 hour or until golden and cooked through. Leave to cool in the tin and make sure the sides are loose before opening the tin.", "equipment_tags": ["FoodProcessor"], "portions": 8, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 488, "protein_g": 6.5, "carbs_g": 69.2, "fat_g": 21.6, "total_kcal": 3900, "total_protein_g": 51.6, "total_carbs_g": 553.6, "total_fat_g": 172.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=MgI-_e4R53Y"}, {"id": "53387", "name": "Dutch Spiced Breakfast Cake (Ontbijtkoek)", "category": "Dessert", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/uwq8001777540502.jpg", "local_image": "53387.jpg", "ingredients": [{"ingredient": "Self-raising Flour", "measure": "250g"}, {"ingredient": "Dark Brown Soft Sugar", "measure": "250g"}, {"ingredient": "Milk", "measure": "250g"}, {"ingredient": "Sugar", "measure": "4"}, {"ingredient": "Ginger", "measure": "1 tablespoon"}, {"ingredient": "Cardamom", "measure": "1/2 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "Preheat the oven to 160˚C (320˚F) Line a cake pan with parchment paper and set aside.\r\n\r\nMix all the dry ingredients together in a large bowl. Place the milk in a small saucepan and heat it until it is almost boiling but not quite.\r\nPour the milk slowly into the dry ingredients while whisking. Don't overmix! As soon as it is combined to a smooth batter you pour it into the cake pan. Sprinkle the pearl sugar over the top and bake it in the oven for about 1 hour.\r\nCheck after about 50 minutes how the cake is progressing. If a cake tester comes out clean the cake it cooked. If not let it cook for a little longer.", "equipment_tags": [], "portions": 6, "prep_minutes": 110, "prep_minutes_source": "explicit", "kcal": 457, "protein_g": 5.4, "carbs_g": 110.1, "fat_g": 1.8, "total_kcal": 2741, "total_protein_g": 32.3, "total_carbs_g": 660.3, "total_fat_g": 11.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/3NIRQ3KMorw"}, {"id": "53388", "name": "Runner Bean Mash (Snijbonen Stamppot)", "category": "Side", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/urq5w21777540535.jpg", "local_image": "53388.jpg", "ingredients": [{"ingredient": "Runner Beans", "measure": "400g"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Potatoes", "measure": "800g"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Mustard", "measure": "1 tablespoon"}, {"ingredient": "Milk", "measure": "1 dash"}, {"ingredient": "Cheese", "measure": "100g"}, {"ingredient": "Bacon", "measure": "75g"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "Wash and chop the runner beans. Place in a saucepan with salted water and bring to a boil.\r\nCook the beans for about 10 minutes or until al dente. Drain and set aside.\r\nMeanwhile, add the potatoes and cook until tender.\r\nHeat a small skillet with a little butter and sauté the onion until translucent. Add the garlic and cook briefly. Add the runner beans to the pan and stir-fry for a few minutes.\r\nMeanwhile, mash the potatoes with a masher. Add a knob of butter and a splash of milk. Add the bean mixture and grated cheese. Season with salt, pepper and mustard.\r\nFry the bacon and serve with the bean mash.", "equipment_tags": [], "portions": 8, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 265, "protein_g": 13.1, "carbs_g": 30.3, "fat_g": 10.4, "total_kcal": 2118, "total_protein_g": 104.9, "total_carbs_g": 242.4, "total_fat_g": 83.2, "macro_confidence": 0.9, "is_new": false, "video": null}, {"id": "53389", "name": "Apple Potato Mash (Hete bliksem) ", "category": "Side", "area": "Netherlands", "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/pa03n41777540582.jpg", "local_image": "53389.jpg", "ingredients": [{"ingredient": "Apples", "measure": "250g"}, {"ingredient": "Potatoes", "measure": "250g"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Maple Syrup", "measure": "1 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "Sprinkling"}, {"ingredient": "Bacon", "measure": "4"}, {"ingredient": "Cheese", "measure": "200g"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Sesame Seed", "measure": "50g"}], "instructions": "Clean and peel the potatoes and cut them into even size chunks. Boil them in salted water for about 10 min and then add the cleaned and chopped apples into the boiling water. Add the cinnamon stick as well. Leave to boil for another 10 minutes or until both apples and potatoes are to your liking. I like mine to be fairly chunky but that is a personal preference\r\nIn the mean time bake the streaky bacon in a dry frying pan until crispy and set aside to drain on paper towels.\r\nSlice a few apple pieces and melt a little butter in a fryin pan. Add the apple slices to it and add a bit of maple syrup into the pan as well as some cinnamon. Let it simmer until the apple is soft.\r\nPrepare a plate with one whisked egg and one plate with sesame seeds. Cut your cheese into the required size. The smaller it is, the easier it is too handle.\r\nDip the cheese into the egg and make sure it coats all sides. Then dip the cheese into the sesame seeds and make sure it is covered everywhere.\r\nHeat a non stick frying pan on high until nice and hot. Put the cheese slice in and bake until the sesame seeds are brown. You have to do this rather quickly or the cheese will melt completely. Turn and bake the other side.\r\nDrain the apples and potatoes and mash them together. Taste and add cinnamon and salt where needed. Remove the cinnamon stick before mashing", "equipment_tags": [], "portions": 6, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 416, "protein_g": 23.9, "carbs_g": 17.6, "fat_g": 28.5, "total_kcal": 2496, "total_protein_g": 143.5, "total_carbs_g": 105.9, "total_fat_g": 170.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53391", "name": "Traditional Dutch rice tart (rijstevlaai)", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/x8opo81777582259.jpg", "local_image": "53391.jpg", "ingredients": [{"ingredient": "Flour", "measure": "200g"}, {"ingredient": "Coconut Oil", "measure": "75g"}, {"ingredient": "Vegetable Millk", "measure": "100g"}, {"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "Sugar", "measure": "50g"}, {"ingredient": "Dessert Rice", "measure": "150g"}, {"ingredient": "Sugar", "measure": "100g"}, {"ingredient": "Vegetable Millk", "measure": "700g"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Cardamom", "measure": "2"}, {"ingredient": "Star Anise", "measure": "2"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Baking Powder", "measure": "1/2 tsp"}, {"ingredient": "Lemon Juice", "measure": "1/2 tsp"}], "instructions": "Heat the oven to 180°C. For the dough, mix flour and sugar in a bowl. Heat the 100 grams of milk to lukewarm and dissolve the yeast in it. Let stand for a while until it starts to bubble. Then add to the flour along with the coconut oil and mix into a smooth dough. Let rise for 30 minutes, covered, in a warm place.\r\nMeanwhile, make the rice pudding by putting the rice with sugar, milk and vanilla extract in a saucepan. Add the cardamom, star anise and cinnamon. Bring to a boil and cook, stirring constantly. Take out the spices. In a small bowl, mix baking soda with lemon juice/apple vinegar. Stir well until baking soda is dissolved, then mix into the rice pudding.\r\nRoll out the dough on a floured work surface (it is very sticky, but don’t stress it will be fine) and line the bottom and edges of a greased mold with it. Spread the rice pudding over the bottom and bake for about 25 to 30 minutes.", "equipment_tags": [], "portions": 9, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 312, "protein_g": 5.7, "carbs_g": 52.5, "fat_g": 9.0, "total_kcal": 2810, "total_protein_g": 51.1, "total_carbs_g": 472.8, "total_fat_g": 80.8, "macro_confidence": 0.86, "is_new": false, "video": "https://www.youtube.com/watch?v=Od8EjjvwN_Y"}, {"id": "53392", "name": "Arnhemse meisjes", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/y4t9zg1777628842.jpg", "local_image": "53392.jpg", "ingredients": [{"ingredient": "Puff Pastry", "measure": "5 Slices"}, {"ingredient": "vanilla sugar", "measure": "100g"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Cardamom", "measure": "1/2"}, {"ingredient": "Lime", "measure": "Zest of 1"}], "instructions": "Take your puff pastry from the freezer and defrost.\r\nSprinkle some flour on the kitchen counter. Stack the sheets of puff pastry on top of each other and roll them out with a rolling pin. You want those five sheets to end up being as thin as one sheet.\r\n\r\nUsing a round or oval form press into the puff pastry and try to be as economical doing that as possible. You want to have as many cookies as you can.\r\nMix the vanilla sugar with the cinnamon, cardemom and limezest in a little bowl\r\nRemove the flour from the counter and sprinkle with a bit of the sugar mix.\r\nBrush your puff pastry with a little bit of eggwash and than dip into the sugar mix and roll them softly to press the sugar in.\r\nPut your sugary puff pastry on a baking sheet (greased or with baking paper) and leave the dough to rest for about 20 to 25 minutes. this will make the cookies even crisper.\r\nPreheat the oven in the meantime to 180 C and put the baking tray in the oven.\r\nbake the cookies golden brown in about 25 minutes and make sure the sugar is caramelised nicely\r\nAnd voila, Girls from Arnhem with an Almeerse twist\r\nVoila, Arnhemse Meisjes met een Almeerse twist.", "equipment_tags": [], "portions": 2, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 502, "protein_g": 4.0, "carbs_g": 37.5, "fat_g": 25.1, "total_kcal": 1004, "total_protein_g": 8.0, "total_carbs_g": 75.0, "total_fat_g": 50.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=AFJm15R4YYw"}, {"id": "53393", "name": "Dutch doughnuts", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/cz1d6v1777627421.jpg", "local_image": "53393.jpg", "ingredients": [{"ingredient": "Flour", "measure": "500g"}, {"ingredient": "Milk", "measure": "500ml"}, {"ingredient": "Instant Yeast", "measure": "10g"}, {"ingredient": "Salt", "measure": "10g"}, {"ingredient": "Sugar", "measure": "25g"}], "instructions": "Place the flour in a large bowl and add the yeast and sugar. If the milk is cold make sure to heat it to lukewarm. Mix your flour mixture bit by bit with the milk until you have a smooth batter. Add the salt and mix with a wooden spoon till the batter is smooth and liquidy.\r\nCover with a clean tea towel and leave in a warm spot for about an hour to rise.\r\n\r\nHeat your deep fryer or add the oil to a large pot. The oil should be a t 180˚C (350˚F) for best results.\r\nBefore starting stir your batter through and scoop the batter with two spoons or with an ice cream scoop. Let it drop into the oil carefully. It is easiest to do this if you dip your spoons or scoop into the oil before dipping into the batter. That way it will slide of the spoons easily. Don't over crowd the fryer to prevent the oil cooling down too quickly and everything sticking together. Once one side is golden brown it usually turns around to the other side automatically. If not help it along with two forks.\r\nTake the balls out once golden brown and leave to drain on a piece of kitchen paper.", "equipment_tags": [], "portions": 7, "prep_minutes": 55, "prep_minutes_source": "estimated", "kcal": 322, "protein_g": 10.0, "carbs_g": 61.9, "fat_g": 3.2, "total_kcal": 2254, "total_protein_g": 70.0, "total_carbs_g": 433.1, "total_fat_g": 22.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53394", "name": "Zeeuwse bolussen", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qawvoy1777627952.jpg", "local_image": "53394.jpg", "ingredients": [{"ingredient": "Yeast", "measure": "10g"}, {"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "Sugar", "measure": "25g"}, {"ingredient": "Flour", "measure": "400g"}, {"ingredient": "Egg", "measure": "1 medium"}, {"ingredient": "Unsalted Butter", "measure": "75g"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Cinnamon", "measure": "1 tablespoon"}, {"ingredient": "Cardamom", "measure": "1 tablespoon"}, {"ingredient": "Brown Sugar", "measure": "75g"}, {"ingredient": "Brown Sugar", "measure": "250g"}], "instructions": "Place the dried yeast, milk and sugar in the bowl of your food processor. Mix and let stand for a few minutes until it begins to foam.\r\nThen add the flour, egg, butter, salt, 1 tsp of cinnamon and cardamom and process until smooth.\r\nForm the dough into a ball, cover the bowl and let it rise for 1 hour or until it has doubled in size.\r\nMix the caster sugar with 1 tablespoon of cinnamon, pour over the dough and roll it in.\r\nForm 10 equal balls (about 75 grams each) and let them “sweat” for a while. The sugar will dissolve a little. When you roll them again later, the rest of the dough will absorb the sugar better.\r\nThen roll the ball into a strand about 35-40 centimeters long while rolling through the powdered sugar.\r\nFold the strand around one end and tuck the other end under the bolus. Push something between the roll to secure the end.\r\nPlace on a baking sheet lined with a baking sheet, cover with plastic wrap and let them rise for ½-1 hour.\r\nMeanwhile, preheat the oven to 250 degrees Celsius/480 Fahrenheit top and bottom heat\r\nBake the Zeeland Boluses for about 8 minutes until done. Be careful – if you bake them too long, they will get dry and you will want something sticky 😉 .\r\nLet them cool out of the oven for 1 minute, then turn them over and let them cool further (on a wire rack if necessary). Enjoy!", "equipment_tags": ["FoodProcessor"], "portions": 7, "prep_minutes": 129, "prep_minutes_source": "explicit", "kcal": 519, "protein_g": 8.5, "carbs_g": 97.7, "fat_g": 11.2, "total_kcal": 3635, "total_protein_g": 59.8, "total_carbs_g": 684.2, "total_fat_g": 78.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=ypXGr9NdMZU"}, {"id": "53395", "name": "Slagroomtaart", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/wxfmk41777628643.jpg", "local_image": "53395.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "175g"}, {"ingredient": "Sugar", "measure": "100g"}, {"ingredient": "vanilla sugar", "measure": "10g"}, {"ingredient": "Flour", "measure": "75g"}, {"ingredient": "Cornstarch", "measure": "25g"}, {"ingredient": "Jam", "measure": "6 tablespoons"}, {"ingredient": "Nougatine", "measure": "100g"}, {"ingredient": "Whipping Cream", "measure": "750 ml"}, {"ingredient": "Sugar", "measure": "6 tablespoons"}, {"ingredient": "Fruit Mix", "measure": "5"}], "instructions": "Beat the eggs, sugar and vanilla sugar until light and fluffy. I beat this in a stand mixer on medium-high speed for about 10 minutes.\r\nSift the flour and cornstarch and add to the mixture. Fold this gently into the mixture; you don’t want all the air you whipped in to disappear.\r\nPour the batter into a greased baking pan. Bake the cake base at 180°C/350°F (conventional oven) for 30 minutes. The cake is done when you press lightly on the top and it springs back. Allow the cake to cool in the pan for a few minutes before removing it to a cake rack.\r\nMeanwhile, prepare the nougatine and jam according to the recipe if you haven’t already.\r\nLet the cake cool completely before you cut it. If, like me, you used a 20 cm/8 inch spring form pan, cut the cake into three layers.", "equipment_tags": [], "portions": 11, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 399, "protein_g": 4.8, "carbs_g": 36.0, "fat_g": 26.3, "total_kcal": 4393, "total_protein_g": 53.2, "total_carbs_g": 396.5, "total_fat_g": 289.4, "macro_confidence": 0.9, "is_new": false, "video": "https://www.youtube.com/watch?v=w6d3N2E_Vdo"}, {"id": "53396", "name": "Baghlaw-e-Khanagi", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/bjtjyl1779552068.jpg", "local_image": "53396.jpg", "ingredients": [{"ingredient": "Flour", "measure": "600g"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Milk", "measure": "450ml"}, {"ingredient": "Vegetable Oil", "measure": "75 ml"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Ground Walnuts", "measure": "50g"}, {"ingredient": "Cardamom", "measure": "10g"}, {"ingredient": "Sugar", "measure": "300g"}, {"ingredient": "Water", "measure": "1 L"}], "instructions": "Place flour in a bowl, and create a hole in the middle of the flour. Whisk eggs, and then pour whisked eggs into the well. \r\nAdd milk, and combine. Then, stir in the ground walnuts, baking powder and cardamom, and add to the mixture. Fold ingredients into the mixture until it forms an elastic dough consistency. \r\nTake dough and with a rolling pin, roll out into a thin rectangle on a clean surface. Then, from the longest side of the rectangle, fold the dough into 3cm-wide lines, until the dough is fully rolled in a long line. Cut folded dough horizontally into 3cm pieces\r\nHeat a deep pan of the vegetable oil, and wait till it reaches frying temperature. Whilst you are waiting. Fill a deep pan with 1 litre of water, and bring to the boil.  Then, pour in the sugar, and stir gently until it becomes thick and syrup-like. Turn down the heat and leave to simmer.\r\nCarefully lower each piece of dough into the frying oil. Fry until golden brown.\r\nWhen golden brown, take the Baghlaw pieces out of the oil, and place them into the sugar syrup to coat.\r\nRemove from the syrup and whilst still warm, sprinkle with ground walnuts, so they stick to the Baghlaw.\r\nLeave to cool. Then, enjoy with your friends and family!", "equipment_tags": [], "portions": 12, "prep_minutes": 67, "prep_minutes_source": "estimated", "kcal": 400, "protein_g": 8.5, "carbs_g": 66.2, "fat_g": 11.5, "total_kcal": 4805, "total_protein_g": 102.5, "total_carbs_g": 794.5, "total_fat_g": 138.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53397", "name": "Haft Mewa Recipe", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/io2u3z1779551885.jpg", "local_image": "53397.jpg", "ingredients": [{"ingredient": "Dried Apricots", "measure": "110g"}, {"ingredient": "Light Raisins", "measure": "50g"}, {"ingredient": "Raisins", "measure": "110g"}, {"ingredient": "Walnuts", "measure": "50g"}, {"ingredient": "Almonds", "measure": "50g"}, {"ingredient": "Pistachio", "measure": "50g"}, {"ingredient": "Cherry", "measure": "50g"}, {"ingredient": "Rose water", "measure": "Splash"}], "instructions": "Wash the apricots and both raisins and place in a bowl - cover with cold water to 5cm above the fruit.\r\n\r\nPut the walnuts, pistachos and almonds in another bowl or pan and add boiling water. Leave to soak, and then peel off all the skins as they soften. This is a fiddly job and make take some time - but it's definitely worth the effort! Throw away the water.\r\n\r\nCombine the fruits with the nuts and cherries, including the juice they have been soaking in. Add the rose water, cover the mixture and leave in the fridge to rest for two days. When you leave the mix, the juice will become sweeter and syrupy, giving the dish a really unique consistency.\r\n\r\nTo serve, spoon the fruit, nuts and juice into individual bowls or cups, and enjoy!", "equipment_tags": [], "portions": 3, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 572, "protein_g": 13.1, "carbs_g": 78.4, "fat_g": 28.4, "total_kcal": 1715, "total_protein_g": 39.2, "total_carbs_g": 235.2, "total_fat_g": 85.3, "macro_confidence": 0.88, "is_new": false, "video": "https://www.youtube.com/watch?v=Mzv2JIg3TRA"}, {"id": "53398", "name": "Kadu Borani", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/walmi81779552709.jpg", "local_image": "53398.jpg", "ingredients": [{"ingredient": "Squash", "measure": "1 medium"}, {"ingredient": "Onion", "measure": "5 chopped"}, {"ingredient": "Green Chilli", "measure": "To taste"}, {"ingredient": "Oil", "measure": "Splash"}, {"ingredient": "Turmeric", "measure": "1 tsp"}, {"ingredient": "Garlic", "measure": "1 Bulb"}, {"ingredient": "Sugar", "measure": "7 tablespoons"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Yogurt", "measure": "4 tablespoons"}], "instructions": "Peel the squash and cut it into pieces 1cm wide. Deep fry it in oil until golden and set aside.\r\n\r\nUsing the same pan and oil, deep fry the onions until golden. Remove the onions and grind with the garlic (if using garlic paste, mix it into the onions once ground).\r\n\r\nAdd a small amount of oil to a pan on medium heat. Once hot, add the turmeric. Mix the salt into one cup of water and add it to the turmeric. Add a layer of squash, then a layer of onion and garlic. Repeat this step until the squash, onion and garlic have been used up.\r\n\r\nAdd the sugar and one cup of water. Turn the heat down and cook until the water has reduced.\r\n\r\nAdd 1-2 tablespoons of melted curd to a plate, add the squash on top with another layer of melted curd. At last, add some green chilli and serve!", "equipment_tags": [], "portions": 3, "prep_minutes": 49, "prep_minutes_source": "estimated", "kcal": 279, "protein_g": 4.1, "carbs_g": 55.6, "fat_g": 6.0, "total_kcal": 838, "total_protein_g": 12.4, "total_carbs_g": 166.7, "total_fat_g": 18.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/DQmh54vl4LE"}, {"id": "53399", "name": "Firni", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/dm8kee1779553541.jpg", "local_image": "53399.jpg", "ingredients": [{"ingredient": "Whole Milk", "measure": "6 cups"}, {"ingredient": "Cornstarch", "measure": "5 tblsp"}, {"ingredient": "Sugar", "measure": "1 1/2 cups"}, {"ingredient": "Ground Cardomom", "measure": "1/2 tsp"}, {"ingredient": "Rose water", "measure": "1 tsp"}, {"ingredient": "Almonds", "measure": "Handful"}, {"ingredient": "Pistachio", "measure": "Handful"}], "instructions": "Pour 1 cup of milk into a small bowl, add the cornstarch and whisk them well until smooth.\r\n\r\nPour the rest of the milk into a non-stick saucepan, adding the sugar and cardamom (and rosewater, if desired) whilst cooking over medium heat.\r\n\r\nBefore it starts to boil, slowly add the milk and cornstarch mixture to the pan, whisking constantly to avoid lumps. Keep stirring until the mixture increases in thickness.\r\n\r\nTake the pan off the heat and pour into a large shallow serving bowl. Let it cool at room temperature, and then put in the refrigerator for about 1 – 2 hours.\r\n\r\nFinally, sprinkle your Firni with sliced almonds and pistachios and serve!", "equipment_tags": [], "portions": 12, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 225, "protein_g": 4.9, "carbs_g": 38.3, "fat_g": 6.4, "total_kcal": 2698, "total_protein_g": 58.9, "total_carbs_g": 460.1, "total_fat_g": 76.3, "macro_confidence": 1.0, "is_new": false, "video": "https://www.bing.com/videos/riverview/relatedvideo?q=youtube+firni&&mid=5A8ED1B70031EFA59BF85A8ED1B70031EFA59BF8&churl=https%3a%2f%2fwww.youtube.com%2fchannel%2fUCoucq1SZiQoAL2KY5CT9ESg&FORM=VAMGZC"}, {"id": "53400", "name": "Mastawa Lamb and Rice", "category": "Lamb", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/4kzx4d1779554755.jpg", "local_image": "53400.jpg", "ingredients": [{"ingredient": "Lamb", "measure": "700g"}, {"ingredient": "Onion", "measure": "3 Medium"}, {"ingredient": "Turmeric", "measure": "1 tsp"}, {"ingredient": "Orange", "measure": "1 large"}, {"ingredient": "Rice", "measure": "150g"}, {"ingredient": "Natural Yoghurt", "measure": "500g"}, {"ingredient": "Garlic Clove", "measure": "4 Cloves Crushed"}, {"ingredient": "Vegetable Oil", "measure": "1 tblsp"}, {"ingredient": "Dried Dill", "measure": "1 tablespoon"}, {"ingredient": "Black Pepper", "measure": "1 tablespoon"}, {"ingredient": "Chickpeas", "measure": "1 Can"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "1. Place the meat cut into pieces, in a large pan with the onions. Add the turmeric and enough water to cover. Bring to the boil then cook gently until the meat is very tender and can easily be removed from the bones. \r\n\r\n2. While the meat is cooking, cut the orange peel into thin match style pieces, removing as much pith as possible. Leave to soak in a bowl of water. \r\n\r\n3. When the meat is tender, remove from the pan and when cool enough, remove the meat from the bones and shred the meat into strips with your hands. Return the meat to the pan.\r\n\r\n4. Wash the short grain rice and then add to the pan with salt according to taste. The juices should cover the rice by about 2cm, add more water if necessary. Bring back to the boil, then reduce the heat to medium and cook with the lid off, stirring from time to time until the rice is \"al dente\" and the liquid is absorbed. \r\n\r\n5. Add the natural yoghurt, and stir in well but carefully. Fry the crushed cloves of garlic in the oil and add to the dish along with the dill, black pepper, the chickpeas and extra salt to taste.\r\n\r\n6. Mix in well, then cover the top of the pan with a clean thick cloth and the lid. Leave on a low heat for about half an hour to allow the flavours to absorb. \r\n\r\nEnjoy with some warm nan bread for extra comfort. ", "equipment_tags": [], "portions": 5, "prep_minutes": 73, "prep_minutes_source": "estimated", "kcal": 792, "protein_g": 49.4, "carbs_g": 63.5, "fat_g": 38.0, "total_kcal": 3959, "total_protein_g": 246.8, "total_carbs_g": 317.4, "total_fat_g": 190.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53401", "name": "Bolani with Potato Filling", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/de0sns1779555283.jpg", "local_image": "53401.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "450g"}, {"ingredient": "Water", "measure": "225ml"}, {"ingredient": "Salt", "measure": "3 tsp"}, {"ingredient": "Potatoes", "measure": "900g"}, {"ingredient": "Spring Onions", "measure": "50g"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "Put the flour and teaspoon of salt in a mixing bowl. Slowly adding as much water as is required. Mix to form a stiff dough.\r\nPlace the dough on a clean work surface and knead for about 5-10 minutes until the dough is elastic, smooth and shiny. Form the dough into a ball, cover with a damp cloth and set aside for at least half an hour.\r\nPeel and wash the potatoes and boil them in salted water until soft. Drain off the water and mash thoroughly. Add the spring onions, salt and black pepper. \r\nDivide the dough into 3 or 4 balls. Roll out each ball as thinly as possible on a lightly floured surface (the thickness should be no more than 1.5mm - if the dough is too thick the Bolani will be tough)\r\nTake a round cutter of 13-15cm (I often use a pan lid or tid lid), and cut as many rounds as possible. On each round spread 1-2 tablespoons of the mashed potato. Moisten the edges of the dough, fold over and seal shut.\r\nThe Bolani should be spread out on a lightly floured surface until ready to fry. Heat enough vegetable oil in a frying-pan and shallow fry one or two Bolani at a time, browning on both sides. \r\nMake sure to keep the fried Bolani warm until all are finished, and serve straight away.", "equipment_tags": [], "portions": 9, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 292, "protein_g": 7.2, "carbs_g": 55.8, "fat_g": 4.0, "total_kcal": 2625, "total_protein_g": 64.4, "total_carbs_g": 501.8, "total_fat_g": 35.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=bvrUPtEs_Uk"}, {"id": "53402", "name": "Mantu Afghan Dumpling", "category": "Starter", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/oemdp11779556068.jpg", "local_image": "53402.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "450g"}, {"ingredient": "Water", "measure": "225ml"}, {"ingredient": "Lamb", "measure": "450g"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Onions", "measure": "450g"}, {"ingredient": "Black Pepper", "measure": "2 tblsp"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Strained Yoghurt", "measure": "425ml"}, {"ingredient": "Coriander", "measure": "Pinch"}], "instructions": "1. To prepare the dough, sift the flour with 1tsp of salt into a mixing bowl. Slowly mix in as much of the water is required, until a stiff dough is formed. Knead on a clean work surface for 5-10 minutes, until the dough is elastic and shiny. Cover with a damp cloth and set aside for about an hour. \r\n\r\n2. Put the chopped lamb, onions, chilli, 1 tsp salt, ground pepper and spices in a bowl and mix thoroughly. \r\n\r\n3. Divide the dough into 4 small balls, and roll out to a thickness of 1.5mm, cutting into 10cm squares. Into each square, place 1 heaped teaspoon of the lamb mixture.\r\n\r\n4. Take two opposite corners and bring them to join in the centre by nipping together firmly between your fingers, and then bring together to other two corners in the same manner. Note that the mantu should not be entirely closed, as the steam has to be penetrate and cook the filling!\r\n\r\n5. Using fat to grease the shelves of the steamer, place your mantu so that there is a small space between each one. Steam for 30-45 minutes over a medium heat. \r\n\r\n6. Meanwhile, make the tomato sauce. Heat the oil in a pan, add tomato puree, and bring to the boil. Stir and simmer on a low heat until the mantu are ready.\r\n\r\n7. Remove the mantu carefully from the steamer and place on a large, warm dish. Spoon the tomato sauce over the top, followed by the strained yoghurt, and sprinkle with chopped coriander to garnish. ", "equipment_tags": [], "portions": 12, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 316, "protein_g": 15.0, "carbs_g": 36.0, "fat_g": 11.7, "total_kcal": 3796, "total_protein_g": 179.8, "total_carbs_g": 431.7, "total_fat_g": 140.0, "macro_confidence": 0.9, "is_new": false, "video": "https://www.youtube.com/shorts/KTgAOhsTTC8"}, {"id": "53403", "name": "Muraba-E-Kadu (Pumpkin Jam)", "category": "Miscellaneous", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ug6bwk1779556566.jpg", "local_image": "53403.jpg", "ingredients": [{"ingredient": "Pumpkin", "measure": "1 kg"}, {"ingredient": "Orange", "measure": "1 kg"}, {"ingredient": "Sugar", "measure": "750g"}, {"ingredient": "Cardamom", "measure": "60g"}], "instructions": "1. Remove the skin of the pumpkin. Also remove the inner seeds.\r\n\r\n2. Cut the flesh into 2cm cubes.\r\n\r\n3. Take the zest off the oranges, with as little pith as possible, and cut into matchstick-sized strips.\r\n\r\n4. Extract the juice from the oranges. Remove the seeds from the cardamom pods and reserve.\r\n\r\n5. Place the pumpkin, orange juice, orange strips, sugar and whole cardamom pod seeds in a large pan, mix well and leave to marinate for about 10 hours or overnight. Stir occasionally.\r\n\r\n6. Bring the mixture to the boil, then reduce the heat and simmer until the liquid has thickened and become syrupy. This can take about an hour or a little bit longer.\r\n\r\nLeave to cool then place in clean, dry jars. Enjoy!", "equipment_tags": [], "portions": 12, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 318, "protein_g": 2.1, "carbs_g": 81.7, "fat_g": 0.5, "total_kcal": 3819, "total_protein_g": 25.5, "total_carbs_g": 980.8, "total_fat_g": 6.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/0q1RvcqnVWA"}, {"id": "53404", "name": "Tavë Kosi Baked Lamb and Yogurt", "category": "Lamb", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/a1mi7t1779643816.jpg", "local_image": "53404.jpg", "ingredients": [{"ingredient": "Lamb", "measure": "600g"}, {"ingredient": "Butter", "measure": "20g"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Rice", "measure": "70g"}, {"ingredient": "Oregano", "measure": "2 tsp"}, {"ingredient": "Boiling Water", "measure": "450ml"}, {"ingredient": "Garlic", "measure": "2 cloves chopped"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Butter", "measure": "50g"}, {"ingredient": "Flour", "measure": "2 tablespoons"}, {"ingredient": "Greek Yogurt", "measure": "750g"}, {"ingredient": "Eggs", "measure": "6"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "1\r\nBaking the Lamb\r\nIn a large pan (with a lid) melt the butter and olive oil together then add the diced lamb. Brown the lamb on a medium heat, this will take around 5 minutes.\r\n2\r\nAdd the garlic, oregano, 300ml of water and season with salt and pepper. Mix well before covering with the lid. Leave to simmer for 50 minutes mixing a couple of times ensuring the lamb doesn’t start to burn.\r\n3\r\nThe juices should have nearly all boiled away so another 150ml of water should be added along with the rice. Mix altogether, bring to the boil, place the lid on and leave for just 10 minutes. It’s advised to check at around 8 minutes – you want the liquid to be evaporated with just moist coating of oily water left over the lamb and rice.\r\n4\r\nPlace the lamb and rice into a casserole dish, the mixture should fully cover the base and have at least 2 inches spare for the yogurt. Alternatively you can split into four ceramic bowls.\r\n5\r\nMaking a Roux\r\nIn a small saucepan melt the butter over a medium heat and then add two tablespoons of flour while continuously stirring for two minutes (add a little extra flour if needed). The roux should not be thick but not too runny, the colour will darken slightly. Pour the roux into a bowl and keep to one side.\r\n6\r\nMaking the Yogurt Mixture\r\nIn a mixing bowl add the yogurt, eggs and season with salt and pepper. Mix together then add the roux continuing to mix fast for a minute to ensure the roux and yogurt are thoroughly combined.\r\n7\r\nPour the yogurt mixture over the baked lamb and rice and sprinkle on a little oregano.\r\n8\r\nCooking\r\nPlace on the bottom shelf of the oven on 180 degrees for 35 minutes then move it up to the middle for a further 10 minutes. The Tavë kosi is ready when the yogurt has risen up high and a golden crust formed.\r\n9\r\nLeave to cool for 5 – 10 minutes before serving.", "equipment_tags": [], "portions": 4, "prep_minutes": 128, "prep_minutes_source": "explicit", "kcal": 1004, "protein_g": 66.3, "carbs_g": 27.7, "fat_g": 69.7, "total_kcal": 4018, "total_protein_g": 265.1, "total_carbs_g": 111.0, "total_fat_g": 278.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=sinI-D-vhKU"}, {"id": "53405", "name": "Tavë me Presh ska Mish Meatless Leek Bake", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/p5m3w21779644533.jpg", "local_image": "53405.jpg", "ingredients": [{"ingredient": "Leek", "measure": "500g"}, {"ingredient": "Red Pepper", "measure": "3 diced"}, {"ingredient": "Rice", "measure": "200g"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Vegetable Stock", "measure": "1 L"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Oregano", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "1 tsp"}, {"ingredient": "Basil", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Olive Oil", "measure": "Splash"}], "instructions": "1\r\nPrepare the dish\r\nFry the leeks in a small dash of olive oil for a few minutes until they start to brown.\r\n2\r\nPrepare the Dish\r\nAdd the roasted red peppers, garlic, stock, herbs, salt, pepper and paprika. Give it a good stir, add the rice and stir again.\r\n3\r\nLeave it to come to the boil. Leave to simmer for 2 minutes.\r\n4\r\nPour the mixture into a baking tray with a depth of 2 inches or more. Mix thoroughly and ensure equally levelled out.\r\n5\r\nCooking\r\nPlace on the bottom self of a preheated oven at 180 degrees. Leave to bake for 1 hour.\r\n6\r\nServing\r\nOnce cooked turn off the oven and keeping the door open leave the leek bake to cool for 10 minutes before serving.", "equipment_tags": [], "portions": 3, "prep_minutes": 72, "prep_minutes_source": "explicit", "kcal": 418, "protein_g": 9.5, "carbs_g": 81.7, "fat_g": 6.6, "total_kcal": 1254, "total_protein_g": 28.4, "total_carbs_g": 245.0, "total_fat_g": 19.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=uRAmHFjVMEA"}, {"id": "53406", "name": "Arra të Mbushura me Fik Walnut Stuffed Figs (with Fig Syrup)", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/dokbyt1779645030.jpg", "local_image": "53406.jpg", "ingredients": [{"ingredient": "Figs", "measure": "4"}, {"ingredient": "Walnuts", "measure": "4"}, {"ingredient": "Water", "measure": "150ml"}, {"ingredient": "Sugar", "measure": "60g"}], "instructions": "1\r\nPrepare the Figs\r\nCut off the hard bits of stalk and then cut the figs in half length ways.\r\n2\r\nPlace the figs in a small frying pan / saute pan with the cut side face up and add the water around them.\r\n3\r\nCooking\r\nLeave the figs on a medium heat to cook through, once they become soft remove them from the pan and place onto a serving dish. This will take around 10 - 15 minutes.\r\n4\r\nPrepare the Syrup\r\nIn the pan there will be a red water juice left from the figs. Add the sugar while remaining on a medium heat. Stir continuously for a couple of minutes until the juice has turned to a thick syrup. Remove from the heat.\r\n5\r\nServing\r\nPush one half of walnut into every fig and then drizzle the syrup over the top.\r\n6\r\nServe warm or cooled.", "equipment_tags": [], "portions": 3, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 162, "protein_g": 1.3, "carbs_g": 33.5, "fat_g": 3.7, "total_kcal": 485, "total_protein_g": 4.0, "total_carbs_g": 100.6, "total_fat_g": 11.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53407", "name": "Lakror me Kungull Summer Squash Pie", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ae4rwb1779645576.jpg", "local_image": "53407.jpg", "ingredients": [{"ingredient": "Squash", "measure": "2"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Flour", "measure": "300g"}, {"ingredient": "Baking Powder", "measure": "1/4 tsp"}, {"ingredient": "Olive Oil", "measure": "Splash"}], "instructions": "\r\n1\r\nPreparation\r\nIn a mixing bowl mix together the summer squash, sugar, eggs and baking soda. Add the flour and continue to mix, you are looking for a thick sticky mixture. Add a bit more flour if the mixture is still thin and slightly runny.\r\n2\r\nIn a large round baking tray (about 2 inches deep) rub some olive oil over the base and edges.\r\n3\r\nScoop the mixture onto the tray and spread out evenly, then pour a small amount of olive oil onto you hand and rub it in circles gently over the top of the mixture. This should flatten it and leave it with a slightly shiny glossing.\r\n4\r\nCooking\r\nBake in the oven for 40 minutes on 180 degrees – the top should be a golden brown once cooked.\r\n5\r\nServing\r\nLeave to cool before slicing into squares and serving.", "equipment_tags": [], "portions": 1, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 1394, "protein_g": 44.0, "carbs_g": 236.4, "fat_g": 28.1, "total_kcal": 1394, "total_protein_g": 44.0, "total_carbs_g": 236.4, "total_fat_g": 28.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=k4aYxqlevGQ"}, {"id": "53408", "name": "Kulaç Soda Bread", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/9aia021779646058.jpg", "local_image": "53408.jpg", "ingredients": [{"ingredient": "Flour", "measure": "450g"}, {"ingredient": "Greek Yogurt", "measure": "500g"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "Splash"}], "instructions": "1\r\nPrepare\r\nOn a large baking tray or a clean work surface, mix together the dry ingredients - flour, baking soda and salt.\r\n2\r\nMake a well in the middle and add the yogurt. Using your hands slowly combined the ingredients together to start to form a dough.\r\n3\r\nKneed the dough on a floured surface, adding extra flour if you find the texture too sticky. The dough is ready when it is of a pizza dough texture and still very slightly sticky, this should only take a few minutes.\r\n4\r\nOn a baking tray add a little oil and put the dough on top. Shape and flatten the dough into a circle shape ensuring the height of the dough is about 5cm.\r\n5\r\nCover the dough with a little bit of olive oil, ensure it is fully covered.\r\n6\r\nYou can bake the Kulaç as it is or you can create patterns which also helps with even cooking. The most common patterns are using the back of a fork to slightly press down to create line dents all over or spiking the dough with the fork.\r\n7\r\nBaking\r\nPlace on the bottom shelf of a pre heated oven. Bake for 40 minutes or until the dough is golden and firm to touch.\r\n8\r\nCooling\r\nOnce removed from the oven, stand upright or place on a cooling rack to allow the Kulaç to cool.\r\n9\r\nServing\r\nCut the Kulaç the way you would a cake into 8 slices. If you are serving warm you may want to snap and pull apart the bread with your hands instead.", "equipment_tags": [], "portions": 10, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 226, "protein_g": 9.0, "carbs_g": 36.3, "fat_g": 4.5, "total_kcal": 2258, "total_protein_g": 90.0, "total_carbs_g": 363.4, "total_fat_g": 44.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=h05_zOhGedo"}, {"id": "53409", "name": "Shendetlie Honey and Nut Cake", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/fx0exq1779646651.jpg", "local_image": "53409.jpg", "ingredients": [{"ingredient": "Sugar", "measure": "300g"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Melted Butter", "measure": "180g"}, {"ingredient": "Flour", "measure": "700g"}, {"ingredient": "Walnuts", "measure": "100g"}, {"ingredient": "Honey", "measure": "4 tablespoons"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "220g"}, {"ingredient": "Water", "measure": "450ml"}], "instructions": "\r\n1\r\nPrepare\r\nIn a mixing bowl cream together the eggs, sugar and cooled melted butter then add the honey and soda.\r\n2\r\nAdd half the flour and the walnuts (you can add the walnuts whole or ground them) and mix well.\r\n3\r\nAdd the rest of the flour and using your hands kneed the mixture together until a firm dough is formed.\r\n4\r\nCoat a large baking tray (traditionally a circle tray is used about 30cm is best with a 2 - 3 inch height) with olive oil. Add the dough and press it down so that it fits the whole tray. Try and get the dough flat and equal in height all over.\r\n5\r\nBaking\r\nPlace on the bottom shelf of a cold oven and turn the temperture up to 180 degrees. Bake for 35 minutes and the dough has turned dark brown and is firm to touch.\r\n6\r\nRemove from the oven and leave to cool while making the syrup.\r\n7\r\nAdding the Syrup\r\nAdd the sugar and water to a saucepan and bring to the boil. Leave boiling for 10 minutes, mixing occasionally. Remove from the heat.\r\n8\r\nCut the Shendetlie into squares of diamond shapes and pour over the hot syrup. Use enough of the syrup to cover the cake plus 1 cm overflowing, sitting on top. This will soak into the cake while you leave it to cool for at least 1 hour before serving.", "equipment_tags": [], "portions": 12, "prep_minutes": 105, "prep_minutes_source": "explicit", "kcal": 582, "protein_g": 8.9, "carbs_g": 94.9, "fat_g": 19.4, "total_kcal": 6981, "total_protein_g": 106.4, "total_carbs_g": 1139.1, "total_fat_g": 232.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=LfeBW8ipt0w"}, {"id": "53410", "name": "Presh me Oriz Leek and Rice Bake", "category": "Lamb", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sjfgbc1779647169.jpg", "local_image": "53410.jpg", "ingredients": [{"ingredient": "Leek", "measure": "500g"}, {"ingredient": "Lamb Mince", "measure": "400g"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Rice", "measure": "200g"}, {"ingredient": "Lamb Stock", "measure": "1 L"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Olive Oil", "measure": "Splash"}], "instructions": "\r\n1\r\nCooking\r\nFry the leeks in a small dash of olive oil for a few minutes until they start to brown.\r\n2\r\nAdd the onions and mince and fry until everything is browned. Ensure you keep stirring to prevent the leeks catching and burning.\r\n3\r\nAdd the rice and stir together for a few minutes ensuring the rice is well blended and coated in any juices.\r\n4\r\nAdd the lamb stock, salt and pepper. Give it a good stir and leave it to come to the boil. Leave to boil for 2 minutes.\r\n5\r\nBaking\r\nPour the mixture into a large baking tray, place on the bottom self of a preheated oven at 180 degrees. Leave to bake for up to 1 hour. The dish is ready when all the liquid is evaporated and the rice is soft.\r\n6\r\nServing\r\nOnce cooked turn off the oven and keeping the door open leave the leek and rice bake to cool for 10 minutes before serving.", "equipment_tags": [], "portions": 4, "prep_minutes": 72, "prep_minutes_source": "explicit", "kcal": 1320, "protein_g": 87.2, "carbs_g": 60.1, "fat_g": 79.0, "total_kcal": 5281, "total_protein_g": 349.0, "total_carbs_g": 240.6, "total_fat_g": 316.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=se2DU0httvg"}, {"id": "53411", "name": "Dolma Japrak Stuffed Vine Leaves", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/lqshrh1779648160.jpg", "local_image": "53411.jpg", "ingredients": [{"ingredient": "Pickled Grape Leaves", "measure": "600g"}, {"ingredient": "Lamb Mince", "measure": "400g"}, {"ingredient": "Onion", "measure": "5 chopped"}, {"ingredient": "Rice", "measure": "75g"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1 tsp"}, {"ingredient": "Vegetable Stock", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "25g"}, {"ingredient": "Basil", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "Splash"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Boiling Water", "measure": "2 Litres"}], "instructions": "\r\n1\r\nPreperation\r\nAdd the onions to a saute pan and fry for 5 minutes in olive oil until the onions start to brown.\r\n2\r\nTurn off the heat and add the meat, rice, pepper, paprika, dried vegetable stock, parsley and basil. Mix all the ingredients together.\r\n3\r\nCarefully unwrap the vine leaves. Place one vine leaf on your hand with the base on the bottom of your palm and the point pointing towards the top. Add a second vine leaf with the point pointing downwards and base of the leaf at the top of your fingers. there should be a good overlap. You can do this on a flat surface if preferred.\r\n4\r\nPlace a spoonful of the meat and rice mixture in the middle of the leaves. Fold the bottom of the leaf over the mixture, fold in both sides and the roll the leaf upwards sealing in the mixture into a parcel shape.\r\n5\r\nLayer a layer of vine leaves covering the bottom of a deep saucepan and then add the vine leaf parcel on top.\r\n6\r\nMake as many vine leaf parcels as the meat and rice mixture will make adding each one to the saucepan. Pack the parcels side by side util the saucepan is covered, then start another layer on top.\r\n7\r\nCooking\r\nPour into the saucepan enough boiling water to just cover the top of the vine leaves and bring to a boil. Leave to simmer with a lid on for 1.5 hours. All water should be absorbed however top up with a little extra boiling water if this happens before the time is up.\r\n8\r\nServing\r\nRemove from the saucepan and leave to cool for 10 minutes before serving.", "equipment_tags": [], "portions": 10, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 269, "protein_g": 12.0, "carbs_g": 20.9, "fat_g": 15.3, "total_kcal": 2691, "total_protein_g": 119.5, "total_carbs_g": 208.8, "total_fat_g": 153.1, "macro_confidence": 0.92, "is_new": false, "video": "https://www.youtube.com/watch?v=G7OLFDL63J4"}, {"id": "53412", "name": "Lakra me Mish Cabbage and Meat Stew", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/mobh1l1779648766.jpg", "local_image": "53412.jpg", "ingredients": [{"ingredient": "Beef", "measure": "500g"}, {"ingredient": "Cabbage", "measure": "1 Diced"}, {"ingredient": "Paprika", "measure": "2 tsp"}, {"ingredient": "Tomato Puree", "measure": "3 tsp"}, {"ingredient": "Red Pepper", "measure": "2 diced"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Chilli Flakes", "measure": "1/4 tsp"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Olive Oil", "measure": "Splash"}, {"ingredient": "Boiling Water", "measure": "1 L"}], "instructions": "\r\n1\r\nCooking\r\nAdd some olive oil to a saute pan or saucepan (one with a lid). One heated add in the onions, diced beef, red peppers and fry for 5 minutes stirring occasionally. The meat should be fully browned.\r\n2\r\nAdd the paprika, tomato puree, chilli flakes and season with salt and pepper. Mix together and continue to fry for 2 minutes.\r\n3\r\nAdd the cabbage and stir the mixture together. Fry the mixture while stirring occasionally for 3-5 minutes. Most of the oil should have burned away.\r\n4\r\nPour the boiling water into the pan, ensuring that the water level completely covers the cabbage, plus about 1 inch above it. Put on the lid and bring to the boil.\r\n5\r\nLeave to simmer for 2.5 hours. The stew is ready when the cabbage is soft and meat tender.\r\n6\r\nServing\r\nServe into wide bowls and leave to cool for 5 minutes.", "equipment_tags": [], "portions": 2, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 566, "protein_g": 52.0, "carbs_g": 10.9, "fat_g": 35.8, "total_kcal": 1132, "total_protein_g": 104.0, "total_carbs_g": 21.9, "total_fat_g": 71.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=KAsoWvGbpGk"}, {"id": "53413", "name": "Flija Layered Pancake / Crepe", "category": "Breakfast", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/eqnf3p1779649407.jpg", "local_image": "53413.jpg", "ingredients": [{"ingredient": "Flour", "measure": "1 kg"}, {"ingredient": "Water", "measure": "1 L"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Melted Butter", "measure": "220g"}, {"ingredient": "Vegetable Oil", "measure": "200ml"}, {"ingredient": "Greek Yogurt", "measure": "5 tablespoons"}, {"ingredient": "Melted Butter", "measure": "220g"}, {"ingredient": "Vegetable Oil", "measure": "200ml"}, {"ingredient": "Clotted Cream", "measure": "3  tablespoons"}, {"ingredient": "Melted Butter", "measure": "220g"}, {"ingredient": "Sour Cream", "measure": "500ml"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}], "instructions": "\r\n1\r\nPrepare the Flour Batter\r\nMix together the flour, water and salt ensuring all the lumps are dissolved. The mixture should be thick but still of a pouring consistency, add a little extra water if required. Put to one side.\r\n2\r\nPrepare the Batter Filling\r\nMix together the butter, oil and chosen yogurt / cream ensuring all the lumps are dissolved. The mixture should be runny, leave to rest for 10 minutes before given it another good mix. The consistency should be similar to custard. Put to one side.\r\n3\r\nBaking\r\nPreheat the gill to a medium setting (I use mark 4 of 6). Take a large deep baking tray or pie pan and rub some olive oil over the base. Make the first layer of flour batter using a squirty bottle or laydel, don't try to pour the batter as it will be too thick in the pan. You need to make a star effect by leaving triangles between each line of batter layers. Place under the grill until golden brown. This will take between 3 - 5 minutes.\r\n4\r\nRemove from under the grill and using a brush or the back of spoon rub over the whole pan (both battered and un-battered areas) a layer of the batter filling. Then, add a layer of the flour filling, use the same star effect this time placing the lines of batter through the gaps left from the previous layering. Also, leaving the same triangle shapes between each line. Place under the grill until golden brown. This will take between 3 - 5 minutes.\r\n5\r\nRepeat step 4 until all the mixture has been used and ensuring each triangle gap is filled with flour batter on each layer - this will take around 2 hours. After every couple of layers, use one layer just to fill up any spaces (large gaps between the batter stars) that may have started to show.\r\n6\r\nServing\r\nOnce the Flija is ready serve straight away with honey or yogurt.", "equipment_tags": ["Grill"], "portions": 12, "prep_minutes": 140, "prep_minutes_source": "explicit", "kcal": 860, "protein_g": 10.5, "carbs_g": 65.7, "fat_g": 61.9, "total_kcal": 10325, "total_protein_g": 125.4, "total_carbs_g": 787.9, "total_fat_g": 742.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=D2zlt4ZXAfA"}, {"id": "53414", "name": "Kurabie Butter Cookies", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qidask1779650423.jpg", "local_image": "53414.jpg", "ingredients": [{"ingredient": "Flour", "measure": "650g"}, {"ingredient": "Greek Yogurt", "measure": "275ml"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Sugar", "measure": "200g"}, {"ingredient": "Melted Butter", "measure": "120g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Vanilla Extract", "measure": "1 drop"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Melted Butter", "measure": "10g"}], "instructions": "\r\n1\r\nPrepare the Dough\r\nIn a large mixing bowl add all the ingredients and mix together until a dough is formed. The dough should be stick - add extra flour if you find the mixture too sticky to work with.\r\n2\r\nUsing the extra melted butter, rub some over your hands before breaking the dough into 20 equal sized pieces and roll each piece into a ball. Before rolling each ball rub melted butter over your hands each time.\r\n3\r\nPlace the balls of dough onto a greased / lined baking tray 5cm apart - you will need to split the balls into two batches cooking one batch at a time.\r\n4\r\nCooking\r\nBrush eat ball with beaten egg and place in the oven at 180 degree for 20 minutes. The Kurabie will be a light golden colour and slightly squishy in the middle. Place on a cooling rack to cool.", "equipment_tags": [], "portions": 10, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 463, "protein_g": 11.7, "carbs_g": 70.9, "fat_g": 14.6, "total_kcal": 4630, "total_protein_g": 116.9, "total_carbs_g": 708.9, "total_fat_g": 145.6, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53415", "name": "Torrijas", "category": "Breakfast", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/927vvp1779732018.jpg", "local_image": "53415.jpg", "ingredients": [{"ingredient": "Orange", "measure": "1 medium"}, {"ingredient": "Lemon", "measure": "1 medium"}, {"ingredient": "Whole Milk", "measure": "4 cups"}, {"ingredient": "Sugar", "measure": "1/2 cup"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Dry sherry", "measure": "1/3 cup"}, {"ingredient": "Baguette", "measure": "1"}, {"ingredient": "Olive Oil", "measure": "1 cup"}, {"ingredient": "Eggs", "measure": "4 large"}, {"ingredient": "Honey", "measure": "To serve"}], "instructions": "Finely grate the zest of 1 medium orange (about 2 teaspoons) and 1 medium lemon (about 1 teaspoon) into a medium saucepan.\r\nAdd 1 quart whole milk, 1/2 cup granulated sugar, and 1 (3-inch) cinnamon stick. Bring to a boil over medium heat. Remove the pan from the heat and add 1/3 cup dry sherry. Let sit until cool enough to handle. Meanwhile, cut 1 (12-ounce) day-old baguette crosswise into 1-inch-thick slices (about 16). Arrange in a single layer on a rimmed baking sheet.\r\nPour the milk mixture over the bread and let it soak for 5 minutes. Flip each slice of bread. Let the bread sit until it absorbs most of the liquid but isn't falling apart, about 5 minutes more.\r\nHeat 1 cup olive oil in a large frying pan over medium-high heat until shimmering. Meanwhile, whisk 4 eggs together in a medium bowl.\r\nWorking with 1 slice at a time, dip the bread in the egg mixture to coat. Let the excess drip off, then add to the pan. Repeat with as many slices as needed until the pan is filled with a single layer. Fry until golden-brown on the bottom, about 4 minutes. Flip the slices and fry until the second side until golden-brown, 3 to 4 minutes more. Transfer to a paper towel-lined plate or baking sheet. Repeat dipping and frying the remaining bread. Drizzle with honey to serve.", "equipment_tags": [], "portions": 7, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 262, "protein_g": 9.1, "carbs_g": 32.9, "fat_g": 10.1, "total_kcal": 1834, "total_protein_g": 63.4, "total_carbs_g": 230.6, "total_fat_g": 70.7, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=ympLYopSKow"}, {"id": "53416", "name": "Trinxat (Potato, Cabbage and Bacon Hash)", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/khpso71779732715.jpg", "local_image": "53416.jpg", "ingredients": [{"ingredient": "Cabbage", "measure": "1/2"}, {"ingredient": "Russet Potato", "measure": "2 medium"}, {"ingredient": "Bacon", "measure": "4 Chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Parsley", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Bring salted water to boil in a large pot.\r\nAdd in the cabbage and potatoes, cook until tender about 30-40 minutes\r\nWhen tender, drain, very well.\r\nReturn the vegetables to the pot and turn on the burner to low. Let steam\r\nMeanwhile cook up the bacon, reserving the fat for frying the hash.\r\nChop up the bacon, into small pieces.\r\nMash the potatoes and cabbage with a potato masher and add in the minced garlic.\r\nAdd in salt and pepper to taste.\r\nUsing a form for individual servings, press the hash mixture into the form with bacon on top, fry in the reserved bacon fat until golden brown, flip over and repeat on the other side.\r\nRemove form and garnish with chopped parsley.\r\nIf you want to make one big hash, just use a skillet, pressing the hash into the skillet with the bacon pieces and reserved fat, then flip over once golden brown. Cut into servings.\r\nGarnish with chopped parsley.", "equipment_tags": [], "portions": 1, "prep_minutes": 40, "prep_minutes_source": "explicit", "kcal": 1367, "protein_g": 82.1, "carbs_g": 65.6, "fat_g": 84.5, "total_kcal": 1367, "total_protein_g": 82.1, "total_carbs_g": 65.6, "total_fat_g": 84.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/Ro-S7zlFvN4"}, {"id": "53417", "name": "Pa Amb Tomaquet (Bread with Tomato)", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/lz9rw91779733434.jpg", "local_image": "53417.jpg", "ingredients": [{"ingredient": "Bread", "measure": "2 sliced"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Tomato", "measure": "3 chopped"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "Splash"}, {"ingredient": "Sea Salt", "measure": "To taste"}], "instructions": "Toast the bread slices -- either in a toaster, or by baking them in the oven at 400°F -- until crispy and golden.  (Toasting/baking time will totally depend on the type and thickness of your bread.)\r\n\r\nTake a clove of garlic and rub it cut-side-down all over the top of a slice of bread.\r\n\r\nTake a tomato half and rub it cut-side-down all over the top of the bread.\r\n\r\nDrizzle the bread evenly with a hint of olive oil.  Sprinkle with a pinch of salt.\r\n\r\nRepeat with the remaining slices of bread.  Then serve immediately while they're nice and warm!", "equipment_tags": [], "portions": 4, "prep_minutes": 37, "prep_minutes_source": "estimated", "kcal": 115, "protein_g": 3.0, "carbs_g": 15.7, "fat_g": 4.7, "total_kcal": 461, "total_protein_g": 12.1, "total_carbs_g": 62.7, "total_fat_g": 18.8, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=nFoQ5K-7_24"}, {"id": "53418", "name": "Cambodian Stir-fried Morning Glory with Pork, Fermented Soybeans, and Garlic", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/wympxc1779734808.jpg", "local_image": "53418.jpg", "ingredients": [{"ingredient": "Morning Glory", "measure": "1  bunch"}, {"ingredient": "Minced Pork", "measure": "150g"}, {"ingredient": "Soya Bean", "measure": "2 tablespoons"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Oil", "measure": "For frying"}, {"ingredient": "Fish Sauce", "measure": "Dash"}, {"ingredient": "Sugar", "measure": "Dash"}, {"ingredient": "Chilli", "measure": "Sprinkling"}], "instructions": "In a wok or large pan, heat 1 tablespoon of vegetable oil over medium heat. Once the oil is hot, add the garlic and stir-fry for about 30 seconds, until fragrant but not burnt.\r\nAdd the minced pork to the pan and break it up with a spatula. Stir-fry until the pork is fully cooked and browned, about 2-3 minutes.\r\nStir in the fermented soy beans and cook for another minute, mixing it thoroughly with the pork.\r\nToss in the cut morning glory and stir-fry for 2-3 minutes to retain its bright green colour and crisp texture.\r\nCheck the seasoning and adjust with fish sauce or sugar if needed. Transfer to a serving dish and serve immediately with steamed rice.", "equipment_tags": [], "portions": 1, "prep_minutes": 6, "prep_minutes_source": "explicit", "kcal": 636, "protein_g": 37.9, "carbs_g": 15.2, "fat_g": 47.3, "total_kcal": 636, "total_protein_g": 37.9, "total_carbs_g": 15.2, "total_fat_g": 47.3, "macro_confidence": 0.88, "is_new": false, "video": "https://www.youtube.com/watch?v=_LsP1TP4P9Q"}, {"id": "53419", "name": "Crispy fried fish with ginger and fermented soybeans (trey chien chuon)", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/9q1ci41779735714.jpg", "local_image": "53419.jpg", "ingredients": [{"ingredient": "Ginger", "measure": "2 cups"}, {"ingredient": "Fish fillet", "measure": "1 lb"}, {"ingredient": "Tempura Flour", "measure": "2 tablespoons"}, {"ingredient": "Oil", "measure": "2 cups"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Soya Bean", "measure": "800g"}, {"ingredient": "Sugar", "measure": "1/2 tbs"}, {"ingredient": "Water", "measure": "1/2 cup"}, {"ingredient": "Spring Onions", "measure": "3"}], "instructions": "Fry the ginger in plenty of oil until golden and slightly crispy. Set aside for later.\r\nCut the fish into strips. Dredge the fish in a very thin layer of tempura flour.\r\nFry the fish in plenty of oil until golden brown and crispy. You can use the same oil as you were using to fry the ginger.\r\nCrush the garlic and chop it into small pieces. Chop the spring onion.\r\nDrain the fermented soybeans using a colander. If you are using salted beans (soybeans in a very salty brine), you need to wash the beans in water before you add them to the dish.\r\nAdd a tablespoon of oil to a deep pan or a large pot, and sauté the garlic until slightly golden.\r\nAdd the soybeans and stir fry for a few minutes. If the soybeans are very salty, add ¼- ½ tablespoon sugar to balance the flavor.\r\nAdd water and fry for a minute.\r\nJust before serving, stir in the fried ginger, the spring onion, and the crispy fish. Serve with steamed rice.", "equipment_tags": [], "portions": 5, "prep_minutes": 58, "prep_minutes_source": "estimated", "kcal": 543, "protein_g": 47.2, "carbs_g": 42.4, "fat_g": 23.8, "total_kcal": 2717, "total_protein_g": 235.9, "total_carbs_g": 212.1, "total_fat_g": 118.9, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=V0G3ODvMg0k"}, {"id": "53420", "name": "Cambodian Waffles (Num Poum)", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/h7zrys1779736460.jpg", "local_image": "53420.jpg", "ingredients": [{"ingredient": "Rice Flour", "measure": "1/2 cup"}, {"ingredient": "Wheat Flour", "measure": "1/2 cup"}, {"ingredient": "Coconut Milk", "measure": "1/2 cup"}, {"ingredient": "Palm Sugar", "measure": "3/4 cup"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Salt", "measure": "1/2 tsp"}], "instructions": "In a bowl, mix the flour, coconut milk, palm sugar and eggs and salt. Brush a waffle iron with oil pour in the batter and cook over an open fire until light brown and crispy.", "equipment_tags": [], "portions": 3, "prep_minutes": 16, "prep_minutes_source": "estimated", "kcal": 491, "protein_g": 9.5, "carbs_g": 85.8, "fat_g": 13.4, "total_kcal": 1474, "total_protein_g": 28.5, "total_carbs_g": 257.4, "total_fat_g": 40.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=QAVOTHkYXLc"}, {"id": "53421", "name": "BEEF LOK LAK (Lok Lak Sach Ko)", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/t2b8bn1779737789.jpg", "local_image": "53421.jpg", "ingredients": [{"ingredient": "Beef Tenderloin", "measure": "1 kg"}, {"ingredient": "Garlic", "measure": "5 cloves"}, {"ingredient": "Oil", "measure": "2 tablespoons"}, {"ingredient": "Palm Sugar", "measure": "1.5 tablespoon"}, {"ingredient": "Sea Salt", "measure": "1 tsp"}, {"ingredient": "White Wine", "measure": "2 tablespoons"}, {"ingredient": "Oyster Sauce", "measure": "2 tablespoons"}, {"ingredient": "Soy Sauce", "measure": "2 tablespoons"}, {"ingredient": "Sesame Seed Oil", "measure": "1.5 tablespoon"}, {"ingredient": "Lettuce", "measure": "500g"}, {"ingredient": "Tomato", "measure": "400g"}, {"ingredient": "Onion", "measure": "200g"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Sea Salt", "measure": "1.5 tablespoon"}, {"ingredient": "Kampot Pepper", "measure": "1 tablespoon"}, {"ingredient": "Lime juice", "measure": "1 tablespoon"}], "instructions": "Fry the eggs sunny-side up and set aside. Finely chop the garlic. Wash the lettuce leaves and drain well. Thinly slice the onion and tomatoes.\r\nCut the beef tenderloin into 2–3 cm cubes. Marinate with sea salt, palm sugar, Chinese cooking wine, oyster sauce, soy sauce, and sesame oil. Mix well.\r\nHeat a frying pan on high heat with cooking oil. Add chopped garlic and stir until the garlic browns lightly. Add the marinated beef (with all the marinade) and cook for 5–7 minutes, depending on how rare you want the beef.\r\nDry roast the black Kampot peppercorns in a frying pan over medium-low heat for 2–3 minutes until fragrant. Grind the roasted pepper, place it in a bowl, then add sea salt and lime juice. Mix well.\r\nOn a serving plate, arrange a bed of lettuce, then layer tomatoes, then onions. Spoon the cooked beef over the vegetables and place fried eggs on top. Serve with the Kampot pepper sauce and fragrant steamed rice.\r\nSear hot and fast, Lok Lak is at its best when the beef stays tender and juicy, with a bold, bright dipping sauce to cut through the richness.", "equipment_tags": [], "portions": 5, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 587, "protein_g": 48.8, "carbs_g": 18.4, "fat_g": 36.2, "total_kcal": 2934, "total_protein_g": 244.2, "total_carbs_g": 91.8, "total_fat_g": 181.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=3oWgjFhQQW0"}, {"id": "53422", "name": "Num E (Sticky Rice Balls in Sugar Syrup and Coconut Cream)", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5572yt1779739329.jpg", "local_image": "53422.jpg", "ingredients": [{"ingredient": "Sticky Rice Flour", "measure": "700g"}, {"ingredient": "Pandan Leaves", "measure": "7"}, {"ingredient": "Beetroot", "measure": "1/4"}, {"ingredient": "Pumpkin", "measure": "100g"}, {"ingredient": "Taro", "measure": "100g"}, {"ingredient": "Longan", "measure": "100g"}, {"ingredient": "Coconut", "measure": "200g"}, {"ingredient": "Water", "measure": "2L"}, {"ingredient": "Water", "measure": "1 L"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Ginger", "measure": "5 Slices"}, {"ingredient": "Coconut Cream", "measure": "3 Cups"}], "instructions": "Place coconut cream in a small pot over low heat. Cut 3 pandan leaves into large strips and add to the pot with brown sugar, salt, and ginger. Bring to a boil, then cook 2 more minutes. Turn off the heat, remove the pandan leaves, and let cool.\r\nChop the remaining 4 pandan leaves, blend with ¼ cup water until very green, then strain well. In a bowl, place 200 g sticky rice flour, add a little pandan liquid, and knead until smooth.\r\nPeel and chop beetroot, blend with ¼ cup water until red, then strain well. In a bowl, place 200 g sticky rice flour, add a little beetroot liquid, and knead until smooth.\r\nBring 3 litres of water to a boil in a medium–large pot. Divide each dough into small pieces, roll into balls about ⅓ the size of a ping pong ball, then drop into boiling water. When they float, remove and place them into fresh, icy water to keep them separate.\r\nDrain well, then place the mixed colored balls into the cooled coconut sugar syrup and stir. Serve in small bowls (add longan and shredded coconut as desired).\r\nAdd the coloring liquids gradually—each flour absorbs differently. You want a dough that’s smooth and pliable, not sticky.", "equipment_tags": [], "portions": 12, "prep_minutes": 55, "prep_minutes_source": "estimated", "kcal": 755, "protein_g": 12.3, "carbs_g": 67.8, "fat_g": 51.9, "total_kcal": 9055, "total_protein_g": 147.0, "total_carbs_g": 813.9, "total_fat_g": 622.3, "macro_confidence": 0.75, "is_new": false, "video": "https://www.youtube.com/watch?v=RDlkKhMho90"}, {"id": "53423", "name": "Meang Nem", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/5rk8vc1779740302.jpg", "local_image": "53423.jpg", "ingredients": [{"ingredient": "Dried Shrimp", "measure": "50g"}, {"ingredient": "Rice", "measure": "40g"}, {"ingredient": "Coconut", "measure": "100g"}, {"ingredient": "Orange Zest", "measure": "20g"}, {"ingredient": "Chilli", "measure": "3"}, {"ingredient": "Peanuts", "measure": "50g"}, {"ingredient": "Pickled Scallion Heads", "measure": "100g"}, {"ingredient": "Pickled Scallion Head Brine", "measure": "30 ml"}, {"ingredient": "Galangal", "measure": "25g"}, {"ingredient": "Shallots", "measure": "30g"}, {"ingredient": "Orange Juice", "measure": "20 ml"}, {"ingredient": "Lime juice", "measure": "50 ml"}, {"ingredient": "Fish Sauce", "measure": "50 ml"}, {"ingredient": "Palm Sugar", "measure": "50g"}], "instructions": "Rinse the rice, soak in water for about 10 minutes, then drain well. Heat a wok or large skillet over medium heat. Add the rice and stir constantly until evenly dark golden brown and very fragrant, about 5 minutes. Transfer to a bowl to cool. Grind finely using a spice grinder or mortar and pestle, then sift through a fine mesh strainer to remove any large pieces. Set aside.\r\nThinly slice the shallots lengthwise. Finely chop the galangal, pickled scallion heads, chili peppers, and bitter orange zest. Coarsely grind the roasted peanuts. Heat a frying pan over low heat, add shredded coconut, and toast, stirring, for 2–3 minutes. Set aside.\r\nIn a large bowl, combine lime juice, bitter orange juice, palm sugar, pickled scallion brine, and fish sauce. Stir until fully dissolved and well mixed.\r\nIn a mixing bowl, combine dried shrimp, toasted coconut, chopped aromatics, and dressing. Mix well. Add roasted rice powder and stir again. Top with coarsely ground roasted peanuts.\r\nPlace the salad on a large plate. Let each guest spoon a little onto their own small plate, wrap in leafy greens with vegetables, and enjoy in bite-size portions.\r\nFor a vegetarian version, omit the dried shrimp and fish sauce. Season to taste with soy sauce and a pinch of sea salt, keeping the sweet-sour balance.", "equipment_tags": [], "portions": 2, "prep_minutes": 18, "prep_minutes_source": "explicit", "kcal": 837, "protein_g": 23.3, "carbs_g": 84.4, "fat_g": 50.7, "total_kcal": 1673, "total_protein_g": 46.5, "total_carbs_g": 168.7, "total_fat_g": 101.4, "macro_confidence": 0.86, "is_new": false, "video": null}, {"id": "53424", "name": "Laos Plantain Coconut Bake (Flourless Muffin)", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/x7cbsp1779811798.jpg", "local_image": "53424.jpg", "ingredients": [{"ingredient": "Coconut Cream", "measure": "450ml"}, {"ingredient": "Plantain", "measure": "4 large"}, {"ingredient": "Sugar", "measure": "4 tablespoons"}], "instructions": "Preheat oven to 350 degrees.\r\nMash the plantains until it has a paste consistency.\r\nMix togher the coconut cream and granulated sugar. Mix well.\r\nAdd muffin liners to muffin pan.\r\nFill the mixture into muffin pan.\r\nBake for 45 minutes until baked all the way through.", "equipment_tags": [], "portions": 5, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 693, "protein_g": 8.2, "carbs_g": 37.8, "fat_g": 61.7, "total_kcal": 3467, "total_protein_g": 41.0, "total_carbs_g": 189.0, "total_fat_g": 308.5, "macro_confidence": 0.67, "is_new": false, "video": null}, {"id": "53425", "name": "Authentic Laos Tapioca Pudding with Bananas", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5pmn0g1779813285.jpg", "local_image": "53425.jpg", "ingredients": [{"ingredient": "Warm Water", "measure": "1 cup"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Tapioca", "measure": "3  tablespoons"}, {"ingredient": "Coconut Milk", "measure": "14 oz jar"}, {"ingredient": "Sugar", "measure": "2 tablespoons"}, {"ingredient": "Banana", "measure": "3 Cups"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "In a bowl of warm water, add tapioca pearls and allow them to soak for 20 minutes.\r\nPrepare bananas by peeling them and cutting them into ½ inch slices. Set the slices aside\r\nOn a stove, pour in 4 cups of water and bring it to a boil. Add in the banana slices.\r\nAfter 20 minutes, drain the tapioca pearls in cold water to allow the pearls to separate from each other.\r\nAdd the tapioca pearls into the the pot. Allow to simmer for 3 minutes or until the tapioca pearls turn clear.\r\nNext, add in sugar and pour in the coconut cream. Stir the ingredients gently for 3 minutes to incorporate the flavors.\r\nAdd salt to taste.", "equipment_tags": [], "portions": 12, "prep_minutes": 46, "prep_minutes_source": "explicit", "kcal": 151, "protein_g": 1.4, "carbs_g": 21.1, "fat_g": 8.1, "total_kcal": 1813, "total_protein_g": 17.1, "total_carbs_g": 252.8, "total_fat_g": 97.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=JbcrpAHmk3s"}, {"id": "53426", "name": "Lao Som Pak Pickled Cabbage", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/44pjrn1779814409.jpg", "local_image": "53426.jpg", "ingredients": [{"ingredient": "Cabbage", "measure": "1 large"}, {"ingredient": "Spring Onions", "measure": "10"}, {"ingredient": "Water", "measure": "16 oz"}, {"ingredient": "Salt", "measure": "2 tablespoons"}], "instructions": "Cut the cabbage and chop it into 1 inch pieces\r\n\r\nPut the cabbage in a large bowl and add cold water to rinse.\r\n\r\nWash the cabbage. Rinse and drain three times.\r\n\r\nIn a large clean bowl, pour in the bottle of water.\r\n\r\nPut the cabbage and green onion into the salt water mixture. \r\n\r\nAdd in the salt.", "equipment_tags": [], "portions": 9, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 40, "protein_g": 2.3, "carbs_g": 9.2, "fat_g": 0.2, "total_kcal": 364, "total_protein_g": 20.4, "total_carbs_g": 83.2, "total_fat_g": 2.2, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=0dkBqf0zj6M"}, {"id": "53427", "name": "Lao Naem Khao", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/0dypw51779817467.jpg", "local_image": "53427.jpg", "ingredients": [{"ingredient": "Jasmine Rice", "measure": "3 Cups"}, {"ingredient": "Coconut", "measure": "1"}, {"ingredient": "Oil", "measure": "Splash"}, {"ingredient": "Sour Pork Sausage", "measure": "2 cups"}, {"ingredient": "Pickled Garlics", "measure": "2 diced"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Fish Sauce", "measure": "2 tablespoons"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 sliced"}, {"ingredient": "Shallots", "measure": "1 sliced"}, {"ingredient": "Spring Onions", "measure": "3 finely chopped"}, {"ingredient": "Cilantro", "measure": "1 cup"}, {"ingredient": "Hot Mint", "measure": "1/2 cup"}, {"ingredient": "Mint", "measure": "1/2 cup"}, {"ingredient": "Roasted Peanut", "measure": "1/4 cup"}, {"ingredient": "Vegetables", "measure": "To serve"}, {"ingredient": "Lettuce", "measure": "To serve"}], "instructions": "Slice the onion and shallots thinly. Let them soak in a ice water bath while preparing the rest of the meal.\r\n\r\nGrate the coconut. Put in a large bowl.\r\n\r\nAdd the coconut in a large bowl. Add the rice. Using your hands, mix the coconut and rice together.\r\n\r\nRoll the mixture to form 2-inch rice ball croquettes. \r\n\r\nHeat up the cooking oil in a pot or pan.\r\n\r\nBeat two eggs and a large bowl. Dip the balls into the egg mixture. Then, drop the balls into the cooking oil.\r\n\r\nAllow the balls to turn a dark amber brown color. Deep fry until crispy, crunchy, and golden. Remove and set on paper towel to drain excess oil.\r\n\r\nOnce cooled, break apart the rice balls and add into a larger bowl.\r\n\r\nDrain the onion and the shallots.\r\n\r\nMake sure you tear the pork sausage up into small pieces. You can use a knife too, but the traditional method is tearing.\r\n\r\nIn the large bowl, add in the onion, shallots, sour pork sausage, pickled garlic, lime juice, fish sauce, sugar, cilantro, hot mint, regular mint.\r\n\r\nTop with peanuts. Serve with Lettuce, dry chilli, and other fresh vegetables.\r\n\r\nPreserving Naem Khao Recipe\r\nNaem Khao can be kept in the refrigerator for 4 days. It can then be served chilled.\r\n\r\nIt should not be frozen. \r\n\r\nServing Naem Khao\r\nNam Khao is generally served with lettuce leaves and a variety of different herbs like hot mint, mint, basil, and perilla. ", "equipment_tags": [], "portions": 5, "prep_minutes": 90, "prep_minutes_source": "estimated", "kcal": 1013, "protein_g": 31.1, "carbs_g": 130.6, "fat_g": 42.2, "total_kcal": 5065, "total_protein_g": 155.4, "total_carbs_g": 652.9, "total_fat_g": 211.0, "macro_confidence": 0.94, "is_new": false, "video": "https://www.youtube.com/watch?v=qDWN61Ib4A4"}, {"id": "53428", "name": "Camaro Grelhado Com Molho Cru (Grilled Prawns with Green Onion Sauce)", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/jg4r991779916649.jpg", "local_image": "53428.jpg", "ingredients": [{"ingredient": "Prawns", "measure": "1 lb"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Spring Onions", "measure": "1/2 cup"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "White Vinegar", "measure": "4 tablespoons"}, {"ingredient": "Water", "measure": "4 tablespoons"}], "instructions": "Make the sauce by combining all the ingredients and grinding them into a paste.\r\nPut the prawns on the skewers and brush with sauce.\r\nGrill until done (they should lose their translucent color), about 3-4 minutes on each side.\r\nServe with extra sauce on the side.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 462, "protein_g": 94.2, "carbs_g": 14.1, "fat_g": 3.7, "total_kcal": 462, "total_protein_g": 94.2, "total_carbs_g": 14.1, "total_fat_g": 3.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53429", "name": "Paracuca (Roasted Peanuts)", "category": "Starter", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vgsipt1779917593.jpg", "local_image": "53429.jpg", "ingredients": [{"ingredient": "Unsalted Peanuts", "measure": "5 Cups"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Salt", "measure": "1/4 tsp"}], "instructions": "1\r\nIn a large heavy saucepan, combine the peanuts, sugar and water. Bring to a boil; cook until syrup has evaporated, about 10 minutes.\r\n2\r\nSpread peanuts in a single layer in a greased 15x10x1-in. baking pan; sprinkle with salt.\r\n3\r\nBake at 300° for 30-35 minutes or until dry and lightly browned. Cool completely. Store in an airtight container.", "equipment_tags": [], "portions": 11, "prep_minutes": 45, "prep_minutes_source": "explicit", "kcal": 690, "protein_g": 28.4, "carbs_g": 36.0, "fat_g": 53.5, "total_kcal": 7593, "total_protein_g": 312.0, "total_carbs_g": 396.0, "total_fat_g": 588.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=G4OFO9c8jS8"}, {"id": "53430", "name": "Antiguan Breakfast (Chop Up and ‘Saltfish’)", "category": "Breakfast", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/jvjnoh1780086318.jpg", "local_image": "53430.jpg", "ingredients": [{"ingredient": "Egg Plants", "measure": "4"}, {"ingredient": "Callaloo", "measure": "8 oz"}, {"ingredient": "Pumpkin", "measure": "1 lb"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Butter", "measure": "2 oz"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}], "instructions": "Peel and chop eggplant and pumpkin into medium-sized pieces.\r\n\r\nHeat butter and add onions and garlic in a medium sized pot set to medium to high heat. Sauté for 2 minutes until softened but not browned.\r\nAdd pumpkin and eggplant. Sauté for an additional two to three minutes.\r\nAdd water just to cover the vegetables. Bring to a boil, reduce heat to a simmer and cook until the vegetables are soft.\r\nAdd the chopped spinach, stir and cook for an additional 3 minutes.\r\nPour the vegetable mixture into a colander and let drain.\r\nAfter vegetable mixture has been drained return it to the pot and mash vigorously with a potato masher or a thick whisk.\r\nAdd salt and pepper. Adjust seasoning to taste.", "equipment_tags": [], "portions": 4, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 234, "protein_g": 9.9, "carbs_g": 14.3, "fat_g": 16.9, "total_kcal": 935, "total_protein_g": 39.8, "total_carbs_g": 57.1, "total_fat_g": 67.5, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53431", "name": "Corn on the cob with lime, green chilli and coconut butter", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/brhaoj1780086661.jpg", "local_image": "53431.jpg", "ingredients": [{"ingredient": "Vegetable Stock", "measure": "1 L"}, {"ingredient": "Corn On The Cob", "measure": "6"}, {"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Lime", "measure": "Zest and juice of 2"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Black Pepper", "measure": "Pinch"}, {"ingredient": "Butter", "measure": "25g"}, {"ingredient": "Desiccated Coconut", "measure": "100g"}, {"ingredient": "Shallots", "measure": "100g"}, {"ingredient": "Coriander", "measure": "10g"}, {"ingredient": "Parsley", "measure": "10g"}], "instructions": "Bring the stock to a rolling boil in a big, deep pan. Slip in the cobs, leave to cook for about five minutes, then turn off the heat and leave the corn to sit in the stock as it cools.\r\n\r\nPut a heavy-based dry frying pan on a high heat and, once hot, lay the drained corn in the pan and char for a couple of minutes on each side – you’ll probably need to cook them two or three at a time, so you don’t overcrowd the pan. Put the coconut milk, lime juice and chillies in a small saucepan, season lightly, then bring up to a gentle simmer. Stir in the butter, turn off the heat and set aside.\r\n\r\nFor the topping, toast the coconut flakes in a hot dry frying pan – coconut burns very easily, so keep them moving and keep your eye on them. As soon as the coconut has a golden, burnished, toasted colour, tip it into a bowl, leave to cool, then mix with the crispy shallots and herbs, and season to taste.\r\n\r\nTo serve, spoon some of the coconut milk mixture over each cob, sprinkle with the toasted coconut mix and lime zest, and tuck in.", "equipment_tags": [], "portions": 11, "prep_minutes": 34, "prep_minutes_source": "estimated", "kcal": 198, "protein_g": 3.2, "carbs_g": 12.4, "fat_g": 17.0, "total_kcal": 2175, "total_protein_g": 35.4, "total_carbs_g": 135.9, "total_fat_g": 187.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53432", "name": "Slow-cooked, Wadadli-spiced Cubano pork belly", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/t1hg8s1780087329.jpg", "local_image": "53432.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "175ml"}, {"ingredient": "Coriander", "measure": "4 tablespoons"}, {"ingredient": "Parsley", "measure": "4 tablespoons"}, {"ingredient": "Oregano", "measure": "6 tablespoons"}, {"ingredient": "Mint", "measure": "6 tablespoons"}, {"ingredient": "Red Chilli", "measure": "2"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Orange", "measure": "Zest and juice of 2"}, {"ingredient": "Lime", "measure": "Zest and juice of 2"}, {"ingredient": "Grapefruit", "measure": "Juice of 1"}, {"ingredient": "Garlic", "measure": "40g"}, {"ingredient": "Ground Cumin", "measure": "3 tsp"}, {"ingredient": "Ground Allspice", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Black Pepper", "measure": "To taste"}], "instructions": "Blitz all the marinade ingredients in a food processor or with a hand blender. Lay the pork in a large dish, pour over the marinade, then turn the meat in the mixture, rubbing in the marinade all over and making sure every bit of the belly is coated. Cover the dish and leave overnight in the fridge.\r\n\r\nThe next day, heat the oven to 140C (120C fan)/275F/gas 1. Lift the meat out of its marinade (don’t wipe off any that sticks to the joint, though; just leave most of the marinade behind in the dish) and transfer to a large roasting dish. Cover with foil, slip into the oven and roast for four and a half hours – every now and then (say, three or four times over the whole cooking period), take the dish out of the oven, lift off the foil lid and spoon the juices from the bottom of the dish over the meat. Return the foil lid, then put back in the oven.\r\n\r\nAfter the time is up, remove the foil, turn up the heat to 180C (160C fan)/350F/gas 4 and give the pork a final blast – after 15-20 minutes, the top will take on a lovely colour and the meat should be yielding and soft enough to cut with a spoon.\r\n\r\nTo make crackling shards to serve with the meat, heat the oven to 200C (180C fan)/390F/gas 6 and line a roasting tray with baking paper. Lightly score the skin from the pork belly with a sharp knife, then rub it with a three or four fat pinches of salt – I also like to add a few caraway, cumin or fennel seeds at this point (use anything that takes your fancy). Cut the skin into long strips and lay these fat side down on the lined tray (you can, of course, leave it whole, but I think its pleasing to dress the plate with long, golden shards of crackling). Lay a second sheet of baking paper on top of the skin, then put a second baking tray of the same size on top, and roast for 45 minutes to an hour (if by this point the crackling has not gone crisp, just put it back in the oven and carry on roasting it until it has).\r\n\r\nCut or pull the pork apart, top with finely chopped coriander and flat-leaf parsley and shards of crackling, if you have made them, and serve at once", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 1, "prep_minutes": 65, "prep_minutes_source": "explicit", "kcal": 724, "protein_g": 25.2, "carbs_g": 142.3, "fat_g": 25.1, "total_kcal": 724, "total_protein_g": 25.2, "total_carbs_g": 142.3, "total_fat_g": 25.1, "macro_confidence": 0.93, "is_new": false, "video": null}, {"id": "53433", "name": "Mango chow", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8hx4fi1780087744.jpg", "local_image": "53433.jpg", "ingredients": [{"ingredient": "Mango", "measure": "1/2"}, {"ingredient": "Spring Onions", "measure": "1 chopped"}, {"ingredient": "Scotch Bonnet", "measure": "1"}, {"ingredient": "Coriander", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "Zest and juice of 1"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Simply combine everything in a bowl and serve alongside just about anything.", "equipment_tags": [], "portions": 1, "prep_minutes": 13, "prep_minutes_source": "estimated", "kcal": 111, "protein_g": 5.1, "carbs_g": 21.3, "fat_g": 2.7, "total_kcal": 111, "total_protein_g": 5.1, "total_carbs_g": 21.3, "total_fat_g": 2.7, "macro_confidence": 0.86, "is_new": false, "video": null}, {"id": "53434", "name": "Koulenje", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/xajyjk1780091885.jpg", "local_image": "53434.jpg", "ingredients": [{"ingredient": "Flour", "measure": "6 cups"}, {"ingredient": "Eggs", "measure": "6 large"}, {"ingredient": "Baking Powder", "measure": "2 1/2 Tbs"}, {"ingredient": "Melted Butter", "measure": "1 cup"}, {"ingredient": "Salt", "measure": "1 tablespoon"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Ground Mahleb", "measure": "1 tablespoon"}, {"ingredient": "Egg", "measure": "1"}], "instructions": "Sift flour, baking powder, salt, and sugar together. In a separate bowl, beat 6 eggs, then blend in the butter and milk.\r\n\r\nSprinkle one tablespoon of sev dzandig (black seeds) and all the mahleb on top of the dry ingredients. Make a hole in the center of the dry ingredients and pour the wet ingredients in all at once, mixing with a few strokes until the dough can be turned out onto a floured board. Add more flour if necessary; it shouldn't be too sticky.\r\n\r\nKnead the mixture gently, just a few times, and then roll it out until it is ½\" thick. Cut it into diamond shapes, circles, or long strips which can be rolled and braided into loaves. Prick each piece several times with a fork.\r\n\r\nBeat the seventh egg with additional sev dzandig (black seeds) added. Brush each piece of koulenje with this glaze and place on cookie sheet covered with baking parchment.\r\n\r\nBake at 400° for 12-15 minutes until slightly golden. Cool on a rack. These are best eaten warm. You can reheat them by wrapping in foil. ", "equipment_tags": [], "portions": 10, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 591, "protein_g": 13.2, "carbs_g": 81.2, "fat_g": 23.8, "total_kcal": 5909, "total_protein_g": 132.3, "total_carbs_g": 812.4, "total_fat_g": 238.4, "macro_confidence": 0.89, "is_new": false, "video": null}, {"id": "53435", "name": "Stuffed Grape Leaves", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/oga0ax1780089591.jpg", "local_image": "53435.jpg", "ingredients": [{"ingredient": "Rice", "measure": "1 cup"}, {"ingredient": "Chicken Stock", "measure": "2 cups"}, {"ingredient": "Tomato Sauce", "measure": "1 cup"}, {"ingredient": "Olive Oil", "measure": "1/4 cup"}, {"ingredient": "Ground Allspice", "measure": "1/4 tsp"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Raisins", "measure": "1/2 cup"}, {"ingredient": "Dill", "measure": "1/2 cup"}, {"ingredient": "Pine Nuts", "measure": "1/2 cup"}, {"ingredient": "Lemon", "measure": "Juice of 1"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}], "instructions": "Wash rice in cold water until water runs clear.\r\nSauté onions in olive oil until tender.\r\nAdd spices and stir until fragrant.\r\nAdd remaining ingredients.\r\nBring to a gentle boil, then simmer for 30 minutes until all stock is absorbed and rice is tender.\r\nServe as a side dish or filling for dolmas.", "equipment_tags": [], "portions": 8, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 323, "protein_g": 5.7, "carbs_g": 38.9, "fat_g": 17.7, "total_kcal": 2582, "total_protein_g": 45.6, "total_carbs_g": 311.3, "total_fat_g": 141.5, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53436", "name": "Jajek", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8x0vgs1780090328.jpg", "local_image": "53436.jpg", "ingredients": [{"ingredient": "Yogurt", "measure": "2 cups"}, {"ingredient": "Cold Water", "measure": "1 cup"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Dried Mint", "measure": "1 tsp"}, {"ingredient": "Cucumber", "measure": "1"}], "instructions": "Place yogurt, water, garlic and salt in food processor and process for a few seconds. Transfer to a bowl and mix with mint and cucumber.  Best served chilled for a few hours. \r\n\r\nWhen serving, add a few ice cubes to add additional refreshment!  Makes about four servings.", "equipment_tags": ["FoodProcessor"], "portions": 4, "prep_minutes": 22, "prep_minutes_source": "estimated", "kcal": 77, "protein_g": 4.4, "carbs_g": 6.4, "fat_g": 4.0, "total_kcal": 307, "total_protein_g": 17.5, "total_carbs_g": 25.8, "total_fat_g": 15.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53437", "name": "Leg of Lamb Armenian-Style", "category": "Lamb", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vy6k391780090969.jpg", "local_image": "53437.jpg", "ingredients": [{"ingredient": "Lamb Leg", "measure": "1"}, {"ingredient": "Garlic", "measure": "1 Bulb"}, {"ingredient": "Garlic", "measure": "1 Bulb"}, {"ingredient": "Parsley", "measure": "1 1/2 cup"}, {"ingredient": "Onion", "measure": "1 cup"}, {"ingredient": "Black Pepper", "measure": "1 tablespoon"}, {"ingredient": "Balsamic Vinegar", "measure": "1 cup"}, {"ingredient": "Olive Oil", "measure": "1/2 cup"}, {"ingredient": "Mint", "measure": "1/4 cup"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "Place all of the above ingredients into your roaster pan at least two days before you want to eat.  Stir occasionally throughout the days to distribute marinade evenly. Bake at a 350-degree oven for 1 hour to 1 1/2 hours or until meat is not red when sliced.  \r\n\r\nYou can also make these on skewers if you wish to go through the process of spearing the meat with other veggies to grill. Freezes well.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 180, "prep_minutes_source": "explicit", "kcal": 802, "protein_g": 18.1, "carbs_g": 46.8, "fat_g": 62.7, "total_kcal": 1605, "total_protein_g": 36.1, "total_carbs_g": 93.6, "total_fat_g": 125.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53438", "name": "Bolita di Keshi", "category": "Miscellaneous", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/skzd0x1780091674.jpg", "local_image": "53438.jpg", "ingredients": [{"ingredient": "Cheddar Cheese", "measure": "1 lb"}, {"ingredient": "Feta", "measure": "1 lb"}, {"ingredient": "Eggs", "measure": "1 beaten"}, {"ingredient": "Cornstarch", "measure": "5 tablespoons"}], "instructions": "Grate finely and toss together.\r\n1 lb. sharp yellow cheese (cheddar or oude boerenkaas)\r\n1 lb. keshi di buriko (or any white cheese such as fromage blanc, queso blanco, ricotto, feta etc.)\r\n\r\nStir in:\r\n6 eggs, beaten\r\n5 Tbs. Cornstarch\r\n\r\nShape the mixture into small balls. These may be kept indefinitely in the freezer. Drop the balls into deep, hot fat and fry until golden. Serve piping hot on toothpicks.", "equipment_tags": [], "portions": 2, "prep_minutes": 52, "prep_minutes_source": "estimated", "kcal": 1689, "protein_g": 91.8, "carbs_g": 46.6, "fat_g": 125.0, "total_kcal": 3378, "total_protein_g": 183.6, "total_carbs_g": 93.3, "total_fat_g": 250.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=WovQkxxrUeE"}, {"id": "53439", "name": "Arepa", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/ejht7k1780092390.jpg", "local_image": "53439.jpg", "ingredients": [{"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Corn Flour", "measure": "1 cup"}, {"ingredient": "Warm Water", "measure": "1 1/4 cup"}], "instructions": "Put the corn flour in a bowl and add the salted water little by little, mixing with the flour until all the water has been used and the flour has become a dough. Let it rest for five minutes. Now, shape the dough into round rolls about 3 inches in diameter and 1/2 inch thick. In a lightly greased skillet, slowly cook the arepas until a crust forms on each side. Now place them into a casserole and bake in the oven at 350 degrees for approximately 20 minutes, until the arepas sound hollow when tapped.\r\n\r\nTo enhance taste: instead of using just water, use chicken or beef broth.", "equipment_tags": [], "portions": 2, "prep_minutes": 20, "prep_minutes_source": "explicit", "kcal": 242, "protein_g": 0.2, "carbs_g": 57.9, "fat_g": 0.1, "total_kcal": 485, "total_protein_g": 0.4, "total_carbs_g": 115.8, "total_fat_g": 0.1, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/n6h5GwO6UpQ"}, {"id": "53440", "name": "Balchi di Pisca", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/qqwhw51780093126.jpg", "local_image": "53440.jpg", "ingredients": [{"ingredient": "Salt Cod", "measure": "1"}, {"ingredient": "Potatoes", "measure": "3 Medium"}, {"ingredient": "Tomato", "measure": "1"}, {"ingredient": "Green Pepper", "measure": "1/2"}, {"ingredient": "Onion", "measure": "1 medium"}, {"ingredient": "Garlic", "measure": "1 clove peeled sliced"}, {"ingredient": "Tobasco Sauce", "measure": "1/2 tsp"}, {"ingredient": "Nutmeg", "measure": "Dash"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Egg", "measure": "1"}], "instructions": "These delectable fish balls can also be made with salmon or fish fillets. Substitute one large can of salmon or one pound of any white fish for the cod.\r\n\r\nSoak for twenty-four hours:\r\n1 salted cod, or bakijow Discard the water.\r\n\r\nPlace cod in saucepan with fresh water to cover. Simmer gently until the fish flakes easily when tested with the tines of a fork. Strain, reserving a bit of the broth. De bone the cod and set it aside for later use. In a saucepan, bring to boil in water to cover: 3 medium potatoes, peeled and diced When the potatoes are tender, drain them well. Add the cod and mash the two ingredients thoroughly together.\r\n\r\nPlace in the container of an electric blender:\r\n1 tomato, peeled and chopped\r\n1/2 green pepper, chopped\r\n1 medium onion, peeled and chopped\r\n1 clove garlic, slivered\r\n1/2 tsp. Tabasco sauce, or minced hot pepper\r\nDash of nutmeg\r\nSalt and pepper to taste\r\n\r\nBlend for a few seconds and pour the sauce over the mashed fish mixture. Combine these ingredients well and add 1 egg, beaten Mixture should be stiff enough to mold into balls about one and a half inches in diameter, If it's too dry, add the fish stock a tablespoon at a time. Fry the balls in hot, deep fat until golden brown.", "equipment_tags": ["Blender"], "portions": 2, "prep_minutes": 76, "prep_minutes_source": "estimated", "kcal": 270, "protein_g": 9.6, "carbs_g": 51.9, "fat_g": 3.2, "total_kcal": 541, "total_protein_g": 19.2, "total_carbs_g": 103.8, "total_fat_g": 6.3, "macro_confidence": 0.91, "is_new": false, "video": null}, {"id": "53441", "name": "Banana den Forno", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/6v583k1780093743.jpg", "local_image": "53441.jpg", "ingredients": [{"ingredient": "Banana", "measure": "4"}, {"ingredient": "Ground Cinnamon", "measure": "2 tablespoons"}, {"ingredient": "Vanilla Extract", "measure": "3  tablespoons"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Water", "measure": "4 cups"}], "instructions": "Peal the bananas and boil them together with the cinnamon, vanilla extract, sugar and water for about 20 minutes. Bake the bananas in the oven at 275°F for 10 minutes. Serve with favorite ice cream.", "equipment_tags": [], "portions": 10, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 117, "protein_g": 0.3, "carbs_g": 28.0, "fat_g": 0.1, "total_kcal": 1171, "total_protein_g": 3.4, "total_carbs_g": 280.0, "total_fat_g": 1.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53442", "name": "Cheese Sticks", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/7i6csk1780094394.jpg", "local_image": "53442.jpg", "ingredients": [{"ingredient": "Flour", "measure": "1 cup"}, {"ingredient": "Milk", "measure": "1/2 cup"}, {"ingredient": "Butter", "measure": "Knob"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Mozzarella", "measure": "1 kg"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "1 tsp"}, {"ingredient": "Oil", "measure": "For frying"}], "instructions": "Cut the cheese and long strips and place in your fridge to prevent it becoming soft. Mix flour, butter and egg in a bowl, and add sugar, salt and olive oil to taste into the mix. Then gradually add milk and knead well for a suitable consistency.\r\n\r\nStretch out the dough with a rolling pin and cut into long strips (2 to 3 cm) and then roll the strips of dough around the cheese strips forming a spiral. Make sure the dough covers the cheese fully so that it doesn't melt out while frying. Roll the cheese & dough strips through flour to prevent them from sticking while frying. Heat oil in a frying pan until hot before placing the cheese sticks, and fry until golden in color.", "equipment_tags": [], "portions": 8, "prep_minutes": 31, "prep_minutes_source": "estimated", "kcal": 480, "protein_g": 37.9, "carbs_g": 17.3, "fat_g": 28.4, "total_kcal": 3838, "total_protein_g": 303.2, "total_carbs_g": 138.2, "total_fat_g": 227.0, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/_RC2m-VGdP0"}, {"id": "53443", "name": "Satee", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/dqxtlh1780153831.jpg", "local_image": "53443.jpg", "ingredients": [{"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Lemons", "measure": "Juice of 2"}, {"ingredient": "Sugar", "measure": "2 tablespoons"}, {"ingredient": "Soy Sauce", "measure": "1 cup"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Ground Coriander", "measure": "1 tsp"}, {"ingredient": "Oil", "measure": "1 cup"}, {"ingredient": "Beef", "measure": "4-5 pound"}, {"ingredient": "Oil", "measure": "1 cup"}, {"ingredient": "Soy Sauce", "measure": "2 tablespoons"}], "instructions": "To make the marinade for the satee put in the container of an electric blender:\r\n\r\n1 large onion, coarsely chopped 2 cloves of garlic\r\nJuice of 2 lemons\r\n2Tbs. of sugar 1 cup of soy sauce\r\n1 tsp. salt 1 tsp. ground coriander for beef (or chicken) or 1 tsp. ground ginger for pork\r\n1 cup of oil\r\nBlend thoroughly and pour over:\r\n5 lbs. of beef or pork tenderloin, cubed\r\nDO NOT marinate overnight, but only for a few hours.\r\n\r\nPlace the meat on: 36 skewers\r\n\r\nBlend well:\r\n\r\n1 cup of oil\r\n2 Tbs. Soy sauce\r\nPour into a large shallow dish.\r\n\r\nTo keep meat from becoming dry, roll each skewer in seasoned oil before frying.\r\n\r\nSatee is also excellent when barbecued.", "equipment_tags": ["Blender", "Grill"], "portions": 6, "prep_minutes": 76, "prep_minutes_source": "estimated", "kcal": 783, "protein_g": 79.5, "carbs_g": 9.0, "fat_g": 47.8, "total_kcal": 4699, "total_protein_g": 477.2, "total_carbs_g": 53.9, "total_fat_g": 286.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53444", "name": "Tirolean Dumplings", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/jbw8m11780155348.jpg", "local_image": "53444.jpg", "ingredients": [{"ingredient": "Bread", "measure": "200g"}, {"ingredient": "Milk", "measure": "200ml"}, {"ingredient": "Smoked Ham", "measure": "100g"}, {"ingredient": "Eggs", "measure": "3"}, {"ingredient": "Shallots", "measure": "2"}, {"ingredient": "Butter", "measure": "Knob"}, {"ingredient": "Parsley", "measure": "2 tablespoons"}, {"ingredient": "Flour", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Nutmeg", "measure": "Pinch"}, {"ingredient": "Butter", "measure": "Garnish"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "Step 1\r\nFinely chop the shallots, and dice the smoked ham or sausage into small cubes. Heat some butter or clarified butter in a pan and sweat the onions in it until translucent. Add the meat and the parsley and fry together briefly before removing from the heat.\r\n\r\nStep 2\r\nPlace the bread in a bowl. Beat the milk with the eggs and season well with salt, pepper and nutmeg. Pour over the bread. Stir in the sausage and onion paste and mix in the flour. Mix together to form a relatively firm paste (adding more bread or flour if necessary) and season again according to taste. Smooth the surface of the dough out and leave to stand for approx. 30 minutes.\r\n\r\nStep 3\r\nHeat up a good quantity of salted water in a large pan. Use the paste to form smaller dumplings (for use as a garnish in soups) or medium-sized dumplings, as required. Moisten the hands regularly with cold water during this stage so that the dumplings take on smooth forms.\r\n\r\nStep 4\r\nPlace in boiling water, bring back to the boil, turn down the heat, and simmer gently for 8-20 minutes, depending on the size.\r\n\r\nStep 5\r\nRemove from the water, dry off well and serve up garnished with chopped parsley and melted butter (which has been taken on a nut-brown colour).", "equipment_tags": [], "portions": 2, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 745, "protein_g": 35.7, "carbs_g": 72.2, "fat_g": 35.7, "total_kcal": 1491, "total_protein_g": 71.3, "total_carbs_g": 144.3, "total_fat_g": 71.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53445", "name": "Kaspressknödel - Cheese Dumplings", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/x26z3y1780155760.jpg", "local_image": "53445.jpg", "ingredients": [{"ingredient": "Bread", "measure": "250g"}, {"ingredient": "Cheese", "measure": "250g"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Parsley", "measure": "Pinch"}, {"ingredient": "Potatoes", "measure": "3"}, {"ingredient": "Flour", "measure": "100g"}, {"ingredient": "Milk", "measure": "250ml"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Butter", "measure": "For frying"}], "instructions": "Step 1\r\nMix the cubed white bread with the milk, season with salt, and let the mixture rest for a while.\r\n\r\nStep 2\r\nNow add the shredded potatoes, the grated cheese, eggs, and parsley.\r\n\r\nStep 3\r\nMelt the butter and fry the cubed onions until golden brown in colour and put into the mixture.\r\n\r\nStep 4\r\nAdd the flour and gently knead the dough. Shape it into round dumplings, gently press them flat and fry them on both sides in butter until golden brown.\r\n\r\nStep 5\r\nServe in clear broth.", "equipment_tags": [], "portions": 3, "prep_minutes": 43, "prep_minutes_source": "estimated", "kcal": 950, "protein_g": 41.7, "carbs_g": 104.5, "fat_g": 40.7, "total_kcal": 2849, "total_protein_g": 125.2, "total_carbs_g": 313.6, "total_fat_g": 122.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53446", "name": "Clear Soup with Semolina Dumplings", "category": "Miscellaneous", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qserum1780156275.jpg", "local_image": "53446.jpg", "ingredients": [{"ingredient": "Semolina", "measure": "120g"}, {"ingredient": "Butter", "measure": "60g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Nutmeg", "measure": "Pinch"}, {"ingredient": "Oil", "measure": "Splash"}, {"ingredient": "Beef Stock", "measure": "1 L"}, {"ingredient": "Parsley", "measure": "Chopped"}], "instructions": "Step 1\r\nAllow butter to come to room temperature before beating in a bowl until creamed. Season with salt and a small, delicate pinch of nutmeg.\r\n\r\nStep 2\r\nAdd in the egg, stirring vigorously. Sprinkle the semolina over this, and mix it in well until the surface is smooth. Cover with saran wrap and leave to rest for 15 – 20 minutes.\r\n\r\nStep 3\r\nUse two spoons, dipped regularly into hot water throughout, to press or shape dumplings from the paste. You can also place these on a lightly oiled board or plate and again leave them to stand for a short while (this allows the dumplings to rise even more).\r\n\r\nStep 4\r\nHeat a generous quantity of salted water in a large pan. Place the dumplings into the water and bring them back to a boil before turning down the heat and leaving to simmer gently for 10 – 15 minutes (do not boil). Carefully turn the dumplings occasionally.\r\n\r\nStep 5\r\nRemove the semolina dumplings carefully and put them in the heated soup. Serve promptly, with a garnish of sprinkled parsley or chives.\r\n\r\nStep 6\r\nThe semolina dumplings can also be cooked in the beef broth, but this causes the soup to take on a slightly dull appearance. The cooked dumplings should never be left standing in the soup for too long, as they will “soak up” the soup and become softened.", "equipment_tags": [], "portions": 3, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 377, "protein_g": 9.4, "carbs_g": 32.4, "fat_g": 23.8, "total_kcal": 1130, "total_protein_g": 28.2, "total_carbs_g": 97.1, "total_fat_g": 71.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53447", "name": "Tafelspitz", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/svf3d01780298321.jpg", "local_image": "53447.jpg", "ingredients": [{"ingredient": "Beef Brisket", "measure": "1.5kg"}, {"ingredient": "Carrots", "measure": "1  bunch"}, {"ingredient": "Celeriac", "measure": "1"}, {"ingredient": "Parsnips", "measure": "2"}, {"ingredient": "Parsley", "measure": "Sprigs of fresh"}, {"ingredient": "Leek", "measure": "1/2"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Peppercorns", "measure": "5"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "Step 1\r\nSlice the unpeeled onion in half widthways and fry off the cut surfaces without fat until fairly well browned.\r\n\r\nStep 2\r\nPut around 3 litres of water into a large saucepan. Add the root vegetables, leek, halves of onion, bay leaves, and peppercorns and bring to a boil. Add the washed meat and bones and, depending on the type of meat, allow to cook until softened in gently simmering water, which will take around 2 1⁄2 – 3 hours. Add more water as required and skim off any foam from the surface. \r\n\r\nStep 3\r\nSeason well with salt, but only after a good 2 hours.\r\n\r\nStep 4\r\nOnce the meat has softened, remove it from the pan and keep it warm in some of the liquid from the soup. Season the remainder of the soup again with salt to taste, and strain it (optional). Serve with semolina dumplings or \"Frittaten\" (sliced pancakes - a traditional Austrian soup garnish) and freshly chopped chives as a starter. Afterwards, slice the boiled beef by cutting on the bias and arrange it on pre-heated plates, or serve in the hot soup in a decorative soup tureen.\r\n\r\nStep 5\r\nServe with roast potatoes, a bread and horseradish mix, green beans in a dill sauce, or creamed spinach and chive sauce. If the root vegetables are to be served at the same time, cook some of them separately to be served al dente.", "equipment_tags": [], "portions": 4, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 737, "protein_g": 77.0, "carbs_g": 9.4, "fat_g": 43.4, "total_kcal": 2948, "total_protein_g": 307.8, "total_carbs_g": 37.5, "total_fat_g": 173.5, "macro_confidence": 0.9, "is_new": false, "video": null}, {"id": "53448", "name": "Tendir Choreyi (Tandoori Bread)", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5mfmh01780158856.jpg", "local_image": "53448.jpg", "ingredients": [{"ingredient": "Yeast", "measure": "2 1/2 Tsp"}, {"ingredient": "Warm Water", "measure": "1 1/2 cups"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Flour", "measure": "3 Cups"}, {"ingredient": "Egg Yolks", "measure": "For brushing"}, {"ingredient": "Poppy Seeds", "measure": "1 tsp"}], "instructions": "First a quick note about tandoori bread (or tandoori anything, really). The name comes from the clay oven, or \"tandoor\" that it is traditionally cooked in, and you will never be able to duplicate the flavor of any tandoori recipe without one of those ovens, no matter how hard you try. Now, a tandoor oven is actually a part of my dream kitchen (I love naan bread and tandoori chicken) but I don't have one in my current kitchen, so this bread just goes in a plain oven, which makes it not very authentic. However, this is how an Azerbaijani stranded in the US would make a tandoori bread, so I guess I don't feel too bad about including it in my meal.\r\n\r\nThe ingredients for this bread are roughly similar to the ingredients for a basic french bread, but the shape is different and it is topped with poppy seeds which actually makes it quite beautiful in appearance. In fact this bread is quite possibly the most beautiful thing I've ever baked (my cakes certainly don't fall into that category).\r\nSo as always I used my bread machine, but this time I didn't proof the yeast first. I just put it in the little yeast dispenser at the top of my machine, then added the water, flour and salt to the bucket. I put it on the dough cycle and then went and picked my kids up from school.\r\n\r\nThis bread uses very basic ingredients, including bread flour and salt.\r\n\r\nIf you want to do it the old-fashioned way:\r\n\r\nMix the yeast with the water and let stand for a few minutes. Then sift the flour with the salt into a large bowl. Gradually add the water and yeast and mix with your hand until the dough forms a ball.\r\nTurn out onto a lightly floured surface. Knead the dough for 8 to 10 minutes, or until it is smooth. Put it in a large bowl and cover, then let it rise in a warm spot until doubled (this typically takes 1 to 1 1/2 hours).\r\n\r\nThe dough after it has risen.\r\n\r\nPunch down and turn out onto a lightly floured surface. Stretch the dough until it is an oblong shape, then with a rolling pin roll it until it is about 1/2 inch thick. Transfer to a greased or non-stick baking sheet and let stand for another 15 minutes.\r\n\r\nAfter stretching and rolling, your dough should be roughly this shape.\r\n\r\nCut crosshatches in the top of the dough, about four in either direction. Brush with the beaten egg yolk (I mixed mine with a little bit of water to make it easier to work with) and sprinkle with poppy seeds.\r\n\r\nCrosshatches, egg wash and poppy seeds give this bread its distinctive look.\r\n\r\nBake in a preheated oven at about 400 degrees for 20 to 25 minutes, until golden on top", "equipment_tags": [], "portions": 8, "prep_minutes": 170, "prep_minutes_source": "explicit", "kcal": 194, "protein_g": 6.1, "carbs_g": 37.2, "fat_g": 1.9, "total_kcal": 1552, "total_protein_g": 48.9, "total_carbs_g": 297.6, "total_fat_g": 15.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53449", "name": "Kelem dolmasi", "category": "Lamb", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/7vdtqi1780160088.jpg", "local_image": "53449.jpg", "ingredients": [{"ingredient": "Lamb Mince", "measure": "500g"}, {"ingredient": "Cabbage", "measure": "1 large"}, {"ingredient": "Onion", "measure": "8 oz"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Turmeric", "measure": "1/2 tsp"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}, {"ingredient": "Cilantro", "measure": "2 tablespoons"}, {"ingredient": "Dill", "measure": "2 tablespoons"}, {"ingredient": "Rice", "measure": "2 oz"}, {"ingredient": "Chickpeas", "measure": "2 oz"}, {"ingredient": "Lamb Fat", "measure": "3 oz"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "3  tablespoons"}], "instructions": "First boil the rice for eight minutes. Meanwhile, peel and finely chop the onion. Then chop the herbs.\r\n\r\nThe recipe didn't really say what to do with the chickpeas (also known of course as garbanzo beans), beyond soaking them overnight and rinsing them. I used canned chickpeas, since I've never actually seen them dried. I decided to chop/mash them slightly so they would better incorporate into the filling.\r\n\r\n\r\nChickpeas (or garbanzo beans) roughly chopped\r\n\r\n\r\nNow mince the lamb (I used my mini food processor). Here's where I ran into another problem: what to do with the lamb fat this recipe calls for? Mince it? Melt it? Does lamb fat even melt? I decided to mince mine. Thankfully, my husband doesn't actually read this blog because he'd be horrified if he knew I put fat in the dolma on purpose.\r\n\r\n\r\nMinced lamb and its good friend, minced fat. Ew.\r\n\r\n\r\n\r\nThe ingredients for the dolma stuffing include onion, cilantro, chickpeas and turmeric.\r\n\r\n\r\nAnyway, now get your hands into all that slimy raw meat and mix in the onion, spices, chickpeas, rice, chopped herbs and fat. Add a little salt and pepper for good measure. In fact, based on my results I would say to err on the side of a little extra salt and pepper.\r\n\r\n\r\nMix well with your hands until the stuffing looks something like this.\r\n\r\n\r\nFill the biggest saucepan you own with salted water and bring it to a boil over high heat. Now pull the outer leaves off of the cabbage (save them) and drop the rest of it, whole, into the water. Let it boil for three or four minutes, turning it if the water level isn't quite high enough to completely cover it.\r\n\r\nThe reason you are doing this is because it's difficult to get whole cabbage leaves off of an American cabbage. The cabbages you typically buy in our supermarkets come in very tight round balls, and because the leaves are crispy they will snap and crack when you try to pull them off in an un-blanched state. Blanching them for a few minutes makes it so they will come right off without tearing.\r\n\r\n\r\n\r\nNow carefully take the cabbage out of the water (but keep the water boiling) and let it cool for a minute or two so you don't burn your fingers. Carefully pull the leaves off the cabbage, cutting them at the base if you have to do so to loosen them. Try to get them off in one piece. If the inner leaves are still crispy, return the cabbage to the boiling water for another three or four minutes. Repeat until all of the useable leaves are free.\r\n\r\n\r\nBlanched cabbage leaves\r\n\r\n\r\nNow put the leaves on a cutting board and cut out the tough stalks (save them). Cut the largest leaves in half.\r\n\r\nRemove the tough inner stalk and set aside. Cut larger leaves in two.\r\n\r\nPut a heaping tablespoon of the filling in the middle of each leaf, making a short cylinder shape. Fold the ends over the filling, then roll tightly (as if you are making a tiny burrito).\r\n\r\n\r\nThis is not much of a cylinder, but you get the idea.\r\n\r\n\r\nFold the edges over ...\r\n\r\n\r\n\r\n\r\nThen roll, as if you were making a really small burrito.\r\n\r\n\r\n\r\nYour finished dolma should look kind of like this, only without the hole in the middle.\r\n\r\n\r\nPut all of the discarded cabbage leaves, stalks etc. into the bottom of a stockpot. I know, this seems a little strange. What you're basically going to be doing is steaming the dolma, with the discarded cabbage pieces forming the base of your steamer. Carefully place the dolma on the bed of cabbage leaves.\r\n\r\n\r\nThese dolma are resting on top of discarded cabbage leaves.\r\n\r\n\r\nAdd water to the stockpot up to about the top of the discarded leaves. Don't cover the dolma.\r\n\r\nNow here's where you have to get a bit creative. The dolma needs to be weighted down so it doesn't unwrap during cooking. I used a metal pie pan, and then I put my mortar on top of it. You could also use a dessert plate with something heavy on top of it, but it would need to be an oven-safe one.\r\n\r\n\r\nThe dolma need to be weighted down during cooking so they don't unwrap. Just improvise.\r\n\r\n\r\nBring the water to a boil, then simmer for 25 minutes.You might have to use your ears to figure out if the water is actually boiling; I personally couldn't see what was in my pot after I weighted it down.\r\n\r\nMeanwhile, make a simple tomato sauce out of the tomato paste and water. Heat it up for a few minutes over a medium flame. After the dolma have been cooking for 25 minutes, pour the sauce over them and cook for another five minutes.", "equipment_tags": ["FoodProcessor"], "portions": 2, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 1055, "protein_g": 65.6, "carbs_g": 47.5, "fat_g": 65.3, "total_kcal": 2111, "total_protein_g": 131.2, "total_carbs_g": 95.0, "total_fat_g": 130.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53450", "name": "Grits", "category": "Breakfast", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/bfok4w1780242078.jpg", "local_image": "53450.jpg", "ingredients": [{"ingredient": "Grits", "measure": "1/4 cup"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1 cup"}], "instructions": "Bring water with salt to a boil then add grits; reduce heat and cover. occasionally stirring. Cook approximately 15 minutes or until grits have desired consistency. Cool then serve", "equipment_tags": [], "portions": 1, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 90, "protein_g": 3.0, "carbs_g": 9.0, "fat_g": 4.8, "total_kcal": 90, "total_protein_g": 3.0, "total_carbs_g": 9.0, "total_fat_g": 4.8, "macro_confidence": 0.67, "is_new": false, "video": null}, {"id": "53451", "name": "Bangladeshi fish curry with daikon", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/r7mcjm1780261264.jpg", "local_image": "53451.jpg", "ingredients": [{"ingredient": "White Fish", "measure": "450g"}, {"ingredient": "Daikon Radish", "measure": "450g"}, {"ingredient": "Vegetable Oil", "measure": "4 tablespoons"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Onion", "measure": "1 medium"}, {"ingredient": "Salt", "measure": "2 tsp"}, {"ingredient": "Ground Turmeric", "measure": "1 tsp"}, {"ingredient": "Ground Coriander", "measure": "2 tsp"}, {"ingredient": "Chilli Powder", "measure": "2 tsp"}, {"ingredient": "Green Chilli", "measure": "2"}, {"ingredient": "Coriander Leaves", "measure": "Handful"}, {"ingredient": "Lime", "measure": "1"}], "instructions": "If you are using rohu fish it will usually be frozen. Soak it in cold water for 30-45 minutes to defrost and while still a little firm, descale and cut each steak into quarters and wash in cold saltwater a few times. Drain and set aside. If using an alternative such as cod, cut into 2 ½ inch chunks then rinse, drain and set aside\r\n2\r\nTop and tail the daikon and peel using a potato peeler. Cut in half widthways then cut each half down the middle, lengthways. Now slice into 2cm-thick half-moon pieces. Rinse and set aside\r\n3\r\nPlace a large, shallow saucepan over a medium heat and add the oil. When the oil is hot add the crushed garlic and stir for a minute until pale golden\r\n4\r\nAdd the onion paste and salt and cook for 3-5 minutes, until the onion softens and becomes translucent, stirring occasionally\r\n5\r\nPour in 200ml of water then cover and cook for 10 minutes, stirring once or twice\r\n6\r\nAfter 10 minutes add the ground spices and stir for a couple of minutes so that the spices cook through. Cover and cook for 5 minutes over a low heat then stir in the daikon. After a minute or so add 200ml of water. Cover and cook for 10 minutes on a medium heat\r\n7\r\nAdd the fish pieces to the pan and mix thoroughly so that the fish is coated in the spices. Gently shake the pan and cover and cook for 5 minutes on medium heat. It is very important not to stir the pot after this stage\r\n8\r\nMeanwhile, boil some water. After the 5 minutes are over carefully pour 500ml hot water into the pan. When doing this pour into the sides of the pan so that you don’t pour boiling water directly onto the fish\r\n9\r\nGive the pan a gentle shake then cover and simmer over high heat for 15 minutes. Add the chopped coriander and chillies and continue cooking for another 5 minutes then turn off the heat. Serve immediately with rice and the lime wedges", "equipment_tags": [], "portions": 3, "prep_minutes": 115, "prep_minutes_source": "explicit", "kcal": 371, "protein_g": 30.2, "carbs_g": 19.7, "fat_g": 20.4, "total_kcal": 1114, "total_protein_g": 90.7, "total_carbs_g": 59.2, "total_fat_g": 61.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53452", "name": "Handesh – Bangladeshi rice flour and date molasses cakes", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/vfybi01780261706.jpg", "local_image": "53452.jpg", "ingredients": [{"ingredient": "Date Molasses", "measure": "250g"}, {"ingredient": "Warm Water", "measure": "400ml"}, {"ingredient": "Rice Flour", "measure": "250g"}, {"ingredient": "Flour", "measure": "150g"}, {"ingredient": "Ground Cinnamon", "measure": "1/4 tsp"}, {"ingredient": "Ground Cardomom", "measure": "1/4 tsp"}], "instructions": "Add the molasses to a large mixing bowl and begin by pouring 300ml of water to start with and whisk together. The texture of Bangladeshi molasses varies from a thick syrup to slightly set. I use brands such as Zilani or Akza. If the set is very syrupy (like golden syrup) you will only require 300–325ml of water\r\n2\r\nPour in the flours and spices (if using) and whisk for 3–5 minutes, until you have a smooth batter. You need to check carefully for lumps, as they prevent the handesh from rising and will cause them to split. Cover the batter and rest for 2 hours\r\n3\r\nAfter 2 hours, thoroughly whisk the batter until smooth, as the rice flour will have settled at the bottom of the bowl. The batter should have a fairly thick consistency, yet remain loose enough to pour – similar to thick pancake or waffle batter. It should form ribbons as you drag the whisk though it\r\n4\r\nTake a cast-iron korai or wok and add enough oil to half-fill the pan, or enough to deep-fry and turn the heat to high. Once the oil is hot reduce the heat to low–medium. Drop in a teaspoon of batter to test the oil – if it rises slowly to the surface the oil is ready\r\n5\r\nPour batter in a quick steady stream into the centre of the pan, preferably using a pyrex jug with a pouring spout (About 45ml of batter for each cake). It should rise to the surface in about 15–20 seconds and slowly puff up. If it rises too quickly, just turn the heat down slightly. Cook for 45 seconds, or until the underside is golden. Carefully turn over and cook for a further 30–45 seconds, until golden. Make sure to not let excess batter drip into the pan as this may prevent the cakes from rising and always fry one at a time\r\n6\r\nIf the batter splits while frying, whisk in 2 tablespoons of flour to the mixture and try again. You should be creating handesh which are about the size of a digestive biscuit\r\n7\r\nUse a slotted spoon to remove the handesh and place on kitchen towel with frilled edge facing down while you continue frying the reaming batter. This helps retain the shape of the cakes\r\n8\r\nEnjoy hot, fresh out of the pan. Once cool, place in an airtight container overnight and in the fridge for up to a week. Reheat in a warm oven for a few minutes to refresh or on a tawa or frying pan over a very low heat, turning a few times", "equipment_tags": [], "portions": 7, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 313, "protein_g": 5.7, "carbs_g": 70.5, "fat_g": 0.6, "total_kcal": 2188, "total_protein_g": 40.2, "total_carbs_g": 493.4, "total_fat_g": 4.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53453", "name": "Bengali Chicken Curry with Potatoes", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/9ya6o71780262651.jpg", "local_image": "53453.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Onion", "measure": "2 diced"}, {"ingredient": "Ginger Garlic Paste", "measure": "1 tablespoon"}, {"ingredient": "Tomato", "measure": "2 diced"}, {"ingredient": "Cayenne Pepper", "measure": "1 tsp"}, {"ingredient": "Curry Powder", "measure": "1 tsp"}, {"ingredient": "Garam Masala", "measure": "1 tsp"}, {"ingredient": "Ground Turmeric", "measure": "1 tsp"}, {"ingredient": "Ground Cumin", "measure": "1 tsp"}, {"ingredient": "Chicken Breast", "measure": "4"}, {"ingredient": "Red Potatoes", "measure": "2 large"}, {"ingredient": "Cilantro", "measure": "1/2 cup"}], "instructions": "Heat the olive oil in a large skillet over medium-high heat. Cook and stir the onions in the hot oil until translucent, about 5 minutes. Add the ginger-garlic paste and continue cooking another 5 minutes. Reduce heat to medium; stir the tomatoes into the mixture and cook until the tomatoes are pulpy, 5 to 10 minutes. Season with the cayenne pepper, curry powder, garam masala, turmeric, and cumin; cook and stir another 5 minutes.\r\n\r\nAdd the chicken and potatoes to the mixture in the skillet; simmer, stirring occasionally, until the potatoes are tender and the chicken is no longer pink in the center, about 20 minutes. Sprinkle the cilantro over the mixture and continue simmering another 10 minutes. Serve hot.", "equipment_tags": [], "portions": 3, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 494, "protein_g": 51.0, "carbs_g": 36.4, "fat_g": 16.1, "total_kcal": 1482, "total_protein_g": 152.9, "total_carbs_g": 109.1, "total_fat_g": 48.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53454", "name": "Breadfruit in Butter Sauce Recipe", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/z672jx1780263633.jpg", "local_image": "53454.jpg", "ingredients": [{"ingredient": "Breadfruit", "measure": "1/2"}, {"ingredient": "Onion", "measure": "1/2"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Onion", "measure": "3"}, {"ingredient": "Garlic", "measure": "1 tablespoon"}, {"ingredient": "Tinned Tomatos", "measure": "500ml"}, {"ingredient": "Parsley", "measure": "3  tablespoons"}, {"ingredient": "Lime juice", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Water", "measure": "250ml"}, {"ingredient": "Red Pepper Paste", "measure": "To taste"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "\r\nCaptain William Bligh was chosen to lead an expedition to the South Seas to bring the breadfruit to the Caribbean.\r\n\r\nHis devotion to the breadfruit saplings and neglect of his crew’s water needs lead to the famous “Mutiny on the Bounty” on his first attempt. Cast overboard; Captain Bligh made his way hundreds of miles to safety in an open boat.\r\n\r\nOn his second attempt in 1793, he sailed into Jamaica’s Port Royal Harbour with a ship so crowded with beautiful leafy breadfruit saplings that the Jamaicans rowed out toward “the ship that has bush.”\r\n\r\nToday large, lush breadfruit trees grow throughout the Caribbean, bearing the football-like starchy staple that has kept hunger away from many a door. Breadfruit may be difficult to find outside the Caribbean.\r\n\r\nYou will need the following ingredients:\r\n1/2 medium breadfruit\r\n1/2 small onion\r\n1 tablespoon olive oil\r\n4 oz/125g butter\r\n3 medium onions, cut into rings\r\n1 tablespoon garlic finely chopped\r\n1 medium 16floz/500ml tin whole tomatoes, drained and sliced\r\n1/4 cup or 3 tablespoons parsley, diced\r\n1 tablespoon lime juice\r\nSalt and pepper to taste\r\n1 cup 8oz or 250ml water\r\nRed pepper sauce to taste.\r\nGarnish: fresh parsley, chopped.\r\nInstructions:\r\nCut the breadfruit, remove the seeds in the core, and peel. Boil in salted water with a little onion and oil, over high heat until tender and drain.\r\n\r\nMeanwhile, melt the butter in a frying pan and lightly brown the onion rings. Add the garlic, tomatoes, parsley, lime juice, salt, and pepper. Continue to sauté for a couple of minutes. Add the water, bring to the boil and simmer for 5-10 minutes.\r\n\r\nSlice the cooled breadfruit and place it in a serving dish. Pour the butter sauce over the breadfruit.\r\n\r\nGarnish with chopped fresh parsley.\r\n\r\nServes 4", "equipment_tags": [], "portions": 12, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 112, "protein_g": 1.1, "carbs_g": 6.2, "fat_g": 9.8, "total_kcal": 1345, "total_protein_g": 13.6, "total_carbs_g": 74.2, "total_fat_g": 117.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53455", "name": "Chicken Liver Pate Recipe", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/hob03q1780264260.jpg", "local_image": "53455.jpg", "ingredients": [{"ingredient": "Chicken Liver", "measure": "1lb"}, {"ingredient": "Bacon", "measure": "1/2 lb"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Ground Mustard", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Milk", "measure": "Splash"}, {"ingredient": "Sherry", "measure": "1 tablespoon"}], "instructions": "Clean livers of sinews and gall.\r\nPut into a fireproof casserole with all other ingredients roughly chopped.\r\nSeason and cover with milk.\r\nPut the lid on the casserole and cook in a slow oven (300ºF) for 2 hours.\r\nLiquidize in a blender.\r\nAdjust seasoning.\r\nAdd sherry or brandy.\r\nPut in a dish and cover with melted butte", "equipment_tags": ["Blender"], "portions": 12, "prep_minutes": 120, "prep_minutes_source": "explicit", "kcal": 154, "protein_g": 13.6, "carbs_g": 2.8, "fat_g": 9.8, "total_kcal": 1851, "total_protein_g": 163.0, "total_carbs_g": 33.9, "total_fat_g": 118.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53456", "name": "Bajan Salt Bread Recipe", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sr7chd1780264758.jpg", "local_image": "53456.jpg", "ingredients": [{"ingredient": "Yeast", "measure": "2 tubs"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Flour", "measure": "6 cups"}, {"ingredient": "Warm Water", "measure": "2 1/2 cups"}], "instructions": "Sift half the flour, mix with salt and yeast in a large mixing bowl, and slowly add warm water until the mixture forms a stiff dough. Add more sifted flour until you have a stiff enough dough to knead.\r\nLightly flour the work surface, knead the dough for 10 minutes until it is smooth and elastic, and then place it in a greased bowl. Now place the bowl warmly for 40-50 minutes until it has doubled. You know the dough is ready when you poke a finger, and the indentation remains.\r\nPreheat oven to 425 degrees F or 220 degrees C.\r\nNow divide the dough into 12 equal portions, roll each into a fist size ball, and place on a greased baking sheet. Now place in a warm place again for a further 40 minutes or again until the dough has doubled in size.\r\nNow place in the oven’s center and bake for 25-30 minutes until golden brown rolls sound hollow when tapped.", "equipment_tags": [], "portions": 12, "prep_minutes": 130, "prep_minutes_source": "explicit", "kcal": 282, "protein_g": 9.7, "carbs_g": 52.5, "fat_g": 3.6, "total_kcal": 3380, "total_protein_g": 116.3, "total_carbs_g": 629.5, "total_fat_g": 42.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53457", "name": "Barbados Pepperpot", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/5tf8j11782236249.jpg", "local_image": "53457.jpg", "ingredients": [{"ingredient": "Pigs Trotters", "measure": "2"}, {"ingredient": "Oxtail", "measure": "2 Lbs"}, {"ingredient": "Lime juice", "measure": "Splash"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Scotch Bonnet", "measure": "2"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Cinnamon Stick", "measure": "1"}, {"ingredient": "Cloves", "measure": "2"}, {"ingredient": "Sugar", "measure": "Pinch"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Basil", "measure": "Sprinkling"}, {"ingredient": "Thyme", "measure": "Sprinkling"}, {"ingredient": "Beef", "measure": "2 Lbs"}], "instructions": "Wash the stewing steak and place it in the mixing bowl with the lemon or lime juice.\r\nSet that to one side; while you slice the garlic into tiny slices, slice the onion. Chop the basil and thyme.\r\nNow you need to be very careful when you slice the scotch bonnet peppers; you want these in fine pieces, which you can either do with a long knife trying not to touch the pepper, or you can wear rubber gloves to cut it up. Wash your hands straight afterward and do not touch your eyes; these peppers really burn your hands and eyes if they make contact with the skin!\r\nNow rinse the lime or lemon juice off the stewing steak. And cut the meat into cubes.\r\nAlso, chop the pig’s trotters and the oxtail into cubes.\r\nFill the large saucepan with water and bring to a boil.\r\nAdd the pig’s trotters.\r\nWhen the pig’s trotters have boiled, drain the excess water, and now add the stewing steak and cover with fresh hot water.\r\nNow add your chopped garlic, onion, and peppers.\r\nNow add the cinnamon stick, cloves, basil, and thyme and a pinch of salt and sugar to taste.\r\nNow simmer until the meat is tender. The flavor of this dish comes out over a few days and therefore gets tastier each time you reheat it; make sure you always reheat the entire pot to boiling point.", "equipment_tags": [], "portions": 4, "prep_minutes": 55, "prep_minutes_source": "estimated", "kcal": 1044, "protein_g": 93.7, "carbs_g": 13.8, "fat_g": 68.3, "total_kcal": 4175, "total_protein_g": 374.9, "total_carbs_g": 55.3, "total_fat_g": 273.2, "macro_confidence": 0.92, "is_new": false, "video": "https://www.youtube.com/watch?v=9L2nQEBRPdg"}, {"id": "53458", "name": "Breadfruit in Butter Sauce", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/6utn1w1782237402.jpg", "local_image": "53458.jpg", "ingredients": [{"ingredient": "Breadfruit", "measure": "1/2"}, {"ingredient": "Onion", "measure": "1/2"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Butter", "measure": "125g"}, {"ingredient": "Onions", "measure": "3 Medium"}, {"ingredient": "Garlic", "measure": "1 tablespoon chopped"}, {"ingredient": "Tinned Tomatos", "measure": "500ml"}, {"ingredient": "Parsley", "measure": "3  tablespoons"}, {"ingredient": "Lime juice", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Water", "measure": "250ml"}, {"ingredient": "Red Pepper Sauce", "measure": "To taste"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "Cut the breadfruit, remove the seeds in the core, and peel. Boil in salted water with a little onion and oil, over high heat until tender and drain.\r\n\r\nMeanwhile, melt the butter in a frying pan and lightly brown the onion rings. Add the garlic, tomatoes, parsley, lime juice, salt, and pepper. Continue to sauté for a couple of minutes. Add the water, bring to the boil and simmer for 5-10 minutes.\r\n\r\nSlice the cooled breadfruit and place it in a serving dish. Pour the butter sauce over the breadfruit.\r\n\r\nGarnish with chopped fresh parsley.\r\n\r\nServes 4", "equipment_tags": [], "portions": 12, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 112, "protein_g": 1.1, "carbs_g": 6.2, "fat_g": 9.8, "total_kcal": 1345, "total_protein_g": 13.6, "total_carbs_g": 74.2, "total_fat_g": 117.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53459", "name": "Chicken and Potato Roti", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/mp9z0i1782238092.jpg", "local_image": "53459.jpg", "ingredients": [{"ingredient": "Flour", "measure": "1 lb"}, {"ingredient": "Shortening", "measure": "3  tablespoons"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Water", "measure": "Splash"}, {"ingredient": "Chicken Breast", "measure": "6"}, {"ingredient": "Parsley", "measure": "Pinch"}, {"ingredient": "Thyme", "measure": "Pinch"}, {"ingredient": "Jerk", "measure": "Pinch"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Sugar", "measure": "Pinch"}, {"ingredient": "Black Pepper", "measure": "Pinch"}, {"ingredient": "Onion", "measure": "2 large"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Scotch Bonnet", "measure": "1"}, {"ingredient": "Potatoes", "measure": "1/2 lb"}], "instructions": "Add a pint of chicken stock to the simmer and put three tablespoons of sugar into a large saucepan on high; cook until the sugar caramelizes, then add the cubed chicken breasts and stir until the chicken browns.\r\nAdd chopped onions, garlic, parsley, thyme, jerk seasoning, salt, and the whole scotch bonnet pepper – do not cut up the pepper! Reduce the heat to low and let this simmer for 25 minutes.\r\nIn a large mixing bowl, sift the flour, and add a pinch of salt to taste.\r\nNow add the first tablespoon of shortening, and with your fingers, rub the flour into the shortening until it forms a breadcrumb-like consistency.\r\nThen add the second tablespoon of shortening and rub against the flour until it looks like breadcrumbs.\r\nNow add the third tablespoon of shortening and repeat the process.\r\nYou should by now have used all the flour. Your bowl should be all breadcrumb-like; if you still have fresh flour, use another tablespoon of shortening until your fresh flour is all used up.\r\nAdd a small amount of water and mix with a butter knife; keep adding small amounts until your mixture forms a soft dough.\r\nNow dust your surface with flour and roll out your pastry; you want to roll wafer-thin rounds – this mixture should make at least 12 roti skins.\r\nCover with a tea towel while returning to the pot.\r\nNow peel the potatoes and cube them into small bite-size pieces.\r\nAfter 25 minutes of simmering, add 1/2 pint of water and the potatoes to the pool.\r\nNow cover and cook for 30 minutes on low heat.\r\nTurn a flat baking tray upside down, lightly cover with foil, and place on the stovetop on high; cook each roti skin for 1 minute on each side until brown but not crisp.\r\nNow pile up your cooked roti skins, remove the pot after 30 minutes, and remove the whole scotch bonnet.\r\nTake the entire pot to the table with a pile of plates; each person assumes the roti skin, lays it flat on the scale, spoons some filling into the middle of the roti skin, and folds around the filling eats enjoy.", "equipment_tags": [], "portions": 4, "prep_minutes": 111, "prep_minutes_source": "explicit", "kcal": 859, "protein_g": 64.2, "carbs_g": 103.3, "fat_g": 18.4, "total_kcal": 3434, "total_protein_g": 256.7, "total_carbs_g": 413.3, "total_fat_g": 73.7, "macro_confidence": 0.93, "is_new": false, "video": "https://www.youtube.com/watch?v=2ehdHb1rcAQ"}, {"id": "53460", "name": "Bajan Sweet Bread", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/5vhbzt1782239221.jpg", "local_image": "53460.jpg", "ingredients": [{"ingredient": "Coconut", "measure": "2 1/2 cups"}, {"ingredient": "Melted Butter", "measure": "1/2 cup"}, {"ingredient": "Flour", "measure": "4 cups"}, {"ingredient": "Shortening", "measure": "1 tablespoon"}, {"ingredient": "Baking Powder", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "3/4 cup"}, {"ingredient": "Raisins", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Evaporated Milk", "measure": "1 1/4 cup"}, {"ingredient": "Almond Essence", "measure": "1 tsp"}], "instructions": "Add all the flour, baking powder, and salt to a large mixing bowl.\r\nMelt the butter in a saucepan.\r\nMix the coconut and most of the sugar in another bowl – leave some back to cover the loaves later, raisins, egg, milk, almond essence, vanilla essence, and melted butter.\r\nMix well until you have a creamy paste.\r\nAdd this to the bowl with the flour, baking powder, and salt. Mix until you form a stiff dough.\r\nNow divide the mixture between the baking tins.\r\nNow boil the water.\r\nMix two tablespoons of sugar with some hot water and brush the top of each loaf.\r\nBake in the center of the oven for 1 hour.\r\nLeave to cool in tins before serving; slice and serve with a fresh pot of tea.", "equipment_tags": [], "portions": 12, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 696, "protein_g": 9.7, "carbs_g": 74.4, "fat_g": 43.3, "total_kcal": 8357, "total_protein_g": 116.9, "total_carbs_g": 893.1, "total_fat_g": 519.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=ZrVAFmPQaZ0"}, {"id": "53461", "name": "Macaroni Pie", "category": "Pasta", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/kpiu4t1782242131.jpg", "local_image": "53461.jpg", "ingredients": [{"ingredient": "Macaroni", "measure": "250g"}, {"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Cheddar Cheese", "measure": "375g"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Milk", "measure": "250ml"}, {"ingredient": "Ground Onion", "measure": "2 tsp"}, {"ingredient": "Mustard", "measure": "1 tsp"}, {"ingredient": "Pepper", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1/2 tsp"}, {"ingredient": "Breadcrumbs", "measure": "2 tablespoons"}, {"ingredient": "Butter", "measure": "2 tsp"}, {"ingredient": "Cheddar Cheese", "measure": "2 tablespoons"}], "instructions": "Bring water to a boil and add the broken-up macaroni, elbows, and salt. Cook uncovered until tender but not overcooked (about 8 minutes).\r\n\r\nPreheat a moderately hot oven to 350F, 180C, or Gas Mark 4.\r\n\r\nDrain the macaroni thoroughly, put it back into the same hot saucepan cooked in, and mix in the butter.\r\n\r\nGrate the cheese and mix it with the macaroni while it is still warm.\r\n\r\nWhisk the egg until fluffy, and add the milk, onion powder, white pepper, salt, pepper sauce, and mustard. Pour in with the macaroni and mix.\r\n\r\nPlace in a greased ovenproof casserole dish. Top with butter, some grated cheese, and fine breadcrumbs. Bake in the center of the oven for about 30-45 minutes, depending on the dish’s depth.", "equipment_tags": [], "portions": 7, "prep_minutes": 53, "prep_minutes_source": "explicit", "kcal": 443, "protein_g": 21.9, "carbs_g": 33.3, "fat_g": 24.6, "total_kcal": 3098, "total_protein_g": 153.5, "total_carbs_g": 232.8, "total_fat_g": 172.5, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/watch?v=38dxvOH7Z-s"}, {"id": "53462", "name": "Cinnamon Roll Cookies", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/txce0y1782494894.jpg", "local_image": "53462.jpg", "ingredients": [{"ingredient": "Plain Flour", "measure": "250g"}, {"ingredient": "Unsalted Butter", "measure": "180g"}, {"ingredient": "Caster Sugar", "measure": "85g"}, {"ingredient": "Egg", "measure": "1 medium"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Ground Cinnamon", "measure": "2 tsp"}, {"ingredient": "Brown Sugar", "measure": "30g"}], "instructions": "1) In a large bowl, combine the butter and caster sugar until creamy. Add the egg and a pinch of salt.\r\n\r\n2) Stir into a buttery mixture. Add the sifted flour.\r\n\r\n3) Whisk well. You should end up with a smooth dough. Cover it with a piece of plastic wrap and put the dough in the fridge for 15 minutes to chill and set.\r\n\r\n4) In the meantime combine the cassonade (or brown sugar) and the cinnamon.\r\n\r\n5) Transfer the dough onto a floured surface and knead it for a minute. Add extra flour if necessary. Roll the dough out gently into a nice rectangle. It should be about ⅕-inch (5 mm) thick. Sprinkle with the sugary cinnamon mixture.\r\n\r\n6) Carefully start rolling the dough up. If it is too sticky, put it in the fridge again for a couple of minutes. Wrap it up tightly in plastic wrap.\r\n\r\n7) Put it in the fridge for 30 minutes to chill and set. After that, remove the cling film and cut the dough roll into even slices.\r\n\r\n8) Place the slices on a baking paper lined baking tray. Bake the cookies in a preheated oven at 356°F (180°C) for 14 to 16 minutes.\r\n\r\n9) Let the baked cinnamon roll cookies cool down fully before eating or wrapping them up.", "equipment_tags": [], "portions": 4, "prep_minutes": 61, "prep_minutes_source": "explicit", "kcal": 685, "protein_g": 8.4, "carbs_g": 78.3, "fat_g": 38.4, "total_kcal": 2740, "total_protein_g": 33.5, "total_carbs_g": 313.2, "total_fat_g": 153.4, "macro_confidence": 1.0, "is_new": false, "video": "https://www.youtube.com/shorts/LZ6ra2I0Edo"}, {"id": "53463", "name": "Belgian Meatballs in Liège Syrup Sauce", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/gjjlzc1782496055.jpg", "local_image": "53463.jpg", "ingredients": [{"ingredient": "Minced Beef", "measure": "300g"}, {"ingredient": "Minced Pork", "measure": "300g"}, {"ingredient": "Onion", "measure": "1 chopped"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Breadcrumbs", "measure": "4 tablespoons"}, {"ingredient": "Mustard", "measure": "1 tablespoon"}, {"ingredient": "Parsley", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Oil", "measure": "Splash"}, {"ingredient": "Onion", "measure": "2 sliced"}, {"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "White Wine Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Mustard", "measure": "2 tablespoons"}, {"ingredient": "Sirop De Liège", "measure": "4 tablespoons"}, {"ingredient": "Beef Stock", "measure": "1 cup"}, {"ingredient": "Bay Leaf", "measure": "1"}, {"ingredient": "Beer", "measure": "Splash"}], "instructions": "Make the meatballs\r\n1) Mix the minced meat with the onion, garlic, egg, breadcrumbs, mustard, parsley, salt, and pepper.\r\n\r\n2) Shape into meatballs. Traditionally, Liège restaurants serve **one or two very large meatballs**, depending on appetite.\r\n\r\n3) For weeknight cooking, I keep mine smaller so they brown faster and cook through quickly.\r\n\r\nBrown the meatballs\r\n4) Heat butter or oil in a large pan.\r\n\r\n5) Brown the meatballs on all sides until they have a nice crust.\r\n\r\n6) Remove them from the pan and set aside.\r\n\r\nStart the sauce\r\n7) In the same pan, melt 1 tbsp butter.\r\n\r\n8) Add the sliced onions and cook until soft and lightly caramelised.\r\n\r\n9) Sprinkle in the brown sugar and let it melt into the onions.\r\n\r\nDeglaze and add the stock\r\n10) Add the vinegar and scrape up all the browned bits from the pan.\r\n\r\n11) Stir in the mustard and Liège syrup.\r\n\r\n12) Pour in the beef stock (and beer if using).\r\n\r\n13) Add the bay leaf.\r\n\r\n14) Stir until the syrup dissolves and the sauce looks glossy.\r\n\r\nSimmer and adjust\r\n15) Return the meatballs to the pan.\r\n\r\n16) Cover and simmer gently for 25–30 minutes (less if your meatballs are small, longer if they’re traditional large boulets). Stir occasionally and let the sauce thicken naturally.\r\n\r\n17) Taste and adjust: more syrup for sweetness, more vinegar for tang, more mustard for depth. The sauce should be sweet‑sour, rich, and velvety.\r\n\r\n18) Serve with fries or mashed potatoes.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 707, "protein_g": 45.3, "carbs_g": 34.5, "fat_g": 42.0, "total_kcal": 2122, "total_protein_g": 136.0, "total_carbs_g": 103.4, "total_fat_g": 126.0, "macro_confidence": 0.95, "is_new": false, "video": null}, {"id": "53464", "name": "Flemish Hutsepot", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/2lywl71782496853.jpg", "local_image": "53464.jpg", "ingredients": [{"ingredient": "Floury Potatoes", "measure": "600g"}, {"ingredient": "Carrots", "measure": "200g"}, {"ingredient": "Turnips", "measure": "200g"}, {"ingredient": "Leek", "measure": "250g"}, {"ingredient": "Sausages", "measure": "4"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Thyme", "measure": "4 sprigs"}, {"ingredient": "Chicken Stock", "measure": "600ml"}, {"ingredient": "Mustard", "measure": "1 tablespoon"}, {"ingredient": "Unsalted Butter", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "1) Peel and chop the onion and garlic. Add both to a large pan with the butter and place it over medium heat.\r\n\r\n2) Let the onion and garlic sweat for 5 minutes. Then add the chopped potatoes, bay leaves and thyme and stir well. Cook for another 5 minutes.\r\n\r\n3) In the meantime peel and slice the carrots. Peel the turnip. Dice it into bite-size pieces. Slice the leek in half lengthwise. Rinse it well to remove any sand. Add the vegetables to the potatoes and onion. Also add the mustard and chicken stock and season with pepper and salt.\r\n\r\n4) Stir all the ingredients well and cover the pan with a lid. Cook the hutsepot for about 20 to 25 minutes or until all the vegetables and potatoes are tender. Stir regularly. Add extra water if necessary. In the meantime pan fry the sausages in a little oil or butter until golden brown and cooked through. Keep warm.\r\n\r\n5) Once the potatoes start to fall apart, stir and turn it all into a mushy and chunky vegetable stew. Check the seasoning and add extra pepper, salt or mustard to taste.\r\n\r\n6) Scoop the hutsepot onto deep plates and top with the sausage. Serve hot with an extra dollop of mustard if you like.", "equipment_tags": [], "portions": 4, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 391, "protein_g": 12.9, "carbs_g": 49.2, "fat_g": 16.8, "total_kcal": 1564, "total_protein_g": 51.5, "total_carbs_g": 196.8, "total_fat_g": 67.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53465", "name": "Frog Legs Recipe in Garlic Butter", "category": "Miscellaneous", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/qcprt21782497529.jpg", "local_image": "53465.jpg", "ingredients": [{"ingredient": "Frogs Legs", "measure": "300g"}, {"ingredient": "Milk", "measure": "3 Cups"}, {"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "1/2 tbs"}, {"ingredient": "Butter", "measure": "2 tablespoons"}, {"ingredient": "Parsley", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}], "instructions": "1. Let the frog legs soak in the milk in the fridge for an hour (optional).\r\n\r\n2. Rinse the legs and pat them dry with kitchen paper.\r\n\r\n3. Add the olive oil and half of the garlic butter to a large wok or frying pan. Place it over high heat until the butter starts to foam. Don't let it burn.\r\n\r\n4. Add the frog legs to the pan. Pan fry them for about 10 minutes until they are golden brown on both sides. Turn the over regularly.\r\n\r\n5. Add the rest of the garlic butter right in the end together with the freshly chopped parsley. Season with a pinch of pepper and salt to taste.\r\n\r\n6. Divide the frog legs over plates. Serve with grilled bread and a green salad.", "equipment_tags": ["Grill"], "portions": 2, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 618, "protein_g": 19.6, "carbs_g": 41.7, "fat_g": 42.5, "total_kcal": 1236, "total_protein_g": 39.3, "total_carbs_g": 83.3, "total_fat_g": 85.1, "macro_confidence": 0.88, "is_new": false, "video": null}, {"id": "53466", "name": "Belgian Waterzooi Chicken", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/nmxec11782498644.jpg", "local_image": "53466.jpg", "ingredients": [{"ingredient": "Chicken Legs", "measure": "1"}, {"ingredient": "Chicken Breast", "measure": "1"}, {"ingredient": "Water", "measure": "3 Cups"}, {"ingredient": "Carrots", "measure": "1 small"}, {"ingredient": "Leek", "measure": "2"}, {"ingredient": "Celery", "measure": "1"}, {"ingredient": "Potatoes", "measure": "100g"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Rosemary", "measure": "1 Sprig"}, {"ingredient": "Cream", "measure": "1 1/2 cups"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Unsalted Butter", "measure": "1 tablespoon"}, {"ingredient": "Egg Yolks", "measure": "1"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "Put the chicken, water and one garlic clove in a large saucepan. Place it over medium-high heat until boiling. Then turn the heat low, cover the pan and simmer the chicken for 10 minutes. Remove the chicken leg and breast. Keep the fresh chicken stock for later.\r\n\r\nLet the chicken cool. Then dice the chicken breast up. Pick the meat off the leg. Discard any bones and skin. Slice the leek, celery and carrot finely (julienne). Add the butter, rosemary and bay leaves to a large pan and place it over medium heat until melted.\r\n\r\nThen add the sliced vegetables. Season with pepper and salt.\r\n\r\nStir and cook the vegetables for 3 minutes. Then add the shredded and diced chicken.\r\n\r\nCover the pan and cook the chicken and vegetables for 5 minutes. Then add the cream and ½ cup (120 ml) of the fresh chicken stock.\r\nLook at this delicious waterzooi recipe! Do try out my chunky chicken stew with fresh leeks, celery, carrots and lots of cream... This is Belgian comfort food!\r\n\r\nCover the pan and cook the stew for 20 minutes until the potatoes are tender. Add the egg yolk and 2 tablespoons of the warm cream from the pan to a cup. Whisk and add it back to the pan to thicken the sauce.\r\n\r\nStir all the ingredients and then turn the heat very low. Check the seasoning and add extra pepper or salt to taste. Remove the rosemary and bay leaves. Divide the stew over deep plates and drizzle with the remaining cream sauce. Serve hot.", "equipment_tags": [], "portions": 3, "prep_minutes": 38, "prep_minutes_source": "explicit", "kcal": 469, "protein_g": 22.3, "carbs_g": 19.7, "fat_g": 33.8, "total_kcal": 1407, "total_protein_g": 67.0, "total_carbs_g": 59.0, "total_fat_g": 101.5, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53467", "name": "Liegeoise Salad", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/ji3mho1782499823.jpg", "local_image": "53467.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "350g"}, {"ingredient": "Green Beans", "measure": "200g"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Bacon", "measure": "125g"}, {"ingredient": "Onion", "measure": "2 tbs chopped"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "White Wine Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Mustard", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "2 tablespoons"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "Scrub the potatoes well but don't peel them. Cut them into bite-size pieces. Add them to a large pan water and a pinch of salt. Bring it to a good boil. Cook the potatoes until tender and then remove them using a slotted spoon. Keep the potatoes at room temperature.\r\n\r\nTrim and clean the green beans. Add them to the pan of hot water you boiled the potatoes in. Cook the green beans until nearly tender (keep them crunchy). Strain and refresh them immediately under cold running tap water to stop the cooking process.\r\n\r\nAdd the bacon to a large non-stick pan and place it over medium heat. Cook the bacon for a couple of minutes until cooked through. Then take the pan off the heat and let the bacon cool down a little.\r\n\r\nCombine the olive oil, vinegar and mustard. Transfer the cooked potatoes, green beans, bacon, chopped onion, parsley and vinaigrette. Season with pepper and salt.\r\n\r\nStir well. Check the seasoning and add extra vinegar, pepper or salt to taste. Transfer the salad to a large serving bowl or 2 deep plates and garnish with the boiled eggs. Serve lukewarm.", "equipment_tags": [], "portions": 7, "prep_minutes": 70, "prep_minutes_source": "estimated", "kcal": 221, "protein_g": 10.2, "carbs_g": 11.7, "fat_g": 15.0, "total_kcal": 1549, "total_protein_g": 71.3, "total_carbs_g": 81.8, "total_fat_g": 105.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53468", "name": "Belgian Stoemp", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/byolko1782500400.jpg", "local_image": "53468.jpg", "ingredients": [{"ingredient": "Sausages", "measure": "2"}, {"ingredient": "Potatoes", "measure": "450g"}, {"ingredient": "Savoy Cabbage", "measure": "200g"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Parsley", "measure": "1 Handfull"}, {"ingredient": "Onion", "measure": "1 small finely diced"}, {"ingredient": "Unsalted Butter", "measure": "3  tablespoons"}, {"ingredient": "Beer", "measure": "1 cup"}, {"ingredient": "Whole Milk", "measure": "60ml"}, {"ingredient": "Nutmeg", "measure": "Pinch"}, {"ingredient": "Pepper", "measure": "Pinch"}, {"ingredient": "Salt", "measure": "Pinch"}], "instructions": "1. Add the chopped potatoes and garlic to a high pan and fill it with tap water until the potatoes are fully submerged.\r\n\r\n2. Add some salt. Then place the pan over high heat and bring the potatoes to a boil. Cook them until tender. In the meantime rinse and drain the savoy cabbage. Slice it up finely.\r\n\r\n3. Add a tablespoon of butter to a large non-stick pan. Place it over medium-high heat. Once melted, add the savoy cabbage. Season with a pinch of pepper and salt.\r\n\r\n4. Stir fry the cabbage for 15 to 20 minutes or until the cabbage is soft and tender. Then turn the heat off and take the cabbage off the heat. In the meantime, pan fry the sausages (or sliced bacon if you are using both) in a non-stick pan in a tablespoon of butter or oil until golden brown and cooked through.\r\n\r\n5. Transfer the sausages (and bacon) to a plate and cover with a lid or tinfoil to keep the meat warm. In the same greasy pan, add the sliced onion and extra butter and cook it gently over medium heat for 10 minutes until softened. (I often add diced bacon as well, if I only serve the stoemp with sausages.)\r\n\r\n6. Then add the beer and turn the heat up. Let the beer reduce until you get a nice beer and onion sauce (you can add a little flour or sauce thickener if you like). Add the pan fried meat back to the pan and cover to keep warm.\r\n\r\n7. Drain the cooked potatoes and garlic, add them back to the pan you cooked them in together with the pan fried cabbage and chopped parsley. Sprinkle with some pepper, salt and nutmeg. Also add the milk and the rest of the unsalted butter.\r\n\r\n8. Mash the potatoes, parsley and cabbage up. Add extra butter or milk if necessary. Also check the seasoning and add extra pepper, nutmeg or salt to taste if necessary. Scoop the cabbage mash onto plates and top with the pan fried sausages (and bacon). Drizzle with the beer and onion sauce. Serve hot.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 408, "protein_g": 10.5, "carbs_g": 39.9, "fat_g": 21.5, "total_kcal": 1225, "total_protein_g": 31.5, "total_carbs_g": 119.6, "total_fat_g": 64.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53469", "name": "Beef pumpkin Stew", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/k07k271782502861.jpg", "local_image": "53469.jpg", "ingredients": [{"ingredient": "Beef", "measure": "3 Lbs"}, {"ingredient": "All purpose flour", "measure": "1/2 cup"}, {"ingredient": "Butter", "measure": "3  tablespoons"}, {"ingredient": "Onion", "measure": "1 cup"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Beef Stock", "measure": "4 cups"}, {"ingredient": "Pumpkin Puree", "measure": "3 Cups"}, {"ingredient": "Worcestershire Sauce", "measure": "1 tablespoon"}, {"ingredient": "Kosher Salt", "measure": "1 tablespoon"}, {"ingredient": "Black Pepper", "measure": "1 teaspoon"}, {"ingredient": "Potatoes", "measure": "3 Lbs"}, {"ingredient": "Carrots", "measure": "1 lb"}, {"ingredient": "Thyme", "measure": "4 sprigs"}], "instructions": "Cut the beef into 1-inch chunks. Dredge the beef in the flour until all of the beef sides are covered.\r\nIn a large soup pot, melt the butter over medium high-heat. In small quantities, brown the beef on all sides, removing the browned beef and setting it aside in a large bowl as you go. When the beef is browned, add the onion and the garlic to the pot. Sauté the onion and garlic for one minute, scraping the bottom of the pot as you stir.\r\nReturn the browned beef to the pot and add the beef stock, pumpkin puree, Worcestershire sauce, salt, and pepper. Stir well and bring to a boil. Once the liquid is boiling, reduce heat to medium-low and simmer for 3 hours, stirring occasionally.\r\nAdd the potatoes, carrots and thyme sprigs to the pot and increase heat to medium. Cook for an additional 30 minutes. Salt to taste and serve.", "equipment_tags": [], "portions": 10, "prep_minutes": 210, "prep_minutes_source": "explicit", "kcal": 459, "protein_g": 32.6, "carbs_g": 41.4, "fat_g": 19.0, "total_kcal": 4592, "total_protein_g": 326.0, "total_carbs_g": 413.6, "total_fat_g": 189.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53470", "name": "Seswaa", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/p7eid81782503889.jpg", "local_image": "53470.jpg", "ingredients": [{"ingredient": "Beef", "measure": "1 kg"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Bay Leaf", "measure": "3"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Black Pepper", "measure": "Sprinkling"}, {"ingredient": "Water", "measure": "1 Litre"}], "instructions": "Pre heat the oven to 160 degrees Celsius. Cut the meat into large chunks then brown in a dish suitable for slow cooking in the oven such as a cast iron casserole dish.\r\nAdd the whole peeled onion, salt, cracked black pepper, water and bay leaves. Bring to the boil then cover and place into the oven for 4 hours.\r\nAfter 4 hours, remove from oven and place onto the stove burner in order to cook off most of the remaining liquid. Use a wooden spoon to pound or mash up the meat, the meat should fall apart quite easily. and will appear shredded. You may brown the meat further if desired.\r\nCheck seasoning then serve with polenta or the more traditional thick cornmeal porridge known as pap or sadza, and a side of green vegetables.", "equipment_tags": [], "portions": 4, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 462, "protein_g": 50.3, "carbs_g": 2.9, "fat_g": 27.6, "total_kcal": 1849, "total_protein_g": 201.4, "total_carbs_g": 11.5, "total_fat_g": 110.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53471", "name": "Phaphatha Flatbreads", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/um1phx1782504510.jpg", "local_image": "53471.jpg", "ingredients": [{"ingredient": "Flour", "measure": "500g"}, {"ingredient": "Baking Powder", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "1 1/2 tsp"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Milk", "measure": "1 cup"}], "instructions": "In a stand mixer bowl, combine the dry ingredients: flour, baking powder, salt, and sugar.\r\nWith the dough hook on low, drizzle in the milk.\r\nContinue to knead until a small ball of dough is formed.\r\nRemove the dough from the bowl, oil the bowl lightly, and return the ball of dough to the bowl. Cover and set aside to rest for 15-30 minutes.\r\nDivide the ball of dough into 12 portions, in roughly even lumps.\r\nHeat a small amount of oil in a large, flat skillet. Flatten a ball of dough with your palm and work it into a slightly larger round with the back of your hand, leaving it a thick round about 10cm (4\") in diameter. Place in the hot skillet. Repeat with as many rounds as will fit in your skillet.\r\nAfter 3-4 minutes, once the bottom is slightly browned in spots, flip and cook for another 1-2 minutes on the second side.", "equipment_tags": [], "portions": 8, "prep_minutes": 36, "prep_minutes_source": "explicit", "kcal": 251, "protein_g": 7.2, "carbs_g": 50.5, "fat_g": 1.6, "total_kcal": 2007, "total_protein_g": 57.7, "total_carbs_g": 404.2, "total_fat_g": 12.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53472", "name": "Madombi: Dumplings from Botswana", "category": "Miscellaneous", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/bjeq6g1782505296.jpg", "local_image": "53472.jpg", "ingredients": [{"ingredient": "Warm Water", "measure": "1 1/4 cup"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Yeast", "measure": "2 1/2 Tsp"}, {"ingredient": "All purpose flour", "measure": "3 Cups"}, {"ingredient": "Salt", "measure": "1 1/2 tsp"}], "instructions": "This recipe requires a stew to steam the dumplings on top of, at abour 180℃ or 350℉, give or take (it doesn't have to be specific, but can't be very high or very love heat). You will add the dumplings in during the last thirty minutes of your stew's cooking time, They need to steam covered, so the stew should be in a lidded pot that is oven-proof.\r\nMix the dumpling dough\r\nIn a measuring cup, combine the warm water, sugar, and yeast. Leave until foamy, about 5 minutes.\r\nTo a stand mixer bowl, or a large bowl if mixing by hand, add the flour and salt. Stream in the water-yeast mixture while kneading.\r\nKnead for several minutes after the dough comes together, until a smooth ball of dough forms.\r\nLeave the dumpling dough to rise\r\nPlace the ball of dough in an oiled dough, cover, and leave to rise until doubled, about 1 hour.\r\nShape the dumplings\r\nDivide the risen ball of dough into 10 equal portions for large dumplings, or 12-14 portions for smaller dumplings.\r\nShape each portion of dough into a smooth, round ball.\r\nSteam the dumplings\r\nIn the last thirty minutes of cooking a stew, place the shaped dumplings right atop the stew. Push them down gently into the stew. Cover tightly and return to the oven for 25-30 minutes. The dumplings are done when they're risen and light golden.", "equipment_tags": [], "portions": 1, "prep_minutes": 95, "prep_minutes_source": "explicit", "kcal": 1463, "protein_g": 43.2, "carbs_g": 303.6, "fat_g": 4.8, "total_kcal": 1463, "total_protein_g": 43.2, "total_carbs_g": 303.6, "total_fat_g": 4.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53473", "name": "Curried Spinach from Botswana", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/lyr07q1782505714.jpg", "local_image": "53473.jpg", "ingredients": [{"ingredient": "Spinach", "measure": "1  bunch"}, {"ingredient": "Tomato", "measure": "2 medium"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Oil", "measure": "2 tablespoons"}, {"ingredient": "Curry Powder", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Water", "measure": "1/4 cup"}], "instructions": "Heat the oil in a skillet over medium heat. When hot, add the diced onion and cook until lightly browned.\r\nAdd the curry powder and salt to taste and toast for a few seconds.\r\nAdd the chopped tomatoes and the water, stir well, and cook until the tomatoes begin to break down, 5-7 minutes.\r\nAdd in the chopped (or baby) spinach and cook for 7-10 minutes more, until soft and wilted.", "equipment_tags": [], "portions": 2, "prep_minutes": 17, "prep_minutes_source": "explicit", "kcal": 182, "protein_g": 2.7, "carbs_g": 12.3, "fat_g": 14.8, "total_kcal": 363, "total_protein_g": 5.3, "total_carbs_g": 24.7, "total_fat_g": 29.6, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53474", "name": "Magwinya: Doughnut Bites from Botswana", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/4ae5tp1782506270.jpg", "local_image": "53474.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "300g"}, {"ingredient": "Warm Water", "measure": "1/4 cup"}, {"ingredient": "Sugar", "measure": "2 tablespoons"}, {"ingredient": "Yeast", "measure": "1 1/2 tsp"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Vegetable Oil", "measure": "1 1/2 tsp"}, {"ingredient": "Ground Sugar", "measure": "1/2 cup"}, {"ingredient": "Vegetable Oil", "measure": "2 cups"}], "instructions": "Mix the dough\r\nIn a stand mixer bowl. add the water, sugar, and yeast. Leave to get foamy, about 5 minutes.\r\nAdd in the flour, salt, and vegetable oil.\r\nKnead with a dough hook until a smooth dough forms, about 5 minutes.\r\nLeave the dough to rise\r\nRemove the dough from the mixer bowl and form into a ball. Lightly mist the bowl with oil and replace the ball of dough into it. Cover the bowl and let rise in a warm place, 1 to 1½ hours, until doubled.\r\nShape and fry the doughnuts\r\nPreheat about 5cm (2\") of vegetable oil in a pot to 180℃ / 350℉ – you can use a smaller pot needing less oil to fill but cooking less doughnuts at a time, or a larger one and cook more each batch. I also like to set up a drying rack set over a paper-towel-lined sheet pan to drain the doughnuts on, so they stay crispy. You can also prep a plate with paper towels if you don't want to bother.\r\nWhen the oil is at temperature, use a cookie scoop or two regular tablespoons to form a piece of dough into a rough ball shape and place in the oil. Repeat for as many doughnuts as will fit in your pot without overcrowding.\r\nFry each doughnut for about a minute on each side, turning halfway through. Drain on prepared rack or paper towels.\r\nWhen the doughnuts have cooled slightly, sprinkle with powdered sugar.", "equipment_tags": [], "portions": 4, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 496, "protein_g": 8.2, "carbs_g": 89.6, "fat_g": 11.4, "total_kcal": 1983, "total_protein_g": 33.0, "total_carbs_g": 358.6, "total_fat_g": 45.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53475", "name": "Brazilian chocolate truffles - brigadeiro", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/dg7tad1782588053.jpg", "local_image": "53475.jpg", "ingredients": [{"ingredient": "Unsalted Butter", "measure": "3  tablespoons"}, {"ingredient": "Condensed Milk", "measure": "400g"}, {"ingredient": "Cocoa Powder", "measure": "4 tablespoons"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Pistachio", "measure": "50g"}, {"ingredient": "Almonds", "measure": "50g"}, {"ingredient": "Desiccated Coconut", "measure": "50g"}], "instructions": "step 1\r\nIn a medium heavy-based saucepan, heat the butter, condensed milk, a pinch of salt and the cocoa, to boiling, stirring constantly with a wooden spoon. Reduce the heat to medium-low; cook for 10-15 mins, stirring constantly, until the mixture is thick and shiny and starts to pull away from the bottom.\r\n\r\nstep 2\r\nStir in the vanilla and vigorously mix again. Pour the mixture onto a buttered plate. Chill for at least 2 hrs.\r\n\r\nstep 3\r\nButter your hands and pinch off some of the dough to make 2.5cm balls. Place your toppings into small bowls and roll the balls of one of the decorations. Place in mini paper baking cups or on a tray lined with non-stick baking paper", "equipment_tags": [], "portions": 4, "prep_minutes": 135, "prep_minutes_source": "explicit", "kcal": 401, "protein_g": 12.3, "carbs_g": 22.9, "fat_g": 34.1, "total_kcal": 1604, "total_protein_g": 49.1, "total_carbs_g": 91.7, "total_fat_g": 136.6, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53476", "name": "Brazilian cheese bread (pão de queijo)", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/sl7cr91782588539.jpg", "local_image": "53476.jpg", "ingredients": [{"ingredient": "Oil", "measure": "Drizzle"}, {"ingredient": "Whole Milk", "measure": "250ml"}, {"ingredient": "Unsalted Butter", "measure": "125g"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Tapioca", "measure": "300g"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Parmesan", "measure": "100g"}], "instructions": "step 1\r\nHeat the oven to 220C/200C fan/gas 7. Oil or butter a baking sheet and set aside.\r\n\r\nstep 2\r\nHeat the milk, butter and salt in a medium saucepan and bring to a boil. Remove from the heat and add the tapioca flour. Stir vigorously, then leave to cool a little.\r\n\r\nstep 3\r\nPour the dough into a standing mix to beat the dough until its cool, or use a wooden spoon and beat by hand. Beat the eggs in one at a time, waiting until each is completely incorporated before adding the next. When the dough is glossy and mixed, add the parmesan. Beat again until mixed.\r\n\r\nstep 4\r\nSpoon the dough onto the baking sheet in 1 tbsp balls, 5cm apart. Bake for 30 mins until crisp and golden. Remove from the oven and eat while still warm.", "equipment_tags": [], "portions": 9, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 329, "protein_g": 6.7, "carbs_g": 31.5, "fat_g": 19.8, "total_kcal": 2962, "total_protein_g": 60.7, "total_carbs_g": 283.4, "total_fat_g": 178.6, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53477", "name": "Coconut quindim", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/46uazv1782588877.jpg", "local_image": "53477.jpg", "ingredients": [{"ingredient": "Butter", "measure": "2 tablespoons"}, {"ingredient": "Egg Yolks", "measure": "10"}, {"ingredient": "Caster Sugar", "measure": "100g"}, {"ingredient": "Coconut Milk", "measure": "300ml"}, {"ingredient": "Desiccated Coconut", "measure": "50g"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}], "instructions": "step 1\r\nHeat oven to 180C/160C fan/gas 4. Rub 4 ramekins, about 175ml capacity, or dariole moulds liberally with the soft butter. Sprinkle with the caster sugar to coat.\r\n\r\nstep 2\r\nIn a medium bowl, press the egg yolks through a wire sieve and mix with the coconut milk, sugar, coconut and vanilla. Pour into ramekins and place in a large roasting tin in the oven.\r\n\r\nstep 3\r\nPour water into the roasting tin to three-quarters up the ramekins so it acts like a bain marie or water bath for the quindim. Bake for 30-35 mins until the tops are golden. Take the ramekins out of the water and leave to cool for 5 mins.\r\n\r\nstep 4\r\nChill for 4 hrs and then run a knife around the edge. Place a plate on top and turn out the quindims to serve.", "equipment_tags": [], "portions": 7, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 463, "protein_g": 12.9, "carbs_g": 21.0, "fat_g": 37.5, "total_kcal": 3238, "total_protein_g": 90.6, "total_carbs_g": 147.2, "total_fat_g": 262.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53478", "name": "Grilled corn with garlic mayo & grated cheese", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/k1if4d1782589892.jpg", "local_image": "53478.jpg", "ingredients": [{"ingredient": "Corn On The Cob", "measure": "6"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Mayonnaise", "measure": "6 tablespoons"}, {"ingredient": "Parmesan", "measure": "4 tablespoons"}, {"ingredient": "Coriander", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "1"}], "instructions": "step 1\r\nBoil the corn cobs for 5 mins. Leave in the water until you’re ready to grill them. Mix the garlic and mayonnaise in a small bowl. Just before barbecuing, remove the cobs from the pan, pat dry and rub the mayonnaise into each one.\r\n\r\nstep 2\r\nSeason the cobs and grill them until marks appear, about 5 mins. Remove and scatter over the Parmesan and coriander. Squeeze lime over to serve.", "equipment_tags": ["Grill"], "portions": 1, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 1165, "protein_g": 35.1, "carbs_g": 71.6, "fat_g": 89.4, "total_kcal": 1165, "total_protein_g": 35.1, "total_carbs_g": 71.6, "total_fat_g": 89.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53479", "name": "Smoky tomato pepper salsa", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/hkz4k71782590338.jpg", "local_image": "53479.jpg", "ingredients": [{"ingredient": "Red Onions", "measure": "1 small"}, {"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Cherry Tomatoes", "measure": "125g"}, {"ingredient": "Red Pepper", "measure": "1/2"}, {"ingredient": "Extra Virgin Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Red Wine Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Paprika", "measure": "1 1/2 tsp"}, {"ingredient": "Sugar", "measure": "Pinch"}], "instructions": "step 1\r\nPut all the ingredients in a food processor and pulse until chopped, but not too fine. Pour into a serving bowl and add seasoning and a pinch of sugar.\r\n\r\n", "equipment_tags": ["FoodProcessor"], "portions": 9, "prep_minutes": 19, "prep_minutes_source": "estimated", "kcal": 52, "protein_g": 0.4, "carbs_g": 2.3, "fat_g": 4.8, "total_kcal": 468, "total_protein_g": 4.0, "total_carbs_g": 20.9, "total_fat_g": 42.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53480", "name": "Creamy Aji green sauce", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/81j8iu1782590903.jpg", "local_image": "53480.jpg", "ingredients": [{"ingredient": "Coriander", "measure": "Bunch"}, {"ingredient": "Jalapeno", "measure": "2"}, {"ingredient": "Spring Onions", "measure": "2"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "White Wine Vinegar", "measure": "1 tablespoon"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Cumin", "measure": "Pinch"}, {"ingredient": "Mayonnaise", "measure": "4 tablespoons"}], "instructions": "step 1\r\nPut all the ingredients in a blender or food processor and mix into a sauce. Add seasoning, then pour into a serving bowl.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 8, "prep_minutes": 19, "prep_minutes_source": "estimated", "kcal": 67, "protein_g": 0.8, "carbs_g": 3.6, "fat_g": 5.8, "total_kcal": 532, "total_protein_g": 6.6, "total_carbs_g": 29.1, "total_fat_g": 46.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53481", "name": "Bahia-style Moqueca prawn stew", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/e2kcut1782591669.jpg", "local_image": "53481.jpg", "ingredients": [{"ingredient": "Raw King Prawns", "measure": "450g"}, {"ingredient": "Lime juice", "measure": "75 ml"}, {"ingredient": "Garlic", "measure": "3 cloves Chopped"}, {"ingredient": "Coconut Oil", "measure": "3  tablespoons"}, {"ingredient": "Spring Onions", "measure": "4 Chopped"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Red Pepper", "measure": "1 chopped"}, {"ingredient": "Chilli Flakes", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "2 tsp"}, {"ingredient": "Plum Tomatoes", "measure": "3 chopped"}, {"ingredient": "Coconut Milk", "measure": "400ml"}, {"ingredient": "Coriander", "measure": "2 tbs chopped"}, {"ingredient": "Rice", "measure": "To serve"}], "instructions": "step 1\r\nPlace the prawns in a bowl with 2 tbsp of the lime juice, 1 tsp of salt and 1 tbsp of the chopped garlic. Chill for 1 hr.\r\n\r\nstep 2\r\nHeat the coconut oil in a large saucepan. Add the spring onion and onion and fry for 5 mins, then add the red pepper, chilli flakes, paprika and remaining garlic.\r\n\r\nstep 3\r\nPour in the tomatoes, coconut milk and a little salt. Bring to a simmer and let reduce for 10 mins. Add the prawns, all the marinade and remaining lime juice. Gently simmer until the prawns turn white, about 3 mins. Serve with the fresh coriander and rice.", "equipment_tags": [], "portions": 4, "prep_minutes": 78, "prep_minutes_source": "explicit", "kcal": 520, "protein_g": 29.1, "carbs_g": 29.8, "fat_g": 35.7, "total_kcal": 2081, "total_protein_g": 116.4, "total_carbs_g": 119.2, "total_fat_g": 142.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53482", "name": "Black bean & meat stew - feijoada", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/xrxz7h1782592711.jpg", "local_image": "53482.jpg", "ingredients": [{"ingredient": "Black Beans", "measure": "250g"}, {"ingredient": "Bacon", "measure": "100g"}, {"ingredient": "Pork Back Ribs", "measure": "500g"}, {"ingredient": "Chorizo", "measure": "3"}, {"ingredient": "Pork Shoulder", "measure": "500g"}, {"ingredient": "Onion", "measure": "3 chopped"}, {"ingredient": "Garlic", "measure": "4 Cloves Chopped"}, {"ingredient": "Chilli Flakes", "measure": "Pinch"}, {"ingredient": "Oil", "measure": "Drizzle"}, {"ingredient": "Bay Leaf", "measure": "2"}], "instructions": "step 1\r\nHeat a large heavy-based saucepan with a fitted lid, add the bacon and fry until crisp. Remove and keep the oil in the pan. In batches sear the ribs, sausages and pork shoulder. Season each batch with salt and pepper.\r\n\r\nstep 2\r\nRemove the meat and set aside. Add the onion, garlic and chilli to the pan. Pour in a little olive oil if it needs more. Season with salt and pepper and fry for 8 mins or until soft.\r\n\r\nstep 3\r\nAdd the meat, bay leaves, white wine vinegar and drained beans. Cover with just enough water to cover, about 650ml. Bring to a boil and reduce the heat to a low simmer. Cover and cook for 2 hrs, or until the beans are soft and the meat is tender. If there is too much liquid in the pot take the lid off in the last hr. You can also use a slow cooker on the short method (4 hr) or make a quick version using a pressure cooker in batches for 30 mins each. Another method is to cook it in the oven for 3-4 hrs at 160C/140C fan/gas 3.\r\n\r\nstep 4\r\nServe with rice, a sprinkle of parsley or coriander, hot pepper sauce and orange slices.", "equipment_tags": ["SlowCooker"], "portions": 4, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 893, "protein_g": 74.9, "carbs_g": 24.7, "fat_g": 52.7, "total_kcal": 3571, "total_protein_g": 299.7, "total_carbs_g": 98.6, "total_fat_g": 210.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53483", "name": "Acaraje black-eyed pea fritters with shrimp filling", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/dxs5t71782678369.jpg", "local_image": "53483.jpg", "ingredients": [{"ingredient": "Black Eyed Peas", "measure": "800g"}, {"ingredient": "Garlic", "measure": "1 clove"}, {"ingredient": "Green Chilli", "measure": "1"}, {"ingredient": "Red Onions", "measure": "1 small finely diced"}, {"ingredient": "Plain Flour", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Chilli Powder", "measure": "1 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Red Onions", "measure": "1 sliced"}, {"ingredient": "Ginger", "measure": "1 tablespoon chopped"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Red Chilli", "measure": "1 chopped"}, {"ingredient": "Raw tiger prawns", "measure": "150g"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Plum Tomatoes", "measure": "2"}, {"ingredient": "Coriander", "measure": "1 tablespoon chopped"}, {"ingredient": "Lime", "measure": "Juice of 1"}], "instructions": "step 1\r\nMake the filling by placing the onion, ginger, garlic, chilli, and some salt into food processor. Purée until smooth. Heat the oil in a frying pan and pour the purée into it. Fry for 5 mins or until cooked through. Add the prawns, tomatoes and chopped coriander. Squeeze in the lime and add salt to taste. Cook for 3 mins, or until the prawns have cooked through. Remove from the heat.\r\n\r\nstep 2\r\nDrain and rinse the black-eyed peas. Pour into a food processor with the garlic and chili. Purée until smooth. Scrape into a bowl and add the onion, flour, salt, chilli powder and baking powder. Mix and roll into 16 balls.\r\n\r\nstep 3\r\nHeat the oven to 190C/170C fan/gas 5. Heat 8cm of the palm or vegetable oil in a wok or small heavy pan. When a small piece of bread sizzles, drop 4-5 balls into the oil. Fry until golden and crisp, about 4-5 mins. Drain on kitchen paper and repeat until they are all finished. You can keep them warm in the oven while you finish. Slice the fritters open down the centre and spoon the prawn filling in. Serve with hot sauce.", "equipment_tags": ["FoodProcessor"], "portions": 3, "prep_minutes": 13, "prep_minutes_source": "explicit", "kcal": 480, "protein_g": 27.6, "carbs_g": 58.4, "fat_g": 16.6, "total_kcal": 1439, "total_protein_g": 82.9, "total_carbs_g": 175.1, "total_fat_g": 49.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53484", "name": "Simple heart of palm & tomato salad", "category": "Starter", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/7whfgi1782678933.jpg", "local_image": "53484.jpg", "ingredients": [{"ingredient": "Palm Hearts", "measure": "400g"}, {"ingredient": "Cherry Tomatoes", "measure": "250g"}, {"ingredient": "Spring Onions", "measure": "2 sliced"}, {"ingredient": "Sherry vinegar", "measure": "1 tablespoon"}, {"ingredient": "Olive Oil", "measure": "3  tablespoons"}, {"ingredient": "Parsley", "measure": "Handful"}], "instructions": "step 1\r\nMix together the hearts of palm, tomatoes and spring onions. Whisk together the sherry vinegar and olive oil. Drizzle over the salad. Sprinkle with the parsley, toss everything together and serve.", "equipment_tags": [], "portions": 7, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 156, "protein_g": 3.9, "carbs_g": 12.5, "fat_g": 10.7, "total_kcal": 1095, "total_protein_g": 27.1, "total_carbs_g": 87.8, "total_fat_g": 74.6, "macro_confidence": 0.83, "is_new": false, "video": null}, {"id": "53485", "name": "Brazilian carrot cake", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/h68o161782679437.jpg", "local_image": "53485.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "250ml"}, {"ingredient": "Plain Flour", "measure": "260g"}, {"ingredient": "Caster Sugar", "measure": "400g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Carrots", "measure": "2 medium"}, {"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Milk", "measure": "250ml"}, {"ingredient": "Cocoa Powder", "measure": "30g"}, {"ingredient": "Caster Sugar", "measure": "60g"}], "instructions": "step 1\r\nHeat the oven to 180C/160C fan/ gas 4. Oil and line the base of a 20cm springform cake tin. Mix the flour, sugar and baking powder together in a large bowl and set aside. Tip the oil, carrots and eggs in a blender and blitz until smooth. Pour the wet ingredients into the dry, stirring until smooth.\r\n\r\nstep 2\r\nPour the batter into the cake tin and give it a shake to get rid of air bubbles. Bake for 45 mins to 1 hr, until a clean knife or skewer inserted into the middle comes out clean. If the middle is sticky, put back in the oven for a further 5 mins. Remove from the oven and leave to cool in the tin.\r\n\r\nstep 3\r\nFor the drizzle, heat the milk, cocoa and sugar in a saucepan over a low heat. Stir until the sugar dissolves (about 5 mins), creating a thick, shiny drizzle.\r\n\r\nstep 4\r\nRemove the cake from the tin and level the top using a serrated knife, then flip so the bottom becomes the top. Pierce all over using a knife or toothpick and put on a wire rack with a tray or large bowl underneath. Pour the drizzle over the cake in batches until it’s all absorbed. You can reuse any drizzle caught in the tray or bowl. Most of the drizzle should be absorbed.", "equipment_tags": ["Blender"], "portions": 8, "prep_minutes": 115, "prep_minutes_source": "explicit", "kcal": 413, "protein_g": 6.8, "carbs_g": 87.7, "fat_g": 5.5, "total_kcal": 3305, "total_protein_g": 54.1, "total_carbs_g": 701.5, "total_fat_g": 43.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53486", "name": "Easy White Bean Soup", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/p5nzbk1782680889.jpg", "local_image": "53486.jpg", "ingredients": [{"ingredient": "Cannellini Beans", "measure": "1 lb"}, {"ingredient": "Onions", "measure": "2 medium"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Red Pepper", "measure": "2 medium"}, {"ingredient": "Tomato Puree", "measure": "1/3 cup"}, {"ingredient": "Carrots", "measure": "2 medium"}, {"ingredient": "Water", "measure": "6 cups"}, {"ingredient": "Dried Mint", "measure": "1 tsp"}, {"ingredient": "Thyme", "measure": "1/2 tsp"}, {"ingredient": "Summer Savoury", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "Place beans in a large pot and cover with cold water. Soak for at least 4 hours or overnight. Drain and rinse, before you use in the soup.\r\nChop one of the onions and leave the other one whole. Chop carrots.\r\nHeat oil on a large pot over medium heat. Add the onion and carrots. Cook for 2 minutes. Add beans, water, peppers, head of onion, salt, pepper, summer savory, mint, thyme, Vegeta and tomato puree. Stir, bring to a boil, then reduce to a simmer and cook for 2 hours, or until the beans are tender.\r\nRemove the peppers and whole onion. Mash the onion. Peel peppers and chop. Return to the pot.\r\nAdd more salt and pepper, if needed. Garnish with chopped parsley. Serve.", "equipment_tags": [], "portions": 5, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 213, "protein_g": 9.7, "carbs_g": 32.1, "fat_g": 6.3, "total_kcal": 1065, "total_protein_g": 48.5, "total_carbs_g": 160.7, "total_fat_g": 31.5, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53487", "name": "Oyster Mushroom Soup", "category": "Starter", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/0r7y5n1782681336.jpg", "local_image": "53487.jpg", "ingredients": [{"ingredient": "Oyster Mushrooms", "measure": "1 lb"}, {"ingredient": "Butter", "measure": "4 tablespoons"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Flour", "measure": "2 tablespoons"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Garlic", "measure": "3 cloves"}, {"ingredient": "Red Wine Vinegar", "measure": "1/3 cup"}, {"ingredient": "Red Pepper Flakes", "measure": "Garnish"}], "instructions": "Clean mushrooms – I usually wash them under cold water, dry them and remove the stems.\r\nCut mushrooms into thin strips.\r\nMelt butter in a small pot. Add the mushrooms and cook for 10 minutes, until the mushrooms release liquid.\r\nCombine the flour and water, whisk to remove any lumps and add to the pot. Add the salt and milk.\r\nCook for 10 more minutes.\r\nIn a small bowl or jar combine the garlic and vinegar.\r\nServe the soup with 1-2 tablespoons (or more) of the garlic and vinegar mixture and hot red pepper.", "equipment_tags": [], "portions": 7, "prep_minutes": 10, "prep_minutes_source": "explicit", "kcal": 106, "protein_g": 3.5, "carbs_g": 6.0, "fat_g": 8.0, "total_kcal": 745, "total_protein_g": 24.4, "total_carbs_g": 42.0, "total_fat_g": 56.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53488", "name": "Cabbage with Ground Beef", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/brmxra1782681940.jpg", "local_image": "53488.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "2 tablespoons"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Onion", "measure": "1 small"}, {"ingredient": "Carrots", "measure": "2 medium"}, {"ingredient": "Red Pepper", "measure": "1 medium"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Garlic", "measure": "2 cloves"}, {"ingredient": "Salt", "measure": "1/2 tbs"}, {"ingredient": "Black Pepper", "measure": "1/2 tbs"}, {"ingredient": "Smoked Paprika", "measure": "1 tsp"}, {"ingredient": "Ground Cumin", "measure": "1/4 tsp"}, {"ingredient": "Cabbage", "measure": "1/2"}, {"ingredient": "Apple Cider Vinegar", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}], "instructions": "Heat a large skillet or braiser over medium heat on the stovetop. Add the olive oil.\r\nA braiser with cooked ground beef \r\nCook the Meat:\r\nAdd the ground meat to the pan. Use a potato masher or wooden spoon to break it into small pieces. Cook for 3–4 minutes until browned.\r\nAdd Vegetables and Seasoning:\r\nStir in the onion, carrots, red pepper, garlic, and tomato paste. Season with salt, black pepper, smoked paprika, ground cumin, and Italian seasoning (if using). Cook for 2–3 minutes, stirring frequently.\r\nA braiser with cooked ground beef, carrots, onions, peppers, garlic and seasoning. \r\n\r\nAdd Cabbage and Liquid:\r\nAdd the chopped cabbage, apple cider vinegar or lemon juice (if using), and water. Stir well to combine. Reduce the heat to medium-low, cover, and cook for 30 minutes. Stir occasionally to prevent the cabbage from sticking to the bottom of the pan.\r\nA pot with cooked ground beef, vegetables and cabbage on a stove top \r\nCheck for Doneness:\r\nUncover and check the texture of the cabbage. If necessary, increase the heat to medium-high and cook for an additional 5–7 minutes to evaporate excess liquid and finish cooking.\r\nA braiser with cooked ground meat and cabbage dish on a stove top \r\nGarnish and Serve:\r\nSprinkle with chopped parsley or fresh herbs before serving.", "equipment_tags": [], "portions": 2, "prep_minutes": 44, "prep_minutes_source": "explicit", "kcal": 783, "protein_g": 41.7, "carbs_g": 19.3, "fat_g": 60.1, "total_kcal": 1566, "total_protein_g": 83.3, "total_carbs_g": 38.5, "total_fat_g": 120.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53489", "name": "Potato Moussaka Recipe", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/08ez421782683409.jpg", "local_image": "53489.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Onion", "measure": "1/3 cup"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Tomato Sauce", "measure": "1/4 cup"}, {"ingredient": "Tomato Puree", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Summer Savoury", "measure": "1 tsp"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Potatoes", "measure": "2 Lbs"}, {"ingredient": "Carrots", "measure": "1/4 cup"}, {"ingredient": "Milk", "measure": "2 cups"}, {"ingredient": "Dried Mint", "measure": "1/2 tsp"}, {"ingredient": "Butter", "measure": "6 tablespoons"}, {"ingredient": "Flour", "measure": "1/2 cup"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Egg Yolks", "measure": "3"}, {"ingredient": "Feta", "measure": "1/2 cup"}, {"ingredient": "Ground Nutmeg", "measure": "1/4 tsp"}], "instructions": "Preheat oven to 350 F.\r\nHeat oil in a skillet. Add the ground meat and cook, breaking it down with a wooden spoon for 6-7 minutes, until browned. Add onion and garlic. Add carrots (optional).Add salt, black pepper, dried mint, summer savory, thyme (optional), tomato sauce and tomato paste. Cook for 2-3 minutes, stirring frequently.\r\n\r\n\r\nGrease a 9×9 or 9×13 baking dish with oil.\r\nAdd in the drained potatoes and meat mixture. Stir to evenly distribute the meat into the potatoes.\r\nAdd cold water to the baking dish, so it just covers the top of the potatoes.\r\nBake for 40-50 minutes, until the water is absorbed by the potatoes and they are fully cooked.\r\nIn the mean time prepare the Bechamel sauce (or the Bulgarian Style Topping).\r\nFor the Bechamel:\r\nIn a bowl, swish egg yolks. Set aside.\r\nMelt butter in a saucepan. add flour. Cook for 3 minutes on medium heat, stirring frequently.\r\nSlowly add the milk, whisking to incorporate. Add salt and nutmeg. Cook for 3 minutes, until thickened. Let the mixture cool for 5 minutes. Add in the egg yolks (with feta). Let the sauce stand at room temperature, while the potatoes and meat are cooking.\r\nPour the sauce over the cooked potatoes. Top with cheese. Bake for 15 minutes, until golden. You can broil for 1-2 minutes, if the top is not getting to the desired golden color.\r\nFor the Bulgarian Moussaka topping:\r\nIn a bowl beat together eggs, yogurt, milk, flour, then add salt and baking soda.\r\n\r\n\r\nPour over the moussaka . Top with cheese. Bake for 10-15 minutes, until golden.", "equipment_tags": [], "portions": 6, "prep_minutes": 103, "prep_minutes_source": "explicit", "kcal": 673, "protein_g": 27.1, "carbs_g": 43.9, "fat_g": 43.1, "total_kcal": 4037, "total_protein_g": 162.6, "total_carbs_g": 263.5, "total_fat_g": 258.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53490", "name": "Cottage Cheese And Feta Stuffed Peppers", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/w0rsga1782683912.jpg", "local_image": "53490.jpg", "ingredients": [{"ingredient": "Red Pepper", "measure": "4"}, {"ingredient": "Feta", "measure": "100g"}, {"ingredient": "Cottage Cheese", "measure": "200g"}, {"ingredient": "Chives", "measure": "1 tablespoon chopped"}, {"ingredient": "Parsley", "measure": "1 tablespoon chopped"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Lemon Juice", "measure": "1 tablespoon"}], "instructions": "Cut the peppers lengthwise and remove the seeds.\r\nIn a bowl combine 3.5 oz (100 grams) Feta cheese, 7 oz (200 grams) cottage cheese, 1 tbsp chopped chives (optional), 1 tbsp chopped parsley (optional), 1/4 tsp salt (more or less to taste) and 1 tbsp lemon juice.\r\nFill the peppers with the mixture. Top with chopped chives and parsley.\r\nServe.", "equipment_tags": [], "portions": 1, "prep_minutes": 28, "prep_minutes_source": "estimated", "kcal": 978, "protein_g": 63.0, "carbs_g": 10.8, "fat_g": 77.3, "total_kcal": 978, "total_protein_g": 63.0, "total_carbs_g": 10.8, "total_fat_g": 77.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53491", "name": "Shopska Salad", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/bqx8mc1782684286.jpg", "local_image": "53491.jpg", "ingredients": [{"ingredient": "Cucumber", "measure": "1 sliced"}, {"ingredient": "Tomatoes", "measure": "3 Cups"}, {"ingredient": "Red Onions", "measure": "1/4"}, {"ingredient": "Green Pepper", "measure": "1 chopped"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Olive Oil", "measure": "1/4 cup"}, {"ingredient": "Feta", "measure": "1/3 cup"}, {"ingredient": "Parsley", "measure": "2 tbs chopped"}], "instructions": "Combine vegetables in a bowl and sprinkle salt on top. Let it stand for 5 minutes. Add the oil. Top with feta and parsley. Serve.", "equipment_tags": [], "portions": 7, "prep_minutes": 5, "prep_minutes_source": "explicit", "kcal": 123, "protein_g": 2.7, "carbs_g": 5.4, "fat_g": 10.5, "total_kcal": 858, "total_protein_g": 19.2, "total_carbs_g": 37.7, "total_fat_g": 73.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53492", "name": "Bulgarian Green Salad", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/6awyvm1782685205.jpg", "local_image": "53492.jpg", "ingredients": [{"ingredient": "Lettuce", "measure": "1/2"}, {"ingredient": "Radish", "measure": "7"}, {"ingredient": "Cucumber", "measure": "1 sliced"}, {"ingredient": "Scallions", "measure": "4 Chopped"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Apple Cider Vinegar", "measure": "2 tablespoons"}, {"ingredient": "Olive Oil", "measure": "1/8 cup"}, {"ingredient": "Dill", "measure": "Garnish"}, {"ingredient": "Parsley", "measure": "Garnish"}], "instructions": "Place sliced lettuce in a large bowl.\r\nAdd radishes, cucumber, and scallions.\r\nDrizzle with vinegar and olive oil.\r\nSeason with salt and gently toss to combine.\r\nTop with sliced hard-boiled eggs, olives, dill and (or) parsley if using and serve immediately.", "equipment_tags": [], "portions": 6, "prep_minutes": 25, "prep_minutes_source": "estimated", "kcal": 67, "protein_g": 1.4, "carbs_g": 5.5, "fat_g": 4.8, "total_kcal": 404, "total_protein_g": 8.7, "total_carbs_g": 33.1, "total_fat_g": 29.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53493", "name": "Bulgarian Honey Cookies", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/y75q5j1782685779.jpg", "local_image": "53493.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "2 large"}, {"ingredient": "Powdered Sugar", "measure": "1 cup"}, {"ingredient": "Honey", "measure": "1/4 cup"}, {"ingredient": "Vanilla Extract", "measure": "1 tsp"}, {"ingredient": "Vegetable Oil", "measure": "3 Cups"}, {"ingredient": "All purpose flour", "measure": "4 cups"}, {"ingredient": "Salt", "measure": "1/4 tsp"}, {"ingredient": "Ground Cinnamon", "measure": "1 tsp"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Chocolate Chips", "measure": "2 cups"}, {"ingredient": "Vegetable Oil", "measure": "2 tsp"}], "instructions": "Preheat oven to 350 F. Line 2-3 baking sheets with parchment paper. \r\nIn a bowl, combine flour, salt, cinnamon and baking soda.\r\nIn the bowl of a stand mixer, fitted with the paddle attachment, beat together eggs and powdered sugar for3 minutes. Add vanilla extract and honey. Mix to combine, then add oil.\r\nAdd the flour mixture in two increments and beat to incorporate. Let the dough rest for 5-10 minutes.\r\nShape 2 tbsp balls, place on baking sheets and press flat. Bake for 12-15 minutes, until golden. Let the cookies cool down completely.\r\nMelt white and semi-sweet chocolate separately with 1 tbsp vegetable oil each.\r\nDip cookies halfway into chocolate. Let it set. Keep in a air tight container or wrapped in cellophane bags for up to 2 weeks in room temperature or refrigerated.", "equipment_tags": [], "portions": 10, "prep_minutes": 28, "prep_minutes_source": "explicit", "kcal": 593, "protein_g": 8.6, "carbs_g": 95.6, "fat_g": 20.7, "total_kcal": 5927, "total_protein_g": 85.9, "total_carbs_g": 955.7, "total_fat_g": 206.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53494", "name": "Keto Banitsa", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/8wynv41782686271.jpg", "local_image": "53494.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Melted Butter", "measure": "80g"}, {"ingredient": "Mozzarella", "measure": "120g"}, {"ingredient": "Cream Cheese", "measure": "30g"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Feta", "measure": "60g"}, {"ingredient": "Sesame Seed", "measure": "Topping"}], "instructions": "Preheat oven to 360 F (180 C)\r\nBeat eggs in a bowl, using a whisk ( no mixer needed).\r\nSlowly add the melted butter, whisking to incorporate.\r\nAdd the cheeses (mozzarella, feta and cream cheese), stir to combine. Then add the baking powder and whisk.\r\nGrease a 8×8 -inch square baking dish with butter and pour the mixture inside. Top with sesame seeds (optional).\r\nBake for 20 minutes, until golden.\r\nLet it cool for 5-10 minutes inside the pan, then cut into pieces and serve.\r\nKeep in the fridge for up to 3 days.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 544, "protein_g": 25.3, "carbs_g": 6.0, "fat_g": 47.7, "total_kcal": 1631, "total_protein_g": 75.9, "total_carbs_g": 18.0, "total_fat_g": 143.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53495", "name": "Amok Trey – Cambodian Fish Curry", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/diuub11782687570.jpg", "local_image": "53495.jpg", "ingredients": [{"ingredient": "Fish fillet", "measure": "1 lb"}, {"ingredient": "Coconut Milk", "measure": "1 Can"}, {"ingredient": "Red Curry Paste", "measure": "2 tablespoons"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Brown Sugar", "measure": "1 tsp"}, {"ingredient": "Chicken Stock", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Kaffir Lime Leaves", "measure": "2"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Banana Leaves", "measure": "Handful"}, {"ingredient": "Cilantro", "measure": "Garnish"}, {"ingredient": "Lime", "measure": "Garnish"}], "instructions": "1. In a medium bowl, combine the coconut milk, red curry paste, fish sauce, palm sugar, and broth, whisking until smooth—this ensures no lumps in the sauce.\r\n2. Heat the vegetable oil in a large skillet over medium heat (about 350°F) for 30 seconds until shimmering.\r\n3. Pour the coconut milk mixture into the skillet and bring it to a gentle simmer, stirring occasionally, which should take about 3-4 minutes.\r\n4. Add the fish cubes and kaffir lime leaves to the skillet, submerging them fully in the sauce.\r\n5. Reduce the heat to low, cover the skillet, and let it cook for 10 minutes until the fish is opaque and flakes easily with a fork—avoid overcooking to keep it tender.\r\n6. Stir in the beaten egg slowly, cooking for 2 more minutes until the sauce thickens slightly, which adds a rich, custard-like texture.\r\n7. While the curry simmers, prepare the banana leaves by briefly passing them over a gas flame for 10 seconds to make them pliable, or use parchment paper as a handy alternative.\r\n8. Spoon the curry into the center of each banana leaf square, folding the edges to form a tight packet to trap steam.\r\n9. Place the packets in a steamer basket over boiling water and steam for 10 minutes until heated through and fragrant.\r\n10. Carefully unwrap the packets and garnish with fresh cilantro and lime wedges before serving", "equipment_tags": [], "portions": 3, "prep_minutes": 24, "prep_minutes_source": "explicit", "kcal": 551, "protein_g": 35.3, "carbs_g": 14.9, "fat_g": 41.1, "total_kcal": 1654, "total_protein_g": 105.9, "total_carbs_g": 44.8, "total_fat_g": 123.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53496", "name": "Bai Sach Chrouk – Grilled Pork with Rice", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/f0cdwk1782688162.jpg", "local_image": "53496.jpg", "ingredients": [{"ingredient": "Pork Shoulder", "measure": "650g"}, {"ingredient": "Coconut Milk", "measure": "1/4 cup"}, {"ingredient": "Soy Sauce", "measure": "3  tablespoons"}, {"ingredient": "Oyster Sauce", "measure": "2 tablespoons"}, {"ingredient": "Honey", "measure": "2 tablespoons"}, {"ingredient": "Garlic", "measure": "4 cloves"}, {"ingredient": "Black Pepper", "measure": "1 tsp"}, {"ingredient": "Jasmine Rice", "measure": "2 cups"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Cucumber", "measure": "1 sliced"}, {"ingredient": "Cilantro Leaves", "measure": "Garnish"}], "instructions": "1. In a large bowl, combine the coconut milk, soy sauce, oyster sauce, honey, minced garlic, and black pepper to make the marinade.\r\n2. Add the thinly sliced pork shoulder to the marinade, ensuring each piece is fully coated, then cover and refrigerate for at least 30 minutes to allow the flavors to penetrate.\r\n3. While the pork marinates, rinse the jasmine rice under cold water until the water runs clear to remove excess starch, which helps prevent clumping.\r\n4. In a medium pot, combine the rinsed rice and 4 cups of water, bring to a boil over high heat, then reduce to a simmer, cover, and cook for 15 minutes until the water is absorbed and the rice is tender.\r\n5. Heat a grill pan or outdoor grill to medium-high heat (about 400°F) and lightly brush with vegetable oil to prevent sticking.\r\n6. Remove the pork from the marinade, shaking off any excess, and place it on the hot grill, cooking for 3-4 minutes per side until nicely charred and cooked through with an internal temperature of 145°F.\r\n7. Tip: Avoid overcrowding the grill pan to ensure even browning and proper caramelization of the marinade.\r\n8. Once the pork is grilled, let it rest for 5 minutes before slicing to retain its juices and tenderness.\r\n9. Tip: If you prefer a saucier dish, simmer the leftover marinade in a small saucepan for 5 minutes until slightly thickened and drizzle it over the pork.\r\n10. Fluff the cooked rice with a fork to separate the grains and serve it warm alongside the grilled pork slices.\r\n11. Arrange the thinly sliced cucumber and fresh cilantro leaves on top as a refreshing garnish.\r\n12. Tip: For an extra kick, serve with a side of pickled vegetables or a squeeze of lime juice to balance the rich, savory flavors.", "equipment_tags": ["Grill"], "portions": 5, "prep_minutes": 59, "prep_minutes_source": "explicit", "kcal": 601, "protein_g": 33.3, "carbs_g": 76.0, "fat_g": 16.8, "total_kcal": 3003, "total_protein_g": 166.7, "total_carbs_g": 380.2, "total_fat_g": 83.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53497", "name": "Nom Banh Chok – Cambodian Noodle Soup", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/6g9gif1782688663.jpg", "local_image": "53497.jpg", "ingredients": [{"ingredient": "Water", "measure": "8 cups"}, {"ingredient": "Chicken Thighs", "measure": "1lb"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Rice Noodles", "measure": "8 oz"}, {"ingredient": "Bean Sprouts", "measure": "2 cups"}, {"ingredient": "Mint", "measure": "1 cup"}, {"ingredient": "Lime", "measure": "1"}, {"ingredient": "Red Chilli", "measure": "1"}], "instructions": "1. Heat the vegetable oil in a large pot over medium heat until it shimmers, about 2 minutes.\r\n2. Add the minced garlic and sauté until fragrant and lightly golden, about 1 minute, stirring constantly to prevent burning.\r\n3. Add the chicken pieces and cook until they turn opaque on all sides, about 5 minutes, stirring occasionally.\r\n4. Pour in the 8 cups of water and bring to a boil over high heat, which should take about 8 minutes.\r\n5. Reduce the heat to low, stir in the fish sauce, salt, and sugar, and simmer uncovered for 20 minutes to develop the flavors.\r\n6. While the broth simmers, cook the rice noodles according to package instructions until al dente, then drain and rinse under cold water to stop the cooking.\r\n7. Divide the cooked noodles evenly among four bowls.\r\n8. Ladle the hot broth and chicken over the noodles in each bowl.\r\n9. Top each bowl with bean sprouts, chopped mint leaves, and optional red chili slices.\r\n10. Serve immediately with lime wedges on the side for squeezing over the soup.", "equipment_tags": [], "portions": 7, "prep_minutes": 36, "prep_minutes_source": "explicit", "kcal": 277, "protein_g": 18.7, "carbs_g": 36.9, "fat_g": 6.8, "total_kcal": 1939, "total_protein_g": 130.8, "total_carbs_g": 258.2, "total_fat_g": 47.4, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53498", "name": "Samlar Kari – Khmer Red Curry", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/k5qzdl1782689660.jpg", "local_image": "53498.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Chicken Thighs", "measure": "1 lb"}, {"ingredient": "Onion", "measure": "1 medium chopped"}, {"ingredient": "Garlic", "measure": "3 Cloves Crushed"}, {"ingredient": "Ginger", "measure": "1 tablespoon"}, {"ingredient": "Red Curry Paste", "measure": "2 tablespoons"}, {"ingredient": "Coconut Milk", "measure": "1 can"}, {"ingredient": "Chicken Stock", "measure": "1 cup"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Bamboo Shoot", "measure": "1 cup"}, {"ingredient": "Red Pepper", "measure": "1 sliced"}, {"ingredient": "Basil", "measure": "Pinch"}, {"ingredient": "Lime", "measure": "To serve"}], "instructions": "1. Heat 1 tbsp vegetable oil in a large pot or Dutch oven over medium-high heat until it shimmers, about 2 minutes.\r\n2. Add 1 lb chicken pieces to the pot and cook until browned on all sides, approximately 5–7 minutes, stirring occasionally to prevent sticking.\r\n3. Remove the chicken from the pot and set it aside on a plate, leaving any oil and juices in the pot.\r\n4. Reduce the heat to medium and add 1 sliced onion to the pot, cooking until softened and translucent, about 4 minutes.\r\n5. Stir in 3 cloves minced garlic and 1 tbsp grated ginger, cooking for 1 minute until fragrant to avoid burning.\r\n6. Add 2 tbsp red curry paste to the pot and cook for 1 minute, stirring constantly to toast the spices and deepen the flavor.\r\n7. Pour in 1 can coconut milk and 1 cup chicken broth, scraping the bottom of the pot to incorporate any browned bits for extra richness.\r\n8. Stir in 1 tbsp fish sauce and 1 tbsp palm sugar until fully dissolved, then return the browned chicken to the pot.\r\n9. Bring the mixture to a gentle boil, then reduce the heat to low, cover, and simmer for 15 minutes to allow the flavors to meld.\r\n10. Add 1 cup bamboo shoots and 1 sliced red bell pepper to the pot, simmering uncovered for an additional 5 minutes until the vegetables are tender-crisp.\r\n11. Remove the pot from the heat and stir in 1 cup Thai basil leaves until just wilted, about 1 minute, to preserve their fresh aroma.\r\n12. Serve the curry hot, garnished with lime wedges for a bright, acidic finish.\r\n\r\n", "equipment_tags": [], "portions": 3, "prep_minutes": 36, "prep_minutes_source": "explicit", "kcal": 605, "protein_g": 37.1, "carbs_g": 23.5, "fat_g": 42.6, "total_kcal": 1815, "total_protein_g": 111.3, "total_carbs_g": 70.6, "total_fat_g": 127.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53499", "name": "Prahok Ktis – Pork and Coconut Dip", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/g80f4t1782690273.jpg", "local_image": "53499.jpg", "ingredients": [{"ingredient": "Ground Pork", "measure": "1 lb"}, {"ingredient": "Coconut Milk", "measure": "1 cup"}, {"ingredient": "Prahok", "measure": "3  tablespoons"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Garlic", "measure": "4 Cloves Crushed"}, {"ingredient": "Shallots", "measure": "2 chopped"}, {"ingredient": "Chilli", "measure": "2"}, {"ingredient": "Brown Sugar", "measure": "1 tablespoon"}, {"ingredient": "Fish Sauce", "measure": "2 tablespoons"}, {"ingredient": "Lime", "measure": "Juice of 1"}, {"ingredient": "Cilantro", "measure": "Garnish"}], "instructions": "1. Heat 2 tbsp vegetable oil in a large skillet over medium-high heat until shimmering, about 1 minute.\r\n2. Add 4 cloves minced garlic and 2 finely chopped shallots to the skillet, stirring constantly until fragrant and lightly golden, 2-3 minutes.\r\n3. Tip: Keep the heat medium to prevent burning—garlic can turn bitter if overcooked.\r\n4. Add 1 lb ground pork to the skillet, breaking it up with a spoon, and cook until no pink remains, 5-7 minutes.\r\n5. Stir in 3 tbsp prahok and cook for 1 minute to blend the flavors, mashing it slightly into the pork.\r\n6. Pour in 1 cup coconut milk, stirring to combine, then reduce heat to medium-low and simmer for 10 minutes until the mixture thickens slightly.\r\n7. Tip: Simmer gently to avoid curdling the coconut milk—a steady bubble is ideal.\r\n8. Add 2 tbsp fish sauce, 1 tbsp palm sugar, and 2 minced Thai chilies, stirring until the sugar dissolves, about 2 minutes.\r\n9. Remove the skillet from heat and stir in 2 tbsp lime juice, mixing thoroughly.\r\n10. Tip: Add lime juice off the heat to preserve its fresh, tangy flavor without cooking it out.\r\n11. Transfer the dip to a serving bowl and garnish with ¼ cup chopped fresh cilantro.\r\n12. Let the dip cool for 5 minutes before serving to allow the flavors to meld.", "equipment_tags": [], "portions": 12, "prep_minutes": 29, "prep_minutes_source": "explicit", "kcal": 149, "protein_g": 8.8, "carbs_g": 5.6, "fat_g": 10.5, "total_kcal": 1794, "total_protein_g": 106.0, "total_carbs_g": 67.7, "total_fat_g": 125.9, "macro_confidence": 0.91, "is_new": false, "video": null}, {"id": "53500", "name": "Num Ansom – Sticky Rice Cake", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/fycrai1782690897.jpg", "local_image": "53500.jpg", "ingredients": [{"ingredient": "Glutinous Rice", "measure": "2 cups"}, {"ingredient": "Coconut Milk", "measure": "1 cup"}, {"ingredient": "Brown Sugar", "measure": "1/2 cup"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Banana Leaves", "measure": "8"}, {"ingredient": "Mung Bean Paste", "measure": "1 cup"}], "instructions": "1. Drain the soaked glutinous rice thoroughly in a fine-mesh strainer.\r\n2. In a medium bowl, combine the coconut milk, palm sugar, and salt, stirring until the sugar dissolves completely.\r\n3. Add the drained rice to the coconut milk mixture, mixing gently to coat every grain evenly. Let it sit for 15 minutes to absorb the liquid.\r\n4. Prepare a steamer by filling the bottom pot with 2 inches of water and bringing it to a boil over high heat.\r\n5. Lay a banana leaf square flat on your work surface, shiny side up. Spoon ¼ cup of the rice mixture into the center, spreading it into a 4-inch rectangle.\r\n6. Place 2 tablespoons of mung bean paste in a line down the middle of the rice rectangle.\r\n7. Fold the banana leaf over the filling lengthwise, then fold in the sides to create a tight parcel. Tip: Press firmly to compact the rice, which helps it hold its shape during steaming.\r\n8. Secure the parcel with kitchen twine, tying it firmly but not too tight to allow for expansion.\r\n9. Repeat steps 5–8 with the remaining ingredients to make 8 parcels total.\r\n10. Arrange the parcels in a single layer in the steamer basket, leaving small gaps between them for steam circulation.\r\n11. Cover the steamer and steam over medium heat for 90 minutes, checking halfway to ensure the water hasn’t boiled dry—add more hot water if needed. Tip: The parcels are done when the banana leaves turn a deep green and the rice feels firm to the touch.\r\n12. Carefully remove the parcels from the steamer and let them cool for 20 minutes before unwrapping. Tip: Cooling sets the texture, making slicing cleaner.\r\n13. Unwrap the banana leaves and slice each parcel into 1-inch thick rounds for serving.", "equipment_tags": [], "portions": 6, "prep_minutes": 125, "prep_minutes_source": "explicit", "kcal": 441, "protein_g": 6.6, "carbs_g": 78.2, "fat_g": 11.7, "total_kcal": 2647, "total_protein_g": 39.3, "total_carbs_g": 468.9, "total_fat_g": 70.1, "macro_confidence": 0.83, "is_new": false, "video": null}, {"id": "53501", "name": "Num Pang – Cambodian Baguette Sandwich", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/o93jur1782769321.jpg", "local_image": "53501.jpg", "ingredients": [{"ingredient": "Baguette", "measure": "4"}, {"ingredient": "Chicken Thighs", "measure": "1 lb"}, {"ingredient": "Soy Sauce", "measure": "1/4 cup"}, {"ingredient": "Honey", "measure": "2 tablespoons"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Carrots", "measure": "1/2 cup"}, {"ingredient": "Daikon Radish", "measure": "1/2 cup"}, {"ingredient": "Rice Vinegar", "measure": "1/4 cup"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Mayonnaise", "measure": "1/4 cup"}, {"ingredient": "Sriracha", "measure": "1 tablespoon"}, {"ingredient": "Cilantro Leaves", "measure": "1/2 cup"}, {"ingredient": "Cucumber", "measure": "1/4 cup"}], "instructions": "1. In a medium bowl, whisk together the soy sauce and honey to create a marinade.\r\n2. Add the chicken thigh strips to the marinade, ensuring each piece is fully coated, and let it sit for 20 minutes at room temperature.\r\n3. While the chicken marinates, combine the julienned carrots, daikon radish, rice vinegar, and granulated sugar in a separate bowl, stirring until the sugar dissolves to pickle the vegetables.\r\n4. In a small bowl, mix the mayonnaise and sriracha sauce thoroughly to make a spicy aioli.\r\n5. Heat the vegetable oil in a large skillet or wok over medium-high heat until it shimmers, about 2 minutes.\r\n6. Add the marinated chicken strips to the hot skillet in a single layer, cooking for 4-5 minutes per side until they reach an internal temperature of 165°F and develop a golden-brown crust.\r\n7. While the chicken cooks, lightly toast the split baguettes in a toaster oven or under a broiler for 2-3 minutes until just crisp on the edges.\r\n8. Spread a generous layer of the spicy aioli on the inside of each toasted baguette.\r\n9. Drain the pickled carrots and daikon radish from their liquid, then layer them onto the bottom half of each baguette.\r\n10. Place the cooked chicken strips evenly over the pickled vegetables in each sandwich.\r\n11. Top the chicken with fresh cilantro leaves and thinly sliced cucumber.\r\n12. Close the sandwiches by pressing the top half of each baguette down gently.", "equipment_tags": [], "portions": 3, "prep_minutes": 30, "prep_minutes_source": "explicit", "kcal": 694, "protein_g": 39.9, "carbs_g": 61.2, "fat_g": 31.5, "total_kcal": 2081, "total_protein_g": 119.7, "total_carbs_g": 183.5, "total_fat_g": 94.6, "macro_confidence": 0.92, "is_new": false, "video": null}, {"id": "53502", "name": "Khmer Banh Xeo – Cambodian Savory Pancake", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/xrv78g1782769859.jpg", "local_image": "53502.jpg", "ingredients": [{"ingredient": "Rice Flour", "measure": "1 cup"}, {"ingredient": "Cornstarch", "measure": "1/4 cup"}, {"ingredient": "Coconut Milk", "measure": "1 1/4 cup"}, {"ingredient": "Water", "measure": "3/4 cup"}, {"ingredient": "Ground Turmeric", "measure": "1/2 tsp"}, {"ingredient": "Pork belly slices", "measure": "1/2 lb"}, {"ingredient": "Bean Sprouts", "measure": "1 cup"}, {"ingredient": "Onion", "measure": "1/2"}, {"ingredient": "Vegetable Oil", "measure": "2 tablespoons"}, {"ingredient": "Fish Sauce", "measure": "Splash"}], "instructions": "Whisk together rice flour, cornstarch, coconut milk, water, and turmeric in a bowl until smooth, then let rest for 15 minutes—this hydrates the flour for better texture.\r\nHeat a 10-inch non-stick skillet over medium-high heat (375°F) and add 1/2 tablespoon of vegetable oil.\r\nSauté pork belly slices for 3–4 minutes until lightly browned, then push to one side of the skillet.\r\nAdd onion slices and cook for 1 minute until slightly softened.\r\nStir the batter briefly and pour about 1/2 cup into the skillet, immediately swirling to coat the bottom thinly.\r\nScatter bean sprouts over half of the pancake and cover the skillet with a lid for 2 minutes to steam the sprouts.\r\nUncover and cook for another 3–4 minutes until the edges curl and turn golden brown and crispy.\r\nFold the pancake in half over the bean sprouts using a spatula, then transfer to a plate.\r\nRepeat steps 2–8 with remaining batter and ingredients, adding oil as needed to prevent sticking.\r\nServe immediately with fish sauce for dipping.", "equipment_tags": [], "portions": 2, "prep_minutes": 26, "prep_minutes_source": "explicit", "kcal": 1318, "protein_g": 24.8, "carbs_g": 94.8, "fat_g": 95.0, "total_kcal": 2635, "total_protein_g": 49.7, "total_carbs_g": 189.5, "total_fat_g": 190.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53503", "name": "Samlar Machu Kreung – Cambodian Sour Stew", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/bmbvjk1782770310.jpg", "local_image": "53503.jpg", "ingredients": [{"ingredient": "Chicken Thighs", "measure": "1 lb"}, {"ingredient": "Vegetable Oil", "measure": "1 tablespoon"}, {"ingredient": "Water", "measure": "4 cups"}, {"ingredient": "Tamarind Paste", "measure": "2 tablespoons"}, {"ingredient": "Fish Sauce", "measure": "1 tablespoon"}, {"ingredient": "Sugar", "measure": "1 tsp"}, {"ingredient": "Pineapple Chunks", "measure": "1 cup"}, {"ingredient": "Cherry Tomatoes", "measure": "1 cup"}, {"ingredient": "Green Beans", "measure": "1 cup"}, {"ingredient": "Lemongrass", "measure": "1 Stalk"}, {"ingredient": "Kaffir Lime Leaves", "measure": "2"}, {"ingredient": "Chilli", "measure": "1 sliced"}], "instructions": "1. Heat 1 tbsp vegetable oil in a large pot over medium-high heat until it shimmers, about 1 minute.\r\n2. Add 1 lb boneless, skinless chicken thighs to the pot and cook until browned on all sides, approximately 5-7 minutes, stirring occasionally to prevent sticking.\r\n3. Pour 4 cups water into the pot and bring to a boil, then reduce heat to a simmer.\r\n4. Stir in 2 tbsp tamarind paste, 1 tbsp fish sauce, and 1 tsp sugar until fully dissolved, about 1 minute.\r\n5. Add 1 stalk lemongrass and 2 kaffir lime leaves to the pot, then cover and simmer for 10 minutes to infuse the broth with flavor.\r\n6. Tip: Bruising the lemongrass before adding helps release its essential oils for a more aromatic stew.\r\n7. Add 1 cup pineapple chunks, 1 cup cherry tomatoes, and 1 cup green beans to the pot, stirring gently to combine.\r\n8. Simmer uncovered for 10-12 minutes, or until the green beans are tender but still crisp and the tomatoes start to soften.\r\n9. Tip: Avoid overcooking the vegetables to maintain their vibrant color and texture in the final dish.\r\n10. Stir in 1 Thai chili and simmer for an additional 2 minutes to incorporate the heat.\r\n11. Tip: Taste the broth and adjust with extra tamarind paste or fish sauce if desired, but do so gradually to avoid overpowering the balance.\r\n12. Remove the pot from heat and discard the lemongrass and kaffir lime leaves before serving.\r\n13. Present the stew hot in bowls, optionally garnished with fresh herbs like cilantro.", "equipment_tags": [], "portions": 5, "prep_minutes": 33, "prep_minutes_source": "explicit", "kcal": 214, "protein_g": 20.4, "carbs_g": 20.1, "fat_g": 6.2, "total_kcal": 1072, "total_protein_g": 102.0, "total_carbs_g": 100.6, "total_fat_g": 31.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53504", "name": "Macaroni Pudding", "category": "Pasta", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/hbte551782770868.jpg", "local_image": "53504.jpg", "ingredients": [{"ingredient": "Macaroni", "measure": "4 cups"}, {"ingredient": "Evaporated Milk", "measure": "4 cups"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Sugar", "measure": "3 Cups"}, {"ingredient": "Salt", "measure": "2 tsp"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Butter", "measure": "1/4 cup"}, {"ingredient": "Raisins", "measure": "1 cup"}, {"ingredient": "Nutmeg", "measure": "2 1/2 Tsp"}, {"ingredient": "Vanilla", "measure": "2 tablespoons"}], "instructions": "Add macaroni to large pan with sufficient water to cover (approximately 4 cups). Add salt and bring to boil until tender (approximately 25 -30 minutes). Meanwhile, beat eggs and sugar together, then add vanilla and nutmeg. Mix well and set aside. In a separate medium sauce pan, heat evaporated milk plus 1 cup of water and butter to almost a boiling point. Remove from heat and add to sugar mixture. Drain cooked macaroni. Add macaroni and raisins to the milk mixture and stir well. (This mixture will have quite a bit of liquid, but this will form a nice custard textured pudding once baked.)\r\n\r\nGrease a large baking dish with butter or margarine, add the macaroni mixture and sprinkle with additional nutmeg. Bake at 350° F for 1 hour or until golden brown. (Pudding should be firm enough to cut, but moist and not dry).", "equipment_tags": [], "portions": 12, "prep_minutes": 90, "prep_minutes_source": "explicit", "kcal": 674, "protein_g": 15.9, "carbs_g": 131.7, "fat_g": 9.9, "total_kcal": 8084, "total_protein_g": 190.2, "total_carbs_g": 1579.9, "total_fat_g": 118.5, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53505", "name": "Conch Fritters", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/nmtq3n1782772031.jpg", "local_image": "53505.jpg", "ingredients": [{"ingredient": "Conchs", "measure": "Can"}, {"ingredient": "Green Pepper", "measure": "1/2"}, {"ingredient": "Red Pepper", "measure": "1/2"}, {"ingredient": "Onion", "measure": "2 large"}, {"ingredient": "Chilli", "measure": "2"}, {"ingredient": "Lime", "measure": "Juice of 2"}, {"ingredient": "Garlic", "measure": "2 tbsp chopped"}, {"ingredient": "Black Pepper", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "1 tablespoon"}, {"ingredient": "Basil", "measure": "1 tsp"}, {"ingredient": "Red Pepper Flakes", "measure": "1 tsp"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "All purpose flour", "measure": "10 tblsp"}, {"ingredient": "Vegetable Oil", "measure": "For frying"}], "instructions": "Note: Make the conch mix the day before and store in the refrigerator to allow time for flavours to meld together. Tartar sauce can also be prepared beforehand. Just combine all the ingredients and mix well. Cover and refrigerate.\r\n\r\nUse your food grinder to grind together the conch pieces, red and green peppers, onions and hot peppers. Once done, add in your lime juice, minced garlic, black pepper, salt, dried basil, and red pepper flakes; make sure to mix it thoroughly. Then add your egg and mix again. Lastly, add your flour one tablespoon at a time and mix until combined. You can either plastic wrap it and let sit in the fridge for an hour or overnight. \r\n\r\nOnce you're ready to fry, fill the deep-frying pan with about 1 ½ to 2 inches of a high heat oil of your choice. Turn stove on to a medium-low heat.\r\n\r\nUse two spoons to form 1-inch balls and drop them into the hot oil one at a time. Each fritter should fry about 5-7 minutes or until golden brown and the inside is cooked. Repeat until you have used all the conch mixture. Serve with your tartar sauce and lime wedges.", "equipment_tags": [], "portions": 2, "prep_minutes": 7, "prep_minutes_source": "explicit", "kcal": 578, "protein_g": 47.3, "carbs_g": 56.9, "fat_g": 19.6, "total_kcal": 1157, "total_protein_g": 94.6, "total_carbs_g": 113.8, "total_fat_g": 39.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53506", "name": "Rice and Beans", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/j8c1d51782772399.jpg", "local_image": "53506.jpg", "ingredients": [{"ingredient": "Kidney Beans", "measure": "1/2 bag"}, {"ingredient": "Coconut Milk", "measure": "1 Can"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Scotch Bonnet", "measure": "3"}, {"ingredient": "Black Pepper", "measure": "1 tablespoon"}, {"ingredient": "Salt", "measure": "1/2 tbs"}], "instructions": "Cook beans until tender, add rice, coconut milk, onion, black pepper and salt, and add enough water to just cover the ingredients. Place Scotch Bonnet peppers on top, careful not to burst them. Simmer until rice is tender. Remove pepper before serving.", "equipment_tags": [], "portions": 1, "prep_minutes": 22, "prep_minutes_source": "estimated", "kcal": 1063, "protein_g": 14.8, "carbs_g": 55.6, "fat_g": 97.2, "total_kcal": 1063, "total_protein_g": 14.8, "total_carbs_g": 55.6, "total_fat_g": 97.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53507", "name": "Cayman Style Potato Salad", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/q21suk1782772956.jpg", "local_image": "53507.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "10"}, {"ingredient": "Green Pepper", "measure": "1/2"}, {"ingredient": "Red Pepper", "measure": "1/4"}, {"ingredient": "Onion", "measure": "1/2"}, {"ingredient": "Mayonnaise", "measure": "1 cup"}, {"ingredient": "Mustard", "measure": "1/4 cup"}, {"ingredient": "Sugar", "measure": "1 tablespoon"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Beets", "measure": "1 Can"}, {"ingredient": "Peas", "measure": "1 Can"}, {"ingredient": "Eggs", "measure": "3"}], "instructions": "Peel and cut potatoes in cubes, boil in salted water until tender. Chop peppers and onion and set aside. Mix together mayonnaise, mustard, sugar and black pepper and set aside. Drain potatoes once tender and place in large mixing bowl. Add remaining ingredients and mix well. The salad may be served warm, but is normally served after it has been refrigerated for 2 to 3 hours.", "equipment_tags": [], "portions": 12, "prep_minutes": 180, "prep_minutes_source": "explicit", "kcal": 350, "protein_g": 8.4, "carbs_g": 36.0, "fat_g": 19.4, "total_kcal": 4194, "total_protein_g": 100.9, "total_carbs_g": 432.5, "total_fat_g": 232.4, "macro_confidence": 0.91, "is_new": false, "video": null}, {"id": "53508", "name": "Cassava Cake", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/2mrghf1782773422.jpg", "local_image": "53508.jpg", "ingredients": [{"ingredient": "Cassava", "measure": "2 Lbs"}, {"ingredient": "Dark Brown Soft Sugar", "measure": "1 lb"}, {"ingredient": "Coconut Milk", "measure": "1 can"}, {"ingredient": "Nutmeg", "measure": "1/4"}, {"ingredient": "Allspice", "measure": "1/2 tsp"}, {"ingredient": "Cinnamon", "measure": "1/2 tsp"}], "instructions": "Bring coconut milk to a boil. Add sugar, stirring until completely dissolved and continue to boil for about 45 minutes. Reserve ½ cup of the coconut milk/sugar mixture for later. Combine remaining ingredients in a large mixing bowl, stir until well blended. Add hot coconut milk mixture and stir well. Mixture should be of a thick liquid texture. Use 1 tablespoons of coconut milk mixture to grease baking pan. Pour batter into prepared baking pan and bake at 350°F (basting occasionally with reserved coconut milk mixture) for 2 to 3 hours or until knife inserted in centre comes out clean. Spread any remaining coconut milk mixture over top of cake. Place cake on top of stove to cool completely.", "equipment_tags": [], "portions": 12, "prep_minutes": 225, "prep_minutes_source": "explicit", "kcal": 338, "protein_g": 4.6, "carbs_g": 51.3, "fat_g": 14.1, "total_kcal": 4054, "total_protein_g": 54.9, "total_carbs_g": 616.0, "total_fat_g": 169.2, "macro_confidence": 0.83, "is_new": false, "video": null}, {"id": "53509", "name": "Fried Crab", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/rprcc51782774240.jpg", "local_image": "53509.jpg", "ingredients": [{"ingredient": "Crab Meay", "measure": "1 lb"}, {"ingredient": "Onions", "measure": "2 medium"}, {"ingredient": "Scotch Bonnet", "measure": "1"}, {"ingredient": "Black Pepper", "measure": "1/2 tsp"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Oil", "measure": "1/4 cup"}], "instructions": "Wash crabs and boil in large pot of water for 15 minutes, remove from boiling water and cool. Crack legs and open backs to remove all meat, set aside.\r\n\r\nRemove seeds from scotch bonnet pepper and dice pepper and onions. Sauté onions and scotch bonnet peppers in oil over medium heat until onions begin to get transparent. Add crab meat, black pepper and salt, stirring occasionally. Cook over medium heat for an additional 5 to 10 minutes.\r\n\r\nServe with “bread kind”, a local dish that consists of a variety of starchy vegetables including pumpkin, squash, plantain, potato, cassava and breadfruit.\r\n\r\nOptional: Seasoned crab meat may also be stuffed in cleaned crab backs and baked. Cover stuffed backs with foil paper and bake at 350 degrees for 30 minutes. ", "equipment_tags": [], "portions": 2, "prep_minutes": 55, "prep_minutes_source": "explicit", "kcal": 489, "protein_g": 42.6, "carbs_g": 13.3, "fat_g": 29.4, "total_kcal": 979, "total_protein_g": 85.3, "total_carbs_g": 26.6, "total_fat_g": 58.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53510", "name": "Cayman-Style Lobster", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/wkhwqr1782774765.jpg", "local_image": "53510.jpg", "ingredients": [{"ingredient": "Lobster", "measure": "6"}, {"ingredient": "Chicken Stock", "measure": "1/2 cup"}, {"ingredient": "Red Pepper", "measure": "1/2 cup"}, {"ingredient": "Green Pepper", "measure": "1/2 cup"}, {"ingredient": "Onion", "measure": "1/2 cup"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Scotch Bonnet", "measure": "1/2"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Pepper", "measure": "To taste"}, {"ingredient": "Thyme", "measure": "To taste"}, {"ingredient": "Cornstarch", "measure": "2 tsp"}, {"ingredient": "Olive Oil", "measure": "2 tablespoons"}], "instructions": "Rinse lobster under cold running water. Bring water and salt to boil in a 12 quart pot. Quickly plunge lobsters, headfirst, into boiling water. Cover and boil for 20 minutes or until lobsters turn red.\r\n\r\nRemove lobster and allow it to cool. Remove lobster tails and cut shell down to middle to remove the meat. Cut the tail meat down the middle to remove the vein inside. Remove large claws and smaller legs by twisting them away from the body. A nut cracker can be used to crush the claw and legs to remove the meat inside.\r\n\r\nChop lobster meat. Heat butter or olive oil in large pan over low heat. Sauté red, green and scotch bonnet peppers, thyme and garlic. Add salt and chicken stock to pan. Then, add lobster meat and sauté for 10 to 15 minutes. Thicken sauce with the corn starch and water mixture.\r\n\r\nServe with your choice of vegetables, salad and/or rice.", "equipment_tags": [], "portions": 2, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 435, "protein_g": 10.1, "carbs_g": 42.0, "fat_g": 26.3, "total_kcal": 870, "total_protein_g": 20.2, "total_carbs_g": 83.9, "total_fat_g": 52.6, "macro_confidence": 0.92, "is_new": false, "video": null}, {"id": "53511", "name": "Salt Beef and Beans", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/dnd87q1782775269.jpg", "local_image": "53511.jpg", "ingredients": [{"ingredient": "Corned Beef", "measure": "1 lb"}, {"ingredient": "Kidney Beans", "measure": "1 1/2 cup"}, {"ingredient": "Scotch Bonnet", "measure": "1"}, {"ingredient": "Scallions", "measure": "2"}, {"ingredient": "Thyme", "measure": "1/4 tsp"}, {"ingredient": "Garlic", "measure": "1 clove finely chopped"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Coconut Milk", "measure": "3 Cups"}, {"ingredient": "Bay Leaf", "measure": "2"}, {"ingredient": "Allspice", "measure": "6"}, {"ingredient": "Garlic", "measure": "2 cloves"}], "instructions": "Cover the diced salt beef with water and bring to a boil. Repeat as necessary, draining and replacing water to eliminate some of the brine. In a separate pan, place beans in water, add coconut milk, bay leaves, pimento seeds, whole garlic, whole scotch bonnet pepper and scallions. Slowly bring to a boil and simmer for about 2 hours, or until beans are tender. Add salt beef, onions, thyme and crushed garlic and simmer for another 20 minutes. Adjust seasonings if necessary. Remove the bay leaves and scotch bonnet pepper, being careful not to burst the pepper. Serve with white rice and your choice of salad or vegetables.", "equipment_tags": [], "portions": 4, "prep_minutes": 140, "prep_minutes_source": "explicit", "kcal": 750, "protein_g": 35.5, "carbs_g": 34.5, "fat_g": 56.3, "total_kcal": 3001, "total_protein_g": 142.1, "total_carbs_g": 137.9, "total_fat_g": 225.1, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53512", "name": "Conch Stew", "category": "Seafood", "area": null, "diet_tag": "Seafood", "image": "https://www.themealdb.com/images/media/meals/mlkjeu1782775816.jpg", "local_image": "53512.jpg", "ingredients": [{"ingredient": "Conchs", "measure": "2 Lbs"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Green Pepper", "measure": "1/2"}, {"ingredient": "Red Pepper", "measure": "1/2"}, {"ingredient": "Scallions", "measure": "2"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Black Pepper", "measure": "1/4 tsp"}, {"ingredient": "Seasoning", "measure": "1/4 tsp"}, {"ingredient": "Coconut", "measure": "1"}, {"ingredient": "Flour", "measure": "1 tablespoon"}, {"ingredient": "Chilli", "measure": "To taste"}, {"ingredient": "All purpose flour", "measure": "1 cup"}, {"ingredient": "Vegetable Oil", "measure": "1/2 tbs"}, {"ingredient": "Salt", "measure": "Dash"}, {"ingredient": "Water", "measure": "Splash"}], "instructions": "Conch Stew Cooking Directions\r\n\r\nClean conch meat and pound to tenderize. Boil conch for 2 - 3 hours or until tender. Make Sea Pie while conch cooks (instructions below). Once cool, cut conch in bite size pieces and season. Add all ingredients, except flour, to pan and simmer for 10 to 20 minutes. Mix flour with 1 cup water and pour into pan to thicken. Add Sea Pie pieces and continue to cook for an additional 10 minutes.\r\n\r\nSea Pie Cooking Directions\r\n\r\nMake dough with flour, pinch of salt and water so that you can roll out as thin as possible, then cut into 2 ½” x 2 ½” squares. Let set for 30 minutes then stretch squares to thin them out and add to conch stew mixture.\r\n\r\nServe with white rice, plantain, breadfruit or your choice of vegetables.", "equipment_tags": [], "portions": 3, "prep_minutes": 240, "prep_minutes_source": "explicit", "kcal": 555, "protein_g": 61.2, "carbs_g": 44.6, "fat_g": 15.2, "total_kcal": 1665, "total_protein_g": 183.6, "total_carbs_g": 133.9, "total_fat_g": 45.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53513", "name": "Chilean-Style Sopaipillas", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/45noa31782850540.jpg", "local_image": "53513.jpg", "ingredients": [{"ingredient": "Zapallo Squash", "measure": "9 oz"}, {"ingredient": "All purpose flour", "measure": "5 Cups"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Melted Butter", "measure": "10 tblsp"}, {"ingredient": "Canola Oil", "measure": "2 cups"}], "instructions": "Peel, seed, and cut zapallo into chunks. Place in a saucepan, cover with water, and bring to a boil over medium-high heat. Cook until zapallo is soft and easily pierced with a fork, 15 to 20 minutes. Drain and allow to cool slightly.\r\n\r\nMix flour, baking soda, and salt together in a mixing bowl, and set aside. Stir together squash and melted butter. Stir the flour mixture into the butter mixture until blended. Turn the dough out onto a lightly floured surface and knead until soft and satiny, adding a little more flour if necessary. Cover dough with a towel and allow to rest 15 minutes.\r\n\r\nRoll out the dough to 1/8-inch thick, and cut into 3-inch diameter circles. Poke each circle a few times with a fork to make holes and prevent rising.\r\n\r\nPour oil into a large, deep skillet and heat over medium-high heat until hot, 385 degrees F (195 degrees C). Place several of the dough circles into hot oil; cook until lightly browned, 3 to 4 minutes. Drain on paper towels. Cook remainder of dough circles in batches.", "equipment_tags": [], "portions": 6, "prep_minutes": 39, "prep_minutes_source": "explicit", "kcal": 621, "protein_g": 11.2, "carbs_g": 83.8, "fat_g": 26.4, "total_kcal": 3729, "total_protein_g": 67.4, "total_carbs_g": 502.8, "total_fat_g": 158.6, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53514", "name": "Chilean Empanada", "category": "Pork", "area": null, "diet_tag": "Pork", "image": "https://www.themealdb.com/images/media/meals/q4xgij1782851193.jpg", "local_image": "53514.jpg", "ingredients": [{"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1 large"}, {"ingredient": "Garlic", "measure": "1 tsp minced"}, {"ingredient": "Dried Oregano", "measure": "1 tsp"}, {"ingredient": "Cumin", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "1/2 tsp"}, {"ingredient": "Ground Pork", "measure": "1 lb"}, {"ingredient": "Raisins", "measure": "1 cup"}, {"ingredient": "Black Olives", "measure": "1 cup"}, {"ingredient": "Eggs", "measure": "3 Large"}, {"ingredient": "Water", "measure": "1 cup"}, {"ingredient": "Shortening", "measure": "1 cup"}, {"ingredient": "All purpose flour", "measure": "5 Cups"}, {"ingredient": "Salt", "measure": "2 tsp"}, {"ingredient": "Eggs", "measure": "2 Beaten"}], "instructions": "Make the filling: Melt butter in a large skillet over medium heat. Add onion, garlic, oregano, cumin, salt, and pepper; cook and stir until onion is golden brown, 5 to 7 minutes. Add pork and cook until completely browned and crumbly, 7 to 10 minutes more. Drain fat from the skillet. Stir in raisins, olives, and hard-cooked eggs.\r\n\r\nWhisk water and cornstarch together in a small bowl; pour into the skillet and stir until liquid thickens. Remove from the heat and set aside.\r\n\r\nMake the dough: Whisk milk and melted shortening together in a bowl until evenly blended. Stir flour and salt together in a separate large bowl. Pour milk mixture into flour mixture; whisk until well combined and a dough forms. Let rest for 10 minutes.\r\n\r\nPreheat the oven to 400 degrees F (200 degrees C). Line a baking sheet with parchment paper.\r\n\r\nRoll dough on a lightly floured surface to a thickness of 1/8 inch. Cut into 12 circles with a round cookie cutter or glass. Spoon filling into the center of each circle. Fold each circle in half and press the edges with a fork to seal. Brush the tops with beaten egg. Place empanadas onto the prepared baking sheet.\r\n\r\nBake in the preheated oven until golden brown, about 25 minutes.", "equipment_tags": [], "portions": 4, "prep_minutes": 52, "prep_minutes_source": "explicit", "kcal": 1189, "protein_g": 49.9, "carbs_g": 177.3, "fat_g": 31.9, "total_kcal": 4755, "total_protein_g": 199.4, "total_carbs_g": 709.3, "total_fat_g": 127.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53515", "name": "Manjar (Dulce de Leche)", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/tmc6ai1782851531.jpg", "local_image": "53515.jpg", "ingredients": [{"ingredient": "Milk", "measure": "1 quart"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Vanilla Extract", "measure": "1/2 tsp"}, {"ingredient": "Baking Powder", "measure": "1/4 tsp"}], "instructions": "Bring milk, sugar, and vanilla extract to a boil in a saucepan over high heat. Reduce heat to medium-low, continue cooking, and continuously stirring until milk has thickened and turned a caramel color, about 1 hour or more.\r\n\r\nStir in baking soda. Continue cooking until caramelized milk has reached a pudding consistency. Pour manjar into a bowl and cool completely in the refrigerator.", "equipment_tags": [], "portions": 8, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 172, "protein_g": 3.8, "carbs_g": 31.3, "fat_g": 3.9, "total_kcal": 1374, "total_protein_g": 30.3, "total_carbs_g": 250.1, "total_fat_g": 31.2, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53516", "name": "Chilean Dobladitas", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/p6hgrj1782851874.jpg", "local_image": "53516.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "4 cups"}, {"ingredient": "Melted Butter", "measure": "1 cup"}, {"ingredient": "Milk", "measure": "1/2 cup"}, {"ingredient": "Baking Powder", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Melted Butter", "measure": "3  tablespoons"}], "instructions": "Preheat the oven to 450 degrees F (230 degrees C). Grease a baking sheet.\r\n\r\nWhisk flour, 1 cup melted butter, milk, baking powder, and salt together in a bowl until begins to pull together. Turn dough out onto a lightly floured surface; knead until smooth and elastic.\r\n\r\nRoll dough out to ⅛-inch thickness; cut into 8-inch circles. Brush circles with remaining 3 tablespoons melted butter. Fold each circle in half, then fold in half again to form triangles. Press firmly to seal the layers; place on the prepared baking sheet.\r\n\r\nBake in the preheated oven until golden brown, about 15 minutes. Serve warm", "equipment_tags": [], "portions": 5, "prep_minutes": 15, "prep_minutes_source": "explicit", "kcal": 778, "protein_g": 11.4, "carbs_g": 79.1, "fat_g": 46.1, "total_kcal": 3892, "total_protein_g": 57.2, "total_carbs_g": 395.5, "total_fat_g": 230.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53517", "name": "Pastel de Papas (Chilean Potato Pie)", "category": "Beef", "area": null, "diet_tag": "Beef", "image": "https://www.themealdb.com/images/media/meals/h031jy1782853081.jpg", "local_image": "53517.jpg", "ingredients": [{"ingredient": "Potatoes", "measure": "5 Cups"}, {"ingredient": "Butter", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Eggs", "measure": "2 Beaten"}, {"ingredient": "Vegetable Oil", "measure": "1/2 cup"}, {"ingredient": "Onion", "measure": "1 Diced"}, {"ingredient": "Garlic", "measure": "1 clove peeled crushed"}, {"ingredient": "Tomato", "measure": "2 diced"}, {"ingredient": "Tomato Puree", "measure": "1 tablespoon"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Panquehue Cheese", "measure": "2 tablespoons"}, {"ingredient": "Parsley", "measure": "1/2 tsp"}, {"ingredient": "Cayenne Pepper", "measure": "1 pinch"}, {"ingredient": "Salt", "measure": "To taste"}, {"ingredient": "Black Pepper", "measure": "To taste"}], "instructions": "Place potatoes into a large pot and cover with salted water; bring to a boil. Reduce the heat to medium-low and simmer until tender, about 20 minutes.\r\n\r\nWhile the potatoes are cooking, heat oil in a large skillet over medium heat. Add onion; cook and stir until translucent, about 5 minutes, adding garlic for the last minute. Stir in diced tomatoes and tomato paste; cook until tomatoes soften and begin to lose their shape, 3 to 5 minutes.\r\n\r\nAdd ground beef to the skillet; cook and stir until browned and crumbly, about 10 minutes. Stir in Panquehue cheese, parsley, and cayenne pepper; season with salt and pepper. Turn off the heat and let sit until needed.\r\n\r\nPreheat the oven to 350 degrees F (175 degrees C). Grease a 2-quart baking dish.\r\n\r\nDrain potatoes in a colander, then allow to steam dry for 1 to 2 minutes. Transfer potatoes back to the pot, add butter and salt, and mash until smooth. Let cool until just warm, 5 to 10 minutes, then stir in beaten egg.\r\n\r\nSpread 1/2 of the mashed potatoes over the bottom of the prepared baking dish. Layer ground beef mixture over top, then completely cover with remaining potatoes.\r\n\r\nBake in the preheated oven until potatoes are hot and lightly browned on top, about 40 minutes.", "equipment_tags": [], "portions": 5, "prep_minutes": 92, "prep_minutes_source": "explicit", "kcal": 722, "protein_g": 25.1, "carbs_g": 45.7, "fat_g": 49.0, "total_kcal": 3608, "total_protein_g": 125.7, "total_carbs_g": 228.7, "total_fat_g": 244.8, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53518", "name": "Empanadas Fritas de Queso", "category": "Vegetarian", "area": null, "diet_tag": "Vegetarian", "image": "https://www.themealdb.com/images/media/meals/9tllzd1782853513.jpg", "local_image": "53518.jpg", "ingredients": [{"ingredient": "All purpose flour", "measure": "3 Cups"}, {"ingredient": "Baking Powder", "measure": "1 tsp"}, {"ingredient": "Salt", "measure": "1/2 tsp"}, {"ingredient": "Lard", "measure": "2 tablespoons"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "1 beaten"}, {"ingredient": "Swiss Cheese", "measure": "1 cup"}], "instructions": "Sift the flour, baking powder, and salt into a large mixing bowl. Combine the lard and milk in a saucepan, and heat until the milk is hot. Pour the hot milk into the flour mixture, and stir until a dough forms. Turn out onto a floured surface, and knead until smooth and elastic. Cover, and allow to rest for 15 minutes.\r\n\r\nPreheat oven to 375 degrees F (190 degrees C).\r\n\r\nRoll the dough out on a floured surface 1/4-inch thick. Cut into 4-inch rounds. Brush the outer edges of each circle with beaten egg, and fill with a small mound of cheese. Fold each circle in half to form a half-moon; press the edges with your fingers or a fork to seal. Place the empanadas onto a parchment paper-lined baking sheet. Brush the tops with remaining egg.\r\n\r\nBake in preheated oven until golden-brown, about 20 minutes.\r\n\r\nAlternatively, the empanadas may be deep fried in 375 degrees F (190 degrees C) oil. If deep frying, do not brush the outsides of the empanadas with egg. Drain on paper towels.", "equipment_tags": [], "portions": 2, "prep_minutes": 35, "prep_minutes_source": "explicit", "kcal": 1360, "protein_g": 55.0, "carbs_g": 154.1, "fat_g": 57.0, "total_kcal": 2720, "total_protein_g": 109.9, "total_carbs_g": 308.3, "total_fat_g": 113.9, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53519", "name": "Leche Asada", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/fnh40v1782853788.jpg", "local_image": "53519.jpg", "ingredients": [{"ingredient": "Milk", "measure": "1 quart"}, {"ingredient": "Lemon", "measure": "Zest of 1"}, {"ingredient": "Cinnamon Stick", "measure": "2"}, {"ingredient": "Eggs", "measure": "4"}, {"ingredient": "Sugar", "measure": "1/2 cup"}], "instructions": "Preheat oven to 350 degrees F (175 degrees C).\r\n\r\nPour the milk into a saucepan along with the lemon zest and cinnamon sticks. Bring to a simmer over medium-high heat, then reduce heat to low, and cook for 5 minutes. Turn heat off, and allow to steep for 15 minutes.\r\n\r\nGently beat the eggs and sugar together until the sugar has dissolved. Slowly beat in 1 cup of the hot milk, a little at a time, until it has been incorporated. Stir the egg mixture back into the hot milk, pour in the pisco, and mix until well combined.\r\n\r\nPour the custard through a fine mesh sieve into a 2-quart ceramic casserole dish to remove the lemon zest and cinnamon. Bake in preheated oven until set, and browned on top, about 30 minutes. Chill before serving.", "equipment_tags": [], "portions": 9, "prep_minutes": 50, "prep_minutes_source": "explicit", "kcal": 141, "protein_g": 6.3, "carbs_g": 17.0, "fat_g": 5.7, "total_kcal": 1269, "total_protein_g": 56.6, "total_carbs_g": 153.2, "total_fat_g": 51.3, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53520", "name": "Pastel de Choclo", "category": "Chicken", "area": null, "diet_tag": "Chicken", "image": "https://www.themealdb.com/images/media/meals/47abic1782854326.jpg", "local_image": "53520.jpg", "ingredients": [{"ingredient": "Eggs", "measure": "2"}, {"ingredient": "Onions", "measure": "2 chopped"}, {"ingredient": "Garlic", "measure": "2 cloves minced"}, {"ingredient": "Salt", "measure": "1 tsp"}, {"ingredient": "Paprika", "measure": "1/2 tsp"}, {"ingredient": "Black Pepper", "measure": "To taste"}, {"ingredient": "Ground Beef", "measure": "1 lb"}, {"ingredient": "Chicken", "measure": "1/2"}, {"ingredient": "Raisins", "measure": "2 tablespoons"}, {"ingredient": "Green Olives", "measure": "2 tablespoons"}, {"ingredient": "Sweetcorn", "measure": "3 cans"}, {"ingredient": "Basil", "measure": "2 tsp"}, {"ingredient": "Butter", "measure": "1 tablespoon"}, {"ingredient": "Milk", "measure": "1 cup"}, {"ingredient": "Sugar", "measure": "2 tsp"}, {"ingredient": "Salt", "measure": "To taste"}], "instructions": "Place eggs in a saucepan and cover with water. Bring to a boil, remove from heat, and let eggs stand in hot water for 15 minutes.\r\n\r\nMeanwhile, heat oil in a skillet over medium heat. Add onions, garlic, 1 pinch salt, ¼ teaspoon paprika, and black pepper; cook until fragrant, about 2 minutes. Add beef, remaining 1 teaspoon salt, remaining ¼ teaspoon paprika, and black pepper; cook and stir until beef mostly browned, about 5 minutes. Add chicken, raisins, and olives.\r\n\r\nRemove eggs from hot water, cool under cold running water, and peel. Roughly chop; add to beef mixture. Keep pino warm.\r\n\r\nCombine corn and basil in a blender or the bowl of a food processor; blend until smooth. Pour into a saucepan over medium heat. Add butter; cook and stir until thickened, 7 to 10 minutes. Stir in milk, 2 teaspoons sugar, and salt; cook until thickened to a paste, about 15 minutes more.\r\n\r\nPreheat the oven to 350 degrees F (175 degrees C).\r\n\r\nSpread pino into a baking dish. Cover with corn paste; sprinkle a little sugar on top.\r\n\r\nBake in the preheated oven until golden brown on top, about 20 minutes.", "equipment_tags": ["Blender", "FoodProcessor"], "portions": 5, "prep_minutes": 67, "prep_minutes_source": "explicit", "kcal": 578, "protein_g": 29.5, "carbs_g": 59.7, "fat_g": 28.8, "total_kcal": 2889, "total_protein_g": 147.6, "total_carbs_g": 298.7, "total_fat_g": 144.0, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53521", "name": "Porotos Granados (Chilean Bean Stew)", "category": "Miscellaneous", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/nimml81782855200.jpg", "local_image": "53521.jpg", "ingredients": [{"ingredient": "Olive Oil", "measure": "1 tablespoon"}, {"ingredient": "Onion", "measure": "1"}, {"ingredient": "Butternut Squash", "measure": "2 cups"}, {"ingredient": "Great Northern Beans", "measure": "1 Can"}, {"ingredient": "Lima Beans", "measure": "1 cup"}, {"ingredient": "Chicken Stock", "measure": "3 Cups"}, {"ingredient": "Sweetcorn", "measure": "2 cups"}, {"ingredient": "Basil", "measure": "2 tbs chopped"}, {"ingredient": "Banana Pepper", "measure": "1"}], "instructions": "Heat the olive oil in a stock pot over medium heat; add the onion and cover. Cook the onions until soft and translucent, about 5 minutes. Stir the squash, great Northern beans, and lima beans into the pot; pour the chicken stock over the mixture. Cover and cook until the squash is tender and beginning to break apart, 30 to 45 minutes.\r\n\r\nStir the corn and basil into the stew; cook until the stew reaches the consistency of pancake batter, about 10 minutes more. Sprinkle the chopped banana pepper over individual portions to serve.", "equipment_tags": [], "portions": 5, "prep_minutes": 60, "prep_minutes_source": "explicit", "kcal": 311, "protein_g": 16.4, "carbs_g": 57.1, "fat_g": 5.0, "total_kcal": 1555, "total_protein_g": 81.9, "total_carbs_g": 285.7, "total_fat_g": 25.2, "macro_confidence": 0.89, "is_new": false, "video": null}, {"id": "53522", "name": "Arroz con Leche Recipe", "category": "Dessert", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/jp09191782856005.jpg", "local_image": "53522.jpg", "ingredients": [{"ingredient": "Rice", "measure": "1 cup"}, {"ingredient": "Cinnamon Stick", "measure": "4"}, {"ingredient": "Water", "measure": "2 cups"}, {"ingredient": "Milk", "measure": "4 cups"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Butter", "measure": "2 tablespoons"}, {"ingredient": "Vanilla Extract", "measure": "2 tablespoons"}, {"ingredient": "Sugar", "measure": "1 cup"}, {"ingredient": "Condensed Milk", "measure": "12 ounces"}], "instructions": "In a small pot, add water and cinnamon sticks, bring to a boil and cook for 10 minutes. Set aside and discard cinnamon sticks.\r\nPlace the rice and the cinnamon water in a large saucepan, over medium heat and cook for 5 minutes.\r\nAdd salt, butter, vanilla extract, 2 cups of milk, and sugar. Stir well to mix and cook uncovered for approximately 15 minutes.\r\nReduce heat to medium low. Add the remaining milk and condensed milk. Stir with a wooden spoon. Cook for 1 hour and 15 minutes, or until the rice pudding thickens to desire consistency.\r\n\r\nStir well and remove from heat, and let it cool at room temperature. The consistency should be very creamy. Refrigerate for a least 1 hour or overnight.", "equipment_tags": [], "portions": 12, "prep_minutes": 165, "prep_minutes_source": "explicit", "kcal": 219, "protein_g": 4.7, "carbs_g": 36.2, "fat_g": 5.6, "total_kcal": 2623, "total_protein_g": 56.4, "total_carbs_g": 434.3, "total_fat_g": 67.7, "macro_confidence": 1.0, "is_new": false, "video": null}, {"id": "53523", "name": "Colombian Buñuelos Recipe", "category": "Side", "area": null, "diet_tag": "Mixed", "image": "https://www.themealdb.com/images/media/meals/bza0g51782856541.jpg", "local_image": "53523.jpg", "ingredients": [{"ingredient": "Vegetable Oil", "measure": "For frying"}, {"ingredient": "Cornstarch", "measure": "1 1/2 cup"}, {"ingredient": "Tapioca", "measure": "1/4 cup"}, {"ingredient": "Feta", "measure": "1 cup"}, {"ingredient": "Farmers Cheese", "measure": "1 cup"}, {"ingredient": "Egg", "measure": "1"}, {"ingredient": "Baking Powder", "measure": "1/2 tsp"}, {"ingredient": "Sugar", "measure": "2 tablespoons"}, {"ingredient": "Salt", "measure": "Pinch"}, {"ingredient": "Milk", "measure": "5 tablespoons"}], "instructions": "Place all the ingredients, except the oil in a medium bowl and mix well using your hands until soft and smooth dough is obtained.\r\nForm small balls using your hands.\r\nIn a deep pot, heat the vegetable oil to 300°F (Warm, not very hot). Carefully drop the balls in the warm oil and fry for about 3 to 4 minutes or until gilden brown.\r\nRemove from the oil and drain on a plate lined with paper towels. Serve.\r\n\r\nFrying Colombian buñuelos using the right temperature is very important. The oil can't be very hot or very cold. Be sure the oil is heated to 300 to 320 grades F.", "equipment_tags": [], "portions": 6, "prep_minutes": 4, "prep_minutes_source": "explicit", "kcal": 590, "protein_g": 16.9, "carbs_g": 71.0, "fat_g": 25.9, "total_kcal": 3542, "total_protein_g": 101.3, "total_carbs_g": 425.8, "total_fat_g": 155.4, "macro_confidence": 1.0, "is_new": false, "video": null}];

// ── DERIVED HELPERS ──────────────────────────────────────────────────────
// scaledMacro() kept for compatibility with any leftover call sites — the
// enriched library has no size multiplier concept (portions are already
// baked into kcal/protein_g/carbs_g/fat_g per portion), so this just reads
// the field straight through. Size scaling (small/regular/large) was a
// feature of the old hand-authored library only; see §8 of the overhaul
// prompt re: whether to bring portion scaling back.
function scaledMacro(m, key) {
  const map = { kcal: 'kcal', protein: 'protein_g', carbs: 'carbs_g', fat: 'fat_g' };
  return m[map[key] || key] || 0;
}

// ── FILTER BAND THRESHOLDS — used by both the shelf functions below and
// the Search > Filters sheet in kitchen-plan.js. Defined once here so the
// two never drift out of sync. Thresholds set from the actual distribution
// of the 733-recipe enriched library (kcal p33/p66, protein median/p80) —
// not arbitrary round numbers picked before seeing the data.
const KITCHEN_CAL_BANDS = [
  { key: 'low',    label: 'Low (≤500 kcal)',      test: m => m.kcal <= 500 },
  { key: 'medium', label: 'Medium (500–800 kcal)', test: m => m.kcal > 500 && m.kcal <= 800 },
  { key: 'high',   label: 'High (800+ kcal)',      test: m => m.kcal > 800 }
];
const KITCHEN_PROTEIN_BANDS = [
  { key: 'average',  label: 'Average (<25g)',      test: m => m.protein_g < 25 },
  { key: 'high',      label: 'High (25–45g)',       test: m => m.protein_g >= 25 && m.protein_g <= 45 },
  { key: 'veryhigh', label: 'Very High (45g+)',     test: m => m.protein_g > 45 }
];
const KITCHEN_TIME_BANDS = [
  { key: '15', label: 'Under 15', test: m => m.prep_minutes <= 15 },
  { key: '20', label: 'Under 20', test: m => m.prep_minutes <= 20 },
  { key: '30', label: 'Under 30', test: m => m.prep_minutes <= 30 },
  { key: '35plus', label: '35+',  test: m => m.prep_minutes >= 35 }
];
const KITCHEN_DIET_TAGS = ['Vegan','Vegetarian','Seafood','Chicken','Beef','Pork','Mixed'];

// Equipment filter — equipment_tags is now populated via keyword-matching
// against instructions (see kitchen-library.js), so this filter is live.
const KITCHEN_EQUIPMENT_TAGS = ['AirFryer','SlowCooker','Blender','FoodProcessor','Grill'];

// ── CURATED SHELVES — not dataset fields, defined as filter/pick functions
// over MEAL_LIBRARY, same test-function pattern the old tier picker used. ─

// Deterministic daily shuffle seed so "Suggested For You" doesn't reshuffle
// on every render/tab-switch within the same day, but does rotate day to day.
function _kitchenDaySeed() {
  const d = new Date();
  return d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
}
function _kitchenSeededShuffle(arr, seed) {
  const a = arr.slice();
  let s = seed;
  for (let i = a.length - 1; i > 0; i--) {
    s = (s * 9301 + 49297) % 233280;
    const j = Math.floor((s / 233280) * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// ── DESSERT DETECTION ── used to keep desserts out of the curated shelves
// below. Category alone ("Dessert") is the reliable signal (human-curated
// at import time), but a dessert with real protein in it (a cheesecake,
// a nut tart, a custard with actual eggs/dairy behind it) isn't the thing
// worth filtering — it behaves like food, not a sugar bomb. So: only items
// tagged Dessert are even considered, and among those we let a genuinely
// protein-forward one back in via a protein/carbs ratio check. Ratio alone
// (no category gate) was tried and rejected — it also flagged plenty of
// ordinary high-carb savory dishes (rice bowls, pasta, casseroles) as
// "dessert-like" purely for having more carbs than protein, which is just
// what a lot of real dinners look like. Gating on category first avoids
// that false-positive flood while still respecting the "some desserts are
// fine" case.
function _kitchenIsDessertLike(m) {
  if (m.category !== 'Dessert') return false;
  const carbs = m.carbs_g || 0;
  const protein = m.protein_g || 0;
  if (carbs < 10) return protein < 5; // negligible-carb "dessert" — still exclude unless it has real protein
  return (protein / carbs) < 0.3;
}

// ── GOAL-AWARE POOL ── narrows the library to what actually fits the
// person's current goalType (Settings > goal) before shelves pick from it.
// "Lose fat" wants satiating-but-lighter meals; "recomposition" wants
// protein first without a hard calorie ceiling (it's eaten at maintenance,
// not a deficit); "gain muscle"/"gain weight" want calorie-and-protein-dense
// meals to make hitting a surplus easier. Unrecognized/missing goalType
// falls back to the unfiltered pool. If a goal filter is too narrow to fill
// a shelf (fewer than 40 matches), we fall back to the full pool rather
// than repeating the same handful of meals every day.
function _kitchenGoalFilteredPool(pool, goalType) {
  let filtered;
  if (goalType === 'lose_fat') {
    filtered = pool.filter(m => m.kcal <= 650 && m.protein_g >= 20);
  } else if (goalType === 'recomposition') {
    filtered = pool.filter(m => m.protein_g >= 30);
  } else if (goalType === 'gain_muscle' || goalType === 'gain_weight') {
    filtered = pool.filter(m => m.protein_g >= 25 && m.kcal >= 600);
  } else {
    filtered = pool;
  }
  return filtered.length >= 40 ? filtered : pool;
}

// Suggested For You — a stable-per-day, varied-by-diet_tag rotation across
// the whole library, narrowed first by the active person's goal and with
// desserts filtered out per _kitchenIsDessertLike above. Rotates daily via
// _kitchenDaySeed so the shelf isn't static, but doesn't reshuffle on every
// render/tab-switch within the same day.
function suggestedForYouMeals(count = 18) {
  const mission = (window.S && S.mission && S.mission[S.currentPerson]) || {};
  const goalType = mission.goalType || 'lose_fat';
  const nonDessert = MEAL_LIBRARY.filter(m => !_kitchenIsDessertLike(m));
  const pool = _kitchenGoalFilteredPool(nonDessert, goalType);
  const shuffled = _kitchenSeededShuffle(pool, _kitchenDaySeed());
  const seenDiet = {};
  const picked = [], rest = [];
  for (const m of shuffled) {
    const n = seenDiet[m.diet_tag] || 0;
    if (n < 3) { picked.push(m); seenDiet[m.diet_tag] = n + 1; }
    else rest.push(m);
    if (picked.length >= count) break;
  }
  while (picked.length < count && rest.length) picked.push(rest.shift());
  return picked;
}

function postWorkoutMeals(count = 18) {
  return MEAL_LIBRARY.filter(m => !_kitchenIsDessertLike(m) && m.protein_g >= 30)
    .sort((a, b) => b.protein_g - a.protein_g).slice(0, count);
}

function under15MinuteMeals(count = 18) {
  return _kitchenSeededShuffle(MEAL_LIBRARY.filter(m => !_kitchenIsDessertLike(m) && m.prep_minutes <= 15), _kitchenDaySeed() + 1).slice(0, count);
}

function weightLossFriendlyMeals(count = 18) {
  return MEAL_LIBRARY.filter(m => !_kitchenIsDessertLike(m) && m.kcal <= 500).sort((a, b) => a.kcal - b.kcal).slice(0, count);
}

const KITCHEN_SHELVES = [
  { key: 'suggested',  label: 'Suggested For You',    sub: 'Add 3 meals to your list!',      cta: true,  fn: suggestedForYouMeals },
  { key: 'postworkout',label: 'Post Workout',          sub: 'Recover after a great workout!', cta: false, fn: postWorkoutMeals },
  { key: 'under15',    label: 'Under 15 Minutes',      sub: 'Quick meals for busy potatoes',  cta: false, fn: under15MinuteMeals },
  { key: 'weightloss', label: 'Weight Loss Friendly',  sub: 'Lighter picks, same flavour',    cta: false, fn: weightLossFriendlyMeals }
];

// ── MEAL LOOKUP — checks both the TheMealDB-derived library and any
// user-created custom meals (S.kitchen.custom), since Recipe Preview /
// Saved / Shopping all need to resolve an id regardless of which array it
// lives in. ────────────────────────────────────────────────────────────
function kitchenFindMeal(id) {
  return MEAL_LIBRARY.find(m => m.id === id) ||
    (S.kitchen.custom || []).find(m => m.id === id);
}
